    // Bellman bridge: lazy-init from soulStore (works with InMemoryDigitalSoulStore)
    private val bellmanBridge: BellmanBridge? by lazy {
        (soulStore as? InMemoryDigitalSoulStore)?.let { BellmanBridge(it) }
    }

    suspend fun handleRequest(request: AgentRequest, cloudGateway: CloudGateway?): AgentResponse {
        val startMs = nowMs()
        val traceId = traceFactory()
        restoreDynamicStateIfNeeded(request.userId)
        val intent = IntentClassifier.classify(request.rawText)
        val module = moduleOverrideForCommand(request.rawText) ?: request.module ?: moduleForIntent(intent)
        val explicitEscalationIntent = shouldTreatAsEscalationIntent(
            rawText = request.rawText,
            module = module
        )
        if (module == ModuleId.CHAT && !explicitEscalationIntent) {
            // Prevent stale LIX escalation context from polluting normal chat requests.
            pendingLixEscalations.remove(request.userId)
        }
        val rawConstraints = resolveRequestConstraints(request)
        val roleContext = resolveRoleExecutionContext(
            request = request,
            module = module,
            constraints = rawConstraints
        )
        val resolvedConstraints = rawConstraints.withRoleContext(roleContext)
        val orchestrationMeta = buildOrchestrationMeta(
            request = request,
            module = module,
            intent = intent,
            resolvedConstraints = resolvedConstraints,
            roleContext = roleContext
        )
        val policyDecision = sensitiveAppDetector.detect(
            packageName = request.sourceApp,
            imeOptions = request.fieldHints.imeOptions
        )
        val policyLevel = inferPolicyLevel(policyDecision.reason)

        if (!policyDecision.isAgentAllowed || policyLevel == PolicyLevel.STRICT_BLOCK) {
            return finalizeGovernedResponse(
                response = AgentResponse(
                    type = AgentResponseType.CARDS,
                    cards = listOf(
                        AgentCard(
                            id = "shield-up",
                            title = "Shield Up",
                            summary = "Sensitive-app policy matched. High-risk operations are disabled and only safe guidance is returned.",
                            deeplink = LumiRoutes.CHAT,
                            riskLevel = "high"
                        )
                    ),
                    summary = "Shield Up is active: no external tasks will run and no twin memory will be written.",
                    privacyAction = PrivacyAction.SHIELD_UP,
                    appDeeplink = LumiRoutes.CHAT,
                    traceId = traceId,
                    latencyMs = nowMs() - startMs,
                    confidence = 0.98,
                    module = ModuleId.CHAT,
                    payload = ModulePayload.ChatPayload(
                        suggestionTitle = "Sensitive context protection enabled",
                        hints = listOf("Return safe guidance only", "Plaintext input will not be recorded"),
                        taskTrack = TaskTrackBuilder.build(
                            module = ModuleId.CHAT,
                            query = request.rawText,
                            traceId = traceId,
                            phase = "shield_up",
                            status = ResponseStatus.PARTIAL,
                            evidenceItems = emptyList(),
                            nowMs = nowMs()
                        )
                    ),
                    actions = listOf(
                        AgentAction(
                            id = "open_chat",
                            label = "Open Lumi Chat",
                            type = AgentActionType.OPEN_DEEPLINK,
                            deeplink = LumiRoutes.CHAT
                        )
                    ),
                    status = ResponseStatus.PARTIAL
                ),
                request = request,
                module = module,
                meta = orchestrationMeta,
                constraints = resolvedConstraints,
                roleContext = roleContext,
                startMs = startMs
            )
        }

        val dynamicState = request.stateVector
            ?: request.keystroke?.let { buildFallbackDynamicState(request, it) }
        if (dynamicState != null) {
            updateDynamicState(request.userId, dynamicState)
        }
        soulStore.onRequest(request.userId, intent, request.locale)

        builtInAgentMarketResponse(
            request = request,
            module = module,
            startMs = startMs,
            traceId = traceId,
            orchestrationMeta = orchestrationMeta
        )?.let {
            return finalizeGovernedResponse(
                response = it,
                request = request,
                module = module,
                meta = orchestrationMeta,
                constraints = resolvedConstraints,
                roleContext = roleContext,
                startMs = startMs
            )
        }

        val localDrafts = DraftTemplateEngine.generateForModule(module, intent, request.rawText)
        val localCards = defaultCardsFor(module, intent)

        val baseResponse = AgentResponse(
            type = if (localCards.isNotEmpty()) AgentResponseType.CARDS else AgentResponseType.DRAFT,
            drafts = localDrafts.take(3),
            cards = localCards,
            summary = summaryFor(module, intent),
            privacyAction = when (policyLevel) {
                PolicyLevel.MASK_ONLY -> PrivacyAction.MASK_ONLY
                PolicyLevel.DISABLE_MEMORY -> PrivacyAction.DISABLE_MEMORY
                else -> PrivacyAction.NONE
            },
            appDeeplink = routeForModule(module, traceId),
            traceId = traceId,
            latencyMs = nowMs() - startMs,
            confidence = confidenceFor(intent),
            module = module,
            payload = payloadForModule(
                module = module,
                userId = request.userId,
                locale = request.locale,
                query = request.rawText,
                traceId = traceId,
                meta = orchestrationMeta
            ),
            actions = defaultActions(module, request.rawText),
            status = ResponseStatus.SUCCESS,
            routingDecision = orchestrationMeta.routingDecision,
            taskGraph = orchestrationMeta.taskGraph,
            skillInvocations = orchestrationMeta.skillInvocations,
            skillGapReport = orchestrationMeta.skillGap,
            skillRequirements = orchestrationMeta.skillRequirements,
            skillCandidates = orchestrationMeta.skillCandidates,
            skillAcquisitionDecisions = orchestrationMeta.skillAcquisitionDecisions,
            skillCanaryReports = orchestrationMeta.skillCanaryReports,
            skillPromotionRecords = orchestrationMeta.skillPromotionRecords,
            skillSelectionTrace = orchestrationMeta.skillSelectionTrace
        )

        if (cloudGateway == null || request.networkPolicy == NetworkPolicy.LOCAL_ONLY) {
            val offlineCloudResponse = if (module == ModuleId.CHAT) {
                baseResponse.copy(
                    status = ResponseStatus.PARTIAL,
                    summary = "Cloud reasoning/decomposition is unavailable in this run. Digital twin state was captured on-device; enable cloud execution to get final synthesized results."
                )
            } else {
                baseResponse
            }
            return finalizeGovernedResponse(
                response = offlineCloudResponse,
                request = request,
                module = module,
                meta = orchestrationMeta,
                constraints = resolvedConstraints,
                roleContext = roleContext,
                startMs = startMs
            )
        }

        val cloudEnhancement = fetchCloudEnhancement(
            module = module,
            intent = intent,
            request = request,
            cloudGateway = cloudGateway,
            meta = orchestrationMeta,
            resolvedRequestConstraints = resolvedConstraints,
            roleContext = roleContext
        )

        val mergedPayload = mergePayload(
            base = baseResponse.payload,
            enhancement = cloudEnhancement.payload,
            meta = orchestrationMeta
        )

        return finalizeGovernedResponse(
            response = baseResponse.copy(
            cards = (baseResponse.cards + cloudEnhancement.cards).distinctBy { it.id }.take(6),
            summary = cloudEnhancement.summary ?: baseResponse.summary,
            payload = mergedPayload,
            status = cloudEnhancement.status ?: baseResponse.status,
            latencyMs = nowMs() - startMs,
            confidence = (baseResponse.confidence + 0.06).coerceAtMost(0.99)
            ),
            request = request,
            module = module,
            meta = orchestrationMeta,
            constraints = resolvedConstraints,
            roleContext = roleContext,
            startMs = startMs
        )
    }

    private fun finalizeGovernedResponse(
        response: AgentResponse,
        request: AgentRequest,
        module: ModuleId,
        meta: OrchestrationMeta,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext,
        startMs: Long
    ): AgentResponse {
        val resolvedConstraints = resolveRequestConstraints(request)
            .mergeWith(constraints)
            .withRoleContext(roleContext)
        val evidence = if (response.evidence.isNotEmpty()) {
            response.evidence
        } else {
            collectEvidenceFromResponse(response)
        }
        val gateDecisions = evaluateStrictGates(
            request = request,
            response = response,
            module = module,
            meta = meta,
            constraints = resolvedConstraints,
            roleContext = roleContext,
            evidence = evidence
        )
        val firstBlockingGate = gateDecisions.firstOrNull { it.decision != GateDecisionStatus.PASSED }
        val normalizedStatus = when {
            response.status == ResponseStatus.CANCELLED || response.status == ResponseStatus.ERROR -> response.status
            firstBlockingGate == null -> response.status
            firstBlockingGate.decision == GateDecisionStatus.BLOCKED -> ResponseStatus.WAITING_USER
            firstBlockingGate.decision == GateDecisionStatus.WAITING_USER -> ResponseStatus.WAITING_USER
            else -> response.status
        }
        val problemFrame = buildProblemFrame(
            request = request,
            module = module,
            meta = meta,
            constraints = resolvedConstraints
        )
        val riskBoundary = buildRiskBoundary(problemFrame)
        val preliminaryPhase = resolvePhase(
            module = module,
            status = normalizedStatus,
            gateDecisions = gateDecisions,
            response = response
        )
        val baselineNextAction = firstBlockingGate?.nextAction
            ?: defaultNextAction(
                status = normalizedStatus,
                module = module,
                phase = preliminaryPhase
            )
        val normalizedSummary = response.summary
            ?.takeIf { it.isNotBlank() }
            ?: "No empty return is allowed. Clarify constraints and continue."
        val returnContractAudit = enforceUserReturnContract(
            summary = normalizedSummary,
            nextAction = baselineNextAction,
            problemFrame = problemFrame,
            evidence = evidence
        )
        val statusAfterAudit = when {
            normalizedStatus == ResponseStatus.SUCCESS && returnContractAudit.shouldRequestRework -> ResponseStatus.PARTIAL
            else -> normalizedStatus
        }
        val phase = resolvePhase(
            module = module,
            status = statusAfterAudit,
            gateDecisions = gateDecisions,
            response = response.copy(
                summary = returnContractAudit.summary,
                status = statusAfterAudit
            )
        )
        val ownerAgent = resolveOwnerAgent(phase, gateDecisions)
        val nextAction = firstBlockingGate?.nextAction
            ?: returnContractAudit.nextActionHint
            ?: defaultNextAction(
                status = statusAfterAudit,
                module = module,
                phase = phase
            )
        val clarificationQuestions = buildClarificationQuestions(
            request = request,
            gateDecisions = gateDecisions,
            problemFrame = problemFrame
        )
        val evidenceClaims = buildEvidenceClaims(
            summary = returnContractAudit.summary,
            evidence = evidence
        )
        val validationReport = buildValidationReport(
            response = response,
            evidence = evidence,
            gateDecisions = gateDecisions,
            phase = phase,
            status = statusAfterAudit,
            returnContractAudit = returnContractAudit
        )
        val handoffPackets = buildHandoffPackets(
            response = response,
            module = module,
            meta = meta,
            phase = phase,
            status = statusAfterAudit,
            gateDecisions = gateDecisions,
            problemFrame = problemFrame,
            evidence = evidence,
            returnContractAudit = returnContractAudit
        )
        val marketEscalation = buildMarketEscalationPacket(
            response = response,
            module = module,
            meta = meta,
            constraints = resolvedConstraints,
            phase = phase,
            gateDecisions = gateDecisions
        )
        val finalDelivery = buildFinalDeliveryPacket(
            response = response.copy(
                summary = returnContractAudit.summary,
                nextAction = nextAction
            ),
            status = statusAfterAudit,
            evidence = evidence,
            gateDecisions = gateDecisions,
            returnContractAudit = returnContractAudit
        )
        val mergedActions = augmentExecutableActions(
            response = response.copy(
                summary = returnContractAudit.summary,
                nextAction = nextAction,
                status = statusAfterAudit
            ),
            module = module,
            evidence = evidence
        )
        val baseResponse = response.copy(
            summary = returnContractAudit.summary,
            status = statusAfterAudit,
            nextAction = nextAction,
            problemFrame = problemFrame,
            clarificationQuestions = clarificationQuestions,
            evidenceClaims = evidenceClaims,
            riskBoundary = riskBoundary,
            evidence = evidence,
            ownerAgent = ownerAgent,
            phase = phase,
            gateDecisions = gateDecisions,
            handoffPackets = handoffPackets,
            validationReport = validationReport,
            marketEscalation = marketEscalation,
            finalDelivery = finalDelivery,
            actions = mergedActions,
            latencyMs = response.latencyMs.takeIf { it > 0 } ?: (nowMs() - startMs).coerceAtLeast(0)
        )
        val externalAnalysis = analyzeExternalFulfillment(
            response = baseResponse,
            constraints = resolvedConstraints,
            roleContext = roleContext,
            gateDecisions = gateDecisions
        )
        val roleImpactReasonCodes = mergeRoleReasonCodes(
            baseResponse.roleImpactReasonCodes,
            resolvedConstraints.roleImpactReasonCodes,
            roleContext.canonicalRoleReasonCodes,
            roleImpactCodesFromRouting(meta.routingDecision.reasonCodes),
            roleImpactCodesFromGateDecisions(gateDecisions),
            roleImpactCodesForStatus(statusAfterAudit),
            externalAnalysis.additionalRoleReasonCodes,
            roleContext.legacyRoleDetailReasons
        )
        val finalizedWithRoleTrace = externalAnalysis.apply(baseResponse).withRoleTrace(
            roleContext = roleContext,
            roleImpactReasonCodes = roleImpactReasonCodes
        )
        val updatedAtMs = nowMs()
        val policySnapshot = buildRolePolicySnapshot(
            request = request,
            constraints = resolvedConstraints,
            roleContext = roleContext,
            boundAtMs = updatedAtMs,
            traceId = finalizedWithRoleTrace.traceId
        )
        val receipt = buildExecutionReceipt(
            response = finalizedWithRoleTrace,
            request = request,
            constraints = resolvedConstraints,
            policySnapshot = policySnapshot,
            startMs = startMs,
            updatedAtMs = updatedAtMs
        )
        val finalized = finalizedWithRoleTrace.withExecutionReceipt(receipt)
        appendExecutionLedgerRecord(
            userId = request.userId,
            request = request,
            response = finalized,
            policySnapshot = policySnapshot,
            updatedAtMs = updatedAtMs
        )
        recordExternalFulfillmentTelemetry(finalized)
        rememberModuleSnapshot(
            userId = request.userId,
            module = module,
            response = finalized
        )
        return finalized
    }

    private fun evaluateStrictGates(
        request: AgentRequest,
        response: AgentResponse,
        module: ModuleId,
        meta: OrchestrationMeta,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext,
        evidence: List<EvidenceItemPayload>
    ): List<GateDecision> {
        val now = nowMs()
        val rolePolicy = roleContext.rolePolicyProfile
        val budgetAmount = parseBudgetAmount(constraints.budget.orEmpty())
        val highRisk = isHighRiskRequest(request.rawText, module)
        val skipConstraintPackage = module == ModuleId.LIX && (
            isLixReviewCommand(request.rawText) ||
                response.status == ResponseStatus.COMMITTED ||
                response.status == ResponseStatus.DISPUTED ||
                response.status == ResponseStatus.ROLLED_BACK
            )
        val requiresLixConstraintPackage = !skipConstraintPackage && requiresLixConstraintPackage(
            module = module,
            rawText = request.rawText,
            summary = response.summary,
            userId = request.userId
        )
        val missingConstraintFields = if (requiresLixConstraintPackage) {
            missingRequiredConstraintFields(constraints)
        } else {
            emptyList()
        }
        val gateR1 = GateDecision(
            gate = GateType.GATE_R1_REQUIRE_CONSTRAINTS,
            decision = when {
                !requiresLixConstraintPackage -> GateDecisionStatus.PASSED
                missingConstraintFields.isEmpty() -> GateDecisionStatus.PASSED
                else -> GateDecisionStatus.WAITING_USER
            },
            reason = if (!requiresLixConstraintPackage) {
                "constraints_not_required_for_current_path"
            } else if (missingConstraintFields.isEmpty()) {
                "constraints_complete"
            } else {
                "missing_fields:${missingConstraintFields.joinToString(",")}"
            },
            nextAction = if (requiresLixConstraintPackage && missingConstraintFields.isNotEmpty()) {
                "Provide ${missingConstraintFields.joinToString(", ")}."
            } else {
                null
            },
            ownerAgent = AgentRole.REQUIREMENT_CLARIFIER,
            phase = AgentPhase.CLARIFY,
            timestampMs = now
        )

        val baseRequiresConfirmationToken = requiresExternalSpendGate(
            module = module,
            rawText = request.rawText,
            response = response,
            userId = request.userId
        )
        val autoApprovalBudgetLimit = rolePolicy.approvalPolicy.autoApprovalBudgetLimit
            ?.takeIf { it > 0.0 }
        val roleAllowsAutoApproval = baseRequiresConfirmationToken &&
            rolePolicy.approvalPolicy.delegationMode == DelegationMode.AUTONOMOUS_WITHIN_POLICY &&
            !highRisk &&
            autoApprovalBudgetLimit != null &&
            budgetAmount != null &&
            budgetAmount in 0.0..autoApprovalBudgetLimit
        val requiresConfirmationToken = baseRequiresConfirmationToken &&
            rolePolicy.approvalPolicy.requiresConfirmationTokenForExternalSpend &&
            !roleAllowsAutoApproval
        val gateR2 = GateDecision(
            gate = GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN,
            decision = when {
                !requiresConfirmationToken -> GateDecisionStatus.PASSED
                constraints.userConfirmationToken.isNullOrBlank() -> GateDecisionStatus.WAITING_USER
                else -> GateDecisionStatus.PASSED
            },
            reason = if (!baseRequiresConfirmationToken) {
                "no_external_spend_action_detected"
            } else if (roleAllowsAutoApproval) {
                "role_policy_auto_approved_within_budget"
            } else if (constraints.userConfirmationToken.isNullOrBlank()) {
                "missing_user_confirmation_token"
            } else {
                "confirmation_token_verified"
            },
            nextAction = if (requiresConfirmationToken && constraints.userConfirmationToken.isNullOrBlank()) {
                "Provide confirmation token to authorize external spend."
            } else {
                null
            },
            ownerAgent = AgentRole.BUDGET_GATEKEEPER,
            phase = AgentPhase.ESCALATE,
            timestampMs = now
        )

        val roleBudgetLimit = rolePolicy.approvalPolicy.maxExternalBudget
            ?.takeIf { it > 0.0 }
            ?: MAX_ESCALATION_BUDGET
        val effectiveBudgetLimit = minOf(MAX_ESCALATION_BUDGET, roleBudgetLimit)
        val gateR3 = GateDecision(
            gate = GateType.GATE_R3_BUDGET_SCOPE_GUARD,
            decision = when {
                !requiresLixConstraintPackage -> GateDecisionStatus.PASSED
                constraints.budget.isNullOrBlank() -> GateDecisionStatus.WAITING_USER
                budgetAmount == null -> GateDecisionStatus.WAITING_USER
                budgetAmount <= 0.0 -> GateDecisionStatus.BLOCKED
                budgetAmount > effectiveBudgetLimit -> GateDecisionStatus.BLOCKED
                else -> GateDecisionStatus.PASSED
            },
            reason = when {
                !requiresLixConstraintPackage -> "budget_gate_not_required"
                constraints.budget.isNullOrBlank() -> "budget_missing"
                budgetAmount == null -> "budget_unparseable"
                budgetAmount <= 0.0 -> "budget_invalid_non_positive"
                budgetAmount > effectiveBudgetLimit -> "budget_exceeds_role_limit"
                else -> "budget_within_scope"
            },
            nextAction = when {
                !requiresLixConstraintPackage -> null
                constraints.budget.isNullOrBlank() || budgetAmount == null ->
                    "Provide a numeric budget to continue."
                budgetAmount <= 0.0 ->
                    "Provide a positive budget value."
                budgetAmount > effectiveBudgetLimit ->
                    "Reduce budget below ${effectiveBudgetLimit.toInt()} and retry."
                else -> null
            },
            ownerAgent = AgentRole.BUDGET_GATEKEEPER,
            phase = AgentPhase.ESCALATE,
            timestampMs = now
        )

        val requiresEvidence = requiresEvidenceForSuccess(module, meta, response)
        val gateR4 = GateDecision(
            gate = GateType.GATE_R4_EVIDENCE_REQUIRED_FOR_SUCCESS,
            decision = when {
                !requiresEvidence || !isSuccessLike(response.status) -> GateDecisionStatus.PASSED
                evidence.isNotEmpty() -> GateDecisionStatus.PASSED
                else -> GateDecisionStatus.BLOCKED
            },
            reason = when {
                !requiresEvidence -> "evidence_optional_for_path"
                !isSuccessLike(response.status) -> "non_success_state"
                evidence.isNotEmpty() -> "evidence_attached"
                else -> "success_without_evidence"
            },
            nextAction = if (requiresEvidence && isSuccessLike(response.status) && evidence.isEmpty()) {
                "Attach verifiable evidence before marking success."
            } else {
                null
            },
            ownerAgent = AgentRole.SOLUTION_VALIDATION_AGENT,
            phase = AgentPhase.VERIFY,
            timestampMs = now
        )

        val supplierValidationRequired = requiresSupplierValidation(module, response)
        val supplierValidationPassed = evidence.isNotEmpty() && verifySolutionAgainstTwin(
            userId = request.userId,
            resultSummary = response.summary.orEmpty(),
            evidence = evidence
        )
        val gateR5 = GateDecision(
            gate = GateType.GATE_R5_SUPPLIER_VALIDATION_REQUIRED,
            decision = when {
                !supplierValidationRequired -> GateDecisionStatus.PASSED
                supplierValidationPassed -> GateDecisionStatus.PASSED
                isSuccessLike(response.status) -> GateDecisionStatus.BLOCKED
                else -> GateDecisionStatus.WAITING_USER
            },
            reason = when {
                !supplierValidationRequired -> "supplier_validation_not_required"
                supplierValidationPassed -> "supplier_solution_validated"
                isSuccessLike(response.status) -> "supplier_solution_unvalidated"
                else -> "awaiting_supplier_validation"
            },
            nextAction = if (supplierValidationRequired && !supplierValidationPassed) {
                "Run supplier validation or negotiation loop before delivery."
            } else {
                null
            },
            ownerAgent = AgentRole.SOLUTION_VALIDATION_AGENT,
            phase = AgentPhase.FINAL_GATE,
            timestampMs = now
        )

        val nonEmptyReturn = isNonEmptyReturn(response)
        val gateR6 = GateDecision(
            gate = GateType.GATE_R6_NO_EMPTY_RETURN,
            decision = if (nonEmptyReturn) GateDecisionStatus.PASSED else GateDecisionStatus.BLOCKED,
            reason = if (nonEmptyReturn) "response_contains_content" else "empty_response_blocked",
            nextAction = if (nonEmptyReturn) null else "Return reason and next action to user.",
            ownerAgent = AgentRole.CODEX_TEAM_LEADER,
            phase = AgentPhase.DELIVER,
            timestampMs = now
        )

        val irreversibleRequested = hasIrreversibleExecutionIntent(request.rawText, response.summary)
        val gateR7 = GateDecision(
            gate = GateType.GATE_R7_HIGH_RISK_EXECUTION_PROHIBITED,
            decision = when {
                !highRisk -> GateDecisionStatus.PASSED
                !irreversibleRequested -> GateDecisionStatus.PASSED
                else -> GateDecisionStatus.BLOCKED
            },
            reason = when {
                !highRisk -> "not_high_risk_domain"
                !irreversibleRequested -> "decision_support_only_path"
                else -> "high_risk_execution_blocked"
            },
            nextAction = if (highRisk && irreversibleRequested) {
                "High-risk domains are decision-support only. Provide reversible goals and evidence constraints."
            } else {
                null
            },
            ownerAgent = AgentRole.COMPLIANCE_GUARD,
            phase = AgentPhase.VERIFY,
            timestampMs = now
        )

        val authenticity = evaluateAuthenticity(
            request = request,
            response = response,
            module = module,
            meta = meta,
            constraints = constraints,
            evidence = evidence
        )
        val gateR8 = GateDecision(
            gate = GateType.GATE_R8_DATA_AUTHENTICITY_REQUIRED,
            decision = when {
                !authenticity.required -> GateDecisionStatus.PASSED
                authenticity.passed -> GateDecisionStatus.PASSED
                response.status == ResponseStatus.SUCCESS -> GateDecisionStatus.BLOCKED
                else -> GateDecisionStatus.WAITING_USER
            },
            reason = authenticity.reason,
            nextAction = authenticity.nextAction,
            ownerAgent = AgentRole.OUTCOME_AUDITOR,
            phase = AgentPhase.FINAL_GATE,
            timestampMs = now
        )

        return listOf(gateR1, gateR2, gateR3, gateR4, gateR5, gateR6, gateR7, gateR8)
    }

    private fun buildProblemFrame(
        request: AgentRequest,
        module: ModuleId,
        meta: OrchestrationMeta,
        constraints: AgentRequestConstraints
    ): ProblemFramePayload {
        val raw = request.rawText.lowercase()
        val domainScores = computeDomainScores(raw = raw, module = module, meta = meta)
            .sortedByDescending { it.score }
            .take(3)
        val primaryDomain = domainScores.firstOrNull()?.domain ?: "general"
        val secondaryDomains = domainScores.drop(1).map { it.domain }
        val requiresLiveData = raw.contains("latest") ||
            raw.contains("实时") ||
            raw.contains("today") ||
            raw.contains("near me") ||
            meta.taskGraph.tasks.any { task ->
                task.requiredCapabilities.any { capability ->
                    capability.contains("live") ||
                        capability.contains("flight") ||
                        capability.contains("hotel") ||
                        capability.contains("search")
                }
            }
        val riskClass = when {
            isHighRiskDomain(primaryDomain) -> "high"
            meta.routingDecision.mode == RoutingMode.MULTI_AGENT -> "medium"
            else -> "low"
        }
        val requiresEscalationConstraints = requiresLixConstraintPackage(
            module = module,
            rawText = request.rawText,
            summary = null,
            userId = request.userId
        )
        return ProblemFramePayload(
            problemType = detectProblemType(raw = raw, module = module),
            primaryDomain = primaryDomain,
            secondaryDomains = secondaryDomains,
            domainScores = domainScores,
            riskClass = riskClass,
            requiresLiveData = requiresLiveData,
            constraintCompleteness = computeConstraintCompleteness(
                constraints = constraints,
                requiresLixConstraintPackage = requiresEscalationConstraints
            )
        )
    }

    private fun buildClarificationQuestions(
        request: AgentRequest,
        gateDecisions: List<GateDecision>,
        problemFrame: ProblemFramePayload
    ): List<ClarificationQuestionPayload> {
        val blockingGate = gateDecisions.firstOrNull { it.decision != GateDecisionStatus.PASSED } ?: return emptyList()
        val commonReason = "This clarification is required to keep execution bounded, verifiable, and non-empty."
        return when (blockingGate.gate) {
            GateType.GATE_R1_REQUIRE_CONSTRAINTS -> {
                val missingField = extractFirstMissingConstraint(blockingGate.reason)
                    ?: "task_detail"
                listOf(
                    ClarificationQuestionPayload(
                        id = "clarify_$missingField",
                        prompt = promptForMissingField(missingField, request.rawText),
                        reason = commonReason,
                        impactsGate = GateType.GATE_R1_REQUIRE_CONSTRAINTS,
                        options = optionsForMissingField(missingField)
                    )
                )
            }
            GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN -> {
                listOf(
                    ClarificationQuestionPayload(
                        id = "clarify_confirmation_token",
                        prompt = "Please provide a confirmation token for this external spend action.",
                        reason = "Per-action confirmation is required before external spending or contracting.",
                        impactsGate = GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN,
                        options = listOf(
                            ClarificationOptionPayload("confirm_now", "Provide token now", "CONFIRM-XXXX"),
                            ClarificationOptionPayload("cancel_action", "Cancel external action", "cancel")
                        )
                    )
                )
            }
            GateType.GATE_R3_BUDGET_SCOPE_GUARD -> {
                listOf(
                    ClarificationQuestionPayload(
                        id = "clarify_budget_scope",
                        prompt = "What numeric budget should we use for this task?",
                        reason = "Budget must be parseable and within scope before escalation.",
                        impactsGate = GateType.GATE_R3_BUDGET_SCOPE_GUARD,
                        options = optionsForMissingField("budget")
                    )
                )
            }
            GateType.GATE_R7_HIGH_RISK_EXECUTION_PROHIBITED -> {
                listOf(
                    ClarificationQuestionPayload(
                        id = "clarify_high_risk_boundary",
                        prompt = "This is a high-risk domain. Please confirm a decision-support-only objective.",
                        reason = "High-risk domains only support reversible planning and evidence-backed guidance.",
                        impactsGate = GateType.GATE_R7_HIGH_RISK_EXECUTION_PROHIBITED,
                        options = listOf(
                            ClarificationOptionPayload("support_only", "Decision support plan", "support_only"),
                            ClarificationOptionPayload("cancel", "Cancel request", "cancel")
                        )
                    )
                )
            }
            GateType.GATE_R8_DATA_AUTHENTICITY_REQUIRED -> {
                listOf(
                    ClarificationQuestionPayload(
                        id = "clarify_data_authenticity",
                        prompt = "Please allow a re-run with live-source verification so every claim has a real, clickable source.",
                        reason = "Final delivery requires authentic, verifiable data and non-fabricated links.",
                        impactsGate = GateType.GATE_R8_DATA_AUTHENTICITY_REQUIRED,
                        options = listOf(
                            ClarificationOptionPayload("rerun_live", "Re-run with live sources", "rerun_live"),
                            ClarificationOptionPayload("tighten_scope", "Tighten scope", "tighten_scope"),
                            ClarificationOptionPayload("cancel", "Cancel", "cancel")
                        )
                    )
                )
            }
            else -> {
                if (problemFrame.constraintCompleteness < 1.0) {
                    listOf(
                        ClarificationQuestionPayload(
                            id = "clarify_general_constraints",
                            prompt = "Please provide one missing task detail so we can continue accurately.",
                            reason = commonReason,
                            impactsGate = GateType.GATE_R1_REQUIRE_CONSTRAINTS,
                            options = listOf(
                                ClarificationOptionPayload("date_or_time", "Date or time window", "date"),
                                ClarificationOptionPayload("location_or_scope", "Location or scope", "location"),
                                ClarificationOptionPayload("success_criteria", "Success criteria", "acceptance_criteria")
                            )
                        )
                    )
                } else {
                    emptyList()
                }
            }
        }
    }

    private fun buildEvidenceClaims(
        summary: String,
        evidence: List<EvidenceItemPayload>
    ): List<EvidenceClaimPayload> {
        if (evidence.isNotEmpty()) {
            return evidence.take(3).mapIndexed { index, item ->
                val evidenceId = "ev_${index + 1}"
                EvidenceClaimPayload(
                    claimId = "claim_${index + 1}",
                    claimText = item.title.ifBlank { "Evidence provided by ${item.source}" },
                    evidenceIds = listOf(evidenceId),
                    confidence = if (!item.url.isNullOrBlank()) 0.78 else 0.62,
                    reproducibleSteps = listOf(
                        "Open the referenced source and verify the claim context.",
                        "Compare claim details with task constraints and acceptance criteria."
                    )
                )
            }
        }
        if (summary.isBlank()) return emptyList()
        return listOf(
            EvidenceClaimPayload(
                claimId = "claim_summary_only",
                claimText = summary.take(180),
                evidenceIds = emptyList(),
                confidence = 0.25,
                reproducibleSteps = listOf("Request external evidence before marking this as final.")
            )
        )
    }

    private fun buildRiskBoundary(problemFrame: ProblemFramePayload): RiskBoundaryPayload {
        val highRisk = isHighRiskDomain(problemFrame.primaryDomain)
        return RiskBoundaryPayload(
            domain = problemFrame.primaryDomain,
            policy = if (highRisk) "decision_support_only" else "bounded_execution",
            blockedActions = if (highRisk) {
                listOf(
                    "auto_execute_high_risk_decision",
                    "auto_purchase_or_contract_without_confirmation",
                    "irreversible_medical_legal_financial_action"
                )
            } else {
                listOf("unconfirmed_external_spend")
            }
        )
    }

    private fun computeDomainScores(
        raw: String,
        module: ModuleId,
        meta: OrchestrationMeta
    ): List<DomainScorePayload> {
        val scores = linkedMapOf(
            "travel" to 0.0,
            "recruitment" to 0.0,
            "finance" to 0.0,
            "health" to 0.0,
            "legal" to 0.0,
            "education" to 0.0,
            "productivity" to 0.0,
            "local_service" to 0.0,
            "general" to 0.1
        )
        val keywordBoosts = listOf(
            Triple("travel", Regex("(flight|hotel|trip|travel|机票|酒店|行程|旅行|holiday|vacation)"), 0.65),
            Triple("recruitment", Regex("(hire|hiring|recruit|resume|cv|招聘|岗位|面试|简历)"), 0.65),
            Triple("finance", Regex("(stock|fund|investment|finance|税|汇率|理财|股票|基金|金融)"), 0.7),
            Triple("health", Regex("(health|medical|symptom|prescription|诊断|症状|医疗|用药|健康)"), 0.7),
            Triple("legal", Regex("(legal|law|contract|clause|仲裁|诉讼|合同|法务|法律)"), 0.7),
            Triple("education", Regex("(course|study|exam|education|学习|课程|备考|教育|考试)"), 0.6),
            Triple("productivity", Regex("(todo|schedule|project|productivity|待办|排期|日程|效率|计划)"), 0.58),
            Triple("local_service", Regex("(nearby|local|delivery|restaurant|附近|本地|外卖|商家|店铺|家政)"), 0.58)
        )
        keywordBoosts.forEach { (domain, pattern, boost) ->
            if (pattern.containsMatchIn(raw)) {
                scores[domain] = (scores[domain] ?: 0.0) + boost
            }
        }
        meta.taskGraph.tasks.flatMap { it.requiredCapabilities }.forEach { cap ->
            when {
                cap.contains("flight") || cap.contains("hotel") || cap.contains("itinerary") || cap.contains("transport") ->
                    scores["travel"] = (scores["travel"] ?: 0.0) + 0.22
                cap.contains("salary") || cap.contains("job") || cap.contains("resume") ->
                    scores["recruitment"] = (scores["recruitment"] ?: 0.0) + 0.22
                cap.contains("finance") || cap.contains("tax") ->
                    scores["finance"] = (scores["finance"] ?: 0.0) + 0.22
                cap.contains("health") || cap.contains("medical") ->
                    scores["health"] = (scores["health"] ?: 0.0) + 0.22
                cap.contains("legal") || cap.contains("contract") ->
                    scores["legal"] = (scores["legal"] ?: 0.0) + 0.22
                cap.contains("course") || cap.contains("study") ->
                    scores["education"] = (scores["education"] ?: 0.0) + 0.22
                cap.contains("task") || cap.contains("time_blocking") || cap.contains("reminder") ->
                    scores["productivity"] = (scores["productivity"] ?: 0.0) + 0.22
                cap.contains("local") || cap.contains("restaurant") ->
                    scores["local_service"] = (scores["local_service"] ?: 0.0) + 0.2
            }
        }
        when (module) {
            ModuleId.LIX -> scores["local_service"] = (scores["local_service"] ?: 0.0) + 0.18
            ModuleId.DESTINY -> scores["productivity"] = (scores["productivity"] ?: 0.0) + 0.15
            ModuleId.AGENT_MARKET -> scores["general"] = (scores["general"] ?: 0.0) + 0.12
            else -> Unit
        }
        return scores.entries.map { (domain, score) ->
            DomainScorePayload(domain = domain, score = score.coerceIn(0.0, 1.0))
        }
    }

    private fun detectProblemType(raw: String, module: ModuleId): String {
        return when {
            raw.contains("plan") || raw.contains("规划") || raw.contains("方案") -> "planning"
            raw.contains("analy") || raw.contains("review") || raw.contains("审查") || raw.contains("分析") -> "analysis"
            raw.contains("compare") || raw.contains("比价") || raw.contains("对比") -> "comparison"
            raw.contains("execute") || raw.contains("publish") || raw.contains("下单") || raw.contains("采购") -> "execution"
            module == ModuleId.CHAT -> "qa"
            else -> "general"
        }
    }

    private fun computeConstraintCompleteness(
        constraints: AgentRequestConstraints,
        requiresLixConstraintPackage: Boolean
    ): Double {
        if (!requiresLixConstraintPackage) return 1.0
        val total = 3.0
        var present = 0.0
        if (!constraints.budget.isNullOrBlank()) present += 1
        if (!constraints.deadline.isNullOrBlank()) present += 1
        if (!constraints.acceptanceCriteria.isNullOrBlank()) present += 1
        return (present / total).coerceIn(0.0, 1.0)
    }

    private fun extractFirstMissingConstraint(reason: String): String? {
        return extractMissingConstraintFields(reason).firstOrNull()
    }

    private fun extractMissingConstraintFields(reason: String): List<String> {
        val marker = "missing_fields:"
        val index = reason.indexOf(marker)
        if (index < 0) return emptyList()
        return reason.substring(index + marker.length)
            .split(",")
            .map { it.trim() }
            .filter { it.isNotBlank() }
    }

    private fun promptForMissingField(field: String, rawText: String): String {
        return when (field) {
            "budget" -> "What is your total budget for this request?"
            "deadline" -> "What is the deadline or latest completion date?"
            "acceptance_criteria" -> "How should we verify success for this request?"
            "出发日期", "travel_date", "date" -> "What date or time window should we use?"
            "origin_and_destination", "route", "location", "具体位置" -> "Which origin/destination or location should we use?"
            "乘客人数", "traveler_count", "people" -> "How many people should this plan cover?"
            "舱位偏好（经济/商务）", "cabin_preference" -> "Which cabin or comfort level do you prefer?"
            else -> "Please provide the missing detail: $field."
        } + if (rawText.isNotBlank()) " Current request: ${rawText.take(80)}" else ""
    }

    private fun optionsForMissingField(field: String): List<ClarificationOptionPayload> {
        return when (field) {
            "budget" -> listOf(
                ClarificationOptionPayload("budget_low", "Low", "1000"),
                ClarificationOptionPayload("budget_mid", "Medium", "5000"),
                ClarificationOptionPayload("budget_high", "High", "20000")
            )
            "deadline" -> listOf(
                ClarificationOptionPayload("deadline_3d", "3 days", "3 days"),
                ClarificationOptionPayload("deadline_7d", "7 days", "7 days"),
                ClarificationOptionPayload("deadline_30d", "30 days", "30 days")
            )
            "acceptance_criteria" -> listOf(
                ClarificationOptionPayload("accept_evidence", "Evidence-backed", "evidence-backed deliverable"),
                ClarificationOptionPayload("accept_bookable", "Bookable output", "bookable and executable options"),
                ClarificationOptionPayload("accept_risk", "Risk notes", "include risk and rollback notes")
            )
            "date", "travel_date", "出发日期" -> listOf(
                ClarificationOptionPayload("today", "Today", "today"),
                ClarificationOptionPayload("tomorrow", "Tomorrow", "tomorrow"),
                ClarificationOptionPayload("next_week", "Next week", "next week")
            )
            "location", "origin_and_destination", "route", "具体位置" -> listOf(
                ClarificationOptionPayload("set_route", "Set route", "origin -> destination"),
                ClarificationOptionPayload("set_location", "Set location", "city/location"),
                ClarificationOptionPayload("keep_current", "Use current context", "use current context")
            )
            else -> listOf(
                ClarificationOptionPayload("provide_value", "Provide value", field)
            )
        }
    }

    private fun isHighRiskDomain(domain: String): Boolean {
        val normalized = domain.trim().lowercase()
        return normalized == "health" || normalized == "legal" || normalized == "finance"
    }

    private fun isHighRiskRequest(rawText: String, module: ModuleId): Boolean {
        val raw = rawText.lowercase()
        if (module == ModuleId.DESTINY && raw.contains("investment")) return true
        return Regex("(health|medical|prescription|diagnosis|legal|law|contract|litigation|finance|investment|stock|tax|医疗|法律|合同|诉讼|金融|投资|股票|税)").containsMatchIn(raw)
    }

    private fun hasIrreversibleExecutionIntent(rawText: String, summary: String?): Boolean {
        val content = "${rawText.lowercase()} ${(summary ?: "").lowercase()}"
        return Regex("(sign|execute now|auto execute|purchase|procure|transfer funds|prescribe|diagnose|裁决|签约|下单|采购|转账|处方|自动执行)").containsMatchIn(content)
    }

    private fun evaluateAuthenticity(
        request: AgentRequest,
        response: AgentResponse,
        module: ModuleId,
        meta: OrchestrationMeta,
        constraints: AgentRequestConstraints,
        evidence: List<EvidenceItemPayload>
    ): AuthenticityAssessment {
        val problemFrame = buildProblemFrame(
            request = request,
            module = module,
            meta = meta,
            constraints = constraints
        )
        val requiredLinkKinds = requiredLinkKindsForDomain(problemFrame)
        val allSummaryUrls = Regex("""https?://[^\s)\]]+""")
            .findAll(response.summary.orEmpty())
            .map { it.value }
            .toList()
        val verifiedSummaryUrls = allSummaryUrls
            .mapNotNull(::verifiedExternalUrlOrNull)
            .toSet()
        val unverifiedSummaryUrls = allSummaryUrls.filter { candidate ->
            verifiedExternalUrlOrNull(candidate) == null
        }
        val verifiedEvidenceLinks = evidence
            .mapNotNull { item ->
                val url = item.url?.takeIf { it.isNotBlank() } ?: return@mapNotNull null
                val verified = verifiedExternalUrlOrNull(url) ?: return@mapNotNull null
                if (isSyntheticEvidenceSource(item.source)) return@mapNotNull null
                verified
            }
            .toSet()
        val verifiedLinks = collectVerifiedLinkEntries(
            summary = response.summary.orEmpty(),
            evidence = evidence
        )
        val providedKinds = collectProvidedLinkKinds(verifiedLinks)
        val missingKinds = requiredLinkKinds.filterNot { providedKinds.contains(it) }
        val combinedText = buildString {
            append(response.summary.orEmpty())
            append('\n')
            append(evidence.joinToString("\n") { "${it.title} ${it.snippet.orEmpty()} ${it.source}" })
        }.lowercase()
        val hasSyntheticMarkers = SYNTHETIC_MARKER_REGEX.containsMatchIn(combinedText)
        val requiresLiveProof = problemFrame.requiresLiveData || requiredLinkKinds.isNotEmpty()
        val hasCredibleVerifiedLinks = verifiedEvidenceLinks.isNotEmpty() || verifiedSummaryUrls.isNotEmpty()
        val required = response.status == ResponseStatus.SUCCESS ||
            requiresLiveProof ||
            requiresEvidenceForSuccess(module, meta, response)
        val passed = !hasSyntheticMarkers &&
            (unverifiedSummaryUrls.isEmpty()) &&
            (!requiresLiveProof || (hasCredibleVerifiedLinks && missingKinds.isEmpty()))
        val reason = when {
            !required -> "authenticity_gate_not_required"
            hasSyntheticMarkers -> "synthetic_or_placeholder_content_detected"
            unverifiedSummaryUrls.isNotEmpty() -> "unverified_links_detected"
            requiresLiveProof && !hasCredibleVerifiedLinks -> "missing_verified_live_sources"
            missingKinds.isNotEmpty() -> "missing_required_link_categories:${missingKinds.joinToString(",")}"
            else -> "authenticity_verified"
        }
        val nextAction = if (passed || !required) {
            null
        } else {
            when {
                hasSyntheticMarkers -> "Replace placeholder or simulated content with verified links from live, trusted sources."
                unverifiedSummaryUrls.isNotEmpty() -> "Remove unverified links and provide trusted public URLs."
                missingKinds.isNotEmpty() ->
                    "Provide verified links for ${missingKinds.joinToString(", ") { it.replace('_', ' ') }}."
                else -> "Re-run retrieval with trustworthy live sources and attach evidence URLs."
            }
        }
        return AuthenticityAssessment(
            required = required,
            passed = passed,
            reason = reason,
            nextAction = nextAction
        )
    }

    private fun isSyntheticEvidenceSource(source: String): Boolean {
        val normalized = source.trim().lowercase()
        if (normalized.isBlank()) return true
        return normalized.contains("template") ||
            normalized.contains("mock") ||
            normalized.contains("dummy") ||
            normalized.contains("synthetic") ||
            normalized.contains("simulated")
    }

    private fun resolvePhase(
        module: ModuleId,
        status: ResponseStatus,
        gateDecisions: List<GateDecision>,
        response: AgentResponse
    ): AgentPhase {
        if (gateDecisions.any { it.gate == GateType.GATE_R1_REQUIRE_CONSTRAINTS && it.decision != GateDecisionStatus.PASSED }) {
            return AgentPhase.CLARIFY
        }
        if (
            gateDecisions.any {
                (it.gate == GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN || it.gate == GateType.GATE_R3_BUDGET_SCOPE_GUARD) &&
                    it.decision != GateDecisionStatus.PASSED
            }
        ) {
            return AgentPhase.ESCALATE
        }
        if (
            gateDecisions.any {
                (
                    it.gate == GateType.GATE_R4_EVIDENCE_REQUIRED_FOR_SUCCESS ||
                        it.gate == GateType.GATE_R7_HIGH_RISK_EXECUTION_PROHIBITED ||
                        it.gate == GateType.GATE_R8_DATA_AUTHENTICITY_REQUIRED
                    ) &&
                    it.decision != GateDecisionStatus.PASSED
            }
        ) {
            return AgentPhase.VERIFY
        }
        val taskPhase = (response.payload as? ModulePayload.ChatPayload)?.taskTrack?.phase?.lowercase().orEmpty()
        if (status == ResponseStatus.WAITING_USER || status == ResponseStatus.AUTH_REQUIRED) {
            return when {
                taskPhase.contains("lix") ||
                    taskPhase.contains("escalat") ||
                    taskPhase.contains("negotiat") -> AgentPhase.ESCALATE
                taskPhase.contains("verify") ||
                    taskPhase.contains("validation") -> AgentPhase.VERIFY
                taskPhase.contains("deliver") ||
                    taskPhase.contains("final") -> AgentPhase.FINAL_GATE
                taskPhase.contains("execute") ||
                    taskPhase.contains("cloud") ||
                    taskPhase.contains("agent") -> AgentPhase.EXECUTE
                else -> AgentPhase.EXECUTE
            }
        }
        return when (status) {
            ResponseStatus.PROCESSING,
            ResponseStatus.RUNNING,
            ResponseStatus.QUOTING -> AgentPhase.EXECUTE
            ResponseStatus.WAITING_USER,
            ResponseStatus.AUTH_REQUIRED -> AgentPhase.EXECUTE
            ResponseStatus.VERIFYING -> AgentPhase.VERIFY
            ResponseStatus.COMMITTED -> if (module == ModuleId.LIX) AgentPhase.FINAL_GATE else AgentPhase.DELIVER
            ResponseStatus.SUCCESS -> if (module == ModuleId.LIX) AgentPhase.FINAL_GATE else AgentPhase.DELIVER
            ResponseStatus.PARTIAL -> AgentPhase.VERIFY
            ResponseStatus.ROLLED_BACK,
            ResponseStatus.DISPUTED,
            ResponseStatus.CANCELLED,
            ResponseStatus.ERROR -> AgentPhase.VERIFY
        }
    }

    private fun resolveOwnerAgent(
        phase: AgentPhase,
        gateDecisions: List<GateDecision>
    ): AgentRole {
        val unresolved = gateDecisions.firstOrNull { it.decision != GateDecisionStatus.PASSED }
        if (unresolved != null) return unresolved.ownerAgent
        return when (phase) {
            AgentPhase.INTAKE -> AgentRole.EDGE_DIGITAL_TWIN_BUILDER
            AgentPhase.CLARIFY -> AgentRole.REQUIREMENT_CLARIFIER
            AgentPhase.PLAN -> AgentRole.TASK_PLANNER
            AgentPhase.EXECUTE -> AgentRole.OPENCLAW_ORCHESTRATOR
            AgentPhase.VERIFY -> AgentRole.SOLUTION_VALIDATION_AGENT
            AgentPhase.ESCALATE -> AgentRole.LIX_DEMAND_PUBLISHER
            AgentPhase.FINAL_GATE -> AgentRole.DELIVERY_QUALITY_GUARD
            AgentPhase.DELIVER -> AgentRole.CODEX_TEAM_LEADER
        }
    }

    private fun buildValidationReport(
        response: AgentResponse,
        evidence: List<EvidenceItemPayload>,
        gateDecisions: List<GateDecision>,
        phase: AgentPhase,
        status: ResponseStatus,
        returnContractAudit: ReturnContractAudit
    ): ValidationReport {
        val gateIssues = gateDecisions
            .filter { it.decision != GateDecisionStatus.PASSED }
            .map { "${it.gate.name.lowercase()}: ${it.reason}" }
        val returnIssues = if (returnContractAudit.missingRequiredLinkKinds.isEmpty()) {
            emptyList()
        } else {
            listOf(
                "return_contract_missing_links:${
                    returnContractAudit.missingRequiredLinkKinds.joinToString(",")
                }"
            )
        }
        val issues = gateIssues + returnIssues
        val validatorAgent = if (phase == AgentPhase.FINAL_GATE || phase == AgentPhase.DELIVER) {
            AgentRole.OUTCOME_AUDITOR
        } else {
            AgentRole.SOLUTION_VALIDATION_AGENT
        }
        val validationPhase = if (validatorAgent == AgentRole.OUTCOME_AUDITOR) {
            AgentPhase.FINAL_GATE
        } else if (phase == AgentPhase.DELIVER) {
            AgentPhase.VERIFY
        } else {
            phase
        }
        val passed = issues.isEmpty() && !(status == ResponseStatus.SUCCESS && returnContractAudit.shouldRequestRework)
        return ValidationReport(
            traceId = response.traceId,
            validatorAgent = validatorAgent,
            phase = validationPhase,
            passed = passed,
            confidence = (if (passed) response.confidence else response.confidence - 0.18).coerceIn(0.0, 1.0),
            issues = issues,
            evidence = evidence.take(6)
        )
    }

    private fun buildFinalDeliveryPacket(
        response: AgentResponse,
        status: ResponseStatus,
        evidence: List<EvidenceItemPayload>,
        gateDecisions: List<GateDecision>,
        returnContractAudit: ReturnContractAudit
    ): FinalDeliveryPacket? {
        val hasBlockingGate = gateDecisions.any { it.decision != GateDecisionStatus.PASSED }
        if (status != ResponseStatus.SUCCESS || hasBlockingGate || returnContractAudit.shouldRequestRework) return null
        val steps = extractExecutableSteps(response)
        val linkCoverageNote = if (returnContractAudit.requiredLinkKinds.isEmpty()) {
            "Link contract not required for current domain."
        } else {
            "Link contract: ${returnContractAudit.providedLinkKinds.size}/${returnContractAudit.requiredLinkKinds.size} required link groups satisfied."
        }
        return FinalDeliveryPacket(
            traceId = response.traceId,
            ownerAgent = AgentRole.CODEX_TEAM_LEADER,
            phase = AgentPhase.DELIVER,
            summary = response.summary.orEmpty(),
            executableSteps = steps,
            riskNotes = listOf(
                "Validate external dependencies before irreversible actions.",
                linkCoverageNote
            ),
            rollbackPlan = listOf("Re-run with tighter constraints if evidence changes."),
            evidenceSummary = evidence.map { it.title.ifBlank { it.source } }.take(6)
        )
    }

    private fun buildHandoffPackets(
        response: AgentResponse,
        module: ModuleId,
        meta: OrchestrationMeta,
        phase: AgentPhase,
        status: ResponseStatus,
        gateDecisions: List<GateDecision>,
        problemFrame: ProblemFramePayload,
        evidence: List<EvidenceItemPayload>,
        returnContractAudit: ReturnContractAudit
    ): List<HandoffPacket> {
        val packets = mutableListOf<HandoffPacket>()
        val traceId = response.traceId
        val gateR1 = gateDecisions.firstOrNull { it.gate == GateType.GATE_R1_REQUIRE_CONSTRAINTS }
        val missingConstraints = gateR1
            ?.takeIf { it.decision != GateDecisionStatus.PASSED }
            ?.reason
            ?.let(::extractMissingConstraintFields)
            .orEmpty()
        val requiresEscalation = isEscalationPath(module, response, meta, gateDecisions)
        val linkCoverage = if (returnContractAudit.requiredLinkKinds.isEmpty()) {
            "n/a"
        } else {
            "${returnContractAudit.providedLinkKinds.size}/${returnContractAudit.requiredLinkKinds.size}"
        }

        packets += handoff(
            traceId = traceId,
            from = AgentRole.EDGE_DIGITAL_TWIN_BUILDER,
            to = AgentRole.CODEX_TEAM_LEADER,
            phase = AgentPhase.INTAKE,
            summary = "Twin context prepared for ${problemFrame.primaryDomain}; risk=${problemFrame.riskClass}; completeness=${"%.2f".format(problemFrame.constraintCompleteness)}."
        )

        packets += handoff(
            traceId = traceId,
            from = AgentRole.CODEX_TEAM_LEADER,
            to = AgentRole.REQUIREMENT_CLARIFIER,
            phase = AgentPhase.CLARIFY,
            summary = if (missingConstraints.isEmpty()) {
                "Required intake details are complete for this execution path."
            } else {
                "Missing user-provided details detected: ${missingConstraints.joinToString(", ")}."
            }
        )

        if (missingConstraints.isNotEmpty()) {
            packets += handoff(
                traceId = traceId,
                from = AgentRole.REQUIREMENT_CLARIFIER,
                to = AgentRole.CODEX_TEAM_LEADER,
                phase = AgentPhase.CLARIFY,
                summary = "Waiting user input for ${missingConstraints.joinToString(", ")} before planning."
            )
            return packets.take(24)
        }

        packets += handoff(
            traceId = traceId,
            from = AgentRole.CODEX_TEAM_LEADER,
            to = AgentRole.TASK_PLANNER,
            phase = AgentPhase.PLAN,
            summary = "Goal converted into DAG with ${meta.taskGraph.tasks.size} tasks and ${meta.taskGraph.edges.size} dependencies."
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.TASK_PLANNER,
            to = AgentRole.OPENCLAW_ORCHESTRATOR,
            phase = AgentPhase.EXECUTE,
            summary = "Execution plan approved; OpenClaw can start orchestration."
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.OPENCLAW_ORCHESTRATOR,
            to = AgentRole.SUB_AGENT_ROUTER,
            phase = AgentPhase.EXECUTE,
            summary = "Dispatch ${meta.taskGraph.tasks.size} subtasks to router with capability mapping."
        )

        if (meta.taskGraph.tasks.isNotEmpty()) {
            meta.taskGraph.tasks.take(4).forEach { task ->
                val capabilityText = task.requiredCapabilities.joinToString(", ").ifBlank { "general" }
                packets += handoff(
                    traceId = traceId,
                    from = AgentRole.SUB_AGENT_ROUTER,
                    to = AgentRole.SKILL_EXECUTION_AGENT,
                    phase = AgentPhase.EXECUTE,
                    summary = "Route ${task.id} (${task.title}) with capabilities: $capabilityText.",
                    taskId = task.id
                )
            }
        } else {
            packets += handoff(
                traceId = traceId,
                from = AgentRole.SUB_AGENT_ROUTER,
                to = AgentRole.SKILL_EXECUTION_AGENT,
                phase = AgentPhase.EXECUTE,
                summary = "No explicit DAG node; run default skill plan."
            )
        }

        packets += handoff(
            traceId = traceId,
            from = AgentRole.SKILL_EXECUTION_AGENT,
            to = AgentRole.SOLUTION_VALIDATION_AGENT,
            phase = AgentPhase.VERIFY,
            summary = "Execution returned ${evidence.size} evidence items; required-link coverage=$linkCoverage.",
            evidence = evidence.take(3)
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.SOLUTION_VALIDATION_AGENT,
            to = AgentRole.COMPLIANCE_GUARD,
            phase = AgentPhase.VERIFY,
            summary = "Validation pass complete for phase=${phase.name.lowercase()} status=${status.name.lowercase()}."
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.COMPLIANCE_GUARD,
            to = AgentRole.BUDGET_GATEKEEPER,
            phase = AgentPhase.ESCALATE,
            summary = if (requiresEscalation) {
                "Escalation path requires budget/token checks."
            } else {
                "Escalation gate checked; no external spend required in this run."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.BUDGET_GATEKEEPER,
            to = AgentRole.LIX_DEMAND_PUBLISHER,
            phase = AgentPhase.ESCALATE,
            summary = if (requiresEscalation) {
                "Budget/token cleared for market escalation."
            } else {
                "LIX publish skipped; internal solution path selected."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.LIX_DEMAND_PUBLISHER,
            to = AgentRole.SUPPLIER_SCOUT,
            phase = AgentPhase.ESCALATE,
            summary = if (requiresEscalation) {
                "Demand published with required capabilities."
            } else {
                "Supplier scout remains standby (no market broadcast)."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.SUPPLIER_SCOUT,
            to = AgentRole.SUPPLIER_NEGOTIATOR,
            phase = AgentPhase.ESCALATE,
            summary = if (requiresEscalation) {
                "Shortlisted supplier candidates and forwarded negotiation brief."
            } else {
                "Supplier negotiation skipped for this run."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.SUPPLIER_NEGOTIATOR,
            to = AgentRole.DELIVERY_QUALITY_GUARD,
            phase = AgentPhase.FINAL_GATE,
            summary = if (requiresEscalation) {
                "Negotiation outputs returned for delivery quality gate."
            } else {
                "No supplier loop output; continue with internal quality gate."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.DELIVERY_QUALITY_GUARD,
            to = AgentRole.OUTCOME_AUDITOR,
            phase = AgentPhase.FINAL_GATE,
            summary = if (returnContractAudit.shouldRequestRework) {
                "Quality guard requests independent audit with rework recommendation."
            } else {
                "Quality gate passed; start independent outcome audit."
            }
        )
        packets += handoff(
            traceId = traceId,
            from = AgentRole.OUTCOME_AUDITOR,
            to = AgentRole.CODEX_TEAM_LEADER,
            phase = AgentPhase.DELIVER,
            summary = if (returnContractAudit.shouldRequestRework) {
                "Audit failed due to missing link categories: ${returnContractAudit.missingRequiredLinkKinds.joinToString(", ")}."
            } else {
                "Audit passed; package final response for user delivery."
            },
            evidence = evidence.take(2)
        )
        return packets.take(24)
    }

    private fun buildMarketEscalationPacket(
        response: AgentResponse,
        module: ModuleId,
        meta: OrchestrationMeta,
        constraints: AgentRequestConstraints,
        phase: AgentPhase,
        gateDecisions: List<GateDecision>
    ): MarketEscalationPacket? {
        val requiresEscalation = isEscalationPath(module, response, meta, gateDecisions)
        if (!requiresEscalation && phase != AgentPhase.ESCALATE) return null
        return MarketEscalationPacket(
            traceId = response.traceId,
            demandId = "demand-${response.traceId.take(8)}",
            publisherAgent = AgentRole.LIX_DEMAND_PUBLISHER,
            phase = AgentPhase.ESCALATE,
            summary = if (requiresEscalation) {
                "Escalation prepared for LIX market execution."
            } else {
                "Escalation lane is available but currently not activated."
            },
            budget = constraints.budget,
            deadline = constraints.deadline,
            acceptanceCriteria = constraints.acceptanceCriteria,
            requiredCapabilities = meta.taskGraph.tasks
                .flatMap { it.requiredCapabilities }
                .distinct()
                .take(10)
        )
    }

    private fun isEscalationPath(
        module: ModuleId,
        response: AgentResponse,
        meta: OrchestrationMeta,
        gateDecisions: List<GateDecision>
    ): Boolean {
        val summarySignal = response.summary.orEmpty().lowercase()
        val hasEscalationGateSignal = gateDecisions.any {
            it.phase == AgentPhase.ESCALATE && it.decision != GateDecisionStatus.PASSED
        }
        return module == ModuleId.LIX ||
            hasEscalationGateSignal ||
            summarySignal.contains("supplier") ||
            summarySignal.contains("escalat") ||
            summarySignal.contains("market") ||
            meta.skillGap?.recommendedAction == SkillGapRecommendation.ADD_SKILL
    }

    private fun handoff(
        traceId: String,
        from: AgentRole,
        to: AgentRole,
        phase: AgentPhase,
        summary: String,
        taskId: String? = null,
        evidence: List<EvidenceItemPayload> = emptyList()
    ): HandoffPacket {
        return HandoffPacket(
            traceId = traceId,
            fromAgent = from,
            toAgent = to,
            phase = phase,
            summary = summary,
            taskId = taskId,
            evidence = evidence
        )
    }

    private fun enforceUserReturnContract(
        summary: String,
        nextAction: String,
        problemFrame: ProblemFramePayload,
        evidence: List<EvidenceItemPayload>
    ): ReturnContractAudit {
        val requiredLinkKinds = requiredLinkKindsForDomain(problemFrame)
        val verifiedLinks = collectVerifiedLinkEntries(summary = summary, evidence = evidence)
        val providedKinds = collectProvidedLinkKinds(verifiedLinks)
        val missingKinds = requiredLinkKinds.filterNot { providedKinds.contains(it) }
        val shouldRequestRework = problemFrame.requiresLiveData && requiredLinkKinds.isNotEmpty() && missingKinds.isNotEmpty()
        val shouldEnrichSummary = shouldRequestRework || requiredLinkKinds.isNotEmpty() || summary.isBlank()

        var enrichedSummary = summary.trim().ifBlank {
            "No empty return is allowed. Provide a concrete plan, evidence, and next action."
        }
        if (shouldEnrichSummary && nextAction.isNotBlank() && !Regex("(?i)next\\s*action").containsMatchIn(enrichedSummary)) {
            enrichedSummary = "$enrichedSummary\n\nNext Action:\n- $nextAction"
        }
        if (shouldEnrichSummary && verifiedLinks.isNotEmpty() && !Regex("(?i)verified\\s+links").containsMatchIn(enrichedSummary)) {
            val linkLines = verifiedLinks.take(8).joinToString("\n") { "- ${it.title}: ${it.url}" }
            enrichedSummary = "$enrichedSummary\n\nVerified Links:\n$linkLines"
        }
        if (shouldEnrichSummary && missingKinds.isNotEmpty()) {
            val readableMissing = missingKinds.joinToString(", ") { kind ->
                kind.replace('_', ' ')
            }
            enrichedSummary = "$enrichedSummary\n\nLink Coverage Gap:\n- Missing clickable links for: $readableMissing."
        }

        val nextActionHint = if (missingKinds.isNotEmpty()) {
            "Provide clickable links for ${missingKinds.joinToString(", ") { it.replace('_', ' ') }} and rerun validation."
        } else {
            null
        }
        return ReturnContractAudit(
            summary = enrichedSummary.trim(),
            requiredLinkKinds = requiredLinkKinds,
            providedLinkKinds = providedKinds.sorted(),
            missingRequiredLinkKinds = missingKinds,
            providedLinks = verifiedLinks,
            shouldRequestRework = shouldRequestRework,
            nextActionHint = nextActionHint
        )
    }

    private fun requiredLinkKindsForDomain(problemFrame: ProblemFramePayload): List<String> {
        if (!problemFrame.requiresLiveData) return emptyList()
        return when (problemFrame.primaryDomain.lowercase()) {
            "travel" -> listOf("flight", "hotel", "restaurant", "attraction")
            "local_service" -> listOf("service", "map")
            "recruitment" -> listOf("job", "company")
            "finance" -> listOf("market_data")
            "health", "legal" -> listOf("official_reference")
            "education" -> listOf("course")
            else -> listOf("primary")
        }
    }

    private fun collectProvidedLinkKinds(links: List<VerifiedLinkEntry>): Set<String> {
        if (links.isEmpty()) return emptySet()
        val kinds = linkedSetOf("primary")
        links.forEach { link ->
            kinds += classifyLinkKinds("${link.title} ${link.url}")
        }
        return kinds
    }

    private fun classifyLinkKinds(textRaw: String): Set<String> {
        val text = textRaw.lowercase()
        val result = linkedSetOf<String>()
        if (Regex("(flight|airline|airport|travel/flights|skyscanner|expedia)").containsMatchIn(text)) result += "flight"
        if (Regex("(hotel|booking|accommodation|stay|hostel)").containsMatchIn(text)) result += "hotel"
        if (Regex("(restaurant|dining|food|cuisine|opentable)").containsMatchIn(text)) result += "restaurant"
        if (Regex("(attraction|museum|castle|landmark|sightseeing|tripadvisor)").containsMatchIn(text)) result += "attraction"
        if (Regex("(transport|transfer|map|maps|metro|bus|train|taxi)").containsMatchIn(text)) result += "map"
        if (Regex("(service|provider|vendor|merchant)").containsMatchIn(text)) result += "service"
        if (Regex("(job|career|hiring|linkedin|indeed|greenhouse|lever)").containsMatchIn(text)) result += "job"
        if (Regex("(company|crunchbase|glassdoor|official site)").containsMatchIn(text)) result += "company"
        if (Regex("(course|curriculum|class|coursera|edx|udemy|khan)").containsMatchIn(text)) result += "course"
        if (Regex("(finance|market|quote|bloomberg|yahoo finance|sec|ft.com)").containsMatchIn(text)) result += "market_data"
        if (Regex("(gov|nhs|sec\\.gov|legislation|court|who\\.int|cdc)").containsMatchIn(text)) result += "official_reference"
        return result
    }

    private fun extractExecutableSteps(response: AgentResponse): List<String> {
        val summaryLines = response.summary
            .orEmpty()
            .replace("\r", "")
            .lines()
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .take(3)
        if (summaryLines.isNotEmpty()) return summaryLines
        val cardSteps = response.cards.map { it.title.ifBlank { it.summary } }.filter { it.isNotBlank() }.take(3)
        if (cardSteps.isNotEmpty()) return cardSteps
        return listOf("Review output and confirm execution constraints.")
    }

    private fun collectEvidenceFromResponse(response: AgentResponse): List<EvidenceItemPayload> {
        val chatEvidence = (response.payload as? ModulePayload.ChatPayload)?.evidenceItems.orEmpty()
        if (chatEvidence.isNotEmpty()) return chatEvidence
        val destinyEvidence = (response.payload as? ModulePayload.DestinyPayload)?.evidenceItems.orEmpty()
        if (destinyEvidence.isNotEmpty()) return destinyEvidence
        return response.evidence
    }

    private fun augmentExecutableActions(
        response: AgentResponse,
        module: ModuleId,
        evidence: List<EvidenceItemPayload>
    ): List<AgentAction> {
        val byId = LinkedHashMap<String, AgentAction>()
        response.actions.forEach { action ->
            if (action.id.isNotBlank()) {
                byId[action.id] = action
            }
        }

        buildEvidenceOpenActions(evidence).forEach { action ->
            byId.putIfAbsent(action.id, action)
        }
        buildSummaryUrlActions(response.summary).forEach { action ->
            byId.putIfAbsent(action.id, action)
        }
        buildTaskTrackSearchActions(response.payload as? ModulePayload.ChatPayload).forEach { action ->
            byId.putIfAbsent(action.id, action)
        }
        if (module == ModuleId.LIX) {
            buildLixOfferActions(response.payload as? ModulePayload.LixPayload).forEach { action ->
                byId.putIfAbsent(action.id, action)
            }
        }

        if (response.nextAction.isNotBlank() && byId.values.none { it.type == AgentActionType.RUN_QUERY && it.prompt == response.nextAction }) {
            byId.putIfAbsent(
                "run_next_action",
                AgentAction(
                    id = "run_next_action",
                    label = "Run next step",
                    type = AgentActionType.RUN_QUERY,
                    prompt = response.nextAction
                )
            )
        }

        if (byId.isEmpty()) {
            defaultActions(module, response.nextAction.ifBlank { response.summary.orEmpty() }).forEach { action ->
                byId.putIfAbsent(action.id, action)
            }
        }
        return byId.values.take(8)
    }

    private fun buildEvidenceOpenActions(evidence: List<EvidenceItemPayload>): List<AgentAction> {
        return evidence
            .mapNotNull { item ->
                val link = item.url?.let(::verifiedExternalUrlOrNull) ?: return@mapNotNull null
                AgentAction(
                    id = "open_evidence_${abs(link.hashCode())}",
                    label = "Open ${item.title.ifBlank { item.source }.take(28)}",
                    type = AgentActionType.OPEN_DEEPLINK,
                    deeplink = link
                )
            }
            .distinctBy { it.deeplink }
            .take(4)
    }

    private fun buildSummaryUrlActions(summary: String?): List<AgentAction> {
        val text = summary.orEmpty()
        if (text.isBlank()) return emptyList()
        val urlRegex = Regex("""https?://[^\s)\]]+""")
        return urlRegex.findAll(text)
            .map { it.value }
            .mapNotNull(::verifiedExternalUrlOrNull)
            .distinct()
            .take(4)
            .mapIndexed { index, link ->
                AgentAction(
                    id = "open_summary_link_${index + 1}_${abs(link.hashCode())}",
                    label = "Open plan link ${index + 1}",
                    type = AgentActionType.OPEN_DEEPLINK,
                    deeplink = link
                )
            }
            .toList()
    }

    private fun buildTaskTrackSearchActions(payload: ModulePayload.ChatPayload?): List<AgentAction> {
        val steps = payload?.taskTrack?.steps.orEmpty()
        if (steps.isEmpty()) return emptyList()
        val statusOnlyRegex = Regex(
            """(?i)^(queued|running|awaiting(\s+confirmation|\s+confirm)?|waiting|processing|error|failed|failure|partial|partially completed|success|done|completed)$"""
        )
        val candidates = steps
            .asReversed()
            .mapNotNull { step ->
                val text = sequenceOf(step.detail, step.title)
                    .map { it.orEmpty().trim() }
                    .firstOrNull { it.isNotBlank() }
                    ?: return@mapNotNull null
                val normalized = text
                    .replace(Regex("""\s+"""), " ")
                    .trim()
                    .take(72)
                if (statusOnlyRegex.matches(normalized)) return@mapNotNull null
                if (normalized.length < 8) return@mapNotNull null
                normalized
            }
            .distinct()
            .take(2)
        return candidates.mapIndexed { index, text ->
            AgentAction(
                id = "open_step_search_${index + 1}_${abs(text.hashCode())}",
                label = "Search: ${text.take(28)}",
                type = AgentActionType.OPEN_DEEPLINK,
                deeplink = "https://www.google.com/search?q=${urlEncode(text)}"
            )
        }
    }

    private suspend fun autoEnrichEvidenceCoverage(
        request: AgentRequest,
        cloudGateway: CloudGateway,
        constraints: AgentTaskConstraints,
        summary: String,
        evidence: List<EvidenceItemPayload>,
        requiredLinkKinds: List<String>
    ): EvidenceCoverageEnrichment {
        val baseSummary = summary.trim().ifBlank { "Live evidence synced. Continue refining the task." }
        if (requiredLinkKinds.isEmpty()) {
            return EvidenceCoverageEnrichment(
                summary = baseSummary,
                evidence = evidence,
                providedKinds = emptySet(),
                missingKinds = emptyList(),
                hint = null
            )
        }

        val initialVerified = collectVerifiedLinkEntries(summary = baseSummary, evidence = evidence)
        val initialProvidedKinds = collectProvidedLinkKinds(initialVerified)
        val initialMissingKinds = requiredLinkKinds.filterNot { initialProvidedKinds.contains(it) }.distinct()
        if (initialMissingKinds.isEmpty()) {
            val verifiedSummary = enforceVerifiedLinks(
                summary = baseSummary,
                verifiedLinks = initialVerified,
                appendMissingVerifiedSection = true
            )
            return EvidenceCoverageEnrichment(
                summary = verifiedSummary,
                evidence = evidence,
                providedKinds = initialProvidedKinds,
                missingKinds = emptyList(),
                hint = "Verified live links are complete for this domain."
            )
        }

        val supplementalEvidence = mutableListOf<EvidenceItemPayload>()
        for (kind in initialMissingKinds) {
            val searchQuery = buildCoverageSearchQuery(request.rawText, kind)
            val searchResult = cloudGateway.liveSearch(
                query = searchQuery,
                constraints = constraints.copy(
                    preferRealtime = true,
                    maxResults = constraints.maxResults.coerceAtLeast(4),
                    reasoningMode = "low"
                )
            )
            if (!searchResult.success) continue
            val kindLabel = coverageKindLabel(kind)
            val labeledEvidence = evidenceFromLiveSearch(searchResult.data).map { row ->
                val baseTitle = row.title.takeIf { it.isNotBlank() } ?: "$kindLabel source"
                if (baseTitle.contains(kindLabel, ignoreCase = true)) {
                    row
                } else {
                    row.copy(title = "$kindLabel · $baseTitle")
                }
            }
            supplementalEvidence += labeledEvidence
        }

        val mergedEvidence = sanitizeEvidenceWithVerifiedUrls(
            (evidence + supplementalEvidence).distinctBy { row ->
                row.url?.ifBlank { null } ?: "${row.source}|${row.title}|${row.snippet.orEmpty().take(80)}"
            }
        )
        val verifiedLinks = collectVerifiedLinkEntries(summary = baseSummary, evidence = mergedEvidence)
        val providedKinds = collectProvidedLinkKinds(verifiedLinks)
        val missingKinds = requiredLinkKinds.filterNot { providedKinds.contains(it) }.distinct()

        val coverageHint = when {
            supplementalEvidence.isEmpty() -> "No new live sources were retrieved for missing link categories."
            missingKinds.isEmpty() -> "Auto live evidence sync completed: all required clickable link categories are covered."
            else -> "Auto live evidence sync completed; still missing: ${missingKinds.joinToString(", ") { it.replace('_', ' ') }}."
        }
        val summaryWithCoverage = buildString {
            append(baseSummary)
            if (!contains(coverageHint, ignoreCase = true)) {
                append("\n\n")
                append(coverageHint)
            }
        }
        val verifiedSummary = enforceVerifiedLinks(
            summary = summaryWithCoverage,
            verifiedLinks = verifiedLinks,
            appendMissingVerifiedSection = true
        )
        return EvidenceCoverageEnrichment(
            summary = verifiedSummary,
            evidence = mergedEvidence,
            providedKinds = providedKinds,
            missingKinds = missingKinds,
            hint = coverageHint
        )
    }

    private fun buildCoverageSearchQuery(rawQuery: String, kind: String): String {
        val context = rawQuery.trim().replace(Regex("\\s+"), " ").take(220)
        return when (kind) {
            "flight" -> "$context official airline booking links and real flight options"
            "hotel" -> "$context official hotel booking links and accommodation options"
            "restaurant" -> "$context official restaurant websites and reservation links"
            "attraction" -> "$context official attraction ticket or venue links"
            "service" -> "$context official service provider links"
            "map" -> "$context official map or transport links"
            "job" -> "$context official job posting links"
            "company" -> "$context official company website links"
            "market_data" -> "$context official market data references"
            "official_reference" -> "$context official government or regulator references"
            "course" -> "$context official course provider links"
            else -> "$context verified official links"
        }
    }

    private fun coverageKindLabel(kind: String): String {
        return when (kind) {
            "flight" -> "Flight"
            "hotel" -> "Hotel"
            "restaurant" -> "Restaurant"
            "attraction" -> "Attraction"
            "service" -> "Service"
            "map" -> "Transport"
            "job" -> "Job"
            "company" -> "Company"
            "market_data" -> "Market data"
            "official_reference" -> "Official reference"
            "course" -> "Course"
            else -> "Verified source"
        }
    }

    private fun buildLixOfferActions(payload: ModulePayload.LixPayload?): List<AgentAction> {
        if (payload == null || payload.offers.isEmpty()) return emptyList()
        val intentDeepLink = LumiRoutes.lixIntent(payload.intentId?.ifBlank { "latest" } ?: "latest")
        return payload.offers.take(4).map { offer ->
            val link = offer.actionDeeplink?.takeIf { it.isNotBlank() }
                ?: offer.actionUrl?.takeIf { it.isNotBlank() }
                ?: intentDeepLink
            AgentAction(
                id = "open_offer_${offer.id.ifBlank { abs(offer.name.hashCode()).toString() }}",
                label = offer.actionLabel ?: "Open ${offer.name.take(24)}",
                type = AgentActionType.OPEN_DEEPLINK,
                deeplink = link
            )
        }
    }

    private fun urlEncode(text: String): String {
        return URLEncoder.encode(text, StandardCharsets.UTF_8)
    }

    private suspend fun synthesizeCloudFinalSummary(
        request: AgentRequest,
        cloudGateway: CloudGateway,
        constraints: AgentTaskConstraints,
        execution: AgentExecutionPayload,
        taskGraph: TaskGraphPayload,
        evidence: List<EvidenceItemPayload>
    ): String {
        val verifiedLinks = collectVerifiedLinkEntries(summary = execution.resultSummary, evidence = evidence)
        val shouldRunSecondPass = taskGraph.tasks.size >= 3 && verifiedLinks.isNotEmpty()
        if (!shouldRunSecondPass) {
            return enforceVerifiedLinks(
                summary = execution.resultSummary,
                verifiedLinks = verifiedLinks,
                appendMissingVerifiedSection = false
            )
        }

        val synthesisPrompt = buildCloudSynthesisPrompt(
            userQuery = request.rawText,
            execution = execution,
            taskGraph = taskGraph,
            evidence = evidence,
            verifiedLinks = verifiedLinks
        )
        val synthesisResult = cloudGateway.executeAgent(
            task = synthesisPrompt,
            constraints = constraints.copy(preferRealtime = false, maxResults = 2, reasoningMode = "high")
        )
        val synthesized = synthesisResult.data?.resultSummary?.trim().orEmpty()
        val fallback = execution.resultSummary
        val candidate = synthesized.ifBlank { fallback }
        return enforceVerifiedLinks(
            summary = candidate,
            verifiedLinks = verifiedLinks,
            appendMissingVerifiedSection = true
        )
    }

    private fun sanitizeEvidenceWithVerifiedUrls(evidence: List<EvidenceItemPayload>): List<EvidenceItemPayload> {
        return evidence.map { item ->
            val verifiedUrl = item.url?.let(::verifiedExternalUrlOrNull)
            if (item.url.isNullOrBlank() || verifiedUrl != null) {
                item.copy(url = verifiedUrl ?: item.url)
            } else {
                val note = "URL verification failed at delivery stage; removed from final actions."
                val mergedSnippet = listOfNotNull(item.snippet?.takeIf { it.isNotBlank() }, note).joinToString(" ")
                item.copy(url = null, snippet = mergedSnippet.take(220))
            }
        }
    }

    private fun collectVerifiedLinkEntries(
        summary: String,
        evidence: List<EvidenceItemPayload>
    ): List<VerifiedLinkEntry> {
        val fromEvidence = evidence.mapNotNull { item ->
            val url = item.url?.let(::verifiedExternalUrlOrNull) ?: return@mapNotNull null
            VerifiedLinkEntry(
                title = item.title.ifBlank { "Evidence link" },
                url = url
            )
        }
        val fromSummary = Regex("""https?://[^\s)\]]+""")
            .findAll(summary)
            .map { it.value }
            .mapNotNull(::verifiedExternalUrlOrNull)
            .mapIndexed { index, url ->
                VerifiedLinkEntry(
                    title = "Summary link ${index + 1}",
                    url = url
                )
            }
            .toList()
        return (fromEvidence + fromSummary)
            .distinctBy { it.url }
            .take(12)
    }

    private fun buildCloudSynthesisPrompt(
        userQuery: String,
        execution: AgentExecutionPayload,
        taskGraph: TaskGraphPayload,
        evidence: List<EvidenceItemPayload>,
        verifiedLinks: List<VerifiedLinkEntry>
    ): String {
        val taskLines = taskGraph.tasks.take(10).joinToString("\n") { task ->
            val caps = task.requiredCapabilities.joinToString(", ").ifBlank { "general" }
            "- ${task.id}: ${task.title} (capabilities: $caps)"
        }
        val evidenceLines = evidence.take(12).joinToString("\n") { item ->
            val title = item.title.ifBlank { item.source }
            val snippet = item.snippet?.takeIf { it.isNotBlank() } ?: "No snippet"
            "- $title: ${snippet.take(120)}"
        }
        val verifiedLinkLines = verifiedLinks.joinToString("\n") { link ->
            "- ${link.title}: ${link.url}"
        }
        return """
Cloud Synthesis Task (Final Packaging)
You are the final cloud LLM synthesis layer.

Original user request:
$userQuery

Subtask decomposition and execution log:
$taskLines

Raw subtask summary:
${execution.resultSummary}

Evidence snippets:
$evidenceLines

Verified URLs (MUST keep exact; do not invent new URLs):
$verifiedLinkLines

Output requirements:
1) Produce an actionable plan with concrete steps.
2) Include a dedicated section "Verified Links" using only the provided verified URLs.
3) Add one "Next Action" line and one "Risk/Fallback" line.
4) Response language: English.
5) No empty response.
        """.trimIndent()
    }

    private fun enforceVerifiedLinks(
        summary: String,
        verifiedLinks: List<VerifiedLinkEntry>,
        appendMissingVerifiedSection: Boolean
    ): String {
        if (summary.isBlank()) {
            return if (verifiedLinks.isEmpty()) {
                "Execution completed with no textual summary. Next action: review validated evidence and continue."
            } else {
                buildString {
                    append("Execution completed. Verified links:\n")
                    append(verifiedLinks.joinToString("\n") { "- ${it.title}: ${it.url}" })
                }
            }
        }

        if (verifiedLinks.isEmpty()) return summary
        val allowed = verifiedLinks.map { it.url }.toSet()
        val urlRegex = Regex("""https?://[^\s)\]]+""")
        val sanitized = urlRegex.replace(summary) { match ->
            val candidate = verifiedExternalUrlOrNull(match.value)
            if (candidate != null && allowed.contains(candidate)) {
                candidate
            } else {
                "[unverified-link-removed]"
            }
        }
        val hasAnyAllowed = allowed.any { sanitized.contains(it) }
        return if (hasAnyAllowed) {
            sanitized
        } else if (appendMissingVerifiedSection) {
            buildString {
                append(sanitized.trim())
                append("\n\nVerified Links:\n")
                append(verifiedLinks.joinToString("\n") { "- ${it.title}: ${it.url}" })
            }.trim()
        } else {
            sanitized
        }
    }

    private fun verifiedExternalUrlOrNull(raw: String): String? {
        val normalized = normalizeExternalUrl(raw) ?: return null
        val cached = verifiedUrlCache[normalized]
        if (cached != null && (nowMs() - cached.checkedAtMs) <= URL_VERIFICATION_TTL_MS) {
            return if (cached.reachable) normalized else null
        }
        val reachable = isUrlReachable(normalized)
        verifiedUrlCache[normalized] = UrlVerificationCacheEntry(reachable = reachable, checkedAtMs = nowMs())
        return if (reachable) normalized else null
    }

    private fun normalizeExternalUrl(raw: String): String? {
        val cleaned = raw
            .trim()
            .trimEnd('.', ',', ';', ':')
            .trim('(', ')', '[', ']', '"', '\'')
            .replace("&amp;", "&")
        if (cleaned.isBlank()) return null
        if (cleaned.startsWith("http://", ignoreCase = true) || cleaned.startsWith("https://", ignoreCase = true)) {
            return cleaned
        }
        if (cleaned.contains("://")) return null
        return "https://$cleaned"
    }

    private fun isUrlReachable(url: String): Boolean {
        val parsed = runCatching { URL(url) }.getOrNull() ?: return false
        val host = parsed.host.lowercase().trim('.')
        if (isBlockedExternalHost(host)) return false
        if (TRUSTED_LINK_HOSTS.any { trusted -> host == trusted || host.endsWith(".$trusted") }) {
            return true
        }
        return runCatching {
            val headCode = requestHttpStatus(url, method = "HEAD")
            when {
                headCode in 200..399 -> true
                headCode == 403 || headCode == 405 || headCode == 429 -> {
                    val getCode = requestHttpStatus(url, method = "GET")
                    getCode in 200..399 || getCode == 403 || getCode == 429
                }
                else -> false
            }
        }.getOrDefault(false)
    }

    private fun isBlockedExternalHost(host: String): Boolean {
        if (host.isBlank()) return true
        if (!host.contains('.')) return true
        if (host in BLOCKED_LINK_HOSTS) return true
        if (BLOCKED_LINK_SUFFIXES.any { host.endsWith(it) }) return true
        if (isReservedIpv4Host(host)) return true
        if (isReservedIpv6Host(host)) return true
        return false
    }

    private fun isReservedIpv4Host(host: String): Boolean {
        val chunks = host.split('.')
        if (chunks.size != 4) return false
        val octets = chunks.map { it.toIntOrNull() ?: return false }
        if (octets.any { it !in 0..255 }) return false
        val first = octets[0]
        val second = octets[1]
        return first == 0 ||
            first == 10 ||
            first == 127 ||
            (first == 169 && second == 254) ||
            (first == 172 && second in 16..31) ||
            (first == 192 && second == 168)
    }

    private fun isReservedIpv6Host(host: String): Boolean {
        val normalized = host.lowercase()
        if (!normalized.contains(":")) return false
        if (normalized == "::1" || normalized == "0:0:0:0:0:0:0:1") return true
        return normalized.startsWith("fc") ||
            normalized.startsWith("fd") ||
            normalized.startsWith("fe80")
    }

    private fun requestHttpStatus(
        url: String,
        method: String
    ): Int {
        val connection = (URL(url).openConnection() as HttpURLConnection).apply {
            requestMethod = method
            connectTimeout = 4500
            readTimeout = 4500
            instanceFollowRedirects = true
            setRequestProperty("User-Agent", "LumiAgent/1.0 (+https://lumi.ai)")
            if (method == "GET") {
                setRequestProperty("Range", "bytes=0-512")
            }
        }
        return try {
            connection.responseCode
        } finally {
            connection.disconnect()
        }
    }

    private fun defaultNextAction(
        status: ResponseStatus,
        module: ModuleId,
        phase: AgentPhase
    ): String {
        if (status == ResponseStatus.AUTH_REQUIRED) {
            return "Complete authorization to continue execution."
        }
        if (status == ResponseStatus.QUOTING) {
            return "Review quote comparison and choose the preferred execution path."
        }
        if (status == ResponseStatus.VERIFYING) {
            return "Wait for proof verification to finish before committing."
        }
        if (status == ResponseStatus.COMMITTED) {
            return "Review committed result, verification proof, and rollback terms."
        }
        if (status == ResponseStatus.ROLLED_BACK) {
            return "Review rollback reason and decide whether to re-run with tighter constraints."
        }
        if (status == ResponseStatus.DISPUTED) {
            return "Provide additional evidence and proceed through dispute resolution."
        }
        if (status == ResponseStatus.WAITING_USER && phase == AgentPhase.CLARIFY) {
            return "Provide the requested details and continue."
        }
        if (status == ResponseStatus.WAITING_USER && phase == AgentPhase.EXECUTE) {
            return "Cloud execution is in progress. Keep this trace open and review incoming evidence."
        }
        if (status == ResponseStatus.WAITING_USER && phase == AgentPhase.ESCALATE) {
            return "Provide confirmation token or budget update for escalation."
        }
        if (status == ResponseStatus.WAITING_USER && phase == AgentPhase.FINAL_GATE) {
            return "Review validated supplier options and confirm the final delivery path."
        }
        if (status == ResponseStatus.WAITING_USER && phase == AgentPhase.VERIFY) {
            return "Adjust request to decision-support mode and attach verifiable evidence."
        }
        return when {
            status == ResponseStatus.SUCCESS && module == ModuleId.CHAT ->
                "Review execution plan and run the first actionable step."
            status == ResponseStatus.SUCCESS && module == ModuleId.LIX ->
                "Open LIX intent and confirm supplier execution."
            status == ResponseStatus.COMMITTED && module == ModuleId.LIX ->
                "Review committed delivery, proof, and rollback/dispute terms."
            status == ResponseStatus.PARTIAL ->
                "Review partial output and continue with refinement."
            else -> "Continue to the next task stage."
        }
    }

    private fun buildCloudIssueNote(error: String?, httpStatus: Int?): String {
        val normalized = error.orEmpty().trim()
        if (normalized.isBlank() && (httpStatus == null || httpStatus == 0)) return ""
        val statusCode = httpStatus ?: Regex("""\b(\d{3})\b""")
            .find(normalized)
            ?.groupValues
            ?.getOrNull(1)
            ?.toIntOrNull()
        val lower = normalized.lowercase()
        val message = when {
            statusCode == 429 || lower.contains("quota") || lower.contains("rate limit") ->
                "Cloud quota is currently exhausted (HTTP 429)."
            statusCode == 403 || lower.contains("forbidden") ->
                "Cloud request is blocked by permission policy (HTTP 403)."
            statusCode == 401 || lower.contains("unauthorized") || lower.contains("api key") ->
                "Cloud authentication failed (HTTP 401)."
            else -> "Cloud execution is unavailable right now${statusCode?.let { " (HTTP $it)" } ?: ""}."
        }
        val action = when {
            statusCode == 429 || lower.contains("quota") || lower.contains("rate limit") ->
                "Top up or switch cloud API key quota, then rerun this task for full live results."
            statusCode == 403 ->
                "Check policy approval or provider access, then retry."
            statusCode == 401 || lower.contains("api key") ->
                "Update the cloud API key configuration and retry."
            else -> "Retry when cloud service recovers."
        }
        return "\n\nCloud Issue:\n- $message\n- $action"
    }

    private fun requiresLixConstraintPackage(
        module: ModuleId,
        rawText: String,
        summary: String? = null,
        userId: String? = null
    ): Boolean {
        val raw = rawText.lowercase()
        val normalizedSummary = summary.orEmpty().lowercase()
        val pendingEscalation = userId?.let { pendingEscalationForUser(it) != null } ?: false
        val explicitEscalationIntent = shouldTreatAsEscalationIntent(rawText = rawText, module = module)
        return module == ModuleId.LIX ||
            (pendingEscalation && explicitEscalationIntent) ||
            raw.contains("lix") ||
            raw.contains("agent marketplace") ||
            raw.contains("agent market") ||
            raw.contains("publish to lix") ||
            raw.contains("publish requirement") ||
            raw.contains("发布需求") ||
            raw.contains("供应商市场") ||
            normalizedSummary.contains("lix escalation") ||
            normalizedSummary.contains("supplier escalation")
    }

    private fun requiresExternalSpendGate(
        module: ModuleId,
        rawText: String,
        response: AgentResponse,
        userId: String? = null
    ): Boolean {
        val raw = rawText.lowercase()
        val lixStage = (response.payload as? ModulePayload.LixPayload)?.stage?.lowercase().orEmpty()
        val pendingEscalation = userId?.let { pendingEscalationForUser(it) != null } ?: false
        val explicitEscalationRequest = shouldTreatAsEscalationIntent(rawText = rawText, module = module)
        val explicitSpendRequest = raw.contains("publish to lix") ||
            raw.contains("publish requirement") ||
            raw.contains("accept offer") ||
            raw.contains("purchase") ||
            raw.contains("procure") ||
            raw.contains("下单") ||
            raw.contains("购买")
        val responseHasSpendSignal = response.marketEscalation != null
        val lixSpendStage = lixStage.contains("accepted") ||
            lixStage.contains("delivery") ||
            lixStage.contains("contract") ||
            lixStage.contains("purchase")
        if (module == ModuleId.LIX || (pendingEscalation && explicitEscalationRequest)) {
            return explicitSpendRequest || responseHasSpendSignal || lixSpendStage
        }
        if (!explicitEscalationRequest) {
            return false
        }
        return explicitSpendRequest || responseHasSpendSignal
    }

    private fun requiresEvidenceForSuccess(
        module: ModuleId,
        meta: OrchestrationMeta,
        response: AgentResponse
    ): Boolean {
        val payloadRoutingMode = (response.payload as? ModulePayload.ChatPayload)?.routingDecision?.mode
        val routingMode = payloadRoutingMode ?: response.routingDecision?.mode ?: meta.routingDecision.mode
        return module == ModuleId.LIX ||
            module == ModuleId.DESTINY ||
            routingMode == RoutingMode.MULTI_AGENT
    }

    private fun requiresSupplierValidation(module: ModuleId, response: AgentResponse): Boolean {
        val summary = response.summary.orEmpty().lowercase()
        val lixStage = (response.payload as? ModulePayload.LixPayload)?.stage?.lowercase().orEmpty()
        return module == ModuleId.LIX && (
            lixStage.contains("validated") ||
                lixStage.contains("delivery") ||
                lixStage.contains("accepted") ||
                summary.contains("supplier")
            )
    }

    private fun isNonEmptyReturn(response: AgentResponse): Boolean {
        return response.summary?.isNotBlank() == true ||
            response.cards.isNotEmpty() ||
            response.drafts.any { it.text.isNotBlank() } ||
            response.actions.isNotEmpty()
    }

    private fun isSuccessLike(status: ResponseStatus): Boolean {
        return status == ResponseStatus.SUCCESS || status == ResponseStatus.COMMITTED
    }

    private fun resolveRoleExecutionContext(
        request: AgentRequest,
        module: ModuleId,
        constraints: AgentRequestConstraints
    ): RoleExecutionContext {
        val previousRole = activeRoleByUser[request.userId]
        val explicitRole = constraints.activeRole
        val inheritedRole = inheritedRoleForRequest(request)
        val profileDefaultRole = profileDefaultRoleForUser(request.userId)
        val inferredRole = inferActiveRole(request, module)

        val resolvedRole: UserRole
        val resolvedSource: RoleSource
        when {
            explicitRole != null -> {
                resolvedRole = explicitRole
                resolvedSource = constraints.roleSource ?: RoleSource.EXPLICIT_USER_SELECTION
            }

            inheritedRole != null -> {
                resolvedRole = inheritedRole
                resolvedSource = RoleSource.TASK_INHERITED
            }

            profileDefaultRole != null -> {
                resolvedRole = profileDefaultRole
                resolvedSource = RoleSource.USER_PROFILE_DEFAULT
            }

            inferredRole != UserRole.PERSONAL -> {
                resolvedRole = inferredRole
                resolvedSource = RoleSource.SAFE_SYSTEM_INFERENCE
            }

            else -> {
                resolvedRole = UserRole.PERSONAL
                resolvedSource = RoleSource.SYSTEM_FALLBACK
            }
        }

        var roleChangeReason = constraints.roleChangeReason
        if (pendingSystemRecoveryByUser.remove(request.userId)) {
            roleChangeReason = roleChangeReason ?: RoleChangeReason.SYSTEM_RECOVERY
        }
        if (roleChangeReason == null && previousRole != null && previousRole != resolvedRole) {
            roleChangeReason = when (resolvedSource) {
                RoleSource.EXPLICIT_USER_SELECTION -> RoleChangeReason.USER_SWITCHED_ROLE
                RoleSource.TASK_INHERITED -> RoleChangeReason.RESUME_INHERITED_ROLE
                RoleSource.USER_PROFILE_DEFAULT -> RoleChangeReason.POLICY_REEVALUATION
                RoleSource.SAFE_SYSTEM_INFERENCE, RoleSource.SYSTEM_FALLBACK -> RoleChangeReason.POLICY_REEVALUATION
            }
        }

        val rolePolicy = effectiveRolePolicyProfile(request.userId, resolvedRole)
        val delegationMode = rolePolicy.delegationPolicy.mode
        val canonicalRoleReasonCodes = mutableListOf(
            roleSourceReasonCode(resolvedSource),
            RoleReasonCodes.ROLE_POLICY_ALLOWED
        )
        if (hasRolePolicyOverride(request.userId, resolvedRole)) {
            canonicalRoleReasonCodes += RoleReasonCodes.ROLE_POLICY_USER_OVERRIDE_APPLIED
        }
        if (delegationMode != DelegationMode.AUTONOMOUS_WITHIN_POLICY) {
            canonicalRoleReasonCodes += RoleReasonCodes.ROLE_DELEGATION_MODE_LIMITED
        }
        if (rolePolicy.dataPolicy.allowedScopes.size <= 1) {
            canonicalRoleReasonCodes += RoleReasonCodes.ROLE_DATA_SCOPE_REDUCED
        }
        if (digitalTwinCloudSyncEnabled && !rolePolicy.dataPolicy.cloudSyncAllowed) {
            canonicalRoleReasonCodes += RoleReasonCodes.ROLE_CLOUD_SYNC_BLOCKED
        }
        when (roleChangeReason) {
            RoleChangeReason.USER_SWITCHED_ROLE -> canonicalRoleReasonCodes += listOf(
                RoleReasonCodes.ROLE_CHANGED_BY_USER,
                RoleReasonCodes.ROLE_CHANGE_TRIGGERED_REEVALUATION,
                RoleReasonCodes.ROLE_CHANGE_REQUIRES_REAPPROVAL
            )

            RoleChangeReason.POLICY_REEVALUATION,
            RoleChangeReason.TASK_RESCOPED,
            RoleChangeReason.RESUME_INHERITED_ROLE -> canonicalRoleReasonCodes += RoleReasonCodes.ROLE_CHANGE_TRIGGERED_REEVALUATION

            RoleChangeReason.SYSTEM_RECOVERY,
            RoleChangeReason.ROLE_INVALIDATED,
            null -> Unit
        }
        if (roleChangeReason == RoleChangeReason.SYSTEM_RECOVERY) {
            canonicalRoleReasonCodes += RoleReasonCodes.ROLE_CHANGED_BY_SYSTEM_SAFE_RULE
        }

        val context = RoleExecutionContext(
            activeRole = resolvedRole,
            roleSource = resolvedSource,
            roleChangeReason = roleChangeReason,
            rolePolicyProfile = rolePolicy,
            delegationMode = delegationMode,
            canonicalRoleReasonCodes = canonicalRoleReasonCodes.distinct(),
            legacyRoleDetailReasons = buildList {
                add("role_source=${resolvedSource.name.lowercase()}")
                roleChangeReason?.let { add("role_change_reason=${it.name.lowercase()}") }
                add("delegation_mode=${delegationMode.name.lowercase()}")
            }
        )
        rememberRoleResolution(request, context)
        return context
    }

    private fun inheritedRoleForRequest(request: AgentRequest): UserRole? {
        val role = activeRoleByUser[request.userId] ?: return null
        val source = activeRoleSourceByUser[request.userId] ?: return null
        val cachedSession = roleSessionByUser[request.userId]
        val recoveryPending = pendingSystemRecoveryByUser.contains(request.userId)
        return when (source) {
            RoleSource.TASK_INHERITED,
            RoleSource.EXPLICIT_USER_SELECTION -> role.takeIf {
                cachedSession == request.sessionId || recoveryPending
            }
            RoleSource.USER_PROFILE_DEFAULT -> null
            RoleSource.SAFE_SYSTEM_INFERENCE,
            RoleSource.SYSTEM_FALLBACK -> null
        }
    }

    private fun profileDefaultRoleForUser(userId: String): UserRole? {
        val source = activeRoleSourceByUser[userId]
        return if (source == RoleSource.USER_PROFILE_DEFAULT) {
            activeRoleByUser[userId]
        } else {
            null
        }
    }

    private fun rememberRoleResolution(
        request: AgentRequest,
        roleContext: RoleExecutionContext
    ) {
        val userId = request.userId
        when (roleContext.roleSource) {
            RoleSource.EXPLICIT_USER_SELECTION,
            RoleSource.TASK_INHERITED -> {
                activeRoleByUser[userId] = roleContext.activeRole
                activeRoleSourceByUser[userId] = roleContext.roleSource
                roleSessionByUser[userId] = request.sessionId
            }

            RoleSource.USER_PROFILE_DEFAULT -> {
                activeRoleByUser[userId] = roleContext.activeRole
                activeRoleSourceByUser[userId] = roleContext.roleSource
                roleSessionByUser.remove(userId)
            }

            RoleSource.SAFE_SYSTEM_INFERENCE,
            RoleSource.SYSTEM_FALLBACK -> {
                // Inferred/fallback role is non-sticky by default to avoid cross-role contamination.
                if (activeRoleSourceByUser[userId] in setOf(RoleSource.SAFE_SYSTEM_INFERENCE, RoleSource.SYSTEM_FALLBACK)) {
                    activeRoleByUser.remove(userId)
                    activeRoleSourceByUser.remove(userId)
                    roleSessionByUser.remove(userId)
                }
            }
        }
    }

    private fun roleSourceReasonCode(source: RoleSource): String {
        return when (source) {
            RoleSource.EXPLICIT_USER_SELECTION -> RoleReasonCodes.ROLE_EXPLICIT_USER_SELECTED
            RoleSource.USER_PROFILE_DEFAULT -> RoleReasonCodes.ROLE_PROFILE_DEFAULT_APPLIED
            RoleSource.TASK_INHERITED -> RoleReasonCodes.ROLE_TASK_INHERITED
            RoleSource.SAFE_SYSTEM_INFERENCE -> RoleReasonCodes.ROLE_SAFE_INFERENCE_APPLIED
            RoleSource.SYSTEM_FALLBACK -> RoleReasonCodes.ROLE_SYSTEM_FALLBACK_APPLIED
        }
    }

    private fun resolveRequestConstraints(request: AgentRequest): AgentRequestConstraints {
        val lines = request.rawText
            .replace("\r", "")
            .lines()
            .map { it.trim() }
            .filter { it.isNotBlank() }
        val budget = request.constraints.budget
            ?: extractLixField(lines, "budget", "max budget", "price cap", "预算")
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:budget|预算)\\s*(?:[:：]|=)\\s*(.+?)(?=(?:deadline|时限|期限|acceptance\\s+criteria|acceptance|验收标准|验收|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|[;\\n]|$)"
            )
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:budget|预算)\\s+(.+?)(?=(?:deadline|时限|期限|acceptance\\s+criteria|acceptance|验收标准|验收|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|$)"
            )
        val deadline = request.constraints.deadline
            ?: extractLixField(lines, "deadline", "completion deadline", "时限", "期限")
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:deadline|时限|期限)\\s*(?:[:：]|=)\\s*(.+?)(?=(?:budget|预算|acceptance\\s+criteria|acceptance|验收标准|验收|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|[;\\n]|$)"
            )
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:deadline|时限|期限)\\s+(.+?)(?=(?:budget|预算|acceptance\\s+criteria|acceptance|验收标准|验收|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|$)"
            )
        val acceptance = request.constraints.acceptanceCriteria
            ?: extractLixField(lines, "acceptance criteria", "acceptance", "验收标准", "验收")
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:acceptance\\s+criteria|acceptance|验收标准|验收)\\s*(?:[:：]|=)\\s*(.+?)(?=(?:budget|预算|deadline|时限|期限|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|[;\\n]|$)"
            )
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:acceptance\\s+criteria|acceptance|验收标准|验收)\\s+(.+?)(?=(?:budget|预算|deadline|时限|期限|user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\b|$)"
            )
        val maxCostPerStep = request.constraints.maxCostPerStep
            ?: extractLixField(lines, "max cost per step", "max cost", "cost tier", "单步成本上限", "成本档位")
            ?: extractInlineValue(
                request.rawText,
                "(?i)(?:max cost per step|max cost|cost tier|单步成本上限|成本档位)\\s*(?:[:：]|=)\\s*([^;\\n]+)"
            )
        val riskTolerance = request.constraints.riskTolerance
            ?: extractLixField(lines, "risk tolerance", "risk level", "风险偏好", "风险容忍度")
            ?: extractInlineValue(
                request.rawText,
                "(?i)(?:risk tolerance|risk level|风险偏好|风险容忍度)\\s*(?:[:：]|=)\\s*([^;\\n]+)"
            )
        val token = request.constraints.userConfirmationToken
            ?: extractLixField(
                lines,
                "user_confirmation_token",
                "user confirmation token",
                "confirmation_token",
                "confirmation token",
                "confirm token",
                "token",
                "确认令牌"
            )
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|token|确认令牌)\\s*(?:[:：]|=)\\s*(.+?)(?=(?:budget|预算|deadline|时限|期限|acceptance\\s+criteria|acceptance|验收标准|验收)\\b|[;\\n]|$)"
            )
            ?: extractInlineValue(
                request.rawText,
                "(?is)(?:user[_\\s-]*confirmation[_\\s-]*token|confirmation[_\\s-]*token|confirmation\\s+token|confirm\\s+token|确认令牌|token)\\s+(.+?)(?=(?:budget|预算|deadline|时限|期限|acceptance\\s+criteria|acceptance|验收标准|验收)\\b|$)"
            )
        val activeRole = request.constraints.activeRole
            ?: request.activeRole
            ?: extractActiveRoleFromLines(lines)
            ?: extractActiveRoleFromInline(request.rawText)
        val roleSource = request.constraints.roleSource ?: request.roleSource
        val roleChangeReason = request.constraints.roleChangeReason ?: request.roleChangeReason
        val roleImpactReasonCodes = mergeRoleReasonCodes(
            request.roleImpactReasonCodes,
            request.constraints.roleImpactReasonCodes
        )
        return AgentRequestConstraints(
            budget = budget?.trim(),
            deadline = deadline?.trim(),
            acceptanceCriteria = acceptance?.trim(),
            maxCostPerStep = maxCostPerStep?.trim(),
            riskTolerance = riskTolerance?.trim(),
            userConfirmationToken = token?.trim()?.let(::normalizeConfirmationToken),
            activeRole = activeRole,
            roleSource = roleSource,
            roleChangeReason = roleChangeReason,
            roleImpactReasonCodes = roleImpactReasonCodes
        )
    }

    private fun AgentRequestConstraints.mergeWith(other: AgentRequestConstraints): AgentRequestConstraints {
        return AgentRequestConstraints(
            budget = budget ?: other.budget,
            deadline = deadline ?: other.deadline,
            acceptanceCriteria = acceptanceCriteria ?: other.acceptanceCriteria,
            maxCostPerStep = maxCostPerStep ?: other.maxCostPerStep,
            riskTolerance = riskTolerance ?: other.riskTolerance,
            userConfirmationToken = userConfirmationToken ?: other.userConfirmationToken,
            activeRole = activeRole ?: other.activeRole,
            roleSource = roleSource ?: other.roleSource,
            roleChangeReason = roleChangeReason ?: other.roleChangeReason,
            roleImpactReasonCodes = mergeRoleReasonCodes(roleImpactReasonCodes, other.roleImpactReasonCodes)
        )
    }

    private fun AgentRequestConstraints.withRoleContext(
        roleContext: RoleExecutionContext
    ): AgentRequestConstraints {
        return copy(
            activeRole = activeRole ?: roleContext.activeRole,
            roleSource = roleSource ?: roleContext.roleSource,
            roleChangeReason = roleChangeReason ?: roleContext.roleChangeReason,
            roleImpactReasonCodes = mergeRoleReasonCodes(
                roleImpactReasonCodes,
                roleContext.canonicalRoleReasonCodes,
                roleContext.legacyRoleDetailReasons
            )
        )
    }

    private fun mergeRoleReasonCodes(vararg groups: List<String>): List<String> {
        return groups
            .asSequence()
            .flatMap { it.asSequence() }
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()
            .toList()
    }

    private fun roleImpactCodesFromRouting(reasonCodes: List<String>): List<String> {
        val canonical = mutableListOf<String>()
        val lowerReasons = reasonCodes.map { it.lowercase() }
        if (lowerReasons.any { it.startsWith("role_") }) {
            canonical += RoleReasonCodes.ROLE_ROUTE_BIAS_APPLIED
        }
        if (lowerReasons.any { it.contains("exclude") || it.contains("blocked") }) {
            canonical += RoleReasonCodes.ROLE_ROUTE_EXCLUDED
        }
        if (lowerReasons.any { it.contains("trusted_provider") || it.contains("prefer_provider") }) {
            canonical += RoleReasonCodes.ROLE_PROVIDER_PREFERRED
        }
        return canonical.distinct()
    }

    private fun roleImpactCodesFromGateDecisions(gates: List<GateDecision>): List<String> {
        val canonical = mutableListOf<String>()
        if (gates.any { it.gate == GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN && it.decision != GateDecisionStatus.PASSED }) {
            canonical += RoleReasonCodes.ROLE_APPROVAL_REQUIRED
        }
        if (gates.any { it.gate == GateType.GATE_R3_BUDGET_SCOPE_GUARD && it.reason.contains("role_limit") }) {
            canonical += RoleReasonCodes.ROLE_APPROVAL_THRESHOLD_EXCEEDED
            canonical += RoleReasonCodes.ROLE_POLICY_DENIED
        }
        return canonical.distinct()
    }

    private fun roleImpactCodesForStatus(status: ResponseStatus): List<String> {
        return when (status) {
            ResponseStatus.ROLLED_BACK -> listOf(RoleReasonCodes.ROLE_POLICY_DENIED)
            ResponseStatus.DISPUTED -> listOf(RoleReasonCodes.ROLE_POLICY_DENIED)
            else -> emptyList()
        }
    }

    private fun AgentResponse.withRoleTrace(
        roleContext: RoleExecutionContext,
        roleImpactReasonCodes: List<String>
    ): AgentResponse {
        return copy(
            activeRole = activeRole ?: roleContext.activeRole,
            roleSource = roleSource ?: roleContext.roleSource,
            roleChangeReason = roleChangeReason ?: roleContext.roleChangeReason,
            roleImpactReasonCodes = mergeRoleReasonCodes(
                this.roleImpactReasonCodes,
                roleImpactReasonCodes
            ),
            delegationMode = delegationMode ?: roleContext.delegationMode,
            payload = payload.withRoleTrace(
                roleContext = roleContext,
                roleImpactReasonCodes = roleImpactReasonCodes
            )
        )
    }

    private fun ModulePayload.withRoleTrace(
        roleContext: RoleExecutionContext,
        roleImpactReasonCodes: List<String>
    ): ModulePayload {
        return when (this) {
            ModulePayload.NonePayload -> this
            is ModulePayload.ChatPayload -> {
                val track = taskTrack
                copy(
                    taskTrack = track?.copy(
                        activeRole = track.activeRole ?: roleContext.activeRole,
                        roleSource = track.roleSource ?: roleContext.roleSource,
                        roleChangeReason = track.roleChangeReason ?: roleContext.roleChangeReason,
                        roleImpactReasonCodes = mergeRoleReasonCodes(
                            track.roleImpactReasonCodes,
                            roleImpactReasonCodes
                        ),
                        delegationMode = track.delegationMode ?: roleContext.delegationMode
                    )
                )
            }

            is ModulePayload.LixPayload -> {
                val contract = intentContract
                copy(
                    intentContract = contract?.copy(
                        activeRole = contract.activeRole,
                        roleSource = contract.roleSource ?: roleContext.roleSource,
                        roleChangeReason = contract.roleChangeReason ?: roleContext.roleChangeReason,
                        roleImpactReasonCodes = mergeRoleReasonCodes(
                            contract.roleImpactReasonCodes,
                            roleImpactReasonCodes
                        ),
                        delegationMode = contract.delegationMode ?: roleContext.delegationMode
                    )
                )
            }

            is ModulePayload.AvatarPayload -> copy(
                activeRole = roleContext.activeRole
            )

            else -> this
        }
    }

    private fun analyzeExternalFulfillment(
        response: AgentResponse,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext,
        gateDecisions: List<GateDecision>
    ): ExternalFulfillmentAnalysis {
        val payload = response.payload as? ModulePayload.LixPayload
            ?: return ExternalFulfillmentAnalysis.NONE
        val dataScope = buildExternalDataScopeSummary(payload, constraints, roleContext)
        val quoteAnalysis = buildRoleAwareQuoteAnalysis(
            payload = payload,
            constraints = constraints,
            roleContext = roleContext,
            dataScopeSummary = dataScope
        )
        val approval = buildExternalApprovalSummary(
            response = response,
            constraints = constraints,
            gateDecisions = gateDecisions,
            quoteAnalysis = quoteAnalysis
        )
        val verification = buildExternalVerificationSummary(response, payload)
        val proof = buildExternalProofSummary(payload, quoteAnalysis, verification)
        val rollback = buildExternalRollbackSummary(response, payload)
        val dispute = buildExternalDisputeSummary(response, verification)
        val settlement = buildExternalSettlementSummary(
            response = response,
            roleImpactCodes = response.roleImpactReasonCodes
        )
        val reconciliation = buildReconciliationSummary(
            response = response,
            settlementSummary = settlement,
            disputeSummary = dispute,
            roleImpactCodes = response.roleImpactReasonCodes,
            updatedAtMs = nowMs()
        )
        val syncIssues = buildSyncIssues(
            response = response,
            settlementSummary = settlement,
            reconciliationSummary = reconciliation,
            disputeSummary = dispute,
            roleImpactCodes = response.roleImpactReasonCodes,
            updatedAtMs = nowMs()
        )
        val externalPayload = payload.copy(
            quotes = quoteAnalysis.quotes,
            providerSelectionSummary = quoteAnalysis.selectionSummary,
            providerPolicyDecisions = quoteAnalysis.providerPolicyDecisions,
            externalApprovalSummary = approval,
            externalDataScopeSummary = dataScope,
            externalVerificationSummary = verification,
            externalProofSummary = proof,
            externalSettlementSummary = settlement,
            externalRollbackSummary = rollback,
            externalDisputeSummary = dispute,
            reconciliationSummary = reconciliation,
            syncIssues = syncIssues
        )
        val reasonCodes = mergeRoleReasonCodes(
            quoteAnalysis.reasonCodes,
            approval.reasonCodes,
            dataScope.reasonCodes,
            verification.reasonCodes,
            proof.reasonCodes,
            settlement?.reasonCodes.orEmpty(),
            rollback.reasonCodes,
            dispute.reasonCodes,
            reconciliation?.reasonCodes.orEmpty(),
            syncIssues.flatMap { it.reasonCodes }
        )
        return ExternalFulfillmentAnalysis(
            payload = externalPayload,
            additionalRoleReasonCodes = reasonCodes
        )
    }

    private fun buildRoleAwareQuoteAnalysis(
        payload: ModulePayload.LixPayload,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext,
        dataScopeSummary: ExternalDataScopeSummary
    ): QuoteDecisionAnalysis {
        val baseQuotes = if (payload.quotes.isNotEmpty()) {
            payload.quotes
        } else {
            payload.capabilityCards.map { card ->
                Quote(
                    quoteId = "quote-${card.id.ifBlank { card.provider }}",
                    capabilityId = card.id,
                    supplier = card.provider.ifBlank { card.name },
                    price = card.priceEstimate ?: "not listed",
                    eta = card.eta ?: "unknown",
                    riskLevel = card.riskLevel,
                    proofMethod = card.proofMethod,
                    rollbackTerms = card.rollbackTerms,
                    disputeTerms = card.disputeTerms,
                    providerTrustFit = if (card.trusted) "high" else "medium",
                    rolePolicyFit = "unknown",
                    rolePolicyNotes = card.description.take(96)
                )
            }
        }
        if (baseQuotes.isEmpty()) {
            return QuoteDecisionAnalysis.EMPTY
        }

        val rolePolicy = roleContext.rolePolicyProfile
        val activeRole = roleContext.activeRole
        val autoApprovalBudget = rolePolicy.approvalPolicy.autoApprovalBudgetLimit
        val externalBudgetLimit = rolePolicy.approvalPolicy.maxExternalBudget
        val taskBudget = parseBudgetAmount(constraints.budget.orEmpty())
        val effectiveBudgetLimit = listOfNotNull(taskBudget, externalBudgetLimit).minOrNull()

        val evaluated = baseQuotes.mapIndexed { index, quote ->
            val priceValue = parseBudgetAmount(quote.price.orEmpty())
            val trustFit = computeProviderTrustFit(quote, rolePolicy)
            val roleFitScore = computeRolePolicyFitScore(
                quote = quote,
                activeRole = activeRole,
                rolePolicy = rolePolicy,
                trustFit = trustFit
            )
            val priceScore = when {
                priceValue == null -> 0.5
                effectiveBudgetLimit == null || effectiveBudgetLimit <= 0.0 -> (1.0 - priceValue / 100_000.0).coerceIn(0.0, 1.0)
                else -> (1.0 - (priceValue / effectiveBudgetLimit)).coerceIn(0.0, 1.0)
            }
            val etaScore = etaScore(quote.eta)
            val riskScore = when (quote.riskLevel.lowercase()) {
                "low" -> 1.0
                "medium" -> 0.65
                else -> 0.2
            }
            val proofScore = if (quote.proofMethod.contains("verification", ignoreCase = true) ||
                quote.proofMethod.contains("proof", ignoreCase = true)
            ) {
                1.0
            } else {
                0.5
            }
            val rollbackScore = if (
                quote.rollbackTerms.contains("rollback", ignoreCase = true) ||
                quote.disputeTerms.contains("dispute", ignoreCase = true)
            ) {
                1.0
            } else {
                0.35
            }
            var rankingScore = (
                (quote.rankingScore.takeIf { it > 0.0 } ?: 0.0) * 0.35 +
                    priceScore * 0.15 +
                    etaScore * 0.15 +
                    riskScore * 0.15 +
                    proofScore * 0.1 +
                    rollbackScore * 0.1
                )
                .coerceIn(0.0, 1.0)
            rankingScore = (rankingScore + roleFitScore * 0.35).coerceIn(0.0, 1.4)
            rankingScore = when (rolePolicy.preferences.externalFulfillmentPreference) {
                ExternalFulfillmentPreference.EXTERNAL_PREFERRED -> (rankingScore + 0.08).coerceAtMost(1.4)
                ExternalFulfillmentPreference.INTERNAL_FIRST -> (rankingScore - 0.08).coerceAtLeast(-1.0)
                ExternalFulfillmentPreference.BALANCED -> rankingScore
            }

            val reasonCodes = mutableListOf<String>(RoleReasonCodes.ROLE_QUOTE_COLLECTED)
            if (roleFitScore >= 0.75) {
                reasonCodes += RoleReasonCodes.ROLE_QUOTE_POLICY_FIT_APPLIED
            }
            if (trustFit == "high") {
                reasonCodes += RoleReasonCodes.ROLE_PROVIDER_PREFERRED
            }
            if (trustFit == "blocked") {
                reasonCodes += RoleReasonCodes.ROLE_PROVIDER_EXCLUDED
            }
            if (dataScopeSummary.reduced) {
                reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_REDUCED
            }
            if (dataScopeSummary.blocked) {
                reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_BLOCKED
            }
            val approvalRequired = rolePolicy.approvalPolicy.requiresConfirmationTokenForExternalSpend &&
                (autoApprovalBudget == null || priceValue == null || priceValue > autoApprovalBudget)
            if (approvalRequired) {
                reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_APPROVAL_REQUIRED
            }
            val denyReason = resolveProviderDenyReason(
                activeRole = activeRole,
                quote = quote,
                trustFit = trustFit,
                effectiveBudgetLimit = effectiveBudgetLimit,
                priceValue = priceValue,
                dataScopeBlocked = dataScopeSummary.blocked,
                approvalRequired = approvalRequired,
                constraints = constraints,
                rolePolicy = rolePolicy
            )
            if (denyReason != null) {
                reasonCodes += RoleReasonCodes.ROLE_PROVIDER_DENIED_BY_POLICY
                reasonCodes += RoleReasonCodes.ROLE_PROVIDER_EXCLUDED
                reasonCodes += RoleReasonCodes.ROLE_POLICY_DENIED
                if (denyReason == ProviderDenyReason.APPROVAL_DENIED || denyReason == ProviderDenyReason.APPROVAL_REQUIRED) {
                    reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_APPROVAL_DENIED
                }
                if (denyReason == ProviderDenyReason.DATA_SCOPE_BLOCKED) {
                    reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_BLOCKED
                }
                if (denyReason == ProviderDenyReason.PROOF_REQUIREMENT_UNMET) {
                    reasonCodes += RoleReasonCodes.ROLE_EXTERNAL_PROOF_MISSING
                }
                rankingScore = (rankingScore - 1.0).coerceAtLeast(-1.0)
            }

            val roleFitLabel = when {
                denyReason != null -> "denied"
                roleFitScore >= 0.75 -> "high"
                roleFitScore >= 0.45 -> "medium"
                else -> "low"
            }
            val policyNote = when (denyReason) {
                ProviderDenyReason.BUDGET_EXCEEDED -> "Denied by budget policy."
                ProviderDenyReason.RISK_EXCEEDED -> "Denied by risk policy."
                ProviderDenyReason.TRUST_MISMATCH -> "Denied by provider trust policy."
                ProviderDenyReason.DATA_SCOPE_BLOCKED -> "Denied because provider data scope is blocked."
                ProviderDenyReason.PROOF_REQUIREMENT_UNMET -> "Denied because proof requirements were not met."
                ProviderDenyReason.APPROVAL_REQUIRED -> "Awaiting approval before provider selection."
                ProviderDenyReason.APPROVAL_DENIED -> "Approval was denied by policy."
                ProviderDenyReason.POLICY_RESTRICTED -> "Denied by role policy restrictions."
                ProviderDenyReason.UNKNOWN, null -> "Role-aware comparison completed."
            }

            val enrichedQuote = quote.copy(
                providerTrustFit = trustFit,
                rolePolicyFit = roleFitLabel,
                rolePolicyNotes = policyNote,
                approvalRequired = approvalRequired,
                dataScopeSummary = dataScopeSummary.summary,
                providerDecision = if (denyReason == null) ProviderDecisionStatus.ALLOWED else ProviderDecisionStatus.DENIED,
                providerDenyReason = denyReason,
                reasonCodes = mergeRoleReasonCodes(quote.reasonCodes, reasonCodes),
                rankingScore = rankingScore
            )
            EvaluatedQuote(
                index = index,
                quote = enrichedQuote,
                rankingScore = rankingScore,
                denyReason = denyReason
            )
        }.sortedByDescending { it.rankingScore }

        val selected = when (activeRole) {
            UserRole.BUYER -> {
                evaluated
                    .asSequence()
                    .filter { it.denyReason == null }
                    .maxByOrNull { candidate ->
                        candidate.rankingScore + buyerAffordabilitySelectionBonus(
                            quote = candidate.quote,
                            effectiveBudgetLimit = effectiveBudgetLimit
                        )
                    }
            }

            else -> evaluated.firstOrNull { it.denyReason == null }
        }
        val finalizedQuotes = evaluated.map { evaluatedQuote ->
            when {
                selected == null -> evaluatedQuote.quote
                evaluatedQuote.quote.quoteId == selected.quote.quoteId -> evaluatedQuote.quote.copy(
                    providerDecision = ProviderDecisionStatus.SELECTED,
                    reasonCodes = mergeRoleReasonCodes(
                        evaluatedQuote.quote.reasonCodes,
                        listOfNotNull(
                            RoleReasonCodes.ROLE_PROVIDER_SELECTED,
                            if (activeRole == UserRole.BUYER) RoleReasonCodes.ROLE_RANKING_BIAS_APPLIED else null
                        )
                    )
                )

                evaluatedQuote.denyReason != null -> evaluatedQuote.quote
                else -> evaluatedQuote.quote.copy(providerDecision = ProviderDecisionStatus.DEPRIORITIZED)
            }
        }

        val providerDecisions = finalizedQuotes.map { quote ->
            ProviderPolicyDecision(
                providerId = quote.capabilityId.ifBlank { quote.quoteId },
                providerName = quote.supplier,
                decision = quote.providerDecision,
                denyReason = quote.providerDenyReason,
                reasonCodes = quote.reasonCodes,
                readableReason = quote.rolePolicyNotes.ifBlank { "No role-policy note provided." },
                activeRole = roleContext.activeRole,
                roleSource = roleContext.roleSource,
                approvalRequired = quote.approvalRequired,
                dataScopeSummary = quote.dataScopeSummary,
                proofRequirementSummary = quote.proofMethod
            )
        }

        val selectedQuote = finalizedQuotes.firstOrNull { it.providerDecision == ProviderDecisionStatus.SELECTED }
        val approvalStatus = when {
            finalizedQuotes.any { it.approvalRequired } && constraints.userConfirmationToken.isNullOrBlank() -> "required"
            finalizedQuotes.any { it.approvalRequired } -> "granted"
            else -> "not_required"
        }
        val quoteSummary = when {
            selectedQuote != null -> {
                "Collected ${finalizedQuotes.size} quote(s); selected ${selectedQuote.supplier} by role-aware policy fit."
            }
            finalizedQuotes.any { it.providerDecision == ProviderDecisionStatus.DENIED } ->
                "Collected ${finalizedQuotes.size} quote(s); all providers denied by current role policy."
            else -> "Collected ${finalizedQuotes.size} quote(s); selection is pending."
        }
        val selectionSummary = ProviderSelectionSummary(
            selectedProviderId = selectedQuote?.capabilityId?.ifBlank { selectedQuote.quoteId },
            selectedProviderName = selectedQuote?.supplier,
            selectionRationale = selectedQuote?.rolePolicyNotes ?: "No provider selected yet.",
            consideredProviderIds = finalizedQuotes.map { it.capabilityId.ifBlank { it.quoteId } },
            deniedProviderIds = finalizedQuotes.filter { it.providerDecision == ProviderDecisionStatus.DENIED }
                .map { it.capabilityId.ifBlank { it.quoteId } },
            decisionReasonCodes = finalizedQuotes.flatMap { it.reasonCodes }.distinct(),
            approvalStatus = approvalStatus,
            dataScopeSummary = dataScopeSummary.summary,
            proofRequirementSummary = selectedQuote?.proofMethod ?: "No provider selected yet.",
            verificationSummary = "Verification follows provider execution.",
            rollbackSummary = selectedQuote?.rollbackTerms ?: "Rollback terms pending provider selection.",
            disputeSummary = selectedQuote?.disputeTerms ?: "Dispute terms pending provider selection."
        )
        val reasonCodes = mergeRoleReasonCodes(
            finalizedQuotes.flatMap { it.reasonCodes },
            listOf(RoleReasonCodes.ROLE_QUOTE_COLLECTED),
            if (selectedQuote != null) listOf(RoleReasonCodes.ROLE_PROVIDER_SELECTED) else emptyList()
        )
        return QuoteDecisionAnalysis(
            quotes = finalizedQuotes,
            providerPolicyDecisions = providerDecisions,
            selectionSummary = selectionSummary,
            quoteSummary = quoteSummary,
            reasonCodes = reasonCodes
        )
    }

    private fun buyerAffordabilitySelectionBonus(
        quote: Quote,
        effectiveBudgetLimit: Double?
    ): Double {
        val priceValue = parseBudgetAmount(quote.price)
        if (priceValue == null || effectiveBudgetLimit == null || effectiveBudgetLimit <= 0.0) {
            return 0.0
        }
        val affordability = ((effectiveBudgetLimit - priceValue) / effectiveBudgetLimit)
            .coerceIn(-1.0, 1.0)
        return affordability * 0.8
    }

    private fun buildExternalApprovalSummary(
        response: AgentResponse,
        constraints: AgentRequestConstraints,
        gateDecisions: List<GateDecision>,
        quoteAnalysis: QuoteDecisionAnalysis
    ): ExternalApprovalSummary {
        val gateApproval = gateDecisions.firstOrNull { it.gate == GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN }
        val budgetGate = gateDecisions.firstOrNull { it.gate == GateType.GATE_R3_BUDGET_SCOPE_GUARD }
        val required = gateApproval?.decision != GateDecisionStatus.PASSED ||
            quoteAnalysis.quotes.any { it.approvalRequired }
        val denied = budgetGate?.decision == GateDecisionStatus.BLOCKED ||
            gateApproval?.decision == GateDecisionStatus.BLOCKED
        val granted = required && !denied &&
            (constraints.userConfirmationToken.isNullOrBlank().not() ||
                gateApproval?.decision == GateDecisionStatus.PASSED ||
                response.status == ResponseStatus.COMMITTED)
        val status = when {
            denied -> "denied"
            required && granted -> "granted"
            required -> "required"
            else -> "not_required"
        }
        val summary = when (status) {
            "denied" -> "Approval denied by role-aware external execution policy."
            "granted" -> "External approval granted under current role policy."
            "required" -> "External provider execution requires explicit approval."
            else -> "No external approval gate was required."
        }
        val reasonCodes = buildList {
            if (required) {
                add(RoleReasonCodes.ROLE_EXTERNAL_APPROVAL_REQUIRED)
                add(RoleReasonCodes.ROLE_APPROVAL_REQUIRED)
            }
            if (granted) {
                add(RoleReasonCodes.ROLE_EXTERNAL_APPROVAL_GRANTED)
            }
            if (denied) {
                add(RoleReasonCodes.ROLE_EXTERNAL_APPROVAL_DENIED)
                add(RoleReasonCodes.ROLE_POLICY_DENIED)
            }
        }
        return ExternalApprovalSummary(
            required = required,
            granted = granted,
            denied = denied,
            status = status,
            summary = summary,
            reasonCodes = reasonCodes
        )
    }

    private fun buildExternalDataScopeSummary(
        payload: ModulePayload.LixPayload,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext
    ): ExternalDataScopeSummary {
        val existing = payload.externalDataScopeSummary
        val policy = roleContext.rolePolicyProfile.dataPolicy
        val reducedByPolicy = policy.allowedScopes.size <= 1 || policy.sharingMode.contains("local_only", ignoreCase = true)
        val isExecutionStage = payload.stage.contains("accepted", ignoreCase = true) ||
            payload.stage.contains("delivery", ignoreCase = true) ||
            payload.stage.contains("executor", ignoreCase = true)
        val blockedByPolicy = isExecutionStage &&
            policy.sharingMode.contains("local_only", ignoreCase = true) &&
            constraints.userConfirmationToken.isNullOrBlank()
        val reduced = reducedByPolicy || existing?.reduced == true
        val blocked = blockedByPolicy || existing?.blocked == true
        val redactedFields = buildList {
            if (reducedByPolicy) {
                add("contact_details")
                add("free_text_personal_context")
            }
            addAll(existing?.redactedFields.orEmpty())
        }.distinct()
        val summary = when {
            blocked -> existing?.summary
                ?.takeIf { it.contains("blocked", ignoreCase = true) }
                ?: "Provider-facing data scope blocked by role policy until explicit confirmation is provided."
            reduced && redactedFields.isNotEmpty() -> existing?.summary
                ?.takeIf {
                    it.contains("reduced", ignoreCase = true) ||
                        it.contains("redact", ignoreCase = true)
                }
                ?: "Provider-facing data scope reduced; sensitive fields were redacted."
            reduced -> existing?.summary
                ?.takeIf { it.contains("reduced", ignoreCase = true) }
                ?: "Provider-facing data scope reduced to approved fields only."
            else -> existing?.summary
                ?.takeIf { it.isNotBlank() }
                ?: "Provider-facing data scope follows role-approved policy."
        }
        val reasonCodes = buildList {
            addAll(existing?.reasonCodes.orEmpty())
            if (reduced) {
                add(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_REDUCED)
                add(RoleReasonCodes.ROLE_DATA_SCOPE_REDUCED)
            }
            if (blocked) {
                add(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_BLOCKED)
                add(RoleReasonCodes.ROLE_POLICY_DENIED)
            }
            if (redactedFields.isNotEmpty()) {
                add(RoleReasonCodes.ROLE_FIELD_REDACTED)
            }
        }
        return ExternalDataScopeSummary(
            sharingMode = existing?.sharingMode?.takeIf { it.isNotBlank() } ?: policy.sharingMode,
            reduced = reduced,
            blocked = blocked,
            summary = summary,
            allowedScopes = existing?.allowedScopes?.takeIf { it.isNotEmpty() } ?: policy.allowedScopes,
            redactedFields = redactedFields,
            reasonCodes = reasonCodes.distinct()
        )
    }

    private fun projectProviderFacingDataScope(
        query: String,
        roleContext: RoleExecutionContext
    ): ProviderFacingDataScopeProjection {
        val policy = roleContext.rolePolicyProfile.dataPolicy
        val emailRegex = Regex("""[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}""")
        val phoneRegex = Regex("""\+?\d[\d\s\-]{7,}\d""")
        val sensitiveRegex = Regex("""(?i)\b(passport|id number|ssn|bank account|credit card|home address)\b""")
        val containsSensitive = emailRegex.containsMatchIn(query) ||
            phoneRegex.containsMatchIn(query) ||
            sensitiveRegex.containsMatchIn(query)

        var projected = query
        val redactedFields = mutableListOf<String>()
        val reduced = policy.allowedScopes.size <= 1 || policy.sharingMode.contains("local_only", ignoreCase = true)
        if (reduced && query.isNotBlank()) {
            if (emailRegex.containsMatchIn(projected)) {
                projected = projected.replace(emailRegex, "[REDACTED_EMAIL]")
                redactedFields += "email"
            }
            if (phoneRegex.containsMatchIn(projected)) {
                projected = projected.replace(phoneRegex, "[REDACTED_PHONE]")
                redactedFields += "phone"
            }
            if (sensitiveRegex.containsMatchIn(projected)) {
                projected = projected.replace(sensitiveRegex, "[REDACTED_SENSITIVE_FIELD]")
                redactedFields += "sensitive_field"
            }
        }

        val blocked = policy.sharingMode.contains("local_only", ignoreCase = true) &&
            roleContext.activeRole == UserRole.PARENT &&
            containsSensitive
        val summary = when {
            blocked -> "Provider-facing data scope is blocked for sensitive fields under Parent role."
            redactedFields.isNotEmpty() -> "Provider-facing data scope reduced; sensitive fields were redacted."
            reduced -> "Provider-facing data scope reduced to minimal role-approved context."
            else -> "Provider-facing data scope allows role-approved task context."
        }
        val reasonCodes = buildList {
            if (reduced) {
                add(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_REDUCED)
                add(RoleReasonCodes.ROLE_DATA_SCOPE_REDUCED)
            }
            if (blocked) {
                add(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_BLOCKED)
                add(RoleReasonCodes.ROLE_POLICY_DENIED)
            }
            if (redactedFields.isNotEmpty()) {
                add(RoleReasonCodes.ROLE_FIELD_REDACTED)
            }
        }
        return ProviderFacingDataScopeProjection(
            providerQuery = projected,
            blocked = blocked,
            summary = ExternalDataScopeSummary(
                sharingMode = policy.sharingMode,
                reduced = reduced,
                blocked = blocked,
                summary = summary,
                allowedScopes = policy.allowedScopes,
                redactedFields = redactedFields.distinct(),
                reasonCodes = reasonCodes
            )
        )
    }

    private fun buildExternalVerificationSummary(
        response: AgentResponse,
        payload: ModulePayload.LixPayload
    ): ExternalVerificationSummary {
        val proof = payload.verificationProof
        val status = when {
            response.status == ResponseStatus.VERIFYING -> "pending"
            response.status == ResponseStatus.DISPUTED -> "failed"
            response.status == ResponseStatus.PARTIAL && proof != null -> "partial"
            response.validationReport?.passed == true || proof?.passed == true -> "passed"
            response.validationReport?.passed == false || proof?.passed == false -> "failed"
            else -> "not_required"
        }
        val summary = when (status) {
            "pending" -> "External verification is in progress."
            "partial" -> "Verification is partial and awaiting additional proof."
            "passed" -> "External verification passed."
            "failed" -> "External verification failed."
            else -> "No external verification step was required."
        }
        val reasonCodes = buildList {
            if (status == "failed") add(RoleReasonCodes.ROLE_EXTERNAL_VERIFICATION_FAILED)
        }
        return ExternalVerificationSummary(
            status = status,
            passed = status == "passed",
            partial = status == "partial",
            summary = summary,
            reasonCodes = reasonCodes
        )
    }

    private fun buildExternalProofSummary(
        payload: ModulePayload.LixPayload,
        quoteAnalysis: QuoteDecisionAnalysis,
        verificationSummary: ExternalVerificationSummary
    ): ExternalProofSummary {
        val required = payload.intentContract?.proofRequired == true || quoteAnalysis.quotes.isNotEmpty()
        val provided = payload.verificationProof != null ||
            quoteAnalysis.quotes.any { it.proofMethod.contains("verification", ignoreCase = true) }
        val proofMethods = quoteAnalysis.quotes.map { it.proofMethod }.filter { it.isNotBlank() }.distinct()
            .take(3)
        val summary = when {
            provided -> "Provider proof returned and attached for verification."
            required -> "Proof is required but missing for current external execution."
            else -> "No external proof requirement was recorded."
        }
        val reasonCodes = buildList {
            if (required) add(RoleReasonCodes.ROLE_EXTERNAL_PROOF_REQUIRED)
            if (required && !provided) add(RoleReasonCodes.ROLE_EXTERNAL_PROOF_MISSING)
            if (verificationSummary.status == "failed") add(RoleReasonCodes.ROLE_EXTERNAL_VERIFICATION_FAILED)
        }
        return ExternalProofSummary(
            required = required,
            provided = provided,
            summary = summary,
            proofMethods = proofMethods,
            reasonCodes = reasonCodes
        )
    }

    private fun buildExternalRollbackSummary(
        response: AgentResponse,
        payload: ModulePayload.LixPayload
    ): ExternalRollbackSummary {
        val available = payload.rollbackPolicy != null || response.finalDelivery?.rollbackPlan?.isNotEmpty() == true
        val triggered = response.status == ResponseStatus.ROLLED_BACK
        val failed = response.summary?.contains("rollback failed", ignoreCase = true) == true ||
            response.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_FAILED)
        val summary = when {
            triggered -> "Rollback triggered and applied to external execution."
            failed -> "Rollback failed because remote settlement rejected the rollback request."
            available -> "Rollback remains available under provider and platform policy."
            else -> "No rollback terms were recorded."
        }
        val reasonCodes = buildList {
            if (available) add(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_AVAILABLE)
            if (triggered) add(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_TRIGGERED)
            if (failed) add(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_FAILED)
        }
        return ExternalRollbackSummary(
            available = available,
            triggered = triggered,
            summary = summary,
            reasonCodes = reasonCodes
        )
    }

    private fun buildExternalDisputeSummary(
        response: AgentResponse,
        verificationSummary: ExternalVerificationSummary
    ): ExternalDisputeSummary {
        val opened = response.status == ResponseStatus.DISPUTED || verificationSummary.status == "failed"
        val text = buildString {
            append(response.summary.orEmpty())
            append(' ')
            append(response.nextAction.orEmpty())
        }
        val syncPending = response.summary
            ?.contains("sync pending", ignoreCase = true) == true ||
            response.summary?.contains("gateway sync", ignoreCase = true) == true
        val acknowledged = text.contains("acknowledged", ignoreCase = true)
        val resolved = text.contains("resolved", ignoreCase = true)
        val closed = text.contains("closed", ignoreCase = true)
        val issueType = response.validationReport?.issues?.firstOrNull()
            ?: response.gateDecisions.firstOrNull { it.decision == GateDecisionStatus.BLOCKED }?.reason
        val summary = when {
            opened && syncPending -> "Dispute opened locally; gateway sync pending."
            opened && acknowledged -> "Dispute acknowledged by provider and awaiting final resolution."
            opened && resolved -> "Dispute resolved and evidence retained."
            opened && closed -> "Dispute closed with durable receipt trace."
            opened -> "Dispute path is open with traceable evidence."
            else -> "No active dispute."
        }
        val reasonCodes = buildList {
            if (opened) add(RoleReasonCodes.ROLE_EXTERNAL_DISPUTE_OPENED)
            if (syncPending) add(RoleReasonCodes.ROLE_EXTERNAL_DISPUTE_SYNC_PENDING)
            if (acknowledged) add(RoleReasonCodes.ROLE_EXTERNAL_DISPUTE_ACKNOWLEDGED)
            if (resolved) add(RoleReasonCodes.ROLE_EXTERNAL_DISPUTE_RESOLVED)
            if (closed) add(RoleReasonCodes.ROLE_EXTERNAL_DISPUTE_CLOSED)
        }
        return ExternalDisputeSummary(
            opened = opened,
            summary = summary,
            issueType = issueType,
            reasonCodes = reasonCodes
        )
    }

    private fun resolveProviderDenyReason(
        activeRole: UserRole,
        quote: Quote,
        trustFit: String,
        effectiveBudgetLimit: Double?,
        priceValue: Double?,
        dataScopeBlocked: Boolean,
        approvalRequired: Boolean,
        constraints: AgentRequestConstraints,
        rolePolicy: RolePolicyProfile
    ): ProviderDenyReason? {
        if (!rolePolicy.preferences.externalFulfillmentAllowed) {
            return ProviderDenyReason.POLICY_RESTRICTED
        }
        if (dataScopeBlocked) return ProviderDenyReason.DATA_SCOPE_BLOCKED
        if (effectiveBudgetLimit != null && priceValue != null && priceValue > effectiveBudgetLimit) {
            return ProviderDenyReason.BUDGET_EXCEEDED
        }
        if (trustFit == "blocked") {
            return ProviderDenyReason.POLICY_RESTRICTED
        }
        if (activeRole == UserRole.PARENT && quote.riskLevel.equals("high", ignoreCase = true)) {
            return ProviderDenyReason.RISK_EXCEEDED
        }
        if ((activeRole == UserRole.WORK || activeRole == UserRole.PARENT) && trustFit == "low") {
            return ProviderDenyReason.TRUST_MISMATCH
        }
        if ((activeRole == UserRole.WORK || activeRole == UserRole.PARENT) &&
            !quote.proofMethod.contains("proof", ignoreCase = true) &&
            !quote.proofMethod.contains("verification", ignoreCase = true)
        ) {
            return ProviderDenyReason.PROOF_REQUIREMENT_UNMET
        }
        if (approvalRequired && constraints.userConfirmationToken.isNullOrBlank()) {
            return ProviderDenyReason.APPROVAL_REQUIRED
        }
        return null
    }

    private fun computeProviderTrustFit(
        quote: Quote,
        rolePolicy: RolePolicyProfile
    ): String {
        val supplierLower = quote.supplier.lowercase()
        val proofLower = quote.proofMethod.lowercase()
        val rollbackLower = "${quote.rollbackTerms} ${quote.disputeTerms}".lowercase()
        val tagText = "$supplierLower $proofLower $rollbackLower ${quote.riskLevel.lowercase()}"
        val blockedHit = rolePolicy.preferences.blockedProviderTags.any { tag ->
            tag.isNotBlank() && tagText.contains(tag.lowercase())
        }
        if (blockedHit) return "blocked"
        val trustedHit = rolePolicy.preferences.trustedProviderTags.any { tag ->
            tag.isNotBlank() && tagText.contains(tag.lowercase())
        }
        if (trustedHit) return "high"
        return when {
            supplierLower.contains("trusted") ||
                supplierLower.contains("verified") ||
                proofLower.contains("verification") ||
                rollbackLower.contains("rollback") && rollbackLower.contains("dispute") -> "high"

            quote.riskLevel.equals("high", ignoreCase = true) ||
                supplierLower.contains("unknown") -> "low"

            else -> "medium"
        }
    }

    private fun computeRolePolicyFitScore(
        quote: Quote,
        activeRole: UserRole,
        rolePolicy: RolePolicyProfile,
        trustFit: String
    ): Double {
        var score = when (trustFit) {
            "high" -> 0.8
            "blocked" -> 0.05
            "medium" -> 0.55
            else -> 0.25
        }
        val riskTolerance = normalizeRiskTolerance(rolePolicy.preferences.riskToleranceDefault)
        val riskLevel = quote.riskLevel.lowercase()
        if (riskTolerance == "low" && riskLevel == "high") {
            score -= 0.25
        } else if (riskTolerance == "high" && riskLevel == "high") {
            score += 0.12
        }
        if (trustFit == "blocked") {
            score -= 0.5
        }
        when (activeRole) {
            UserRole.WORK -> {
                if (quote.proofMethod.contains("verification", ignoreCase = true)) score += 0.15
                if (quote.rollbackTerms.contains("rollback", ignoreCase = true)) score += 0.1
            }

            UserRole.BUYER -> {
                if (quote.disputeTerms.contains("dispute", ignoreCase = true)) score += 0.15
                if (quote.rollbackTerms.contains("rollback", ignoreCase = true)) score += 0.1
            }

            UserRole.TRAVELER -> {
                score += etaScore(quote.eta) * 0.2
            }

            UserRole.PARENT -> {
                if (quote.riskLevel.equals("low", ignoreCase = true)) score += 0.2
                if (trustFit == "high") score += 0.15
            }

            UserRole.CUSTOM,
            UserRole.PERSONAL -> score += 0.05
        }
        val maxCostTier = normalizeCostTier(rolePolicy.preferences.maxCostPerStepDefault)
        if (maxCostTier != null) {
            val quoteTier = normalizeCostTier(quote.price)
            if (quoteTier != null && costTierRank(quoteTier) > costTierRank(maxCostTier)) {
                score -= 0.2
            }
        }
        return score.coerceIn(0.0, 1.2)
    }

    private fun etaScore(eta: String): Double {
        val normalized = eta.trim().lowercase()
        val value = when {
            normalized.endsWith("m") -> normalized.dropLast(1).toDoubleOrNull()?.coerceAtLeast(1.0)
            normalized.endsWith("h") -> normalized.dropLast(1).toDoubleOrNull()?.times(60.0)
            normalized.endsWith("d") -> normalized.dropLast(1).toDoubleOrNull()?.times(24.0 * 60.0)
            else -> null
        } ?: return 0.4
        return when {
            value <= 60.0 -> 1.0
            value <= 240.0 -> 0.8
            value <= 720.0 -> 0.55
            else -> 0.3
        }
    }

    private fun ExternalFulfillmentAnalysis.apply(response: AgentResponse): AgentResponse {
        val payload = payload ?: return response
        return response.copy(payload = payload)
    }

    private fun recordExternalFulfillmentTelemetry(response: AgentResponse) {
        val receipt = response.executionReceipt ?: return
        val payload = response.payload as? ModulePayload.LixPayload ?: return
        val proofSummary = receipt.externalProofSummary
        val dispute = receipt.externalDisputeSummary
        synchronized(externalTelemetryLock) {
            externalTelemetryCounters.merge("external_receipt_generation_rate", 1, Int::plus)
            if (receipt.providerPolicyDecisions.any { it.decision == ProviderDecisionStatus.DENIED }) {
                externalTelemetryCounters.merge("provider_denied_by_role_policy_rate", 1, Int::plus)
            }
            if (receipt.externalApprovalSummary?.required == true) {
                externalTelemetryCounters.merge("approval_required_rate_by_role_for_external_runs", 1, Int::plus)
            }
            if (receipt.externalDataScopeSummary?.reduced == true || receipt.externalDataScopeSummary?.blocked == true) {
                externalTelemetryCounters.merge("external_data_scope_reduction_rate_by_role", 1, Int::plus)
            }
            if (proofSummary?.required == true && !proofSummary.provided) {
                externalTelemetryCounters.merge("proof_missing_rate_by_role", 1, Int::plus)
            }
            if (receipt.externalVerificationSummary?.status == "failed") {
                externalTelemetryCounters.merge("verification_failure_rate_by_role", 1, Int::plus)
            }
            if (receipt.externalRollbackSummary?.available == true) {
                externalTelemetryCounters.merge("rollback_receipt_coverage", 1, Int::plus)
            }
            if (receipt.externalDisputeSummary?.opened == true) {
                externalTelemetryCounters.merge("dispute_traceability_coverage", 1, Int::plus)
            }
            if (receipt.externalSettlementSummary?.syncState == SettlementSyncState.SYNC_PENDING) {
                externalTelemetryCounters.merge("settlement_sync_pending_rate", 1, Int::plus)
            }
            if (receipt.reconciliationSummary?.mismatchDetected == true) {
                externalTelemetryCounters.merge("settlement_reconciliation_mismatch_rate", 1, Int::plus)
            }
            if (receipt.reconciliationSummary?.retryScheduled == true) {
                externalTelemetryCounters.merge("reconciliation_retry_scheduled_rate", 1, Int::plus)
            }
            if (receipt.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED)) {
                externalTelemetryCounters.merge("duplicate_callback_ignored_rate", 1, Int::plus)
            }
            if (receipt.externalRollbackSummary?.summary?.contains("failed", ignoreCase = true) == true) {
                externalTelemetryCounters.merge("rollback_failure_rate", 1, Int::plus)
            }
            if (receipt.externalRollbackSummary?.triggered == true || response.status == ResponseStatus.ROLLED_BACK) {
                externalTelemetryCounters.merge("rollback_success_rate", 1, Int::plus)
            }
            if (dispute?.summary?.contains("sync pending", ignoreCase = true) == true) {
                externalTelemetryCounters.merge("dispute_ack_delay_rate", 1, Int::plus)
            }
            if (dispute?.summary?.contains("resolved", ignoreCase = true) == true ||
                dispute?.summary?.contains("closed", ignoreCase = true) == true
            ) {
                externalTelemetryCounters.merge("dispute_resolution_rate", 1, Int::plus)
            }
            if (dispute?.opened == true &&
                dispute.summary.contains("resolved", ignoreCase = true).not() &&
                dispute.summary.contains("closed", ignoreCase = true).not()
            ) {
                externalTelemetryCounters.merge("unresolved_dispute_backlog", 1, Int::plus)
            }
            if (receipt.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_TIMEOUT)) {
                externalTelemetryCounters.merge("provider_ack_timeout_rate", 1, Int::plus)
            }
            if (payload.quotes.isNotEmpty()) {
                externalTelemetryCounters.merge("quote_selection_divergence_by_role", 1, Int::plus)
            }
        }
    }

    private fun AgentResponse.withExecutionReceipt(receipt: ExecutionReceipt): AgentResponse {
        return copy(
            executionReceipt = receipt,
            payload = payload.withExecutionReceipt(receipt)
        )
    }

    private fun ModulePayload.withExecutionReceipt(receipt: ExecutionReceipt): ModulePayload {
        return when (this) {
            ModulePayload.NonePayload -> this
            is ModulePayload.ChatPayload -> {
                val track = taskTrack
                copy(
                    taskTrack = track?.copy(
                        executionReceipt = track.executionReceipt ?: receipt
                    )
                )
            }

            else -> this
        }
    }

    private fun buildExecutionReceipt(
        response: AgentResponse,
        request: AgentRequest,
        constraints: AgentRequestConstraints,
        policySnapshot: RolePolicySnapshot?,
        startMs: Long,
        updatedAtMs: Long
    ): ExecutionReceipt {
        val roleImpactCodes = response.roleImpactReasonCodes
        val existingReceipt = response.executionReceipt
        val workflowRolloutState = existingReceipt?.workflowPolicyRolloutState
        val lixPayload = response.payload as? ModulePayload.LixPayload
        val externalApprovalSummary = lixPayload?.externalApprovalSummary
        val externalDataScopeSummary = lixPayload?.externalDataScopeSummary
        val externalVerificationSummary = lixPayload?.externalVerificationSummary
        val externalProofSummary = lixPayload?.externalProofSummary
        val externalSettlementSummary = lixPayload?.externalSettlementSummary
            ?: buildExternalSettlementSummary(response, roleImpactCodes)
        val externalRollbackSummary = lixPayload?.externalRollbackSummary
        val externalDisputeSummary = lixPayload?.externalDisputeSummary
        val reconciliationSummary = lixPayload?.reconciliationSummary
            ?: buildReconciliationSummary(response, externalSettlementSummary, externalDisputeSummary, roleImpactCodes, updatedAtMs)
        val syncIssues = (lixPayload?.syncIssues ?: buildSyncIssues(
            response = response,
            settlementSummary = externalSettlementSummary,
            reconciliationSummary = reconciliationSummary,
            disputeSummary = externalDisputeSummary,
            roleImpactCodes = roleImpactCodes,
            updatedAtMs = updatedAtMs
        ))
            .distinctBy { "${it.issueType}:${it.providerId}:${it.summary}" }
            .take(6)
        val providerSelectionSummary = lixPayload?.providerSelectionSummary
        val providerPolicyDecisions = lixPayload?.providerPolicyDecisions.orEmpty()
        val roleImpactSummary = buildRoleImpactSummary(roleImpactCodes)
        val approvalSummary = externalApprovalSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: buildApprovalSummary(response, roleImpactCodes)
        val dataScopeSummary = externalDataScopeSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: buildDataScopeSummary(response, roleImpactCodes)
        val providerSummary = buildProviderSummary(response, roleImpactCodes)
        val quoteSummary = buildQuoteSummary(response)
        val verificationSummary = externalVerificationSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: buildVerificationSummary(response)
        val proofLinks = collectProofLinks(response)
        val proofSummary = externalProofSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: buildProofSummary(response, proofLinks)
        val rollbackSummary = externalRollbackSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: buildRollbackSummary(response)
        val issueSummary = buildIssueSummary(response) ?: externalDisputeSummary?.summary
        val selectedCapabilityIds = collectSelectedCapabilityIds(response)
        val blockedCapabilityIds = collectBlockedCapabilityIds(response)
        val selectedProviderId = resolveSelectedProviderId(response)
        val artifactReferences = collectArtifactReferences(response)
        val completedAt = if (response.status.isTerminalForReceipt()) updatedAtMs else null
        val constraintPrecedenceSummary = buildConstraintPrecedenceSummary(constraints)
        val rolloutPromotionCandidate = workflowRolloutState?.promotionCandidate
            ?: existingReceipt?.rolloutPromotionCandidate
        val rolloutPromotionReadiness = workflowRolloutState?.promotionReadinessSummary
            ?: existingReceipt?.rolloutPromotionReadiness
        val crossWaveAnalyticsSummary = workflowRolloutState?.crossWaveAnalyticsSummary
            ?: existingReceipt?.crossWaveAnalyticsSummary
        val windowImpactSummary = workflowRolloutState?.windowImpactSummary
            ?: existingReceipt?.windowImpactSummary
        val latestPromotionOperation = workflowRolloutState?.promotionOperationRecords
            ?.maxByOrNull { it.timestampMs }
            ?: existingReceipt?.rolloutPromotionOperation
        val programCoordination = workflowRolloutState?.programCoordination
            ?: existingReceipt?.programCoordination
        val crossProgramGovernanceSummary = workflowRolloutState?.crossProgramGovernanceSummary
            ?: existingReceipt?.crossProgramGovernanceSummary
        val rolloutPromotionReadinessSummaryText = rolloutPromotionReadiness
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.rolloutPromotionReadinessSummary
        val crossWaveSummaryText = crossWaveAnalyticsSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.crossWaveSummary
        val windowImpactSummaryText = windowImpactSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.windowImpactReadableSummary
        val promotionOperationSummaryText = latestPromotionOperation
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: workflowRolloutState?.promotionOperationSummary
                ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.rolloutPromotionOperationSummary
        val programCoordinationSummaryText = workflowRolloutState?.programCoordinationSummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.programCoordinationSummary
        val crossProgramSummaryText = crossProgramGovernanceSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.crossProgramSummary
        val programEscalationSummaryText = programCoordination
            ?.escalation
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.programEscalationSummary
        val governanceCapacityPool = workflowRolloutState?.governanceCapacityPool
            ?: existingReceipt?.governanceCapacityPool
        val approvalQueuePressure = workflowRolloutState?.approvalQueuePressure
            ?: existingReceipt?.approvalQueuePressure
        val approvalBalancingDecision = workflowRolloutState?.approvalBalancingDecision
            ?: existingReceipt?.approvalBalancingDecision
        val approvalAssignmentRecommendation = workflowRolloutState?.approvalAssignmentRecommendation
            ?: existingReceipt?.approvalAssignmentRecommendation
        val capacityAwarePromotionDecision = workflowRolloutState?.capacityAwarePromotionDecision
            ?: existingReceipt?.capacityAwarePromotionDecision
        val portfolioCapacitySnapshot = workflowRolloutState?.portfolioCapacitySnapshot
            ?: existingReceipt?.portfolioCapacitySnapshot
        val programPortfolioSummary = workflowRolloutState?.programPortfolioSummary
            ?: existingReceipt?.programPortfolioSummary
        val approvalLoadSummaryText = workflowRolloutState?.approvalLoadSummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.approvalLoadSummary
        val capacityBlockSummaryText = workflowRolloutState?.capacityBlockSummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.capacityBlockSummary
        val policyBlockSummaryText = workflowRolloutState?.policyBlockSummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.policyBlockSummary
        val capacityBalancingSummaryText = workflowRolloutState?.capacityBalancingSummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.capacityBalancingSummary
        val portfolioCapacitySummaryText = workflowRolloutState?.portfolioCapacitySummary
            ?.takeIf { it.isNotBlank() }
            ?: existingReceipt?.portfolioCapacitySummary
        val events = buildReceiptEvents(
            response = response,
            approvalSummary = approvalSummary,
            dataScopeSummary = dataScopeSummary,
            providerSummary = providerSummary,
            quoteSummary = quoteSummary,
            verificationSummary = verificationSummary,
            proofSummary = proofSummary,
            rollbackSummary = rollbackSummary,
            settlementSummary = externalSettlementSummary,
            reconciliationSummary = reconciliationSummary,
            policySnapshot = policySnapshot,
            disputeSummary = externalDisputeSummary?.summary,
            issueSummary = issueSummary,
            startMs = startMs,
            updatedAtMs = updatedAtMs
        )
        val mergedEvents = (
            events +
                buildPolicyPromotionEvents(existingReceipt, updatedAtMs) +
                buildRolloutPromotionEvents(
                    readiness = rolloutPromotionReadiness,
                    crossWave = crossWaveAnalyticsSummary,
                    windowImpact = windowImpactSummary,
                    operation = latestPromotionOperation,
                    programCoordination = programCoordination,
                    crossProgram = crossProgramGovernanceSummary,
                    updatedAtMs = updatedAtMs
                )
            )
            .distinctBy { "${it.type}:${it.detail}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(MAX_LEDGER_EVENTS_PER_RUN)

        return ExecutionReceipt(
            runId = response.traceId,
            intentSummary = request.rawText.trim().ifBlank {
                response.summary?.trim().orEmpty()
            }.ifBlank {
                constraints.acceptanceCriteria.orEmpty()
            },
            status = response.status,
            activeRole = response.activeRole,
            roleSource = response.roleSource,
            delegationMode = response.delegationMode,
            roleImpactReasonCodes = roleImpactCodes,
            roleImpactSummary = roleImpactSummary,
            approvalSummary = approvalSummary,
            dataScopeSummary = dataScopeSummary,
            providerSummary = providerSummary,
            quoteSummary = quoteSummary,
            verificationSummary = verificationSummary,
            proofSummary = proofSummary,
            rollbackSummary = rollbackSummary,
            policySnapshotId = policySnapshot?.snapshotId,
            policySnapshotVersion = policySnapshot?.policyVersion,
            constraintPrecedenceSummary = constraintPrecedenceSummary,
            startedAt = startMs,
            updatedAt = updatedAtMs,
            completedAt = completedAt,
            roleChangeReason = response.roleChangeReason,
            selectedCapabilityIds = selectedCapabilityIds,
            blockedCapabilityIds = blockedCapabilityIds,
            selectedProviderId = selectedProviderId,
            providerSelectionSummary = providerSelectionSummary,
            providerPolicyDecisions = providerPolicyDecisions,
            externalApprovalSummary = externalApprovalSummary,
            externalDataScopeSummary = externalDataScopeSummary,
            externalVerificationSummary = externalVerificationSummary,
            externalProofSummary = externalProofSummary,
            externalSettlementSummary = externalSettlementSummary,
            externalRollbackSummary = externalRollbackSummary,
            externalDisputeSummary = externalDisputeSummary,
            reconciliationSummary = reconciliationSummary,
            syncIssues = syncIssues,
            proofLinks = proofLinks,
            artifactReferences = artifactReferences,
            nextActionSummary = response.nextAction?.takeIf { it.isNotBlank() },
            issueSummary = issueSummary,
            workflowPolicySummary = existingReceipt?.workflowPolicySummary,
            workflowPolicyPackId = existingReceipt?.workflowPolicyPackId,
            workflowPolicyPackVersion = existingReceipt?.workflowPolicyPackVersion,
            workflowPolicyBindingId = existingReceipt?.workflowPolicyBindingId,
