            workflowPolicyPrecedenceSource = existingReceipt?.workflowPolicyPrecedenceSource,
            workflowPolicyResolutionSummary = existingReceipt?.workflowPolicyResolutionSummary,
            workflowPolicyResolutionReasonCodes = existingReceipt?.workflowPolicyResolutionReasonCodes.orEmpty(),
            workflowSimulationOnly = existingReceipt?.workflowSimulationOnly,
            workflowPolicyRolloutState = existingReceipt?.workflowPolicyRolloutState,
