    private fun buildPolicyPromotionEvents(
        existingReceipt: ExecutionReceipt?,
        updatedAtMs: Long
    ): List<ExecutionReceiptEvent> {
        if (existingReceipt == null) return emptyList()
        val events = mutableListOf<ExecutionReceiptEvent>()
        existingReceipt.policyPromotionRequest
            ?.takeIf { it.requestId.isNotBlank() }
            ?.let { request ->
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.POLICY_PROMOTION_REQUESTED,
                    title = "Policy promotion requested",
                    detail = request.summary.ifBlank { "Policy promotion request was submitted." },
                    timestampMs = request.requestedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
        existingReceipt.policyPromotionDecision
            ?.takeIf { it.decisionId.isNotBlank() || it.status != PolicyPromotionStatus.NOT_REQUESTED }
            ?.let { decision ->
                val eventType = when (decision.status) {
                    PolicyPromotionStatus.APPROVED -> ExecutionReceiptEventType.POLICY_PROMOTION_APPROVED
                    PolicyPromotionStatus.REJECTED,
                    PolicyPromotionStatus.BLOCKED -> ExecutionReceiptEventType.POLICY_PROMOTION_REJECTED
                    PolicyPromotionStatus.ADVANCED -> ExecutionReceiptEventType.POLICY_ROLLOUT_ADVANCED
                    else -> null
                } ?: return@let
                val title = when (eventType) {
                    ExecutionReceiptEventType.POLICY_PROMOTION_APPROVED -> "Policy promotion approved"
                    ExecutionReceiptEventType.POLICY_PROMOTION_REJECTED -> "Policy promotion rejected"
                    ExecutionReceiptEventType.POLICY_ROLLOUT_ADVANCED -> "Policy rollout advanced"
                    else -> "Policy promotion updated"
                }
                events += ExecutionReceiptEvent(
                    type = eventType,
                    title = title,
                    detail = decision.summary.ifBlank { title },
                    timestampMs = decision.decidedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
        existingReceipt.policyPromotionReadiness
            ?.takeIf { it.summary.isNotBlank() || it.blockers.isNotEmpty() }
            ?.let { readiness ->
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.POLICY_PROMOTION_READINESS_EVALUATED,
                    title = "Policy promotion readiness evaluated",
                    detail = readiness.summary.ifBlank {
                        "Readiness is ${readiness.status.name.lowercase().replace('_', ' ')}."
                    },
                    timestampMs = readiness.evaluatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
        }
        return events
    }

    private fun buildRolloutPromotionEvents(
        readiness: RolloutPromotionReadinessSummary?,
        crossWave: CrossWaveAnalyticsSummary?,
        windowImpact: WindowImpactSummary?,
        operation: RolloutPromotionOperationRecord?,
        programCoordination: RolloutProgramCoordinationRecord?,
        crossProgram: CrossProgramGovernanceSummary?,
        updatedAtMs: Long
    ): List<ExecutionReceiptEvent> {
        val events = mutableListOf<ExecutionReceiptEvent>()
        readiness?.let { readinessSummary ->
            val eventType = when (readinessSummary.status) {
                RolloutPromotionReadinessStatus.READY,
                RolloutPromotionReadinessStatus.READY_WITH_CAUTION ->
                    ExecutionReceiptEventType.ROLLOUT_PROMOTION_READY

                else ->
                    ExecutionReceiptEventType.ROLLOUT_PROMOTION_BLOCKED
            }
            events += ExecutionReceiptEvent(
                type = eventType,
                title = if (eventType == ExecutionReceiptEventType.ROLLOUT_PROMOTION_READY) {
                    "Rollout promotion ready"
                } else {
                    "Rollout promotion blocked"
                },
                detail = readinessSummary.summary.ifBlank {
                    "Promotion readiness is ${readinessSummary.status.name.lowercase().replace('_', ' ')}."
                },
                timestampMs = readinessSummary.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
            )
        }
        crossWave
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?.let { summary ->
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.CROSS_WAVE_ANALYTICS_UPDATED,
                    title = "Cross-wave analytics updated",
                    detail = summary,
                    timestampMs = crossWave.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
        windowImpact
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?.let { summary ->
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.WINDOW_IMPACT_EVALUATED,
                    title = "Window impact evaluated",
                    detail = summary,
                    timestampMs = windowImpact.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
        operation?.let { operationRecord ->
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLOUT_PROMOTION_OPERATION_RECORDED,
                title = "Rollout promotion operation recorded",
                detail = operationRecord.summary.ifBlank {
                    "Operation ${operationRecord.type.name.lowercase().replace('_', ' ')} " +
                        "is ${operationRecord.status.name.lowercase().replace('_', ' ')}."
                },
                timestampMs = operationRecord.timestampMs.takeIf { it > 0L } ?: updatedAtMs
            )
        }
        programCoordination?.let { coordination ->
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_PRIORITY_APPLIED,
                title = "Rollout program priority applied",
                detail = coordination.priorityDecision?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: coordination.summary.ifBlank {
                        "Program coordination is ${coordination.coordinationState.name.lowercase().replace('_', ' ')}."
                    },
                timestampMs = coordination.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
            )
            if (coordination.coordinationState == RolloutProgramCoordinationState.DEFERRED ||
                coordination.coordinationState == RolloutProgramCoordinationState.CONTENTION_BLOCKED
            ) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_DEFERRED,
                    title = "Rollout program deferred",
                    detail = coordination.summary.ifBlank {
                        "Program deferred by coordination policy."
                    },
                    timestampMs = coordination.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
            if (coordination.dependencies.any { it.blocked }) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_DEPENDENCY_BLOCKED,
                    title = "Rollout program dependency blocked",
                    detail = coordination.dependencies
                        .firstOrNull { it.blocked }
                        ?.summary
                        ?.takeIf { it.isNotBlank() }
                        ?: "Program is blocked by unresolved dependency chain.",
                    timestampMs = coordination.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
            if (coordination.conflicts.isNotEmpty()) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_CONFLICT_DETECTED,
                    title = "Rollout program conflict detected",
                    detail = coordination.conflicts.firstOrNull()?.summary
                        ?.takeIf { it.isNotBlank() }
                        ?: "Program has rollout conflict constraints.",
                    timestampMs = coordination.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
            val contention = coordination.contention
            if (contention?.type != null &&
                contention.type != RolloutProgramContentionType.NONE
            ) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_CONTENTION_DETECTED,
                    title = "Rollout program contention detected",
                    detail = contention.summary.ifBlank {
                        "Program is under rollout contention constraints."
                    },
                    timestampMs = coordination.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
            val escalation = coordination.escalation
            when (escalation?.status) {
                RolloutProgramEscalationStatus.OPEN,
                RolloutProgramEscalationStatus.IN_PROGRESS -> {
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_ESCALATION_OPENED,
                        title = "Rollout program escalation opened",
                        detail = escalation.summary.ifBlank {
                            "Escalation opened due to rollout coordination blockers."
                        },
                        timestampMs = escalation.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                    )
                }

                RolloutProgramEscalationStatus.RESOLVED -> {
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_ESCALATION_RESOLVED,
                        title = "Rollout program escalation resolved",
                        detail = escalation.summary.ifBlank {
                            "Escalation resolved after rollout coordination recovered."
                        },
                        timestampMs = escalation.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                    )
                }

                else -> Unit
            }
        }
        crossProgram
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?.let { summary ->
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.ROLLOUT_PROGRAM_CONTENTION_DETECTED,
                    title = "Cross-program governance updated",
                    detail = summary,
                    timestampMs = crossProgram.updatedAtMs.takeIf { it > 0L } ?: updatedAtMs
                )
            }
        return events
    }

    private fun buildQuoteSummary(response: AgentResponse): String {
        val lixPayload = response.payload as? ModulePayload.LixPayload ?: return "No external quote comparison was required."
        val selection = lixPayload.providerSelectionSummary
        return when {
            selection != null && selection.selectedProviderName?.isNotBlank() == true ->
                "Quote comparison selected ${selection.selectedProviderName} (${selection.approvalStatus.replace('_', ' ')})."
            lixPayload.quotes.isNotEmpty() ->
                "Quote comparison collected ${lixPayload.quotes.size} provider option(s); selection pending."
            else ->
                "No external quote comparison was required."
        }
    }

    private fun buildExternalSettlementSummary(
        response: AgentResponse,
        roleImpactCodes: List<String>
    ): ExternalSettlementSummary? {
        val lixPayload = response.payload as? ModulePayload.LixPayload ?: return null
        if (!isExternalRun(response, lixPayload)) return null
        val summaryText = buildString {
            append(response.summary.orEmpty())
            append(' ')
            append(response.nextAction.orEmpty())
        }.lowercase()
        val mismatch = summaryText.contains("mismatch") ||
            summaryText.contains("conflict") ||
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH)
        val syncPending = summaryText.contains("sync pending") ||
            summaryText.contains("awaiting gateway sync") ||
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_SYNC_PENDING)
        val syncResolved = summaryText.contains("sync resolved") ||
            summaryText.contains("reconciled") ||
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_RECONCILED)
        val settlementStatus = when {
            response.status == ResponseStatus.ROLLED_BACK -> SettlementStatus.ROLLED_BACK
            response.status == ResponseStatus.DISPUTED -> SettlementStatus.DISPUTED
            response.status == ResponseStatus.ERROR -> SettlementStatus.FAILED
            syncPending -> SettlementStatus.SYNC_PENDING
            syncResolved -> SettlementStatus.RECONCILED
            response.status == ResponseStatus.COMMITTED ||
                response.status == ResponseStatus.SUCCESS ||
                response.status == ResponseStatus.PARTIAL -> SettlementStatus.COMMITTED

            response.status == ResponseStatus.QUOTING ||
                response.status == ResponseStatus.AUTH_REQUIRED ||
                response.status == ResponseStatus.VERIFYING ||
                response.status == ResponseStatus.RUNNING ||
                response.status == ResponseStatus.PROCESSING ||
                response.status == ResponseStatus.WAITING_USER -> SettlementStatus.STARTED

            else -> SettlementStatus.NOT_REQUIRED
        }
        val syncState = when {
            settlementStatus == SettlementStatus.NOT_REQUIRED -> SettlementSyncState.NOT_REQUIRED
            mismatch -> SettlementSyncState.MISMATCH
            syncPending -> SettlementSyncState.SYNC_PENDING
            syncResolved -> SettlementSyncState.RECONCILED
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_RECEIVED) -> SettlementSyncState.ACKNOWLEDGED
            else -> SettlementSyncState.LOCAL_ONLY
        }
        val reasonCodes = buildList {
            addAll(
                roleImpactCodes.filter { code ->
                    code.startsWith("ROLE_EXTERNAL_SETTLEMENT_") ||
                        code.startsWith("ROLE_EXTERNAL_RECONCILIATION_") ||
                        code.startsWith("ROLE_EXTERNAL_PROVIDER_ACK_") ||
                        code == RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED
                }
            )
            when (settlementStatus) {
                SettlementStatus.STARTED -> add(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_STARTED)
                SettlementStatus.COMMITTED -> add(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_COMMITTED)
                SettlementStatus.SYNC_PENDING -> add(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_SYNC_PENDING)
                SettlementStatus.RECONCILED -> add(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_RECONCILED)
                else -> Unit
            }
            if (syncState == SettlementSyncState.MISMATCH) {
                add(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH)
            }
            if (syncState == SettlementSyncState.SYNC_PENDING) {
                add(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_SYNC_PENDING)
            }
        }.distinct()
        val settlementSummary = when {
            settlementStatus == SettlementStatus.SYNC_PENDING ->
                "Settlement is authoritative locally; remote acknowledgement is pending."
            settlementStatus == SettlementStatus.RECONCILED ->
                "Settlement has been reconciled with remote acknowledgement."
            settlementStatus == SettlementStatus.DISPUTED ->
                "Settlement remains disputed and requires reconciliation."
            settlementStatus == SettlementStatus.ROLLED_BACK ->
                "Settlement was rolled back and recorded as final."
            settlementStatus == SettlementStatus.FAILED ->
                "Settlement failed and requires issue handling."
            else ->
                "Settlement state was recorded for this external run."
        }
        return ExternalSettlementSummary(
            status = settlementStatus,
            syncState = syncState,
            summary = settlementSummary,
            authoritativeLocalState = syncState == SettlementSyncState.SYNC_PENDING || syncState == SettlementSyncState.MISMATCH,
            reasonCodes = reasonCodes
        )
    }

    private fun buildReconciliationSummary(
        response: AgentResponse,
        settlementSummary: ExternalSettlementSummary?,
        disputeSummary: ExternalDisputeSummary?,
        roleImpactCodes: List<String>,
        updatedAtMs: Long
    ): MarketplaceReconciliationSummary? {
        if (settlementSummary == null && disputeSummary == null) return null
        val responseText = buildString {
            append(response.summary.orEmpty())
            append(' ')
            append(disputeSummary?.summary.orEmpty())
            append(' ')
            append(response.nextAction.orEmpty())
        }.lowercase()
        val mismatchDetected = responseText.contains("mismatch") ||
            responseText.contains("conflict") ||
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH)
        val retryScheduled = responseText.contains("retry") ||
            roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY)
        val syncState = settlementSummary?.syncState ?: when {
            mismatchDetected -> SettlementSyncState.MISMATCH
            disputeSummary?.summary?.contains("sync pending", ignoreCase = true) == true -> SettlementSyncState.SYNC_PENDING
            else -> SettlementSyncState.LOCAL_ONLY
        }
        val result = when {
            mismatchDetected && retryScheduled -> SettlementReconciliationResult.RETRY_SCHEDULED
            mismatchDetected -> SettlementReconciliationResult.MISMATCH
            syncState == SettlementSyncState.RECONCILED -> SettlementReconciliationResult.RESOLVED
            syncState == SettlementSyncState.SYNC_PENDING -> SettlementReconciliationResult.RETRY_SCHEDULED
            settlementSummary?.status == SettlementStatus.NOT_REQUIRED -> SettlementReconciliationResult.NOT_REQUIRED
            else -> SettlementReconciliationResult.MATCHED
        }
        val summary = when (result) {
            SettlementReconciliationResult.MISMATCH ->
                "Local and remote settlement states differ; reconciliation is required."
            SettlementReconciliationResult.RETRY_SCHEDULED ->
                "Reconciliation retry is scheduled while local state remains authoritative."
            SettlementReconciliationResult.RESOLVED ->
                "Reconciliation completed and local/remote states are aligned."
            SettlementReconciliationResult.MATCHED ->
                "Reconciliation confirms no local/remote mismatch."
            SettlementReconciliationResult.NOT_REQUIRED ->
                "No reconciliation step was required."
        }
        val reasonCodes = buildList {
            if (mismatchDetected) add(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH)
            if (retryScheduled) add(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY)
            addAll(roleImpactCodes.filter { it.startsWith("ROLE_EXTERNAL_RECONCILIATION_") })
        }.distinct()
        return MarketplaceReconciliationSummary(
            result = result,
            syncState = syncState,
            summary = summary,
            mismatchDetected = mismatchDetected,
            retryScheduled = retryScheduled,
            reasonCodes = reasonCodes,
            lastCheckedAtMs = updatedAtMs
        )
    }

    private fun buildSyncIssues(
        response: AgentResponse,
        settlementSummary: ExternalSettlementSummary?,
        reconciliationSummary: MarketplaceReconciliationSummary?,
        disputeSummary: ExternalDisputeSummary?,
        roleImpactCodes: List<String>,
        updatedAtMs: Long
    ): List<MarketplaceSyncIssue> {
        val providerId = resolveSelectedProviderId(response)
        val issues = mutableListOf<MarketplaceSyncIssue>()
        if (settlementSummary?.syncState == SettlementSyncState.SYNC_PENDING ||
            disputeSummary?.summary?.contains("sync pending", ignoreCase = true) == true
        ) {
            issues += MarketplaceSyncIssue(
                issueId = "sync_pending_${response.traceId.take(12)}",
                providerId = providerId,
                issueType = "sync_pending",
                summary = "Gateway acknowledgement is pending while local state remains authoritative.",
                reasonCodes = listOf(RoleReasonCodes.ROLE_EXTERNAL_SETTLEMENT_SYNC_PENDING),
                detectedAtMs = updatedAtMs
            )
        }
        if (reconciliationSummary?.mismatchDetected == true ||
            settlementSummary?.syncState == SettlementSyncState.MISMATCH
        ) {
            issues += MarketplaceSyncIssue(
                issueId = "sync_mismatch_${response.traceId.take(12)}",
                providerId = providerId,
                issueType = "reconciliation_mismatch",
                summary = "Remote callback disagrees with local settlement/dispute state.",
                reasonCodes = listOf(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH),
                detectedAtMs = updatedAtMs
            )
        }
        if (roleImpactCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_TIMEOUT)) {
            issues += MarketplaceSyncIssue(
                issueId = "ack_timeout_${response.traceId.take(12)}",
                providerId = providerId,
                issueType = "provider_ack_timeout",
                summary = "Provider acknowledgement timed out; reconciliation remains open.",
                reasonCodes = listOf(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_TIMEOUT),
                detectedAtMs = updatedAtMs
            )
        }
        return issues
            .distinctBy { "${it.issueType}:${it.providerId}:${it.summary}" }
            .take(6)
    }

    private fun isExternalRun(
        response: AgentResponse,
        payload: ModulePayload.LixPayload
    ): Boolean {
        return response.module == ModuleId.LIX ||
            payload.quotes.isNotEmpty() ||
            payload.capabilityCards.isNotEmpty() ||
            payload.providerPolicyDecisions.isNotEmpty() ||
            payload.providerSelectionSummary != null
    }

    private fun buildRoleImpactSummary(roleImpactCodes: List<String>): String {
        if (roleImpactCodes.isEmpty()) {
            return "No material role impact was recorded for this run."
        }
        return roleImpactCodes
            .map(::readableRoleImpact)
            .distinct()
            .take(2)
            .joinToString(separator = " · ")
            .ifBlank { "Role impact was recorded but no readable mapping was available." }
    }

    private fun buildApprovalSummary(
        response: AgentResponse,
        roleImpactCodes: List<String>
    ): String {
        val gates = response.gateDecisions
        val requiresApproval = roleImpactCodes.contains(RoleReasonCodes.ROLE_APPROVAL_REQUIRED) ||
            response.status == ResponseStatus.AUTH_REQUIRED ||
            gates.any {
                it.gate == GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN &&
                    it.decision != GateDecisionStatus.PASSED
            }
        val approvalDenied = roleImpactCodes.contains(RoleReasonCodes.ROLE_POLICY_DENIED) ||
            gates.any {
                it.gate == GateType.GATE_R3_BUDGET_SCOPE_GUARD &&
                    it.decision == GateDecisionStatus.BLOCKED
            }
        return when {
            approvalDenied -> "Approval denied by role policy constraints."
            requiresApproval && response.status == ResponseStatus.WAITING_USER ->
                "Approval required before execution can continue."
            requiresApproval -> "Approval requirement was satisfied for this run."
            else -> "No approval gate was required."
        }
    }

    private fun buildDataScopeSummary(
        response: AgentResponse,
        roleImpactCodes: List<String>
    ): String {
        return when {
            roleImpactCodes.contains(RoleReasonCodes.ROLE_CLOUD_SYNC_BLOCKED) ->
                "Cloud sync was blocked by role data policy."
            roleImpactCodes.contains(RoleReasonCodes.ROLE_DATA_SCOPE_REDUCED) ||
                roleImpactCodes.contains(RoleReasonCodes.ROLE_FIELD_REDACTED) ->
                "Data sharing scope was reduced by role policy."
            (response.payload as? ModulePayload.AvatarPayload)
                ?.dataSharingScope
                ?.isNotEmpty() == true -> {
                val scope = (response.payload as ModulePayload.AvatarPayload).dataSharingScope.take(2).joinToString("; ")
                "Data scope applied: $scope"
            }

            else -> "No additional data-scope restrictions were recorded."
        }
    }

    private fun buildProviderSummary(
        response: AgentResponse,
        roleImpactCodes: List<String>
    ): String {
        val lixPayload = response.payload as? ModulePayload.LixPayload
        lixPayload?.providerSelectionSummary?.let { summary ->
            if (summary.selectedProviderName?.isNotBlank() == true) {
                return "Provider selected: ${summary.selectedProviderName}. ${summary.selectionRationale}"
            }
            if (summary.deniedProviderIds.isNotEmpty()) {
                return "Provider denied by policy (${summary.deniedProviderIds.size} blocked option(s))."
            }
        }
        val selectedProvider = resolveSelectedProviderId(response)
        val providerBlocked = roleImpactCodes.contains(RoleReasonCodes.ROLE_PROVIDER_EXCLUDED) ||
            response.skillCandidates.any { !it.policyPassed } ||
            response.routingDecision?.reasonCodes?.any { code ->
                code.contains("exclude", ignoreCase = true) || code.contains("blocked", ignoreCase = true)
            } == true
        val providerCompared = lixPayload?.quotes?.isNotEmpty() == true || lixPayload?.capabilityCards?.isNotEmpty() == true
        return when {
            providerBlocked && selectedProvider != null ->
                "Provider options were restricted by policy; selected provider: $selectedProvider."
            providerBlocked ->
                "Provider blocked by policy. Choose another provider or adjust constraints."
            selectedProvider != null ->
                "Provider selected: $selectedProvider."
            providerCompared ->
                "Provider options were compared but no final provider was selected yet."
            else ->
                "No external provider decision was required."
        }
    }

    private fun buildVerificationSummary(response: AgentResponse): String {
        val typed = (response.payload as? ModulePayload.LixPayload)?.externalVerificationSummary
        if (typed?.summary?.isNotBlank() == true) return typed.summary
        val report = response.validationReport
        val proof = (response.payload as? ModulePayload.LixPayload)?.verificationProof
        return when {
            response.status == ResponseStatus.VERIFYING -> "Verification is in progress."
            response.status == ResponseStatus.DISPUTED -> "Verification failed and moved to dispute handling."
            report?.passed == true || proof?.passed == true -> "Verification passed."
            report?.passed == false || proof?.passed == false -> "Verification failed."
            proof != null -> "Verification evidence was submitted and is pending review."
            else -> "No additional verification step was recorded."
        }
    }

    private fun buildProofSummary(
        response: AgentResponse,
        proofLinks: List<String>
    ): String {
        val typed = (response.payload as? ModulePayload.LixPayload)?.externalProofSummary
        if (typed?.summary?.isNotBlank() == true) return typed.summary
        val reportEvidence = response.validationReport?.evidence.orEmpty()
        return when {
            proofLinks.isNotEmpty() -> "Proof is available via ${proofLinks.size} reference link(s)."
            response.evidence.isNotEmpty() || reportEvidence.isNotEmpty() ->
                "Proof is captured in execution evidence records."
            else -> "No proof artifacts were recorded."
        }
    }

    private fun buildRollbackSummary(response: AgentResponse): String {
        val lixPayload = response.payload as? ModulePayload.LixPayload
        val typed = lixPayload?.externalRollbackSummary
        if (typed?.summary?.isNotBlank() == true) return typed.summary
        val hasRollbackPlan = response.finalDelivery?.rollbackPlan?.isNotEmpty() == true ||
            lixPayload?.rollbackPolicy != null
        return when {
            response.status == ResponseStatus.ROLLED_BACK ->
                "Execution was rolled back according to policy."
            hasRollbackPlan ->
                "Rollback is available if verification fails or the outcome is disputed."
            response.status == ResponseStatus.DISPUTED ->
                "Issue is in dispute handling flow."
            else ->
                "No rollback action was triggered."
        }
    }

    private fun buildIssueSummary(response: AgentResponse): String? {
        return when {
            response.validationReport?.issues?.isNotEmpty() == true ->
                response.validationReport?.issues?.firstOrNull()
            response.gateDecisions.any { it.decision == GateDecisionStatus.BLOCKED } ->
                response.gateDecisions.firstOrNull { it.decision == GateDecisionStatus.BLOCKED }?.reason
            response.status == ResponseStatus.ERROR ->
                response.summary?.takeIf { it.isNotBlank() } ?: "Execution failed."
            response.status == ResponseStatus.DISPUTED ->
                response.summary?.takeIf {
                    it.contains("sync pending", ignoreCase = true) ||
                        it.contains("dispute", ignoreCase = true)
                } ?: "Execution moved to dispute resolution."
            else -> null
        }
    }

    private fun collectProofLinks(response: AgentResponse): List<String> {
        val lixPayload = response.payload as? ModulePayload.LixPayload
        return buildList {
            lixPayload?.verificationProof?.proofUrl?.takeIf { it.isNotBlank() }?.let { add(it) }
            lixPayload?.capabilityCards
                ?.mapNotNull { it.verificationUrl?.takeIf { url -> url.isNotBlank() } }
                ?.let(::addAll)
            response.validationReport?.evidence
                ?.mapNotNull { item -> item.url?.takeIf { it.isNotBlank() } }
                ?.let(::addAll)
            response.evidence
                .mapNotNull { item ->
                    item.url?.takeIf { it.isNotBlank() }
                }
                .let(::addAll)
        }.distinct().take(6)
    }

    private fun collectArtifactReferences(response: AgentResponse): List<String> {
        return response.validationReport
            ?.evidence
            ?.mapNotNull { item ->
                item.title.takeIf { it.isNotBlank() } ?: item.source.takeIf { it.isNotBlank() }
            }
            ?.distinct()
            ?.take(6)
            .orEmpty()
    }

    private fun resolveSelectedProviderId(response: AgentResponse): String? {
        val lixPayload = response.payload as? ModulePayload.LixPayload ?: return null
        return lixPayload.providerSelectionSummary?.selectedProviderName?.takeIf { it.isNotBlank() }
            ?: lixPayload.quotes.firstOrNull { it.providerDecision == ProviderDecisionStatus.SELECTED }
                ?.supplier
                ?.takeIf { it.isNotBlank() }
            ?: lixPayload.quotes.firstOrNull()?.supplier?.takeIf { it.isNotBlank() }
            ?: lixPayload.capabilityCards.firstOrNull()?.provider?.takeIf { it.isNotBlank() }
    }

    private fun collectSelectedCapabilityIds(response: AgentResponse): List<String> {
        val lixPayload = response.payload as? ModulePayload.LixPayload ?: return emptyList()
        return buildList {
            addAll(lixPayload.capabilityCards.mapNotNull { it.id.takeIf { id -> id.isNotBlank() } })
            addAll(
                lixPayload.quotes
                    .filter { it.providerDecision == ProviderDecisionStatus.SELECTED || it.providerDecision == ProviderDecisionStatus.ALLOWED }
                    .mapNotNull { it.capabilityId.takeIf { id -> id.isNotBlank() } }
            )
        }.distinct().take(8)
    }

    private fun collectBlockedCapabilityIds(response: AgentResponse): List<String> {
        val policyBlockedSkills = response.skillCandidates
            .asSequence()
            .filterNot { it.policyPassed }
            .map { it.id }
            .filter { it.isNotBlank() }
            .toList()
        val blockedProviders = (response.payload as? ModulePayload.LixPayload)
            ?.quotes
            ?.asSequence()
            ?.filter { it.providerDecision == ProviderDecisionStatus.DENIED }
            ?.mapNotNull { it.capabilityId.takeIf { id -> id.isNotBlank() } }
            ?.toList()
            .orEmpty()
        return (policyBlockedSkills + blockedProviders)
            .distinct()
            .take(8)
    }

    private fun buildReceiptEvents(
        response: AgentResponse,
        approvalSummary: String,
        dataScopeSummary: String,
        providerSummary: String,
        quoteSummary: String,
        verificationSummary: String,
        proofSummary: String,
        rollbackSummary: String,
        settlementSummary: ExternalSettlementSummary?,
        reconciliationSummary: MarketplaceReconciliationSummary?,
        policySnapshot: RolePolicySnapshot?,
        disputeSummary: String?,
        issueSummary: String?,
        startMs: Long,
        updatedAtMs: Long
    ): List<ExecutionReceiptEvent> {
        val events = mutableListOf<ExecutionReceiptEvent>()
        events += ExecutionReceiptEvent(
            type = ExecutionReceiptEventType.RUN_STARTED,
            title = "Run started",
            detail = "Execution run ${response.traceId.take(12)} started.",
            timestampMs = startMs
        )
        events += ExecutionReceiptEvent(
            type = ExecutionReceiptEventType.EXECUTION_STARTED,
            title = "Execution started",
            detail = "Status is ${response.status.name.lowercase().replace('_', ' ')}.",
            timestampMs = startMs
        )
        response.activeRole?.let { role ->
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLE_APPLIED,
                title = "Role applied",
                detail = "Running as ${role.name.lowercase()} role (${response.roleSource?.name?.lowercase()?.replace('_', ' ') ?: "source unknown"}).",
                timestampMs = updatedAtMs
            )
        }
        policySnapshot?.let {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLE_POLICY_SNAPSHOT_BOUND,
                title = "Policy snapshot bound",
                detail = "Policy snapshot ${it.snapshotId.take(18)} (${it.policyVersion}) was bound at decision time.",
                timestampMs = updatedAtMs
            )
        }
        response.roleChangeReason?.let { reason ->
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLE_CHANGED,
                title = "Role changed",
                detail = "Role change reason: ${reason.name.lowercase().replace('_', ' ')}.",
                timestampMs = updatedAtMs
            )
        }
        if (approvalSummary.contains("required", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.APPROVAL_REQUIRED,
                title = "Approval required",
                detail = approvalSummary,
                timestampMs = updatedAtMs
            )
        } else if (approvalSummary.contains("denied", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.APPROVAL_DENIED,
                title = "Approval denied",
                detail = approvalSummary,
                timestampMs = updatedAtMs
            )
        } else if (response.gateDecisions.any { it.gate == GateType.GATE_R2_REQUIRE_USER_CONFIRMATION_TOKEN }) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.APPROVAL_GRANTED,
                title = "Approval granted",
                detail = approvalSummary,
                timestampMs = updatedAtMs
            )
        }
        if (dataScopeSummary.contains("blocked", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.DATA_SCOPE_BLOCKED,
                title = "Data scope blocked",
                detail = dataScopeSummary,
                timestampMs = updatedAtMs
            )
        } else if (dataScopeSummary.contains("reduced", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.DATA_SCOPE_REDUCED,
                title = "Data scope reduced",
                detail = dataScopeSummary,
                timestampMs = updatedAtMs
            )
        }
        if (providerSummary.contains("selected", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROVIDER_SELECTED,
                title = "Provider selected",
                detail = providerSummary,
                timestampMs = updatedAtMs
            )
        }
        if (providerSummary.contains("blocked", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROVIDER_BLOCKED,
                title = "Provider blocked",
                detail = providerSummary,
                timestampMs = updatedAtMs
            )
        }
        if (quoteSummary.contains("quote", ignoreCase = true) || quoteSummary.contains("provider option", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.QUOTE_COLLECTED,
                title = "Quote collected",
                detail = quoteSummary,
                timestampMs = updatedAtMs
            )
        }
        if (proofSummary.contains("returned", ignoreCase = true) ||
            proofSummary.contains("available", ignoreCase = true)
        ) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROOF_RETURNED,
                title = "Proof returned",
                detail = proofSummary,
                timestampMs = updatedAtMs
            )
        } else if (proofSummary.contains("missing", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROOF_MISSING,
                title = "Proof missing",
                detail = proofSummary,
                timestampMs = updatedAtMs
            )
        }
        if (verificationSummary.contains("passed", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.VERIFICATION_PASSED,
                title = "Verification passed",
                detail = verificationSummary,
                timestampMs = updatedAtMs
            )
        } else if (verificationSummary.contains("partial", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.VERIFICATION_PARTIAL,
                title = "Verification partial",
                detail = verificationSummary,
                timestampMs = updatedAtMs
            )
        } else if (verificationSummary.contains("failed", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.VERIFICATION_FAILED,
                title = "Verification failed",
                detail = verificationSummary,
                timestampMs = updatedAtMs
            )
        }
        if (response.status == ResponseStatus.SUCCESS || response.status == ResponseStatus.PARTIAL || response.status == ResponseStatus.COMMITTED) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.RESULT_DELIVERED,
                title = "Result delivered",
                detail = response.summary?.takeIf { it.isNotBlank() } ?: "Result delivered.",
                timestampMs = updatedAtMs
            )
        }
        settlementSummary?.let { settlement ->
            if (settlement.status != SettlementStatus.NOT_REQUIRED) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.SETTLEMENT_STARTED,
                    title = "Settlement started",
                    detail = settlement.summary.ifBlank { "Settlement lifecycle started for external fulfillment." },
                    timestampMs = updatedAtMs
                )
            }
            when (settlement.status) {
                SettlementStatus.COMMITTED ->
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.SETTLEMENT_COMMITTED,
                        title = "Settlement committed",
                        detail = settlement.summary.ifBlank { "Settlement committed locally." },
                        timestampMs = updatedAtMs
                    )

                SettlementStatus.SYNC_PENDING ->
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.SETTLEMENT_SYNC_PENDING,
                        title = "Settlement sync pending",
                        detail = settlement.summary.ifBlank { "Local state is authoritative while remote sync is pending." },
                        timestampMs = updatedAtMs
                    )

                SettlementStatus.RECONCILED ->
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.SETTLEMENT_RECONCILED,
                        title = "Settlement reconciled",
                        detail = settlement.summary.ifBlank { "Settlement reconciled with remote acknowledgement." },
                        timestampMs = updatedAtMs
                    )

                SettlementStatus.ROLLBACK_REQUESTED ->
                    events += ExecutionReceiptEvent(
                        type = ExecutionReceiptEventType.ROLLBACK_REQUESTED,
                        title = "Rollback requested",
                        detail = settlement.summary.ifBlank { "Rollback was requested and is pending final outcome." },
                        timestampMs = updatedAtMs
                    )

                else -> Unit
            }
        }
        val hasProviderAck = settlementSummary?.reasonCodes?.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_RECEIVED) == true
        if (hasProviderAck) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROVIDER_ACK_RECEIVED,
                title = "Provider acknowledged",
                detail = "Remote provider acknowledged the settlement/dispute chain.",
                timestampMs = updatedAtMs
            )
        }
        if (rollbackSummary.contains("available", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLBACK_AVAILABLE,
                title = "Rollback available",
                detail = rollbackSummary,
                timestampMs = updatedAtMs
            )
        }
        if (rollbackSummary.contains("requested", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLBACK_REQUESTED,
                title = "Rollback requested",
                detail = rollbackSummary,
                timestampMs = updatedAtMs
            )
        }
        if (response.status == ResponseStatus.ROLLED_BACK) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLED_BACK,
                title = "Rolled back",
                detail = rollbackSummary,
                timestampMs = updatedAtMs
            )
        } else if (rollbackSummary.contains("failed", ignoreCase = true)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLBACK_FAILED,
                title = "Rollback failed",
                detail = rollbackSummary,
                timestampMs = updatedAtMs
            )
        }
        if (!disputeSummary.isNullOrBlank() &&
            (disputeSummary.contains("dispute", ignoreCase = true) ||
                response.status == ResponseStatus.DISPUTED)
        ) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.DISPUTE_OPENED,
                title = "Dispute opened",
                detail = disputeSummary,
                timestampMs = updatedAtMs
            )
            if (disputeSummary.contains("sync pending", ignoreCase = true)) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.DISPUTE_SYNC_PENDING,
                    title = "Dispute sync pending",
                    detail = disputeSummary,
                    timestampMs = updatedAtMs
                )
            }
            if (disputeSummary.contains("acknowledged", ignoreCase = true)) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.DISPUTE_ACKNOWLEDGED,
                    title = "Dispute acknowledged",
                    detail = disputeSummary,
                    timestampMs = updatedAtMs
                )
            }
            if (disputeSummary.contains("resolved", ignoreCase = true)) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.DISPUTE_RESOLVED,
                    title = "Dispute resolved",
                    detail = disputeSummary,
                    timestampMs = updatedAtMs
                )
            }
            if (disputeSummary.contains("closed", ignoreCase = true)) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.DISPUTE_CLOSED,
                    title = "Dispute closed",
                    detail = disputeSummary,
                    timestampMs = updatedAtMs
                )
            }
        }
        reconciliationSummary?.let { reconciliation ->
            if (reconciliation.mismatchDetected || reconciliation.result == SettlementReconciliationResult.MISMATCH) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.RECONCILIATION_MISMATCH_DETECTED,
                    title = "Reconciliation mismatch",
                    detail = reconciliation.summary.ifBlank { "Local and remote states are inconsistent and require reconciliation." },
                    timestampMs = updatedAtMs
                )
            }
            if (reconciliation.retryScheduled || reconciliation.result == SettlementReconciliationResult.RETRY_SCHEDULED) {
                events += ExecutionReceiptEvent(
                    type = ExecutionReceiptEventType.RECONCILIATION_RETRY_SCHEDULED,
                    title = "Reconciliation retry scheduled",
                    detail = reconciliation.summary.ifBlank { "A retry was scheduled to reconcile local and remote state." },
                    timestampMs = updatedAtMs
                )
            }
        }
        issueSummary?.let { issue ->
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ISSUE_REPORTED,
                title = "Issue reported",
                detail = issue,
                timestampMs = updatedAtMs
            )
        }
        val impactReasonCodes = response.roleImpactReasonCodes
            .map { it.trim().uppercase() }
            .toSet()
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_ROLLOUT_WAVE_ASSIGNED)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLOUT_WAVE_ASSIGNED,
                title = "Rollout wave assigned",
                detail = "A rollout wave assignment was applied for this promotion step.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_ROLLOUT_WAVE_PARTIAL_COMPLETION)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLOUT_WAVE_PARTIAL_COMPLETION,
                title = "Rollout wave partial completion",
                detail = "Current rollout wave is partially complete and pending target carry-forward.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_ROLLOUT_WAVE_CARRIED_FORWARD)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.ROLLOUT_WAVE_CARRIED_FORWARD,
                title = "Rollout wave carried forward",
                detail = "Pending rollout wave scope was carried forward to the next eligible window.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_PROMOTION_WINDOW_DEFERRED)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROMOTION_WINDOW_DEFERRED,
                title = "Promotion window deferred",
                detail = "Promotion was deferred by current window governance constraints.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_PROMOTION_WINDOW_EXPIRED)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.PROMOTION_WINDOW_EXPIRED,
                title = "Promotion window expired",
                detail = "Promotion window expired before wave completion.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_CROSS_WINDOW_PAUSED)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.CROSS_WINDOW_PAUSED,
                title = "Cross-window rollout paused",
                detail = "Cross-window rollout is paused by governance controls.",
                timestampMs = updatedAtMs
            )
        }
        if (impactReasonCodes.contains(RoleReasonCodes.ROLE_CROSS_WINDOW_RESUMED)) {
            events += ExecutionReceiptEvent(
                type = ExecutionReceiptEventType.CROSS_WINDOW_RESUMED,
                title = "Cross-window rollout resumed",
                detail = "Cross-window rollout resumed after pause/hold conditions cleared.",
                timestampMs = updatedAtMs
            )
        }
        return events.distinctBy { "${it.type}:${it.detail}" }.take(12)
    }

    private fun buildRolePolicySnapshot(
        request: AgentRequest,
        constraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext,
        boundAtMs: Long,
        traceId: String
    ): RolePolicySnapshot {
        val policy = roleContext.rolePolicyProfile
        val hardOverrides = mutableListOf<String>()
        if (!constraints.budget.isNullOrBlank()) hardOverrides += "budget"
        if (!constraints.deadline.isNullOrBlank()) hardOverrides += "deadline"
        if (!constraints.acceptanceCriteria.isNullOrBlank()) hardOverrides += "acceptance_criteria"
        if (!constraints.maxCostPerStep.isNullOrBlank()) hardOverrides += "max_cost_per_step"
        if (!constraints.riskTolerance.isNullOrBlank()) hardOverrides += "risk_tolerance"
        if (!constraints.userConfirmationToken.isNullOrBlank()) hardOverrides += "user_confirmation_token"
        val overrideSource = if (hasRolePolicyOverride(request.userId, roleContext.activeRole)) {
            "user_role_policy_override"
        } else {
            "default_role_policy_profile"
        }
        return RolePolicySnapshot(
            snapshotId = "policy_${traceId.take(12)}_$boundAtMs",
            policyVersion = policy.version,
            activeRole = roleContext.activeRole,
            roleSource = roleContext.roleSource,
            delegationMode = roleContext.delegationMode,
            overrideSource = overrideSource,
            approvalPolicy = policy.approvalPolicy,
            dataPolicy = policy.dataPolicy,
            externalFulfillmentAllowed = policy.preferences.externalFulfillmentAllowed,
            externalFulfillmentPreference = policy.preferences.externalFulfillmentPreference,
            trustedProviderTags = policy.preferences.trustedProviderTags,
            blockedProviderTags = policy.preferences.blockedProviderTags,
            riskToleranceDefault = policy.preferences.riskToleranceDefault,
            maxCostPerStepDefault = policy.preferences.maxCostPerStepDefault,
            hardConstraintOverrides = hardOverrides.distinct(),
            precedenceNote = "Explicit task constraints override role defaults.",
            boundAtMs = boundAtMs
        )
    }

    private fun buildConstraintPrecedenceSummary(constraints: AgentRequestConstraints): String {
        val overrides = buildList {
            if (!constraints.budget.isNullOrBlank()) add("budget")
            if (!constraints.deadline.isNullOrBlank()) add("deadline")
            if (!constraints.acceptanceCriteria.isNullOrBlank()) add("acceptance criteria")
            if (!constraints.maxCostPerStep.isNullOrBlank()) add("max cost per step")
            if (!constraints.riskTolerance.isNullOrBlank()) add("risk tolerance")
            if (!constraints.userConfirmationToken.isNullOrBlank()) add("approval token")
        }
        return if (overrides.isEmpty()) {
            "No explicit task constraints overrode role defaults in this run."
        } else {
            "Explicit task constraints overrode role defaults for: ${overrides.joinToString(", ")}."
        }
    }

    private fun appendExecutionLedgerRecord(
        userId: String,
        request: AgentRequest,
        response: AgentResponse,
        policySnapshot: RolePolicySnapshot,
        updatedAtMs: Long
    ) {
        val receipt = response.executionReceipt ?: return
        val record = buildExecutionReceiptRecord(
            userId = userId,
            request = request,
            response = response,
            receipt = receipt,
            policySnapshot = policySnapshot,
            updatedAtMs = updatedAtMs
        )
        val mergedRecord = synchronized(dynamicStateLock) {
            val queue = executionLedgerByUser.getOrPut(userId) { ArrayDeque() }
            val previousRecord = queue.firstOrNull { it.runId == record.runId }
            val mergedRecord = if (previousRecord == null) {
                record
            } else {
                mergeExecutionReceiptRecord(previousRecord, record)
            }
            val deduped = queue
                .asSequence()
                .filterNot { it.runId == mergedRecord.runId }
                .toList()
                .takeLast((MAX_LEDGER_RECORDS - 1).coerceAtLeast(0))
            queue.clear()
            deduped.forEach(queue::addLast)
            queue.addLast(mergedRecord)
            while (queue.size > MAX_LEDGER_RECORDS) {
                queue.removeFirst()
            }
            mergedRecord
        }
        updateRemotePipelineRecords(userId = userId, record = mergedRecord)
        persistDynamicState(userId)
    }

    private fun mergeExecutionReceiptRecord(
        previous: ExecutionReceiptRecord,
        incoming: ExecutionReceiptRecord
    ): ExecutionReceiptRecord {
        val mergedRunEvents = (previous.runEvents + incoming.runEvents)
            .distinctBy { "${it.type}:${it.detail}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(MAX_LEDGER_EVENTS_PER_RUN)
        val mergedProviderDecisions = (previous.providerDecisions + incoming.providerDecisions)
            .distinctBy { "${it.providerId}:${it.providerName}:${it.decision}" }
            .take(16)
        val mergedSettlement = mergeSettlementRecord(previous.settlementRecord, incoming.settlementRecord)
        val mergedRollbackAttempts = (previous.rollbackAttempts + incoming.rollbackAttempts)
            .distinctBy { "${it.attemptId}:${it.outcome}" }
            .take(8)
        val mergedDisputeCase = mergeDisputeCaseRecord(previous.disputeCaseRecord, incoming.disputeCaseRecord)
        val mergedSyncIssues = (previous.syncIssues + incoming.syncIssues)
            .distinctBy { "${it.issueType}:${it.providerId}:${it.summary}" }
            .take(10)
        val incomingReceipt = incoming.receipt
        val previousReceipt = previous.receipt
        val mergedReasonCodes = buildSet {
            addAll(previousReceipt?.roleImpactReasonCodes.orEmpty())
            addAll(incomingReceipt?.roleImpactReasonCodes.orEmpty())
        }.toList()
        val mergedReceipt = incomingReceipt?.copy(
            roleImpactReasonCodes = if (incomingReceipt.roleImpactReasonCodes.isNotEmpty()) {
                incomingReceipt.roleImpactReasonCodes
            } else {
                mergedReasonCodes
            },
            syncIssues = if (incomingReceipt.syncIssues.isNotEmpty()) incomingReceipt.syncIssues else mergedSyncIssues,
            reconciliationSummary = incomingReceipt.reconciliationSummary
                ?: mergedSettlement?.reconciliation
                ?: previousReceipt?.reconciliationSummary
        ) ?: previousReceipt
        val earliestCreated = listOf(previous.createdAtMs, incoming.createdAtMs)
            .filter { it > 0L }
            .minOrNull() ?: incoming.createdAtMs
        val latestUpdated = maxOf(previous.updatedAtMs, incoming.updatedAtMs)
        return incoming.copy(
            recordId = previous.recordId.ifBlank { incoming.recordId },
            snapshotBinding = incoming.snapshotBinding ?: previous.snapshotBinding,
            policySnapshot = incoming.policySnapshot ?: previous.policySnapshot,
            receipt = mergedReceipt,
            runEvents = mergedRunEvents,
            providerDecisions = mergedProviderDecisions,
            verificationRecord = incoming.verificationRecord ?: previous.verificationRecord,
            settlementRecord = mergedSettlement ?: incoming.settlementRecord ?: previous.settlementRecord,
            rollbackRecord = incoming.rollbackRecord ?: previous.rollbackRecord,
            rollbackAttempts = mergedRollbackAttempts,
            disputeRecord = incoming.disputeRecord ?: previous.disputeRecord,
            disputeCaseRecord = mergedDisputeCase ?: incoming.disputeCaseRecord ?: previous.disputeCaseRecord,
            reconciliationSummary = incoming.reconciliationSummary ?: previous.reconciliationSummary ?: mergedSettlement?.reconciliation,
            syncIssues = mergedSyncIssues,
            responseSnapshot = incoming.responseSnapshot ?: previous.responseSnapshot,
            legacySummary = incoming.legacySummary.ifBlank { previous.legacySummary },
            createdAtMs = earliestCreated,
            updatedAtMs = latestUpdated,
            ledgerVersion = "m7_v1"
        )
    }

    private fun mergeSettlementRecord(
        previous: SettlementRecord?,
        incoming: SettlementRecord?
    ): SettlementRecord? {
        if (previous == null) return incoming
        if (incoming == null) return previous
        val existingKeys = previous.attempts.mapNotNull { it.idempotencyKey.takeIf(String::isNotBlank) }.toSet()
        val mergedAttempts = mutableListOf<SettlementAttempt>()
        mergedAttempts += previous.attempts
        incoming.attempts.forEach { attempt ->
            if (attempt.idempotencyKey.isNotBlank() && existingKeys.contains(attempt.idempotencyKey)) {
                mergedAttempts += attempt.copy(
                    duplicateIgnored = true,
                    detail = if (attempt.detail.isBlank()) {
                        "Duplicate callback ignored by idempotency key."
                    } else {
                        "${attempt.detail} (duplicate callback ignored)."
                    }
                )
            } else {
                mergedAttempts += attempt
            }
        }
        val mergedAcks = (previous.providerAcks + incoming.providerAcks)
            .distinctBy { "${it.providerId}:${it.callbackId}:${it.status}" }
            .take(8)
        val mergedReconciliation = incoming.reconciliation ?: previous.reconciliation
        val mergedReasonCodes = buildList {
            addAll(previous.reasonCodes)
            addAll(incoming.reasonCodes)
            if (mergedAttempts.any { it.duplicateIgnored }) {
                add(RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED)
            }
        }.distinct()
        val mergedStatus = when {
            incoming.status.ordinal >= previous.status.ordinal -> incoming.status
            else -> previous.status
        }
        val mergedSyncState = when {
            incoming.syncState == SettlementSyncState.MISMATCH || previous.syncState == SettlementSyncState.MISMATCH ->
                SettlementSyncState.MISMATCH
            incoming.syncState == SettlementSyncState.SYNC_PENDING || previous.syncState == SettlementSyncState.SYNC_PENDING ->
                SettlementSyncState.SYNC_PENDING
            incoming.syncState != SettlementSyncState.NOT_REQUIRED -> incoming.syncState
            else -> previous.syncState
        }
        return incoming.copy(
            status = mergedStatus,
            syncState = mergedSyncState,
            summary = incoming.summary.ifBlank { previous.summary },
            authoritativeLocalState = incoming.authoritativeLocalState || previous.authoritativeLocalState,
            selectedProviderId = incoming.selectedProviderId ?: previous.selectedProviderId,
            selectedProviderName = incoming.selectedProviderName ?: previous.selectedProviderName,
            attempts = mergedAttempts.takeLast(12),
            providerAcks = mergedAcks,
            reconciliation = mergedReconciliation,
            reasonCodes = mergedReasonCodes,
            recordedAtMs = maxOf(previous.recordedAtMs, incoming.recordedAtMs)
        )
    }

    private fun mergeDisputeCaseRecord(
        previous: DisputeCaseRecord?,
        incoming: DisputeCaseRecord?
    ): DisputeCaseRecord? {
        if (previous == null) return incoming
        if (incoming == null) return previous
        val mergedEvents = (previous.events + incoming.events)
            .distinctBy { "${it.status}:${it.summary}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .take(12)
        val mergedStatus = when {
            incoming.status == DisputeStatus.CLOSED || incoming.status == DisputeStatus.RESOLVED -> incoming.status
            previous.status == DisputeStatus.CLOSED || previous.status == DisputeStatus.RESOLVED -> previous.status
            incoming.status.ordinal >= previous.status.ordinal -> incoming.status
            else -> previous.status
        }
        return incoming.copy(
            caseId = incoming.caseId.ifBlank { previous.caseId },
            status = mergedStatus,
            summary = incoming.summary.ifBlank { previous.summary },
            issueType = incoming.issueType ?: previous.issueType,
            evidenceRefs = (previous.evidenceRefs + incoming.evidenceRefs).distinct().take(10),
            reasonCodes = (previous.reasonCodes + incoming.reasonCodes).distinct(),
            events = mergedEvents,
            openedAtMs = previous.openedAtMs ?: incoming.openedAtMs,
            updatedAtMs = maxOf(previous.updatedAtMs, incoming.updatedAtMs),
            closedAtMs = incoming.closedAtMs ?: previous.closedAtMs
        )
    }

    private fun updateRemotePipelineRecords(
        userId: String,
        record: ExecutionReceiptRecord,
        forceReconciliationRetry: Boolean = false
    ) {
        if (userId.isBlank() || record.runId.isBlank()) return
        val now = nowMs()
        val telemetryRecord = buildTelemetryEmissionRecord(record, now)
        val alertRecord = buildAlertDeliveryRecord(record, now)
        val reconciliationJob = buildReconciliationJobRecord(
            record = record,
            now = now,
            forceRetry = forceReconciliationRetry
        )
        synchronized(dynamicStateLock) {
            telemetryRecord?.let { upsertTelemetryEmissionRecord(userId, it) }
            alertRecord?.let { upsertAlertDeliveryRecord(userId, it) }
            reconciliationJob?.let { upsertReconciliationJobRecord(userId, it) }

            val ledger = executionLedgerByUser[userId] ?: return@synchronized
            val records = ledger.toMutableList()
            val targetIndex = records.indexOfLast { it.runId == record.runId }
            if (targetIndex < 0) return@synchronized
            val target = records[targetIndex]
            val updatedReceipt = target.receipt?.copy(
                remotePipelineSummary = remotePipelineSummaryForRunLocked(userId, record.runId),
                remoteOperatorHandoffSummary = buildRemoteOperatorHandoffSummary(
                    remoteOperatorHandoffForRunLocked(userId, record.runId)
                ),
                alertRoutingSummary = buildAlertRoutingSummary(
                    alertRoutingForRunLocked(userId, record.runId)
                )
            )
            records[targetIndex] = target.copy(
                receipt = updatedReceipt,
                updatedAtMs = maxOf(target.updatedAtMs, now)
            )
            executionLedgerByUser[userId] = ArrayDeque(records.takeLast(MAX_LEDGER_RECORDS))
        }
    }

    private fun buildTelemetryEmissionRecord(
        record: ExecutionReceiptRecord,
        now: Long
    ): TelemetryEmissionRecord? {
        if (record.runId.isBlank()) return null
        val signal = toGovernanceSignal(record)
        val reasonCodes = collectReasonCodes(record).toList().sorted()
        val policyVersion = record.policySnapshot?.policyVersion
            ?: record.snapshotBinding?.snapshotVersion
            ?: record.receipt?.policySnapshotVersion
        val providerId = record.receipt?.selectedProviderId
            ?: record.settlementRecord?.selectedProviderId
            ?: record.providerDecisions.firstOrNull()?.providerId
        val dedupeKey = "telemetry:${record.runId}"
        val envelope = GovernanceTelemetryEnvelope(
            envelopeId = "telemetry_env_${record.runId}_$now",
            runId = record.runId,
            role = record.activeRole ?: signal.role,
            providerId = providerId,
            policySnapshotVersion = policyVersion,
            outcomeStatus = record.status,
            reasonFamily = signal.reasonFamilies.firstOrNull(),
            reasonCodes = reasonCodes,
            metrics = mapOf(
                "approval_required" to if (signal.approvalRequired) 1.0 else 0.0,
                "approval_denied" to if (signal.approvalDenied) 1.0 else 0.0,
                "external_attempt" to if (signal.externalAttempt) 1.0 else 0.0,
                "verification_failed" to if (signal.verificationFailed) 1.0 else 0.0,
                "rollback_triggered" to if (signal.rollbackTriggered) 1.0 else 0.0,
                "dispute_opened" to if (signal.disputeOpened) 1.0 else 0.0,
                "sync_pending" to if (signal.settlementSyncPending) 1.0 else 0.0
            ),
            createdAtMs = now
        )
        val batch = GovernanceTelemetryBatch(
            batchId = "telemetry_batch_${record.runId}",
            dedupeKey = dedupeKey,
            generatedAtMs = now,
            status = TelemetryDeliveryStatus.QUEUED,
            envelopes = listOf(envelope)
        )
        val attempt = telemetrySinkPort.deliver(batch, now)
        val status = attempt.status
        val reasonCodesWithRemote = buildSet {
            addAll(reasonCodes)
            when (status) {
                TelemetryDeliveryStatus.DELIVERED -> add(RoleReasonCodes.ROLE_REMOTE_TELEMETRY_DELIVERED)
                TelemetryDeliveryStatus.FAILED -> add(RoleReasonCodes.ROLE_REMOTE_TELEMETRY_DELIVERY_FAILED)
                TelemetryDeliveryStatus.QUEUED,
                TelemetryDeliveryStatus.LOCAL_ONLY -> add(RoleReasonCodes.ROLE_REMOTE_TELEMETRY_BATCH_QUEUED)
            }
        }.toList()
        return TelemetryEmissionRecord(
            recordId = "telemetry_record_${record.runId}",
            runId = record.runId,
            dedupeKey = dedupeKey,
            status = status,
            batch = batch.copy(
                status = status,
                envelopes = listOf(envelope.copy(reasonCodes = reasonCodesWithRemote)),
                attempts = listOf(attempt)
            ),
            attemptCount = 1,
            lastAttemptAtMs = now,
            lastErrorSummary = when (status) {
                TelemetryDeliveryStatus.FAILED,
                TelemetryDeliveryStatus.LOCAL_ONLY -> attempt.summary
                else -> null
            }
        )
    }

    private fun upsertTelemetryEmissionRecord(userId: String, incoming: TelemetryEmissionRecord) {
        val queue = telemetryRecordsByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val targetIndex = records.indexOfLast {
            it.runId == incoming.runId || it.dedupeKey == incoming.dedupeKey
        }
        if (targetIndex >= 0) {
            records[targetIndex] = mergeTelemetryEmissionRecord(records[targetIndex], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun mergeTelemetryEmissionRecord(
        previous: TelemetryEmissionRecord,
        incoming: TelemetryEmissionRecord
    ): TelemetryEmissionRecord {
        val mergedAttempts = (previous.batch.attempts + incoming.batch.attempts)
            .distinctBy { "${it.sinkTarget}:${it.status}:${it.dedupeKey}:${it.errorCode}" }
            .takeLast(8)
        val mergedStatus = when {
            previous.status == TelemetryDeliveryStatus.FAILED || incoming.status == TelemetryDeliveryStatus.FAILED ->
                TelemetryDeliveryStatus.FAILED
            previous.status == TelemetryDeliveryStatus.QUEUED || incoming.status == TelemetryDeliveryStatus.QUEUED ->
                TelemetryDeliveryStatus.QUEUED
            previous.status == TelemetryDeliveryStatus.LOCAL_ONLY || incoming.status == TelemetryDeliveryStatus.LOCAL_ONLY ->
                TelemetryDeliveryStatus.LOCAL_ONLY
            else -> TelemetryDeliveryStatus.DELIVERED
        }
        val mergedEnvelopes = (previous.batch.envelopes + incoming.batch.envelopes)
            .distinctBy { it.envelopeId.ifBlank { "${it.runId}:${it.createdAtMs}" } }
            .takeLast(8)
        return incoming.copy(
            status = mergedStatus,
            batch = incoming.batch.copy(
                status = mergedStatus,
                envelopes = mergedEnvelopes,
                attempts = mergedAttempts
            ),
            attemptCount = mergedAttempts.size,
            lastAttemptAtMs = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs),
            lastErrorSummary = incoming.lastErrorSummary ?: previous.lastErrorSummary
        )
    }

    private fun buildAlertDeliveryRecord(
        record: ExecutionReceiptRecord,
        now: Long
    ): AlertDeliveryRecord? {
        val request = buildAlertDispatchRequest(record, now) ?: return null
        val attempt = alertDeliveryPort.dispatch(request, now)
        val status = attempt.status
        return AlertDeliveryRecord(
            recordId = "alert_record_${request.requestId}",
            runId = request.runId,
            alertCode = request.alertCode,
            dedupeKey = request.dedupeKey,
            status = status,
            request = request,
            attempts = listOf(attempt),
            lastAttemptAtMs = now,
            deliveredAtMs = if (status == AlertDispatchStatus.DELIVERED) now else null,
            lastErrorSummary = when (status) {
                AlertDispatchStatus.FAILED,
                AlertDispatchStatus.LOCAL_ONLY -> attempt.summary
                else -> null
            }
        )
    }

    private fun buildAlertDispatchRequest(
        record: ExecutionReceiptRecord,
        now: Long
    ): AlertDispatchRequest? {
        val syncState = syncStateFor(record)
        val disputeStatus = disputeStatusFor(record)
        val providerIssue = hasProviderIssue(record)
        val code: String
        val severity: GovernanceAlertSeverity
        val title: String
        val summary: String
        val queueType: GovernanceQueueType
        when {
            syncState == SettlementSyncState.MISMATCH -> {
                code = "GOVERNANCE_ALERT_SETTLEMENT_MISMATCH"
                severity = GovernanceAlertSeverity.CRITICAL
                title = "Settlement mismatch"
                summary = "Local state and provider settlement outcome are mismatched for this run."
                queueType = GovernanceQueueType.RECONCILIATION_MISMATCH
            }
            disputeStatus == DisputeStatus.SYNC_PENDING -> {
                code = "GOVERNANCE_ALERT_DISPUTE_SYNC_PENDING"
                severity = GovernanceAlertSeverity.HIGH
                title = "Dispute sync pending"
                summary = "Dispute remains locally open while remote acknowledgement is pending."
                queueType = GovernanceQueueType.DISPUTE_FOLLOW_UP
            }
            providerIssue -> {
                code = "GOVERNANCE_ALERT_PROVIDER_ISSUE"
                severity = GovernanceAlertSeverity.WARNING
                title = "Provider issue"
                summary = "Provider decision or acknowledgement requires operator follow-up."
                queueType = GovernanceQueueType.PROVIDER_ISSUE
            }
            record.status == ResponseStatus.ERROR ||
                record.status == ResponseStatus.DISPUTED ||
                record.status == ResponseStatus.ROLLED_BACK -> {
                code = "GOVERNANCE_ALERT_RUN_ISSUE"
                severity = GovernanceAlertSeverity.WARNING
                title = "Run issue"
                summary = "External execution finished with an issue that should be reviewed."
                queueType = GovernanceQueueType.NEEDS_ATTENTION
            }
            else -> return null
        }
        val dedupeKey = "alert:${record.runId}:$code"
        return AlertDispatchRequest(
            requestId = "alert_${record.runId}_$code",
            runId = record.runId,
            alertCode = code,
            severity = severity,
            title = title,
            summary = summary,
            relatedQueue = queueType,
            dedupeKey = dedupeKey,
            target = AlertDeliveryTarget(
                targetId = "governance_console_local",
                label = "Governance Console",
                channel = AlertDeliveryChannel.LOCAL_CONSOLE
            ),
            createdAtMs = now
        )
    }

    private fun upsertAlertDeliveryRecord(userId: String, incoming: AlertDeliveryRecord) {
        val queue = alertDeliveryByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val targetIndex = records.indexOfLast {
            it.runId == incoming.runId && it.alertCode == incoming.alertCode
        }
        if (targetIndex >= 0) {
            records[targetIndex] = mergeAlertDeliveryRecord(records[targetIndex], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun mergeAlertDeliveryRecord(
        previous: AlertDeliveryRecord,
        incoming: AlertDeliveryRecord
    ): AlertDeliveryRecord {
        val mergedAttempts = (previous.attempts + incoming.attempts)
            .distinctBy { "${it.channel}:${it.status}:${it.dedupeKey}:${it.errorCode}" }
            .takeLast(8)
        val mergedStatus = when {
            previous.status == AlertDispatchStatus.FAILED || incoming.status == AlertDispatchStatus.FAILED ->
                AlertDispatchStatus.FAILED
            previous.status == AlertDispatchStatus.QUEUED || incoming.status == AlertDispatchStatus.QUEUED ->
                AlertDispatchStatus.QUEUED
            previous.status == AlertDispatchStatus.LOCAL_ONLY || incoming.status == AlertDispatchStatus.LOCAL_ONLY ->
                AlertDispatchStatus.LOCAL_ONLY
            previous.status == AlertDispatchStatus.DUPLICATE_SUPPRESSED || incoming.status == AlertDispatchStatus.DUPLICATE_SUPPRESSED ->
                AlertDispatchStatus.DUPLICATE_SUPPRESSED
            else -> AlertDispatchStatus.DELIVERED
        }
        return incoming.copy(
            status = mergedStatus,
            attempts = mergedAttempts,
            lastAttemptAtMs = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs),
            deliveredAtMs = incoming.deliveredAtMs ?: previous.deliveredAtMs,
            lastErrorSummary = incoming.lastErrorSummary ?: previous.lastErrorSummary
        )
    }

    private fun buildReconciliationJobRecord(
        record: ExecutionReceiptRecord,
        now: Long,
        forceRetry: Boolean
    ): ReconciliationJobRecord? {
        val jobType = reconciliationJobTypeFor(record) ?: if (forceRetry) ReconciliationJobType.SYNC_PENDING else null
        if (jobType == null) return null
        val dedupeKey = "reconciliation:${record.runId}:${jobType.name.lowercase()}"
        val reasonCodes = buildSet {
            add(RoleReasonCodes.ROLE_RECONCILIATION_JOB_CREATED)
            if (forceRetry) {
                add(RoleReasonCodes.ROLE_REMOTE_RETRY_REQUESTED)
            }
            collectReasonCodes(record).forEach { code ->
                if (
                    code.contains("RECONCILIATION", ignoreCase = true) ||
                    code.contains("SETTLEMENT", ignoreCase = true) ||
                    code.contains("SYNC", ignoreCase = true) ||
                    code.contains("DISPUTE", ignoreCase = true) ||
                    code.contains("PROVIDER", ignoreCase = true)
                ) {
                    add(code)
                }
            }
        }.toList()
        val baseSummary = when (jobType) {
            ReconciliationJobType.RECONCILIATION_MISMATCH ->
                "Reconciliation mismatch requires remote handoff and operator tracking."
            ReconciliationJobType.UNRESOLVED_DISPUTE ->
                "Unresolved dispute requires remote acknowledgement and follow-up."
            ReconciliationJobType.PROVIDER_ISSUE ->
                "Provider issue requires retry/handoff tracking."
            ReconciliationJobType.SYNC_PENDING ->
                "Sync pending requires remote reconciliation follow-up."
        }
        val baseJob = ReconciliationJobRecord(
            jobId = "recon_job_${record.runId}_${jobType.name.lowercase()}",
            runId = record.runId,
            type = jobType,
            status = if (forceRetry) ReconciliationJobStatus.RETRY_SCHEDULED else ReconciliationJobStatus.OPEN,
            handoffStatus = RemoteSyncHandoffStatus.LOCAL_ONLY,
            dedupeKey = dedupeKey,
            summary = baseSummary,
            reasonCodes = reasonCodes,
            retryPolicy = ReconciliationRetryPolicy(),
            retryCount = if (forceRetry) 1 else 0,
            nextActionSummary = if (forceRetry) {
                "Retry scheduled. Keep local authoritative state until remote acknowledgement."
            } else {
                "Track handoff and confirm reconciliation/dispute state."
            },
            createdAtMs = now,
            updatedAtMs = now
        )
        val handoffAttempt = reconciliationHandoffPort.handoff(baseJob, now)
        val handoffStatus = handoffAttempt.handoffStatus
        val resolvedStatus = when (handoffStatus) {
            RemoteSyncHandoffStatus.FAILED -> ReconciliationJobStatus.BLOCKED
            RemoteSyncHandoffStatus.HANDOFF_PENDING -> ReconciliationJobStatus.HANDOFF_PENDING
            RemoteSyncHandoffStatus.HANDED_OFF,
            RemoteSyncHandoffStatus.ACKNOWLEDGED -> ReconciliationJobStatus.IN_PROGRESS
            RemoteSyncHandoffStatus.LOCAL_ONLY -> if (forceRetry) ReconciliationJobStatus.RETRY_SCHEDULED else ReconciliationJobStatus.OPEN
        }
        return baseJob.copy(
            status = resolvedStatus,
            handoffStatus = handoffStatus,
            attempts = listOf(handoffAttempt),
            lastErrorSummary = handoffAttempt.errorCode ?: when (handoffStatus) {
                RemoteSyncHandoffStatus.FAILED,
                RemoteSyncHandoffStatus.LOCAL_ONLY -> handoffAttempt.summary
                else -> null
            },
            nextActionSummary = nextActionForReconciliationJob(resolvedStatus, handoffStatus),
            updatedAtMs = now
        )
    }

    private fun reconciliationJobTypeFor(record: ExecutionReceiptRecord): ReconciliationJobType? {
        val syncState = syncStateFor(record)
        val disputeStatus = disputeStatusFor(record)
        return when {
            syncState == SettlementSyncState.MISMATCH -> ReconciliationJobType.RECONCILIATION_MISMATCH
            disputeStatus == DisputeStatus.OPENED ||
                disputeStatus == DisputeStatus.SYNC_PENDING ||
                disputeStatus == DisputeStatus.ACKNOWLEDGED ||
                disputeStatus == DisputeStatus.UNDER_REVIEW -> ReconciliationJobType.UNRESOLVED_DISPUTE
            hasProviderIssue(record) -> ReconciliationJobType.PROVIDER_ISSUE
            syncState == SettlementSyncState.SYNC_PENDING -> ReconciliationJobType.SYNC_PENDING
            else -> null
        }
    }

    private fun nextActionForReconciliationJob(
        status: ReconciliationJobStatus,
        handoffStatus: RemoteSyncHandoffStatus
    ): String {
        return when {
            status == ReconciliationJobStatus.BLOCKED || handoffStatus == RemoteSyncHandoffStatus.FAILED ->
                "Remote handoff failed. Keep local authoritative state and escalate provider follow-up."
            status == ReconciliationJobStatus.HANDOFF_PENDING ->
                "Handoff is pending. Monitor remote acknowledgement before closing the case."
            status == ReconciliationJobStatus.IN_PROGRESS ->
                "Remote handoff is active. Wait for acknowledgement or reconciliation completion."
            status == ReconciliationJobStatus.RETRY_SCHEDULED ->
                "Retry was scheduled. Re-attempt handoff and keep local state authoritative."
            else ->
                "Track reconciliation progress and update operator case once remote status changes."
        }
    }

    private fun upsertReconciliationJobRecord(userId: String, incoming: ReconciliationJobRecord) {
        val queue = reconciliationJobsByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val targetIndex = records.indexOfLast {
            it.runId == incoming.runId && it.type == incoming.type
        }
        if (targetIndex >= 0) {
            records[targetIndex] = mergeReconciliationJobRecord(records[targetIndex], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun mergeReconciliationJobRecord(
        previous: ReconciliationJobRecord,
        incoming: ReconciliationJobRecord
    ): ReconciliationJobRecord {
        val mergedAttempts = (previous.attempts + incoming.attempts)
            .distinctBy { "${it.handoffStatus}:${it.dedupeKey}:${it.errorCode}" }
            .takeLast(8)
        val mergedStatus = when {
            previous.status == ReconciliationJobStatus.BLOCKED || incoming.status == ReconciliationJobStatus.BLOCKED ->
                ReconciliationJobStatus.BLOCKED
            previous.status == ReconciliationJobStatus.HANDOFF_PENDING || incoming.status == ReconciliationJobStatus.HANDOFF_PENDING ->
                ReconciliationJobStatus.HANDOFF_PENDING
            previous.status == ReconciliationJobStatus.RETRY_SCHEDULED || incoming.status == ReconciliationJobStatus.RETRY_SCHEDULED ->
                ReconciliationJobStatus.RETRY_SCHEDULED
            previous.status == ReconciliationJobStatus.IN_PROGRESS || incoming.status == ReconciliationJobStatus.IN_PROGRESS ->
                ReconciliationJobStatus.IN_PROGRESS
            previous.status == ReconciliationJobStatus.OPEN || incoming.status == ReconciliationJobStatus.OPEN ->
                ReconciliationJobStatus.OPEN
            else -> ReconciliationJobStatus.RESOLVED
        }
        val mergedHandoffStatus = when {
            previous.handoffStatus == RemoteSyncHandoffStatus.FAILED || incoming.handoffStatus == RemoteSyncHandoffStatus.FAILED ->
                RemoteSyncHandoffStatus.FAILED
            previous.handoffStatus == RemoteSyncHandoffStatus.HANDOFF_PENDING || incoming.handoffStatus == RemoteSyncHandoffStatus.HANDOFF_PENDING ->
                RemoteSyncHandoffStatus.HANDOFF_PENDING
            previous.handoffStatus == RemoteSyncHandoffStatus.LOCAL_ONLY || incoming.handoffStatus == RemoteSyncHandoffStatus.LOCAL_ONLY ->
                RemoteSyncHandoffStatus.LOCAL_ONLY
            previous.handoffStatus == RemoteSyncHandoffStatus.HANDED_OFF || incoming.handoffStatus == RemoteSyncHandoffStatus.HANDED_OFF ->
                RemoteSyncHandoffStatus.HANDED_OFF
            else -> RemoteSyncHandoffStatus.ACKNOWLEDGED
        }
        return incoming.copy(
            status = mergedStatus,
            handoffStatus = mergedHandoffStatus,
            reasonCodes = (previous.reasonCodes + incoming.reasonCodes).distinct(),
            retryCount = maxOf(previous.retryCount, incoming.retryCount),
            attempts = mergedAttempts,
            lastErrorSummary = incoming.lastErrorSummary ?: previous.lastErrorSummary,
            nextActionSummary = incoming.nextActionSummary.ifBlank {
                previous.nextActionSummary.ifBlank {
                    nextActionForReconciliationJob(mergedStatus, mergedHandoffStatus)
                }
            },
            createdAtMs = listOf(previous.createdAtMs, incoming.createdAtMs).filter { it > 0L }.minOrNull()
                ?: incoming.createdAtMs,
            updatedAtMs = maxOf(previous.updatedAtMs, incoming.updatedAtMs)
        )
    }

    private fun remotePipelineSummaryForRun(userId: String, runId: String): RemotePipelineSummary? {
        if (userId.isBlank() || runId.isBlank()) return null
        restoreDynamicStateIfNeeded(userId)
        return synchronized(dynamicStateLock) {
            remotePipelineSummaryForRunLocked(userId, runId)
        }
    }

    private fun remotePipelineSummaryForRunLocked(userId: String, runId: String): RemotePipelineSummary? {
        val telemetry = telemetryRecordsByUser[userId]
            ?.filter { it.runId == runId }
            .orEmpty()
        val alerts = alertDeliveryByUser[userId]
            ?.filter { it.runId == runId }
            .orEmpty()
        val reconciliation = reconciliationJobsByUser[userId]
            ?.filter { it.runId == runId }
            .orEmpty()
        if (telemetry.isEmpty() && alerts.isEmpty() && reconciliation.isEmpty()) return null
        return buildRemotePipelineSummary(telemetry, alerts, reconciliation)
    }

    private fun remotePipelineSummaryForCases(
        userId: String,
        cases: List<GovernanceCaseRecord>
    ): RemotePipelineSummary? {
        if (cases.isEmpty()) return null
        val runIds = cases.map { it.summary.runId }.filter { it.isNotBlank() }.toSet()
        if (runIds.isEmpty()) return null
        val telemetry = synchronized(dynamicStateLock) {
            telemetryRecordsByUser[userId]
                ?.asSequence()
                ?.filter { runIds.contains(it.runId) }
                ?.toList()
                .orEmpty()
        }
        val alerts = synchronized(dynamicStateLock) {
            alertDeliveryByUser[userId]
                ?.asSequence()
                ?.filter { runIds.contains(it.runId) }
                ?.toList()
                .orEmpty()
        }
        val reconciliation = synchronized(dynamicStateLock) {
            reconciliationJobsByUser[userId]
                ?.asSequence()
                ?.filter { runIds.contains(it.runId) }
                ?.toList()
                .orEmpty()
        }
        if (telemetry.isEmpty() && alerts.isEmpty() && reconciliation.isEmpty()) return null
        val base = buildRemotePipelineSummary(telemetry, alerts, reconciliation)
        return base.copy(
            summary = "Remote pipeline across ${runIds.size} run(s): ${base.summary}"
        )
    }

    private fun buildRemotePipelineSummary(
        telemetry: List<TelemetryEmissionRecord>,
        alerts: List<AlertDeliveryRecord>,
        reconciliation: List<ReconciliationJobRecord>
    ): RemotePipelineSummary {
        val telemetryStatus = when {
            telemetry.any { it.status == TelemetryDeliveryStatus.FAILED } -> TelemetryDeliveryStatus.FAILED
            telemetry.any { it.status == TelemetryDeliveryStatus.QUEUED } -> TelemetryDeliveryStatus.QUEUED
            telemetry.any { it.status == TelemetryDeliveryStatus.LOCAL_ONLY } -> TelemetryDeliveryStatus.LOCAL_ONLY
            telemetry.any { it.status == TelemetryDeliveryStatus.DELIVERED } -> TelemetryDeliveryStatus.DELIVERED
            else -> TelemetryDeliveryStatus.LOCAL_ONLY
        }
        val alertStatus = when {
            alerts.any { it.status == AlertDispatchStatus.FAILED } -> AlertDispatchStatus.FAILED
            alerts.any { it.status == AlertDispatchStatus.QUEUED } -> AlertDispatchStatus.QUEUED
            alerts.any { it.status == AlertDispatchStatus.LOCAL_ONLY } -> AlertDispatchStatus.LOCAL_ONLY
            alerts.any { it.status == AlertDispatchStatus.DUPLICATE_SUPPRESSED } -> AlertDispatchStatus.DUPLICATE_SUPPRESSED
            alerts.any { it.status == AlertDispatchStatus.DELIVERED } -> AlertDispatchStatus.DELIVERED
            else -> AlertDispatchStatus.LOCAL_ONLY
        }
        val reconciliationStatus = when {
            reconciliation.any { it.status == ReconciliationJobStatus.BLOCKED } -> ReconciliationJobStatus.BLOCKED
            reconciliation.any { it.status == ReconciliationJobStatus.HANDOFF_PENDING } -> ReconciliationJobStatus.HANDOFF_PENDING
            reconciliation.any { it.status == ReconciliationJobStatus.RETRY_SCHEDULED } -> ReconciliationJobStatus.RETRY_SCHEDULED
            reconciliation.any { it.status == ReconciliationJobStatus.IN_PROGRESS } -> ReconciliationJobStatus.IN_PROGRESS
            reconciliation.any { it.status == ReconciliationJobStatus.OPEN } -> ReconciliationJobStatus.OPEN
            reconciliation.any { it.status == ReconciliationJobStatus.RESOLVED } -> ReconciliationJobStatus.RESOLVED
            else -> null
        }
        val handoffStatus = when {
            reconciliation.any { it.handoffStatus == RemoteSyncHandoffStatus.FAILED } -> RemoteSyncHandoffStatus.FAILED
            reconciliation.any { it.handoffStatus == RemoteSyncHandoffStatus.HANDOFF_PENDING } -> RemoteSyncHandoffStatus.HANDOFF_PENDING
            reconciliation.any { it.handoffStatus == RemoteSyncHandoffStatus.LOCAL_ONLY } -> RemoteSyncHandoffStatus.LOCAL_ONLY
            reconciliation.any { it.handoffStatus == RemoteSyncHandoffStatus.HANDED_OFF } -> RemoteSyncHandoffStatus.HANDED_OFF
            reconciliation.any { it.handoffStatus == RemoteSyncHandoffStatus.ACKNOWLEDGED } -> RemoteSyncHandoffStatus.ACKNOWLEDGED
            else -> RemoteSyncHandoffStatus.LOCAL_ONLY
        }
        val telemetryPendingCount = telemetry.count {
            it.status == TelemetryDeliveryStatus.QUEUED || it.status == TelemetryDeliveryStatus.LOCAL_ONLY
        }
        val telemetryFailedCount = telemetry.count { it.status == TelemetryDeliveryStatus.FAILED }
        val alertPendingCount = alerts.count {
            it.status == AlertDispatchStatus.QUEUED || it.status == AlertDispatchStatus.LOCAL_ONLY
        }
        val alertFailedCount = alerts.count { it.status == AlertDispatchStatus.FAILED }
        val reconciliationOpenCount = reconciliation.count { it.status != ReconciliationJobStatus.RESOLVED }
        val handoffPendingCount = reconciliation.count {
            it.handoffStatus == RemoteSyncHandoffStatus.HANDOFF_PENDING ||
                it.handoffStatus == RemoteSyncHandoffStatus.LOCAL_ONLY
        }
        val handoffFailedCount = reconciliation.count { it.handoffStatus == RemoteSyncHandoffStatus.FAILED }
        val lastUpdatedAt = buildList {
            addAll(telemetry.map { it.lastAttemptAtMs })
            addAll(alerts.map { it.lastAttemptAtMs })
            addAll(reconciliation.map { it.updatedAtMs })
        }
            .filter { it > 0L }
            .maxOrNull()
            ?: nowMs()
        val summary = buildString {
            append(
                "Telemetry ${telemetryStatus.name.lowercase().replace('_', ' ')} " +
                    "(pending $telemetryPendingCount, failed $telemetryFailedCount)"
            )
            append(" · Alerts ${alertStatus.name.lowercase().replace('_', ' ')} ")
            append("(pending $alertPendingCount, failed $alertFailedCount)")
            if (reconciliationStatus != null) {
                append(" · Reconciliation ${reconciliationStatus.name.lowercase().replace('_', ' ')} ")
                append("(open $reconciliationOpenCount, handoff pending $handoffPendingCount, failed $handoffFailedCount)")
            }
        }
        return RemotePipelineSummary(
            telemetryStatus = telemetryStatus,
            telemetryPendingCount = telemetryPendingCount,
            telemetryFailedCount = telemetryFailedCount,
            alertStatus = alertStatus,
            alertPendingCount = alertPendingCount,
            alertFailedCount = alertFailedCount,
            reconciliationStatus = reconciliationStatus,
            handoffStatus = handoffStatus,
            reconciliationOpenCount = reconciliationOpenCount,
            handoffPendingCount = handoffPendingCount,
            handoffFailedCount = handoffFailedCount,
            lastUpdatedAtMs = lastUpdatedAt,
            summary = summary
        )
    }

    private fun remoteDeliveryIssuesForRun(userId: String, runId: String): List<RemoteDeliveryIssue> {
        if (userId.isBlank() || runId.isBlank()) return emptyList()
        restoreDynamicStateIfNeeded(userId)
        return synchronized(dynamicStateLock) {
            val telemetry = telemetryRecordsByUser[userId]
                ?.filter { it.runId == runId }
                .orEmpty()
            val alerts = alertDeliveryByUser[userId]
                ?.filter { it.runId == runId }
                .orEmpty()
            val reconciliation = reconciliationJobsByUser[userId]
                ?.filter { it.runId == runId }
                .orEmpty()
            buildRemoteDeliveryIssues(runId, telemetry, alerts, reconciliation)
        }
    }

    private fun aggregateRemoteDeliveryIssues(
        userId: String,
        cases: List<GovernanceCaseRecord>
    ): List<RemoteDeliveryIssue> {
        if (cases.isEmpty()) return emptyList()
        val runIds = cases.map { it.summary.runId }.filter { it.isNotBlank() }.toSet()
        if (runIds.isEmpty()) return emptyList()
        val snapshot = synchronized(dynamicStateLock) {
            Triple(
                telemetryRecordsByUser[userId]
                    ?.asSequence()
                    ?.filter { runIds.contains(it.runId) }
                    ?.groupBy { it.runId }
                    .orEmpty(),
                alertDeliveryByUser[userId]
                    ?.asSequence()
                    ?.filter { runIds.contains(it.runId) }
                    ?.groupBy { it.runId }
                    .orEmpty(),
                reconciliationJobsByUser[userId]
                    ?.asSequence()
                    ?.filter { runIds.contains(it.runId) }
                    ?.groupBy { it.runId }
                    .orEmpty()
            )
        }
        val telemetryByRun = snapshot.first
        val alertsByRun = snapshot.second
        val reconciliationByRun = snapshot.third
        val grouped = linkedMapOf<String, RemoteDeliveryIssue>()
        runIds.forEach { runId ->
            val issues = buildRemoteDeliveryIssues(
                runId = runId,
                telemetry = telemetryByRun[runId].orEmpty(),
                alerts = alertsByRun[runId].orEmpty(),
                reconciliation = reconciliationByRun[runId].orEmpty()
            )
            issues.forEach { issue ->
                val key = "${issue.code}:${issue.relatedRunId.orEmpty()}"
                val existing = grouped[key]
                grouped[key] = if (existing == null) {
                    issue
                } else {
                    existing.copy(
                        severity = if (issue.severity.ordinal > existing.severity.ordinal) issue.severity else existing.severity,
                        summary = if (existing.summary.length >= issue.summary.length) existing.summary else issue.summary,
                        lastOccurredAtMs = maxOf(existing.lastOccurredAtMs, issue.lastOccurredAtMs)
                    )
                }
            }
        }
        return grouped.values
            .sortedWith(compareByDescending<RemoteDeliveryIssue> { it.severity.ordinal }.thenByDescending { it.lastOccurredAtMs })
            .take(12)
    }

    private fun buildRemoteDeliveryIssues(
        runId: String,
        telemetry: List<TelemetryEmissionRecord>,
        alerts: List<AlertDeliveryRecord>,
        reconciliation: List<ReconciliationJobRecord>
    ): List<RemoteDeliveryIssue> {
        val issues = mutableListOf<RemoteDeliveryIssue>()
        telemetry
            .filter { it.status == TelemetryDeliveryStatus.FAILED || it.status == TelemetryDeliveryStatus.LOCAL_ONLY }
            .forEach { item ->
                val code = if (item.status == TelemetryDeliveryStatus.FAILED) {
                    "REMOTE_TELEMETRY_FAILED"
                } else {
                    "REMOTE_TELEMETRY_LOCAL_ONLY"
                }
                val severity = if (item.status == TelemetryDeliveryStatus.FAILED) {
                    GovernanceAlertSeverity.WARNING
                } else {
                    GovernanceAlertSeverity.INFO
                }
                issues += RemoteDeliveryIssue(
                    code = code,
                    severity = severity,
                    title = "Telemetry delivery issue",
                    summary = item.lastErrorSummary ?: "Telemetry stayed local and was not remotely delivered.",
                    relatedRunId = runId,
                    lastOccurredAtMs = item.lastAttemptAtMs
                )
            }
        alerts
            .filter { it.status == AlertDispatchStatus.FAILED || it.status == AlertDispatchStatus.LOCAL_ONLY }
            .forEach { item ->
                val code = if (item.status == AlertDispatchStatus.FAILED) {
                    "REMOTE_ALERT_FAILED"
                } else {
                    "REMOTE_ALERT_LOCAL_ONLY"
                }
                val severity = if (item.status == AlertDispatchStatus.FAILED) {
                    GovernanceAlertSeverity.WARNING
                } else {
                    GovernanceAlertSeverity.INFO
                }
                issues += RemoteDeliveryIssue(
                    code = code,
                    severity = severity,
                    title = "Alert delivery issue",
                    summary = item.lastErrorSummary ?: "Alert remained local and was not remotely delivered.",
                    relatedRunId = runId,
                    lastOccurredAtMs = item.lastAttemptAtMs
                )
            }
        reconciliation
            .filter {
                it.status == ReconciliationJobStatus.BLOCKED ||
                    it.status == ReconciliationJobStatus.HANDOFF_PENDING ||
                    it.handoffStatus == RemoteSyncHandoffStatus.FAILED
            }
            .forEach { item ->
                val code = when {
                    item.handoffStatus == RemoteSyncHandoffStatus.FAILED -> "REMOTE_RECONCILIATION_HANDOFF_FAILED"
                    item.status == ReconciliationJobStatus.BLOCKED -> "REMOTE_RECONCILIATION_BLOCKED"
                    else -> "REMOTE_RECONCILIATION_PENDING"
                }
                val severity = when {
                    item.handoffStatus == RemoteSyncHandoffStatus.FAILED -> GovernanceAlertSeverity.HIGH
                    item.status == ReconciliationJobStatus.BLOCKED -> GovernanceAlertSeverity.HIGH
                    else -> GovernanceAlertSeverity.WARNING
                }
                issues += RemoteDeliveryIssue(
                    code = code,
                    severity = severity,
                    title = "Reconciliation handoff issue",
                    summary = item.lastErrorSummary ?: item.summary,
                    relatedRunId = runId,
                    lastOccurredAtMs = item.updatedAtMs
                )
            }
        return issues
            .distinctBy { "${it.code}:${it.summary}" }
            .take(8)
    }

    private fun aggregateCollaborationSummary(
        cases: List<GovernanceCaseRecord>
    ): GovernanceConsoleCollaborationSummary? {
        if (cases.isEmpty()) return null
        val states = cases.mapNotNull { it.collaborationState }
        if (states.isEmpty()) return null
        return GovernanceConsoleCollaborationSummary(
            claimedCases = states.count { it.claimStatus == OperatorCaseClaimStatus.CLAIMED },
            assignedCases = states.count { it.assignedTo != null },
            followUpPendingCases = states.count {
                it.status == OperatorCollaborationStatus.FOLLOW_UP_PENDING ||
                    it.followUp?.ackPending == true
            },
            noteCount = states.sumOf { it.notes.size },
            lastUpdatedAtMs = states.maxOfOrNull { it.updatedAtMs } ?: nowMs()
        )
    }

    private fun aggregateRemoteOperatorSummary(
        cases: List<GovernanceCaseRecord>
    ): GovernanceConsoleRemoteOperatorSummary? {
        if (cases.isEmpty()) return null
        val handoffRecords = cases.mapNotNull { it.remoteOperatorHandoff }
        val routingRecords = cases.flatMap { it.alertRoutingRecords }
        if (handoffRecords.isEmpty() && routingRecords.isEmpty()) return null
        val lastUpdated = maxOf(
            handoffRecords.maxOfOrNull { it.lastAttemptAtMs } ?: 0L,
            routingRecords.maxOfOrNull { it.lastAttemptAtMs } ?: 0L
        )
        return GovernanceConsoleRemoteOperatorSummary(
            handoffPendingCases = handoffRecords.count {
                it.status == RemoteOperatorHandoffStatus.HANDOFF_PENDING ||
                    it.status == RemoteOperatorHandoffStatus.REQUESTED
            },
            ackPendingCases = handoffRecords.count { it.status == RemoteOperatorHandoffStatus.ACK_PENDING },
            failedHandoffCases = handoffRecords.count { it.status == RemoteOperatorHandoffStatus.FAILED },
            alertRoutingFailedCases = routingRecords.count { it.status == AlertRoutingStatus.FAILED },
            connectorDeadLetterCases = cases.count { it.summary.connectorDeadLetterCount > 0 },
            connectorUnavailableCases = cases.count { case ->
                (case.connectorRoutingSummary?.unavailableTargets ?: 0) > 0 ||
                    (case.connectorHealthSummary?.unavailableTargets ?: 0) > 0
            },
            lastUpdatedAtMs = if (lastUpdated > 0) lastUpdated else nowMs()
        )
    }

    private fun buildOperatorQueuePresets(
        cases: List<GovernanceCaseRecord>
    ): List<OperatorQueuePresetMatch> {
        fun highPriorityCount(matches: Sequence<GovernanceCaseRecord>): Int {
            return matches.count { case ->
                case.summary.priority == GovernanceCasePriority.HIGH ||
                    case.summary.priority == GovernanceCasePriority.CRITICAL
            }
        }
        return listOf(
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.ALL,
                label = "All open cases",
                count = cases.size,
                highPriorityCount = highPriorityCount(cases.asSequence())
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.NEEDS_ATTENTION,
                label = "Needs attention",
                queueHint = GovernanceQueueType.NEEDS_ATTENTION,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.NEEDS_ATTENTION) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.NEEDS_ATTENTION) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.SYNC_PENDING,
                label = "Sync pending",
                queueHint = GovernanceQueueType.SYNC_PENDING,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.SYNC_PENDING) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.SYNC_PENDING) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.PROVIDER_ISSUE,
                label = "Provider issues",
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.DISPUTE_FOLLOW_UP,
                label = "Dispute follow-up",
                queueHint = GovernanceQueueType.DISPUTE_FOLLOW_UP,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.VERIFICATION_FAILURE,
                label = "Verification failures",
                queueHint = GovernanceQueueType.VERIFICATION_FAILURE,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.ROLLBACK_FAILURE,
                label = "Rollback failures",
                queueHint = GovernanceQueueType.ROLLBACK_FAILURE,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter { it.summary.queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE) }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.RECONCILIATION_MISMATCH,
                label = "Reconciliation mismatch",
                queueHint = GovernanceQueueType.RECONCILIATION_MISMATCH,
                count = cases.count { it.summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) },
                highPriorityCount = highPriorityCount(
                    cases.asSequence().filter {
                        it.summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH)
                    }
                )
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.CONNECTOR_HEALTH,
                label = "Connector health issues",
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                count = cases.count { hasConnectorHealthIssue(it) },
                highPriorityCount = highPriorityCount(cases.asSequence().filter { hasConnectorHealthIssue(it) })
            ),
            OperatorQueuePresetMatch(
                preset = OperatorQueuePreset.VAULT_HEALTH,
                label = "Vault and credential issues",
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                count = cases.count { hasVaultHealthIssue(it) },
                highPriorityCount = highPriorityCount(cases.asSequence().filter { hasVaultHealthIssue(it) })
            )
        )
    }

    private fun buildOperatorHomeSummary(
        cases: List<GovernanceCaseRecord>,
        presets: List<OperatorQueuePresetMatch>,
        alerts: List<GovernanceAlert>
    ): OperatorHomeSummary {
        val now = nowMs()
        val connectorIssueCases = cases.count { hasConnectorHealthIssue(it) }
        val vaultIssueCases = cases.count { hasVaultHealthIssue(it) }
        val syncPendingCases = cases.count { it.summary.queueTags.contains(GovernanceQueueType.SYNC_PENDING) }
        val disputeCases = cases.count { it.summary.queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) }
        val mismatchCases = cases.count { it.summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) }
        val directorySyncCases = cases.count {
            it.directorySyncSummary.contains("stale", ignoreCase = true) ||
                it.directorySyncSummary.contains("error", ignoreCase = true) ||
                it.directorySyncSummary.contains("blocked", ignoreCase = true)
        }
        val authProvenanceCases = cases.count {
            it.sessionAuthProvenanceSummary.contains("fallback", ignoreCase = true) ||
                it.remoteAuthorizationSummary.contains("denied", ignoreCase = true)
        }
        val healthBuckets = listOf(
            OperatorHealthBucket(
                type = OperatorHealthBucketType.CONNECTOR_HEALTH,
                label = "Connector health",
                severity = if (connectorIssueCases > 0) GovernanceAlertSeverity.HIGH else GovernanceAlertSeverity.INFO,
                count = connectorIssueCases,
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                summary = if (connectorIssueCases > 0) {
                    "$connectorIssueCases case(s) need connector retry or reroute."
                } else {
                    "No connector health issues detected."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.VAULT_HEALTH,
                label = "Vault and credential",
                severity = if (vaultIssueCases > 0) GovernanceAlertSeverity.HIGH else GovernanceAlertSeverity.INFO,
                count = vaultIssueCases,
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                summary = if (vaultIssueCases > 0) {
                    "$vaultIssueCases case(s) blocked or degraded by vault/credential state."
                } else {
                    "Vault and credential status is healthy for tracked cases."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.SYNC_PENDING,
                label = "Sync pending",
                severity = if (syncPendingCases > 0) GovernanceAlertSeverity.WARNING else GovernanceAlertSeverity.INFO,
                count = syncPendingCases,
                queueHint = GovernanceQueueType.SYNC_PENDING,
                summary = if (syncPendingCases > 0) {
                    "$syncPendingCases case(s) are waiting for remote sync acknowledgement."
                } else {
                    "No pending sync backlog."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.DISPUTE_OPEN,
                label = "Dispute follow-up",
                severity = if (disputeCases > 0) GovernanceAlertSeverity.HIGH else GovernanceAlertSeverity.INFO,
                count = disputeCases,
                queueHint = GovernanceQueueType.DISPUTE_FOLLOW_UP,
                summary = if (disputeCases > 0) {
                    "$disputeCases case(s) require dispute follow-up."
                } else {
                    "No active dispute follow-up queue."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.RECONCILIATION_MISMATCH,
                label = "Reconciliation mismatch",
                severity = if (mismatchCases > 0) GovernanceAlertSeverity.WARNING else GovernanceAlertSeverity.INFO,
                count = mismatchCases,
                queueHint = GovernanceQueueType.RECONCILIATION_MISMATCH,
                summary = if (mismatchCases > 0) {
                    "$mismatchCases case(s) show reconciliation mismatch."
                } else {
                    "No reconciliation mismatches detected."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.DIRECTORY_SYNC,
                label = "Directory sync health",
                severity = if (directorySyncCases > 0) GovernanceAlertSeverity.WARNING else GovernanceAlertSeverity.INFO,
                count = directorySyncCases,
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                summary = if (directorySyncCases > 0) {
                    "$directorySyncCases case(s) include stale or blocked directory sync signals."
                } else {
                    "Directory sync looks stable for tracked cases."
                }
            ),
            OperatorHealthBucket(
                type = OperatorHealthBucketType.AUTH_PROVENANCE,
                label = "Authorization provenance",
                severity = if (authProvenanceCases > 0) GovernanceAlertSeverity.WARNING else GovernanceAlertSeverity.INFO,
                count = authProvenanceCases,
                queueHint = GovernanceQueueType.PROVIDER_ISSUE,
                summary = if (authProvenanceCases > 0) {
                    "$authProvenanceCases case(s) are using fallback or denied remote auth context."
                } else {
                    "Authorization provenance has no active fallback warnings."
                }
            )
        )
        val highPriority = cases.count {
            it.summary.priority == GovernanceCasePriority.HIGH ||
                it.summary.priority == GovernanceCasePriority.CRITICAL
        }
        val summary = "Open ${cases.size} · High priority $highPriority · " +
            "Sync pending $syncPendingCases · Alerts ${alerts.sumOf { it.count }}"
        return OperatorHomeSummary(
            openCases = cases.count { !it.summary.reviewed },
            highPriorityCases = highPriority,
            syncPendingCases = syncPendingCases,
            escalatedCases = cases.count { it.summary.escalated },
            connectorIssueCases = connectorIssueCases,
            vaultIssueCases = vaultIssueCases,
            updatedAtMs = now,
            presets = presets,
            healthBuckets = healthBuckets,
            summary = summary
        )
    }

    private fun hasConnectorHealthIssue(case: GovernanceCaseRecord): Boolean {
        return case.summary.connectorDeadLetterCount > 0 ||
            case.summary.connectorFailedCount > 0 ||
            (case.connectorHealthSummary?.degradedTargets ?: 0) > 0 ||
            (case.connectorHealthSummary?.deadLetterTargets ?: 0) > 0 ||
            (case.connectorHealthSummary?.unavailableTargets ?: 0) > 0 ||
            case.deadLetterSummary.isNotBlank()
    }

    private fun hasVaultHealthIssue(case: GovernanceCaseRecord): Boolean {
        return (case.vaultHealth?.status ?: VaultLeaseStatus.UNKNOWN) != VaultLeaseStatus.ACTIVE ||
            case.vaultCredentialSummary.contains("expired", ignoreCase = true) ||
            case.vaultCredentialSummary.contains("revoked", ignoreCase = true) ||
            case.vaultCredentialSummary.contains("rotation", ignoreCase = true) ||
            case.vaultCredentialSummary.contains("degraded", ignoreCase = true) ||
            case.connectorCredentialSummary.contains("vault", ignoreCase = true)
    }

    private fun buildExecutionReceiptRecord(
        userId: String,
        request: AgentRequest,
        response: AgentResponse,
        receipt: ExecutionReceipt,
        policySnapshot: RolePolicySnapshot,
        updatedAtMs: Long
    ): ExecutionReceiptRecord {
        val runEvents = buildLedgerRunEvents(
            receipt = receipt,
            policySnapshot = policySnapshot,
            updatedAtMs = updatedAtMs
        )
        val providerDecisions = buildLedgerProviderDecisions(
            receipt = receipt,
            updatedAtMs = updatedAtMs
        )
        val verificationRecord = buildLedgerVerificationRecord(
            receipt = receipt,
            updatedAtMs = updatedAtMs
        )
        val settlementRecord = buildLedgerSettlementRecord(
            receipt = receipt,
            updatedAtMs = updatedAtMs
        )
        val rollbackRecord = buildLedgerRollbackRecord(
            receipt = receipt,
            updatedAtMs = updatedAtMs
        )
        val rollbackAttempts = buildLedgerRollbackAttempts(
            receipt = receipt,
            settlementRecord = settlementRecord,
            updatedAtMs = updatedAtMs
        )
        val disputeRecord = buildLedgerDisputeRecord(
            receipt = receipt,
            updatedAtMs = updatedAtMs
        )
        val disputeCaseRecord = buildLedgerDisputeCaseRecord(
            receipt = receipt,
            disputeRecord = disputeRecord,
            updatedAtMs = updatedAtMs
        )
        val collaborationState = collaborationStateForRunLocked(userId, receipt.runId)
        val remoteOperatorHandoff = remoteOperatorHandoffForRunLocked(userId, receipt.runId)
        val alertRoutingRecords = alertRoutingForRunLocked(userId, receipt.runId)
        val connectorRoutingSummary = receipt.connectorRoutingSummary
            ?: buildConnectorRoutingSummary(alertRoutingRecords)
        val connectorHealthSummary = receipt.connectorHealthSummary
            ?: connectorRoutingSummary?.connectorHealthSummary
            ?: alertRoutingRecords
                .mapNotNull { it.connectorHealthSummary }
                .maxByOrNull { it.lastUpdatedAtMs }
        val remoteAuthorization = alertRoutingRecords
            .mapNotNull { it.authorization }
            .maxByOrNull { it.evaluatedAtMs }
            ?: collaborationState?.operatorSession?.remoteAuthorization
        val operatorConnectorAudit = buildOperatorConnectorAuditLink(
            operatorIdentity = collaborationState?.operatorSession?.identity ?: OperatorIdentity(
                userId = request.userId.ifBlank { "local-user" },
                displayName = defaultOperatorDisplayName(request.userId.ifBlank { "local-user" })
            ),
            directoryEntry = null,
            remoteAuthorization = remoteAuthorization,
            routingRecord = alertRoutingRecords.lastOrNull(),
            now = updatedAtMs
        )
        val remoteAuthorizationSummary = remoteAuthorizationSummaryFor(remoteAuthorization)
            ?: receipt.remoteAuthorizationSummary
        val connectorDestinationSummary = connectorDestinationSummaryFor(alertRoutingRecords)
            ?: receipt.connectorDestinationSummary
        val connectorAuthProfileSummary = connectorAuthProfileSummaryFor(alertRoutingRecords)
            ?: receipt.connectorAuthProfileSummary
        val directorySyncSummary = directorySyncSummaryFor(remoteAuthorization, alertRoutingRecords)
            ?: receipt.directorySyncSummary
        val sessionAuthProvenanceSummary = sessionAuthProvenanceSummaryFor(remoteAuthorization)
            ?: receipt.sessionAuthProvenanceSummary
        val connectorCredentialSummary = connectorCredentialSummaryFor(alertRoutingRecords)
            ?: receipt.connectorCredentialSummary
        val operatorIdentityProvenance = operatorConnectorAudit?.identityProvenance
            ?: receipt.operatorIdentityProvenance
        val enterpriseAuthIntegration = alertRoutingRecords
            .mapNotNull { it.enterpriseAuthIntegration }
            .maxByOrNull { integration ->
                integration.directoryUpdate?.processedAtMs
                    ?: integration.directorySync?.syncedAtMs
                    ?: 0L
            }
            ?: receipt.enterpriseAuthIntegration
        val enterpriseIdentitySummary = enterpriseAuthIntegration?.identityAssertion?.summary
            ?.takeIf { it.isNotBlank() }
            ?: receipt.enterpriseIdentitySummary
            ?: operatorIdentityProvenance?.remoteIdentityLink?.identityAssertion?.summary
        val enterpriseSessionSummary = enterpriseAuthIntegration?.summary
            ?.takeIf { it.isNotBlank() }
            ?: receipt.enterpriseSessionSummary
            ?: sessionAuthProvenanceSummary
        val scimDirectorySummary = enterpriseAuthIntegration?.directoryUpdate?.summary
            ?.takeIf { it.isNotBlank() }
            ?: receipt.scimDirectorySummary
            ?: directorySyncSummary
        val vaultCredentialSummary = enterpriseAuthIntegration?.credentialBinding
            ?.vaultCredential
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: receipt.vaultCredentialSummary
            ?: connectorCredentialSummary
        val tenantRolloutProfile = alertRoutingRecords
            .mapNotNull { it.tenantRolloutProfile }
            .maxByOrNull { it.updatedAtMs }
            ?: enterpriseAuthIntegration?.tenantRolloutProfile
            ?: receipt.tenantRolloutProfile
        val workspaceRolloutProfile = alertRoutingRecords
            .mapNotNull { it.workspaceRolloutProfile }
            .maxByOrNull { it.updatedAtMs }
            ?: enterpriseAuthIntegration?.workspaceRolloutProfile
            ?: receipt.workspaceRolloutProfile
        val cutoverReadiness = alertRoutingRecords
            .mapNotNull { it.cutoverReadiness }
            .maxByOrNull { it.updatedAtMs }
            ?: enterpriseAuthIntegration?.cutoverReadiness
            ?: receipt.cutoverReadiness
        val vaultResolution = alertRoutingRecords
            .flatMap { it.vaultResolutions }
            .maxByOrNull { it.lease?.expiresAtMs ?: 0L }
            ?: enterpriseAuthIntegration?.vaultResolution
            ?: receipt.vaultResolution
        val vaultHealth = alertRoutingRecords
            .mapNotNull { it.vaultHealth }
            .maxByOrNull { it.lastCheckedAtMs }
            ?: enterpriseAuthIntegration?.vaultHealth
            ?: receipt.vaultHealth
            ?: connectorRoutingSummary?.let {
                buildVaultHealthSummary(
                    resolutions = alertRoutingRecords.flatMap { record -> record.vaultResolutions },
                    now = updatedAtMs
                )
            }
        val fallbackPolicy = alertRoutingRecords
            .mapNotNull { it.fallbackPolicy }
            .lastOrNull()
            ?: enterpriseAuthIntegration?.fallbackPolicy
            ?: receipt.fallbackPolicy
        val rolloutSummary = connectorRoutingSummary?.rolloutSummary
            ?.takeIf { it.isNotBlank() }
            ?: tenantRolloutProfile?.summary
            ?: receipt.rolloutSummary
        val cutoverReadinessSummary = connectorRoutingSummary?.cutoverSummary
            ?.takeIf { it.isNotBlank() }
            ?: cutoverReadiness?.summary
            ?: receipt.cutoverReadinessSummary
        val vaultRuntimeSummary = connectorRoutingSummary?.vaultRuntimeSummary
            ?.takeIf { it.isNotBlank() }
            ?: vaultHealth?.summary
            ?: vaultResolution?.summary
            ?: receipt.vaultRuntimeSummary
        val enterpriseFallbackSummary = connectorRoutingSummary?.enterpriseFallbackSummary
            ?.takeIf { it.isNotBlank() }
            ?: fallbackPolicy?.summary
            ?: receipt.enterpriseFallbackSummary
        val sessionAuthContext = remoteAuthorization?.sessionAuthContext
            ?: operatorConnectorAudit?.sessionAuthContext
            ?: receipt.sessionAuthContext
        val idpProviderConfig = enterpriseAuthIntegration?.idpProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.idpProviderConfig }.lastOrNull()
            ?: receipt.idpProviderConfig
        val idpSessionExchange = enterpriseAuthIntegration?.idpSessionExchange
            ?: alertRoutingRecords.mapNotNull { it.idpSessionExchange }.lastOrNull()
            ?: sessionAuthContext?.idpSessionExchange
            ?: receipt.idpSessionExchange
        val idpProviderHealth = enterpriseAuthIntegration?.idpProviderHealth
            ?: alertRoutingRecords.mapNotNull { it.idpProviderHealth }.lastOrNull()
            ?: sessionAuthContext?.idpProviderHealth
            ?: receipt.idpProviderHealth
        val scimProviderConfig = enterpriseAuthIntegration?.scimProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.scimProviderConfig }.lastOrNull()
            ?: receipt.scimProviderConfig
        val scimProviderResult = enterpriseAuthIntegration?.scimProviderResult
            ?: alertRoutingRecords.mapNotNull { it.scimProviderResult }.lastOrNull()
            ?: remoteAuthorization?.provenance?.scimProviderResult
            ?: receipt.scimProviderResult
        val directorySyncCheckpoint = enterpriseAuthIntegration?.directorySyncCheckpoint
            ?: alertRoutingRecords.mapNotNull { it.directorySyncCheckpoint }.lastOrNull()
            ?: scimProviderResult?.checkpoint
            ?: receipt.directorySyncCheckpoint
        val vaultProviderConfig = enterpriseAuthIntegration?.vaultProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.vaultProviderConfig }.lastOrNull()
            ?: receipt.vaultProviderConfig
        val vaultMaterialization = enterpriseAuthIntegration?.vaultMaterialization
            ?: alertRoutingRecords.flatMap { it.vaultMaterializationResults }
                .maxByOrNull { it.evaluatedAtMs }
            ?: receipt.vaultMaterialization
        val vaultProviderHealth = enterpriseAuthIntegration?.vaultProviderHealth
            ?: alertRoutingRecords.mapNotNull { it.vaultProviderHealth }.lastOrNull()
            ?: receipt.vaultProviderHealth
        val vaultCredentialHealthCheck = enterpriseAuthIntegration?.vaultCredentialHealthCheck
            ?: alertRoutingRecords.flatMap { it.vaultCredentialHealthChecks }
                .maxByOrNull { it.checkedAtMs }
            ?: receipt.vaultCredentialHealthCheck
        val idpProviderSummary = idpSessionExchange?.summary
            ?.takeIf { it.isNotBlank() }
            ?: idpProviderHealth?.summary
                ?.takeIf { it.isNotBlank() }
            ?: idpProviderConfig?.summary
                ?.takeIf { it.isNotBlank() }
            ?: receipt.idpProviderSummary
        val scimProviderSummary = scimProviderResult?.summary
            ?.takeIf { it.isNotBlank() }
            ?: scimProviderResult?.health?.summary
                ?.takeIf { it.isNotBlank() }
            ?: scimProviderConfig?.summary
                ?.takeIf { it.isNotBlank() }
            ?: receipt.scimProviderSummary
        val vaultProviderSummary = vaultMaterialization?.summary
            ?.takeIf { it.isNotBlank() }
            ?: vaultProviderHealth?.summary
                ?.takeIf { it.isNotBlank() }
            ?: vaultProviderConfig?.summary
                ?.takeIf { it.isNotBlank() }
            ?: receipt.vaultProviderSummary
        val directorySyncSnapshot = alertRoutingRecords
            .mapNotNull { it.directorySync }
            .maxByOrNull { it.syncedAtMs ?: 0L }
            ?: operatorConnectorAudit?.identityProvenance?.directorySync
            ?: receipt.directorySyncSnapshot
        val connectorCredentialLifecycle = alertRoutingRecords
            .flatMap { routing ->
                buildList {
                    addAll(routing.credentialLifecycleSummaries)
                    addAll(routing.targets.mapNotNull { it.credentialLifecycle })
                }
            }
            .maxByOrNull { it.evaluatedAtMs }
            ?: operatorConnectorAudit?.credentialLifecycle
            ?: receipt.connectorCredentialLifecycle
        val remoteAuthProvenance = remoteAuthorization?.provenance
            ?: receipt.remoteAuthProvenance
        val deadLetterRecords = alertRoutingRecords
            .flatMap { it.deadLetterRecords }
            .distinctBy { "${it.targetId}:${it.providerType}:${it.dedupeKey}:${it.createdAtMs}" }
        val deadLetterSummary = receipt.deadLetterSummary
            ?: deadLetterSummaryForRouting(
                routing = alertRoutingRecords,
                connectorSummary = connectorRoutingSummary,
                deadLetters = deadLetterRecords
            )
        val normalizedReceipt = if (
            receipt.connectorRoutingSummary != connectorRoutingSummary ||
            receipt.connectorHealthSummary != connectorHealthSummary ||
            receipt.deadLetterSummary != deadLetterSummary ||
            receipt.remoteAuthorizationSummary != remoteAuthorizationSummary ||
            receipt.connectorDestinationSummary != connectorDestinationSummary ||
            receipt.connectorAuthProfileSummary != connectorAuthProfileSummary ||
            receipt.directorySyncSummary != directorySyncSummary ||
            receipt.sessionAuthProvenanceSummary != sessionAuthProvenanceSummary ||
            receipt.connectorCredentialSummary != connectorCredentialSummary ||
            receipt.enterpriseIdentitySummary != enterpriseIdentitySummary ||
            receipt.enterpriseSessionSummary != enterpriseSessionSummary ||
            receipt.scimDirectorySummary != scimDirectorySummary ||
            receipt.idpProviderSummary != idpProviderSummary ||
            receipt.scimProviderSummary != scimProviderSummary ||
            receipt.vaultProviderSummary != vaultProviderSummary ||
            receipt.vaultCredentialSummary != vaultCredentialSummary ||
            receipt.rolloutSummary != rolloutSummary ||
            receipt.cutoverReadinessSummary != cutoverReadinessSummary ||
            receipt.vaultRuntimeSummary != vaultRuntimeSummary ||
            receipt.enterpriseFallbackSummary != enterpriseFallbackSummary ||
            receipt.directorySyncSnapshot != directorySyncSnapshot ||
            receipt.connectorCredentialLifecycle != connectorCredentialLifecycle ||
            receipt.idpProviderConfig != idpProviderConfig ||
            receipt.idpSessionExchange != idpSessionExchange ||
            receipt.idpProviderHealth != idpProviderHealth ||
            receipt.scimProviderConfig != scimProviderConfig ||
            receipt.scimProviderResult != scimProviderResult ||
            receipt.directorySyncCheckpoint != directorySyncCheckpoint ||
            receipt.vaultProviderConfig != vaultProviderConfig ||
            receipt.vaultMaterialization != vaultMaterialization ||
            receipt.vaultProviderHealth != vaultProviderHealth ||
            receipt.vaultCredentialHealthCheck != vaultCredentialHealthCheck ||
            receipt.enterpriseAuthIntegration != enterpriseAuthIntegration ||
            receipt.tenantRolloutProfile != tenantRolloutProfile ||
            receipt.workspaceRolloutProfile != workspaceRolloutProfile ||
            receipt.cutoverReadiness != cutoverReadiness ||
            receipt.vaultHealth != vaultHealth ||
            receipt.vaultResolution != vaultResolution ||
            receipt.fallbackPolicy != fallbackPolicy ||
            receipt.operatorIdentityProvenance != operatorIdentityProvenance ||
            receipt.remoteAuthProvenance != remoteAuthProvenance ||
            receipt.sessionAuthContext != sessionAuthContext ||
            receipt.operatorConnectorAudit != operatorConnectorAudit
        ) {
            receipt.copy(
                connectorRoutingSummary = connectorRoutingSummary,
                connectorHealthSummary = connectorHealthSummary,
                deadLetterSummary = deadLetterSummary,
                identityProvenanceSummary = operatorIdentityProvenance?.summary,
                directorySyncSummary = directorySyncSummary,
                sessionAuthProvenanceSummary = sessionAuthProvenanceSummary,
                connectorCredentialSummary = connectorCredentialSummary,
                enterpriseIdentitySummary = enterpriseIdentitySummary,
                enterpriseSessionSummary = enterpriseSessionSummary,
                scimDirectorySummary = scimDirectorySummary,
                idpProviderSummary = idpProviderSummary,
                scimProviderSummary = scimProviderSummary,
                vaultProviderSummary = vaultProviderSummary,
                vaultCredentialSummary = vaultCredentialSummary,
                rolloutSummary = rolloutSummary,
                cutoverReadinessSummary = cutoverReadinessSummary,
                vaultRuntimeSummary = vaultRuntimeSummary,
                enterpriseFallbackSummary = enterpriseFallbackSummary,
                operatorIdentityProvenance = operatorIdentityProvenance,
                directorySyncSnapshot = directorySyncSnapshot,
                remoteAuthProvenance = remoteAuthProvenance,
                sessionAuthContext = sessionAuthContext,
                connectorCredentialLifecycle = connectorCredentialLifecycle,
                idpProviderConfig = idpProviderConfig,
                idpSessionExchange = idpSessionExchange,
                idpProviderHealth = idpProviderHealth,
                scimProviderConfig = scimProviderConfig,
                scimProviderResult = scimProviderResult,
                directorySyncCheckpoint = directorySyncCheckpoint,
                vaultProviderConfig = vaultProviderConfig,
                vaultMaterialization = vaultMaterialization,
                vaultProviderHealth = vaultProviderHealth,
                vaultCredentialHealthCheck = vaultCredentialHealthCheck,
                enterpriseAuthIntegration = enterpriseAuthIntegration,
                tenantRolloutProfile = tenantRolloutProfile,
                workspaceRolloutProfile = workspaceRolloutProfile,
                cutoverReadiness = cutoverReadiness,
                vaultHealth = vaultHealth,
                vaultResolution = vaultResolution,
                fallbackPolicy = fallbackPolicy,
                remoteAuthorizationSummary = remoteAuthorizationSummary,
                connectorDestinationSummary = connectorDestinationSummary,
                connectorAuthProfileSummary = connectorAuthProfileSummary,
                operatorConnectorAudit = operatorConnectorAudit
            )
        } else {
            receipt
        }
        return ExecutionReceiptRecord(
            recordId = "ledger_${receipt.runId.take(12)}_$updatedAtMs",
            runId = receipt.runId,
            userId = userId,
            sessionId = request.sessionId,
            module = response.module,
            status = response.status,
            activeRole = response.activeRole,
            roleSource = response.roleSource,
            delegationMode = response.delegationMode,
            snapshotBinding = ReceiptSnapshotBinding(
                snapshotId = policySnapshot.snapshotId,
                runId = receipt.runId,
                snapshotVersion = policySnapshot.policyVersion,
                boundAtMs = policySnapshot.boundAtMs
            ),
            policySnapshot = policySnapshot,
            receipt = normalizedReceipt,
            runEvents = runEvents,
            providerDecisions = providerDecisions,
            verificationRecord = verificationRecord,
            settlementRecord = settlementRecord,
            rollbackRecord = rollbackRecord,
            rollbackAttempts = rollbackAttempts,
            disputeRecord = disputeRecord,
            disputeCaseRecord = disputeCaseRecord,
            reconciliationSummary = normalizedReceipt.reconciliationSummary ?: settlementRecord.reconciliation,
            syncIssues = normalizedReceipt.syncIssues,
            collaborationState = collaborationState,
            workflowPolicyProfile = collaborationState?.workflowRun?.policyProfile,
            workflowRun = collaborationState?.workflowRun,
            workflowRolloutState = normalizedReceipt.workflowPolicyRolloutState,
            workflowRolloutSummary = normalizedReceipt.workflowRolloutSummary.orEmpty(),
            workflowRolloutApprovalSummary = normalizedReceipt.workflowRolloutApprovalSummary.orEmpty(),
            workflowRolloutFreezeSummary = normalizedReceipt.workflowRolloutFreezeSummary.orEmpty(),
            workflowRolloutRollbackSummary = normalizedReceipt.workflowRolloutRollbackSummary.orEmpty(),
            rolloutWaveSummary = normalizedReceipt.rolloutWaveSummary.orEmpty(),
            calendarAwarePromotionSummary = normalizedReceipt.calendarAwarePromotionSummary.orEmpty(),
            crossWindowGovernanceSummary = normalizedReceipt.crossWindowGovernanceSummary.orEmpty(),
            rolloutPromotionCandidate = normalizedReceipt.rolloutPromotionCandidate,
            rolloutPromotionReadiness = normalizedReceipt.rolloutPromotionReadiness,
            crossWaveAnalyticsSummary = normalizedReceipt.crossWaveAnalyticsSummary,
            windowImpactSummary = normalizedReceipt.windowImpactSummary,
            rolloutPromotionOperation = normalizedReceipt.rolloutPromotionOperation,
            rolloutPromotionReadinessSummary = normalizedReceipt.rolloutPromotionReadinessSummary,
            crossWaveSummary = normalizedReceipt.crossWaveSummary,
            windowImpactReadableSummary = normalizedReceipt.windowImpactReadableSummary,
            rolloutPromotionOperationSummary = normalizedReceipt.rolloutPromotionOperationSummary,
            programCoordination = normalizedReceipt.programCoordination,
            crossProgramGovernanceSummary = normalizedReceipt.crossProgramGovernanceSummary,
            programCoordinationSummary = normalizedReceipt.programCoordinationSummary,
            crossProgramSummary = normalizedReceipt.crossProgramSummary,
            programEscalationSummary = normalizedReceipt.programEscalationSummary,
            approvalLoadSummary = normalizedReceipt.approvalLoadSummary,
            capacityBlockSummary = normalizedReceipt.capacityBlockSummary,
            policyBlockSummary = normalizedReceipt.policyBlockSummary,
            capacityBalancingSummary = normalizedReceipt.capacityBalancingSummary,
            portfolioCapacitySummary = normalizedReceipt.portfolioCapacitySummary,
            governanceCapacityPool = normalizedReceipt.governanceCapacityPool,
            approvalQueuePressure = normalizedReceipt.approvalQueuePressure,
            approvalBalancingDecision = normalizedReceipt.approvalBalancingDecision,
            approvalAssignmentRecommendation = normalizedReceipt.approvalAssignmentRecommendation,
            capacityAwarePromotionDecision = normalizedReceipt.capacityAwarePromotionDecision,
            portfolioCapacitySnapshot = normalizedReceipt.portfolioCapacitySnapshot,
            programPortfolioSummary = normalizedReceipt.programPortfolioSummary,
            remoteOperatorHandoff = remoteOperatorHandoff,
            alertRoutingRecords = alertRoutingRecords,
            connectorHealthSummary = connectorHealthSummary,
            deadLetterRecords = deadLetterRecords,
            connectorRoutingSummary = connectorRoutingSummary,
            operatorIdentityProvenance = normalizedReceipt.operatorIdentityProvenance,
            directorySyncSnapshot = normalizedReceipt.directorySyncSnapshot,
            sessionAuthContext = normalizedReceipt.sessionAuthContext,
            connectorCredentialLifecycle = normalizedReceipt.connectorCredentialLifecycle,
            enterpriseAuthIntegration = normalizedReceipt.enterpriseAuthIntegration,
            tenantRolloutProfile = normalizedReceipt.tenantRolloutProfile,
            workspaceRolloutProfile = normalizedReceipt.workspaceRolloutProfile,
            cutoverReadiness = normalizedReceipt.cutoverReadiness,
            vaultHealth = normalizedReceipt.vaultHealth,
            vaultResolution = normalizedReceipt.vaultResolution,
            fallbackPolicy = normalizedReceipt.fallbackPolicy,
            remoteAuthorizationResult = remoteAuthorization,
            operatorConnectorAudit = operatorConnectorAudit,
            responseSnapshot = response,
            legacySummary = response.summary.orEmpty(),
            createdAtMs = receipt.startedAt.takeIf { it > 0 } ?: updatedAtMs,
            updatedAtMs = updatedAtMs,
            ledgerVersion = "m7_v1"
        )
    }

    private fun buildLedgerRunEvents(
        receipt: ExecutionReceipt,
        policySnapshot: RolePolicySnapshot,
        updatedAtMs: Long
    ): List<RunEventRecord> {
        val runEvents = mutableListOf<RunEventRecord>()
        runEvents += RunEventRecord(
            eventId = "${receipt.runId}:role_selected",
            type = ProofLedgerEventType.ROLE_SELECTED,
            title = "Role selected",
            detail = "Role ${receipt.activeRole?.name?.lowercase() ?: "unknown"} was selected for this run.",
            timestampMs = receipt.startedAt.takeIf { it > 0 } ?: updatedAtMs,
            reasonCodes = receipt.roleImpactReasonCodes
        )
        runEvents += RunEventRecord(
            eventId = "${receipt.runId}:role_source_resolved",
            type = ProofLedgerEventType.ROLE_SOURCE_RESOLVED,
            title = "Role source resolved",
            detail = "Role source resolved as ${receipt.roleSource?.name?.lowercase() ?: "unknown"}.",
            timestampMs = policySnapshot.boundAtMs,
            reasonCodes = receipt.roleImpactReasonCodes
        )
        runEvents += RunEventRecord(
            eventId = "${receipt.runId}:policy_snapshot_bound",
            type = ProofLedgerEventType.ROLE_POLICY_SNAPSHOT_BOUND,
            title = "Policy snapshot bound",
            detail = "Snapshot ${policySnapshot.snapshotId} (${policySnapshot.policyVersion}) bound to this run.",
            timestampMs = policySnapshot.boundAtMs,
            reasonCodes = receipt.roleImpactReasonCodes
        )
        receipt.workflowPolicyPackId
            ?.takeIf { it.isNotBlank() }
            ?.let { packId ->
                runEvents += RunEventRecord(
                    eventId = "${receipt.runId}:workflow_pack_applied",
                    type = ProofLedgerEventType.WORKFLOW_POLICY_PACK_APPLIED,
                    title = "Workflow policy pack applied",
                    detail = receipt.workflowPolicyPackSummary
                        ?.takeIf { it.isNotBlank() }
                        ?: "Workflow policy pack $packId was applied.",
                    timestampMs = updatedAtMs,
                    reasonCodes = buildList {
                        add(RoleReasonCodes.ROLE_WORKFLOW_POLICY_PACK_APPLIED)
                        addAll(receipt.workflowPolicyResolutionReasonCodes)
                    }.distinct()
                )
            }
        if (
            !receipt.tenantWorkflowOverrideId.isNullOrBlank() ||
            !receipt.workspaceWorkflowOverrideId.isNullOrBlank()
        ) {
            runEvents += RunEventRecord(
                eventId = "${receipt.runId}:workflow_override_applied",
                type = ProofLedgerEventType.WORKFLOW_POLICY_OVERRIDE_APPLIED,
                title = "Workflow override applied",
                detail = receipt.workflowPolicyOverrideSummary
                    ?.takeIf { it.isNotBlank() }
                    ?: "Tenant/workspace workflow overrides influenced this run.",
                timestampMs = updatedAtMs,
                reasonCodes = buildList {
                    if (!receipt.tenantWorkflowOverrideId.isNullOrBlank()) {
                        add(RoleReasonCodes.ROLE_WORKFLOW_TENANT_OVERRIDE_APPLIED)
                    }
                    if (!receipt.workspaceWorkflowOverrideId.isNullOrBlank()) {
                        add(RoleReasonCodes.ROLE_WORKFLOW_WORKSPACE_OVERRIDE_APPLIED)
                    }
                    addAll(receipt.workflowPolicyResolutionReasonCodes)
                }.distinct()
            )
        }
        if (receipt.workflowSimulationOnly == true) {
            runEvents += RunEventRecord(
                eventId = "${receipt.runId}:workflow_simulation_only",
                type = ProofLedgerEventType.AUTOMATION_SIMULATION_ONLY,
                title = "Workflow automation simulation only",
                detail = receipt.workflowAutomationControlSummary
                    ?.takeIf { it.isNotBlank() }
                    ?: "Workflow automation executed in simulation-only mode.",
                timestampMs = updatedAtMs,
                reasonCodes = buildList {
                    add(RoleReasonCodes.ROLE_AUTOMATION_SIMULATION_ONLY)
                    addAll(receipt.workflowPolicyResolutionReasonCodes)
                }.distinct()
            )
        }
        if (receipt.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_POLICY_USER_OVERRIDE_APPLIED)) {
            runEvents += RunEventRecord(
                eventId = "${receipt.runId}:policy_override_applied",
                type = ProofLedgerEventType.ROLE_POLICY_OVERRIDE_APPLIED,
                title = "Policy override applied",
                detail = "User-edited role policy override influenced this run.",
                timestampMs = policySnapshot.boundAtMs,
                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_USER_OVERRIDE_APPLIED)
            )
        }
        receipt.events.forEachIndexed { index, event ->
            val mappedType = mapReceiptEventToLedgerType(event.type) ?: return@forEachIndexed
            runEvents += RunEventRecord(
                eventId = "${receipt.runId}:${mappedType.name.lowercase()}:$index",
                type = mappedType,
                title = event.title,
                detail = event.detail,
                timestampMs = event.timestampMs,
                reasonCodes = receipt.roleImpactReasonCodes
            )
        }
        return runEvents
            .distinctBy { "${it.type}:${it.detail}" }
            .sortedBy { it.timestampMs }
            .takeLast(MAX_LEDGER_EVENTS_PER_RUN)
    }

    private fun mapReceiptEventToLedgerType(type: ExecutionReceiptEventType): ProofLedgerEventType? {
        return when (type) {
            ExecutionReceiptEventType.ROLE_POLICY_SNAPSHOT_BOUND -> ProofLedgerEventType.ROLE_POLICY_SNAPSHOT_BOUND
            ExecutionReceiptEventType.APPROVAL_REQUIRED -> ProofLedgerEventType.APPROVAL_REQUESTED
            ExecutionReceiptEventType.APPROVAL_GRANTED -> ProofLedgerEventType.APPROVAL_GRANTED
            ExecutionReceiptEventType.APPROVAL_DENIED -> ProofLedgerEventType.APPROVAL_DENIED
            ExecutionReceiptEventType.QUOTE_COLLECTED -> ProofLedgerEventType.QUOTE_COLLECTED
            ExecutionReceiptEventType.PROVIDER_SELECTED -> ProofLedgerEventType.PROVIDER_SELECTED
            ExecutionReceiptEventType.PROVIDER_BLOCKED -> ProofLedgerEventType.PROVIDER_DENIED
            ExecutionReceiptEventType.DATA_SCOPE_REDUCED -> ProofLedgerEventType.DATA_SCOPE_REDUCED
            ExecutionReceiptEventType.DATA_SCOPE_BLOCKED -> ProofLedgerEventType.DATA_SCOPE_BLOCKED
            ExecutionReceiptEventType.PROOF_RETURNED -> ProofLedgerEventType.PROOF_RECEIVED
            ExecutionReceiptEventType.VERIFICATION_PASSED -> ProofLedgerEventType.VERIFICATION_PASSED
            ExecutionReceiptEventType.VERIFICATION_FAILED -> ProofLedgerEventType.VERIFICATION_FAILED
            ExecutionReceiptEventType.SETTLEMENT_STARTED -> ProofLedgerEventType.SETTLEMENT_STARTED
            ExecutionReceiptEventType.SETTLEMENT_COMMITTED -> ProofLedgerEventType.SETTLEMENT_COMMITTED
            ExecutionReceiptEventType.SETTLEMENT_SYNC_PENDING -> ProofLedgerEventType.SETTLEMENT_SYNC_PENDING
            ExecutionReceiptEventType.SETTLEMENT_RECONCILED -> ProofLedgerEventType.SETTLEMENT_RECONCILED
            ExecutionReceiptEventType.PROVIDER_ACK_RECEIVED -> ProofLedgerEventType.PROVIDER_ACK_RECEIVED
            ExecutionReceiptEventType.ROLLBACK_AVAILABLE -> ProofLedgerEventType.ROLLBACK_AVAILABLE
            ExecutionReceiptEventType.ROLLBACK_REQUESTED -> ProofLedgerEventType.ROLLBACK_REQUESTED
            ExecutionReceiptEventType.ROLLED_BACK -> ProofLedgerEventType.ROLLBACK_TRIGGERED
            ExecutionReceiptEventType.ROLLBACK_FAILED -> ProofLedgerEventType.ROLLBACK_FAILED
            ExecutionReceiptEventType.DISPUTE_OPENED -> ProofLedgerEventType.DISPUTE_OPENED
            ExecutionReceiptEventType.DISPUTE_SYNC_PENDING -> ProofLedgerEventType.DISPUTE_SYNC_PENDING
            ExecutionReceiptEventType.DISPUTE_ACKNOWLEDGED -> ProofLedgerEventType.DISPUTE_ACKNOWLEDGED
            ExecutionReceiptEventType.DISPUTE_RESOLVED -> ProofLedgerEventType.DISPUTE_RESOLVED
            ExecutionReceiptEventType.DISPUTE_CLOSED -> ProofLedgerEventType.DISPUTE_CLOSED
            ExecutionReceiptEventType.RECONCILIATION_MISMATCH_DETECTED -> ProofLedgerEventType.RECONCILIATION_MISMATCH_DETECTED
            ExecutionReceiptEventType.RECONCILIATION_RETRY_SCHEDULED -> ProofLedgerEventType.RECONCILIATION_RETRY_SCHEDULED
            ExecutionReceiptEventType.POLICY_PROMOTION_REQUESTED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REQUESTED
            ExecutionReceiptEventType.POLICY_PROMOTION_APPROVED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_APPROVED
            ExecutionReceiptEventType.POLICY_PROMOTION_REJECTED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REJECTED
            ExecutionReceiptEventType.POLICY_ROLLOUT_ADVANCED -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ADVANCED
            ExecutionReceiptEventType.POLICY_PROMOTION_READINESS_EVALUATED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED
            ExecutionReceiptEventType.ROLLOUT_WAVE_ASSIGNED -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_WAVE_ASSIGNED
            ExecutionReceiptEventType.ROLLOUT_WAVE_PARTIAL_COMPLETION -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_WAVE_PARTIAL_COMPLETION
            ExecutionReceiptEventType.ROLLOUT_WAVE_CARRIED_FORWARD -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_WAVE_CARRIED_FORWARD
            ExecutionReceiptEventType.PROMOTION_WINDOW_DEFERRED -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_WINDOW_DEFERRED
            ExecutionReceiptEventType.PROMOTION_WINDOW_EXPIRED -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_WINDOW_EXPIRED
            ExecutionReceiptEventType.CROSS_WINDOW_PAUSED -> ProofLedgerEventType.WORKFLOW_POLICY_CROSS_WINDOW_PAUSED
            ExecutionReceiptEventType.CROSS_WINDOW_RESUMED -> ProofLedgerEventType.WORKFLOW_POLICY_CROSS_WINDOW_RESUMED
            ExecutionReceiptEventType.ROLLOUT_PROMOTION_READY -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED
            ExecutionReceiptEventType.ROLLOUT_PROMOTION_BLOCKED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED
            ExecutionReceiptEventType.CROSS_WAVE_ANALYTICS_UPDATED -> ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED
            ExecutionReceiptEventType.WINDOW_IMPACT_EVALUATED -> ProofLedgerEventType.WORKFLOW_POLICY_SCHEDULE_WINDOW_EVALUATED
            ExecutionReceiptEventType.ROLLOUT_PROMOTION_OPERATION_RECORDED -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ADVANCED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_PRIORITY_APPLIED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_PRIORITY_APPLIED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_DEFERRED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_DEFERRED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_DEPENDENCY_BLOCKED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_DEPENDENCY_BLOCKED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_CONFLICT_DETECTED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CONFLICT_DETECTED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_CONTENTION_DETECTED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CONTENTION_DETECTED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_ESCALATION_OPENED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_ESCALATION_OPENED
            ExecutionReceiptEventType.ROLLOUT_PROGRAM_ESCALATION_RESOLVED -> ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_ESCALATION_RESOLVED
            else -> null
        }
    }

    private fun buildLedgerProviderDecisions(
        receipt: ExecutionReceipt,
        updatedAtMs: Long
    ): List<ProviderDecisionRecord> {
        val decisions = receipt.providerPolicyDecisions.map { decision ->
            ProviderDecisionRecord(
                providerId = decision.providerId,
                providerName = decision.providerName,
                decision = decision.decision,
                denyReason = decision.denyReason,
                reasonCodes = decision.reasonCodes,
                readableReason = decision.readableReason,
                approvalRequired = decision.approvalRequired,
                dataScopeSummary = decision.dataScopeSummary,
                proofRequirementSummary = decision.proofRequirementSummary,
                recordedAtMs = updatedAtMs
            )
        }.toMutableList()
        val selection = receipt.providerSelectionSummary
        val selectedProviderId = selection?.selectedProviderId
        if (selectedProviderId != null && decisions.none { it.providerId == selectedProviderId }) {
            decisions += ProviderDecisionRecord(
                providerId = selectedProviderId,
                providerName = selection.selectedProviderName.orEmpty(),
                decision = ProviderDecisionStatus.SELECTED,
                denyReason = null,
                reasonCodes = selection.decisionReasonCodes,
                readableReason = selection.selectionRationale,
                approvalRequired = receipt.externalApprovalSummary?.required == true,
                dataScopeSummary = selection.dataScopeSummary.ifBlank { receipt.dataScopeSummary },
                proofRequirementSummary = selection.proofRequirementSummary.ifBlank { receipt.proofSummary },
                recordedAtMs = updatedAtMs
            )
        }
        return decisions.distinctBy { "${it.providerId}:${it.decision}" }.take(12)
    }

    private fun buildLedgerVerificationRecord(
        receipt: ExecutionReceipt,
        updatedAtMs: Long
    ): VerificationRecord {
        val verification = receipt.externalVerificationSummary
        val proof = receipt.externalProofSummary
        val status = verification?.status
            ?.takeIf { it.isNotBlank() }
            ?: when {
                receipt.status == ResponseStatus.DISPUTED -> "failed"
                receipt.status == ResponseStatus.VERIFYING -> "pending"
                else -> "not_required"
            }
        return VerificationRecord(
            runId = receipt.runId,
            status = status,
            passed = verification?.passed == true || status.equals("passed", ignoreCase = true),
            partial = verification?.partial == true || status.equals("partial", ignoreCase = true),
            summary = verification?.summary?.ifBlank { receipt.verificationSummary } ?: receipt.verificationSummary,
            proofRequired = proof?.required == true,
            proofProvided = proof?.provided == true || receipt.proofLinks.isNotEmpty(),
            proofLinks = receipt.proofLinks,
            reasonCodes = (verification?.reasonCodes ?: emptyList()).ifEmpty { receipt.roleImpactReasonCodes },
            recordedAtMs = updatedAtMs
        )
    }

    private fun buildLedgerSettlementRecord(
        receipt: ExecutionReceipt,
        updatedAtMs: Long
    ): SettlementRecord {
        val settlementSummary = receipt.externalSettlementSummary
        val reconciliationSummary = receipt.reconciliationSummary
        val selectedProviderId = receipt.providerSelectionSummary?.selectedProviderId ?: receipt.selectedProviderId
        val selectedProviderName = receipt.providerSelectionSummary?.selectedProviderName
        val status = settlementSummary?.status ?: inferSettlementStatusFromReceipt(receipt)
        val syncState = settlementSummary?.syncState
            ?: reconciliationSummary?.syncState
            ?: inferSettlementSyncStateFromReceipt(receipt)
        val reasonCodes = buildList {
            addAll(settlementSummary?.reasonCodes.orEmpty())
            addAll(reconciliationSummary?.reasonCodes.orEmpty())
            addAll(receipt.roleImpactReasonCodes.filter { it.startsWith("ROLE_EXTERNAL_SETTLEMENT_") || it.startsWith("ROLE_EXTERNAL_RECONCILIATION_") })
        }.distinct()
        val attempt = SettlementAttempt(
            attemptId = "attempt_${receipt.runId.take(12)}_${status.name.lowercase()}",
            action = status.name.lowercase(),
            idempotencyKey = "${receipt.runId}:${status.name.lowercase()}:${syncState.name.lowercase()}",
            remoteCallbackId = selectedProviderId?.takeIf { it.isNotBlank() }?.let { "$it:${status.name.lowercase()}" },
            status = status,
            detail = settlementSummary?.summary?.ifBlank { receipt.providerSummary } ?: receipt.providerSummary,
            duplicateIgnored = false,
            timestampMs = updatedAtMs
        )
        val providerAcks = buildList {
            val reasonCodesLower = reasonCodes.joinToString(" ").lowercase()
            when {
                reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_RECEIVED) ||
                    syncState == SettlementSyncState.ACKNOWLEDGED ||
                    syncState == SettlementSyncState.RECONCILED ->
                    add(
                        ProviderAckRecord(
                            ackId = "ack_${receipt.runId.take(12)}",
                            providerId = selectedProviderId.orEmpty(),
                            providerName = selectedProviderName.orEmpty(),
                            callbackId = selectedProviderId?.let { "$it:ack" },
                            status = ProviderAckStatus.RECEIVED,
                            detail = "Provider acknowledgement received.",
                            ackAtMs = updatedAtMs
                        )
                    )

                reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_TIMEOUT) ||
                    reasonCodesLower.contains("ack timeout") ->
                    add(
                        ProviderAckRecord(
                            ackId = "ack_timeout_${receipt.runId.take(12)}",
                            providerId = selectedProviderId.orEmpty(),
                            providerName = selectedProviderName.orEmpty(),
                            callbackId = selectedProviderId?.let { "$it:timeout" },
                            status = ProviderAckStatus.TIMEOUT,
                            detail = "Provider acknowledgement timed out.",
                            ackAtMs = updatedAtMs
                        )
                    )
            }
        }
        return SettlementRecord(
            runId = receipt.runId,
            status = status,
            syncState = syncState,
            summary = settlementSummary?.summary?.ifBlank { receipt.providerSummary } ?: receipt.providerSummary,
            authoritativeLocalState = settlementSummary?.authoritativeLocalState ?: (
                syncState == SettlementSyncState.SYNC_PENDING || syncState == SettlementSyncState.MISMATCH
                ),
            selectedProviderId = selectedProviderId,
            selectedProviderName = selectedProviderName,
            attempts = listOf(attempt),
            providerAcks = providerAcks,
            reconciliation = reconciliationSummary,
            reasonCodes = reasonCodes,
            recordedAtMs = updatedAtMs
        )
    }

    private fun buildLedgerRollbackAttempts(
        receipt: ExecutionReceipt,
        settlementRecord: SettlementRecord,
        updatedAtMs: Long
    ): List<RollbackAttemptRecord> {
        val rollback = receipt.externalRollbackSummary
        if (rollback == null && receipt.status != ResponseStatus.ROLLED_BACK) {
            return emptyList()
        }
        val outcome = when {
            receipt.status == ResponseStatus.ROLLED_BACK || rollback?.triggered == true -> RollbackOutcome.SUCCEEDED
            rollback?.summary?.contains("failed", ignoreCase = true) == true ||
                receipt.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_FAILED) -> RollbackOutcome.FAILED
            settlementRecord.status == SettlementStatus.ROLLBACK_REQUESTED ||
                rollback?.summary?.contains("requested", ignoreCase = true) == true -> RollbackOutcome.REQUESTED
            else -> RollbackOutcome.NOT_REQUESTED
        }
        return listOf(
            RollbackAttemptRecord(
                attemptId = "rollback_${receipt.runId.take(12)}_${outcome.name.lowercase()}",
                outcome = outcome,
                summary = rollback?.summary?.ifBlank { receipt.rollbackSummary } ?: receipt.rollbackSummary,
                remoteSyncPending = settlementRecord.syncState == SettlementSyncState.SYNC_PENDING,
                reasonCodes = buildList {
                    addAll(rollback?.reasonCodes.orEmpty())
                    addAll(receipt.roleImpactReasonCodes.filter { it.contains("ROLLBACK", ignoreCase = true) })
                }.distinct(),
                timestampMs = updatedAtMs
            )
        )
    }

    private fun buildLedgerDisputeCaseRecord(
        receipt: ExecutionReceipt,
        disputeRecord: DisputeRecord,
        updatedAtMs: Long
    ): DisputeCaseRecord {
        val opened = disputeRecord.opened || receipt.status == ResponseStatus.DISPUTED
        val status = when {
            !opened -> DisputeStatus.NOT_OPEN
            disputeRecord.summary.contains("closed", ignoreCase = true) -> DisputeStatus.CLOSED
            disputeRecord.summary.contains("resolved", ignoreCase = true) -> DisputeStatus.RESOLVED
            disputeRecord.summary.contains("under review", ignoreCase = true) -> DisputeStatus.UNDER_REVIEW
            disputeRecord.summary.contains("acknowledged", ignoreCase = true) -> DisputeStatus.ACKNOWLEDGED
            disputeRecord.syncState.equals("sync_pending", ignoreCase = true) -> DisputeStatus.SYNC_PENDING
            else -> DisputeStatus.OPENED
        }
        val events = mutableListOf<DisputeEventRecord>()
        if (opened) {
            events += DisputeEventRecord(
                eventId = "dispute_opened_${receipt.runId.take(12)}",
                status = DisputeStatus.OPENED,
                summary = disputeRecord.summary.ifBlank { "Dispute was opened." },
                timestampMs = updatedAtMs
            )
        }
        if (status != DisputeStatus.OPENED && status != DisputeStatus.NOT_OPEN) {
            events += DisputeEventRecord(
                eventId = "dispute_${status.name.lowercase()}_${receipt.runId.take(12)}",
                status = status,
                summary = disputeRecord.summary.ifBlank { "Dispute moved to ${status.name.lowercase().replace('_', ' ')}." },
                timestampMs = updatedAtMs
            )
        }
        return DisputeCaseRecord(
            runId = receipt.runId,
            caseId = if (opened) "dispute_${receipt.runId.take(12)}" else "",
            status = status,
            summary = disputeRecord.summary,
            issueType = disputeRecord.issueType,
            evidenceRefs = receipt.proofLinks,
            reasonCodes = disputeRecord.reasonCodes,
            events = events,
            openedAtMs = if (opened) (receipt.completedAt ?: updatedAtMs) else null,
            updatedAtMs = updatedAtMs,
            closedAtMs = if (status == DisputeStatus.CLOSED || status == DisputeStatus.RESOLVED) updatedAtMs else null
        )
    }

    private fun inferSettlementStatusFromReceipt(receipt: ExecutionReceipt): SettlementStatus {
        return when {
            receipt.status == ResponseStatus.ROLLED_BACK -> SettlementStatus.ROLLED_BACK
            receipt.status == ResponseStatus.DISPUTED -> SettlementStatus.DISPUTED
            receipt.status == ResponseStatus.ERROR -> SettlementStatus.FAILED
            receipt.status == ResponseStatus.COMMITTED ||
                receipt.status == ResponseStatus.SUCCESS ||
                receipt.status == ResponseStatus.PARTIAL -> SettlementStatus.COMMITTED
            receipt.quoteSummary.startsWith("No external quote comparison", ignoreCase = true) &&
                receipt.providerPolicyDecisions.isEmpty() &&
                receipt.providerSelectionSummary == null -> SettlementStatus.NOT_REQUIRED
            else -> SettlementStatus.STARTED
        }
    }

    private fun inferSettlementSyncStateFromReceipt(receipt: ExecutionReceipt): SettlementSyncState {
        val combined = buildString {
            append(receipt.issueSummary.orEmpty())
            append(' ')
            append(receipt.externalDisputeSummary?.summary.orEmpty())
            append(' ')
            append(receipt.reconciliationSummary?.summary.orEmpty())
        }.lowercase()
        return when {
            combined.contains("mismatch") || combined.contains("conflict") -> SettlementSyncState.MISMATCH
            combined.contains("sync pending") -> SettlementSyncState.SYNC_PENDING
            combined.contains("reconciled") || combined.contains("sync resolved") -> SettlementSyncState.RECONCILED
            receipt.roleImpactReasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_RECEIVED) -> SettlementSyncState.ACKNOWLEDGED
            receipt.quoteSummary.startsWith("No external quote comparison", ignoreCase = true) &&
                receipt.providerSelectionSummary == null -> SettlementSyncState.NOT_REQUIRED
            else -> SettlementSyncState.LOCAL_ONLY
        }
    }

    private fun buildLedgerRollbackRecord(
        receipt: ExecutionReceipt,
        updatedAtMs: Long
    ): RollbackRecord {
        val rollback = receipt.externalRollbackSummary
        return RollbackRecord(
            runId = receipt.runId,
            available = rollback?.available == true,
            triggered = rollback?.triggered == true || receipt.status == ResponseStatus.ROLLED_BACK,
            summary = rollback?.summary?.ifBlank { receipt.rollbackSummary } ?: receipt.rollbackSummary,
            reasonCodes = (rollback?.reasonCodes ?: emptyList()).ifEmpty { receipt.roleImpactReasonCodes },
            recordedAtMs = updatedAtMs
        )
    }

    private fun buildLedgerDisputeRecord(
        receipt: ExecutionReceipt,
        updatedAtMs: Long
    ): DisputeRecord {
        val dispute = receipt.externalDisputeSummary
        val reconciliation = receipt.reconciliationSummary
        val combined = buildString {
            append(dispute?.summary.orEmpty())
            append(' ')
            append(receipt.issueSummary.orEmpty())
            append(' ')
            append(reconciliation?.summary.orEmpty())
        }.lowercase()
        val syncState = when {
            combined.contains("sync pending") -> "sync_pending"
            combined.contains("sync resolved") -> "sync_resolved"
            combined.contains("acknowledged") -> "acknowledged"
            dispute?.opened == true -> "local_only"
            else -> "not_required"
        }
        return DisputeRecord(
            runId = receipt.runId,
            opened = dispute?.opened == true || receipt.status == ResponseStatus.DISPUTED,
            summary = dispute?.summary?.ifBlank { receipt.issueSummary.orEmpty() } ?: receipt.issueSummary.orEmpty(),
            issueType = dispute?.issueType,
            syncState = syncState,
            reasonCodes = (dispute?.reasonCodes ?: emptyList())
                .plus(reconciliation?.reasonCodes.orEmpty())
                .ifEmpty { receipt.roleImpactReasonCodes }
                .distinct(),
            recordedAtMs = updatedAtMs
        )
    }

    private fun readableRoleImpact(code: String): String {
