    private fun ResponseStatus.isTerminalForReceipt(): Boolean {
        return this == ResponseStatus.SUCCESS ||
            this == ResponseStatus.PARTIAL ||
            this == ResponseStatus.COMMITTED ||
            this == ResponseStatus.ROLLED_BACK ||
            this == ResponseStatus.DISPUTED ||
            this == ResponseStatus.ERROR ||
            this == ResponseStatus.CANCELLED
    }

    private fun extractActiveRoleFromLines(lines: List<String>): UserRole? {
        val raw = extractLixField(
            lines,
            "active role",
            "role",
            "persona",
            "self role",
            "profile role",
            "角色"
        )
        return parseUserRole(raw)
    }

    private fun extractActiveRoleFromInline(rawText: String): UserRole? {
        val inline = extractInlineValue(
            rawText = rawText,
            regex = "(?is)(?:active\\s*role|role|persona|self\\s*role|profile\\s*role|角色)\\s*(?:[:：]|=)\\s*([A-Za-z_\\-\\s]{2,40})(?=[;\\n]|$)"
        ) ?: extractInlineValue(
            rawText = rawText,
            regex = "(?is)(?:as|under)\\s+(?:a\\s+)?([A-Za-z_\\-\\s]{2,24})\\s+(?:role|mode)\\b"
        )
        return parseUserRole(inline)
    }

    private fun parseUserRole(raw: String?): UserRole? {
        val text = raw?.trim()?.lowercase().orEmpty()
        if (text.isBlank()) return null
        return when {
            text.contains("work") || text.contains("office") || text.contains("professional") || text.contains("job") -> UserRole.WORK
            text.contains("buyer") || text.contains("purchase") || text.contains("shopping") || text.contains("procurement") -> UserRole.BUYER
            text.contains("travel") || text.contains("trip") || text.contains("traveler") || text.contains("tour") -> UserRole.TRAVELER
            text.contains("parent") || text.contains("family") || text.contains("kid") || text.contains("child") -> UserRole.PARENT
            text.contains("custom") -> UserRole.CUSTOM
            text.contains("personal") || text.contains("private") -> UserRole.PERSONAL
            else -> null
        }
    }

    private fun inferActiveRole(
        request: AgentRequest,
        module: ModuleId?,
        rawLower: String = request.rawText.lowercase()
    ): UserRole {
        val source = request.sourceApp.lowercase()
        if (module == ModuleId.LIX) return UserRole.BUYER
        if (
            rawLower.contains("flight") ||
            rawLower.contains("hotel") ||
            rawLower.contains("itinerary") ||
            rawLower.contains("trip") ||
            rawLower.contains("airport") ||
            rawLower.contains("visa")
        ) {
            return UserRole.TRAVELER
        }
        if (
            rawLower.contains("buy") ||
            rawLower.contains("purchase") ||
            rawLower.contains("quote") ||
            rawLower.contains("checkout") ||
            rawLower.contains("supplier")
        ) {
            return UserRole.BUYER
        }
        if (
            rawLower.contains("kid") ||
            rawLower.contains("child") ||
            rawLower.contains("family") ||
            rawLower.contains("school")
        ) {
            return UserRole.PARENT
        }
        if (
            source.contains("slack") ||
            source.contains("teams") ||
            source.contains("outlook") ||
            source.contains("gmail") ||
            source.contains("jira") ||
            source.contains("github") ||
            source.contains("notion")
        ) {
            return UserRole.WORK
        }
        return UserRole.PERSONAL
    }

    private fun missingRequiredConstraintFields(constraints: AgentRequestConstraints): List<String> {
        val missing = mutableListOf<String>()
        if (constraints.budget.isNullOrBlank()) missing += "budget"
        if (constraints.deadline.isNullOrBlank()) missing += "deadline"
        if (constraints.acceptanceCriteria.isNullOrBlank()) missing += "acceptance_criteria"
        return missing
    }

    private fun extractInlineValue(rawText: String, regex: String): String? {
        return Regex(regex)
            .find(rawText)
            ?.groupValues
            ?.getOrNull(1)
            ?.trim()
            ?.takeIf { it.isNotBlank() }
    }

    fun getModuleSnapshot(userId: String, module: ModuleId): AgentResponse {
        moduleSnapshotByUser[userId]?.get(module)?.let { cached ->
            return cached.copy(latencyMs = 0)
        }
        val traceId = traceFactory()
        return AgentResponse(
            type = AgentResponseType.CARDS,
            summary = "${module.label()} module is ready",
            traceId = traceId,
            latencyMs = 0,
            confidence = 0.82,
            module = module,
            payload = payloadForModule(
                module = module,
                userId = userId,
                locale = "zh-CN",
                query = "${module.label()} module snapshot",
                traceId = traceId
            ),
            cards = defaultSnapshotCards(module),
            actions = defaultActions(module, ""),
            status = ResponseStatus.SUCCESS
        )
    }

    private fun rememberModuleSnapshot(
        userId: String,
        module: ModuleId,
        response: AgentResponse
    ) {
        val userMap = moduleSnapshotByUser.getOrPut(userId) { ConcurrentHashMap() }
        userMap[module] = response
    }

    fun recordInteraction(event: InteractionEvent) {
        val sanitizedPayload = event.payload.filterKeys {
            it != "rawText" && it != "text" && it != "message"
        }
        val sanitizedEvent = event.copy(payload = sanitizedPayload)
        soulStore.onEvent(sanitizedEvent)

        synchronized(interactionLock) {
            val cutoff = nowMs() - INTERACTION_RETENTION_MS
            interactionEvents.addLast(sanitizedEvent)
            while (interactionEvents.size > MAX_INTERACTION_EVENTS) {
                interactionEvents.removeFirst()
            }
            while (interactionEvents.isNotEmpty() && interactionEvents.first().timestampMs < cutoff) {
                interactionEvents.removeFirst()
            }
        }
    }

