    }

    fun updateStateConsensus(userId: String, patch: StateConsensusPayload): Boolean {
        restoreDynamicStateIfNeeded(userId)
        val current = dynamicStateByUser[userId] ?: return false
        val patched = current.copy(
            l2 = current.l2.copy(
                energyLevel = when (patch.energyLabel.lowercase()) {
                    "high" -> 0.8
                    "low" -> 0.25
                    else -> 0.5
                }
            ),
            l3 = current.l3.copy(
                polarity = when (patch.moodLabel.lowercase()) {
                    "positive" -> 0.4
                    "negative" -> -0.4
                    else -> 0.0
                },
                focusScore = when (patch.focusLabel.lowercase()) {
                    "focused" -> 82
                    "scattered" -> 32
                    else -> 55
                }
            ),
            updatedAtMs = nowMs()
        )
        updateDynamicState(userId, patched)
        return true
    }

    fun getRolePolicyEditorState(userId: String, role: UserRole): RolePolicyEditorState {
        restoreDynamicStateIfNeeded(userId)
        val effective = effectiveRolePolicyProfile(userId, role)
        return RolePolicyEditorState(
            role = role,
            effectivePolicy = effective,
            editableFields = editableRolePolicyFields(role),
            protectedFields = protectedRolePolicyFields(role),
            lastUpdatedAtMs = rolePolicyUpdatedAtByUser[userId]?.get(role)
        )
    }

    fun updateRolePolicy(
        userId: String,
        role: UserRole,
        draft: RolePolicyDraft
    ): RolePolicyUpdateResult {
        restoreDynamicStateIfNeeded(userId)
        val base = effectiveRolePolicyProfile(userId, role)
        val candidate = applyRolePolicyDraft(base, role, draft)
        val validation = validateRolePolicyDraft(
            role = role,
            candidate = candidate,
            draft = draft
        )
        if (!validation.valid) {
            return RolePolicyUpdateResult(
                saved = false,
                role = role,
                effectivePolicy = base,
                validation = validation,
                lastUpdatedAtMs = rolePolicyUpdatedAtByUser[userId]?.get(role)
            )
        }
        val overrides = rolePolicyOverridesByUser.getOrPut(userId) { ConcurrentHashMap() }
        overrides[role] = candidate
        val updatedAt = nowMs()
        rolePolicyUpdatedAtByUser
            .getOrPut(userId) { ConcurrentHashMap() }[role] = updatedAt
        persistDynamicState(userId)
        val effective = effectiveRolePolicyProfile(userId, role)
        return RolePolicyUpdateResult(
            saved = true,
            role = role,
            effectivePolicy = effective,
            validation = validation.copy(previewLines = buildRolePolicyPreviewLines(effective)),
            lastUpdatedAtMs = updatedAt
        )
    }

    fun resetRolePolicy(userId: String, role: UserRole): RolePolicyUpdateResult {
        restoreDynamicStateIfNeeded(userId)
        rolePolicyOverridesByUser[userId]?.remove(role)
        rolePolicyUpdatedAtByUser[userId]?.remove(role)
        persistDynamicState(userId)
        val effective = effectiveRolePolicyProfile(userId, role)
        return RolePolicyUpdateResult(
            saved = true,
            role = role,
            effectivePolicy = effective,
            validation = RolePolicyValidationResult(
                valid = true,
                previewLines = buildRolePolicyPreviewLines(effective)
            ),
            lastUpdatedAtMs = nowMs()
        )
    }

    fun getExecutionLedger(
        userId: String,
        filter: LedgerQueryFilter = LedgerQueryFilter()
    ): List<ExecutionReceiptRecord> {
        restoreDynamicStateIfNeeded(userId)
        val records = synchronized(dynamicStateLock) {
            executionLedgerByUser[userId]?.toList().orEmpty()
                .map { record ->
                    applyPortfolioOptimizationLearningContextToLedgerRecordLocked(
                        userId = userId,
                        record = record
                    )
                }
        }.asReversed()
        val limit = filter.limit.coerceIn(1, MAX_LEDGER_QUERY_LIMIT)
        val runIdFilter = filter.runId
        val roleFilter = filter.role
        val providerIdFilter = filter.providerId
        val approvalStateFilter = filter.approvalState?.lowercase()
        val verificationStateFilter = filter.verificationState?.lowercase()
        val disputeRollbackFilter = filter.disputeOrRollbackState?.lowercase()
        val settlementStatusFilter = filter.settlementStatus
        val disputeStatusFilter = filter.disputeStatus
        val syncStateFilter = filter.syncState
        val unresolvedOnly = filter.unresolvedOnly
        val syncPendingOnly = filter.syncPendingOnly
        val providerIssueOnly = filter.providerIssueOnly
        val policySnapshotIdFilter = filter.policySnapshotId
        return records
            .asSequence()
            .filter { record ->
                runIdFilter.isNullOrBlank() || record.runId == runIdFilter
            }
            .filter { record ->
                roleFilter == null ||
                    record.activeRole == roleFilter ||
                    record.policySnapshot?.activeRole == roleFilter
            }
            .filter { record ->
                providerIdFilter.isNullOrBlank() || providerMatches(record, providerIdFilter)
            }
            .filter { record ->
                approvalStateFilter.isNullOrBlank() || approvalStateFor(record) == approvalStateFilter
            }
            .filter { record ->
                verificationStateFilter.isNullOrBlank() || verificationStateFor(record) == verificationStateFilter
            }
            .filter { record ->
                disputeRollbackFilter.isNullOrBlank() ||
                    disputeOrRollbackStateFor(record) == disputeRollbackFilter
            }
            .filter { record ->
                settlementStatusFilter == null || settlementStatusFor(record) == settlementStatusFilter
            }
            .filter { record ->
                disputeStatusFilter == null || disputeStatusFor(record) == disputeStatusFilter
            }
            .filter { record ->
                syncStateFilter == null || syncStateFor(record) == syncStateFilter
            }
            .filter { record ->
                !unresolvedOnly || hasUnresolvedSettlementOrDispute(record)
            }
            .filter { record ->
                !syncPendingOnly || isSyncPendingRecord(record)
            }
            .filter { record ->
                !providerIssueOnly || hasProviderIssue(record)
            }
            .filter { record ->
                policySnapshotIdFilter.isNullOrBlank() || policySnapshotMatches(record, policySnapshotIdFilter)
            }
            .take(limit)
            .toList()
    }

    fun getGovernanceSummary(
        userId: String,
        query: GovernanceQuery = GovernanceQuery()
    ): GovernanceSummary {
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val windowDays = query.windowDays.coerceIn(1, 90)
        val windowStart = now - (windowDays.toLong() * 24L * 60L * 60L * 1000L)
        val allRecords = synchronized(dynamicStateLock) {
            executionLedgerByUser[userId]?.toList().orEmpty()
        }.asReversed()
        val windowed = allRecords.filter { recordTimestampMs(it) >= windowStart }
        val signals = windowed.map(::toGovernanceSignal)
        val providerFilter = query.providerId?.trim().orEmpty().lowercase()
        val snapshotVersionFilter = query.policySnapshotVersion?.trim().orEmpty().lowercase()
        val limit = query.limit.coerceIn(1, MAX_GOVERNANCE_QUERY_LIMIT)
        val filtered = signals
            .asSequence()
            .filter { query.includeLegacyWithoutReceipt || it.receiptTraceable }
            .filter { query.role == null || it.role == query.role }
            .filter { signal ->
                providerFilter.isBlank() || signal.providerIds.any { provider ->
                    provider.lowercase().contains(providerFilter)
                }
            }
            .filter { signal ->
                snapshotVersionFilter.isBlank() ||
                    (signal.policySnapshotVersion?.equals(snapshotVersionFilter, ignoreCase = true) == true)
            }
            .filter { signal -> query.outcomeStatus == null || signal.outcomeStatus == query.outcomeStatus }
            .filter { signal -> query.reasonFamily == null || signal.reasonFamilies.contains(query.reasonFamily) }
            .take(limit)
            .toList()
        val total = filtered.size
        val metrics = mutableListOf<GovernanceMetricValue>()
        val notes = mutableListOf<String>()
        if (total == 0) {
            notes += "No governance records matched the current window and filters."
        }
        if (query.includeLegacyWithoutReceipt) {
            notes += "Legacy records without receipts are included when typed fallback fields are available."
        } else {
            notes += "Legacy records without receipts are excluded from this governance query."
        }
        notes += "ledger_restore_success_rate and old_new_history_merge_success_rate remain reserved for session-telemetry integration."

        val requiredRateByRole = filtered.groupBy { it.role?.name?.lowercase() ?: "unknown" }
        requiredRateByRole.forEach { (role, roleSignals) ->
            val denominator = roleSignals.size
            metrics += metric(
                key = GovernanceMetricKey.APPROVAL_REQUIRED_RATE_BY_ROLE,
                numerator = roleSignals.count { it.approvalRequired },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.APPROVAL_DENIED_RATE_BY_ROLE,
                numerator = roleSignals.count { it.approvalDenied },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.AUTO_RUN_RATE_BY_ROLE,
                numerator = roleSignals.count { it.autoRun },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.POLICY_OVERRIDE_APPLIED_RATE_BY_ROLE,
                numerator = roleSignals.count { it.policyOverrideApplied },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.PROVIDER_SELECTION_RATE_BY_ROLE,
                numerator = roleSignals.count { it.providerSelected },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.PROVIDER_DENIAL_RATE_BY_ROLE,
                numerator = roleSignals.count { it.providerDenied },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.QUOTE_SELECTION_DIVERGENCE_BY_ROLE,
                numerator = roleSignals.count { it.quoteSelectionDivergence },
                denominator = denominator,
                dimension = "role",
                value = role
            )
            metrics += metric(
                key = GovernanceMetricKey.CLOUD_SYNC_BLOCK_RATE_BY_ROLE,
                numerator = roleSignals.count { it.cloudSyncBlocked },
                denominator = denominator,
                dimension = "role",
                value = role
            )
        }
        filtered
            .groupBy { it.roleSource?.name?.lowercase() ?: "unknown" }
            .forEach { (source, sourceSignals) ->
                metrics += metric(
                    key = GovernanceMetricKey.ROLE_SOURCE_DISTRIBUTION,
                    numerator = sourceSignals.size,
                    denominator = total,
                    dimension = "role_source",
                    value = source
                )
            }
        val deniedCount = filtered.count { it.providerDenied }
        filtered
            .flatMap { signal ->
                signal.reasonFamilies
                    .filter { it == GovernanceReasonFamily.PROVIDER_POLICY }
                    .ifEmpty {
                        if (signal.providerDenied) listOf(GovernanceReasonFamily.PROVIDER_POLICY) else emptyList()
                    }
            }
            .groupingBy { it.name.lowercase() }
            .eachCount()
            .forEach { (family, count) ->
                metrics += metric(
                    key = GovernanceMetricKey.PROVIDER_DENIAL_RATE_BY_REASON_FAMILY,
                    numerator = count,
                    denominator = deniedCount,
                    dimension = "reason_family",
                    value = family
                )
            }
        metrics += metric(
            key = GovernanceMetricKey.EXTERNAL_FULFILLMENT_ATTEMPT_RATE,
            numerator = filtered.count { it.externalAttempt },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.EXPLICIT_CONSTRAINT_PRECEDENCE_RATE,
            numerator = filtered.count { it.explicitConstraintPrecedence },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DATA_SCOPE_FULL_RATE,
            numerator = filtered.count { it.dataScopeFull },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DATA_SCOPE_REDUCED_RATE,
            numerator = filtered.count { it.dataScopeReduced },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DATA_SCOPE_REDACTED_RATE,
            numerator = filtered.count { it.dataScopeRedacted },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DATA_SCOPE_BLOCKED_RATE,
            numerator = filtered.count { it.dataScopeBlocked },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.VERIFICATION_PASS_RATE,
            numerator = filtered.count { it.verificationPassed },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.VERIFICATION_FAIL_RATE,
            numerator = filtered.count { it.verificationFailed },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.PROOF_MISSING_RATE,
            numerator = filtered.count { it.proofMissing },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.ROLLBACK_AVAILABLE_RATE,
            numerator = filtered.count { it.rollbackAvailable },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.ROLLBACK_TRIGGERED_RATE,
            numerator = filtered.count { it.rollbackTriggered },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DISPUTE_OPEN_RATE,
            numerator = filtered.count { it.disputeOpened },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.SETTLEMENT_SYNC_PENDING_RATE,
            numerator = filtered.count { it.settlementSyncPending },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.SETTLEMENT_RECONCILIATION_MISMATCH_RATE,
            numerator = filtered.count { it.reconciliationMismatch },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DUPLICATE_CALLBACK_IGNORED_RATE,
            numerator = filtered.count { it.duplicateCallbackIgnored },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.ROLLBACK_SUCCESS_RATE,
            numerator = filtered.count { it.rollbackTriggered },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.ROLLBACK_FAILURE_RATE,
            numerator = filtered.count { it.rollbackFailed },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DISPUTE_ACK_DELAY_RATE,
            numerator = filtered.count { it.disputeAckDelayed },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.DISPUTE_RESOLUTION_RATE,
            numerator = filtered.count { it.disputeResolved },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.UNRESOLVED_DISPUTE_BACKLOG,
            numerator = filtered.count { it.unresolvedDispute },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.PROVIDER_ACK_TIMEOUT_RATE,
            numerator = filtered.count { it.providerAckTimeout },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.SNAPSHOT_BINDING_COVERAGE,
            numerator = filtered.count { it.snapshotBound },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.RECEIPT_TRACEABILITY_COVERAGE,
            numerator = filtered.count { it.receiptTraceable },
            denominator = total
        )
        metrics += metric(
            key = GovernanceMetricKey.LEDGER_RESTORE_SUCCESS_RATE,
            numerator = 0,
            denominator = 0
        )
        metrics += metric(
            key = GovernanceMetricKey.OLD_NEW_HISTORY_MERGE_SUCCESS_RATE,
            numerator = 0,
            denominator = 0
        )
        val byRole = filtered
            .groupBy { it.role?.name?.lowercase() ?: "unknown" }
            .map { (bucket, items) -> bucketSummary(bucket, items) }
            .sortedByDescending { it.runCount }
        val byProvider = aggregateByProvider(filtered)
        val byPolicyVersion = filtered
            .groupBy { it.policySnapshotVersion ?: "unknown" }
            .map { (bucket, items) -> bucketSummary(bucket, items) }
            .sortedByDescending { it.runCount }
        val byOutcome = filtered
            .groupBy { it.outcomeStatus.name.lowercase() }
            .map { (bucket, items) -> bucketSummary(bucket, items) }
            .sortedByDescending { it.runCount }
        val byReasonFamily = aggregateByReasonFamily(filtered)
        val optimizationSummary = getPortfolioOptimizationState(
            userId = userId,
            query = PortfolioOptimizationQuery(limit = 6)
        ).summary
        return GovernanceSummary(
            query = query,
            generatedAtMs = now,
            window = GovernanceAggregationWindow(
                startAtMs = windowStart,
                endAtMs = now,
                windowDays = windowDays
            ),
            totalRecords = windowed.size,
            matchedRecords = total,
            receiptBackedRecords = filtered.count { it.receiptTraceable },
            snapshotBoundRecords = filtered.count { it.snapshotBound },
            metricValues = metrics.sortedWith(compareBy({ it.key.ordinal }, { it.dimension.orEmpty() }, { it.value.orEmpty() })),
            byRole = byRole,
            byProvider = byProvider,
            byPolicySnapshotVersion = byPolicyVersion,
            byOutcomeStatus = byOutcome,
            byReasonFamily = byReasonFamily,
            portfolioOptimizationSummary = optimizationSummary,
            notes = notes
        )
    }

    fun getGovernanceCases(
        userId: String,
        filter: GovernanceConsoleFilter = GovernanceConsoleFilter()
    ): List<GovernanceCaseRecord> {
        restoreDynamicStateIfNeeded(userId)
        val normalizedFilter = normalizeGovernanceConsoleFilter(filter)
        val ledgerFilter = LedgerQueryFilter(
            role = normalizedFilter.role,
            providerId = normalizedFilter.providerId,
            settlementStatus = normalizedFilter.settlementStatus,
            disputeStatus = normalizedFilter.disputeStatus,
            syncState = normalizedFilter.syncState,
            unresolvedOnly = normalizedFilter.unresolvedOnly,
            syncPendingOnly = normalizedFilter.syncPendingOnly,
            providerIssueOnly = normalizedFilter.providerIssueOnly,
            limit = normalizedFilter.limit.coerceIn(1, MAX_GOVERNANCE_QUERY_LIMIT)
        )
        val records = getExecutionLedger(userId, ledgerFilter)
        val cases = records.map { buildGovernanceCaseRecord(userId, it) }
        return cases
            .asSequence()
            .filter { case ->
                normalizedFilter.policySnapshotVersion.isNullOrBlank() ||
                    case.summary.policySnapshotVersion.equals(
                        normalizedFilter.policySnapshotVersion,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.reasonFamily == null ||
                    case.summary.reasonFamilies.contains(normalizedFilter.reasonFamily)
            }
            .filter { case ->
                normalizedFilter.queueType == null ||
                    case.summary.queueTags.contains(normalizedFilter.queueType)
            }
            .filter { case ->
                !normalizedFilter.mismatchOnly ||
                    case.summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH)
            }
            .filter { case ->
                normalizedFilter.assigneeUserId.isNullOrBlank() ||
                    case.collaborationState?.assignedTo?.userId.equals(
                        normalizedFilter.assigneeUserId,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                !normalizedFilter.escalatedOnly || case.summary.escalated
            }
            .filter { case ->
                !normalizedFilter.permissionDeniedOnly ||
                    case.summary.permissionDeniedCount > 0
            }
            .filter { case ->
                normalizedFilter.connectorTargetType == null ||
                    case.alertRoutingRecords.any { routing ->
                        routing.targets.any { target -> target.targetType == normalizedFilter.connectorTargetType }
                    }
            }
            .filter { case ->
                !normalizedFilter.connectorFailureOnly ||
                    case.summary.connectorFailedCount > 0
            }
            .filter { case ->
                !normalizedFilter.connectorDeadLetterOnly ||
                    case.summary.connectorDeadLetterCount > 0
            }
            .filter { case ->
                normalizedFilter.workflowTemplateId.isNullOrBlank() ||
                    case.summary.workflowTemplateId.equals(
                        normalizedFilter.workflowTemplateId,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.workflowPolicyPackId.isNullOrBlank() ||
                    case.summary.workflowPolicyPackId.equals(
                        normalizedFilter.workflowPolicyPackId,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.workflowPolicyPackVersion.isNullOrBlank() ||
                    case.summary.workflowPolicyPackVersion.equals(
                        normalizedFilter.workflowPolicyPackVersion,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.workflowStage == null ||
                    case.summary.workflowStage == normalizedFilter.workflowStage
            }
            .filter { case ->
                normalizedFilter.slaStatus == null ||
                    case.summary.slaStatus == normalizedFilter.slaStatus
            }
            .filter { case ->
                normalizedFilter.stageTimerStatus == null ||
                    case.summary.stageTimerStatus == normalizedFilter.stageTimerStatus
            }
            .filter { case ->
                normalizedFilter.escalationTimerStatus == null ||
                    case.summary.escalationTimerStatus == normalizedFilter.escalationTimerStatus
            }
            .filter { case ->
                normalizedFilter.automationEligibility == null ||
                    case.summary.automationEligibility == normalizedFilter.automationEligibility
            }
            .filter { case ->
                !normalizedFilter.automationEligibleOnly ||
                    case.summary.automationEligible
            }
            .filter { case ->
                !normalizedFilter.automationBlockedOnly ||
                    (
                        case.summary.automationEligibility != null &&
                            case.summary.automationEligibility != WorkflowAutomationEligibilityStatus.ALLOWED
                        )
            }
            .filter { case ->
                !normalizedFilter.scheduledOnly ||
                    (
                        case.summary.scheduledRemediationStatus != null &&
                            case.summary.scheduledRemediationStatus != ScheduledRemediationStatus.NOT_SCHEDULED &&
                            case.summary.scheduledRemediationStatus != ScheduledRemediationStatus.CANCELLED &&
                            case.summary.scheduledRemediationStatus != ScheduledRemediationStatus.EXECUTED
                        )
            }
            .filter { case ->
                !normalizedFilter.approvalRequiredOnly ||
                    case.summary.automationApprovalRequired
            }
            .filter { case ->
                !normalizedFilter.cooldownOnly ||
                    case.summary.automationCooldownActive
            }
            .filter { case ->
                !normalizedFilter.suppressedOnly ||
                    case.summary.automationSuppressed
            }
            .filter { case ->
                !normalizedFilter.maintenanceWindowOnly ||
                    case.summary.automationMaintenanceWindowBlocked
            }
            .filter { case ->
                normalizedFilter.scheduleWindowStatus == null ||
                    case.summary.scheduleWindowStatus == normalizedFilter.scheduleWindowStatus
            }
            .filter { case ->
                normalizedFilter.scheduleDecision == null ||
                    case.summary.scheduleDecision == normalizedFilter.scheduleDecision
            }
            .filter { case ->
                normalizedFilter.scheduleBlockReason == null ||
                    case.summary.scheduleBlockReason == normalizedFilter.scheduleBlockReason
            }
            .filter { case ->
                !normalizedFilter.scheduleBlockedOnly ||
                    case.summary.scheduleDecision == ExecutionWindowDecision.BLOCKED
            }
            .filter { case ->
                !normalizedFilter.scheduleDeferredOnly ||
                    case.summary.scheduleDecision == ExecutionWindowDecision.DEFERRED
            }
            .filter { case ->
                !normalizedFilter.schedulePausedOnly ||
                    case.summary.scheduleDecision == ExecutionWindowDecision.PAUSED
            }
            .filter { case ->
                !normalizedFilter.scheduleExpiredOnly ||
                    case.summary.scheduleDecision == ExecutionWindowDecision.EXPIRED
            }
            .filter { case ->
                !normalizedFilter.scheduleEligibleOnly ||
                    case.summary.scheduleDecision == ExecutionWindowDecision.ELIGIBLE
            }
            .filter { case ->
                !normalizedFilter.scheduleWaitingMaintenanceOnly ||
                    case.summary.scheduleWaitingMaintenance ||
                    case.summary.scheduleBlockReason == ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW
            }
            .filter { case ->
                normalizedFilter.rolloutWaveStatus == null ||
                    case.summary.rolloutWaveStatus == normalizedFilter.rolloutWaveStatus
            }
            .filter { case ->
                normalizedFilter.rolloutWindowEligibility == null ||
                    case.summary.rolloutWindowEligibility == normalizedFilter.rolloutWindowEligibility
            }
            .filter { case ->
                !normalizedFilter.deferredOnly ||
                    (
                        case.summary.rolloutWaveStatus == RolloutWaveStatus.DEFERRED ||
                            case.summary.rolloutWindowEligibility == PromotionWindowEligibility.DEFERRED
                        )
            }
            .filter { case ->
                !normalizedFilter.carryForwardOnly ||
                    (
                        case.summary.rolloutCarryForwardPending ||
                            case.summary.rolloutWaveStatus == RolloutWaveStatus.CARRIED_FORWARD ||
                            case.summary.rolloutWaveCompletionState == RolloutWaveCompletionState.CARRIED_FORWARD
                        )
            }
            .filter { case ->
                !normalizedFilter.expiredOnly ||
                    (
                        case.summary.rolloutWaveStatus == RolloutWaveStatus.EXPIRED ||
                            case.summary.rolloutWindowEligibility == PromotionWindowEligibility.EXPIRED
                        )
            }
            .filter { case ->
                !normalizedFilter.blockedByWindowOnly ||
                    (
                        case.summary.rolloutWaveStatus == RolloutWaveStatus.BLOCKED ||
                            case.summary.rolloutWindowEligibility == PromotionWindowEligibility.BLOCKED
                        )
            }
            .filter { case ->
                !normalizedFilter.crossWindowPausedOnly ||
                    case.summary.rolloutCrossWindowPaused
            }
            .filter { case ->
                !normalizedFilter.nextWindowPendingOnly ||
                    case.summary.rolloutNextWindowPending
            }
            .filter { case ->
                normalizedFilter.rolloutPromotionReadinessStatus == null ||
                    case.summary.rolloutPromotionReadinessStatus == normalizedFilter.rolloutPromotionReadinessStatus
            }
            .filter { case ->
                normalizedFilter.crossWaveHealthBucket == null ||
                    case.summary.crossWaveHealthBucket == normalizedFilter.crossWaveHealthBucket
            }
            .filter { case ->
                normalizedFilter.windowDelayReason == null ||
                    case.summary.windowDelayReason == normalizedFilter.windowDelayReason
            }
            .filter { case ->
                normalizedFilter.promotionOperationType == null ||
                    case.summary.promotionOperationType == normalizedFilter.promotionOperationType
            }
            .filter { case ->
                normalizedFilter.promotionOperationStatus == null ||
                    case.summary.promotionOperationStatus == normalizedFilter.promotionOperationStatus
            }
            .filter { case ->
                normalizedFilter.programCoordinationState == null ||
                    case.summary.programCoordinationState == normalizedFilter.programCoordinationState
            }
            .filter { case ->
                normalizedFilter.programContentionType == null ||
                    case.summary.programContentionType == normalizedFilter.programContentionType
            }
            .filter { case ->
                normalizedFilter.programContentionLevel == null ||
                    case.summary.programContentionLevel == normalizedFilter.programContentionLevel
            }
            .filter { case ->
                normalizedFilter.programEscalationStatus == null ||
                    case.summary.programEscalationStatus == normalizedFilter.programEscalationStatus
            }
            .filter { case ->
                !normalizedFilter.rolloutPromotionReadyOnly ||
                    case.summary.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.READY ||
                    case.summary.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.READY_WITH_CAUTION
            }
            .filter { case ->
                !normalizedFilter.rolloutPromotionBlockedOnly ||
                    case.summary.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.BLOCKED
            }
            .filter { case ->
                !normalizedFilter.rolloutPromotionDeferredOnly ||
                    case.summary.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.DEFERRED
            }
            .filter { case ->
                !normalizedFilter.rolloutPromotionExpiredOnly ||
                    case.summary.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.EXPIRED
            }
            .filter { case ->
                !normalizedFilter.crossWaveDegradedOnly ||
                    case.summary.crossWaveHealthBucket == WaveHealthBucket.DEGRADED ||
                    case.summary.crossWaveHealthBucket == WaveHealthBucket.BLOCKED
            }
            .filter { case ->
                !normalizedFilter.windowImpactBlockedOnly ||
                    (
                        case.summary.windowDelayReason != null &&
                            case.summary.windowDelayReason != WindowDelayReason.NONE
                        )
            }
            .filter { case ->
                !normalizedFilter.promotionOperationPendingOnly ||
                    case.summary.promotionOperationStatus == GovernanceProgramOperationStatus.SCHEDULED ||
                    case.summary.promotionOperationStatus == GovernanceProgramOperationStatus.APPROVAL_REQUIRED
            }
            .filter { case ->
                !normalizedFilter.priorityDeferredOnly ||
                    case.summary.programCoordinationState == RolloutProgramCoordinationState.DEFERRED ||
                    case.summary.programCoordinationState == RolloutProgramCoordinationState.CONTENTION_BLOCKED
            }
            .filter { case ->
                !normalizedFilter.dependencyBlockedOnly ||
                    case.summary.programCoordinationState == RolloutProgramCoordinationState.DEPENDENCY_BLOCKED ||
                    case.summary.programDependencyBlockedCount > 0
            }
            .filter { case ->
                !normalizedFilter.coordinationEscalatedOnly ||
                    case.summary.programCoordinationState == RolloutProgramCoordinationState.ESCALATED ||
                    case.summary.programEscalationStatus == RolloutProgramEscalationStatus.OPEN ||
                    case.summary.programEscalationStatus == RolloutProgramEscalationStatus.IN_PROGRESS
            }
            .filter { case ->
                !normalizedFilter.contentionOnly ||
                    (
                        case.summary.programContentionType != null &&
                            case.summary.programContentionType != RolloutProgramContentionType.NONE
                        )
            }
            .filter { case ->
                normalizedFilter.capacityPoolKey.isNullOrBlank() ||
                    case.summary.capacityPoolKey.equals(
                        normalizedFilter.capacityPoolKey,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.approvalLoadBucket == null ||
                    case.summary.approvalLoadBucket == normalizedFilter.approvalLoadBucket
            }
            .filter { case ->
                normalizedFilter.capacityDeferralReason == null ||
                    case.summary.capacityDeferralReason == normalizedFilter.capacityDeferralReason
            }
            .filter { case ->
                normalizedFilter.balancingDecisionType == null ||
                    case.summary.balancingDecisionType == normalizedFilter.balancingDecisionType
            }
            .filter { case ->
                !normalizedFilter.capacityBlockedOnly || case.summary.capacityBlocked
            }
            .filter { case ->
                !normalizedFilter.policyBlockedOnly || case.summary.policyBlocked
            }
            .filter { case ->
                !normalizedFilter.bottleneckOnly || case.summary.portfolioBottleneck
            }
            .filter { case ->
                !normalizedFilter.criticalCapacityReservedOnly || case.summary.criticalCapacityReserved
            }
            .filter { case ->
                !normalizedFilter.slaBreachOnly ||
                    case.summary.slaStatus == WorkflowSlaStatus.BREACHED
            }
            .filter { case ->
                !normalizedFilter.escalationPendingOnly ||
                    (
                        case.summary.escalationTimerStatus == WorkflowEscalationTimerStatus.PENDING ||
                            case.summary.escalationTimerStatus == WorkflowEscalationTimerStatus.REQUIRED ||
                            case.summary.escalationTimerStatus == WorkflowEscalationTimerStatus.TRIGGERED
                        )
            }
            .filter { case ->
                !normalizedFilter.policyOverrideAppliedOnly ||
                    (
                        case.summary.workflowPolicyPrecedenceSource == WorkflowPolicyPrecedenceSource.WORKSPACE_OVERRIDE ||
                            case.summary.workflowPolicyPrecedenceSource == WorkflowPolicyPrecedenceSource.TENANT_OVERRIDE ||
                            case.summary.workflowPolicyPrecedenceSource == WorkflowPolicyPrecedenceSource.OPERATOR_OVERRIDE ||
                            case.summary.workflowPolicyPrecedenceSource == WorkflowPolicyPrecedenceSource.EXPLICIT_CONSTRAINT
                        )
            }
            .filter { case ->
                normalizedFilter.workflowSimulationOnly == null ||
                    case.summary.workflowSimulationOnly == normalizedFilter.workflowSimulationOnly
            }
            .filter { case ->
                normalizedFilter.workflowRolloutStage == null ||
                    case.summary.workflowRolloutStage == normalizedFilter.workflowRolloutStage
            }
            .filter { case ->
                normalizedFilter.workflowRolloutMode == null ||
                    case.summary.workflowRolloutMode == normalizedFilter.workflowRolloutMode
            }
            .filter { case ->
                normalizedFilter.workflowRolloutScope == null ||
                    case.summary.workflowRolloutScope == normalizedFilter.workflowRolloutScope
            }
            .filter { case ->
                normalizedFilter.workflowRolloutApprovalState == null ||
                    case.summary.workflowRolloutApprovalState == normalizedFilter.workflowRolloutApprovalState
            }
            .filter { case ->
                !normalizedFilter.workflowRolloutFrozenOnly ||
                    (
                        case.summary.workflowRolloutFreezeState != null &&
                            case.summary.workflowRolloutFreezeState != PolicyRolloutFreezeState.NOT_FROZEN
                        )
            }
            .filter { case ->
                !normalizedFilter.workflowRolloutPausedOnly ||
                    case.summary.workflowRolloutStage == PolicyRolloutStage.PAUSED ||
                    case.summary.workflowRolloutFreezeState == PolicyRolloutFreezeState.PAUSED_BY_OPERATOR
            }
            .filter { case ->
                normalizedFilter.policyPromotionStatus == null ||
                    case.summary.policyPromotionStatus == normalizedFilter.policyPromotionStatus
            }
            .filter { case ->
                normalizedFilter.policyPromotionReadiness == null ||
                    case.summary.policyPromotionReadiness == normalizedFilter.policyPromotionReadiness
            }
            .filter { case ->
                !normalizedFilter.policyApprovalPendingOnly ||
                    case.summary.policyApprovalPending
            }
            .filter { case ->
                normalizedFilter.policyEstateDriftSeverity == null ||
                    case.summary.policyEstateDriftSeverity == normalizedFilter.policyEstateDriftSeverity
            }
            .filter { case ->
                normalizedFilter.policyEstateRemediationStatus == null ||
                    (
                        case.policyEstateRemediationPlan?.status == normalizedFilter.policyEstateRemediationStatus ||
                            case.policyEstateRemediationActions.lastOrNull()?.status == normalizedFilter.policyEstateRemediationStatus
                        )
            }
            .filter { case ->
                !normalizedFilter.policyEstateBlockedOnly ||
                    case.summary.policyEstateBlockerCount > 0 ||
                    case.summary.policyEstateRemediationPending
            }
            .filter { case ->
                normalizedFilter.portfolioOptimizationDecisionId.isNullOrBlank() ||
                    case.summary.portfolioOptimizationDecisionId.equals(
                        normalizedFilter.portfolioOptimizationDecisionId,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.portfolioCalibrationSnapshotId.isNullOrBlank() ||
                    case.summary.portfolioCalibrationSnapshotId.equals(
                        normalizedFilter.portfolioCalibrationSnapshotId,
                        ignoreCase = true
                    )
            }
            .filter { case ->
                normalizedFilter.portfolioObjectiveProfileSnapshotId.isNullOrBlank() ||
                    case.summary.portfolioObjectiveProfileSnapshotId.equals(
                        normalizedFilter.portfolioObjectiveProfileSnapshotId,
                        ignoreCase = true
