                    case.summary.portfolioRemediationApprovalRequired
            }
            .filter { case ->
                !normalizedFilter.portfolioSharedBlockersOnly ||
                    case.summary.portfolioSharedBlockerCount > 0
            }
            .filter { case ->
                !normalizedFilter.portfolioDataExchangeApprovalPendingOnly ||
                    case.summary.portfolioDataExchangeApprovalStatus ==
                    PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW
            }
            .filter { case ->
                normalizedFilter.includeReviewed || !case.summary.reviewed
            }
            .take(normalizedFilter.limit.coerceIn(1, MAX_GOVERNANCE_QUERY_LIMIT))
            .toList()
    }

    fun getGovernanceConsoleState(
        userId: String,
        filter: GovernanceConsoleFilter = GovernanceConsoleFilter()
    ): GovernanceConsoleState {
        val normalizedFilter = normalizeGovernanceConsoleFilter(filter)
        val cases = getGovernanceCases(userId, normalizedFilter)
        val queueCounts = GovernanceQueueType.entries.map { queue ->
            GovernanceQueueCount(
                queue = queue,
                count = cases.count { it.summary.queueTags.contains(queue) },
                highPriorityCount = cases.count {
                    it.summary.queueTags.contains(queue) &&
                        (it.summary.priority == GovernanceCasePriority.HIGH ||
                            it.summary.priority == GovernanceCasePriority.CRITICAL)
                }
            )
        }.filter { it.count > 0 }
            .sortedByDescending { it.count }
        val alerts = aggregateGovernanceAlerts(cases)
        val savedPresets = buildOperatorQueuePresets(cases)
        val homeSummary = buildOperatorHomeSummary(cases, savedPresets, alerts)
        val remotePipelineSummary = remotePipelineSummaryForCases(userId, cases)
        val remoteDeliveryIssues = aggregateRemoteDeliveryIssues(userId, cases)
        val collaborationSummary = aggregateCollaborationSummary(cases)
        val remoteOperatorSummary = aggregateRemoteOperatorSummary(cases)
        val portfolioSimulationState = getPortfolioSimulationState(
            userId = userId,
            query = PortfolioSimulationQuery(
                includeCompleted = true,
                includeFailed = true,
                limit = MAX_PORTFOLIO_SIMULATION_ITEMS
            )
        )
        val portfolioOptimizationState = getPortfolioOptimizationState(
            userId = userId,
            query = PortfolioOptimizationQuery(
                includeCompleted = true,
                limit = MAX_PORTFOLIO_OPTIMIZATION_ITEMS
            )
        )
        val notes = buildList {
            add("Queues derive from durable receipt/ledger facts; they are not transient UI-only states.")
            add("Operator actions are durable overlays on execution truth; receipts and settlement/dispute outcomes remain authoritative.")
            portfolioOptimizationState.summary
                ?.summary
                ?.takeIf { it.isNotBlank() }
                ?.let { add("Portfolio optimization: $it") }
            remotePipelineSummary?.summary
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it) }
            remoteOperatorSummary
                ?.takeIf {
                    it.handoffPendingCases > 0 ||
                        it.ackPendingCases > 0 ||
                        it.failedHandoffCases > 0 ||
                        it.connectorDeadLetterCases > 0 ||
                        it.connectorUnavailableCases > 0
                }
                ?.let {
                    add(
                        "Remote operator handoff: pending ${it.handoffPendingCases}, " +
                            "ack pending ${it.ackPendingCases}, failed ${it.failedHandoffCases}; " +
                            "connector dead-letter ${it.connectorDeadLetterCases}, unavailable ${it.connectorUnavailableCases}."
                    )
                }
        }
        return GovernanceConsoleState(
            filter = normalizedFilter,
            generatedAtMs = nowMs(),
            totalRecords = cases.size,
            matchedCases = cases.size,
            reviewedCases = cases.count { it.summary.reviewed },
            highPriorityCases = cases.count {
                it.summary.priority == GovernanceCasePriority.HIGH ||
                    it.summary.priority == GovernanceCasePriority.CRITICAL
            },
            queueCounts = queueCounts,
            alerts = alerts,
            cases = cases,
            savedPresets = savedPresets,
            homeSummary = homeSummary,
            remotePipelineSummary = remotePipelineSummary,
            remoteDeliveryIssues = remoteDeliveryIssues,
            collaborationSummary = collaborationSummary,
            remoteOperatorSummary = remoteOperatorSummary,
            portfolioSimulationState = portfolioSimulationState,
            portfolioOptimizationState = portfolioOptimizationState,
            notes = notes
        )
    }

    fun getPortfolioSimulationState(
        userId: String,
        query: PortfolioSimulationQuery = PortfolioSimulationQuery()
    ): PortfolioSimulationState {
        if (userId.isBlank()) return PortfolioSimulationState(query = query, generatedAtMs = nowMs())
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val normalizedLimit = query.limit.coerceIn(1, MAX_PORTFOLIO_SIMULATION_ITEMS)
        val baseline = deriveBaselinePortfolioSnapshot(userId = userId, now = now)
        val scenarios = synchronized(dynamicStateLock) {
            portfolioScenarioDefinitionsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter { query.scenarioId.isNullOrBlank() || it.scenarioId == query.scenarioId }
            .sortedWith(
                compareByDescending<PortfolioScenarioDefinition> { it.updatedAtMs }
                    .thenBy { it.scenarioId }
            )
            .take(normalizedLimit)
        val runs = synchronized(dynamicStateLock) {
            portfolioSimulationRunsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .asSequence()
            .filter { query.scenarioId.isNullOrBlank() || it.scenarioId == query.scenarioId }
            .filter { query.runId.isNullOrBlank() || it.runId == query.runId }
            .filter { query.includeCompleted || it.status != PortfolioSimulationRunStatus.COMPLETED }
            .filter { query.includeFailed || it.status != PortfolioSimulationRunStatus.FAILED }
            .sortedWith(
                compareByDescending<PortfolioSimulationRunRecord> { it.startedAtMs }
                    .thenBy { it.runId }
            )
            .take(normalizedLimit)
            .toList()
        val comparisons = synchronized(dynamicStateLock) {
            portfolioScenarioComparisonsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .sortedWith(
                compareByDescending<PortfolioScenarioComparison> { it.createdAtMs }
                    .thenBy { it.comparisonId }
            )
            .take(normalizedLimit)
        val latestRun = runs.firstOrNull()
        val summary = PortfolioSimulationSummary(
            latestRunId = latestRun?.runId,
            scenarioCount = synchronized(dynamicStateLock) {
                portfolioScenarioDefinitionsByUser[userId]?.size ?: 0
            },
            runCount = synchronized(dynamicStateLock) {
                portfolioSimulationRunsByUser[userId]?.size ?: 0
            },
            lastRunStatus = latestRun?.status,
            capacityBreachPredicted = runs.any { run ->
                run.breachSignals.any { signal -> signal.type == PortfolioForecastBreachType.CAPACITY_BREACH }
            },
            backlogGrowthPredicted = runs.any { run ->
                run.breachSignals.any { signal -> signal.type == PortfolioForecastBreachType.BACKLOG_GROWTH }
            },
            completionDelayPredicted = runs.any { run ->
                run.breachSignals.any { signal -> signal.type == PortfolioForecastBreachType.COMPLETION_DELAY }
            },
            topRecommendation = latestRun?.topRecommendation.orEmpty(),
            reasonCodes = latestRun?.recommendationReasonCodes.orEmpty(),
            summary = latestRun?.summary?.takeIf { it.isNotBlank() }
                ?: "No simulation run is available yet. Create and run a bounded scenario."
        )
        val notes = buildList {
            add("Baseline snapshot is derived from durable governance/ledger records, not transient UI state.")
            add("Simulation artifacts are decision-support overlays and never rewrite receipt/ledger truth.")
            if (scenarios.isEmpty()) {
                add("No saved scenarios yet. Create one with bounded window/wave/capacity controls.")
            }
        }
        return PortfolioSimulationState(
            query = query.copy(limit = normalizedLimit),
            generatedAtMs = now,
            baseline = baseline,
            scenarios = scenarios,
            runs = runs,
            comparisons = comparisons,
            summary = summary,
            notes = notes
        )
    }

    fun getPortfolioOptimizationState(
        userId: String,
        query: PortfolioOptimizationQuery = PortfolioOptimizationQuery()
    ): PortfolioOptimizationState {
        if (userId.isBlank()) return PortfolioOptimizationState(query = query, generatedAtMs = nowMs())
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val normalizedLimit = query.limit.coerceIn(1, MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
        val queryObjectiveProfileSnapshotId = query.objectiveProfileSnapshotId
        val baseline = deriveBaselinePortfolioSnapshot(userId = userId, now = now)
        val activeObjectiveProfileSnapshot = activePortfolioOptimizationObjectiveProfileSnapshot(userId, now)
        val activeCalibrationSnapshot = activePortfolioOptimizationCalibrationSnapshot(userId, now)
        val objectiveProfileSnapshots = synchronized(dynamicStateLock) {
            ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
            portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() || it.snapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.binding.scope == query.learningScope }
            .sortedWith(
                compareByDescending<PortfolioOptimizationObjectiveProfileSnapshot> { it.createdAtMs }
                    .thenBy { it.snapshotId }
            )
            .take(normalizedLimit)
        val calibrationSnapshots = synchronized(dynamicStateLock) {
            ensurePortfolioOptimizationCalibrationSnapshotsInitializedLocked(userId, now)
            portfolioOptimizationCalibrationSnapshotsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter { query.calibrationSnapshotId.isNullOrBlank() || it.snapshotId == query.calibrationSnapshotId }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .sortedWith(
                compareByDescending<PortfolioOptimizationCalibrationSnapshot> { it.createdAtMs }
                    .thenBy { it.snapshotId }
            )
            .take(normalizedLimit)
        val requests = synchronized(dynamicStateLock) {
            portfolioOptimizationRequestsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter { query.requestId.isNullOrBlank() || it.requestId == query.requestId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .sortedWith(
                compareByDescending<PortfolioOptimizationRequest> { it.updatedAtMs }
                    .thenBy { it.requestId }
            )
            .take(normalizedLimit)
        val results = synchronized(dynamicStateLock) {
            portfolioOptimizationResultsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter { query.requestId.isNullOrBlank() || it.requestId == query.requestId }
            .filter { query.resultId.isNullOrBlank() || it.resultId == query.resultId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .filter { query.includeCompleted || it.status != PortfolioOptimizationResultStatus.COMPLETED }
            .sortedWith(
                compareByDescending<PortfolioOptimizationResult> { it.startedAtMs }
                    .thenBy { it.resultId }
            )
            .take(normalizedLimit)
        val decisions = synchronized(dynamicStateLock) {
            portfolioOptimizationDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
        }
            .filter { query.requestId.isNullOrBlank() || it.requestId == query.requestId }
            .filter { query.resultId.isNullOrBlank() || it.resultId == query.resultId }
            .filter { query.decisionId.isNullOrBlank() || it.decisionId == query.decisionId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .sortedWith(
                compareByDescending<PortfolioOptimizationDecisionRecord> { it.selectedAtMs }
                    .thenBy { it.decisionId }
            )
            .take(normalizedLimit)
        val outcomes = synchronized(dynamicStateLock) {
            portfolioOptimizationOutcomesByUser[userId]?.toList().orEmpty()
        }
            .filter { query.requestId.isNullOrBlank() || it.requestId == query.requestId }
            .filter { query.resultId.isNullOrBlank() || it.resultId == query.resultId }
            .filter { query.decisionId.isNullOrBlank() || it.decisionId == query.decisionId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .sortedWith(
                compareByDescending<PortfolioScheduleOutcomeRecord> { it.recordedAtMs }
                    .thenBy { it.outcomeId }
            )
            .take(normalizedLimit)
        val driftSummaries = synchronized(dynamicStateLock) {
            portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
        }
            .filter { query.decisionId.isNullOrBlank() || it.decisionId == query.decisionId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .filter { query.driftSeverity == null || it.highestSeverity == query.driftSeverity }
            .sortedWith(
                compareByDescending<PortfolioOptimizationDriftSummary> { it.createdAtMs }
                    .thenBy { it.driftId }
            )
            .take(normalizedLimit)
        val tuningSuggestions = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningSuggestionsByUser[userId]?.toList().orEmpty()
        }
            .filter { query.decisionId.isNullOrBlank() || it.decisionId == query.decisionId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .filter { query.tuningStatus == null || it.status == query.tuningStatus }
            .filter { query.tuningTargetFamily == null || it.targetFamily == query.tuningTargetFamily }
            .sortedWith(
                compareByDescending<PortfolioOptimizationTuningSuggestion> { it.createdAtMs }
                    .thenBy { it.suggestionId }
            )
            .take(normalizedLimit)
        val tuningDecisionRecords = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningDecisionsByUser[userId]?.toList().orEmpty()
        }
            .filter { query.decisionId.isNullOrBlank() || it.decisionId == query.decisionId }
            .filter {
                query.calibrationSnapshotId.isNullOrBlank() || it.calibrationSnapshotId == query.calibrationSnapshotId
            }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.objectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.objectiveProfileBinding.scope == query.learningScope }
            .filter { query.tuningStatus == null || it.status == query.tuningStatus }
            .sortedWith(
                compareByDescending<PortfolioOptimizationTuningDecisionRecord> { it.decidedAtMs }
                    .thenBy { it.tuningDecisionId }
            )
            .take(normalizedLimit)
        val propagationAttempts = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAttemptsByUser[userId]?.toList().orEmpty()
        }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.sourceObjectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.targetScope == query.learningScope }
            .filter { query.propagationStatus == null || it.status == query.propagationStatus }
            .sortedWith(
                compareByDescending<PortfolioOptimizationPropagationAttemptRecord> { it.createdAtMs }
                    .thenBy { it.attemptId }
            )
            .take(normalizedLimit)
        val propagationApprovals = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationApprovalsByUser[userId]?.toList().orEmpty()
        }
            .filter { approval ->
                propagationAttempts.any { it.attemptId == approval.attemptId } ||
                    query.propagationStatus == null
            }
            .sortedWith(
                compareByDescending<PortfolioOptimizationPropagationApprovalRecord> { it.decidedAtMs }
                    .thenBy { it.approvalId }
            )
            .take(normalizedLimit)
        val propagationAdoptions = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAdoptionsByUser[userId]?.toList().orEmpty()
        }
            .filter {
                query.objectiveProfileSnapshotId.isNullOrBlank() ||
                    it.sourceObjectiveProfileSnapshotId == query.objectiveProfileSnapshotId ||
                    it.targetObjectiveProfileSnapshotId == query.objectiveProfileSnapshotId
            }
            .filter { query.learningScope == null || it.targetBinding.scope == query.learningScope }
            .filter { query.propagationStatus == null || it.status == query.propagationStatus }
            .sortedWith(
                compareByDescending<PortfolioOptimizationPropagationAdoptionRecord> { it.adoptedAtMs }
                    .thenBy { it.adoptionId }
