            latestLearningSummary = buildString {
                val fragments = listOf(
                    activeObjectiveProfileSnapshot.summary,
                    latestOutcome?.summary,
                    latestDrift?.summary,
                    latestTuningDecision?.summary ?: latestTuningSuggestion?.summary,
                    latestPropagationAdoption?.summary ?: latestPropagationApproval?.summary ?: latestPropagationAttempt?.summary,
                    latestSyncAttempt?.summary ?: latestSyncConflict?.summary,
