                    latestAggregation?.summary
                ).filterNotNull().filter { it.isNotBlank() }
                if (fragments.isNotEmpty()) {
                    append(fragments.joinToString(" "))
                }
            },
            reasonCodes = buildList {
                add(RoleReasonCodes.ROLE_LEARNING_SCOPE_RESOLVED)
                addAll(topCandidate?.bindingConstraints?.flatMap { it.reasonCodes }.orEmpty())
                addAll(topCandidate?.tradeoffExplanations?.flatMap { it.reasonCodes }.orEmpty())
                if (latestDecision != null) add(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_SCHEDULE_SELECTED)
                if (latestOutcome != null) add(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_OUTCOME_RECORDED)
                if (latestDrift?.signals?.isNotEmpty() == true) add(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_DRIFT_DETECTED)
                when (latestTuningDecision?.status ?: latestTuningSuggestion?.status) {
                    PortfolioOptimizationTuningStatus.PENDING ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_SUGGESTED)
                    PortfolioOptimizationTuningStatus.APPLIED ->
