                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_SUPPRESSED_BY_DRIFT)
                    PortfolioOptimizationPropagationEligibilityStatus.BLOCKED ->
                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED)
                    null -> Unit
                }
                when (latestSyncAttempt?.status) {
                    PortfolioOptimizationLearningSyncStatus.EXPORTED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_DELIVERED)
                    PortfolioOptimizationLearningSyncStatus.APPLIED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_DELIVERED)
                    PortfolioOptimizationLearningSyncStatus.BLOCKED -> {
                        if (learningSyncConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED) {
                            add(RoleReasonCodes.ROLE_CONSENT_DENIED)
                        } else if (!activePrivacyPolicy.cloudSyncAllowed) {
                            add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY)
                        } else {
                            add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY)
                        }
                    }
                    PortfolioOptimizationLearningSyncStatus.CONFLICT_REVIEW_REQUIRED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED)
                    PortfolioOptimizationLearningSyncStatus.FAILED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_FAILED)
                    PortfolioOptimizationLearningSyncStatus.QUEUED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_ENQUEUED)
                    null -> Unit
                }
                when (latestSyncConflict?.resolution) {
                    PortfolioOptimizationLearningSyncConflictResolution.SAFE_MERGE,
                    PortfolioOptimizationLearningSyncConflictResolution.LAST_WRITE_WINS_LOCAL,
                    PortfolioOptimizationLearningSyncConflictResolution.LAST_WRITE_WINS_INCOMING ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_RESOLVED)
                    PortfolioOptimizationLearningSyncConflictResolution.REVIEW_REQUIRED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED)
                    PortfolioOptimizationLearningSyncConflictResolution.BLOCKED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_FAILED)
                    null,
                    PortfolioOptimizationLearningSyncConflictResolution.NONE -> Unit
                }
                if (latestAggregation != null) {
                    add(RoleReasonCodes.ROLE_FEDERATED_AGGREGATION_APPLIED)
                }
                addAll(latestRemoteTransportAttempt?.reasonCodes.orEmpty())
                addAll(latestAuditExportResult?.reasonCodes.orEmpty())
                when (latestConsent?.decision) {
                    PortfolioOptimizationConsentDecision.ALLOWED -> add(RoleReasonCodes.ROLE_CONSENT_GRANTED)
                    PortfolioOptimizationConsentDecision.DENIED,
                    PortfolioOptimizationConsentDecision.PENDING -> add(RoleReasonCodes.ROLE_CONSENT_DENIED)
                    PortfolioOptimizationConsentDecision.REVOKED -> add(RoleReasonCodes.ROLE_CONSENT_REVOKED)
                    PortfolioOptimizationConsentDecision.EXPIRED -> add(RoleReasonCodes.ROLE_CONSENT_EXPIRED)
                    null -> Unit
                }
                when (latestRemoteTransportAttempt?.status) {
                    PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_ONLY ->
                        add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_LOCAL_ONLY)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK ->
                        add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.QUEUED,
                    PortfolioOptimizationRemoteLearningDeliveryStatus.SENT,
                    PortfolioOptimizationRemoteLearningDeliveryStatus.ACK_PENDING ->
                        add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_QUEUED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.ACKED ->
                        add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_ACKED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.DEDUPED ->
                        add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEDUPED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.RETRY_SCHEDULED ->
                        add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_RETRIED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED ->
                        add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEAD_LETTERED)
                    PortfolioOptimizationRemoteLearningDeliveryStatus.BLOCKED -> {
                        if (remoteTransportConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED) {
                            add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_CONSENT)
                        } else {
                            add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_ROLE_POLICY)
                        }
                    }
                    PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED ->
                        add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_FAILED)
                    null -> Unit
                }
                when (latestAuditExportResult?.status) {
                    PortfolioOptimizationComplianceAuditExportStatus.COMPLETE ->
                        add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_GENERATED)
                    PortfolioOptimizationComplianceAuditExportStatus.BLOCKED -> {
                        if (auditExportConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED) {
                            add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_CONSENT)
                        } else {
                            add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_POLICY)
                        }
                    }
                    PortfolioOptimizationComplianceAuditExportStatus.QUEUED ->
                        add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_REQUESTED)
                    PortfolioOptimizationComplianceAuditExportStatus.FAILED ->
                        add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_POLICY)
                    null -> Unit
                }
                addAll(latestDataExchangeDecision?.reasonCodes.orEmpty())
                addAll(latestCrossBoundaryApproval?.reasonCodes.orEmpty())
                addAll(latestCrossBoundaryAudit?.reasonCodes.orEmpty())
                when (latestDestinationTrustTierAssignment?.trustTier) {
                    PortfolioOptimizationDestinationTrustTier.RESTRICTED ->
                        add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_RESTRICTED)
                    PortfolioOptimizationDestinationTrustTier.LIMITED,
                    PortfolioOptimizationDestinationTrustTier.UNVERIFIED ->
                        add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_DEFERRED)
                    PortfolioOptimizationDestinationTrustTier.TRUSTED,
                    PortfolioOptimizationDestinationTrustTier.HIGH_TRUST ->
                        add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_ASSIGNED)
                    null -> Unit
                }
                when (latestJurisdictionRolloutPlan?.rolloutState) {
                    PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED ->
                        add(RoleReasonCodes.ROLE_JURISDICTION_ROLLOUT_SPLIT_RECOMMENDED)
                    PortfolioOptimizationJurisdictionRolloutState.BLOCKED,
                    PortfolioOptimizationJurisdictionRolloutState.DEFERRED ->
                        add(RoleReasonCodes.ROLE_JURISDICTION_ROLLOUT_RESEQUENCED)
                    null,
                    PortfolioOptimizationJurisdictionRolloutState.READY,
                    PortfolioOptimizationJurisdictionRolloutState.HELD -> Unit
                }
                if (latestPortfolioPriorityDecision != null) {
                    add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_PRIORITY_SELECTED)
                }
                if (latestPortfolioRecommendation != null) {
                    add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_RECOMMENDATION_UPDATED)
                }
                if (latestPortfolioBlocker?.programIds?.size ?: 0 > 1) {
                    add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_SHARED_BLOCKER_DETECTED)
                }
                if (latestPortfolioConflict != null) {
                    add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_CONFLICT_OPENED)
                }
                if (latestPortfolioAnalytics != null) {
                    add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_ANALYTICS_UPDATED)
                }
                if (latestTrustTierDrift != null &&
                    latestTrustTierDrift.driftState != PortfolioOptimizationTrustTierDriftState.HEALTHY
                ) {
                    add(RoleReasonCodes.ROLE_TRUST_TIER_DRIFT_DETECTED)
                }
                if (latestJurisdictionDrift != null &&
                    latestJurisdictionDrift.driftState != PortfolioOptimizationJurisdictionDriftState.HEALTHY
                ) {
                    add(RoleReasonCodes.ROLE_JURISDICTION_DRIFT_DETECTED)
                }
                if (latestRiskBudget != null) {
                    add(RoleReasonCodes.ROLE_RISK_BUDGET_UPDATED)
                    if (latestRiskBudget.status == PortfolioOptimizationRiskBudgetStatus.EXCEEDED ||
                        latestRiskBudget.status == PortfolioOptimizationRiskBudgetStatus.HELD
                    ) {
                        add(RoleReasonCodes.ROLE_RISK_BUDGET_BREACHED)
                    }
                }
                when (latestPortfolioSafetySummary?.safetyState) {
                    PortfolioOptimizationPortfolioSafetyState.AT_RISK ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_AT_RISK)
                    PortfolioOptimizationPortfolioSafetyState.GUARDED ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_GUARDED)
                    PortfolioOptimizationPortfolioSafetyState.QUARANTINED,
                    PortfolioOptimizationPortfolioSafetyState.BLOCKED ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_QUARANTINED)
                    PortfolioOptimizationPortfolioSafetyState.SAFE,
                    null -> Unit
                }
                when (latestBudgetGuardrail?.state) {
                    PortfolioOptimizationBudgetGuardrailState.WARNING ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_WARNING)
                    PortfolioOptimizationBudgetGuardrailState.SOFT_STOP ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_SOFT_STOP)
                    PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_HARD_STOP)
                    PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                    PortfolioOptimizationBudgetGuardrailState.WITHIN_LIMIT,
                    null -> Unit
                }
                when (latestRemediationAutomationControl?.automationState) {
                    PortfolioOptimizationRemediationAutomationState.ALLOWED ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_ALLOWED)
                    PortfolioOptimizationRemediationAutomationState.THROTTLED ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_THROTTLED)
                    PortfolioOptimizationRemediationAutomationState.SUPPRESSED ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_SUPPRESSED)
                    PortfolioOptimizationRemediationAutomationState.COOLDOWN_ACTIVE ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_COOLDOWN_ACTIVE)
                    PortfolioOptimizationRemediationAutomationState.APPROVAL_REQUIRED ->
                        add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                    PortfolioOptimizationRemediationAutomationState.QUARANTINED ->
                        add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                    null -> Unit
                }
                if (latestPortfolioRiskRecommendation != null) {
                    add(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_RECOMMENDATION_ISSUED)
                }
                if (latestPortfolioCorrectiveAction != null) {
                    add(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_ACTION_RECORDED)
                }
            }.distinct(),
            summary = buildString {
                when {
                    latestPortfolioAnalytics != null && latestRiskBudget != null -> {
                        append("Governance portfolio ")
                        append((latestPortfolioAnalytics.portfolioId.ifBlank {
                            latestCrossBoundaryGovernancePortfolio?.portfolioId.orEmpty()
                        }).takeLast(10))
                        append(" is ")
                        append(
                            latestPortfolioSafetySummary?.safetyState?.name?.lowercase()
                                ?: latestPortfolioAnalytics.healthStatus.name.lowercase()
                        )
                        append(" with risk budget ")
                        append(latestRiskBudget.status.name.lowercase().replace('_', ' '))
                        latestRemediationAutomationControl?.automationState?.let { automationState ->
                            append(" and remediation ")
                            append(automationState.name.lowercase().replace('_', ' '))
                        }
                        append('.')
                    }
                    latestCrossBoundaryGovernancePortfolio != null && latestPortfolioRecommendation != null -> {
                        append("Governance portfolio ")
                        append(latestCrossBoundaryGovernancePortfolio.portfolioId.takeLast(10))
                        append(" is ")
                        append(latestCrossBoundaryGovernancePortfolio.status.name.lowercase())
                        append(" with recommendation ")
                        append(latestPortfolioRecommendation.action.name.lowercase().replace('_', ' '))
                        append('.')
                    }
                    latestSyncAttempt != null && latestSyncAttempt.status == PortfolioOptimizationLearningSyncStatus.BLOCKED -> {
                        append("Learning sync is blocked by current privacy or role policy.")
                    }
                    latestSyncConflict?.reviewRequired == true -> {
                        append("Learning sync conflict requires review before artifacts can be applied safely.")
                    }
                    latestPropagationAdoption != null -> {
                        append("Objective profile ")
                        append(activeObjectiveProfileSnapshot.snapshotId.takeLast(10))
                        append(" is active at ")
                        append(portfolioOptimizationScopeLabel(activeObjectiveProfileSnapshot.binding.scope))
                        append(" scope after propagation review.")
                    }
                    latestTuningDecision?.status == PortfolioOptimizationTuningStatus.APPLIED -> {
                        append("Calibration snapshot ")
                        append(latestTuningDecision.appliedSnapshotId?.takeLast(10) ?: activeCalibrationSnapshot.snapshotId.takeLast(10))
                        append(" applied after drift review.")
                    }
                    latestOutcome != null && latestDrift != null -> {
                        append("Outcome ")
                        append(latestOutcome.outcomeId.takeLast(10))
                        append(" recorded with ")
                        append(latestDrift.highestSeverity.name.lowercase())
                        append(" drift.")
                    }
                    latestResult == null -> append("No optimization result is available yet. Save and run a bounded request.")
                    latestDecision != null -> {
                        append("Selected schedule ")
                        append(latestDecision.candidateId.takeLast(10))
                        append(" from result ")
                        append(latestResult.resultId.takeLast(10))
                        append('.')
                    }
                    topCandidate != null -> {
                        append("Recommended schedule ")
                        append(topCandidate.candidateId.takeLast(10))
                        append(": ")
                        append(topCandidate.summary.ifBlank { "top candidate ready for review" })
                    }
                    else -> append(latestResult.summary.ifBlank { "Optimization completed without candidate schedules." })
                }
            }
        )
        val notes = buildList {
            add("Optimization results are advisory schedules; selecting a candidate does not auto-execute rollout actions.")
            add("All schedules are derived from local durable governance truth and preserve restore/process-death continuity.")
            add("Closed-loop learning stays local-first, deterministic, and manual-control-first; tuning is never auto-applied.")
            add("Objective profiles resolve deterministically as user, workspace, tenant, then global baseline, while explicit task constraints and role policy still take precedence.")
            add("Learning sync is artifact-only and redacted; raw user content and raw prompts are never synced.")
            add("Remote learning transport is optional and defaults to a no-op local-first boundary until consent and transport mode allow export.")
            add("Compliance audit export is redaction-first, purpose-limited, and excludes raw prompts and raw user messages by default.")
            add("Remote destination routing is residency-aware, jurisdiction-aware, and preserves local-first fallback when no compliant route is available.")
            add("Data exchange bundles remain typed, redaction-first, and boundary-audited; receipt and governance traces stay local when remote bundle policy requires a split.")
            add("Cross-boundary governance portfolios coordinate trust-tier rollout order, jurisdiction sequencing, shared blockers, and next portfolio actions deterministically.")
            add("Portfolio analytics derive trust-tier drift, jurisdiction drift, and bounded risk budgets from durable cross-boundary governance state.")
            add("Corrective recommendations and operator-recorded safe actions remain advisory and auditable; they do not auto-execute remote changes.")
            add("Portfolio safety rails, budget guardrails, and remediation controls are durable, non-destructive enforcement signals that can warn, soft-stop, hard-stop, quarantine, or require approval.")
            add("Federated aggregation remains same-tenant by default and cross-tenant aggregation is blocked unless explicitly relaxed in future milestones.")
            if (requests.isEmpty()) {
                add("No optimization requests saved yet. Create one with a typed objective and constraint profile.")
            }
            if (outcomes.size < 3) {
                add("At least three outcomes under the active calibration snapshot are required before tuning suggestions can be applied.")
            }
        }
        return PortfolioOptimizationState(
            query = query.copy(limit = normalizedLimit),
            generatedAtMs = now,
            baseline = baseline,
            objectiveProfileSnapshots = objectiveProfileSnapshots,
            calibrationSnapshots = calibrationSnapshots,
            requests = requests,
            results = results,
            decisions = decisions,
            outcomes = outcomes,
            driftSummaries = driftSummaries,
            tuningSuggestions = tuningSuggestions,
            tuningDecisionRecords = tuningDecisionRecords,
            propagationAttemptRecords = propagationAttempts,
            propagationApprovalRecords = propagationApprovals,
            propagationAdoptionRecords = propagationAdoptions,
            learningSyncEnvelopes = syncEnvelopes,
            learningSyncAttemptRecords = syncAttemptRecords,
            learningSyncConflictRecords = syncConflictRecords,
            consentRecords = consentRecords,
            remoteLearningEnvelopes = remoteLearningEnvelopes,
            remoteLearningBatches = remoteLearningBatches,
            remoteLearningTransportAttemptRecords = remoteLearningTransportAttempts,
            remoteDestinationProfiles = remoteDestinationProfiles,
            remoteDestinationDecisionRecords = remoteDestinationDecisions,
            remoteTransportConnectorProfiles = remoteTransportConnectorProfiles,
            enterpriseKeyReferences = enterpriseKeyReferences,
            remoteTransportDeadLetterRecords = remoteTransportDeadLetterRecords,
            complianceAuditExportRequests = complianceAuditExportRequests,
            complianceAuditExportResults = complianceAuditExportResults,
            complianceExportRouteRecords = complianceExportRoutes,
            dataExchangeBundles = dataExchangeBundles,
            dataExchangeBundleDecisionRecords = dataExchangeBundleDecisions,
            dataExchangeManifests = dataExchangeManifests,
            crossBoundaryApprovalRecords = crossBoundaryApprovals,
            crossBoundaryAuditRecords = crossBoundaryAudits,
            destinationTrustTierAssignments = destinationTrustTierAssignments,
            crossBoundaryProgramRecords = crossBoundaryProgramRecords,
            crossBoundaryGovernancePortfolios = crossBoundaryGovernancePortfolios,
            trustTierProgramSummaries = trustTierProgramSummaries,
            jurisdictionRolloutPlans = jurisdictionRolloutPlans,
            portfolioBlockerSummaries = portfolioBlockerSummaries,
            portfolioDependencySummaries = portfolioDependencySummaries,
            portfolioConflictSummaries = portfolioConflictSummaries,
            portfolioPriorityDecisions = portfolioPriorityDecisions,
            portfolioCoordinationRecommendations = portfolioCoordinationRecommendations,
            portfolioWaveCoordinationRecords = portfolioWaveCoordinationRecords,
            crossBoundaryPortfolioAnalyticsSummaries = crossBoundaryPortfolioAnalyticsSummaries,
            portfolioRiskBudgets = portfolioRiskBudgets,
            trustTierDriftSummaries = trustTierDriftSummaries,
            jurisdictionDriftSummaries = jurisdictionDriftSummaries,
            destinationRiskConcentrationSummaries = destinationRiskConcentrationSummaries,
            portfolioBlockerTrendSummaries = portfolioBlockerTrendSummaries,
            portfolioRiskRecommendations = portfolioRiskRecommendations,
            crossBoundaryCorrectiveActionRecords = crossBoundaryCorrectiveActionRecords,
            portfolioSafetyRails = portfolioSafetyRails,
            portfolioBudgetGuardrails = portfolioBudgetGuardrails,
            portfolioSafetySummaries = portfolioSafetySummaries,
            portfolioRemediationAutomationControls = portfolioRemediationAutomationControls,
            federatedAggregationSummaries = federatedAggregationSummaries,
            activeLearningSyncPrivacyPolicy = activePrivacyPolicy,
            activeEnterprisePrivacyPolicy = activeEnterprisePrivacy,
            activeFederationBoundary = activeFederationBoundary,
            summary = summary,
            notes = notes
        )
    }

    fun savePortfolioScenario(
        userId: String,
        scenario: PortfolioScenarioDefinition
    ): PortfolioScenarioDefinition {
        if (userId.isBlank()) return scenario
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val normalized = normalizePortfolioScenarioDefinition(
            scenario = scenario,
            now = now
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioScenarioDefinitionsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.scenarioId == normalized.scenarioId }
                .plus(normalized)
                .sortedWith(
                    compareByDescending<PortfolioScenarioDefinition> { it.updatedAtMs }
                        .thenBy { it.scenarioId }
                )
                .take(MAX_PORTFOLIO_SIMULATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return normalized
    }

    fun savePortfolioOptimizationRequest(
        userId: String,
        request: PortfolioOptimizationRequest
    ): PortfolioOptimizationRequest {
        if (userId.isBlank()) return request
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val requestedBinding = resolvePortfolioOptimizationScopeBinding(userId, request.objectiveProfileBinding)
        val explicitObjectiveProfileSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, request.objectiveProfileSnapshotId)
        }
        val explicitCalibrationSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationCalibrationSnapshotLocked(userId, request.calibrationSnapshotId)
        }
        val resolvedObjectiveProfileSnapshot = explicitObjectiveProfileSnapshot
            ?: explicitCalibrationSnapshot
                ?.objectiveProfileSnapshotId
                ?.let { snapshotId ->
                    synchronized(dynamicStateLock) {
                        findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, snapshotId)
                    }
                }
            ?: resolvePortfolioOptimizationObjectiveProfileSnapshot(
                userId = userId,
                binding = requestedBinding,
                now = now
            )
        val calibrationSnapshot = explicitCalibrationSnapshot
            ?: resolvePortfolioOptimizationCalibrationSnapshot(
                userId = userId,
                snapshotId = null,
                objectiveProfileSnapshot = resolvedObjectiveProfileSnapshot,
                now = now
            )
        val normalized = normalizePortfolioOptimizationRequest(
            request = request,
            now = now,
            calibrationSnapshotId = calibrationSnapshot.snapshotId
        ).copy(
            objectiveProfileSnapshotId = resolvedObjectiveProfileSnapshot.snapshotId,
            objectiveProfileBinding = resolvedObjectiveProfileSnapshot.binding
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationRequestsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.requestId == normalized.requestId }
                .plus(normalized)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationRequest> { it.updatedAtMs }
                        .thenBy { it.requestId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return normalized
    }

    fun runPortfolioScenario(
        userId: String,
        scenarioId: String
    ): PortfolioSimulationRunRecord {
        if (userId.isBlank()) {
            return PortfolioSimulationRunRecord(
                runId = "simulation_run_invalid_user",
                scenarioId = scenarioId,
                status = PortfolioSimulationRunStatus.FAILED,
                summary = "Simulation run failed: missing user identity.",
                startedAtMs = nowMs(),
                completedAtMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val scenario = synchronized(dynamicStateLock) {
            portfolioScenarioDefinitionsByUser[userId]
                ?.lastOrNull { it.scenarioId == scenarioId }
        } ?: savePortfolioScenario(
            userId = userId,
            scenario = PortfolioScenarioDefinition(
                scenarioId = scenarioId.ifBlank { "scenario_${now}" },
                name = "Portfolio simulation scenario",
                summary = "Auto-created scenario because requested scenario was not found.",
                assumptions = PortfolioScenarioAssumptionSet(
                    horizonDays = PORTFOLIO_SIMULATION_HORIZON_DAYS,
                    bucketHours = PORTFOLIO_SIMULATION_BUCKET_HOURS
                ),
                modifications = emptyList(),
                simulationOnly = true,
                active = true,
                createdAtMs = now,
                updatedAtMs = now
            )
        )
        val baseline = deriveBaselinePortfolioSnapshot(userId = userId, now = now)
        val run = simulatePortfolioScenarioRun(
            scenario = scenario,
            baseline = baseline,
            now = now
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioSimulationRunsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.runId == run.runId }
                .plus(run)
                .sortedWith(
                    compareByDescending<PortfolioSimulationRunRecord> { it.startedAtMs }
                        .thenBy { it.runId }
                )
                .take(MAX_PORTFOLIO_SIMULATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return run
    }

    fun runPortfolioOptimization(
        userId: String,
        requestId: String
    ): PortfolioOptimizationResult {
        if (userId.isBlank()) {
            return PortfolioOptimizationResult(
                resultId = "portfolio_opt_missing_user",
                requestId = requestId,
                status = PortfolioOptimizationResultStatus.FAILED,
                summary = "Portfolio optimization failed: missing user identity.",
                startedAtMs = nowMs(),
                completedAtMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val request = synchronized(dynamicStateLock) {
            portfolioOptimizationRequestsByUser[userId]
                ?.lastOrNull { it.requestId == requestId }
        } ?: savePortfolioOptimizationRequest(
            userId = userId,
            request = PortfolioOptimizationRequest(
                requestId = requestId.ifBlank { "portfolio_opt_request_${now}" },
                name = "Portfolio optimization request",
                summary = "Auto-created request because requested optimization profile was not found.",
                objectiveProfile = defaultPortfolioOptimizationObjectiveProfile(),
                constraintProfile = defaultPortfolioOptimizationConstraintProfile(),
                scenarioSet = PortfolioOptimizationScenarioSet(),
                calibrationSnapshotId = activePortfolioOptimizationCalibrationSnapshot(userId, now).snapshotId,
                solverConfig = PortfolioOptimizationSolverConfig(),
                active = true,
                createdAtMs = now,
                updatedAtMs = now
            )
        )
        val resolvedObjectiveProfileSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, request.objectiveProfileSnapshotId)
        } ?: resolvePortfolioOptimizationObjectiveProfileSnapshot(
            userId = userId,
            binding = request.objectiveProfileBinding,
            now = now
        )
        val calibrationSnapshot = if (request.calibrationSnapshotId.isNotBlank()) {
            resolvePortfolioOptimizationCalibrationSnapshot(
                userId = userId,
                snapshotId = request.calibrationSnapshotId,
                now = now,
                binding = resolvedObjectiveProfileSnapshot.binding
            )
        } else {
            resolvePortfolioOptimizationCalibrationSnapshot(
                userId = userId,
                snapshotId = null,
                objectiveProfileSnapshot = resolvedObjectiveProfileSnapshot,
                now = now
            )
        }
        val baseline = deriveBaselinePortfolioSnapshot(userId = userId, now = now)
        val cases = getGovernanceCases(
            userId = userId,
            filter = GovernanceConsoleFilter(
                includeReviewed = true,
                limit = MAX_GOVERNANCE_QUERY_LIMIT
            )
        )
        val result = optimizePortfolioRequest(
            request = request,
            baseline = baseline,
            cases = cases,
            calibrationSnapshot = calibrationSnapshot,
            now = now
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationResultsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.resultId == result.resultId }
                .plus(result)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationResult> { it.startedAtMs }
                        .thenBy { it.resultId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return result
    }

    fun comparePortfolioSimulationRuns(
        userId: String,
        baselineRunId: String,
        candidateRunId: String
    ): PortfolioScenarioComparison? {
        if (userId.isBlank() || baselineRunId.isBlank() || candidateRunId.isBlank()) return null
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val runs = synchronized(dynamicStateLock) {
            portfolioSimulationRunsByUser[userId]?.toList().orEmpty()
        }
        val baseline = runs.firstOrNull { it.runId == baselineRunId } ?: return null
        val candidate = runs.firstOrNull { it.runId == candidateRunId } ?: return null

        val baselineDemand = baseline.approvalDemandForecast.sumOf { it.expectedDemand }
        val candidateDemand = candidate.approvalDemandForecast.sumOf { it.expectedDemand }
        val baselineBacklog = baseline.queuePressureForecast.lastOrNull()?.backlogGrowth ?: 0
        val candidateBacklog = candidate.queuePressureForecast.lastOrNull()?.backlogGrowth ?: 0
        val baselineBreachCount = baseline.breachSignals.size
        val candidateBreachCount = candidate.breachSignals.size
        val baselineCompletionDelay = baseline.programCompletionForecast.sumOf { it.delayBuckets }
        val candidateCompletionDelay = candidate.programCompletionForecast.sumOf { it.delayBuckets }
        val baselineScore = baselineBreachCount * 100 + baselineBacklog * 8 + baselineCompletionDelay * 10 + baselineDemand
        val candidateScore = candidateBreachCount * 100 + candidateBacklog * 8 + candidateCompletionDelay * 10 + candidateDemand
        val preferredRunId = when {
            candidateScore < baselineScore -> candidate.runId
            baselineScore < candidateScore -> baseline.runId
            else -> null
        }
        val reasonCodes = when (preferredRunId) {
            candidate.runId -> candidate.recommendationReasonCodes
            baseline.runId -> baseline.recommendationReasonCodes
            else -> (candidate.recommendationReasonCodes + baseline.recommendationReasonCodes).distinct()
        }
        val comparison = PortfolioScenarioComparison(
            comparisonId = "simulation_compare_${baselineRunId.take(12)}_${candidateRunId.take(12)}_${now}",
            baselineRunId = baselineRunId,
            candidateRunId = candidateRunId,
            preferredRunId = preferredRunId,
            approvalDemandDelta = candidateDemand - baselineDemand,
            backlogDelta = candidateBacklog - baselineBacklog,
            breachCountDelta = candidateBreachCount - baselineBreachCount,
            completionDelayDelta = candidateCompletionDelay - baselineCompletionDelay,
            reasonCodes = reasonCodes,
            summary = buildString {
                append("Comparison ")
                append(candidateRunId.take(12))
                append(" vs ")
                append(baselineRunId.take(12))
                append(": demand Δ ")
                append(candidateDemand - baselineDemand)
                append(", breach Δ ")
                append(candidateBreachCount - baselineBreachCount)
                append(", completion delay Δ ")
                append(candidateCompletionDelay - baselineCompletionDelay)
                when (preferredRunId) {
                    candidate.runId -> append(". Candidate run is preferred.")
                    baseline.runId -> append(". Baseline run remains preferred.")
                    else -> append(". Runs are equivalent under current deterministic score.")
                }
            },
            createdAtMs = now
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioScenarioComparisonsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.comparisonId == comparison.comparisonId }
                .plus(comparison)
                .sortedWith(
                    compareByDescending<PortfolioScenarioComparison> { it.createdAtMs }
                        .thenBy { it.comparisonId }
                )
                .take(MAX_PORTFOLIO_SIMULATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return comparison
    }

    fun exportPortfolioSimulationSummary(
        userId: String,
        runId: String
    ): String {
        if (userId.isBlank() || runId.isBlank()) {
            return "Portfolio simulation export is unavailable: missing run identity."
        }
        restoreDynamicStateIfNeeded(userId)
        val run = synchronized(dynamicStateLock) {
            portfolioSimulationRunsByUser[userId]?.lastOrNull { it.runId == runId }
        } ?: return "Portfolio simulation run $runId was not found."
        val scenario = synchronized(dynamicStateLock) {
            portfolioScenarioDefinitionsByUser[userId]?.lastOrNull { it.scenarioId == run.scenarioId }
        }
        val bucket = run.approvalDemandForecast.lastOrNull()
        val breaches = run.breachSignals.joinToString { signal ->
            signal.type.name.lowercase().replace('_', ' ')
        }.ifBlank { "none" }
        return buildString {
            appendLine("Portfolio Simulation Run")
            appendLine("Run: ${run.runId}")
            appendLine("Scenario: ${scenario?.name?.ifBlank { run.scenarioId } ?: run.scenarioId}")
            appendLine("Status: ${run.status.name.lowercase().replace('_', ' ')}")
            appendLine("Top recommendation: ${run.topRecommendation.ifBlank { "No recommendation." }}")
            appendLine("Breach signals: $breaches")
            bucket?.let {
                appendLine(
                    "Final forecast bucket: demand ${it.expectedDemand}, capacity ${it.expectedCapacity}, backlog ${it.expectedBacklog}."
                )
            }
            if (run.summary.isNotBlank()) {
                appendLine("Summary: ${run.summary}")
            }
            if (run.notes.isNotEmpty()) {
                appendLine("Notes: ${run.notes.joinToString(" | ")}")
            }
        }.trim()
    }

    fun selectPortfolioOptimizationSchedule(
        userId: String,
        resultId: String,
        candidateId: String,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationDecisionRecord {
        if (userId.isBlank() || resultId.isBlank() || candidateId.isBlank()) {
            return PortfolioOptimizationDecisionRecord(
                resultId = resultId,
                candidateId = candidateId,
                selectedByOperatorId = operatorId,
                selectedByOperatorName = operatorName,
                selectedAtMs = nowMs(),
                summary = "Portfolio optimization selection failed: missing identity or candidate."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val result = synchronized(dynamicStateLock) {
            portfolioOptimizationResultsByUser[userId]?.lastOrNull { it.resultId == resultId }
        } ?: return PortfolioOptimizationDecisionRecord(
            resultId = resultId,
            candidateId = candidateId,
            selectedByOperatorId = operatorId,
            selectedByOperatorName = operatorName,
            selectedAtMs = now,
            summary = "Portfolio optimization selection failed: result was not found."
        )
        val candidate = result.candidateSchedules.firstOrNull { it.candidateId == candidateId }
            ?: return PortfolioOptimizationDecisionRecord(
                requestId = result.requestId,
                resultId = resultId,
                candidateId = candidateId,
                selectedByOperatorId = operatorId,
                selectedByOperatorName = operatorName,
                selectedAtMs = now,
                summary = "Portfolio optimization selection failed: candidate was not found."
            )
        val decision = PortfolioOptimizationDecisionRecord(
            decisionId = "portfolio_opt_select_${resultId.take(10)}_${candidateId.take(10)}_${now}",
            requestId = result.requestId,
            resultId = resultId,
            candidateId = candidateId,
            calibrationSnapshotId = result.calibrationSnapshotId,
            objectiveProfileSnapshotId = result.objectiveProfileSnapshotId,
            objectiveProfileBinding = result.objectiveProfileBinding,
            objectiveProfileProvenance = result.objectiveProfileProvenance,
            objectiveProfile = result.objectiveProfile,
            constraintProfile = result.constraintProfile,
            selectedByOperatorId = operatorId,
            selectedByOperatorName = operatorName,
            selectedAtMs = now,
            summary = buildString {
                append("Selected candidate ")
                append(candidateId.takeLast(10))
                append(" from result ")
                append(resultId.takeLast(10))
                append(": ")
                append(candidate.summary.ifBlank { "schedule committed for future governance review" })
            }
        )
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationDecisionsByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue
                .toList()
                .filterNot { it.decisionId == decision.decisionId }
                .plus(decision)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationDecisionRecord> { it.selectedAtMs }
                        .thenBy { it.decisionId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
        persistDynamicState(userId)
        return decision
    }

    fun recordPortfolioOptimizationOutcome(
        userId: String,
        decisionId: String,
        observations: PortfolioOutcomeObservationSet
    ): PortfolioScheduleOutcomeRecord {
        if (userId.isBlank() || decisionId.isBlank()) {
            return PortfolioScheduleOutcomeRecord(
                decisionId = decisionId,
                observations = observations,
                summary = "Portfolio optimization outcome recording failed: missing identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val decision = synchronized(dynamicStateLock) {
            portfolioOptimizationDecisionsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.decisionId == decisionId }
        } ?: return PortfolioScheduleOutcomeRecord(
            decisionId = decisionId,
            observations = observations,
            summary = "Portfolio optimization outcome recording failed: decision was not found."
        )
        val result = synchronized(dynamicStateLock) {
            portfolioOptimizationResultsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.resultId == decision.resultId }
        } ?: return PortfolioScheduleOutcomeRecord(
            decisionId = decisionId,
            requestId = decision.requestId,
            resultId = decision.resultId,
            candidateId = decision.candidateId,
            calibrationSnapshotId = decision.calibrationSnapshotId,
            objectiveProfileSnapshotId = decision.objectiveProfileSnapshotId,
            objectiveProfileBinding = decision.objectiveProfileBinding,
            observations = observations,
            summary = "Portfolio optimization outcome recording failed: result was not found."
        )
        val candidate = result.candidateSchedules.firstOrNull { it.candidateId == decision.candidateId }
            ?: return PortfolioScheduleOutcomeRecord(
                decisionId = decisionId,
                requestId = decision.requestId,
                resultId = decision.resultId,
                candidateId = decision.candidateId,
                calibrationSnapshotId = decision.calibrationSnapshotId,
                objectiveProfileSnapshotId = decision.objectiveProfileSnapshotId,
                objectiveProfileBinding = decision.objectiveProfileBinding,
                observations = observations,
                summary = "Portfolio optimization outcome recording failed: candidate was not found."
            )
        val casesByRunId = getGovernanceCases(
            userId = userId,
            filter = GovernanceConsoleFilter(
                includeReviewed = true,
                limit = MAX_GOVERNANCE_QUERY_LIMIT
            )
        ).associateBy { it.summary.runId }
        val derivedObservations = derivePortfolioOptimizationOutcomeObservations(
            candidate = candidate,
            casesByRunId = casesByRunId,
            solverConfig = result.solverConfig,
            now = now
        )
        val mergedObservations = mergePortfolioOptimizationOutcomeObservations(
            derived = derivedObservations,
            manual = observations
        )
        val sourceRunIds = (candidate.scheduledActions.map { it.sourceRunId } +
            candidate.deferredActions.map { it.sourceRunId })
            .distinct()
        val outcome = PortfolioScheduleOutcomeRecord(
            outcomeId = "portfolio_opt_outcome_${decisionId.takeLast(10)}_$now",
            decisionId = decision.decisionId,
            requestId = decision.requestId,
            resultId = decision.resultId,
            candidateId = decision.candidateId,
            calibrationSnapshotId = decision.calibrationSnapshotId,
            objectiveProfileSnapshotId = decision.objectiveProfileSnapshotId,
            objectiveProfileBinding = decision.objectiveProfileBinding,
            scheduledSourceRunIds = sourceRunIds,
            predictedScheduledCount = candidate.scheduledActions.size,
            predictedDeferredCount = candidate.deferredActions.size,
            predictedOnTimeCount = candidate.scheduledActions.size,
            predictedWindowMissCount = candidate.deferredActions.count {
                it.blockedBy == PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY
            },
            predictedReadinessDelayCount = candidate.deferredActions.count {
                it.blockedBy == PortfolioOptimizationConstraintFamily.READINESS_GATE
            },
            predictedRiskIncidentCount = candidate.scheduledActions.count {
                it.riskBucket == PortfolioOptimizationRiskBucket.HIGH ||
                    it.riskBucket == PortfolioOptimizationRiskBucket.CRITICAL
            },
            predictedAverageApprovalLatencyHours = candidate.scheduledActions
                .filter { it.requiresApproval }
                .map { (it.scheduledBucketIndex + 1) * result.solverConfig.bucketHours.toDouble() }
                .average()
                .takeIf { !it.isNaN() }
                ?: 0.0,
            predictedBindingConstraints = candidate.bindingConstraints.map { it.family }.distinct(),
            observations = mergedObservations,
            evidenceRefs = sourceRunIds.map { runId ->
                PortfolioDriftEvidenceRef(
                    sourceRunId = runId,
                    relatedId = decision.decisionId,
                    summary = "Linked to governance run $runId for outcome review."
                )
            },
            summary = "Outcome recorded for candidate ${decision.candidateId.takeLast(10)}.",
            recordedAtMs = now
        )
        val driftSummary = computePortfolioOptimizationDriftSummary(
            outcome = outcome,
            now = now
        )
        val finalizedOutcome = outcome.copy(
            driftSummaryId = driftSummary.driftId,
            summary = "Outcome recorded for candidate ${decision.candidateId.takeLast(10)} with ${driftSummary.highestSeverity.name.lowercase()} drift."
        )
        storePortfolioOptimizationOutcome(userId, finalizedOutcome)
        storePortfolioOptimizationDriftSummary(userId, driftSummary)
        markPortfolioOptimizationPropagationReviewRequired(
            userId = userId,
            objectiveProfileSnapshotId = finalizedOutcome.objectiveProfileSnapshotId,
            severity = driftSummary.highestSeverity
        )
        maybeBuildPortfolioOptimizationTuningSuggestion(
            userId = userId,
            activeCalibrationSnapshot = resolvePortfolioOptimizationCalibrationSnapshot(
                userId = userId,
                snapshotId = decision.calibrationSnapshotId,
                now = now,
                binding = decision.objectiveProfileBinding
            ),
            outcome = finalizedOutcome,
            driftSummary = driftSummary,
            now = now
        )?.let { storePortfolioOptimizationTuningSuggestion(userId, it) }
        persistDynamicState(userId)
        return finalizedOutcome
    }

    fun applyPortfolioOptimizationTuning(
        userId: String,
        suggestionId: String,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationTuningDecisionRecord {
        if (userId.isBlank() || suggestionId.isBlank()) {
            return PortfolioOptimizationTuningDecisionRecord(
                suggestionId = suggestionId,
                operatorId = operatorId,
                operatorName = operatorName,
                status = PortfolioOptimizationTuningStatus.BLOCKED,
                summary = "Portfolio optimization tuning apply failed: missing identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val suggestion = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningSuggestionsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.suggestionId == suggestionId }
        } ?: return PortfolioOptimizationTuningDecisionRecord(
            suggestionId = suggestionId,
            operatorId = operatorId,
            operatorName = operatorName,
            status = PortfolioOptimizationTuningStatus.BLOCKED,
            summary = "Portfolio optimization tuning apply failed: suggestion was not found."
        )
        val blockedGuardrails = portfolioOptimizationApplyTuningGuardrailBlocks(
            userId = userId,
            suggestion = suggestion,
            now = now
        )
        if (blockedGuardrails.isNotEmpty()) {
            val blockedDecision = PortfolioOptimizationTuningDecisionRecord(
                tuningDecisionId = "portfolio_opt_tuning_block_${suggestionId.takeLast(10)}_$now",
                suggestionId = suggestion.suggestionId,
                decisionId = suggestion.decisionId,
                calibrationSnapshotId = suggestion.calibrationSnapshotId,
                objectiveProfileSnapshotId = suggestion.objectiveProfileSnapshotId,
                objectiveProfileBinding = suggestion.objectiveProfileBinding,
                status = PortfolioOptimizationTuningStatus.BLOCKED,
                operatorId = operatorId,
                operatorName = operatorName,
                blockedGuardrails = blockedGuardrails,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_BLOCKED_GUARDRAIL),
                summary = "Tuning suggestion ${suggestion.suggestionId.takeLast(10)} was blocked by guardrails.",
                decidedAtMs = now
            )
            storePortfolioOptimizationTuningSuggestion(
                userId,
                suggestion.copy(status = PortfolioOptimizationTuningStatus.BLOCKED)
            )
            storePortfolioOptimizationTuningDecision(userId, blockedDecision)
            persistDynamicState(userId)
            return blockedDecision
        }
        val currentSnapshot = resolvePortfolioOptimizationCalibrationSnapshot(
            userId = userId,
            snapshotId = suggestion.calibrationSnapshotId,
            now = now,
            binding = suggestion.objectiveProfileBinding
        )
        val currentObjectiveProfileSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, suggestion.objectiveProfileSnapshotId)
        } ?: resolvePortfolioOptimizationObjectiveProfileSnapshot(
            userId = userId,
            binding = suggestion.objectiveProfileBinding,
            now = now
        )
        val appliedObjectiveProfileSnapshot = buildPortfolioOptimizationTunedObjectiveProfileSnapshot(
            userId = userId,
            sourceSnapshot = currentObjectiveProfileSnapshot,
            suggestion = suggestion,
            operatorId = operatorId,
            operatorName = operatorName,
            now = now
        )
        val appliedSnapshot = applyPortfolioOptimizationSuggestionToSnapshot(
            snapshot = currentSnapshot.copy(
                objectiveProfileSnapshotId = appliedObjectiveProfileSnapshot.snapshotId,
                objectiveProfileBinding = appliedObjectiveProfileSnapshot.binding,
                objectiveProfileProvenance = appliedObjectiveProfileSnapshot.provenance
            ),
            suggestion = suggestion,
            now = now
        )
        val appliedDecision = PortfolioOptimizationTuningDecisionRecord(
            tuningDecisionId = "portfolio_opt_tuning_apply_${suggestionId.takeLast(10)}_$now",
            suggestionId = suggestion.suggestionId,
            decisionId = suggestion.decisionId,
            calibrationSnapshotId = suggestion.calibrationSnapshotId,
            objectiveProfileSnapshotId = appliedObjectiveProfileSnapshot.snapshotId,
            objectiveProfileBinding = appliedObjectiveProfileSnapshot.binding,
            appliedSnapshotId = appliedSnapshot.snapshotId,
            status = PortfolioOptimizationTuningStatus.APPLIED,
            operatorId = operatorId,
            operatorName = operatorName,
            reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_APPLIED),
            summary = "Applied tuning suggestion ${suggestion.suggestionId.takeLast(10)} into calibration snapshot v${appliedSnapshot.version}.",
            decidedAtMs = now
        )
        storePortfolioOptimizationObjectiveProfileSnapshot(userId, appliedObjectiveProfileSnapshot)
        storePortfolioOptimizationCalibrationSnapshot(userId, appliedSnapshot)
        storePortfolioOptimizationTuningSuggestion(
            userId,
            suggestion.copy(status = PortfolioOptimizationTuningStatus.APPLIED)
        )
        storePortfolioOptimizationTuningDecision(userId, appliedDecision)
        persistDynamicState(userId)
        return appliedDecision
    }

