    fun recordPortfolioOptimizationCorrectiveAction(
        userId: String,
        portfolioId: String,
        actionType: PortfolioOptimizationCorrectiveActionType,
        targetProgramId: String? = null,
        targetTrustTier: PortfolioOptimizationDestinationTrustTier? = null,
        targetJurisdiction: PortfolioOptimizationJurisdiction? = null,
        operatorId: String? = null,
        operatorName: String? = null,
        note: String = ""
    ): PortfolioOptimizationCrossBoundaryCorrectiveActionRecord {
        if (userId.isBlank() || portfolioId.isBlank()) {
            return PortfolioOptimizationCrossBoundaryCorrectiveActionRecord(
                portfolioId = portfolioId,
                actionType = actionType,
                targetProgramId = targetProgramId,
                targetTrustTier = targetTrustTier,
                targetJurisdiction = targetJurisdiction,
                actorId = operatorId,
                actorName = operatorName,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_ACTION_RECORDED),
                summary = "Portfolio corrective action failed: missing identity or portfolio.",
                recordedAtMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val analytics = synchronized(dynamicStateLock) {
            recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(userId, now)
            portfolioOptimizationCrossBoundaryPortfolioAnalyticsByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.portfolioId == portfolioId }
        }
        val recommendation = synchronized(dynamicStateLock) {
            portfolioOptimizationPortfolioRiskRecommendationsByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.portfolioId == portfolioId }
        }
        val record = PortfolioOptimizationCrossBoundaryCorrectiveActionRecord(
            actionRecordId = "portfolio_corrective_${portfolioId.takeLast(10)}_${actionType.name.lowercase()}_$now",
            portfolioId = portfolioId,
            actionType = actionType,
            targetProgramId = targetProgramId ?: recommendation?.targetProgramId,
            targetTrustTier = targetTrustTier ?: recommendation?.targetTrustTier,
            targetJurisdiction = targetJurisdiction ?: recommendation?.targetJurisdiction,
            analyticsId = analytics?.analyticsId,
            riskRecommendationId = recommendation?.recommendationId,
            actorId = operatorId,
            actorName = operatorName,
            reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_ACTION_RECORDED),
            summary = buildString {
                append("Recorded ")
                append(actionType.name.lowercase().replace('_', ' '))
                append(" for portfolio ")
                append(portfolioId.takeLast(10))
                if (note.isNotBlank()) {
                    append(" · ")
                    append(note.trim())
                }
            },
            recordedAtMs = now
        )
        storePortfolioOptimizationCrossBoundaryCorrectiveAction(userId, record)
        synchronized(dynamicStateLock) {
            recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(userId, now)
        }
        persistDynamicState(userId)
        return record
    }

    fun propagatePortfolioOptimizationObjectiveProfile(
        userId: String,
        sourceObjectiveProfileSnapshotId: String,
        targetScope: PortfolioOptimizationLearningScope,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationPropagationAttemptRecord {
        if (userId.isBlank() || sourceObjectiveProfileSnapshotId.isBlank()) {
            return PortfolioOptimizationPropagationAttemptRecord(
                sourceObjectiveProfileSnapshotId = sourceObjectiveProfileSnapshotId,
                targetScope = targetScope,
                requestedByOperatorId = operatorId,
                requestedByOperatorName = operatorName,
                status = PortfolioOptimizationPropagationEligibilityStatus.BLOCKED,
                blockReason = PortfolioOptimizationPropagationBlockReason.MISSING_SCOPE_CONTEXT,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED),
                summary = "Objective profile propagation failed: missing identity or source snapshot."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val sourceSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, sourceObjectiveProfileSnapshotId)
        } ?: return PortfolioOptimizationPropagationAttemptRecord(
            sourceObjectiveProfileSnapshotId = sourceObjectiveProfileSnapshotId,
            targetScope = targetScope,
            requestedByOperatorId = operatorId,
            requestedByOperatorName = operatorName,
            status = PortfolioOptimizationPropagationEligibilityStatus.BLOCKED,
            blockReason = PortfolioOptimizationPropagationBlockReason.MISSING_SCOPE_CONTEXT,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED),
            summary = "Objective profile propagation failed: source snapshot was not found."
        )
        val targetBinding = resolvePortfolioOptimizationScopeBinding(
            userId = userId,
            requested = portfolioOptimizationBindingForScope(
                userId = userId,
                scope = targetScope,
                tenantId = sourceSnapshot.binding.tenantId,
                workspaceId = sourceSnapshot.binding.workspaceId
            )
        )
        val rule = portfolioOptimizationPropagationRuleFor(sourceSnapshot.binding.scope, targetScope)
        val isolationDecision = evaluatePortfolioOptimizationIsolationDecision(
            sourceBinding = sourceSnapshot.binding,
            targetBinding = targetBinding,
            policy = sourceSnapshot.isolationPolicy,
            rule = rule
        )
        val sourceCalibrationSnapshot = synchronized(dynamicStateLock) {
            portfolioOptimizationCalibrationSnapshotsByUser[userId]?.toList().orEmpty()
                .filter { it.objectiveProfileSnapshotId == sourceSnapshot.snapshotId }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationCalibrationSnapshot> { it.createdAtMs }
                        .thenBy { it.snapshotId }
                )
        }
        val targetBaseSnapshot = synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationTargetBaseSnapshotLocked(userId, targetBinding, now)
        }
        val patch = buildPortfolioOptimizationPropagationPatch(
            sourceSnapshot = sourceSnapshot,
            sourceCalibrationSnapshot = sourceCalibrationSnapshot,
            targetBinding = targetBinding,
            targetBaseSnapshot = targetBaseSnapshot,
            now = now
        )
        val latestDrift = latestPortfolioOptimizationDriftForObjectiveProfileLineage(userId, sourceSnapshot.snapshotId)
        val suppressedByDrift = rule?.reviewRequiredOnHighDrift == true &&
            (latestDrift?.highestSeverity == PortfolioDriftSeverity.HIGH ||
                latestDrift?.highestSeverity == PortfolioDriftSeverity.CRITICAL)
        val status = when {
            !isolationDecision.allowed ->
                PortfolioOptimizationPropagationEligibilityStatus.BLOCKED
            portfolioOptimizationLearningPatchIsNoOp(patch) ->
                PortfolioOptimizationPropagationEligibilityStatus.BLOCKED
            suppressedByDrift ->
                PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED
            rule?.approvalRequirement == PortfolioOptimizationPropagationApprovalRequirement.REQUIRED ->
                PortfolioOptimizationPropagationEligibilityStatus.PENDING_APPROVAL
            else -> PortfolioOptimizationPropagationEligibilityStatus.ADOPTED
        }
        val blockReason = when {
            !isolationDecision.allowed -> isolationDecision.blockReason
            portfolioOptimizationLearningPatchIsNoOp(patch) ->
                PortfolioOptimizationPropagationBlockReason.DUPLICATE_TARGET_PROFILE
            suppressedByDrift ->
                PortfolioOptimizationPropagationBlockReason.DRIFT_SUPPRESSED
            rule?.approvalRequirement == PortfolioOptimizationPropagationApprovalRequirement.REQUIRED ->
                PortfolioOptimizationPropagationBlockReason.APPROVAL_REQUIRED
            else -> PortfolioOptimizationPropagationBlockReason.NONE
        }
        val attempt = PortfolioOptimizationPropagationAttemptRecord(
            attemptId = "portfolio_opt_propagation_${sourceSnapshot.snapshotId.takeLast(8)}_${targetScope.name.lowercase()}_$now",
            patch = patch,
            rule = rule ?: PortfolioOptimizationPropagationRule(
                sourceScope = sourceSnapshot.binding.scope,
                targetScope = targetScope,
                enabled = false
            ),
            sourceObjectiveProfileSnapshotId = sourceSnapshot.snapshotId,
            targetScope = targetScope,
            approvalRequirement = rule?.approvalRequirement
                ?: PortfolioOptimizationPropagationApprovalRequirement.NOT_REQUIRED,
            status = status,
            blockReason = blockReason,
            isolationDecision = isolationDecision,
            requestedByOperatorId = operatorId,
            requestedByOperatorName = operatorName,
            suppressedByDrift = suppressedByDrift,
            reviewRequired = suppressedByDrift,
            reasonCodes = buildList {
                addAll(isolationDecision.reasonCodes)
                when (status) {
                    PortfolioOptimizationPropagationEligibilityStatus.ADOPTED ->
                        add(RoleReasonCodes.ROLE_LEARNING_PATCH_ADOPTED)
                    PortfolioOptimizationPropagationEligibilityStatus.PENDING_APPROVAL ->
                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_APPROVAL_REQUIRED)
                    PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED,
                    PortfolioOptimizationPropagationEligibilityStatus.REVIEW_REQUIRED ->
                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_SUPPRESSED_BY_DRIFT)
                    PortfolioOptimizationPropagationEligibilityStatus.BLOCKED ->
                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED)
                    else ->
                        add(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_ELIGIBLE)
                }
            }.distinct(),
            summary = when (status) {
                PortfolioOptimizationPropagationEligibilityStatus.ADOPTED ->
                    "Objective profile propagation adopted into ${portfolioOptimizationScopeLabel(targetScope)} scope."
                PortfolioOptimizationPropagationEligibilityStatus.PENDING_APPROVAL ->
                    "Objective profile propagation is pending approval for ${portfolioOptimizationScopeLabel(targetScope)} scope."
                PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED ->
                    "Objective profile propagation is suppressed until ${latestDrift?.highestSeverity?.name?.lowercase() ?: "high"} drift is reviewed."
                PortfolioOptimizationPropagationEligibilityStatus.BLOCKED ->
                    "Objective profile propagation was blocked by ${blockReason.name.lowercase().replace('_', ' ')}."
                else ->
                    "Objective profile propagation is ready for review."
            },
            createdAtMs = now
        )
        storePortfolioOptimizationPropagationAttempt(userId, attempt)
        if (status == PortfolioOptimizationPropagationEligibilityStatus.ADOPTED) {
            val provenance = PortfolioOptimizationLearningProvenanceSummary(
                type = PortfolioOptimizationObjectiveProfileProvenanceType.ADOPTED,
                sourceScope = sourceSnapshot.binding.scope,
                sourceSnapshotId = sourceSnapshot.snapshotId,
                sourceAttemptId = attempt.attemptId,
                operatorId = operatorId,
                operatorName = operatorName,
                summary = "Propagation adopted from ${portfolioOptimizationScopeLabel(sourceSnapshot.binding.scope)} into ${portfolioOptimizationScopeLabel(targetScope)} scope."
            )
            val targetSnapshot = applyPortfolioOptimizationLearningPatchToSnapshot(
                baseSnapshot = targetBaseSnapshot,
                patch = patch,
                provenance = provenance,
                now = now
            )
            storePortfolioOptimizationObjectiveProfileSnapshot(userId, targetSnapshot)
            storePortfolioOptimizationPropagationAdoption(
                userId,
                PortfolioOptimizationPropagationAdoptionRecord(
                    adoptionId = "portfolio_opt_adoption_${attempt.attemptId.takeLast(8)}_$now",
                    attemptId = attempt.attemptId,
                    sourceObjectiveProfileSnapshotId = sourceSnapshot.snapshotId,
                    targetObjectiveProfileSnapshotId = targetSnapshot.snapshotId,
                    targetBinding = targetBinding,
                    status = PortfolioOptimizationPropagationEligibilityStatus.ADOPTED,
                    provenance = provenance,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PATCH_ADOPTED),
                    summary = "Objective profile adopted into ${portfolioOptimizationScopeLabel(targetScope)} scope.",
                    adoptedAtMs = now
                )
            )
        }
        persistDynamicState(userId)
        return attempt
    }

    fun approvePortfolioOptimizationPropagation(
        userId: String,
        attemptId: String,
        approverId: String? = null,
        approverName: String? = null
    ): PortfolioOptimizationPropagationAdoptionRecord {
        if (userId.isBlank() || attemptId.isBlank()) {
            return PortfolioOptimizationPropagationAdoptionRecord(
                attemptId = attemptId,
                status = PortfolioOptimizationPropagationEligibilityStatus.BLOCKED,
                summary = "Propagation approval failed: missing identity or attempt."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val attempt = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAttemptsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.attemptId == attemptId }
        } ?: return PortfolioOptimizationPropagationAdoptionRecord(
            attemptId = attemptId,
            status = PortfolioOptimizationPropagationEligibilityStatus.BLOCKED,
            summary = "Propagation approval failed: attempt was not found."
        )
        if (attempt.status != PortfolioOptimizationPropagationEligibilityStatus.PENDING_APPROVAL) {
            return synchronized(dynamicStateLock) {
                portfolioOptimizationPropagationAdoptionsByUser[userId]?.toList().orEmpty()
                    .firstOrNull { it.attemptId == attemptId }
            } ?: PortfolioOptimizationPropagationAdoptionRecord(
                attemptId = attemptId,
                status = attempt.status,
                summary = "Propagation attempt is not awaiting approval."
            )
        }
        val sourceSnapshot = synchronized(dynamicStateLock) {
            findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, attempt.sourceObjectiveProfileSnapshotId)
        } ?: return PortfolioOptimizationPropagationAdoptionRecord(
            attemptId = attemptId,
            status = PortfolioOptimizationPropagationEligibilityStatus.BLOCKED,
            summary = "Propagation approval failed: source snapshot was not found."
        )
        val approval = PortfolioOptimizationPropagationApprovalRecord(
            approvalId = "portfolio_opt_approval_${attemptId.takeLast(8)}_$now",
            attemptId = attemptId,
            approved = true,
            approverId = approverId,
            approverName = approverName,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_APPROVED),
            summary = "Propagation approved for ${portfolioOptimizationScopeLabel(attempt.targetScope)} scope.",
            decidedAtMs = now
        )
        val targetBaseSnapshot = synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationTargetBaseSnapshotLocked(userId, attempt.patch.targetBinding, now)
        }
        val provenance = PortfolioOptimizationLearningProvenanceSummary(
            type = PortfolioOptimizationObjectiveProfileProvenanceType.ADOPTED,
            sourceScope = sourceSnapshot.binding.scope,
            sourceSnapshotId = sourceSnapshot.snapshotId,
            sourceAttemptId = attempt.attemptId,
            operatorId = approverId,
            operatorName = approverName,
            summary = "Propagation approved into ${portfolioOptimizationScopeLabel(attempt.targetScope)} scope."
        )
        val targetSnapshot = applyPortfolioOptimizationLearningPatchToSnapshot(
            baseSnapshot = targetBaseSnapshot,
            patch = attempt.patch,
            provenance = provenance,
            now = now
        )
        val adoption = PortfolioOptimizationPropagationAdoptionRecord(
            adoptionId = "portfolio_opt_adoption_${attemptId.takeLast(8)}_$now",
            attemptId = attemptId,
            sourceObjectiveProfileSnapshotId = sourceSnapshot.snapshotId,
            targetObjectiveProfileSnapshotId = targetSnapshot.snapshotId,
            targetBinding = attempt.patch.targetBinding,
            approvalRecordId = approval.approvalId,
            status = PortfolioOptimizationPropagationEligibilityStatus.ADOPTED,
            provenance = provenance,
            reasonCodes = listOf(
                RoleReasonCodes.ROLE_LEARNING_PROPAGATION_APPROVED,
                RoleReasonCodes.ROLE_LEARNING_PATCH_ADOPTED
            ),
            summary = "Propagation approved and adopted into ${portfolioOptimizationScopeLabel(attempt.targetScope)} scope.",
            adoptedAtMs = now
        )
        storePortfolioOptimizationPropagationApproval(userId, approval)
        storePortfolioOptimizationPropagationAttempt(
            userId,
            attempt.copy(
                status = PortfolioOptimizationPropagationEligibilityStatus.ADOPTED,
                blockReason = PortfolioOptimizationPropagationBlockReason.NONE,
                reasonCodes = (attempt.reasonCodes + RoleReasonCodes.ROLE_LEARNING_PROPAGATION_APPROVED + RoleReasonCodes.ROLE_LEARNING_PATCH_ADOPTED).distinct(),
                summary = adoption.summary
            )
        )
        storePortfolioOptimizationObjectiveProfileSnapshot(userId, targetSnapshot)
        storePortfolioOptimizationPropagationAdoption(userId, adoption)
        persistDynamicState(userId)
        return adoption
    }

    fun rejectPortfolioOptimizationPropagation(
        userId: String,
        attemptId: String,
        approverId: String? = null,
        approverName: String? = null,
        reason: String = ""
    ): PortfolioOptimizationPropagationApprovalRecord {
        if (userId.isBlank() || attemptId.isBlank()) {
            return PortfolioOptimizationPropagationApprovalRecord(
                attemptId = attemptId,
                approved = false,
                approverId = approverId,
                approverName = approverName,
                reason = reason,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_REJECTED),
                summary = "Propagation rejection failed: missing identity or attempt."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val attempt = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAttemptsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.attemptId == attemptId }
        } ?: return PortfolioOptimizationPropagationApprovalRecord(
            attemptId = attemptId,
            approved = false,
            approverId = approverId,
            approverName = approverName,
            reason = reason,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_REJECTED),
            summary = "Propagation rejection failed: attempt was not found."
        )
        val approval = PortfolioOptimizationPropagationApprovalRecord(
            approvalId = "portfolio_opt_rejection_${attemptId.takeLast(8)}_$now",
            attemptId = attemptId,
            approved = false,
            approverId = approverId,
            approverName = approverName,
            reason = reason,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_REJECTED),
            summary = "Propagation rejected for ${portfolioOptimizationScopeLabel(attempt.targetScope)} scope.",
            decidedAtMs = now
        )
        storePortfolioOptimizationPropagationApproval(userId, approval)
        storePortfolioOptimizationPropagationAttempt(
            userId,
            attempt.copy(
                status = PortfolioOptimizationPropagationEligibilityStatus.REJECTED,
                reasonCodes = (attempt.reasonCodes + RoleReasonCodes.ROLE_LEARNING_PROPAGATION_REJECTED).distinct(),
                summary = approval.summary
            )
        )
        persistDynamicState(userId)
        return approval
    }

    fun recordPortfolioOptimizationConsent(
        userId: String,
        consent: PortfolioOptimizationConsentRecord
    ): PortfolioOptimizationConsentRecord {
        if (userId.isBlank()) {
            return consent.copy(
                decision = PortfolioOptimizationConsentDecision.DENIED,
                reasonCodes = (consent.reasonCodes + RoleReasonCodes.ROLE_CONSENT_DENIED).distinct(),
                summary = "Portfolio learning consent was denied because user identity is missing."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val normalized = synchronized(dynamicStateLock) {
            normalizePortfolioOptimizationConsentRecordLocked(userId, consent, now)
        }
        storePortfolioOptimizationConsentRecord(userId, normalized)
        persistDynamicState(userId)
        return normalized
    }

    fun revokePortfolioOptimizationConsent(
        userId: String,
        consentId: String,
        operatorId: String? = null,
        operatorName: String? = null,
        reason: String = ""
    ): PortfolioOptimizationConsentRecord {
        if (userId.isBlank() || consentId.isBlank()) {
            return PortfolioOptimizationConsentRecord(
                consentId = consentId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                decision = PortfolioOptimizationConsentDecision.DENIED,
                provenance = PortfolioOptimizationConsentProvenance(
                    grantedById = operatorId,
                    grantedByName = operatorName
                ),
                reasonCodes = listOf(RoleReasonCodes.ROLE_CONSENT_DENIED),
                summary = "Portfolio learning consent revoke failed: missing identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val existing = synchronized(dynamicStateLock) {
            portfolioOptimizationConsentRecordsByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.consentId == consentId }
        } ?: return PortfolioOptimizationConsentRecord(
            consentId = consentId,
            purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
            decision = PortfolioOptimizationConsentDecision.DENIED,
            provenance = PortfolioOptimizationConsentProvenance(
                grantedById = operatorId,
                grantedByName = operatorName
            ),
            reasonCodes = listOf(RoleReasonCodes.ROLE_CONSENT_DENIED),
            summary = "Portfolio learning consent revoke failed: consent was not found."
        )
        val revoked = existing.copy(
            decision = PortfolioOptimizationConsentDecision.REVOKED,
            provenance = existing.provenance.copy(
                grantedById = operatorId ?: existing.provenance.grantedById,
                grantedByName = operatorName ?: existing.provenance.grantedByName
            ),
            revokedAtMs = now,
            reasonCodes = (existing.reasonCodes + RoleReasonCodes.ROLE_CONSENT_REVOKED).distinct(),
            summary = if (reason.isNotBlank()) {
                reason
            } else {
                "Consent for ${existing.purpose.name.lowercase().replace('_', ' ')} was revoked."
            },
            recordedAtMs = now
        )
        storePortfolioOptimizationConsentRecord(userId, revoked)
        persistDynamicState(userId)
        return revoked
    }

    private fun portfolioOptimizationResidencyRegionFor(
        vararg hints: String?
    ): PortfolioOptimizationResidencyRegion {
        val normalized = hints
            .mapNotNull { it?.lowercase(Locale.getDefault()) }
            .joinToString(" ")
        return when {
            normalized.contains(" uk ") ||
                normalized.startsWith("uk") ||
                normalized.contains("london") ||
                normalized.contains("england") ->
                PortfolioOptimizationResidencyRegion.UK
            normalized.contains(" eu ") ||
                normalized.startsWith("eu") ||
                normalized.contains("frankfurt") ||
                normalized.contains("amsterdam") ||
                normalized.contains("ireland") ||
                normalized.contains("germany") ->
                PortfolioOptimizationResidencyRegion.EU
            normalized.contains(" us ") ||
                normalized.startsWith("us") ||
                normalized.contains("virginia") ||
                normalized.contains("oregon") ||
                normalized.contains("ohio") ->
                PortfolioOptimizationResidencyRegion.US
            normalized.contains("apac") ||
                normalized.contains("singapore") ||
                normalized.contains("tokyo") ||
                normalized.contains("sydney") ->
                PortfolioOptimizationResidencyRegion.APAC
            normalized.contains("global") || normalized.contains("multi-region") ->
                PortfolioOptimizationResidencyRegion.GLOBAL
            else -> PortfolioOptimizationResidencyRegion.TENANT_HOME
        }
    }

    private fun portfolioOptimizationJurisdictionFor(
        region: PortfolioOptimizationResidencyRegion,
        vararg hints: String?
    ): PortfolioOptimizationJurisdiction {
        val normalized = hints
            .mapNotNull { it?.lowercase(Locale.getDefault()) }
            .joinToString(" ")
        return when {
            normalized.contains("gdpr") && region == PortfolioOptimizationResidencyRegion.UK ->
                PortfolioOptimizationJurisdiction.UK_GDPR
            normalized.contains("gdpr") && region == PortfolioOptimizationResidencyRegion.EU ->
                PortfolioOptimizationJurisdiction.EU_GDPR
            normalized.contains("privacy") && region == PortfolioOptimizationResidencyRegion.US ->
                PortfolioOptimizationJurisdiction.US_PRIVACY
            normalized.contains("apac") || region == PortfolioOptimizationResidencyRegion.APAC ->
                PortfolioOptimizationJurisdiction.APAC_ENTERPRISE
            normalized.contains("global") || region == PortfolioOptimizationResidencyRegion.GLOBAL ->
                PortfolioOptimizationJurisdiction.GLOBAL_RESTRICTED
            PortfolioOptimizationResidencyRegion.UK == region ->
                PortfolioOptimizationJurisdiction.UK_GDPR
            PortfolioOptimizationResidencyRegion.EU == region ->
                PortfolioOptimizationJurisdiction.EU_GDPR
            PortfolioOptimizationResidencyRegion.US == region ->
                PortfolioOptimizationJurisdiction.US_PRIVACY
            else -> PortfolioOptimizationJurisdiction.TENANT_POLICY_ZONE
        }
    }

    private fun portfolioOptimizationIsLocalDestination(
        type: PortfolioOptimizationRemoteDestinationType?
    ): Boolean {
        return type == PortfolioOptimizationRemoteDestinationType.LOCAL_DEVICE ||
            type == PortfolioOptimizationRemoteDestinationType.LOCAL_COMPLIANCE_ARCHIVE
    }

    private fun derivePortfolioOptimizationResidencyBoundary(
        binding: PortfolioOptimizationObjectiveProfileBinding,
        connectorProfile: PortfolioOptimizationRemoteTransportConnectorProfile? = null
    ): PortfolioOptimizationResidencyBoundary {
        val region = portfolioOptimizationResidencyRegionFor(
            binding.tenantId,
            binding.workspaceId,
            connectorProfile?.endpointRef,
            connectorProfile?.displayName
        )
        val jurisdiction = portfolioOptimizationJurisdictionFor(
            region = region,
            binding.tenantId,
            binding.workspaceId,
            connectorProfile?.endpointRef
        )
        return PortfolioOptimizationResidencyBoundary(
            boundaryId = "portfolio_residency_${binding.tenantId ?: "tenant"}_${binding.workspaceId ?: "workspace"}",
            tenantId = binding.tenantId,
            workspaceId = binding.workspaceId,
            region = region,
            jurisdiction = jurisdiction,
            sameTenantOnly = true,
            summary = "Residency boundary requires ${region.name.lowercase().replace('_', ' ')} / ${jurisdiction.name.lowercase().replace('_', ' ')} handling."
        )
    }

    private fun derivePortfolioOptimizationDataResidencyPolicy(
        binding: PortfolioOptimizationObjectiveProfileBinding,
        purpose: PortfolioOptimizationConsentPurpose,
        preferredDestinationType: PortfolioOptimizationRemoteDestinationType? = null,
        connectorProfile: PortfolioOptimizationRemoteTransportConnectorProfile? = null
    ): PortfolioOptimizationDataResidencyPolicy {
        val boundary = derivePortfolioOptimizationResidencyBoundary(binding, connectorProfile)
        val allowLocalFallback = purpose != PortfolioOptimizationConsentPurpose.AUDIT_EXPORT ||
            preferredDestinationType != PortfolioOptimizationRemoteDestinationType.REMOTE_COMPLIANCE_ARCHIVE
        return PortfolioOptimizationDataResidencyPolicy(
            policyId = "portfolio_residency_policy_${purpose.name.lowercase()}_${binding.tenantId ?: "tenant"}",
            residencyBoundary = boundary,
            allowedRegions = listOf(boundary.region, PortfolioOptimizationResidencyRegion.TENANT_HOME).distinct(),
            allowedJurisdictions = listOf(
                boundary.jurisdiction,
                PortfolioOptimizationJurisdiction.TENANT_POLICY_ZONE
            ).distinct(),
            strictResidency = true,
            strictJurisdiction = purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
            localFallbackAllowed = allowLocalFallback,
            holdForReviewOnMismatch = purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT &&
                preferredDestinationType == PortfolioOptimizationRemoteDestinationType.REMOTE_COMPLIANCE_ARCHIVE,
            summary = "Residency policy keeps ${boundary.region.name.lowercase().replace('_', ' ')} artifacts inside ${boundary.jurisdiction.name.lowercase().replace('_', ' ')} boundaries."
        )
    }

    private fun derivePortfolioOptimizationRemoteDestinationProfiles(
        purpose: PortfolioOptimizationConsentPurpose,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        connectorProfile: PortfolioOptimizationRemoteTransportConnectorProfile,
        residencyPolicy: PortfolioOptimizationDataResidencyPolicy,
        now: Long
    ): List<PortfolioOptimizationRemoteDestinationProfile> {
        val remoteCapable = connectorProfile.type !in setOf(
            PortfolioOptimizationRemoteTransportConnectorType.NO_OP,
            PortfolioOptimizationRemoteTransportConnectorType.LOCAL_DURABLE
        )
        val localType = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
            PortfolioOptimizationRemoteDestinationType.LOCAL_COMPLIANCE_ARCHIVE
        } else {
            PortfolioOptimizationRemoteDestinationType.LOCAL_DEVICE
        }
        val remoteType = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
            PortfolioOptimizationRemoteDestinationType.REMOTE_COMPLIANCE_ARCHIVE
        } else {
            PortfolioOptimizationRemoteDestinationType.REMOTE_LEARNING_CONNECTOR
        }
        val localProfile = PortfolioOptimizationRemoteDestinationProfile(
            destinationId = "portfolio_destination_local_${purpose.name.lowercase()}_${binding.tenantId ?: "tenant"}",
            type = localType,
            displayName = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                "Local compliance archive"
            } else {
                "Local-first learning store"
            },
            residencyRegion = residencyPolicy.residencyBoundary.region,
            jurisdiction = residencyPolicy.residencyBoundary.jurisdiction,
            destinationPolicy = PortfolioOptimizationRemoteDestinationPolicy(
                policyId = "portfolio_destination_policy_local_${purpose.name.lowercase()}",
                allowedPurposes = listOf(purpose),
                sameTenantOnly = true,
                requiresResidencyMatch = false,
                requiresJurisdictionMatch = false,
                localOnly = true,
                localFallbackAllowed = true,
                summary = "Local destination preserves local-first authority."
            ),
            priority = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) 0 else 1,
            summary = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                "Local compliance archive retains redaction-first export bundles in-device."
            } else {
                "Local-first learning store preserves artifact history on-device."
            },
            updatedAtMs = now
        )
        val remoteRegion = portfolioOptimizationResidencyRegionFor(
            connectorProfile.endpointRef,
            connectorProfile.displayName,
            connectorProfile.profileId
        )
        val remoteJurisdiction = portfolioOptimizationJurisdictionFor(
            region = remoteRegion,
            connectorProfile.endpointRef,
            connectorProfile.displayName
        )
        val remoteProfile = PortfolioOptimizationRemoteDestinationProfile(
            destinationId = "portfolio_destination_remote_${connectorProfile.profileId}_${purpose.name.lowercase()}",
            type = remoteType,
            displayName = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                "Remote compliance archive"
            } else {
                connectorProfile.displayName.ifBlank { "Remote learning connector" }
            },
            connectorProfileId = connectorProfile.profileId,
            residencyRegion = remoteRegion,
            jurisdiction = remoteJurisdiction,
            destinationPolicy = PortfolioOptimizationRemoteDestinationPolicy(
                policyId = "portfolio_destination_policy_remote_${connectorProfile.profileId}_${purpose.name.lowercase()}",
                allowedPurposes = listOf(purpose),
                sameTenantOnly = true,
                requiresHealthyConnector = true,
                requiresHealthyKey = true,
                requiresResidencyMatch = true,
                requiresJurisdictionMatch = purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                localOnly = false,
                localFallbackAllowed = true,
                holdForReviewOnPolicyMismatch = purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                summary = "Remote destination stays purpose-limited, same-tenant, and residency-aware."
            ),
            active = remoteCapable,
            priority = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) 1 else 0,
            summary = if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                "Remote compliance archive is available when residency and jurisdiction checks pass."
            } else {
                "Remote learning connector is available when consent, connector, key, and residency checks pass."
            },
            updatedAtMs = now
        )
        return buildList {
            add(localProfile)
            add(remoteProfile)
        }.sortedWith(
            compareBy<PortfolioOptimizationRemoteDestinationProfile> { it.priority }
                .thenBy { it.destinationId }
        )
    }

    private fun evaluatePortfolioOptimizationRemoteDestinationRoute(
        purpose: PortfolioOptimizationConsentPurpose,
        sourceId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        connectorProfile: PortfolioOptimizationRemoteTransportConnectorProfile,
        privacyPolicy: PortfolioOptimizationLearningSyncPrivacyPolicy?,
        enterprisePrivacy: PortfolioOptimizationEnterprisePrivacyPolicySummary,
        consentRecord: PortfolioOptimizationConsentRecord?,
        enterpriseKeyReference: PortfolioOptimizationEnterpriseKeyReference?,
        credentialResolution: PortfolioOptimizationTransportCredentialResolutionResult,
        preferredDestinationId: String? = null,
        preferredDestinationType: PortfolioOptimizationRemoteDestinationType? = null,
        now: Long
    ): PortfolioOptimizationRemoteDestinationRouteSelection {
        val residencyPolicy = derivePortfolioOptimizationDataResidencyPolicy(
            binding = binding,
            purpose = purpose,
            preferredDestinationType = preferredDestinationType,
            connectorProfile = connectorProfile
        )
        val profiles = derivePortfolioOptimizationRemoteDestinationProfiles(
            purpose = purpose,
            binding = binding,
            connectorProfile = connectorProfile,
            residencyPolicy = residencyPolicy,
            now = now
        )
        val suppressedDecision = when {
            consentRecord?.decision != PortfolioOptimizationConsentDecision.ALLOWED ->
                PortfolioOptimizationRemoteDestinationDecisionRecord(
                    decisionId = "portfolio_destination_decision_${sourceId.takeLast(8)}_$now",
                    purpose = purpose,
                    sourceId = sourceId,
                    status = PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
                    preferredDestinationId = preferredDestinationId,
                    selectedDestinationId = null,
                    selectedDestinationType = null,
                    residencyPolicy = residencyPolicy,
                    residencyRegion = residencyPolicy.residencyBoundary.region,
                    jurisdiction = residencyPolicy.residencyBoundary.jurisdiction,
                    blockReason = PortfolioOptimizationRemoteDestinationBlockReason.CONSENT_DENIED,
                    eligibility = emptyList(),
                    reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_SUPPRESSED),
                    summary = consentRecord?.summary?.takeIf { it.isNotBlank() }
                        ?: "Destination routing was suppressed because consent is not allowed.",
                    createdAtMs = now
                )
            purpose == PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT &&
                !enterprisePrivacy.remoteTransportAllowedByRolePolicy ->
                PortfolioOptimizationRemoteDestinationDecisionRecord(
                    decisionId = "portfolio_destination_decision_${sourceId.takeLast(8)}_$now",
                    purpose = purpose,
                    sourceId = sourceId,
                    status = PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
                    preferredDestinationId = preferredDestinationId,
                    residencyPolicy = residencyPolicy,
                    residencyRegion = residencyPolicy.residencyBoundary.region,
                    jurisdiction = residencyPolicy.residencyBoundary.jurisdiction,
                    blockReason = PortfolioOptimizationRemoteDestinationBlockReason.ROLE_POLICY_BLOCKED,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_SUPPRESSED),
                    summary = enterprisePrivacy.summary.ifBlank {
                        "Destination routing was suppressed because role policy denied remote transport."
                    },
                    createdAtMs = now
                )
            purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT &&
                !enterprisePrivacy.auditExportAllowedByRolePolicy ->
                PortfolioOptimizationRemoteDestinationDecisionRecord(
                    decisionId = "portfolio_destination_decision_${sourceId.takeLast(8)}_$now",
                    purpose = purpose,
                    sourceId = sourceId,
                    status = PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
                    preferredDestinationId = preferredDestinationId,
                    residencyPolicy = residencyPolicy,
                    residencyRegion = residencyPolicy.residencyBoundary.region,
                    jurisdiction = residencyPolicy.residencyBoundary.jurisdiction,
                    blockReason = PortfolioOptimizationRemoteDestinationBlockReason.ROLE_POLICY_BLOCKED,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_SUPPRESSED),
                    summary = enterprisePrivacy.summary.ifBlank {
                        "Destination routing was suppressed because role policy denied audit export."
                    },
                    createdAtMs = now
                )
            privacyPolicy != null &&
                !privacyPolicy.cloudSyncAllowed &&
                purpose == PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT ->
                PortfolioOptimizationRemoteDestinationDecisionRecord(
                    decisionId = "portfolio_destination_decision_${sourceId.takeLast(8)}_$now",
                    purpose = purpose,
                    sourceId = sourceId,
                    status = PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
                    preferredDestinationId = preferredDestinationId,
                    residencyPolicy = residencyPolicy,
                    residencyRegion = residencyPolicy.residencyBoundary.region,
                    jurisdiction = residencyPolicy.residencyBoundary.jurisdiction,
                    blockReason = PortfolioOptimizationRemoteDestinationBlockReason.PRIVACY_POLICY_BLOCKED,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_SUPPRESSED),
                    summary = privacyPolicy.summary.ifBlank {
                        "Destination routing was suppressed because privacy policy denied remote delivery."
                    },
                    createdAtMs = now
                )
            else -> null
        }
        if (suppressedDecision != null) {
            return PortfolioOptimizationRemoteDestinationRouteSelection(
                destinationProfiles = profiles,
                decision = suppressedDecision
            )
        }

        val preferredProfile = profiles.firstOrNull { it.destinationId == preferredDestinationId }
            ?: profiles.firstOrNull { preferredDestinationType != null && it.type == preferredDestinationType }
            ?: if (purpose == PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT) {
                profiles.firstOrNull { !portfolioOptimizationIsLocalDestination(it.type) }
                    ?: profiles.firstOrNull()
            } else {
                profiles.firstOrNull { it.type == PortfolioOptimizationRemoteDestinationType.LOCAL_COMPLIANCE_ARCHIVE }
                    ?: profiles.firstOrNull()
            }

        val keyBlocked = enterpriseKeyReference?.status in setOf(
            PortfolioOptimizationEnterpriseKeyStatus.EXPIRED,
            PortfolioOptimizationEnterpriseKeyStatus.REVOKED,
            PortfolioOptimizationEnterpriseKeyStatus.MISCONFIGURED
        )
        val eligibility = profiles.map { profile ->
            val blockReason = when {
                !profile.active -> PortfolioOptimizationRemoteDestinationBlockReason.DESTINATION_POLICY_BLOCKED
                profile.destinationPolicy.allowedPurposes.isNotEmpty() &&
                    purpose !in profile.destinationPolicy.allowedPurposes ->
                    PortfolioOptimizationRemoteDestinationBlockReason.DESTINATION_POLICY_BLOCKED
                profile.destinationPolicy.sameTenantOnly &&
                    residencyPolicy.residencyBoundary.sameTenantOnly &&
                    binding.tenantId.isNullOrBlank() ->
                    PortfolioOptimizationRemoteDestinationBlockReason.DESTINATION_POLICY_BLOCKED
                profile.destinationPolicy.requiresResidencyMatch &&
                    profile.residencyRegion !in residencyPolicy.allowedRegions ->
                    PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED
                profile.destinationPolicy.requiresJurisdictionMatch &&
                    profile.jurisdiction !in residencyPolicy.allowedJurisdictions ->
                    PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED
                profile.destinationPolicy.requiresHealthyConnector &&
                    connectorProfile.healthStatus == PortfolioOptimizationRemoteTransportConnectorHealthStatus.UNHEALTHY ->
                    PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY
                profile.destinationPolicy.requiresHealthyKey && keyBlocked ->
                    PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED
                profile.destinationPolicy.requiresHealthyKey &&
                    !credentialResolution.resolved &&
                    credentialResolution.blockReason != PortfolioOptimizationTransportCredentialBlockReason.NONE ->
                    PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED
                else -> PortfolioOptimizationRemoteDestinationBlockReason.NONE
            }
            PortfolioOptimizationRemoteDestinationEligibility(
                destinationId = profile.destinationId,
                type = profile.type,
                eligible = blockReason == PortfolioOptimizationRemoteDestinationBlockReason.NONE,
                blockReason = blockReason,
                residencyCompatible = blockReason != PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED,
                jurisdictionCompatible = blockReason != PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED,
                summary = when (blockReason) {
                    PortfolioOptimizationRemoteDestinationBlockReason.NONE -> {
                        "Destination ${profile.displayName} is eligible."
                    }
                    PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED -> {
                        "Destination ${profile.displayName} is blocked by residency policy."
                    }
                    PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED -> {
                        "Destination ${profile.displayName} is blocked by jurisdiction policy."
                    }
                    PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY -> {
                        "Destination ${profile.displayName} is blocked because connector health is unhealthy."
                    }
                    PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED -> {
                        "Destination ${profile.displayName} is blocked because enterprise key state is unsafe."
                    }
                    PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED -> {
                        "Destination ${profile.displayName} is blocked because connector credentials are unresolved."
                    }
                    else -> {
                        "Destination ${profile.displayName} is blocked by destination policy."
                    }
                }
            )
        }
        val eligibleProfiles = profiles.filter { profile ->
            eligibility.firstOrNull { it.destinationId == profile.destinationId }?.eligible == true
        }
        val selectedProfile = preferredProfile?.takeIf { profile ->
            eligibility.firstOrNull { it.destinationId == profile.destinationId }?.eligible == true
        } ?: eligibleProfiles.firstOrNull()
        val preferredEligibility = preferredProfile?.let { profile ->
            eligibility.firstOrNull { it.destinationId == profile.destinationId }
        }
        val hasRemoteEligibleDestination = eligibleProfiles.any {
            !portfolioOptimizationIsLocalDestination(it.type)
        }
        val status = when {
            selectedProfile != null &&
                preferredProfile == null &&
                purpose == PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT &&
                portfolioOptimizationIsLocalDestination(selectedProfile.type) &&
                !hasRemoteEligibleDestination ->
                PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK
            selectedProfile != null && preferredProfile != null &&
                selectedProfile.destinationId == preferredProfile.destinationId ->
                PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED
            selectedProfile != null &&
                purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT &&
                residencyPolicy.holdForReviewOnMismatch &&
                preferredDestinationType == PortfolioOptimizationRemoteDestinationType.REMOTE_COMPLIANCE_ARCHIVE &&
                preferredEligibility?.blockReason in setOf(
                    PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED,
                    PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED
                ) ->
                PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE
            selectedProfile != null &&
                preferredEligibility?.blockReason in setOf(
                    PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY,
                    PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED,
                    PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED
                ) &&
                portfolioOptimizationIsLocalDestination(selectedProfile.type) ->
                PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK
            selectedProfile != null ->
                PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED
            preferredEligibility?.blockReason == PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED ->
                if (residencyPolicy.holdForReviewOnMismatch) {
                    PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE
                } else {
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY
                }
            preferredEligibility?.blockReason == PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED ->
                if (residencyPolicy.holdForReviewOnMismatch) {
                    PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE
                } else {
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION
                }
            else -> PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY
        }
        val blockReason = when (status) {
            PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED -> PortfolioOptimizationRemoteDestinationBlockReason.NONE
            PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED,
            PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                preferredEligibility?.blockReason ?: PortfolioOptimizationRemoteDestinationBlockReason.NONE
            PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                PortfolioOptimizationRemoteDestinationBlockReason.REVIEW_REQUIRED
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED ->
                preferredEligibility?.blockReason ?: PortfolioOptimizationRemoteDestinationBlockReason.DESTINATION_POLICY_BLOCKED
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY ->
                PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION ->
                PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY ->
                preferredEligibility?.blockReason
                    ?: PortfolioOptimizationRemoteDestinationBlockReason.NO_APPROVED_DESTINATION
        }
        val reasonCodes = when (status) {
            PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED ->
                if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                    listOf(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_ROUTE_SELECTED)
                } else {
                    listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_ROUTED)
                }
            PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED ->
                if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                    listOf(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_ROUTE_REROUTED)
                } else {
                    listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_REROUTED)
                }
            PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                listOf(
                    if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                        RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_ROUTE_HELD
                    } else {
                        RoleReasonCodes.ROLE_REMOTE_DESTINATION_HELD
                    }
                )
            PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                listOf(
                    if (purpose == PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) {
                        RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_ROUTE_LOCAL_ONLY
                    } else {
                        RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED
                    }
                )
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED ->
                listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_SUPPRESSED)
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY ->
                listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_BLOCKED_BY_RESIDENCY)
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION ->
                listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_BLOCKED_BY_JURISDICTION)
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY ->
                listOf(RoleReasonCodes.ROLE_REMOTE_DESTINATION_BLOCKED_BY_POLICY)
        }
        val summary = when (status) {
            PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED ->
                "Destination ${selectedProfile?.displayName ?: "n/a"} was routed inside ${residencyPolicy.residencyBoundary.region.name.lowercase().replace('_', ' ')} residency."
            PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED ->
                "Preferred destination ${preferredProfile?.displayName ?: "n/a"} was rerouted to ${selectedProfile?.displayName ?: "n/a"} under current policy."
            PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                "Destination routing is held for compliance review because residency or jurisdiction could not be satisfied safely."
            PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                "Destination routing fell back to ${selectedProfile?.displayName ?: "local-first handling"} to preserve local-first truth."
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED ->
                "Destination routing was suppressed by consent, role policy, or privacy policy."
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY ->
                "Destination routing was blocked because no approved destination satisfied residency policy."
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION ->
                "Destination routing was blocked because no approved destination satisfied jurisdiction policy."
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY ->
                "Destination routing was blocked because no approved destination satisfied destination policy."
        }
        return PortfolioOptimizationRemoteDestinationRouteSelection(
            destinationProfiles = profiles,
            decision = PortfolioOptimizationRemoteDestinationDecisionRecord(
                decisionId = "portfolio_destination_decision_${sourceId.takeLast(8)}_$now",
                purpose = purpose,
                sourceId = sourceId,
                status = status,
                preferredDestinationId = preferredProfile?.destinationId ?: preferredDestinationId,
                selectedDestinationId = selectedProfile?.destinationId,
                selectedDestinationType = selectedProfile?.type,
                reroutedFromDestinationId = preferredProfile
                    ?.destinationId
                    ?.takeIf { selectedProfile != null && selectedProfile.destinationId != it },
                residencyPolicy = residencyPolicy,
                residencyRegion = selectedProfile?.residencyRegion ?: residencyPolicy.residencyBoundary.region,
                jurisdiction = selectedProfile?.jurisdiction ?: residencyPolicy.residencyBoundary.jurisdiction,
                blockReason = blockReason,
                eligibility = eligibility,
                reasonCodes = reasonCodes,
                summary = summary,
                createdAtMs = now
            )
        )
    }

    private fun portfolioOptimizationDataExchangeArtifactClassFor(
        artifactType: PortfolioOptimizationLearningSyncArtifactType
    ): PortfolioOptimizationDataExchangeArtifactClass {
        return when (artifactType) {
            PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT ->
                PortfolioOptimizationDataExchangeArtifactClass.OBJECTIVE_PROFILE_SNAPSHOT
            PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT ->
                PortfolioOptimizationDataExchangeArtifactClass.CALIBRATION_SNAPSHOT
            PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY ->
                PortfolioOptimizationDataExchangeArtifactClass.DRIFT_SUMMARY
            PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE ->
                PortfolioOptimizationDataExchangeArtifactClass.OUTCOME_AGGREGATE
            PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY ->
                PortfolioOptimizationDataExchangeArtifactClass.FEDERATED_AGGREGATION_SUMMARY
        }
    }

    private fun buildPortfolioOptimizationRemoteTransportDataExchangeArtifacts(
        remoteEnvelope: PortfolioOptimizationRemoteLearningEnvelope
    ): List<PortfolioOptimizationDataExchangeArtifactRef> {
        return remoteEnvelope.artifactRefs.map { artifactRef ->
            PortfolioOptimizationDataExchangeArtifactRef(
                artifactClass = portfolioOptimizationDataExchangeArtifactClassFor(artifactRef.artifactType),
                artifactId = artifactRef.artifactId,
                artifactHash = artifactRef.artifactHash,
                artifactType = artifactRef.artifactType,
                redacted = true,
                summary = artifactRef.summary
            )
        }
    }

    private fun buildPortfolioOptimizationComplianceAuditDataExchangeArtifacts(
        bundle: PortfolioOptimizationComplianceAuditExportBundle
    ): List<PortfolioOptimizationDataExchangeArtifactRef> {
        val learningArtifacts = bundle.artifactRefs.map { artifactRef ->
            PortfolioOptimizationDataExchangeArtifactRef(
                artifactClass = portfolioOptimizationDataExchangeArtifactClassFor(artifactRef.artifactType),
                artifactId = artifactRef.artifactId,
                artifactHash = artifactRef.artifactHash,
                artifactType = artifactRef.artifactType,
                redacted = true,
                summary = artifactRef.summary
            )
        }
        val consentArtifact = bundle.consentRecords.takeIf { it.isNotEmpty() }?.let { records ->
            PortfolioOptimizationDataExchangeArtifactRef(
                artifactClass = PortfolioOptimizationDataExchangeArtifactClass.CONSENT_RECORD,
                artifactId = "consent_${bundle.bundleId}",
                artifactHash = sha256Hex(DomainJson.encode(records)),
                redacted = bundle.redactionPolicy.operatorNamesRedacted,
                summary = "Consent bundle contains ${records.size} consent record(s)."
            )
        }
        val receiptArtifact = bundle.receiptItems.takeIf { it.isNotEmpty() }?.let { items ->
            PortfolioOptimizationDataExchangeArtifactRef(
                artifactClass = PortfolioOptimizationDataExchangeArtifactClass.RECEIPT_TRACE,
                artifactId = "receipt_${bundle.bundleId}",
                artifactHash = sha256Hex(DomainJson.encode(items)),
                redacted = bundle.redactionPolicy.rawPromptsExcluded,
                summary = "Receipt bundle contains ${items.size} redaction-first receipt trace(s)."
            )
        }
        val governanceArtifact = bundle.governanceItems.takeIf { it.isNotEmpty() }?.let { items ->
            PortfolioOptimizationDataExchangeArtifactRef(
                artifactClass = PortfolioOptimizationDataExchangeArtifactClass.GOVERNANCE_CASE_SUMMARY,
                artifactId = "governance_${bundle.bundleId}",
                artifactHash = sha256Hex(DomainJson.encode(items)),
                redacted = true,
                summary = "Governance bundle contains ${items.size} case summary artifact(s)."
            )
        }
        return buildList {
            addAll(learningArtifacts)
            consentArtifact?.let(::add)
            receiptArtifact?.let(::add)
            governanceArtifact?.let(::add)
        }
    }

    private fun buildPortfolioOptimizationDestinationBundlePolicy(
        purpose: PortfolioOptimizationConsentPurpose,
        bundleType: PortfolioOptimizationSafeDestinationBundleType
    ): PortfolioOptimizationDestinationBundlePolicy {
        return when (bundleType) {
            PortfolioOptimizationSafeDestinationBundleType.LEARNING_ARTIFACT_EXCHANGE ->
                PortfolioOptimizationDestinationBundlePolicy(
                    policyId = "portfolio_bundle_policy_learning_${purpose.name.lowercase()}",
                    bundleType = bundleType,
                    allowedRemoteArtifactClasses = listOf(
                        PortfolioOptimizationDataExchangeArtifactClass.OBJECTIVE_PROFILE_SNAPSHOT,
                        PortfolioOptimizationDataExchangeArtifactClass.CALIBRATION_SNAPSHOT,
                        PortfolioOptimizationDataExchangeArtifactClass.DRIFT_SUMMARY,
                        PortfolioOptimizationDataExchangeArtifactClass.OUTCOME_AGGREGATE,
                        PortfolioOptimizationDataExchangeArtifactClass.FEDERATED_AGGREGATION_SUMMARY
                    ),
                    localOnlyArtifactClasses = emptyList(),
                    splitAllowed = false,
                    redactionRequired = true,
                    approvalRequiredOnHold = true,
                    summary = "Learning exchange remains artifact-only, redacted, and same-tenant."
                )

            PortfolioOptimizationSafeDestinationBundleType.COMPLIANCE_AUDIT_EXCHANGE ->
                PortfolioOptimizationDestinationBundlePolicy(
                    policyId = "portfolio_bundle_policy_audit_${purpose.name.lowercase()}",
                    bundleType = bundleType,
                    allowedRemoteArtifactClasses = listOf(
                        PortfolioOptimizationDataExchangeArtifactClass.OBJECTIVE_PROFILE_SNAPSHOT,
                        PortfolioOptimizationDataExchangeArtifactClass.CALIBRATION_SNAPSHOT,
                        PortfolioOptimizationDataExchangeArtifactClass.DRIFT_SUMMARY,
                        PortfolioOptimizationDataExchangeArtifactClass.OUTCOME_AGGREGATE,
                        PortfolioOptimizationDataExchangeArtifactClass.FEDERATED_AGGREGATION_SUMMARY,
                        PortfolioOptimizationDataExchangeArtifactClass.CONSENT_RECORD
                    ),
                    localOnlyArtifactClasses = listOf(
                        PortfolioOptimizationDataExchangeArtifactClass.RECEIPT_TRACE,
                        PortfolioOptimizationDataExchangeArtifactClass.GOVERNANCE_CASE_SUMMARY
                    ),
                    splitAllowed = true,
                    redactionRequired = true,
                    approvalRequiredOnHold = true,
                    summary = "Compliance exchange keeps receipt and governance traces local when remote archives are selected."
                )
        }
    }

    private fun evaluatePortfolioOptimizationDataExchangeBundle(
        purpose: PortfolioOptimizationConsentPurpose,
        sourceId: String,
        bundleType: PortfolioOptimizationSafeDestinationBundleType,
        artifacts: List<PortfolioOptimizationDataExchangeArtifactRef>,
        destinationSelection: PortfolioOptimizationRemoteDestinationRouteSelection,
        connectorProfile: PortfolioOptimizationRemoteTransportConnectorProfile,
        enterpriseKeyReference: PortfolioOptimizationEnterpriseKeyReference?,
        complianceDecision: PortfolioOptimizationComplianceGateDecision?,
        consentAllowed: Boolean,
        rolePolicyAllowed: Boolean,
        privacyPolicyAllowed: Boolean,
        now: Long
    ): PortfolioOptimizationDataExchangeEvaluation {
        val destinationDecision = destinationSelection.decision
        val bundlePolicy = buildPortfolioOptimizationDestinationBundlePolicy(
            purpose = purpose,
            bundleType = bundleType
        )
        val primaryDestination = destinationSelection.destinationProfiles.firstOrNull { profile ->
            profile.destinationId == destinationDecision.selectedDestinationId
        }
        val localDestination = destinationSelection.destinationProfiles.firstOrNull { profile ->
            portfolioOptimizationIsLocalDestination(profile.type)
        }
        val connectorHealthy =
            connectorProfile.healthStatus != PortfolioOptimizationRemoteTransportConnectorHealthStatus.UNHEALTHY
        val keyHealthy = enterpriseKeyReference?.status !in setOf(
            PortfolioOptimizationEnterpriseKeyStatus.EXPIRED,
            PortfolioOptimizationEnterpriseKeyStatus.REVOKED,
            PortfolioOptimizationEnterpriseKeyStatus.MISCONFIGURED
        )
        val destinationPolicyAllowed = destinationDecision.status !in setOf(
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY
        )
        val boundarySummary = PortfolioOptimizationDataExchangeBoundarySummary(
            boundaryId = "portfolio_exchange_boundary_${sourceId.takeLast(8)}_$now",
            purpose = purpose,
            residencyRegion = destinationDecision.residencyRegion,
            jurisdiction = destinationDecision.jurisdiction,
            consentAllowed = consentAllowed,
            rolePolicyAllowed = rolePolicyAllowed,
            privacyPolicyAllowed = privacyPolicyAllowed,
            destinationPolicyAllowed = destinationPolicyAllowed,
            connectorHealthy = connectorHealthy,
            keyHealthy = keyHealthy,
            complianceDecision = complianceDecision,
            summary = listOfNotNull(
                destinationDecision.residencyPolicy.summary.takeIf { it.isNotBlank() },
                destinationDecision.summary.takeIf { it.isNotBlank() }
            ).joinToString(" ").ifBlank {
                "Cross-boundary policy evaluation applied to a typed exchange bundle."
            }
        )
        val artifactClasses = artifacts.map { it.artifactClass }.distinct()
        val localOnlyClasses = artifactClasses.filter { it in bundlePolicy.localOnlyArtifactClasses }
        val remoteAllowedClasses = artifactClasses.filter { it in bundlePolicy.allowedRemoteArtifactClasses }
        val redactedClasses = artifacts.filter { it.redacted }.map { it.artifactClass }.distinct()
        val splitRequired = bundlePolicy.splitAllowed &&
            primaryDestination != null &&
            !portfolioOptimizationIsLocalDestination(primaryDestination.type) &&
            localOnlyClasses.isNotEmpty()
        val compatibility = destinationSelection.destinationProfiles.map { profile ->
            val blockedClasses = if (portfolioOptimizationIsLocalDestination(profile.type)) {
                emptyList()
            } else {
                artifactClasses.filterNot { it in bundlePolicy.allowedRemoteArtifactClasses }
            }
            val status = when {
                destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REVIEW_REQUIRED
                destinationDecision.status in setOf(
                    PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY,
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION,
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY
                ) && profile.destinationId == (destinationDecision.selectedDestinationId
                    ?: destinationDecision.preferredDestinationId) ->
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.INCOMPATIBLE
                splitRequired && profile.destinationId == primaryDestination?.destinationId ->
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REQUIRES_SPLIT
                redactedClasses.isNotEmpty() ->
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REQUIRES_REDACTION
                else -> PortfolioOptimizationDestinationBundleCompatibilityStatus.COMPATIBLE
            }
            PortfolioOptimizationDestinationBundleCompatibility(
                destinationId = profile.destinationId,
                destinationType = profile.type,
                status = status,
                allowedArtifactClasses = if (portfolioOptimizationIsLocalDestination(profile.type)) {
                    artifactClasses
                } else {
                    remoteAllowedClasses
                },
                blockedArtifactClasses = blockedClasses,
                redactedArtifactClasses = redactedClasses,
                summary = when (status) {
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REQUIRES_SPLIT ->
                        "Destination ${profile.displayName} requires a local split for receipt or governance artifacts."
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REQUIRES_REDACTION ->
                        "Destination ${profile.displayName} is compatible after redaction-first handling."
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.REVIEW_REQUIRED ->
                        "Destination ${profile.displayName} requires explicit compliance review."
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.INCOMPATIBLE ->
                        "Destination ${profile.displayName} is incompatible with current boundary policy."
                    PortfolioOptimizationDestinationBundleCompatibilityStatus.COMPATIBLE ->
                        "Destination ${profile.displayName} is compatible with the current bundle."
                }
            )
        }
        val splitResult = if (splitRequired && primaryDestination != null && localDestination != null) {
            PortfolioOptimizationDestinationBundleSplitResult(
                splitRequired = true,
                primaryDestinationId = primaryDestination.destinationId,
                secondaryDestinationId = localDestination.destinationId,
                remoteArtifactClasses = remoteAllowedClasses,
                localArtifactClasses = localOnlyClasses,
                summary = "Bundle split keeps receipt and governance traces local while remote-safe artifacts continue to ${primaryDestination.displayName}."
            )
        } else {
            null
        }
        val redactionResult = PortfolioOptimizationDestinationBundleRedactionResult(
            redactionApplied = redactedClasses.isNotEmpty() || bundlePolicy.redactionRequired,
            redactedArtifactClasses = redactedClasses,
            excludedArtifactClasses = emptyList(),
            excludedArtifactCount = 0,
            summary = if (redactedClasses.isNotEmpty() || bundlePolicy.redactionRequired) {
                "Redaction-first handling applies to ${redactedClasses.size.coerceAtLeast(1)} artifact class(es)."
            } else {
                "No additional redaction was required for this exchange bundle."
            }
        )
        val bundleStatus = when {
            splitRequired -> PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT
            destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED ->
                PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED
            destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED ||
                destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED
            destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD
            destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED ->
                PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED
            else -> PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED
        }
        val manifestStatus = when (bundleStatus) {
            PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED ->
                if (primaryDestination?.type?.let(::portfolioOptimizationIsLocalDestination) == true) {
                    PortfolioOptimizationDataExchangeManifestStatus.LOCAL_ONLY
                } else {
                    PortfolioOptimizationDataExchangeManifestStatus.ROUTED
                }
            PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ->
                PortfolioOptimizationDataExchangeManifestStatus.SPLIT
            PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ->
                if (primaryDestination?.type?.let(::portfolioOptimizationIsLocalDestination) == true) {
                    PortfolioOptimizationDataExchangeManifestStatus.LOCAL_ONLY
                } else {
                    PortfolioOptimizationDataExchangeManifestStatus.REROUTED
                }
            PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                PortfolioOptimizationDataExchangeManifestStatus.HELD
            PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ->
                PortfolioOptimizationDataExchangeManifestStatus.SUPPRESSED
            PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                PortfolioOptimizationDataExchangeManifestStatus.BLOCKED
        }
        val holdReason = when (destinationDecision.status) {
            PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                when (destinationDecision.blockReason) {
                    PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED ->
                        PortfolioOptimizationDataExchangeHoldReason.RESIDENCY_REVIEW_REQUIRED
                    PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED ->
                        PortfolioOptimizationDataExchangeHoldReason.JURISDICTION_REVIEW_REQUIRED
                    PortfolioOptimizationRemoteDestinationBlockReason.CONSENT_DENIED ->
                        PortfolioOptimizationDataExchangeHoldReason.CONSENT_REQUIRED
                    PortfolioOptimizationRemoteDestinationBlockReason.ROLE_POLICY_BLOCKED ->
                        PortfolioOptimizationDataExchangeHoldReason.ROLE_POLICY_REVIEW_REQUIRED
                    else -> PortfolioOptimizationDataExchangeHoldReason.DESTINATION_POLICY_REVIEW_REQUIRED
                }

            else -> PortfolioOptimizationDataExchangeHoldReason.NONE
        }
        val bundle = PortfolioOptimizationSafeDestinationBundle(
            bundleId = "portfolio_exchange_bundle_${sourceId.takeLast(8)}_$now",
            purpose = purpose,
            bundleType = bundleType,
            sourceId = sourceId,
            destinationIds = buildList {
                primaryDestination?.destinationId?.let(::add)
                splitResult?.secondaryDestinationId
                    ?.takeIf { it != primaryDestination?.destinationId }
                    ?.let(::add)
            },
            destinationTypes = buildList {
                primaryDestination?.type?.let(::add)
                localDestination?.type
                    ?.takeIf { splitRequired && it != primaryDestination?.type }
                    ?.let(::add)
            },
            artifacts = artifacts,
            artifactClasses = artifactClasses,
            summary = "Bundle packages ${artifactClasses.size} artifact class(es) across ${artifacts.size} artifact reference(s).",
            createdAtMs = now
        )
        val decisionReasonCodes = buildList {
            when (bundleStatus) {
                PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_ALLOWED)
                PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_SPLIT)
                PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_REROUTED)
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_HELD)
                PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_SUPPRESSED)
                PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                    add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_BLOCKED)
            }
            if (redactionResult.redactionApplied) {
                add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_REDACTED)
            }
            when (destinationDecision.blockReason) {
                PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED ->
                    add(RoleReasonCodes.ROLE_RESIDENCY_BOUNDARY_BLOCKED)
                PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED ->
                    add(RoleReasonCodes.ROLE_JURISDICTION_BOUNDARY_BLOCKED)
                PortfolioOptimizationRemoteDestinationBlockReason.DESTINATION_POLICY_BLOCKED,
                PortfolioOptimizationRemoteDestinationBlockReason.NO_APPROVED_DESTINATION ->
                    add(RoleReasonCodes.ROLE_DESTINATION_POLICY_BLOCKED)
                else -> Unit
            }
        }.distinct()
        val decision = PortfolioOptimizationDestinationBundleDecisionRecord(
            decisionId = "portfolio_exchange_decision_${sourceId.takeLast(8)}_$now",
            bundleId = bundle.bundleId,
            purpose = purpose,
            bundleType = bundleType,
            sourceId = sourceId,
            destinationPolicy = bundlePolicy,
            boundarySummary = boundarySummary,
            status = bundleStatus,
            primaryDestinationId = primaryDestination?.destinationId ?: localDestination?.destinationId,
            primaryDestinationType = primaryDestination?.type ?: localDestination?.type,
            compatibility = compatibility,
            splitResult = splitResult,
            redactionResult = redactionResult,
            approvalRequired = bundleStatus == PortfolioOptimizationDestinationBundleDecisionStatus.HELD,
            reasonCodes = decisionReasonCodes,
            summary = when (bundleStatus) {
                PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED ->
                    "Bundle allowed for ${primaryDestination?.displayName ?: "local-first handling"} under current boundary controls."
                PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ->
                    splitResult?.summary.orEmpty()
                PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ->
                    "Bundle rerouted to ${primaryDestination?.displayName ?: "local-first handling"} to preserve local-first truth."
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                    "Bundle is held pending explicit cross-boundary review."
                PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ->
                    "Bundle was suppressed by consent, role policy, or privacy policy."
                PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                    "Bundle was blocked because no safe destination satisfied the active boundary policy."
            },
            createdAtMs = now
        )
        val manifest = PortfolioOptimizationDataExchangeManifest(
            manifestId = "portfolio_exchange_manifest_${sourceId.takeLast(8)}_$now",
            bundleId = bundle.bundleId,
            bundleDecisionId = decision.decisionId,
            purpose = purpose,
            bundleType = bundleType,
            status = manifestStatus,
            destinationIds = bundle.destinationIds,
            destinationTypes = bundle.destinationTypes,
            artifactRefs = artifacts,
            excludedArtifactRefs = if (bundleStatus in setOf(
                    PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED,
                    PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED
                )
            ) {
                artifacts
            } else {
                emptyList()
            },
            boundarySummary = boundarySummary,
            rerouteSummary = if (
                bundleStatus == PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED &&
                destinationDecision.reroutedFromDestinationId != null
            ) {
                PortfolioOptimizationDataExchangeRerouteSummary(
                    rerouted = true,
                    fromDestinationId = destinationDecision.reroutedFromDestinationId,
                    toDestinationId = decision.primaryDestinationId,
                    fromDestinationType = destinationSelection.destinationProfiles
                        .firstOrNull { it.destinationId == destinationDecision.reroutedFromDestinationId }
                        ?.type,
                    toDestinationType = decision.primaryDestinationType,
                    summary = "Bundle reroute preserved policy-safe handling."
                )
            } else {
                null
            },
            holdReason = holdReason,
            summary = when (manifestStatus) {
                PortfolioOptimizationDataExchangeManifestStatus.SPLIT ->
                    splitResult?.summary.orEmpty()
                PortfolioOptimizationDataExchangeManifestStatus.LOCAL_ONLY ->
                    "Manifest remains local-only and authoritative."
                PortfolioOptimizationDataExchangeManifestStatus.HELD ->
                    "Manifest is held pending cross-boundary review."
                PortfolioOptimizationDataExchangeManifestStatus.SUPPRESSED ->
                    "Manifest is suppressed by higher-precedence policy."
                PortfolioOptimizationDataExchangeManifestStatus.BLOCKED ->
                    "Manifest is blocked by boundary policy."
                PortfolioOptimizationDataExchangeManifestStatus.REROUTED ->
                    "Manifest rerouted safely under current destination policy."
                PortfolioOptimizationDataExchangeManifestStatus.ROUTED ->
                    "Manifest routed safely under current destination policy."
            },
            createdAtMs = now
        )
        val approvalStatus = when (bundleStatus) {
            PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW
            PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED,
            PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                PortfolioOptimizationCrossBoundaryApprovalStatus.DENIED
            else -> PortfolioOptimizationCrossBoundaryApprovalStatus.AUTO_APPROVED
        }
        val approval = PortfolioOptimizationCrossBoundaryApprovalRecord(
            approvalId = "portfolio_exchange_approval_${sourceId.takeLast(8)}_$now",
            bundleDecisionId = decision.decisionId,
            manifestId = manifest.manifestId,
            sourceId = sourceId,
            required = bundleStatus == PortfolioOptimizationDestinationBundleDecisionStatus.HELD,
            status = approvalStatus,
            reasonCodes = buildList {
                when (approvalStatus) {
                    PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW ->
                        add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_APPROVAL_PENDING)
                    PortfolioOptimizationCrossBoundaryApprovalStatus.AUTO_APPROVED,
                    PortfolioOptimizationCrossBoundaryApprovalStatus.APPROVED ->
                        add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_AUTO_APPROVED)
                    PortfolioOptimizationCrossBoundaryApprovalStatus.DENIED ->
                        add(RoleReasonCodes.ROLE_DESTINATION_BUNDLE_BLOCKED)
                }
            },
            summary = when (approvalStatus) {
                PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW ->
                    "Cross-boundary approval is pending explicit review."
                PortfolioOptimizationCrossBoundaryApprovalStatus.DENIED ->
                    "Cross-boundary approval was denied by boundary policy."
                else ->
                    "Cross-boundary approval was auto-approved because the bundle remained within safe bounds."
            },
            recordedAtMs = now
        )
        val primaryAudit = PortfolioOptimizationCrossBoundaryAuditRecord(
            auditId = "portfolio_exchange_audit_${sourceId.takeLast(8)}_${now}_1",
            bundleDecisionId = decision.decisionId,
            manifestId = manifest.manifestId,
            purpose = purpose,
            bundleType = bundleType,
            operationType = when (bundleStatus) {
                PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.BOUNDARY_CHECK_PASSED
                PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.BUNDLE_SPLIT_REQUIRED
                PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.REROUTE_COMPLETED
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.HOLD_CONFIRMED
                PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.SUPPRESSION_CONFIRMED
                PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                    PortfolioOptimizationCrossBoundaryAuditOperationType.BOUNDARY_CHECK_FAILED
            },
            result = when (bundleStatus) {
                PortfolioOptimizationDestinationBundleDecisionStatus.ALLOWED ->
                    PortfolioOptimizationCrossBoundaryAuditResult.PASSED
                PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT,
                PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ->
                    PortfolioOptimizationCrossBoundaryAuditResult.RECORDED
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                    PortfolioOptimizationCrossBoundaryAuditResult.REVIEW_REQUIRED
                PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED,
                PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                    PortfolioOptimizationCrossBoundaryAuditResult.FAILED
            },
            issues = buildList {
                if (holdReason != PortfolioOptimizationDataExchangeHoldReason.NONE) {
                    add(
                        PortfolioOptimizationCrossBoundaryAuditIssue(
                            code = holdReason.name,
                            blocking = bundleStatus == PortfolioOptimizationDestinationBundleDecisionStatus.HELD,
                            summary = decision.summary
                        )
                    )
                }
                compatibility.filter { it.blockedArtifactClasses.isNotEmpty() }.forEach { compatibilityRecord ->
                    add(
                        PortfolioOptimizationCrossBoundaryAuditIssue(
                            code = compatibilityRecord.status.name,
                            blocking = compatibilityRecord.status ==
                                PortfolioOptimizationDestinationBundleCompatibilityStatus.INCOMPATIBLE,
                            summary = compatibilityRecord.summary
                        )
                    )
                }
            },
            recommendation = when (bundleStatus) {
                PortfolioOptimizationDestinationBundleDecisionStatus.HELD ->
                    PortfolioOptimizationCrossBoundaryAuditRecommendation(
                        action = "review_bundle",
                        summary = "Record an operator review before retrying this cross-boundary exchange."
                    )
                PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                    PortfolioOptimizationCrossBoundaryAuditRecommendation(
                        action = "reroute_local",
                        summary = "Keep the bundle local or select a destination inside the active boundary."
                    )
                else -> null
            },
            reasonCodes = (decisionReasonCodes + RoleReasonCodes.ROLE_CROSS_BOUNDARY_AUDIT_RECORDED).distinct(),
            summary = "Cross-boundary audit recorded: ${decision.summary}",
            recordedAtMs = now
        )
        val redactionAudit = redactionResult.takeIf { it.redactionApplied }?.let {
            PortfolioOptimizationCrossBoundaryAuditRecord(
                auditId = "portfolio_exchange_audit_${sourceId.takeLast(8)}_${now}_2",
                bundleDecisionId = decision.decisionId,
                manifestId = manifest.manifestId,
                purpose = purpose,
                bundleType = bundleType,
                operationType = PortfolioOptimizationCrossBoundaryAuditOperationType.REDACTION_APPLIED,
                result = PortfolioOptimizationCrossBoundaryAuditResult.RECORDED,
                reasonCodes = listOf(
                    RoleReasonCodes.ROLE_DESTINATION_BUNDLE_REDACTED,
                    RoleReasonCodes.ROLE_CROSS_BOUNDARY_AUDIT_RECORDED
                ),
                summary = "Cross-boundary audit recorded: ${it.summary}",
                recordedAtMs = now
            )
        }
        return PortfolioOptimizationDataExchangeEvaluation(
            bundle = bundle,
            decision = decision,
            manifest = manifest,
            approval = approval,
            audits = listOfNotNull(primaryAudit, redactionAudit)
        )
    }

    fun dispatchPortfolioOptimizationRemoteLearningTransport(
        userId: String,
        envelopeId: String,
        purpose: PortfolioOptimizationConsentPurpose =
            PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationRemoteLearningTransportAttemptRecord {
        if (userId.isBlank() || envelopeId.isBlank()) {
            return PortfolioOptimizationRemoteLearningTransportAttemptRecord(
                remoteEnvelopeId = envelopeId,
                transportMode = remoteLearningTransportPort.transportMode,
                purpose = purpose,
                status = PortfolioOptimizationRemoteLearningDeliveryStatus.BLOCKED,
                issues = listOf(
                    PortfolioOptimizationRemoteLearningTransportIssue(
                        type = PortfolioOptimizationRemoteLearningTransportIssueType.CONSENT_BLOCKED,
                        blocking = true,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_CONSENT),
                        summary = "Remote learning transport failed: missing user or envelope identity."
                    )
                ),
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_CONSENT),
                summary = "Remote learning transport failed: missing user or envelope identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
        val syncEnvelope = synchronized(dynamicStateLock) {
            portfolioOptimizationLearningSyncEnvelopesByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.envelopeId == envelopeId }
        }
        if (syncEnvelope == null) {
            val missingAttempt = PortfolioOptimizationRemoteLearningTransportAttemptRecord(
                attemptId = "portfolio_remote_transport_${envelopeId.takeLast(8)}_$now",
                remoteEnvelopeId = envelopeId,
                transportMode = remoteLearningTransportPort.transportMode,
                purpose = purpose,
                status = PortfolioOptimizationRemoteLearningDeliveryStatus.BLOCKED,
                issues = listOf(
                    PortfolioOptimizationRemoteLearningTransportIssue(
                        type = PortfolioOptimizationRemoteLearningTransportIssueType.ENVELOPE_NOT_FOUND,
                        blocking = true,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_FAILED),
                        summary = "Remote learning transport failed: source learning sync envelope was not found."
                    )
                ),
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_FAILED),
                summary = "Remote learning transport failed: source learning sync envelope was not found.",
                processedAtMs = now
            )
            storePortfolioOptimizationRemoteLearningTransportAttempt(userId, missingAttempt)
            persistDynamicState(userId)
            return missingAttempt
        }
        val resolvedScopeBinding = resolvePortfolioOptimizationScopeBinding(userId)
        val binding = resolvedScopeBinding.copy(
            workspaceId = syncEnvelope.boundary.workspaceId ?: resolvedScopeBinding.workspaceId,
            tenantId = syncEnvelope.boundary.tenantId ?: resolvedScopeBinding.tenantId
        )
        val privacyPolicy = derivePortfolioOptimizationLearningSyncPrivacyPolicy(
            userId = userId,
            mode = syncEnvelope.mode,
            binding = binding,
            activeRole = activeRole
        )
        val consentRecord = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = purpose,
                binding = binding,
                now = now
            )
        }
        val enterprisePrivacy = derivePortfolioOptimizationEnterprisePrivacyPolicySummary(
            userId = userId,
            binding = binding,
            activeRole = activeRole,
            learningSyncConsent = synchronized(dynamicStateLock) {
                effectivePortfolioOptimizationConsentRecordLocked(
                    userId = userId,
                    purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                    binding = binding,
                    now = now
                )
            },
            remoteTransportConsent = consentRecord,
            auditExportConsent = synchronized(dynamicStateLock) {
                effectivePortfolioOptimizationConsentRecordLocked(
                    userId = userId,
                    purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                    binding = binding,
                    now = now
                )
            }
        )
        val remoteEnvelope = buildPortfolioOptimizationRemoteLearningEnvelope(
            syncEnvelope = syncEnvelope,
            consentRecord = consentRecord,
            enterprisePrivacy = enterprisePrivacy,
            now = now
        )
        val connectorRuntime = remoteLearningTransportPort.inspect(
            purpose = purpose,
            nowMs = now
        )
        val connectorProfile = connectorRuntime.connectorProfile.copy(
            updatedAtMs = now,
            summary = connectorRuntime.connectorProfile.summary.ifBlank {
                connectorRuntime.connectorProfile.displayName.ifBlank {
                    connectorRuntime.connectorProfile.type.name.lowercase().replace('_', ' ')
                }
            }
        )
        val enterpriseKeyReference = connectorRuntime.enterpriseKeyReference?.copy(
            connectorProfileId = connectorRuntime.enterpriseKeyReference.connectorProfileId.ifBlank {
                connectorProfile.profileId
            },
            updatedAtMs = now,
            summary = connectorRuntime.enterpriseKeyReference.summary.ifBlank {
                "Enterprise key ${connectorRuntime.enterpriseKeyReference.keyRefId} is ${connectorRuntime.enterpriseKeyReference.status.name.lowercase().replace('_', ' ')}."
            }
        )
        val connectorBinding = PortfolioOptimizationRemoteTransportConnectorBinding(
            profileId = connectorProfile.profileId,
            type = connectorProfile.type,
            healthStatus = connectorProfile.healthStatus,
            keyRefId = enterpriseKeyReference?.keyRefId,
            summary = connectorProfile.summary.ifBlank {
                connectorProfile.displayName.ifBlank {
                    connectorProfile.type.name.lowercase().replace('_', ' ')
                }
            }
        )
        val credentialResolution = connectorRuntime.credentialResolution.copy(
            connectorProfileId = connectorRuntime.credentialResolution.connectorProfileId.ifBlank {
                connectorProfile.profileId
            },
            keyRefId = connectorRuntime.credentialResolution.keyRefId ?: enterpriseKeyReference?.keyRefId,
            checkedAtMs = now,
            summary = connectorRuntime.credentialResolution.summary.ifBlank {
                if (connectorRuntime.credentialResolution.resolved) {
                    "Connector credential resolved successfully."
                } else {
                    "Connector credential resolution failed."
                }
            }
        )
        val routeSelection = evaluatePortfolioOptimizationRemoteDestinationRoute(
            purpose = purpose,
            sourceId = remoteEnvelope.remoteEnvelopeId,
            binding = binding,
            connectorProfile = connectorProfile,
            privacyPolicy = privacyPolicy,
            enterprisePrivacy = enterprisePrivacy,
            consentRecord = consentRecord,
            enterpriseKeyReference = enterpriseKeyReference,
            credentialResolution = credentialResolution,
            now = now
        )
        val destinationDecision = routeSelection.decision
        val retryPolicy = connectorProfile.retryPolicy
        val issues = mutableListOf<PortfolioOptimizationRemoteLearningTransportIssue>()
        var complianceDecision = PortfolioOptimizationComplianceGateDecision.ALLOWED_WITH_REDACTION
        var complianceBlockReason = PortfolioOptimizationComplianceBlockReason.NONE
        var preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.NONE
        var complianceSummary = "Compliance gate passed with redaction-first artifact transport."
        when (destinationDecision.status) {
            PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED -> Unit
            PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.REROUTED,
                    blocking = false,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                if (portfolioOptimizationIsLocalDestination(destinationDecision.selectedDestinationType) &&
                    connectorProfile.type !in setOf(
                        PortfolioOptimizationRemoteTransportConnectorType.NO_OP,
                        PortfolioOptimizationRemoteTransportConnectorType.LOCAL_DURABLE
                    )
                ) {
                    complianceDecision = PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
                    complianceBlockReason = when (destinationDecision.blockReason) {
                        PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.RESIDENCY_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.JURISDICTION_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY ->
                            PortfolioOptimizationComplianceBlockReason.CONNECTOR_UNHEALTHY
                        PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
                        else -> PortfolioOptimizationComplianceBlockReason.DESTINATION_POLICY_BLOCKED
                    }
                    preDispatchFailureReason = when (destinationDecision.blockReason) {
                        PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED ->
                            when (enterpriseKeyReference?.status) {
                                PortfolioOptimizationEnterpriseKeyStatus.EXPIRED ->
                                    PortfolioOptimizationRemoteTransportFailureReason.KEY_EXPIRED
                                PortfolioOptimizationEnterpriseKeyStatus.REVOKED ->
                                    PortfolioOptimizationRemoteTransportFailureReason.KEY_REVOKED
                                else -> PortfolioOptimizationRemoteTransportFailureReason.KEY_MISCONFIGURED
                            }
                        PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY ->
                            PortfolioOptimizationRemoteTransportFailureReason.CONNECTOR_UNHEALTHY
                        PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED ->
                            PortfolioOptimizationRemoteTransportFailureReason.KEY_MISSING
                        else -> PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                    }
                    complianceSummary = destinationDecision.summary
                }
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.HELD_FOR_COMPLIANCE,
                    blocking = true,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
                complianceBlockReason = PortfolioOptimizationComplianceBlockReason.REVIEW_REQUIRED
                preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                complianceSummary = destinationDecision.summary
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.LOCAL_FALLBACK_USED,
                    blocking = false,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                if (connectorProfile.type !in setOf(
                        PortfolioOptimizationRemoteTransportConnectorType.NO_OP,
                        PortfolioOptimizationRemoteTransportConnectorType.LOCAL_DURABLE
                    )
                ) {
                    complianceDecision = PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
                    complianceBlockReason = when (destinationDecision.blockReason) {
                        PortfolioOptimizationRemoteDestinationBlockReason.RESIDENCY_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.RESIDENCY_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.JURISDICTION_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.JURISDICTION_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY ->
                            PortfolioOptimizationComplianceBlockReason.CONNECTOR_UNHEALTHY
                        PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED ->
                            PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
                        else -> PortfolioOptimizationComplianceBlockReason.DESTINATION_POLICY_BLOCKED
                    }
                    preDispatchFailureReason = when (destinationDecision.blockReason) {
                        PortfolioOptimizationRemoteDestinationBlockReason.KEY_HEALTH_BLOCKED ->
                            when (enterpriseKeyReference?.status) {
                                PortfolioOptimizationEnterpriseKeyStatus.EXPIRED ->
                                    PortfolioOptimizationRemoteTransportFailureReason.KEY_EXPIRED
                                PortfolioOptimizationEnterpriseKeyStatus.REVOKED ->
                                    PortfolioOptimizationRemoteTransportFailureReason.KEY_REVOKED
                                else -> PortfolioOptimizationRemoteTransportFailureReason.KEY_MISCONFIGURED
                            }
                        PortfolioOptimizationRemoteDestinationBlockReason.CONNECTOR_UNHEALTHY ->
                            PortfolioOptimizationRemoteTransportFailureReason.CONNECTOR_UNHEALTHY
                        PortfolioOptimizationRemoteDestinationBlockReason.CREDENTIAL_BLOCKED ->
                            PortfolioOptimizationRemoteTransportFailureReason.KEY_MISSING
                        else -> PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                    }
                    complianceSummary = destinationDecision.summary
                }
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = when (destinationDecision.blockReason) {
                        PortfolioOptimizationRemoteDestinationBlockReason.CONSENT_DENIED ->
                            PortfolioOptimizationRemoteLearningTransportIssueType.CONSENT_BLOCKED
                        PortfolioOptimizationRemoteDestinationBlockReason.ROLE_POLICY_BLOCKED ->
                            PortfolioOptimizationRemoteLearningTransportIssueType.ROLE_POLICY_BLOCKED
                        else -> PortfolioOptimizationRemoteLearningTransportIssueType.PRIVACY_POLICY_BLOCKED
                    },
                    blocking = true,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
                complianceBlockReason = when (destinationDecision.blockReason) {
                    PortfolioOptimizationRemoteDestinationBlockReason.CONSENT_DENIED ->
                        PortfolioOptimizationComplianceBlockReason.CONSENT_DENIED
                    PortfolioOptimizationRemoteDestinationBlockReason.ROLE_POLICY_BLOCKED ->
                        PortfolioOptimizationComplianceBlockReason.ROLE_POLICY_BLOCKED
                    else -> PortfolioOptimizationComplianceBlockReason.PRIVACY_POLICY_BLOCKED
                }
                preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                complianceSummary = destinationDecision.summary
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.RESIDENCY_BLOCKED,
                    blocking = true,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
                complianceBlockReason = PortfolioOptimizationComplianceBlockReason.RESIDENCY_BLOCKED
                preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                complianceSummary = destinationDecision.summary
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.JURISDICTION_BLOCKED,
                    blocking = true,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
                complianceBlockReason = PortfolioOptimizationComplianceBlockReason.JURISDICTION_BLOCKED
                preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                complianceSummary = destinationDecision.summary
            }
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.DESTINATION_POLICY_BLOCKED,
                    blocking = true,
                    reasonCodes = destinationDecision.reasonCodes,
                    summary = destinationDecision.summary
                )
                complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
                complianceBlockReason = PortfolioOptimizationComplianceBlockReason.DESTINATION_POLICY_BLOCKED
                preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
                complianceSummary = destinationDecision.summary
            }
        }
        if (purpose != PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.CONSENT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_CONSENT),
                summary = "Remote learning transport only supports the remote transport purpose."
            )
            complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
            complianceBlockReason = PortfolioOptimizationComplianceBlockReason.PURPOSE_NOT_ALLOWED
            preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
            complianceSummary = "Compliance gate blocked remote transport because the requested purpose is not allowed."
        }
        if (consentRecord?.decision != PortfolioOptimizationConsentDecision.ALLOWED) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.CONSENT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_CONSENT),
                summary = consentRecord?.summary?.takeIf { it.isNotBlank() }
                    ?: "Remote learning transport is blocked until consent is explicitly allowed."
            )
            complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
            complianceBlockReason = PortfolioOptimizationComplianceBlockReason.CONSENT_DENIED
            preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
            complianceSummary = consentRecord?.summary?.takeIf { it.isNotBlank() }
                ?: "Compliance gate blocked remote transport because consent was denied."
        }
        if (!enterprisePrivacy.remoteTransportAllowedByRolePolicy) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.ROLE_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_ROLE_POLICY),
                summary = enterprisePrivacy.summary.ifBlank {
                    "Role policy keeps remote learning transport disabled."
                }
            )
            complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
            complianceBlockReason = PortfolioOptimizationComplianceBlockReason.ROLE_POLICY_BLOCKED
            preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
            complianceSummary = enterprisePrivacy.summary.ifBlank {
                "Compliance gate blocked remote transport because role policy denied it."
            }
        }
        if (!privacyPolicy.cloudSyncAllowed && syncEnvelope.mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.PRIVACY_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(
                    RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_BLOCKED_BY_ROLE_POLICY,
                    RoleReasonCodes.ROLE_COMPLIANCE_GATE_BLOCKED
                ),
                summary = privacyPolicy.summary.ifBlank {
                    "Privacy policy blocks remote learning transport."
                }
            )
            complianceDecision = PortfolioOptimizationComplianceGateDecision.BLOCKED
            complianceBlockReason = PortfolioOptimizationComplianceBlockReason.PRIVACY_POLICY_BLOCKED
            preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
            complianceSummary = privacyPolicy.summary.ifBlank {
                "Compliance gate blocked remote transport because privacy policy denied it."
            }
        }
        if (connectorProfile.healthStatus == PortfolioOptimizationRemoteTransportConnectorHealthStatus.DEGRADED) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.CONNECTOR_HEALTH_BLOCKED,
                blocking = false,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_CONNECTOR_DEGRADED),
                summary = connectorProfile.summary.ifBlank {
                    "Connector health is degraded."
                }
            )
        }
        if (connectorProfile.healthStatus == PortfolioOptimizationRemoteTransportConnectorHealthStatus.UNHEALTHY) {
            val fallbackAllowed = retryPolicy.localFallbackAllowed
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = if (fallbackAllowed) {
                    PortfolioOptimizationRemoteLearningTransportIssueType.LOCAL_FALLBACK_USED
                } else {
                    PortfolioOptimizationRemoteLearningTransportIssueType.CONNECTOR_HEALTH_BLOCKED
                },
                blocking = !fallbackAllowed,
                reasonCodes = buildList {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_CONNECTOR_DEGRADED)
                    if (fallbackAllowed) {
                        add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED)
                    } else {
                        add(RoleReasonCodes.ROLE_COMPLIANCE_GATE_BLOCKED)
                    }
                },
                summary = connectorProfile.summary.ifBlank {
                    "Connector health is unhealthy."
                }
            )
            complianceDecision = if (fallbackAllowed) {
                PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
            } else {
                PortfolioOptimizationComplianceGateDecision.BLOCKED
            }
            complianceBlockReason = PortfolioOptimizationComplianceBlockReason.CONNECTOR_UNHEALTHY
            preDispatchFailureReason = PortfolioOptimizationRemoteTransportFailureReason.CONNECTOR_UNHEALTHY
            complianceSummary = if (fallbackAllowed) {
                "Connector health is unhealthy, so the operation fell back to local-only handling."
            } else {
                "Compliance gate blocked remote transport because connector health is unhealthy."
            }
        }
        when (enterpriseKeyReference?.status) {
            PortfolioOptimizationEnterpriseKeyStatus.ROTATION_REQUIRED -> {
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = PortfolioOptimizationRemoteLearningTransportIssueType.KEY_HEALTH_BLOCKED,
                    blocking = false,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_ENTERPRISE_KEY_ROTATION_REQUIRED),
                    summary = enterpriseKeyReference.summary.ifBlank {
                        "Enterprise key rotation is required."
                    }
                )
            }
            PortfolioOptimizationEnterpriseKeyStatus.EXPIRED,
            PortfolioOptimizationEnterpriseKeyStatus.REVOKED,
            PortfolioOptimizationEnterpriseKeyStatus.MISCONFIGURED -> {
                val fallbackAllowed = retryPolicy.localFallbackAllowed
                issues += PortfolioOptimizationRemoteLearningTransportIssue(
                    type = if (fallbackAllowed) {
                        PortfolioOptimizationRemoteLearningTransportIssueType.LOCAL_FALLBACK_USED
                    } else {
                        PortfolioOptimizationRemoteLearningTransportIssueType.KEY_HEALTH_BLOCKED
                    },
                    blocking = !fallbackAllowed,
                    reasonCodes = buildList {
                        add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_HEALTH_BLOCKED)
                        when (enterpriseKeyReference.status) {
                            PortfolioOptimizationEnterpriseKeyStatus.REVOKED ->
                                add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_REVOKED)
                            PortfolioOptimizationEnterpriseKeyStatus.ROTATION_REQUIRED ->
                                add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_ROTATION_REQUIRED)
                            else -> Unit
                        }
                        if (fallbackAllowed) {
                            add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED)
                        }
                    },
                    summary = enterpriseKeyReference.summary.ifBlank {
                        "Enterprise key state blocks remote transport."
                    }
                )
                complianceDecision = if (fallbackAllowed) {
                    PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
                } else {
                    PortfolioOptimizationComplianceGateDecision.BLOCKED
                }
                complianceBlockReason = PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
                preDispatchFailureReason = when (enterpriseKeyReference.status) {
                    PortfolioOptimizationEnterpriseKeyStatus.EXPIRED ->
                        PortfolioOptimizationRemoteTransportFailureReason.KEY_EXPIRED
                    PortfolioOptimizationEnterpriseKeyStatus.REVOKED ->
                        PortfolioOptimizationRemoteTransportFailureReason.KEY_REVOKED
                    else -> PortfolioOptimizationRemoteTransportFailureReason.KEY_MISCONFIGURED
                }
                complianceSummary = if (fallbackAllowed) {
                    "Enterprise key state blocks remote transport, so the operation fell back locally."
                } else {
                    "Compliance gate blocked remote transport because the enterprise key is ${enterpriseKeyReference.status.name.lowercase().replace('_', ' ')}."
                }
            }
            else -> Unit
        }
        if (!credentialResolution.resolved &&
            credentialResolution.blockReason != PortfolioOptimizationTransportCredentialBlockReason.NONE
        ) {
            val fallbackAllowed = retryPolicy.localFallbackAllowed
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = if (fallbackAllowed) {
                    PortfolioOptimizationRemoteLearningTransportIssueType.LOCAL_FALLBACK_USED
                } else {
                    PortfolioOptimizationRemoteLearningTransportIssueType.KEY_HEALTH_BLOCKED
                },
                blocking = !fallbackAllowed,
                reasonCodes = buildList {
                    add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_HEALTH_BLOCKED)
                    if (fallbackAllowed) add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED)
                },
                summary = credentialResolution.summary.ifBlank {
                    "Credential resolution failed for the selected connector."
                }
            )
            complianceDecision = if (fallbackAllowed) {
                PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
            } else {
                PortfolioOptimizationComplianceGateDecision.BLOCKED
            }
            complianceBlockReason = when (credentialResolution.blockReason) {
                PortfolioOptimizationTransportCredentialBlockReason.COMPLIANCE_BLOCKED ->
                    PortfolioOptimizationComplianceBlockReason.REDACTION_REQUIRED
                PortfolioOptimizationTransportCredentialBlockReason.ROLE_POLICY_BLOCKED ->
                    PortfolioOptimizationComplianceBlockReason.ROLE_POLICY_BLOCKED
                else -> PortfolioOptimizationComplianceBlockReason.KEY_HEALTH_BLOCKED
            }
            preDispatchFailureReason = when (credentialResolution.blockReason) {
                PortfolioOptimizationTransportCredentialBlockReason.KEY_MISSING ->
                    PortfolioOptimizationRemoteTransportFailureReason.KEY_MISSING
                PortfolioOptimizationTransportCredentialBlockReason.KEY_EXPIRED ->
                    PortfolioOptimizationRemoteTransportFailureReason.KEY_EXPIRED
                PortfolioOptimizationTransportCredentialBlockReason.KEY_REVOKED ->
                    PortfolioOptimizationRemoteTransportFailureReason.KEY_REVOKED
                PortfolioOptimizationTransportCredentialBlockReason.KEY_MISCONFIGURED ->
                    PortfolioOptimizationRemoteTransportFailureReason.KEY_MISCONFIGURED
                PortfolioOptimizationTransportCredentialBlockReason.CONNECTOR_UNHEALTHY ->
                    PortfolioOptimizationRemoteTransportFailureReason.CONNECTOR_UNHEALTHY
                else -> PortfolioOptimizationRemoteTransportFailureReason.COMPLIANCE_BLOCKED
            }
            complianceSummary = credentialResolution.summary.ifBlank {
                "Compliance gate blocked remote transport because credential resolution failed."
            }
        }
        val complianceGateResult = PortfolioOptimizationComplianceGateResult(
            decision = complianceDecision,
            blockReason = complianceBlockReason,
            redactionEnforced = true,
            localFallbackAllowed =
                retryPolicy.localFallbackAllowed && destinationDecision.residencyPolicy.localFallbackAllowed,
            summary = complianceSummary,
            checkedAtMs = now
        )
        val transportSummary = connectorRuntime.transportSummary.copy(
            connectorSummary = connectorRuntime.transportSummary.connectorSummary.ifBlank {
                connectorBinding.summary
            },
            keySummary = connectorRuntime.transportSummary.keySummary.ifBlank {
                enterpriseKeyReference?.summary.orEmpty()
            },
            complianceSummary = listOfNotNull(
                complianceGateResult.summary.takeIf { it.isNotBlank() },
                destinationDecision.summary.takeIf { it.isNotBlank() }
            ).joinToString(" "),
            summary = connectorRuntime.transportSummary.summary.ifBlank {
                listOfNotNull(
                    connectorRuntime.transportSummary.connectorSummary.takeIf { it.isNotBlank() },
                    enterpriseKeyReference?.summary?.takeIf { it.isNotBlank() },
                    complianceGateResult.summary.takeIf { it.isNotBlank() },
                    destinationDecision.summary.takeIf { it.isNotBlank() },
                    destinationDecision.residencyPolicy.summary.takeIf { it.isNotBlank() }
                ).joinToString(" ")
            }
        )
        val batch = PortfolioOptimizationRemoteLearningBatch(
            batchId = "portfolio_remote_batch_${envelopeId.takeLast(8)}_$now",
            transportMode = remoteLearningTransportPort.transportMode,
            purpose = purpose,
            remoteEnvelopeIds = listOf(remoteEnvelope.remoteEnvelopeId),
            idempotencyKey = "portfolio_remote:${syncEnvelope.envelopeId}:${purpose.name}:${remoteLearningTransportPort.transportMode.name}",
            envelopeCount = 1,
            artifactCount = remoteEnvelope.artifactCount,
            payloadHash = remoteEnvelope.payloadHash,
            summary = "Remote learning batch carries ${remoteEnvelope.artifactCount} redacted learning artifact(s).",
            createdAtMs = now
        )
        val dataExchangeEvaluation = evaluatePortfolioOptimizationDataExchangeBundle(
            purpose = purpose,
            sourceId = batch.batchId,
            bundleType = PortfolioOptimizationSafeDestinationBundleType.LEARNING_ARTIFACT_EXCHANGE,
            artifacts = buildPortfolioOptimizationRemoteTransportDataExchangeArtifacts(remoteEnvelope),
            destinationSelection = routeSelection,
            connectorProfile = connectorProfile,
            enterpriseKeyReference = enterpriseKeyReference,
            complianceDecision = complianceGateResult.decision,
            consentAllowed = consentRecord?.decision == PortfolioOptimizationConsentDecision.ALLOWED,
            rolePolicyAllowed = enterprisePrivacy.remoteTransportAllowedByRolePolicy,
            privacyPolicyAllowed = privacyPolicy.cloudSyncAllowed ||
                syncEnvelope.mode == PortfolioOptimizationLearningSyncMode.LOCAL_ONLY,
            now = now
        )
        val priorAttemptsForBatch = synchronized(dynamicStateLock) {
            portfolioOptimizationRemoteLearningTransportAttemptsByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { it.idempotencyKey == batch.idempotencyKey }
        }
        val duplicateAttempt = synchronized(dynamicStateLock) {
            priorAttemptsForBatch.firstOrNull {
                it.status !in setOf(
                    PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED,
                    PortfolioOptimizationRemoteLearningDeliveryStatus.RETRY_SCHEDULED
                )
            }
        }
        val priorRetryCount = priorAttemptsForBatch.maxOfOrNull {
            it.deliveryResult?.retryCount ?: 0
        } ?: 0
        val delivery = if (
            issues.any { it.blocking } ||
            complianceGateResult.decision == PortfolioOptimizationComplianceGateDecision.BLOCKED ||
            complianceGateResult.decision == PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
        ) {
            null
        } else if (duplicateAttempt != null) {
            RemoteLearningTransportDelivery(
                status = PortfolioOptimizationRemoteLearningDeliveryStatus.DEDUPED,
                issues = listOf(
                    PortfolioOptimizationRemoteLearningTransportIssue(
                        type = PortfolioOptimizationRemoteLearningTransportIssueType.DUPLICATE_BATCH_SKIPPED,
                        blocking = false,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEDUPED),
                        summary = "Duplicate remote learning batch was skipped by idempotency key."
                    )
                ),
                ackRecord = duplicateAttempt.ackRecord,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEDUPED),
                summary = "Duplicate remote learning batch was skipped by idempotency key."
            )
        } else {
            remoteLearningTransportPort.deliver(batch, now)
        }
        val deliveryResult = when {
            duplicateAttempt != null && delivery != null ->
                PortfolioOptimizationRemoteTransportDeliveryResult(
                    status = PortfolioOptimizationRemoteLearningDeliveryStatus.DEDUPED,
                    retryCount = priorRetryCount,
                    deduplicated = true,
                    summary = delivery.summary
                )
            complianceGateResult.decision == PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK ->
                PortfolioOptimizationRemoteTransportDeliveryResult(
                    status = PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK,
                    failureReason = preDispatchFailureReason,
                    retryCount = priorRetryCount,
                    localFallbackUsed = true,
                    summary = complianceGateResult.summary
                )
            complianceGateResult.decision == PortfolioOptimizationComplianceGateDecision.BLOCKED ->
                PortfolioOptimizationRemoteTransportDeliveryResult(
                    status = PortfolioOptimizationRemoteLearningDeliveryStatus.BLOCKED,
                    failureReason = preDispatchFailureReason,
                    retryCount = priorRetryCount,
                    summary = complianceGateResult.summary
                )
            delivery?.status == PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED -> {
                val nextRetryCount = priorRetryCount + 1
                if (nextRetryCount < retryPolicy.maxAttempts) {
                    issues += PortfolioOptimizationRemoteLearningTransportIssue(
                        type = PortfolioOptimizationRemoteLearningTransportIssueType.RETRY_SCHEDULED,
                        blocking = false,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_RETRIED),
                        summary = "Connector delivery failed and retry $nextRetryCount/${retryPolicy.maxAttempts} was scheduled."
                    )
                    PortfolioOptimizationRemoteTransportDeliveryResult(
                        status = PortfolioOptimizationRemoteLearningDeliveryStatus.RETRY_SCHEDULED,
                        failureReason = delivery.failureReason,
                        retryCount = nextRetryCount,
                        summary = "Connector delivery failed and retry $nextRetryCount/${retryPolicy.maxAttempts} was scheduled."
                    )
                } else {
                    val failureReason = if (
                        delivery.failureReason == PortfolioOptimizationRemoteTransportFailureReason.NONE
                    ) {
                        PortfolioOptimizationRemoteTransportFailureReason.RETRY_EXHAUSTED
                    } else {
                        delivery.failureReason
                    }
                    if (retryPolicy.deadLetterAfterMaxAttempts) {
                        PortfolioOptimizationRemoteTransportDeliveryResult(
                            status = if (retryPolicy.localFallbackAllowed) {
                                PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK
                            } else {
                                PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED
                            },
                            failureReason = failureReason,
                            retryCount = nextRetryCount,
                            localFallbackUsed = retryPolicy.localFallbackAllowed,
                            summary = if (retryPolicy.localFallbackAllowed) {
                                "Connector delivery failed after $nextRetryCount attempts; local fallback was used."
                            } else {
                                "Connector delivery failed after $nextRetryCount attempts and was dead-lettered."
                            }
                        )
                    } else {
                        PortfolioOptimizationRemoteTransportDeliveryResult(
                            status = PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED,
                            failureReason = failureReason,
                            retryCount = nextRetryCount,
                            summary = delivery.summary
                        )
                    }
                }
            }
            else -> PortfolioOptimizationRemoteTransportDeliveryResult(
                status = delivery?.status ?: PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED,
                failureReason = delivery?.failureReason ?: PortfolioOptimizationRemoteTransportFailureReason.NONE,
                retryCount = priorRetryCount,
                summary = delivery?.summary.orEmpty()
            )
        }
        val status = deliveryResult.status
        val deadLetterRecord = if (
            status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED ||
            (status == PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK &&
                deliveryResult.failureReason != PortfolioOptimizationRemoteTransportFailureReason.NONE &&
                duplicateAttempt == null &&
                complianceGateResult.decision != PortfolioOptimizationComplianceGateDecision.LOCAL_FALLBACK
                )
        ) {
            PortfolioOptimizationRemoteTransportDeadLetterRecord(
                deadLetterId = "portfolio_remote_dead_letter_${envelopeId.takeLast(8)}_$now",
                attemptId = "portfolio_remote_transport_${envelopeId.takeLast(8)}_$now",
                batchId = batch.batchId,
                remoteEnvelopeId = remoteEnvelope.remoteEnvelopeId,
                connectorProfileId = connectorProfile.profileId,
                failureReason = deliveryResult.failureReason,
                localFallbackUsed = deliveryResult.localFallbackUsed,
                summary = if (deliveryResult.localFallbackUsed) {
                    "Connector delivery exhausted retries and fell back to local-first handling."
                } else {
                    "Connector delivery exhausted retries and was dead-lettered."
                },
                createdAtMs = now
            )
        } else {
            null
        }
        if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.DEAD_LETTERED,
                blocking = false,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEAD_LETTERED),
                summary = deadLetterRecord?.summary ?: "Connector delivery was dead-lettered."
            )
        }
        if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK) {
            issues += PortfolioOptimizationRemoteLearningTransportIssue(
                type = PortfolioOptimizationRemoteLearningTransportIssueType.LOCAL_FALLBACK_USED,
                blocking = false,
                reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED),
                summary = deliveryResult.summary.ifBlank {
                    "Remote delivery fell back to local-first handling."
                }
            )
        }
        val attempt = PortfolioOptimizationRemoteLearningTransportAttemptRecord(
            attemptId = "portfolio_remote_transport_${envelopeId.takeLast(8)}_$now",
            batchId = batch.batchId,
            remoteEnvelopeId = remoteEnvelope.remoteEnvelopeId,
            transportMode = remoteLearningTransportPort.transportMode,
            purpose = purpose,
            status = status,
            idempotencyKey = batch.idempotencyKey,
            consentDecision = consentRecord?.decision,
            connectorBinding = connectorBinding,
            destinationDecision = destinationDecision,
            enterpriseKeyReference = enterpriseKeyReference,
            credentialResolution = credentialResolution,
            complianceGateResult = complianceGateResult,
            transportSummary = transportSummary,
            deliveryResult = deliveryResult,
            deadLetterRecordId = deadLetterRecord?.deadLetterId,
            dataExchangeBundle = dataExchangeEvaluation.bundle,
            bundleDecision = dataExchangeEvaluation.decision,
            dataExchangeManifest = dataExchangeEvaluation.manifest,
            crossBoundaryApprovalRecordId = dataExchangeEvaluation.approval.approvalId,
            crossBoundaryAuditRecordIds = dataExchangeEvaluation.audits.map { it.auditId },
            privacySummary = enterprisePrivacy.summary,
            issues = (issues + delivery?.issues.orEmpty()).distinctBy { "${it.type}:${it.summary}" },
            ackRecord = delivery?.ackRecord,
            reasonCodes = buildList {
                add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_CONNECTOR_SELECTED)
                addAll(destinationDecision.reasonCodes)
                addAll(dataExchangeEvaluation.decision.reasonCodes)
                addAll(dataExchangeEvaluation.approval.reasonCodes)
                addAll(dataExchangeEvaluation.audits.flatMap { it.reasonCodes })
                addAll(issues.flatMap { it.reasonCodes })
                addAll(delivery?.reasonCodes.orEmpty())
                if (complianceGateResult.decision == PortfolioOptimizationComplianceGateDecision.BLOCKED) {
                    add(RoleReasonCodes.ROLE_COMPLIANCE_GATE_BLOCKED)
                }
                if (connectorProfile.healthStatus == PortfolioOptimizationRemoteTransportConnectorHealthStatus.DEGRADED ||
                    connectorProfile.healthStatus == PortfolioOptimizationRemoteTransportConnectorHealthStatus.UNHEALTHY
                ) {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_CONNECTOR_DEGRADED)
                }
                when (enterpriseKeyReference?.status) {
                    PortfolioOptimizationEnterpriseKeyStatus.REVOKED -> add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_REVOKED)
                    PortfolioOptimizationEnterpriseKeyStatus.ROTATION_REQUIRED -> add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_ROTATION_REQUIRED)
                    PortfolioOptimizationEnterpriseKeyStatus.EXPIRED,
                    PortfolioOptimizationEnterpriseKeyStatus.MISCONFIGURED -> add(RoleReasonCodes.ROLE_ENTERPRISE_KEY_HEALTH_BLOCKED)
                    else -> Unit
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_ONLY) {
                    add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_LOCAL_ONLY)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK) {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_LOCAL_FALLBACK_USED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.QUEUED) {
                    add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_QUEUED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.RETRY_SCHEDULED) {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_RETRIED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.ACKED) {
                    add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_ACKED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEDUPED) {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEDUPED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED) {
                    add(RoleReasonCodes.ROLE_REMOTE_TRANSPORT_DELIVERY_DEAD_LETTERED)
                }
                if (status == PortfolioOptimizationRemoteLearningDeliveryStatus.FAILED) {
                    add(RoleReasonCodes.ROLE_REMOTE_LEARNING_TRANSPORT_FAILED)
                }
            }.distinct(),
            summary = when {
                status == PortfolioOptimizationRemoteLearningDeliveryStatus.BLOCKED ->
                    complianceGateResult.summary.ifBlank {
                        issues.firstOrNull { it.blocking }?.summary
                        ?: "Remote learning transport was blocked."
                    }
                status == PortfolioOptimizationRemoteLearningDeliveryStatus.LOCAL_FALLBACK ->
                    deliveryResult.summary.ifBlank {
                        "Remote delivery fell back to local-first handling."
                    }
                status == PortfolioOptimizationRemoteLearningDeliveryStatus.RETRY_SCHEDULED ->
                    deliveryResult.summary
                status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED ->
                    deadLetterRecord?.summary ?: deliveryResult.summary
                else -> delivery?.summary.orEmpty()
            },
            processedAtMs = now
        )
        routeSelection.destinationProfiles.forEach { storePortfolioOptimizationRemoteDestinationProfile(userId, it) }
        storePortfolioOptimizationRemoteDestinationDecision(userId, destinationDecision)
        storePortfolioOptimizationRemoteTransportConnectorProfile(userId, connectorProfile)
        enterpriseKeyReference?.let { storePortfolioOptimizationEnterpriseKeyReference(userId, it) }
        storePortfolioOptimizationRemoteLearningEnvelope(userId, remoteEnvelope)
        storePortfolioOptimizationRemoteLearningBatch(userId, batch)
        storePortfolioOptimizationDataExchangeBundle(userId, dataExchangeEvaluation.bundle)
        storePortfolioOptimizationDataExchangeBundleDecision(userId, dataExchangeEvaluation.decision)
        storePortfolioOptimizationDataExchangeManifest(userId, dataExchangeEvaluation.manifest)
        storePortfolioOptimizationCrossBoundaryApproval(userId, dataExchangeEvaluation.approval)
        dataExchangeEvaluation.audits.forEach { storePortfolioOptimizationCrossBoundaryAudit(userId, it) }
        storePortfolioOptimizationRemoteLearningTransportAttempt(userId, attempt)
        deadLetterRecord?.let { storePortfolioOptimizationRemoteTransportDeadLetter(userId, it) }
        synchronized(dynamicStateLock) {
            recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(userId, now)
        }
        persistDynamicState(userId)
        return attempt
    }

    fun requestPortfolioOptimizationComplianceAuditExport(
        userId: String,
        request: PortfolioOptimizationComplianceAuditExportRequest
    ): PortfolioOptimizationComplianceAuditExportResult {
        if (userId.isBlank()) {
            return PortfolioOptimizationComplianceAuditExportResult(
                requestId = request.requestId,
                status = PortfolioOptimizationComplianceAuditExportStatus.BLOCKED,
                reasonCodes = listOf(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_CONSENT),
                issueSummary = "Compliance audit export failed: missing user identity.",
                summary = "Compliance audit export failed: missing user identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
        val objectiveProfileSnapshot = synchronized(dynamicStateLock) {
            request.objectiveProfileSnapshotId
                ?.takeIf { it.isNotBlank() }
                ?.let { findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, it) }
                ?: activePortfolioOptimizationObjectiveProfileSnapshot(userId, now)
        }
        val binding = resolvePortfolioOptimizationScopeBinding(userId, objectiveProfileSnapshot.binding)
        val learningSyncConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                binding = binding,
                now = now
            )
        }
        val remoteTransportConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT,
                binding = binding,
                now = now
            )
        }
        val auditConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                binding = binding,
                now = now
            )
        }
        val enterprisePrivacy = derivePortfolioOptimizationEnterprisePrivacyPolicySummary(
            userId = userId,
            binding = binding,
            activeRole = activeRole,
            learningSyncConsent = learningSyncConsent,
            remoteTransportConsent = remoteTransportConsent,
            auditExportConsent = auditConsent
        )
        val normalizedRequest = request.copy(
            requestId = request.requestId.ifBlank { "portfolio_audit_export_${userId.takeLast(8)}_$now" },
            objectiveProfileSnapshotId = request.objectiveProfileSnapshotId ?: objectiveProfileSnapshot.snapshotId,
            purposes = request.purposes.ifEmpty { listOf(PortfolioOptimizationConsentPurpose.AUDIT_EXPORT) },
            summary = request.summary.ifBlank {
                "Redaction-first compliance audit export for ${binding.tenantId ?: "tenant_default"}."
            },
            requestedAtMs = request.requestedAtMs.takeIf { it > 0L } ?: now
        )
        val auditConnectorRuntime = remoteLearningTransportPort.inspect(
            purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
            nowMs = now
        )
        val auditConnectorProfile = auditConnectorRuntime.connectorProfile.copy(
            updatedAtMs = now,
            summary = auditConnectorRuntime.connectorProfile.summary.ifBlank {
                auditConnectorRuntime.connectorProfile.displayName.ifBlank {
                    auditConnectorRuntime.connectorProfile.type.name.lowercase().replace('_', ' ')
                }
            }
        )
        val auditEnterpriseKeyReference = auditConnectorRuntime.enterpriseKeyReference?.copy(
            connectorProfileId = auditConnectorRuntime.enterpriseKeyReference.connectorProfileId.ifBlank {
                auditConnectorProfile.profileId
            },
            updatedAtMs = now,
            summary = auditConnectorRuntime.enterpriseKeyReference.summary.ifBlank {
                "Enterprise key ${auditConnectorRuntime.enterpriseKeyReference.keyRefId} is ${auditConnectorRuntime.enterpriseKeyReference.status.name.lowercase().replace('_', ' ')}."
            }
        )
        val auditCredentialResolution = auditConnectorRuntime.credentialResolution.copy(
            connectorProfileId = auditConnectorRuntime.credentialResolution.connectorProfileId.ifBlank {
                auditConnectorProfile.profileId
            },
            keyRefId = auditConnectorRuntime.credentialResolution.keyRefId
                ?: auditEnterpriseKeyReference?.keyRefId,
            checkedAtMs = now,
            summary = auditConnectorRuntime.credentialResolution.summary.ifBlank {
                if (auditConnectorRuntime.credentialResolution.resolved) {
                    "Audit export connector credential resolved successfully."
                } else {
                    "Audit export connector credential resolution failed."
                }
            }
        )
        val destinationSelection = evaluatePortfolioOptimizationRemoteDestinationRoute(
            purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
            sourceId = normalizedRequest.requestId,
            binding = binding,
            connectorProfile = auditConnectorProfile,
            privacyPolicy = null,
            enterprisePrivacy = enterprisePrivacy,
            consentRecord = auditConsent,
            enterpriseKeyReference = auditEnterpriseKeyReference,
            credentialResolution = auditCredentialResolution,
            preferredDestinationId = normalizedRequest.preferredDestinationId,
            preferredDestinationType = normalizedRequest.preferredDestinationType,
            now = now
        )
        val destinationDecision = destinationSelection.decision
        val resultId = "portfolio_audit_result_${normalizedRequest.requestId.takeLast(8)}_$now"
        val blockedByConsent = auditConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED
        val blockedByPolicy = !enterprisePrivacy.auditExportAllowedByRolePolicy
        val blockedByDestination = destinationDecision.status in setOf(
            PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION,
            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY
        )
        val heldForCompliance =
            destinationDecision.status == PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE
        val complianceGateResult = PortfolioOptimizationComplianceGateResult(
            decision = if (blockedByConsent || blockedByPolicy || blockedByDestination || heldForCompliance) {
                PortfolioOptimizationComplianceGateDecision.BLOCKED
            } else {
                PortfolioOptimizationComplianceGateDecision.ALLOWED_WITH_REDACTION
            },
            blockReason = when {
                blockedByConsent -> PortfolioOptimizationComplianceBlockReason.CONSENT_DENIED
                blockedByPolicy -> PortfolioOptimizationComplianceBlockReason.ROLE_POLICY_BLOCKED
                heldForCompliance -> PortfolioOptimizationComplianceBlockReason.REVIEW_REQUIRED
                destinationDecision.status ==
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY ->
                    PortfolioOptimizationComplianceBlockReason.RESIDENCY_BLOCKED
                destinationDecision.status ==
                    PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION ->
                    PortfolioOptimizationComplianceBlockReason.JURISDICTION_BLOCKED
                blockedByDestination -> PortfolioOptimizationComplianceBlockReason.DESTINATION_POLICY_BLOCKED
                else -> PortfolioOptimizationComplianceBlockReason.NONE
            },
            redactionEnforced = true,
            localFallbackAllowed = destinationDecision.residencyPolicy.localFallbackAllowed,
            summary = when {
                blockedByConsent -> auditConsent?.summary?.takeIf { it.isNotBlank() }
                    ?: "Compliance gate blocked audit export until consent is explicitly allowed."
                blockedByPolicy -> enterprisePrivacy.summary.ifBlank {
                    "Compliance gate blocked audit export because role policy denied it."
                }
                heldForCompliance -> destinationDecision.summary
                blockedByDestination -> destinationDecision.summary
                else -> "Compliance gate allowed a redaction-first audit export bundle."
            },
            checkedAtMs = now
        )
        val transportSummary = PortfolioOptimizationComplianceTransportSummary(
            connectorSummary = auditConnectorProfile.summary.ifBlank {
                "Audit export remains local-first and in-process."
            },
            keySummary = auditEnterpriseKeyReference?.summary.orEmpty(),
            complianceSummary = complianceGateResult.summary,
            summary = listOfNotNull(
                auditConnectorProfile.summary.takeIf { it.isNotBlank() },
                auditEnterpriseKeyReference?.summary?.takeIf { it.isNotBlank() },
                destinationDecision.summary.takeIf { it.isNotBlank() },
                destinationDecision.residencyPolicy.summary.takeIf { it.isNotBlank() },
                complianceGateResult.summary.takeIf { it.isNotBlank() }
            ).joinToString(" ").ifBlank {
                "Audit export is evaluated locally with redaction-first compliance controls."
            }
        )
        val exportRoute = PortfolioOptimizationComplianceExportRouteRecord(
            routeId = "portfolio_export_route_${normalizedRequest.requestId.takeLast(8)}_$now",
            requestId = normalizedRequest.requestId,
            resultId = resultId,
            destinationDecisionId = destinationDecision.decisionId,
            destinationId = destinationDecision.selectedDestinationId,
            destinationType = destinationDecision.selectedDestinationType,
            status = when (destinationDecision.status) {
                PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED ->
                    if (portfolioOptimizationIsLocalDestination(destinationDecision.selectedDestinationType)) {
                        PortfolioOptimizationComplianceExportRouteStatus.LOCAL_ARCHIVED
                    } else {
                        PortfolioOptimizationComplianceExportRouteStatus.REMOTE_ARCHIVED
                    }
                PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED ->
                    PortfolioOptimizationComplianceExportRouteStatus.REROUTED
                PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ->
                    PortfolioOptimizationComplianceExportRouteStatus.HELD
                PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                    PortfolioOptimizationComplianceExportRouteStatus.LOCAL_ONLY_FALLBACK
                PortfolioOptimizationRemoteDestinationDecisionStatus.SUPPRESSED ->
                    PortfolioOptimizationComplianceExportRouteStatus.SUPPRESSED
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY,
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION,
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY ->
                    PortfolioOptimizationComplianceExportRouteStatus.BLOCKED
            },
            residencyRegion = destinationDecision.residencyRegion,
            jurisdiction = destinationDecision.jurisdiction,
            locationRef = "",
            reasonCodes = destinationDecision.reasonCodes,
            summary = destinationDecision.summary,
            createdAtMs = now
        )
        val auditDataBundle = buildPortfolioOptimizationComplianceAuditExportBundle(
            userId = userId,
            request = normalizedRequest,
            enterprisePrivacy = enterprisePrivacy,
            now = now
        )
        val dataExchangeEvaluation = evaluatePortfolioOptimizationDataExchangeBundle(
            purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
            sourceId = normalizedRequest.requestId,
            bundleType = PortfolioOptimizationSafeDestinationBundleType.COMPLIANCE_AUDIT_EXCHANGE,
            artifacts = buildPortfolioOptimizationComplianceAuditDataExchangeArtifacts(auditDataBundle),
            destinationSelection = destinationSelection,
            connectorProfile = auditConnectorProfile,
            enterpriseKeyReference = auditEnterpriseKeyReference,
            complianceDecision = complianceGateResult.decision,
            consentAllowed = auditConsent?.decision == PortfolioOptimizationConsentDecision.ALLOWED,
            rolePolicyAllowed = enterprisePrivacy.auditExportAllowedByRolePolicy,
            privacyPolicyAllowed = true,
            now = now
        )
        val result = if (blockedByConsent || blockedByPolicy || blockedByDestination || heldForCompliance) {
            PortfolioOptimizationComplianceAuditExportResult(
                resultId = resultId,
                requestId = normalizedRequest.requestId,
                status = PortfolioOptimizationComplianceAuditExportStatus.BLOCKED,
                hashSummary = PortfolioOptimizationComplianceAuditHashSummary(),
                redactionSummary = normalizedRequest.redactionPolicy.summary.ifBlank {
                    "Audit export remains redaction-first and excludes raw prompts and messages."
                },
                destinationDecision = destinationDecision,
                exportRoute = exportRoute,
                complianceGateResult = complianceGateResult,
                transportSummary = transportSummary,
                issueSummary = when {
                    blockedByConsent -> auditConsent?.summary?.takeIf { it.isNotBlank() }
                        ?: "Compliance audit export is blocked until consent is explicitly allowed."
                    blockedByPolicy -> enterprisePrivacy.summary
                    else -> destinationDecision.summary
                },
                accessRecord = PortfolioOptimizationComplianceAuditExportAccessRecord(
                    accessId = "portfolio_audit_access_${normalizedRequest.requestId.takeLast(8)}_$now",
                    requestId = normalizedRequest.requestId,
                    operatorId = normalizedRequest.requestedByOperatorId,
                    operatorName = normalizedRequest.requestedByOperatorName
                        ?.takeUnless { normalizedRequest.redactionPolicy.operatorNamesRedacted },
                    consentRecordId = auditConsent?.consentId,
                    authority = auditConsent?.provenance?.authority,
                    purposes = normalizedRequest.purposes,
                    summary = "Compliance export request was evaluated against consent and role policy.",
                    accessedAtMs = now
                ),
                dataExchangeBundle = dataExchangeEvaluation.bundle,
                bundleDecision = dataExchangeEvaluation.decision,
                dataExchangeManifest = dataExchangeEvaluation.manifest,
                crossBoundaryApprovalRecordId = dataExchangeEvaluation.approval.approvalId,
                crossBoundaryAuditRecordIds = dataExchangeEvaluation.audits.map { it.auditId },
                reasonCodes = buildList {
                    add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_REQUESTED)
                    add(RoleReasonCodes.ROLE_COMPLIANCE_GATE_BLOCKED)
                    addAll(destinationDecision.reasonCodes)
                    addAll(dataExchangeEvaluation.decision.reasonCodes)
                    addAll(dataExchangeEvaluation.approval.reasonCodes)
                    addAll(dataExchangeEvaluation.audits.flatMap { it.reasonCodes })
                    if (blockedByConsent) add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_CONSENT)
                    if (blockedByPolicy) add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_BLOCKED_BY_POLICY)
                }.distinct(),
                summary = when {
                    blockedByConsent -> "Compliance audit export blocked by consent."
                    blockedByPolicy -> "Compliance audit export blocked by role policy."
                    heldForCompliance -> "Compliance audit export is held for compliance review."
                    else -> "Compliance audit export is blocked by destination routing policy. ${dataExchangeEvaluation.decision.summary}"
                },
                completedAtMs = now
            )
        } else {
            val bundle = auditDataBundle
            val routedLocation = when (exportRoute.status) {
                PortfolioOptimizationComplianceExportRouteStatus.REMOTE_ARCHIVED ->
                    "memory://portfolio-audit/${bundle.bundleId}.${normalizedRequest.format.name.lowercase()}#remote-approved"
                else ->
                    "memory://portfolio-audit/${bundle.bundleId}.${normalizedRequest.format.name.lowercase()}"
            }
            PortfolioOptimizationComplianceAuditExportResult(
                resultId = resultId,
                requestId = normalizedRequest.requestId,
                status = PortfolioOptimizationComplianceAuditExportStatus.COMPLETE,
                bundle = bundle,
                locationRef = routedLocation,
                hashSummary = bundle.hashSummary,
                redactionSummary = normalizedRequest.redactionPolicy.summary.ifBlank {
                    "Audit export is redaction-first and excludes raw prompts and messages."
                },
                destinationDecision = destinationDecision,
                exportRoute = exportRoute.copy(locationRef = routedLocation),
                complianceGateResult = complianceGateResult,
                transportSummary = transportSummary,
                issueSummary = "",
                accessRecord = PortfolioOptimizationComplianceAuditExportAccessRecord(
                    accessId = "portfolio_audit_access_${normalizedRequest.requestId.takeLast(8)}_$now",
                    requestId = normalizedRequest.requestId,
                    operatorId = normalizedRequest.requestedByOperatorId,
                    operatorName = normalizedRequest.requestedByOperatorName
                        ?.takeUnless { normalizedRequest.redactionPolicy.operatorNamesRedacted },
                    consentRecordId = auditConsent?.consentId,
                    authority = auditConsent?.provenance?.authority,
                    purposes = normalizedRequest.purposes,
                    summary = "Compliance audit export access was granted with redaction-first controls.",
                    accessedAtMs = now
                ),
                dataExchangeBundle = dataExchangeEvaluation.bundle,
                bundleDecision = dataExchangeEvaluation.decision,
                dataExchangeManifest = dataExchangeEvaluation.manifest,
                crossBoundaryApprovalRecordId = dataExchangeEvaluation.approval.approvalId,
                crossBoundaryAuditRecordIds = dataExchangeEvaluation.audits.map { it.auditId },
                reasonCodes = buildList {
                    add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_REQUESTED)
                    add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_ALLOWED)
                    add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_REDACTION_ENFORCED)
                    add(RoleReasonCodes.ROLE_COMPLIANCE_EXPORT_GENERATED)
                    addAll(destinationDecision.reasonCodes)
                    addAll(dataExchangeEvaluation.decision.reasonCodes)
                    addAll(dataExchangeEvaluation.approval.reasonCodes)
                    addAll(dataExchangeEvaluation.audits.flatMap { it.reasonCodes })
                }.distinct(),
                summary = listOf(bundle.summary, dataExchangeEvaluation.decision.summary)
                    .filter { it.isNotBlank() }
                    .joinToString(" "),
                completedAtMs = now
            )
        }
        destinationSelection.destinationProfiles.forEach {
            storePortfolioOptimizationRemoteDestinationProfile(userId, it)
        }
        storePortfolioOptimizationRemoteDestinationDecision(userId, destinationDecision)
        storePortfolioOptimizationComplianceExportRoute(
            userId,
            result.exportRoute ?: exportRoute
        )
        storePortfolioOptimizationDataExchangeBundle(userId, dataExchangeEvaluation.bundle)
        storePortfolioOptimizationDataExchangeBundleDecision(userId, dataExchangeEvaluation.decision)
        storePortfolioOptimizationDataExchangeManifest(userId, dataExchangeEvaluation.manifest)
        storePortfolioOptimizationCrossBoundaryApproval(userId, dataExchangeEvaluation.approval)
        dataExchangeEvaluation.audits.forEach { storePortfolioOptimizationCrossBoundaryAudit(userId, it) }
        storePortfolioOptimizationRemoteTransportConnectorProfile(userId, auditConnectorProfile)
        auditEnterpriseKeyReference?.let { storePortfolioOptimizationEnterpriseKeyReference(userId, it) }
        storePortfolioOptimizationComplianceAuditExportRequest(userId, normalizedRequest)
        storePortfolioOptimizationComplianceAuditExportResult(userId, result)
        synchronized(dynamicStateLock) {
            recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(userId, now)
        }
        persistDynamicState(userId)
        return result
    }

    fun exportPortfolioOptimizationLearningSyncEnvelope(
        userId: String,
        objectiveProfileSnapshotId: String = "",
        calibrationSnapshotId: String = "",
        mode: PortfolioOptimizationLearningSyncMode =
            PortfolioOptimizationLearningSyncMode.DEVICE_SYNC,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationLearningSyncEnvelope {
        if (userId.isBlank()) {
            return PortfolioOptimizationLearningSyncEnvelope(
                mode = mode,
                issues = listOf(
                    PortfolioOptimizationLearningSyncIssue(
                        type = PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED,
                        blocking = true,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                        summary = "Learning sync export failed: missing user identity."
                    )
                ),
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                summary = "Learning sync export failed: missing user identity."
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
        val objectiveProfileSnapshot = synchronized(dynamicStateLock) {
            if (objectiveProfileSnapshotId.isNotBlank()) {
                findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, objectiveProfileSnapshotId)
            } else {
                activePortfolioOptimizationObjectiveProfileSnapshot(userId, now)
            }
        }
        val binding = objectiveProfileSnapshot
            ?.let { resolvePortfolioOptimizationScopeBinding(userId, it.binding) }
            ?: resolvePortfolioOptimizationScopeBinding(userId)
        val privacyPolicy = derivePortfolioOptimizationLearningSyncPrivacyPolicy(
            userId = userId,
            mode = mode,
            binding = binding,
            activeRole = activeRole
        )
        val learningSyncConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                binding = binding,
                now = now
            )
        }
        val boundary = derivePortfolioOptimizationFederatedAggregationBoundary(
            binding = binding,
            mode = mode,
            activeRole = activeRole
        )
        val groupKey = derivePortfolioOptimizationFederatedAggregationGroupKey(boundary, mode)
        val aggregationRule = defaultPortfolioOptimizationFederatedAggregationRule(mode)
        val redactionPolicy = PortfolioOptimizationLearningSyncRedactionPolicy(
            summary = "Raw user content, raw prompts, operator names, and evidence refs are removed before sync."
        )
        val issues = mutableListOf<PortfolioOptimizationLearningSyncIssue>()
        if (
            mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY &&
            learningSyncConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED
        ) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.CONSENT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_CONSENT_DENIED),
                summary = learningSyncConsent?.summary?.takeIf { it.isNotBlank() }
                    ?: "Learning sync export is blocked until consent is explicitly allowed."
            )
        }
        if (mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY && !privacyPolicy.cloudSyncAllowed) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                summary = privacyPolicy.summary.ifBlank {
                    "Privacy policy blocks cross-device learning sync."
                }
            )
        }
        if (mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY && activeRole == UserRole.PARENT) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.ROLE_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY),
                summary = "Parent role blocks cross-device learning sync."
            )
        }
        val calibrationSnapshot = synchronized(dynamicStateLock) {
            val explicitSnapshot = calibrationSnapshotId
                .takeIf { it.isNotBlank() }
                ?.let { findPortfolioOptimizationCalibrationSnapshotLocked(userId, it) }
            explicitSnapshot
                ?: resolvePortfolioOptimizationCalibrationSnapshotLocked(
                    userId = userId,
                    snapshotId = null,
                    objectiveProfileSnapshot = objectiveProfileSnapshot
                        ?: resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(userId, binding, now),
                    now = now
                )
        }
        val artifacts = synchronized(dynamicStateLock) {
            if (issues.any { it.blocking }) {
                emptyList()
            } else {
                portfolioOptimizationLearningSyncArtifactsLocked(
                    userId = userId,
                    objectiveProfileSnapshot = objectiveProfileSnapshot
                        ?: resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(userId, binding, now),
                    calibrationSnapshot = calibrationSnapshot
                )
            }
        }
        val envelope = PortfolioOptimizationLearningSyncEnvelope(
            envelopeId = "portfolio_sync_export_${userId.takeLast(8)}_${now}",
            mode = mode,
            boundary = boundary,
            groupKey = groupKey,
            aggregationRule = aggregationRule,
            privacyPolicy = privacyPolicy,
            redactionPolicy = redactionPolicy,
            provenance = portfolioOptimizationLearningSyncProvenance(
                userId = userId,
                binding = binding,
                operatorId = operatorId,
                operatorName = operatorName,
                now = now
            ),
            artifacts = artifacts,
            issues = issues,
            reasonCodes = buildList {
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.CONSENT_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_CONSENT_DENIED)
                }
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY)
                }
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.ROLE_POLICY_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY)
                }
                if (issues.isEmpty()) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_ENQUEUED)
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_DELIVERED)
                }
            }.distinct(),
            summary = when {
                issues.any { it.blocking } ->
                    "Learning sync export blocked for ${portfolioOptimizationLearningSyncModeLabel(mode)}."
                else ->
                    "Exported ${artifacts.size} redacted learning artifact(s) for ${portfolioOptimizationLearningSyncModeLabel(mode)}."
            },
            createdAtMs = now
        )
        val attempt = PortfolioOptimizationLearningSyncAttemptRecord(
            attemptId = "portfolio_sync_attempt_export_${userId.takeLast(8)}_${now}",
            direction = PortfolioOptimizationLearningSyncDirection.EXPORT,
            envelopeId = envelope.envelopeId,
            mode = envelope.mode,
            status = if (issues.any { it.blocking }) {
                PortfolioOptimizationLearningSyncStatus.BLOCKED
            } else {
                PortfolioOptimizationLearningSyncStatus.EXPORTED
            },
            boundary = envelope.boundary,
            groupKey = envelope.groupKey,
            privacyPolicy = envelope.privacyPolicy,
            provenance = envelope.provenance,
            artifactCount = envelope.artifacts.size,
            appliedArtifactCount = 0,
            conflictCount = 0,
            issues = envelope.issues,
            reasonCodes = envelope.reasonCodes.ifEmpty {
                listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_ENQUEUED)
            },
            summary = envelope.summary,
            processedAtMs = now
        )
        storePortfolioOptimizationLearningSyncEnvelope(userId, envelope)
        storePortfolioOptimizationLearningSyncAttempt(userId, attempt)
        recomputePortfolioOptimizationFederatedAggregationSummaries(userId, now)
        persistDynamicState(userId)
        return envelope
    }

    fun importPortfolioOptimizationLearningSyncEnvelope(
        userId: String,
        envelope: PortfolioOptimizationLearningSyncEnvelope,
        operatorId: String? = null,
        operatorName: String? = null
    ): PortfolioOptimizationLearningSyncAttemptRecord {
        if (userId.isBlank() || envelope.envelopeId.isBlank()) {
            return PortfolioOptimizationLearningSyncAttemptRecord(
                direction = PortfolioOptimizationLearningSyncDirection.IMPORT,
                envelopeId = envelope.envelopeId,
                mode = envelope.mode,
                status = PortfolioOptimizationLearningSyncStatus.BLOCKED,
                issues = listOf(
                    PortfolioOptimizationLearningSyncIssue(
                        type = PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED,
                        blocking = true,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                        summary = "Learning sync import failed: missing identity or envelope id."
                    )
                ),
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                summary = "Learning sync import failed: missing identity or envelope id.",
                processedAtMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
        val targetBinding = resolvePortfolioOptimizationScopeBinding(userId)
        val localObjectiveProfileSnapshot = activePortfolioOptimizationObjectiveProfileSnapshot(userId, now)
        val localBinding = localObjectiveProfileSnapshot.binding
        val localPrivacyPolicy = derivePortfolioOptimizationLearningSyncPrivacyPolicy(
            userId = userId,
            mode = envelope.mode,
            binding = localBinding,
            activeRole = activeRole
        )
        val learningSyncConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                binding = targetBinding,
                now = now
            )
        }
        val issues = mutableListOf<PortfolioOptimizationLearningSyncIssue>()
        val conflicts = mutableListOf<PortfolioOptimizationLearningSyncConflictRecord>()
        val redactionBlocked = !envelope.redactionPolicy.rawContentRemoved ||
            !envelope.redactionPolicy.rawPromptsRemoved ||
            !envelope.redactionPolicy.evidenceRefsRedacted ||
            !envelope.redactionPolicy.operatorNamesRedacted
        if (
            envelope.mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY &&
            learningSyncConsent?.decision != PortfolioOptimizationConsentDecision.ALLOWED
        ) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.CONSENT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_CONSENT_DENIED),
                summary = learningSyncConsent?.summary?.takeIf { it.isNotBlank() }
                    ?: "Learning sync import is blocked until consent is explicitly allowed."
            )
        }
        if (envelope.mode == PortfolioOptimizationLearningSyncMode.LOCAL_ONLY) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.ROLE_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY),
                summary = "Local-only learning envelopes are not eligible for cross-device import."
            )
        }
        if (redactionBlocked) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.RAW_CONTENT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                summary = "Learning sync import blocked because the envelope redaction policy is incomplete."
            )
        }
        if (!localPrivacyPolicy.cloudSyncAllowed && envelope.mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY),
                summary = localPrivacyPolicy.summary.ifBlank {
                    "Privacy policy blocks cross-device learning sync."
                }
            )
        }
        if (activeRole == UserRole.PARENT && envelope.mode != PortfolioOptimizationLearningSyncMode.LOCAL_ONLY) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.ROLE_POLICY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY),
                summary = "Parent role blocks cross-device learning sync."
            )
        }
        if (
            envelope.boundary.sameTenantOnly &&
            envelope.boundary.tenantId != null &&
            targetBinding.tenantId != null &&
            envelope.boundary.tenantId != targetBinding.tenantId
        ) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.CROSS_TENANT_BOUNDARY_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED),
                summary = "Learning sync import blocked because cross-tenant aggregation is disabled by default."
            )
        }
        if (
            envelope.mode == PortfolioOptimizationLearningSyncMode.DEVICE_SYNC &&
            envelope.provenance.sourceUserId.isNotBlank() &&
            envelope.provenance.sourceUserId != userId
        ) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.UNSAFE_ARTIFACT_BLOCKED,
                blocking = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED),
                summary = "Device-sync learning import requires the same user identity on both devices."
            )
        }
        val existingEnvelopes = synchronized(dynamicStateLock) {
            portfolioOptimizationLearningSyncEnvelopesByUser[userId]?.toList().orEmpty()
        }
        if (existingEnvelopes.any { it.envelopeId == envelope.envelopeId }) {
            issues += PortfolioOptimizationLearningSyncIssue(
                type = PortfolioOptimizationLearningSyncIssueType.DUPLICATE_ENVELOPE_SKIPPED,
                blocking = false,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_DELIVERED),
                summary = "Duplicate learning sync envelope ${envelope.envelopeId.takeLast(8)} was skipped."
            )
        }
        var appliedArtifactCount = 0
        if (issues.none { it.blocking }) {
            synchronized(dynamicStateLock) {
                envelope.artifacts.forEach { artifact ->
                    when (artifact.artifactType) {
                        PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT -> {
                            val snapshot = artifact.objectiveProfileSnapshot ?: return@forEach
                            if (
                                snapshot.binding.scope == PortfolioOptimizationLearningScope.USER &&
                                envelope.provenance.sourceUserId.isNotBlank() &&
                                envelope.provenance.sourceUserId != userId
                            ) {
                                issues += PortfolioOptimizationLearningSyncIssue(
                                    type = PortfolioOptimizationLearningSyncIssueType.UNSAFE_ARTIFACT_BLOCKED,
                                    blocking = true,
                                    artifactType = artifact.artifactType,
                                    artifactId = artifact.artifactId,
                                    reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED),
                                    summary = "User-scoped objective profile snapshots cannot cross users."
                                )
                                return@forEach
                            }
                            val local = findPortfolioOptimizationObjectiveProfileSnapshotLocked(
                                userId = userId,
                                snapshotId = snapshot.snapshotId
                            )
                            when {
                                local == null -> {
                                    storePortfolioOptimizationObjectiveProfileSnapshot(userId, snapshot)
                                    appliedArtifactCount += 1
                                }
                                portfolioOptimizationLearningSyncEnvelopeFingerprint(artifact) ==
                                    portfolioOptimizationLearningSyncEnvelopeFingerprint(
                                        PortfolioOptimizationLearningSyncArtifactEnvelope(
                                            artifactType = artifact.artifactType,
                                            artifactId = artifact.artifactId,
                                            artifactVersion = local.version,
                                            objectiveProfileSnapshot = local
                                        )
                                    ) -> Unit

                                else -> {
                                    conflicts += PortfolioOptimizationLearningSyncConflictRecord(
                                        conflictId = "portfolio_sync_conflict_${artifact.artifactId.takeLast(8)}_$now",
                                        envelopeId = envelope.envelopeId,
                                        artifactType = artifact.artifactType,
                                        artifactId = artifact.artifactId,
                                        localVersion = local.version,
                                        incomingVersion = snapshot.version,
                                        resolution = PortfolioOptimizationLearningSyncConflictResolution.REVIEW_REQUIRED,
                                        reviewRequired = true,
                                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED),
                                        summary = "Objective profile snapshot ${artifact.artifactId.takeLast(8)} differs locally and requires review.",
                                        detectedAtMs = now
                                    )
                                }
                            }
                        }

                        PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT -> {
                            val snapshot = artifact.calibrationSnapshot ?: return@forEach
                            if (
                                snapshot.objectiveProfileBinding.scope == PortfolioOptimizationLearningScope.USER &&
                                envelope.provenance.sourceUserId.isNotBlank() &&
                                envelope.provenance.sourceUserId != userId
                            ) {
                                issues += PortfolioOptimizationLearningSyncIssue(
                                    type = PortfolioOptimizationLearningSyncIssueType.UNSAFE_ARTIFACT_BLOCKED,
                                    blocking = true,
                                    artifactType = artifact.artifactType,
                                    artifactId = artifact.artifactId,
                                    reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED),
                                    summary = "User-scoped calibration snapshots cannot cross users."
                                )
                                return@forEach
                            }
                            val local = findPortfolioOptimizationCalibrationSnapshotLocked(
                                userId = userId,
                                snapshotId = snapshot.snapshotId
                            )
                            when {
                                local == null -> {
                                    storePortfolioOptimizationCalibrationSnapshot(userId, snapshot)
                                    appliedArtifactCount += 1
                                }
                                portfolioOptimizationLearningSyncEnvelopeFingerprint(artifact) ==
                                    portfolioOptimizationLearningSyncEnvelopeFingerprint(
                                        PortfolioOptimizationLearningSyncArtifactEnvelope(
                                            artifactType = artifact.artifactType,
                                            artifactId = artifact.artifactId,
                                            artifactVersion = local.version,
                                            calibrationSnapshot = local
                                        )
                                    ) -> Unit

                                else -> {
                                    conflicts += PortfolioOptimizationLearningSyncConflictRecord(
                                        conflictId = "portfolio_sync_conflict_${artifact.artifactId.takeLast(8)}_$now",
                                        envelopeId = envelope.envelopeId,
                                        artifactType = artifact.artifactType,
                                        artifactId = artifact.artifactId,
                                        localVersion = local.version,
                                        incomingVersion = snapshot.version,
                                        resolution = PortfolioOptimizationLearningSyncConflictResolution.REVIEW_REQUIRED,
                                        reviewRequired = true,
                                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED),
                                        summary = "Calibration snapshot ${artifact.artifactId.takeLast(8)} differs locally and requires review.",
                                        detectedAtMs = now
                                    )
                                }
                            }
                        }

                        PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY -> {
                            val drift = artifact.driftSummary ?: return@forEach
                            val local = portfolioOptimizationDriftSummariesByUser[userId]
                                ?.toList()
                                .orEmpty()
                                .firstOrNull { it.driftId == drift.driftId }
                            when {
                                local == null -> {
                                    storePortfolioOptimizationDriftSummary(userId, drift)
                                    appliedArtifactCount += 1
                                }
                                portfolioOptimizationLearningSyncEnvelopeFingerprint(artifact) ==
                                    portfolioOptimizationLearningSyncEnvelopeFingerprint(
                                        PortfolioOptimizationLearningSyncArtifactEnvelope(
                                            artifactType = artifact.artifactType,
                                            artifactId = artifact.artifactId,
                                            artifactVersion = artifact.artifactVersion,
                                            driftSummary = local
                                        )
                                    ) -> Unit

                                drift.createdAtMs > local.createdAtMs ||
                                    (
                                        drift.createdAtMs == local.createdAtMs &&
                                            envelope.envelopeId > existingEnvelopes
                                                .firstOrNull { prior ->
                                                    prior.artifacts.any { it.artifactId == artifact.artifactId }
                                                }
                                                ?.envelopeId
                                                .orEmpty()
                                        ) -> {
                                    storePortfolioOptimizationDriftSummary(userId, drift)
                                    conflicts += PortfolioOptimizationLearningSyncConflictRecord(
                                        conflictId = "portfolio_sync_conflict_${artifact.artifactId.takeLast(8)}_$now",
                                        envelopeId = envelope.envelopeId,
                                        artifactType = artifact.artifactType,
                                        artifactId = artifact.artifactId,
                                        localVersion = 1,
                                        incomingVersion = 1,
                                        resolution = PortfolioOptimizationLearningSyncConflictResolution.LAST_WRITE_WINS_INCOMING,
                                        reviewRequired = false,
                                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_RESOLVED),
                                        summary = "Incoming drift summary ${artifact.artifactId.takeLast(8)} replaced the local summary deterministically.",
                                        detectedAtMs = now
                                    )
                                    appliedArtifactCount += 1
                                }

                                else -> {
                                    conflicts += PortfolioOptimizationLearningSyncConflictRecord(
                                        conflictId = "portfolio_sync_conflict_${artifact.artifactId.takeLast(8)}_$now",
                                        envelopeId = envelope.envelopeId,
                                        artifactType = artifact.artifactType,
                                        artifactId = artifact.artifactId,
                                        localVersion = 1,
                                        incomingVersion = 1,
                                        resolution = PortfolioOptimizationLearningSyncConflictResolution.LAST_WRITE_WINS_LOCAL,
                                        reviewRequired = false,
                                        reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_RESOLVED),
                                        summary = "Local drift summary ${artifact.artifactId.takeLast(8)} remained authoritative deterministically.",
                                        detectedAtMs = now
                                    )
                                }
                            }
                        }

                        PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE -> {
                            appliedArtifactCount += 1
                        }

                        PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY -> {
                            val incomingSummary = artifact.federatedAggregationSummary ?: return@forEach
                            val local = portfolioOptimizationFederatedAggregationSummariesByUser[userId]
                                ?.toList()
                                .orEmpty()
                                .firstOrNull { it.groupKey.groupKey == incomingSummary.groupKey.groupKey }
                            val merged = if (local == null) {
                                incomingSummary.copy(
                                    reasonCodes = (incomingSummary.reasonCodes +
                                        RoleReasonCodes.ROLE_FEDERATED_AGGREGATION_APPLIED).distinct(),
                                    updatedAtMs = now
                                )
                            } else {
                                incomingSummary.copy(
                                    aggregationId = local.aggregationId,
                                    artifactCount = maxOf(local.artifactCount, incomingSummary.artifactCount),
                                    deviceCount = maxOf(local.deviceCount, incomingSummary.deviceCount),
                                    highestDriftSeverity = maxOf(
                                        local.highestDriftSeverity,
                                        incomingSummary.highestDriftSeverity
                                    ),
                                    reasonCodes = (
                                        local.reasonCodes +
                                            incomingSummary.reasonCodes +
                                            RoleReasonCodes.ROLE_FEDERATED_AGGREGATION_APPLIED
                                        ).distinct(),
                                    summary = if (incomingSummary.summary.isNotBlank()) {
                                        incomingSummary.summary
                                    } else {
                                        local.summary
                                    },
                                    updatedAtMs = now
                                )
                            }
                            storePortfolioOptimizationFederatedAggregationSummary(userId, merged)
                            conflicts += PortfolioOptimizationLearningSyncConflictRecord(
                                conflictId = "portfolio_sync_conflict_${artifact.artifactId.takeLast(8)}_$now",
                                envelopeId = envelope.envelopeId,
                                artifactType = artifact.artifactType,
                                artifactId = artifact.artifactId,
                                localVersion = local?.artifactCount,
                                incomingVersion = incomingSummary.artifactCount,
                                resolution = PortfolioOptimizationLearningSyncConflictResolution.SAFE_MERGE,
                                reviewRequired = false,
                                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_RESOLVED),
                                summary = "Federated aggregation summary ${artifact.artifactId.takeLast(8)} merged safely.",
                                detectedAtMs = now
                            )
                            appliedArtifactCount += 1
                        }
                    }
                }
            }
        }
        conflicts.forEach { storePortfolioOptimizationLearningSyncConflict(userId, it) }
        val persistedEnvelope = envelope.copy(
            provenance = envelope.provenance.copy(
                operatorId = operatorId ?: envelope.provenance.operatorId,
                operatorName = operatorName ?: envelope.provenance.operatorName
            ),
            issues = (envelope.issues + issues).distinctBy {
                "${it.type}:${it.artifactType}:${it.artifactId}:${it.summary}"
            },
            artifacts = if (redactionBlocked) {
                emptyList()
            } else {
                envelope.artifacts
            },
            reasonCodes = buildList {
                addAll(envelope.reasonCodes)
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.CONSENT_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_CONSENT_DENIED)
                }
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.PRIVACY_POLICY_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY)
                }
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.ROLE_POLICY_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY)
                }
                if (issues.any { it.type == PortfolioOptimizationLearningSyncIssueType.CROSS_TENANT_BOUNDARY_BLOCKED }) {
                    add(RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED)
                }
                if (conflicts.isNotEmpty()) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED)
                }
            }.distinct(),
            summary = when {
                issues.any { it.blocking } ->
                    "Learning sync import blocked for ${portfolioOptimizationLearningSyncModeLabel(envelope.mode)}."
                conflicts.any { it.reviewRequired } ->
                    "Learning sync import requires review before all artifacts can be applied."
                else ->
                    "Imported $appliedArtifactCount redacted learning artifact(s) for ${portfolioOptimizationLearningSyncModeLabel(envelope.mode)}."
            }
        )
        val attemptStatus = when {
            issues.any { it.blocking } -> PortfolioOptimizationLearningSyncStatus.BLOCKED
            conflicts.any { it.reviewRequired } -> PortfolioOptimizationLearningSyncStatus.CONFLICT_REVIEW_REQUIRED
            else -> PortfolioOptimizationLearningSyncStatus.APPLIED
        }
        val attempt = PortfolioOptimizationLearningSyncAttemptRecord(
            attemptId = "portfolio_sync_attempt_import_${userId.takeLast(8)}_${now}",
            direction = PortfolioOptimizationLearningSyncDirection.IMPORT,
            envelopeId = persistedEnvelope.envelopeId,
            mode = persistedEnvelope.mode,
            status = attemptStatus,
            boundary = persistedEnvelope.boundary,
            groupKey = persistedEnvelope.groupKey,
            privacyPolicy = localPrivacyPolicy,
            provenance = persistedEnvelope.provenance,
            artifactCount = persistedEnvelope.artifacts.size,
            appliedArtifactCount = appliedArtifactCount,
            conflictCount = conflicts.size,
            issues = persistedEnvelope.issues,
            reasonCodes = buildList {
                when (attemptStatus) {
                    PortfolioOptimizationLearningSyncStatus.APPLIED -> add(RoleReasonCodes.ROLE_LEARNING_SYNC_DELIVERED)
                    PortfolioOptimizationLearningSyncStatus.CONFLICT_REVIEW_REQUIRED ->
                        add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_DETECTED)
                    PortfolioOptimizationLearningSyncStatus.BLOCKED ->
                        addAll(
                            persistedEnvelope.reasonCodes.filter {
                                it == RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_PRIVACY ||
                                    it == RoleReasonCodes.ROLE_LEARNING_SYNC_BLOCKED_BY_ROLE_POLICY ||
                                    it == RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED
                            }
                        )
                    else -> Unit
                }
                if (conflicts.any { !it.reviewRequired }) {
                    add(RoleReasonCodes.ROLE_LEARNING_SYNC_CONFLICT_RESOLVED)
                }
            }.distinct(),
            summary = persistedEnvelope.summary,
            processedAtMs = now
        )
        storePortfolioOptimizationLearningSyncEnvelope(userId, persistedEnvelope)
        storePortfolioOptimizationLearningSyncAttempt(userId, attempt)
        recomputePortfolioOptimizationFederatedAggregationSummaries(userId, now)
        persistDynamicState(userId)
        return attempt
    }

    fun exportPortfolioOptimizationSummary(
        userId: String,
        resultId: String
    ): String {
        if (userId.isBlank() || resultId.isBlank()) {
            return "Portfolio optimization export is unavailable: missing result identity."
        }
        restoreDynamicStateIfNeeded(userId)
        val result = synchronized(dynamicStateLock) {
            portfolioOptimizationResultsByUser[userId]?.lastOrNull { it.resultId == resultId }
        } ?: return "Portfolio optimization result $resultId was not found."
        val request = synchronized(dynamicStateLock) {
            portfolioOptimizationRequestsByUser[userId]?.lastOrNull { it.requestId == result.requestId }
        }
        val decision = synchronized(dynamicStateLock) {
            portfolioOptimizationDecisionsByUser[userId]?.lastOrNull { it.resultId == resultId }
        }
        val outcome = synchronized(dynamicStateLock) {
            portfolioOptimizationOutcomesByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.resultId == resultId }
        }
        val driftSummary = outcome?.driftSummaryId?.let { driftId ->
            synchronized(dynamicStateLock) {
                portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
                    .firstOrNull { it.driftId == driftId }
            }
        }
        val tuningSuggestion = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningSuggestionsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.decisionId == decision?.decisionId && it.status == PortfolioOptimizationTuningStatus.PENDING }
        }
        val tuningDecision = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningDecisionsByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.decisionId == decision?.decisionId }
        }
        val latestPropagationAttempt = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAttemptsByUser[userId]?.toList().orEmpty()
                .filter { attempt ->
                    attempt.sourceObjectiveProfileSnapshotId == result.objectiveProfileSnapshotId ||
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = attempt.sourceObjectiveProfileSnapshotId,
                            rightSnapshotId = result.objectiveProfileSnapshotId
                        )
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPropagationAttemptRecord> { it.createdAtMs }
                        .thenBy { it.attemptId }
                )
        }
        val latestPropagationAdoption = synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAdoptionsByUser[userId]?.toList().orEmpty()
                .filter { adoption ->
                    adoption.sourceObjectiveProfileSnapshotId == result.objectiveProfileSnapshotId ||
                        adoption.targetObjectiveProfileSnapshotId == result.objectiveProfileSnapshotId
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPropagationAdoptionRecord> { it.adoptedAtMs }
                    .thenBy { it.adoptionId }
                )
        }
        val latestSyncAttempt = synchronized(dynamicStateLock) {
            portfolioOptimizationLearningSyncAttemptsByUser[userId]?.toList().orEmpty()
                .filter { attempt ->
                    portfolioOptimizationLearningSyncEnvelopesByUser[userId]
                        ?.toList()
                        ?.firstOrNull { it.envelopeId == attempt.envelopeId }
                        ?.let { envelope ->
                            portfolioOptimizationLearningSyncEnvelopeAppliesToObjectiveProfileLineageLocked(
                                userId = userId,
                                envelope = envelope,
                                objectiveProfileSnapshotId = result.objectiveProfileSnapshotId
                            )
                        } == true
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationLearningSyncAttemptRecord> { it.processedAtMs }
                        .thenBy { it.attemptId }
                )
        }
        val latestSyncConflict = synchronized(dynamicStateLock) {
            val envelopesById = portfolioOptimizationLearningSyncEnvelopesByUser[userId]
                ?.toList()
                .orEmpty()
                .associateBy { it.envelopeId }
            portfolioOptimizationLearningSyncConflictsByUser[userId]?.toList().orEmpty()
                .filter { conflict ->
                    portfolioOptimizationLearningSyncConflictAppliesToObjectiveProfileLineageLocked(
                        userId = userId,
                        conflict = conflict,
                        objectiveProfileSnapshotId = result.objectiveProfileSnapshotId,
                        envelopesById = envelopesById
                    )
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationLearningSyncConflictRecord> { it.detectedAtMs }
                        .thenBy { it.conflictId }
                )
        }
        val effectiveObjectiveProfileBinding = synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationScopeBinding(userId, result.objectiveProfileBinding)
        }
        val latestAggregation = synchronized(dynamicStateLock) {
            portfolioOptimizationFederatedAggregationSummariesByUser[userId]?.toList().orEmpty()
                .filter {
                    it.boundary.tenantId == null ||
                        it.boundary.tenantId == effectiveObjectiveProfileBinding.tenantId
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationFederatedAggregationSummary> { it.updatedAtMs }
                        .thenBy { it.aggregationId }
                )
        }
        val latestConsent = synchronized(dynamicStateLock) {
            portfolioOptimizationConsentRecordsByUser[userId]?.toList().orEmpty()
                .filter { consent ->
                    portfolioOptimizationConsentScopeMatches(
                        userId = userId,
                        requiredBinding = effectiveObjectiveProfileBinding,
                        consentBinding = consent.scopeBinding
                    )
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationConsentRecord> { it.recordedAtMs }
                        .thenBy { it.consentId }
                )
        }
        val latestRemoteTransportAttempt = synchronized(dynamicStateLock) {
            portfolioOptimizationRemoteLearningTransportAttemptsByUser[userId]?.toList().orEmpty()
                .filter { attempt ->
                    attempt.remoteEnvelopeId.isBlank() ||
                        portfolioOptimizationRemoteLearningEnvelopesByUser[userId]
                            ?.toList()
                            ?.firstOrNull { it.remoteEnvelopeId == attempt.remoteEnvelopeId }
                            ?.let { envelope ->
                                (
                                    envelope.boundary.tenantId == null ||
                                        envelope.boundary.tenantId == effectiveObjectiveProfileBinding.tenantId
                                    ) &&
                                    (
                                        envelope.boundary.workspaceId == null ||
                                            envelope.boundary.workspaceId ==
                                            effectiveObjectiveProfileBinding.workspaceId
                                        )
                            } != false
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationRemoteLearningTransportAttemptRecord> { it.processedAtMs }
                        .thenBy { it.attemptId }
                )
        }
        val latestRemoteDestinationDecision =
            latestRemoteTransportAttempt?.destinationDecision ?: synchronized(dynamicStateLock) {
                portfolioOptimizationRemoteDestinationDecisionsByUser[userId]?.toList().orEmpty()
                    .filter { decisionRecord ->
                        decisionRecord.purpose == PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT &&
                            (
                                latestRemoteTransportAttempt == null ||
                                    decisionRecord.sourceId == latestRemoteTransportAttempt.attemptId
                                )
                    }
                    .maxWithOrNull(
                        compareBy<PortfolioOptimizationRemoteDestinationDecisionRecord> { it.createdAtMs }
                            .thenBy { it.decisionId }
                    )
            }
        val latestAuditExportRequest = synchronized(dynamicStateLock) {
            portfolioOptimizationComplianceAuditExportRequestsByUser[userId]?.toList().orEmpty()
                .filter { exportRequest ->
                    (exportRequest.objectiveProfileSnapshotId.isNullOrBlank() ||
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = exportRequest.objectiveProfileSnapshotId.orEmpty(),
                            rightSnapshotId = result.objectiveProfileSnapshotId
                        )) &&
                        (
                            exportRequest.resultId.isNullOrBlank() ||
                                exportRequest.resultId == result.resultId
                            ) &&
                        (
                            exportRequest.decisionId.isNullOrBlank() ||
                                exportRequest.decisionId == decision?.decisionId
                            )
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationComplianceAuditExportRequest> { it.requestedAtMs }
                        .thenBy { it.requestId }
                )
        }
        val latestAuditExportResult = synchronized(dynamicStateLock) {
            portfolioOptimizationComplianceAuditExportResultsByUser[userId]?.toList().orEmpty()
                .filter { export ->
                    latestAuditExportRequest?.requestId == null ||
                        export.requestId == latestAuditExportRequest.requestId
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationComplianceAuditExportResult> { it.completedAtMs }
                        .thenBy { it.resultId }
                )
        }
        val latestComplianceExportRoute =
            latestAuditExportResult?.exportRoute ?: synchronized(dynamicStateLock) {
                portfolioOptimizationComplianceExportRoutesByUser[userId]?.toList().orEmpty()
                    .filter { route ->
                        (
                            latestAuditExportRequest?.requestId == null ||
                                route.requestId == latestAuditExportRequest.requestId
                            ) &&
                            (
                                latestAuditExportResult?.resultId == null ||
                                    route.resultId == latestAuditExportResult.resultId
                                )
                    }
                    .maxWithOrNull(
                        compareBy<PortfolioOptimizationComplianceExportRouteRecord> { it.createdAtMs }
                            .thenBy { it.routeId }
                    )
            }
        val latestDataExchangeBundle = latestRemoteTransportAttempt?.dataExchangeBundle
            ?: latestAuditExportResult?.dataExchangeBundle
        val latestDataExchangeDecision = latestRemoteTransportAttempt?.bundleDecision
            ?: latestAuditExportResult?.bundleDecision
        val latestDataExchangeManifest = latestRemoteTransportAttempt?.dataExchangeManifest
            ?: latestAuditExportResult?.dataExchangeManifest
        val latestCrossBoundaryApproval = latestDataExchangeDecision?.decisionId?.let { decisionId ->
            portfolioOptimizationCrossBoundaryApprovalsByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.bundleDecisionId == decisionId }
        }
        val latestCrossBoundaryAudit = latestDataExchangeDecision?.decisionId?.let { decisionId ->
            portfolioOptimizationCrossBoundaryAuditsByUser[userId]
                ?.toList()
                .orEmpty()
                .firstOrNull { it.bundleDecisionId == decisionId }
        }
        val exportNow = nowMs()
        val optimizationSummary = getPortfolioOptimizationState(
            userId = userId,
            query = PortfolioOptimizationQuery(
                resultId = resultId,
                includeCompleted = true,
                limit = MAX_PORTFOLIO_OPTIMIZATION_TOP_N
            )
        ).summary
        val activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
        val effectiveSyncConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                binding = effectiveObjectiveProfileBinding,
                now = exportNow
            )
        }
        val effectiveRemoteTransportConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT,
                binding = effectiveObjectiveProfileBinding,
                now = exportNow
            )
        }
        val effectiveAuditExportConsent = synchronized(dynamicStateLock) {
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                binding = effectiveObjectiveProfileBinding,
                now = exportNow
            )
        }
        val activeEnterprisePrivacy = derivePortfolioOptimizationEnterprisePrivacyPolicySummary(
            userId = userId,
            binding = effectiveObjectiveProfileBinding,
            activeRole = activeRole,
            learningSyncConsent = effectiveSyncConsent,
            remoteTransportConsent = effectiveRemoteTransportConsent,
            auditExportConsent = effectiveAuditExportConsent
        )
        val candidate = result.candidateSchedules.firstOrNull()
        val binding = candidate?.bindingConstraints?.joinToString(" | ") { it.summary }.orEmpty()
        val tradeoffs = candidate?.tradeoffExplanations?.joinToString(" | ") { it.summary }.orEmpty()
        return buildString {
            appendLine("Portfolio Optimization Result")
            appendLine("Result: ${result.resultId}")
            appendLine("Request: ${request?.name?.ifBlank { result.requestId } ?: result.requestId}")
            appendLine("Status: ${result.status.name.lowercase().replace('_', ' ')}")
            appendLine("Calibration snapshot: ${result.calibrationSnapshotId.ifBlank { "default" }}")
            appendLine(
                "Objective profile: ${result.objectiveProfileSnapshotId.ifBlank { "default" }} · ${
                    portfolioOptimizationScopeLabel(result.objectiveProfileBinding.scope)
                } · ${result.objectiveProfileProvenance.type.name.lowercase().replace('_', ' ')}"
            )
            appendLine("Top candidate: ${candidate?.candidateId ?: "none"}")
            appendLine("Recommended schedule: ${candidate?.summary ?: "No candidate schedule."}")
            if (binding.isNotBlank()) {
                appendLine("Binding constraints: $binding")
            }
            if (tradeoffs.isNotBlank()) {
                appendLine("Tradeoffs: $tradeoffs")
            }
            decision?.let {
                appendLine("Selected schedule: ${it.candidateId} (${it.selectedByOperatorName ?: it.selectedByOperatorId ?: "unknown operator"})")
            }
            outcome?.let {
                appendLine("Latest outcome: ${it.summary}")
            }
            driftSummary?.let {
                appendLine("Latest drift: ${it.highestSeverity.name.lowercase()} · ${it.summary}")
            }
            tuningSuggestion?.let {
                appendLine("Pending tuning: ${it.summary}")
            }
            tuningDecision?.let {
                appendLine("Latest tuning decision: ${it.status.name.lowercase()} · ${it.summary}")
            }
            latestPropagationAttempt?.let {
                appendLine(
                    "Latest propagation: ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestPropagationAdoption?.let {
                appendLine(
                    "Latest adoption: ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestSyncAttempt?.let {
                appendLine(
                    "Learning sync: ${it.mode.name.lowercase().replace('_', ' ')} · ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestSyncConflict?.let {
                appendLine(
                    "Learning sync conflict: ${it.resolution.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestConsent?.let {
                appendLine(
                    "Latest consent: ${it.purpose.name.lowercase().replace('_', ' ')} · ${it.decision.name.lowercase()} · ${it.summary}"
                )
            }
            appendLine(
                "Consent status: sync ${effectiveSyncConsent?.decision?.name?.lowercase() ?: "pending"} · transport ${effectiveRemoteTransportConsent?.decision?.name?.lowercase() ?: "pending"} · audit ${effectiveAuditExportConsent?.decision?.name?.lowercase() ?: "pending"}"
            )
            latestRemoteTransportAttempt?.let {
                appendLine(
                    "Remote transport: ${it.transportMode.name.lowercase().replace('_', ' ')} · ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestRemoteDestinationDecision?.let {
                appendLine(
                    "Remote destination: ${it.status.name.lowercase().replace('_', ' ')} · ${
                        it.selectedDestinationType?.name?.lowercase()?.replace('_', ' ') ?: "n/a"
                    } · ${it.summary}"
                )
                appendLine(
                    "Residency routing: ${it.residencyRegion.name.lowercase().replace('_', ' ')} · ${
                        it.jurisdiction.name.lowercase().replace('_', ' ')
                    } · ${it.residencyPolicy.summary.ifBlank { "Policy-safe residency evaluation applied." }}"
                )
            }
            latestAuditExportResult?.let {
                appendLine(
                    "Compliance audit export: ${latestAuditExportRequest?.format?.name?.lowercase() ?: "json"} · ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestComplianceExportRoute?.let {
                appendLine(
                    "Compliance export route: ${it.status.name.lowercase().replace('_', ' ')} · ${
                        it.destinationType?.name?.lowercase()?.replace('_', ' ') ?: "n/a"
                    } · ${it.summary}"
                )
            }
            latestDataExchangeDecision?.let {
                appendLine(
                    "Exchange bundle: ${it.bundleType.name.lowercase().replace('_', ' ')} · ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestDataExchangeManifest?.let {
                appendLine(
                    "Exchange boundary: ${it.status.name.lowercase().replace('_', ' ')} · ${it.boundarySummary.summary}"
                )
            }
            latestCrossBoundaryApproval?.let {
                appendLine(
                    "Exchange approval: ${it.status.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            latestCrossBoundaryAudit?.let {
                appendLine(
                    "Cross-boundary audit: ${it.operationType.name.lowercase().replace('_', ' ')} · ${it.summary}"
                )
            }
            if (activeEnterprisePrivacy.summary.isNotBlank()) {
                appendLine("Enterprise privacy: ${activeEnterprisePrivacy.summary}")
            }
            latestAggregation?.let {
                appendLine("Federated aggregation: ${it.summary}")
            }
            optimizationSummary?.takeIf {
                it.activeCrossBoundaryGovernancePortfolioStatus != null ||
                    it.activeDestinationTrustTier != null ||
                    it.latestGovernancePortfolioSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Governance portfolio: ${
                        buildList {
                            summary.activeCrossBoundaryGovernancePortfolioStatus?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                            summary.activeDestinationTrustTier?.let {
                                add("trust ${it.name.lowercase().replace('_', ' ')}")
                            }
                            summary.latestPortfolioPriority?.let {
                                add("priority ${it.name.lowercase().replace('_', ' ')}")
                            }
                        }.joinToString(" · ").ifBlank { "n/a" }
                    }${summary.latestGovernancePortfolioSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.latestCrossBoundaryProgramStatus != null ||
                    it.latestTrustTierRolloutState != null ||
                    it.latestTrustTierProgramSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Trust tier rollout: ${
                        buildList {
                            summary.latestCrossBoundaryProgramStatus?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                            summary.latestTrustTierRolloutState?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                        }.joinToString(" · ").ifBlank { "n/a" }
                    }${summary.latestTrustTierProgramSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.latestJurisdictionRolloutState != null || it.latestJurisdictionRolloutSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Jurisdiction rollout: ${
                        summary.latestJurisdictionRolloutState?.name?.lowercase()?.replace('_', ' ') ?: "n/a"
                    }${summary.latestJurisdictionRolloutSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.sharedPortfolioBlockerCount > 0 || it.latestPortfolioBlockerSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Shared blockers: ${summary.sharedPortfolioBlockerCount}${summary.latestPortfolioBlockerSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.latestPortfolioDependencySummary
                ?.takeIf { it.isNotBlank() }
                ?.let { appendLine("Dependencies: $it") }
            optimizationSummary?.takeIf {
                it.portfolioConflictCount > 0 || it.latestPortfolioConflictSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Coordination conflicts: ${summary.portfolioConflictCount}${summary.latestPortfolioConflictSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.latestPortfolioRecommendationAction != null || it.latestPortfolioRecommendationSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Next action: ${summary.latestPortfolioRecommendationAction?.name?.lowercase()?.replace('_', ' ') ?: "n/a"}${summary.latestPortfolioRecommendationSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.activePortfolioHealthStatus != null ||
                    it.activePortfolioTrajectoryState != null ||
                    it.latestPortfolioAnalyticsSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Portfolio analytics: ${
                        buildList {
                            summary.activePortfolioHealthStatus?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                            summary.activePortfolioTrajectoryState?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                        }.joinToString(" · ").ifBlank { "n/a" }
                    }${summary.latestPortfolioAnalyticsSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.latestTrustTierDriftState != null || it.latestTrustTierDriftSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Trust-tier drift: ${summary.latestTrustTierDriftState?.name?.lowercase()?.replace('_', ' ') ?: "n/a"}${summary.latestTrustTierDriftSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.latestJurisdictionDriftState != null || it.latestJurisdictionDriftSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Jurisdiction drift: ${summary.latestJurisdictionDriftState?.name?.lowercase()?.replace('_', ' ') ?: "n/a"}${summary.latestJurisdictionDriftSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.activeRiskBudgetStatus != null || it.latestRiskBudgetSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Risk budget: ${summary.activeRiskBudgetStatus?.name?.lowercase()?.replace('_', ' ') ?: "n/a"} · breaches ${summary.riskBudgetBreachCount}${summary.latestRiskBudgetSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.activePortfolioSafetyState != null ||
                    it.activePortfolioEnforcementMode != null ||
                    it.activeRemediationAutomationState != null ||
                    it.latestPortfolioSafetySummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Portfolio safety: ${
                        buildList {
                            summary.activePortfolioSafetyState?.let {
                                add(it.name.lowercase().replace('_', ' '))
                            }
                            summary.activePortfolioEnforcementMode?.let {
                                add("enforcement ${it.name.lowercase().replace('_', ' ')}")
                            }
                            summary.activeRemediationAutomationState?.let {
                                add("remediation ${it.name.lowercase().replace('_', ' ')}")
                            }
                        }.joinToString(" · ").ifBlank { "n/a" }
                    }${summary.latestPortfolioSafetySummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.takeIf {
                it.activeBudgetGuardrailState != null ||
                    it.remediationApprovalRequiredCount > 0 ||
                    it.latestBudgetGuardrailSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Budget guardrail: ${summary.activeBudgetGuardrailState?.name?.lowercase()?.replace('_', ' ') ?: "n/a"} · approvals ${summary.remediationApprovalRequiredCount}${summary.latestBudgetGuardrailSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.latestPortfolioSafetyRailSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { appendLine("Safety rail: $it") }
            optimizationSummary?.takeIf {
                it.activeRemediationAutomationState != null ||
                    it.quarantinedPortfolioCount > 0 ||
                    it.latestRemediationAutomationSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Remediation control: ${summary.activeRemediationAutomationState?.name?.lowercase()?.replace('_', ' ') ?: "n/a"} · quarantined ${summary.quarantinedPortfolioCount}${summary.latestRemediationAutomationSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.latestDestinationRiskConcentrationSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { appendLine("Destination concentration: $it") }
            optimizationSummary?.latestPortfolioBlockerTrendSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { appendLine("Blocker trend: $it") }
            optimizationSummary?.takeIf {
                it.latestPortfolioRiskRecommendationAction != null ||
                    it.latestPortfolioRiskRecommendationSummary.isNotBlank()
            }?.let { summary ->
                appendLine(
                    "Risk recommendation: ${summary.latestPortfolioRiskRecommendationAction?.name?.lowercase()?.replace('_', ' ') ?: "n/a"}${summary.latestPortfolioRiskRecommendationSummary.takeIf { it.isNotBlank() }?.let { " · $it" } ?: ""}"
                )
            }
            optimizationSummary?.latestPortfolioCorrectiveActionSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { appendLine("Corrective action: $it") }
            if (result.summary.isNotBlank()) {
                appendLine("Summary: ${result.summary}")
            }
            if (result.notes.isNotEmpty()) {
                appendLine("Notes: ${result.notes.joinToString(" | ")}")
            }
        }.trim()
    }

    private fun deriveBaselinePortfolioSnapshot(
        userId: String,
        now: Long
    ): BaselinePortfolioSnapshot {
        val cases = getGovernanceCases(
            userId = userId,
            filter = GovernanceConsoleFilter(
                includeReviewed = true,
                limit = MAX_GOVERNANCE_QUERY_LIMIT
            )
        ).sortedWith(
            compareBy<GovernanceCaseRecord>(
                { it.summary.policyGovernanceProgramId ?: "program_untracked" },
                { it.summary.rolloutWaveId ?: "wave_untracked" },
                { it.summary.runId }
            )
        )
        val totalCases = cases.size
        val approvalPendingCases = cases.count {
            it.summary.policyApprovalPending ||
                it.summary.status == ResponseStatus.WAITING_USER ||
                it.summary.status == ResponseStatus.AUTH_REQUIRED
        }
        val capacityBlockedCases = cases.count { it.summary.capacityBlocked }
        val policyBlockedCases = cases.count { it.summary.policyBlocked }
        val deferredCases = cases.count {
            it.summary.scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                it.summary.programCoordinationState == RolloutProgramCoordinationState.DEFERRED
        }
        val carryForwardCases = cases.count { it.summary.rolloutCarryForwardPending }
        val nextEligibleAtMs = cases.mapNotNull { case ->
            listOf(
                case.summary.nextEligiblePromotionAtMs,
                case.summary.scheduleNextEligibleAtMs
            ).mapNotNull { candidate -> candidate?.takeIf { it > 0L } }.minOrNull()
        }.minOrNull()
        val dominantPoolKey = cases
            .mapNotNull { it.summary.capacityPoolKey?.takeIf { key -> key.isNotBlank() } }
            .groupingBy { it }
            .eachCount()
            .maxByOrNull { (_, count) -> count }
            ?.key
            ?: "not_tracked"
        val dominantLoadBucket = cases
            .mapNotNull { it.summary.approvalLoadBucket }
            .maxByOrNull { approvalLoadBucketSeverity(it) }
            ?: ApprovalLoadBucket.BALANCED
        val approvalDemandBaseline = maxOf(
            approvalPendingCases,
            cases.count { it.summary.approvalQueueSaturated },
            1
        )
        val approvalCapacityBaseline = maxOf(
            1,
            approvalDemandBaseline - capacityBlockedCases + maxOf(1, totalCases / 4)
        )
        val backlogBaseline = maxOf(0, approvalDemandBaseline - approvalCapacityBaseline)
        val utilizationRate = (approvalDemandBaseline.toDouble() / approvalCapacityBaseline.toDouble()).coerceAtLeast(0.0)

        val programs = cases
            .groupBy { it.summary.policyGovernanceProgramId ?: "program_untracked" }
            .map { (programId, programCases) ->
                val waves = programCases
                    .groupBy { it.summary.rolloutWaveId ?: "wave_untracked" }
                    .map { (waveId, waveCases) ->
                        val waveNextEligible = waveCases.mapNotNull { case ->
                            listOf(
                                case.summary.nextEligiblePromotionAtMs,
                                case.summary.scheduleNextEligibleAtMs
                            ).mapNotNull { candidate -> candidate?.takeIf { it > 0L } }.minOrNull()
                        }.minOrNull()
                        BaselineWaveStateSnapshot(
                            waveId = waveId,
                            programId = programId,
                            waveStatus = waveCases.mapNotNull { it.summary.rolloutWaveStatus }.lastOrNull(),
                            openCaseCount = waveCases.size,
                            deferredCaseCount = waveCases.count {
                                it.summary.scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                                    it.summary.programCoordinationState == RolloutProgramCoordinationState.DEFERRED
                            },
                            blockedCaseCount = waveCases.count {
                                it.summary.capacityBlocked || it.summary.policyBlocked
                            },
                            nextEligibleAtMs = waveNextEligible,
                            orderIndex = 0,
                            reasonCodes = buildList {
                                if (waveCases.any { it.summary.rolloutCarryForwardPending }) {
                                    add(RoleReasonCodes.ROLE_ROLLOUT_WAVE_CARRIED_FORWARD)
                                }
                                if (waveCases.any { it.summary.rolloutWaveCompletionState == RolloutWaveCompletionState.PARTIAL_COMPLETION }) {
                                    add(RoleReasonCodes.ROLE_ROLLOUT_WAVE_PARTIAL_COMPLETION)
                                }
                            },
                            summary = "Wave $waveId has ${waveCases.size} tracked case(s)."
                        )
                    }
                    .sortedWith(compareBy<BaselineWaveStateSnapshot> { it.orderIndex }.thenBy { it.waveId })
                BaselineProgramStateSnapshot(
                    programId = programId,
                    programName = programCases.firstOrNull()?.summary?.workflowTemplateName
                        ?.takeIf { it.isNotBlank() }
                        ?: programId,
                    priority = programCases
                        .mapNotNull { it.summary.programPriority }
                        .maxByOrNull { rolloutProgramPrioritySeverity(it) },
                    openCaseCount = programCases.size,
                    deferredCaseCount = programCases.count {
                        it.summary.scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                            it.summary.programCoordinationState == RolloutProgramCoordinationState.DEFERRED
                    },
                    blockedCaseCount = programCases.count {
                        it.summary.capacityBlocked || it.summary.policyBlocked
                    },
                    pendingApprovalCount = programCases.count { it.summary.policyApprovalPending },
                    nextEligibleAtMs = programCases.mapNotNull { case ->
                        listOf(
                            case.summary.nextEligiblePromotionAtMs,
                            case.summary.scheduleNextEligibleAtMs
                        ).mapNotNull { candidate -> candidate?.takeIf { it > 0L } }.minOrNull()
                    }.minOrNull(),
                    waves = waves,
                    reasonCodes = buildList {
                        if (programCases.any { it.summary.capacityBlocked }) {
                            add(RoleReasonCodes.ROLE_GOVERNANCE_CAPACITY_BLOCKED)
                        }
                        if (programCases.any { it.summary.policyBlocked }) {
                            add(RoleReasonCodes.ROLE_POLICY_APPROVAL_REQUIRED)
                        }
                    },
                    summary = "Program $programId has ${programCases.size} tracked case(s)."
                )
            }
            .sortedBy { it.programId }

        return BaselinePortfolioSnapshot(
            snapshotId = "baseline_${userId.lowercase()}_${now}",
            generatedAtMs = now,
            totalCases = totalCases,
            approvalPendingCases = approvalPendingCases,
            capacityBlockedCases = capacityBlockedCases,
            policyBlockedCases = policyBlockedCases,
            deferredCases = deferredCases,
            carryForwardCases = carryForwardCases,
            nextEligibleAtMs = nextEligibleAtMs,
            capacity = BaselineCapacitySnapshot(
                snapshotId = "baseline_capacity_${userId.lowercase()}_${now}",
                poolKey = dominantPoolKey,
                loadBucket = dominantLoadBucket,
                approvalCapacityBaseline = approvalCapacityBaseline,
                approvalDemandBaseline = approvalDemandBaseline,
                backlogBaseline = backlogBaseline,
                utilizationRate = utilizationRate,
                nextAvailableAtMs = nextEligibleAtMs,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BASELINE_DERIVED),
                summary = "Capacity baseline demand $approvalDemandBaseline vs capacity $approvalCapacityBaseline."
            ),
            programs = programs,
            reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BASELINE_DERIVED),
            summary = "Baseline derived from $totalCases durable governance case(s)."
        )
    }

    private fun normalizePortfolioScenarioDefinition(
        scenario: PortfolioScenarioDefinition,
        now: Long
    ): PortfolioScenarioDefinition {
        val scenarioId = scenario.scenarioId.trim().ifBlank {
            "portfolio_scenario_${now}"
        }
        val assumptions = scenario.assumptions.copy(
            horizonDays = scenario.assumptions.horizonDays.coerceIn(1, PORTFOLIO_SIMULATION_HORIZON_DAYS),
            bucketHours = PORTFOLIO_SIMULATION_BUCKET_HOURS,
            timezone = scenario.assumptions.timezone.ifBlank { "UTC" },
            queueDecayRate = scenario.assumptions.queueDecayRate.coerceIn(0.0, 1.0),
            backlogGrowthThreshold = scenario.assumptions.backlogGrowthThreshold.coerceIn(1, 500)
        )
        val modifications = scenario.modifications
            .mapIndexed { index, modification ->
                val modificationId = modification.modificationId
                    .trim()
                    .ifBlank { "scenario_mod_${scenarioId}_$index" }
                modification.copy(modificationId = modificationId)
            }
        return scenario.copy(
            scenarioId = scenarioId,
            name = scenario.name.ifBlank { "Scenario ${scenarioId.takeLast(6)}" },
            summary = scenario.summary.ifBlank {
                "Bounded scenario for portfolio simulation."
            },
            assumptions = assumptions,
            modifications = modifications,
            simulationOnly = true,
            active = scenario.active,
            createdAtMs = scenario.createdAtMs.takeIf { it > 0L } ?: now,
            updatedAtMs = now
        )
    }

    private fun simulatePortfolioScenarioRun(
        scenario: PortfolioScenarioDefinition,
        baseline: BaselinePortfolioSnapshot,
        now: Long
    ): PortfolioSimulationRunRecord {
        val normalizedScenario = normalizePortfolioScenarioDefinition(scenario, now)
        val notes = mutableListOf<String>()
        val controls = resolvePortfolioSimulationControls(
            modifications = normalizedScenario.modifications,
            notes = notes
        )
        val horizonDays = PORTFOLIO_SIMULATION_HORIZON_DAYS
        val dayMs = 24L * 60L * 60L * 1000L
        val startAtMs = utcDayStartMs(now)
        val buckets = (0 until horizonDays).map { index ->
            ForecastTimeBucket(
                bucketIndex = index,
                startAtMs = startAtMs + (index * dayMs),
                endAtMs = startAtMs + ((index + 1) * dayMs)
            )
        }
        val baseCapacity = maxOf(1, baseline.capacity.approvalCapacityBaseline)
        val baseDemand = maxOf(1, baseline.capacity.approvalDemandBaseline)
        var backlog = maxOf(0, baseline.capacity.backlogBaseline)
        val pausedProgramCount = controls.pausedProgramIds.size
        val resumedProgramCount = controls.resumedProgramIds.size
        val pauseFactor = (1.0 - (pausedProgramCount * 0.10)).coerceIn(0.35, 1.0)
        val resumeFactor = (1.0 + (resumedProgramCount * 0.05)).coerceIn(1.0, 1.35)
        val waveScale = (1.0 + controls.waveSizeAdjustmentPct / 100.0).coerceIn(0.5, 1.5)
        val capacityScale = (1.0 + controls.capacityAdjustmentPct / 100.0).coerceIn(0.5, 2.0)
        val allocationScale = controls.allocationWeight
        val simulationOnlyFactor = if (controls.automationSimulationOnly == true) 0.95 else 1.0
        val demandScale = (waveScale * pauseFactor * resumeFactor * allocationScale * simulationOnlyFactor)
            .coerceIn(0.35, 2.4)

        val approvalForecast = mutableListOf<ApprovalDemandForecast>()
        val queuePressureForecast = mutableListOf<QueuePressureForecast>()
        var positiveBacklogGrowthStreak = 0
        var firstCapacityBreachBucket: Int? = null
        var firstBacklogGrowthBucket: Int? = null
        buckets.forEach { bucket ->
            val timeGrowth = 1.0 + (bucket.bucketIndex * 0.03)
            val shiftedIndex = (bucket.bucketIndex - controls.windowShiftBuckets).coerceAtLeast(0)
            val shiftFactor = 1.0 + (shiftedIndex * 0.015)
            val expectedDemand = maxOf(
                0,
                (baseDemand.toDouble() * demandScale * timeGrowth * shiftFactor).toInt()
            )
            val expectedCapacity = maxOf(
                1,
                (baseCapacity.toDouble() * capacityScale).toInt()
            )
            val expectedBacklog = maxOf(0, backlog + expectedDemand - expectedCapacity)
            val saturated = expectedDemand + backlog > expectedCapacity
            val utilizationRate = ((expectedDemand + backlog).toDouble() / expectedCapacity.toDouble())
                .coerceAtLeast(0.0)
            val approvalReasons = buildList {
                if (saturated) {
                    add(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_CAPACITY_BREACH_PREDICTED)
                }
                if (controls.windowShiftBuckets != 0) {
                    add(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_SHIFT_WINDOW)
                }
            }
            approvalForecast += ApprovalDemandForecast(
                bucket = bucket,
                expectedDemand = expectedDemand,
                expectedCapacity = expectedCapacity,
                expectedBacklog = expectedBacklog,
                utilizationRate = utilizationRate,
                saturated = saturated,
                reasonCodes = approvalReasons,
                summary = if (saturated) {
                    "Demand exceeds capacity in bucket ${bucket.bucketIndex}."
                } else {
                    "Capacity remains sufficient in bucket ${bucket.bucketIndex}."
                }
            )
            if (saturated && firstCapacityBreachBucket == null) {
                firstCapacityBreachBucket = bucket.bucketIndex
            }

            val backlogGrowth = expectedBacklog - backlog
            if (backlogGrowth > normalizedScenario.assumptions.backlogGrowthThreshold) {
                positiveBacklogGrowthStreak += 1
                if (firstBacklogGrowthBucket == null) {
                    firstBacklogGrowthBucket = bucket.bucketIndex
                }
            } else {
                positiveBacklogGrowthStreak = 0
            }
            queuePressureForecast += QueuePressureForecast(
                bucket = bucket,
                pressureScore = utilizationRate,
                backlogGrowth = backlogGrowth,
                saturated = saturated || positiveBacklogGrowthStreak >= 2,
                reasonCodes = buildList {
                    if (backlogGrowth > normalizedScenario.assumptions.backlogGrowthThreshold) {
                        add(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BACKLOG_GROWTH_PREDICTED)
                    }
                },
                summary = "Queue pressure ${"%.2f".format(utilizationRate)} with backlog growth $backlogGrowth."
            )
            backlog = expectedBacklog
        }

        val programForecast = baseline.programs.map { program ->
            val programPaused = controls.pausedProgramIds.contains(program.programId)
            val openCases = maxOf(1, program.openCaseCount + program.deferredCaseCount + program.blockedCaseCount)
            val throughput = maxOf(1, ((baseCapacity * capacityScale) / maxOf(1, baseline.programs.size)).toInt())
            val estimatedCompletionBucket = maxOf(1, (openCases + throughput - 1) / throughput)
            val shiftedCompletionBucket = (estimatedCompletionBucket + maxOf(0, controls.windowShiftBuckets))
                .coerceAtMost(horizonDays)
            val estimatedCompletionAtMs = startAtMs + (shiftedCompletionBucket.toLong() * dayMs)
            val programNextEligibleAtMs = program.nextEligibleAtMs
            val delayed = if (programNextEligibleAtMs != null && programNextEligibleAtMs > 0L) {
                estimatedCompletionAtMs > (programNextEligibleAtMs + dayMs)
            } else {
                controls.windowShiftBuckets > 0 || programPaused
            }
            val delayBuckets = if (delayed) maxOf(1, shiftedCompletionBucket - estimatedCompletionBucket) else 0
            ProgramCompletionForecast(
                programId = program.programId,
                estimatedCompletionBucket = shiftedCompletionBucket,
                estimatedCompletionAtMs = estimatedCompletionAtMs,
                delayed = delayed,
                delayBuckets = delayBuckets,
                reasonCodes = buildList {
                    if (delayed) {
                        add(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_COMPLETION_DELAY_PREDICTED)
                    }
                },
                summary = if (delayed) {
                    "Program ${program.programId} completion is delayed by $delayBuckets bucket(s)."
                } else {
                    "Program ${program.programId} completion remains within expected window."
                }
            )
        }

        val windowForecast = baseline.programs.flatMap { program ->
            val baseWave = if (program.waves.isEmpty()) {
                listOf(
                    BaselineWaveStateSnapshot(
                        waveId = "wave_untracked",
                        programId = program.programId,
                        nextEligibleAtMs = program.nextEligibleAtMs,
                        summary = "No explicit wave tracking; using program-level window."
                    )
                )
            } else {
                program.waves
            }
            baseWave.map { wave ->
                val baseNextEligible = wave.nextEligibleAtMs ?: program.nextEligibleAtMs ?: baseline.nextEligibleAtMs
                val shiftedNextEligible = baseNextEligible?.plus(controls.windowShiftBuckets.toLong() * dayMs)
                val eligible = shiftedNextEligible == null || shiftedNextEligible <= (startAtMs + horizonDays * dayMs)
                val delayReason = when {
                    controls.pausedProgramIds.contains(program.programId) -> WindowDelayReason.GOVERNANCE_PAUSE
                    controls.windowShiftBuckets > 0 -> WindowDelayReason.UNKNOWN
                    else -> WindowDelayReason.NONE
                }
                WindowEligibilityForecast(
                    programId = program.programId,
                    waveId = wave.waveId,
                    eligible = eligible,
                    nextEligibleAtMs = shiftedNextEligible,
                    delayReason = delayReason,
                    reasonCodes = buildList {
                        if (!eligible) {
                            add(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_COMPLETION_DELAY_PREDICTED)
                        }
                    },
                    summary = if (eligible) {
                        "Wave ${wave.waveId} remains eligible in the forecast horizon."
                    } else {
                        "Wave ${wave.waveId} is delayed beyond the forecast horizon."
                    }
                )
            }
        }

        val breachSignals = mutableListOf<PortfolioForecastBreachSignal>()
        if (firstCapacityBreachBucket != null) {
            breachSignals += PortfolioForecastBreachSignal(
                signalId = "portfolio_signal_capacity_${now}",
                type = PortfolioForecastBreachType.CAPACITY_BREACH,
                severity = GovernanceAlertSeverity.HIGH,
                bucketIndex = firstCapacityBreachBucket,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_CAPACITY_BREACH_PREDICTED),
                summary = "Capacity breach is predicted in bucket $firstCapacityBreachBucket."
            )
        }
        if (firstBacklogGrowthBucket != null) {
            breachSignals += PortfolioForecastBreachSignal(
                signalId = "portfolio_signal_backlog_${now}",
                type = PortfolioForecastBreachType.BACKLOG_GROWTH,
                severity = GovernanceAlertSeverity.WARNING,
                bucketIndex = firstBacklogGrowthBucket,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BACKLOG_GROWTH_PREDICTED),
                summary = "Sustained backlog growth is predicted in bucket $firstBacklogGrowthBucket."
            )
        }
        val firstDelayedProgram = programForecast.firstOrNull { it.delayed }
        if (firstDelayedProgram != null) {
            breachSignals += PortfolioForecastBreachSignal(
                signalId = "portfolio_signal_completion_${now}",
                type = PortfolioForecastBreachType.COMPLETION_DELAY,
                severity = GovernanceAlertSeverity.WARNING,
                programId = firstDelayedProgram.programId,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_COMPLETION_DELAY_PREDICTED),
                summary = "Completion delay is predicted for program ${firstDelayedProgram.programId}."
            )
        }

        val topRecommendationCode = when {
            breachSignals.any { it.type == PortfolioForecastBreachType.CAPACITY_BREACH } ->
                RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_INCREASE_CAPACITY
            breachSignals.any { it.type == PortfolioForecastBreachType.BACKLOG_GROWTH } ->
                RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_REDUCE_WAVE_SIZE
            breachSignals.any { it.type == PortfolioForecastBreachType.COMPLETION_DELAY } ->
                RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_SHIFT_WINDOW
            else -> RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BASELINE_DERIVED
        }
        val topRecommendation = when (topRecommendationCode) {
            RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_INCREASE_CAPACITY ->
                "Increase approval capacity or reallocate queue ownership."
            RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_REDUCE_WAVE_SIZE ->
                "Reduce wave/cohort size to control queue pressure."
            RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RECOMMENDATION_SHIFT_WINDOW ->
                "Shift rollout window to align with next eligible capacity window."
            else ->
                "No high-severity breach predicted; keep current portfolio plan."
        }
        val recommendationReasonCodes = listOf(
            RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_RUN_CREATED,
            RoleReasonCodes.ROLE_PORTFOLIO_SIMULATION_BASELINE_DERIVED,
            topRecommendationCode
        ).plus(
            breachSignals.flatMap { it.reasonCodes }
        ).distinct()
        if (controls.clampedInputCount > 0) {
            notes += "One or more scenario inputs were clamped to bounded limits."
        }
        if (controls.automationSimulationOnly == true) {
            notes += "Automation simulation-only toggle affects forecast output only; no live policy mutation was applied."
        }
        val summary = buildString {
            append("Forecast horizon ")
            append(horizonDays)
            append(" day(s): ")
            append(breachSignals.size)
            append(" breach signal(s), top recommendation: ")
            append(topRecommendation.lowercase())
        }
        return PortfolioSimulationRunRecord(
            runId = "portfolio_sim_run_${normalizedScenario.scenarioId.take(12)}_${now}",
            scenarioId = normalizedScenario.scenarioId,
            baselineSnapshotId = baseline.snapshotId,
            status = PortfolioSimulationRunStatus.COMPLETED,
            assumptions = normalizedScenario.assumptions.copy(
                horizonDays = horizonDays,
                bucketHours = PORTFOLIO_SIMULATION_BUCKET_HOURS,
                timezone = "UTC"
            ),
            baselineSnapshot = baseline,
            approvalDemandForecast = approvalForecast,
            queuePressureForecast = queuePressureForecast,
            programCompletionForecast = programForecast,
            windowEligibilityForecast = windowForecast,
            breachSignals = breachSignals,
            recommendationReasonCodes = recommendationReasonCodes,
            topRecommendation = topRecommendation,
            notes = notes,
            summary = summary,
            startedAtMs = now,
            completedAtMs = now
        )
    }

    private fun resolvePortfolioSimulationControls(
        modifications: List<PortfolioScenarioModification>,
        notes: MutableList<String>
    ): PortfolioSimulationControls {
        var windowShiftBuckets = 0
        var waveSizeAdjustmentPct = 0
        var capacityAdjustmentPct = 0
        var allocationWeight = 1.0
        var automationSimulationOnly: Boolean? = null
        var clampedInputCount = 0
        val pausedPrograms = mutableSetOf<String>()
        val resumedPrograms = mutableSetOf<String>()

        modifications.forEach { modification ->
            when (modification.type) {
                PortfolioScenarioModificationType.SHIFT_ROLLOUT_WINDOW -> {
                    val raw = modification.intValue ?: modification.doubleValue?.toInt() ?: 0
                    val clamped = raw.coerceIn(-3, 3)
                    if (clamped != raw) {
                        clampedInputCount += 1
                        notes += "Window shift ${raw} was clamped to $clamped."
                    }
                    windowShiftBuckets = (windowShiftBuckets + clamped).coerceIn(-3, 3)
                }
                PortfolioScenarioModificationType.ADJUST_WAVE_SIZE -> {
                    val raw = modification.doubleValue ?: modification.intValue?.toDouble() ?: 0.0
                    val clamped = raw.coerceIn(-50.0, 50.0)
                    if (clamped != raw) {
                        clampedInputCount += 1
                        notes += "Wave size adjustment ${"%.1f".format(raw)} was clamped to ${"%.1f".format(clamped)}."
                    }
                    waveSizeAdjustmentPct = clamped.toInt()
                }
                PortfolioScenarioModificationType.ADJUST_APPROVAL_CAPACITY -> {
                    val raw = modification.doubleValue ?: modification.intValue?.toDouble() ?: 0.0
                    val clamped = raw.coerceIn(-50.0, 100.0)
                    if (clamped != raw) {
                        clampedInputCount += 1
                        notes += "Capacity adjustment ${"%.1f".format(raw)} was clamped to ${"%.1f".format(clamped)}."
                    }
                    capacityAdjustmentPct = clamped.toInt()
                }
                PortfolioScenarioModificationType.ADJUST_ALLOCATION_WEIGHT -> {
                    val raw = modification.doubleValue ?: modification.intValue?.toDouble() ?: 1.0
                    val clamped = raw.coerceIn(0.2, 2.0)
                    if (clamped != raw) {
                        clampedInputCount += 1
                        notes += "Allocation weight ${"%.2f".format(raw)} was clamped to ${"%.2f".format(clamped)}."
                    }
                    allocationWeight = clamped
                }
                PortfolioScenarioModificationType.TOGGLE_AUTOMATION_SIMULATION_ONLY -> {
                    automationSimulationOnly = modification.boolValue ?: true
                }
                PortfolioScenarioModificationType.PAUSE_PROGRAM -> {
                    modification.targetProgramId
                        ?.takeIf { it.isNotBlank() }
                        ?.let { pausedPrograms += it }
                }
                PortfolioScenarioModificationType.RESUME_PROGRAM -> {
                    modification.targetProgramId
                        ?.takeIf { it.isNotBlank() }
                        ?.let { resumedPrograms += it }
                }
            }
        }
        return PortfolioSimulationControls(
            windowShiftBuckets = windowShiftBuckets,
            waveSizeAdjustmentPct = waveSizeAdjustmentPct,
            capacityAdjustmentPct = capacityAdjustmentPct,
            allocationWeight = allocationWeight,
            pausedProgramIds = pausedPrograms,
            resumedProgramIds = resumedPrograms,
            automationSimulationOnly = automationSimulationOnly,
            clampedInputCount = clampedInputCount
        )
    }

    private fun defaultPortfolioOptimizationObjectiveProfile(
        preset: PortfolioOptimizationObjectivePreset = PortfolioOptimizationObjectivePreset.BALANCED
    ): PortfolioOptimizationObjectiveProfile {
        return PortfolioOptimizationObjectiveProfile(
            profileId = "objective_${preset.name.lowercase()}",
            preset = preset,
            weights = defaultPortfolioOptimizationObjectiveWeights(preset),
            summary = "Objective preset ${preset.name.lowercase().replace('_', ' ')}."
        )
    }

    private fun defaultPortfolioOptimizationConstraintProfile(
        preset: PortfolioOptimizationConstraintPreset = PortfolioOptimizationConstraintPreset.DEFAULT_GUARDED,
        riskTolerance: PortfolioOptimizationRiskTolerance = when (preset) {
            PortfolioOptimizationConstraintPreset.RISK_STRICT -> PortfolioOptimizationRiskTolerance.LOW
            PortfolioOptimizationConstraintPreset.CRITICAL_PATH_PROTECTION -> PortfolioOptimizationRiskTolerance.MODERATE
            else -> PortfolioOptimizationRiskTolerance.MODERATE
        }
    ): PortfolioOptimizationConstraintProfile {
        return PortfolioOptimizationConstraintProfile(
            profileId = "constraint_${preset.name.lowercase()}",
            preset = preset,
            riskTolerance = riskTolerance,
            constraints = defaultPortfolioOptimizationConstraints(
                preset = preset,
                riskTolerance = riskTolerance
            ),
            summary = "Constraint preset ${preset.name.lowercase().replace('_', ' ')}."
        )
    }

    private fun defaultPortfolioOptimizationObjectiveWeights(
        preset: PortfolioOptimizationObjectivePreset
    ): List<PortfolioOptimizationObjectiveWeight> {
        val weights = when (preset) {
            PortfolioOptimizationObjectivePreset.BALANCED -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 3,
                PortfolioOptimizationObjectiveFamily.RISK to 3,
                PortfolioOptimizationObjectiveFamily.SLA to 2,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 2,
                PortfolioOptimizationObjectiveFamily.STABILITY to 2,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 2
            )
            PortfolioOptimizationObjectivePreset.THROUGHPUT_FIRST -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 5,
                PortfolioOptimizationObjectiveFamily.RISK to 1,
                PortfolioOptimizationObjectiveFamily.SLA to 2,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 1,
                PortfolioOptimizationObjectiveFamily.STABILITY to 1,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 2
            )
            PortfolioOptimizationObjectivePreset.RISK_AVERSE -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 2,
                PortfolioOptimizationObjectiveFamily.RISK to 5,
                PortfolioOptimizationObjectiveFamily.SLA to 3,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 2,
                PortfolioOptimizationObjectiveFamily.STABILITY to 3,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 2
            )
            PortfolioOptimizationObjectivePreset.SLA_RECOVERY -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 2,
                PortfolioOptimizationObjectiveFamily.RISK to 3,
                PortfolioOptimizationObjectiveFamily.SLA to 5,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 1,
                PortfolioOptimizationObjectiveFamily.STABILITY to 2,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 4
            )
            PortfolioOptimizationObjectivePreset.FAIRNESS_FIRST -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 2,
                PortfolioOptimizationObjectiveFamily.RISK to 3,
                PortfolioOptimizationObjectiveFamily.SLA to 2,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 5,
                PortfolioOptimizationObjectiveFamily.STABILITY to 2,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 2
            )
            PortfolioOptimizationObjectivePreset.CRITICAL_PATH_FIRST -> mapOf(
                PortfolioOptimizationObjectiveFamily.THROUGHPUT to 2,
                PortfolioOptimizationObjectiveFamily.RISK to 3,
                PortfolioOptimizationObjectiveFamily.SLA to 4,
                PortfolioOptimizationObjectiveFamily.FAIRNESS to 1,
                PortfolioOptimizationObjectiveFamily.STABILITY to 2,
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION to 1,
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION to 5
            )
        }
        return PortfolioOptimizationObjectiveFamily.entries.map { family ->
            PortfolioOptimizationObjectiveWeight(
                family = family,
                weight = weights[family] ?: 0
            )
        }
    }

    private fun defaultPortfolioOptimizationConstraints(
        preset: PortfolioOptimizationConstraintPreset,
        riskTolerance: PortfolioOptimizationRiskTolerance
    ): List<PortfolioOptimizationConstraint> {
        val riskyLimit = when (riskTolerance) {
            PortfolioOptimizationRiskTolerance.LOW -> 0
            PortfolioOptimizationRiskTolerance.MODERATE -> 1
            PortfolioOptimizationRiskTolerance.HIGH -> 2
        }
        val automationLimit = when (preset) {
            PortfolioOptimizationConstraintPreset.CAPACITY_TIGHT -> 1
            else -> 2
        }
        return listOf(
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY,
                enabled = true,
                hardConstraint = true,
                summary = "Respect approval capacity in each window."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY,
                enabled = true,
                hardConstraint = true,
                summary = "Do not schedule inside blackout or maintenance blocks."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE,
                enabled = true,
                hardConstraint = true,
                summary = "Schedule dependent programs only after prerequisites."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.READINESS_GATE,
                enabled = true,
                hardConstraint = true,
                summary = "Respect readiness state before scheduling rollout actions."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.POLICY_GUARDRAIL,
                enabled = true,
                hardConstraint = true,
                summary = "Guardrail and policy-denied states remain blocking."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS,
                enabled = true,
                hardConstraint = true,
                intLimit = riskyLimit,
                summary = "Bound concurrent risky promotions per window."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.MANDATORY_REVIEW,
                enabled = true,
                hardConstraint = true,
                boolValue = true,
                summary = "Schedule review before promotion when approval is pending."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.MAX_AUTOMATION_ACTIONS_PER_WINDOW,
                enabled = true,
                hardConstraint = false,
                intLimit = automationLimit,
                summary = "Limit safe automation recommendations per window."
            ),
            PortfolioOptimizationConstraint(
                family = PortfolioOptimizationConstraintFamily.PINNED_TARGETS,
                enabled = true,
                hardConstraint = true,
                boolValue = true,
                summary = "Do not move pinned targets."
            )
        )
    }

    private fun normalizePortfolioOptimizationRequest(
        request: PortfolioOptimizationRequest,
        now: Long,
        calibrationSnapshotId: String = request.calibrationSnapshotId
    ): PortfolioOptimizationRequest {
        val requestId = request.requestId.trim().ifBlank { "portfolio_opt_request_${now}" }
        val objectiveProfile = normalizePortfolioOptimizationObjectiveProfile(
            profile = request.objectiveProfile,
            requestId = requestId
        )
        val constraintProfile = normalizePortfolioOptimizationConstraintProfile(
            profile = request.constraintProfile,
            requestId = requestId
        )
        val solverConfig = request.solverConfig.copy(
            seed = request.solverConfig.seed.takeIf { it != 0L } ?: 33L,
            topCandidateCount = request.solverConfig.topCandidateCount.coerceIn(1, MAX_PORTFOLIO_OPTIMIZATION_TOP_N),
            maxCandidateIterations = request.solverConfig.maxCandidateIterations.coerceIn(1, MAX_PORTFOLIO_OPTIMIZATION_ITERATIONS),
            horizonDays = request.solverConfig.horizonDays.coerceIn(1, PORTFOLIO_OPTIMIZATION_HORIZON_DAYS),
            bucketHours = PORTFOLIO_SIMULATION_BUCKET_HOURS,
            maxWindowLookaheadBuckets = request.solverConfig.maxWindowLookaheadBuckets
                .coerceIn(1, PORTFOLIO_OPTIMIZATION_HORIZON_DAYS)
        )
        val scenarioSet = request.scenarioSet.copy(
            scenarioIds = request.scenarioSet.scenarioIds
                .map(String::trim)
                .filter(String::isNotBlank)
                .distinct(),
            summary = request.scenarioSet.summary.ifBlank {
                if (request.scenarioSet.scenarioIds.isEmpty()) {
                    "Optimization uses the current durable baseline only."
                } else {
                    "Optimization overlays ${request.scenarioSet.scenarioIds.size} saved scenario(s)."
                }
            }
        )
        return request.copy(
            requestId = requestId,
            name = request.name.ifBlank { "Optimization ${requestId.takeLast(6)}" },
            summary = request.summary.ifBlank { "Bounded multi-objective portfolio optimization request." },
            targetProgramIds = request.targetProgramIds.map(String::trim).filter(String::isNotBlank).distinct(),
            objectiveProfile = objectiveProfile,
            constraintProfile = constraintProfile,
            scenarioSet = scenarioSet,
            calibrationSnapshotId = calibrationSnapshotId.trim().ifBlank {
                request.calibrationSnapshotId.trim()
            },
            solverConfig = solverConfig,
            active = request.active,
            createdAtMs = request.createdAtMs.takeIf { it > 0L } ?: now,
            updatedAtMs = now
        )
    }

    private fun normalizePortfolioOptimizationObjectiveProfile(
        profile: PortfolioOptimizationObjectiveProfile,
        requestId: String
    ): PortfolioOptimizationObjectiveProfile {
        val base = defaultPortfolioOptimizationObjectiveProfile(profile.preset)
        val provided = profile.weights.associateBy { it.family }
        return base.copy(
            profileId = profile.profileId.ifBlank { "objective_${requestId.takeLast(8)}" },
            weights = base.weights.map { weight ->
                val resolved = provided[weight.family]?.weight ?: weight.weight
                PortfolioOptimizationObjectiveWeight(
                    family = weight.family,
                    weight = resolved.coerceIn(0, 10)
                )
            },
            summary = profile.summary.ifBlank {
                "Objective preset ${profile.preset.name.lowercase().replace('_', ' ')}."
            }
        )
    }

    private fun normalizePortfolioOptimizationConstraintProfile(
        profile: PortfolioOptimizationConstraintProfile,
        requestId: String
    ): PortfolioOptimizationConstraintProfile {
        val base = defaultPortfolioOptimizationConstraintProfile(
            preset = profile.preset,
            riskTolerance = profile.riskTolerance
        )
        val provided = profile.constraints.associateBy { it.family }
        return base.copy(
            profileId = profile.profileId.ifBlank { "constraint_${requestId.takeLast(8)}" },
            constraints = base.constraints.map { constraint ->
                val override = provided[constraint.family]
                constraint.copy(
                    enabled = override?.enabled ?: constraint.enabled,
                    hardConstraint = override?.hardConstraint ?: constraint.hardConstraint,
                    intLimit = override?.intLimit ?: constraint.intLimit,
                    doubleLimit = override?.doubleLimit ?: constraint.doubleLimit,
                    boolValue = override?.boolValue ?: constraint.boolValue,
                    reasonCodes = override?.reasonCodes ?: constraint.reasonCodes,
                    summary = override?.summary?.takeIf { it.isNotBlank() } ?: constraint.summary
                )
            },
            summary = profile.summary.ifBlank {
                "Constraint preset ${profile.preset.name.lowercase().replace('_', ' ')}."
            }
        )
    }

    private fun defaultPortfolioOptimizationLearningIsolationPolicy():
        PortfolioOptimizationLearningIsolationPolicy {
        return PortfolioOptimizationLearningIsolationPolicy(
            policyId = "portfolio_learning_isolation_default",
            mode = PortfolioOptimizationLearningIsolationMode.ISOLATED_BY_DEFAULT,
            workspacePropagationEnabled = true,
            tenantPropagationEnabled = true,
            globalPropagationEnabled = false,
            crossTenantContaminationBlocked = true,
            summary = "Learning remains isolated by default; broader propagation is bounded and approval-aware."
        )
    }

    private fun defaultPortfolioOptimizationPropagationRules(): List<PortfolioOptimizationPropagationRule> {
        return listOf(
            PortfolioOptimizationPropagationRule(
                ruleId = "portfolio_propagation_user_to_workspace",
                sourceScope = PortfolioOptimizationLearningScope.USER,
                targetScope = PortfolioOptimizationLearningScope.WORKSPACE,
                enabled = true,
                approvalRequirement = PortfolioOptimizationPropagationApprovalRequirement.NOT_REQUIRED,
                sameTenantOnly = true,
                reviewRequiredOnHighDrift = true,
                summary = "User learning can promote into the current workspace when tenant isolation remains intact."
            ),
            PortfolioOptimizationPropagationRule(
                ruleId = "portfolio_propagation_workspace_to_tenant",
                sourceScope = PortfolioOptimizationLearningScope.WORKSPACE,
                targetScope = PortfolioOptimizationLearningScope.TENANT,
                enabled = true,
                approvalRequirement = PortfolioOptimizationPropagationApprovalRequirement.REQUIRED,
                sameTenantOnly = true,
                reviewRequiredOnHighDrift = true,
                summary = "Workspace learning requires approval before it can promote into the tenant baseline."
            ),
            PortfolioOptimizationPropagationRule(
                ruleId = "portfolio_propagation_tenant_to_global",
                sourceScope = PortfolioOptimizationLearningScope.TENANT,
                targetScope = PortfolioOptimizationLearningScope.GLOBAL_BASELINE,
                enabled = false,
                approvalRequirement = PortfolioOptimizationPropagationApprovalRequirement.REQUIRED,
                sameTenantOnly = false,
                reviewRequiredOnHighDrift = true,
                summary = "Tenant learning does not propagate into the global baseline by default."
            )
        )
    }

    private fun portfolioOptimizationScopePrecedence(): List<PortfolioOptimizationLearningScope> {
        return listOf(
            PortfolioOptimizationLearningScope.USER,
            PortfolioOptimizationLearningScope.WORKSPACE,
            PortfolioOptimizationLearningScope.TENANT,
            PortfolioOptimizationLearningScope.GLOBAL_BASELINE
        )
    }

    private fun portfolioOptimizationBindingForScope(
        userId: String,
        scope: PortfolioOptimizationLearningScope,
        tenantId: String?,
        workspaceId: String?
    ): PortfolioOptimizationObjectiveProfileBinding {
        val precedence = portfolioOptimizationScopePrecedence()
        return when (scope) {
            PortfolioOptimizationLearningScope.USER -> PortfolioOptimizationObjectiveProfileBinding(
                scope = scope,
                userId = userId,
                workspaceId = workspaceId,
                tenantId = tenantId,
                precedenceChain = precedence,
                summary = "User-scoped objective profile for $userId."
            )
            PortfolioOptimizationLearningScope.WORKSPACE -> PortfolioOptimizationObjectiveProfileBinding(
                scope = scope,
                userId = userId,
                workspaceId = workspaceId,
                tenantId = tenantId,
                precedenceChain = precedence,
                summary = "Workspace objective profile for ${workspaceId ?: "workspace_default"}."
            )
            PortfolioOptimizationLearningScope.TENANT -> PortfolioOptimizationObjectiveProfileBinding(
                scope = scope,
                userId = userId,
                workspaceId = workspaceId,
                tenantId = tenantId,
                precedenceChain = precedence,
                summary = "Tenant objective profile for ${tenantId ?: "tenant_default"}."
            )
            PortfolioOptimizationLearningScope.GLOBAL_BASELINE -> PortfolioOptimizationObjectiveProfileBinding(
                scope = scope,
                userId = userId,
                workspaceId = workspaceId,
                tenantId = tenantId,
                precedenceChain = precedence,
                summary = "Global baseline objective profile."
            )
        }
    }

    private fun resolvePortfolioOptimizationScopeBinding(
        userId: String,
        requested: PortfolioOptimizationObjectiveProfileBinding = PortfolioOptimizationObjectiveProfileBinding()
    ): PortfolioOptimizationObjectiveProfileBinding {
        val ledger = synchronized(dynamicStateLock) {
            executionLedgerByUser[userId]?.toList().orEmpty()
        }
        val tenantProfile = ledger
            .mapNotNull { record ->
                record.tenantRolloutProfile ?: record.receipt?.tenantRolloutProfile
            }
            .maxByOrNull { it.updatedAtMs }
        val workspaceProfile = ledger
            .mapNotNull { record ->
                record.workspaceRolloutProfile ?: record.receipt?.workspaceRolloutProfile
            }
            .maxByOrNull { it.updatedAtMs }
        val tenantId = requested.tenantId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: tenantProfile?.tenantId?.takeIf { it.isNotBlank() }
            ?: userId.substringBefore('_', userId).takeIf { it.isNotBlank() }
            ?: "tenant_default"
        val workspaceId = requested.workspaceId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: workspaceProfile?.workspaceId?.takeIf { it.isNotBlank() }
            ?: tenantProfile?.workspaceId?.takeIf { it.isNotBlank() }
            ?: "workspace_default"
        return portfolioOptimizationBindingForScope(
            userId = requested.userId?.takeIf { it.isNotBlank() } ?: userId,
            scope = requested.scope,
            tenantId = tenantId,
            workspaceId = workspaceId
        )
    }

    private fun portfolioOptimizationBindingMatches(
        snapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        binding: PortfolioOptimizationObjectiveProfileBinding
    ): Boolean {
        return when (snapshot.binding.scope) {
            PortfolioOptimizationLearningScope.USER ->
                snapshot.binding.userId == binding.userId
            PortfolioOptimizationLearningScope.WORKSPACE ->
                snapshot.binding.workspaceId == binding.workspaceId &&
                    snapshot.binding.tenantId == binding.tenantId
            PortfolioOptimizationLearningScope.TENANT ->
                snapshot.binding.tenantId == binding.tenantId
            PortfolioOptimizationLearningScope.GLOBAL_BASELINE -> true
        }
    }

    private fun portfolioOptimizationScopeLabel(scope: PortfolioOptimizationLearningScope?): String {
        return scope?.name?.lowercase()?.replace('_', ' ') ?: "unscoped"
    }

    private fun findPortfolioOptimizationObjectiveProfileSnapshotLocked(
        userId: String,
        snapshotId: String?
    ): PortfolioOptimizationObjectiveProfileSnapshot? {
        if (snapshotId.isNullOrBlank()) return null
        return portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]
            ?.toList()
            ?.firstOrNull { it.snapshotId == snapshotId }
    }

    private fun findPortfolioOptimizationCalibrationSnapshotLocked(
        userId: String,
        snapshotId: String?
    ): PortfolioOptimizationCalibrationSnapshot? {
        if (snapshotId.isNullOrBlank()) return null
        return portfolioOptimizationCalibrationSnapshotsByUser[userId]
            ?.toList()
            ?.firstOrNull { it.snapshotId == snapshotId }
    }

    private fun latestPortfolioOptimizationObjectiveProfileSnapshotForScopeLocked(
        userId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding
    ): PortfolioOptimizationObjectiveProfileSnapshot? {
        return portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { it.binding.scope == binding.scope }
            .filter { portfolioOptimizationBindingMatches(it, binding) }
            .filterNot { portfolioOptimizationObjectiveProfileSnapshotSuppressed(userId, it.snapshotId) }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationObjectiveProfileSnapshot> { it.version }
                    .thenBy { it.createdAtMs }
                    .thenBy { it.snapshotId }
            )
    }

    private fun portfolioOptimizationScopesFromTarget(
        targetScope: PortfolioOptimizationLearningScope
    ): List<PortfolioOptimizationLearningScope> {
        val precedence = portfolioOptimizationScopePrecedence()
        val startIndex = precedence.indexOf(targetScope).takeIf { it >= 0 } ?: 0
        return precedence.drop(startIndex)
    }

    private fun resolvePortfolioOptimizationTargetBaseSnapshotLocked(
        userId: String,
        targetBinding: PortfolioOptimizationObjectiveProfileBinding,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
        portfolioOptimizationScopesFromTarget(targetBinding.scope).forEach { scope ->
            val candidateBinding = portfolioOptimizationBindingForScope(
                userId = targetBinding.userId ?: userId,
                scope = scope,
                tenantId = targetBinding.tenantId,
                workspaceId = targetBinding.workspaceId
            )
            latestPortfolioOptimizationObjectiveProfileSnapshotForScopeLocked(
                userId = userId,
                binding = candidateBinding
            )?.let { return it }
        }
        return ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
    }

    private fun ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(
        userId: String,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        val queue = portfolioOptimizationObjectiveProfileSnapshotsByUser.getOrPut(userId) { ArrayDeque() }
        val existingGlobal = queue.toList().firstOrNull {
            it.binding.scope == PortfolioOptimizationLearningScope.GLOBAL_BASELINE
        }
        if (existingGlobal != null) return existingGlobal
        val globalBinding = portfolioOptimizationBindingForScope(
            userId = userId,
            scope = PortfolioOptimizationLearningScope.GLOBAL_BASELINE,
            tenantId = null,
            workspaceId = null
        )
        val globalSnapshot = PortfolioOptimizationObjectiveProfileSnapshot(
            snapshotId = "portfolio_opt_profile_global_${userId.takeLast(6)}_$now",
            profileId = "objective_profile_global_balanced",
            version = 1,
            binding = globalBinding,
            objectiveProfile = defaultPortfolioOptimizationObjectiveProfile(),
            parameterCalibration = PortfolioOptimizationParameterCalibration(
                summary = "Global baseline penalty multipliers."
            ),
            isolationPolicy = defaultPortfolioOptimizationLearningIsolationPolicy(),
            provenance = PortfolioOptimizationLearningProvenanceSummary(
                type = PortfolioOptimizationObjectiveProfileProvenanceType.GLOBAL_DEFAULT,
                summary = "Global balanced objective profile baseline."
            ),
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SCOPE_RESOLVED),
            summary = "Global baseline objective profile derived from M33/M34 defaults.",
            createdAtMs = now
        )
        queue.addLast(globalSnapshot)
        return globalSnapshot
    }

    private fun activePortfolioOptimizationObjectiveProfileSnapshot(
        userId: String,
        now: Long,
        binding: PortfolioOptimizationObjectiveProfileBinding = resolvePortfolioOptimizationScopeBinding(userId)
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        return synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(userId, binding, now)
        }
    }

    private fun resolvePortfolioOptimizationObjectiveProfileSnapshot(
        userId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        return synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(
                userId = userId,
                binding = binding,
                now = now
            )
        }
    }

    private fun resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(
        userId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        val normalizedBinding = resolvePortfolioOptimizationScopeBinding(userId, binding)
        val globalBaseline = ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
        val snapshots = portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]?.toList().orEmpty()
        portfolioOptimizationScopePrecedence().forEach { scope ->
            val matched = snapshots
                .filter { it.binding.scope == scope }
                .filter { portfolioOptimizationBindingMatches(it, normalizedBinding) }
                .filterNot { portfolioOptimizationObjectiveProfileSnapshotSuppressed(userId, it.snapshotId) }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationObjectiveProfileSnapshot> { it.version }
                        .thenBy { it.createdAtMs }
                        .thenBy { it.snapshotId }
                )
            if (matched != null) {
                return matched
            }
        }
        return globalBaseline
    }

    private fun portfolioOptimizationObjectiveProfileSnapshotSuppressed(
        userId: String,
        snapshotId: String
    ): Boolean {
        return portfolioOptimizationPropagationAdoptionsByUser[userId]
            ?.toList()
            ?.any { adoption ->
                adoption.targetObjectiveProfileSnapshotId == snapshotId &&
                    (adoption.reviewRequired ||
                        adoption.status == PortfolioOptimizationPropagationEligibilityStatus.REVIEW_REQUIRED ||
                        adoption.status == PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED)
            }
            ?: false
    }

    private fun buildPortfolioOptimizationCalibrationSnapshotFromObjectiveProfile(
        userId: String,
        objectiveProfileSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        now: Long
    ): PortfolioOptimizationCalibrationSnapshot {
        return PortfolioOptimizationCalibrationSnapshot(
            snapshotId = "portfolio_opt_calibration_${userId.takeLast(6)}_${objectiveProfileSnapshot.snapshotId.takeLast(8)}_$now",
            version = objectiveProfileSnapshot.version,
            objectiveProfileSnapshotId = objectiveProfileSnapshot.snapshotId,
            objectiveProfileBinding = objectiveProfileSnapshot.binding,
            objectiveProfileProvenance = objectiveProfileSnapshot.provenance,
            objectiveWeights = objectiveProfileSnapshot.objectiveProfile.weights,
            parameterCalibration = objectiveProfileSnapshot.parameterCalibration,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_SCOPE_RESOLVED),
            summary = "Calibration snapshot bound to ${portfolioOptimizationScopeLabel(objectiveProfileSnapshot.binding.scope)} objective profile v${objectiveProfileSnapshot.version}.",
            createdAtMs = now
        )
    }

    private fun ensurePortfolioOptimizationCalibrationSnapshotsInitializedLocked(
        userId: String,
        now: Long
    ): PortfolioOptimizationCalibrationSnapshot {
        val queue = portfolioOptimizationCalibrationSnapshotsByUser.getOrPut(userId) { ArrayDeque() }
        queue.firstOrNull()?.let { return it }
        val objectiveProfileSnapshot = ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
        val defaultSnapshot = buildPortfolioOptimizationCalibrationSnapshotFromObjectiveProfile(
            userId = userId,
            objectiveProfileSnapshot = objectiveProfileSnapshot,
            now = now
        )
        queue.addLast(defaultSnapshot)
        return defaultSnapshot
    }

    private fun activePortfolioOptimizationCalibrationSnapshot(
        userId: String,
        now: Long,
        binding: PortfolioOptimizationObjectiveProfileBinding = resolvePortfolioOptimizationScopeBinding(userId)
    ): PortfolioOptimizationCalibrationSnapshot {
        return synchronized(dynamicStateLock) {
            val objectiveProfileSnapshot = resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(
                userId = userId,
                binding = binding,
                now = now
            )
            resolvePortfolioOptimizationCalibrationSnapshotLocked(
                userId = userId,
                snapshotId = null,
                objectiveProfileSnapshot = objectiveProfileSnapshot,
                now = now
            )
        }
    }

    private fun resolvePortfolioOptimizationCalibrationSnapshot(
        userId: String,
        snapshotId: String?,
        now: Long,
        binding: PortfolioOptimizationObjectiveProfileBinding = resolvePortfolioOptimizationScopeBinding(userId)
    ): PortfolioOptimizationCalibrationSnapshot {
        return synchronized(dynamicStateLock) {
            ensurePortfolioOptimizationObjectiveProfileSnapshotsInitializedLocked(userId, now)
            ensurePortfolioOptimizationCalibrationSnapshotsInitializedLocked(userId, now)
            val explicitCalibration = findPortfolioOptimizationCalibrationSnapshotLocked(userId, snapshotId)
            val objectiveProfileSnapshot = explicitCalibration
                ?.objectiveProfileSnapshotId
                ?.let { objectiveSnapshotId ->
                    findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, objectiveSnapshotId)
                }
                ?: resolvePortfolioOptimizationObjectiveProfileSnapshotLocked(
                    userId = userId,
                    binding = binding,
                    now = now
                )
            resolvePortfolioOptimizationCalibrationSnapshotLocked(
                userId = userId,
                snapshotId = snapshotId,
                objectiveProfileSnapshot = objectiveProfileSnapshot,
                now = now
            )
        }
    }

    private fun resolvePortfolioOptimizationCalibrationSnapshot(
        userId: String,
        snapshotId: String?,
        objectiveProfileSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        now: Long
    ): PortfolioOptimizationCalibrationSnapshot {
        return synchronized(dynamicStateLock) {
            resolvePortfolioOptimizationCalibrationSnapshotLocked(
                userId = userId,
                snapshotId = snapshotId,
                objectiveProfileSnapshot = objectiveProfileSnapshot,
                now = now
            )
        }
    }

    private fun resolvePortfolioOptimizationCalibrationSnapshotLocked(
        userId: String,
        snapshotId: String?,
        objectiveProfileSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        now: Long
    ): PortfolioOptimizationCalibrationSnapshot {
        ensurePortfolioOptimizationCalibrationSnapshotsInitializedLocked(userId, now)
        val queue = portfolioOptimizationCalibrationSnapshotsByUser.getOrPut(userId) { ArrayDeque() }
        if (!snapshotId.isNullOrBlank()) {
            return queue.toList().firstOrNull { it.snapshotId == snapshotId }
                ?: resolvePortfolioOptimizationCalibrationSnapshotLocked(
                    userId = userId,
                    snapshotId = null,
                    objectiveProfileSnapshot = objectiveProfileSnapshot,
                    now = now
                )
        }
        val matching = queue.toList()
            .filter { it.objectiveProfileSnapshotId == objectiveProfileSnapshot.snapshotId }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationCalibrationSnapshot> { it.createdAtMs }
                    .thenBy { it.snapshotId }
            )
        if (matching != null) return matching
        val created = buildPortfolioOptimizationCalibrationSnapshotFromObjectiveProfile(
            userId = userId,
            objectiveProfileSnapshot = objectiveProfileSnapshot,
            now = now
        )
        storePortfolioOptimizationCalibrationSnapshotLocked(userId, created)
        return created
    }

    private fun storePortfolioOptimizationObjectiveProfileSnapshot(
        userId: String,
        snapshot: PortfolioOptimizationObjectiveProfileSnapshot
    ) {
        synchronized(dynamicStateLock) {
            storePortfolioOptimizationObjectiveProfileSnapshotLocked(userId, snapshot)
        }
    }

    private fun storePortfolioOptimizationObjectiveProfileSnapshotLocked(
        userId: String,
        snapshot: PortfolioOptimizationObjectiveProfileSnapshot
    ) {
        val queue = portfolioOptimizationObjectiveProfileSnapshotsByUser.getOrPut(userId) { ArrayDeque() }
        val merged = queue.toList()
            .filterNot { it.snapshotId == snapshot.snapshotId }
            .plus(snapshot)
            .sortedWith(
                compareByDescending<PortfolioOptimizationObjectiveProfileSnapshot> { it.createdAtMs }
                    .thenByDescending { it.version }
                    .thenBy { it.snapshotId }
            )
            .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
        queue.clear()
        merged.forEach(queue::addLast)
    }

    private fun storePortfolioOptimizationCalibrationSnapshot(
        userId: String,
        snapshot: PortfolioOptimizationCalibrationSnapshot
    ) {
        synchronized(dynamicStateLock) {
            storePortfolioOptimizationCalibrationSnapshotLocked(userId, snapshot)
        }
    }

    private fun storePortfolioOptimizationCalibrationSnapshotLocked(
        userId: String,
        snapshot: PortfolioOptimizationCalibrationSnapshot
    ) {
        val queue = portfolioOptimizationCalibrationSnapshotsByUser.getOrPut(userId) { ArrayDeque() }
        val merged = queue.toList()
            .filterNot { it.snapshotId == snapshot.snapshotId }
            .plus(snapshot)
            .sortedWith(
                compareByDescending<PortfolioOptimizationCalibrationSnapshot> { it.createdAtMs }
                    .thenByDescending { it.version }
                    .thenBy { it.snapshotId }
            )
            .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
        queue.clear()
        merged.forEach(queue::addLast)
    }

    private fun storePortfolioOptimizationOutcome(
        userId: String,
        outcome: PortfolioScheduleOutcomeRecord
    ) {
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationOutcomesByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue.toList()
                .filterNot { it.outcomeId == outcome.outcomeId }
                .plus(outcome)
                .sortedWith(
                    compareByDescending<PortfolioScheduleOutcomeRecord> { it.recordedAtMs }
                        .thenBy { it.outcomeId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
