    private fun effectivePortfolioOptimizationObjectiveProfile(
        profile: PortfolioOptimizationObjectiveProfile,
        calibrationSnapshot: PortfolioOptimizationCalibrationSnapshot
    ): PortfolioOptimizationObjectiveProfile {
        val balancedDefaults = defaultPortfolioOptimizationObjectiveWeights(
            PortfolioOptimizationObjectivePreset.BALANCED
        ).associate { it.family to it.weight.coerceIn(0, 10) }
        val snapshotWeights = calibrationSnapshot.objectiveWeights
            .associate { it.family to it.weight.coerceIn(0, 10) }
        val profileWeights = profile.weights
            .associate { it.family to it.weight.coerceIn(0, 10) }
        return profile.copy(
            weights = PortfolioOptimizationObjectiveFamily.entries.map { family ->
                val baseWeight = profileWeights[family] ?: balancedDefaults[family] ?: 0
                val snapshotBaseline = balancedDefaults[family] ?: 0
                val snapshotWeight = snapshotWeights[family] ?: snapshotBaseline
                PortfolioOptimizationObjectiveWeight(
                    family = family,
                    weight = (baseWeight + (snapshotWeight - snapshotBaseline)).coerceIn(0, 10)
                )
            },
            summary = buildString {
                append(profile.summary.ifBlank {
                    "Objective preset ${profile.preset.name.lowercase().replace('_', ' ')}."
                })
                append(" Calibration snapshot v")
                append(calibrationSnapshot.version)
                append(" applied.")
            }
        )
    }

    private fun portfolioOptimizationObjectiveFamilyForTarget(
        targetFamily: PortfolioOptimizationTuningTargetFamily
    ): PortfolioOptimizationObjectiveFamily? {
        return when (targetFamily) {
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_THROUGHPUT ->
                PortfolioOptimizationObjectiveFamily.THROUGHPUT
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_RISK ->
                PortfolioOptimizationObjectiveFamily.RISK
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_SLA ->
                PortfolioOptimizationObjectiveFamily.SLA
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_FAIRNESS ->
                PortfolioOptimizationObjectiveFamily.FAIRNESS
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_STABILITY ->
                PortfolioOptimizationObjectiveFamily.STABILITY
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_OPERATOR_FRICTION ->
                PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_CRITICAL_PATH_PROTECTION ->
                PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION
            PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY,
            PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY,
            PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY,
            PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY -> null
        }
    }

    private fun derivePortfolioOptimizationOutcomeObservations(
        candidate: PortfolioOptimizationCandidateSchedule,
        casesByRunId: Map<String, GovernanceCaseRecord>,
        solverConfig: PortfolioOptimizationSolverConfig,
        now: Long
    ): PortfolioOutcomeObservationSet {
        val scheduledByRunId = candidate.scheduledActions.associateBy { it.sourceRunId }
        val deferredByRunId = candidate.deferredActions.associateBy { it.sourceRunId }
        val runIds = (scheduledByRunId.keys + deferredByRunId.keys)
            .distinct()
            .sorted()
        val executionObservations = runIds.map { runId ->
            val scheduled = scheduledByRunId[runId]
            val deferred = deferredByRunId[runId]
            val case = casesByRunId[runId]
            val readinessDelayed = case?.summary?.rolloutPromotionReadinessStatus in setOf(
                RolloutPromotionReadinessStatus.BLOCKED,
                RolloutPromotionReadinessStatus.DEFERRED,
                RolloutPromotionReadinessStatus.PAUSED,
                RolloutPromotionReadinessStatus.EXPIRED
            ) || deferred?.blockedBy == PortfolioOptimizationConstraintFamily.READINESS_GATE
            val windowDelayed = case?.summary?.scheduleDecision in setOf(
                ExecutionWindowDecision.BLOCKED,
                ExecutionWindowDecision.DEFERRED,
                ExecutionWindowDecision.EXPIRED
            ) || case?.summary?.scheduleWaitingMaintenance == true ||
                case?.summary?.windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
                case?.summary?.windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW ||
                deferred?.blockedBy == PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY
            val executedOnTime = scheduled != null &&
                case?.summary?.capacityBlocked != true &&
                case?.summary?.policyBlocked != true &&
                !readinessDelayed &&
                !windowDelayed
            PortfolioExecutionObservation(
                sourceRunId = runId,
                executedOnTime = executedOnTime,
                executedAtMs = if (executedOnTime) {
                    scheduled?.scheduledAtMs ?: now
                } else {
                    null
                },
                actualBucketIndex = when {
                    executedOnTime -> scheduled?.scheduledBucketIndex
                    scheduled != null -> scheduled.scheduledBucketIndex + 1
                    else -> null
                },
                actualActionType = scheduled?.type ?: PortfolioOptimizationActionType.DEFER_TO_NEXT_WINDOW,
                readinessDelayed = readinessDelayed,
                summary = if (executedOnTime) {
                    "$runId stayed on the planned schedule."
                } else {
                    "$runId drifted from the planned schedule."
                }
            )
        }
        val approvalLatencyObservations = runIds.mapNotNull { runId ->
            val scheduled = scheduledByRunId[runId]
            val deferred = deferredByRunId[runId]
            val case = casesByRunId[runId] ?: return@mapNotNull null
            val requiresApproval = scheduled?.requiresApproval == true ||
                case.summary.policyApprovalPending ||
                deferred?.blockedBy == PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY
            if (!requiresApproval) return@mapNotNull null
            val latencyHours = when {
                case.summary.approvalQueueSaturated -> solverConfig.bucketHours * 2.0
                case.summary.policyApprovalPending -> solverConfig.bucketHours.toDouble()
                else -> 0.0
            }
            PortfolioApprovalLatencyObservation(
                sourceRunId = runId,
                latencyHours = latencyHours,
                approved = !case.summary.policyApprovalPending,
                summary = if (latencyHours > 0.0) {
                    "Approval latency remained elevated for $runId."
                } else {
                    "Approval latency stayed within the planned window for $runId."
                }
            )
        }
        val windowUtilizationObservations = runIds.map { runId ->
            val deferred = deferredByRunId[runId]
            val case = casesByRunId[runId]
            val missedWindow = case?.summary?.scheduleDecision in setOf(
                ExecutionWindowDecision.BLOCKED,
                ExecutionWindowDecision.DEFERRED
            ) || case?.summary?.windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
                case?.summary?.windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW ||
                deferred?.blockedBy == PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY
            val expiredWindow = case?.summary?.scheduleDecision == ExecutionWindowDecision.EXPIRED ||
                case?.summary?.rolloutPromotionReadinessStatus == RolloutPromotionReadinessStatus.EXPIRED
            PortfolioWindowUtilizationObservation(
                sourceRunId = runId,
                missedWindow = missedWindow,
                expiredWindow = expiredWindow,
                actualEligibleAtMs = case?.summary?.nextEligiblePromotionAtMs
                    ?: case?.summary?.scheduleNextEligibleAtMs,
                summary = if (missedWindow || expiredWindow) {
                    "Window availability drifted for $runId."
                } else {
                    "Window availability matched the plan for $runId."
                }
            )
        }
        val riskIncidentObservations = runIds.map { runId ->
            val case = casesByRunId[runId]
            val riskSeverity = case?.let {
                portfolioOptimizationRiskBucket(portfolioOptimizationRiskPenalty(it))
            } ?: PortfolioOptimizationRiskBucket.LOW
            val incidentCount = buildList {
                when (case?.summary?.crossWaveHealthBucket) {
                    WaveHealthBucket.DEGRADED -> add(1)
                    WaveHealthBucket.BLOCKED -> add(2)
                    else -> Unit
                }
                if (case?.connectorHealthSummary?.overallStatus?.contains("degraded", ignoreCase = true) == true ||
                    case?.connectorHealthSummary?.overallStatus?.contains("unavailable", ignoreCase = true) == true
                ) {
                    add(1)
                }
                when (case?.lastConnectorCredentialLifecycle?.state) {
                    ConnectorCredentialLifecycleState.EXPIRED,
                    ConnectorCredentialLifecycleState.REVOKED,
                    ConnectorCredentialLifecycleState.ROTATION_REQUIRED,
                    ConnectorCredentialLifecycleState.MISCONFIGURED -> add(1)
                    else -> Unit
                }
            }.sum()
            PortfolioRiskIncidentObservation(
                sourceRunId = runId,
                incidentCount = incidentCount,
                severity = riskSeverity,
                summary = if (incidentCount > 0) {
                    "Risk incidents surfaced for $runId."
                } else {
                    "No material risk incidents surfaced for $runId."
                }
            )
        }
        val constraintBindingObservations = runIds.flatMap { runId ->
            val case = casesByRunId[runId]
            val observedFamilies = buildSet {
                if (case?.summary?.capacityBlocked == true || case?.summary?.approvalQueueSaturated == true) {
                    add(PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY)
                }
                if (case?.summary?.scheduleDecision in setOf(
                        ExecutionWindowDecision.BLOCKED,
                        ExecutionWindowDecision.DEFERRED,
                        ExecutionWindowDecision.EXPIRED
                    ) || case?.summary?.scheduleWaitingMaintenance == true ||
                    case?.summary?.windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
                    case?.summary?.windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW
                ) {
                    add(PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY)
                }
                if ((case?.summary?.programDependencyBlockedCount ?: 0) > 0) {
                    add(PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE)
                }
                if (case?.summary?.rolloutPromotionReadinessStatus in setOf(
                        RolloutPromotionReadinessStatus.BLOCKED,
                        RolloutPromotionReadinessStatus.DEFERRED,
                        RolloutPromotionReadinessStatus.PAUSED,
                        RolloutPromotionReadinessStatus.EXPIRED
                    )
                ) {
                    add(PortfolioOptimizationConstraintFamily.READINESS_GATE)
                }
                if (case?.summary?.policyBlocked == true) {
                    add(PortfolioOptimizationConstraintFamily.POLICY_GUARDRAIL)
                }
                if (case?.summary?.policyApprovalPending == true) {
                    add(PortfolioOptimizationConstraintFamily.MANDATORY_REVIEW)
                }
                if ((scheduledByRunId[runId]?.riskBucket == PortfolioOptimizationRiskBucket.HIGH ||
                        scheduledByRunId[runId]?.riskBucket == PortfolioOptimizationRiskBucket.CRITICAL) &&
                    case?.summary?.crossWaveHealthBucket in setOf(WaveHealthBucket.DEGRADED, WaveHealthBucket.BLOCKED)
                ) {
                    add(PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS)
                }
            }
            observedFamilies.map { family ->
                PortfolioConstraintBindingObservation(
                    sourceRunId = runId,
                    family = family,
                    bindingObserved = true,
                    count = 1,
                    summary = "$family remained binding for $runId."
                )
            }
        }
        return PortfolioOutcomeObservationSet(
            executionObservations = executionObservations,
            approvalLatencyObservations = approvalLatencyObservations,
            windowUtilizationObservations = windowUtilizationObservations,
            riskIncidentObservations = riskIncidentObservations,
            constraintBindingObservations = constraintBindingObservations,
            summary = "Derived deterministic outcome observations from current governance truth."
        )
    }

    private fun mergePortfolioOptimizationOutcomeObservations(
        derived: PortfolioOutcomeObservationSet,
        manual: PortfolioOutcomeObservationSet
    ): PortfolioOutcomeObservationSet {
        fun <T> merge(
            derivedItems: List<T>,
            manualItems: List<T>,
            key: (T) -> String
        ): List<T> {
            val merged = linkedMapOf<String, T>()
            derivedItems.sortedBy(key).forEach { merged[key(it)] = it }
            manualItems.sortedBy(key).forEach { merged[key(it)] = it }
            return merged.values.toList()
        }
        return PortfolioOutcomeObservationSet(
            executionObservations = merge(
                derived.executionObservations,
                manual.executionObservations
            ) { it.sourceRunId },
            approvalLatencyObservations = merge(
                derived.approvalLatencyObservations,
                manual.approvalLatencyObservations
            ) { it.sourceRunId },
            windowUtilizationObservations = merge(
                derived.windowUtilizationObservations,
                manual.windowUtilizationObservations
            ) { it.sourceRunId },
            riskIncidentObservations = merge(
                derived.riskIncidentObservations,
                manual.riskIncidentObservations
            ) { it.sourceRunId },
            constraintBindingObservations = merge(
                derived.constraintBindingObservations,
                manual.constraintBindingObservations
            ) { "${it.sourceRunId}:${it.family.name}" },
            summary = manual.summary.ifBlank { derived.summary }
        )
    }

    private fun computePortfolioOptimizationDriftSummary(
        outcome: PortfolioScheduleOutcomeRecord,
        now: Long
    ): PortfolioOptimizationDriftSummary {
        fun normalizedDelta(predicted: Double, actual: Double): Double {
            if (predicted <= 0.0 && actual <= 0.0) return 0.0
            return (kotlin.math.abs(actual - predicted) / maxOf(1.0, predicted, actual))
                .coerceIn(0.0, 1.0)
        }
        val actualOnTimeCount = outcome.observations.executionObservations.count { it.executedOnTime }.toDouble()
        val actualWindowMissCount = outcome.observations.windowUtilizationObservations.count {
            it.missedWindow || it.expiredWindow
        }.toDouble()
        val actualReadinessDelayCount = outcome.observations.executionObservations.count { it.readinessDelayed }.toDouble()
        val actualRiskIncidentCount = outcome.observations.riskIncidentObservations.sumOf { it.incidentCount }.toDouble()
        val actualApprovalLatencyHours = outcome.observations.approvalLatencyObservations
            .map { it.latencyHours }
            .average()
            .takeIf { !it.isNaN() }
            ?: 0.0
        val actualBindingConstraintCount = outcome.observations.constraintBindingObservations
            .filter { it.bindingObserved }
            .map { it.family }
            .distinct()
            .size
            .toDouble()
        val deltas = listOf(
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.OBJECTIVE_THROUGHPUT,
                predictedValue = outcome.predictedOnTimeCount.toDouble(),
                actualValue = actualOnTimeCount,
                normalizedDelta = normalizedDelta(outcome.predictedOnTimeCount.toDouble(), actualOnTimeCount),
                summary = "On-time execution drift."
            ),
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY,
                predictedValue = outcome.predictedAverageApprovalLatencyHours,
                actualValue = actualApprovalLatencyHours,
                normalizedDelta = normalizedDelta(outcome.predictedAverageApprovalLatencyHours, actualApprovalLatencyHours),
                summary = "Approval latency drift."
            ),
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY,
                predictedValue = outcome.predictedWindowMissCount.toDouble(),
                actualValue = actualWindowMissCount,
                normalizedDelta = normalizedDelta(outcome.predictedWindowMissCount.toDouble(), actualWindowMissCount),
                summary = "Window miss drift."
            ),
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY,
                predictedValue = outcome.predictedReadinessDelayCount.toDouble(),
                actualValue = actualReadinessDelayCount,
                normalizedDelta = normalizedDelta(outcome.predictedReadinessDelayCount.toDouble(), actualReadinessDelayCount),
                summary = "Readiness delay drift."
            ),
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY,
                predictedValue = outcome.predictedRiskIncidentCount.toDouble(),
                actualValue = actualRiskIncidentCount,
                normalizedDelta = normalizedDelta(outcome.predictedRiskIncidentCount.toDouble(), actualRiskIncidentCount),
                summary = "Risk incident drift."
            ),
            PortfolioPredictionVsActualDelta(
                family = PortfolioOptimizationTuningTargetFamily.OBJECTIVE_STABILITY,
                predictedValue = outcome.predictedBindingConstraints.size.toDouble(),
                actualValue = actualBindingConstraintCount,
                normalizedDelta = normalizedDelta(
                    outcome.predictedBindingConstraints.size.toDouble(),
                    actualBindingConstraintCount
                ),
                summary = "Binding constraint drift."
            )
        )
        val signals = deltas.mapNotNull { delta ->
            val severity = portfolioOptimizationDriftSeverity(delta.normalizedDelta)
            if (severity == PortfolioDriftSeverity.NONE) {
                null
            } else {
                PortfolioDriftSignal(
                    signalId = "portfolio_opt_drift_signal_${outcome.decisionId.takeLast(8)}_${delta.family.name.lowercase()}",
                    family = delta.family,
                    severity = severity,
                    normalizedDelta = delta.normalizedDelta,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_DRIFT_DETECTED),
                    summary = "${delta.family.name.lowercase().replace('_', ' ')} drift is ${severity.name.lowercase()}."
                )
            }
        }
        val highestSeverity = signals.maxByOrNull { it.severity.ordinal }?.severity ?: PortfolioDriftSeverity.NONE
        return PortfolioOptimizationDriftSummary(
            driftId = "portfolio_opt_drift_${outcome.decisionId.takeLast(10)}_$now",
            decisionId = outcome.decisionId,
            outcomeId = outcome.outcomeId,
            calibrationSnapshotId = outcome.calibrationSnapshotId,
            objectiveProfileSnapshotId = outcome.objectiveProfileSnapshotId,
            objectiveProfileBinding = outcome.objectiveProfileBinding,
            highestSeverity = highestSeverity,
            deltas = deltas,
            signals = signals,
            evidenceRefs = outcome.evidenceRefs,
            reasonCodes = if (signals.isNotEmpty()) {
                listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_DRIFT_DETECTED)
            } else {
                emptyList()
            },
            summary = if (signals.isEmpty()) {
                "No material drift detected against the selected schedule."
            } else {
                "${highestSeverity.name.lowercase().replaceFirstChar { it.uppercase() }} drift detected across ${
                    signals.joinToString { it.family.name.lowercase().replace('_', ' ') }
                }."
            },
            createdAtMs = now
        )
    }

    private fun portfolioOptimizationDriftSeverity(
        normalizedDelta: Double
    ): PortfolioDriftSeverity {
        return when {
            normalizedDelta >= 0.50 -> PortfolioDriftSeverity.CRITICAL
            normalizedDelta >= 0.35 -> PortfolioDriftSeverity.HIGH
            normalizedDelta >= 0.20 -> PortfolioDriftSeverity.MEDIUM
            normalizedDelta >= 0.10 -> PortfolioDriftSeverity.LOW
            else -> PortfolioDriftSeverity.NONE
        }
    }

    private fun maybeBuildPortfolioOptimizationTuningSuggestion(
        userId: String,
        activeCalibrationSnapshot: PortfolioOptimizationCalibrationSnapshot,
        outcome: PortfolioScheduleOutcomeRecord,
        driftSummary: PortfolioOptimizationDriftSummary,
        now: Long
    ): PortfolioOptimizationTuningSuggestion? {
        if (activeCalibrationSnapshot.snapshotId != driftSummary.calibrationSnapshotId) return null
        val outcomesForSnapshot = synchronized(dynamicStateLock) {
            portfolioOptimizationOutcomesByUser[userId]?.toList().orEmpty()
                .filter { it.calibrationSnapshotId == activeCalibrationSnapshot.snapshotId }
        }.sortedWith(
            compareByDescending<PortfolioScheduleOutcomeRecord> { it.recordedAtMs }
                .thenBy { it.outcomeId }
        )
        if (outcomesForSnapshot.size < 3) return null
        val recentOutcomeIds = outcomesForSnapshot.take(5).map { it.outcomeId }.toSet()
        val recentDrifts = synchronized(dynamicStateLock) {
            portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
                .filter { it.outcomeId in recentOutcomeIds }
        }
        val latestHighSignal = driftSummary.signals
            .filter { it.severity == PortfolioDriftSeverity.HIGH || it.severity == PortfolioDriftSeverity.CRITICAL }
            .maxByOrNull { it.severity.ordinal }
        val repeatedMediumSignal = recentDrifts
            .flatMap { it.signals }
            .groupBy { it.family }
            .mapNotNull { (family, signals) ->
                if (signals.count { it.severity == PortfolioDriftSeverity.MEDIUM } >= 2) {
                    signals.maxByOrNull { it.normalizedDelta }?.copy(family = family)
                } else {
                    null
                }
            }
            .maxByOrNull { it.normalizedDelta }
        val selectedSignal = latestHighSignal ?: repeatedMediumSignal ?: return null
        val existingPending = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningSuggestionsByUser[userId]?.toList().orEmpty().any {
                it.calibrationSnapshotId == activeCalibrationSnapshot.snapshotId &&
                    it.targetFamily == selectedSignal.family &&
                    it.status == PortfolioOptimizationTuningStatus.PENDING
            }
        }
        if (existingPending) return null
        val delta = (driftSummary.deltas + recentDrifts.flatMap { it.deltas })
            .firstOrNull { it.family == selectedSignal.family }
            ?: return null
        val objectiveFamily = portfolioOptimizationObjectiveFamilyForTarget(selectedSignal.family)
        val currentObjectiveWeights = activeCalibrationSnapshot.objectiveWeights
            .associate { it.family to it.weight }
        val currentParameterCalibration = activeCalibrationSnapshot.parameterCalibration
        val shouldIncrease = when (selectedSignal.family) {
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_THROUGHPUT ->
                delta.actualValue < delta.predictedValue
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_STABILITY ->
                delta.actualValue > delta.predictedValue
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_RISK,
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_SLA,
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_FAIRNESS,
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_OPERATOR_FRICTION,
            PortfolioOptimizationTuningTargetFamily.OBJECTIVE_CRITICAL_PATH_PROTECTION,
            PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY,
            PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY,
            PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY,
            PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY -> delta.actualValue > delta.predictedValue
        }
        val guardrails = buildList {
            if (objectiveFamily != null) {
                add(PortfolioOptimizationTuningGuardrail.OBJECTIVE_WEIGHT_DELTA_CAP)
            } else {
                add(PortfolioOptimizationTuningGuardrail.PARAMETER_MULTIPLIER_DELTA_CAP)
            }
            if (selectedSignal.family == PortfolioOptimizationTuningTargetFamily.OBJECTIVE_RISK ||
                selectedSignal.family == PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY
            ) {
                add(PortfolioOptimizationTuningGuardrail.RISK_REGRESSION_PROTECTION)
            }
        }
        return if (objectiveFamily != null) {
            val currentValue = currentObjectiveWeights[objectiveFamily]
                ?: defaultPortfolioOptimizationObjectiveWeights(PortfolioOptimizationObjectivePreset.BALANCED)
                    .firstOrNull { it.family == objectiveFamily }
                    ?.weight
                ?: 0
            val intDelta = if (shouldIncrease) 1 else -1
            val proposedValue = (currentValue + intDelta).coerceIn(0, 10)
            PortfolioOptimizationTuningSuggestion(
                suggestionId = "portfolio_opt_tune_${selectedSignal.family.name.lowercase()}_$now",
                decisionId = outcome.decisionId,
                driftId = driftSummary.driftId,
                calibrationSnapshotId = activeCalibrationSnapshot.snapshotId,
                objectiveProfileSnapshotId = activeCalibrationSnapshot.objectiveProfileSnapshotId,
                objectiveProfileBinding = activeCalibrationSnapshot.objectiveProfileBinding,
                targetFamily = selectedSignal.family,
                status = PortfolioOptimizationTuningStatus.PENDING,
                currentIntValue = currentValue,
                proposedIntValue = proposedValue,
                intDelta = intDelta,
                guardrails = guardrails,
                evidenceRefs = driftSummary.evidenceRefs,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_SUGGESTED),
                summary = "Suggest ${if (intDelta > 0) "increasing" else "decreasing"} ${
                    selectedSignal.family.name.lowercase().replace('_', ' ')
                } from $currentValue to $proposedValue.",
                createdAtMs = now
            )
        } else {
            val currentValue = when (selectedSignal.family) {
                PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY ->
                    currentParameterCalibration.approvalLatencyPenaltyMultiplier
                PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY ->
                    currentParameterCalibration.readinessDelayPenaltyMultiplier
                PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY ->
                    currentParameterCalibration.windowMissPenaltyMultiplier
                PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY ->
                    currentParameterCalibration.riskIncidentPenaltyMultiplier
                else -> 1.0
            }
            val doubleDelta = if (shouldIncrease) 0.20 else -0.20
            val proposedValue = (currentValue + doubleDelta).coerceIn(0.50, 2.00)
            PortfolioOptimizationTuningSuggestion(
                suggestionId = "portfolio_opt_tune_${selectedSignal.family.name.lowercase()}_$now",
                decisionId = outcome.decisionId,
                driftId = driftSummary.driftId,
                calibrationSnapshotId = activeCalibrationSnapshot.snapshotId,
                objectiveProfileSnapshotId = activeCalibrationSnapshot.objectiveProfileSnapshotId,
                objectiveProfileBinding = activeCalibrationSnapshot.objectiveProfileBinding,
                targetFamily = selectedSignal.family,
                status = PortfolioOptimizationTuningStatus.PENDING,
                currentDoubleValue = currentValue,
                proposedDoubleValue = proposedValue,
                doubleDelta = doubleDelta,
                guardrails = guardrails,
                evidenceRefs = driftSummary.evidenceRefs,
                reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_SUGGESTED),
                summary = "Suggest ${if (doubleDelta > 0.0) "raising" else "lowering"} ${
                    selectedSignal.family.name.lowercase().replace('_', ' ')
                } from ${"%.2f".format(Locale.US, currentValue)} to ${"%.2f".format(Locale.US, proposedValue)}.",
                createdAtMs = now
            )
        }
    }

    private fun portfolioOptimizationApplyTuningGuardrailBlocks(
        userId: String,
        suggestion: PortfolioOptimizationTuningSuggestion,
        now: Long
    ): List<PortfolioOptimizationTuningGuardrail> {
        val blocks = mutableListOf<PortfolioOptimizationTuningGuardrail>()
        if (kotlin.math.abs(suggestion.intDelta ?: 0) > 1) {
            blocks += PortfolioOptimizationTuningGuardrail.OBJECTIVE_WEIGHT_DELTA_CAP
        }
        if (kotlin.math.abs(suggestion.doubleDelta ?: 0.0) > 0.20 + 1e-9) {
            blocks += PortfolioOptimizationTuningGuardrail.PARAMETER_MULTIPLIER_DELTA_CAP
        }
        val outcomeCount = synchronized(dynamicStateLock) {
            portfolioOptimizationOutcomesByUser[userId]?.count {
                it.calibrationSnapshotId == suggestion.calibrationSnapshotId
            } ?: 0
        }
        if (outcomeCount < 3) {
            blocks += PortfolioOptimizationTuningGuardrail.MINIMUM_OUTCOME_EVIDENCE
        }
        val recentAppliedCount = synchronized(dynamicStateLock) {
            portfolioOptimizationTuningDecisionsByUser[userId]?.toList().orEmpty().count { decision ->
                decision.status == PortfolioOptimizationTuningStatus.APPLIED &&
                    now - decision.decidedAtMs <= PORTFOLIO_OPTIMIZATION_TUNING_LINEAGE_WINDOW_MS &&
                    portfolioOptimizationSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = decision.calibrationSnapshotId,
                        rightSnapshotId = suggestion.calibrationSnapshotId
                    )
            }
        }
        if (recentAppliedCount >= 2) {
            blocks += PortfolioOptimizationTuningGuardrail.MAX_APPLIES_PER_LINEAGE_WINDOW
        }
        val reducesRiskProtection = (suggestion.targetFamily == PortfolioOptimizationTuningTargetFamily.OBJECTIVE_RISK &&
            (suggestion.intDelta ?: 0) < 0) ||
            (suggestion.targetFamily == PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY &&
                (suggestion.doubleDelta ?: 0.0) < 0.0)
        if (reducesRiskProtection && portfolioOptimizationRiskIncidentsTrendingUp(userId, suggestion.calibrationSnapshotId)) {
            blocks += PortfolioOptimizationTuningGuardrail.RISK_REGRESSION_PROTECTION
        }
        return blocks.distinct()
    }

    private fun portfolioOptimizationRiskIncidentsTrendingUp(
        userId: String,
        calibrationSnapshotId: String
    ): Boolean {
        return synchronized(dynamicStateLock) {
            portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
                .filter { it.calibrationSnapshotId == calibrationSnapshotId }
                .sortedWith(compareByDescending<PortfolioOptimizationDriftSummary> { it.createdAtMs }.thenBy { it.driftId })
                .take(5)
                .flatMap { it.deltas }
                .any { delta ->
                    delta.family == PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY &&
                        delta.actualValue > delta.predictedValue
                }
        }
    }

    private fun portfolioOptimizationSnapshotsShareLineage(
        userId: String,
        leftSnapshotId: String,
        rightSnapshotId: String
    ): Boolean {
        if (leftSnapshotId == rightSnapshotId) return true
        val snapshotsById = synchronized(dynamicStateLock) {
            portfolioOptimizationCalibrationSnapshotsByUser[userId]?.toList().orEmpty()
                .associateBy { it.snapshotId }
        }
        fun lineage(snapshotId: String): Set<String> {
            val lineageIds = mutableSetOf<String>()
            var cursor: PortfolioOptimizationCalibrationSnapshot? = snapshotsById[snapshotId]
            while (cursor != null && lineageIds.add(cursor.snapshotId)) {
                cursor = cursor.parentSnapshotId?.let { snapshotsById[it] }
            }
            return lineageIds
        }
        val leftLineage = lineage(leftSnapshotId)
        val rightLineage = lineage(rightSnapshotId)
        return leftLineage.intersect(rightLineage).isNotEmpty()
    }

    private fun portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
        userId: String,
        leftSnapshotId: String,
        rightSnapshotId: String
    ): Boolean {
        if (leftSnapshotId == rightSnapshotId) return true
        val snapshotsById = synchronized(dynamicStateLock) {
            portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]?.toList().orEmpty()
                .associateBy { it.snapshotId }
        }
        fun lineage(snapshotId: String): Set<String> {
            val lineageIds = mutableSetOf<String>()
            var cursor: PortfolioOptimizationObjectiveProfileSnapshot? = snapshotsById[snapshotId]
            while (cursor != null && lineageIds.add(cursor.snapshotId)) {
                cursor = cursor.parentSnapshotId?.let { snapshotsById[it] }
            }
            return lineageIds
        }
        val leftLineage = lineage(leftSnapshotId)
        val rightLineage = lineage(rightSnapshotId)
        return leftLineage.intersect(rightLineage).isNotEmpty()
    }

    private fun buildPortfolioOptimizationTunedObjectiveProfileSnapshot(
        userId: String,
        sourceSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        suggestion: PortfolioOptimizationTuningSuggestion,
        operatorId: String?,
        operatorName: String?,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        val currentWeights = sourceSnapshot.objectiveProfile.weights
            .associate { it.family to it.weight.coerceIn(0, 10) }
        val objectiveTarget = portfolioOptimizationObjectiveFamilyForTarget(suggestion.targetFamily)
        val updatedWeights = PortfolioOptimizationObjectiveFamily.entries.map { family ->
            val current = currentWeights[family] ?: 0
            val proposed = if (family == objectiveTarget) {
                suggestion.proposedIntValue ?: (current + (suggestion.intDelta ?: 0)).coerceIn(0, 10)
            } else {
                current
            }
            PortfolioOptimizationObjectiveWeight(
                family = family,
                weight = proposed.coerceIn(0, 10)
            )
        }
        val updatedParameterCalibration = when (suggestion.targetFamily) {
            PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY ->
                sourceSnapshot.parameterCalibration.copy(
                    approvalLatencyPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: sourceSnapshot.parameterCalibration.approvalLatencyPenaltyMultiplier +
                                (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY ->
                sourceSnapshot.parameterCalibration.copy(
                    readinessDelayPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: sourceSnapshot.parameterCalibration.readinessDelayPenaltyMultiplier +
                                (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY ->
                sourceSnapshot.parameterCalibration.copy(
                    windowMissPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: sourceSnapshot.parameterCalibration.windowMissPenaltyMultiplier +
                                (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY ->
                sourceSnapshot.parameterCalibration.copy(
                    riskIncidentPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: sourceSnapshot.parameterCalibration.riskIncidentPenaltyMultiplier +
                                (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            else -> sourceSnapshot.parameterCalibration
        }
        val userBinding = portfolioOptimizationBindingForScope(
            userId = userId,
            scope = PortfolioOptimizationLearningScope.USER,
            tenantId = sourceSnapshot.binding.tenantId,
            workspaceId = sourceSnapshot.binding.workspaceId
        )
        return PortfolioOptimizationObjectiveProfileSnapshot(
            snapshotId = "portfolio_opt_profile_user_${suggestion.suggestionId.takeLast(8)}_$now",
            parentSnapshotId = sourceSnapshot.snapshotId,
            profileId = sourceSnapshot.profileId.ifBlank { "objective_profile_user_${userId.takeLast(6)}" },
            version = sourceSnapshot.version + 1,
            binding = userBinding,
            objectiveProfile = sourceSnapshot.objectiveProfile.copy(
                profileId = sourceSnapshot.objectiveProfile.profileId.ifBlank {
                    "objective_${suggestion.suggestionId.takeLast(8)}"
                },
                weights = updatedWeights,
                summary = "User objective profile tuned from ${portfolioOptimizationScopeLabel(sourceSnapshot.binding.scope)} scope."
            ),
            parameterCalibration = updatedParameterCalibration.copy(
                summary = "User parameter calibration tuned from suggestion ${suggestion.suggestionId.takeLast(8)}."
            ),
            isolationPolicy = sourceSnapshot.isolationPolicy,
            provenance = PortfolioOptimizationLearningProvenanceSummary(
                type = PortfolioOptimizationObjectiveProfileProvenanceType.LOCAL_TUNED,
                sourceScope = sourceSnapshot.binding.scope,
                sourceSnapshotId = sourceSnapshot.snapshotId,
                operatorId = operatorId,
                operatorName = operatorName,
                summary = "Local user tuning applied on top of ${portfolioOptimizationScopeLabel(sourceSnapshot.binding.scope)} profile lineage."
            ),
            reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_APPLIED),
            summary = "User objective profile snapshot v${sourceSnapshot.version + 1} tuned from suggestion ${suggestion.suggestionId.takeLast(8)}.",
            createdAtMs = now
        )
    }

    private fun portfolioOptimizationPropagationRuleFor(
        sourceScope: PortfolioOptimizationLearningScope,
        targetScope: PortfolioOptimizationLearningScope
    ): PortfolioOptimizationPropagationRule? {
        return defaultPortfolioOptimizationPropagationRules().firstOrNull { rule ->
            rule.sourceScope == sourceScope && rule.targetScope == targetScope
        }
    }

    private fun evaluatePortfolioOptimizationIsolationDecision(
        sourceBinding: PortfolioOptimizationObjectiveProfileBinding,
        targetBinding: PortfolioOptimizationObjectiveProfileBinding,
        policy: PortfolioOptimizationLearningIsolationPolicy,
        rule: PortfolioOptimizationPropagationRule?
    ): PortfolioOptimizationLearningIsolationDecision {
        val decisionId = buildString {
            append("portfolio_opt_isolation_")
            append(portfolioOptimizationScopeLabel(sourceBinding.scope))
            append("_to_")
            append(portfolioOptimizationScopeLabel(targetBinding.scope))
        }
        if (rule == null) {
            return PortfolioOptimizationLearningIsolationDecision(
                decisionId = decisionId,
                sourceBinding = sourceBinding,
                targetBinding = targetBinding,
                policy = policy,
                allowed = false,
                blockReason = PortfolioOptimizationPropagationBlockReason.UNSUPPORTED_SOURCE_SCOPE,
                reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED),
                summary = "No bounded propagation rule allows ${portfolioOptimizationScopeLabel(sourceBinding.scope)} learning to promote into ${portfolioOptimizationScopeLabel(targetBinding.scope)}."
            )
        }
        val scopeEnabled = when (targetBinding.scope) {
            PortfolioOptimizationLearningScope.USER -> true
            PortfolioOptimizationLearningScope.WORKSPACE -> policy.workspacePropagationEnabled
            PortfolioOptimizationLearningScope.TENANT -> policy.tenantPropagationEnabled
            PortfolioOptimizationLearningScope.GLOBAL_BASELINE -> policy.globalPropagationEnabled
        }
        if (!rule.enabled || !scopeEnabled) {
            return PortfolioOptimizationLearningIsolationDecision(
                decisionId = decisionId,
                sourceBinding = sourceBinding,
                targetBinding = targetBinding,
                policy = policy,
                allowed = false,
                blockReason = PortfolioOptimizationPropagationBlockReason.RULE_DISABLED,
                reasonCodes = listOf(
                    RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED,
                    RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED
                ),
                summary = "Propagation into ${portfolioOptimizationScopeLabel(targetBinding.scope)} is disabled by the current isolation policy."
            )
        }
        if (
            targetBinding.scope != PortfolioOptimizationLearningScope.GLOBAL_BASELINE &&
            ((targetBinding.scope == PortfolioOptimizationLearningScope.WORKSPACE && targetBinding.workspaceId.isNullOrBlank()) ||
                targetBinding.tenantId.isNullOrBlank())
        ) {
            return PortfolioOptimizationLearningIsolationDecision(
                decisionId = decisionId,
                sourceBinding = sourceBinding,
                targetBinding = targetBinding,
                policy = policy,
                allowed = false,
                blockReason = PortfolioOptimizationPropagationBlockReason.MISSING_SCOPE_CONTEXT,
                reasonCodes = listOf(
                    RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED,
                    RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED
                ),
                summary = "Target scope context is incomplete, so propagation stays blocked."
            )
        }
        if (policy.crossTenantContaminationBlocked && rule.sameTenantOnly) {
            val sourceTenant = sourceBinding.tenantId?.takeIf { it.isNotBlank() }
            val targetTenant = targetBinding.tenantId?.takeIf { it.isNotBlank() }
            if (sourceTenant != null && targetTenant != null && sourceTenant != targetTenant) {
                return PortfolioOptimizationLearningIsolationDecision(
                    decisionId = decisionId,
                    sourceBinding = sourceBinding,
                    targetBinding = targetBinding,
                    policy = policy,
                    allowed = false,
                    blockReason = PortfolioOptimizationPropagationBlockReason.CROSS_TENANT_ISOLATION,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_LEARNING_ISOLATION_ENFORCED,
                        RoleReasonCodes.ROLE_LEARNING_PROPAGATION_BLOCKED
                    ),
                    summary = "Cross-tenant propagation is blocked to prevent learning contamination."
                )
            }
        }
        return PortfolioOptimizationLearningIsolationDecision(
            decisionId = decisionId,
            sourceBinding = sourceBinding,
            targetBinding = targetBinding,
            policy = policy,
            allowed = true,
            blockReason = PortfolioOptimizationPropagationBlockReason.NONE,
            reasonCodes = listOf(
                RoleReasonCodes.ROLE_LEARNING_SCOPE_RESOLVED,
                RoleReasonCodes.ROLE_LEARNING_PROPAGATION_ELIGIBLE
            ),
            summary = "Isolation policy allows ${portfolioOptimizationScopeLabel(sourceBinding.scope)} learning to promote into ${portfolioOptimizationScopeLabel(targetBinding.scope)}."
        )
    }

    private fun latestPortfolioOptimizationDriftForObjectiveProfileLineage(
        userId: String,
        objectiveProfileSnapshotId: String
    ): PortfolioOptimizationDriftSummary? {
        return synchronized(dynamicStateLock) {
            portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
                .filter { drift ->
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = drift.objectiveProfileSnapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationDriftSummary> { it.createdAtMs }
                        .thenBy { it.driftId }
                )
        }
    }

    private fun buildPortfolioOptimizationPropagationPatch(
        sourceSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        sourceCalibrationSnapshot: PortfolioOptimizationCalibrationSnapshot?,
        targetBinding: PortfolioOptimizationObjectiveProfileBinding,
        targetBaseSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        now: Long
    ): PortfolioOptimizationLearningPatch {
        val sourceWeights = sourceSnapshot.objectiveProfile.weights.associate { it.family to it.weight }
        val baseWeights = targetBaseSnapshot.objectiveProfile.weights.associate { it.family to it.weight }
        val objectiveWeightDeltas = PortfolioOptimizationObjectiveFamily.entries.mapNotNull { family ->
            val delta = (sourceWeights[family] ?: 0) - (baseWeights[family] ?: 0)
            if (delta == 0) {
                null
            } else {
                PortfolioOptimizationObjectiveWeightDelta(
                    family = family,
                    delta = delta
                )
            }
        }
        val parameterDelta = PortfolioOptimizationParameterCalibrationDelta(
            approvalLatencyPenaltyMultiplierDelta =
                sourceSnapshot.parameterCalibration.approvalLatencyPenaltyMultiplier -
                    targetBaseSnapshot.parameterCalibration.approvalLatencyPenaltyMultiplier,
            readinessDelayPenaltyMultiplierDelta =
                sourceSnapshot.parameterCalibration.readinessDelayPenaltyMultiplier -
                    targetBaseSnapshot.parameterCalibration.readinessDelayPenaltyMultiplier,
            windowMissPenaltyMultiplierDelta =
                sourceSnapshot.parameterCalibration.windowMissPenaltyMultiplier -
                    targetBaseSnapshot.parameterCalibration.windowMissPenaltyMultiplier,
            riskIncidentPenaltyMultiplierDelta =
                sourceSnapshot.parameterCalibration.riskIncidentPenaltyMultiplier -
                    targetBaseSnapshot.parameterCalibration.riskIncidentPenaltyMultiplier,
            summary = "Parameter calibration delta from ${portfolioOptimizationScopeLabel(sourceSnapshot.binding.scope)} to ${portfolioOptimizationScopeLabel(targetBinding.scope)}."
        )
        return PortfolioOptimizationLearningPatch(
            patchId = "portfolio_opt_patch_${sourceSnapshot.snapshotId.takeLast(8)}_${targetBinding.scope.name.lowercase()}_$now",
            sourceObjectiveProfileSnapshotId = sourceSnapshot.snapshotId,
            sourceCalibrationSnapshotId = sourceCalibrationSnapshot?.snapshotId,
            sourceBinding = sourceSnapshot.binding,
            targetBinding = targetBinding,
            objectiveWeightDeltas = objectiveWeightDeltas,
            parameterCalibrationDelta = parameterDelta,
            evidenceRefs = sourceCalibrationSnapshot?.evidenceRefs.orEmpty(),
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PROPAGATION_ELIGIBLE),
            summary = "Propagation patch promotes ${portfolioOptimizationScopeLabel(sourceSnapshot.binding.scope)} learning into ${portfolioOptimizationScopeLabel(targetBinding.scope)} scope.",
            createdAtMs = now
        )
    }

    private fun portfolioOptimizationLearningPatchIsNoOp(
        patch: PortfolioOptimizationLearningPatch
    ): Boolean {
        val parameterDelta = patch.parameterCalibrationDelta
        return patch.objectiveWeightDeltas.isEmpty() &&
            kotlin.math.abs(parameterDelta.approvalLatencyPenaltyMultiplierDelta) < 1e-9 &&
            kotlin.math.abs(parameterDelta.readinessDelayPenaltyMultiplierDelta) < 1e-9 &&
            kotlin.math.abs(parameterDelta.windowMissPenaltyMultiplierDelta) < 1e-9 &&
            kotlin.math.abs(parameterDelta.riskIncidentPenaltyMultiplierDelta) < 1e-9
    }

    private fun applyPortfolioOptimizationLearningPatchToSnapshot(
        baseSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        patch: PortfolioOptimizationLearningPatch,
        provenance: PortfolioOptimizationLearningProvenanceSummary,
        now: Long
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        val currentWeights = baseSnapshot.objectiveProfile.weights
            .associate { it.family to it.weight.coerceIn(0, 10) }
        val deltaWeights = patch.objectiveWeightDeltas.associate { it.family to it.delta }
        val updatedWeights = PortfolioOptimizationObjectiveFamily.entries.map { family ->
            PortfolioOptimizationObjectiveWeight(
                family = family,
                weight = ((currentWeights[family] ?: 0) + (deltaWeights[family] ?: 0)).coerceIn(0, 10)
            )
        }
        val parameterDelta = patch.parameterCalibrationDelta
        val updatedParameterCalibration = baseSnapshot.parameterCalibration.copy(
            approvalLatencyPenaltyMultiplier = (
                baseSnapshot.parameterCalibration.approvalLatencyPenaltyMultiplier +
                    parameterDelta.approvalLatencyPenaltyMultiplierDelta
                ).coerceIn(0.50, 2.00),
            readinessDelayPenaltyMultiplier = (
                baseSnapshot.parameterCalibration.readinessDelayPenaltyMultiplier +
                    parameterDelta.readinessDelayPenaltyMultiplierDelta
                ).coerceIn(0.50, 2.00),
            windowMissPenaltyMultiplier = (
                baseSnapshot.parameterCalibration.windowMissPenaltyMultiplier +
                    parameterDelta.windowMissPenaltyMultiplierDelta
                ).coerceIn(0.50, 2.00),
            riskIncidentPenaltyMultiplier = (
                baseSnapshot.parameterCalibration.riskIncidentPenaltyMultiplier +
                    parameterDelta.riskIncidentPenaltyMultiplierDelta
                ).coerceIn(0.50, 2.00),
            summary = "Parameter calibration adopted from propagation patch ${patch.patchId.takeLast(8)}."
        )
        return PortfolioOptimizationObjectiveProfileSnapshot(
            snapshotId = "portfolio_opt_profile_${patch.targetBinding.scope.name.lowercase()}_${patch.patchId.takeLast(8)}_$now",
            parentSnapshotId = baseSnapshot.snapshotId,
            profileId = baseSnapshot.profileId.ifBlank {
                "objective_profile_${patch.targetBinding.scope.name.lowercase()}_${patch.patchId.takeLast(8)}"
            },
            version = baseSnapshot.version + 1,
            binding = patch.targetBinding,
            objectiveProfile = baseSnapshot.objectiveProfile.copy(
                profileId = baseSnapshot.objectiveProfile.profileId.ifBlank {
                    "objective_${patch.patchId.takeLast(8)}"
                },
                weights = updatedWeights,
                summary = "Objective profile adopted into ${portfolioOptimizationScopeLabel(patch.targetBinding.scope)} scope."
            ),
            parameterCalibration = updatedParameterCalibration,
            isolationPolicy = baseSnapshot.isolationPolicy,
            provenance = provenance,
            reasonCodes = listOf(RoleReasonCodes.ROLE_LEARNING_PATCH_ADOPTED),
            summary = "Objective profile snapshot v${baseSnapshot.version + 1} adopted into ${portfolioOptimizationScopeLabel(patch.targetBinding.scope)} scope.",
            createdAtMs = now
        )
    }

    private fun markPortfolioOptimizationPropagationReviewRequired(
        userId: String,
        objectiveProfileSnapshotId: String,
        severity: PortfolioDriftSeverity
    ) {
        if (severity != PortfolioDriftSeverity.HIGH && severity != PortfolioDriftSeverity.CRITICAL) return
        synchronized(dynamicStateLock) {
            portfolioOptimizationPropagationAttemptsByUser[userId]?.let { queue ->
                val updated = queue.toList().map { attempt ->
                    if (
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = attempt.sourceObjectiveProfileSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        ) &&
                        attempt.status != PortfolioOptimizationPropagationEligibilityStatus.BLOCKED &&
                        attempt.status != PortfolioOptimizationPropagationEligibilityStatus.REJECTED &&
                        attempt.status != PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED
                    ) {
                        attempt.copy(
                            status = PortfolioOptimizationPropagationEligibilityStatus.SUPPRESSED,
                            blockReason = PortfolioOptimizationPropagationBlockReason.DRIFT_SUPPRESSED,
                            suppressedByDrift = true,
                            reviewRequired = true,
                            reasonCodes = (attempt.reasonCodes + RoleReasonCodes.ROLE_LEARNING_PROPAGATION_SUPPRESSED_BY_DRIFT).distinct(),
                            summary = "Propagation suppressed because ${severity.name.lowercase()} drift surfaced on the source lineage."
                        )
                    } else {
                        attempt
                    }
                }
                queue.clear()
                updated.forEach(queue::addLast)
            }
            portfolioOptimizationPropagationAdoptionsByUser[userId]?.let { queue ->
                val updated = queue.toList().map { adoption ->
                    if (
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = adoption.sourceObjectiveProfileSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        ) &&
                        adoption.status != PortfolioOptimizationPropagationEligibilityStatus.REJECTED
                    ) {
                        adoption.copy(
                            status = PortfolioOptimizationPropagationEligibilityStatus.REVIEW_REQUIRED,
                            suppressedByDrift = true,
                            reviewRequired = true,
                            reasonCodes = (adoption.reasonCodes + RoleReasonCodes.ROLE_LEARNING_PROPAGATION_SUPPRESSED_BY_DRIFT).distinct(),
                            summary = "Propagation adoption requires review because ${severity.name.lowercase()} drift surfaced on the source lineage."
                        )
                    } else {
                        adoption
                    }
                }
                queue.clear()
                updated.forEach(queue::addLast)
            }
        }
    }

    private fun portfolioOptimizationLearningSyncModeLabel(
        mode: PortfolioOptimizationLearningSyncMode?
    ): String {
        return mode?.name?.lowercase()?.replace('_', ' ') ?: "local only"
    }

    private fun defaultPortfolioOptimizationFederatedAggregationRule(
        mode: PortfolioOptimizationLearningSyncMode
    ): PortfolioOptimizationFederatedAggregationRule {
        return when (mode) {
            PortfolioOptimizationLearningSyncMode.LOCAL_ONLY ->
                PortfolioOptimizationFederatedAggregationRule(
                    ruleId = "portfolio_sync_rule_local_only",
                    mode = mode,
                    boundaryType = PortfolioOptimizationFederatedAggregationBoundaryType.USER_DEVICE,
                    sameTenantOnly = true,
                    sameWorkspaceOnly = true,
                    allowRolePartition = true,
                    allowDeviceClassPartition = true,
                    allowEnterpriseIntegrationPartition = false,
                    summary = "Local-only mode keeps learning artifacts on one device."
                )

            PortfolioOptimizationLearningSyncMode.DEVICE_SYNC ->
                PortfolioOptimizationFederatedAggregationRule(
                    ruleId = "portfolio_sync_rule_device_sync",
                    mode = mode,
                    boundaryType = PortfolioOptimizationFederatedAggregationBoundaryType.USER_DEVICE,
                    sameTenantOnly = true,
                    sameWorkspaceOnly = true,
                    allowRolePartition = true,
                    allowDeviceClassPartition = true,
                    allowEnterpriseIntegrationPartition = false,
                    summary = "Device sync allows the same user's devices to exchange redacted learning artifacts inside one workspace and tenant."
                )

            PortfolioOptimizationLearningSyncMode.TENANT_PRIVATE_SYNC ->
                PortfolioOptimizationFederatedAggregationRule(
                    ruleId = "portfolio_sync_rule_tenant_private",
                    mode = mode,
                    boundaryType = PortfolioOptimizationFederatedAggregationBoundaryType.TENANT,
                    sameTenantOnly = true,
                    sameWorkspaceOnly = false,
                    allowRolePartition = true,
                    allowDeviceClassPartition = true,
                    allowEnterpriseIntegrationPartition = false,
                    summary = "Tenant-private sync allows redacted learning artifacts to aggregate only inside one tenant."
                )

            PortfolioOptimizationLearningSyncMode.ENTERPRISE_PRIVATE_SYNC ->
                PortfolioOptimizationFederatedAggregationRule(
                    ruleId = "portfolio_sync_rule_enterprise_private",
                    mode = mode,
                    boundaryType = PortfolioOptimizationFederatedAggregationBoundaryType.ENTERPRISE_INTEGRATION,
                    sameTenantOnly = true,
                    sameWorkspaceOnly = false,
                    allowRolePartition = true,
                    allowDeviceClassPartition = true,
                    allowEnterpriseIntegrationPartition = true,
                    summary = "Enterprise-private sync allows redacted learning artifacts inside one tenant and one enterprise integration boundary."
                )
        }
    }

    private fun derivePortfolioOptimizationLearningSyncPrivacyPolicy(
        userId: String,
        mode: PortfolioOptimizationLearningSyncMode,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        activeRole: UserRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
    ): PortfolioOptimizationLearningSyncPrivacyPolicy {
        val rolePolicy = effectiveRolePolicyProfile(userId, activeRole)
        val sharingMode = rolePolicy.dataPolicy.sharingMode.lowercase()
        val cloudSyncAllowed = rolePolicy.dataPolicy.cloudSyncAllowed &&
            !sharingMode.contains("local_only")
        val allowEnterpriseAggregation = mode == PortfolioOptimizationLearningSyncMode.ENTERPRISE_PRIVATE_SYNC &&
            cloudSyncAllowed &&
            activeRole != UserRole.PARENT
        val policyId = "portfolio_sync_privacy_${activeRole.name.lowercase()}_${mode.name.lowercase()}"
        val summary = when {
            mode == PortfolioOptimizationLearningSyncMode.LOCAL_ONLY ->
                "Local-only mode keeps learning artifacts on-device."
            !rolePolicy.dataPolicy.cloudSyncAllowed ->
                "Role policy blocks cross-device learning sync and keeps learning artifacts local."
            sharingMode.contains("local_only") ->
                "Privacy sharing mode keeps learning artifacts local and blocks cross-device sync."
            activeRole == UserRole.PARENT ->
                "Parent role keeps cross-device learning sync blocked by default."
            mode == PortfolioOptimizationLearningSyncMode.ENTERPRISE_PRIVATE_SYNC && !allowEnterpriseAggregation ->
                "Enterprise-private sync is not allowed by the current privacy policy."
            else ->
                "Learning sync is artifact-only, redacted, and restricted to ${binding.tenantId ?: "tenant_default"}."
        }
        return PortfolioOptimizationLearningSyncPrivacyPolicy(
            policyId = policyId,
            mode = mode,
            cloudSyncAllowed = cloudSyncAllowed && activeRole != UserRole.PARENT,
            rawContentSyncBlocked = true,
            rawPromptSyncBlocked = true,
            sameTenantOnly = true,
            allowObjectiveProfileSnapshots = true,
            allowCalibrationSnapshots = true,
            allowDriftSummaries = true,
            allowOutcomeAggregates = true,
            allowEnterpriseAggregation = allowEnterpriseAggregation,
            summary = summary
        )
    }

    private fun currentPortfolioOptimizationDeviceId(userId: String): String {
        return "device_${userId.takeLast(8)}"
    }

    private fun portfolioOptimizationRolePolicyAllowsCloudTransfer(
        userId: String,
        activeRole: UserRole
    ): Boolean {
        val rolePolicy = effectiveRolePolicyProfile(userId, activeRole)
        val sharingMode = rolePolicy.dataPolicy.sharingMode.lowercase()
        return rolePolicy.dataPolicy.cloudSyncAllowed &&
            !sharingMode.contains("local_only") &&
            activeRole != UserRole.PARENT
    }

    private fun defaultPortfolioOptimizationConsentScopeBinding(
        userId: String,
        scope: PortfolioOptimizationConsentScope,
        binding: PortfolioOptimizationObjectiveProfileBinding
    ): PortfolioOptimizationConsentScopeBinding {
        return when (scope) {
            PortfolioOptimizationConsentScope.DEVICE ->
                PortfolioOptimizationConsentScopeBinding(
                    scope = scope,
                    userId = userId,
                    workspaceId = binding.workspaceId,
                    tenantId = binding.tenantId,
                    deviceId = currentPortfolioOptimizationDeviceId(userId),
                    summary = "Device-scoped consent for ${binding.tenantId ?: "tenant_default"}."
                )

            PortfolioOptimizationConsentScope.ACCOUNT ->
                PortfolioOptimizationConsentScopeBinding(
                    scope = scope,
                    userId = userId,
                    workspaceId = binding.workspaceId,
                    tenantId = binding.tenantId,
                    summary = "Account-scoped consent for ${binding.tenantId ?: "tenant_default"}."
                )

            PortfolioOptimizationConsentScope.WORKSPACE ->
                PortfolioOptimizationConsentScopeBinding(
                    scope = scope,
                    userId = userId,
                    workspaceId = binding.workspaceId,
                    tenantId = binding.tenantId,
                    summary = "Workspace-scoped consent for ${binding.workspaceId ?: "workspace_default"}."
                )

            PortfolioOptimizationConsentScope.TENANT ->
                PortfolioOptimizationConsentScopeBinding(
                    scope = scope,
                    userId = userId,
                    workspaceId = binding.workspaceId,
                    tenantId = binding.tenantId,
                    summary = "Tenant-scoped consent for ${binding.tenantId ?: "tenant_default"}."
                )
        }
    }

