                listOf(
                    PortfolioOptimizationLearningDataCategory.OBJECTIVE_PROFILE_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.CALIBRATION_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.DRIFT_SUMMARY,
                    PortfolioOptimizationLearningDataCategory.OUTCOME_AGGREGATE
                )

            PortfolioOptimizationConsentPurpose.FEDERATED_AGGREGATION ->
