                    PortfolioOptimizationLearningDataCategory.OUTCOME_AGGREGATE,
                    PortfolioOptimizationLearningDataCategory.FEDERATED_AGGREGATION_SUMMARY
                )

            PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT ->
                listOf(
                    PortfolioOptimizationLearningDataCategory.OBJECTIVE_PROFILE_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.CALIBRATION_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.DRIFT_SUMMARY,
                    PortfolioOptimizationLearningDataCategory.OUTCOME_AGGREGATE,
                    PortfolioOptimizationLearningDataCategory.FEDERATED_AGGREGATION_SUMMARY
                )

            PortfolioOptimizationConsentPurpose.AUDIT_EXPORT ->
                listOf(
                    PortfolioOptimizationLearningDataCategory.OBJECTIVE_PROFILE_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.CALIBRATION_SNAPSHOT,
                    PortfolioOptimizationLearningDataCategory.DRIFT_SUMMARY,
                    PortfolioOptimizationLearningDataCategory.OUTCOME_AGGREGATE,
                    PortfolioOptimizationLearningDataCategory.FEDERATED_AGGREGATION_SUMMARY,
                    PortfolioOptimizationLearningDataCategory.COMPLIANCE_AUDIT_METADATA
                )
        }
    }

    private fun normalizePortfolioOptimizationConsentDecision(
        consent: PortfolioOptimizationConsentRecord,
        now: Long
    ): PortfolioOptimizationConsentDecision {
        val revokedAtMs = consent.revokedAtMs
        val expiresAtMs = consent.expiresAtMs
        return when {
            revokedAtMs != null && revokedAtMs <= now ->
                PortfolioOptimizationConsentDecision.REVOKED
            expiresAtMs != null && expiresAtMs <= now ->
                PortfolioOptimizationConsentDecision.EXPIRED
            else -> consent.decision
        }
    }

    private fun normalizePortfolioOptimizationConsentRecordLocked(
        userId: String,
        consent: PortfolioOptimizationConsentRecord,
        now: Long
    ): PortfolioOptimizationConsentRecord {
        val binding = resolvePortfolioOptimizationScopeBinding(userId)
        val scopeBinding = consent.scopeBinding.takeIf {
            it.scope == consent.scopeBinding.scope &&
                (
                    it.userId != null ||
                        it.workspaceId != null ||
                        it.tenantId != null ||
                        it.deviceId != null
                    )
        } ?: defaultPortfolioOptimizationConsentScopeBinding(
            userId = userId,
            scope = consent.scopeBinding.scope,
            binding = binding
        )
        val decision = normalizePortfolioOptimizationConsentDecision(consent, now)
        val reasonCode = when (decision) {
            PortfolioOptimizationConsentDecision.ALLOWED -> RoleReasonCodes.ROLE_CONSENT_GRANTED
            PortfolioOptimizationConsentDecision.DENIED,
            PortfolioOptimizationConsentDecision.PENDING -> RoleReasonCodes.ROLE_CONSENT_DENIED
            PortfolioOptimizationConsentDecision.REVOKED -> RoleReasonCodes.ROLE_CONSENT_REVOKED
            PortfolioOptimizationConsentDecision.EXPIRED -> RoleReasonCodes.ROLE_CONSENT_EXPIRED
        }
        val defaultSummary = when (decision) {
            PortfolioOptimizationConsentDecision.ALLOWED ->
                "Consent allows ${consent.purpose.name.lowercase().replace('_', ' ')} for ${scopeBinding.scope.name.lowercase()} scope."
            PortfolioOptimizationConsentDecision.PENDING ->
                "Consent is pending for ${consent.purpose.name.lowercase().replace('_', ' ')}."
            PortfolioOptimizationConsentDecision.DENIED ->
                "Consent denies ${consent.purpose.name.lowercase().replace('_', ' ')}."
            PortfolioOptimizationConsentDecision.EXPIRED ->
                "Consent expired for ${consent.purpose.name.lowercase().replace('_', ' ')}."
            PortfolioOptimizationConsentDecision.REVOKED ->
                "Consent was revoked for ${consent.purpose.name.lowercase().replace('_', ' ')}."
        }
        return consent.copy(
            consentId = consent.consentId.ifBlank {
                "portfolio_consent_${consent.purpose.name.lowercase()}_${userId.takeLast(8)}_$now"
            },
            scopeBinding = scopeBinding,
            decision = decision,
            dataCategories = consent.dataCategories.ifEmpty {
                defaultPortfolioOptimizationConsentDataCategories(consent.purpose)
            },
            minimizationRules = consent.minimizationRules.ifEmpty {
                listOf(
                    PortfolioOptimizationDataMinimizationRule.REDACTED,
                    PortfolioOptimizationDataMinimizationRule.AGGREGATED_ONLY
                )
            },
            retentionPolicy = consent.retentionPolicy.takeIf { it.retentionDays > 0 }
                ?: PortfolioOptimizationRetentionPolicy(
                    retentionDays = 30,
                    purgeRequired = true,
                    summary = "Learning artifacts are retained for 30 days with purge required."
                ),
            reasonCodes = (consent.reasonCodes + reasonCode).distinct(),
            summary = consent.summary.ifBlank { defaultSummary },
            recordedAtMs = consent.recordedAtMs.takeIf { it > 0L } ?: now
        )
    }

    private fun portfolioOptimizationConsentScopeMatches(
        userId: String,
        requiredBinding: PortfolioOptimizationObjectiveProfileBinding,
        consentBinding: PortfolioOptimizationConsentScopeBinding
    ): Boolean {
        return when (consentBinding.scope) {
            PortfolioOptimizationConsentScope.DEVICE ->
                consentBinding.userId == userId &&
                    consentBinding.deviceId == currentPortfolioOptimizationDeviceId(userId)
            PortfolioOptimizationConsentScope.ACCOUNT ->
                consentBinding.userId == userId
            PortfolioOptimizationConsentScope.WORKSPACE ->
                !requiredBinding.workspaceId.isNullOrBlank() &&
                    requiredBinding.workspaceId == consentBinding.workspaceId
            PortfolioOptimizationConsentScope.TENANT ->
                !requiredBinding.tenantId.isNullOrBlank() &&
                    requiredBinding.tenantId == consentBinding.tenantId
        }
    }

    private fun effectivePortfolioOptimizationConsentRecordLocked(
        userId: String,
        purpose: PortfolioOptimizationConsentPurpose,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        now: Long
    ): PortfolioOptimizationConsentRecord? {
        return portfolioOptimizationConsentRecordsByUser[userId]
            ?.toList()
            .orEmpty()
            .asSequence()
            .filter { it.purpose == purpose }
            .filter { portfolioOptimizationConsentScopeMatches(userId, binding, it.scopeBinding) }
            .sortedWith(
                compareByDescending<PortfolioOptimizationConsentRecord> { it.recordedAtMs }
                    .thenBy { it.consentId }
            )
            .map { normalizePortfolioOptimizationConsentRecordLocked(userId, it, now) }
            .firstOrNull()
    }

    private fun derivePortfolioOptimizationEnterprisePrivacyPolicySummary(
        userId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        activeRole: UserRole,
        learningSyncConsent: PortfolioOptimizationConsentRecord?,
        remoteTransportConsent: PortfolioOptimizationConsentRecord?,
        auditExportConsent: PortfolioOptimizationConsentRecord?
    ): PortfolioOptimizationEnterprisePrivacyPolicySummary {
        val roleAllowsRemote = portfolioOptimizationRolePolicyAllowsCloudTransfer(userId, activeRole)
        val roleAllowsAuditExport = roleAllowsRemote
        return PortfolioOptimizationEnterprisePrivacyPolicySummary(
            policyId = "portfolio_enterprise_privacy_${activeRole.name.lowercase()}_${binding.tenantId ?: "tenant_default"}",
            sameTenantOnly = true,
            rawContentBlocked = true,
            rawPromptsBlocked = true,
            remoteTransportAllowedByRolePolicy = roleAllowsRemote,
            auditExportAllowedByRolePolicy = roleAllowsAuditExport,
            learningSyncConsentDecision = learningSyncConsent?.decision,
            remoteTransportConsentDecision = remoteTransportConsent?.decision,
            auditExportConsentDecision = auditExportConsent?.decision,
            summary = buildString {
                append("Enterprise privacy keeps raw content and prompts out of sync, transport, and audit export")
                append(" · tenant ")
                append(binding.tenantId ?: "tenant_default")
                append(" · remote ")
                append(if (roleAllowsRemote) "role-allowed" else "role-blocked")
                append(" · audit ")
                append(if (roleAllowsAuditExport) "role-allowed" else "role-blocked")
            }
        )
    }

    private fun derivePortfolioOptimizationFederatedAggregationBoundary(
        binding: PortfolioOptimizationObjectiveProfileBinding,
        mode: PortfolioOptimizationLearningSyncMode,
        activeRole: UserRole
    ): PortfolioOptimizationFederatedAggregationBoundary {
        val boundaryType = when (mode) {
            PortfolioOptimizationLearningSyncMode.LOCAL_ONLY,
            PortfolioOptimizationLearningSyncMode.DEVICE_SYNC ->
                PortfolioOptimizationFederatedAggregationBoundaryType.USER_DEVICE

            PortfolioOptimizationLearningSyncMode.TENANT_PRIVATE_SYNC ->
                PortfolioOptimizationFederatedAggregationBoundaryType.TENANT

            PortfolioOptimizationLearningSyncMode.ENTERPRISE_PRIVATE_SYNC ->
                PortfolioOptimizationFederatedAggregationBoundaryType.ENTERPRISE_INTEGRATION
        }
        return PortfolioOptimizationFederatedAggregationBoundary(
            boundaryId = "portfolio_sync_boundary_${boundaryType.name.lowercase()}_${binding.tenantId ?: "tenant_default"}_${binding.workspaceId ?: "workspace_default"}",
            boundaryType = boundaryType,
            tenantId = binding.tenantId,
            workspaceId = binding.workspaceId,
            role = activeRole,
            deviceClass = PortfolioOptimizationLearningDeviceClass.UNKNOWN,
            enterpriseIntegrationKey = if (mode == PortfolioOptimizationLearningSyncMode.ENTERPRISE_PRIVATE_SYNC) {
                binding.tenantId?.let { "$it:enterprise_private" } ?: "enterprise_private"
            } else {
                null
            },
            sameTenantOnly = true,
            summary = when (boundaryType) {
                PortfolioOptimizationFederatedAggregationBoundaryType.USER_DEVICE ->
                    "Artifact sync stays inside one tenant/workspace and one user/device boundary."
                PortfolioOptimizationFederatedAggregationBoundaryType.TENANT ->
                    "Artifact aggregation is tenant-private and cross-tenant aggregation remains blocked."
                PortfolioOptimizationFederatedAggregationBoundaryType.ENTERPRISE_INTEGRATION ->
                    "Artifact aggregation is tenant-private and restricted to one enterprise integration boundary."
                PortfolioOptimizationFederatedAggregationBoundaryType.WORKSPACE ->
                    "Artifact aggregation is workspace-scoped."
                PortfolioOptimizationFederatedAggregationBoundaryType.ROLE ->
                    "Artifact aggregation is role-scoped."
                PortfolioOptimizationFederatedAggregationBoundaryType.DEVICE_CLASS ->
                    "Artifact aggregation is partitioned by device class."
            }
        )
    }

    private fun derivePortfolioOptimizationFederatedAggregationGroupKey(
        boundary: PortfolioOptimizationFederatedAggregationBoundary,
        mode: PortfolioOptimizationLearningSyncMode
    ): PortfolioOptimizationFederatedAggregationGroupKey {
        val key = listOfNotNull(
            mode.name.lowercase(),
            boundary.boundaryType.name.lowercase(),
            boundary.tenantId,
            boundary.workspaceId,
            boundary.role?.name?.lowercase(),
            boundary.deviceClass.name.lowercase(),
            boundary.enterpriseIntegrationKey
        ).joinToString(":")
        return PortfolioOptimizationFederatedAggregationGroupKey(
            groupKey = key,
            mode = mode,
            tenantId = boundary.tenantId,
            workspaceId = boundary.workspaceId,
            role = boundary.role,
            deviceClass = boundary.deviceClass,
            boundaryType = boundary.boundaryType,
            summary = "Federated aggregation key $key."
        )
    }

    private fun portfolioOptimizationLearningSyncProvenance(
        userId: String,
        binding: PortfolioOptimizationObjectiveProfileBinding,
        operatorId: String?,
        operatorName: String?,
        now: Long
    ): PortfolioOptimizationLearningSyncProvenance {
        return PortfolioOptimizationLearningSyncProvenance(
            deviceId = "device_${userId.takeLast(8)}",
            sessionId = "portfolio_sync_${userId.takeLast(8)}",
            sourceUserId = userId,
            operatorId = operatorId,
            operatorName = operatorName,
            sourceTenantId = binding.tenantId,
            sourceWorkspaceId = binding.workspaceId,
            exportedAtMs = now,
            summary = "Portfolio learning sync originated from ${binding.tenantId ?: "tenant_default"} / ${binding.workspaceId ?: "workspace_default"}."
        )
    }

    private fun redactPortfolioOptimizationObjectiveProfileSnapshot(
        snapshot: PortfolioOptimizationObjectiveProfileSnapshot
    ): PortfolioOptimizationObjectiveProfileSnapshot {
        return snapshot.copy(
            provenance = snapshot.provenance.copy(operatorName = null)
        )
    }

    private fun redactPortfolioOptimizationCalibrationSnapshot(
        snapshot: PortfolioOptimizationCalibrationSnapshot
    ): PortfolioOptimizationCalibrationSnapshot {
        return snapshot.copy(
            evidenceRefs = snapshot.evidenceRefs.map { it.copy(sourceRunId = "", relatedId = null) }
        )
    }

    private fun redactPortfolioOptimizationDriftSummary(
        summary: PortfolioOptimizationDriftSummary
    ): PortfolioOptimizationDriftSummary {
        return summary.copy(
            evidenceRefs = summary.evidenceRefs.map { it.copy(sourceRunId = "", relatedId = null) }
        )
    }

    private fun buildPortfolioOptimizationOutcomeAggregate(
        outcome: PortfolioScheduleOutcomeRecord
    ): PortfolioOptimizationOutcomeAggregate {
        val executionObservations = outcome.observations.executionObservations
        val windowObservations = outcome.observations.windowUtilizationObservations
        val approvalObservations = outcome.observations.approvalLatencyObservations
        val riskObservations = outcome.observations.riskIncidentObservations
        val observedRunIds = buildSet {
            executionObservations.mapTo(this) { it.sourceRunId }
            windowObservations.mapTo(this) { it.sourceRunId }
            approvalObservations.mapTo(this) { it.sourceRunId }
            riskObservations.mapTo(this) { it.sourceRunId }
        }.filter { it.isNotBlank() }
        val actualAverageApprovalLatencyHours = approvalObservations
            .map { it.latencyHours }
            .takeIf { it.isNotEmpty() }
            ?.average()
            ?: 0.0
        return PortfolioOptimizationOutcomeAggregate(
            aggregateId = "portfolio_sync_outcome_${outcome.outcomeId.takeLast(8)}",
            outcomeId = outcome.outcomeId,
            decisionId = outcome.decisionId,
            calibrationSnapshotId = outcome.calibrationSnapshotId,
            objectiveProfileSnapshotId = outcome.objectiveProfileSnapshotId,
            objectiveProfileBinding = outcome.objectiveProfileBinding,
            predictedScheduledCount = outcome.predictedScheduledCount,
            predictedOnTimeCount = outcome.predictedOnTimeCount,
            predictedWindowMissCount = outcome.predictedWindowMissCount,
            predictedReadinessDelayCount = outcome.predictedReadinessDelayCount,
            predictedRiskIncidentCount = outcome.predictedRiskIncidentCount,
            predictedAverageApprovalLatencyHours = outcome.predictedAverageApprovalLatencyHours,
            observedRunCount = observedRunIds.size,
            actualScheduledCount = executionObservations.size,
            actualOnTimeCount = executionObservations.count { it.executedOnTime },
            actualWindowMissCount = windowObservations.count { it.missedWindow || it.expiredWindow },
            actualReadinessDelayCount = executionObservations.count { it.readinessDelayed },
            actualRiskIncidentCount = riskObservations.sumOf { it.incidentCount },
            actualAverageApprovalLatencyHours = actualAverageApprovalLatencyHours,
            summary = outcome.summary.ifBlank {
                "Outcome aggregate for decision ${outcome.decisionId.takeLast(8)}."
            },
            recordedAtMs = outcome.recordedAtMs
        )
    }

    private fun portfolioOptimizationLearningSyncArtifactsLocked(
        userId: String,
        objectiveProfileSnapshot: PortfolioOptimizationObjectiveProfileSnapshot,
        calibrationSnapshot: PortfolioOptimizationCalibrationSnapshot
    ): List<PortfolioOptimizationLearningSyncArtifactEnvelope> {
        val driftArtifacts = portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
            .filter { drift ->
                portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                    userId = userId,
                    leftSnapshotId = drift.objectiveProfileSnapshotId,
                    rightSnapshotId = objectiveProfileSnapshot.snapshotId
                )
            }
            .sortedWith(
                compareByDescending<PortfolioOptimizationDriftSummary> { it.createdAtMs }
                    .thenBy { it.driftId }
            )
            .take(5)
            .map { drift ->
                PortfolioOptimizationLearningSyncArtifactEnvelope(
                    envelopeArtifactId = "sync_artifact_drift_${drift.driftId.takeLast(8)}",
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY,
                    artifactId = drift.driftId,
                    artifactVersion = 1,
                    driftSummary = redactPortfolioOptimizationDriftSummary(drift),
                    summary = drift.summary
                )
            }
        val outcomeArtifacts = portfolioOptimizationOutcomesByUser[userId]?.toList().orEmpty()
            .filter { outcome ->
                portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                    userId = userId,
                    leftSnapshotId = outcome.objectiveProfileSnapshotId,
                    rightSnapshotId = objectiveProfileSnapshot.snapshotId
                )
            }
            .sortedWith(
                compareByDescending<PortfolioScheduleOutcomeRecord> { it.recordedAtMs }
                    .thenBy { it.outcomeId }
            )
            .take(5)
            .map { outcome ->
                val aggregate = buildPortfolioOptimizationOutcomeAggregate(outcome)
                PortfolioOptimizationLearningSyncArtifactEnvelope(
                    envelopeArtifactId = "sync_artifact_outcome_${aggregate.aggregateId.takeLast(8)}",
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE,
                    artifactId = aggregate.aggregateId,
                    artifactVersion = 1,
                    outcomeAggregate = aggregate,
                    summary = aggregate.summary
                )
            }
        return buildList {
            add(
                PortfolioOptimizationLearningSyncArtifactEnvelope(
                    envelopeArtifactId = "sync_artifact_profile_${objectiveProfileSnapshot.snapshotId.takeLast(8)}",
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT,
                    artifactId = objectiveProfileSnapshot.snapshotId,
                    artifactVersion = objectiveProfileSnapshot.version,
                    objectiveProfileSnapshot = redactPortfolioOptimizationObjectiveProfileSnapshot(
                        objectiveProfileSnapshot
                    ),
                    summary = objectiveProfileSnapshot.summary
                )
            )
            add(
                PortfolioOptimizationLearningSyncArtifactEnvelope(
                    envelopeArtifactId = "sync_artifact_calibration_${calibrationSnapshot.snapshotId.takeLast(8)}",
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT,
                    artifactId = calibrationSnapshot.snapshotId,
                    artifactVersion = calibrationSnapshot.version,
                    calibrationSnapshot = redactPortfolioOptimizationCalibrationSnapshot(
                        calibrationSnapshot
                    ),
                    summary = calibrationSnapshot.summary
                )
            )
            addAll(driftArtifacts)
            addAll(outcomeArtifacts)
        }
    }

    private fun buildPortfolioOptimizationRemoteLearningEnvelope(
        syncEnvelope: PortfolioOptimizationLearningSyncEnvelope,
        consentRecord: PortfolioOptimizationConsentRecord?,
        enterprisePrivacy: PortfolioOptimizationEnterprisePrivacyPolicySummary,
        now: Long
    ): PortfolioOptimizationRemoteLearningEnvelope {
        val artifactRefs = syncEnvelope.artifacts.map { artifact ->
            PortfolioOptimizationRemoteLearningArtifactRef(
                artifactType = artifact.artifactType,
                artifactId = artifact.artifactId,
                artifactVersion = artifact.artifactVersion,
                artifactHash = sha256Hex(portfolioOptimizationLearningSyncEnvelopeFingerprint(artifact)),
                summary = artifact.summary
            )
        }
        val payloadHash = sha256Hex(DomainJson.encode(artifactRefs))
        return PortfolioOptimizationRemoteLearningEnvelope(
            remoteEnvelopeId = "portfolio_remote_envelope_${syncEnvelope.envelopeId.takeLast(8)}_$now",
            sourceEnvelopeId = syncEnvelope.envelopeId,
            purpose = PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT,
            mode = syncEnvelope.mode,
            boundary = syncEnvelope.boundary,
            groupKey = syncEnvelope.groupKey,
            privacyPolicy = syncEnvelope.privacyPolicy,
            enterprisePrivacyPolicy = enterprisePrivacy,
            redactionPolicy = syncEnvelope.redactionPolicy,
            consentRecordId = consentRecord?.consentId,
            provenance = syncEnvelope.provenance,
            artifactRefs = artifactRefs,
            artifactCount = artifactRefs.size,
            payloadHash = payloadHash,
            summary = "Remote learning envelope carries ${artifactRefs.size} redacted artifact reference(s).",
            createdAtMs = now
        )
    }

    private fun buildPortfolioOptimizationComplianceAuditExportBundle(
        userId: String,
        request: PortfolioOptimizationComplianceAuditExportRequest,
        enterprisePrivacy: PortfolioOptimizationEnterprisePrivacyPolicySummary,
        now: Long
    ): PortfolioOptimizationComplianceAuditExportBundle {
        val objectiveProfileSnapshotId = request.objectiveProfileSnapshotId.orEmpty()
        val artifactRefs = synchronized(dynamicStateLock) {
            buildPortfolioOptimizationComplianceArtifactRefsLocked(
                userId = userId,
                objectiveProfileSnapshotId = objectiveProfileSnapshotId,
                startAtMs = request.timeRangeStartMs,
                endAtMs = request.timeRangeEndMs
            )
        }
        val consentRecords = synchronized(dynamicStateLock) {
            portfolioOptimizationConsentRecordsByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { consent ->
                    request.purposes.contains(consent.purpose) &&
                        portfolioOptimizationTimeInRange(
                            timestamp = consent.recordedAtMs,
                            startAtMs = request.timeRangeStartMs,
                            endAtMs = request.timeRangeEndMs
                        )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationConsentRecord> { it.recordedAtMs }
                        .thenBy { it.consentId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
                .map { consent ->
                    if (request.redactionPolicy.operatorNamesRedacted) {
                        consent.copy(
                            provenance = consent.provenance.copy(grantedByName = null)
                        )
                    } else {
                        consent
                    }
                }
        }
        val receiptItems = synchronized(dynamicStateLock) {
            executionLedgerByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { record ->
                    (request.decisionId.isNullOrBlank() ||
                        record.portfolioOptimizationDecisionId == request.decisionId) &&
                        (request.resultId.isNullOrBlank() ||
                            record.portfolioOptimizationResultId == request.resultId) &&
                        (
                            objectiveProfileSnapshotId.isBlank() ||
                                record.portfolioObjectiveProfileSnapshotId == objectiveProfileSnapshotId ||
                                (
                                    !record.portfolioObjectiveProfileSnapshotId.isNullOrBlank() &&
                                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                                            userId = userId,
                                            leftSnapshotId = record.portfolioObjectiveProfileSnapshotId.orEmpty(),
                                            rightSnapshotId = objectiveProfileSnapshotId
                                        )
                                    )
                            ) &&
                        portfolioOptimizationTimeInRange(
                            timestamp = record.updatedAtMs,
                            startAtMs = request.timeRangeStartMs,
                            endAtMs = request.timeRangeEndMs
                        )
                }
                .sortedWith(
                    compareByDescending<ExecutionReceiptRecord> { it.updatedAtMs }
                        .thenBy { it.recordId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
                .map { record ->
                    PortfolioOptimizationComplianceAuditReceiptItem(
                        runId = record.runId,
                        decisionId = record.portfolioOptimizationDecisionId,
                        status = record.status,
                        activeRole = record.activeRole,
                        reasonCodes = record.receipt?.roleImpactReasonCodes.orEmpty(),
                        summary = listOfNotNull(
                            record.portfolioLearningSummary?.takeIf { it.isNotBlank() },
                            record.portfolioRemoteTransportSummary?.takeIf { it.isNotBlank() },
                            record.portfolioComplianceAuditExportSummary?.takeIf { it.isNotBlank() },
                            record.legacySummary.takeIf { it.isNotBlank() }
                        ).joinToString(" ").ifBlank {
                            "Governance receipt for ${record.runId.takeLast(8)}."
                        },
                        updatedAtMs = record.updatedAtMs
                    )
                }
        }
        val governanceItems = getGovernanceCases(
            userId = userId,
            filter = GovernanceConsoleFilter(
                includeReviewed = true,
                portfolioOptimizationDecisionId = request.decisionId,
                portfolioObjectiveProfileSnapshotId = request.objectiveProfileSnapshotId,
                limit = MAX_PORTFOLIO_OPTIMIZATION_ITEMS
            )
        )
            .filter { case ->
                portfolioOptimizationTimeInRange(
                    timestamp = case.summary.lastEventAtMs,
                    startAtMs = request.timeRangeStartMs,
                    endAtMs = request.timeRangeEndMs
                )
            }
            .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            .map { case ->
                PortfolioOptimizationComplianceAuditGovernanceItem(
                    caseId = case.summary.caseId,
                    runId = case.summary.runId,
                    primaryQueue = case.summary.primaryQueue,
                    priority = case.summary.priority,
                    reviewed = case.summary.reviewed,
                    reasonCodes = case.reasonCodes,
                    summary = listOf(
                        case.summary.summary,
                        case.summary.portfolioLearningSummary,
                        case.summary.portfolioRemoteTransportSummary,
                        case.summary.portfolioComplianceAuditExportSummary
                    ).filter { it.isNotBlank() }.joinToString(" ").ifBlank {
                        "Governance case ${case.summary.caseId.takeLast(8)}."
                    },
                    updatedAtMs = case.summary.lastEventAtMs
                )
            }
        val hashSummary = PortfolioOptimizationComplianceAuditHashSummary(
            bundleHash = sha256Hex(
                listOf(
                    DomainJson.encode(artifactRefs),
                    DomainJson.encode(consentRecords),
                    DomainJson.encode(receiptItems),
                    DomainJson.encode(governanceItems),
                    enterprisePrivacy.summary
                ).joinToString("|")
            ),
            artifactHash = sha256Hex(DomainJson.encode(artifactRefs)),
            consentHash = sha256Hex(DomainJson.encode(consentRecords)),
            receiptHash = sha256Hex(DomainJson.encode(receiptItems)),
            governanceHash = sha256Hex(DomainJson.encode(governanceItems)),
            artifactCount = artifactRefs.size,
            consentCount = consentRecords.size,
            receiptCount = receiptItems.size,
            governanceCount = governanceItems.size,
            summary = "Hashes cover ${artifactRefs.size} artifacts, ${consentRecords.size} consents, ${receiptItems.size} receipts, and ${governanceItems.size} governance items."
        )
        return PortfolioOptimizationComplianceAuditExportBundle(
            bundleId = "portfolio_audit_bundle_${request.requestId.takeLast(8)}_$now",
            format = request.format,
            redactionPolicy = request.redactionPolicy,
            artifactRefs = artifactRefs,
            consentRecords = consentRecords,
            receiptItems = receiptItems,
            governanceItems = governanceItems,
            hashSummary = hashSummary,
            summary = "Compliance audit export captured ${artifactRefs.size} learning artifact reference(s), ${receiptItems.size} receipt(s), ${governanceItems.size} governance item(s), and ${consentRecords.size} consent record(s). ${enterprisePrivacy.summary}",
            createdAtMs = now
        )
    }

    private fun buildPortfolioOptimizationComplianceArtifactRefsLocked(
        userId: String,
        objectiveProfileSnapshotId: String,
        startAtMs: Long?,
        endAtMs: Long?
    ): List<PortfolioOptimizationRemoteLearningArtifactRef> {
        val objectiveProfileRefs = portfolioOptimizationObjectiveProfileSnapshotsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { snapshot ->
                objectiveProfileSnapshotId.isBlank() ||
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = snapshot.snapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
            }
            .filter { snapshot ->
                portfolioOptimizationTimeInRange(snapshot.createdAtMs, startAtMs, endAtMs)
            }
            .map { snapshot ->
                PortfolioOptimizationRemoteLearningArtifactRef(
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT,
                    artifactId = snapshot.snapshotId,
                    artifactVersion = snapshot.version,
                    artifactHash = sha256Hex(DomainJson.encode(redactPortfolioOptimizationObjectiveProfileSnapshot(snapshot))),
                    summary = snapshot.summary
                )
            }
        val calibrationRefs = portfolioOptimizationCalibrationSnapshotsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { snapshot ->
                objectiveProfileSnapshotId.isBlank() ||
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = snapshot.objectiveProfileSnapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
            }
            .filter { snapshot ->
                portfolioOptimizationTimeInRange(snapshot.createdAtMs, startAtMs, endAtMs)
            }
            .map { snapshot ->
                PortfolioOptimizationRemoteLearningArtifactRef(
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT,
                    artifactId = snapshot.snapshotId,
                    artifactVersion = snapshot.version,
                    artifactHash = sha256Hex(DomainJson.encode(redactPortfolioOptimizationCalibrationSnapshot(snapshot))),
                    summary = snapshot.summary
                )
            }
        val driftRefs = portfolioOptimizationDriftSummariesByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { drift ->
                objectiveProfileSnapshotId.isBlank() ||
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = drift.objectiveProfileSnapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
            }
            .filter { drift ->
                portfolioOptimizationTimeInRange(drift.createdAtMs, startAtMs, endAtMs)
            }
            .map { drift ->
                PortfolioOptimizationRemoteLearningArtifactRef(
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY,
                    artifactId = drift.driftId,
                    artifactVersion = 1,
                    artifactHash = sha256Hex(DomainJson.encode(redactPortfolioOptimizationDriftSummary(drift))),
                    summary = drift.summary
                )
            }
        val outcomeRefs = portfolioOptimizationOutcomesByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { outcome ->
                objectiveProfileSnapshotId.isBlank() ||
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = outcome.objectiveProfileSnapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
            }
            .filter { outcome ->
                portfolioOptimizationTimeInRange(outcome.recordedAtMs, startAtMs, endAtMs)
            }
            .map { outcome ->
                val aggregate = buildPortfolioOptimizationOutcomeAggregate(outcome)
                PortfolioOptimizationRemoteLearningArtifactRef(
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE,
                    artifactId = aggregate.aggregateId,
                    artifactVersion = 1,
                    artifactHash = sha256Hex(DomainJson.encode(aggregate)),
                    summary = aggregate.summary
                )
            }
        val aggregationRefs = portfolioOptimizationFederatedAggregationSummariesByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { summary ->
                objectiveProfileSnapshotId.isBlank() ||
                    findPortfolioOptimizationObjectiveProfileSnapshotLocked(userId, objectiveProfileSnapshotId)
                        ?.binding
                        ?.tenantId
                        ?.let { tenantId -> summary.boundary.tenantId == tenantId }
                        ?: true
            }
            .filter { summary ->
                portfolioOptimizationTimeInRange(summary.updatedAtMs, startAtMs, endAtMs)
            }
            .map { summary ->
                PortfolioOptimizationRemoteLearningArtifactRef(
                    artifactType = PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY,
                    artifactId = summary.aggregationId,
                    artifactVersion = summary.artifactCount,
                    artifactHash = sha256Hex(DomainJson.encode(summary)),
                    summary = summary.summary
                )
            }
        return (
            objectiveProfileRefs +
                calibrationRefs +
                driftRefs +
                outcomeRefs +
                aggregationRefs
            )
            .distinctBy { "${it.artifactType}:${it.artifactId}:${it.artifactVersion}" }
            .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
    }

    private fun portfolioOptimizationTimeInRange(
        timestamp: Long,
        startAtMs: Long?,
        endAtMs: Long?
    ): Boolean {
        if (timestamp <= 0L) return false
        if (startAtMs != null && timestamp < startAtMs) return false
        if (endAtMs != null && timestamp > endAtMs) return false
        return true
    }

    private fun sha256Hex(raw: String): String {
        val digest = MessageDigest.getInstance("SHA-256").digest(raw.toByteArray(StandardCharsets.UTF_8))
        return digest.joinToString("") { byte -> "%02x".format(byte) }
    }

    private fun storePortfolioOptimizationLearningSyncEnvelope(
        userId: String,
        envelope: PortfolioOptimizationLearningSyncEnvelope
    ) {
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationLearningSyncEnvelopesByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue.toList()
                .filterNot { it.envelopeId == envelope.envelopeId }
                .plus(envelope)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationLearningSyncEnvelope> { it.createdAtMs }
                        .thenBy { it.envelopeId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
    }

