    private fun storePortfolioOptimizationCrossBoundaryAudit(
        userId: String,
        audit: PortfolioOptimizationCrossBoundaryAuditRecord
    ) {
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationCrossBoundaryAuditsByUser.getOrPut(userId) {
                ArrayDeque()
            }
            val merged = queue.toList()
                .filterNot { it.auditId == audit.auditId }
                .plus(audit)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationCrossBoundaryAuditRecord> {
                        it.recordedAtMs
                    }.thenBy { it.auditId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
    }

    private fun storePortfolioOptimizationCrossBoundaryCorrectiveAction(
        userId: String,
        correctiveAction: PortfolioOptimizationCrossBoundaryCorrectiveActionRecord
    ) {
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationCrossBoundaryCorrectiveActionsByUser.getOrPut(userId) {
                ArrayDeque()
            }
            val merged = queue.toList()
                .filterNot { it.actionRecordId == correctiveAction.actionRecordId }
                .plus(correctiveAction)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationCrossBoundaryCorrectiveActionRecord> {
                        it.recordedAtMs
                    }.thenBy { it.actionRecordId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
    }

    private fun <T> replacePortfolioOptimizationDerivedQueueLocked(
        queues: ConcurrentHashMap<String, ArrayDeque<T>>,
        userId: String,
        items: List<T>
    ) {
        val queue = queues.getOrPut(userId) { ArrayDeque() }
        queue.clear()
        items.take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS).forEach(queue::addLast)
    }

    private fun portfolioOptimizationDestinationTrustTierRank(
        tier: PortfolioOptimizationDestinationTrustTier
    ): Int {
        return when (tier) {
            PortfolioOptimizationDestinationTrustTier.HIGH_TRUST -> 4
            PortfolioOptimizationDestinationTrustTier.TRUSTED -> 3
            PortfolioOptimizationDestinationTrustTier.LIMITED -> 2
            PortfolioOptimizationDestinationTrustTier.UNVERIFIED -> 1
            PortfolioOptimizationDestinationTrustTier.RESTRICTED -> 0
        }
    }

    private fun portfolioOptimizationJurisdictionRank(
        jurisdiction: PortfolioOptimizationJurisdiction
    ): Int {
        return when (jurisdiction) {
            PortfolioOptimizationJurisdiction.TENANT_POLICY_ZONE -> 0
            PortfolioOptimizationJurisdiction.UK_GDPR -> 1
            PortfolioOptimizationJurisdiction.EU_GDPR -> 2
            PortfolioOptimizationJurisdiction.US_PRIVACY -> 3
            PortfolioOptimizationJurisdiction.APAC_ENTERPRISE -> 4
            PortfolioOptimizationJurisdiction.GLOBAL_RESTRICTED -> 5
        }
    }

    private fun portfolioOptimizationPriorityForScore(score: Int): PortfolioOptimizationPortfolioPriority {
        return when {
            score >= 120 -> PortfolioOptimizationPortfolioPriority.CRITICAL
            score >= 90 -> PortfolioOptimizationPortfolioPriority.HIGH
            score >= 60 -> PortfolioOptimizationPortfolioPriority.MEDIUM
            else -> PortfolioOptimizationPortfolioPriority.LOW
        }
    }

    private fun portfolioOptimizationProgramRiskUnits(
        status: PortfolioOptimizationCrossBoundaryProgramStatus
    ): Int {
        return when (status) {
            PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE -> 2
            PortfolioOptimizationCrossBoundaryProgramStatus.DEGRADED -> 8
            PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED -> 6
            PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED -> 18
            PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING -> 10
            PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED -> 12
        }
    }

    private fun portfolioOptimizationTrustTierDriftWeight(
        state: PortfolioOptimizationTrustTierDriftState
    ): Int {
        return when (state) {
            PortfolioOptimizationTrustTierDriftState.HEALTHY -> 0
            PortfolioOptimizationTrustTierDriftState.AT_RISK -> 6
            PortfolioOptimizationTrustTierDriftState.DRIFTING -> 12
            PortfolioOptimizationTrustTierDriftState.DEGRADED -> 8
            PortfolioOptimizationTrustTierDriftState.BLOCKED -> 16
        }
    }

    private fun portfolioOptimizationJurisdictionDriftWeight(
        state: PortfolioOptimizationJurisdictionDriftState
    ): Int {
        return when (state) {
            PortfolioOptimizationJurisdictionDriftState.HEALTHY -> 0
            PortfolioOptimizationJurisdictionDriftState.AT_RISK -> 6
            PortfolioOptimizationJurisdictionDriftState.DRIFTING -> 12
            PortfolioOptimizationJurisdictionDriftState.DEGRADED -> 8
            PortfolioOptimizationJurisdictionDriftState.BLOCKED -> 16
        }
    }

    private fun portfolioOptimizationRiskBudgetStatus(
        allocatedUnits: Int,
        consumedUnits: Int,
        holdRequested: Boolean
    ): PortfolioOptimizationRiskBudgetStatus {
        if (holdRequested) return PortfolioOptimizationRiskBudgetStatus.HELD
        return when {
            consumedUnits <= 0 -> PortfolioOptimizationRiskBudgetStatus.NOT_STARTED
            consumedUnits >= allocatedUnits -> PortfolioOptimizationRiskBudgetStatus.EXCEEDED
            consumedUnits >= (allocatedUnits * 0.75).toInt().coerceAtLeast(1) ->
                PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT
            else -> PortfolioOptimizationRiskBudgetStatus.WITHIN_BUDGET
        }
    }

    private fun portfolioOptimizationTrustTierDriftState(
        rolloutState: PortfolioOptimizationTrustTierRolloutState,
        rerouteCount: Int,
        blockedCount: Int,
        heldCount: Int,
        degradedCount: Int
    ): PortfolioOptimizationTrustTierDriftState {
        return when {
            rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED ||
                blockedCount > 0 && blockedCount >= (blockedCount + heldCount + rerouteCount).coerceAtLeast(1) ->
                PortfolioOptimizationTrustTierDriftState.BLOCKED
            rerouteCount > 0 && blockedCount > 0 ->
                PortfolioOptimizationTrustTierDriftState.DRIFTING
            degradedCount > 0 ->
                PortfolioOptimizationTrustTierDriftState.DEGRADED
            heldCount > 0 || blockedCount > 0 ->
                PortfolioOptimizationTrustTierDriftState.AT_RISK
            else -> PortfolioOptimizationTrustTierDriftState.HEALTHY
        }
    }

    private fun portfolioOptimizationJurisdictionDriftState(
        rolloutState: PortfolioOptimizationJurisdictionRolloutState,
        rerouteCount: Int,
        blockedCount: Int,
        deferredCount: Int,
        heldCount: Int,
        degradedCount: Int,
        sharedBlockerCount: Int
    ): PortfolioOptimizationJurisdictionDriftState {
        return when {
            rolloutState == PortfolioOptimizationJurisdictionRolloutState.BLOCKED ->
                PortfolioOptimizationJurisdictionDriftState.BLOCKED
            rolloutState == PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED ||
                (rerouteCount > 0 && blockedCount > 0) ->
                PortfolioOptimizationJurisdictionDriftState.DRIFTING
            degradedCount > 0 ->
                PortfolioOptimizationJurisdictionDriftState.DEGRADED
            deferredCount > 0 || heldCount > 0 || sharedBlockerCount > 0 ->
                PortfolioOptimizationJurisdictionDriftState.AT_RISK
            else -> PortfolioOptimizationJurisdictionDriftState.HEALTHY
        }
    }

    private fun portfolioOptimizationPortfolioHealthStatus(
        portfolioStatus: PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus,
        riskBudgetStatus: PortfolioOptimizationRiskBudgetStatus,
        trustTierDriftState: PortfolioOptimizationTrustTierDriftState,
        jurisdictionDriftState: PortfolioOptimizationJurisdictionDriftState
    ): PortfolioOptimizationCrossBoundaryPortfolioHealthStatus {
        return when {
            riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.HELD ||
                riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.EXCEEDED ||
                trustTierDriftState == PortfolioOptimizationTrustTierDriftState.BLOCKED ||
                jurisdictionDriftState == PortfolioOptimizationJurisdictionDriftState.BLOCKED ||
                portfolioStatus == PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.BLOCKED ->
                PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.BLOCKED
            riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT ||
                trustTierDriftState == PortfolioOptimizationTrustTierDriftState.DRIFTING ||
                jurisdictionDriftState == PortfolioOptimizationJurisdictionDriftState.DRIFTING ->
                PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.AT_RISK
            trustTierDriftState == PortfolioOptimizationTrustTierDriftState.DEGRADED ||
                jurisdictionDriftState == PortfolioOptimizationJurisdictionDriftState.DEGRADED ||
                portfolioStatus == PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.DEGRADED ->
                PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DEGRADED
            trustTierDriftState == PortfolioOptimizationTrustTierDriftState.AT_RISK ||
                jurisdictionDriftState == PortfolioOptimizationJurisdictionDriftState.AT_RISK ||
                portfolioStatus == PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.REVIEW_REQUIRED ->
                PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DRIFTING
            else -> PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.HEALTHY
        }
    }

    private fun portfolioOptimizationTrajectoryState(
        healthStatus: PortfolioOptimizationCrossBoundaryPortfolioHealthStatus,
        blockerTrendDirection: PortfolioOptimizationTrendDirection
    ): PortfolioOptimizationPortfolioTrajectoryState {
        return when {
            healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.BLOCKED ->
                PortfolioOptimizationPortfolioTrajectoryState.STALLED
            blockerTrendDirection == PortfolioOptimizationTrendDirection.RISING &&
                healthStatus in setOf(
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.AT_RISK,
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DEGRADED
                ) -> PortfolioOptimizationPortfolioTrajectoryState.DRIFTING
            blockerTrendDirection == PortfolioOptimizationTrendDirection.FALLING &&
                healthStatus in setOf(
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.HEALTHY,
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DRIFTING
                ) -> PortfolioOptimizationPortfolioTrajectoryState.CONVERGING
            healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.HEALTHY ->
                PortfolioOptimizationPortfolioTrajectoryState.CONVERGING
            else -> PortfolioOptimizationPortfolioTrajectoryState.STALLED
        }
    }

    private fun portfolioOptimizationPortfolioSafetyState(
        healthStatus: PortfolioOptimizationCrossBoundaryPortfolioHealthStatus,
        riskBudgetStatus: PortfolioOptimizationRiskBudgetStatus,
        trustTierDriftState: PortfolioOptimizationTrustTierDriftState,
        jurisdictionDriftState: PortfolioOptimizationJurisdictionDriftState,
        concentrationRatio: Double,
        highRiskDestinationCount: Int,
        sharedBlockerCount: Int,
        conflictCount: Int
    ): PortfolioOptimizationPortfolioSafetyState {
        return when {
            riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.HELD ||
                healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.BLOCKED ->
                PortfolioOptimizationPortfolioSafetyState.BLOCKED
            (riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.EXCEEDED &&
                trustTierDriftState in setOf(
                    PortfolioOptimizationTrustTierDriftState.DRIFTING,
                    PortfolioOptimizationTrustTierDriftState.DEGRADED,
                    PortfolioOptimizationTrustTierDriftState.BLOCKED
                )) ||
                (riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.EXCEEDED &&
                    jurisdictionDriftState in setOf(
                        PortfolioOptimizationJurisdictionDriftState.DRIFTING,
                        PortfolioOptimizationJurisdictionDriftState.DEGRADED,
                        PortfolioOptimizationJurisdictionDriftState.BLOCKED
                    )) ||
                (concentrationRatio >= 0.75 && highRiskDestinationCount > 0) ||
                (sharedBlockerCount >= 2 && conflictCount > 0) ->
                PortfolioOptimizationPortfolioSafetyState.QUARANTINED
            riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.EXCEEDED ||
                healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DEGRADED ||
                trustTierDriftState in setOf(
                    PortfolioOptimizationTrustTierDriftState.DRIFTING,
                    PortfolioOptimizationTrustTierDriftState.DEGRADED
                ) ||
                jurisdictionDriftState in setOf(
                    PortfolioOptimizationJurisdictionDriftState.DRIFTING,
                    PortfolioOptimizationJurisdictionDriftState.DEGRADED
                ) ->
                PortfolioOptimizationPortfolioSafetyState.GUARDED
            riskBudgetStatus == PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT ||
                healthStatus in setOf(
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.AT_RISK,
                    PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DRIFTING
                ) ||
                trustTierDriftState == PortfolioOptimizationTrustTierDriftState.AT_RISK ||
                jurisdictionDriftState == PortfolioOptimizationJurisdictionDriftState.AT_RISK ->
                PortfolioOptimizationPortfolioSafetyState.AT_RISK
            else -> PortfolioOptimizationPortfolioSafetyState.SAFE
        }
    }

    private fun portfolioOptimizationBudgetGuardrailState(
        riskBudget: PortfolioOptimizationRiskBudget,
        healthStatus: PortfolioOptimizationCrossBoundaryPortfolioHealthStatus
    ): PortfolioOptimizationBudgetGuardrailState {
        val utilizationPct = if (riskBudget.allocatedUnits <= 0) {
            0.0
        } else {
            (riskBudget.consumedUnits.toDouble() / riskBudget.allocatedUnits.toDouble()) * 100.0
        }
        return when {
            riskBudget.status == PortfolioOptimizationRiskBudgetStatus.HELD ||
                (riskBudget.status == PortfolioOptimizationRiskBudgetStatus.EXCEEDED &&
                    riskBudget.breachUnits >= maxOf(1, riskBudget.allocatedUnits / 10)) ->
                PortfolioOptimizationBudgetGuardrailState.HARD_STOP
            riskBudget.status == PortfolioOptimizationRiskBudgetStatus.EXCEEDED ->
                PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED
            utilizationPct >= 90.0 ||
                (riskBudget.status == PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT &&
                    healthStatus in setOf(
                        PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.AT_RISK,
                        PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DEGRADED,
                        PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.BLOCKED
                    )) ->
                PortfolioOptimizationBudgetGuardrailState.SOFT_STOP
            utilizationPct >= 75.0 ||
                riskBudget.status == PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT ->
                PortfolioOptimizationBudgetGuardrailState.WARNING
            else -> PortfolioOptimizationBudgetGuardrailState.WITHIN_LIMIT
        }
    }

    private fun portfolioOptimizationEnforcementMode(
        safetyState: PortfolioOptimizationPortfolioSafetyState,
        budgetGuardrailState: PortfolioOptimizationBudgetGuardrailState,
        approvalRequired: Boolean
    ): PortfolioOptimizationPortfolioEnforcementMode {
        return when {
            safetyState == PortfolioOptimizationPortfolioSafetyState.BLOCKED ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP
            safetyState == PortfolioOptimizationPortfolioSafetyState.QUARANTINED ->
                PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE
            approvalRequired ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ->
                PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED
            safetyState == PortfolioOptimizationPortfolioSafetyState.GUARDED ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.SOFT_STOP ->
                PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP
            safetyState == PortfolioOptimizationPortfolioSafetyState.AT_RISK ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.WARNING ->
                PortfolioOptimizationPortfolioEnforcementMode.WARNING
            else -> PortfolioOptimizationPortfolioEnforcementMode.OBSERVE
        }
    }

    private fun portfolioOptimizationRemediationSuppressionReason(
        automationState: PortfolioOptimizationRemediationAutomationState,
        budgetGuardrailState: PortfolioOptimizationBudgetGuardrailState,
        trustTierDriftState: PortfolioOptimizationTrustTierDriftState,
        jurisdictionDriftState: PortfolioOptimizationJurisdictionDriftState,
        concentrationRatio: Double,
        sharedBlockerCount: Int
    ): PortfolioOptimizationRemediationSuppressionReason? {
        return when (automationState) {
            PortfolioOptimizationRemediationAutomationState.SUPPRESSED ->
                when {
                    budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                        PortfolioOptimizationRemediationSuppressionReason.RISK_BUDGET_HARD_STOP
                    trustTierDriftState in setOf(
                        PortfolioOptimizationTrustTierDriftState.DRIFTING,
                        PortfolioOptimizationTrustTierDriftState.DEGRADED,
                        PortfolioOptimizationTrustTierDriftState.BLOCKED
                    ) -> PortfolioOptimizationRemediationSuppressionReason.TRUST_TIER_DRIFT
                    jurisdictionDriftState in setOf(
                        PortfolioOptimizationJurisdictionDriftState.DRIFTING,
                        PortfolioOptimizationJurisdictionDriftState.DEGRADED,
                        PortfolioOptimizationJurisdictionDriftState.BLOCKED
                    ) -> PortfolioOptimizationRemediationSuppressionReason.JURISDICTION_DRIFT
                    concentrationRatio >= 0.60 ->
                        PortfolioOptimizationRemediationSuppressionReason.DESTINATION_CONCENTRATION
                    else -> PortfolioOptimizationRemediationSuppressionReason.SHARED_BLOCKERS
                }
            PortfolioOptimizationRemediationAutomationState.COOLDOWN_ACTIVE ->
                PortfolioOptimizationRemediationSuppressionReason.COOLDOWN_ACTIVE
            PortfolioOptimizationRemediationAutomationState.APPROVAL_REQUIRED ->
                PortfolioOptimizationRemediationSuppressionReason.MANUAL_APPROVAL_REQUIRED
            PortfolioOptimizationRemediationAutomationState.QUARANTINED ->
                PortfolioOptimizationRemediationSuppressionReason.QUARANTINE_ACTIVE
            PortfolioOptimizationRemediationAutomationState.THROTTLED ->
                when {
                    trustTierDriftState in setOf(
                        PortfolioOptimizationTrustTierDriftState.AT_RISK,
                        PortfolioOptimizationTrustTierDriftState.DRIFTING,
                        PortfolioOptimizationTrustTierDriftState.DEGRADED
                    ) -> PortfolioOptimizationRemediationSuppressionReason.TRUST_TIER_DRIFT
                    jurisdictionDriftState in setOf(
                        PortfolioOptimizationJurisdictionDriftState.AT_RISK,
                        PortfolioOptimizationJurisdictionDriftState.DRIFTING,
                        PortfolioOptimizationJurisdictionDriftState.DEGRADED
                    ) -> PortfolioOptimizationRemediationSuppressionReason.JURISDICTION_DRIFT
                    concentrationRatio >= 0.60 ->
                        PortfolioOptimizationRemediationSuppressionReason.DESTINATION_CONCENTRATION
                    sharedBlockerCount > 1 ->
                        PortfolioOptimizationRemediationSuppressionReason.SHARED_BLOCKERS
                    else -> PortfolioOptimizationRemediationSuppressionReason.SHARED_BLOCKERS
                }
            PortfolioOptimizationRemediationAutomationState.ALLOWED -> null
        }
    }

    private fun portfolioOptimizationRemediationAutomationState(
        safetyState: PortfolioOptimizationPortfolioSafetyState,
        budgetGuardrailState: PortfolioOptimizationBudgetGuardrailState,
        blockerTrendDirection: PortfolioOptimizationTrendDirection,
        sharedBlockerCount: Int,
        recentCorrectiveActionAtMs: Long?,
        now: Long
    ): PortfolioOptimizationRemediationAutomationState {
        val cooldownActive = recentCorrectiveActionAtMs != null &&
            now - recentCorrectiveActionAtMs < PORTFOLIO_REMEDIATION_COOLDOWN_MS
        return when {
            safetyState == PortfolioOptimizationPortfolioSafetyState.QUARANTINED ->
                PortfolioOptimizationRemediationAutomationState.QUARANTINED
            safetyState == PortfolioOptimizationPortfolioSafetyState.BLOCKED ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                PortfolioOptimizationRemediationAutomationState.SUPPRESSED
            cooldownActive ->
                PortfolioOptimizationRemediationAutomationState.COOLDOWN_ACTIVE
            budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ->
                PortfolioOptimizationRemediationAutomationState.APPROVAL_REQUIRED
            safetyState == PortfolioOptimizationPortfolioSafetyState.GUARDED ||
                budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.SOFT_STOP ||
                blockerTrendDirection == PortfolioOptimizationTrendDirection.RISING ||
                sharedBlockerCount > 1 ->
                PortfolioOptimizationRemediationAutomationState.THROTTLED
            else -> PortfolioOptimizationRemediationAutomationState.ALLOWED
        }
    }

    private fun derivePortfolioOptimizationDestinationTrustTier(
        profile: PortfolioOptimizationRemoteDestinationProfile?,
        decisions: List<PortfolioOptimizationRemoteDestinationDecisionRecord>
    ): PortfolioOptimizationDestinationTrustTier {
        val latestDecision = decisions.maxWithOrNull(
            compareBy<PortfolioOptimizationRemoteDestinationDecisionRecord> { it.createdAtMs }
                .thenBy { it.decisionId }
        )
        val destinationType = profile?.type ?: latestDecision?.selectedDestinationType
        val blockingDecision = decisions.any { decision ->
            decision.status in setOf(
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY,
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION,
                PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY
            )
        }
        return when {
            profile?.active == false -> PortfolioOptimizationDestinationTrustTier.RESTRICTED
            destinationType == PortfolioOptimizationRemoteDestinationType.LOCAL_DEVICE ||
                destinationType == PortfolioOptimizationRemoteDestinationType.LOCAL_COMPLIANCE_ARCHIVE ->
                PortfolioOptimizationDestinationTrustTier.HIGH_TRUST
            profile?.destinationPolicy?.localOnly == true && destinationType != null ->
                PortfolioOptimizationDestinationTrustTier.RESTRICTED
            blockingDecision -> PortfolioOptimizationDestinationTrustTier.RESTRICTED
            latestDecision?.status == PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED &&
                profile?.type == PortfolioOptimizationRemoteDestinationType.REMOTE_COMPLIANCE_ARCHIVE ->
                PortfolioOptimizationDestinationTrustTier.TRUSTED
            latestDecision?.status == PortfolioOptimizationRemoteDestinationDecisionStatus.ROUTED &&
                profile?.destinationPolicy?.sameTenantOnly == true ->
                PortfolioOptimizationDestinationTrustTier.TRUSTED
            latestDecision?.status == PortfolioOptimizationRemoteDestinationDecisionStatus.HELD_FOR_COMPLIANCE ||
                latestDecision?.status == PortfolioOptimizationRemoteDestinationDecisionStatus.REROUTED ||
                latestDecision?.status == PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                PortfolioOptimizationDestinationTrustTier.LIMITED
            profile?.active == true && profile.destinationPolicy.sameTenantOnly ->
                PortfolioOptimizationDestinationTrustTier.LIMITED
            else -> PortfolioOptimizationDestinationTrustTier.UNVERIFIED
        }
    }

    private fun recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(
        userId: String,
        now: Long
    ) {
        synchronized(dynamicStateLock) {
            data class BlockerKey(
                val portfolioId: String,
                val type: PortfolioOptimizationPortfolioBlockerType,
                val scopeKey: String
            )

            data class BlockerAggregate(
                val key: BlockerKey,
                val programIds: MutableSet<String> = linkedSetOf(),
                val bundleDecisionIds: MutableSet<String> = linkedSetOf(),
                val reasonCodes: MutableSet<String> = linkedSetOf(),
                var blocking: Boolean = true
            )

            data class ProgramContext(
                val portfolioId: String,
                val programId: String,
                val purpose: PortfolioOptimizationConsentPurpose,
                val bundleType: PortfolioOptimizationSafeDestinationBundleType,
                val trustTier: PortfolioOptimizationDestinationTrustTier,
                val jurisdiction: PortfolioOptimizationJurisdiction,
                val bundleDecisionId: String,
                val bundleId: String,
                val destinationIds: Set<String>,
                val blockerTypes: Set<PortfolioOptimizationPortfolioBlockerType>,
                val programStatus: PortfolioOptimizationCrossBoundaryProgramStatus,
                val suggestedAction: PortfolioOptimizationPortfolioRecommendationAction,
                val priorityScore: Int,
                val priority: PortfolioOptimizationPortfolioPriority,
                val summary: String
            )

            val previousBlockerTrendsByPortfolio = portfolioOptimizationPortfolioBlockerTrendsByUser[userId]
                ?.toList()
                .orEmpty()
                .associateBy { it.portfolioId }
            val latestCorrectiveActionByPortfolio = portfolioOptimizationCrossBoundaryCorrectiveActionsByUser[userId]
                ?.toList()
                .orEmpty()
                .groupBy { it.portfolioId }
                .mapValues { (_, actions) ->
                    actions.maxWithOrNull(
                        compareBy<PortfolioOptimizationCrossBoundaryCorrectiveActionRecord> { it.recordedAtMs }
                            .thenBy { it.actionRecordId }
                    )
                }

            val destinationProfiles = portfolioOptimizationRemoteDestinationProfilesByUser[userId]
                ?.toList()
                .orEmpty()
                .sortedWith(
                    compareByDescending<PortfolioOptimizationRemoteDestinationProfile> { it.updatedAtMs }
                        .thenBy { it.destinationId }
                )
            val latestDestinationProfilesById = linkedMapOf<String, PortfolioOptimizationRemoteDestinationProfile>()
            destinationProfiles.forEach { profile ->
                if (!latestDestinationProfilesById.containsKey(profile.destinationId)) {
                    latestDestinationProfilesById[profile.destinationId] = profile
                }
            }
            val destinationDecisions = portfolioOptimizationRemoteDestinationDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
            val bundleDecisions = portfolioOptimizationDataExchangeBundleDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
                .sortedWith(
                    compareByDescending<PortfolioOptimizationDestinationBundleDecisionRecord> { it.createdAtMs }
                        .thenBy { it.decisionId }
                )
            val bundlesById = portfolioOptimizationDataExchangeBundlesByUser[userId]
                ?.toList()
                .orEmpty()
                .associateBy { it.bundleId }
            val manifestsByDecisionId = portfolioOptimizationDataExchangeManifestsByUser[userId]
                ?.toList()
                .orEmpty()
                .groupBy { it.bundleDecisionId }
                .mapValues { (_, manifests) ->
                    manifests.maxWithOrNull(
                        compareBy<PortfolioOptimizationDataExchangeManifest> { it.createdAtMs }
                            .thenBy { it.manifestId }
                    )
                }
            val approvalsByDecisionId = portfolioOptimizationCrossBoundaryApprovalsByUser[userId]
                ?.toList()
                .orEmpty()
                .groupBy { it.bundleDecisionId }
                .mapValues { (_, approvals) ->
                    approvals.maxWithOrNull(
                        compareBy<PortfolioOptimizationCrossBoundaryApprovalRecord> { it.recordedAtMs }
                            .thenBy { it.approvalId }
                    )
                }
            val auditsByDecisionId = portfolioOptimizationCrossBoundaryAuditsByUser[userId]
                ?.toList()
                .orEmpty()
                .groupBy { it.bundleDecisionId }
            val hasCrossBoundarySourceState =
                destinationProfiles.isNotEmpty() ||
                    destinationDecisions.isNotEmpty() ||
                    bundleDecisions.isNotEmpty() ||
                    bundlesById.isNotEmpty() ||
                    manifestsByDecisionId.isNotEmpty() ||
                    approvalsByDecisionId.isNotEmpty() ||
                    auditsByDecisionId.isNotEmpty()
            if (!hasCrossBoundarySourceState) {
                return
            }
            val decisionContexts = mutableListOf<ProgramContext>()
            val blockerAggregates = linkedMapOf<BlockerKey, BlockerAggregate>()
            val referencedDestinationIds = linkedSetOf<String>()
            bundleDecisions.forEach { decision ->
                val bundle = bundlesById[decision.bundleId]
                val manifest = manifestsByDecisionId[decision.decisionId]
                val approval = approvalsByDecisionId[decision.decisionId]
                val audits = auditsByDecisionId[decision.decisionId].orEmpty()
                val candidateDestinationIds = linkedSetOf<String>().apply {
                    addAll(bundle?.destinationIds.orEmpty())
                    decision.primaryDestinationId?.let(::add)
                    decision.splitResult?.primaryDestinationId?.let(::add)
                    decision.splitResult?.secondaryDestinationId?.let(::add)
                    manifest?.destinationIds?.forEach(::add)
                }
                referencedDestinationIds += candidateDestinationIds
                val relatedDestinationDecision = destinationDecisions
                    .filter { destinationDecision ->
                        destinationDecision.sourceId == decision.sourceId ||
                            destinationDecision.selectedDestinationId in candidateDestinationIds ||
                            destinationDecision.reroutedFromDestinationId in candidateDestinationIds
                    }
                    .maxWithOrNull(
                        compareBy<PortfolioOptimizationRemoteDestinationDecisionRecord> { it.createdAtMs }
                            .thenBy { it.decisionId }
                    )
                relatedDestinationDecision?.selectedDestinationId?.let(referencedDestinationIds::add)
                val trustTier = candidateDestinationIds
                    .map { destinationId ->
                        val profile = latestDestinationProfilesById[destinationId]
                        val decisionsForDestination = destinationDecisions.filter { destinationDecision ->
                            destinationDecision.selectedDestinationId == destinationId ||
                                destinationDecision.reroutedFromDestinationId == destinationId ||
                                destinationDecision.eligibility.any { eligibility ->
                                    eligibility.destinationId == destinationId
                                }
                        }
                        derivePortfolioOptimizationDestinationTrustTier(profile, decisionsForDestination)
                    }
                    .maxByOrNull { portfolioOptimizationDestinationTrustTierRank(it) }
                    ?: derivePortfolioOptimizationDestinationTrustTier(
                        profile = relatedDestinationDecision?.selectedDestinationId?.let(latestDestinationProfilesById::get),
                        decisions = relatedDestinationDecision?.let(::listOf).orEmpty()
                    )
                val jurisdiction = relatedDestinationDecision?.jurisdiction
                    ?: manifest?.boundarySummary?.jurisdiction
                    ?: decision.boundarySummary.jurisdiction
                    ?: PortfolioOptimizationJurisdiction.TENANT_POLICY_ZONE
                val blockerTypes = linkedSetOf<PortfolioOptimizationPortfolioBlockerType>().apply {
                    if (
                        trustTier == PortfolioOptimizationDestinationTrustTier.RESTRICTED ||
                        trustTier == PortfolioOptimizationDestinationTrustTier.UNVERIFIED
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.TRUST_TIER)
                    }
                    if (
                        relatedDestinationDecision?.status ==
                            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_JURISDICTION ||
                        manifest?.holdReason ==
                            PortfolioOptimizationDataExchangeHoldReason.JURISDICTION_REVIEW_REQUIRED
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.JURISDICTION)
                    }
                    if (
                        relatedDestinationDecision?.status ==
                            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_RESIDENCY ||
                        manifest?.holdReason ==
                            PortfolioOptimizationDataExchangeHoldReason.RESIDENCY_REVIEW_REQUIRED
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.RESIDENCY)
                    }
                    if (approval?.status == PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW) {
                        add(PortfolioOptimizationPortfolioBlockerType.APPROVAL)
                    }
                    if (
                        relatedDestinationDecision?.status ==
                            PortfolioOptimizationRemoteDestinationDecisionStatus.BLOCKED_BY_DESTINATION_POLICY ||
                        decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ||
                        decision.boundarySummary.destinationPolicyAllowed.not()
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.DESTINATION_POLICY)
                    }
                    if (
                        decision.boundarySummary.complianceDecision ==
                            PortfolioOptimizationComplianceGateDecision.BLOCKED ||
                        audits.any { audit ->
                            audit.result == PortfolioOptimizationCrossBoundaryAuditResult.FAILED
                        }
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.COMPLIANCE)
                    }
                    if (
                        decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ||
                        manifest?.status == PortfolioOptimizationDataExchangeManifestStatus.SPLIT ||
                        decision.splitResult?.splitRequired == true
                    ) {
                        add(PortfolioOptimizationPortfolioBlockerType.LOCAL_ONLY_SPLIT)
                    }
                }
                val programStatus = when {
                    decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ||
                        blockerTypes.any {
                            it == PortfolioOptimizationPortfolioBlockerType.COMPLIANCE ||
                                it == PortfolioOptimizationPortfolioBlockerType.RESIDENCY ||
                                it == PortfolioOptimizationPortfolioBlockerType.JURISDICTION
                        } &&
                        decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.BLOCKED ->
                        PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED
                    approval?.status == PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW ||
                        decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.HELD ||
                        audits.any { audit ->
                            audit.result == PortfolioOptimizationCrossBoundaryAuditResult.REVIEW_REQUIRED
                        } ->
                        PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED
                    decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.SUPPRESSED ->
                        PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED
                    decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.REROUTED ||
                        decision.status == PortfolioOptimizationDestinationBundleDecisionStatus.SPLIT ||
                        manifest?.status == PortfolioOptimizationDataExchangeManifestStatus.REROUTED ||
                        manifest?.status == PortfolioOptimizationDataExchangeManifestStatus.SPLIT ->
                        PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING
                    relatedDestinationDecision?.status ==
                        PortfolioOptimizationRemoteDestinationDecisionStatus.LOCAL_ONLY_FALLBACK ->
                        PortfolioOptimizationCrossBoundaryProgramStatus.DEGRADED
                    else -> PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                }
                val portfolioId =
                    "cross_boundary_portfolio_${decision.purpose.name.lowercase()}_${decision.bundleType.name.lowercase()}"
                val programId = buildString {
                    append("cross_boundary_program_")
                    append(decision.purpose.name.lowercase())
                    append('_')
                    append(decision.bundleType.name.lowercase())
                    append('_')
                    append(trustTier.name.lowercase())
                    append('_')
                    append(jurisdiction.name.lowercase())
                }
                val priorityScore =
                    when (programStatus) {
                        PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE -> 80
                        PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING -> 68
                        PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED -> 54
                        PortfolioOptimizationCrossBoundaryProgramStatus.DEGRADED -> 42
                        PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED -> 20
                        PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED -> 8
                    } +
                        (portfolioOptimizationDestinationTrustTierRank(trustTier) * 12) -
                        (blockerTypes.size * 8) -
                        if (approval?.status == PortfolioOptimizationCrossBoundaryApprovalStatus.PENDING_REVIEW) 10 else 0
                val priority = portfolioOptimizationPriorityForScore(priorityScore)
                val suggestedAction = when {
                    blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.JURISDICTION) ||
                        blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.LOCAL_ONLY_SPLIT) ->
                        PortfolioOptimizationPortfolioRecommendationAction.SPLIT_BY_JURISDICTION
                    blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.TRUST_TIER) ->
                        PortfolioOptimizationPortfolioRecommendationAction.HOLD_TRUST_TIER
                    programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING ->
                        PortfolioOptimizationPortfolioRecommendationAction.REROUTE_DESTINATION_GROUP
                    programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE ->
                        PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM
                    else -> PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM
                }
                val context = ProgramContext(
                    portfolioId = portfolioId,
                    programId = programId,
                    purpose = decision.purpose,
                    bundleType = decision.bundleType,
                    trustTier = trustTier,
                    jurisdiction = jurisdiction,
                    bundleDecisionId = decision.decisionId,
                    bundleId = decision.bundleId,
                    destinationIds = candidateDestinationIds,
                    blockerTypes = blockerTypes,
                    programStatus = programStatus,
                    suggestedAction = suggestedAction,
                    priorityScore = priorityScore,
                    priority = priority,
                    summary = buildString {
                        append(decision.bundleType.name.lowercase().replace('_', ' '))
                        append(" program at ")
                        append(trustTier.name.lowercase().replace('_', ' '))
                        append(" trust for ")
                        append(jurisdiction.name.lowercase().replace('_', ' '))
                        append(" is ")
                        append(programStatus.name.lowercase().replace('_', ' '))
                        decision.summary.takeIf { it.isNotBlank() }?.let {
                            append(" · ")
                            append(it)
                        }
                    }
                )
                decisionContexts += context
                blockerTypes.forEach { blockerType ->
                    val scopeKey = when (blockerType) {
                        PortfolioOptimizationPortfolioBlockerType.TRUST_TIER -> trustTier.name
                        PortfolioOptimizationPortfolioBlockerType.JURISDICTION -> jurisdiction.name
                        PortfolioOptimizationPortfolioBlockerType.APPROVAL ->
                            approval?.status?.name ?: "approval_pending"
                        PortfolioOptimizationPortfolioBlockerType.DESTINATION_POLICY ->
                            relatedDestinationDecision?.blockReason?.name ?: "destination_policy"
                        PortfolioOptimizationPortfolioBlockerType.RESIDENCY ->
                            relatedDestinationDecision?.residencyRegion?.name
                                ?: decision.boundarySummary.residencyRegion?.name
                                ?: "residency"
                        PortfolioOptimizationPortfolioBlockerType.COMPLIANCE ->
                            decision.boundarySummary.complianceDecision?.name ?: "compliance"
                        PortfolioOptimizationPortfolioBlockerType.LOCAL_ONLY_SPLIT ->
                            decision.bundleType.name
                    }
                    val blockerKey = BlockerKey(
                        portfolioId = portfolioId,
                        type = blockerType,
                        scopeKey = scopeKey
                    )
                    val aggregate = blockerAggregates.getOrPut(blockerKey) {
                        BlockerAggregate(key = blockerKey)
                    }
                    aggregate.programIds += programId
                    aggregate.bundleDecisionIds += decision.decisionId
                    aggregate.reasonCodes += decision.reasonCodes
                    aggregate.reasonCodes += approval?.reasonCodes.orEmpty()
                    aggregate.reasonCodes += audits.flatMap { it.reasonCodes }
                    aggregate.blocking = aggregate.blocking &&
                        programStatus != PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                }
            }
            val destinationTrustTierAssignments = (
                latestDestinationProfilesById.keys + referencedDestinationIds
                )
                .filter { it.isNotBlank() }
                .distinct()
                .map { destinationId ->
                    val profile = latestDestinationProfilesById[destinationId]
                    val decisionsForDestination = destinationDecisions.filter { decision ->
                        decision.selectedDestinationId == destinationId ||
                            decision.reroutedFromDestinationId == destinationId ||
                            decision.eligibility.any { eligibility -> eligibility.destinationId == destinationId }
                    }
                    val trustTier = derivePortfolioOptimizationDestinationTrustTier(profile, decisionsForDestination)
                    PortfolioOptimizationDestinationTrustTierAssignment(
                        assignmentId = "destination_trust_${destinationId.takeLast(8)}",
                        destinationId = destinationId,
                        destinationType = profile?.type ?: decisionsForDestination.maxByOrNull { it.createdAtMs }?.selectedDestinationType,
                        trustTier = trustTier,
                        sourceIds = decisionsForDestination.map { it.sourceId }.filter { it.isNotBlank() }.distinct(),
                        reasonCodes = buildList {
                            when (trustTier) {
                                PortfolioOptimizationDestinationTrustTier.RESTRICTED -> {
                                    add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_RESTRICTED)
                                }
                                PortfolioOptimizationDestinationTrustTier.LIMITED,
                                PortfolioOptimizationDestinationTrustTier.UNVERIFIED -> {
                                    add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_DEFERRED)
                                }
                                PortfolioOptimizationDestinationTrustTier.TRUSTED,
                                PortfolioOptimizationDestinationTrustTier.HIGH_TRUST -> {
                                    add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_ASSIGNED)
                                }
                            }
                        },
                        summary = buildString {
                            append(profile?.displayName?.takeIf { it.isNotBlank() } ?: destinationId)
                            append(" is ")
                            append(trustTier.name.lowercase().replace('_', ' '))
                            append(" for cross-boundary rollout.")
                        },
                        updatedAtMs = profile?.updatedAtMs ?: decisionsForDestination.maxOfOrNull { it.createdAtMs } ?: now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationDestinationTrustTierAssignment> { it.updatedAtMs }
                        .thenBy { it.assignmentId }
                )
            val blockerSummaries = blockerAggregates.values
                .map { aggregate ->
                    val programIds = aggregate.programIds.toList().sorted()
                    PortfolioOptimizationPortfolioBlockerSummary(
                        blockerId = "portfolio_blocker_${aggregate.key.portfolioId}_${aggregate.key.type.name.lowercase()}_${aggregate.key.scopeKey.lowercase()}",
                        portfolioId = aggregate.key.portfolioId,
                        type = aggregate.key.type,
                        scopeKey = aggregate.key.scopeKey,
                        programIds = programIds,
                        bundleDecisionIds = aggregate.bundleDecisionIds.toList().sorted(),
                        blocking = aggregate.blocking,
                        reasonCodes = (
                            aggregate.reasonCodes +
                                if (programIds.size > 1) {
                                    listOf(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_SHARED_BLOCKER_DETECTED)
                                } else {
                                    emptyList()
                                }
                            ).distinct(),
                        summary = buildString {
                            append(
                                aggregate.key.type.name.lowercase().replace('_', ' ')
                            )
                            append(" blocker affects ")
                            append(programIds.size)
                            append(" cross-boundary program")
                            if (programIds.size != 1) append('s')
                            append(" at scope ")
                            append(aggregate.key.scopeKey.lowercase().replace('_', ' '))
                            append('.')
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioBlockerSummary> { it.updatedAtMs }
                        .thenBy { it.blockerId }
                )
            val blockerIdsByProgram = mutableMapOf<String, MutableList<String>>()
            blockerSummaries.forEach { blocker ->
                if (blocker.programIds.size > 1) {
                    blocker.programIds.forEach { programId ->
                        blockerIdsByProgram.getOrPut(programId) { mutableListOf() }.add(blocker.blockerId)
                    }
                }
            }
            val dependencySummaries = mutableListOf<PortfolioOptimizationPortfolioDependencySummary>()
            val dependencyIdsByProgram = mutableMapOf<String, MutableList<String>>()
            decisionContexts.groupBy { it.portfolioId }.forEach { (portfolioId, portfolioPrograms) ->
                portfolioPrograms
                    .groupBy { "${it.jurisdiction.name}:${it.bundleType.name}" }
                    .values
                    .forEach { jurisdictionPrograms ->
                        val sortedPrograms = jurisdictionPrograms.sortedWith(
                            compareByDescending<ProgramContext> {
                                portfolioOptimizationDestinationTrustTierRank(it.trustTier)
                            }.thenByDescending { it.priorityScore }
                                .thenBy { it.programId }
                        )
                        sortedPrograms.forEachIndexed { index, program ->
                            val dependsOnPrograms = sortedPrograms
                                .take(index)
                                .map { it.programId }
                                .distinct()
                            if (dependsOnPrograms.isNotEmpty()) {
                                val dependencyId = "portfolio_dependency_${program.programId}"
                                dependencySummaries += PortfolioOptimizationPortfolioDependencySummary(
                                    dependencyId = dependencyId,
                                    portfolioId = portfolioId,
                                    programId = program.programId,
                                    dependsOnProgramIds = dependsOnPrograms,
                                    reasonCodes = listOf(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_DEFERRED),
                                    summary = "Program ${program.programId.takeLast(8)} depends on higher-trust rollout sequencing.",
                                    updatedAtMs = now
                                )
                                dependencyIdsByProgram.getOrPut(program.programId) { mutableListOf() }
                                    .add(dependencyId)
                            }
                        }
                    }
            }
            val trustTierProgramSummaries = mutableListOf<PortfolioOptimizationTrustTierProgramSummary>()
            val jurisdictionRolloutPlans = mutableListOf<PortfolioOptimizationJurisdictionRolloutPlan>()
            decisionContexts.groupBy { it.portfolioId }.forEach { (portfolioId, portfolioPrograms) ->
                portfolioPrograms.groupBy { it.trustTier }.forEach { (trustTier, programs) ->
                    val rolloutState = when {
                        trustTier == PortfolioOptimizationDestinationTrustTier.RESTRICTED ->
                            PortfolioOptimizationTrustTierRolloutState.RESTRICTED
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED } ->
                            PortfolioOptimizationTrustTierRolloutState.HELD
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED } ->
                            PortfolioOptimizationTrustTierRolloutState.HELD
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING } ->
                            PortfolioOptimizationTrustTierRolloutState.ADVANCING
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED } ->
                            PortfolioOptimizationTrustTierRolloutState.DEFERRED
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE } ->
                            PortfolioOptimizationTrustTierRolloutState.READY
                        else -> PortfolioOptimizationTrustTierRolloutState.DEFERRED
                    }
                    trustTierProgramSummaries += PortfolioOptimizationTrustTierProgramSummary(
                        summaryId = "trust_tier_program_${portfolioId}_${trustTier.name.lowercase()}",
                        portfolioId = portfolioId,
                        trustTier = trustTier,
                        rolloutState = rolloutState,
                        programIds = programs.map { it.programId }.distinct().sorted(),
                        readyProgramCount = programs.count {
                            it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                        },
                        blockedProgramCount = programs.count {
                            it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED ||
                                it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED
                        },
                        summary = "${trustTier.name.lowercase().replace('_', ' ')} trust tier has ${programs.size} program(s) and is ${rolloutState.name.lowercase().replace('_', ' ')}.",
                        updatedAtMs = now
                    )
                }
                portfolioPrograms.groupBy { it.jurisdiction }.forEach { (jurisdiction, programs) ->
                    val rolloutState = when {
                        programs.any { it.blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.JURISDICTION) } ->
                            PortfolioOptimizationJurisdictionRolloutState.BLOCKED
                        programs.any { it.blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.LOCAL_ONLY_SPLIT) } ->
                            PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED
                        programs.any { it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED } ->
                            PortfolioOptimizationJurisdictionRolloutState.HELD
                        programs.any {
                            it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED ||
                                it.blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.TRUST_TIER)
                        } -> PortfolioOptimizationJurisdictionRolloutState.DEFERRED
                        else -> PortfolioOptimizationJurisdictionRolloutState.READY
                    }
                    jurisdictionRolloutPlans += PortfolioOptimizationJurisdictionRolloutPlan(
                        planId = "jurisdiction_rollout_${portfolioId}_${jurisdiction.name.lowercase()}",
                        portfolioId = portfolioId,
                        jurisdiction = jurisdiction,
                        rolloutState = rolloutState,
                        programIds = programs.map { it.programId }.distinct().sorted(),
                        sharedBlockerIds = programs.flatMap { blockerIdsByProgram[it.programId].orEmpty() }
                            .distinct()
                            .sorted(),
                        summary = "${jurisdiction.name.lowercase().replace('_', ' ')} rollout is ${rolloutState.name.lowercase().replace('_', ' ')} across ${programs.size} program(s).",
                        updatedAtMs = now
                    )
                }
            }
            val conflictSummaries = mutableListOf<PortfolioOptimizationPortfolioConflictSummary>()
            val conflictIdsByProgram = mutableMapOf<String, MutableList<String>>()
            blockerSummaries
                .filter { it.programIds.size > 1 }
                .forEach { blocker ->
                    val conflictId = "portfolio_conflict_shared_${blocker.blockerId}"
                    val conflict = PortfolioOptimizationPortfolioConflictSummary(
                        conflictId = conflictId,
                        portfolioId = blocker.portfolioId,
                        type = PortfolioOptimizationPortfolioConflictType.SHARED_BLOCKER,
                        programIds = blocker.programIds,
                        blockerIds = listOf(blocker.blockerId),
                        blocking = blocker.blocking,
                        summary = "Shared blocker ${blocker.type.name.lowercase().replace('_', ' ')} spans ${blocker.programIds.size} programs.",
                        updatedAtMs = now
                    )
                    conflictSummaries += conflict
                    blocker.programIds.forEach { programId ->
                        conflictIdsByProgram.getOrPut(programId) { mutableListOf() }.add(conflictId)
                    }
                }
            decisionContexts.groupBy { it.portfolioId }.forEach { (portfolioId, portfolioPrograms) ->
                val approvalPendingPrograms = portfolioPrograms.filter {
                    it.blockerTypes.contains(PortfolioOptimizationPortfolioBlockerType.APPROVAL)
                }
                if (approvalPendingPrograms.size > 1) {
                    val conflictId = "portfolio_conflict_approval_${portfolioId}"
                    conflictSummaries += PortfolioOptimizationPortfolioConflictSummary(
                        conflictId = conflictId,
                        portfolioId = portfolioId,
                        type = PortfolioOptimizationPortfolioConflictType.APPROVAL_CONTENTION,
                        programIds = approvalPendingPrograms.map { it.programId }.distinct().sorted(),
                        blockerIds = blockerSummaries
                            .filter { it.portfolioId == portfolioId && it.type == PortfolioOptimizationPortfolioBlockerType.APPROVAL }
                            .map { it.blockerId },
                        blocking = true,
                        summary = "Approval review is contending across ${approvalPendingPrograms.size} programs.",
                        updatedAtMs = now
                    )
                    approvalPendingPrograms.forEach { program ->
                        conflictIdsByProgram.getOrPut(program.programId) { mutableListOf() }.add(conflictId)
                    }
                }
                val jurisdictionPlans = jurisdictionRolloutPlans.filter { it.portfolioId == portfolioId }
                if (
                    jurisdictionPlans.size > 1 &&
                    (
                        jurisdictionPlans.any {
                            it.rolloutState == PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED
                        } ||
                            jurisdictionPlans.any {
                                it.rolloutState == PortfolioOptimizationJurisdictionRolloutState.BLOCKED
                            }
                        )
                ) {
                    val conflictId = "portfolio_conflict_jurisdiction_${portfolioId}"
                    val affectedPrograms = jurisdictionPlans.flatMap { it.programIds }.distinct().sorted()
                    conflictSummaries += PortfolioOptimizationPortfolioConflictSummary(
                        conflictId = conflictId,
                        portfolioId = portfolioId,
                        type = PortfolioOptimizationPortfolioConflictType.JURISDICTION_SEQUENCE,
                        programIds = affectedPrograms,
                        blockerIds = jurisdictionPlans.flatMap { it.sharedBlockerIds }.distinct().sorted(),
                        blocking = true,
                        summary = "Jurisdiction rollout requires resequencing across ${jurisdictionPlans.size} jurisdictions.",
                        updatedAtMs = now
                    )
                    affectedPrograms.forEach { programId ->
                        conflictIdsByProgram.getOrPut(programId) { mutableListOf() }.add(conflictId)
                    }
                }
                val trustTierSummaries = trustTierProgramSummaries.filter { it.portfolioId == portfolioId }
                if (
                    trustTierSummaries.any {
                        it.rolloutState == PortfolioOptimizationTrustTierRolloutState.HELD ||
                            it.rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED
                    } && trustTierSummaries.size > 1
                ) {
                    val conflictId = "portfolio_conflict_trust_tier_${portfolioId}"
                    val affectedPrograms = trustTierSummaries.flatMap { it.programIds }.distinct().sorted()
                    conflictSummaries += PortfolioOptimizationPortfolioConflictSummary(
                        conflictId = conflictId,
                        portfolioId = portfolioId,
                        type = PortfolioOptimizationPortfolioConflictType.TRUST_TIER_SEQUENCE,
                        programIds = affectedPrograms,
                        blockerIds = blockerSummaries
                            .filter {
                                it.portfolioId == portfolioId &&
                                    it.type == PortfolioOptimizationPortfolioBlockerType.TRUST_TIER
                            }
                            .map { it.blockerId },
                        blocking = true,
                        summary = "Trust-tier rollout sequence is constrained by higher-trust blockers.",
                        updatedAtMs = now
                    )
                    affectedPrograms.forEach { programId ->
                        conflictIdsByProgram.getOrPut(programId) { mutableListOf() }.add(conflictId)
                    }
                }
            }
            dependencySummaries.forEach { dependency ->
                val dependsOnBlocked = dependency.dependsOnProgramIds.any { dependsOnId ->
                    decisionContexts.firstOrNull { it.programId == dependsOnId }?.programStatus !=
                        PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                }
                if (dependsOnBlocked) {
                    val conflictId = "portfolio_conflict_dependency_${dependency.programId}"
                    conflictSummaries += PortfolioOptimizationPortfolioConflictSummary(
                        conflictId = conflictId,
                        portfolioId = dependency.portfolioId,
                        type = PortfolioOptimizationPortfolioConflictType.DESTINATION_DEPENDENCY,
                        programIds = listOf(dependency.programId) + dependency.dependsOnProgramIds,
                        blockerIds = blockerIdsByProgram[dependency.programId].orEmpty().distinct().sorted(),
                        blocking = true,
                        summary = "Program ${dependency.programId.takeLast(8)} depends on a blocked higher-trust program.",
                        updatedAtMs = now
                    )
                    conflictIdsByProgram.getOrPut(dependency.programId) { mutableListOf() }.add(conflictId)
                }
            }
            val programRecords = decisionContexts
                .groupBy { it.programId }
                .map { (_, programContexts) ->
                    val latestContext = programContexts.maxWithOrNull(
                        compareBy<ProgramContext> { it.priorityScore }
                            .thenBy { it.bundleDecisionId }
                    ) ?: programContexts.first()
                    PortfolioOptimizationCrossBoundaryProgramRecord(
                        programId = latestContext.programId,
                        portfolioId = latestContext.portfolioId,
                        purpose = latestContext.purpose,
                        bundleType = latestContext.bundleType,
                        destinationTrustTier = latestContext.trustTier,
                        jurisdiction = latestContext.jurisdiction,
                        programStatus = latestContext.programStatus,
                        priority = latestContext.priority,
                        bundleDecisionIds = programContexts.map { it.bundleDecisionId }.distinct().sorted(),
                        bundleIds = programContexts.map { it.bundleId }.distinct().sorted(),
                        destinationIds = programContexts.flatMap { it.destinationIds }.distinct().sorted(),
                        sharedBlockerIds = blockerIdsByProgram[latestContext.programId].orEmpty().distinct().sorted(),
                        dependencyIds = dependencyIdsByProgram[latestContext.programId].orEmpty().distinct().sorted(),
                        conflictIds = conflictIdsByProgram[latestContext.programId].orEmpty().distinct().sorted(),
                        nextAction = latestContext.suggestedAction,
                        summary = latestContext.summary,
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationCrossBoundaryProgramRecord> { it.updatedAtMs }
                        .thenBy { it.programId }
                )
            val programById = programRecords.associateBy { it.programId }
            val priorityDecisions = programRecords
                .groupBy { it.portfolioId }
                .map { (portfolioId, portfolioPrograms) ->
                    val rankedPrograms = portfolioPrograms.sortedWith(
                        compareByDescending<PortfolioOptimizationCrossBoundaryProgramRecord> { program ->
                            when (program.priority) {
                                PortfolioOptimizationPortfolioPriority.CRITICAL -> 4
                                PortfolioOptimizationPortfolioPriority.HIGH -> 3
                                PortfolioOptimizationPortfolioPriority.MEDIUM -> 2
                                PortfolioOptimizationPortfolioPriority.LOW -> 1
                            }
                        }.thenByDescending { portfolioOptimizationDestinationTrustTierRank(it.destinationTrustTier) }
                            .thenBy { portfolioOptimizationJurisdictionRank(it.jurisdiction) }
                            .thenBy { it.programId }
                    )
                    val winningProgram = rankedPrograms.firstOrNull()
                    PortfolioOptimizationPortfolioPriorityDecision(
                        decisionId = "portfolio_priority_${portfolioId}_$now",
                        portfolioId = portfolioId,
                        winningProgramId = winningProgram?.programId,
                        priority = winningProgram?.priority ?: PortfolioOptimizationPortfolioPriority.LOW,
                        rankedProgramIds = rankedPrograms.map { it.programId },
                        reasonCodes = listOf(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_PRIORITY_SELECTED),
                        summary = if (winningProgram == null) {
                            "No cross-boundary program is available for portfolio prioritization."
                        } else {
                            "Portfolio priority favors program ${winningProgram.programId.takeLast(8)} at ${winningProgram.destinationTrustTier.name.lowercase().replace('_', ' ')} trust."
                        },
                        createdAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioPriorityDecision> { it.createdAtMs }
                        .thenBy { it.decisionId }
                )
            val recommendations = priorityDecisions.map { priorityDecision ->
                val portfolioId = priorityDecision.portfolioId
                val portfolioPrograms = programRecords.filter { it.portfolioId == portfolioId }
                val winningProgram = priorityDecision.winningProgramId?.let(programById::get)
                val sharedBlocker = blockerSummaries.firstOrNull {
                    it.portfolioId == portfolioId && it.programIds.size > 1 && it.blocking
                }
                val jurisdictionPlan = jurisdictionRolloutPlans.firstOrNull {
                    it.portfolioId == portfolioId &&
                        (
                            it.rolloutState == PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED ||
                                it.rolloutState == PortfolioOptimizationJurisdictionRolloutState.BLOCKED
                            )
                }
                val trustTierSummary = trustTierProgramSummaries.firstOrNull {
                    it.portfolioId == portfolioId &&
                        (
                            it.rolloutState == PortfolioOptimizationTrustTierRolloutState.HELD ||
                                it.rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED ||
                                it.rolloutState == PortfolioOptimizationTrustTierRolloutState.DEFERRED
                            )
                }
                val action = when {
                    sharedBlocker != null ->
                        PortfolioOptimizationPortfolioRecommendationAction.REVIEW_SHARED_BLOCKER
                    jurisdictionPlan != null ->
                        PortfolioOptimizationPortfolioRecommendationAction.SPLIT_BY_JURISDICTION
                    trustTierSummary != null ->
                        PortfolioOptimizationPortfolioRecommendationAction.HOLD_TRUST_TIER
                    winningProgram?.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING ->
                        PortfolioOptimizationPortfolioRecommendationAction.REROUTE_DESTINATION_GROUP
                    winningProgram?.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE ->
                        PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM
                    else -> PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM
                }
                val targetProgramId = when (action) {
                    PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM,
                    PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM,
                    PortfolioOptimizationPortfolioRecommendationAction.REROUTE_DESTINATION_GROUP ->
                        winningProgram?.programId
                    else -> portfolioPrograms.firstOrNull()?.programId
                }
                PortfolioOptimizationPortfolioCoordinationRecommendation(
                    recommendationId = "portfolio_recommendation_${portfolioId}_$now",
                    portfolioId = portfolioId,
                    action = action,
                    targetProgramId = targetProgramId,
                    targetTrustTier = trustTierSummary?.trustTier ?: winningProgram?.destinationTrustTier,
                    targetJurisdiction = jurisdictionPlan?.jurisdiction ?: winningProgram?.jurisdiction,
                    blocking = action != PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM,
                    reasonCodes = buildList {
                        add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_RECOMMENDATION_UPDATED)
                        if (sharedBlocker != null) add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_SHARED_BLOCKER_DETECTED)
                        if (jurisdictionPlan != null) add(RoleReasonCodes.ROLE_JURISDICTION_ROLLOUT_SPLIT_RECOMMENDED)
                        if (trustTierSummary != null &&
                            trustTierSummary.rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED
                        ) {
                            add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_RESTRICTED)
                        }
                    }.distinct(),
                    summary = when (action) {
                        PortfolioOptimizationPortfolioRecommendationAction.REVIEW_SHARED_BLOCKER ->
                            "Review shared blocker ${sharedBlocker?.type?.name?.lowercase()?.replace('_', ' ') ?: "state"} before broader rollout."
                        PortfolioOptimizationPortfolioRecommendationAction.SPLIT_BY_JURISDICTION ->
                            "Split rollout by ${jurisdictionPlan?.jurisdiction?.name?.lowercase()?.replace('_', ' ') ?: "jurisdiction"} to preserve policy-safe sequencing."
                        PortfolioOptimizationPortfolioRecommendationAction.HOLD_TRUST_TIER ->
                            "Hold ${trustTierSummary?.trustTier?.name?.lowercase()?.replace('_', ' ') ?: "lower"} trust-tier rollout until higher-trust blockers clear."
                        PortfolioOptimizationPortfolioRecommendationAction.REROUTE_DESTINATION_GROUP ->
                            "Reroute winning program ${winningProgram?.programId?.takeLast(8) ?: "n/a"} to a safer destination group."
                        PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM ->
                            "Defer program ${winningProgram?.programId?.takeLast(8) ?: "n/a"} until portfolio blockers clear."
                        PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM ->
                            "Advance program ${winningProgram?.programId?.takeLast(8) ?: "n/a"} next."
                    },
                    createdAtMs = now
                )
            }.sortedWith(
                compareByDescending<PortfolioOptimizationPortfolioCoordinationRecommendation> { it.createdAtMs }
                    .thenBy { it.recommendationId }
            )
            val portfolios = programRecords
                .groupBy { it.portfolioId }
                .map { (portfolioId, portfolioPrograms) ->
                    val sharedBlockerCount = blockerSummaries.count {
                        it.portfolioId == portfolioId && it.programIds.size > 1
                    }
                    val conflictCount = conflictSummaries.count { it.portfolioId == portfolioId }
                    val recommendation = recommendations.firstOrNull { it.portfolioId == portfolioId }
                    val priorityDecision = priorityDecisions.firstOrNull { it.portfolioId == portfolioId }
                    val status = when {
                        portfolioPrograms.isNotEmpty() &&
                            portfolioPrograms.all {
                                it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED
                            } -> PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.BLOCKED
                        recommendation?.action == PortfolioOptimizationPortfolioRecommendationAction.REVIEW_SHARED_BLOCKER ||
                            portfolioPrograms.any {
                                it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED
                            } -> PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.REVIEW_REQUIRED
                        portfolioPrograms.isNotEmpty() &&
                            portfolioPrograms.all {
                                it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED
                            } -> PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.PAUSED
                        sharedBlockerCount > 0 ||
                            conflictCount > 0 ||
                            portfolioPrograms.any {
                                it.programStatus != PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                            } -> PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.DEGRADED
                        else -> PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.ACTIVE
                    }
                    PortfolioOptimizationCrossBoundaryGovernancePortfolio(
                        portfolioId = portfolioId,
                        scopeKey = portfolioId.removePrefix("cross_boundary_portfolio_"),
                        status = status,
                        programIds = portfolioPrograms.map { it.programId }.distinct().sorted(),
                        sharedBlockerCount = sharedBlockerCount,
                        conflictCount = conflictCount,
                        priorityDecisionId = priorityDecision?.decisionId,
                        recommendationId = recommendation?.recommendationId,
                        summary = buildString {
                            append(status.name.lowercase().replace('_', ' '))
                            append(" governance portfolio with ")
                            append(portfolioPrograms.size)
                            append(" program(s)")
                            if (sharedBlockerCount > 0 || conflictCount > 0) {
                                append(" · blockers ")
                                append(sharedBlockerCount)
                                append(", conflicts ")
                                append(conflictCount)
                            }
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationCrossBoundaryGovernancePortfolio> { it.updatedAtMs }
                        .thenBy { it.portfolioId }
                )
            val waveCoordinationRecords = programRecords
                .groupBy { "${it.portfolioId}:${it.destinationTrustTier.name}:${it.jurisdiction.name}" }
                .values
                .sortedWith(
                    compareBy<List<PortfolioOptimizationCrossBoundaryProgramRecord>> {
                        it.firstOrNull()?.portfolioId.orEmpty()
                    }.thenByDescending {
                        it.firstOrNull()?.destinationTrustTier?.let(::portfolioOptimizationDestinationTrustTierRank) ?: 0
                    }.thenBy {
                        it.firstOrNull()?.jurisdiction?.let(::portfolioOptimizationJurisdictionRank) ?: 0
                    }
                )
                .mapIndexed { index, programs ->
                    val first = programs.first()
                    PortfolioOptimizationPortfolioWaveCoordinationRecord(
                        coordinationId = "portfolio_wave_${first.portfolioId}_${index + 1}",
                        portfolioId = first.portfolioId,
                        waveKey = "${first.destinationTrustTier.name.lowercase()}_${first.jurisdiction.name.lowercase()}",
                        sequenceIndex = index + 1,
                        trustTier = first.destinationTrustTier,
                        jurisdiction = first.jurisdiction,
                        programIds = programs.map { it.programId }.distinct().sorted(),
                        blocking = programs.any {
                            it.programStatus != PortfolioOptimizationCrossBoundaryProgramStatus.ACTIVE
                        },
                        summary = "Wave ${index + 1} coordinates ${first.destinationTrustTier.name.lowercase().replace('_', ' ')} / ${first.jurisdiction.name.lowercase().replace('_', ' ')} across ${programs.size} program(s).",
                        createdAtMs = now
                    )
                }
            val destinationTrustTierByDestinationId = destinationTrustTierAssignments
                .associate { it.destinationId to it.trustTier }
            val trustTierDriftSummaries = trustTierProgramSummaries
                .map { trustTierSummary ->
                    val programs = trustTierSummary.programIds.mapNotNull(programById::get)
                    val rerouteCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING
                    }
                    val blockedCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED
                    }
                    val heldCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED ||
                            it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED
                    }
                    val degradedCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.DEGRADED
                    }
                    val driftReasons = linkedSetOf<PortfolioOptimizationTrustTierDriftReason>().apply {
                        if (trustTierSummary.rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED) {
                            add(PortfolioOptimizationTrustTierDriftReason.POLICY_MISMATCH)
                        }
                        if (rerouteCount > 0) add(PortfolioOptimizationTrustTierDriftReason.REPEATED_JURISDICTION_REROUTE)
                        if (blockedCount > 0) add(PortfolioOptimizationTrustTierDriftReason.BLOCKER_CONCENTRATION)
                        if (heldCount > 0) add(PortfolioOptimizationTrustTierDriftReason.PROLONGED_HOLD)
                        if (programs.any { it.sharedBlockerIds.isNotEmpty() }) {
                            add(PortfolioOptimizationTrustTierDriftReason.BLOCKER_CONCENTRATION)
                        }
                    }
                    val driftState = portfolioOptimizationTrustTierDriftState(
                        rolloutState = trustTierSummary.rolloutState,
                        rerouteCount = rerouteCount,
                        blockedCount = blockedCount,
                        heldCount = heldCount,
                        degradedCount = degradedCount
                    )
                    PortfolioOptimizationTrustTierDriftSummary(
                        driftId = "portfolio_trust_drift_${trustTierSummary.portfolioId}_${trustTierSummary.trustTier.name.lowercase()}_$now",
                        portfolioId = trustTierSummary.portfolioId,
                        trustTier = trustTierSummary.trustTier,
                        driftState = driftState,
                        driftReasons = driftReasons.toList(),
                        programIds = trustTierSummary.programIds,
                        rerouteCount = rerouteCount,
                        blockedCount = blockedCount,
                        heldCount = heldCount,
                        reasonCodes = buildList {
                            if (driftState != PortfolioOptimizationTrustTierDriftState.HEALTHY) {
                                add(RoleReasonCodes.ROLE_TRUST_TIER_DRIFT_DETECTED)
                            }
                            if (trustTierSummary.rolloutState == PortfolioOptimizationTrustTierRolloutState.RESTRICTED) {
                                add(RoleReasonCodes.ROLE_DESTINATION_TRUST_TIER_RESTRICTED)
                            }
                        }.distinct(),
                        summary = buildString {
                            append(trustTierSummary.trustTier.name.lowercase().replace('_', ' '))
                            append(" trust tier is ")
                            append(driftState.name.lowercase().replace('_', ' '))
                            append(" with ")
                            append(blockedCount)
                            append(" blocked, ")
                            append(heldCount)
                            append(" held, and ")
                            append(rerouteCount)
                            append(" rerouted program(s).")
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationTrustTierDriftSummary> { it.updatedAtMs }
                        .thenBy { it.driftId }
                )
            val jurisdictionDriftSummaries = jurisdictionRolloutPlans
                .map { jurisdictionPlan ->
                    val programs = jurisdictionPlan.programIds.mapNotNull(programById::get)
                    val rerouteCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REROUTING
                    }
                    val blockedCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.BLOCKED
                    }
                    val deferredCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.PAUSED
                    }
                    val heldCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.REVIEW_REQUIRED
                    }
                    val degradedCount = programs.count {
                        it.programStatus == PortfolioOptimizationCrossBoundaryProgramStatus.DEGRADED
                    }
                    val driftReasons = linkedSetOf<PortfolioOptimizationJurisdictionDriftReason>().apply {
                        if (jurisdictionPlan.rolloutState == PortfolioOptimizationJurisdictionRolloutState.BLOCKED) {
                            add(PortfolioOptimizationJurisdictionDriftReason.REPEATED_BLOCK)
                        }
                        if (jurisdictionPlan.rolloutState == PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED) {
                            add(PortfolioOptimizationJurisdictionDriftReason.BLOCKER_CONCENTRATION)
                        }
                        if (rerouteCount > 0) add(PortfolioOptimizationJurisdictionDriftReason.REPEATED_REROUTE)
                        if (deferredCount > 0) add(PortfolioOptimizationJurisdictionDriftReason.REPEATED_DEFER)
                        if (heldCount > 0) add(PortfolioOptimizationJurisdictionDriftReason.REPEATED_HOLD)
                        if (jurisdictionPlan.sharedBlockerIds.isNotEmpty()) {
                            add(PortfolioOptimizationJurisdictionDriftReason.BLOCKER_CONCENTRATION)
                        }
                    }
                    val driftState = portfolioOptimizationJurisdictionDriftState(
                        rolloutState = jurisdictionPlan.rolloutState,
                        rerouteCount = rerouteCount,
                        blockedCount = blockedCount,
                        deferredCount = deferredCount,
                        heldCount = heldCount,
                        degradedCount = degradedCount,
                        sharedBlockerCount = jurisdictionPlan.sharedBlockerIds.size
                    )
                    PortfolioOptimizationJurisdictionDriftSummary(
                        driftId = "portfolio_jurisdiction_drift_${jurisdictionPlan.portfolioId}_${jurisdictionPlan.jurisdiction.name.lowercase()}_$now",
                        portfolioId = jurisdictionPlan.portfolioId,
                        jurisdiction = jurisdictionPlan.jurisdiction,
                        driftState = driftState,
                        driftReasons = driftReasons.toList(),
                        programIds = jurisdictionPlan.programIds,
                        rerouteCount = rerouteCount,
                        blockedCount = blockedCount,
                        deferredCount = deferredCount,
                        heldCount = heldCount,
                        sharedBlockerCount = jurisdictionPlan.sharedBlockerIds.size,
                        reasonCodes = buildList {
                            if (driftState != PortfolioOptimizationJurisdictionDriftState.HEALTHY) {
                                add(RoleReasonCodes.ROLE_JURISDICTION_DRIFT_DETECTED)
                            }
                            if (jurisdictionPlan.rolloutState == PortfolioOptimizationJurisdictionRolloutState.SPLIT_REQUIRED) {
                                add(RoleReasonCodes.ROLE_JURISDICTION_ROLLOUT_SPLIT_RECOMMENDED)
                            }
                            if (jurisdictionPlan.rolloutState == PortfolioOptimizationJurisdictionRolloutState.BLOCKED) {
                                add(RoleReasonCodes.ROLE_JURISDICTION_ROLLOUT_RESEQUENCED)
                            }
                        }.distinct(),
                        summary = buildString {
                            append(jurisdictionPlan.jurisdiction.name.lowercase().replace('_', ' '))
                            append(" jurisdiction is ")
                            append(driftState.name.lowercase().replace('_', ' '))
                            append(" with ")
                            append(blockedCount)
                            append(" blocked, ")
                            append(heldCount + deferredCount)
                            append(" held/deferred, and ")
                            append(rerouteCount)
                            append(" rerouted program(s).")
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationJurisdictionDriftSummary> { it.updatedAtMs }
                        .thenBy { it.driftId }
                )
            val destinationRiskConcentrationSummaries = programRecords
                .groupBy { it.portfolioId }
                .map { (portfolioId, portfolioPrograms) ->
                    val destinationReferences = portfolioPrograms.flatMap { it.destinationIds }
                    val destinationCounts = destinationReferences.groupingBy { it }.eachCount()
                    val dominantDestination = destinationCounts.maxWithOrNull(
                        compareBy<Map.Entry<String, Int>> { it.value }.thenBy { it.key }
                    )
                    val referenceCount = destinationReferences.size.coerceAtLeast(1)
                    val concentrationRatio = ((dominantDestination?.value ?: 0).toDouble() / referenceCount.toDouble())
                        .coerceIn(0.0, 1.0)
                    val highRiskDestinationCount = destinationCounts.keys.count { destinationId ->
                        destinationTrustTierByDestinationId[destinationId] in setOf(
                            PortfolioOptimizationDestinationTrustTier.RESTRICTED,
                            PortfolioOptimizationDestinationTrustTier.UNVERIFIED,
                            PortfolioOptimizationDestinationTrustTier.LIMITED
                        )
                    }
                    PortfolioOptimizationDestinationRiskConcentrationSummary(
                        concentrationId = "portfolio_destination_risk_${portfolioId}_$now",
                        portfolioId = portfolioId,
                        dominantDestinationId = dominantDestination?.key,
                        dominantDestinationCount = dominantDestination?.value ?: 0,
                        totalDestinationCount = referenceCount,
                        concentrationRatio = concentrationRatio,
                        highRiskDestinationCount = highRiskDestinationCount,
                        summary = buildString {
                            append("Destination concentration is ")
                            append((concentrationRatio * 100).toInt())
                            append("%")
                            dominantDestination?.key?.takeIf { it.isNotBlank() }?.let {
                                append(" on ")
                                append(it.takeLast(10))
                            }
                            append(" across ")
                            append(referenceCount)
                            append(" destination placement(s).")
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationDestinationRiskConcentrationSummary> {
                        it.updatedAtMs
                    }.thenBy { it.concentrationId }
                )
            val portfolioBlockerTrendSummaries = portfolios
                .map { portfolio ->
                    val blockerCounts = blockerSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .groupingBy { it.type }
                        .eachCount()
                    val dominantBlocker = blockerCounts.maxWithOrNull(
                        compareBy<Map.Entry<PortfolioOptimizationPortfolioBlockerType, Int>> { it.value }
                            .thenBy { it.key.name }
                    )
                    val previous = previousBlockerTrendsByPortfolio[portfolio.portfolioId]
                    val currentCount = dominantBlocker?.value ?: 0
                    val previousCount = previous?.currentCount ?: 0
                    val direction = when {
                        currentCount > previousCount -> PortfolioOptimizationTrendDirection.RISING
                        currentCount < previousCount -> PortfolioOptimizationTrendDirection.FALLING
                        else -> PortfolioOptimizationTrendDirection.STABLE
                    }
                    PortfolioOptimizationPortfolioBlockerTrendSummary(
                        trendId = "portfolio_blocker_trend_${portfolio.portfolioId}_$now",
                        portfolioId = portfolio.portfolioId,
                        dominantBlockerType = dominantBlocker?.key
                            ?: previous?.dominantBlockerType
                            ?: PortfolioOptimizationPortfolioBlockerType.COMPLIANCE,
                        currentCount = currentCount,
                        previousCount = previousCount,
                        direction = direction,
                        summary = buildString {
                            append("Dominant blocker trend is ")
                            append(direction.name.lowercase())
                            append(" at ")
                            append(currentCount)
                            append(" item(s)")
                            if (previousCount > 0) {
                                append(" from ")
                                append(previousCount)
                            }
                            append('.')
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioBlockerTrendSummary> { it.updatedAtMs }
                        .thenBy { it.trendId }
                )
            val riskBudgets = portfolios
                .map { portfolio ->
                    val portfolioPrograms = programRecords.filter { it.portfolioId == portfolio.portfolioId }
                    val trustDrift = trustTierDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .maxByOrNull { it.driftState.ordinal }
                    val jurisdictionDrift = jurisdictionDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .maxByOrNull { it.driftState.ordinal }
                    val concentration = destinationRiskConcentrationSummaries
                        .firstOrNull { it.portfolioId == portfolio.portfolioId }
                    val correctiveAction = latestCorrectiveActionByPortfolio[portfolio.portfolioId]
                    val allocatedUnits = (
                        portfolioPrograms.size.coerceAtLeast(1) * 20 +
                            portfolio.sharedBlockerCount * 4 +
                            portfolio.conflictCount * 3
                        ).coerceAtLeast(20)
                    val consumedUnits = (
                        portfolioPrograms.sumOf { portfolioOptimizationProgramRiskUnits(it.programStatus) } +
                            portfolioOptimizationTrustTierDriftWeight(
                                trustDrift?.driftState ?: PortfolioOptimizationTrustTierDriftState.HEALTHY
                            ) +
                            portfolioOptimizationJurisdictionDriftWeight(
                                jurisdictionDrift?.driftState ?: PortfolioOptimizationJurisdictionDriftState.HEALTHY
                            ) +
                            portfolio.sharedBlockerCount * 6 +
                            portfolio.conflictCount * 4 +
                            if ((concentration?.concentrationRatio ?: 0.0) >= 0.60) 8 else 0 +
                            (concentration?.highRiskDestinationCount ?: 0) * 3
                        ).coerceAtLeast(0)
                    val holdRequested =
                        correctiveAction?.actionType ==
                            PortfolioOptimizationCorrectiveActionType.REQUEST_RISK_HOLD
                    val budgetStatus = portfolioOptimizationRiskBudgetStatus(
                        allocatedUnits = allocatedUnits,
                        consumedUnits = consumedUnits,
                        holdRequested = holdRequested
                    )
                    val remainingUnits = (allocatedUnits - consumedUnits).coerceAtLeast(0)
                    val breachUnits = (consumedUnits - allocatedUnits).coerceAtLeast(0)
                    PortfolioOptimizationRiskBudget(
                        budgetId = "portfolio_risk_budget_${portfolio.portfolioId}_$now",
                        portfolioId = portfolio.portfolioId,
                        allocatedUnits = allocatedUnits,
                        consumedUnits = consumedUnits,
                        remainingUnits = remainingUnits,
                        breachUnits = breachUnits,
                        status = budgetStatus,
                        programIds = portfolioPrograms.map { it.programId }.sorted(),
                        reasonCodes = buildList {
                            add(RoleReasonCodes.ROLE_RISK_BUDGET_UPDATED)
                            if (budgetStatus == PortfolioOptimizationRiskBudgetStatus.EXCEEDED ||
                                budgetStatus == PortfolioOptimizationRiskBudgetStatus.HELD
                            ) {
                                add(RoleReasonCodes.ROLE_RISK_BUDGET_BREACHED)
                            }
                            if (holdRequested) {
                                add(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_ACTION_RECORDED)
                            }
                        }.distinct(),
                        summary = buildString {
                            append("Risk budget is ")
                            append(budgetStatus.name.lowercase().replace('_', ' '))
                            append(" at ")
                            append(consumedUnits)
                            append('/')
                            append(allocatedUnits)
                            append(" units")
                            if (holdRequested) append(" after a requested risk hold")
                            append('.')
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationRiskBudget> { it.updatedAtMs }
                        .thenBy { it.budgetId }
                )
            val analyticsSummaries = portfolios
                .map { portfolio ->
                    val trustDriftIds = trustTierDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                    val jurisdictionDriftIds = jurisdictionDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                    val dominantTrustDrift = trustDriftIds.maxByOrNull { it.driftState.ordinal }
                    val dominantJurisdictionDrift = jurisdictionDriftIds.maxByOrNull { it.driftState.ordinal }
                    val riskBudget = riskBudgets.firstOrNull { it.portfolioId == portfolio.portfolioId }
                    val blockerTrend = portfolioBlockerTrendSummaries.firstOrNull {
                        it.portfolioId == portfolio.portfolioId
                    }
                    val concentration = destinationRiskConcentrationSummaries.firstOrNull {
                        it.portfolioId == portfolio.portfolioId
                    }
                    val healthStatus = portfolioOptimizationPortfolioHealthStatus(
                        portfolioStatus = portfolio.status,
                        riskBudgetStatus = riskBudget?.status
                            ?: PortfolioOptimizationRiskBudgetStatus.NOT_STARTED,
                        trustTierDriftState = dominantTrustDrift?.driftState
                            ?: PortfolioOptimizationTrustTierDriftState.HEALTHY,
                        jurisdictionDriftState = dominantJurisdictionDrift?.driftState
                            ?: PortfolioOptimizationJurisdictionDriftState.HEALTHY
                    )
                    val trajectoryState = portfolioOptimizationTrajectoryState(
                        healthStatus = healthStatus,
                        blockerTrendDirection = blockerTrend?.direction
                            ?: PortfolioOptimizationTrendDirection.STABLE
                    )
                    PortfolioOptimizationCrossBoundaryPortfolioAnalyticsSummary(
                        analyticsId = "portfolio_analytics_${portfolio.portfolioId}_$now",
                        portfolioId = portfolio.portfolioId,
                        healthStatus = healthStatus,
                        trajectoryState = trajectoryState,
                        riskBudgetId = riskBudget?.budgetId,
                        trustTierDriftIds = trustDriftIds.map { it.driftId },
                        jurisdictionDriftIds = jurisdictionDriftIds.map { it.driftId },
                        destinationRiskConcentrationId = concentration?.concentrationId,
                        blockerTrendId = blockerTrend?.trendId,
                        sharedBlockerCount = portfolio.sharedBlockerCount,
                        conflictCount = portfolio.conflictCount,
                        riskBudgetBreached = riskBudget?.status in setOf(
                            PortfolioOptimizationRiskBudgetStatus.EXCEEDED,
                            PortfolioOptimizationRiskBudgetStatus.HELD
                        ),
                        reasonCodes = buildList {
                            add(RoleReasonCodes.ROLE_CROSS_BOUNDARY_PORTFOLIO_ANALYTICS_UPDATED)
                            if (riskBudget?.status in setOf(
                                    PortfolioOptimizationRiskBudgetStatus.EXCEEDED,
                                    PortfolioOptimizationRiskBudgetStatus.HELD
                                )
                            ) {
                                add(RoleReasonCodes.ROLE_RISK_BUDGET_BREACHED)
                            }
                        }.distinct(),
                        summary = buildString {
                            append("Portfolio is ")
                            append(healthStatus.name.lowercase())
                            append(" and ")
                            append(trajectoryState.name.lowercase())
                            append(" with ")
                            append(portfolio.sharedBlockerCount)
                            append(" shared blocker(s) and ")
                            append(portfolio.conflictCount)
                            append(" conflict(s).")
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationCrossBoundaryPortfolioAnalyticsSummary> {
                        it.updatedAtMs
                    }.thenBy { it.analyticsId }
                )
            val riskRecommendations = portfolios
                .map { portfolio ->
                    val analytics = analyticsSummaries.firstOrNull { it.portfolioId == portfolio.portfolioId }
                    val riskBudget = riskBudgets.firstOrNull { it.portfolioId == portfolio.portfolioId }
                    val trustDrift = trustTierDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .maxByOrNull { it.driftState.ordinal }
                    val jurisdictionDrift = jurisdictionDriftSummaries
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .maxByOrNull { it.driftState.ordinal }
                    val concentration = destinationRiskConcentrationSummaries
                        .firstOrNull { it.portfolioId == portfolio.portfolioId }
                    val correctiveAction = latestCorrectiveActionByPortfolio[portfolio.portfolioId]
                    val targetProgram = programRecords
                        .filter { it.portfolioId == portfolio.portfolioId }
                        .sortedWith(
                            compareByDescending<PortfolioOptimizationCrossBoundaryProgramRecord> {
                                when (it.priority) {
                                    PortfolioOptimizationPortfolioPriority.CRITICAL -> 4
                                    PortfolioOptimizationPortfolioPriority.HIGH -> 3
                                    PortfolioOptimizationPortfolioPriority.MEDIUM -> 2
                                    PortfolioOptimizationPortfolioPriority.LOW -> 1
                                }
                            }.thenBy { it.programId }
                        )
                        .firstOrNull()
                    val action = when {
                        correctiveAction?.actionType ==
                            PortfolioOptimizationCorrectiveActionType.REQUEST_RISK_HOLD ||
                            riskBudget?.status in setOf(
                                PortfolioOptimizationRiskBudgetStatus.HELD,
                                PortfolioOptimizationRiskBudgetStatus.EXCEEDED
                            ) -> PortfolioOptimizationPortfolioRiskRecommendationAction.HOLD_PORTFOLIO
                        jurisdictionDrift?.driftState in setOf(
                            PortfolioOptimizationJurisdictionDriftState.BLOCKED,
                            PortfolioOptimizationJurisdictionDriftState.DRIFTING
                        ) -> PortfolioOptimizationPortfolioRiskRecommendationAction.SPLIT_JURISDICTION_LANE
                        trustDrift?.driftState in setOf(
                            PortfolioOptimizationTrustTierDriftState.BLOCKED,
                            PortfolioOptimizationTrustTierDriftState.DRIFTING
                        ) -> PortfolioOptimizationPortfolioRiskRecommendationAction.TIGHTEN_TRUST_TIER
                        (concentration?.concentrationRatio ?: 0.0) >= 0.60 &&
                            (concentration?.dominantDestinationCount ?: 0) > 1 ->
                            PortfolioOptimizationPortfolioRiskRecommendationAction.REBALANCE_DESTINATION_SET
                        riskBudget?.status == PortfolioOptimizationRiskBudgetStatus.NEAR_LIMIT ||
                            analytics?.healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DRIFTING ->
                            PortfolioOptimizationPortfolioRiskRecommendationAction.REVIEW_POLICY_PACK
                        analytics?.healthStatus == PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.DEGRADED ->
                            PortfolioOptimizationPortfolioRiskRecommendationAction.DEFER_PORTFOLIO
                        else -> PortfolioOptimizationPortfolioRiskRecommendationAction.CONTINUE_ROLLOUT
                    }
                    PortfolioOptimizationPortfolioRiskRecommendation(
                        recommendationId = "portfolio_risk_recommendation_${portfolio.portfolioId}_$now",
                        portfolioId = portfolio.portfolioId,
                        analyticsId = analytics?.analyticsId,
                        riskBudgetId = riskBudget?.budgetId,
                        action = action,
                        targetProgramId = correctiveAction?.targetProgramId ?: targetProgram?.programId,
                        targetTrustTier = correctiveAction?.targetTrustTier
                            ?: trustDrift?.trustTier
                            ?: targetProgram?.destinationTrustTier,
                        targetJurisdiction = correctiveAction?.targetJurisdiction
                            ?: jurisdictionDrift?.jurisdiction
                            ?: targetProgram?.jurisdiction,
                        blocking = action != PortfolioOptimizationPortfolioRiskRecommendationAction.CONTINUE_ROLLOUT,
                        reasonCodes = buildList {
                            add(RoleReasonCodes.ROLE_PORTFOLIO_CORRECTIVE_RECOMMENDATION_ISSUED)
                            if (riskBudget?.status in setOf(
                                    PortfolioOptimizationRiskBudgetStatus.EXCEEDED,
                                    PortfolioOptimizationRiskBudgetStatus.HELD
                                )
                            ) {
                                add(RoleReasonCodes.ROLE_RISK_BUDGET_BREACHED)
                            }
                            if (trustDrift?.driftState != null &&
                                trustDrift.driftState != PortfolioOptimizationTrustTierDriftState.HEALTHY
                            ) {
                                add(RoleReasonCodes.ROLE_TRUST_TIER_DRIFT_DETECTED)
                            }
                            if (jurisdictionDrift?.driftState != null &&
                                jurisdictionDrift.driftState != PortfolioOptimizationJurisdictionDriftState.HEALTHY
                            ) {
                                add(RoleReasonCodes.ROLE_JURISDICTION_DRIFT_DETECTED)
                            }
                        }.distinct(),
                        summary = when (action) {
                            PortfolioOptimizationPortfolioRiskRecommendationAction.HOLD_PORTFOLIO ->
                                "Hold portfolio rollout until risk budget pressure and blockers are reduced."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.TIGHTEN_TRUST_TIER ->
                                "Tighten trust-tier exposure before continuing cross-boundary rollout."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.SPLIT_JURISDICTION_LANE ->
                                "Split rollout lanes by jurisdiction to absorb drift safely."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.REBALANCE_DESTINATION_SET ->
                                "Rebalance destination usage to reduce concentration on a single route."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.REVIEW_POLICY_PACK ->
                                "Review the governing policy pack before budget pressure becomes a breach."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.DEFER_PORTFOLIO ->
                                "Defer broader rollout until degraded portfolio conditions recover."
                            PortfolioOptimizationPortfolioRiskRecommendationAction.CONTINUE_ROLLOUT ->
                                "Continue rollout; risk budget and drift signals remain within bounds."
                        },
                        createdAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioRiskRecommendation> { it.createdAtMs }
                        .thenBy { it.recommendationId }
                )
            data class PortfolioSafetyControlContext(
                val portfolio: PortfolioOptimizationCrossBoundaryGovernancePortfolio,
                val analytics: PortfolioOptimizationCrossBoundaryPortfolioAnalyticsSummary?,
                val riskBudget: PortfolioOptimizationRiskBudget,
                val trustDrift: PortfolioOptimizationTrustTierDriftSummary?,
                val jurisdictionDrift: PortfolioOptimizationJurisdictionDriftSummary?,
                val concentration: PortfolioOptimizationDestinationRiskConcentrationSummary?,
                val blockerTrend: PortfolioOptimizationPortfolioBlockerTrendSummary?,
                val correctiveAction: PortfolioOptimizationCrossBoundaryCorrectiveActionRecord?,
                val riskRecommendation: PortfolioOptimizationPortfolioRiskRecommendation?,
                val safetyState: PortfolioOptimizationPortfolioSafetyState,
                val budgetGuardrailState: PortfolioOptimizationBudgetGuardrailState,
                val enforcementMode: PortfolioOptimizationPortfolioEnforcementMode,
                val remediationAutomationState: PortfolioOptimizationRemediationAutomationState,
                val suppressionReason: PortfolioOptimizationRemediationSuppressionReason?,
                val approvalRequired: Boolean,
                val quarantineActive: Boolean
            )

            val safetyContextsByPortfolioId = portfolios.associate { portfolio ->
                val analytics = analyticsSummaries.firstOrNull { it.portfolioId == portfolio.portfolioId }
                val riskBudget = riskBudgets.firstOrNull { it.portfolioId == portfolio.portfolioId }
                    ?: PortfolioOptimizationRiskBudget(portfolioId = portfolio.portfolioId)
                val trustDrift = trustTierDriftSummaries
                    .filter { it.portfolioId == portfolio.portfolioId }
                    .maxByOrNull { it.driftState.ordinal }
                val jurisdictionDrift = jurisdictionDriftSummaries
                    .filter { it.portfolioId == portfolio.portfolioId }
                    .maxByOrNull { it.driftState.ordinal }
                val concentration = destinationRiskConcentrationSummaries
                    .firstOrNull { it.portfolioId == portfolio.portfolioId }
                val blockerTrend = portfolioBlockerTrendSummaries
                    .firstOrNull { it.portfolioId == portfolio.portfolioId }
                val correctiveAction = latestCorrectiveActionByPortfolio[portfolio.portfolioId]
                val riskRecommendation = riskRecommendations.firstOrNull { it.portfolioId == portfolio.portfolioId }
                val safetyState = portfolioOptimizationPortfolioSafetyState(
                    healthStatus = analytics?.healthStatus
                        ?: PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.HEALTHY,
                    riskBudgetStatus = riskBudget.status,
                    trustTierDriftState = trustDrift?.driftState
                        ?: PortfolioOptimizationTrustTierDriftState.HEALTHY,
                    jurisdictionDriftState = jurisdictionDrift?.driftState
                        ?: PortfolioOptimizationJurisdictionDriftState.HEALTHY,
                    concentrationRatio = concentration?.concentrationRatio ?: 0.0,
                    highRiskDestinationCount = concentration?.highRiskDestinationCount ?: 0,
                    sharedBlockerCount = portfolio.sharedBlockerCount,
                    conflictCount = portfolio.conflictCount
                )
                val budgetGuardrailState = portfolioOptimizationBudgetGuardrailState(
                    riskBudget = riskBudget,
                    healthStatus = analytics?.healthStatus
                        ?: PortfolioOptimizationCrossBoundaryPortfolioHealthStatus.HEALTHY
                )
                val approvalRequired = budgetGuardrailState == PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ||
                    (
                        safetyState == PortfolioOptimizationPortfolioSafetyState.GUARDED &&
                            portfolio.status == PortfolioOptimizationCrossBoundaryGovernancePortfolioStatus.REVIEW_REQUIRED
                        ) ||
                    correctiveAction?.actionType == PortfolioOptimizationCorrectiveActionType.REQUEST_REEVALUATION
                val enforcementMode = portfolioOptimizationEnforcementMode(
                    safetyState = safetyState,
                    budgetGuardrailState = budgetGuardrailState,
                    approvalRequired = approvalRequired
                )
                val remediationAutomationState = portfolioOptimizationRemediationAutomationState(
                    safetyState = safetyState,
                    budgetGuardrailState = budgetGuardrailState,
                    blockerTrendDirection = blockerTrend?.direction
                        ?: PortfolioOptimizationTrendDirection.STABLE,
                    sharedBlockerCount = portfolio.sharedBlockerCount,
                    recentCorrectiveActionAtMs = correctiveAction?.recordedAtMs,
                    now = now
                )
                val suppressionReason = portfolioOptimizationRemediationSuppressionReason(
                    automationState = remediationAutomationState,
                    budgetGuardrailState = budgetGuardrailState,
                    trustTierDriftState = trustDrift?.driftState
                        ?: PortfolioOptimizationTrustTierDriftState.HEALTHY,
                    jurisdictionDriftState = jurisdictionDrift?.driftState
                        ?: PortfolioOptimizationJurisdictionDriftState.HEALTHY,
                    concentrationRatio = concentration?.concentrationRatio ?: 0.0,
                    sharedBlockerCount = portfolio.sharedBlockerCount
                )
                portfolio.portfolioId to PortfolioSafetyControlContext(
                    portfolio = portfolio,
                    analytics = analytics,
                    riskBudget = riskBudget,
                    trustDrift = trustDrift,
                    jurisdictionDrift = jurisdictionDrift,
                    concentration = concentration,
                    blockerTrend = blockerTrend,
                    correctiveAction = correctiveAction,
                    riskRecommendation = riskRecommendation,
                    safetyState = safetyState,
                    budgetGuardrailState = budgetGuardrailState,
                    enforcementMode = enforcementMode,
                    remediationAutomationState = remediationAutomationState,
                    suppressionReason = suppressionReason,
                    approvalRequired = approvalRequired,
                    quarantineActive = safetyState == PortfolioOptimizationPortfolioSafetyState.QUARANTINED ||
                        enforcementMode == PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE
                )
            }
            val budgetGuardrails = safetyContextsByPortfolioId.values
                .map { context ->
                    PortfolioOptimizationBudgetGuardrail(
                        guardrailId = "portfolio_budget_guardrail_${context.portfolio.portfolioId}_$now",
                        portfolioId = context.portfolio.portfolioId,
                        riskBudgetId = context.riskBudget.budgetId,
                        state = context.budgetGuardrailState,
                        enforcementMode = context.enforcementMode,
                        approvalRequired = context.approvalRequired,
                        breachUnits = context.riskBudget.breachUnits,
                        reasonCodes = buildList {
                            when (context.budgetGuardrailState) {
                                PortfolioOptimizationBudgetGuardrailState.WARNING ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_WARNING)
                                PortfolioOptimizationBudgetGuardrailState.SOFT_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_SOFT_STOP)
                                PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_HARD_STOP)
                                PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                                PortfolioOptimizationBudgetGuardrailState.WITHIN_LIMIT -> Unit
                            }
                        }.distinct(),
                        summary = when (context.budgetGuardrailState) {
                            PortfolioOptimizationBudgetGuardrailState.WARNING ->
                                "Budget warning is active because portfolio utilization is nearing the configured limit."
                            PortfolioOptimizationBudgetGuardrailState.SOFT_STOP ->
                                "Budget soft-stop is active; broadened rollout should slow until risk pressure declines."
                            PortfolioOptimizationBudgetGuardrailState.HARD_STOP ->
                                "Budget hard-stop is active; additional cross-boundary rollout is blocked."
                            PortfolioOptimizationBudgetGuardrailState.APPROVAL_REQUIRED ->
                                "Budget escalation requires operator approval before more rollout or remediation."
                            PortfolioOptimizationBudgetGuardrailState.WITHIN_LIMIT ->
                                "Budget remains within the configured portfolio threshold."
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationBudgetGuardrail> { it.updatedAtMs }
                        .thenBy { it.guardrailId }
                )
            val budgetGuardrailByPortfolioId = budgetGuardrails.associateBy { it.portfolioId }
            val safetyRails = safetyContextsByPortfolioId.values
                .flatMap { context ->
                    buildList {
                        fun addRail(
                            type: PortfolioOptimizationPortfolioSafetyRailType,
                            summary: String
                        ) {
                            add(
                                PortfolioOptimizationPortfolioSafetyRail(
                                    safetyRailId =
                                        "portfolio_safety_${type.name.lowercase()}_${context.portfolio.portfolioId}_$now",
                                    portfolioId = context.portfolio.portfolioId,
                                    type = type,
                                    safetyState = context.safetyState,
                                    enforcementMode = context.enforcementMode,
                                    blocking = context.enforcementMode in setOf(
                                        PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP,
                                        PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE,
                                        PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED
                                    ),
                                    targetProgramId = context.riskRecommendation?.targetProgramId,
                                    targetTrustTier = context.riskRecommendation?.targetTrustTier,
                                    targetJurisdiction = context.riskRecommendation?.targetJurisdiction,
                                    reasonCodes = buildList {
                                        when (context.safetyState) {
                                            PortfolioOptimizationPortfolioSafetyState.AT_RISK ->
                                                add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_AT_RISK)
                                            PortfolioOptimizationPortfolioSafetyState.GUARDED ->
                                                add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_GUARDED)
                                            PortfolioOptimizationPortfolioSafetyState.QUARANTINED,
                                            PortfolioOptimizationPortfolioSafetyState.BLOCKED ->
                                                add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_QUARANTINED)
                                            PortfolioOptimizationPortfolioSafetyState.SAFE -> Unit
                                        }
                                        if (context.quarantineActive) {
                                            add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                                        }
                                    }.distinct(),
                                    summary = summary,
                                    updatedAtMs = now
                                )
                            )
                        }
                        if (context.budgetGuardrailState != PortfolioOptimizationBudgetGuardrailState.WITHIN_LIMIT) {
                            addRail(
                                PortfolioOptimizationPortfolioSafetyRailType.RISK_BUDGET,
                                "Risk budget guardrail is ${context.budgetGuardrailState.name.lowercase().replace('_', ' ')}."
                            )
                        }
                        context.trustDrift
                            ?.takeIf { it.driftState != PortfolioOptimizationTrustTierDriftState.HEALTHY }
                            ?.let {
                                addRail(
                                    PortfolioOptimizationPortfolioSafetyRailType.TRUST_TIER_DRIFT,
                                    "Trust-tier drift keeps this portfolio ${context.safetyState.name.lowercase().replace('_', ' ')}."
                                )
                            }
                        context.jurisdictionDrift
                            ?.takeIf { it.driftState != PortfolioOptimizationJurisdictionDriftState.HEALTHY }
                            ?.let {
                                addRail(
                                    PortfolioOptimizationPortfolioSafetyRailType.JURISDICTION_DRIFT,
                                    "Jurisdiction drift keeps this portfolio ${context.safetyState.name.lowercase().replace('_', ' ')}."
                                )
                            }
                        context.concentration
                            ?.takeIf { it.concentrationRatio >= 0.60 }
                            ?.let {
                                addRail(
                                    PortfolioOptimizationPortfolioSafetyRailType.DESTINATION_CONCENTRATION,
                                    "Destination concentration exceeds the safe spread for this portfolio."
                                )
                            }
                        if (context.portfolio.sharedBlockerCount > 1 || context.portfolio.conflictCount > 0) {
                            addRail(
                                PortfolioOptimizationPortfolioSafetyRailType.SHARED_BLOCKERS,
                                "Shared blockers or conflicts require tighter portfolio coordination."
                            )
                        }
                        if (
                            blockerSummaries.any {
                                it.portfolioId == context.portfolio.portfolioId &&
                                    it.type == PortfolioOptimizationPortfolioBlockerType.COMPLIANCE
                            }
                        ) {
                            addRail(
                                PortfolioOptimizationPortfolioSafetyRailType.COMPLIANCE_PRESSURE,
                                "Compliance blocker pressure is constraining safe cross-boundary rollout."
                            )
                        }
                    }
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioSafetyRail> { it.updatedAtMs }
                        .thenBy { it.safetyRailId }
                )
            val safetyRailIdsByPortfolioId = safetyRails.groupBy { it.portfolioId }
                .mapValues { (_, rails) -> rails.map { it.safetyRailId } }
            val remediationAutomationControls = safetyContextsByPortfolioId.values
                .map { context ->
                    val cooldownUntilMs = context.correctiveAction
                        ?.recordedAtMs
                        ?.takeIf { recordedAtMs -> now - recordedAtMs < PORTFOLIO_REMEDIATION_COOLDOWN_MS }
                        ?.plus(PORTFOLIO_REMEDIATION_COOLDOWN_MS)
                    PortfolioOptimizationRemediationAutomationControl(
                        controlId = "portfolio_remediation_control_${context.portfolio.portfolioId}_$now",
                        portfolioId = context.portfolio.portfolioId,
                        automationState = context.remediationAutomationState,
                        enforcementMode = context.enforcementMode,
                        suppressionReason = context.suppressionReason,
                        throttleLimit = if (
                            context.remediationAutomationState ==
                            PortfolioOptimizationRemediationAutomationState.THROTTLED
                        ) {
                            1
                        } else {
                            null
                        },
                        cooldownUntilMs = cooldownUntilMs,
                        approvalRequired = context.approvalRequired,
                        quarantined = context.quarantineActive,
                        linkedRecommendationId = context.riskRecommendation?.recommendationId,
                        linkedCorrectiveActionId = context.correctiveAction?.actionRecordId,
                        reasonCodes = buildList {
                            when (context.remediationAutomationState) {
                                PortfolioOptimizationRemediationAutomationState.ALLOWED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_ALLOWED)
                                PortfolioOptimizationRemediationAutomationState.THROTTLED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_THROTTLED)
                                PortfolioOptimizationRemediationAutomationState.SUPPRESSED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_SUPPRESSED)
                                PortfolioOptimizationRemediationAutomationState.COOLDOWN_ACTIVE ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_COOLDOWN_ACTIVE)
                                PortfolioOptimizationRemediationAutomationState.APPROVAL_REQUIRED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                                PortfolioOptimizationRemediationAutomationState.QUARANTINED ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                            }
                        }.distinct(),
                        summary = when (context.remediationAutomationState) {
                            PortfolioOptimizationRemediationAutomationState.ALLOWED ->
                                "Remediation automation remains allowed within the current safety budget."
                            PortfolioOptimizationRemediationAutomationState.THROTTLED ->
                                "Remediation automation is throttled while portfolio drift and blocker pressure stabilize."
                            PortfolioOptimizationRemediationAutomationState.SUPPRESSED ->
                                "Remediation automation is suppressed because current safety rails do not allow more action."
                            PortfolioOptimizationRemediationAutomationState.COOLDOWN_ACTIVE ->
                                "Remediation automation is cooling down after a recent corrective action."
                            PortfolioOptimizationRemediationAutomationState.APPROVAL_REQUIRED ->
                                "Remediation automation requires operator approval before broader rollout resumes."
                            PortfolioOptimizationRemediationAutomationState.QUARANTINED ->
                                "Remediation automation is quarantined to a narrower safe subset."
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationRemediationAutomationControl> { it.updatedAtMs }
                        .thenBy { it.controlId }
                )
            val remediationControlByPortfolioId = remediationAutomationControls.associateBy { it.portfolioId }
            val portfolioSafetySummaries = safetyContextsByPortfolioId.values
                .map { context ->
                    PortfolioOptimizationPortfolioSafetySummary(
                        summaryId = "portfolio_safety_summary_${context.portfolio.portfolioId}_$now",
                        portfolioId = context.portfolio.portfolioId,
                        safetyState = context.safetyState,
                        enforcementMode = context.enforcementMode,
                        activeSafetyRailIds = safetyRailIdsByPortfolioId[context.portfolio.portfolioId].orEmpty(),
                        budgetGuardrailId = budgetGuardrailByPortfolioId[context.portfolio.portfolioId]?.guardrailId,
                        remediationControlId = remediationControlByPortfolioId[context.portfolio.portfolioId]?.controlId,
                        violationCount = safetyRailIdsByPortfolioId[context.portfolio.portfolioId]?.size ?: 0,
                        quarantineActive = context.quarantineActive,
                        approvalRequired = context.approvalRequired,
                        reasonCodes = buildList {
                            when (context.safetyState) {
                                PortfolioOptimizationPortfolioSafetyState.AT_RISK ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_AT_RISK)
                                PortfolioOptimizationPortfolioSafetyState.GUARDED ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_GUARDED)
                                PortfolioOptimizationPortfolioSafetyState.QUARANTINED,
                                PortfolioOptimizationPortfolioSafetyState.BLOCKED ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_SAFETY_QUARANTINED)
                                PortfolioOptimizationPortfolioSafetyState.SAFE -> Unit
                            }
                            if (context.quarantineActive) {
                                add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                            }
                            if (context.approvalRequired) {
                                add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                            }
                        }.distinct(),
                        summary = buildString {
                            append("Portfolio safety is ")
                            append(context.safetyState.name.lowercase().replace('_', ' '))
                            append(" with ")
                            append(context.enforcementMode.name.lowercase().replace('_', ' '))
                            append(" enforcement")
                            if (context.approvalRequired) {
                                append(" and manual approval required")
                            }
                            append('.')
                        },
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioSafetySummary> { it.updatedAtMs }
                        .thenBy { it.summaryId }
                )
            val safetySummaryByPortfolioId = portfolioSafetySummaries.associateBy { it.portfolioId }
            val adjustedRiskRecommendations = riskRecommendations
                .map { recommendation ->
                    val context = safetyContextsByPortfolioId[recommendation.portfolioId] ?: return@map recommendation
                    val adjustedAction = when (context.enforcementMode) {
                        PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP,
                        PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                            PortfolioOptimizationPortfolioRiskRecommendationAction.HOLD_PORTFOLIO
                        PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                            when (context.suppressionReason) {
                                PortfolioOptimizationRemediationSuppressionReason.JURISDICTION_DRIFT ->
                                    PortfolioOptimizationPortfolioRiskRecommendationAction.SPLIT_JURISDICTION_LANE
                                PortfolioOptimizationRemediationSuppressionReason.DESTINATION_CONCENTRATION ->
                                    PortfolioOptimizationPortfolioRiskRecommendationAction.REBALANCE_DESTINATION_SET
                                else -> PortfolioOptimizationPortfolioRiskRecommendationAction.TIGHTEN_TRUST_TIER
                            }
                        PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                            PortfolioOptimizationPortfolioRiskRecommendationAction.DEFER_PORTFOLIO
                        PortfolioOptimizationPortfolioEnforcementMode.WARNING ->
                            if (recommendation.action == PortfolioOptimizationPortfolioRiskRecommendationAction.CONTINUE_ROLLOUT) {
                                PortfolioOptimizationPortfolioRiskRecommendationAction.REVIEW_POLICY_PACK
                            } else {
                                recommendation.action
                            }
                        PortfolioOptimizationPortfolioEnforcementMode.OBSERVE -> recommendation.action
                    }
                    recommendation.copy(
                        action = adjustedAction,
                        blocking =
                            adjustedAction != PortfolioOptimizationPortfolioRiskRecommendationAction.CONTINUE_ROLLOUT,
                        reasonCodes = (recommendation.reasonCodes + buildList {
                            when (context.enforcementMode) {
                                PortfolioOptimizationPortfolioEnforcementMode.WARNING ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_WARNING)
                                PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_SOFT_STOP)
                                PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_HARD_STOP)
                                PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                                PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                                PortfolioOptimizationPortfolioEnforcementMode.OBSERVE -> Unit
                            }
                        }).distinct(),
                        summary = when (context.enforcementMode) {
                            PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP ->
                                "Hold portfolio rollout until the hard-stop safety rails are cleared."
                            PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                                "Quarantine rollout to a narrower safe subset before broader expansion."
                            PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                                "Hold portfolio rollout until operator approval clears the active safety rails."
                            PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                                "Slow or defer portfolio rollout while budget and drift pressure normalize."
                            PortfolioOptimizationPortfolioEnforcementMode.WARNING ->
                                "Review policy and pacing because portfolio safety rails are approaching a stop condition."
                            PortfolioOptimizationPortfolioEnforcementMode.OBSERVE ->
                                recommendation.summary
                        }
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioRiskRecommendation> { it.createdAtMs }
                        .thenBy { it.recommendationId }
                )
            val adjustedRecommendationByPortfolioId = adjustedRiskRecommendations.associateBy { it.portfolioId }
            val adjustedPortfolioRecommendations = recommendations
                .map { recommendation ->
                    val context = safetyContextsByPortfolioId[recommendation.portfolioId] ?: return@map recommendation
                    val adjustedAction = when (context.enforcementMode) {
                        PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP ->
                            PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM
                        PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                            when (context.suppressionReason) {
                                PortfolioOptimizationRemediationSuppressionReason.JURISDICTION_DRIFT ->
                                    PortfolioOptimizationPortfolioRecommendationAction.SPLIT_BY_JURISDICTION
                                else -> PortfolioOptimizationPortfolioRecommendationAction.HOLD_TRUST_TIER
                            }
                        PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                            PortfolioOptimizationPortfolioRecommendationAction.REVIEW_SHARED_BLOCKER
                        PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                            PortfolioOptimizationPortfolioRecommendationAction.DEFER_PROGRAM
                        PortfolioOptimizationPortfolioEnforcementMode.WARNING,
                        PortfolioOptimizationPortfolioEnforcementMode.OBSERVE -> recommendation.action
                    }
                    recommendation.copy(
                        action = adjustedAction,
                        blocking = adjustedAction != PortfolioOptimizationPortfolioRecommendationAction.ADVANCE_PROGRAM,
                        reasonCodes = (recommendation.reasonCodes + buildList {
                            when (context.enforcementMode) {
                                PortfolioOptimizationPortfolioEnforcementMode.WARNING ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_WARNING)
                                PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_SOFT_STOP)
                                PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_BUDGET_HARD_STOP)
                                PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                                    add(RoleReasonCodes.ROLE_PORTFOLIO_QUARANTINE_APPLIED)
                                PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                                    add(RoleReasonCodes.ROLE_REMEDIATION_AUTOMATION_APPROVAL_REQUIRED)
                                PortfolioOptimizationPortfolioEnforcementMode.OBSERVE -> Unit
                            }
                        }).distinct(),
                        summary = when (context.enforcementMode) {
                            PortfolioOptimizationPortfolioEnforcementMode.HARD_STOP ->
                                "Further rollout is paused until hard-stop budget and safety rails clear."
                            PortfolioOptimizationPortfolioEnforcementMode.QUARANTINE ->
                                "Quarantine the affected trust-tier or jurisdiction lane before proceeding."
                            PortfolioOptimizationPortfolioEnforcementMode.APPROVAL_REQUIRED ->
                                "Pause broader rollout and route the portfolio for manual approval review."
                            PortfolioOptimizationPortfolioEnforcementMode.SOFT_STOP ->
                                "Defer the next program while budget guardrails remain in soft-stop mode."
                            PortfolioOptimizationPortfolioEnforcementMode.WARNING ->
                                recommendation.summary
                            PortfolioOptimizationPortfolioEnforcementMode.OBSERVE ->
                                recommendation.summary
                        }
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioCoordinationRecommendation> { it.createdAtMs }
                        .thenBy { it.recommendationId }
                )
            val recommendationByPortfolioId = adjustedRecommendationByPortfolioId
            val finalizedAnalyticsSummaries = analyticsSummaries.map { analytics ->
                analytics.copy(
                    latestRiskRecommendationId = recommendationByPortfolioId[analytics.portfolioId]?.recommendationId
                )
            }
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationDestinationTrustTierAssignmentsByUser,
                userId,
                destinationTrustTierAssignments
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationCrossBoundaryProgramsByUser,
                userId,
                programRecords
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationCrossBoundaryGovernancePortfoliosByUser,
                userId,
                portfolios
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationTrustTierProgramsByUser,
                userId,
                trustTierProgramSummaries.sortedWith(
                    compareByDescending<PortfolioOptimizationTrustTierProgramSummary> { it.updatedAtMs }
                        .thenBy { it.summaryId }
                )
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationJurisdictionRolloutPlansByUser,
                userId,
                jurisdictionRolloutPlans.sortedWith(
                    compareByDescending<PortfolioOptimizationJurisdictionRolloutPlan> { it.updatedAtMs }
                        .thenBy { it.planId }
                )
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioBlockersByUser,
                userId,
                blockerSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioDependenciesByUser,
                userId,
                dependencySummaries.sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioDependencySummary> { it.updatedAtMs }
                        .thenBy { it.dependencyId }
                )
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioConflictsByUser,
                userId,
                conflictSummaries.sortedWith(
                    compareByDescending<PortfolioOptimizationPortfolioConflictSummary> { it.updatedAtMs }
                        .thenBy { it.conflictId }
                )
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioPriorityDecisionsByUser,
                userId,
                priorityDecisions
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioRecommendationsByUser,
                userId,
                adjustedPortfolioRecommendations
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioWaveCoordinationsByUser,
                userId,
                waveCoordinationRecords
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationCrossBoundaryPortfolioAnalyticsByUser,
                userId,
                finalizedAnalyticsSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationRiskBudgetsByUser,
                userId,
                riskBudgets
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationTrustTierDriftsByUser,
                userId,
                trustTierDriftSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationJurisdictionDriftsByUser,
                userId,
                jurisdictionDriftSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationDestinationRiskConcentrationsByUser,
                userId,
                destinationRiskConcentrationSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioBlockerTrendsByUser,
                userId,
                portfolioBlockerTrendSummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioRiskRecommendationsByUser,
                userId,
                adjustedRiskRecommendations
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioSafetyRailsByUser,
                userId,
                safetyRails
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationBudgetGuardrailsByUser,
                userId,
                budgetGuardrails
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationPortfolioSafetySummariesByUser,
                userId,
                portfolioSafetySummaries
            )
            replacePortfolioOptimizationDerivedQueueLocked(
                portfolioOptimizationRemediationAutomationControlsByUser,
                userId,
                remediationAutomationControls
            )
        }
    }

    private fun storePortfolioOptimizationFederatedAggregationSummary(
        userId: String,
        summary: PortfolioOptimizationFederatedAggregationSummary
    ) {
        synchronized(dynamicStateLock) {
            val queue = portfolioOptimizationFederatedAggregationSummariesByUser.getOrPut(userId) { ArrayDeque() }
            val merged = queue.toList()
                .filterNot { it.aggregationId == summary.aggregationId }
                .plus(summary)
                .sortedWith(
                    compareByDescending<PortfolioOptimizationFederatedAggregationSummary> { it.updatedAtMs }
                        .thenBy { it.aggregationId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            queue.clear()
            merged.forEach(queue::addLast)
        }
    }

    private fun recomputePortfolioOptimizationFederatedAggregationSummaries(
        userId: String,
        now: Long
    ) {
        synchronized(dynamicStateLock) {
            val envelopesById = portfolioOptimizationLearningSyncEnvelopesByUser[userId]
                ?.toList()
                .orEmpty()
                .associateBy { it.envelopeId }
            val successfulAttempts = portfolioOptimizationLearningSyncAttemptsByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { attempt ->
                    attempt.status == PortfolioOptimizationLearningSyncStatus.EXPORTED ||
                        attempt.status == PortfolioOptimizationLearningSyncStatus.APPLIED
                }
            val summaries = successfulAttempts
                .mapNotNull { attempt -> envelopesById[attempt.envelopeId] }
                .groupBy { it.groupKey.groupKey }
                .values
                .map { envelopes ->
                    val first = envelopes.first()
                    val highestDrift = envelopes
                        .flatMap { envelope ->
                            envelope.artifacts.mapNotNull { artifact -> artifact.driftSummary?.highestSeverity }
                        }
                        .maxByOrNull { it.ordinal }
                        ?: PortfolioDriftSeverity.NONE
                    PortfolioOptimizationFederatedAggregationSummary(
                        aggregationId = "portfolio_federated_${first.groupKey.groupKey.hashCode()}_${now}",
                        groupKey = first.groupKey,
                        boundary = first.boundary,
                        artifactCount = envelopes.sumOf { it.artifacts.size },
                        deviceCount = envelopes.map { it.provenance.deviceId }.distinct().count(),
                        highestDriftSeverity = highestDrift,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_FEDERATED_AGGREGATION_APPLIED),
                        summary = "Federated aggregation spans ${envelopes.map { it.provenance.deviceId }.distinct().count()} device(s) and ${envelopes.sumOf { it.artifacts.size }} redacted artifact(s).",
                        updatedAtMs = now
                    )
                }
                .sortedWith(
                    compareByDescending<PortfolioOptimizationFederatedAggregationSummary> { it.updatedAtMs }
                        .thenBy { it.aggregationId }
                )
                .take(MAX_PORTFOLIO_OPTIMIZATION_ITEMS)
            val queue = portfolioOptimizationFederatedAggregationSummariesByUser.getOrPut(userId) { ArrayDeque() }
            queue.clear()
            summaries.forEach(queue::addLast)
        }
    }

    private fun portfolioOptimizationLearningSyncEnvelopeFingerprint(
        artifact: PortfolioOptimizationLearningSyncArtifactEnvelope
    ): String {
        return when (artifact.artifactType) {
            PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT ->
                DomainJson.encode(artifact.objectiveProfileSnapshot)
            PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT ->
                DomainJson.encode(artifact.calibrationSnapshot)
            PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY ->
                DomainJson.encode(artifact.driftSummary)
            PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE ->
                DomainJson.encode(artifact.outcomeAggregate)
            PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY ->
                DomainJson.encode(artifact.federatedAggregationSummary)
        }
    }

    private fun applyPortfolioOptimizationSuggestionToSnapshot(
        snapshot: PortfolioOptimizationCalibrationSnapshot,
        suggestion: PortfolioOptimizationTuningSuggestion,
        now: Long
    ): PortfolioOptimizationCalibrationSnapshot {
        val objectiveWeights = snapshot.objectiveWeights
            .associate { it.family to it.weight.coerceIn(0, 10) }
        val objectiveTarget = portfolioOptimizationObjectiveFamilyForTarget(suggestion.targetFamily)
        val updatedWeights = PortfolioOptimizationObjectiveFamily.entries.map { family ->
            val current = objectiveWeights[family] ?: 0
            val proposed = if (family == objectiveTarget) {
                suggestion.proposedIntValue ?: (current + (suggestion.intDelta ?: 0)).coerceIn(0, 10)
            } else {
                current
            }
            PortfolioOptimizationObjectiveWeight(
                family = family,
                weight = proposed.coerceIn(0, 10)
            )
        }
        val updatedParameterCalibration = when (suggestion.targetFamily) {
            PortfolioOptimizationTuningTargetFamily.APPROVAL_LATENCY_PENALTY ->
                snapshot.parameterCalibration.copy(
                    approvalLatencyPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: snapshot.parameterCalibration.approvalLatencyPenaltyMultiplier + (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.READINESS_DELAY_PENALTY ->
                snapshot.parameterCalibration.copy(
                    readinessDelayPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: snapshot.parameterCalibration.readinessDelayPenaltyMultiplier + (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.WINDOW_MISS_PENALTY ->
                snapshot.parameterCalibration.copy(
                    windowMissPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: snapshot.parameterCalibration.windowMissPenaltyMultiplier + (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            PortfolioOptimizationTuningTargetFamily.RISK_INCIDENT_PENALTY ->
                snapshot.parameterCalibration.copy(
                    riskIncidentPenaltyMultiplier = (
                        suggestion.proposedDoubleValue
                            ?: snapshot.parameterCalibration.riskIncidentPenaltyMultiplier + (suggestion.doubleDelta ?: 0.0)
                        ).coerceIn(0.50, 2.00)
                )
            else -> snapshot.parameterCalibration
        }
        return PortfolioOptimizationCalibrationSnapshot(
            snapshotId = "portfolio_opt_calibration_${suggestion.suggestionId.takeLast(8)}_$now",
            parentSnapshotId = snapshot.snapshotId,
            version = snapshot.version + 1,
            objectiveProfileSnapshotId = snapshot.objectiveProfileSnapshotId,
            objectiveProfileBinding = snapshot.objectiveProfileBinding,
            objectiveProfileProvenance = snapshot.objectiveProfileProvenance,
            objectiveWeights = updatedWeights,
            parameterCalibration = updatedParameterCalibration.copy(
                summary = "Calibration snapshot v${snapshot.version + 1} created from tuning suggestion ${suggestion.suggestionId.takeLast(8)}."
            ),
            reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_LEARNING_TUNING_APPLIED),
            evidenceRefs = suggestion.evidenceRefs,
            summary = "Applied ${suggestion.targetFamily.name.lowercase().replace('_', ' ')} tuning from suggestion ${suggestion.suggestionId.takeLast(8)}.",
            createdAtMs = now
        )
    }

    private fun optimizePortfolioRequest(
        request: PortfolioOptimizationRequest,
        baseline: BaselinePortfolioSnapshot,
        cases: List<GovernanceCaseRecord>,
        calibrationSnapshot: PortfolioOptimizationCalibrationSnapshot,
        now: Long
    ): PortfolioOptimizationResult {
        val normalizedRequest = normalizePortfolioOptimizationRequest(
            request = request,
            now = now,
            calibrationSnapshotId = calibrationSnapshot.snapshotId
        ).copy(
            objectiveProfileSnapshotId = calibrationSnapshot.objectiveProfileSnapshotId,
            objectiveProfileBinding = calibrationSnapshot.objectiveProfileBinding
        )
        val effectiveObjectiveProfile = effectivePortfolioOptimizationObjectiveProfile(
            profile = normalizedRequest.objectiveProfile,
            calibrationSnapshot = calibrationSnapshot
        )
        val notes = mutableListOf<String>()
        val scenarioControls = resolvePortfolioOptimizationScenarioControls(
            request = normalizedRequest,
            notes = notes
        )
        val allUnits = derivePortfolioOptimizationUnits(
            cases = cases,
            parameterCalibration = calibrationSnapshot.parameterCalibration
        )
        val scopedUnits = if (normalizedRequest.targetProgramIds.isEmpty()) {
            allUnits
        } else {
            allUnits.filter { normalizedRequest.targetProgramIds.contains(it.programId) }
        }
        if (scopedUnits.isEmpty()) {
            return PortfolioOptimizationResult(
                resultId = "portfolio_opt_result_${normalizedRequest.requestId.take(12)}_${now}",
                requestId = normalizedRequest.requestId,
                baselineSnapshotId = baseline.snapshotId,
                calibrationSnapshotId = calibrationSnapshot.snapshotId,
                objectiveProfileSnapshotId = calibrationSnapshot.objectiveProfileSnapshotId,
                objectiveProfileBinding = calibrationSnapshot.objectiveProfileBinding,
                objectiveProfileProvenance = calibrationSnapshot.objectiveProfileProvenance,
                status = PortfolioOptimizationResultStatus.COMPLETED,
                objectiveProfile = effectiveObjectiveProfile,
                constraintProfile = normalizedRequest.constraintProfile,
                scenarioSet = normalizedRequest.scenarioSet.copy(
                    baselineSnapshotId = normalizedRequest.scenarioSet.baselineSnapshotId ?: baseline.snapshotId
                ),
                solverConfig = normalizedRequest.solverConfig,
                baselineSnapshot = baseline,
                candidateSchedules = emptyList(),
                paretoFrontierSummary = PortfolioOptimizationParetoFrontierSummary(
                    summary = "No schedulable governance units were available for optimization."
                ),
                notes = notes + "No eligible governance units were found in the current baseline.",
                summary = "Optimization completed with no candidate schedules.",
                startedAtMs = now,
                completedAtMs = now
            )
        }

        val strategies = buildPortfolioOptimizationStrategySequence(normalizedRequest.objectiveProfile.preset)
        val targetCount = normalizedRequest.solverConfig.topCandidateCount
        val candidates = mutableListOf<PortfolioOptimizationCandidateSchedule>()
        val seenSignatures = mutableSetOf<String>()
        var iteration = 0
        while (candidates.size < targetCount && iteration < normalizedRequest.solverConfig.maxCandidateIterations) {
            val strategy = strategies[iteration % strategies.size]
            val candidate = buildPortfolioOptimizationCandidate(
                request = normalizedRequest.copy(objectiveProfile = effectiveObjectiveProfile),
                baseline = baseline,
                units = scopedUnits,
                scenarioControls = scenarioControls,
                strategy = strategy,
                iteration = iteration,
                parameterCalibration = calibrationSnapshot.parameterCalibration,
                now = now
            )
            val signature = portfolioOptimizationCandidateSignature(candidate)
            if (seenSignatures.add(signature)) {
                candidates += candidate
            }
            iteration += 1
        }

        val rankedCandidates = candidates
            .sortedWith(
                compareByDescending<PortfolioOptimizationCandidateSchedule> { it.score.weightedTotalScore }
                    .thenByDescending { it.score.riskScore }
                    .thenByDescending { it.score.slaScore }
                    .thenByDescending { it.score.throughputScore }
                    .thenBy { it.candidateId }
            )
            .mapIndexed { index, candidate -> candidate.copy(rank = index + 1) }
        val candidatesWithTradeoffs = attachPortfolioOptimizationTradeoffs(
            candidates = rankedCandidates,
            objectiveProfile = normalizedRequest.objectiveProfile
        )
        val paretoFrontier = computePortfolioOptimizationParetoFrontier(candidatesWithTradeoffs)
        val topCandidate = candidatesWithTradeoffs.firstOrNull()
        if (scenarioControls.clampedInputCount > 0) {
            notes += "Scenario overlays were clamped to bounded optimization limits."
        }
        notes += "Optimization used seed ${normalizedRequest.solverConfig.seed} for deterministic candidate generation."
        notes += "Calibration snapshot ${calibrationSnapshot.snapshotId.takeLast(10)} (v${calibrationSnapshot.version}) informed ranking."
        notes += "Objective profile ${calibrationSnapshot.objectiveProfileSnapshotId.takeLast(10)} resolved at ${portfolioOptimizationScopeLabel(calibrationSnapshot.objectiveProfileBinding.scope)} scope."
        val summary = buildString {
            append("Generated ")
            append(candidatesWithTradeoffs.size)
            append(" candidate schedule(s)")
            topCandidate?.let {
                append("; top candidate ")
                append(it.candidateId.takeLast(10))
                append(" scores ")
                append(String.format(Locale.US, "%.1f", it.score.weightedTotalScore))
            }
        }
        return PortfolioOptimizationResult(
            resultId = "portfolio_opt_result_${normalizedRequest.requestId.take(12)}_${now}",
            requestId = normalizedRequest.requestId,
            baselineSnapshotId = baseline.snapshotId,
            calibrationSnapshotId = calibrationSnapshot.snapshotId,
            objectiveProfileSnapshotId = calibrationSnapshot.objectiveProfileSnapshotId,
            objectiveProfileBinding = calibrationSnapshot.objectiveProfileBinding,
            objectiveProfileProvenance = calibrationSnapshot.objectiveProfileProvenance,
            status = PortfolioOptimizationResultStatus.COMPLETED,
            objectiveProfile = effectiveObjectiveProfile,
            constraintProfile = normalizedRequest.constraintProfile,
            scenarioSet = normalizedRequest.scenarioSet.copy(
                baselineSnapshotId = normalizedRequest.scenarioSet.baselineSnapshotId ?: baseline.snapshotId
            ),
            solverConfig = normalizedRequest.solverConfig,
            baselineSnapshot = baseline,
            candidateSchedules = candidatesWithTradeoffs,
            paretoFrontierSummary = paretoFrontier,
            notes = notes,
            summary = summary,
            startedAtMs = now,
            completedAtMs = now
        )
    }

    private fun buildPortfolioOptimizationStrategySequence(
        preset: PortfolioOptimizationObjectivePreset
    ): List<PortfolioOptimizationCandidateStrategy> {
        val aligned = when (preset) {
            PortfolioOptimizationObjectivePreset.THROUGHPUT_FIRST ->
                PortfolioOptimizationCandidateStrategy.THROUGHPUT_BIASED
            PortfolioOptimizationObjectivePreset.RISK_AVERSE ->
                PortfolioOptimizationCandidateStrategy.RISK_AVERSE
            PortfolioOptimizationObjectivePreset.SLA_RECOVERY ->
                PortfolioOptimizationCandidateStrategy.SLA_RECOVERY
            PortfolioOptimizationObjectivePreset.FAIRNESS_FIRST ->
                PortfolioOptimizationCandidateStrategy.FAIRNESS_BALANCED
            PortfolioOptimizationObjectivePreset.CRITICAL_PATH_FIRST ->
                PortfolioOptimizationCandidateStrategy.CRITICAL_PATH_FIRST
            PortfolioOptimizationObjectivePreset.BALANCED ->
                PortfolioOptimizationCandidateStrategy.BALANCED_GREEDY
        }
        return listOf(
            aligned,
            PortfolioOptimizationCandidateStrategy.BALANCED_GREEDY,
            PortfolioOptimizationCandidateStrategy.THROUGHPUT_BIASED,
            PortfolioOptimizationCandidateStrategy.RISK_AVERSE,
            PortfolioOptimizationCandidateStrategy.SLA_RECOVERY,
            PortfolioOptimizationCandidateStrategy.FAIRNESS_BALANCED,
            PortfolioOptimizationCandidateStrategy.CRITICAL_PATH_FIRST
        ).distinct()
    }

    private fun buildPortfolioOptimizationCandidate(
        request: PortfolioOptimizationRequest,
        baseline: BaselinePortfolioSnapshot,
        units: List<PortfolioOptimizationUnit>,
        scenarioControls: PortfolioSimulationControls,
        strategy: PortfolioOptimizationCandidateStrategy,
        iteration: Int,
        parameterCalibration: PortfolioOptimizationParameterCalibration,
        now: Long
    ): PortfolioOptimizationCandidateSchedule {
        val bucketCount = request.solverConfig.horizonDays.coerceIn(1, PORTFOLIO_OPTIMIZATION_HORIZON_DAYS)
        val bucketMs = request.solverConfig.bucketHours.coerceIn(1, PORTFOLIO_SIMULATION_BUCKET_HOURS) *
            60L * 60L * 1000L
        val startAtMs = utcDayStartMs(now)
        val searchLookahead = request.solverConfig.maxWindowLookaheadBuckets.coerceIn(1, bucketCount)
        val baseCapacity = maxOf(1, baseline.capacity.approvalCapacityBaseline)
        val adjustedCapacity = maxOf(
            1,
            (baseCapacity.toDouble() * (1.0 + scenarioControls.capacityAdjustmentPct / 100.0)).toInt()
        )
        val capacityUsed = IntArray(bucketCount)
        val riskyPromotionsByBucket = IntArray(bucketCount)
        val automationActionsByBucket = IntArray(bucketCount)
        val objectiveWeights = portfolioOptimizationObjectiveWeightMap(request.objectiveProfile)
        val riskLimit = portfolioOptimizationRiskLimit(request.constraintProfile)
        val automationLimit = portfolioOptimizationAutomationLimit(request.constraintProfile)
        val pinnedTargetsEnabled = portfolioOptimizationConstraintEnabled(
            request.constraintProfile,
            PortfolioOptimizationConstraintFamily.PINNED_TARGETS
        )
        val capacityEnabled = portfolioOptimizationConstraintEnabled(
            request.constraintProfile,
            PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY
        )
        val riskLimitEnabled = portfolioOptimizationConstraintEnabled(
            request.constraintProfile,
            PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS
        )
        val automationLimitEnabled = portfolioOptimizationConstraintEnabled(
            request.constraintProfile,
            PortfolioOptimizationConstraintFamily.MAX_AUTOMATION_ACTIONS_PER_WINDOW
        )
        val mandatoryReviewEnabled = portfolioOptimizationConstraintEnabled(
            request.constraintProfile,
            PortfolioOptimizationConstraintFamily.MANDATORY_REVIEW
        )
        val unitMap = units.associateBy { it.sourceRunId }
        val allProgramIds = units.map { it.programId }.toSet()
        val bindingEvents = mutableListOf<PortfolioOptimizationBindingEvent>()
        val scheduledActions = mutableListOf<PortfolioOptimizationScheduledAction>()
        val deferredActions = mutableListOf<PortfolioOptimizationDeferredAction>()
        val scheduledProgramBuckets = mutableMapOf<String, Int>()
        val sortedUnits = units.sortedWith(
            compareByDescending<PortfolioOptimizationUnit> {
                portfolioOptimizationPriorityScore(
                    unit = it,
                    strategy = strategy,
                    objectiveWeights = objectiveWeights,
                    seed = request.solverConfig.seed,
                    iteration = iteration
                )
            }.thenBy { it.programId }
                .thenBy { it.waveId.orEmpty() }
                .thenBy { it.sourceRunId }
        )
        var pending = ArrayDeque<PortfolioOptimizationUnit>().apply { addAll(sortedUnits) }
        var dependencyPass = 0
        while (pending.isNotEmpty() && dependencyPass <= units.size) {
            val remaining = ArrayDeque<PortfolioOptimizationUnit>()
            var progress = false
            while (pending.isNotEmpty()) {
                val unit = pending.removeFirst()
                val unresolvedDependencies = unit.dependencyProgramIds
                    .filter { dependencyId -> dependencyId in allProgramIds && dependencyId !in scheduledProgramBuckets }
                if (unresolvedDependencies.isNotEmpty()) {
                    remaining.addLast(unit)
                    continue
                }
                val actionType = when {
                    unit.escalated && unit.slaSeverity >= 2 -> PortfolioOptimizationActionType.PRIORITIZE_ESCALATION
                    unit.requiresApproval && mandatoryReviewEnabled -> PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW
                    unit.safeAutomationEligible && automationLimit > 0 -> PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION
                    else -> PortfolioOptimizationActionType.PROMOTE_WAVE
                }
                if (pinnedTargetsEnabled && unit.pinned) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.PINNED_TARGETS,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_GUARDRAIL_CONSTRAINT_BOUND,
                        summary = "Pinned targets prevent schedule changes for ${unit.programId}."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.PINNED_TARGETS,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_GUARDRAIL_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Pinned targets locked this program in place."
                    )
                    progress = true
                    continue
                }
                if (unit.policyBlocked) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.POLICY_GUARDRAIL,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_GUARDRAIL_CONSTRAINT_BOUND,
                        summary = "Policy or guardrail gating prevents scheduling ${unit.programId}."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.POLICY_GUARDRAIL,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_GUARDRAIL_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Guardrail state remained binding for ${unit.programId}."
                    )
                    progress = true
                    continue
                }
                if (scenarioControls.pausedProgramIds.contains(unit.programId) &&
                    !scenarioControls.resumedProgramIds.contains(unit.programId)
                ) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.READINESS_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_READINESS_CONSTRAINT_BOUND,
                        summary = "Scenario overlay keeps ${unit.programId} paused for this optimization run."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.READINESS_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_READINESS_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Paused program overlay blocked scheduling."
                    )
                    progress = true
                    continue
                }
                if (unit.dependencyBlocked || unit.dependencyProgramIds.any { dependencyId -> dependencyId !in allProgramIds }) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_DEPENDENCY_CONSTRAINT_BOUND,
                        summary = "Dependencies remain unresolved for ${unit.programId}."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_DEPENDENCY_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Dependency gating blocked ${unit.programId}."
                    )
                    progress = true
                    continue
                }
                val readinessBlocked = when (unit.readinessStatus) {
                    RolloutPromotionReadinessStatus.BLOCKED,
                    RolloutPromotionReadinessStatus.EXPIRED,
                    RolloutPromotionReadinessStatus.PAUSED -> true
                    else -> false
                }
                if (readinessBlocked) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.READINESS_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_READINESS_CONSTRAINT_BOUND,
                        summary = "Readiness gating prevents scheduling ${unit.programId}."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.READINESS_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_READINESS_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Readiness state remained binding for ${unit.programId}."
                    )
                    progress = true
                    continue
                }

                var earliestBucket = portfolioOptimizationEarliestBucket(
                    startAtMs = startAtMs,
                    bucketMs = bucketMs,
                    nextEligibleAtMs = unit.nextEligibleAtMs
                ) + scenarioControls.windowShiftBuckets
                earliestBucket = earliestBucket.coerceAtLeast(0)
                val dependencyBucket = unit.dependencyProgramIds
                    .mapNotNull { dependencyId -> scheduledProgramBuckets[dependencyId] }
                    .maxOrNull()
                if (dependencyBucket != null) {
                    earliestBucket = maxOf(earliestBucket, dependencyBucket + 1)
                }
                val blockedByWindowWithoutNext = unit.windowBlockReason in setOf(
                    ExecutionWindowBlockReason.BLACKOUT_WINDOW,
                    ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW,
                    ExecutionWindowBlockReason.SCHEDULE_EXPIRED
                ) && unit.nextEligibleAtMs == null
                if (blockedByWindowWithoutNext || earliestBucket >= bucketCount) {
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_WINDOW_CONSTRAINT_BOUND,
                        summary = "Window eligibility pushes ${unit.programId} beyond the optimization horizon."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_WINDOW_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Window eligibility constrained ${unit.programId}."
                    )
                    progress = true
                    continue
                }

                val isRiskyPromotion = actionType == PortfolioOptimizationActionType.PROMOTE_WAVE &&
                    unit.riskBucket >= PortfolioOptimizationRiskBucket.HIGH
                val actionCapacityCost = if (actionType == PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION) {
                    0
                } else {
                    unit.capacityCost
                }
                var selectedBucket: Int? = null
                var finalBlockingFamily: PortfolioOptimizationConstraintFamily? = null
                val feasibleBuckets = mutableListOf<Int>()
                val upperBound = minOf(bucketCount, earliestBucket + searchLookahead)
                for (bucketIndex in earliestBucket until upperBound) {
                    var blockedFamily: PortfolioOptimizationConstraintFamily? = null
                    var blockedReasonCode: String? = null
                    var blockedSummary: String? = null
                    if (capacityEnabled && actionCapacityCost > 0 && capacityUsed[bucketIndex] + actionCapacityCost > adjustedCapacity) {
                        blockedFamily = PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY
                        blockedReasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_CAPACITY_CONSTRAINT_BOUND
                        blockedSummary = "Approval capacity is full in bucket $bucketIndex."
                    } else if (automationLimitEnabled &&
                        actionType == PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION &&
                        automationActionsByBucket[bucketIndex] >= automationLimit
                    ) {
                        blockedFamily = PortfolioOptimizationConstraintFamily.MAX_AUTOMATION_ACTIONS_PER_WINDOW
                        blockedReasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_CAPACITY_CONSTRAINT_BOUND
                        blockedSummary = "Safe automation window limit is reached in bucket $bucketIndex."
                    } else if (riskLimitEnabled && isRiskyPromotion && riskLimit >= 0 &&
                        riskyPromotionsByBucket[bucketIndex] > riskLimit - 1
                    ) {
                        blockedFamily = PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS
                        blockedReasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_RISK_LIMIT_BOUND
                        blockedSummary = "Risk limit is binding in bucket $bucketIndex."
                    }
                    if (blockedFamily != null && blockedReasonCode != null && blockedSummary != null) {
                        bindingEvents += PortfolioOptimizationBindingEvent(
                            family = blockedFamily,
                            reasonCode = blockedReasonCode,
                            bucketIndex = bucketIndex,
                            programId = unit.programId,
                            waveId = unit.waveId,
                            summary = blockedSummary
                        )
                        finalBlockingFamily = blockedFamily
                        continue
                    }
                    feasibleBuckets += bucketIndex
                }
                if (feasibleBuckets.isNotEmpty()) {
                    val preferredIndex = when (strategy) {
                        PortfolioOptimizationCandidateStrategy.THROUGHPUT_BIASED -> 0
                        PortfolioOptimizationCandidateStrategy.BALANCED_GREEDY -> 0
                        PortfolioOptimizationCandidateStrategy.RISK_AVERSE -> when {
                            feasibleBuckets.size == 1 -> 0
                            isRiskyPromotion -> feasibleBuckets.lastIndex
                            unit.riskBucket >= PortfolioOptimizationRiskBucket.MODERATE -> 1
                            else -> 0
                        }
                        PortfolioOptimizationCandidateStrategy.SLA_RECOVERY -> when {
                            feasibleBuckets.size == 1 -> 0
                            unit.slaSeverity >= 2 || unit.criticalPath -> 0
                            else -> 1
                        }
                        PortfolioOptimizationCandidateStrategy.FAIRNESS_BALANCED -> when {
                            feasibleBuckets.size == 1 -> 0
                            unit.currentDeferred -> minOf(2, feasibleBuckets.lastIndex)
                            else -> minOf(1, feasibleBuckets.lastIndex)
                        }
                        PortfolioOptimizationCandidateStrategy.CRITICAL_PATH_FIRST -> when {
                            feasibleBuckets.size == 1 -> 0
                            unit.criticalPath -> 0
                            else -> minOf(1, feasibleBuckets.lastIndex)
                        }
                    }
                    selectedBucket = feasibleBuckets[preferredIndex]
                }
                if (selectedBucket == null) {
                    val blockedBy = finalBlockingFamily ?: PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY
                    val reasonCode = when (blockedBy) {
                        PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS ->
                            RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_RISK_LIMIT_BOUND
                        PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY ->
                            RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_WINDOW_CONSTRAINT_BOUND
                        else ->
                            RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_CAPACITY_CONSTRAINT_BOUND
                    }
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = blockedBy,
                        reasonCode = reasonCode,
                        summary = "No feasible bucket remained for ${unit.programId} within the current limits."
                    )
                    progress = true
                    continue
                }
                val scheduledAtMs = startAtMs + (selectedBucket.toLong() * bucketMs)
                if (actionCapacityCost > 0) {
                    capacityUsed[selectedBucket] += actionCapacityCost
                }
                if (isRiskyPromotion) {
                    riskyPromotionsByBucket[selectedBucket] += 1
                }
                if (actionType == PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION) {
                    automationActionsByBucket[selectedBucket] += 1
                }
                scheduledProgramBuckets[unit.programId] = selectedBucket
                scheduledActions += PortfolioOptimizationScheduledAction(
                    actionId = "opt_action_${unit.sourceRunId.take(10)}_${selectedBucket}_${strategy.name.lowercase()}",
                    type = actionType,
                    sourceRunId = unit.sourceRunId,
                    programId = unit.programId,
                    waveId = unit.waveId,
                    scheduledBucketIndex = selectedBucket,
                    scheduledAtMs = scheduledAtMs,
                    capacityCost = actionCapacityCost,
                    riskBucket = unit.riskBucket,
                    requiresApproval = actionType == PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW ||
                        unit.requiresApproval,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_CANDIDATE_GENERATED),
                    summary = buildString {
                        append(
                            when (actionType) {
                                PortfolioOptimizationActionType.PROMOTE_WAVE -> "Promote"
                                PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW -> "Review"
                                PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION -> "Run safe automation for"
                                PortfolioOptimizationActionType.HOLD_WAVE -> "Hold"
                                PortfolioOptimizationActionType.DEFER_TO_NEXT_WINDOW -> "Defer"
                                PortfolioOptimizationActionType.PRIORITIZE_ESCALATION -> "Prioritize escalation for"
                            }
                        )
                        append(' ')
                        append(unit.programId)
                        unit.waveId?.let { append(" / $it") }
                        append(" in bucket ")
                        append(selectedBucket)
                    }
                )
                progress = true
            }
            if (!progress) {
                remaining.forEach { unit ->
                    deferredActions += buildDeferredPortfolioOptimizationAction(
                        unit = unit,
                        blockedBy = PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_DEPENDENCY_CONSTRAINT_BOUND,
                        summary = "Dependency deadlock prevented scheduling ${unit.programId}."
                    )
                    bindingEvents += PortfolioOptimizationBindingEvent(
                        family = PortfolioOptimizationConstraintFamily.DEPENDENCY_GATE,
                        reasonCode = RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_DEPENDENCY_CONSTRAINT_BOUND,
                        programId = unit.programId,
                        waveId = unit.waveId,
                        summary = "Dependency deadlock prevented further scheduling progress."
                    )
                }
                break
            }
            pending = remaining
            dependencyPass += 1
        }

        val score = buildPortfolioOptimizationCandidateScore(
            objectiveWeights = objectiveWeights,
            scheduledActions = scheduledActions,
            deferredActions = deferredActions,
            units = units,
            unitMap = unitMap,
            parameterCalibration = parameterCalibration
        )
        val bindingConstraints = collapsePortfolioOptimizationBindingEvents(bindingEvents)
        val scheduledPromotions = scheduledActions.count {
            it.type == PortfolioOptimizationActionType.PROMOTE_WAVE ||
                it.type == PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION
        }
        val deferredHighRisk = deferredActions.count { action ->
            unitMap[action.sourceRunId]?.riskBucket?.let { bucket ->
                bucket == PortfolioOptimizationRiskBucket.HIGH || bucket == PortfolioOptimizationRiskBucket.CRITICAL
            } == true
        }
        return PortfolioOptimizationCandidateSchedule(
            candidateId = "opt_candidate_${strategy.name.lowercase()}_${request.requestId.takeLast(6)}_$iteration",
            strategy = strategy,
            scheduledActions = scheduledActions.sortedWith(
                compareBy<PortfolioOptimizationScheduledAction> { it.scheduledBucketIndex }
                    .thenBy { it.programId }
                    .thenBy { it.waveId.orEmpty() }
                    .thenBy { it.actionId }
            ),
            deferredActions = deferredActions.sortedWith(
                compareBy<PortfolioOptimizationDeferredAction> { it.programId }
                    .thenBy { it.waveId.orEmpty() }
                    .thenBy { it.sourceRunId }
            ),
            score = score,
            bindingConstraints = bindingConstraints,
            tradeoffExplanations = emptyList(),
            summary = buildString {
                append("${scheduledPromotions} promotion-ready action(s)")
                val reviews = scheduledActions.count { it.type == PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW }
                if (reviews > 0) {
                    append(", $reviews review action(s)")
                }
                if (deferredActions.isNotEmpty()) {
                    append("; ${deferredActions.size} deferred")
                }
                if (deferredHighRisk > 0) {
                    append("; defers $deferredHighRisk high-risk item(s)")
                }
                bindingConstraints.firstOrNull()?.summary?.takeIf { it.isNotBlank() }?.let {
                    append(". Binding: ")
                    append(it)
                }
            }
        )
    }

    private fun buildPortfolioOptimizationCandidateScore(
        objectiveWeights: Map<PortfolioOptimizationObjectiveFamily, Int>,
        scheduledActions: List<PortfolioOptimizationScheduledAction>,
        deferredActions: List<PortfolioOptimizationDeferredAction>,
        units: List<PortfolioOptimizationUnit>,
        unitMap: Map<String, PortfolioOptimizationUnit>,
        parameterCalibration: PortfolioOptimizationParameterCalibration
    ): PortfolioOptimizationCandidateScore {
        val totalUnits = maxOf(1, units.size)
        val totalPrograms = maxOf(1, units.map { it.programId }.distinct().size)
        val scheduledPromotions = scheduledActions.count {
            it.type == PortfolioOptimizationActionType.PROMOTE_WAVE ||
                it.type == PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION
        }
        val scheduledReviews = scheduledActions.count { it.type == PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW }
        val throughputScore = (
            ((scheduledPromotions.toDouble() + (scheduledReviews.toDouble() * 0.35)) / totalUnits.toDouble()) * 100.0
            ).coerceIn(0.0, 100.0)
        val scheduledRiskExposure = scheduledActions.sumOf { action ->
            val unit = unitMap[action.sourceRunId] ?: return@sumOf 0.0
            val exposureMultiplier = when (action.type) {
                PortfolioOptimizationActionType.PROMOTE_WAVE,
                PortfolioOptimizationActionType.SAFE_AUTOMATION_REMEDIATION -> 1.0
                PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW -> 0.35
                PortfolioOptimizationActionType.PRIORITIZE_ESCALATION -> 0.5
                else -> 0.25
            }
            unit.riskPenalty * exposureMultiplier
        }
        val riskScore = (100.0 - scheduledRiskExposure * 12.0).coerceIn(0.0, 100.0)
        val slaRelevantUnits = units.filter { it.slaSeverity > 0 || it.escalated }
        val slaScore = if (slaRelevantUnits.isEmpty()) {
            100.0
        } else {
            val achieved = slaRelevantUnits.sumOf { unit ->
                val scheduled = scheduledActions.firstOrNull { it.sourceRunId == unit.sourceRunId }
                if (scheduled == null) {
                    0.0
                } else {
                    ((4 - scheduled.scheduledBucketIndex).coerceAtLeast(1) * maxOf(1, unit.slaSeverity)).toDouble()
                }
            }
            val possible = slaRelevantUnits.sumOf { (4 * maxOf(1, it.slaSeverity)).toDouble() }.coerceAtLeast(1.0)
            ((achieved / possible) * 100.0).coerceIn(0.0, 100.0)
        }
        val programCoverage = scheduledActions.map { it.programId }.distinct().size.toDouble() / totalPrograms.toDouble()
        val perProgramCounts = scheduledActions.groupingBy { it.programId }.eachCount()
        val dominancePenalty = ((perProgramCounts.values.maxOrNull() ?: 1) - 1) * 12.0
        val fairnessScore = ((programCoverage * 100.0) - dominancePenalty).coerceIn(0.0, 100.0)
        val delayPenalty = scheduledActions.sumOf { it.scheduledBucketIndex.toDouble() * 4.0 } +
            deferredActions.sumOf { action ->
                when (action.blockedBy) {
                    PortfolioOptimizationConstraintFamily.WINDOW_ELIGIBILITY ->
                        9.0 * parameterCalibration.windowMissPenaltyMultiplier
                    PortfolioOptimizationConstraintFamily.READINESS_GATE ->
                        9.0 * parameterCalibration.readinessDelayPenaltyMultiplier
                    else -> 9.0
                }
            } +
            units.count { it.currentDeferred } * 2.0 * parameterCalibration.readinessDelayPenaltyMultiplier
        val stabilityScore = (100.0 - delayPenalty).coerceIn(0.0, 100.0)
        val operatorLoadPenalty = scheduledActions.sumOf { action ->
            when (action.type) {
                PortfolioOptimizationActionType.REQUEST_APPROVAL_REVIEW ->
                    10.0 * parameterCalibration.approvalLatencyPenaltyMultiplier
                PortfolioOptimizationActionType.PROMOTE_WAVE -> 6.0
                PortfolioOptimizationActionType.PRIORITIZE_ESCALATION -> 8.0
                else -> 2.5
            }
        } + deferredActions.count { it.blockedBy == PortfolioOptimizationConstraintFamily.APPROVAL_CAPACITY } *
            3.0 * parameterCalibration.approvalLatencyPenaltyMultiplier
        val operatorFrictionScore = (100.0 - operatorLoadPenalty).coerceIn(0.0, 100.0)
        val criticalUnits = units.filter { it.criticalPath }
        val criticalPathScore = if (criticalUnits.isEmpty()) {
            100.0
        } else {
            val achieved = criticalUnits.sumOf { unit ->
                val scheduled = scheduledActions.firstOrNull { it.sourceRunId == unit.sourceRunId }
                if (scheduled == null) {
                    0.0
                } else {
                    (5 - scheduled.scheduledBucketIndex).coerceAtLeast(1).toDouble()
                }
            }
            val possible = criticalUnits.size * 5.0
            ((achieved / possible) * 100.0).coerceIn(0.0, 100.0)
        }
        val weightedTotal = buildList {
            add(throughputScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.THROUGHPUT] ?: 0))
            add(riskScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.RISK] ?: 0))
            add(slaScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.SLA] ?: 0))
            add(fairnessScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.FAIRNESS] ?: 0))
            add(stabilityScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.STABILITY] ?: 0))
            add(operatorFrictionScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.OPERATOR_FRICTION] ?: 0))
            add(criticalPathScore * (objectiveWeights[PortfolioOptimizationObjectiveFamily.CRITICAL_PATH_PROTECTION] ?: 0))
        }.sum() / maxOf(1, objectiveWeights.values.sum()).toDouble()
        return PortfolioOptimizationCandidateScore(
            throughputScore = throughputScore,
            riskScore = riskScore,
            slaScore = slaScore,
            fairnessScore = fairnessScore,
            stabilityScore = stabilityScore,
            operatorFrictionScore = operatorFrictionScore,
            criticalPathScore = criticalPathScore,
            weightedTotalScore = weightedTotal,
            summary = buildString {
                append("Weighted ")
                append(String.format(Locale.US, "%.1f", weightedTotal))
                append(" · throughput ")
                append(String.format(Locale.US, "%.1f", throughputScore))
                append(" · risk ")
                append(String.format(Locale.US, "%.1f", riskScore))
            }
        )
    }

    private fun resolvePortfolioOptimizationScenarioControls(
        request: PortfolioOptimizationRequest,
        notes: MutableList<String>
    ): PortfolioSimulationControls {
        if (request.scenarioSet.scenarioIds.isEmpty()) return PortfolioSimulationControls()
        val modifications = request.scenarioSet.scenarioIds.flatMap { scenarioId ->
            synchronized(dynamicStateLock) {
                portfolioScenarioDefinitionsByUser.values
                    .asSequence()
                    .flatMap { it.asSequence() }
                    .firstOrNull { it.scenarioId == scenarioId }
                    ?.modifications
                    .orEmpty()
            }
        }
        if (modifications.isEmpty()) {
            notes += "Scenario overlays referenced by the optimization request were not found locally."
            return PortfolioSimulationControls()
        }
        notes += "Optimization applied ${request.scenarioSet.scenarioIds.size} saved scenario overlay(s)."
        return resolvePortfolioSimulationControls(modifications, notes)
    }

    private fun derivePortfolioOptimizationUnits(
        cases: List<GovernanceCaseRecord>,
        parameterCalibration: PortfolioOptimizationParameterCalibration = PortfolioOptimizationParameterCalibration()
    ): List<PortfolioOptimizationUnit> {
        val deduped = cases
            .groupBy { case ->
                val programId = case.summary.policyGovernanceProgramId
                    ?: case.summary.workflowTemplateId
                    ?: "program_${case.summary.runId}"
                val waveId = case.summary.rolloutWaveId ?: case.summary.runId
                "$programId::$waveId"
            }
            .values
            .mapNotNull { grouped ->
                grouped.maxWithOrNull(
                    compareBy<GovernanceCaseRecord> { it.summary.lastEventAtMs }
                        .thenBy { it.summary.runId }
                )
            }
            .sortedWith(
                compareBy<GovernanceCaseRecord>(
                    { it.summary.policyGovernanceProgramId ?: it.summary.workflowTemplateId ?: it.summary.runId },
                    { it.summary.rolloutWaveId ?: it.summary.runId },
                    { it.summary.runId }
                )
            )
        return deduped.map { case ->
            val summary = case.summary
            val programId = summary.policyGovernanceProgramId
                ?: summary.workflowTemplateId
                ?: "program_${summary.runId}"
            val priority = summary.programPriority ?: when (summary.priority) {
                GovernanceCasePriority.CRITICAL -> RolloutProgramPriority.CRITICAL
                GovernanceCasePriority.HIGH -> RolloutProgramPriority.HIGH
                GovernanceCasePriority.MEDIUM -> RolloutProgramPriority.MEDIUM
                GovernanceCasePriority.LOW -> RolloutProgramPriority.LOW
            }
            val riskPenalty = portfolioOptimizationRiskPenalty(
                case = case,
                parameterCalibration = parameterCalibration
            )
            PortfolioOptimizationUnit(
                sourceRunId = summary.runId,
                programId = programId,
                waveId = summary.rolloutWaveId,
                priority = priority,
                nextEligibleAtMs = listOf(
                    summary.scheduleNextEligibleAtMs,
                    summary.nextEligiblePromotionAtMs
                ).filterNotNull().filter { it > 0L }.minOrNull(),
                readinessStatus = summary.rolloutPromotionReadinessStatus,
                policyBlocked = summary.policyBlocked ||
                    summary.workflowRolloutApprovalState == PolicyRolloutApprovalState.DENIED ||
                    summary.scheduleBlockReason == ExecutionWindowBlockReason.SCHEDULE_SUPPRESSED,
                dependencyProgramIds = case.programCoordination?.dependencies
                    ?.map { it.dependsOnProgramId }
                    ?.filter { it.isNotBlank() }
                    ?.toSet()
                    .orEmpty(),
                dependencyBlocked = summary.programDependencyBlockedCount > 0 ||
                    case.programCoordination?.dependencies?.any { it.blocked } == true,
                windowBlockReason = summary.scheduleBlockReason,
                windowDelayReason = summary.windowDelayReason,
                capacityCost = if (summary.policyApprovalPending) 1 else 1,
                requiresApproval = summary.policyApprovalPending ||
                    summary.workflowRolloutApprovalState == PolicyRolloutApprovalState.PENDING,
                safeAutomationEligible = summary.automationEligible &&
                    !summary.automationApprovalRequired &&
                    !summary.automationSuppressed,
                escalated = summary.escalated || summary.slaStatus == WorkflowSlaStatus.BREACHED,
                slaSeverity = when (summary.slaStatus) {
                    WorkflowSlaStatus.BREACHED -> 3
                    WorkflowSlaStatus.APPROACHING_BREACH -> 2
                    WorkflowSlaStatus.ON_TIME -> 1
                    else -> 0
                },
                currentDeferred = summary.scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                    summary.programCoordinationState == RolloutProgramCoordinationState.DEFERRED,
                pinned = summary.crossTenantPinnedTargets > 0,
                criticalPath = priority == RolloutProgramPriority.CRITICAL ||
                    summary.escalated ||
                    summary.criticalCapacityReserved,
                riskPenalty = riskPenalty,
                riskBucket = portfolioOptimizationRiskBucket(riskPenalty),
                title = summary.title.ifBlank { summary.summary.ifBlank { summary.runId } }
            )
        }
    }

    private fun portfolioOptimizationRiskPenalty(
        case: GovernanceCaseRecord,
        parameterCalibration: PortfolioOptimizationParameterCalibration = PortfolioOptimizationParameterCalibration()
    ): Double {
        var risk = 0.0
        when (case.summary.rolloutPromotionReadinessStatus) {
            RolloutPromotionReadinessStatus.READY_WITH_CAUTION ->
                risk += 2.0 * parameterCalibration.readinessDelayPenaltyMultiplier
            RolloutPromotionReadinessStatus.BLOCKED,
            RolloutPromotionReadinessStatus.PAUSED,
            RolloutPromotionReadinessStatus.EXPIRED ->
                risk += 3.5 * parameterCalibration.readinessDelayPenaltyMultiplier
            else -> Unit
        }
        when (case.summary.crossWaveHealthBucket) {
            WaveHealthBucket.CAUTION -> risk += 1.5 * parameterCalibration.riskIncidentPenaltyMultiplier
            WaveHealthBucket.DEGRADED -> risk += 2.5 * parameterCalibration.riskIncidentPenaltyMultiplier
            WaveHealthBucket.BLOCKED -> risk += 3.5 * parameterCalibration.riskIncidentPenaltyMultiplier
            else -> Unit
        }
        if (case.connectorHealthSummary?.overallStatus?.contains("degraded", ignoreCase = true) == true ||
            case.connectorHealthSummary?.overallStatus?.contains("unavailable", ignoreCase = true) == true
        ) {
            risk += 3.0 * parameterCalibration.riskIncidentPenaltyMultiplier
        }
        when (case.lastConnectorCredentialLifecycle?.state) {
            ConnectorCredentialLifecycleState.EXPIRING ->
                risk += 1.5 * parameterCalibration.riskIncidentPenaltyMultiplier
            ConnectorCredentialLifecycleState.EXPIRED,
            ConnectorCredentialLifecycleState.REVOKED,
            ConnectorCredentialLifecycleState.ROTATION_REQUIRED,
            ConnectorCredentialLifecycleState.MISCONFIGURED ->
                risk += 2.5 * parameterCalibration.riskIncidentPenaltyMultiplier
            else -> Unit
        }
        if (case.summary.policyApprovalPending) {
            risk += 1.0 * parameterCalibration.approvalLatencyPenaltyMultiplier
        }
        if (case.summary.windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
            case.summary.windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW
        ) {
            risk += 1.0 * parameterCalibration.windowMissPenaltyMultiplier
        }
        return risk
    }

    private fun portfolioOptimizationRiskBucket(
        riskPenalty: Double
    ): PortfolioOptimizationRiskBucket {
        return when {
            riskPenalty >= 6.0 -> PortfolioOptimizationRiskBucket.CRITICAL
            riskPenalty >= 4.0 -> PortfolioOptimizationRiskBucket.HIGH
            riskPenalty >= 2.0 -> PortfolioOptimizationRiskBucket.MODERATE
            else -> PortfolioOptimizationRiskBucket.LOW
        }
    }

    private fun portfolioOptimizationPriorityScore(
        unit: PortfolioOptimizationUnit,
        strategy: PortfolioOptimizationCandidateStrategy,
        objectiveWeights: Map<PortfolioOptimizationObjectiveFamily, Int>,
        seed: Long,
        iteration: Int
    ): Double {
        val priorityScore = rolloutProgramPrioritySeverity(unit.priority).toDouble() * 2.0
        val criticalBoost = if (unit.criticalPath) 4.0 else 0.0
        val slaBoost = unit.slaSeverity.toDouble() * 2.0
        val readinessBoost = when (unit.readinessStatus) {
            RolloutPromotionReadinessStatus.READY -> 2.5
            RolloutPromotionReadinessStatus.READY_WITH_CAUTION -> 1.0
            RolloutPromotionReadinessStatus.DEFERRED -> -0.5
            else -> -2.0
        }
        val riskPenalty = unit.riskPenalty
        val strategyBias = when (strategy) {
            PortfolioOptimizationCandidateStrategy.BALANCED_GREEDY ->
                priorityScore + criticalBoost + slaBoost + readinessBoost - riskPenalty
            PortfolioOptimizationCandidateStrategy.THROUGHPUT_BIASED ->
                priorityScore + readinessBoost + (objectiveWeights[PortfolioOptimizationObjectiveFamily.THROUGHPUT]
                    ?: 0) - (riskPenalty * 0.5)
            PortfolioOptimizationCandidateStrategy.RISK_AVERSE ->
                priorityScore + criticalBoost - (riskPenalty * 2.5)
            PortfolioOptimizationCandidateStrategy.SLA_RECOVERY ->
                priorityScore + criticalBoost + (slaBoost * 2.0) - riskPenalty
            PortfolioOptimizationCandidateStrategy.FAIRNESS_BALANCED ->
                priorityScore + readinessBoost - riskPenalty + if (unit.currentDeferred) 1.5 else 0.0
            PortfolioOptimizationCandidateStrategy.CRITICAL_PATH_FIRST ->
                priorityScore + (criticalBoost * 2.0) + slaBoost - (riskPenalty * 0.75)
        }
        val tieBreaker = deterministicPortfolioOptimizationBias(
            seed = seed,
            iteration = iteration,
            key = "${unit.programId}:${unit.waveId.orEmpty()}:${strategy.name}"
        )
        return strategyBias + tieBreaker
    }

    private fun deterministicPortfolioOptimizationBias(
        seed: Long,
        iteration: Int,
        key: String
    ): Double {
        val hash = key.hashCode().toLong()
        val mixed = (seed * 37L) + (iteration * 17L) + (hash * 13L)
        val bounded = kotlin.math.abs(mixed % 1000L)
        return bounded.toDouble() / 1000.0
    }

    private fun portfolioOptimizationEarliestBucket(
        startAtMs: Long,
        bucketMs: Long,
        nextEligibleAtMs: Long?
    ): Int {
        if (nextEligibleAtMs == null || nextEligibleAtMs <= startAtMs) return 0
        val delta = nextEligibleAtMs - startAtMs
        return ((delta + bucketMs - 1L) / bucketMs).toInt()
    }

    private fun portfolioOptimizationConstraintEnabled(
        profile: PortfolioOptimizationConstraintProfile,
        family: PortfolioOptimizationConstraintFamily
    ): Boolean {
        return profile.constraints.firstOrNull { it.family == family }?.enabled ?: false
    }

    private fun portfolioOptimizationRiskLimit(
        profile: PortfolioOptimizationConstraintProfile
    ): Int {
        return profile.constraints.firstOrNull {
            it.family == PortfolioOptimizationConstraintFamily.MAX_CONCURRENT_RISKY_PROMOTIONS
        }?.intLimit ?: when (profile.riskTolerance) {
            PortfolioOptimizationRiskTolerance.LOW -> 0
            PortfolioOptimizationRiskTolerance.MODERATE -> 1
            PortfolioOptimizationRiskTolerance.HIGH -> 2
        }
    }

    private fun portfolioOptimizationAutomationLimit(
        profile: PortfolioOptimizationConstraintProfile
    ): Int {
        return profile.constraints.firstOrNull {
            it.family == PortfolioOptimizationConstraintFamily.MAX_AUTOMATION_ACTIONS_PER_WINDOW
        }?.intLimit ?: 1
    }

    private fun portfolioOptimizationObjectiveWeightMap(
        profile: PortfolioOptimizationObjectiveProfile
    ): Map<PortfolioOptimizationObjectiveFamily, Int> {
        return profile.weights.associate { it.family to it.weight.coerceIn(0, 10) }
    }

    private fun buildDeferredPortfolioOptimizationAction(
        unit: PortfolioOptimizationUnit,
        blockedBy: PortfolioOptimizationConstraintFamily,
        reasonCode: String,
        summary: String
    ): PortfolioOptimizationDeferredAction {
        return PortfolioOptimizationDeferredAction(
            sourceRunId = unit.sourceRunId,
            programId = unit.programId,
            waveId = unit.waveId,
            blockedBy = blockedBy,
            nextEligibleAtMs = unit.nextEligibleAtMs,
            reasonCodes = listOf(reasonCode),
            summary = summary
        )
    }

    private fun collapsePortfolioOptimizationBindingEvents(
        events: List<PortfolioOptimizationBindingEvent>
    ): List<PortfolioOptimizationBindingConstraintSummary> {
        return events.groupBy { event ->
            listOf(
                event.family.name,
                event.programId.orEmpty(),
                event.waveId.orEmpty(),
                event.bucketIndex?.toString().orEmpty(),
                event.reasonCode
            ).joinToString("|")
        }.values
            .map { grouped ->
                val first = grouped.first()
                PortfolioOptimizationBindingConstraintSummary(
                    family = first.family,
                    hardConstraint = first.family != PortfolioOptimizationConstraintFamily.MAX_AUTOMATION_ACTIONS_PER_WINDOW,
                    bucketIndex = first.bucketIndex,
                    programId = first.programId,
                    waveId = first.waveId,
                    bindingCount = grouped.size,
                    reasonCodes = grouped.map { it.reasonCode }.distinct(),
                    summary = first.summary
                )
            }
            .sortedWith(
                compareByDescending<PortfolioOptimizationBindingConstraintSummary> { it.bindingCount }
                    .thenBy { it.family.name }
            )
            .take(8)
    }

    private fun attachPortfolioOptimizationTradeoffs(
        candidates: List<PortfolioOptimizationCandidateSchedule>,
        objectiveProfile: PortfolioOptimizationObjectiveProfile
    ): List<PortfolioOptimizationCandidateSchedule> {
        if (candidates.isEmpty()) return emptyList()
        val primaryObjective = objectiveProfile.weights
            .maxByOrNull { it.weight }
            ?.family
            ?: PortfolioOptimizationObjectiveFamily.THROUGHPUT
        val best = candidates.maxByOrNull { it.score.weightedTotalScore } ?: return candidates
        val highestThroughput = candidates.maxByOrNull { it.score.throughputScore }
        val safest = candidates.maxByOrNull { it.score.riskScore }
        val highestSla = candidates.maxByOrNull { it.score.slaScore }
        return candidates.map { candidate ->
            val explanations = mutableListOf<PortfolioOptimizationTradeoffExplanation>()
            if (candidate.candidateId == best.candidateId) {
                if (highestThroughput != null &&
                    highestThroughput.candidateId != candidate.candidateId &&
                    highestThroughput.score.throughputScore > candidate.score.throughputScore
                ) {
                    explanations += PortfolioOptimizationTradeoffExplanation(
                        primaryObjective = PortfolioOptimizationObjectiveFamily.RISK,
                        secondaryObjective = PortfolioOptimizationObjectiveFamily.THROUGHPUT,
                        direction = PortfolioOptimizationTradeoffDirection.IMPROVES_PRIMARY_WORSENS_SECONDARY,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_TRADEOFF_THROUGHPUT_FOR_RISK),
                        summary = "Reduces risk versus the highest-throughput alternative, but completes less work immediately."
                    )
                }
            } else {
                if (candidate.score.throughputScore > best.score.throughputScore &&
                    candidate.score.riskScore < best.score.riskScore
                ) {
                    explanations += PortfolioOptimizationTradeoffExplanation(
                        primaryObjective = PortfolioOptimizationObjectiveFamily.THROUGHPUT,
                        secondaryObjective = PortfolioOptimizationObjectiveFamily.RISK,
                        direction = PortfolioOptimizationTradeoffDirection.IMPROVES_PRIMARY_WORSENS_SECONDARY,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_TRADEOFF_RISK_FOR_THROUGHPUT),
                        summary = "Improves throughput compared with the top balanced schedule, but accepts higher risk exposure."
                    )
                }
                if (candidate.score.riskScore > best.score.riskScore &&
                    candidate.score.throughputScore < best.score.throughputScore
                ) {
                    explanations += PortfolioOptimizationTradeoffExplanation(
                        primaryObjective = PortfolioOptimizationObjectiveFamily.RISK,
                        secondaryObjective = PortfolioOptimizationObjectiveFamily.THROUGHPUT,
                        direction = PortfolioOptimizationTradeoffDirection.IMPROVES_PRIMARY_WORSENS_SECONDARY,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_TRADEOFF_THROUGHPUT_FOR_RISK),
                        summary = "Lowers risk more aggressively than the top balanced schedule, but defers additional throughput."
                    )
                }
                if (candidate.score.slaScore > best.score.slaScore &&
                    candidate.score.stabilityScore < best.score.stabilityScore
                ) {
                    explanations += PortfolioOptimizationTradeoffExplanation(
                        primaryObjective = PortfolioOptimizationObjectiveFamily.SLA,
                        secondaryObjective = PortfolioOptimizationObjectiveFamily.STABILITY,
                        direction = PortfolioOptimizationTradeoffDirection.IMPROVES_PRIMARY_WORSENS_SECONDARY,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_PORTFOLIO_OPTIMIZATION_TRADEOFF_SLA_FOR_STABILITY),
                        summary = "Pulls SLA-sensitive work forward, but introduces more schedule churn."
                    )
                }
            }
            if (explanations.isEmpty()) {
                explanations += PortfolioOptimizationTradeoffExplanation(
                    primaryObjective = primaryObjective,
                    secondaryObjective = PortfolioOptimizationObjectiveFamily.STABILITY,
                    direction = PortfolioOptimizationTradeoffDirection.BALANCES_PRIMARY_AND_SECONDARY,
                    summary = "Balances the primary objective against hard constraints without violating bounded governance rules."
                )
            }
            candidate.copy(tradeoffExplanations = explanations.take(3))
        }
    }

    private fun computePortfolioOptimizationParetoFrontier(
        candidates: List<PortfolioOptimizationCandidateSchedule>
    ): PortfolioOptimizationParetoFrontierSummary {
        if (candidates.isEmpty()) {
            return PortfolioOptimizationParetoFrontierSummary(
                summary = "No optimization candidates were generated."
            )
        }
        fun dominates(
            left: PortfolioOptimizationCandidateSchedule,
            right: PortfolioOptimizationCandidateSchedule
        ): Boolean {
            val leftScore = left.score
            val rightScore = right.score
            val noWorse = leftScore.throughputScore >= rightScore.throughputScore &&
                leftScore.riskScore >= rightScore.riskScore &&
                leftScore.slaScore >= rightScore.slaScore &&
                leftScore.weightedTotalScore >= rightScore.weightedTotalScore
            val strictlyBetter = leftScore.throughputScore > rightScore.throughputScore ||
                leftScore.riskScore > rightScore.riskScore ||
                leftScore.slaScore > rightScore.slaScore ||
                leftScore.weightedTotalScore > rightScore.weightedTotalScore
            return noWorse && strictlyBetter
        }
        val frontier = candidates.filter { candidate ->
            candidates.none { other -> other.candidateId != candidate.candidateId && dominates(other, candidate) }
        }
        val dominated = candidates.filterNot { candidate ->
            frontier.any { it.candidateId == candidate.candidateId }
        }
        return PortfolioOptimizationParetoFrontierSummary(
            frontierCandidateIds = frontier.map { it.candidateId },
            dominatedCandidateIds = dominated.map { it.candidateId },
            summary = "Pareto frontier contains ${frontier.size} candidate(s) out of ${candidates.size}."
        )
    }

    private fun portfolioOptimizationCandidateSignature(
        candidate: PortfolioOptimizationCandidateSchedule
    ): String {
        val scheduled = candidate.scheduledActions.joinToString("|") { action ->
            listOf(
                action.type.name,
                action.programId,
                action.waveId.orEmpty(),
                action.scheduledBucketIndex.toString()
            ).joinToString(":")
        }
        val deferred = candidate.deferredActions.joinToString("|") { action ->
            listOf(
                action.programId,
                action.waveId.orEmpty(),
                action.blockedBy.name
            ).joinToString(":")
        }
        return "$scheduled#$deferred"
    }

    private fun approvalLoadBucketSeverity(bucket: ApprovalLoadBucket): Int {
        return when (bucket) {
            ApprovalLoadBucket.IDLE -> 0
            ApprovalLoadBucket.BALANCED -> 1
            ApprovalLoadBucket.ELEVATED -> 2
            ApprovalLoadBucket.HIGH -> 3
            ApprovalLoadBucket.SATURATED -> 4
        }
    }

    private fun rolloutProgramPrioritySeverity(priority: RolloutProgramPriority): Int {
        return when (priority) {
            RolloutProgramPriority.LOW -> 0
            RolloutProgramPriority.MEDIUM -> 1
            RolloutProgramPriority.HIGH -> 2
            RolloutProgramPriority.CRITICAL -> 3
        }
    }

    private fun utcDayStartMs(epochMs: Long): Long {
        val date = Instant.ofEpochMilli(epochMs).atZone(ZoneOffset.UTC).toLocalDate()
        return date
            .atStartOfDay()
            .toInstant(ZoneOffset.UTC)
            .toEpochMilli()
    }

    fun markGovernanceCaseReviewed(userId: String, runId: String): GovernanceActionResult {
        if (userId.isBlank() || runId.isBlank()) {
            return GovernanceActionResult(
                action = GovernanceActionType.MARK_REVIEWED,
                runId = runId,
                success = false,
                message = "Missing user or run identity for review action.",
                timestampMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val operatorResolution = resolveOperatorContext(fallbackUserId = userId)
        val operatorIdentity = operatorResolution.identity
        val currentState = synchronized(dynamicStateLock) {
            collaborationStateForRunLocked(userId, runId)
        }
        val permissionDecision = authorizeOperatorAction(
            action = GovernanceActionType.MARK_REVIEWED,
            identity = operatorIdentity,
            currentState = currentState
        )
        if (!permissionDecision.allowed) {
            val recorded = synchronized(dynamicStateLock) {
                recordPermissionDeniedLocked(
                    userId = userId,
                    runId = runId,
                    action = GovernanceActionType.MARK_REVIEWED,
                    actor = OperatorAssigneeRef(
                        userId = operatorIdentity.userId,
                        displayName = operatorIdentity.displayName
                    ),
                    denialReason = permissionDecision.denialReason
                        ?: OperatorPermissionDenialReason.PERMISSION_MISSING,
                    message = permissionDecision.message,
                    requiredPermission = permissionDecision.requiredPermission,
                    now = now
                )
            }
            if (recorded) persistDynamicState(userId)
            return GovernanceActionResult(
                action = GovernanceActionType.MARK_REVIEWED,
                runId = runId,
                success = false,
                message = permissionDecision.message,
                denialReason = permissionDecision.denialReason,
                requiredPermission = permissionDecision.requiredPermission,
                operatorIdentity = operatorIdentity,
                timestampMs = now
            )
        }
        val remoteAuthorization = synchronized(dynamicStateLock) {
            authorizeRemoteOperatorActionLocked(
                userId = userId,
                action = GovernanceActionType.MARK_REVIEWED,
                identity = operatorIdentity,
                requiredPermission = permissionDecision.requiredPermission,
                command = null,
                currentState = currentState
            )
        }
        if (!remoteAuthorization.result.allowed) {
            val denialMessage = remoteAuthorization.result.reason.ifBlank {
                "Remote authorization denied for mark reviewed."
            }
            val recorded = synchronized(dynamicStateLock) {
                recordPermissionDeniedLocked(
                    userId = userId,
                    runId = runId,
                    action = GovernanceActionType.MARK_REVIEWED,
                    actor = OperatorAssigneeRef(
                        userId = operatorIdentity.userId,
                        displayName = operatorIdentity.displayName
                    ),
                    denialReason = remoteAuthorization.denialReason ?: OperatorPermissionDenialReason.REMOTE_AUTH_DENIED,
                    message = denialMessage,
                    requiredPermission = permissionDecision.requiredPermission,
                    now = now
                )
            }
            if (recorded) persistDynamicState(userId)
            return GovernanceActionResult(
                action = GovernanceActionType.MARK_REVIEWED,
                runId = runId,
                success = false,
                message = denialMessage,
                denialReason = remoteAuthorization.denialReason ?: OperatorPermissionDenialReason.REMOTE_AUTH_DENIED,
                requiredPermission = permissionDecision.requiredPermission,
                operatorIdentity = operatorIdentity,
                remoteAuthorizationResult = remoteAuthorization.result,
                timestampMs = now
            )
        }
        val updated = synchronized(dynamicStateLock) {
            val deque = executionLedgerByUser[userId] ?: return@synchronized false
            val records = deque.toMutableList()
            val targetIndex = records.indexOfLast { it.runId == runId }
            if (targetIndex < 0) return@synchronized false
            val target = records[targetIndex]
            val alreadyReviewed = target.runEvents.any { it.type == ProofLedgerEventType.OPERATOR_MARKED_REVIEWED }
            if (alreadyReviewed) return@synchronized true
            val remoteAuthEvent = RunEventRecord(
                eventId = "remote_auth_${runId}_mark_reviewed_${remoteAuthorization.result.evaluatedAtMs}",
                type = ProofLedgerEventType.REMOTE_OPERATOR_AUTH_ALLOWED,
                title = "Remote operator authorization allowed",
                detail = remoteAuthorization.result.reason,
                timestampMs = remoteAuthorization.result.evaluatedAtMs.takeIf { it > 0 } ?: now,
                reasonCodes = remoteAuthorization.result.reasonCodes
            )
            val updatedRecord = target.copy(
                runEvents = target.runEvents + remoteAuthEvent + RunEventRecord(
                    eventId = "operator_review_${runId}_$now",
                    type = ProofLedgerEventType.OPERATOR_MARKED_REVIEWED,
                    title = "Operator marked case reviewed",
                    detail = "Case was marked reviewed in the internal governance console.",
                    timestampMs = now,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_OPERATOR_CASE_REVIEWED)
                ),
                remoteAuthorizationResult = remoteAuthorization.result,
                operatorConnectorAudit = buildOperatorConnectorAuditLink(
                    operatorIdentity = operatorIdentity,
                    directoryEntry = operatorResolution.directoryEntry,
                    remoteAuthorization = remoteAuthorization.result,
                    routingRecord = target.alertRoutingRecords.lastOrNull(),
                    now = now
                ),
                receipt = target.receipt?.copy(
                    remoteAuthorizationSummary = remoteAuthorizationSummaryFor(remoteAuthorization.result),
                    directorySyncSummary = directorySyncSummaryFor(remoteAuthorization.result, target.alertRoutingRecords),
                    sessionAuthProvenanceSummary = sessionAuthProvenanceSummaryFor(remoteAuthorization.result),
                    connectorCredentialSummary = connectorCredentialSummaryFor(target.alertRoutingRecords),
                    enterpriseIdentitySummary = remoteAuthorization.result.sessionAuthContext?.identityAssertion?.summary
                        ?: target.receipt?.enterpriseIdentitySummary,
                    enterpriseSessionSummary = remoteAuthorization.result.sessionAuthContext?.sessionProvenance
                        ?.name
                        ?.lowercase()
                        ?.replace('_', ' ')
                        ?.let { "Enterprise session $it." }
                        ?: target.receipt?.enterpriseSessionSummary,
                    scimDirectorySummary = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration?.directoryUpdate?.summary }
                        .lastOrNull()
                        ?: target.receipt?.scimDirectorySummary,
                    vaultCredentialSummary = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration?.credentialBinding?.vaultCredential?.summary }
                        .lastOrNull()
                        ?: target.receipt?.vaultCredentialSummary,
                    enterpriseAuthIntegration = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration }
                        .maxByOrNull { it.directoryUpdate?.processedAtMs ?: it.directorySync?.syncedAtMs ?: 0L }
                        ?: target.receipt?.enterpriseAuthIntegration,
                    operatorIdentityProvenance = buildOperatorConnectorAuditLink(
                        operatorIdentity = operatorIdentity,
                        directoryEntry = operatorResolution.directoryEntry,
                        remoteAuthorization = remoteAuthorization.result,
                        routingRecord = target.alertRoutingRecords.lastOrNull(),
                        now = now
                    )?.identityProvenance,
                    remoteAuthProvenance = remoteAuthorization.result.provenance,
                    sessionAuthContext = remoteAuthorization.result.sessionAuthContext,
                    operatorConnectorAudit = buildOperatorConnectorAuditLink(
                        operatorIdentity = operatorIdentity,
                        directoryEntry = operatorResolution.directoryEntry,
                        remoteAuthorization = remoteAuthorization.result,
                        routingRecord = target.alertRoutingRecords.lastOrNull(),
                        now = now
                    )
                ),
                updatedAtMs = now
            )
            records[targetIndex] = updatedRecord
            executionLedgerByUser[userId] = ArrayDeque(records)
            true
        }
        if (updated) {
            persistDynamicState(userId)
        }
        return GovernanceActionResult(
            action = GovernanceActionType.MARK_REVIEWED,
            runId = runId,
            success = updated,
            message = if (updated) {
                "Marked case as reviewed."
            } else {
                "Case not found."
            },
            operatorIdentity = operatorIdentity,
            remoteAuthorizationResult = remoteAuthorization.result,
            timestampMs = now
        )
    }

    fun retryGovernanceSyncIntent(userId: String, runId: String): GovernanceActionResult {
        if (userId.isBlank() || runId.isBlank()) {
            return GovernanceActionResult(
                action = GovernanceActionType.RETRY_SYNC_INTENT,
                runId = runId,
                success = false,
                message = "Missing user or run identity for retry action.",
                timestampMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = nowMs()
        val operatorResolution = resolveOperatorContext(fallbackUserId = userId)
        val operatorIdentity = operatorResolution.identity
        val currentState = synchronized(dynamicStateLock) {
            collaborationStateForRunLocked(userId, runId)
        }
        val permissionDecision = authorizeOperatorAction(
            action = GovernanceActionType.RETRY_SYNC_INTENT,
            identity = operatorIdentity,
            currentState = currentState
        )
        if (!permissionDecision.allowed) {
            val recorded = synchronized(dynamicStateLock) {
                recordPermissionDeniedLocked(
                    userId = userId,
                    runId = runId,
                    action = GovernanceActionType.RETRY_SYNC_INTENT,
                    actor = OperatorAssigneeRef(
                        userId = operatorIdentity.userId,
                        displayName = operatorIdentity.displayName
                    ),
                    denialReason = permissionDecision.denialReason
                        ?: OperatorPermissionDenialReason.PERMISSION_MISSING,
                    message = permissionDecision.message,
                    requiredPermission = permissionDecision.requiredPermission,
                    now = now
                )
            }
            if (recorded) persistDynamicState(userId)
            return GovernanceActionResult(
                action = GovernanceActionType.RETRY_SYNC_INTENT,
                runId = runId,
                success = false,
                message = permissionDecision.message,
                denialReason = permissionDecision.denialReason,
                requiredPermission = permissionDecision.requiredPermission,
                operatorIdentity = operatorIdentity,
                timestampMs = now
            )
        }
        val remoteAuthorization = synchronized(dynamicStateLock) {
            authorizeRemoteOperatorActionLocked(
                userId = userId,
                action = GovernanceActionType.RETRY_SYNC_INTENT,
                identity = operatorIdentity,
                requiredPermission = permissionDecision.requiredPermission,
                command = null,
                currentState = currentState
            )
        }
        if (!remoteAuthorization.result.allowed) {
            val denialMessage = remoteAuthorization.result.reason.ifBlank {
                "Remote authorization denied for retry sync."
            }
            val recorded = synchronized(dynamicStateLock) {
                recordPermissionDeniedLocked(
                    userId = userId,
                    runId = runId,
                    action = GovernanceActionType.RETRY_SYNC_INTENT,
                    actor = OperatorAssigneeRef(
                        userId = operatorIdentity.userId,
                        displayName = operatorIdentity.displayName
                    ),
                    denialReason = remoteAuthorization.denialReason ?: OperatorPermissionDenialReason.REMOTE_AUTH_DENIED,
                    message = denialMessage,
                    requiredPermission = permissionDecision.requiredPermission,
                    now = now
                )
            }
            if (recorded) persistDynamicState(userId)
            return GovernanceActionResult(
                action = GovernanceActionType.RETRY_SYNC_INTENT,
                runId = runId,
                success = false,
                message = denialMessage,
                denialReason = remoteAuthorization.denialReason ?: OperatorPermissionDenialReason.REMOTE_AUTH_DENIED,
                requiredPermission = permissionDecision.requiredPermission,
                operatorIdentity = operatorIdentity,
                remoteAuthorizationResult = remoteAuthorization.result,
                timestampMs = now
            )
        }
        val updatedRecord: ExecutionReceiptRecord? = synchronized(dynamicStateLock) {
            val deque = executionLedgerByUser[userId] ?: return@synchronized null
            val records = deque.toMutableList()
            val targetIndex = records.indexOfLast { it.runId == runId }
            if (targetIndex < 0) return@synchronized null
            val target = records[targetIndex]
            val remoteAuthEvent = RunEventRecord(
                eventId = "remote_auth_${runId}_retry_sync_${remoteAuthorization.result.evaluatedAtMs}",
                type = ProofLedgerEventType.REMOTE_OPERATOR_AUTH_ALLOWED,
                title = "Remote operator authorization allowed",
                detail = remoteAuthorization.result.reason,
                timestampMs = remoteAuthorization.result.evaluatedAtMs.takeIf { it > 0 } ?: now,
                reasonCodes = remoteAuthorization.result.reasonCodes
            )
            val retryEvent = RunEventRecord(
                eventId = "operator_retry_${runId}_$now",
                type = ProofLedgerEventType.OPERATOR_SYNC_RETRY_REQUESTED,
                title = "Operator requested sync retry",
                detail = "Manual sync retry was requested for reconciliation/dispute follow-up.",
                timestampMs = now,
                reasonCodes = listOf(
                    RoleReasonCodes.ROLE_OPERATOR_SYNC_RETRY_REQUESTED,
                    RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY
                )
            )
            val currentReconciliation = target.reconciliationSummary
            val currentSettlement = target.settlementRecord
            val reconciliation = currentReconciliation?.copy(
                result = SettlementReconciliationResult.RETRY_SCHEDULED,
                retryScheduled = true,
                summary = "Operator requested a sync retry. Local state remains authoritative until remote acknowledgement.",
                reasonCodes = (currentReconciliation.reasonCodes + RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY)
                    .distinct(),
                lastCheckedAtMs = now
            ) ?: MarketplaceReconciliationSummary(
                result = SettlementReconciliationResult.RETRY_SCHEDULED,
                syncState = syncStateFor(target),
                summary = "Operator requested a sync retry. Local state remains authoritative until remote acknowledgement.",
                mismatchDetected = syncStateFor(target) == SettlementSyncState.MISMATCH,
                retryScheduled = true,
                reasonCodes = listOf(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY),
                lastCheckedAtMs = now
            )
            val currentReceipt = target.receipt
            val updatedRecord = target.copy(
                runEvents = target.runEvents + remoteAuthEvent + retryEvent,
                reconciliationSummary = reconciliation,
                settlementRecord = currentSettlement?.copy(
                    reconciliation = reconciliation,
                    reasonCodes = (currentSettlement.reasonCodes + RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_RETRY)
                        .distinct(),
                    recordedAtMs = now
                ),
                receipt = currentReceipt?.copy(
                    reconciliationSummary = reconciliation,
                    syncIssues = currentReceipt.syncIssues,
                    remoteAuthorizationSummary = remoteAuthorizationSummaryFor(remoteAuthorization.result),
                    directorySyncSummary = directorySyncSummaryFor(remoteAuthorization.result, target.alertRoutingRecords),
                    sessionAuthProvenanceSummary = sessionAuthProvenanceSummaryFor(remoteAuthorization.result),
                    connectorCredentialSummary = connectorCredentialSummaryFor(target.alertRoutingRecords),
                    enterpriseIdentitySummary = remoteAuthorization.result.sessionAuthContext?.identityAssertion?.summary
                        ?: currentReceipt.enterpriseIdentitySummary,
                    enterpriseSessionSummary = remoteAuthorization.result.sessionAuthContext?.sessionProvenance
                        ?.name
                        ?.lowercase()
                        ?.replace('_', ' ')
                        ?.let { "Enterprise session $it." }
                        ?: currentReceipt.enterpriseSessionSummary,
                    scimDirectorySummary = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration?.directoryUpdate?.summary }
                        .lastOrNull()
                        ?: currentReceipt.scimDirectorySummary,
                    vaultCredentialSummary = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration?.credentialBinding?.vaultCredential?.summary }
                        .lastOrNull()
                        ?: currentReceipt.vaultCredentialSummary,
                    enterpriseAuthIntegration = target.alertRoutingRecords
                        .mapNotNull { it.enterpriseAuthIntegration }
                        .maxByOrNull { it.directoryUpdate?.processedAtMs ?: it.directorySync?.syncedAtMs ?: 0L }
                        ?: currentReceipt.enterpriseAuthIntegration,
                    operatorConnectorAudit = buildOperatorConnectorAuditLink(
                        operatorIdentity = operatorIdentity,
                        directoryEntry = operatorResolution.directoryEntry,
                        remoteAuthorization = remoteAuthorization.result,
                        routingRecord = target.alertRoutingRecords.lastOrNull(),
                        now = now
                    ),
                    operatorIdentityProvenance = buildOperatorConnectorAuditLink(
                        operatorIdentity = operatorIdentity,
                        directoryEntry = operatorResolution.directoryEntry,
                        remoteAuthorization = remoteAuthorization.result,
                        routingRecord = target.alertRoutingRecords.lastOrNull(),
                        now = now
                    )?.identityProvenance,
                    remoteAuthProvenance = remoteAuthorization.result.provenance,
                    sessionAuthContext = remoteAuthorization.result.sessionAuthContext,
                    issueSummary = currentReceipt.issueSummary
                        ?.takeIf { it.isNotBlank() }
                        ?: "Manual sync retry requested by operator."
                ),
                remoteAuthorizationResult = remoteAuthorization.result,
                operatorConnectorAudit = buildOperatorConnectorAuditLink(
                    operatorIdentity = operatorIdentity,
                    directoryEntry = operatorResolution.directoryEntry,
                    remoteAuthorization = remoteAuthorization.result,
                    routingRecord = target.alertRoutingRecords.lastOrNull(),
                    now = now
                ),
                updatedAtMs = now
            )
            records[targetIndex] = updatedRecord
            executionLedgerByUser[userId] = ArrayDeque(records)
            updatedRecord
        }
        if (updatedRecord != null) {
            updateRemotePipelineRecords(
                userId = userId,
                record = updatedRecord,
                forceReconciliationRetry = true
            )
            persistDynamicState(userId)
        }
        return GovernanceActionResult(
            action = GovernanceActionType.RETRY_SYNC_INTENT,
            runId = runId,
            success = updatedRecord != null,
            message = if (updatedRecord != null) {
                "Sync retry intent recorded for operator follow-up."
            } else {
                "Case not found."
            },
            operatorIdentity = operatorIdentity,
            remoteAuthorizationResult = remoteAuthorization.result,
            timestampMs = now
        )
    }

    fun updateGovernanceCaseCollaboration(
        userId: String,
        runId: String,
        command: GovernanceCollaborationCommand
    ): GovernanceActionResult {
        if (userId.isBlank() || runId.isBlank()) {
            return GovernanceActionResult(
                action = command.commandType,
                runId = runId,
                success = false,
                message = "Missing user or run identity for collaboration action.",
                timestampMs = nowMs()
            )
        }
        restoreDynamicStateIfNeeded(userId)
        val now = command.timestampMs.takeIf { it > 0 } ?: nowMs()
        val actor = command.toActor()
        val operatorResolution = resolveOperatorContext(command = command, fallbackUserId = userId)
        val operatorIdentity = operatorResolution.identity
        val result = synchronized(dynamicStateLock) {
            val ledger = executionLedgerByUser[userId] ?: return@synchronized CollaborationMutationResult(
                success = false,
                message = "Case not found."
            )
            val records = ledger.toMutableList()
            val targetIndex = records.indexOfLast { it.runId == runId }
            if (targetIndex < 0) {
                return@synchronized CollaborationMutationResult(
                    success = false,
                    message = "Case not found."
                )
            }
            val target = records[targetIndex]
            val currentCollaboration = target.collaborationState
                ?: collaborationStateForRunLocked(userId, runId)
                ?: GovernanceCaseCollaborationState(runId = runId, updatedAtMs = now)
            val currentHandoff = target.remoteOperatorHandoff
                ?: remoteOperatorHandoffForRunLocked(userId, runId)
            val permissionDecision = authorizeOperatorAction(
                action = command.commandType,
                identity = operatorIdentity,
                currentState = currentCollaboration,
                command = command
            )
            val mutation = if (!permissionDecision.allowed) {
                val denialReason = permissionDecision.denialReason
                    ?: OperatorPermissionDenialReason.PERMISSION_MISSING
                val denialRecord = OperatorPermissionDenialRecord(
                    denialId = "denial_${runId}_${command.commandType.name.lowercase()}_$now",
                    action = command.commandType,
                    reason = denialReason,
                    message = permissionDecision.message,
                    actor = actor,
                    timestampMs = now
                )
                val denialState = currentCollaboration.copy(
                    operatorSession = buildOperatorSessionSummary(
                        identity = operatorIdentity,
                        now = now
                    ),
                    permissionDenials = (currentCollaboration.permissionDenials + denialRecord).takeLast(20),
                    lastActionSummary = permissionDecision.message,
                    updatedAtMs = now
                )
                CollaborationMutationResult(
                    success = false,
                    message = permissionDecision.message,
                    updatedCollaborationState = denialState,
                    event = RunEventRecord(
                        eventId = "perm_denied_${runId}_${command.commandType.name.lowercase()}_$now",
                        type = ProofLedgerEventType.OPERATOR_PERMISSION_DENIED,
                        title = "Operator permission denied",
                        detail = permissionDecision.message,
                        timestampMs = now,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_OPERATOR_PERMISSION_DENIED)
                    ),
                    denialReason = denialReason,
                    requiredPermission = permissionDecision.requiredPermission,
                    operatorIdentity = operatorIdentity
                )
            } else {
                val remoteAuthorization = authorizeRemoteOperatorActionLocked(
                    userId = userId,
                    action = command.commandType,
                    identity = operatorIdentity,
                    requiredPermission = permissionDecision.requiredPermission,
                    command = command,
                    currentState = currentCollaboration
                )
                if (!remoteAuthorization.result.allowed) {
                    val denialReason = remoteAuthorization.denialReason
                        ?: OperatorPermissionDenialReason.REMOTE_AUTH_DENIED
                    val denialMessage = remoteAuthorization.result.reason.ifBlank {
                        "Remote authorization denied for ${command.commandType.name.lowercase().replace('_', ' ')}."
                    }
                    val denialRecord = OperatorPermissionDenialRecord(
                        denialId = "remote_denial_${runId}_${command.commandType.name.lowercase()}_$now",
                        action = command.commandType,
                        reason = denialReason,
                        message = denialMessage,
                        actor = actor,
                        timestampMs = now
                    )
                    val denialState = currentCollaboration.copy(
                        operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization.result
                        ),
                        permissionDenials = (currentCollaboration.permissionDenials + denialRecord).takeLast(20),
                        lastActionSummary = denialMessage,
                        updatedAtMs = now
                    )
                    CollaborationMutationResult(
                        success = false,
                        message = denialMessage,
                        updatedCollaborationState = denialState,
                        event = RunEventRecord(
                            eventId = "remote_auth_denied_${runId}_${command.commandType.name.lowercase()}_$now",
                            type = ProofLedgerEventType.REMOTE_OPERATOR_AUTH_DENIED,
                            title = "Remote operator authorization denied",
                            detail = denialMessage,
                            timestampMs = now,
                            reasonCodes = remoteAuthorization.result.reasonCodes.ifEmpty {
                                listOf(RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED)
                            }
                        ),
                        denialReason = denialReason,
                        requiredPermission = remoteAuthorization.result.requiredPermission,
                        operatorIdentity = operatorIdentity,
                        remoteAuthorizationResult = remoteAuthorization.result
                    )
                } else {
                    mutateCollaborationState(
                        userId = userId,
                        command = command,
                        actor = actor,
                        operatorIdentity = operatorIdentity,
                        operatorResolution = operatorResolution,
                        remoteAuthorization = remoteAuthorization.result,
                        runId = runId,
                        now = now,
                        currentState = currentCollaboration,
                        currentHandoff = currentHandoff
                    )
                }
            }
            if (
                !mutation.success &&
                mutation.updatedCollaborationState == null &&
                mutation.updatedRemoteHandoff == null &&
                mutation.updatedAlertRoutingRecords.isEmpty() &&
                mutation.event == null
            ) {
                return@synchronized mutation
            }

            mutation.updatedCollaborationState?.let { upsertCollaborationStateLocked(userId, it) }
            mutation.updatedRemoteHandoff?.let { upsertRemoteOperatorHandoffRecordLocked(userId, it) }
            mutation.updatedAlertRoutingRecords.forEach { upsertAlertRoutingRecordLocked(userId, it) }

            val finalCollaboration = mutation.updatedCollaborationState
                ?: collaborationStateForRunLocked(userId, runId)
            val finalHandoff = mutation.updatedRemoteHandoff
                ?: remoteOperatorHandoffForRunLocked(userId, runId)
            val finalRouting = alertRoutingForRunLocked(userId, runId)
            val handoffSummary = buildRemoteOperatorHandoffSummary(finalHandoff)
            val routingSummary = buildAlertRoutingSummary(finalRouting)
            val connectorRoutingSummary = buildConnectorRoutingSummary(finalRouting)
                ?: mutation.connectorRoutingSummary
            val connectorHealthSummary = connectorRoutingSummary?.connectorHealthSummary
                ?: finalRouting
                    .mapNotNull { it.connectorHealthSummary }
                    .maxByOrNull { it.lastUpdatedAtMs }
            val deadLetterRecords = finalRouting
                .flatMap { it.deadLetterRecords }
                .distinctBy { "${it.targetId}:${it.providerType}:${it.dedupeKey}:${it.createdAtMs}" }
            val deadLetterSummary = deadLetterSummaryForRouting(
                routing = finalRouting,
                connectorSummary = connectorRoutingSummary,
                deadLetters = deadLetterRecords
            )
            val event = mutation.event
            val existingEvents = target.runEvents.toMutableList()
            if (event != null && existingEvents.any { it.eventId == event.eventId }) {
                return@synchronized mutation.copy(
                    message = "Duplicate collaboration command suppressed."
                )
            }
            if (event != null && existingEvents.none { it.eventId == event.eventId }) {
                existingEvents += event
            }
            val remoteAuth = mutation.remoteAuthorizationResult
            if (
                remoteAuth != null &&
                existingEvents.none {
                    it.eventId == "remote_auth_${runId}_${command.commandType.name.lowercase()}_${remoteAuth.evaluatedAtMs}"
                }
            ) {
                existingEvents += RunEventRecord(
                    eventId = "remote_auth_${runId}_${command.commandType.name.lowercase()}_${remoteAuth.evaluatedAtMs}",
                    type = if (remoteAuth.allowed) {
                        ProofLedgerEventType.REMOTE_OPERATOR_AUTH_ALLOWED
                    } else {
                        ProofLedgerEventType.REMOTE_OPERATOR_AUTH_DENIED
                    },
                    title = if (remoteAuth.allowed) {
                        "Remote operator authorization allowed"
                    } else {
                        "Remote operator authorization denied"
                    },
                    detail = remoteAuth.reason.ifBlank { "Remote authorization evaluated for governance action." },
                    timestampMs = remoteAuth.evaluatedAtMs.takeIf { it > 0 } ?: now,
                    reasonCodes = remoteAuth.reasonCodes
                )
            }
            val routingEvents = buildCollaborationRoutingRunEvents(
                runId = runId,
                records = finalRouting,
                fallbackTimestampMs = now
            )
            routingEvents.forEach { routingEvent ->
                if (existingEvents.none { it.eventId == routingEvent.eventId }) {
                    existingEvents += routingEvent
                }
            }
            val resolvedWaveIdForReceipt = finalCollaboration?.workflowRun?.policyRolloutState?.currentRolloutWaveId
                ?: target.receipt?.currentRolloutWaveId
            val resolvedRolloutWindowEligibility = finalCollaboration?.workflowRun?.policyRolloutState
                ?.calendarAwarePromotionDecision
                ?.windowEligibility
                ?: target.receipt?.currentRolloutWindowEligibility
            val resolvedNextEligibleAtMs = finalCollaboration?.workflowRun?.policyRolloutState
                ?.calendarAwarePromotionDecision
                ?.nextEligibleWindow
                ?.nextEligibleAtMs
                ?: target.receipt?.workflowPolicyRolloutState?.calendarEvaluation?.nextEligibleAtMs
            val resolvedCarryForwardPending = finalCollaboration?.workflowRun?.policyRolloutState
                ?.rolloutWaves
                ?.firstOrNull { rolloutWave -> rolloutWave.waveId == resolvedWaveIdForReceipt }
                ?.carryForwardState
                ?.carryForwardPending
                ?: target.receipt?.rolloutCarryForwardPending
                ?: false
            val resolvedCrossWindowPauseState = finalCollaboration?.workflowRun?.policyRolloutState
                ?.crossWindowGovernanceControl
                ?.pauseState
                ?: target.receipt?.workflowPolicyRolloutState?.crossWindowGovernanceControl?.pauseState
            val resolvedNextWindowPending = (
                resolvedRolloutWindowEligibility != null &&
                    resolvedRolloutWindowEligibility != PromotionWindowEligibility.ELIGIBLE
                ) && (
                (resolvedNextEligibleAtMs != null && resolvedNextEligibleAtMs > 0L) ||
                    resolvedCarryForwardPending
                )
            val resolvedRolloutStateForReceipt = finalCollaboration?.workflowRun?.policyRolloutState
                ?: target.receipt?.workflowPolicyRolloutState
            val updatedReceipt = target.receipt?.copy(
                remoteOperatorHandoffSummary = handoffSummary,
                alertRoutingSummary = routingSummary,
                connectorHealthSummary = connectorHealthSummary,
                deadLetterSummary = deadLetterSummary,
                connectorRoutingSummary = connectorRoutingSummary,
                workflowPolicySummary = finalCollaboration?.workflowRun?.workflowPolicySummary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.workflowPolicySummary,
                workflowPolicyPackId = finalCollaboration?.workflowRun?.policyPack?.packId
                    ?: target.receipt?.workflowPolicyPackId,
                workflowPolicyPackVersion = finalCollaboration?.workflowRun?.policyPackBinding?.versionId
                    ?: target.receipt?.workflowPolicyPackVersion,
                workflowPolicyBindingId = finalCollaboration?.workflowRun?.policyPackBinding?.bindingId
                    ?: target.receipt?.workflowPolicyBindingId,
                tenantWorkflowOverrideId = finalCollaboration?.workflowRun?.tenantOverride?.overrideId
                    ?: target.receipt?.tenantWorkflowOverrideId,
                workspaceWorkflowOverrideId = finalCollaboration?.workflowRun?.workspaceOverride?.overrideId
                    ?: target.receipt?.workspaceWorkflowOverrideId,
                workflowPolicyPrecedenceSource = finalCollaboration?.workflowRun?.policyResolution?.precedenceSource
                    ?: target.receipt?.workflowPolicyPrecedenceSource,
                workflowPolicyResolutionSummary = finalCollaboration?.workflowRun?.policyResolutionSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: finalCollaboration?.workflowRun?.policyResolution?.summary
                    ?: target.receipt?.workflowPolicyResolutionSummary,
                workflowPolicyResolutionReasonCodes = finalCollaboration?.workflowRun?.policyResolution?.reasonCodes
                    ?.takeIf { it.isNotEmpty() }
                    ?: target.receipt?.workflowPolicyResolutionReasonCodes.orEmpty(),
                workflowSimulationOnly = finalCollaboration?.workflowRun?.workflowSimulationOnly
                    ?: target.receipt?.workflowSimulationOnly,
                workflowPolicyRolloutState = finalCollaboration?.workflowRun?.policyRolloutState
                    ?: target.receipt?.workflowPolicyRolloutState,
                workflowRolloutStage = finalCollaboration?.workflowRun?.policyRolloutState?.stage
                    ?: target.receipt?.workflowRolloutStage,
                workflowRolloutMode = finalCollaboration?.workflowRun?.policyRolloutState?.mode
                    ?: target.receipt?.workflowRolloutMode,
                workflowRolloutScope = finalCollaboration?.workflowRun?.policyRolloutState?.target?.scope
                    ?: target.receipt?.workflowRolloutScope,
                workflowRolloutApprovalState = finalCollaboration?.workflowRun?.policyRolloutState?.approvalState
                    ?: target.receipt?.workflowRolloutApprovalState,
                workflowRolloutFreezeState = finalCollaboration?.workflowRun?.policyRolloutState?.freezeState
                    ?: target.receipt?.workflowRolloutFreezeState,
                workflowRolloutSummary = finalCollaboration?.workflowRun?.workflowRolloutSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.workflowRolloutSummary,
                workflowRolloutApprovalSummary = finalCollaboration?.workflowRun?.workflowRolloutApprovalSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.workflowRolloutApprovalSummary,
                workflowRolloutFreezeSummary = finalCollaboration?.workflowRun?.workflowRolloutFreezeSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.workflowRolloutFreezeSummary,
                workflowRolloutRollbackSummary = finalCollaboration?.workflowRun?.workflowRolloutRollbackSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.workflowRolloutRollbackSummary,
                rolloutWaveSummary = finalCollaboration?.workflowRun?.policyRolloutState?.rolloutWaveSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.rolloutWaveSummary,
                calendarAwarePromotionSummary = finalCollaboration?.workflowRun?.policyRolloutState
                    ?.calendarAwarePromotionDecision
                    ?.summary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.calendarAwarePromotionSummary,
                crossWindowGovernanceSummary = finalCollaboration?.workflowRun?.policyRolloutState
                    ?.crossWindowGovernanceSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.crossWindowGovernanceSummary,
                currentRolloutWaveId = finalCollaboration?.workflowRun?.policyRolloutState?.currentRolloutWaveId
                    ?: target.receipt?.currentRolloutWaveId,
                currentRolloutWaveStatus = finalCollaboration?.workflowRun?.policyRolloutState?.currentRolloutWaveStatus
                    ?: target.receipt?.currentRolloutWaveStatus,
                currentRolloutWaveCompletionState = finalCollaboration?.workflowRun?.policyRolloutState
                    ?.currentRolloutWaveCompletionState
                    ?: target.receipt?.currentRolloutWaveCompletionState,
                currentRolloutWaveDecision = finalCollaboration?.workflowRun?.policyRolloutState
                    ?.calendarAwarePromotionDecision
                    ?.decisionType
                    ?: target.receipt?.currentRolloutWaveDecision,
                currentRolloutWindowEligibility = finalCollaboration?.workflowRun?.policyRolloutState
                    ?.calendarAwarePromotionDecision
                    ?.windowEligibility
                    ?: target.receipt?.currentRolloutWindowEligibility,
                rolloutCarryForwardPending = resolvedCarryForwardPending,
                rolloutNextWindowPending = resolvedNextWindowPending,
                rolloutCrossWindowPaused = resolvedCrossWindowPauseState == CrossWindowPauseState.PAUSED,
                rolloutPromotionCandidate = resolvedRolloutStateForReceipt?.promotionCandidate
                    ?: target.receipt?.rolloutPromotionCandidate,
                rolloutPromotionReadiness = resolvedRolloutStateForReceipt?.promotionReadinessSummary
                    ?: target.receipt?.rolloutPromotionReadiness,
                crossWaveAnalyticsSummary = resolvedRolloutStateForReceipt?.crossWaveAnalyticsSummary
                    ?: target.receipt?.crossWaveAnalyticsSummary,
                windowImpactSummary = resolvedRolloutStateForReceipt?.windowImpactSummary
                    ?: target.receipt?.windowImpactSummary,
                rolloutPromotionOperation = resolvedRolloutStateForReceipt?.promotionOperationRecords
                    ?.maxByOrNull { operation -> operation.timestampMs }
                    ?: target.receipt?.rolloutPromotionOperation,
                rolloutPromotionReadinessSummary = resolvedRolloutStateForReceipt?.promotionReadinessSummary
                    ?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.rolloutPromotionReadinessSummary,
                crossWaveSummary = resolvedRolloutStateForReceipt?.crossWaveAnalyticsSummary
                    ?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.crossWaveSummary,
                windowImpactReadableSummary = resolvedRolloutStateForReceipt?.windowImpactSummary
                    ?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.windowImpactReadableSummary,
                rolloutPromotionOperationSummary = resolvedRolloutStateForReceipt?.promotionOperationSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: resolvedRolloutStateForReceipt?.promotionOperationRecords
                        ?.maxByOrNull { operation -> operation.timestampMs }
                        ?.summary
                        ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.rolloutPromotionOperationSummary,
                programCoordination = resolvedRolloutStateForReceipt?.programCoordination
                    ?: target.receipt?.programCoordination,
                crossProgramGovernanceSummary = resolvedRolloutStateForReceipt?.crossProgramGovernanceSummary
                    ?: target.receipt?.crossProgramGovernanceSummary,
                programCoordinationSummary = resolvedRolloutStateForReceipt?.programCoordinationSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.programCoordinationSummary,
                crossProgramSummary = resolvedRolloutStateForReceipt?.crossProgramGovernanceSummary
                    ?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.crossProgramSummary,
                programEscalationSummary = resolvedRolloutStateForReceipt?.programCoordination
                    ?.escalation
                    ?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: target.receipt?.programEscalationSummary,
                approvalLoadSummary = resolvedRolloutStateForReceipt?.approvalLoadSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.approvalLoadSummary,
                capacityBlockSummary = resolvedRolloutStateForReceipt?.capacityBlockSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.capacityBlockSummary,
                policyBlockSummary = resolvedRolloutStateForReceipt?.policyBlockSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.policyBlockSummary,
                capacityBalancingSummary = resolvedRolloutStateForReceipt?.capacityBalancingSummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.capacityBalancingSummary,
                portfolioCapacitySummary = resolvedRolloutStateForReceipt?.portfolioCapacitySummary
                    .takeUnless { it.isNullOrBlank() }
                    ?: target.receipt?.portfolioCapacitySummary,
                governanceCapacityPool = resolvedRolloutStateForReceipt?.governanceCapacityPool
                    ?: target.receipt?.governanceCapacityPool,
                approvalQueuePressure = resolvedRolloutStateForReceipt?.approvalQueuePressure
                    ?: target.receipt?.approvalQueuePressure,
                approvalBalancingDecision = resolvedRolloutStateForReceipt?.approvalBalancingDecision
                    ?: target.receipt?.approvalBalancingDecision,
                approvalAssignmentRecommendation = resolvedRolloutStateForReceipt?.approvalAssignmentRecommendation
