            )
            executionLedgerByUser[userId] = ArrayDeque(records.takeLast(MAX_LEDGER_RECORDS))
            mutation
        }
        if (
            result.success ||
            result.event != null ||
            result.updatedCollaborationState != null ||
            result.updatedRemoteHandoff != null ||
            result.updatedAlertRoutingRecords.isNotEmpty()
        ) {
