    fun performGovernanceBulkAction(
        userId: String,
        request: GovernanceBulkActionRequest
    ): GovernanceBulkActionResult {
        if (userId.isBlank()) {
            return GovernanceBulkActionResult(
                action = request.action,
                requestedCount = request.runIds.size,
                failureCount = request.runIds.size,
                message = "Missing user identity for bulk action.",
                timestampMs = nowMs()
            )
        }
        val normalizedRunIds = request.runIds
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .distinct()
            .take(80)
        if (normalizedRunIds.isEmpty()) {
            return GovernanceBulkActionResult(
                action = request.action,
                requestedCount = 0,
                skippedCount = request.runIds.size,
                message = "No eligible run IDs were provided.",
                timestampMs = nowMs()
            )
        }
        val supported = request.action == GovernanceActionType.MARK_REVIEWED ||
            request.action == GovernanceActionType.RETRY_SYNC_INTENT
        if (!supported) {
            return GovernanceBulkActionResult(
                action = request.action,
                requestedCount = normalizedRunIds.size,
                skippedCount = normalizedRunIds.size,
                message = "Unsupported bulk action. Only mark reviewed and retry sync are supported.",
                timestampMs = nowMs()
            )
        }
        val results = normalizedRunIds.map { runId ->
            when (request.action) {
                GovernanceActionType.MARK_REVIEWED -> markGovernanceCaseReviewed(userId, runId)
                GovernanceActionType.RETRY_SYNC_INTENT -> retryGovernanceSyncIntent(userId, runId)
                else -> GovernanceActionResult(
                    action = request.action,
                    runId = runId,
                    success = false,
                    message = "Unsupported bulk action.",
                    timestampMs = nowMs()
                )
            }
        }
        val successCount = results.count { it.success }
        val failureCount = results.count { !it.success }
        return GovernanceBulkActionResult(
            action = request.action,
            requestedCount = normalizedRunIds.size,
            successCount = successCount,
            failureCount = failureCount,
            skippedCount = request.runIds.size - normalizedRunIds.size,
            message = if (failureCount == 0) {
                "Bulk action completed for $successCount case(s)."
            } else {
                "Bulk action completed with $failureCount failure(s)."
            },
            results = results,
            timestampMs = nowMs()
        )
    }

    private fun mutateCollaborationState(
        userId: String,
        command: GovernanceCollaborationCommand,
        actor: OperatorAssigneeRef,
        operatorIdentity: OperatorIdentity,
        operatorResolution: OperatorResolution,
        remoteAuthorization: RemoteAuthorizationResult,
        runId: String,
        now: Long,
        currentState: GovernanceCaseCollaborationState,
        currentHandoff: RemoteOperatorHandoffRecord?
    ): CollaborationMutationResult {
        val auth = authorizeOperatorAction(
            action = command.commandType,
            identity = operatorIdentity,
            currentState = currentState,
            command = command
        )
        if (!auth.allowed) {
            val denialRecord = OperatorPermissionDenialRecord(
                denialId = "denial_${runId}_${command.commandType.name.lowercase()}_$now",
                action = command.commandType,
                reason = auth.denialReason ?: OperatorPermissionDenialReason.PERMISSION_MISSING,
                message = auth.message,
                actor = actor,
                timestampMs = now
            )
            val denialState = currentState.copy(
                operatorSession = buildOperatorSessionSummary(
                    identity = operatorIdentity,
                    now = now,
                    remoteAuthorization = remoteAuthorization
                ),
                permissionDenials = (currentState.permissionDenials + denialRecord).takeLast(20),
                lastActionSummary = auth.message,
                updatedAtMs = now
            )
            return CollaborationMutationResult(
                success = false,
                message = auth.message,
                updatedCollaborationState = denialState,
                event = RunEventRecord(
                    eventId = "perm_denied_${runId}_${command.commandType.name.lowercase()}_$now",
                    type = ProofLedgerEventType.OPERATOR_PERMISSION_DENIED,
                    title = "Operator permission denied",
                    detail = auth.message,
                    timestampMs = now,
                    reasonCodes = listOf(RoleReasonCodes.ROLE_OPERATOR_PERMISSION_DENIED)
                ),
                denialReason = auth.denialReason,
                requiredPermission = auth.requiredPermission,
                operatorIdentity = operatorIdentity,
                remoteAuthorizationResult = remoteAuthorization
            )
        }
        val nextVersion = (currentState.version + 1).coerceAtLeast(1)
        val commandBucket = (now / COLLABORATION_COMMAND_BUCKET_MS) * COLLABORATION_COMMAND_BUCKET_MS
        val dedupeQualifier = when (command.commandType) {
            GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION ->
                (command.scheduledAtMs ?: 0L).toString()
            else -> ""
        }
        val commandDedupeId = buildString {
            append("collab:")
            append(runId)
            append(':')
            append(command.commandType.name)
            append(':')
            append(actor.userId)
            append(':')
            append(commandBucket)
            if (dedupeQualifier.isNotBlank()) {
                append(':')
                append(dedupeQualifier)
            }
        }
        val mutation = when (command.commandType) {
            GovernanceActionType.CLAIM_CASE -> {
                if (currentState.claimStatus == OperatorCaseClaimStatus.CLAIMED &&
                    currentState.claimedBy?.userId == actor.userId
                ) {
                    CollaborationMutationResult(
                        success = true,
                        message = "Case already claimed by ${actor.displayName}."
                    )
                } else {
                    val baseUpdated = currentState.copy(
                        status = OperatorCollaborationStatus.CLAIMED,
                        claimStatus = OperatorCaseClaimStatus.CLAIMED,
                        claimedBy = actor,
                        assignedTo = currentState.assignedTo ?: actor,
                        operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                        lastActionSummary = "Case claimed by ${actor.displayName}.",
                        version = nextVersion,
                        updatedAtMs = now
                    )
                    val assignmentReasonCodes = listOf(
                        RoleReasonCodes.ROLE_OPERATOR_CASE_CLAIMED,
                        RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                    )
                    val updated = baseUpdated.copy(
                        assignment = assignmentFromState(runId, baseUpdated, now),
                        assignmentEvents = (
                            currentState.assignmentEvents +
                                assignmentEventFrom(
                                    eventId = "${commandDedupeId}:assignment",
                                    type = GovernanceCaseAssignmentEventType.CLAIMED,
                                    actor = actor,
                                    summary = "Case claimed by ${actor.displayName}.",
                                    reasonCodes = assignmentReasonCodes,
                                    now = now
                                )
                            ).takeLast(20)
                    )
                    CollaborationMutationResult(
                        success = true,
                        message = "Case claimed by ${actor.displayName}.",
                        operatorIdentity = operatorIdentity,
                        updatedCollaborationState = updated,
                        event = RunEventRecord(
                            eventId = commandDedupeId,
                            type = ProofLedgerEventType.OPERATOR_CASE_CLAIMED,
                            title = "Operator claimed case",
                            detail = "Case was claimed by ${actor.displayName}.",
                            timestampMs = now,
                            reasonCodes = assignmentReasonCodes
                        )
                    )
                }
            }

            GovernanceActionType.UNCLAIM_CASE -> {
                val baseUpdated = currentState.copy(
                    status = OperatorCollaborationStatus.UNCLAIMED,
                    claimStatus = OperatorCaseClaimStatus.UNCLAIMED,
                    claimedBy = null,
                    assignedTo = null,
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    lastActionSummary = "Case was unclaimed by ${actor.displayName}.",
                    version = nextVersion,
                    updatedAtMs = now
                )
                val assignmentReasonCodes = listOf(
                    RoleReasonCodes.ROLE_OPERATOR_CASE_UNCLAIMED,
                    RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                )
                val updated = baseUpdated.copy(
                    assignment = assignmentFromState(runId, baseUpdated, now),
                    assignmentEvents = (
                        currentState.assignmentEvents +
                            assignmentEventFrom(
                                eventId = "${commandDedupeId}:assignment",
                                type = GovernanceCaseAssignmentEventType.RELEASED,
                                actor = actor,
                                summary = "Case was released back to unclaimed queue.",
                                reasonCodes = assignmentReasonCodes,
                                now = now
                            )
                        ).takeLast(20),
                    escalation = null
                )
                CollaborationMutationResult(
                    success = true,
                    message = "Case unclaimed.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updated,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = ProofLedgerEventType.OPERATOR_CASE_UNCLAIMED,
                        title = "Operator unclaimed case",
                        detail = "Case was moved back to unclaimed queue.",
                        timestampMs = now,
                        reasonCodes = assignmentReasonCodes
                    )
                )
            }

            GovernanceActionType.RELEASE_CASE -> {
                val baseUpdated = currentState.copy(
                    status = OperatorCollaborationStatus.UNCLAIMED,
                    claimStatus = OperatorCaseClaimStatus.UNCLAIMED,
                    claimedBy = null,
                    assignedTo = currentState.assignedTo,
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    lastActionSummary = "Case ownership released by ${actor.displayName}.",
                    version = nextVersion,
                    updatedAtMs = now
                )
                val reasonCodes = listOf(
                    RoleReasonCodes.ROLE_OPERATOR_CASE_RELEASED,
                    RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                )
                val updated = baseUpdated.copy(
                    assignment = assignmentFromState(runId, baseUpdated, now),
                    assignmentEvents = (
                        currentState.assignmentEvents +
                            assignmentEventFrom(
                                eventId = "${commandDedupeId}:assignment",
                                type = GovernanceCaseAssignmentEventType.RELEASED,
                                actor = actor,
                                summary = "Case ownership released by ${actor.displayName}.",
                                reasonCodes = reasonCodes,
                                now = now
                            )
                        ).takeLast(20)
                )
                CollaborationMutationResult(
                    success = true,
                    message = "Case ownership released.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updated,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = ProofLedgerEventType.OPERATOR_CASE_RELEASED,
                        title = "Operator released case ownership",
                        detail = "Case ownership was released by ${actor.displayName}.",
                        timestampMs = now,
                        reasonCodes = reasonCodes
                    )
                )
            }

            GovernanceActionType.ASSIGN_CASE -> {
                val assignee = command.assignee ?: actor
                val baseUpdated = currentState.copy(
                    status = OperatorCollaborationStatus.ASSIGNED,
                    claimStatus = OperatorCaseClaimStatus.CLAIMED,
                    claimedBy = currentState.claimedBy ?: actor,
                    assignedTo = assignee,
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    lastActionSummary = "Case assigned to ${assignee.displayName}.",
                    version = nextVersion,
                    updatedAtMs = now
                )
                val reasonCodes = listOf(
                    RoleReasonCodes.ROLE_OPERATOR_CASE_ASSIGNED,
                    RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                )
                val updated = baseUpdated.copy(
                    assignment = assignmentFromState(runId, baseUpdated, now),
                    assignmentEvents = (
                        currentState.assignmentEvents +
                            assignmentEventFrom(
                                eventId = "${commandDedupeId}:assignment",
                                type = GovernanceCaseAssignmentEventType.ASSIGNED,
                                actor = actor,
                                summary = "Case assigned to ${assignee.displayName}.",
                                reasonCodes = reasonCodes,
                                now = now
                            )
                        ).takeLast(20)
                )
                CollaborationMutationResult(
                    success = true,
                    message = "Case assigned to ${assignee.displayName}.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updated,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = ProofLedgerEventType.OPERATOR_CASE_ASSIGNED,
                        title = "Operator assigned case",
                        detail = "Case assigned to ${assignee.displayName}.",
                        timestampMs = now,
                        reasonCodes = reasonCodes
                    )
                )
            }

            GovernanceActionType.REASSIGN_CASE -> {
                val assignee = command.assignee ?: return CollaborationMutationResult(
                    success = false,
                    message = "Assignee is required for reassign action.",
                    denialReason = OperatorPermissionDenialReason.INVALID_ASSIGNMENT_PAYLOAD,
                    requiredPermission = OperatorPermission.REASSIGN_CASE,
                    operatorIdentity = operatorIdentity
                )
                val baseUpdated = currentState.copy(
                    status = OperatorCollaborationStatus.ASSIGNED,
                    claimStatus = OperatorCaseClaimStatus.CLAIMED,
                    claimedBy = currentState.claimedBy ?: actor,
                    assignedTo = assignee,
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    lastActionSummary = "Case reassigned to ${assignee.displayName}.",
                    version = nextVersion,
                    updatedAtMs = now
                )
                val reasonCodes = listOf(
                    RoleReasonCodes.ROLE_OPERATOR_CASE_REASSIGNED,
                    RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                )
                val updated = baseUpdated.copy(
                    assignment = assignmentFromState(runId, baseUpdated, now),
                    assignmentEvents = (
                        currentState.assignmentEvents +
                            assignmentEventFrom(
                                eventId = "${commandDedupeId}:assignment",
                                type = GovernanceCaseAssignmentEventType.REASSIGNED,
                                actor = actor,
                                summary = "Case reassigned to ${assignee.displayName}.",
                                reasonCodes = reasonCodes,
                                now = now
                            )
                        ).takeLast(20)
                )
                CollaborationMutationResult(
                    success = true,
                    message = "Case reassigned to ${assignee.displayName}.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updated,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = ProofLedgerEventType.OPERATOR_CASE_REASSIGNED,
                        title = "Operator reassigned case",
                        detail = "Case reassigned to ${assignee.displayName}.",
                        timestampMs = now,
                        reasonCodes = reasonCodes
                    )
                )
            }

            GovernanceActionType.ADD_NOTE -> {
                val text = command.note?.trim().orEmpty()
                if (text.isBlank()) {
                    CollaborationMutationResult(
                        success = false,
                        message = "Note content is required."
                    )
                } else {
                    val note = GovernanceCaseNoteRecord(
                        noteId = "note_${runId}_$now",
                        actor = actor,
                        note = text,
                        createdAtMs = now
                    )
                    val existingNotes = currentState.notes.toMutableList()
                    if (existingNotes.none { it.note == text && it.actor.userId == actor.userId }) {
                        existingNotes += note
                    }
                    val updated = currentState.copy(
                        status = if (currentState.status == OperatorCollaborationStatus.UNCLAIMED) {
                            OperatorCollaborationStatus.REVIEW_IN_PROGRESS
                        } else {
                            currentState.status
                        },
                        claimStatus = if (currentState.claimStatus == OperatorCaseClaimStatus.UNCLAIMED) {
                            OperatorCaseClaimStatus.CLAIMED
                        } else {
                            currentState.claimStatus
                        },
                        claimedBy = currentState.claimedBy ?: actor,
                        operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                        notes = existingNotes.takeLast(20),
                        lastActionSummary = "Note added by ${actor.displayName}.",
                        version = nextVersion,
                        updatedAtMs = now
                    )
                    CollaborationMutationResult(
                        success = true,
                        message = "Note added.",
                        operatorIdentity = operatorIdentity,
                        updatedCollaborationState = updated,
                        event = RunEventRecord(
                            eventId = commandDedupeId,
                            type = ProofLedgerEventType.OPERATOR_NOTE_ADDED,
                            title = "Operator note added",
                            detail = "Added note: ${text.take(120)}",
                            timestampMs = now,
                            reasonCodes = listOf(RoleReasonCodes.ROLE_OPERATOR_NOTE_ADDED)
                        )
                    )
                }
            }

            GovernanceActionType.REQUEST_FOLLOW_UP -> {
                val summary = command.followUpSummary?.trim().takeUnless { it.isNullOrBlank() }
                    ?: "Operator requested follow-up for this case."
                val baseUpdatedState = currentState.copy(
                    status = OperatorCollaborationStatus.FOLLOW_UP_PENDING,
                    claimStatus = OperatorCaseClaimStatus.CLAIMED,
                    claimedBy = currentState.claimedBy ?: actor,
                    assignedTo = currentState.assignedTo ?: actor,
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    followUp = GovernanceCaseFollowUpState(
                        requested = true,
                        requestedBy = actor,
                        requestedAtMs = now,
                        summary = summary,
                        ackPending = true
                    ),
                    lastActionSummary = summary,
                    version = nextVersion,
                    updatedAtMs = now
                )
                val updatedState = baseUpdatedState.copy(
                    assignment = assignmentFromState(runId, baseUpdatedState, now)
                )
                val handoffTarget = command.target?.trim().takeUnless { it.isNullOrBlank() }
                    ?: "remote_operator_stub"
                val handoffDedupeKey = "handoff:${runId}:${updatedState.version}:$handoffTarget"
                val handoffRequest = RemoteOperatorHandoffRequest(
                    requestId = "handoff_${runId}_$now",
                    runId = runId,
                    caseStateVersion = updatedState.version,
                    target = handoffTarget,
                    summary = summary,
                    requestedBy = actor,
                    dedupeKey = handoffDedupeKey,
                    requestedAtMs = now
                )
                val handoffAttempt = remoteOperatorWorkflowPort.handoff(handoffRequest, now)
                val resolvedHandoffStatus = when (handoffAttempt.status) {
                    RemoteOperatorHandoffStatus.FAILED -> RemoteOperatorHandoffStatus.FAILED
                    RemoteOperatorHandoffStatus.HANDED_OFF -> RemoteOperatorHandoffStatus.ACK_PENDING
                    RemoteOperatorHandoffStatus.ACKNOWLEDGED -> RemoteOperatorHandoffStatus.ACKNOWLEDGED
                    RemoteOperatorHandoffStatus.HANDOFF_PENDING -> RemoteOperatorHandoffStatus.HANDOFF_PENDING
                    RemoteOperatorHandoffStatus.REQUESTED -> RemoteOperatorHandoffStatus.REQUESTED
                    RemoteOperatorHandoffStatus.ACK_PENDING -> RemoteOperatorHandoffStatus.ACK_PENDING
                    RemoteOperatorHandoffStatus.NOT_REQUESTED -> RemoteOperatorHandoffStatus.REQUESTED
                }
                val updatedHandoff = mergeRemoteOperatorHandoffRecord(
                    previous = currentHandoff,
                    incoming = RemoteOperatorHandoffRecord(
                        recordId = "handoff_record_${runId}_$now",
                        runId = runId,
                        status = resolvedHandoffStatus,
                        dedupeKey = handoffDedupeKey,
                        request = handoffRequest,
                        attempts = listOf(
                            handoffAttempt.copy(
                                status = resolvedHandoffStatus,
                                summary = when (resolvedHandoffStatus) {
                                    RemoteOperatorHandoffStatus.FAILED ->
                                        handoffAttempt.summary.ifBlank { "Remote operator handoff failed." }
                                    RemoteOperatorHandoffStatus.ACK_PENDING ->
                                        "Remote handoff accepted and waiting manual acknowledgement."
                                    RemoteOperatorHandoffStatus.HANDOFF_PENDING ->
                                        "Remote handoff queued and pending processing."
                                    RemoteOperatorHandoffStatus.ACKNOWLEDGED ->
                                        "Remote handoff acknowledged."
                                    else ->
                                        handoffAttempt.summary.ifBlank { "Remote handoff requested." }
                                }
                            )
                        ),
                        lastAttemptAtMs = now,
                        lastErrorSummary = if (resolvedHandoffStatus == RemoteOperatorHandoffStatus.FAILED) {
                            handoffAttempt.summary
                        } else {
                            null
                        }
                    )
                )
                val routingRecord = buildOperatorAlertRoutingRecord(
                    userId = userId,
                    runId = runId,
                    summary = summary,
                    command = command,
                    operatorIdentity = operatorIdentity,
                    operatorResolution = operatorResolution,
                    remoteAuthorization = remoteAuthorization,
                    preferredTargets = command.connectorTargets,
                    now = now
                )
                val connectorSummary = buildConnectorRoutingSummary(listOf(routingRecord))
                val routingActionType = if (currentState.routingActions.isEmpty()) {
                    GovernanceRoutingActionType.ROUTE_REQUESTED
                } else {
                    GovernanceRoutingActionType.ROUTE_RETRIED
                }
                val updatedStateWithRouting = updatedState.copy(
                    routingActions = appendRoutingActions(
                        existing = updatedState.routingActions,
                        record = routingRecord,
                        actor = actor,
                        actionType = routingActionType,
                        summary = summary,
                        now = now
                    )
                )
                val eventType = when (resolvedHandoffStatus) {
                    RemoteOperatorHandoffStatus.FAILED -> ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_FAILED
                    RemoteOperatorHandoffStatus.ACK_PENDING -> ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_ACK_PENDING
                    RemoteOperatorHandoffStatus.HANDOFF_PENDING -> ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_PENDING
                    RemoteOperatorHandoffStatus.ACKNOWLEDGED -> ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED
                    else -> ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_REQUESTED
                }
                val reasonCodes = mutableListOf(
                    RoleReasonCodes.ROLE_OPERATOR_FOLLOW_UP_REQUESTED,
                    RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_REQUESTED,
                    RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_REQUESTED
                )
                when (resolvedHandoffStatus) {
                    RemoteOperatorHandoffStatus.ACK_PENDING ->
                        reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_ACK_PENDING
                    RemoteOperatorHandoffStatus.HANDOFF_PENDING ->
                        reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_PENDING
                    RemoteOperatorHandoffStatus.ACKNOWLEDGED ->
                        reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED
                    RemoteOperatorHandoffStatus.FAILED ->
                        reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_FAILED
                    else -> Unit
                }
                reasonCodes += when (routingRecord.status) {
                    AlertRoutingStatus.DELIVERED -> RoleReasonCodes.ROLE_ALERT_ROUTING_DELIVERED
                    AlertRoutingStatus.FAILED -> RoleReasonCodes.ROLE_ALERT_ROUTING_FAILED
                    AlertRoutingStatus.QUEUED,
                    AlertRoutingStatus.LOCAL_ONLY,
                    AlertRoutingStatus.DUPLICATE_SUPPRESSED -> RoleReasonCodes.ROLE_ALERT_ROUTING_QUEUED
                }
                reasonCodes += if (routingRecord.status == AlertRoutingStatus.FAILED) {
                    RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
                } else {
                    RoleReasonCodes.ROLE_CONNECTOR_ROUTE_SELECTED
                }
                reasonCodes += connectorSummary?.reasonCodes.orEmpty()
                CollaborationMutationResult(
                    success = true,
                    message = "Follow-up requested and remote handoff queued.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updatedStateWithRouting,
                    updatedRemoteHandoff = updatedHandoff,
                    updatedAlertRoutingRecords = listOf(routingRecord),
                    connectorRoutingSummary = connectorSummary,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = eventType,
                        title = "Operator requested follow-up",
                        detail = summary,
                        timestampMs = now,
                        reasonCodes = reasonCodes.distinct()
                    )
                )
            }

            GovernanceActionType.ESCALATE_CASE -> {
                val escalationTarget = command.escalationTarget?.trim().orEmpty()
                if (escalationTarget.isBlank()) {
                    CollaborationMutationResult(
                        success = false,
                        message = "Escalation target is required for escalation action.",
                        denialReason = OperatorPermissionDenialReason.INVALID_ESCALATION_PAYLOAD,
                        requiredPermission = OperatorPermission.ESCALATE_CASE,
                        operatorIdentity = operatorIdentity
                    )
                } else {
                    val escalationSummary = command.followUpSummary?.trim().takeUnless { it.isNullOrBlank() }
                        ?: "Case escalated to $escalationTarget."
                    val followUpResult = mutateCollaborationState(
                        userId = userId,
                        command = command.copy(
                            commandType = GovernanceActionType.REQUEST_FOLLOW_UP,
                            followUpSummary = escalationSummary,
                            target = escalationTarget
                        ),
                        actor = actor,
                        operatorIdentity = operatorIdentity,
                        operatorResolution = operatorResolution,
                        remoteAuthorization = remoteAuthorization,
                        runId = runId,
                        now = now,
                        currentState = currentState,
                        currentHandoff = currentHandoff
                    )
                    if (!followUpResult.success) {
                        followUpResult
                    } else {
                        val escalatedBase = (followUpResult.updatedCollaborationState ?: currentState).copy(
                            status = OperatorCollaborationStatus.FOLLOW_UP_PENDING,
                            operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                            escalation = GovernanceCaseEscalationState(
                                escalated = true,
                                target = escalationTarget,
                                summary = escalationSummary,
                                requestedBy = actor,
                                requestedAtMs = now,
                                level = ((currentState.escalation?.level ?: 0) + 1).coerceAtMost(5)
                            ),
                            lastActionSummary = "Case escalated to $escalationTarget by ${actor.displayName}.",
                            version = maxOf(nextVersion, (followUpResult.updatedCollaborationState?.version ?: nextVersion)),
                            updatedAtMs = now
                        )
                        val escalateReasonCodes = (
                            listOf(
                                RoleReasonCodes.ROLE_OPERATOR_ESCALATION_REQUESTED,
                                RoleReasonCodes.ROLE_OPERATOR_ASSIGNMENT_UPDATED
                            ) +
                                (followUpResult.event?.reasonCodes ?: emptyList())
                            ).distinct()
                        val escalatedRoutingActions = followUpResult.updatedAlertRoutingRecords
                            .lastOrNull()
                            ?.let { routing ->
                                appendRoutingActions(
                                    existing = escalatedBase.routingActions,
                                    record = routing,
                                    actor = actor,
                                    actionType = GovernanceRoutingActionType.ROUTE_ESCALATED,
                                    summary = escalationSummary,
                                    now = now
                                )
                            }
                            ?: escalatedBase.routingActions
                        val escalatedState = escalatedBase.copy(
                            assignment = assignmentFromState(runId, escalatedBase, now),
                            assignmentEvents = (
                                escalatedBase.assignmentEvents +
                                    assignmentEventFrom(
                                        eventId = "${commandDedupeId}:assignment",
                                        type = GovernanceCaseAssignmentEventType.ESCALATED,
                                        actor = actor,
                                        summary = "Case escalated to $escalationTarget.",
                                        reasonCodes = escalateReasonCodes,
                                        now = now
                                    )
                                ).takeLast(20),
                            routingActions = escalatedRoutingActions
                        )
                        CollaborationMutationResult(
                            success = true,
                            message = "Case escalated to $escalationTarget.",
                            updatedCollaborationState = escalatedState,
                            updatedRemoteHandoff = followUpResult.updatedRemoteHandoff,
                            updatedAlertRoutingRecords = followUpResult.updatedAlertRoutingRecords,
                            connectorRoutingSummary = followUpResult.connectorRoutingSummary,
                            event = RunEventRecord(
                                eventId = commandDedupeId,
                                type = ProofLedgerEventType.OPERATOR_CASE_ESCALATED,
                                title = "Operator escalated case",
                                detail = "Escalation requested to $escalationTarget.",
                                timestampMs = now,
                                reasonCodes = escalateReasonCodes
                            ),
                            operatorIdentity = operatorIdentity
                        )
                    }
                }
            }

            GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE -> {
                val templateId = command.workflowTemplateId?.trim().orEmpty()
                if (templateId.isBlank()) {
                    CollaborationMutationResult(
                        success = false,
                        message = "Workflow template ID is required.",
                        denialReason = OperatorPermissionDenialReason.INVALID_WORKFLOW_PAYLOAD,
                        requiredPermission = OperatorPermission.APPLY_WORKFLOW_TEMPLATE,
                        operatorIdentity = operatorIdentity
                    )
                } else {
                    val template = resolveOperatorWorkflowTemplate(templateId, currentState)
                    val initialStage = template.defaultStage
                    val stageSummary = workflowStageSummary(template, initialStage)
                    val policyEval = evaluateWorkflowPolicyState(
                        template = template,
                        stage = initialStage,
                        now = now,
                        stageEnteredAtMs = now,
                        previousRun = null,
                        command = command,
                        currentState = currentState
                    )
                    val workflowRun = OperatorWorkflowRun(
                        runId = runId,
                        templateId = template.templateId,
                        templateName = template.name.ifBlank { template.templateId },
                        status = OperatorWorkflowRunStatus.ACTIVE,
                        currentStage = initialStage,
                        stageHistory = listOf(
                            OperatorWorkflowStageRecord(
                                stage = initialStage,
                                status = OperatorWorkflowStepStatus.IN_PROGRESS,
                                summary = stageSummary,
                                enteredAtMs = now
                            )
                        ),
                        policyProfile = policyEval.policyProfile,
                        policyPack = policyEval.policyPack,
                        policyPackBinding = policyEval.policyPackBinding,
                        tenantOverride = policyEval.tenantOverride,
                        workspaceOverride = policyEval.workspaceOverride,
                        advancedAutomationControls = policyEval.advancedAutomationControls,
                        policyResolution = policyEval.policyResolution,
                        policyRolloutState = policyEval.policyRolloutState,
                        slaClock = policyEval.slaClock,
                        stageTimer = policyEval.stageTimer,
                        escalationTimer = policyEval.escalationTimer,
                        workflowPolicySummary = policyEval.workflowPolicySummary,
                        policyPackSummary = policyEval.policyPackSummary,
                        policyOverrideSummary = policyEval.policyOverrideSummary,
                        automationControlSummary = policyEval.automationControlSummary,
                        policyResolutionSummary = policyEval.policyResolutionSummary,
                        workflowSimulationOnly = policyEval.workflowSimulationOnly,
                        workflowRolloutSummary = policyEval.rolloutSummary,
                        workflowRolloutApprovalSummary = policyEval.rolloutApprovalSummary,
                        workflowRolloutFreezeSummary = policyEval.rolloutFreezeSummary,
                        workflowRolloutRollbackSummary = policyEval.rolloutRollbackSummary,
                        slaSummary = policyEval.slaSummary,
                        stageTimerSummary = policyEval.stageTimerSummary,
                        escalationTimerSummary = policyEval.escalationTimerSummary,
                        nextAction = nextWorkflowActionForStage(template, initialStage),
                        updatedAtMs = now
                    )
                    val updated = currentState.copy(
                        status = if (currentState.status == OperatorCollaborationStatus.UNCLAIMED) {
                            OperatorCollaborationStatus.REVIEW_IN_PROGRESS
                        } else {
                            currentState.status
                        },
                        claimStatus = if (currentState.claimStatus == OperatorCaseClaimStatus.UNCLAIMED) {
                            OperatorCaseClaimStatus.CLAIMED
                        } else {
                            currentState.claimStatus
                        },
                        claimedBy = currentState.claimedBy ?: actor,
                        assignedTo = currentState.assignedTo ?: actor,
                        operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                        workflowRun = workflowRun,
                        lastActionSummary = "Workflow template \"${workflowRun.templateName}\" attached.",
                        version = nextVersion,
                        updatedAtMs = now
                    )
                    CollaborationMutationResult(
                        success = true,
                        message = "Workflow template attached.",
                        operatorIdentity = operatorIdentity,
                        updatedCollaborationState = updated,
                        event = RunEventRecord(
                            eventId = commandDedupeId,
                            type = ProofLedgerEventType.WORKFLOW_TEMPLATE_ATTACHED,
                            title = "Workflow template attached",
                            detail = "Template ${workflowRun.templateName} attached at stage ${initialStage.name.lowercase().replace('_', ' ')}.",
                            timestampMs = now,
                            reasonCodes = (listOf(RoleReasonCodes.ROLE_WORKFLOW_TEMPLATE_ATTACHED) + policyEval.reasonCodes)
                                .distinct()
                        )
                    )
                }
            }

            GovernanceActionType.ADVANCE_WORKFLOW_STAGE -> {
                val targetStage = command.workflowStage
                if (targetStage == null) {
                    CollaborationMutationResult(
                        success = false,
                        message = "Workflow stage is required.",
                        denialReason = OperatorPermissionDenialReason.INVALID_WORKFLOW_PAYLOAD,
                        requiredPermission = OperatorPermission.ADVANCE_WORKFLOW_STAGE,
                        operatorIdentity = operatorIdentity
                    )
                } else {
                    val currentRun = currentState.workflowRun
                    val template = resolveOperatorWorkflowTemplate(
                        templateId = currentRun?.templateId ?: command.workflowTemplateId ?: "wf_generic_triage",
                        state = currentState
                    )
                    val baseRun = currentRun ?: OperatorWorkflowRun(
                        runId = runId,
                        templateId = template.templateId,
                        templateName = template.name.ifBlank { template.templateId },
                        status = OperatorWorkflowRunStatus.ACTIVE,
                        currentStage = template.defaultStage,
                        stageHistory = listOf(
                            OperatorWorkflowStageRecord(
                                stage = template.defaultStage,
                                status = OperatorWorkflowStepStatus.COMPLETED,
                                summary = workflowStageSummary(template, template.defaultStage),
                                enteredAtMs = now
                            )
                        ),
                        nextAction = nextWorkflowActionForStage(template, template.defaultStage),
                        updatedAtMs = now
                    )
                    val previousStage = baseRun.currentStage
                    val previousStageEnteredAtMs = baseRun.stageHistory
                        .lastOrNull { it.stage == previousStage }
                        ?.enteredAtMs
                        ?.takeIf { it > 0L }
                        ?: now
                    val currentPolicyEval = evaluateWorkflowPolicyState(
                        template = template,
                        stage = previousStage,
                        now = now,
                        stageEnteredAtMs = previousStageEnteredAtMs,
                        previousRun = baseRun,
                        command = command,
                        currentState = currentState
                    )
                    val policy = currentPolicyEval.policyProfile
                    val transitionAllowed = isWorkflowTransitionAllowed(
                        policy = policy,
                        from = previousStage,
                        to = targetStage
                    )
                    if (!transitionAllowed) {
                        val blockedSummary = "Workflow transition blocked by policy (${previousStage.name.lowercase().replace('_', ' ')} -> ${targetStage.name.lowercase().replace('_', ' ')})."
                        val blockedState = currentState.copy(
                            operatorSession = buildOperatorSessionSummary(
                                identity = operatorIdentity,
                                now = now,
                                remoteAuthorization = remoteAuthorization
                            ),
                            workflowRun = baseRun.copy(
                                policyProfile = currentPolicyEval.policyProfile,
                                policyPack = currentPolicyEval.policyPack,
                                policyPackBinding = currentPolicyEval.policyPackBinding,
                                tenantOverride = currentPolicyEval.tenantOverride,
                                workspaceOverride = currentPolicyEval.workspaceOverride,
                                advancedAutomationControls = currentPolicyEval.advancedAutomationControls,
                                policyResolution = currentPolicyEval.policyResolution,
                                workflowPolicySummary = currentPolicyEval.workflowPolicySummary,
                                policyPackSummary = currentPolicyEval.policyPackSummary,
                                policyOverrideSummary = currentPolicyEval.policyOverrideSummary,
                                automationControlSummary = currentPolicyEval.automationControlSummary,
                                policyResolutionSummary = currentPolicyEval.policyResolutionSummary,
                                workflowSimulationOnly = currentPolicyEval.workflowSimulationOnly,
                                slaClock = currentPolicyEval.slaClock,
                                stageTimer = currentPolicyEval.stageTimer,
                                escalationTimer = currentPolicyEval.escalationTimer,
                                slaSummary = currentPolicyEval.slaSummary,
                                stageTimerSummary = currentPolicyEval.stageTimerSummary,
                                escalationTimerSummary = currentPolicyEval.escalationTimerSummary,
                                updatedAtMs = now
                            ),
                            lastActionSummary = blockedSummary,
                            version = nextVersion,
                            updatedAtMs = now
                        )
                        CollaborationMutationResult(
                            success = false,
                            message = blockedSummary,
                            operatorIdentity = operatorIdentity,
                            updatedCollaborationState = blockedState,
                            event = RunEventRecord(
                                eventId = commandDedupeId,
                                type = ProofLedgerEventType.WORKFLOW_POLICY_APPLIED,
                                title = "Workflow policy blocked transition",
                                detail = blockedSummary,
                                timestampMs = now,
                                reasonCodes = (
                                    listOf(
                                        RoleReasonCodes.ROLE_WORKFLOW_POLICY_APPLIED,
                                        RoleReasonCodes.ROLE_POLICY_DENIED
                                    ) + currentPolicyEval.reasonCodes
                                    ).distinct()
                            )
                        )
                    } else {
                        val normalizedHistory = baseRun.stageHistory.map { entry ->
                            if (entry.stage == previousStage && entry.status == OperatorWorkflowStepStatus.IN_PROGRESS) {
                                entry.copy(status = OperatorWorkflowStepStatus.COMPLETED)
                            } else {
                                entry
                            }
                        }
                        val stageRecord = OperatorWorkflowStageRecord(
                            stage = targetStage,
                            status = if (targetStage == OperatorWorkflowStage.RESOLVED) {
                                OperatorWorkflowStepStatus.COMPLETED
                            } else {
                                OperatorWorkflowStepStatus.IN_PROGRESS
                            },
                            summary = workflowStageSummary(template, targetStage),
                            enteredAtMs = now
                        )
                        val policyEval = evaluateWorkflowPolicyState(
                            template = template,
                            stage = targetStage,
                            now = now,
                            stageEnteredAtMs = stageRecord.enteredAtMs,
                            previousRun = baseRun,
                            command = command,
                            currentState = currentState
                        )
                        val updatedRun = baseRun.copy(
                            status = workflowRunStatusForStage(targetStage),
                            currentStage = targetStage,
                            stageHistory = (normalizedHistory + stageRecord).takeLast(16),
                            policyProfile = policyEval.policyProfile,
                            policyPack = policyEval.policyPack,
                            policyPackBinding = policyEval.policyPackBinding,
                            tenantOverride = policyEval.tenantOverride,
                            workspaceOverride = policyEval.workspaceOverride,
                            advancedAutomationControls = policyEval.advancedAutomationControls,
                            policyResolution = policyEval.policyResolution,
                            policyRolloutState = policyEval.policyRolloutState,
                            slaClock = policyEval.slaClock,
                            stageTimer = policyEval.stageTimer,
                            escalationTimer = policyEval.escalationTimer,
                            workflowPolicySummary = policyEval.workflowPolicySummary,
                            policyPackSummary = policyEval.policyPackSummary,
                            policyOverrideSummary = policyEval.policyOverrideSummary,
                            automationControlSummary = policyEval.automationControlSummary,
                            policyResolutionSummary = policyEval.policyResolutionSummary,
                            workflowSimulationOnly = policyEval.workflowSimulationOnly,
                            workflowRolloutSummary = policyEval.rolloutSummary,
                            workflowRolloutApprovalSummary = policyEval.rolloutApprovalSummary,
                            workflowRolloutFreezeSummary = policyEval.rolloutFreezeSummary,
                            workflowRolloutRollbackSummary = policyEval.rolloutRollbackSummary,
                            slaSummary = policyEval.slaSummary,
                            stageTimerSummary = policyEval.stageTimerSummary,
                            escalationTimerSummary = policyEval.escalationTimerSummary,
                            nextAction = nextWorkflowActionForStage(template, targetStage),
                            updatedAtMs = now
                        )
                        val updated = currentState.copy(
                            status = collaborationStatusForWorkflowStage(targetStage, currentState.status),
                            claimStatus = if (currentState.claimStatus == OperatorCaseClaimStatus.UNCLAIMED) {
                                OperatorCaseClaimStatus.CLAIMED
                            } else {
                                currentState.claimStatus
                            },
                            claimedBy = currentState.claimedBy ?: actor,
                            assignedTo = currentState.assignedTo ?: actor,
                            operatorSession = buildOperatorSessionSummary(
                                identity = operatorIdentity,
                                now = now,
                                remoteAuthorization = remoteAuthorization
                            ),
                            workflowRun = updatedRun,
                            lastActionSummary = "Workflow stage updated to ${targetStage.name.lowercase().replace('_', ' ')}.",
                            version = nextVersion,
                            updatedAtMs = now
                        )
                        CollaborationMutationResult(
                            success = true,
                            message = "Workflow stage updated.",
                            operatorIdentity = operatorIdentity,
                            updatedCollaborationState = updated,
                            event = RunEventRecord(
                                eventId = commandDedupeId,
                                type = ProofLedgerEventType.WORKFLOW_STAGE_CHANGED,
                                title = "Workflow stage changed",
                                detail = "Workflow moved from ${previousStage.name.lowercase().replace('_', ' ')} to ${targetStage.name.lowercase().replace('_', ' ')}.",
                                timestampMs = now,
                                reasonCodes = (listOf(RoleReasonCodes.ROLE_WORKFLOW_STAGE_CHANGED) + policyEval.reasonCodes)
                                    .distinct()
                            )
                        )
                    }
                }
            }

            GovernanceActionType.RUN_SAFE_AUTOMATION -> {
                val workflowRun = currentState.workflowRun
                val template = resolveOperatorWorkflowTemplate(
                    templateId = workflowRun?.templateId ?: command.workflowTemplateId ?: "wf_generic_triage",
                    state = currentState
                )
                val baseRun = workflowRun ?: run {
                    val initialStage = template.defaultStage
                    val initialEval = evaluateWorkflowPolicyState(
                        template = template,
                        stage = initialStage,
                        now = now,
                        stageEnteredAtMs = now,
                        previousRun = null,
                        command = command,
                        currentState = currentState
                    )
                    OperatorWorkflowRun(
                        runId = runId,
                        templateId = template.templateId,
                        templateName = template.name.ifBlank { template.templateId },
                        status = OperatorWorkflowRunStatus.ACTIVE,
                        currentStage = initialStage,
                        stageHistory = listOf(
                            OperatorWorkflowStageRecord(
                                stage = initialStage,
                                status = OperatorWorkflowStepStatus.IN_PROGRESS,
                                summary = workflowStageSummary(template, initialStage),
                                enteredAtMs = now
                            )
                        ),
                        policyProfile = initialEval.policyProfile,
                        policyPack = initialEval.policyPack,
                        policyPackBinding = initialEval.policyPackBinding,
                        tenantOverride = initialEval.tenantOverride,
                        workspaceOverride = initialEval.workspaceOverride,
                        advancedAutomationControls = initialEval.advancedAutomationControls,
                        policyResolution = initialEval.policyResolution,
                        slaClock = initialEval.slaClock,
                        stageTimer = initialEval.stageTimer,
                        escalationTimer = initialEval.escalationTimer,
                        workflowPolicySummary = initialEval.workflowPolicySummary,
                        policyPackSummary = initialEval.policyPackSummary,
                        policyOverrideSummary = initialEval.policyOverrideSummary,
                        automationControlSummary = initialEval.automationControlSummary,
                        policyResolutionSummary = initialEval.policyResolutionSummary,
                        workflowSimulationOnly = initialEval.workflowSimulationOnly,
                        slaSummary = initialEval.slaSummary,
                        stageTimerSummary = initialEval.stageTimerSummary,
                        escalationTimerSummary = initialEval.escalationTimerSummary,
                        nextAction = nextWorkflowActionForStage(template, initialStage),
                        updatedAtMs = now
                    )
                }
                val currentStage = baseRun.currentStage
                val stageEnteredAt = baseRun.stageHistory
                    .lastOrNull { it.stage == currentStage }
                    ?.enteredAtMs
                    ?.takeIf { it > 0L }
                    ?: now
                val policyEval = evaluateWorkflowPolicyState(
                    template = template,
                    stage = currentStage,
                    now = now,
                    stageEnteredAtMs = stageEnteredAt,
                    previousRun = baseRun,
                    command = command,
                    currentState = currentState
                )
                val policyRun = baseRun.copy(
                    policyProfile = policyEval.policyProfile,
                    policyPack = policyEval.policyPack,
                    policyPackBinding = policyEval.policyPackBinding,
                    tenantOverride = policyEval.tenantOverride,
                    workspaceOverride = policyEval.workspaceOverride,
                    advancedAutomationControls = policyEval.advancedAutomationControls,
                    policyResolution = policyEval.policyResolution,
                    policyRolloutState = policyEval.policyRolloutState,
                    slaClock = policyEval.slaClock,
                    stageTimer = policyEval.stageTimer,
                    escalationTimer = policyEval.escalationTimer,
                    workflowPolicySummary = policyEval.workflowPolicySummary,
                    policyPackSummary = policyEval.policyPackSummary,
                    policyOverrideSummary = policyEval.policyOverrideSummary,
                    automationControlSummary = policyEval.automationControlSummary,
                    policyResolutionSummary = policyEval.policyResolutionSummary,
                    workflowSimulationOnly = policyEval.workflowSimulationOnly,
                    workflowRolloutSummary = policyEval.rolloutSummary,
                    workflowRolloutApprovalSummary = policyEval.rolloutApprovalSummary,
                    workflowRolloutFreezeSummary = policyEval.rolloutFreezeSummary,
                    workflowRolloutRollbackSummary = policyEval.rolloutRollbackSummary,
                    slaSummary = policyEval.slaSummary,
                    stageTimerSummary = policyEval.stageTimerSummary,
                    escalationTimerSummary = policyEval.escalationTimerSummary,
                    updatedAtMs = now
                )
                val trigger = inferAutomationTriggerForState(currentState, workflowRun)
                val defaultAction = when (trigger) {
                    RemoteOpsAutomationTrigger.SYNC_PENDING,
                    RemoteOpsAutomationTrigger.RECONCILIATION_MISMATCH -> GovernanceActionType.RETRY_SYNC_INTENT
                    RemoteOpsAutomationTrigger.PROVIDER_ISSUE -> GovernanceActionType.REQUEST_FOLLOW_UP
                    RemoteOpsAutomationTrigger.ROLLBACK_FAILURE,
                    RemoteOpsAutomationTrigger.DISPUTE_FOLLOW_UP -> GovernanceActionType.ESCALATE_CASE
                }
                val rule = RemoteOpsAutomationRule(
                    ruleId = command.automationRuleId?.trim().takeUnless { it.isNullOrBlank() }
                        ?: "auto_${trigger.name.lowercase()}",
                    name = "Safe ${trigger.name.lowercase().replace('_', ' ')} automation",
                    templateId = workflowRun?.templateId ?: template.templateId,
                    trigger = trigger,
                    action = defaultAction,
                    enabled = true,
                    maxRunsPerCase = 1
                )
                val guardrail = policyRun.policyProfile?.automationGuardrail ?: WorkflowAutomationGuardrail()
                val advancedControls = policyRun.advancedAutomationControls
                    ?: workflowAutomationControlsFromPolicy(
                        policyRun.policyProfile ?: workflowPolicyProfileForTemplate(template.templateId)
                    )
                val effectiveCooldownMs = if (advancedControls.cooldownMs > 0L) {
                    advancedControls.cooldownMs
                } else {
                    guardrail.cooldownMs
                }
                val effectiveThrottleWindowMs = if (advancedControls.throttleWindowMs > 0L) {
                    advancedControls.throttleWindowMs
                } else {
                    guardrail.throttleWindowMs
                }
                val effectiveMaxRunsPerWindow = if (advancedControls.maxRunsPerWindow > 0) {
                    advancedControls.maxRunsPerWindow
                } else {
                    guardrail.maxRunsPerWindow.coerceAtLeast(1)
                }
                val effectiveMaxRunsPerCase = when {
                    advancedControls.maxRunsPerCase < 0 -> rule.maxRunsPerCase
                    else -> advancedControls.maxRunsPerCase
                }
                val suppressionStages = (guardrail.suppressedStages + advancedControls.suppressionStages).distinct()
                val stageSuppressed = suppressionStages.contains(policyRun.currentStage)
                val outsideQuietHours = !isWithinAutomationWindow(advancedControls.quietHours, now)
                val outsideMaintenanceWindow = !isWithinAutomationWindow(advancedControls.maintenanceWindow, now)
                val simulationOnly = policyRun.workflowSimulationOnly || advancedControls.simulationOnly
                val priorRuns = currentState.automationAudit.count {
                    it.ruleId == rule.ruleId && it.status == RemoteOpsAutomationDecisionStatus.EXECUTED
                }
                val recentSameRule = currentState.automationAudit
                    .filter { it.ruleId == rule.ruleId }
                    .sortedByDescending { it.timestampMs }
                val lastSameRule = recentSameRule.firstOrNull()
                val executedInWindow = if (effectiveThrottleWindowMs > 0L) {
                    currentState.automationAudit.count {
                        it.ruleId == rule.ruleId &&
                            it.status == RemoteOpsAutomationDecisionStatus.EXECUTED &&
                            it.timestampMs >= now - effectiveThrottleWindowMs
                    }
                } else {
                    priorRuns
                }
                val safeAction = isSafeAutomationAction(rule.action)
                val escalationRequired = policyRun.escalationTimer?.status == WorkflowEscalationTimerStatus.REQUIRED ||
                    policyRun.escalationTimer?.status == WorkflowEscalationTimerStatus.TRIGGERED
                val slaBreached = policyRun.slaClock?.status == WorkflowSlaStatus.BREACHED
                val automationStatus = when {
                    simulationOnly ->
                        RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY

                    !rule.enabled || !guardrail.allowAutomation || !safeAction ||
                        effectiveMaxRunsPerCase <= 0 ||
                        guardrail.blockedActions.contains(rule.action) ||
                        (guardrail.blockWhenSlaBreached && slaBreached) ||
                        (guardrail.blockWhenEscalationRequired && escalationRequired) ->
                        RemoteOpsAutomationDecisionStatus.BLOCKED

                    stageSuppressed ||
                        outsideQuietHours ||
                        outsideMaintenanceWindow ->
                        RemoteOpsAutomationDecisionStatus.SUPPRESSED

                    effectiveCooldownMs > 0L &&
                        lastSameRule != null &&
                        now - lastSameRule.timestampMs < effectiveCooldownMs ->
                        RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE

                    executedInWindow >= effectiveMaxRunsPerWindow.coerceAtLeast(1) ||
                        (effectiveMaxRunsPerCase > 0 && priorRuns >= effectiveMaxRunsPerCase) ->
                        RemoteOpsAutomationDecisionStatus.THROTTLED

                    else -> RemoteOpsAutomationDecisionStatus.EXECUTED
                }
                val executed = automationStatus == RemoteOpsAutomationDecisionStatus.EXECUTED
                val nextRequiredHumanAction = when (automationStatus) {
                    RemoteOpsAutomationDecisionStatus.BLOCKED ->
                        policyRun.nextRequiredHumanAction
                            ?: "Review workflow policy guardrails and execute this step manually."
                    RemoteOpsAutomationDecisionStatus.SUPPRESSED ->
                        "Run manual follow-up for ${policyRun.currentStage.name.lowercase().replace('_', ' ')} stage."
                    RemoteOpsAutomationDecisionStatus.THROTTLED ->
                        "Wait for throttle window reset, or manually continue with operator review."
                    RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE ->
                        "Retry after cooldown, or continue manually if urgent."
                    RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY ->
                        "Automation is running in simulation-only mode; review policy impact and execute manually if needed."
                    else -> null
                }
                val status = when {
                    automationStatus == RemoteOpsAutomationDecisionStatus.EXECUTED -> RemoteOpsAutomationDecisionStatus.EXECUTED
                    automationStatus == RemoteOpsAutomationDecisionStatus.BLOCKED -> RemoteOpsAutomationDecisionStatus.BLOCKED
                    automationStatus == RemoteOpsAutomationDecisionStatus.SUPPRESSED -> RemoteOpsAutomationDecisionStatus.SUPPRESSED
                    automationStatus == RemoteOpsAutomationDecisionStatus.THROTTLED -> RemoteOpsAutomationDecisionStatus.THROTTLED
                    automationStatus == RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE
                    automationStatus == RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY -> RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY
                    else -> RemoteOpsAutomationDecisionStatus.SKIPPED
                }
                val summary = when {
                    status == RemoteOpsAutomationDecisionStatus.BLOCKED ->
                        "Automation blocked by workflow policy guardrails for ${policyRun.currentStage.name.lowercase().replace('_', ' ')} stage."
                    status == RemoteOpsAutomationDecisionStatus.SUPPRESSED ->
                        when {
                            outsideMaintenanceWindow ->
                                "Automation suppressed because execution is outside the maintenance window."
                            outsideQuietHours ->
                                "Automation suppressed because execution is outside quiet-hours policy."
                            stageSuppressed ->
                                "Automation suppressed in ${policyRun.currentStage.name.lowercase().replace('_', ' ')} stage by policy."
                            else ->
                                "Automation suppressed by workflow policy."
                        }
                    status == RemoteOpsAutomationDecisionStatus.THROTTLED ->
                        "Automation throttled because run limits were reached in the active policy window."
                    status == RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE ->
                        "Automation cooldown is active; this run is deferred."
                    status == RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY ->
                        "Automation simulated for ${trigger.name.lowercase().replace('_', ' ')}. Manual execution is still required."
                    executed ->
                        "Automation executed ${rule.action.name.lowercase().replace('_', ' ')} for ${trigger.name.lowercase().replace('_', ' ')}."
                    else ->
                        "Automation skipped by policy."
                }
                val reasonCodes = mutableListOf(
                    RoleReasonCodes.ROLE_AUTOMATION_RULE_TRIGGERED
                )
                reasonCodes += policyEval.reasonCodes
                reasonCodes += when (status) {
                    RemoteOpsAutomationDecisionStatus.EXECUTED -> listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_ELIGIBLE,
                        RoleReasonCodes.ROLE_AUTOMATION_ALLOWED,
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_EXECUTED,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_EXECUTED
                    )
                    RemoteOpsAutomationDecisionStatus.BLOCKED -> listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_BLOCKED,
                        if (!safeAction) {
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_APPROVAL_REQUIRED
                        } else {
                            RoleReasonCodes.ROLE_AUTOMATION_BLOCKED
                        },
                        RoleReasonCodes.ROLE_AUTOMATION_BLOCKED,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED
                    )
                    RemoteOpsAutomationDecisionStatus.SUPPRESSED -> listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_SUPPRESSED,
                        if (outsideMaintenanceWindow) {
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_WINDOW_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_AUTOMATION_SUPPRESSED
                        },
                        RoleReasonCodes.ROLE_AUTOMATION_SUPPRESSED,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED
                    )
                    RemoteOpsAutomationDecisionStatus.THROTTLED -> listOf(
                        RoleReasonCodes.ROLE_AUTOMATION_THROTTLED,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED
                    )
                    RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_COOLDOWN,
                        RoleReasonCodes.ROLE_AUTOMATION_COOLDOWN_ACTIVE,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED
                    )
                    RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY -> listOf(
                        RoleReasonCodes.ROLE_AUTOMATION_SIMULATION_ONLY,
                        RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED
                    )
                    else -> listOf(RoleReasonCodes.ROLE_AUTOMATION_ACTION_SKIPPED)
                }
                val guardrailDecision = WorkflowAutomationGuardrailDecision(
                    status = when (status) {
                        RemoteOpsAutomationDecisionStatus.EXECUTED -> WorkflowAutomationEligibilityStatus.ALLOWED
                        RemoteOpsAutomationDecisionStatus.BLOCKED -> WorkflowAutomationEligibilityStatus.BLOCKED
                        RemoteOpsAutomationDecisionStatus.SUPPRESSED -> WorkflowAutomationEligibilityStatus.SUPPRESSED
                        RemoteOpsAutomationDecisionStatus.THROTTLED -> WorkflowAutomationEligibilityStatus.THROTTLED
                        RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> WorkflowAutomationEligibilityStatus.COOLDOWN_ACTIVE
                        RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY -> WorkflowAutomationEligibilityStatus.SIMULATION_ONLY
                        else -> WorkflowAutomationEligibilityStatus.SUPPRESSED
                    },
                    summary = summary,
                    reasonCodes = reasonCodes.distinct(),
                    evaluatedAtMs = now,
                    nextRequiredHumanAction = nextRequiredHumanAction
                )
                val auditRecord = RemoteOpsAutomationAuditRecord(
                    auditId = "automation_${runId}_${rule.ruleId}_$now",
                    ruleId = rule.ruleId,
                    trigger = rule.trigger,
                    action = rule.action,
                    status = status,
                    summary = summary,
                    source = GovernanceCollaborationActionSource.LOCAL_AUTOMATION,
                    reasonCodes = reasonCodes,
                    timestampMs = now
                )
                val workflowNextAction = if (executed) {
                    WorkflowNextActionSuggestion(
                        title = "Run ${rule.action.name.lowercase().replace('_', ' ')}",
                        detail = summary,
                        action = rule.action,
                        automationEligible = true
                    )
                } else {
                    nextWorkflowActionForStage(
                        template = template,
                        stage = policyRun.currentStage
                    ) ?: WorkflowNextActionSuggestion(
                        title = "Manual follow-up required",
                        detail = nextRequiredHumanAction ?: summary,
                        action = GovernanceActionType.ADD_NOTE,
                        automationEligible = false
                    )
                }
                val updatedRun = policyRun.copy(
                    policyProfile = policyEval.policyProfile,
                    policyPack = policyEval.policyPack,
                    policyPackBinding = policyEval.policyPackBinding,
                    tenantOverride = policyEval.tenantOverride,
                    workspaceOverride = policyEval.workspaceOverride,
                    advancedAutomationControls = policyEval.advancedAutomationControls,
                    policyResolution = policyEval.policyResolution,
                    policyRolloutState = policyEval.policyRolloutState,
                    slaClock = policyEval.slaClock,
                    stageTimer = policyEval.stageTimer,
                    escalationTimer = policyEval.escalationTimer,
                    workflowPolicySummary = policyEval.workflowPolicySummary,
                    policyPackSummary = policyEval.policyPackSummary,
                    policyOverrideSummary = policyEval.policyOverrideSummary,
                    automationControlSummary = policyEval.automationControlSummary,
                    policyResolutionSummary = policyEval.policyResolutionSummary,
                    workflowSimulationOnly = policyEval.workflowSimulationOnly,
                    workflowRolloutSummary = policyEval.rolloutSummary,
                    workflowRolloutApprovalSummary = policyEval.rolloutApprovalSummary,
                    workflowRolloutFreezeSummary = policyEval.rolloutFreezeSummary,
                    workflowRolloutRollbackSummary = policyEval.rolloutRollbackSummary,
                    slaSummary = policyEval.slaSummary,
                    stageTimerSummary = policyEval.stageTimerSummary,
                    escalationTimerSummary = policyEval.escalationTimerSummary,
                    automationGuardrailDecision = guardrailDecision,
                    automationGuardrailSummary = when (guardrailDecision.status) {
                        WorkflowAutomationEligibilityStatus.ALLOWED -> "Automation allowed by workflow policy."
                        WorkflowAutomationEligibilityStatus.BLOCKED -> "Automation blocked by workflow guardrails."
                        WorkflowAutomationEligibilityStatus.SUPPRESSED -> "Automation suppressed at current workflow stage."
                        WorkflowAutomationEligibilityStatus.THROTTLED -> "Automation throttled by workflow guardrails."
                        WorkflowAutomationEligibilityStatus.COOLDOWN_ACTIVE -> "Automation cooldown is active."
                        WorkflowAutomationEligibilityStatus.SIMULATION_ONLY -> "Automation simulated only by workflow controls."
                    },
                    automationSuppressionSummary = if (guardrailDecision.status == WorkflowAutomationEligibilityStatus.ALLOWED) {
                        ""
                    } else {
                        summary
                    },
                    nextRequiredHumanAction = nextRequiredHumanAction,
                    nextAction = workflowNextAction,
                    updatedAtMs = now
                )
                val updatedState = currentState.copy(
                    status = if (currentState.status == OperatorCollaborationStatus.UNCLAIMED) {
                        OperatorCollaborationStatus.REVIEW_IN_PROGRESS
                    } else {
                        currentState.status
                    },
                    claimStatus = if (currentState.claimStatus == OperatorCaseClaimStatus.UNCLAIMED) {
                        OperatorCaseClaimStatus.CLAIMED
                    } else {
                        currentState.claimStatus
                    },
                    claimedBy = currentState.claimedBy ?: actor,
                    assignedTo = currentState.assignedTo ?: actor,
                    operatorSession = buildOperatorSessionSummary(
                        identity = operatorIdentity,
                        now = now,
                        remoteAuthorization = remoteAuthorization
                    ),
                    workflowRun = updatedRun,
                    automationAudit = (currentState.automationAudit + auditRecord).takeLast(40),
                    lastActionSummary = summary,
                    version = nextVersion,
                    updatedAtMs = now
                )
                CollaborationMutationResult(
                    success = true,
                    message = summary,
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updatedState,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = when (status) {
                            RemoteOpsAutomationDecisionStatus.EXECUTED ->
                                ProofLedgerEventType.AUTOMATION_ACTION_EXECUTED
                            RemoteOpsAutomationDecisionStatus.THROTTLED,
                            RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE ->
                                ProofLedgerEventType.AUTOMATION_GUARDRAIL_THROTTLED
                            RemoteOpsAutomationDecisionStatus.BLOCKED,
                            RemoteOpsAutomationDecisionStatus.SUPPRESSED ->
                                ProofLedgerEventType.AUTOMATION_GUARDRAIL_BLOCKED
                            RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY ->
                                ProofLedgerEventType.AUTOMATION_SIMULATION_ONLY
                            else -> ProofLedgerEventType.AUTOMATION_ACTION_SKIPPED
                        },
                        title = when (status) {
                            RemoteOpsAutomationDecisionStatus.EXECUTED -> "Safe automation executed"
                            RemoteOpsAutomationDecisionStatus.THROTTLED,
                            RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> "Automation throttled"
                            RemoteOpsAutomationDecisionStatus.BLOCKED,
                            RemoteOpsAutomationDecisionStatus.SUPPRESSED -> "Automation blocked"
                            RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY -> "Automation simulated"
                            else -> "Safe automation skipped"
                        },
                        detail = summary,
                        timestampMs = now,
                        reasonCodes = reasonCodes.distinct()
                    )
                )
            }

            GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.APPROVE_POLICY_ROLLOUT,
            GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
            GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
            GovernanceActionType.PAUSE_POLICY_ROLLOUT,
            GovernanceActionType.RESUME_POLICY_ROLLOUT,
            GovernanceActionType.FREEZE_POLICY_ROLLOUT,
            GovernanceActionType.ROLLBACK_POLICY_ROLLOUT,
            GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE,
            GovernanceActionType.REQUEST_POLICY_PROMOTION,
            GovernanceActionType.APPROVE_POLICY_PROMOTION,
            GovernanceActionType.REJECT_POLICY_PROMOTION,
            GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
            GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
            GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.DEPRECATE_POLICY_PACK,
            GovernanceActionType.RETIRE_POLICY_PACK,
            GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT,
            GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
            GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
            GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION -> {
                val workflowRun = currentState.workflowRun
                val template = resolveOperatorWorkflowTemplate(
                    templateId = workflowRun?.templateId ?: command.workflowTemplateId ?: "wf_generic_triage",
                    state = currentState
                )
                val baseRun = workflowRun ?: run {
                    val initialStage = template.defaultStage
                    val initialEval = evaluateWorkflowPolicyState(
                        template = template,
                        stage = initialStage,
                        now = now,
                        stageEnteredAtMs = now,
                        previousRun = null,
                        command = null,
                        currentState = currentState
                    )
                    OperatorWorkflowRun(
                        runId = runId,
                        templateId = template.templateId,
                        templateName = template.name.ifBlank { template.templateId },
                        status = OperatorWorkflowRunStatus.ACTIVE,
                        currentStage = initialStage,
                        stageHistory = listOf(
                            OperatorWorkflowStageRecord(
                                stage = initialStage,
                                status = OperatorWorkflowStepStatus.IN_PROGRESS,
                                summary = workflowStageSummary(template, initialStage),
                                enteredAtMs = now
                            )
                        ),
                        policyProfile = initialEval.policyProfile,
                        policyPack = initialEval.policyPack,
                        policyPackBinding = initialEval.policyPackBinding,
                        tenantOverride = initialEval.tenantOverride,
                        workspaceOverride = initialEval.workspaceOverride,
                        advancedAutomationControls = initialEval.advancedAutomationControls,
                        policyResolution = initialEval.policyResolution,
                        policyRolloutState = initialEval.policyRolloutState,
                        slaClock = initialEval.slaClock,
                        stageTimer = initialEval.stageTimer,
                        escalationTimer = initialEval.escalationTimer,
                        workflowPolicySummary = initialEval.workflowPolicySummary,
                        policyPackSummary = initialEval.policyPackSummary,
                        policyOverrideSummary = initialEval.policyOverrideSummary,
                        automationControlSummary = initialEval.automationControlSummary,
                        policyResolutionSummary = initialEval.policyResolutionSummary,
                        workflowSimulationOnly = initialEval.workflowSimulationOnly,
                        workflowRolloutSummary = initialEval.rolloutSummary,
                        workflowRolloutApprovalSummary = initialEval.rolloutApprovalSummary,
                        workflowRolloutFreezeSummary = initialEval.rolloutFreezeSummary,
                        workflowRolloutRollbackSummary = initialEval.rolloutRollbackSummary,
                        workflowPromotionStatus = initialEval.policyRolloutState?.promotionStatus,
                        workflowPromotionSummary = initialEval.policyRolloutState?.summary.orEmpty(),
                        workflowPromotionReadinessSummary = initialEval.policyRolloutState
                            ?.promotionReadiness
                            ?.summary
                            .orEmpty(),
                        workflowPromotionBlockerSummary = initialEval.policyRolloutState
                            ?.promotionReadiness
                            ?.blockers
                            ?.mapNotNull { it.summary.takeIf(String::isNotBlank) }
                            ?.joinToString("; ")
                            .orEmpty(),
                        workflowPromotionRecommendationSummary = initialEval.policyRolloutState
                            ?.promotionReadiness
                            ?.recommendation
                            ?.summary
                            .orEmpty(),
                        slaSummary = initialEval.slaSummary,
                        stageTimerSummary = initialEval.stageTimerSummary,
                        escalationTimerSummary = initialEval.escalationTimerSummary,
                        nextAction = nextWorkflowActionForStage(template, initialStage),
                        updatedAtMs = now
                    )
                }
                val stageEnteredAt = baseRun.stageHistory
                    .lastOrNull { it.stage == baseRun.currentStage }
                    ?.enteredAtMs
                    ?.takeIf { it > 0L }
                    ?: now
                val policyEval = evaluateWorkflowPolicyState(
                    template = template,
                    stage = baseRun.currentStage,
                    now = now,
                    stageEnteredAtMs = stageEnteredAt,
                    previousRun = baseRun,
                    command = command,
                    currentState = currentState
                )
                val updatedRun = baseRun.copy(
                    policyProfile = policyEval.policyProfile,
                    policyPack = policyEval.policyPack,
                    policyPackBinding = policyEval.policyPackBinding,
                    tenantOverride = policyEval.tenantOverride,
                    workspaceOverride = policyEval.workspaceOverride,
                    advancedAutomationControls = policyEval.advancedAutomationControls,
                    policyResolution = policyEval.policyResolution,
                    policyRolloutState = policyEval.policyRolloutState,
                    slaClock = policyEval.slaClock,
                    stageTimer = policyEval.stageTimer,
                    escalationTimer = policyEval.escalationTimer,
                    workflowPolicySummary = policyEval.workflowPolicySummary,
                    policyPackSummary = policyEval.policyPackSummary,
                    policyOverrideSummary = policyEval.policyOverrideSummary,
                    automationControlSummary = policyEval.automationControlSummary,
                    policyResolutionSummary = policyEval.policyResolutionSummary,
                    workflowSimulationOnly = policyEval.workflowSimulationOnly,
                    workflowRolloutSummary = policyEval.rolloutSummary,
                    workflowRolloutApprovalSummary = policyEval.rolloutApprovalSummary,
                    workflowRolloutFreezeSummary = policyEval.rolloutFreezeSummary,
                    workflowRolloutRollbackSummary = policyEval.rolloutRollbackSummary,
                    workflowPromotionStatus = policyEval.policyRolloutState?.promotionStatus,
                    workflowPromotionSummary = policyEval.policyRolloutState?.summary.orEmpty(),
                    workflowPromotionReadinessSummary = policyEval.policyRolloutState
                        ?.promotionReadiness
                        ?.summary
                        .orEmpty(),
                    workflowPromotionBlockerSummary = policyEval.policyRolloutState
                        ?.promotionReadiness
                        ?.blockers
                        ?.mapNotNull { it.summary.takeIf(String::isNotBlank) }
                        ?.joinToString("; ")
                        .orEmpty(),
                    workflowPromotionRecommendationSummary = policyEval.policyRolloutState
                        ?.promotionReadiness
                        ?.recommendation
                        ?.summary
                        .orEmpty(),
                    slaSummary = policyEval.slaSummary,
                    stageTimerSummary = policyEval.stageTimerSummary,
                    escalationTimerSummary = policyEval.escalationTimerSummary,
                    nextRequiredHumanAction = baseRun.nextRequiredHumanAction,
                    nextAction = nextWorkflowActionForStage(template, baseRun.currentStage),
                    updatedAtMs = now
                )
                val promotionState = policyEval.policyRolloutState
                val summary = when (command.commandType) {
                    GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
                    GovernanceActionType.APPROVE_POLICY_ROLLOUT,
                    GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL ->
                        policyEval.rolloutApprovalSummary
                    GovernanceActionType.PAUSE_POLICY_ROLLOUT,
                    GovernanceActionType.RESUME_POLICY_ROLLOUT,
                    GovernanceActionType.FREEZE_POLICY_ROLLOUT ->
                        policyEval.rolloutFreezeSummary
                    GovernanceActionType.ROLLBACK_POLICY_ROLLOUT ->
                        policyEval.rolloutRollbackSummary
                    GovernanceActionType.REQUEST_POLICY_PROMOTION ->
                        promotionState?.promotionRequest?.summary
                            ?.takeIf { it.isNotBlank() }
                            ?: promotionState?.summary.orEmpty()
                    GovernanceActionType.APPROVE_POLICY_PROMOTION,
                    GovernanceActionType.REJECT_POLICY_PROMOTION ->
                        promotionState?.promotionDecision?.summary
                            ?.takeIf { it.isNotBlank() }
                            ?: promotionState?.approvalReviewSummary?.summary.orEmpty()
                    GovernanceActionType.ADVANCE_POLICY_ROLLOUT ->
                        promotionState?.promotionReadiness?.recommendation?.summary
                            ?.takeIf { it.isNotBlank() }
                            ?: policyEval.rolloutSummary
                    GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
                    GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
                    GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
                    GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
                    GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
                    GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
                    GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
                    GovernanceActionType.DEPRECATE_POLICY_PACK,
                    GovernanceActionType.RETIRE_POLICY_PACK,
                    GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT,
                    GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
                    GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
                    GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION ->
                        promotionState?.summary
                            ?.takeIf { it.isNotBlank() }
                            ?: policyEval.rolloutSummary
                    else -> policyEval.rolloutSummary
                }.ifBlank {
                    when (command.commandType) {
                        GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL -> "Policy rollout approval requested."
                        GovernanceActionType.APPROVE_POLICY_ROLLOUT -> "Policy rollout approval granted."
                        GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL -> "Policy rollout approval denied."
                        GovernanceActionType.PROMOTE_POLICY_ROLLOUT -> "Policy rollout promoted."
                        GovernanceActionType.ENFORCE_POLICY_ROLLOUT -> "Policy rollout enforced."
                        GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE -> "Policy rollout scope expanded."
                        GovernanceActionType.PAUSE_POLICY_ROLLOUT -> "Policy rollout paused."
                        GovernanceActionType.RESUME_POLICY_ROLLOUT -> "Policy rollout resumed."
                        GovernanceActionType.FREEZE_POLICY_ROLLOUT -> "Policy rollout frozen."
                        GovernanceActionType.ROLLBACK_POLICY_ROLLOUT -> "Policy rollout rolled back."
                        GovernanceActionType.REQUEST_POLICY_PROMOTION -> "Policy promotion requested."
                        GovernanceActionType.APPROVE_POLICY_PROMOTION -> "Policy promotion approved."
                        GovernanceActionType.REJECT_POLICY_PROMOTION -> "Policy promotion rejected."
                        GovernanceActionType.ADVANCE_POLICY_ROLLOUT -> "Policy rollout advanced."
                        GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM -> "Policy governance program created."
                        GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE -> "Policy governance wave advanced."
                        GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE -> "Policy governance wave paused."
                        GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION -> "Policy rollout exemption added."
                        GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION -> "Policy rollout exemption removed."
                        GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET -> "Policy rollout target pinned."
                        GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET -> "Policy rollout target unpinned."
                        GovernanceActionType.DEPRECATE_POLICY_PACK -> "Policy pack marked deprecated."
                        GovernanceActionType.RETIRE_POLICY_PACK -> "Policy pack retirement started."
                        GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT -> "Policy pack replacement plan attached."
                        GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN -> "Policy estate remediation plan attached."
                        GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER -> "Policy estate blocker acknowledged."
                        GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION -> "Policy estate remediation scheduled."
                        GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION -> "Policy estate remediation paused."
                        GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION -> "Policy estate remediation resumed."
                        GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION -> "Policy estate remediation cancelled."
                        GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION -> "Safe policy estate remediation applied."
                        else -> "Policy rollout state updated."
                    }
                }
                val actionReasonCode = when (command.commandType) {
                    GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVAL_REQUESTED
                    GovernanceActionType.APPROVE_POLICY_ROLLOUT ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVED
                    GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_DENIED
                    GovernanceActionType.PROMOTE_POLICY_ROLLOUT ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED)) {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_STAGED
                        }
                    GovernanceActionType.ENFORCE_POLICY_ROLLOUT ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED)) {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_ENFORCED
                        }
                    GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED)) {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_SCOPE_EXPANDED
                        }
                    GovernanceActionType.PAUSE_POLICY_ROLLOUT ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_PAUSED
                    GovernanceActionType.FREEZE_POLICY_ROLLOUT ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_FROZEN
                    GovernanceActionType.RESUME_POLICY_ROLLOUT ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_RESTORED_LAST_SAFE
                    GovernanceActionType.ROLLBACK_POLICY_ROLLOUT ->
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_ROLLED_BACK
                    GovernanceActionType.REQUEST_POLICY_PROMOTION ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED)) {
                            RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_PROMOTION_REQUESTED
                        }
                    GovernanceActionType.APPROVE_POLICY_PROMOTION ->
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_APPROVED
                    GovernanceActionType.REJECT_POLICY_PROMOTION ->
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_REJECTED
                    GovernanceActionType.ADVANCE_POLICY_ROLLOUT ->
                        if (
                            policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_DENIED) ||
                            policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED)
                        ) {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_DENIED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_ALLOWED
                        }
                    GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM ->
                        RoleReasonCodes.ROLE_POLICY_PROGRAM_CREATED
                    GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE ->
                        RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_ADVANCED
                    GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE ->
                        RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_PAUSED
                    GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION ->
                        RoleReasonCodes.ROLE_POLICY_TARGET_EXEMPTED
                    GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION ->
                        RoleReasonCodes.ROLE_POLICY_TARGET_UNEXEMPTED
                    GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET ->
                        RoleReasonCodes.ROLE_POLICY_TARGET_PINNED
                    GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET ->
                        RoleReasonCodes.ROLE_POLICY_TARGET_UNPINNED
                    GovernanceActionType.DEPRECATE_POLICY_PACK ->
                        RoleReasonCodes.ROLE_POLICY_PACK_DEPRECATED
                    GovernanceActionType.RETIRE_POLICY_PACK ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED)) {
                            RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED
                        } else {
                            RoleReasonCodes.ROLE_POLICY_PACK_RETIREMENT_STARTED
                        }
                    GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT ->
                        RoleReasonCodes.ROLE_POLICY_PACK_REPLACEMENT_ATTACHED
                    GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN ->
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED
                    GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER ->
                        RoleReasonCodes.ROLE_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED
                    GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION ->
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_SCHEDULED
                    GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION ->
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_PAUSED
                    GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION ->
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_RESUMED
                    GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION ->
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_CANCELLED
                    GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION ->
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_APPLIED
                    else -> RoleReasonCodes.ROLE_POLICY_ROLLOUT_SIMULATION_ONLY
                }
                val eventType = when (command.commandType) {
                    GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVAL_REQUESTED
                    GovernanceActionType.APPROVE_POLICY_ROLLOUT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVED
                    GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVAL_DENIED
                    GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
                    GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
                    GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE ->
                        if (policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED)) {
                            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PROMOTION_REQUESTED
                        } else if (command.commandType == GovernanceActionType.ENFORCE_POLICY_ROLLOUT) {
                            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ENFORCED
                        } else if (command.commandType == GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE) {
                            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_SCOPE_EXPANDED
                        } else {
                            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PROMOTED
                        }
                    GovernanceActionType.PAUSE_POLICY_ROLLOUT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PAUSED
                    GovernanceActionType.FREEZE_POLICY_ROLLOUT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_FROZEN
                    GovernanceActionType.RESUME_POLICY_ROLLOUT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_RESUMED
                    GovernanceActionType.ROLLBACK_POLICY_ROLLOUT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ROLLED_BACK
                    GovernanceActionType.REQUEST_POLICY_PROMOTION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REQUESTED
                    GovernanceActionType.APPROVE_POLICY_PROMOTION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_APPROVED
                    GovernanceActionType.REJECT_POLICY_PROMOTION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REJECTED
                    GovernanceActionType.ADVANCE_POLICY_ROLLOUT ->
                        if (
                            policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_DENIED) ||
                            policyEval.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED)
                        ) {
                            ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED
                        } else {
                            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ADVANCED
                        }
                    GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CREATED
                    GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_ADVANCED
                    GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_PAUSED
                    GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_TARGET_EXEMPTED
                    GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNEXEMPTED
                    GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET ->
                        ProofLedgerEventType.WORKFLOW_POLICY_TARGET_PINNED
                    GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET ->
                        ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNPINNED
                    GovernanceActionType.DEPRECATE_POLICY_PACK ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PACK_DEPRECATED
                    GovernanceActionType.RETIRE_POLICY_PACK ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PACK_RETIREMENT_STARTED
                    GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT ->
                        ProofLedgerEventType.WORKFLOW_POLICY_PACK_REPLACEMENT_ATTACHED
                    GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED
                    GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED
                    GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_SCHEDULED
                    GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED
                    GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_SCHEDULED
                    GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION ->
                        ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_APPLIED
                    else -> ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_SIMULATION_STARTED
                }
                val eventTitle = when (eventType) {
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVAL_REQUESTED ->
                        "Workflow rollout approval requested"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVED ->
                        "Workflow rollout approval granted"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVAL_DENIED ->
                        "Workflow rollout approval denied"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PROMOTION_REQUESTED ->
                        "Workflow rollout promotion blocked"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PROMOTED ->
                        "Workflow rollout promoted"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ENFORCED ->
                        "Workflow rollout enforced"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_SCOPE_EXPANDED ->
                        "Workflow rollout scope expanded"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_PAUSED ->
                        "Workflow rollout paused"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_RESUMED ->
                        "Workflow rollout resumed"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_FROZEN ->
                        "Workflow rollout frozen"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ROLLED_BACK ->
                        "Workflow rollout rolled back"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REQUESTED ->
                        "Workflow policy promotion requested"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_APPROVED ->
                        "Workflow policy promotion approved"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_REJECTED ->
                        "Workflow policy promotion rejected"
                    ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_ADVANCED ->
                        "Workflow rollout advanced"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROMOTION_READINESS_EVALUATED ->
                        "Workflow promotion readiness evaluated"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CREATED ->
                        "Policy governance program created"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_ADVANCED ->
                        "Policy governance wave advanced"
                    ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_PAUSED ->
                        "Policy governance wave paused"
                    ProofLedgerEventType.WORKFLOW_POLICY_TARGET_EXEMPTED ->
                        "Policy rollout target exempted"
                    ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNEXEMPTED ->
                        "Policy rollout exemption removed"
                    ProofLedgerEventType.WORKFLOW_POLICY_TARGET_PINNED ->
                        "Policy rollout target pinned"
                    ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNPINNED ->
                        "Policy rollout target unpinned"
                    ProofLedgerEventType.WORKFLOW_POLICY_PACK_DEPRECATED ->
                        "Policy pack deprecated"
                    ProofLedgerEventType.WORKFLOW_POLICY_PACK_RETIREMENT_STARTED ->
                        "Policy pack retirement started"
                    ProofLedgerEventType.WORKFLOW_POLICY_PACK_REPLACEMENT_ATTACHED ->
                        "Policy replacement attached"
                    ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED ->
                        "Policy estate remediation plan attached"
                    ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED ->
                        "Policy estate blocker acknowledged"
                    ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_SCHEDULED ->
                        "Policy estate remediation scheduled"
                    ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_APPLIED ->
                        "Policy estate remediation applied"
                    else -> "Workflow rollout simulation started"
                }
                val updatedState = currentState.copy(
                    status = if (currentState.status == OperatorCollaborationStatus.UNCLAIMED) {
                        OperatorCollaborationStatus.REVIEW_IN_PROGRESS
                    } else {
                        currentState.status
                    },
                    claimStatus = if (currentState.claimStatus == OperatorCaseClaimStatus.UNCLAIMED) {
                        OperatorCaseClaimStatus.CLAIMED
                    } else {
                        currentState.claimStatus
                    },
                    claimedBy = currentState.claimedBy ?: actor,
                    assignedTo = currentState.assignedTo ?: actor,
                    operatorSession = buildOperatorSessionSummary(
                        identity = operatorIdentity,
                        now = now,
                        remoteAuthorization = remoteAuthorization
                    ),
                    workflowRun = updatedRun,
                    lastActionSummary = summary,
                    version = nextVersion,
                    updatedAtMs = now
                )
                CollaborationMutationResult(
                    success = true,
                    message = summary,
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updatedState,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = eventType,
                        title = eventTitle,
                        detail = summary,
                        timestampMs = now,
                        reasonCodes = (listOf(actionReasonCode) + policyEval.reasonCodes).distinct()
                    )
                )
            }

            GovernanceActionType.ACK_REMOTE_HANDOFF -> {
                val handoff = currentHandoff ?: return CollaborationMutationResult(
                    success = false,
                    message = "No remote handoff record exists for this case."
                )
                if (handoff.status == RemoteOperatorHandoffStatus.ACKNOWLEDGED) {
                    return CollaborationMutationResult(
                        success = true,
                        message = "Remote handoff already acknowledged."
                    )
                }
                val ackAttempt = RemoteOperatorHandoffAttempt(
                    attemptId = "handoff_ack_${runId}_$now",
                    status = RemoteOperatorHandoffStatus.ACKNOWLEDGED,
                    dedupeKey = handoff.dedupeKey.ifBlank { "handoff:${runId}:ack" },
                    summary = "Manual handoff acknowledgement recorded in governance console.",
                    timestampMs = now
                )
                val updatedHandoff = mergeRemoteOperatorHandoffRecord(
                    previous = handoff,
                    incoming = handoff.copy(
                        status = RemoteOperatorHandoffStatus.ACKNOWLEDGED,
                        attempts = handoff.attempts + ackAttempt,
                        lastAttemptAtMs = now,
                        lastErrorSummary = null
                    )
                )
                val updatedState = currentState.copy(
                    followUp = currentState.followUp?.copy(
                        ackPending = false,
                        resolvedAtMs = now
                    ),
                    status = if (currentState.status == OperatorCollaborationStatus.FOLLOW_UP_PENDING) {
                        OperatorCollaborationStatus.REVIEW_IN_PROGRESS
                    } else {
                        currentState.status
                    },
                    operatorSession = buildOperatorSessionSummary(
                            identity = operatorIdentity,
                            now = now,
                            remoteAuthorization = remoteAuthorization
                        ),
                    lastActionSummary = "Remote handoff acknowledged by ${actor.displayName}.",
                    version = nextVersion,
                    updatedAtMs = now
                )
                CollaborationMutationResult(
                    success = true,
                    message = "Remote handoff acknowledged.",
                    operatorIdentity = operatorIdentity,
                    updatedCollaborationState = updatedState,
                    updatedRemoteHandoff = updatedHandoff,
                    event = RunEventRecord(
                        eventId = commandDedupeId,
                        type = ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED,
                        title = "Remote handoff acknowledged",
                        detail = "Operator acknowledged remote handoff for this case.",
                        timestampMs = now,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED)
                    )
                )
            }

            else -> {
                CollaborationMutationResult(
                    success = false,
                    message = "Unsupported collaboration command: ${command.commandType.name.lowercase()}."
                )
            }
        }
        val enrichedMutation = enrichCollaborationMutationState(
            runId = runId,
            command = command,
            actor = actor,
            now = now,
            previousState = currentState,
            mutation = mutation
        )
        val audit = enrichedMutation.operatorConnectorAudit ?: buildOperatorConnectorAuditLink(
            operatorIdentity = operatorIdentity,
            directoryEntry = operatorResolution.directoryEntry,
            remoteAuthorization = remoteAuthorization,
            routingRecord = enrichedMutation.updatedAlertRoutingRecords.lastOrNull(),
            now = now
        )
        return enrichedMutation.copy(
            remoteAuthorizationResult = enrichedMutation.remoteAuthorizationResult ?: remoteAuthorization,
            operatorConnectorAudit = audit
        )
    }

    private fun enrichCollaborationMutationState(
        runId: String,
        command: GovernanceCollaborationCommand,
        actor: OperatorAssigneeRef,
        now: Long,
        previousState: GovernanceCaseCollaborationState,
        mutation: CollaborationMutationResult
    ): CollaborationMutationResult {
        val updated = mutation.updatedCollaborationState ?: return mutation
        val source = command.collaborationSource
        val actorRecord = GovernanceCollaborationActor(
            actorId = actor.userId,
            displayName = actor.displayName,
            source = source
        )
        var state = updated
        val reasonCodes = mutation.event?.reasonCodes.orEmpty()
        val workflowStage = state.workflowRun?.currentStage

        fun appendCollaborationEvent(
            type: GovernanceCollaborationEventType,
            summary: String,
            eventReasonCodes: List<String>,
            stage: OperatorWorkflowStage? = workflowStage
        ) {
            if (summary.isBlank()) return
            val record = GovernanceCollaborationEventRecord(
                eventId = "collab_event_${runId}_${type.name.lowercase()}_$now",
                type = type,
                actor = actorRecord,
                summary = summary,
                reasonCodes = eventReasonCodes.distinct(),
                workflowStage = stage,
                timestampMs = now
            )
            state = state.copy(
                collaborationEvents = (state.collaborationEvents + record).takeLast(60)
            )
        }

        when (command.commandType) {
            GovernanceActionType.ADD_NOTE -> {
                val latest = state.notes.lastOrNull()
                if (latest != null) {
                    val noteType = if (source == GovernanceCollaborationActionSource.LOCAL_AUTOMATION) {
                        GovernanceCaseNoteType.AUTOMATION
                    } else {
                        GovernanceCaseNoteType.GENERAL
                    }
                    val retagged = latest.copy(
                        noteType = noteType,
                        source = source
                    )
                    state = state.copy(
                        notes = (state.notes.dropLast(1) + retagged).takeLast(20)
                    )
                }
                appendCollaborationEvent(
                    type = GovernanceCollaborationEventType.NOTE_ADDED,
                    summary = state.lastActionSummary.ifBlank { "Operator note added." },
                    eventReasonCodes = reasonCodes.ifEmpty {
                        listOf(RoleReasonCodes.ROLE_CASE_NOTE_ADDED)
                    }
                )
            }

            GovernanceActionType.REQUEST_FOLLOW_UP -> {
                val handoff = GovernanceCaseHandoffRecord(
                    handoffId = "handoff_hist_${runId}_$now",
                    fromAssignee = previousState.assignedTo ?: previousState.claimedBy,
                    toAssignee = state.assignedTo ?: actor,
                    targetTeam = command.target?.trim()?.takeIf { it.isNotBlank() },
                    reason = state.followUp?.summary?.ifBlank { state.lastActionSummary }
                        ?: "Operator follow-up requested.",
                    workflowStage = state.workflowRun?.currentStage,
                    source = source,
                    createdAtMs = now
                )
                state = state.copy(
                    handoffHistory = (state.handoffHistory + handoff).takeLast(40)
                )
                appendCollaborationEvent(
                    type = GovernanceCollaborationEventType.HANDOFF_CREATED,
                    summary = handoff.reason,
                    eventReasonCodes = reasonCodes.ifEmpty {
                        listOf(RoleReasonCodes.ROLE_CASE_HANDOFF_CREATED)
                    },
                    stage = handoff.workflowStage
                )
            }

            GovernanceActionType.ESCALATE_CASE -> {
                val escalationState = state.escalation
                val escalation = GovernanceCaseEscalationRecord(
                    escalationId = "escalation_hist_${runId}_$now",
                    target = escalationState?.target.orEmpty().ifBlank {
                        command.escalationTarget?.trim().orEmpty()
                    },
                    reason = escalationState?.summary
                        ?.takeIf { it.isNotBlank() }
                        ?: state.lastActionSummary,
                    status = GovernanceCaseEscalationRecordStatus.REQUESTED,
                    requestedBy = actor,
                    workflowStage = state.workflowRun?.currentStage,
                    createdAtMs = now
                )
                state = state.copy(
                    escalationHistory = (state.escalationHistory + escalation).takeLast(40)
                )
                appendCollaborationEvent(
                    type = GovernanceCollaborationEventType.ESCALATION_CREATED,
                    summary = escalation.reason,
                    eventReasonCodes = reasonCodes.ifEmpty {
                        listOf(RoleReasonCodes.ROLE_CASE_ESCALATION_CREATED)
                    },
                    stage = escalation.workflowStage
                )
            }

            GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE -> {
                appendCollaborationEvent(
                    type = GovernanceCollaborationEventType.WORKFLOW_TEMPLATE_ATTACHED,
                    summary = state.lastActionSummary.ifBlank { "Workflow template attached." },
                    eventReasonCodes = reasonCodes.ifEmpty {
                        listOf(RoleReasonCodes.ROLE_WORKFLOW_TEMPLATE_ATTACHED)
                    }
                )
                state.workflowRun?.workflowPolicySummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { policySummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.WORKFLOW_POLICY_APPLIED,
                            summary = policySummary,
                            eventReasonCodes = listOf(RoleReasonCodes.ROLE_WORKFLOW_POLICY_APPLIED)
                        )
                    }
                state.workflowRun?.slaSummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { slaSummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.SLA_STATUS_CHANGED,
                            summary = slaSummary,
                            eventReasonCodes = state.workflowRun?.slaClock?.status?.toSlaReasonCodes().orEmpty()
                        )
                    }
                state.workflowRun?.escalationTimerSummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { escalationSummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.ESCALATION_TIMER_STATUS_CHANGED,
                            summary = escalationSummary,
                            eventReasonCodes = state.workflowRun?.escalationTimer?.status?.toEscalationReasonCodes().orEmpty()
                        )
                    }
            }

            GovernanceActionType.ADVANCE_WORKFLOW_STAGE -> {
                appendCollaborationEvent(
                    type = GovernanceCollaborationEventType.WORKFLOW_STAGE_CHANGED,
                    summary = state.lastActionSummary.ifBlank { "Workflow stage changed." },
                    eventReasonCodes = reasonCodes.ifEmpty {
                        listOf(RoleReasonCodes.ROLE_WORKFLOW_STAGE_CHANGED)
                    }
                )
                state.workflowRun?.workflowPolicySummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { policySummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.WORKFLOW_POLICY_APPLIED,
                            summary = policySummary,
                            eventReasonCodes = listOf(RoleReasonCodes.ROLE_WORKFLOW_POLICY_APPLIED)
                        )
                    }
                state.workflowRun?.slaSummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { slaSummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.SLA_STATUS_CHANGED,
                            summary = slaSummary,
                            eventReasonCodes = state.workflowRun?.slaClock?.status?.toSlaReasonCodes().orEmpty()
                        )
                    }
                state.workflowRun?.escalationTimerSummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { escalationSummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.ESCALATION_TIMER_STATUS_CHANGED,
                            summary = escalationSummary,
                            eventReasonCodes = state.workflowRun?.escalationTimer?.status?.toEscalationReasonCodes().orEmpty()
                        )
                    }
            }

            GovernanceActionType.RUN_SAFE_AUTOMATION -> {
                val latestAudit = state.automationAudit.lastOrNull()
                val eventType = when (latestAudit?.status) {
                    RemoteOpsAutomationDecisionStatus.EXECUTED ->
                        GovernanceCollaborationEventType.AUTOMATION_ACTION_EXECUTED
                    RemoteOpsAutomationDecisionStatus.BLOCKED,
                    RemoteOpsAutomationDecisionStatus.SUPPRESSED,
                    RemoteOpsAutomationDecisionStatus.THROTTLED,
                    RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY,
                    RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE ->
                        GovernanceCollaborationEventType.AUTOMATION_GUARDRAIL_EVALUATED
                    else -> GovernanceCollaborationEventType.AUTOMATION_ACTION_SKIPPED
                }
                appendCollaborationEvent(
                    type = eventType,
                    summary = latestAudit?.summary?.ifBlank { state.lastActionSummary } ?: state.lastActionSummary,
                    eventReasonCodes = latestAudit?.reasonCodes.orEmpty().ifEmpty {
                        reasonCodes.ifEmpty {
                            listOf(RoleReasonCodes.ROLE_AUTOMATION_RULE_TRIGGERED)
                        }
                    }
                )
                state.workflowRun?.automationGuardrailSummary
                    ?.takeIf { it.isNotBlank() }
                    ?.let { guardrailSummary ->
                        appendCollaborationEvent(
                            type = GovernanceCollaborationEventType.AUTOMATION_GUARDRAIL_EVALUATED,
                            summary = guardrailSummary,
                            eventReasonCodes = state.workflowRun
                                ?.automationGuardrailDecision
                                ?.reasonCodes
                                .orEmpty()
                        )
                    }
            }

            GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.APPROVE_POLICY_ROLLOUT,
            GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
            GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
            GovernanceActionType.PAUSE_POLICY_ROLLOUT,
            GovernanceActionType.RESUME_POLICY_ROLLOUT,
            GovernanceActionType.FREEZE_POLICY_ROLLOUT,
            GovernanceActionType.ROLLBACK_POLICY_ROLLOUT,
            GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE,
            GovernanceActionType.REQUEST_POLICY_PROMOTION,
            GovernanceActionType.APPROVE_POLICY_PROMOTION,
            GovernanceActionType.REJECT_POLICY_PROMOTION,
            GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
            GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
            GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.DEPRECATE_POLICY_PACK,
            GovernanceActionType.RETIRE_POLICY_PACK,
            GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT,
            GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
            GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
            GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION -> {
                val rolloutSummary = when (command.commandType) {
                    GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
                    GovernanceActionType.APPROVE_POLICY_ROLLOUT,
                    GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL ->
                        state.workflowRun?.workflowRolloutApprovalSummary
                    GovernanceActionType.PAUSE_POLICY_ROLLOUT,
                    GovernanceActionType.RESUME_POLICY_ROLLOUT,
                    GovernanceActionType.FREEZE_POLICY_ROLLOUT ->
                        state.workflowRun?.workflowRolloutFreezeSummary
                    GovernanceActionType.ROLLBACK_POLICY_ROLLOUT ->
                        state.workflowRun?.workflowRolloutRollbackSummary
                    GovernanceActionType.REQUEST_POLICY_PROMOTION ->
                        state.workflowRun?.workflowPromotionSummary
                    GovernanceActionType.APPROVE_POLICY_PROMOTION,
                    GovernanceActionType.REJECT_POLICY_PROMOTION ->
                        state.workflowRun?.workflowPromotionReadinessSummary
                    GovernanceActionType.ADVANCE_POLICY_ROLLOUT ->
                        state.workflowRun?.workflowPromotionRecommendationSummary
                    GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
                    GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
                    GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
                    GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
                    GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
                    GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
                    GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
                    GovernanceActionType.DEPRECATE_POLICY_PACK,
                    GovernanceActionType.RETIRE_POLICY_PACK,
                    GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT ->
                        state.workflowRun?.workflowProgramSummary
                            .takeUnless { it.isNullOrBlank() }
                            ?: state.workflowRun?.workflowCrossTenantSummary
                            .takeUnless { it.isNullOrBlank() }
                            ?: state.workflowRun?.workflowPackLifecycleSummary
                            .takeUnless { it.isNullOrBlank() }
                    GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
                    GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
                    GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
                    GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION ->
                        state.workflowRun?.policyRolloutState?.policyEstateSummary
                            .takeUnless { it.isNullOrBlank() }
                            ?: state.workflowRun?.policyRolloutState?.policyEstateRemediationSummary
                            .takeUnless { it.isNullOrBlank() }
                            ?: state.workflowRun?.policyRolloutState?.scheduledRemediationPlan?.summary
                            .takeUnless { it.isNullOrBlank() }
                            ?: state.workflowRun?.policyRolloutState?.policyEstateBlockerSummary
                            .takeUnless { it.isNullOrBlank() }
                    else -> state.workflowRun?.workflowRolloutSummary
                }.orEmpty().ifBlank {
                    state.lastActionSummary.ifBlank { "Workflow rollout state updated." }
                }
                val collabType = when (command.commandType) {
                    GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
                    GovernanceActionType.APPROVE_POLICY_ROLLOUT,
                    GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL,
                    GovernanceActionType.APPROVE_POLICY_PROMOTION,
                    GovernanceActionType.REJECT_POLICY_PROMOTION ->
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_APPROVAL_UPDATED
                    GovernanceActionType.ROLLBACK_POLICY_ROLLOUT ->
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_ROLLED_BACK
                    else ->
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_UPDATED
                }
                appendCollaborationEvent(
                    type = collabType,
                    summary = rolloutSummary,
                    eventReasonCodes = reasonCodes.ifEmpty {
                        state.workflowRun?.policyRolloutState?.summary
                            ?.takeIf { it.isNotBlank() }
                            ?.let { listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_SIMULATION_ONLY) }
                            ?: emptyList()
                    }
                )
            }

            else -> Unit
        }
        return mutation.copy(updatedCollaborationState = state)
    }

    private fun WorkflowSlaStatus.toSlaReasonCodes(): List<String> {
        return when (this) {
            WorkflowSlaStatus.ON_TIME -> listOf(RoleReasonCodes.ROLE_SLA_ACTIVE)
            WorkflowSlaStatus.APPROACHING_BREACH -> listOf(RoleReasonCodes.ROLE_SLA_APPROACHING_BREACH)
            WorkflowSlaStatus.BREACHED -> listOf(RoleReasonCodes.ROLE_SLA_BREACHED)
            WorkflowSlaStatus.NONE,
            WorkflowSlaStatus.PAUSED -> emptyList()
        }
    }

    private fun WorkflowEscalationTimerStatus.toEscalationReasonCodes(): List<String> {
        return when (this) {
            WorkflowEscalationTimerStatus.REQUIRED -> listOf(RoleReasonCodes.ROLE_ESCALATION_REQUIRED)
            WorkflowEscalationTimerStatus.TRIGGERED -> listOf(RoleReasonCodes.ROLE_ESCALATION_TRIGGERED)
            WorkflowEscalationTimerStatus.NOT_REQUIRED,
            WorkflowEscalationTimerStatus.PENDING,
            WorkflowEscalationTimerStatus.CLEARED -> emptyList()
        }
    }

    private fun resolveOperatorWorkflowTemplate(
        templateId: String,
        state: GovernanceCaseCollaborationState
    ): OperatorWorkflowTemplate {
        val normalizedId = templateId.trim().ifBlank { "wf_generic_triage" }
        val catalog = workflowTemplateCatalog()
        val direct = catalog.firstOrNull { it.templateId.equals(normalizedId, ignoreCase = true) }
        if (direct != null) return direct
        val inferredByState = when {
            state.status == OperatorCollaborationStatus.FOLLOW_UP_PENDING ->
                catalog.firstOrNull { it.templateId == "wf_provider_follow_up" }
            state.escalation?.escalated == true ->
                catalog.firstOrNull { it.templateId == "wf_escalation_resolution" }
            else ->
                catalog.firstOrNull { it.templateId == "wf_generic_triage" }
        }
        return inferredByState ?: catalog.first()
    }

    private fun workflowTemplateCatalog(): List<OperatorWorkflowTemplate> {
        return listOf(
            OperatorWorkflowTemplate(
                templateId = "wf_generic_triage",
                name = "General Governance Triage",
                summary = "Triage, review evidence, and close low-risk governance runs.",
                queueTags = listOf(GovernanceQueueType.NEEDS_ATTENTION),
                reasonFamilies = listOf(GovernanceReasonFamily.DURABILITY),
                defaultStage = OperatorWorkflowStage.TRIAGE,
                stages = listOf(
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.TRIAGE,
                        title = "Triage",
                        summary = "Classify the case and confirm ownership.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.CLAIM_CASE,
                                summary = "Claim case ownership.",
                                safeAutomationEligible = false
                            ),
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.ADD_NOTE,
                                summary = "Add concise triage note.",
                                safeAutomationEligible = true
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.UNDER_REVIEW,
                        title = "Under review",
                        summary = "Review receipt and evidence trail before resolution.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.MARK_REVIEWED,
                                summary = "Mark reviewed when no blocker remains.",
                                safeAutomationEligible = true
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.RESOLVED,
                        title = "Resolved",
                        summary = "Case has been resolved and closed.",
                        recommendedActions = emptyList()
                    )
                ),
                policyProfile = workflowPolicyProfileForTemplate("wf_generic_triage")
            ),
            OperatorWorkflowTemplate(
                templateId = "wf_provider_follow_up",
                name = "Provider Follow-up",
                summary = "Track provider acknowledgements and resolve sync/policy issues.",
                queueTags = listOf(
                    GovernanceQueueType.PROVIDER_ISSUE,
                    GovernanceQueueType.SYNC_PENDING,
                    GovernanceQueueType.DISPUTE_FOLLOW_UP
                ),
                reasonFamilies = listOf(
                    GovernanceReasonFamily.PROVIDER_POLICY,
                    GovernanceReasonFamily.SETTLEMENT_RECONCILIATION
                ),
                defaultStage = OperatorWorkflowStage.WAITING_PROVIDER,
                stages = listOf(
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.WAITING_PROVIDER,
                        title = "Waiting provider",
                        summary = "Provider acknowledgement or callback is pending.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.REQUEST_FOLLOW_UP,
                                summary = "Request provider follow-up.",
                                safeAutomationEligible = false
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.WAITING_SYNC,
                        title = "Waiting sync",
                        summary = "Reconciliation sync is pending confirmation.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.RETRY_SYNC_INTENT,
                                summary = "Request sync retry.",
                                safeAutomationEligible = true
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.UNDER_REVIEW,
                        title = "Under review",
                        summary = "Review provider response and dispute/rollback trail.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.ACK_REMOTE_HANDOFF,
                                summary = "Acknowledge remote handoff when response arrives.",
                                safeAutomationEligible = false
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.RESOLVED,
                        title = "Resolved",
                        summary = "Provider follow-up completed and case is closed.",
                        recommendedActions = emptyList()
                    )
                ),
                policyProfile = workflowPolicyProfileForTemplate("wf_provider_follow_up")
            ),
            OperatorWorkflowTemplate(
                templateId = "wf_escalation_resolution",
                name = "Escalation Resolution",
                summary = "Escalate critical reconciliation/rollback issues and track closure.",
                queueTags = listOf(
                    GovernanceQueueType.RECONCILIATION_MISMATCH,
                    GovernanceQueueType.ROLLBACK_FAILURE
                ),
                reasonFamilies = listOf(
                    GovernanceReasonFamily.ROLLBACK_DISPUTE,
                    GovernanceReasonFamily.SETTLEMENT_RECONCILIATION
                ),
                defaultStage = OperatorWorkflowStage.AWAITING_ESCALATION,
                stages = listOf(
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.AWAITING_ESCALATION,
                        title = "Awaiting escalation",
                        summary = "Critical mismatch or rollback failure requires escalation.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.ESCALATE_CASE,
                                summary = "Escalate to specialist queue.",
                                safeAutomationEligible = false
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.AWAITING_RETRY,
                        title = "Awaiting retry",
                        summary = "Wait for retry after escalation guidance.",
                        recommendedActions = listOf(
                            OperatorWorkflowActionTemplate(
                                action = GovernanceActionType.RETRY_SYNC_INTENT,
                                summary = "Request reconciliation retry.",
                                safeAutomationEligible = true
                            )
                        )
                    ),
                    OperatorWorkflowStageDefinition(
                        stage = OperatorWorkflowStage.RESOLVED,
                        title = "Resolved",
                        summary = "Escalated issue has been resolved.",
                        recommendedActions = emptyList()
                    )
                ),
                policyProfile = workflowPolicyProfileForTemplate("wf_escalation_resolution")
            )
        )
    }

    private fun workflowPolicyProfileForTemplate(templateId: String): WorkflowPolicyProfile {
        return when (templateId) {
            "wf_provider_follow_up" -> WorkflowPolicyProfile(
                policyId = "wf_policy_provider_follow_up",
                version = "m20_v1",
                summary = "Provider follow-up policy enforces SLA and escalation-aware automation guardrails.",
                stagePolicies = listOf(
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.WAITING_PROVIDER,
                        maxStageDurationMs = 4 * 60 * 60 * 1000L,
                        escalationAfterMs = 2 * 60 * 60 * 1000L,
                        allowAutomation = false,
                        requiredHumanAction = "Request provider follow-up or escalate if provider acknowledgement remains pending."
                    ),
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.WAITING_SYNC,
                        maxStageDurationMs = 3 * 60 * 60 * 1000L,
                        escalationAfterMs = 90 * 60 * 1000L,
                        allowAutomation = true,
                        requiredHumanAction = "Monitor sync acknowledgement and verify settlement reconciliation before closure."
                    ),
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.UNDER_REVIEW,
                        maxStageDurationMs = 2 * 60 * 60 * 1000L,
                        allowAutomation = false,
                        requiredHumanAction = "Review proof and verification outcomes manually."
                    ),
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.RESOLVED,
                        allowAutomation = false
                    )
                ),
                transitionPolicies = listOf(
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.WAITING_PROVIDER,
                        allowedTo = listOf(
                            OperatorWorkflowStage.WAITING_SYNC,
                            OperatorWorkflowStage.AWAITING_ESCALATION,
                            OperatorWorkflowStage.UNDER_REVIEW
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.WAITING_SYNC,
                        allowedTo = listOf(
                            OperatorWorkflowStage.UNDER_REVIEW,
                            OperatorWorkflowStage.AWAITING_ESCALATION,
                            OperatorWorkflowStage.RESOLVED
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.UNDER_REVIEW,
                        allowedTo = listOf(
                            OperatorWorkflowStage.AWAITING_ESCALATION,
                            OperatorWorkflowStage.RESOLVED
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.AWAITING_ESCALATION,
                        allowedTo = listOf(
                            OperatorWorkflowStage.AWAITING_RETRY,
                            OperatorWorkflowStage.UNDER_REVIEW,
                            OperatorWorkflowStage.RESOLVED
                        )
                    )
                ),
                slaPolicy = WorkflowSlaPolicy(
                    targetMs = 6 * 60 * 60 * 1000L,
                    warningMs = 60 * 60 * 1000L
                ),
                escalationPolicy = WorkflowEscalationPolicy(
                    enabled = true,
                    targetMs = 2 * 60 * 60 * 1000L,
                    triggerOnSlaBreach = true
                ),
                automationGuardrail = WorkflowAutomationGuardrail(
                    allowAutomation = true,
                    suppressedStages = listOf(
                        OperatorWorkflowStage.UNDER_REVIEW,
                        OperatorWorkflowStage.AWAITING_ESCALATION
                    ),
                    blockedActions = listOf(GovernanceActionType.ESCALATE_CASE),
                    blockWhenSlaBreached = true,
                    blockWhenEscalationRequired = true,
                    cooldownMs = 10 * 60 * 1000L,
                    throttleWindowMs = 60 * 60 * 1000L,
                    maxRunsPerWindow = 2
                )
            )

            "wf_escalation_resolution" -> WorkflowPolicyProfile(
                policyId = "wf_policy_escalation_resolution",
                version = "m20_v1",
                summary = "Escalation workflow policy prioritizes human review and limits automation to retry intents.",
                stagePolicies = listOf(
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.AWAITING_ESCALATION,
                        maxStageDurationMs = 90 * 60 * 1000L,
                        escalationAfterMs = 45 * 60 * 1000L,
                        allowAutomation = false,
                        requiredHumanAction = "Escalate to specialist queue and capture triage note."
                    ),
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.AWAITING_RETRY,
                        maxStageDurationMs = 2 * 60 * 60 * 1000L,
                        allowAutomation = true,
                        requiredHumanAction = "Confirm retry result and reconcile any mismatch."
                    )
                ),
                transitionPolicies = listOf(
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.AWAITING_ESCALATION,
                        allowedTo = listOf(
                            OperatorWorkflowStage.AWAITING_RETRY,
                            OperatorWorkflowStage.UNDER_REVIEW
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.AWAITING_RETRY,
                        allowedTo = listOf(
                            OperatorWorkflowStage.UNDER_REVIEW,
                            OperatorWorkflowStage.RESOLVED
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.UNDER_REVIEW,
                        allowedTo = listOf(OperatorWorkflowStage.RESOLVED)
                    )
                ),
                slaPolicy = WorkflowSlaPolicy(
                    targetMs = 4 * 60 * 60 * 1000L,
                    warningMs = 30 * 60 * 1000L
                ),
                escalationPolicy = WorkflowEscalationPolicy(
                    enabled = true,
                    targetMs = 45 * 60 * 1000L,
                    triggerOnSlaBreach = true
                ),
                automationGuardrail = WorkflowAutomationGuardrail(
                    allowAutomation = true,
                    suppressedStages = listOf(OperatorWorkflowStage.AWAITING_ESCALATION),
                    blockedActions = listOf(
                        GovernanceActionType.ESCALATE_CASE,
                        GovernanceActionType.REQUEST_FOLLOW_UP
                    ),
                    blockWhenSlaBreached = true,
                    blockWhenEscalationRequired = true,
                    cooldownMs = 15 * 60 * 1000L,
                    throttleWindowMs = 60 * 60 * 1000L,
                    maxRunsPerWindow = 1
                )
            )

            else -> WorkflowPolicyProfile(
                policyId = "wf_policy_generic_triage",
                version = "m20_v1",
                summary = "Generic triage policy keeps workflows measurable with bounded low-risk automation.",
                stagePolicies = listOf(
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.TRIAGE,
                        maxStageDurationMs = 2 * 60 * 60 * 1000L,
                        escalationAfterMs = 60 * 60 * 1000L,
                        allowAutomation = false,
                        requiredHumanAction = "Claim ownership and capture triage context."
                    ),
                    WorkflowStagePolicy(
                        stage = OperatorWorkflowStage.UNDER_REVIEW,
                        maxStageDurationMs = 3 * 60 * 60 * 1000L,
                        allowAutomation = true,
                        requiredHumanAction = "Verify evidence before marking reviewed."
                    )
                ),
                transitionPolicies = listOf(
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.TRIAGE,
                        allowedTo = listOf(
                            OperatorWorkflowStage.UNDER_REVIEW,
                            OperatorWorkflowStage.AWAITING_ESCALATION
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.UNDER_REVIEW,
                        allowedTo = listOf(
                            OperatorWorkflowStage.RESOLVED,
                            OperatorWorkflowStage.AWAITING_ESCALATION
                        )
                    ),
                    WorkflowTransitionPolicy(
                        from = OperatorWorkflowStage.AWAITING_ESCALATION,
                        allowedTo = listOf(
                            OperatorWorkflowStage.UNDER_REVIEW,
                            OperatorWorkflowStage.RESOLVED
                        )
                    )
                ),
                slaPolicy = WorkflowSlaPolicy(
                    targetMs = 8 * 60 * 60 * 1000L,
                    warningMs = 90 * 60 * 1000L
                ),
                escalationPolicy = WorkflowEscalationPolicy(
                    enabled = true,
                    targetMs = 60 * 60 * 1000L,
                    triggerOnSlaBreach = true
                ),
                automationGuardrail = WorkflowAutomationGuardrail(
                    allowAutomation = true,
                    suppressedStages = listOf(OperatorWorkflowStage.TRIAGE),
                    blockedActions = listOf(GovernanceActionType.ESCALATE_CASE),
                    blockWhenSlaBreached = true,
                    blockWhenEscalationRequired = true,
                    cooldownMs = 10 * 60 * 1000L,
                    throttleWindowMs = 60 * 60 * 1000L,
                    maxRunsPerWindow = 1
                )
            )
        }
    }

    private data class WorkflowPolicyResolution(
        val policyProfile: WorkflowPolicyProfile,
        val policyPack: WorkflowPolicyPack? = null,
        val policyPackBinding: WorkflowPolicyPackBinding? = null,
        val tenantOverride: TenantWorkflowPolicyOverride? = null,
        val workspaceOverride: WorkspaceWorkflowPolicyOverride? = null,
        val advancedAutomationControls: WorkflowAutomationAdvancedControls? = null,
        val policyResolution: WorkflowPolicyResolutionTrace = WorkflowPolicyResolutionTrace(),
        val policyRolloutState: WorkflowPolicyRolloutState? = null,
        val policyPackSummary: String = "",
        val policyOverrideSummary: String = "",
        val automationControlSummary: String = "",
        val policyResolutionSummary: String = "",
        val rolloutSummary: String = "",
        val rolloutApprovalSummary: String = "",
        val rolloutFreezeSummary: String = "",
        val rolloutRollbackSummary: String = "",
        val simulationOnly: Boolean = false,
        val reasonCodes: List<String> = emptyList()
    )

    private data class WorkflowPolicyEvaluation(
        val policyProfile: WorkflowPolicyProfile,
        val policyPack: WorkflowPolicyPack? = null,
        val policyPackBinding: WorkflowPolicyPackBinding? = null,
        val tenantOverride: TenantWorkflowPolicyOverride? = null,
        val workspaceOverride: WorkspaceWorkflowPolicyOverride? = null,
        val advancedAutomationControls: WorkflowAutomationAdvancedControls? = null,
        val policyResolution: WorkflowPolicyResolutionTrace = WorkflowPolicyResolutionTrace(),
        val policyRolloutState: WorkflowPolicyRolloutState? = null,
        val slaClock: WorkflowSlaClock,
        val stageTimer: WorkflowStageTimerState,
        val escalationTimer: WorkflowEscalationTimerState,
        val workflowPolicySummary: String,
        val policyPackSummary: String,
        val policyOverrideSummary: String,
        val automationControlSummary: String,
        val policyResolutionSummary: String,
        val rolloutSummary: String,
        val rolloutApprovalSummary: String,
        val rolloutFreezeSummary: String,
        val rolloutRollbackSummary: String,
        val workflowSimulationOnly: Boolean,
        val slaSummary: String,
        val stageTimerSummary: String,
        val escalationTimerSummary: String,
        val reasonCodes: List<String>
    )

    private fun evaluateWorkflowPolicyState(
        template: OperatorWorkflowTemplate,
        stage: OperatorWorkflowStage,
        now: Long,
        stageEnteredAtMs: Long,
        previousRun: OperatorWorkflowRun?,
        command: GovernanceCollaborationCommand? = null,
        currentState: GovernanceCaseCollaborationState? = null
    ): WorkflowPolicyEvaluation {
        val resolution = resolveWorkflowPolicyResolution(
            template = template,
            command = command,
            currentState = currentState,
            previousRun = previousRun,
            now = now
        )
        val policy = resolution.policyProfile
        val stagePolicy = policy.stagePolicies.firstOrNull { it.stage == stage }
        val stageDueAt = stagePolicy?.maxStageDurationMs
            ?.takeIf { it > 0L }
            ?.let { stageEnteredAtMs + it }
        val stageTimerStatus = when {
            stage == OperatorWorkflowStage.RESOLVED -> WorkflowStageTimerStatus.COMPLETED
            stageDueAt != null && now >= stageDueAt -> WorkflowStageTimerStatus.OVERDUE
            else -> WorkflowStageTimerStatus.ACTIVE
        }
        val stageTimerSummary = when (stageTimerStatus) {
            WorkflowStageTimerStatus.OVERDUE ->
                "Stage timer is overdue for ${stage.name.lowercase().replace('_', ' ')}."
            WorkflowStageTimerStatus.COMPLETED ->
                "Stage timer completed for ${stage.name.lowercase().replace('_', ' ')}."
            WorkflowStageTimerStatus.ACTIVE ->
                "Stage timer is active for ${stage.name.lowercase().replace('_', ' ')}."
            WorkflowStageTimerStatus.PAUSED ->
                "Stage timer is paused for ${stage.name.lowercase().replace('_', ' ')}."
            WorkflowStageTimerStatus.NOT_STARTED ->
                "Stage timer has not started."
        }
        val stageTimer = WorkflowStageTimerState(
            status = stageTimerStatus,
            startedAtMs = stageEnteredAtMs,
            dueAtMs = stageDueAt,
            summary = stageTimerSummary
        )

        val slaStart = previousRun?.slaClock?.startedAtMs
            ?.takeIf { it > 0L }
            ?: stageEnteredAtMs
        val slaPolicy = policy.slaPolicy
        val slaDueAt = slaPolicy?.targetMs
            ?.takeIf { it > 0L }
            ?.let { slaStart + it }
        val slaWarningAt = if (slaDueAt != null && (slaPolicy?.warningMs ?: 0L) > 0L) {
            slaDueAt - (slaPolicy?.warningMs ?: 0L)
        } else {
            null
        }
        val slaStatus = when {
            slaPolicy == null || slaPolicy.targetMs <= 0L -> WorkflowSlaStatus.NONE
            stage == OperatorWorkflowStage.RESOLVED -> WorkflowSlaStatus.ON_TIME
            slaDueAt != null && now >= slaDueAt -> WorkflowSlaStatus.BREACHED
            slaWarningAt != null && now >= slaWarningAt -> WorkflowSlaStatus.APPROACHING_BREACH
            else -> WorkflowSlaStatus.ON_TIME
        }
        val slaSummary = when (slaStatus) {
            WorkflowSlaStatus.NONE -> "SLA is not tracked for this workflow policy."
            WorkflowSlaStatus.ON_TIME -> "SLA is on time."
            WorkflowSlaStatus.APPROACHING_BREACH -> "SLA is approaching breach and needs active follow-up."
            WorkflowSlaStatus.BREACHED -> "SLA is breached and requires escalation handling."
            WorkflowSlaStatus.PAUSED -> "SLA is paused by workflow policy."
        }
        val slaClock = WorkflowSlaClock(
            startedAtMs = slaStart,
            dueAtMs = slaDueAt,
            warningAtMs = slaWarningAt,
            status = slaStatus,
            breachedAtMs = if (slaStatus == WorkflowSlaStatus.BREACHED) {
                previousRun?.slaClock?.breachedAtMs ?: now
            } else {
                previousRun?.slaClock?.breachedAtMs
            },
            summary = slaSummary
        )

        val escalationPolicy = policy.escalationPolicy
        val stageEscalationAfterMs = stagePolicy?.escalationAfterMs?.takeIf { it > 0L }
        val escalationDueAt = when {
            escalationPolicy == null || !escalationPolicy.enabled -> null
            stage == OperatorWorkflowStage.RESOLVED -> null
            stageEscalationAfterMs != null -> stageEnteredAtMs + stageEscalationAfterMs
            escalationPolicy.targetMs > 0L -> stageEnteredAtMs + escalationPolicy.targetMs
            else -> null
        }
        val escalationRequiredByTimer = escalationDueAt != null && now >= escalationDueAt
        val escalationRequiredBySla = escalationPolicy?.triggerOnSlaBreach == true &&
            slaStatus == WorkflowSlaStatus.BREACHED
        val previouslyEscalated = previousRun?.escalationTimer?.status == WorkflowEscalationTimerStatus.REQUIRED ||
            previousRun?.escalationTimer?.status == WorkflowEscalationTimerStatus.TRIGGERED
        val escalationStatus = when {
            escalationPolicy == null || !escalationPolicy.enabled -> WorkflowEscalationTimerStatus.NOT_REQUIRED
            stage == OperatorWorkflowStage.RESOLVED -> WorkflowEscalationTimerStatus.CLEARED
            escalationRequiredByTimer || escalationRequiredBySla -> {
                if (previouslyEscalated) {
                    WorkflowEscalationTimerStatus.TRIGGERED
                } else {
                    WorkflowEscalationTimerStatus.REQUIRED
                }
            }
            else -> WorkflowEscalationTimerStatus.PENDING
        }
        val escalationSummary = when (escalationStatus) {
            WorkflowEscalationTimerStatus.NOT_REQUIRED -> "Escalation timer is not required for this policy."
            WorkflowEscalationTimerStatus.PENDING -> "Escalation timer is pending."
            WorkflowEscalationTimerStatus.REQUIRED -> "Escalation is required by workflow policy."
            WorkflowEscalationTimerStatus.TRIGGERED -> "Escalation timer was triggered."
            WorkflowEscalationTimerStatus.CLEARED -> "Escalation timer is cleared."
        }
        val escalationTimer = WorkflowEscalationTimerState(
            status = escalationStatus,
            dueAtMs = escalationDueAt,
            triggeredAtMs = if (
                escalationStatus == WorkflowEscalationTimerStatus.REQUIRED ||
                escalationStatus == WorkflowEscalationTimerStatus.TRIGGERED
            ) {
                previousRun?.escalationTimer?.triggeredAtMs ?: now
            } else {
                previousRun?.escalationTimer?.triggeredAtMs
            },
            summary = escalationSummary
        )

        val workflowPolicySummary = policy.summary.ifBlank {
            "Workflow policy ${policy.policyId.ifBlank { template.templateId }} is active."
        }
        val reasonCodes = buildList {
            add(RoleReasonCodes.ROLE_WORKFLOW_POLICY_APPLIED)
            addAll(resolution.reasonCodes)
            addAll(slaStatus.toSlaReasonCodes())
            addAll(escalationStatus.toEscalationReasonCodes())
        }.distinct()
        return WorkflowPolicyEvaluation(
            policyProfile = policy,
            policyPack = resolution.policyPack,
            policyPackBinding = resolution.policyPackBinding,
            tenantOverride = resolution.tenantOverride,
            workspaceOverride = resolution.workspaceOverride,
            advancedAutomationControls = resolution.advancedAutomationControls,
            policyResolution = resolution.policyResolution,
            policyRolloutState = resolution.policyRolloutState,
            slaClock = slaClock,
            stageTimer = stageTimer,
            escalationTimer = escalationTimer,
            workflowPolicySummary = workflowPolicySummary,
            policyPackSummary = resolution.policyPackSummary,
            policyOverrideSummary = resolution.policyOverrideSummary,
            automationControlSummary = resolution.automationControlSummary,
            policyResolutionSummary = resolution.policyResolutionSummary,
            rolloutSummary = resolution.rolloutSummary,
            rolloutApprovalSummary = resolution.rolloutApprovalSummary,
            rolloutFreezeSummary = resolution.rolloutFreezeSummary,
            rolloutRollbackSummary = resolution.rolloutRollbackSummary,
            workflowSimulationOnly = resolution.simulationOnly,
            slaSummary = slaSummary,
            stageTimerSummary = stageTimerSummary,
            escalationTimerSummary = escalationSummary,
            reasonCodes = reasonCodes
        )
    }

    private fun resolveWorkflowPolicyResolution(
        template: OperatorWorkflowTemplate,
        command: GovernanceCollaborationCommand?,
        currentState: GovernanceCaseCollaborationState?,
        previousRun: OperatorWorkflowRun?,
        now: Long
    ): WorkflowPolicyResolution {
        val templatePolicy = template.policyProfile ?: workflowPolicyProfileForTemplate(template.templateId)
        val previousPack = previousRun?.policyPack
        val previousBinding = previousRun?.policyPackBinding
        val previousTenantOverride = previousRun?.tenantOverride
        val previousWorkspaceOverride = previousRun?.workspaceOverride
        val previousRolloutState = previousRun?.policyRolloutState

        val requestedPackId = command?.policyPackId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: command?.workflowPolicyPackId
                ?.trim()
                ?.takeIf { it.isNotBlank() }
            ?: previousPack?.packId
        val requestedPackVersion = command?.policyPackVersionId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: command?.workflowPolicyPackVersion
                ?.trim()
                ?.takeIf { it.isNotBlank() }
            ?: previousBinding?.versionId
            ?: previousPack?.activeVersionId

        val baseControls = previousRun?.advancedAutomationControls
            ?: workflowAutomationControlsFromPolicy(templatePolicy)

        val selectedPackVersion = when {
            previousPack != null && requestedPackId != null &&
                previousPack.packId.equals(requestedPackId, ignoreCase = true) -> {
                previousPack.versions.firstOrNull { version ->
                    requestedPackVersion == null || version.versionId.equals(requestedPackVersion, ignoreCase = true)
                }
            }

            else -> null
        }
            ?: requestedPackId?.let { packId ->
                val versionId = requestedPackVersion ?: "${template.templateId}_v1"
                WorkflowPolicyPackVersion(
                    versionId = versionId,
                    policyVersion = "${templatePolicy.version}_${packId.take(24)}",
                    workflowTemplateIds = listOf(template.templateId),
                    policyProfile = templatePolicy.copy(
                        version = "${templatePolicy.version}_${packId.take(24)}",
                        summary = templatePolicy.summary.ifBlank {
                            "Workflow policy ${templatePolicy.policyId.ifBlank { template.templateId }} is active."
                        }
                    ),
                    automationControls = baseControls,
                    createdAtMs = now,
                    updatedAtMs = now,
                    summary = "Pack version $versionId for template ${template.name.ifBlank { template.templateId }}."
                )
            }

        val explicitSimulationRequested = command?.automationSimulationOnly == true ||
            command?.explicitCaseConstraintSimulationOnly == true
        val inferredPackActivation = when {
            explicitSimulationRequested -> WorkflowPolicyPackActivationState.SIMULATION_ONLY
            previousPack?.activationState != null -> previousPack.activationState
            requestedPackId != null -> WorkflowPolicyPackActivationState.ACTIVE
            else -> WorkflowPolicyPackActivationState.INACTIVE
        }

        val policyPack = when {
            previousPack != null && requestedPackId == null -> previousPack
            requestedPackId != null -> {
                val version = selectedPackVersion
                val versionId = version?.versionId ?: requestedPackVersion ?: "${template.templateId}_v1"
                WorkflowPolicyPack(
                    packId = requestedPackId,
                    name = previousPack?.name?.takeIf { it.isNotBlank() }
                        ?: "Workflow pack ${requestedPackId.take(16)}",
                    scope = previousPack?.scope ?: WorkflowPolicyPackScope.GLOBAL,
                    activationState = inferredPackActivation,
                    activeVersionId = versionId,
                    versions = listOfNotNull(version),
                    createdAtMs = previousPack?.createdAtMs?.takeIf { it > 0L } ?: now,
                    updatedAtMs = now,
                    summary = previousPack?.summary?.takeIf { it.isNotBlank() }
                        ?: "Workflow policy pack $requestedPackId is active for ${template.name.ifBlank { template.templateId }}."
                )
            }

            else -> previousPack
        }

        val policyPackBinding = policyPack?.let { pack ->
            val scope = when {
                !command?.workspacePolicyOverrideId.isNullOrBlank() -> WorkflowPolicyPackScope.WORKSPACE
                !command?.tenantPolicyOverrideId.isNullOrBlank() -> WorkflowPolicyPackScope.TENANT
                previousBinding?.scope != null -> previousBinding.scope
                else -> pack.scope
            }
            val boundVersion = selectedPackVersion?.versionId
                ?: requestedPackVersion
                ?: previousBinding?.versionId
                ?: pack.activeVersionId
                ?: "${template.templateId}_v1"
            previousBinding?.takeIf {
                it.packId.equals(pack.packId, ignoreCase = true) &&
                    it.versionId.equals(boundVersion, ignoreCase = true) &&
                    it.scope == scope
            } ?: WorkflowPolicyPackBinding(
                bindingId = "binding_${pack.packId.take(24)}_${template.templateId.take(16)}",
                packId = pack.packId,
                versionId = boundVersion,
                scope = scope,
                tenantId = previousBinding?.tenantId?.takeIf { it.isNotBlank() } ?: "tenant_default",
                workspaceId = previousBinding?.workspaceId?.takeIf { it.isNotBlank() } ?: "workspace_default",
                workflowTemplateIds = listOf(template.templateId),
                activationState = pack.activationState,
                precedence = when (scope) {
                    WorkflowPolicyPackScope.WORKSPACE -> 30
                    WorkflowPolicyPackScope.TENANT -> 20
                    WorkflowPolicyPackScope.GLOBAL -> 10
                },
                boundAtMs = now,
                summary = "Policy pack ${pack.packId} bound at $scope scope."
            )
        }

        val tenantOverride = resolveTenantWorkflowOverride(
            command = command,
            template = template,
            templatePolicy = templatePolicy,
            now = now,
            previousOverride = previousTenantOverride
        )
        val workspaceOverride = resolveWorkspaceWorkflowOverride(
            command = command,
            template = template,
            templatePolicy = templatePolicy,
            now = now,
            previousOverride = previousWorkspaceOverride
        )

        val tenantOverrideActive = tenantOverride?.takeIf { isWorkflowOverrideActive(it.approvalState, it.effectiveFromMs, it.effectiveUntilMs, now) }
        val workspaceOverrideActive = workspaceOverride?.takeIf { isWorkflowOverrideActive(it.approvalState, it.effectiveFromMs, it.effectiveUntilMs, now) }

        var precedence = WorkflowPolicyPrecedenceSource.TEMPLATE_DEFAULT
        var resolvedPolicy = templatePolicy
        var resolvedControls = baseControls
        val resolutionReasonCodes = mutableListOf<String>()

        policyPackBinding?.let {
            val policyFromPack = selectedPackVersion?.policyProfile ?: templatePolicy
            val controlsFromPack = selectedPackVersion?.automationControls ?: resolvedControls
            resolvedPolicy = policyFromPack
            resolvedControls = mergeWorkflowAutomationControls(resolvedControls, controlsFromPack)
            precedence = WorkflowPolicyPrecedenceSource.POLICY_PACK
            resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PACK_APPLIED
            resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_POLICY_PACK
        } ?: run {
            resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_TEMPLATE_DEFAULT
        }

        tenantOverride?.let { override ->
            if (tenantOverrideActive == null) {
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_OVERRIDE_DENIED
            } else {
                precedence = WorkflowPolicyPrecedenceSource.TENANT_OVERRIDE
                resolvedPolicy = override.policyProfile ?: resolvedPolicy
                resolvedControls = mergeWorkflowAutomationControls(resolvedControls, override.automationControls)
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_TENANT_OVERRIDE_APPLIED
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_TENANT_OVERRIDE
            }
        }

        workspaceOverride?.let { override ->
            if (workspaceOverrideActive == null) {
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_OVERRIDE_DENIED
            } else {
                precedence = WorkflowPolicyPrecedenceSource.WORKSPACE_OVERRIDE
                resolvedPolicy = override.policyProfile ?: resolvedPolicy
                resolvedControls = mergeWorkflowAutomationControls(resolvedControls, override.automationControls)
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_WORKSPACE_OVERRIDE_APPLIED
                resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_WORKSPACE_OVERRIDE
            }
        }

        val explicitNoAutomation = command?.explicitCaseConstraintNoAutomation == true
        val explicitSimulation = command?.explicitCaseConstraintSimulationOnly == true
        val commandSimulation = command?.automationSimulationOnly == true
        if (explicitNoAutomation || explicitSimulation) {
            precedence = WorkflowPolicyPrecedenceSource.EXPLICIT_CONSTRAINT
            resolutionReasonCodes += RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_EXPLICIT_CONSTRAINT
        }
        if (explicitNoAutomation) {
            resolvedControls = resolvedControls.copy(
                maxRunsPerCase = 0,
                maxRunsPerWindow = 0,
                suppressionStages = OperatorWorkflowStage.entries.toList(),
                summary = "Explicit case constraint disabled workflow automation for this run."
            )
            resolutionReasonCodes += RoleReasonCodes.ROLE_AUTOMATION_BLOCKED
        }
        if (explicitSimulation || commandSimulation || policyPack?.activationState == WorkflowPolicyPackActivationState.SIMULATION_ONLY) {
            resolvedControls = resolvedControls.copy(
                simulationOnly = true,
                summary = resolvedControls.summary.ifBlank {
                    "Workflow automation runs in simulation-only mode."
                }
            )
            resolutionReasonCodes += RoleReasonCodes.ROLE_AUTOMATION_SIMULATION_ONLY
        }

        val rolloutResolution = resolveWorkflowPolicyRolloutState(
            previous = previousRolloutState,
            command = command,
            actor = command?.toActor(),
            workflowTemplateId = template.templateId,
            workflowPackVersion = policyPackBinding?.versionId ?: selectedPackVersion?.versionId,
            defaultScope = when (policyPackBinding?.scope ?: policyPack?.scope) {
                WorkflowPolicyPackScope.GLOBAL -> PolicyRolloutScope.GLOBAL
                WorkflowPolicyPackScope.TENANT -> PolicyRolloutScope.TENANT
                WorkflowPolicyPackScope.WORKSPACE -> PolicyRolloutScope.WORKSPACE
                null -> PolicyRolloutScope.WORKFLOW_TEMPLATE
            },
            now = now
        )
        if (rolloutResolution.forceSimulationOnly) {
            resolvedControls = resolvedControls.copy(
                simulationOnly = true,
                summary = resolvedControls.summary.ifBlank {
                    "Workflow automation runs in simulation-only mode."
                }
            )
        }
        if (rolloutResolution.freezeBlocksAutomation) {
            resolvedControls = resolvedControls.copy(
                maxRunsPerCase = 0,
                maxRunsPerWindow = 0,
                suppressionStages = OperatorWorkflowStage.entries.toList(),
                simulationOnly = true,
                summary = "Rollout freeze/pause blocked automation; manual operator action is required."
            )
        }
        resolutionReasonCodes += rolloutResolution.reasonCodes

        val policyPackSummary = when {
            policyPack == null ->
                "No workflow policy pack binding was applied."
            else -> {
                val activeVersion = policyPackBinding?.versionId
                    ?: policyPack.activeVersionId
                    ?: selectedPackVersion?.versionId
                    ?: "unknown"
                "Workflow policy pack ${policyPack.name.ifBlank { policyPack.packId }} ($activeVersion) is ${policyPack.activationState.name.lowercase().replace('_', ' ')}."
            }
        }
        val policyOverrideSummary = buildList {
            workspaceOverrideActive?.let {
                add("Workspace override ${it.overrideId} applied.")
            }
            tenantOverrideActive?.let {
                add("Tenant override ${it.overrideId} applied.")
            }
            if (isEmpty()) {
                tenantOverride?.let {
                    add("Tenant override ${it.overrideId} not active.")
                }
                workspaceOverride?.let {
                    add("Workspace override ${it.overrideId} not active.")
                }
            }
        }.joinToString(" ").ifBlank { "No tenant/workspace overrides were applied." }
        val automationControlSummary = resolvedControls.summary.ifBlank {
            buildString {
                append("Automation controls")
                append(" max runs/case ${resolvedControls.maxRunsPerCase.coerceAtLeast(0)}")
                append(", max runs/window ${resolvedControls.maxRunsPerWindow.coerceAtLeast(0)}")
                if (resolvedControls.cooldownMs > 0L) {
                    append(", cooldown ${resolvedControls.cooldownMs / 1000}s")
                }
                if (resolvedControls.throttleWindowMs > 0L) {
                    append(", throttle window ${resolvedControls.throttleWindowMs / 1000}s")
                }
                if (resolvedControls.simulationOnly) {
                    append(", simulation only")
                }
                append(".")
            }
        }
        val policyResolutionSummary = when (precedence) {
            WorkflowPolicyPrecedenceSource.EXPLICIT_CONSTRAINT ->
                "Policy resolution used explicit case constraints over workspace/tenant/pack defaults."
            WorkflowPolicyPrecedenceSource.OPERATOR_OVERRIDE ->
                "Policy resolution used operator override settings."
            WorkflowPolicyPrecedenceSource.WORKSPACE_OVERRIDE ->
                "Policy resolution used workspace workflow override settings."
            WorkflowPolicyPrecedenceSource.TENANT_OVERRIDE ->
                "Policy resolution used tenant workflow override settings."
            WorkflowPolicyPrecedenceSource.POLICY_PACK ->
                "Policy resolution used workflow policy pack binding."
            WorkflowPolicyPrecedenceSource.TEMPLATE_DEFAULT ->
                "Policy resolution used workflow template defaults."
        }
        val simulationOnly = resolvedControls.simulationOnly || rolloutResolution.forceSimulationOnly
        val policyResolution = WorkflowPolicyResolutionTrace(
            precedenceSource = precedence,
            packId = policyPack?.packId,
            packVersionId = policyPackBinding?.versionId ?: selectedPackVersion?.versionId,
            bindingId = policyPackBinding?.bindingId,
            tenantOverrideId = tenantOverride?.overrideId,
            workspaceOverrideId = workspaceOverride?.overrideId,
            simulationOnly = simulationOnly,
            reasonCodes = (resolutionReasonCodes + precedenceReasonCodeFor(precedence)).distinct(),
            summary = policyResolutionSummary
        )

        return WorkflowPolicyResolution(
            policyProfile = resolvedPolicy,
            policyPack = policyPack,
            policyPackBinding = policyPackBinding,
            tenantOverride = tenantOverride,
            workspaceOverride = workspaceOverride,
            advancedAutomationControls = resolvedControls,
            policyResolution = policyResolution,
            policyRolloutState = rolloutResolution.state,
            policyPackSummary = policyPackSummary,
            policyOverrideSummary = policyOverrideSummary,
            automationControlSummary = automationControlSummary,
            policyResolutionSummary = policyResolutionSummary,
            rolloutSummary = rolloutResolution.rolloutSummary,
            rolloutApprovalSummary = rolloutResolution.approvalSummary,
            rolloutFreezeSummary = rolloutResolution.freezeSummary,
            rolloutRollbackSummary = rolloutResolution.rollbackSummary,
            simulationOnly = simulationOnly,
            reasonCodes = (resolutionReasonCodes + precedenceReasonCodeFor(precedence)).distinct()
        )
    }

    private data class WorkflowPolicyRolloutResolution(
        val state: WorkflowPolicyRolloutState,
        val reasonCodes: List<String> = emptyList(),
        val forceSimulationOnly: Boolean = false,
        val freezeBlocksAutomation: Boolean = false,
        val rolloutSummary: String = "",
        val approvalSummary: String = "",
        val freezeSummary: String = "",
        val rollbackSummary: String = ""
    )

    private fun resolveWorkflowPolicyRolloutState(
        previous: WorkflowPolicyRolloutState?,
        command: GovernanceCollaborationCommand?,
        actor: OperatorAssigneeRef?,
        workflowTemplateId: String,
        workflowPackVersion: String?,
        defaultScope: PolicyRolloutScope,
        now: Long
    ): WorkflowPolicyRolloutResolution {
        val defaultTarget = PolicyRolloutTarget(
            scope = defaultScope,
            tenantId = command?.policyRolloutTenantId?.takeIf { it.isNotBlank() },
            workspaceId = command?.policyRolloutWorkspaceId?.takeIf { it.isNotBlank() },
            workflowTemplateId = workflowTemplateId,
            summary = "Policy rollout target $defaultScope for workflow template $workflowTemplateId."
        )
        var state = previous ?: WorkflowPolicyRolloutState(
            stage = PolicyRolloutStage.SIMULATION_ONLY,
            mode = PolicyRolloutMode.SIMULATION_ONLY,
            target = defaultTarget,
            approvalRequirement = PolicyRolloutApprovalRequirement.NOT_REQUIRED,
            approvalState = PolicyRolloutApprovalState.NOT_REQUIRED,
            freezeState = PolicyRolloutFreezeState.NOT_FROZEN,
            riskSummary = "Rollout defaults to simulation-only for safe policy evaluation.",
            guardrailSummary = "Simulation-only rollout remains non-enforcing until governance promotion.",
            lastSafeStage = PolicyRolloutStage.SIMULATION_ONLY,
            lastSafeMode = PolicyRolloutMode.SIMULATION_ONLY,
            lastSafePackVersionId = workflowPackVersion,
            summary = "Workflow policy rollout is in simulation-only mode.",
            updatedAtMs = now
        )
        val actorRef = actor ?: OperatorAssigneeRef(
            userId = command?.actorUserId?.ifBlank { "local-user" } ?: "local-user",
            displayName = command?.actorDisplayName?.ifBlank { "Local Operator" } ?: "Local Operator"
        )
        val reasonCodes = mutableListOf<String>()
        val audits = state.auditRecords.toMutableList()

        fun appendAudit(
            action: PolicyRolloutAuditAction,
            summary: String,
            codes: List<String>
        ) {
            audits += PolicyRolloutAuditRecord(
                auditId = "rollout_${action.name.lowercase()}_${now}_${audits.size + 1}",
                action = action,
                actor = actorRef,
                summary = summary,
                reasonCodes = codes.distinct(),
                timestampMs = now
            )
        }

        fun normalizeScopeScope(input: PolicyRolloutScope?): PolicyRolloutScope {
            return input ?: state.target.scope.takeIf { it != PolicyRolloutScope.WORKFLOW_TEMPLATE } ?: defaultScope
        }

        fun scopeRank(scope: PolicyRolloutScope): Int {
            return when (scope) {
                PolicyRolloutScope.WORKFLOW_TEMPLATE -> 1
                PolicyRolloutScope.ROLE -> 2
                PolicyRolloutScope.WORKSPACE -> 3
                PolicyRolloutScope.TENANT -> 4
                PolicyRolloutScope.GLOBAL -> 5
            }
        }

        fun updateTarget(scope: PolicyRolloutScope): PolicyRolloutTarget {
            return state.target.copy(
                scope = scope,
                tenantId = command?.policyRolloutTenantId
                    ?.takeIf { it.isNotBlank() }
                    ?: state.target.tenantId,
                workspaceId = command?.policyRolloutWorkspaceId
                    ?.takeIf { it.isNotBlank() }
                    ?: state.target.workspaceId,
                workflowTemplateId = workflowTemplateId,
                summary = "Policy rollout target $scope for workflow template $workflowTemplateId."
            )
        }

        fun requiredApprovalFor(
            mode: PolicyRolloutMode,
            scope: PolicyRolloutScope,
            previousScope: PolicyRolloutScope
        ): PolicyRolloutApprovalRequirement {
            if (scopeRank(scope) > scopeRank(previousScope)) {
                return PolicyRolloutApprovalRequirement.REQUIRED_FOR_SCOPE_EXPANSION
            }
            if (mode == PolicyRolloutMode.ENFORCED) {
                return PolicyRolloutApprovalRequirement.REQUIRED_FOR_PROMOTION
            }
            return PolicyRolloutApprovalRequirement.NOT_REQUIRED
        }

        fun toStage(mode: PolicyRolloutMode): PolicyRolloutStage {
            return when (mode) {
                PolicyRolloutMode.INACTIVE -> PolicyRolloutStage.NOT_STARTED
                PolicyRolloutMode.SIMULATION_ONLY -> PolicyRolloutStage.SIMULATION_ONLY
                PolicyRolloutMode.STAGED -> PolicyRolloutStage.STAGED
                PolicyRolloutMode.ENFORCED -> PolicyRolloutStage.ENFORCED
            }
        }

        var promotionStatus = state.promotionStatus
        var promotionRequest = state.promotionRequest
        var promotionDecision = state.promotionDecision
        var promotionReadiness = state.promotionReadiness
        var rolloutAnalytics = state.rolloutAnalyticsSummary
        var approvalOperations = state.approvalOperations.toMutableList()
        var approvalReviewSummary = state.approvalReviewSummary
        val promotionAudits = state.promotionAuditRecords.toMutableList()
        var governanceProgram = state.governanceProgram
        var crossTenantRollout = state.crossTenantRollout ?: CrossTenantRolloutSummary(
            totalTargets = 1,
            adoptedTargets = 1,
            readinessStatus = CrossTenantRolloutReadinessStatus.READY,
            adoptionSummary = "Cross-tenant adoption is initialized.",
            summary = "Cross-tenant rollout is ready."
        )
        var packLifecycleStatus = state.packLifecycleStatus
        val packLifecycleEvents = state.packLifecycleEvents.toMutableList()
        var packDeprecationSummary = state.packDeprecationSummary
        var packRetirementSummary = state.packRetirementSummary
        var packReplacementPlan = state.packReplacementPlan
        var programSummary = state.programSummary
        var crossTenantSummary = state.crossTenantSummary
        var packLifecycleSummary = state.packLifecycleSummary
        var policyEstateSnapshot = state.policyEstateSnapshot
        var policyEstateSummary = state.policyEstateSummary
        var policyEstateDriftSummary = state.policyEstateDriftSummary
        var policyEstateBlockerSummary = state.policyEstateBlockerSummary
        var policyEstateRemediationSummary = state.policyEstateRemediationSummary
        var policyEstateRemediationPlan = state.policyEstateRemediationPlan
        val policyEstateRemediationActions = state.policyEstateRemediationActions.toMutableList()
        var estateAutomationRule = state.estateAutomationRule
        var estateAutomationEligibility = state.estateAutomationEligibility
        var scheduledRemediationPlan = state.scheduledRemediationPlan
        val governanceProgramOperations = state.governanceProgramOperations.toMutableList()
        var automationReplaySummary = state.automationReplaySummary
        val automationCancellationRecords = state.automationCancellationRecords.toMutableList()
        var policySchedulingWindow = state.policySchedulingWindow
        var rolloutCalendar = state.rolloutCalendar
        var calendarEvaluation = state.calendarEvaluation
        var scheduleSummary = state.scheduleSummary
        var rolloutCalendarSummary = state.rolloutCalendarSummary

        fun policyEstateSeverityReasonCode(severity: PolicyEstateDriftSeverity): String {
            return when (severity) {
                PolicyEstateDriftSeverity.LOW -> RoleReasonCodes.ROLE_POLICY_ESTATE_DRIFT_SEVERITY_LOW
                PolicyEstateDriftSeverity.MEDIUM -> RoleReasonCodes.ROLE_POLICY_ESTATE_DRIFT_SEVERITY_MEDIUM
                PolicyEstateDriftSeverity.HIGH -> RoleReasonCodes.ROLE_POLICY_ESTATE_DRIFT_SEVERITY_HIGH
                PolicyEstateDriftSeverity.CRITICAL -> RoleReasonCodes.ROLE_POLICY_ESTATE_DRIFT_SEVERITY_CRITICAL
            }
        }

        fun computePolicyEstateSnapshot() {
            val activePins = crossTenantRollout.pins.filter { it.active }
            val activeExemptions = crossTenantRollout.exemptions.filter { it.active }
            val rolloutBlocked = crossTenantRollout.readinessStatus == CrossTenantRolloutReadinessStatus.BLOCKED
            val rolloutHeld = crossTenantRollout.readinessStatus == CrossTenantRolloutReadinessStatus.HOLD
            val currentPackId = governanceProgram?.packId
                ?.takeIf { it.isNotBlank() }
                ?: state.target.workflowTemplateId?.takeIf { it.isNotBlank() }
            val currentPackVersion = governanceProgram?.packVersionId
                ?.takeIf { it.isNotBlank() }
                ?: workflowPackVersion
                    ?.takeIf { it.isNotBlank() }
                ?: state.lastSafePackVersionId?.takeIf { it.isNotBlank() }

            val driftRecords = mutableListOf<PolicyEstateDriftRecord>()
            if (state.mode == PolicyRolloutMode.SIMULATION_ONLY || state.stage == PolicyRolloutStage.SIMULATION_ONLY) {
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_simulation_only_$now",
                    type = PolicyEstateDriftType.SIMULATION_ONLY_SCOPE_NOT_PROMOTED,
                    severity = PolicyEstateDriftSeverity.LOW,
                    summary = "Rollout remains simulation-only and has not promoted to target enforcement mode.",
                    tenantId = state.target.tenantId,
                    workspaceId = state.target.workspaceId,
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_DRIFT_DETECTED,
                        policyEstateSeverityReasonCode(PolicyEstateDriftSeverity.LOW)
                    )
                )
            }
            if (activePins.isNotEmpty() && workflowPackVersion != null) {
                val pinnedBehind = activePins.any {
                    it.packVersionId?.isNotBlank() == true && !it.packVersionId.equals(workflowPackVersion, ignoreCase = true)
                }
                if (pinnedBehind) {
                    driftRecords += PolicyEstateDriftRecord(
                        driftId = "estate_drift_pin_version_$now",
                        type = PolicyEstateDriftType.PACK_VERSION_BEHIND_TARGET,
                        severity = PolicyEstateDriftSeverity.MEDIUM,
                        summary = "One or more pinned rollout targets are behind the target pack version.",
                        tenantId = activePins.firstOrNull()?.tenantId,
                        workspaceId = activePins.firstOrNull()?.workspaceId,
                        packId = currentPackId,
                        packVersionId = currentPackVersion,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_POLICY_DRIFT_DETECTED,
                            policyEstateSeverityReasonCode(PolicyEstateDriftSeverity.MEDIUM)
                        )
                    )
                }
            }
            if (activePins.isNotEmpty() &&
                (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRING)
            ) {
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_retiring_pinned_$now",
                    type = PolicyEstateDriftType.PACK_RETIRING_BUT_STILL_PINNED,
                    severity = PolicyEstateDriftSeverity.HIGH,
                    summary = "Pack lifecycle cannot progress while active pins still hold retiring/deprecated targets.",
                    tenantId = activePins.firstOrNull()?.tenantId,
                    workspaceId = activePins.firstOrNull()?.workspaceId,
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED,
                        policyEstateSeverityReasonCode(PolicyEstateDriftSeverity.HIGH)
                    )
                )
            }
            if (activeExemptions.isNotEmpty() &&
                (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRING)
            ) {
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_exemption_retirement_$now",
                    type = PolicyEstateDriftType.TENANT_EXEMPTION_BLOCKS_RETIREMENT,
                    severity = PolicyEstateDriftSeverity.HIGH,
                    summary = "Active rollout exemptions are blocking retirement readiness.",
                    tenantId = activeExemptions.firstOrNull()?.tenantId,
                    workspaceId = activeExemptions.firstOrNull()?.workspaceId,
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED,
                        policyEstateSeverityReasonCode(PolicyEstateDriftSeverity.HIGH)
                    )
                )
            }
            if (crossTenantRollout.driftedTargets > 0) {
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_override_divergence_$now",
                    type = PolicyEstateDriftType.WORKSPACE_OVERRIDE_DIVERGES_FROM_INTENDED_PACK,
                    severity = if (crossTenantRollout.driftedTargets >= 3) {
                        PolicyEstateDriftSeverity.HIGH
                    } else {
                        PolicyEstateDriftSeverity.MEDIUM
                    },
                    summary = "Cross-tenant rollout drift indicates tenant/workspace policy divergence from intended pack state.",
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_DRIFT_DETECTED,
                        policyEstateSeverityReasonCode(
                            if (crossTenantRollout.driftedTargets >= 3) {
                                PolicyEstateDriftSeverity.HIGH
                            } else {
                                PolicyEstateDriftSeverity.MEDIUM
                            }
                        )
                    )
                )
            }
            if (
                (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRING) &&
                packReplacementPlan == null
            ) {
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_missing_replacement_$now",
                    type = PolicyEstateDriftType.REPLACEMENT_PLAN_MISSING,
                    severity = PolicyEstateDriftSeverity.CRITICAL,
                    summary = "Replacement plan is missing while lifecycle state requires controlled transition.",
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED,
                        policyEstateSeverityReasonCode(PolicyEstateDriftSeverity.CRITICAL)
                    )
                )
            }
            if (rolloutBlocked || rolloutHeld) {
                val severity = if (rolloutBlocked) {
                    PolicyEstateDriftSeverity.CRITICAL
                } else {
                    PolicyEstateDriftSeverity.MEDIUM
                }
                driftRecords += PolicyEstateDriftRecord(
                    driftId = "estate_drift_lifecycle_blocker_$now",
                    type = PolicyEstateDriftType.LIFECYCLE_BLOCKER_ACTIVE,
                    severity = severity,
                    summary = crossTenantRollout.blockerSummary.ifBlank {
                        "Cross-tenant rollout blockers prevent lifecycle progression."
                    },
                    packId = currentPackId,
                    packVersionId = currentPackVersion,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD,
                        policyEstateSeverityReasonCode(severity)
                    )
                )
            }

            val blockers = buildList {
                if (activePins.isNotEmpty()) {
                    add(
                        PolicyEstateBlocker(
                            blockerId = "estate_blocker_pins_$now",
                            severity = PolicyEstateDriftSeverity.HIGH,
                            summary = "Active pinned rollout targets must be reviewed before lifecycle progression.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED),
                            acknowledged = false
                        )
                    )
                }
                if (activeExemptions.isNotEmpty()) {
                    add(
                        PolicyEstateBlocker(
                            blockerId = "estate_blocker_exemptions_$now",
                            severity = PolicyEstateDriftSeverity.MEDIUM,
                            summary = "Active rollout exemptions should be cleared or justified before retirement.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD),
                            acknowledged = false
                        )
                    )
                }
                if (rolloutBlocked) {
                    add(
                        PolicyEstateBlocker(
                            blockerId = "estate_blocker_cross_tenant_$now",
                            severity = PolicyEstateDriftSeverity.CRITICAL,
                            summary = crossTenantRollout.blockerSummary.ifBlank {
                                "Cross-tenant rollout is blocked by unresolved governance conditions."
                            },
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD),
                            acknowledged = false
                        )
                    )
                }
                if (
                    packReplacementPlan == null &&
                    (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                        packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ||
                        packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRING)
                ) {
                    add(
                        PolicyEstateBlocker(
                            blockerId = "estate_blocker_replacement_missing_$now",
                            severity = PolicyEstateDriftSeverity.CRITICAL,
                            summary = "Replacement plan is required before retirement progression.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED),
                            acknowledged = false
                        )
                    )
                }
            }

            val highestSeverity = (driftRecords.map { it.severity } + blockers.map { it.severity })
                .maxByOrNull { it.ordinal }
                ?: PolicyEstateDriftSeverity.LOW

            val suggestions = buildList {
                if (activePins.isNotEmpty()) {
                    add(
                        PolicyEstateRemediationSuggestion(
                            suggestionId = "estate_suggestion_unpin_$now",
                            action = PolicyEstateRemediationActionType.UNPIN_TARGET,
                            summary = "Unpin rollout targets that no longer require legacy version hold.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED),
                            safe = true
                        )
                    )
                }
                if (activeExemptions.isNotEmpty()) {
                    add(
                        PolicyEstateRemediationSuggestion(
                            suggestionId = "estate_suggestion_unexempt_$now",
                            action = PolicyEstateRemediationActionType.REMOVE_EXEMPTION,
                            summary = "Remove resolved rollout exemptions to reduce drift.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED),
                            safe = true
                        )
                    )
                }
                if (
                    packReplacementPlan == null &&
                    (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                        packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ||
                        packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRING)
                ) {
                    add(
                        PolicyEstateRemediationSuggestion(
                            suggestionId = "estate_suggestion_replacement_$now",
                            action = PolicyEstateRemediationActionType.ATTACH_REPLACEMENT_PLAN,
                            summary = "Attach a replacement plan before retirement progression.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED),
                            safe = true
                        )
                    )
                }
                if (state.mode == PolicyRolloutMode.SIMULATION_ONLY || state.stage == PolicyRolloutStage.SIMULATION_ONLY) {
                    add(
                        PolicyEstateRemediationSuggestion(
                            suggestionId = "estate_suggestion_move_target_$now",
                            action = PolicyEstateRemediationActionType.MOVE_TO_TARGET_PACK_VERSION,
                            summary = "Promote simulation-only rollout to target version when readiness blockers clear.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED),
                            safe = false
                        )
                    )
                }
                if (blockers.isNotEmpty()) {
                    add(
                        PolicyEstateRemediationSuggestion(
                            suggestionId = "estate_suggestion_hold_retirement_$now",
                            action = PolicyEstateRemediationActionType.HOLD_RETIREMENT,
                            summary = "Hold retirement until blockers are remediated or acknowledged.",
                            reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED),
                            safe = true
                        )
                    )
                }
            }

            val currentPlan = policyEstateRemediationPlan ?: PolicyEstateRemediationPlan(
                planId = "estate_plan_${workflowTemplateId}_$now",
                packId = currentPackId,
                packVersionId = currentPackVersion
            )
            val unresolvedActions = policyEstateRemediationActions.any {
                it.status == PolicyEstateRemediationStatus.RECOMMENDED ||
                    it.status == PolicyEstateRemediationStatus.ACKNOWLEDGED ||
                    it.status == PolicyEstateRemediationStatus.SCHEDULED
            }
            val planStatus = when {
                policyEstateRemediationActions.any { it.status == PolicyEstateRemediationStatus.SCHEDULED } ->
                    PolicyEstateRemediationStatus.SCHEDULED
                policyEstateRemediationActions.any { it.status == PolicyEstateRemediationStatus.ACKNOWLEDGED } ->
                    PolicyEstateRemediationStatus.ACKNOWLEDGED
                policyEstateRemediationActions.any { it.status == PolicyEstateRemediationStatus.APPLIED } &&
                    blockers.isEmpty() &&
                    !unresolvedActions ->
                    PolicyEstateRemediationStatus.APPLIED
                blockers.isNotEmpty() || suggestions.isNotEmpty() ->
                    PolicyEstateRemediationStatus.RECOMMENDED
                policyEstateRemediationActions.any { it.status == PolicyEstateRemediationStatus.DEFERRED } ->
                    PolicyEstateRemediationStatus.DEFERRED
                else -> currentPlan.status
            }
            policyEstateRemediationPlan = currentPlan.copy(
                packId = currentPackId ?: currentPlan.packId,
                packVersionId = currentPackVersion ?: currentPlan.packVersionId,
                status = planStatus,
                summary = when {
                    blockers.isNotEmpty() ->
                        "Estate remediation has ${blockers.size} blocker(s) and ${suggestions.size} recommended action(s)."
                    suggestions.isNotEmpty() ->
                        "Estate remediation has ${suggestions.size} recommended action(s) with no active blockers."
                    else ->
                        "No active estate remediation blockers detected."
                },
                suggestions = suggestions.take(20),
                actions = policyEstateRemediationActions.takeLast(40),
                updatedAtMs = now
            )

            val adoption = PolicyEstateAdoptionSummary(
                totalTargets = crossTenantRollout.totalTargets,
                adoptedTargets = crossTenantRollout.adoptedTargets,
                driftedTargets = crossTenantRollout.driftedTargets,
                blockedTargets = crossTenantRollout.blockedTargets,
                summary = "Adoption ${crossTenantRollout.adoptedTargets}/${crossTenantRollout.totalTargets}, drift ${crossTenantRollout.driftedTargets}, blockers ${crossTenantRollout.blockedTargets}."
            )
            val retirementReady = blockers.isEmpty() &&
                activePins.isEmpty() &&
                activeExemptions.isEmpty() &&
                (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.ACTIVE ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.STAGED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.DEPRECATED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.SUPERSEDED)
            val replacementReady = packReplacementPlan != null || packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.SUPERSEDED
            val lifecycleHealth = PolicyEstateLifecycleHealthSummary(
                status = packLifecycleStatus,
                retirementReady = retirementReady,
                replacementReady = replacementReady,
                summary = "Lifecycle ${packLifecycleStatus.name.lowercase().replace('_', ' ')}; retirement ready=$retirementReady; replacement ready=$replacementReady."
            )

            policyEstateSnapshot = PolicyEstateSnapshot(
                snapshotId = policyEstateSnapshot?.snapshotId?.takeIf { it.isNotBlank() }
                    ?: "estate_snapshot_${workflowTemplateId}_$now",
                packId = currentPackId,
                packVersionId = currentPackVersion,
                generatedAtMs = now,
                adoption = adoption,
                lifecycleHealth = lifecycleHealth,
                driftRecords = driftRecords.distinctBy { it.driftId },
                blockers = blockers.distinctBy { it.blockerId },
                remediationPlan = policyEstateRemediationPlan,
                summary = "Policy estate ${highestSeverity.name.lowercase().replace('_', ' ')} severity; adoption ${adoption.adoptedTargets}/${adoption.totalTargets}; blockers ${blockers.size}."
            )
            policyEstateSummary = policyEstateSnapshot?.summary.orEmpty()
            policyEstateDriftSummary = if (driftRecords.isEmpty()) {
                "No estate drift detected."
            } else {
                "Estate drift ${driftRecords.size}: " +
                    driftRecords.joinToString("; ") { it.summary }
            }
            policyEstateBlockerSummary = if (blockers.isEmpty()) {
                "No active estate blockers."
            } else {
                "Estate blockers ${blockers.size}: " +
                    blockers.joinToString("; ") { it.summary }
            }
            policyEstateRemediationSummary = policyEstateRemediationPlan?.summary.orEmpty()

            reasonCodes += RoleReasonCodes.ROLE_POLICY_ESTATE_SNAPSHOT_COMPUTED
            reasonCodes += policyEstateSeverityReasonCode(highestSeverity)
            if (suggestions.isNotEmpty()) {
                reasonCodes += RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED
            }
        }

        fun appendPackLifecycleEvent(
            type: WorkflowPolicyPackLifecycleEventType,
            summary: String,
            codes: List<String>
        ) {
            packLifecycleEvents += WorkflowPolicyPackLifecycleEvent(
                eventId = "pack_lifecycle_${type.name.lowercase()}_${now}_${packLifecycleEvents.size + 1}",
                type = type,
                summary = summary,
                reasonCodes = codes.distinct(),
                timestampMs = now
            )
        }

        fun recomputeCrossTenantRollout(
            forceHold: Boolean = false,
            holdSummary: String? = null
        ) {
            val existing = crossTenantRollout
            val activeExemptions = existing.exemptions.filter { it.active }
            val activePins = existing.pins.filter { it.active }
            val driftedTargets = maxOf(
                existing.driftedTargets,
                activeExemptions.size + activePins.size
            )
            val totalTargets = maxOf(
                existing.totalTargets,
                driftedTargets + 1
            )
            val freezeOrPause =
                state.freezeState != PolicyRolloutFreezeState.NOT_FROZEN ||
                    state.stage == PolicyRolloutStage.PAUSED ||
                    state.stage == PolicyRolloutStage.FROZEN
            val blockedTargets = when {
                packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ->
                    maxOf(existing.blockedTargets, 1)
                forceHold || freezeOrPause ->
                    maxOf(existing.blockedTargets, 1)
                else -> existing.blockedTargets
            }
            val readinessStatus = when {
                blockedTargets > 0 || forceHold || packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED ->
                    CrossTenantRolloutReadinessStatus.BLOCKED
                activeExemptions.isNotEmpty() ||
                    activePins.isNotEmpty() ||
                    state.approvalState == PolicyRolloutApprovalState.PENDING ->
                    CrossTenantRolloutReadinessStatus.HOLD
                else -> CrossTenantRolloutReadinessStatus.READY
            }
            val driftReasons = buildSet {
                if (activePins.isNotEmpty()) add(RolloutDriftReason.VERSION_PINNED)
                if (activeExemptions.isNotEmpty()) add(RolloutDriftReason.EXEMPTION_ACTIVE)
                if (forceHold || packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED) {
                    add(RolloutDriftReason.RETIREMENT_HOLD)
                }
                if (state.stage == PolicyRolloutStage.PAUSED || state.stage == PolicyRolloutStage.FROZEN) {
                    add(RolloutDriftReason.MANUAL_OVERRIDE)
                }
            }.toList()
            val adoptedTargets = maxOf(
                0,
                totalTargets - driftedTargets - blockedTargets
            )
            val adoptionSummary = "Adoption $adoptedTargets/$totalTargets."
            val driftSummary = if (driftReasons.isEmpty()) {
                "No rollout drift detected."
            } else {
                "Drift reasons: ${driftReasons.joinToString(", ") { it.name.lowercase().replace('_', ' ') }}."
            }
            val exemptionSummary = if (activeExemptions.isEmpty()) {
                "No active rollout exemptions."
            } else {
                "Active exemptions ${activeExemptions.size}."
            }
            val pinningSummary = if (activePins.isEmpty()) {
                "No active rollout pins."
            } else {
                "Active pins ${activePins.size}."
            }
            val blockerSummary = holdSummary?.takeIf { it.isNotBlank() } ?: when (readinessStatus) {
                CrossTenantRolloutReadinessStatus.BLOCKED ->
                    "Cross-tenant rollout is blocked pending governance remediation."
                CrossTenantRolloutReadinessStatus.HOLD ->
                    "Cross-tenant rollout is on hold pending drift/exemption review."
                CrossTenantRolloutReadinessStatus.READY ->
                    "No cross-tenant blockers are active."
            }
            val recommendationSummary = when (readinessStatus) {
                CrossTenantRolloutReadinessStatus.READY ->
                    "Recommendation: continue rollout progression."
                CrossTenantRolloutReadinessStatus.HOLD ->
                    "Recommendation: resolve drift and exemptions before expanding scope."
                CrossTenantRolloutReadinessStatus.BLOCKED ->
                    "Recommendation: pause expansion and resolve blockers first."
            }
            val summary = "Cross-tenant rollout ${readinessStatus.name.lowercase().replace('_', ' ')}. " +
                "$adoptionSummary $exemptionSummary $pinningSummary"
            crossTenantRollout = existing.copy(
                totalTargets = totalTargets,
                adoptedTargets = adoptedTargets,
                driftedTargets = driftedTargets,
                exemptedTargets = activeExemptions.size,
                pinnedTargets = activePins.size,
                blockedTargets = blockedTargets,
                readinessStatus = readinessStatus,
                driftReasons = driftReasons,
                adoptionSummary = adoptionSummary,
                driftSummary = driftSummary,
                exemptionSummary = exemptionSummary,
                pinningSummary = pinningSummary,
                blockerSummary = blockerSummary,
                recommendationSummary = recommendationSummary,
                summary = summary,
                updatedAtMs = now
            )
            if (readinessStatus != CrossTenantRolloutReadinessStatus.READY) {
                reasonCodes += RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD
            }
        }

        fun appendPromotionAudit(
            action: GovernanceActionType,
            summary: String,
            codes: List<String>
        ) {
            promotionAudits += PolicyPromotionAuditRecord(
                auditId = "promotion_${action.name.lowercase()}_${now}_${promotionAudits.size + 1}",
                action = action,
                actor = actorRef,
                summary = summary,
                reasonCodes = codes.distinct(),
                timestampMs = now
            )
        }

        fun updateApprovalReviewSummaryFromQueue(): ApprovalReviewSummary {
            val pending = approvalOperations.count { it.status == ApprovalOperationStatus.PENDING }
            val approved = approvalOperations.count { it.status == ApprovalOperationStatus.APPROVED }
            val rejected = approvalOperations.count { it.status == ApprovalOperationStatus.REJECTED }
            val summary = buildString {
                append("Approval queue pending ")
                append(pending)
                append(", approved ")
                append(approved)
                append(", rejected ")
                append(rejected)
                append('.')
            }
            return ApprovalReviewSummary(
                pendingCount = pending,
                approvedCount = approved,
                rejectedCount = rejected,
                summary = summary
            )
        }

        fun currentPromotionTarget(
            requestedScope: PolicyRolloutScope? = null,
            requestedMode: PolicyRolloutMode? = null
        ): PolicyPromotionTarget {
            val fromStage = state.stage
            val fromMode = state.mode
            val targetScope = requestedScope ?: state.target.scope
            val toMode = requestedMode ?: when (state.mode) {
                PolicyRolloutMode.SIMULATION_ONLY -> PolicyRolloutMode.STAGED
                PolicyRolloutMode.STAGED -> PolicyRolloutMode.ENFORCED
                PolicyRolloutMode.ENFORCED -> PolicyRolloutMode.ENFORCED
                PolicyRolloutMode.INACTIVE -> PolicyRolloutMode.SIMULATION_ONLY
            }
            val toStage = toStage(toMode)
            return PolicyPromotionTarget(
                packId = state.target.workflowTemplateId ?: workflowTemplateId,
                packVersionId = workflowPackVersion,
                scope = targetScope,
                tenantId = state.target.tenantId,
                workspaceId = state.target.workspaceId,
                workflowTemplateId = workflowTemplateId,
                fromStage = fromStage,
                toStage = toStage,
                fromMode = fromMode,
                toMode = toMode,
                summary = "Promote workflow rollout from ${fromMode.name.lowercase().replace('_', ' ')} to ${toMode.name.lowercase().replace('_', ' ')} at ${targetScope.name.lowercase().replace('_', ' ')} scope."
            )
        }

        fun upsertApprovalOperation(operation: ApprovalOperationQueueItem) {
            val index = approvalOperations.indexOfFirst { it.operationId == operation.operationId }
            if (index >= 0) {
                approvalOperations[index] = operation
            } else {
                approvalOperations += operation
            }
        }

        fun currentRolloutAnalytics(target: PolicyPromotionTarget): RolloutAnalyticsSummary {
            val windowDays = 7
            val pending = approvalOperations.count { it.status == ApprovalOperationStatus.PENDING }
            val denied = approvalOperations.count { it.status == ApprovalOperationStatus.REJECTED }
            val baseSimulationRuns = maxOf(
                1,
                audits.count { it.action == PolicyRolloutAuditAction.SIMULATION_STARTED } +
                    if (state.mode == PolicyRolloutMode.SIMULATION_ONLY) 1 else 0
            )
            val simulationRuns = if (
                state.approvalState == PolicyRolloutApprovalState.APPROVED ||
                promotionStatus == PolicyPromotionStatus.APPROVED
            ) {
                maxOf(baseSimulationRuns, 3)
            } else {
                baseSimulationRuns
            }
            val totalRuns = maxOf(audits.size, simulationRuns)
            val automationSuppressedCount = audits.count {
                it.reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_ROLLOUT_GUARDRAIL_BLOCKED)
            }
            val automationThrottledCount = audits.count {
                it.reasonCodes.contains(RoleReasonCodes.ROLE_AUTOMATION_THROTTLED)
            }
            val summary = "Rollout analytics: total $totalRuns, simulation $simulationRuns, pending approvals $pending, denied approvals $denied."
            return RolloutAnalyticsSummary(
                target = target,
                windowDays = windowDays,
                totalRuns = totalRuns,
                simulationRuns = simulationRuns,
                approvalPendingCount = pending,
                approvalDeniedCount = denied,
                verificationFailedCount = 0,
                rollbackFailedCount = 0,
                disputeOpenCount = 0,
                automationSuppressedCount = automationSuppressedCount,
                automationThrottledCount = automationThrottledCount,
                summary = summary
            )
        }

        fun currentPromotionReadiness(
            target: PolicyPromotionTarget,
            analytics: RolloutAnalyticsSummary
        ): PromotionReadinessResult {
            val blockers = mutableListOf<PolicyPromotionBlocker>()
            if (state.approvalState == PolicyRolloutApprovalState.DENIED) {
                blockers += PolicyPromotionBlocker(
                    type = PolicyPromotionBlockerType.APPROVAL_REQUIRED,
                    code = "approval_denied",
                    summary = "Promotion cannot proceed because rollout approval was denied.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_DENIED,
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED
                    )
                )
            } else if (
                state.approvalState == PolicyRolloutApprovalState.PENDING ||
                approvalOperations.any { it.status == ApprovalOperationStatus.PENDING }
            ) {
                blockers += PolicyPromotionBlocker(
                    type = PolicyPromotionBlockerType.APPROVAL_PENDING,
                    code = "approval_pending",
                    summary = "Promotion is waiting for approval operations to complete.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_PENDING,
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED
                    )
                )
            } else if (
                state.approvalRequirement != PolicyRolloutApprovalRequirement.NOT_REQUIRED &&
                state.approvalState != PolicyRolloutApprovalState.APPROVED
            ) {
                blockers += PolicyPromotionBlocker(
                    type = PolicyPromotionBlockerType.APPROVAL_REQUIRED,
                    code = "approval_required",
                    summary = "Promotion requires approval for risky rollout transition.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_REQUIRED,
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED
                    )
                )
            }
            if (
                state.freezeState != PolicyRolloutFreezeState.NOT_FROZEN ||
                state.stage == PolicyRolloutStage.PAUSED ||
                state.stage == PolicyRolloutStage.FROZEN
            ) {
                blockers += PolicyPromotionBlocker(
                    type = PolicyPromotionBlockerType.ROLLOUT_FROZEN,
                    code = "rollout_frozen",
                    summary = "Promotion is blocked while rollout is paused or frozen.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED,
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_GUARDRAIL_BLOCKED
                    )
                )
            }
            if (analytics.simulationRuns < 3) {
                blockers += PolicyPromotionBlocker(
                    type = PolicyPromotionBlockerType.SIMULATION_EVIDENCE_INSUFFICIENT,
                    code = "simulation_evidence_insufficient",
                    summary = "At least 3 simulation runs are required before promotion.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_POLICY_SIMULATION_EVIDENCE_INSUFFICIENT,
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED
                    )
                )
            }
            val status = when {
                blockers.any {
                    it.type == PolicyPromotionBlockerType.ROLLOUT_FROZEN ||
                        it.code == "approval_denied"
                } -> PolicyPromotionReadinessStatus.BLOCKED
                blockers.isNotEmpty() -> PolicyPromotionReadinessStatus.HOLD
                state.stage == PolicyRolloutStage.ROLLED_BACK -> PolicyPromotionReadinessStatus.ROLLBACK_RECOMMENDED
                else -> PolicyPromotionReadinessStatus.READY
            }
            val recommendation = when (status) {
                PolicyPromotionReadinessStatus.READY -> PolicyPromotionRecommendation(
                    action = PolicyPromotionRecommendationType.ADVANCE,
                    summary = "Readiness checks passed; advance rollout promotion is recommended.",
                    reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ANALYTICS_RECOMMENDATION_ADVANCE)
                )
                PolicyPromotionReadinessStatus.ROLLBACK_RECOMMENDED -> PolicyPromotionRecommendation(
                    action = PolicyPromotionRecommendationType.ROLLBACK,
                    summary = "Rollback is recommended before advancing due to recent rollback state.",
                    reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ANALYTICS_RECOMMENDATION_ROLLBACK)
                )
                PolicyPromotionReadinessStatus.BLOCKED -> PolicyPromotionRecommendation(
                    action = PolicyPromotionRecommendationType.REJECT,
                    summary = "Promotion is blocked until approval/freeze blockers are resolved.",
                    reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED)
                )
                PolicyPromotionReadinessStatus.HOLD -> PolicyPromotionRecommendation(
                    action = PolicyPromotionRecommendationType.HOLD,
                    summary = "Hold promotion until evidence and approval blockers are cleared.",
                    reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_ANALYTICS_RECOMMENDATION_HOLD)
                )
            }
            val summary = when (status) {
                PolicyPromotionReadinessStatus.READY ->
                    "Promotion readiness is ready for ${target.toMode.name.lowercase().replace('_', ' ')}."
                PolicyPromotionReadinessStatus.HOLD ->
                    "Promotion readiness is on hold pending ${blockers.size} blocker(s)."
                PolicyPromotionReadinessStatus.BLOCKED ->
                    "Promotion readiness is blocked by governance controls."
                PolicyPromotionReadinessStatus.ROLLBACK_RECOMMENDED ->
                    "Promotion readiness recommends rollback before advancing."
            }
            return PromotionReadinessResult(
                status = status,
                evidence = PolicyPromotionEvidenceSummary(
                    simulationRuns = analytics.simulationRuns,
                    approvalDeniedRate = if (analytics.totalRuns > 0) {
                        analytics.approvalDeniedCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    verificationFailRate = if (analytics.totalRuns > 0) {
                        analytics.verificationFailedCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    rollbackFailureRate = if (analytics.totalRuns > 0) {
                        analytics.rollbackFailedCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    disputeOpenRate = if (analytics.totalRuns > 0) {
                        analytics.disputeOpenCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    automationSuppressionRate = if (analytics.totalRuns > 0) {
                        analytics.automationSuppressedCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    automationThrottleRate = if (analytics.totalRuns > 0) {
                        analytics.automationThrottledCount.toDouble() / analytics.totalRuns.toDouble()
                    } else {
                        0.0
                    },
                    summary = analytics.summary
                ),
                blockers = blockers,
                recommendation = recommendation,
                evaluatedAtMs = now,
                summary = summary
            )
        }

        command?.let { cmd ->
            computePolicyEstateSnapshot()
            when (cmd.commandType) {
                GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL -> {
                    val requirement = cmd.policyRolloutApprovalRequirement
                        ?: PolicyRolloutApprovalRequirement.REQUIRED_FOR_RISKY_CHANGE
                    state = state.copy(
                        approvalRequirement = requirement,
                        approvalState = PolicyRolloutApprovalState.PENDING,
                        approvalRecord = PolicyRolloutApprovalRecord(
                            requestId = "rollout_approval_req_${now}",
                            requestedBy = actorRef,
                            decisionBy = null,
                            status = PolicyRolloutApprovalState.PENDING,
                            requirement = requirement,
                            reason = cmd.policyRolloutReason.orEmpty(),
                            requestedAtMs = now,
                            decidedAtMs = null
                        ),
                        updatedAtMs = now
                    )
                    val codes = listOf(
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVAL_REQUIRED,
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVAL_REQUESTED
                    )
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.APPROVAL_REQUESTED,
                        summary = "Policy rollout approval requested.",
                        codes = codes
                    )
                }

                GovernanceActionType.APPROVE_POLICY_ROLLOUT -> {
                    state = state.copy(
                        approvalState = PolicyRolloutApprovalState.APPROVED,
                        approvalRecord = (state.approvalRecord ?: PolicyRolloutApprovalRecord(
                            requestId = "rollout_approval_req_${now}",
                            requestedBy = actorRef,
                            status = PolicyRolloutApprovalState.APPROVED
                        )).copy(
                            status = PolicyRolloutApprovalState.APPROVED,
                            decisionBy = actorRef,
                            decidedAtMs = now,
                            reason = cmd.policyRolloutReason.orEmpty().ifBlank {
                                state.approvalRecord?.reason.orEmpty()
                            }
                        ),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVED)
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.APPROVAL_GRANTED,
                        summary = "Policy rollout approval granted.",
                        codes = codes
                    )
                }

                GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL -> {
                    state = state.copy(
                        approvalState = PolicyRolloutApprovalState.DENIED,
                        approvalRecord = (state.approvalRecord ?: PolicyRolloutApprovalRecord(
                            requestId = "rollout_approval_req_${now}",
                            requestedBy = actorRef,
                            status = PolicyRolloutApprovalState.DENIED
                        )).copy(
                            status = PolicyRolloutApprovalState.DENIED,
                            decisionBy = actorRef,
                            decidedAtMs = now,
                            reason = cmd.policyRolloutReason.orEmpty().ifBlank {
                                "Approval denied by operator."
                            }
                        ),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_DENIED)
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.APPROVAL_DENIED,
                        summary = "Policy rollout approval denied.",
                        codes = codes
                    )
                }

                GovernanceActionType.REQUEST_POLICY_PROMOTION -> {
                    val target = currentPromotionTarget(
                        requestedScope = cmd.policyRolloutScope,
                        requestedMode = cmd.policyRolloutMode
                    )
                    val request = PolicyPromotionRequest(
                        requestId = "promotion_req_${state.target.workflowTemplateId ?: workflowTemplateId}_$now",
                        target = target,
                        requestedBy = actorRef,
                        requestedAtMs = now,
                        reason = cmd.policyRolloutReason.orEmpty().ifBlank {
                            "Promotion requested through governance console."
                        },
                        window = PolicyPromotionWindow(
                            windowStartMs = now - (7 * 24 * 60 * 60 * 1000L),
                            windowEndMs = now,
                            minimumSimulationRuns = 3,
                            summary = "Default readiness window is last 7 days with minimum 3 simulation runs."
                        ),
                        summary = "Promotion requested for ${target.toMode.name.lowercase().replace('_', ' ')} at ${target.scope.name.lowercase().replace('_', ' ')} scope."
                    )
                    promotionRequest = request
                    promotionStatus = PolicyPromotionStatus.REQUESTED
                    val operation = ApprovalOperationQueueItem(
                        operationId = "promotion_op_${request.requestId}",
                        operationType = ApprovalOperationType.PROMOTION_APPROVAL,
                        status = ApprovalOperationStatus.PENDING,
                        action = GovernanceActionType.APPROVE_POLICY_PROMOTION,
                        request = request,
                        requiredPermission = OperatorPermission.APPROVE_POLICY_ROLLOUT,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_POLICY_PROMOTION_REQUESTED,
                            RoleReasonCodes.ROLE_POLICY_APPROVAL_REQUIRED
                        ),
                        summary = "Approval operation queued for policy promotion request ${request.requestId}.",
                        createdAtMs = now,
                        updatedAtMs = now
                    )
                    upsertApprovalOperation(operation)
                    approvalReviewSummary = updateApprovalReviewSummaryFromQueue()
                    state = state.copy(
                        promotionStatus = promotionStatus,
                        promotionRequest = promotionRequest,
                        approvalOperations = approvalOperations,
                        approvalReviewSummary = approvalReviewSummary,
                        updatedAtMs = now
                    )
                    val codes = listOf(
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_REQUESTED,
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_REQUIRED
                    )
                    reasonCodes += codes
                    appendPromotionAudit(
                        action = GovernanceActionType.REQUEST_POLICY_PROMOTION,
                        summary = request.summary,
                        codes = codes
                    )
                }

                GovernanceActionType.APPROVE_POLICY_PROMOTION -> {
                    val request = promotionRequest ?: PolicyPromotionRequest(
                        requestId = "promotion_req_${state.target.workflowTemplateId ?: workflowTemplateId}_$now",
                        target = currentPromotionTarget(),
                        requestedBy = actorRef,
                        requestedAtMs = now,
                        summary = "Promotion requested for current rollout target."
                    )
                    val decision = PolicyPromotionDecision(
                        decisionId = "promotion_decision_${request.requestId}_$now",
                        requestId = request.requestId,
                        status = PolicyPromotionStatus.APPROVED,
                        decidedBy = actorRef,
                        decidedAtMs = now,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_POLICY_PROMOTION_APPROVED,
                            RoleReasonCodes.ROLE_POLICY_APPROVAL_GRANTED
                        ),
                        summary = cmd.policyRolloutReason.orEmpty().ifBlank {
                            "Policy promotion approved for ${request.target.toMode.name.lowercase().replace('_', ' ')} rollout."
                        }
                    )
                    promotionRequest = request
                    promotionDecision = decision
                    promotionStatus = PolicyPromotionStatus.APPROVED
                    state = state.copy(
                        approvalState = PolicyRolloutApprovalState.APPROVED,
                        promotionStatus = promotionStatus,
                        promotionRequest = promotionRequest,
                        promotionDecision = promotionDecision,
                        updatedAtMs = now
                    )
                    approvalOperations = approvalOperations.map { operation ->
                        if (
                            operation.operationType == ApprovalOperationType.PROMOTION_APPROVAL &&
                            operation.status == ApprovalOperationStatus.PENDING &&
                            (operation.request?.requestId == request.requestId || operation.operationId.endsWith(request.requestId))
                        ) {
                            operation.copy(
                                status = ApprovalOperationStatus.APPROVED,
                                decision = decision,
                                reasonCodes = (operation.reasonCodes + decision.reasonCodes).distinct(),
                                summary = decision.summary,
                                updatedAtMs = now
                            )
                        } else {
                            operation
                        }
                    }.toMutableList()
                    approvalReviewSummary = updateApprovalReviewSummaryFromQueue()
                    state = state.copy(
                        approvalOperations = approvalOperations,
                        approvalReviewSummary = approvalReviewSummary
                    )
                    val codes = listOf(
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_APPROVED,
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_GRANTED
                    )
                    reasonCodes += codes
                    appendPromotionAudit(
                        action = GovernanceActionType.APPROVE_POLICY_PROMOTION,
                        summary = decision.summary,
                        codes = codes
                    )
                }

                GovernanceActionType.REJECT_POLICY_PROMOTION -> {
                    val request = promotionRequest ?: PolicyPromotionRequest(
                        requestId = "promotion_req_${state.target.workflowTemplateId ?: workflowTemplateId}_$now",
                        target = currentPromotionTarget(),
                        requestedBy = actorRef,
                        requestedAtMs = now,
                        summary = "Promotion requested for current rollout target."
                    )
                    val decision = PolicyPromotionDecision(
                        decisionId = "promotion_decision_${request.requestId}_$now",
                        requestId = request.requestId,
                        status = PolicyPromotionStatus.REJECTED,
                        decidedBy = actorRef,
                        decidedAtMs = now,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_POLICY_PROMOTION_REJECTED,
                            RoleReasonCodes.ROLE_POLICY_APPROVAL_DENIED
                        ),
                        summary = cmd.policyRolloutReason.orEmpty().ifBlank {
                            "Policy promotion rejected by governance operator."
                        }
                    )
                    promotionRequest = request
                    promotionDecision = decision
                    promotionStatus = PolicyPromotionStatus.REJECTED
                    state = state.copy(
                        approvalState = PolicyRolloutApprovalState.DENIED,
                        promotionStatus = promotionStatus,
                        promotionRequest = promotionRequest,
                        promotionDecision = promotionDecision,
                        updatedAtMs = now
                    )
                    approvalOperations = approvalOperations.map { operation ->
                        if (
                            operation.operationType == ApprovalOperationType.PROMOTION_APPROVAL &&
                            operation.status == ApprovalOperationStatus.PENDING &&
                            (operation.request?.requestId == request.requestId || operation.operationId.endsWith(request.requestId))
                        ) {
                            operation.copy(
                                status = ApprovalOperationStatus.REJECTED,
                                decision = decision,
                                reasonCodes = (operation.reasonCodes + decision.reasonCodes).distinct(),
                                summary = decision.summary,
                                updatedAtMs = now
                            )
                        } else {
                            operation
                        }
                    }.toMutableList()
                    approvalReviewSummary = updateApprovalReviewSummaryFromQueue()
                    state = state.copy(
                        approvalOperations = approvalOperations,
                        approvalReviewSummary = approvalReviewSummary
                    )
                    val codes = listOf(
                        RoleReasonCodes.ROLE_POLICY_PROMOTION_REJECTED,
                        RoleReasonCodes.ROLE_POLICY_APPROVAL_DENIED
                    )
                    reasonCodes += codes
                    appendPromotionAudit(
                        action = GovernanceActionType.REJECT_POLICY_PROMOTION,
                        summary = decision.summary,
                        codes = codes
                    )
                }

                GovernanceActionType.ADVANCE_POLICY_ROLLOUT -> {
                    val requestedScope = normalizeScopeScope(cmd.policyRolloutScope)
                    val currentTarget = currentPromotionTarget(
                        requestedScope = requestedScope,
                        requestedMode = cmd.policyRolloutMode
                    )
                    val analytics = currentRolloutAnalytics(currentTarget)
                    val readiness = currentPromotionReadiness(currentTarget, analytics)
                    rolloutAnalytics = analytics
                    promotionReadiness = readiness
                    val blocked = readiness.status != PolicyPromotionReadinessStatus.READY ||
                        readiness.recommendation.action != PolicyPromotionRecommendationType.ADVANCE
                    if (blocked) {
                        promotionStatus = PolicyPromotionStatus.BLOCKED
                        val decision = PolicyPromotionDecision(
                            decisionId = "promotion_decision_${promotionRequest?.requestId ?: currentTarget.workflowTemplateId}_$now",
                            requestId = promotionRequest?.requestId.orEmpty(),
                            status = PolicyPromotionStatus.BLOCKED,
                            decidedBy = actorRef,
                            decidedAtMs = now,
                            reasonCodes = (
                                readiness.blockers.flatMap { it.reasonCodes } +
                                    listOf(
                                        RoleReasonCodes.ROLE_POLICY_PROMOTION_BLOCKED,
                                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_DENIED
                                    )
                                ).distinct(),
                            summary = readiness.summary.ifBlank {
                                "Policy rollout advance is blocked by promotion readiness checks."
                            }
                        )
                        promotionDecision = decision
                        state = state.copy(
                            promotionStatus = promotionStatus,
                            promotionDecision = promotionDecision,
                            promotionReadiness = promotionReadiness,
                            rolloutAnalyticsSummary = rolloutAnalytics,
                            updatedAtMs = now
                        )
                        val codes = decision.reasonCodes
                        reasonCodes += codes
                        appendPromotionAudit(
                            action = GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
                            summary = decision.summary,
                            codes = codes
                        )
                    } else {
                        val nextMode = currentTarget.toMode
                        val nextStage = currentTarget.toStage
                        val nextTarget = updateTarget(requestedScope)
                        promotionStatus = PolicyPromotionStatus.ADVANCED
                        val decision = PolicyPromotionDecision(
                            decisionId = "promotion_decision_${promotionRequest?.requestId ?: currentTarget.workflowTemplateId}_$now",
                            requestId = promotionRequest?.requestId.orEmpty(),
                            status = PolicyPromotionStatus.ADVANCED,
                            decidedBy = actorRef,
                            decidedAtMs = now,
                            reasonCodes = listOf(
                                RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_ALLOWED,
                                RoleReasonCodes.ROLE_POLICY_ANALYTICS_RECOMMENDATION_ADVANCE
                            ),
                            summary = cmd.policyRolloutReason.orEmpty().ifBlank {
                                "Policy rollout advanced to ${nextMode.name.lowercase().replace('_', ' ')} mode."
                            }
                        )
                        promotionDecision = decision
                        state = state.copy(
                            stage = nextStage,
                            mode = nextMode,
                            target = nextTarget,
                            promotionStatus = promotionStatus,
                            promotionDecision = promotionDecision,
                            promotionReadiness = promotionReadiness,
                            rolloutAnalyticsSummary = rolloutAnalytics,
                            approvalRequirement = PolicyRolloutApprovalRequirement.NOT_REQUIRED,
                            approvalState = PolicyRolloutApprovalState.APPROVED,
                            lastSafeStage = if (nextStage == PolicyRolloutStage.ENFORCED) {
                                state.lastSafeStage
                            } else {
                                nextStage
                            },
                            lastSafeMode = if (nextMode == PolicyRolloutMode.ENFORCED) {
                                state.lastSafeMode
                            } else {
                                nextMode
                            },
                            lastSafePackVersionId = workflowPackVersion ?: state.lastSafePackVersionId,
                            updatedAtMs = now
                        )
                        val codes = decision.reasonCodes
                        reasonCodes += codes
                        appendPromotionAudit(
                            action = GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
                            summary = decision.summary,
                            codes = codes
                        )
                    }
                }

                GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM -> {
                    val programId = cmd.policyProgramId
                        ?.trim()
                        ?.takeIf { it.isNotBlank() }
                        ?: governanceProgram?.programId?.takeIf { it.isNotBlank() }
                        ?: "program_${workflowTemplateId}_${now}"
                    val programName = cmd.policyProgramName
                        ?.trim()
                        ?.takeIf { it.isNotBlank() }
                        ?: governanceProgram?.name?.takeIf { it.isNotBlank() }
                        ?: "Policy Governance Program"
                    val waveId = cmd.policyProgramWaveId
                        ?.trim()
                        ?.takeIf { it.isNotBlank() }
                        ?: "wave_${now}"
                    val initialWave = PolicyGovernanceProgramWave(
                        waveId = waveId,
                        waveIndex = 1,
                        name = "Wave ${waveId.takeLast(6)}",
                        status = cmd.policyProgramWaveStatus ?: PolicyGovernanceWaveStatus.STAGED,
                        targetScope = normalizeScopeScope(cmd.policyRolloutScope),
                        targetTenantIds = listOfNotNull(
                            cmd.policyRolloutTenantId?.takeIf { it.isNotBlank() }
                        ),
                        targetWorkspaceIds = listOfNotNull(
                            cmd.policyRolloutWorkspaceId?.takeIf { it.isNotBlank() }
                        ),
                        summary = "Wave ${waveId.takeLast(6)} initialized for policy governance program.",
                        updatedAtMs = now
                    )
                    governanceProgram = PolicyGovernanceProgram(
                        programId = programId,
                        name = programName,
                        status = PolicyGovernanceProgramStatus.ACTIVE,
                        packId = cmd.workflowPolicyPackId
                            ?: cmd.policyPackId
                            ?: governanceProgram?.packId
                            ?: state.target.workflowTemplateId,
                        packVersionId = cmd.workflowPolicyPackVersion
                            ?: cmd.policyPackVersionId
                            ?: workflowPackVersion
                            ?: governanceProgram?.packVersionId,
                        currentWaveId = waveId,
                        waves = listOf(initialWave),
                        blockers = emptyList(),
                        recommendations = listOf(
                            PolicyGovernanceProgramRecommendation(
                                code = "program_created",
                                summary = "Program created; continue staged rollout with cross-tenant readiness checks.",
                                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_CREATED)
                            )
                        ),
                        summary = "Governance program $programName is active with wave ${waveId.takeLast(6)}.",
                        updatedAtMs = now
                    )
                    packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.STAGED
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_CREATED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.PROGRAM_CREATED,
                        summary = "Policy governance program $programName created.",
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE -> {
                    val currentProgram = governanceProgram ?: PolicyGovernanceProgram(
                        programId = cmd.policyProgramId?.takeIf { it.isNotBlank() } ?: "program_${workflowTemplateId}_${now}",
                        name = cmd.policyProgramName?.takeIf { it.isNotBlank() } ?: "Policy Governance Program",
                        status = PolicyGovernanceProgramStatus.ACTIVE,
                        updatedAtMs = now
                    )
                    val requestedWaveId = cmd.policyProgramWaveId
                        ?.trim()
                        ?.takeIf { it.isNotBlank() }
                        ?: currentProgram.currentWaveId
                        ?: "wave_${now}"
                    val updatedWaves = currentProgram.waves.toMutableList()
                    val idx = updatedWaves.indexOfFirst { it.waveId == requestedWaveId }
                    val stagedStatus = cmd.policyProgramWaveStatus ?: PolicyGovernanceWaveStatus.ADVANCING
                    if (idx >= 0) {
                        updatedWaves[idx] = updatedWaves[idx].copy(
                            status = stagedStatus,
                            summary = "Wave ${requestedWaveId.takeLast(6)} advanced to ${stagedStatus.name.lowercase().replace('_', ' ')}.",
                            updatedAtMs = now
                        )
                    } else {
                        val nextWaveIndex = updatedWaves.maxOfOrNull { it.waveIndex.takeIf { idxVal -> idxVal > 0 } ?: 0 }
                            ?.plus(1)
                            ?: 1
                        updatedWaves += PolicyGovernanceProgramWave(
                            waveId = requestedWaveId,
                            waveIndex = nextWaveIndex,
                            name = "Wave ${requestedWaveId.takeLast(6)}",
                            status = stagedStatus,
                            targetScope = normalizeScopeScope(cmd.policyRolloutScope),
                            targetTenantIds = listOfNotNull(cmd.policyRolloutTenantId?.takeIf { it.isNotBlank() }),
                            targetWorkspaceIds = listOfNotNull(cmd.policyRolloutWorkspaceId?.takeIf { it.isNotBlank() }),
                            summary = "Wave ${requestedWaveId.takeLast(6)} advanced by governance action.",
                            updatedAtMs = now
                        )
                    }
                    governanceProgram = currentProgram.copy(
                        status = PolicyGovernanceProgramStatus.ACTIVE,
                        currentWaveId = requestedWaveId,
                        waves = updatedWaves.takeLast(20),
                        recommendations = listOf(
                            PolicyGovernanceProgramRecommendation(
                                code = "advance_wave",
                                summary = "Advance next wave only after cross-tenant readiness remains healthy.",
                                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_ADVANCED)
                            )
                        ),
                        summary = "Governance wave ${requestedWaveId.takeLast(6)} advanced.",
                        updatedAtMs = now
                    )
                    val existingTargets = crossTenantRollout.totalTargets.coerceAtLeast(1)
                    crossTenantRollout = crossTenantRollout.copy(
                        totalTargets = existingTargets,
                        adoptedTargets = (crossTenantRollout.adoptedTargets + 1).coerceAtMost(existingTargets),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_ADVANCED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.WAVE_ADVANCED,
                        summary = "Governance wave ${requestedWaveId.takeLast(6)} advanced.",
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE -> {
                    val currentProgram = governanceProgram ?: PolicyGovernanceProgram(
                        programId = cmd.policyProgramId?.takeIf { it.isNotBlank() } ?: "program_${workflowTemplateId}_${now}",
                        name = cmd.policyProgramName?.takeIf { it.isNotBlank() } ?: "Policy Governance Program",
                        status = PolicyGovernanceProgramStatus.PAUSED,
                        updatedAtMs = now
                    )
                    val pausedWaveId = cmd.policyProgramWaveId
                        ?.trim()
                        ?.takeIf { it.isNotBlank() }
                        ?: currentProgram.currentWaveId
                        ?: "wave_${now}"
                    val updatedWaves = currentProgram.waves.toMutableList()
                    val idx = updatedWaves.indexOfFirst { it.waveId == pausedWaveId }
                    if (idx >= 0) {
                        updatedWaves[idx] = updatedWaves[idx].copy(
                            status = cmd.policyProgramWaveStatus ?: PolicyGovernanceWaveStatus.PAUSED,
                            summary = "Wave ${pausedWaveId.takeLast(6)} paused by governance action.",
                            updatedAtMs = now
                        )
                    } else {
                        val nextWaveIndex = updatedWaves.maxOfOrNull { it.waveIndex.takeIf { idxVal -> idxVal > 0 } ?: 0 }
                            ?.plus(1)
                            ?: 1
                        updatedWaves += PolicyGovernanceProgramWave(
                            waveId = pausedWaveId,
                            waveIndex = nextWaveIndex,
                            name = "Wave ${pausedWaveId.takeLast(6)}",
                            status = cmd.policyProgramWaveStatus ?: PolicyGovernanceWaveStatus.PAUSED,
                            targetScope = normalizeScopeScope(cmd.policyRolloutScope),
                            summary = "Wave ${pausedWaveId.takeLast(6)} paused by governance action.",
                            updatedAtMs = now
                        )
                    }
                    governanceProgram = currentProgram.copy(
                        status = PolicyGovernanceProgramStatus.PAUSED,
                        currentWaveId = pausedWaveId,
                        waves = updatedWaves.takeLast(20),
                        blockers = listOf(
                            PolicyGovernanceProgramBlocker(
                                code = "wave_paused",
                                summary = "Current governance wave is paused pending operator review.",
                                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_PAUSED)
                            )
                        ),
                        summary = "Governance wave ${pausedWaveId.takeLast(6)} is paused.",
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_PROGRAM_WAVE_PAUSED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.WAVE_PAUSED,
                        summary = "Governance wave ${pausedWaveId.takeLast(6)} paused.",
                        codes = codes
                    )
                    recomputeCrossTenantRollout(
                        forceHold = true,
                        holdSummary = "Wave pause blocks cross-tenant rollout progression."
                    )
                }

                GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION -> {
                    val scope = normalizeScopeScope(cmd.policyRolloutScope)
                    val exemption = PolicyRolloutExemptionRecord(
                        exemptionId = "exemption_${scope.name.lowercase()}_${now}",
                        scope = scope,
                        tenantId = cmd.policyRolloutTenantId?.takeIf { it.isNotBlank() },
                        workspaceId = cmd.policyRolloutWorkspaceId?.takeIf { it.isNotBlank() },
                        reason = cmd.policyExemptionReason
                            ?.takeIf { it.isNotBlank() }
                            ?: cmd.policyRolloutReason
                                ?.takeIf { it.isNotBlank() }
                            ?: "Governance exemption added by operator.",
                        active = true,
                        addedBy = actorRef,
                        addedAtMs = now,
                        summary = "Exemption added for ${scope.name.lowercase().replace('_', ' ')} scope."
                    )
                    val existing = crossTenantRollout.exemptions.filterNot {
                        it.scope == scope &&
                            it.tenantId == exemption.tenantId &&
                            it.workspaceId == exemption.workspaceId &&
                            it.active
                    }
                    crossTenantRollout = crossTenantRollout.copy(
                        exemptions = (existing + exemption).takeLast(40),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_TARGET_EXEMPTED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.TARGET_EXEMPTED,
                        summary = exemption.summary,
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION -> {
                    val scope = normalizeScopeScope(cmd.policyRolloutScope)
                    val updatedExemptions = crossTenantRollout.exemptions.map { record ->
                        if (
                            record.active &&
                            record.scope == scope &&
                            (cmd.policyRolloutTenantId.isNullOrBlank() || record.tenantId == cmd.policyRolloutTenantId) &&
                            (cmd.policyRolloutWorkspaceId.isNullOrBlank() || record.workspaceId == cmd.policyRolloutWorkspaceId)
                        ) {
                            record.copy(
                                active = false,
                                removedAtMs = now,
                                summary = "Exemption removed for ${scope.name.lowercase().replace('_', ' ')} scope."
                            )
                        } else {
                            record
                        }
                    }
                    crossTenantRollout = crossTenantRollout.copy(
                        exemptions = updatedExemptions.takeLast(40),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_TARGET_UNEXEMPTED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.TARGET_UNEXEMPTED,
                        summary = "Exemption removed for ${scope.name.lowercase().replace('_', ' ')} scope.",
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET -> {
                    val scope = normalizeScopeScope(cmd.policyRolloutScope)
                    val pin = PolicyRolloutPinRecord(
                        pinId = "pin_${scope.name.lowercase()}_${now}",
                        scope = scope,
                        tenantId = cmd.policyRolloutTenantId?.takeIf { it.isNotBlank() },
                        workspaceId = cmd.policyRolloutWorkspaceId?.takeIf { it.isNotBlank() },
                        packVersionId = cmd.policyPinPackVersionId
                            ?.takeIf { it.isNotBlank() }
                            ?: workflowPackVersion
                            ?: state.lastSafePackVersionId,
                        reason = cmd.policyLifecycleReason
                            ?.takeIf { it.isNotBlank() }
                            ?: cmd.policyRolloutReason
                                ?.takeIf { it.isNotBlank() }
                            ?: "Policy rollout target pinned by operator.",
                        active = true,
                        pinnedBy = actorRef,
                        pinnedAtMs = now,
                        summary = "Target pinned at ${scope.name.lowercase().replace('_', ' ')} scope."
                    )
                    val existing = crossTenantRollout.pins.filterNot {
                        it.scope == scope &&
                            it.tenantId == pin.tenantId &&
                            it.workspaceId == pin.workspaceId &&
                            it.active
                    }
                    crossTenantRollout = crossTenantRollout.copy(
                        pins = (existing + pin).takeLast(40),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_TARGET_PINNED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.TARGET_PINNED,
                        summary = pin.summary,
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET -> {
                    val scope = normalizeScopeScope(cmd.policyRolloutScope)
                    val updatedPins = crossTenantRollout.pins.map { record ->
                        if (
                            record.active &&
                            record.scope == scope &&
                            (cmd.policyRolloutTenantId.isNullOrBlank() || record.tenantId == cmd.policyRolloutTenantId) &&
                            (cmd.policyRolloutWorkspaceId.isNullOrBlank() || record.workspaceId == cmd.policyRolloutWorkspaceId)
                        ) {
                            record.copy(
                                active = false,
                                unpinnedAtMs = now,
                                summary = "Target unpinned at ${scope.name.lowercase().replace('_', ' ')} scope."
                            )
                        } else {
                            record
                        }
                    }
                    crossTenantRollout = crossTenantRollout.copy(
                        pins = updatedPins.takeLast(40),
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_TARGET_UNPINNED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.TARGET_UNPINNED,
                        summary = "Target unpinned at ${scope.name.lowercase().replace('_', ' ')} scope.",
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.DEPRECATE_POLICY_PACK -> {
                    packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.DEPRECATED
                    packDeprecationSummary = cmd.policyLifecycleReason
                        ?.takeIf { it.isNotBlank() }
                        ?: "Policy pack marked as deprecated; no new targets should be attached."
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_PACK_DEPRECATED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.PACK_DEPRECATED,
                        summary = packDeprecationSummary,
                        codes = codes
                    )
                    recomputeCrossTenantRollout(
                        forceHold = true,
                        holdSummary = "Pack deprecation requires cross-tenant drift review before retirement."
                    )
                }

                GovernanceActionType.RETIRE_POLICY_PACK -> {
                    val hasActivePins = crossTenantRollout.pins.any { it.active }
                    val hasActiveExemptions = crossTenantRollout.exemptions.any { it.active }
                    val blocked = hasActivePins || hasActiveExemptions
                    if (blocked) {
                        packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.BLOCKED
                        packRetirementSummary = "Pack retirement blocked by active pins/exemptions."
                        reasonCodes += listOf(
                            RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED,
                            RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD
                        )
                        appendPackLifecycleEvent(
                            type = WorkflowPolicyPackLifecycleEventType.CROSS_TENANT_ROLLOUT_HELD,
                            summary = "Pack retirement blocked by active pins/exemptions.",
                            codes = listOf(
                                RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED,
                                RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD
                            )
                        )
                    } else {
                        packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.RETIRED
                        packRetirementSummary = cmd.policyLifecycleReason
                            ?.takeIf { it.isNotBlank() }
                            ?: "Policy pack retirement started."
                        val codes = listOf(RoleReasonCodes.ROLE_POLICY_PACK_RETIREMENT_STARTED)
                        reasonCodes += codes
                        appendPackLifecycleEvent(
                            type = WorkflowPolicyPackLifecycleEventType.PACK_RETIREMENT_STARTED,
                            summary = packRetirementSummary,
                            codes = codes
                        )
                    }
                    recomputeCrossTenantRollout(
                        forceHold = blocked,
                        holdSummary = if (blocked) {
                            "Cross-tenant rollout held until retirement blockers are cleared."
                        } else {
                            null
                        }
                    )
                }

                GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT -> {
                    val fromPackId = cmd.workflowPolicyPackId
                        ?: cmd.policyPackId
                        ?: governanceProgram?.packId
                        ?: state.target.workflowTemplateId
                        ?: "pack_current"
                    val toPackId = cmd.policyReplacementPackId
                        ?.takeIf { it.isNotBlank() }
                        ?: "${fromPackId}_replacement"
                    val toVersion = cmd.policyReplacementPackVersionId
                        ?.takeIf { it.isNotBlank() }
                        ?: cmd.policyPinPackVersionId
                            ?.takeIf { it.isNotBlank() }
                    packReplacementPlan = WorkflowPolicyPackReplacementPlan(
                        replacementId = "replacement_${fromPackId}_${now}",
                        fromPackId = fromPackId,
                        toPackId = toPackId,
                        toPackVersionId = toVersion,
                        reason = cmd.policyLifecycleReason
                            ?.takeIf { it.isNotBlank() }
                            ?: "Attach replacement plan for controlled policy transition.",
                        effectiveAfterMs = now,
                        summary = "Replacement plan attached: $fromPackId -> $toPackId."
                    )
                    packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.SUPERSEDED
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_PACK_REPLACEMENT_ATTACHED)
                    reasonCodes += codes
                    appendPackLifecycleEvent(
                        type = WorkflowPolicyPackLifecycleEventType.PACK_REPLACEMENT_ATTACHED,
                        summary = packReplacementPlan?.summary.orEmpty(),
                        codes = codes
                    )
                    recomputeCrossTenantRollout()
                }

                GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN -> {
                    computePolicyEstateSnapshot()
                    val resolvedPlan = (policyEstateRemediationPlan ?: policyEstateSnapshot?.remediationPlan)
                        ?: PolicyEstateRemediationPlan(
                            planId = "estate_plan_${workflowTemplateId}_$now",
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion
                        )
                    val summary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: "Policy estate remediation plan attached for drift and lifecycle blockers."
                    policyEstateRemediationPlan = resolvedPlan.copy(
                        status = PolicyEstateRemediationStatus.RECOMMENDED,
                        summary = summary,
                        actions = policyEstateRemediationActions.takeLast(40),
                        updatedAtMs = now
                    )
                    policyEstateRemediationActions += PolicyEstateRemediationActionRecord(
                        actionId = "estate_action_attach_plan_$now",
                        action = policyEstateRemediationPlan?.suggestions?.firstOrNull()?.action
                            ?: PolicyEstateRemediationActionType.HOLD_RETIREMENT,
                        status = PolicyEstateRemediationStatus.RECOMMENDED,
                        summary = summary,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED,
                            RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED
                        ),
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += listOf(
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED,
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_RECOMMENDED
                    )
                }

                GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER -> {
                    computePolicyEstateSnapshot()
                    val existingSnapshot = policyEstateSnapshot ?: PolicyEstateSnapshot(
                        snapshotId = "estate_snapshot_${workflowTemplateId}_$now",
                        generatedAtMs = now
                    )
                    val targetBlocker = existingSnapshot.blockers.firstOrNull { !it.acknowledged }
                    val updatedBlockers = if (targetBlocker == null) {
                        existingSnapshot.blockers
                    } else {
                        existingSnapshot.blockers.map { blocker ->
                            if (blocker.blockerId == targetBlocker.blockerId) {
                                blocker.copy(
                                    acknowledged = true,
                                    acknowledgedBy = actorRef,
                                    acknowledgedAtMs = now
                                )
                            } else {
                                blocker
                            }
                        }
                    }
                    policyEstateSnapshot = existingSnapshot.copy(
                        blockers = updatedBlockers,
                        generatedAtMs = now,
                        remediationPlan = policyEstateRemediationPlan ?: existingSnapshot.remediationPlan
                    )
                    val summary = if (targetBlocker == null) {
                        "No outstanding policy estate blocker required acknowledgement."
                    } else {
                        "Policy estate blocker acknowledged: ${targetBlocker.summary}"
                    }
                    val status = if (targetBlocker == null) {
                        PolicyEstateRemediationStatus.DEFERRED
                    } else {
                        PolicyEstateRemediationStatus.ACKNOWLEDGED
                    }
                    policyEstateRemediationActions += PolicyEstateRemediationActionRecord(
                        actionId = "estate_action_ack_blocker_$now",
                        action = PolicyEstateRemediationActionType.ACK_BLOCKER,
                        status = status,
                        summary = summary,
                        reasonCodes = if (targetBlocker == null) {
                            listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED)
                        } else {
                            listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED)
                        },
                        actor = actorRef,
                        timestampMs = now
                    )
                    policyEstateRemediationPlan = (policyEstateRemediationPlan ?: existingSnapshot.remediationPlan)
                        ?.copy(
                            status = status,
                            summary = summary,
                            actions = policyEstateRemediationActions.takeLast(40),
                            updatedAtMs = now
                        )
                    reasonCodes += if (targetBlocker == null) {
                        listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED)
                    } else {
                        listOf(RoleReasonCodes.ROLE_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED)
                    }
                }

                GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION -> {
                    computePolicyEstateSnapshot()
                    val chosenSuggestion = policyEstateRemediationPlan
                        ?.suggestions
                        ?.firstOrNull { it.safe }
                        ?: policyEstateRemediationPlan
                            ?.suggestions
                            ?.firstOrNull()
                    val chosenAction = chosenSuggestion?.action
                        ?: PolicyEstateRemediationActionType.HOLD_RETIREMENT
                    val approvalRequired = chosenSuggestion?.safe == false
                    val scheduledAt = cmd.scheduledAtMs ?: now
                    val summary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: if (approvalRequired) {
                            "Policy estate remediation requires approval before automatic execution."
                        } else {
                            "Policy estate remediation scheduled for operator execution."
                        }
                    val scheduleReasonCodes = buildList {
                        add(RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_SCHEDULED)
                        add(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_SCHEDULED)
                        if (approvalRequired) {
                            add(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_APPROVAL_REQUIRED)
                        }
                    }.distinct()
                    policyEstateRemediationActions += PolicyEstateRemediationActionRecord(
                        actionId = "estate_action_scheduled_$now",
                        action = chosenAction,
                        status = PolicyEstateRemediationStatus.SCHEDULED,
                        summary = summary,
                        reasonCodes = scheduleReasonCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    policyEstateRemediationPlan = (policyEstateRemediationPlan ?: PolicyEstateRemediationPlan(
                        planId = "estate_plan_${workflowTemplateId}_$now",
                        packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                        packVersionId = workflowPackVersion
                    )).copy(
                        status = if (approvalRequired) {
                            PolicyEstateRemediationStatus.ACKNOWLEDGED
                        } else {
                            PolicyEstateRemediationStatus.SCHEDULED
                        },
                        summary = summary,
                        actions = policyEstateRemediationActions.takeLast(40),
                        updatedAtMs = now
                    )
                    estateAutomationRule = (estateAutomationRule ?: EstateAutomationRule(
                        ruleId = "estate_safe_remediation",
                        name = "Estate safe remediation",
                        summary = "Schedule and auto-apply bounded safe remediation only."
                    )).copy(enabled = true, allowScheduling = true)
                    scheduledRemediationPlan = ScheduledRemediationPlan(
                        scheduleId = scheduledRemediationPlan?.scheduleId
                            ?.takeIf { it.isNotBlank() }
                            ?: "estate_schedule_${workflowTemplateId}_$scheduledAt",
                        action = chosenAction,
                        status = if (approvalRequired) {
                            ScheduledRemediationStatus.APPROVAL_REQUIRED
                        } else {
                            ScheduledRemediationStatus.SCHEDULED
                        },
                        target = ScheduledRemediationTarget(
                            scope = state.target.scope,
                            tenantId = state.target.tenantId,
                            workspaceId = state.target.workspaceId,
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion,
                            summary = "Scheduled remediation target ${state.target.scope.name.lowercase().replace('_', ' ')}."
                        ),
                        scheduledAtMs = scheduledAt,
                        scheduledBy = actorRef,
                        nextRunAtMs = scheduledAt,
                        approvalRequirement = if (approvalRequired) {
                            AutomationApprovalRequirement.REQUIRED_FOR_RISKY_OPERATION
                        } else {
                            AutomationApprovalRequirement.NOT_REQUIRED
                        },
                        approvalDecision = if (approvalRequired) {
                            AutomationApprovalDecision.PENDING
                        } else {
                            AutomationApprovalDecision.NOT_REQUIRED
                        },
                        summary = summary,
                        reasonCodes = scheduleReasonCodes,
                        updatedAtMs = now
                    )
                    estateAutomationEligibility = EstateAutomationEligibility(
                        status = if (approvalRequired) {
                            EstateAutomationEligibilityStatus.APPROVAL_REQUIRED
                        } else {
                            EstateAutomationEligibilityStatus.SCHEDULED
                        },
                        summary = summary,
                        reasonCodes = scheduleReasonCodes,
                        approvalRequirement = if (approvalRequired) {
                            AutomationApprovalRequirement.REQUIRED_FOR_RISKY_OPERATION
                        } else {
                            AutomationApprovalRequirement.NOT_REQUIRED
                        },
                        approvalDecision = if (approvalRequired) {
                            AutomationApprovalDecision.PENDING
                        } else {
                            AutomationApprovalDecision.NOT_REQUIRED
                        },
                        evaluatedAtMs = now
                    )
                    governanceProgramOperations += GovernanceProgramOperation(
                        operationId = "program_op_schedule_estate_$now",
                        action = GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
                        status = if (approvalRequired) {
                            GovernanceProgramOperationStatus.APPROVAL_REQUIRED
                        } else {
                            GovernanceProgramOperationStatus.SCHEDULED
                        },
                        summary = summary,
                        reasonCodes = scheduleReasonCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += scheduleReasonCodes
                }

                GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION -> {
                    val existing = scheduledRemediationPlan ?: ScheduledRemediationPlan(
                        scheduleId = "estate_schedule_${workflowTemplateId}_$now",
                        action = policyEstateRemediationPlan
                            ?.suggestions
                            ?.firstOrNull()
                            ?.action
                            ?: PolicyEstateRemediationActionType.HOLD_RETIREMENT,
                        target = ScheduledRemediationTarget(
                            scope = state.target.scope,
                            tenantId = state.target.tenantId,
                            workspaceId = state.target.workspaceId,
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion
                        )
                    )
                    val summary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: "Policy estate scheduled remediation paused."
                    val pauseCodes = listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_PAUSED,
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED
                    )
                    scheduledRemediationPlan = existing.copy(
                        status = ScheduledRemediationStatus.PAUSED,
                        summary = summary,
                        reasonCodes = (existing.reasonCodes + pauseCodes).distinct(),
                        updatedAtMs = now
                    )
                    policyEstateRemediationPlan = policyEstateRemediationPlan?.copy(
                        status = PolicyEstateRemediationStatus.DEFERRED,
                        summary = summary,
                        updatedAtMs = now
                    )
                    estateAutomationEligibility = EstateAutomationEligibility(
                        status = EstateAutomationEligibilityStatus.PAUSED,
                        summary = summary,
                        reasonCodes = pauseCodes,
                        suppressionState = EstateAutomationSuppressionState.OPERATOR_OVERRIDE,
                        evaluatedAtMs = now
                    )
                    governanceProgramOperations += GovernanceProgramOperation(
                        operationId = "program_op_pause_estate_$now",
                        action = GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
                        status = GovernanceProgramOperationStatus.PAUSED,
                        summary = summary,
                        reasonCodes = pauseCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += pauseCodes
                }

                GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION -> {
                    val existing = scheduledRemediationPlan ?: ScheduledRemediationPlan(
                        scheduleId = "estate_schedule_${workflowTemplateId}_$now",
                        action = policyEstateRemediationPlan
                            ?.suggestions
                            ?.firstOrNull()
                            ?.action
                            ?: PolicyEstateRemediationActionType.HOLD_RETIREMENT,
                        target = ScheduledRemediationTarget(
                            scope = state.target.scope,
                            tenantId = state.target.tenantId,
                            workspaceId = state.target.workspaceId,
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion
                        )
                    )
                    val summary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: "Policy estate scheduled remediation resumed."
                    val resumeCodes = listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_RESUMED,
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_SCHEDULED
                    )
                    scheduledRemediationPlan = existing.copy(
                        status = ScheduledRemediationStatus.SCHEDULED,
                        summary = summary,
                        reasonCodes = (existing.reasonCodes + resumeCodes).distinct(),
                        nextRunAtMs = now,
                        updatedAtMs = now
                    )
                    policyEstateRemediationPlan = policyEstateRemediationPlan?.copy(
                        status = PolicyEstateRemediationStatus.SCHEDULED,
                        summary = summary,
                        updatedAtMs = now
                    )
                    estateAutomationEligibility = EstateAutomationEligibility(
                        status = EstateAutomationEligibilityStatus.SCHEDULED,
                        summary = summary,
                        reasonCodes = resumeCodes,
                        evaluatedAtMs = now
                    )
                    governanceProgramOperations += GovernanceProgramOperation(
                        operationId = "program_op_resume_estate_$now",
                        action = GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
                        status = GovernanceProgramOperationStatus.RESUMED,
                        summary = summary,
                        reasonCodes = resumeCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += resumeCodes
                }

                GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION -> {
                    val existing = scheduledRemediationPlan
                    val summary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: "Policy estate scheduled remediation cancelled."
                    val cancelCodes = listOf(
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_CANCELLED,
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED
                    )
                    scheduledRemediationPlan = (existing ?: ScheduledRemediationPlan(
                        scheduleId = "estate_schedule_${workflowTemplateId}_$now",
                        action = PolicyEstateRemediationActionType.HOLD_RETIREMENT,
                        target = ScheduledRemediationTarget(
                            scope = state.target.scope,
                            tenantId = state.target.tenantId,
                            workspaceId = state.target.workspaceId,
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion
                        )
                    )).copy(
                        status = ScheduledRemediationStatus.CANCELLED,
                        summary = summary,
                        reasonCodes = ((existing?.reasonCodes ?: emptyList()) + cancelCodes).distinct(),
                        nextRunAtMs = null,
                        updatedAtMs = now
                    )
                    policyEstateRemediationPlan = policyEstateRemediationPlan?.copy(
                        status = PolicyEstateRemediationStatus.DEFERRED,
                        summary = summary,
                        updatedAtMs = now
                    )
                    automationCancellationRecords += AutomationCancellationRecord(
                        cancellationId = "estate_cancel_${workflowTemplateId}_$now",
                        scheduleId = scheduledRemediationPlan?.scheduleId.orEmpty(),
                        reason = summary,
                        reasonCodes = cancelCodes,
                        cancelledBy = actorRef,
                        cancelledAtMs = now
                    )
                    estateAutomationEligibility = EstateAutomationEligibility(
                        status = EstateAutomationEligibilityStatus.CANCELLED,
                        summary = summary,
                        reasonCodes = cancelCodes,
                        suppressionState = EstateAutomationSuppressionState.OPERATOR_OVERRIDE,
                        evaluatedAtMs = now
                    )
                    governanceProgramOperations += GovernanceProgramOperation(
                        operationId = "program_op_cancel_estate_$now",
                        action = GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
                        status = GovernanceProgramOperationStatus.CANCELLED,
                        summary = summary,
                        reasonCodes = cancelCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += cancelCodes
                }

                GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION -> {
                    computePolicyEstateSnapshot()
                    val chosenSuggestion = policyEstateRemediationPlan
                        ?.suggestions
                        ?.firstOrNull { it.safe }
                        ?: policyEstateRemediationPlan
                            ?.suggestions
                            ?.firstOrNull()
                    val chosenAction = chosenSuggestion?.action ?: PolicyEstateRemediationActionType.HOLD_RETIREMENT
                    val approvalRequired = chosenSuggestion?.safe == false
                    var applied = false
                    var appliedSummary = cmd.policyRolloutReason
                        ?.takeIf { it.isNotBlank() }
                        ?: chosenSuggestion?.summary
                        ?: "Policy estate remediation action was applied."
                    if (approvalRequired) {
                        appliedSummary = "Policy estate remediation is blocked from automatic execution until approval is granted."
                    }
                    when (chosenAction) {
                        PolicyEstateRemediationActionType.UNPIN_TARGET -> {
                            val activePin = crossTenantRollout.pins.firstOrNull { it.active }
                            if (activePin != null) {
                                crossTenantRollout = crossTenantRollout.copy(
                                    pins = crossTenantRollout.pins.map { pin ->
                                        if (pin.pinId == activePin.pinId) {
                                            pin.copy(
                                                active = false,
                                                unpinnedAtMs = now,
                                                summary = "Target unpinned by safe estate remediation."
                                            )
                                        } else {
                                            pin
                                        }
                                    }.takeLast(40),
                                    updatedAtMs = now
                                )
                                appliedSummary = "Policy estate remediation unpinned rollout target ${activePin.pinId}."
                                reasonCodes += RoleReasonCodes.ROLE_POLICY_TARGET_UNPINNED
                                applied = true
                            }
                        }

                        PolicyEstateRemediationActionType.REMOVE_EXEMPTION -> {
                            val activeExemption = crossTenantRollout.exemptions.firstOrNull { it.active }
                            if (activeExemption != null) {
                                crossTenantRollout = crossTenantRollout.copy(
                                    exemptions = crossTenantRollout.exemptions.map { exemption ->
                                        if (exemption.exemptionId == activeExemption.exemptionId) {
                                            exemption.copy(
                                                active = false,
                                                removedAtMs = now,
                                                summary = "Exemption removed by safe estate remediation."
                                            )
                                        } else {
                                            exemption
                                        }
                                    }.takeLast(40),
                                    updatedAtMs = now
                                )
                                appliedSummary = "Policy estate remediation removed exemption ${activeExemption.exemptionId}."
                                reasonCodes += RoleReasonCodes.ROLE_POLICY_TARGET_UNEXEMPTED
                                applied = true
                            }
                        }

                        PolicyEstateRemediationActionType.ATTACH_REPLACEMENT_PLAN -> {
                            if (packReplacementPlan == null) {
                                val fromPackId = governanceProgram?.packId
                                    ?: state.target.workflowTemplateId
                                    ?: "pack_current"
                                val toPackId = "${fromPackId}_replacement"
                                packReplacementPlan = WorkflowPolicyPackReplacementPlan(
                                    replacementId = "replacement_${fromPackId}_$now",
                                    fromPackId = fromPackId,
                                    toPackId = toPackId,
                                    toPackVersionId = workflowPackVersion,
                                    reason = "Safe estate remediation attached replacement plan.",
                                    effectiveAfterMs = now,
                                    summary = "Replacement plan attached: $fromPackId -> $toPackId."
                                )
                                packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.SUPERSEDED
                                appliedSummary = "Policy estate remediation attached replacement plan $fromPackId -> $toPackId."
                                reasonCodes += RoleReasonCodes.ROLE_POLICY_PACK_REPLACEMENT_ATTACHED
                                applied = true
                            }
                        }

                        PolicyEstateRemediationActionType.MOVE_TO_TARGET_PACK_VERSION -> {
                            if (workflowPackVersion != null && workflowPackVersion != state.lastSafePackVersionId) {
                                state = state.copy(lastSafePackVersionId = workflowPackVersion)
                                appliedSummary = "Policy estate remediation aligned last safe pack version to $workflowPackVersion."
                                applied = true
                            }
                        }

                        PolicyEstateRemediationActionType.HOLD_RETIREMENT -> {
                            packLifecycleStatus = WorkflowPolicyPackLifecycleStatus.BLOCKED
                            packRetirementSummary = "Policy estate remediation held retirement until blockers clear."
                            reasonCodes += RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED
                            appliedSummary = "Policy estate remediation held retirement to preserve safe lifecycle progression."
                            applied = true
                        }

                        PolicyEstateRemediationActionType.ACK_BLOCKER -> {
                            val targetBlocker = policyEstateSnapshot?.blockers?.firstOrNull { !it.acknowledged }
                            if (targetBlocker != null) {
                                policyEstateSnapshot = policyEstateSnapshot?.copy(
                                    blockers = policyEstateSnapshot
                                        ?.blockers
                                        .orEmpty()
                                        .map { blocker ->
                                            if (blocker.blockerId == targetBlocker.blockerId) {
                                                blocker.copy(
                                                    acknowledged = true,
                                                    acknowledgedBy = actorRef,
                                                    acknowledgedAtMs = now
                                                )
                                            } else {
                                                blocker
                                            }
                                        }
                                )
                                appliedSummary = "Policy estate remediation acknowledged blocker ${targetBlocker.blockerId}."
                                applied = true
                            }
                        }
                    }
                    recomputeCrossTenantRollout()
                    val actionStatus = if (approvalRequired) {
                        PolicyEstateRemediationStatus.DEFERRED
                    } else if (applied) {
                        PolicyEstateRemediationStatus.APPLIED
                    } else {
                        PolicyEstateRemediationStatus.DEFERRED
                    }
                    val applyReasonCodes = if (approvalRequired) {
                        listOf(
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_APPROVAL_REQUIRED,
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_BLOCKED,
                            RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED
                        )
                    } else if (applied) {
                        listOf(
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_EXECUTED,
                            RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_APPLIED
                        )
                    } else {
                        listOf(
                            RoleReasonCodes.ROLE_ESTATE_AUTOMATION_BLOCKED,
                            RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED
                        )
                    }
                    policyEstateRemediationActions += PolicyEstateRemediationActionRecord(
                        actionId = "estate_action_apply_$now",
                        action = chosenAction,
                        status = actionStatus,
                        summary = appliedSummary,
                        reasonCodes = applyReasonCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    policyEstateRemediationPlan = (policyEstateRemediationPlan ?: PolicyEstateRemediationPlan(
                        planId = "estate_plan_${workflowTemplateId}_$now",
                        packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                        packVersionId = workflowPackVersion
                    )).copy(
                        status = actionStatus,
                        summary = appliedSummary,
                        actions = policyEstateRemediationActions.takeLast(40),
                        updatedAtMs = now
                    )
                    scheduledRemediationPlan = (scheduledRemediationPlan ?: ScheduledRemediationPlan(
                        scheduleId = "estate_schedule_${workflowTemplateId}_$now",
                        action = chosenAction,
                        target = ScheduledRemediationTarget(
                            scope = state.target.scope,
                            tenantId = state.target.tenantId,
                            workspaceId = state.target.workspaceId,
                            packId = governanceProgram?.packId ?: state.target.workflowTemplateId,
                            packVersionId = workflowPackVersion
                        ),
                        scheduledAtMs = now,
                        scheduledBy = actorRef
                    )).copy(
                        status = when {
                            approvalRequired -> ScheduledRemediationStatus.APPROVAL_REQUIRED
                            applied -> ScheduledRemediationStatus.EXECUTED
                            else -> ScheduledRemediationStatus.BLOCKED
                        },
                        approvalRequirement = if (approvalRequired) {
                            AutomationApprovalRequirement.REQUIRED_FOR_RISKY_OPERATION
                        } else {
                            AutomationApprovalRequirement.NOT_REQUIRED
                        },
                        approvalDecision = if (approvalRequired) {
                            AutomationApprovalDecision.PENDING
                        } else {
                            AutomationApprovalDecision.NOT_REQUIRED
                        },
                        lastExecution = ScheduledRemediationExecution(
                            executionId = "estate_exec_${workflowTemplateId}_$now",
                            status = when {
                                approvalRequired -> ScheduledRemediationStatus.APPROVAL_REQUIRED
                                applied -> ScheduledRemediationStatus.EXECUTED
                                else -> ScheduledRemediationStatus.BLOCKED
                            },
                            summary = appliedSummary,
                            reasonCodes = applyReasonCodes,
                            executedAtMs = now
                        ),
                        result = ScheduledRemediationResult(
                            status = when {
                                approvalRequired -> ScheduledRemediationStatus.APPROVAL_REQUIRED
                                applied -> ScheduledRemediationStatus.EXECUTED
                                else -> ScheduledRemediationStatus.BLOCKED
                            },
                            summary = appliedSummary,
                            reasonCodes = applyReasonCodes
                        ),
                        summary = appliedSummary,
                        reasonCodes = (scheduledRemediationPlan?.reasonCodes.orEmpty() + applyReasonCodes).distinct(),
                        updatedAtMs = now
                    )
                    estateAutomationEligibility = EstateAutomationEligibility(
                        status = when {
                            approvalRequired -> EstateAutomationEligibilityStatus.APPROVAL_REQUIRED
                            applied -> EstateAutomationEligibilityStatus.EXECUTED
                            else -> EstateAutomationEligibilityStatus.BLOCKED
                        },
                        summary = appliedSummary,
                        reasonCodes = applyReasonCodes,
                        approvalRequirement = if (approvalRequired) {
                            AutomationApprovalRequirement.REQUIRED_FOR_RISKY_OPERATION
                        } else {
                            AutomationApprovalRequirement.NOT_REQUIRED
                        },
                        approvalDecision = if (approvalRequired) {
                            AutomationApprovalDecision.PENDING
                        } else {
                            AutomationApprovalDecision.NOT_REQUIRED
                        },
                        evaluatedAtMs = now
                    )
                    governanceProgramOperations += GovernanceProgramOperation(
                        operationId = "program_op_apply_estate_$now",
                        action = GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION,
                        status = when {
                            approvalRequired -> GovernanceProgramOperationStatus.APPROVAL_REQUIRED
                            applied -> GovernanceProgramOperationStatus.EXECUTED
                            else -> GovernanceProgramOperationStatus.BLOCKED
                        },
                        summary = appliedSummary,
                        reasonCodes = applyReasonCodes,
                        actor = actorRef,
                        timestampMs = now
                    )
                    reasonCodes += if (approvalRequired) {
                        RoleReasonCodes.ROLE_ESTATE_AUTOMATION_APPROVAL_REQUIRED
                    } else if (applied) {
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_APPLIED
                    } else {
                        RoleReasonCodes.ROLE_POLICY_ESTATE_REMEDIATION_DEFERRED
                    }
                }

                GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
                GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
                GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE -> {
                    val requestedMode = when (cmd.commandType) {
                        GovernanceActionType.ENFORCE_POLICY_ROLLOUT -> PolicyRolloutMode.ENFORCED
                        GovernanceActionType.PROMOTE_POLICY_ROLLOUT ->
                            cmd.policyRolloutMode ?: if (state.mode == PolicyRolloutMode.SIMULATION_ONLY) {
                                PolicyRolloutMode.STAGED
                            } else {
                                PolicyRolloutMode.ENFORCED
                            }
                        else -> cmd.policyRolloutMode ?: state.mode
                    }
                    val requestedScope = normalizeScopeScope(cmd.policyRolloutScope)
                    val requirement = requiredApprovalFor(
                        mode = requestedMode,
                        scope = requestedScope,
                        previousScope = state.target.scope
                    )
                    val riskyTransition = requirement != PolicyRolloutApprovalRequirement.NOT_REQUIRED
                    val approved = state.approvalState == PolicyRolloutApprovalState.APPROVED
                    val scopeExpansion = scopeRank(requestedScope) > scopeRank(state.target.scope)
                    if (riskyTransition && !approved) {
                        state = state.copy(
                            approvalRequirement = requirement,
                            approvalState = PolicyRolloutApprovalState.PENDING,
                            approvalRecord = (state.approvalRecord ?: PolicyRolloutApprovalRecord(
                                requestId = "rollout_approval_req_${now}",
                                requestedBy = actorRef,
                                status = PolicyRolloutApprovalState.PENDING
                            )).copy(
                                status = PolicyRolloutApprovalState.PENDING,
                                requirement = requirement,
                                reason = cmd.policyRolloutReason.orEmpty().ifBlank {
                                    "Promotion blocked pending rollout governance approval."
                                },
                                requestedAtMs = state.approvalRecord?.requestedAtMs?.takeIf { it > 0L } ?: now
                            ),
                            riskSummary = "Risky rollout transition requires explicit approval before enforcement.",
                            updatedAtMs = now
                        )
                        val codes = listOf(
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVAL_REQUIRED,
                            RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
                        )
                        reasonCodes += codes
                        appendAudit(
                            action = PolicyRolloutAuditAction.PROMOTION_REQUESTED,
                            summary = "Rollout promotion blocked pending approval.",
                            codes = codes
                        )
                    } else {
                        val nextStage = cmd.policyRolloutStage ?: toStage(requestedMode)
                        val nextTarget = updateTarget(requestedScope)
                        val modeReason = when (requestedMode) {
                            PolicyRolloutMode.SIMULATION_ONLY -> RoleReasonCodes.ROLE_POLICY_ROLLOUT_SIMULATION_ONLY
                            PolicyRolloutMode.STAGED -> RoleReasonCodes.ROLE_POLICY_ROLLOUT_STAGED
                            PolicyRolloutMode.ENFORCED -> RoleReasonCodes.ROLE_POLICY_ROLLOUT_ENFORCED
                            PolicyRolloutMode.INACTIVE -> RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
                        }
                        val scopeCodes = if (scopeExpansion) {
                            listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_SCOPE_EXPANDED)
                        } else {
                            emptyList()
                        }
                        state = state.copy(
                            stage = nextStage,
                            mode = requestedMode,
                            target = nextTarget,
                            approvalRequirement = PolicyRolloutApprovalRequirement.NOT_REQUIRED,
                            approvalState = if (requestedMode == PolicyRolloutMode.ENFORCED) {
                                PolicyRolloutApprovalState.APPROVED
                            } else {
                                state.approvalState
                            },
                            lastSafeStage = if (nextStage == PolicyRolloutStage.ENFORCED) {
                                state.lastSafeStage
                            } else {
                                nextStage
                            },
                            lastSafeMode = if (requestedMode == PolicyRolloutMode.ENFORCED) {
                                state.lastSafeMode
                            } else {
                                requestedMode
                            },
                            lastSafePackVersionId = workflowPackVersion ?: state.lastSafePackVersionId,
                            riskSummary = when (requestedMode) {
                                PolicyRolloutMode.ENFORCED ->
                                    "Rollout is enforced after approval checks."
                                PolicyRolloutMode.STAGED ->
                                    "Rollout is staged for partial enforcement."
                                PolicyRolloutMode.SIMULATION_ONLY ->
                                    "Rollout remains simulation-only."
                                PolicyRolloutMode.INACTIVE ->
                                    "Rollout is inactive."
                            },
                            updatedAtMs = now
                        )
                        val codes = (listOf(modeReason) + scopeCodes).distinct()
                        reasonCodes += codes
                        appendAudit(
                            action = if (requestedMode == PolicyRolloutMode.ENFORCED) {
                                PolicyRolloutAuditAction.ENFORCED
                            } else {
                                PolicyRolloutAuditAction.PROMOTED
                            },
                            summary = if (requestedMode == PolicyRolloutMode.ENFORCED) {
                                "Policy rollout promoted to enforced mode."
                            } else {
                                "Policy rollout promoted to ${requestedMode.name.lowercase().replace('_', ' ')} mode."
                            },
                            codes = codes
                        )
                        if (scopeExpansion) {
                            appendAudit(
                                action = PolicyRolloutAuditAction.SCOPE_EXPANDED,
                                summary = "Policy rollout scope expanded to ${requestedScope.name.lowercase().replace('_', ' ')}.",
                                codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_SCOPE_EXPANDED)
                            )
                        }
                    }
                }

                GovernanceActionType.PAUSE_POLICY_ROLLOUT -> {
                    state = state.copy(
                        stage = PolicyRolloutStage.PAUSED,
                        freezeState = PolicyRolloutFreezeState.PAUSED_BY_OPERATOR,
                        promotionStatus = PolicyPromotionStatus.PAUSED,
                        updatedAtMs = now
                    )
                    promotionStatus = PolicyPromotionStatus.PAUSED
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_PAUSED)
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.PAUSED,
                        summary = "Policy rollout paused by operator.",
                        codes = codes
                    )
                }

                GovernanceActionType.FREEZE_POLICY_ROLLOUT -> {
                    state = state.copy(
                        stage = PolicyRolloutStage.FROZEN,
                        freezeState = PolicyRolloutFreezeState.FROZEN_BY_OPERATOR,
                        updatedAtMs = now
                    )
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_FROZEN)
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.FROZEN,
                        summary = "Policy rollout frozen by operator.",
                        codes = codes
                    )
                }

                GovernanceActionType.RESUME_POLICY_ROLLOUT -> {
                    val restoredMode = state.lastSafeMode.takeIf { it != PolicyRolloutMode.INACTIVE }
                        ?: PolicyRolloutMode.SIMULATION_ONLY
                    state = state.copy(
                        stage = toStage(restoredMode),
                        mode = restoredMode,
                        freezeState = PolicyRolloutFreezeState.NOT_FROZEN,
                        promotionStatus = if (promotionStatus == PolicyPromotionStatus.PAUSED) {
                            PolicyPromotionStatus.REQUESTED
                        } else {
                            promotionStatus
                        },
                        updatedAtMs = now
                    )
                    if (promotionStatus == PolicyPromotionStatus.PAUSED) {
                        promotionStatus = PolicyPromotionStatus.REQUESTED
                    }
                    val codes = listOf(RoleReasonCodes.ROLE_POLICY_ROLLOUT_RESTORED_LAST_SAFE)
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.RESUMED,
                        summary = "Policy rollout resumed using last safe rollout state.",
                        codes = codes
                    )
                }

                GovernanceActionType.ROLLBACK_POLICY_ROLLOUT -> {
                    val restoredMode = state.lastSafeMode.takeIf { it != PolicyRolloutMode.INACTIVE }
                        ?: PolicyRolloutMode.SIMULATION_ONLY
                    val restoredStage = state.lastSafeStage.takeIf { it != PolicyRolloutStage.NOT_STARTED }
                        ?: PolicyRolloutStage.SIMULATION_ONLY
                    val rollbackRecord = PolicyRolloutRollbackRecord(
                        rollbackId = "rollout_rollback_${now}",
                        fromStage = state.stage,
                        toStage = restoredStage,
                        fromMode = state.mode,
                        toMode = restoredMode,
                        fromPackVersion = workflowPackVersion ?: state.lastSafePackVersionId,
                        toPackVersion = state.lastSafePackVersionId ?: workflowPackVersion,
                        triggeredBy = actorRef,
                        reason = cmd.policyRolloutReason.orEmpty().ifBlank {
                            "Rollback restored the last safe rollout state."
                        },
                        rolledBackAtMs = now,
                        summary = "Policy rollout rolled back to last safe state (${restoredMode.name.lowercase().replace('_', ' ')})."
                    )
                    state = state.copy(
                        stage = PolicyRolloutStage.ROLLED_BACK,
                        mode = restoredMode,
                        freezeState = PolicyRolloutFreezeState.NOT_FROZEN,
                        promotionStatus = PolicyPromotionStatus.ROLLED_BACK,
                        rollbackRecord = rollbackRecord,
                        updatedAtMs = now
                    )
                    promotionStatus = PolicyPromotionStatus.ROLLED_BACK
                    val codes = listOf(
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_ROLLED_BACK,
                        RoleReasonCodes.ROLE_POLICY_ROLLOUT_RESTORED_LAST_SAFE
                    )
                    reasonCodes += codes
                    appendAudit(
                        action = PolicyRolloutAuditAction.ROLLED_BACK,
                        summary = rollbackRecord.summary,
                        codes = codes
                    )
                }

                else -> Unit
            }
        }

        val readinessTarget = currentPromotionTarget()
        rolloutAnalytics = currentRolloutAnalytics(readinessTarget)
        promotionReadiness = currentPromotionReadiness(readinessTarget, rolloutAnalytics!!)
        approvalReviewSummary = updateApprovalReviewSummaryFromQueue()

        val blockerReasonCodes = promotionReadiness
            ?.blockers
            ?.flatMap { it.reasonCodes }
            .orEmpty()
        val recommendationReasonCodes = promotionReadiness
            ?.recommendation
            ?.reasonCodes
            .orEmpty()
        reasonCodes += blockerReasonCodes
        reasonCodes += recommendationReasonCodes
        if (approvalReviewSummary?.pendingCount ?: 0 > 0) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_APPROVAL_PENDING
        }
        if ((approvalReviewSummary?.approvedCount ?: 0) > 0) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_APPROVAL_GRANTED
        }
        if ((approvalReviewSummary?.rejectedCount ?: 0) > 0) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_APPROVAL_DENIED
        }
        if (promotionStatus == PolicyPromotionStatus.REQUESTED) {
            val hasApprovalBlocker = promotionReadiness?.blockers?.any {
                it.type == PolicyPromotionBlockerType.APPROVAL_PENDING ||
                    it.type == PolicyPromotionBlockerType.APPROVAL_REQUIRED
            } == true
            if (hasApprovalBlocker) {
                promotionStatus = PolicyPromotionStatus.APPROVAL_PENDING
            }
        }
        if (
            promotionStatus == PolicyPromotionStatus.REQUESTED ||
            promotionStatus == PolicyPromotionStatus.APPROVAL_PENDING
        ) {
            if (promotionReadiness?.status == PolicyPromotionReadinessStatus.BLOCKED) {
                promotionStatus = PolicyPromotionStatus.BLOCKED
            }
        }

        recomputeCrossTenantRollout()
        governanceProgram = governanceProgram?.let { program ->
            val resolvedStatus = when {
                packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.RETIRED ||
                    packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.SUPERSEDED ->
                    PolicyGovernanceProgramStatus.RETIRED
                crossTenantRollout.readinessStatus == CrossTenantRolloutReadinessStatus.BLOCKED ->
                    PolicyGovernanceProgramStatus.HELD
                crossTenantRollout.readinessStatus == CrossTenantRolloutReadinessStatus.HOLD ->
                    PolicyGovernanceProgramStatus.PAUSED
                else ->
                    program.status
            }
            val recommendation = when (crossTenantRollout.readinessStatus) {
                CrossTenantRolloutReadinessStatus.READY ->
                    "Cross-tenant rollout is healthy; continue wave progression."
                CrossTenantRolloutReadinessStatus.HOLD ->
                    "Resolve exemptions/pins before expanding rollout scope."
                CrossTenantRolloutReadinessStatus.BLOCKED ->
                    "Clear cross-tenant blockers before any promotion."
            }
            program.copy(
                status = resolvedStatus,
                recommendations = listOf(
                    PolicyGovernanceProgramRecommendation(
                        code = "cross_tenant_readiness",
                        summary = recommendation,
                        reasonCodes = listOf(
                            if (crossTenantRollout.readinessStatus == CrossTenantRolloutReadinessStatus.READY) {
                                RoleReasonCodes.ROLE_POLICY_ROLLOUT_ADVANCE_ALLOWED
                            } else {
                                RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD
                            }
                        )
                    )
                ),
                summary = "Program ${program.name.ifBlank { program.programId }} is ${resolvedStatus.name.lowercase().replace('_', ' ')} " +
                    "with readiness ${crossTenantRollout.readinessStatus.name.lowercase().replace('_', ' ')}.",
                updatedAtMs = now
            )
        }
        programSummary = governanceProgram?.summary.orEmpty()
        crossTenantSummary = crossTenantRollout.summary
        packLifecycleSummary = buildString {
            append("Pack lifecycle is ")
            append(packLifecycleStatus.name.lowercase().replace('_', ' '))
            append('.')
            if (packDeprecationSummary.isNotBlank()) {
                append(' ')
                append(packDeprecationSummary)
            }
            if (packRetirementSummary.isNotBlank()) {
                append(' ')
                append(packRetirementSummary)
            }
            if (packReplacementPlan?.summary?.isNotBlank() == true) {
                append(' ')
                append(packReplacementPlan?.summary)
            }
        }.trim()
        if (packLifecycleStatus == WorkflowPolicyPackLifecycleStatus.BLOCKED) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_RETIREMENT_BLOCKED
        }
        if (
            crossTenantRollout.readinessStatus != CrossTenantRolloutReadinessStatus.READY &&
            packLifecycleEvents.none {
                it.type == WorkflowPolicyPackLifecycleEventType.CROSS_TENANT_ROLLOUT_HELD &&
                    it.timestampMs == now
            }
        ) {
            appendPackLifecycleEvent(
                type = WorkflowPolicyPackLifecycleEventType.CROSS_TENANT_ROLLOUT_HELD,
                summary = crossTenantRollout.blockerSummary.ifBlank {
                    "Cross-tenant rollout held by governance controls."
                },
                codes = listOf(RoleReasonCodes.ROLE_POLICY_CROSS_TENANT_ROLLOUT_HELD)
            )
        }

        val scheduleWindowInput = scheduledRemediationPlan?.window ?: estateAutomationEligibility?.window
        val hasScheduleSignal = scheduleWindowInput != null ||
            scheduledRemediationPlan != null ||
            estateAutomationEligibility != null ||
            policySchedulingWindow != null ||
            calendarEvaluation != null ||
            rolloutCalendar != null ||
            scheduleSummary.isNotBlank() ||
            rolloutCalendarSummary.isNotBlank()
        val scheduleReasonCodes = mutableListOf<String>()
        val derivedWindowType = when (scheduleWindowInput?.type) {
            EstateAutomationWindowType.QUIET_HOURS -> SchedulingWindowType.BLACKOUT_WINDOW
            EstateAutomationWindowType.MAINTENANCE_WINDOW -> SchedulingWindowType.MAINTENANCE_WINDOW
            null -> policySchedulingWindow?.windowType ?: SchedulingWindowType.MAINTENANCE_WINDOW
        }
        var scheduleDecision = calendarEvaluation?.decision ?: ExecutionWindowDecision.ELIGIBLE
        var scheduleWindowStatus = calendarEvaluation?.windowStatus ?: SchedulingWindowStatus.NOT_TRACKED
        var scheduleBlockReason = calendarEvaluation?.blockReason ?: ExecutionWindowBlockReason.NONE
        var scheduleNextEligibleAtMs = calendarEvaluation?.nextEligibleAtMs
            ?: scheduledRemediationPlan?.nextRunAtMs
            ?: estateAutomationEligibility?.cooldownState?.nextEligibleAtMs

        if (!hasScheduleSignal) {
            scheduleDecision = ExecutionWindowDecision.ELIGIBLE
            scheduleWindowStatus = SchedulingWindowStatus.NOT_TRACKED
            scheduleBlockReason = ExecutionWindowBlockReason.NONE
            scheduleSummary = "Schedule is not tracked for this rollout action."
        } else {
            val hasRuntimeScheduleInputs = scheduleWindowInput != null ||
                scheduledRemediationPlan != null ||
                estateAutomationEligibility != null
            val preserveHistoricalCalendarState = !hasRuntimeScheduleInputs &&
                (calendarEvaluation != null || policySchedulingWindow != null)
            scheduleReasonCodes += policySchedulingWindow?.reasonCodes.orEmpty()
            scheduleReasonCodes += calendarEvaluation?.reasonCodes.orEmpty()
            val cooldownActive = scheduledRemediationPlan?.cooldownState?.active == true ||
                estateAutomationEligibility?.cooldownState?.active == true ||
                scheduledRemediationPlan?.status == ScheduledRemediationStatus.COOLDOWN_ACTIVE ||
                estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.COOLDOWN_ACTIVE
            val pausedBySchedule = scheduledRemediationPlan?.status == ScheduledRemediationStatus.PAUSED ||
                state.stage == PolicyRolloutStage.PAUSED ||
                state.stage == PolicyRolloutStage.FROZEN ||
                state.freezeState == PolicyRolloutFreezeState.PAUSED_BY_OPERATOR ||
                state.freezeState == PolicyRolloutFreezeState.FROZEN_BY_OPERATOR ||
                state.freezeState == PolicyRolloutFreezeState.FROZEN_BY_GUARDRAIL
            val explicitSuppressed = scheduledRemediationPlan?.status == ScheduledRemediationStatus.SUPPRESSED ||
                estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.SUPPRESSED ||
                scheduledRemediationPlan?.suppressionState == EstateAutomationSuppressionState.OPERATOR_OVERRIDE
            val blackoutActive = scheduleWindowInput?.type == EstateAutomationWindowType.QUIET_HOURS &&
                scheduleWindowInput.active
            val waitingMaintenance = (
                scheduleWindowInput?.type == EstateAutomationWindowType.MAINTENANCE_WINDOW &&
                    !scheduleWindowInput.active
                ) ||
                scheduledRemediationPlan?.status == ScheduledRemediationStatus.WINDOW_BLOCKED ||
                estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.WINDOW_BLOCKED
            val schedulePlan = scheduledRemediationPlan
            val approvalPending = schedulePlan?.status == ScheduledRemediationStatus.APPROVAL_REQUIRED
            val scheduleDueAtMs = listOfNotNull(
                schedulePlan?.nextRunAtMs?.takeIf { it != 0L },
                schedulePlan?.scheduledAtMs?.takeIf { it != 0L }
            ).minOrNull()
            val scheduleExpired = (
                schedulePlan?.status == ScheduledRemediationStatus.DEFERRED ||
                    schedulePlan?.status == ScheduledRemediationStatus.SCHEDULED ||
                    schedulePlan?.status == ScheduledRemediationStatus.APPROVAL_REQUIRED
                ) &&
                scheduleDueAtMs != null &&
                scheduleDueAtMs < now

            when {
                preserveHistoricalCalendarState -> {
                    scheduleDecision = calendarEvaluation?.decision ?: scheduleDecision
                    scheduleWindowStatus = calendarEvaluation?.windowStatus ?: scheduleWindowStatus
                    scheduleBlockReason = calendarEvaluation?.blockReason ?: scheduleBlockReason
                    scheduleNextEligibleAtMs = calendarEvaluation?.nextEligibleAtMs ?: scheduleNextEligibleAtMs
                    scheduleSummary = calendarEvaluation?.summary
                        ?.takeIf { it.isNotBlank() }
                        ?: policySchedulingWindow?.summary
                        ?.takeIf { it.isNotBlank() }
                        ?: scheduleSummary
                }

                pausedBySchedule -> {
                    scheduleDecision = ExecutionWindowDecision.PAUSED
                    scheduleWindowStatus = SchedulingWindowStatus.PAUSED
                    scheduleBlockReason = ExecutionWindowBlockReason.PAUSED_BY_OPERATOR
                    scheduleReasonCodes += RoleReasonCodes.ROLE_AUTOMATION_SUPPRESSED_BY_SCHEDULE
                }

                blackoutActive -> {
                    scheduleDecision = ExecutionWindowDecision.BLOCKED
                    scheduleWindowStatus = SchedulingWindowStatus.BLOCKED
                    scheduleBlockReason = ExecutionWindowBlockReason.BLACKOUT_WINDOW
                    scheduleReasonCodes += RoleReasonCodes.ROLE_SCHEDULE_BLOCKED_BY_BLACKOUT
                    scheduleReasonCodes += RoleReasonCodes.ROLE_AUTOMATION_SUPPRESSED_BY_SCHEDULE
                }

                explicitSuppressed -> {
                    scheduleDecision = ExecutionWindowDecision.BLOCKED
                    scheduleWindowStatus = SchedulingWindowStatus.BLOCKED
                    scheduleBlockReason = ExecutionWindowBlockReason.SCHEDULE_SUPPRESSED
                    scheduleReasonCodes += RoleReasonCodes.ROLE_AUTOMATION_SUPPRESSED_BY_SCHEDULE
                }

                cooldownActive -> {
                    scheduleDecision = ExecutionWindowDecision.DEFERRED
                    scheduleWindowStatus = SchedulingWindowStatus.DEFERRED
                    scheduleBlockReason = ExecutionWindowBlockReason.COOLDOWN_ACTIVE
                    scheduleNextEligibleAtMs = scheduleNextEligibleAtMs
                        ?: scheduledRemediationPlan?.cooldownState?.nextEligibleAtMs
                        ?: estateAutomationEligibility?.cooldownState?.nextEligibleAtMs
                    scheduleReasonCodes += RoleReasonCodes.ROLE_SCHEDULE_COOLDOWN_ACTIVE
                }

                waitingMaintenance -> {
                    scheduleDecision = ExecutionWindowDecision.DEFERRED
                    scheduleWindowStatus = SchedulingWindowStatus.DEFERRED
                    scheduleBlockReason = ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW
                    scheduleReasonCodes += RoleReasonCodes.ROLE_SCHEDULE_WAITING_FOR_MAINTENANCE_WINDOW
                }

                scheduleExpired -> {
                    scheduleDecision = ExecutionWindowDecision.EXPIRED
                    scheduleWindowStatus = SchedulingWindowStatus.EXPIRED
                    scheduleBlockReason = ExecutionWindowBlockReason.SCHEDULE_EXPIRED
                    scheduleNextEligibleAtMs = null
                    scheduleReasonCodes += RoleReasonCodes.ROLE_SCHEDULE_EXPIRED
                }

                approvalPending -> {
                    scheduleDecision = ExecutionWindowDecision.BLOCKED
                    scheduleWindowStatus = SchedulingWindowStatus.BLOCKED
                    scheduleBlockReason = ExecutionWindowBlockReason.APPROVAL_PENDING
                }

                else -> {
                    scheduleDecision = ExecutionWindowDecision.ELIGIBLE
                    scheduleWindowStatus = SchedulingWindowStatus.ELIGIBLE
                    scheduleBlockReason = ExecutionWindowBlockReason.NONE
                    scheduleReasonCodes += RoleReasonCodes.ROLE_SCHEDULE_WINDOW_ACTIVE
                    if (
                        state.stage != PolicyRolloutStage.NOT_STARTED &&
                        state.stage != PolicyRolloutStage.SIMULATION_ONLY
                    ) {
                        scheduleReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_STAGE_ADVANCED_IN_WINDOW
                    }
                }
            }

            if (
                scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                scheduleDecision == ExecutionWindowDecision.BLOCKED ||
                scheduleDecision == ExecutionWindowDecision.PAUSED ||
                scheduleDecision == ExecutionWindowDecision.EXPIRED
            ) {
                scheduleReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_STAGE_DEFERRED_BY_CALENDAR
            }
            scheduleSummary = buildString {
                when (scheduleDecision) {
                    ExecutionWindowDecision.ELIGIBLE ->
                        append("Schedule window is active and rollout can progress.")
                    ExecutionWindowDecision.DEFERRED ->
                        append("Rollout is deferred by schedule policy.")
                    ExecutionWindowDecision.BLOCKED ->
                        append("Rollout is blocked by schedule policy.")
                    ExecutionWindowDecision.PAUSED ->
                        append("Rollout is paused by schedule governance.")
                    ExecutionWindowDecision.EXPIRED ->
                        append("Rollout schedule expired before execution.")
                }
                when (scheduleBlockReason) {
                    ExecutionWindowBlockReason.BLACKOUT_WINDOW ->
                        append(" Blackout window is active.")
                    ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW ->
                        append(" Waiting for maintenance window.")
                    ExecutionWindowBlockReason.COOLDOWN_ACTIVE ->
                        append(" Cooldown is active.")
                    ExecutionWindowBlockReason.APPROVAL_PENDING ->
                        append(" Approval is still pending.")
                    ExecutionWindowBlockReason.PAUSED_BY_OPERATOR ->
                        append(" Paused by operator/governance freeze.")
                    ExecutionWindowBlockReason.SCHEDULE_EXPIRED ->
                        append(" Scheduled execution window expired.")
                    ExecutionWindowBlockReason.SCHEDULE_SUPPRESSED ->
                        append(" Schedule is suppressed by governance policy.")
                    ExecutionWindowBlockReason.NONE -> Unit
                }
                scheduleNextEligibleAtMs?.let {
                    if (it > 0L) {
                        append(" Next eligible at ")
                        append(it)
                        append(".")
                    }
                }
            }.trim()
        }

        policySchedulingWindow = PolicySchedulingWindow(
            windowId = policySchedulingWindow?.windowId?.takeIf { it.isNotBlank() }
                ?: scheduledRemediationPlan?.scheduleId
                    ?.takeIf { it.isNotBlank() }
                    ?.let { "schedule_window_$it" }
                ?: "schedule_window_${workflowTemplateId}_$now",
            windowType = derivedWindowType,
            status = scheduleWindowStatus,
            timezone = scheduleWindowInput?.timezone
                ?.takeIf { it.isNotBlank() }
                ?: policySchedulingWindow?.timezone
                ?: "UTC",
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            summary = scheduleSummary,
            reasonCodes = scheduleReasonCodes.distinct(),
            updatedAtMs = now
        )
        calendarEvaluation = CalendarEvaluationResult(
            decision = scheduleDecision,
            windowStatus = scheduleWindowStatus,
            blockReason = scheduleBlockReason,
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            summary = scheduleSummary,
            reasonCodes = scheduleReasonCodes.distinct(),
            evaluatedAtMs = now
        )
        val calendarEntryStatus = when (scheduleDecision) {
            ExecutionWindowDecision.ELIGIBLE -> RolloutCalendarEntryStatus.ACTIVE
            ExecutionWindowDecision.DEFERRED -> RolloutCalendarEntryStatus.DEFERRED
            ExecutionWindowDecision.BLOCKED -> RolloutCalendarEntryStatus.BLOCKED
            ExecutionWindowDecision.PAUSED -> RolloutCalendarEntryStatus.PAUSED
            ExecutionWindowDecision.EXPIRED -> RolloutCalendarEntryStatus.EXPIRED
        }
        val currentWaveId = governanceProgram?.currentWaveId
            ?.takeIf { it.isNotBlank() }
            ?: rolloutCalendar?.currentWaveId
        val previousEntries = rolloutCalendar?.entries.orEmpty()
        val existingEntry = previousEntries.firstOrNull { entry ->
            entry.stage == state.stage && entry.waveId == currentWaveId
        }
        val updatedEntry = RolloutCalendarEntry(
            entryId = existingEntry?.entryId?.takeIf { it.isNotBlank() }
                ?: "rollout_entry_${workflowTemplateId}_${state.stage.name.lowercase()}_$now",
            waveId = currentWaveId,
            stage = state.stage,
            windowType = SchedulingWindowType.ROLLOUT_STAGE_WINDOW,
            status = calendarEntryStatus,
            summary = when (calendarEntryStatus) {
                RolloutCalendarEntryStatus.ACTIVE -> "Rollout stage is active in the current schedule window."
                RolloutCalendarEntryStatus.DEFERRED -> "Rollout stage is deferred by calendar constraints."
                RolloutCalendarEntryStatus.BLOCKED -> "Rollout stage is blocked by schedule policy."
                RolloutCalendarEntryStatus.PAUSED -> "Rollout stage is paused by schedule governance."
                RolloutCalendarEntryStatus.EXPIRED -> "Rollout stage schedule expired before execution."
                RolloutCalendarEntryStatus.SCHEDULED ->
                    "Rollout stage is scheduled."
                RolloutCalendarEntryStatus.COMPLETED ->
                    "Rollout stage completed."
            },
            reasonCodes = scheduleReasonCodes.distinct(),
            updatedAtMs = now
        )
        val mergedEntries = (
            previousEntries.filterNot { entry ->
                entry.entryId == updatedEntry.entryId ||
                    (entry.waveId == updatedEntry.waveId && entry.stage == updatedEntry.stage)
            } + updatedEntry
            )
            .sortedByDescending { it.updatedAtMs }
            .take(30)
            .reversed()
        rolloutCalendar = RolloutCalendar(
            calendarId = rolloutCalendar?.calendarId?.takeIf { it.isNotBlank() }
                ?: "rollout_calendar_${workflowTemplateId}",
            currentWaveId = currentWaveId,
            currentStage = state.stage,
            entries = mergedEntries,
            summary = buildString {
                append("Rollout calendar ")
                append(calendarEntryStatus.name.lowercase().replace('_', ' '))
                append(" for stage ")
                append(state.stage.name.lowercase().replace('_', ' '))
                if (currentWaveId != null) {
                    append(" (wave ")
                    append(currentWaveId)
                    append(")")
                }
                append('.')
            },
            updatedAtMs = now
        )
        rolloutCalendarSummary = rolloutCalendar?.summary.orEmpty()
        val indexedProgramWaves = governanceProgram
            ?.waves
            .orEmpty()
            .mapIndexed { index, wave -> wave to (wave.waveIndex.takeIf { it > 0 } ?: (index + 1)) }
            .sortedBy { it.second }
        val currentWaveTuple = indexedProgramWaves.firstOrNull { (wave, _) ->
            wave.waveId == currentWaveId
        } ?: indexedProgramWaves.firstOrNull()
        val currentWave = currentWaveTuple?.first
        val currentWaveIndex = currentWaveTuple?.second ?: 1
        val previousWaveIncomplete = indexedProgramWaves.any { (wave, index) ->
            index < currentWaveIndex &&
                wave.status != PolicyGovernanceWaveStatus.COMPLETED
        }
        val explicitWaveTargetCount = currentWave?.let { wave ->
            (wave.targetTenantIds + wave.targetWorkspaceIds)
                .map { it.trim() }
                .filter { it.isNotBlank() }
                .distinct()
                .size
        } ?: 0
        val totalWaveTargets = when {
            explicitWaveTargetCount > 0 -> explicitWaveTargetCount
            (crossTenantRollout.totalTargets) > 0 -> crossTenantRollout.totalTargets
            else -> 1
        }
        val completedWaveTargets = crossTenantRollout.adoptedTargets
            .coerceAtLeast(0)
            .coerceAtMost(totalWaveTargets)
        val pendingWaveTargets = (totalWaveTargets - completedWaveTargets).coerceAtLeast(0)
        val partialWaveCompletion = completedWaveTargets > 0 && pendingWaveTargets > 0
        val carryForwardPending = pendingWaveTargets > 0 && (
            scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                scheduleDecision == ExecutionWindowDecision.BLOCKED ||
                scheduleDecision == ExecutionWindowDecision.PAUSED ||
                scheduleDecision == ExecutionWindowDecision.EXPIRED
            )
        val waveCompletionState = when {
            pendingWaveTargets == 0 && completedWaveTargets > 0 -> RolloutWaveCompletionState.COMPLETED
            carryForwardPending -> RolloutWaveCompletionState.CARRIED_FORWARD
            partialWaveCompletion -> RolloutWaveCompletionState.PARTIAL_COMPLETION
            scheduleDecision == ExecutionWindowDecision.DEFERRED -> RolloutWaveCompletionState.DEFERRED
            scheduleDecision == ExecutionWindowDecision.PAUSED -> RolloutWaveCompletionState.PAUSED
            scheduleDecision == ExecutionWindowDecision.EXPIRED -> RolloutWaveCompletionState.EXPIRED
            completedWaveTargets > 0 -> RolloutWaveCompletionState.IN_PROGRESS
            else -> RolloutWaveCompletionState.NOT_STARTED
        }
        val promotionWindowEligibility = when (scheduleDecision) {
            ExecutionWindowDecision.ELIGIBLE -> PromotionWindowEligibility.ELIGIBLE
            ExecutionWindowDecision.DEFERRED -> PromotionWindowEligibility.DEFERRED
            ExecutionWindowDecision.BLOCKED -> PromotionWindowEligibility.BLOCKED
            ExecutionWindowDecision.PAUSED -> PromotionWindowEligibility.PAUSED
            ExecutionWindowDecision.EXPIRED -> PromotionWindowEligibility.EXPIRED
        }
        val crossWindowHoldReason = when {
            previousWaveIncomplete -> CrossWindowHoldReason.WAVE_ORDERING
            scheduleBlockReason == ExecutionWindowBlockReason.BLACKOUT_WINDOW -> CrossWindowHoldReason.BLACKOUT_WINDOW
            scheduleBlockReason == ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW -> CrossWindowHoldReason.MAINTENANCE_WINDOW
            scheduleBlockReason == ExecutionWindowBlockReason.APPROVAL_PENDING ||
                state.approvalState == PolicyRolloutApprovalState.PENDING -> CrossWindowHoldReason.APPROVAL_PENDING
            scheduleDecision == ExecutionWindowDecision.PAUSED -> CrossWindowHoldReason.GOVERNANCE_PAUSE
            scheduleDecision == ExecutionWindowDecision.EXPIRED -> CrossWindowHoldReason.WINDOW_EXPIRED
            scheduleDecision == ExecutionWindowDecision.BLOCKED -> CrossWindowHoldReason.WINDOW_BLOCKED
            else -> CrossWindowHoldReason.NONE
        }
        val waveDecisionType = when {
            previousWaveIncomplete -> RolloutWaveDecisionType.MARK_WINDOW_BLOCKED
            carryForwardPending && partialWaveCompletion -> RolloutWaveDecisionType.CARRY_FORWARD_PARTIAL_WAVE
            scheduleDecision == ExecutionWindowDecision.DEFERRED -> RolloutWaveDecisionType.DEFER_TO_NEXT_WINDOW
            scheduleDecision == ExecutionWindowDecision.EXPIRED -> RolloutWaveDecisionType.EXPIRE_PENDING_WINDOW_SLOT
            scheduleDecision == ExecutionWindowDecision.PAUSED -> RolloutWaveDecisionType.PAUSE_CROSS_WINDOW_ROLLOUT
            command?.commandType == GovernanceActionType.RESUME_POLICY_ROLLOUT -> RolloutWaveDecisionType.RESUME_NEXT_ELIGIBLE_WINDOW
            scheduleDecision == ExecutionWindowDecision.BLOCKED -> RolloutWaveDecisionType.MARK_WINDOW_BLOCKED
            else -> RolloutWaveDecisionType.PROMOTE_IN_CURRENT_WINDOW
        }
        val waveStatus = when {
            previousWaveIncomplete -> RolloutWaveStatus.BLOCKED
            scheduleDecision == ExecutionWindowDecision.PAUSED -> RolloutWaveStatus.PAUSED
            scheduleDecision == ExecutionWindowDecision.EXPIRED -> RolloutWaveStatus.EXPIRED
            carryForwardPending -> RolloutWaveStatus.CARRIED_FORWARD
            partialWaveCompletion -> RolloutWaveStatus.PARTIAL
            pendingWaveTargets == 0 && completedWaveTargets > 0 -> RolloutWaveStatus.COMPLETED
            scheduleDecision == ExecutionWindowDecision.DEFERRED -> RolloutWaveStatus.DEFERRED
            scheduleDecision == ExecutionWindowDecision.BLOCKED -> RolloutWaveStatus.BLOCKED
            scheduleDecision == ExecutionWindowDecision.ELIGIBLE -> RolloutWaveStatus.ACTIVE
            else -> RolloutWaveStatus.PLANNED
        }
        val waveReasonCodes = mutableListOf<String>()
        if (currentWaveId != null) {
            waveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_ASSIGNED
        }
        if (previousWaveIncomplete || scheduleDecision == ExecutionWindowDecision.BLOCKED) {
            waveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_BLOCKED
        }
        if (partialWaveCompletion) {
            waveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_PARTIAL_COMPLETION
        }
        if (carryForwardPending) {
            waveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_CARRIED_FORWARD
        }
        when (scheduleDecision) {
            ExecutionWindowDecision.BLOCKED -> waveReasonCodes += RoleReasonCodes.ROLE_PROMOTION_WINDOW_BLOCKED
            ExecutionWindowDecision.DEFERRED -> waveReasonCodes += RoleReasonCodes.ROLE_PROMOTION_WINDOW_DEFERRED
            ExecutionWindowDecision.EXPIRED -> waveReasonCodes += RoleReasonCodes.ROLE_PROMOTION_WINDOW_EXPIRED
            else -> Unit
        }
        if (scheduleNextEligibleAtMs != null && scheduleNextEligibleAtMs > 0L) {
            waveReasonCodes += RoleReasonCodes.ROLE_PROMOTION_NEXT_WINDOW_SELECTED
        }
        if (scheduleDecision == ExecutionWindowDecision.PAUSED || crossWindowHoldReason == CrossWindowHoldReason.GOVERNANCE_PAUSE) {
            waveReasonCodes += RoleReasonCodes.ROLE_CROSS_WINDOW_PAUSED
        }
        if (command?.commandType == GovernanceActionType.RESUME_POLICY_ROLLOUT) {
            waveReasonCodes += RoleReasonCodes.ROLE_CROSS_WINDOW_RESUMED
        }
        if (crossWindowHoldReason == CrossWindowHoldReason.APPROVAL_PENDING) {
            waveReasonCodes += RoleReasonCodes.ROLE_CROSS_WINDOW_WAITING_APPROVAL
        }
        if (crossWindowHoldReason == CrossWindowHoldReason.MAINTENANCE_WINDOW) {
            waveReasonCodes += RoleReasonCodes.ROLE_CROSS_WINDOW_MAINTENANCE_BLOCK
        }
        if (crossWindowHoldReason == CrossWindowHoldReason.BLACKOUT_WINDOW) {
            waveReasonCodes += RoleReasonCodes.ROLE_CROSS_WINDOW_BLACKOUT_BLOCK
        }
        val rolloutWaveProgress = RolloutWaveProgress(
            totalTargets = totalWaveTargets,
            completedTargets = completedWaveTargets,
            pendingTargets = pendingWaveTargets,
            deferredTargets = if (scheduleDecision == ExecutionWindowDecision.DEFERRED) pendingWaveTargets else 0,
            carriedForwardTargets = if (carryForwardPending) pendingWaveTargets else 0,
            expiredTargets = if (scheduleDecision == ExecutionWindowDecision.EXPIRED) pendingWaveTargets else 0,
            summary = "Completed $completedWaveTargets/$totalWaveTargets targets; pending $pendingWaveTargets."
        )
        val nextEligibleWindow = NextEligibleWindowSummary(
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            windowId = policySchedulingWindow?.windowId?.takeIf { it.isNotBlank() },
            reasonCodes = waveReasonCodes.distinct(),
            summary = when {
                scheduleNextEligibleAtMs != null && scheduleNextEligibleAtMs > 0L ->
                    "Next eligible window starts at $scheduleNextEligibleAtMs."
                scheduleDecision == ExecutionWindowDecision.EXPIRED ->
                    "Current window expired; operator must schedule next eligible window."
                else ->
                    "No future eligible window is currently tracked."
            }
        )
        val waveWindowAssignment = WaveWindowAssignment(
            windowId = policySchedulingWindow?.windowId.orEmpty(),
            windowType = policySchedulingWindow?.windowType ?: SchedulingWindowType.ROLLOUT_STAGE_WINDOW,
            windowStatus = scheduleWindowStatus,
            eligibility = promotionWindowEligibility,
            startAtMs = policySchedulingWindow?.startAtMs,
            endAtMs = policySchedulingWindow?.endAtMs,
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            summary = scheduleSummary
        )
        val carryForwardState = RolloutWaveCarryForwardState(
            carryForwardEnabled = pendingWaveTargets > 0,
            carryForwardPending = carryForwardPending,
            pendingTargets = pendingWaveTargets,
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            reasonCodes = waveReasonCodes.distinct(),
            summary = when {
                carryForwardPending -> "Pending rollout targets are carried forward to the next eligible window."
                pendingWaveTargets > 0 -> "Pending rollout targets remain in this wave."
                else -> "No carry-forward is required for this wave."
            }
        )
        val resolvedWaveId = currentWaveId ?: "wave_${workflowTemplateId}_${currentWaveIndex}"
        val resolvedWaveName = currentWave?.name?.takeIf { it.isNotBlank() } ?: "Wave $currentWaveIndex"
        val rolloutWave = RolloutWave(
            waveId = resolvedWaveId,
            waveIndex = currentWaveIndex,
            name = resolvedWaveName,
            status = waveStatus,
            completionState = waveCompletionState,
            progress = rolloutWaveProgress,
            windowAssignment = waveWindowAssignment,
            carryForwardState = carryForwardState,
            nextEligibleWindow = nextEligibleWindow,
            decision = waveDecisionType,
            blockReason = crossWindowHoldReason,
            reasonCodes = (scheduleReasonCodes + waveReasonCodes).distinct(),
            summary = buildString {
                append(resolvedWaveName)
                append(" is ")
                append(waveStatus.name.lowercase().replace('_', ' '))
                append(" (")
                append(completedWaveTargets)
                append("/")
                append(totalWaveTargets)
                append(" complete")
                if (carryForwardPending) {
                    append(", carry-forward pending")
                }
                append(").")
            },
            updatedAtMs = now
        )
        val mergedRolloutWaves = (
            state.rolloutWaves.filterNot { it.waveId == rolloutWave.waveId } + rolloutWave
            )
            .sortedBy { it.waveIndex }
            .takeLast(30)
        val calendarAwarePromotionDecision = CalendarAwarePromotionDecision(
            promotionId = "promotion_window_${resolvedWaveId}_$now",
            waveId = resolvedWaveId,
            windowEligibility = promotionWindowEligibility,
            decisionType = waveDecisionType,
            blockReason = crossWindowHoldReason,
            deferReasonCodes = waveReasonCodes.filter {
                it == RoleReasonCodes.ROLE_PROMOTION_WINDOW_DEFERRED ||
                    it == RoleReasonCodes.ROLE_PROMOTION_WINDOW_BLOCKED ||
                    it == RoleReasonCodes.ROLE_PROMOTION_WINDOW_EXPIRED
            },
            carryForwardReasonCodes = waveReasonCodes.filter {
                it == RoleReasonCodes.ROLE_ROLLOUT_WAVE_CARRIED_FORWARD ||
                    it == RoleReasonCodes.ROLE_ROLLOUT_WAVE_PARTIAL_COMPLETION
            },
            nextEligibleWindow = nextEligibleWindow.takeIf {
                it.nextEligibleAtMs != null || it.summary.isNotBlank()
            },
            approvalDependencySummary = if (state.approvalState == PolicyRolloutApprovalState.PENDING) {
                "Approval remains pending before this wave can advance."
            } else {
                "No approval blocker is active for current wave/window progression."
            },
            summary = buildString {
                append("Wave ")
                append(resolvedWaveName)
                append(" decision: ")
                append(waveDecisionType.name.lowercase().replace('_', ' '))
                append(" (")
                append(promotionWindowEligibility.name.lowercase().replace('_', ' '))
                append(").")
                if (crossWindowHoldReason != CrossWindowHoldReason.NONE) {
                    append(" Hold reason: ")
                    append(crossWindowHoldReason.name.lowercase().replace('_', ' '))
                    append('.')
                }
            },
            createdAtMs = now
        )
        val crossWindowPauseState = when {
            scheduleDecision == ExecutionWindowDecision.PAUSED -> CrossWindowPauseState.PAUSED
            command?.commandType == GovernanceActionType.RESUME_POLICY_ROLLOUT -> CrossWindowPauseState.RESUMED
            crossWindowHoldReason != CrossWindowHoldReason.NONE && crossWindowHoldReason != CrossWindowHoldReason.WINDOW_BLOCKED ->
                CrossWindowPauseState.HELD
            else -> CrossWindowPauseState.NOT_PAUSED
        }
        val crossWindowGovernanceControl = CrossWindowGovernanceControl(
            controlId = state.crossWindowGovernanceControl?.controlId?.takeIf { it.isNotBlank() }
                ?: "cross_window_control_${workflowTemplateId}",
            programId = governanceProgram?.programId,
            scope = state.target.scope,
            pauseState = crossWindowPauseState,
            holdReason = crossWindowHoldReason,
            effectiveWindowStartAtMs = policySchedulingWindow?.startAtMs,
            effectiveWindowEndAtMs = policySchedulingWindow?.endAtMs,
            resumeConditionSummary = when {
                crossWindowPauseState == CrossWindowPauseState.PAUSED ->
                    "Resume when governance pause is lifted and window eligibility is restored."
                crossWindowPauseState == CrossWindowPauseState.HELD ->
                    "Resolve hold reason before cross-window rollout can resume."
                else ->
                    "Cross-window rollout is not paused."
            },
            summary = buildString {
                append("Cross-window control ")
                append(crossWindowPauseState.name.lowercase().replace('_', ' '))
                append('.')
                if (crossWindowHoldReason != CrossWindowHoldReason.NONE) {
                    append(" Hold reason: ")
                    append(crossWindowHoldReason.name.lowercase().replace('_', ' '))
                    append('.')
                }
            },
            reasonCodes = waveReasonCodes.distinct(),
            updatedAtMs = now
        )
        val rolloutWaveSummary = rolloutWave.summary
        val crossWindowGovernanceSummary = crossWindowGovernanceControl.summary
        val nextEligibleWindowSummary = nextEligibleWindow.summary
        reasonCodes += scheduleReasonCodes
        reasonCodes += waveReasonCodes
        val repeatedWaveBlockerReasonCodes = mergedRolloutWaves
            .flatMap { wave -> wave.reasonCodes }
            .groupingBy { code -> code }
            .eachCount()
            .filterValues { count -> count > 1 }
            .keys
            .toList()
            .sorted()
            .take(8)
        val blockedWaveCount = mergedRolloutWaves.count { wave -> wave.status == RolloutWaveStatus.BLOCKED }
        val deferredWaveCount = mergedRolloutWaves.count { wave ->
            wave.status == RolloutWaveStatus.DEFERRED ||
                wave.decision == RolloutWaveDecisionType.DEFER_TO_NEXT_WINDOW
        }
        val carriedForwardWaveCount = mergedRolloutWaves.count { wave ->
            wave.status == RolloutWaveStatus.CARRIED_FORWARD ||
                wave.carryForwardState?.carryForwardPending == true
        }
        val completedWaveCount = mergedRolloutWaves.count { wave -> wave.status == RolloutWaveStatus.COMPLETED }
        val carryForwardPressure = carriedForwardWaveCount > 1 || (carryForwardPending && pendingWaveTargets > 0)
        val crossWaveHealthBucket = when {
            blockedWaveCount > 0 -> WaveHealthBucket.BLOCKED
            deferredWaveCount > 1 || carryForwardPressure || repeatedWaveBlockerReasonCodes.isNotEmpty() -> WaveHealthBucket.DEGRADED
            deferredWaveCount > 0 || carriedForwardWaveCount > 0 -> WaveHealthBucket.CAUTION
            else -> WaveHealthBucket.STABLE
        }
        val crossWaveReasonCodes = mutableListOf<String>()
        when (crossWaveHealthBucket) {
            WaveHealthBucket.BLOCKED,
            WaveHealthBucket.DEGRADED -> crossWaveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_HEALTH_DEGRADED
            WaveHealthBucket.STABLE -> crossWaveReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_WAVE_HEALTH_STABLE
            WaveHealthBucket.CAUTION -> Unit
        }
        if (repeatedWaveBlockerReasonCodes.isNotEmpty()) {
            crossWaveReasonCodes += RoleReasonCodes.ROLE_CROSS_WAVE_BLOCKER_REPEAT
        }
        if (carryForwardPressure) {
            crossWaveReasonCodes += RoleReasonCodes.ROLE_CROSS_WAVE_CARRY_FORWARD_PRESSURE
        }
        val crossWaveAnalyticsSummary = CrossWaveAnalyticsSummary(
            healthBucket = crossWaveHealthBucket,
            totalWaves = mergedRolloutWaves.size,
            completedWaves = completedWaveCount,
            blockedWaves = blockedWaveCount,
            deferredWaves = deferredWaveCount,
            carriedForwardWaves = carriedForwardWaveCount,
            repeatedBlockerReasonCodes = repeatedWaveBlockerReasonCodes,
            carryForwardPressure = carryForwardPressure,
            summary = buildString {
                append("Cross-wave health ")
                append(crossWaveHealthBucket.name.lowercase().replace('_', ' '))
                append(": completed ")
                append(completedWaveCount)
                append('/')
                append(mergedRolloutWaves.size)
                append(", blocked ")
                append(blockedWaveCount)
                append(", deferred ")
                append(deferredWaveCount)
                append(", carried-forward ")
                append(carriedForwardWaveCount)
                if (carryForwardPressure) {
                    append(" (carry-forward pressure active)")
                }
                append('.')
            },
            updatedAtMs = now
        )
        val windowDelayReason = when {
            scheduleDecision == ExecutionWindowDecision.ELIGIBLE -> WindowDelayReason.NONE
            scheduleDecision == ExecutionWindowDecision.EXPIRED -> WindowDelayReason.WINDOW_EXPIRED
            scheduleDecision == ExecutionWindowDecision.PAUSED ||
                crossWindowHoldReason == CrossWindowHoldReason.GOVERNANCE_PAUSE -> WindowDelayReason.GOVERNANCE_PAUSE
            scheduleBlockReason == ExecutionWindowBlockReason.BLACKOUT_WINDOW ||
                crossWindowHoldReason == CrossWindowHoldReason.BLACKOUT_WINDOW -> WindowDelayReason.BLACKOUT_WINDOW
            scheduleBlockReason == ExecutionWindowBlockReason.WAITING_MAINTENANCE_WINDOW ||
                crossWindowHoldReason == CrossWindowHoldReason.MAINTENANCE_WINDOW -> WindowDelayReason.MAINTENANCE_WINDOW
            scheduleBlockReason == ExecutionWindowBlockReason.APPROVAL_PENDING ||
                crossWindowHoldReason == CrossWindowHoldReason.APPROVAL_PENDING ||
                state.approvalState == PolicyRolloutApprovalState.PENDING -> WindowDelayReason.APPROVAL_PENDING
            scheduleDecision == ExecutionWindowDecision.BLOCKED ||
                scheduleDecision == ExecutionWindowDecision.DEFERRED -> WindowDelayReason.UNKNOWN
            else -> WindowDelayReason.UNKNOWN
        }
        val windowImpactReasonCodes = mutableListOf<String>()
        if (windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW) {
            windowImpactReasonCodes += RoleReasonCodes.ROLE_WINDOW_BLOCK_BLACKOUT
        }
        if (windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW) {
            windowImpactReasonCodes += RoleReasonCodes.ROLE_WINDOW_BLOCK_MAINTENANCE
        }
        if (scheduleNextEligibleAtMs != null && scheduleNextEligibleAtMs > 0L) {
            windowImpactReasonCodes += RoleReasonCodes.ROLE_WINDOW_NEXT_ELIGIBLE_COMPUTED
        }
        val windowImpactSummary = WindowImpactSummary(
            decision = scheduleDecision,
            windowStatus = scheduleWindowStatus,
            eligibility = promotionWindowEligibility,
            delayReason = windowDelayReason,
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            blockedTargets = if (
                scheduleDecision == ExecutionWindowDecision.BLOCKED ||
                    scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                    scheduleDecision == ExecutionWindowDecision.EXPIRED
            ) {
                pendingWaveTargets
            } else {
                0
            },
            reasonCodes = (windowImpactReasonCodes + scheduleReasonCodes).distinct(),
            summary = buildString {
                append("Window impact ")
                append(scheduleDecision.name.lowercase().replace('_', ' '))
                append(" (")
                append(promotionWindowEligibility.name.lowercase().replace('_', ' '))
                append(')')
                if (windowDelayReason != WindowDelayReason.NONE) {
                    append(", reason ")
                    append(windowDelayReason.name.lowercase().replace('_', ' '))
                }
                if (scheduleNextEligibleAtMs != null && scheduleNextEligibleAtMs > 0L) {
                    append(", next eligible ")
                    append(scheduleNextEligibleAtMs)
                }
                append('.')
            },
            updatedAtMs = now
        )
        val readinessBlockers = mutableListOf<RolloutPromotionBlocker>()
        if (state.approvalState == PolicyRolloutApprovalState.PENDING) {
            readinessBlockers += RolloutPromotionBlocker(
                blockerId = "promotion_blocker_approval_pending_$now",
                severity = PolicyEstateDriftSeverity.HIGH,
                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_APPROVAL_PENDING),
                summary = "Promotion is waiting for approval before advancing to stronger enforcement."
            )
        } else if (state.approvalState == PolicyRolloutApprovalState.DENIED) {
            readinessBlockers += RolloutPromotionBlocker(
                blockerId = "promotion_blocker_approval_denied_$now",
                severity = PolicyEstateDriftSeverity.CRITICAL,
                reasonCodes = listOf(RoleReasonCodes.ROLE_POLICY_APPROVAL_DENIED),
                summary = "Promotion is blocked because approval was denied."
            )
        }
        if (previousWaveIncomplete) {
            readinessBlockers += RolloutPromotionBlocker(
                blockerId = "promotion_blocker_wave_order_$now",
                severity = PolicyEstateDriftSeverity.HIGH,
                reasonCodes = listOf(RoleReasonCodes.ROLE_ROLLOUT_WAVE_BLOCKED),
                summary = "Earlier rollout waves are incomplete and block current-wave promotion."
            )
        }
        if (windowDelayReason != WindowDelayReason.NONE) {
            readinessBlockers += RolloutPromotionBlocker(
                blockerId = "promotion_blocker_window_${windowDelayReason.name.lowercase()}_$now",
                severity = if (
                    windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
                        windowDelayReason == WindowDelayReason.WINDOW_EXPIRED
                ) {
                    PolicyEstateDriftSeverity.HIGH
                } else {
                    PolicyEstateDriftSeverity.MEDIUM
                },
                reasonCodes = windowImpactReasonCodes.distinct(),
                summary = "Window impact delays promotion (${windowDelayReason.name.lowercase().replace('_', ' ')})."
            )
        }
        if (crossWaveHealthBucket == WaveHealthBucket.BLOCKED || crossWaveHealthBucket == WaveHealthBucket.DEGRADED) {
            readinessBlockers += RolloutPromotionBlocker(
                blockerId = "promotion_blocker_cross_wave_${crossWaveHealthBucket.name.lowercase()}_$now",
                severity = if (crossWaveHealthBucket == WaveHealthBucket.BLOCKED) {
                    PolicyEstateDriftSeverity.HIGH
                } else {
                    PolicyEstateDriftSeverity.MEDIUM
                },
                reasonCodes = crossWaveReasonCodes.distinct(),
                summary = "Cross-wave health is ${crossWaveHealthBucket.name.lowercase().replace('_', ' ')}."
            )
        }
        val readinessStatus = when {
            promotionWindowEligibility == PromotionWindowEligibility.EXPIRED ||
                scheduleDecision == ExecutionWindowDecision.EXPIRED -> RolloutPromotionReadinessStatus.EXPIRED
            scheduleDecision == ExecutionWindowDecision.PAUSED ||
                crossWindowPauseState == CrossWindowPauseState.PAUSED -> RolloutPromotionReadinessStatus.PAUSED
            state.approvalState == PolicyRolloutApprovalState.DENIED ||
                promotionWindowEligibility == PromotionWindowEligibility.BLOCKED ||
                crossWaveHealthBucket == WaveHealthBucket.BLOCKED -> RolloutPromotionReadinessStatus.BLOCKED
            promotionWindowEligibility == PromotionWindowEligibility.DEFERRED ||
                windowDelayReason != WindowDelayReason.NONE -> RolloutPromotionReadinessStatus.DEFERRED
            crossWaveHealthBucket == WaveHealthBucket.CAUTION ||
                crossWaveHealthBucket == WaveHealthBucket.DEGRADED ||
                carryForwardPressure -> RolloutPromotionReadinessStatus.READY_WITH_CAUTION
            else -> RolloutPromotionReadinessStatus.READY
        }
        val readinessReasonCodes = mutableListOf<String>()
        when (readinessStatus) {
            RolloutPromotionReadinessStatus.READY ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_READY
            RolloutPromotionReadinessStatus.READY_WITH_CAUTION ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_READY_WITH_CAUTION
            RolloutPromotionReadinessStatus.BLOCKED ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_BLOCKED
            RolloutPromotionReadinessStatus.DEFERRED ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_DEFERRED_TO_WINDOW
            RolloutPromotionReadinessStatus.EXPIRED ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_EXPIRED
            RolloutPromotionReadinessStatus.PAUSED ->
                readinessReasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_DEFERRED_TO_WINDOW
        }
        val promotionCandidate = RolloutPromotionCandidate(
            candidateId = "promotion_candidate_${workflowTemplateId}_${resolvedWaveId}_$now",
            waveId = resolvedWaveId,
            waveIndex = currentWaveIndex,
            targetScope = state.target.scope,
            windowEligibility = promotionWindowEligibility,
            nextEligibleAtMs = scheduleNextEligibleAtMs,
            reasonCodes = (readinessReasonCodes + crossWaveReasonCodes + windowImpactReasonCodes + waveReasonCodes)
                .distinct(),
            summary = buildString {
                append("Promotion candidate for ")
                append(resolvedWaveName)
                append(" is ")
                append(readinessStatus.name.lowercase().replace('_', ' '))
                append(" with window ")
                append(promotionWindowEligibility.name.lowercase().replace('_', ' '))
                append('.')
            },
            updatedAtMs = now
        )
        val recommendedOperation = when (readinessStatus) {
            RolloutPromotionReadinessStatus.READY -> RolloutPromotionOperationType.PROMOTE
            RolloutPromotionReadinessStatus.READY_WITH_CAUTION -> RolloutPromotionOperationType.HOLD
            RolloutPromotionReadinessStatus.BLOCKED -> RolloutPromotionOperationType.HOLD
            RolloutPromotionReadinessStatus.DEFERRED -> RolloutPromotionOperationType.DEFER
            RolloutPromotionReadinessStatus.EXPIRED -> RolloutPromotionOperationType.EXPIRE
            RolloutPromotionReadinessStatus.PAUSED -> RolloutPromotionOperationType.PAUSE
        }
        val rolloutPromotionReadiness = RolloutPromotionReadinessSummary(
            status = readinessStatus,
            candidate = promotionCandidate,
            blockers = readinessBlockers.distinctBy { blocker -> blocker.blockerId },
            recommendation = recommendedOperation,
            reasonCodes = (
                readinessReasonCodes +
                    readinessBlockers.flatMap { blocker -> blocker.reasonCodes } +
                    crossWaveReasonCodes +
                    windowImpactReasonCodes
                ).distinct(),
            summary = buildString {
                append("Promotion readiness ")
                append(readinessStatus.name.lowercase().replace('_', ' '))
                append(" with ")
                append(readinessBlockers.size)
                append(" blocker(s). Recommendation: ")
                append(recommendedOperation.name.lowercase().replace('_', ' '))
                append('.')
            },
            updatedAtMs = now
        )
        fun operationReasonCode(type: RolloutPromotionOperationType): String {
            return when (type) {
                RolloutPromotionOperationType.PROMOTE -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_PROMOTE
                RolloutPromotionOperationType.HOLD -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_HOLD
                RolloutPromotionOperationType.DEFER -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_DEFER
                RolloutPromotionOperationType.PAUSE -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_PAUSE
                RolloutPromotionOperationType.RESUME -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_RESUME
                RolloutPromotionOperationType.EXPIRE -> RoleReasonCodes.ROLE_ROLLOUT_PROMOTION_OPERATION_EXPIRE
            }
        }
        val operationTypeFromCommand = when (command?.commandType) {
            GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
            GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
            GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
            GovernanceActionType.APPROVE_POLICY_PROMOTION -> RolloutPromotionOperationType.PROMOTE

            GovernanceActionType.REQUEST_POLICY_PROMOTION -> RolloutPromotionOperationType.PROMOTE
            GovernanceActionType.REJECT_POLICY_PROMOTION,
            GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL -> RolloutPromotionOperationType.HOLD
            GovernanceActionType.PAUSE_POLICY_ROLLOUT,
            GovernanceActionType.FREEZE_POLICY_ROLLOUT -> RolloutPromotionOperationType.PAUSE
            GovernanceActionType.RESUME_POLICY_ROLLOUT -> RolloutPromotionOperationType.RESUME
            GovernanceActionType.ROLLBACK_POLICY_ROLLOUT -> RolloutPromotionOperationType.HOLD
            else -> null
        }
        val derivedOperationType = when {
            operationTypeFromCommand != null -> operationTypeFromCommand
            readinessStatus == RolloutPromotionReadinessStatus.DEFERRED -> RolloutPromotionOperationType.DEFER
            readinessStatus == RolloutPromotionReadinessStatus.EXPIRED -> RolloutPromotionOperationType.EXPIRE
            readinessStatus == RolloutPromotionReadinessStatus.PAUSED -> RolloutPromotionOperationType.PAUSE
            else -> null
        }
        val updatedPromotionOperations = state.promotionOperationRecords.toMutableList()
        val latestPromotionOperation = derivedOperationType?.let { opType ->
            val opStatus = when (opType) {
                RolloutPromotionOperationType.PROMOTE -> when {
                    readinessStatus == RolloutPromotionReadinessStatus.READY -> GovernanceProgramOperationStatus.EXECUTED
                    readinessStatus == RolloutPromotionReadinessStatus.READY_WITH_CAUTION -> GovernanceProgramOperationStatus.SCHEDULED
                    state.approvalState == PolicyRolloutApprovalState.PENDING -> GovernanceProgramOperationStatus.APPROVAL_REQUIRED
                    else -> GovernanceProgramOperationStatus.BLOCKED
                }

                RolloutPromotionOperationType.HOLD -> GovernanceProgramOperationStatus.BLOCKED
                RolloutPromotionOperationType.DEFER -> GovernanceProgramOperationStatus.SCHEDULED
                RolloutPromotionOperationType.PAUSE -> GovernanceProgramOperationStatus.PAUSED
                RolloutPromotionOperationType.RESUME -> GovernanceProgramOperationStatus.RESUMED
                RolloutPromotionOperationType.EXPIRE -> GovernanceProgramOperationStatus.CANCELLED
            }
            RolloutPromotionOperationRecord(
                operationId = "rollout_promotion_op_${opType.name.lowercase()}_$now",
                type = opType,
                status = opStatus,
                actor = actorRef,
                reasonCodes = listOf(operationReasonCode(opType)),
                summary = "Promotion operation ${opType.name.lowercase()} is ${opStatus.name.lowercase().replace('_', ' ')}.",
                timestampMs = now
            ).also { operation ->
                val isSemanticDuplicate = updatedPromotionOperations.lastOrNull()?.let { last ->
                    last.type == operation.type &&
                        last.status == operation.status &&
                        last.summary.equals(operation.summary, ignoreCase = true)
                } == true
                if (!isSemanticDuplicate && updatedPromotionOperations.none { it.operationId == operation.operationId }) {
                    updatedPromotionOperations += operation
                }
                reasonCodes += operation.reasonCodes
            }
        }
        reasonCodes += readinessReasonCodes
        reasonCodes += crossWaveReasonCodes
        reasonCodes += windowImpactReasonCodes

        val previousProgramCoordination = state.programCoordination
        fun rolloutProgramPriorityFor(scope: PolicyRolloutScope): RolloutProgramPriority {
            return when (scope) {
                PolicyRolloutScope.GLOBAL -> RolloutProgramPriority.CRITICAL
                PolicyRolloutScope.TENANT -> RolloutProgramPriority.HIGH
                PolicyRolloutScope.WORKSPACE -> RolloutProgramPriority.MEDIUM
                PolicyRolloutScope.ROLE -> RolloutProgramPriority.MEDIUM
                PolicyRolloutScope.WORKFLOW_TEMPLATE -> RolloutProgramPriority.LOW
            }
        }
        val dependencies = buildList {
            if (previousWaveIncomplete) {
                add(
                    RolloutProgramDependency(
                        dependencyId = "dep_${workflowTemplateId}_${resolvedWaveId}_$now",
                        programId = workflowTemplateId,
                        dependsOnProgramId = "${workflowTemplateId}_wave_${(currentWaveIndex - 1).coerceAtLeast(1)}",
                        blocked = true,
                        reasonCodes = listOf(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_BLOCKED_BY_DEPENDENCY),
                        summary = "Current wave depends on an earlier wave that is not complete."
                    )
                )
            }
        }
        val conflicts = buildList {
            when (windowDelayReason) {
                WindowDelayReason.BLACKOUT_WINDOW -> add(
                    RolloutProgramConflict(
                        conflictId = "conflict_blackout_${workflowTemplateId}_$now",
                        type = RolloutProgramConflictType.WINDOW_OVERLAP,
                        severity = RolloutProgramConflictSeverity.HIGH,
                        withProgramId = null,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_CONFLICT_DETECTED,
                            RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_WINDOW_CONTENTION
                        ),
                        summary = "Promotion window conflicts with blackout policy."
                    )
                )

                WindowDelayReason.MAINTENANCE_WINDOW -> add(
                    RolloutProgramConflict(
                        conflictId = "conflict_maintenance_${workflowTemplateId}_$now",
                        type = RolloutProgramConflictType.WINDOW_OVERLAP,
                        severity = RolloutProgramConflictSeverity.MEDIUM,
                        withProgramId = null,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_CONFLICT_DETECTED,
                            RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_WINDOW_CONTENTION
                        ),
                        summary = "Promotion window conflicts with maintenance window constraints."
                    )
                )

                else -> Unit
            }
        }
        val contentionType = when {
            windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW ||
                windowDelayReason == WindowDelayReason.MAINTENANCE_WINDOW -> RolloutProgramContentionType.WINDOW
            carryForwardPressure || pendingWaveTargets > 1 -> RolloutProgramContentionType.CAPACITY
            else -> RolloutProgramContentionType.NONE
        }
        val contentionLevel = when {
            contentionType == RolloutProgramContentionType.NONE -> RolloutProgramContentionLevel.NONE
            windowDelayReason == WindowDelayReason.BLACKOUT_WINDOW -> RolloutProgramContentionLevel.HIGH
            pendingWaveTargets > 2 -> RolloutProgramContentionLevel.HIGH
            carryForwardPressure || pendingWaveTargets > 1 -> RolloutProgramContentionLevel.MEDIUM
            else -> RolloutProgramContentionLevel.LOW
        }
        val contentionSummary = if (contentionType == RolloutProgramContentionType.NONE) {
            null
        } else {
            RolloutProgramContentionSummary(
                type = contentionType,
                level = contentionLevel,
                contendedProgramIds = listOf(workflowTemplateId),
                reasonCodes = buildList {
                    if (contentionType == RolloutProgramContentionType.WINDOW) {
                        add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_WINDOW_CONTENTION)
                    }
                    if (contentionType == RolloutProgramContentionType.CAPACITY) {
                        add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_CAPACITY_BLOCKED)
                    }
                }.distinct(),
                summary = when (contentionType) {
                    RolloutProgramContentionType.WINDOW -> "Window contention limits rollout progression in this cycle."
                    RolloutProgramContentionType.CAPACITY -> "Capacity contention limits concurrent rollout progression."
                    else -> ""
                }
            )
        }
        val baseDecisionReason = when {
            dependencies.any { it.blocked } -> RolloutProgramDecisionReason.DEPENDENCY_BLOCK
            conflicts.isNotEmpty() -> RolloutProgramDecisionReason.CONFLICT_BLOCK
            contentionType == RolloutProgramContentionType.WINDOW -> RolloutProgramDecisionReason.WINDOW_CONTENTION
            contentionType == RolloutProgramContentionType.CAPACITY -> RolloutProgramDecisionReason.CAPACITY_CONTENTION
            readinessStatus == RolloutPromotionReadinessStatus.READY ||
                readinessStatus == RolloutPromotionReadinessStatus.READY_WITH_CAUTION -> RolloutProgramDecisionReason.PRIORITY_WIN
            readinessStatus == RolloutPromotionReadinessStatus.PAUSED -> RolloutProgramDecisionReason.GOVERNANCE_PAUSE
            state.approvalState == PolicyRolloutApprovalState.PENDING -> RolloutProgramDecisionReason.APPROVAL_PENDING
            else -> RolloutProgramDecisionReason.PRIORITY_DEFER
        }
        val baseCoordinationState = when {
            dependencies.any { it.blocked } -> RolloutProgramCoordinationState.DEPENDENCY_BLOCKED
            conflicts.isNotEmpty() -> RolloutProgramCoordinationState.CONFLICT_BLOCKED
            contentionType != RolloutProgramContentionType.NONE &&
                (scheduleDecision == ExecutionWindowDecision.BLOCKED ||
                    scheduleDecision == ExecutionWindowDecision.DEFERRED ||
                    scheduleDecision == ExecutionWindowDecision.EXPIRED) ->
                RolloutProgramCoordinationState.CONTENTION_BLOCKED
            readinessStatus == RolloutPromotionReadinessStatus.READY ||
                readinessStatus == RolloutPromotionReadinessStatus.READY_WITH_CAUTION ->
                RolloutProgramCoordinationState.ACTIVE
            else -> RolloutProgramCoordinationState.DEFERRED
        }
        val shouldEscalate = baseCoordinationState != RolloutProgramCoordinationState.ACTIVE &&
            (
                readinessStatus == RolloutPromotionReadinessStatus.BLOCKED ||
                    readinessStatus == RolloutPromotionReadinessStatus.DEFERRED ||
                    dependencies.any { it.blocked } ||
                    conflicts.any { it.severity == RolloutProgramConflictSeverity.HIGH || it.severity == RolloutProgramConflictSeverity.CRITICAL } ||
                    contentionLevel == RolloutProgramContentionLevel.HIGH ||
                    contentionLevel == RolloutProgramContentionLevel.CRITICAL
                )
        val escalationStatus = when {
            shouldEscalate -> RolloutProgramEscalationStatus.OPEN
            (
                previousProgramCoordination?.escalation?.status == RolloutProgramEscalationStatus.OPEN ||
                    previousProgramCoordination?.escalation?.status == RolloutProgramEscalationStatus.IN_PROGRESS
                ) && baseCoordinationState == RolloutProgramCoordinationState.ACTIVE ->
                RolloutProgramEscalationStatus.RESOLVED
            else -> RolloutProgramEscalationStatus.NOT_ESCALATED
        }
        val escalationReason = when {
            dependencies.any { it.blocked } -> RolloutProgramEscalationReason.DEPENDENCY_DEADLOCK
            conflicts.isNotEmpty() -> RolloutProgramEscalationReason.CONFLICT_UNRESOLVED
            readinessStatus == RolloutPromotionReadinessStatus.EXPIRED -> RolloutProgramEscalationReason.WINDOW_MISSED
            contentionType == RolloutProgramContentionType.CAPACITY -> RolloutProgramEscalationReason.CAPACITY_CONTENTION
            baseCoordinationState == RolloutProgramCoordinationState.DEFERRED -> RolloutProgramEscalationReason.REPEATED_DEFER
            else -> RolloutProgramEscalationReason.NONE
        }
        val escalationState = RolloutProgramEscalationState(
            escalationId = previousProgramCoordination?.escalation?.escalationId
                ?.takeIf { it.isNotBlank() }
                ?: "program_escalation_${workflowTemplateId}_$now",
            status = escalationStatus,
            reason = escalationReason,
            openedAtMs = when {
                escalationStatus == RolloutProgramEscalationStatus.OPEN ->
                    previousProgramCoordination?.escalation?.openedAtMs ?: now
                escalationStatus == RolloutProgramEscalationStatus.RESOLVED ->
                    previousProgramCoordination?.escalation?.openedAtMs
                else -> null
            },
            updatedAtMs = now,
            resolvedAtMs = if (escalationStatus == RolloutProgramEscalationStatus.RESOLVED) now else null,
            reasonCodes = buildList {
                if (escalationStatus == RolloutProgramEscalationStatus.OPEN) {
                    add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_ESCALATION_OPENED)
                }
                if (escalationStatus == RolloutProgramEscalationStatus.RESOLVED) {
                    add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_ESCALATION_RESOLVED)
                }
            }.distinct(),
            summary = when (escalationStatus) {
                RolloutProgramEscalationStatus.OPEN ->
                    "Escalation opened due to rollout coordination blockers."
                RolloutProgramEscalationStatus.RESOLVED ->
                    "Escalation resolved after rollout coordination recovered."
                RolloutProgramEscalationStatus.IN_PROGRESS ->
                    "Escalation is in progress."
                else -> "No escalation is active."
            }
        )
        val coordinationState = if (escalationStatus == RolloutProgramEscalationStatus.OPEN) {
            RolloutProgramCoordinationState.ESCALATED
        } else {
            baseCoordinationState
        }
        val priorityDecision = RolloutProgramPriorityDecision(
            decisionId = previousProgramCoordination?.priorityDecision?.decisionId
                ?.takeIf { it.isNotBlank() }
                ?: "program_priority_${workflowTemplateId}_$now",
            selectedProgramId = if (coordinationState == RolloutProgramCoordinationState.ACTIVE) {
                workflowTemplateId
            } else {
                previousProgramCoordination?.priorityDecision?.selectedProgramId
                    ?.takeIf { it.isNotBlank() }
                    ?: "higher_priority_program"
            },
            selectedPriority = rolloutProgramPriorityFor(state.target.scope),
            deferredProgramIds = if (coordinationState == RolloutProgramCoordinationState.ACTIVE) {
                emptyList()
            } else {
                listOf(workflowTemplateId)
            },
            decisionReason = baseDecisionReason,
            reasonCodes = buildList {
                add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_PRIORITY_APPLIED)
                if (coordinationState != RolloutProgramCoordinationState.ACTIVE) {
                    add(RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_DEFERRED_BY_PRIORITY)
                }
            }.distinct(),
            summary = if (coordinationState == RolloutProgramCoordinationState.ACTIVE) {
                "Program keeps rollout priority for the current eligibility window."
            } else {
                "Program is deferred by current multi-program coordination priority."
            },
            nextEligibleAtMs = promotionCandidate.nextEligibleAtMs,
            updatedAtMs = now
        )
        val resolvedProgramPriority = rolloutProgramPriorityFor(state.target.scope)
        val capacityPoolKey = "${workflowTemplateId}_approval_pool"
        val capacityRequestedSlots = pendingWaveTargets.coerceAtLeast(1)
        val capacityAvailableSlots = when {
            contentionType == RolloutProgramContentionType.CAPACITY -> 0
            resolvedProgramPriority == RolloutProgramPriority.CRITICAL &&
                readinessStatus == RolloutPromotionReadinessStatus.READY -> 2
            else -> 1
        }
        val capacityBlockedSlots = (capacityRequestedSlots - capacityAvailableSlots).coerceAtLeast(0)
        val queueUtilization = if (capacityAvailableSlots <= 0) {
            capacityRequestedSlots.toDouble()
        } else {
            capacityRequestedSlots.toDouble() / capacityAvailableSlots.toDouble()
        }
        val approvalLoadBucket = when {
            capacityRequestedSlots == 0 -> ApprovalLoadBucket.IDLE
            capacityBlockedSlots == 0 && queueUtilization <= 0.75 -> ApprovalLoadBucket.BALANCED
            capacityBlockedSlots == 0 -> ApprovalLoadBucket.ELEVATED
            queueUtilization < 2.0 -> ApprovalLoadBucket.HIGH
            else -> ApprovalLoadBucket.SATURATED
        }
        val policyBlockedByGate = dependencies.any { it.blocked } ||
            conflicts.isNotEmpty() ||
            state.freezeState != PolicyRolloutFreezeState.NOT_FROZEN ||
            state.approvalState == PolicyRolloutApprovalState.PENDING ||
            state.approvalState == PolicyRolloutApprovalState.DENIED
        val capacityBlocked = capacityBlockedSlots > 0
        val criticalProgramReserved = resolvedProgramPriority == RolloutProgramPriority.CRITICAL &&
            (capacityBlocked || carryForwardPressure)
        val deferralReason = when {
            policyBlockedByGate -> ApprovalDeferralReason.POLICY_BLOCKED
            contentionType == RolloutProgramContentionType.WINDOW -> ApprovalDeferralReason.WINDOW_LOCK
            approvalLoadBucket == ApprovalLoadBucket.SATURATED -> ApprovalDeferralReason.QUEUE_SATURATED
            criticalProgramReserved -> ApprovalDeferralReason.CRITICAL_CAPACITY_RESERVED
            capacityBlocked -> ApprovalDeferralReason.CAPACITY_EXHAUSTED
            else -> ApprovalDeferralReason.NONE
        }
        val balancingDecisionType = when {
            policyBlockedByGate -> ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE
            criticalProgramReserved -> ApprovalBalancingDecisionType.RESERVE_CAPACITY_FOR_CRITICAL_PROGRAM
            capacityBlocked && resolvedProgramPriority == RolloutProgramPriority.HIGH ->
                ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE
            capacityBlocked && resolvedProgramPriority == RolloutProgramPriority.MEDIUM ->
                ApprovalBalancingDecisionType.DEFER_FOR_CAPACITY
            capacityBlocked && resolvedProgramPriority == RolloutProgramPriority.LOW ->
                ApprovalBalancingDecisionType.PAUSE_LOWER_PRIORITY_PROGRAM
            else -> ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE
        }
        val capacityReasonCodes = buildList {
            if (capacityBlocked) add(RoleReasonCodes.ROLE_GOVERNANCE_CAPACITY_BLOCKED)
            if (approvalLoadBucket == ApprovalLoadBucket.SATURATED) {
                add(RoleReasonCodes.ROLE_GOVERNANCE_APPROVAL_QUEUE_SATURATED)
            }
            when (balancingDecisionType) {
                ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE ->
                    add(RoleReasonCodes.ROLE_GOVERNANCE_CAPACITY_REASSIGNED)

                ApprovalBalancingDecisionType.DEFER_FOR_CAPACITY ->
                    add(RoleReasonCodes.ROLE_GOVERNANCE_CAPACITY_DEFERRED)

                ApprovalBalancingDecisionType.RESERVE_CAPACITY_FOR_CRITICAL_PROGRAM ->
                    add(RoleReasonCodes.ROLE_GOVERNANCE_CRITICAL_PROGRAM_RESERVED)

                ApprovalBalancingDecisionType.PAUSE_LOWER_PRIORITY_PROGRAM ->
                    add(RoleReasonCodes.ROLE_GOVERNANCE_PORTFOLIO_PRIORITIZED)

                ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE -> Unit
            }
            if (balancingDecisionType != ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE) {
                add(RoleReasonCodes.ROLE_GOVERNANCE_APPROVAL_LOAD_BALANCED)
            }
        }.distinct()
        val previousCapacityBlocked = previousProgramCoordination
            ?.capacityImpact
            ?.capacityBlocked == true
        if (previousCapacityBlocked && !capacityBlocked) {
            reasonCodes += RoleReasonCodes.ROLE_GOVERNANCE_CAPACITY_RESUMED
        }
        val capacityBudget = ApprovalCapacityBudget(
            availableSlots = capacityAvailableSlots,
            requestedSlots = capacityRequestedSlots,
            reservedSlots = if (criticalProgramReserved) 1 else 0,
            utilizationRate = queueUtilization,
            summary = if (capacityBlocked) {
                "Approval capacity is constrained for this rollout cycle."
            } else {
                "Approval capacity is currently available."
            }
        )
        val governanceCapacityPool = GovernanceCapacityPool(
            poolKey = capacityPoolKey,
            scope = when (state.target.scope) {
                PolicyRolloutScope.GLOBAL -> GovernanceCapacityScope.GLOBAL
                PolicyRolloutScope.TENANT -> GovernanceCapacityScope.TENANT
                PolicyRolloutScope.WORKSPACE -> GovernanceCapacityScope.WORKSPACE
                else -> GovernanceCapacityScope.PROGRAM
            },
            scopeId = state.target.workspaceId
                ?: state.target.tenantId
                ?: state.target.workflowTemplateId
                ?: workflowTemplateId,
            loadBucket = approvalLoadBucket,
            budget = capacityBudget,
            nextAvailableAtMs = promotionCandidate.nextEligibleAtMs,
            reasonCodes = capacityReasonCodes,
            summary = "Approval pool ${capacityPoolKey.take(32)} is ${
                approvalLoadBucket.name.lowercase().replace('_', ' ')
            }."
        )
        val approvalQueuePressure = ApprovalQueuePressureSummary(
            poolKey = capacityPoolKey,
            loadBucket = approvalLoadBucket,
            pendingApprovals = capacityRequestedSlots,
            inFlightApprovals = capacityAvailableSlots.coerceAtLeast(0),
            blockedApprovals = capacityBlockedSlots,
            reasonCodes = capacityReasonCodes,
            summary = "Approval queue pressure is ${
                approvalLoadBucket.name.lowercase().replace('_', ' ')
            } (${capacityBlockedSlots} blocked of $capacityRequestedSlots)."
        )
        val approvalBalancingDecision = ApprovalBalancingDecision(
            decisionType = balancingDecisionType,
            fromPoolKey = capacityPoolKey,
            toPoolKey = when (balancingDecisionType) {
                ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE ->
                    "${capacityPoolKey}_low_pressure"
                else -> null
            },
            deferralReason = deferralReason,
            applied = balancingDecisionType != ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE,
            deferUntilMs = if (
                balancingDecisionType == ApprovalBalancingDecisionType.DEFER_FOR_CAPACITY ||
                balancingDecisionType == ApprovalBalancingDecisionType.PAUSE_LOWER_PRIORITY_PROGRAM
            ) {
                promotionCandidate.nextEligibleAtMs
            } else {
                null
            },
            reasonCodes = capacityReasonCodes,
            summary = when (balancingDecisionType) {
                ApprovalBalancingDecisionType.REMAIN_IN_CURRENT_QUEUE ->
                    "Approval stays in current queue; no balancing action applied."
                ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE ->
                    "Approval reassigned to a lower-pressure queue due to capacity pressure."
                ApprovalBalancingDecisionType.DEFER_FOR_CAPACITY ->
                    "Approval deferred until queue capacity is available."
                ApprovalBalancingDecisionType.PAUSE_LOWER_PRIORITY_PROGRAM ->
                    "Lower-priority program paused to avoid approval bottleneck spillover."
                ApprovalBalancingDecisionType.RESERVE_CAPACITY_FOR_CRITICAL_PROGRAM ->
                    "Capacity reserved for a critical rollout program."
            },
            updatedAtMs = now
        )
        val approvalAssignmentRecommendation = ApprovalAssignmentRecommendation(
            recommendedPoolKey = approvalBalancingDecision.toPoolKey ?: capacityPoolKey,
            recommendedAssigneeId = if (balancingDecisionType == ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE) {
                "ops-capacity-lp"
            } else {
                null
            },
            recommendedAssigneeDisplayName = if (balancingDecisionType == ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE) {
                "Lower-pressure approval queue"
            } else {
                null
            },
            reasonCodes = capacityReasonCodes,
            summary = if (balancingDecisionType == ApprovalBalancingDecisionType.REASSIGN_TO_LOWER_PRESSURE_QUEUE) {
                "Recommendation: route approval to lower-pressure queue."
            } else {
                "Recommendation: keep current approval assignment."
            }
        )
        val capacityImpact = ProgramCapacityImpactSummary(
            capacityBlocked = capacityBlocked,
            policyBlocked = policyBlockedByGate,
            loadBucket = approvalLoadBucket,
            deferralReason = deferralReason,
            reasonCodes = capacityReasonCodes,
            summary = if (policyBlockedByGate) {
                "Program is policy-gated; capacity pressure is advisory."
            } else if (capacityBlocked) {
                "Program is capacity-blocked and requires balancing or defer."
            } else {
                "Program has sufficient approval capacity for progression."
            }
        )
        val portfolioCapacitySnapshot = PortfolioCapacitySnapshot(
            totalPools = maxOf(1, crossWaveAnalyticsSummary.totalWaves.coerceAtLeast(1)),
            saturatedPools = if (approvalLoadBucket == ApprovalLoadBucket.SATURATED) 1 else 0,
            deferredPrograms = crossWaveAnalyticsSummary.deferredWaves +
                if (balancingDecisionType == ApprovalBalancingDecisionType.DEFER_FOR_CAPACITY) 1 else 0,
            criticalReservedPrograms = if (criticalProgramReserved) 1 else 0,
            reasonCodes = capacityReasonCodes,
            summary = "Portfolio capacity: ${
                approvalLoadBucket.name.lowercase().replace('_', ' ')
            } load; ${if (capacityBlocked) "capacity constrained" else "capacity available"}.",
            updatedAtMs = now
        )
        val programPortfolioSummary = ProgramPortfolioSummary(
            activeProgramId = if (!policyBlockedByGate && !capacityBlocked) workflowTemplateId else null,
            capacityBlockedPrograms = if (capacityBlocked) 1 else 0,
            policyBlockedPrograms = if (policyBlockedByGate) 1 else 0,
            balancedPrograms = if (!capacityBlocked && !policyBlockedByGate) 1 else 0,
            criticalReservedPrograms = if (criticalProgramReserved) 1 else 0,
            bottleneckPoolKeys = if (capacityBlocked) listOf(capacityPoolKey) else emptyList(),
            recommendedNextAction = approvalBalancingDecision.summary,
            reasonCodes = capacityReasonCodes,
            summary = "Program portfolio view: ${if (capacityBlocked) "capacity bottleneck detected" else "no approval bottleneck detected"}.",
            updatedAtMs = now
        )
        val capacityAwarePromotionDecision = CapacityAwarePromotionDecision(
            decisionId = "capacity_decision_${workflowTemplateId}_$now",
            allowedNow = !policyBlockedByGate && !capacityBlocked,
            capacityBlocked = capacityBlocked,
            policyBlocked = policyBlockedByGate,
            decisionType = balancingDecisionType,
            deferralReason = deferralReason,
            nextEligibleAtMs = promotionCandidate.nextEligibleAtMs,
            reasonCodes = capacityReasonCodes,
            summary = if (policyBlockedByGate) {
                "Promotion decision is policy-blocked; capacity balancing cannot override policy gates."
            } else if (capacityBlocked) {
                "Promotion decision deferred due to approval capacity constraints."
            } else {
                "Promotion decision can proceed under current approval capacity."
            },
            updatedAtMs = now
        )
        val capacitySummary = RolloutProgramCapacitySummary(
            capacityKey = "${workflowTemplateId}_window_capacity",
            availableSlots = capacityAvailableSlots.coerceAtLeast(0),
            requestedSlots = capacityRequestedSlots,
            blockedSlots = capacityBlockedSlots,
            summary = if (capacityBlocked) {
                "Capacity is oversubscribed for this rollout window."
            } else {
                "Capacity is sufficient for current rollout progression."
            }
        )
        val programCoordination = RolloutProgramCoordinationRecord(
            programId = workflowTemplateId,
            programName = governanceProgram?.name?.takeIf { it.isNotBlank() } ?: workflowTemplateId,
            priority = resolvedProgramPriority,
            coordinationState = coordinationState,
            decisionReason = baseDecisionReason,
            priorityDecision = priorityDecision,
            dependencies = dependencies,
            conflicts = conflicts,
            contention = contentionSummary,
            escalation = escalationState,
            capacity = capacitySummary,
            capacityImpact = capacityImpact,
            balancingDecision = approvalBalancingDecision,
            assignmentRecommendation = approvalAssignmentRecommendation,
            capacityAwarePromotionDecision = capacityAwarePromotionDecision,
            programPortfolioSummary = programPortfolioSummary,
            nextEligibleAtMs = promotionCandidate.nextEligibleAtMs,
            reasonCodes = (
                priorityDecision.reasonCodes +
                    dependencies.flatMap { it.reasonCodes } +
                    conflicts.flatMap { it.reasonCodes } +
                    (contentionSummary?.reasonCodes ?: emptyList()) +
                    escalationState.reasonCodes +
                    capacityReasonCodes
                ).distinct(),
            summary = buildString {
                append("Program coordination is ")
                append(coordinationState.name.lowercase().replace('_', ' '))
                append(" with ")
                append(baseDecisionReason.name.lowercase().replace('_', ' '))
                append(" decision.")
            },
            updatedAtMs = now
        )
        val crossProgramGovernanceSummary = CrossProgramGovernanceSummary(
            activeProgramId = priorityDecision.selectedProgramId.takeIf { it.isNotBlank() },
            competingProgramCount = maxOf(1, crossWaveAnalyticsSummary.totalWaves.coerceAtLeast(1)),
            deferredProgramCount = (if (coordinationState == RolloutProgramCoordinationState.DEFERRED ||
                coordinationState == RolloutProgramCoordinationState.CONTENTION_BLOCKED
            ) {
                1
            } else {
                0
            }) + crossWaveAnalyticsSummary.deferredWaves,
            blockedProgramCount = dependencies.count { it.blocked } + conflicts.size,
            escalatedProgramCount = if (escalationStatus == RolloutProgramEscalationStatus.OPEN) 1 else 0,
            contentionType = contentionType,
            contentionLevel = contentionLevel,
            portfolioCapacitySnapshot = portfolioCapacitySnapshot,
            reasonCodes = programCoordination.reasonCodes,
            summary = buildString {
                append("Cross-program coordination: ")
                append(coordinationState.name.lowercase().replace('_', ' '))
                append(", contention ")
                append(contentionLevel.name.lowercase().replace('_', ' '))
                append(", approval load ")
                append(approvalLoadBucket.name.lowercase().replace('_', ' '))
                append('.')
            },
            updatedAtMs = now
        )
        val programCoordinationSummary = programCoordination.summary
        val crossProgramSummary = crossProgramGovernanceSummary.summary
        val programEscalationSummary = escalationState.summary
        val approvalLoadSummary = approvalQueuePressure.summary
        val capacityBlockSummary = if (capacityBlocked) {
            "Approval capacity blocked this rollout step (${capacityBlockedSlots}/${capacityRequestedSlots} requests blocked)."
        } else {
            "Approval capacity did not block this rollout step."
        }
        val policyBlockSummary = if (policyBlockedByGate) {
            "Policy and rollout safety gates are blocking progression independently of capacity."
        } else {
            "No policy/safety gate currently blocks rollout progression."
        }
        val capacityBalancingSummary = approvalBalancingDecision.summary
        val portfolioCapacitySummary = programPortfolioSummary.summary

        reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_PRIORITY_APPLIED
        if (coordinationState != RolloutProgramCoordinationState.ACTIVE) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_DEFERRED_BY_PRIORITY
        }
        if (dependencies.any { it.blocked }) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_BLOCKED_BY_DEPENDENCY
        }
        if (conflicts.isNotEmpty()) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_CONFLICT_DETECTED
        }
        if (contentionType == RolloutProgramContentionType.WINDOW) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_WINDOW_CONTENTION
        }
        if (contentionType == RolloutProgramContentionType.CAPACITY) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_CAPACITY_BLOCKED
        }
        reasonCodes += capacityReasonCodes
        if (escalationStatus == RolloutProgramEscalationStatus.OPEN) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_ESCALATION_OPENED
        } else if (escalationStatus == RolloutProgramEscalationStatus.RESOLVED) {
            reasonCodes += RoleReasonCodes.ROLE_ROLLOUT_PROGRAM_ESCALATION_RESOLVED
        }

        val normalizedTargetScope = state.target.scope
        val freezeBlocks = state.freezeState != PolicyRolloutFreezeState.NOT_FROZEN ||
            state.stage == PolicyRolloutStage.PAUSED ||
            state.stage == PolicyRolloutStage.FROZEN
        val forceSimulationOnly = state.mode == PolicyRolloutMode.SIMULATION_ONLY ||
            state.stage == PolicyRolloutStage.SIMULATION_ONLY ||
            freezeBlocks ||
            state.approvalState == PolicyRolloutApprovalState.PENDING ||
            state.approvalState == PolicyRolloutApprovalState.DENIED

        if (forceSimulationOnly && state.mode == PolicyRolloutMode.ENFORCED) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_ROLLOUT_PROMOTION_BLOCKED
        }
        if (freezeBlocks) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_ROLLOUT_GUARDRAIL_BLOCKED
        }
        if (state.approvalState == PolicyRolloutApprovalState.PENDING) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_ROLLOUT_APPROVAL_REQUIRED
        }
        if (state.mode == PolicyRolloutMode.SIMULATION_ONLY || forceSimulationOnly) {
            reasonCodes += RoleReasonCodes.ROLE_POLICY_ROLLOUT_SIMULATION_ONLY
        }
        val rolloutSummary = buildString {
            append("Workflow policy rollout ")
            append(state.stage.name.lowercase().replace('_', ' '))
            append(" in ")
            append(state.mode.name.lowercase().replace('_', ' '))
            append(" mode for ")
            append(normalizedTargetScope.name.lowercase().replace('_', ' '))
            append(" scope.")
        }
        val approvalSummary = when (state.approvalState) {
            PolicyRolloutApprovalState.NOT_REQUIRED ->
                "No rollout approval gate is currently required."
            PolicyRolloutApprovalState.PENDING ->
                "Rollout approval is pending before risky promotion or scope expansion."
            PolicyRolloutApprovalState.APPROVED ->
                "Rollout approval was granted for the current promotion scope."
            PolicyRolloutApprovalState.DENIED ->
                "Rollout approval was denied; enforcement stays blocked."
        }
        val freezeSummary = when (state.freezeState) {
            PolicyRolloutFreezeState.NOT_FROZEN ->
                "Rollout freeze is not active."
            PolicyRolloutFreezeState.PAUSED_BY_OPERATOR ->
                "Rollout is paused by operator and cannot strengthen enforcement."
            PolicyRolloutFreezeState.FROZEN_BY_OPERATOR ->
                "Rollout is frozen by operator pending manual governance review."
            PolicyRolloutFreezeState.FROZEN_BY_GUARDRAIL ->
                "Rollout is frozen by guardrails due to policy safety checks."
        }
        val rollbackSummary = state.rollbackRecord?.summary
            ?.takeIf { it.isNotBlank() }
            ?: "No rollout rollback was recorded."
        val promotionStatusSummary = "Policy promotion ${promotionStatus.name.lowercase().replace('_', ' ')}."
        val policyPromotionReadinessSummaryText = promotionReadiness?.summary
            ?.takeIf { it.isNotBlank() }
            ?: "Promotion readiness is not tracked."
        val promotionBlockerSummary = promotionReadiness
            ?.blockers
            ?.mapNotNull { it.summary.takeIf(String::isNotBlank) }
            ?.distinct()
            ?.joinToString("; ")
            .orEmpty()
        val promotionRecommendationSummary = promotionReadiness
            ?.recommendation
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: "No promotion recommendation recorded."
        automationReplaySummary = AutomationReplaySummary(
            executedCount = governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.EXECUTED },
            scheduledCount = governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.SCHEDULED },
            blockedCount = governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.BLOCKED },
            suppressedCount = governanceProgramOperations.count { operation ->
                operation.status == GovernanceProgramOperationStatus.PAUSED ||
                    operation.status == GovernanceProgramOperationStatus.SKIPPED
            },
            approvalRequiredCount = governanceProgramOperations.count {
                it.status == GovernanceProgramOperationStatus.APPROVAL_REQUIRED
            },
            summary = buildString {
                append("Ops ")
                append(governanceProgramOperations.size)
                append(" · scheduled ")
                append(governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.SCHEDULED })
                append(" · executed ")
                append(governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.EXECUTED })
                append(" · approval-required ")
                append(governanceProgramOperations.count { it.status == GovernanceProgramOperationStatus.APPROVAL_REQUIRED })
            },
            updatedAtMs = now
        )
        val combinedSummary = buildString {
            append(rolloutSummary)
            append(' ')
            append(promotionStatusSummary)
            append(' ')
            append(policyPromotionReadinessSummaryText)
            if (promotionBlockerSummary.isNotBlank()) {
                append(" Blockers: ")
                append(promotionBlockerSummary)
                append('.')
            }
            if (promotionRecommendationSummary.isNotBlank()) {
                append(" Recommendation: ")
                append(promotionRecommendationSummary)
            }
            if (programSummary.isNotBlank()) {
                append(" Program: ")
                append(programSummary)
            }
            if (crossTenantSummary.isNotBlank()) {
                append(" Cross-tenant: ")
                append(crossTenantSummary)
            }
            if (packLifecycleSummary.isNotBlank()) {
                append(" Pack lifecycle: ")
                append(packLifecycleSummary)
            }
            append(" Promotion readiness: ")
            append(rolloutPromotionReadiness.summary)
            append(" Cross-wave: ")
            append(crossWaveAnalyticsSummary.summary)
            append(" Window impact: ")
            append(windowImpactSummary.summary)
            latestPromotionOperation
                ?.summary
                ?.takeIf { it.isNotBlank() }
                ?.let {
                    append(" Operation: ")
                    append(it)
                }
            if (programCoordinationSummary.isNotBlank()) {
                append(" Program coordination: ")
                append(programCoordinationSummary)
            }
            if (crossProgramSummary.isNotBlank()) {
                append(" Cross-program: ")
                append(crossProgramSummary)
            }
            if (approvalLoadSummary.isNotBlank()) {
                append(" Approval load: ")
                append(approvalLoadSummary)
            }
            if (capacityBlockSummary.isNotBlank()) {
                append(" Capacity block: ")
                append(capacityBlockSummary)
            }
            if (policyBlockSummary.isNotBlank()) {
                append(" Policy block: ")
                append(policyBlockSummary)
            }
            if (capacityBalancingSummary.isNotBlank()) {
                append(" Balancing: ")
                append(capacityBalancingSummary)
            }
            if (portfolioCapacitySummary.isNotBlank()) {
                append(" Portfolio capacity: ")
                append(portfolioCapacitySummary)
            }
            if (programEscalationSummary.isNotBlank() &&
                !programEscalationSummary.equals("No escalation is active.", ignoreCase = true)
            ) {
                append(" Escalation: ")
                append(programEscalationSummary)
            }
        }.trim()
        state = state.copy(
            target = state.target.takeIf { it.workflowTemplateId?.isNotBlank() == true } ?: defaultTarget,
            auditRecords = audits.takeLast(30),
            promotionStatus = promotionStatus,
            promotionRequest = promotionRequest,
            promotionDecision = promotionDecision,
            promotionReadiness = promotionReadiness,
            rolloutAnalyticsSummary = rolloutAnalytics,
            approvalOperations = approvalOperations.takeLast(20),
            approvalReviewSummary = approvalReviewSummary,
            promotionAuditRecords = promotionAudits.takeLast(30),
            governanceProgram = governanceProgram,
            crossTenantRollout = crossTenantRollout,
            packLifecycleStatus = packLifecycleStatus,
            packLifecycleEvents = packLifecycleEvents.takeLast(40),
            packDeprecationSummary = packDeprecationSummary,
            packRetirementSummary = packRetirementSummary,
            packReplacementPlan = packReplacementPlan,
            programSummary = programSummary,
            crossTenantSummary = crossTenantSummary,
            packLifecycleSummary = packLifecycleSummary,
            policyEstateSnapshot = policyEstateSnapshot,
            policyEstateSummary = policyEstateSummary,
            policyEstateDriftSummary = policyEstateDriftSummary,
            policyEstateBlockerSummary = policyEstateBlockerSummary,
            policyEstateRemediationSummary = policyEstateRemediationSummary,
            policyEstateRemediationPlan = policyEstateRemediationPlan,
            policyEstateRemediationActions = policyEstateRemediationActions.takeLast(40),
            estateAutomationRule = estateAutomationRule,
            estateAutomationEligibility = estateAutomationEligibility,
            scheduledRemediationPlan = scheduledRemediationPlan,
            governanceProgramOperations = governanceProgramOperations.takeLast(60),
            automationReplaySummary = automationReplaySummary,
            automationCancellationRecords = automationCancellationRecords.takeLast(40),
            policySchedulingWindow = policySchedulingWindow,
            rolloutCalendar = rolloutCalendar,
            calendarEvaluation = calendarEvaluation,
            scheduleSummary = scheduleSummary,
            rolloutCalendarSummary = rolloutCalendarSummary,
            rolloutWaves = mergedRolloutWaves,
            currentRolloutWaveId = resolvedWaveId,
            currentRolloutWaveStatus = waveStatus,
            currentRolloutWaveCompletionState = waveCompletionState,
            calendarAwarePromotionDecision = calendarAwarePromotionDecision,
            crossWindowGovernanceControl = crossWindowGovernanceControl,
            rolloutWaveSummary = rolloutWaveSummary,
            crossWindowGovernanceSummary = crossWindowGovernanceSummary,
            nextEligibleWindowSummary = nextEligibleWindowSummary,
            promotionCandidate = promotionCandidate,
            promotionReadinessSummary = rolloutPromotionReadiness,
            crossWaveAnalyticsSummary = crossWaveAnalyticsSummary,
            windowImpactSummary = windowImpactSummary,
            promotionOperationRecords = updatedPromotionOperations
                .distinctBy { operation -> operation.operationId }
                .sortedBy { operation -> operation.timestampMs }
                .takeLast(40),
            promotionOperationSummary = latestPromotionOperation
                ?.summary
                ?.takeIf { it.isNotBlank() }
                ?: state.promotionOperationSummary,
            programCoordination = programCoordination,
            crossProgramGovernanceSummary = crossProgramGovernanceSummary,
            governanceCapacityPool = governanceCapacityPool,
            approvalQueuePressure = approvalQueuePressure,
            approvalBalancingDecision = approvalBalancingDecision,
            approvalAssignmentRecommendation = approvalAssignmentRecommendation,
            capacityAwarePromotionDecision = capacityAwarePromotionDecision,
            portfolioCapacitySnapshot = portfolioCapacitySnapshot,
            programPortfolioSummary = programPortfolioSummary,
            programCoordinationSummary = buildString {
                append(programCoordinationSummary)
                if (programEscalationSummary.isNotBlank() &&
                    !programEscalationSummary.equals("No escalation is active.", ignoreCase = true)
                ) {
                    append(" ")
                    append(programEscalationSummary)
                }
            }.trim(),
            approvalLoadSummary = approvalLoadSummary,
            capacityBlockSummary = capacityBlockSummary,
            policyBlockSummary = policyBlockSummary,
            capacityBalancingSummary = capacityBalancingSummary,
            portfolioCapacitySummary = portfolioCapacitySummary,
            summary = combinedSummary,
            updatedAtMs = now
        )
        return WorkflowPolicyRolloutResolution(
            state = state,
            reasonCodes = reasonCodes.distinct(),
            forceSimulationOnly = forceSimulationOnly,
            freezeBlocksAutomation = freezeBlocks,
            rolloutSummary = rolloutSummary,
            approvalSummary = approvalSummary,
            freezeSummary = freezeSummary,
            rollbackSummary = rollbackSummary
        )
    }

    private fun resolveTenantWorkflowOverride(
        command: GovernanceCollaborationCommand?,
        template: OperatorWorkflowTemplate,
        templatePolicy: WorkflowPolicyProfile,
        now: Long,
        previousOverride: TenantWorkflowPolicyOverride?
    ): TenantWorkflowPolicyOverride? {
        val overrideId = command?.tenantPolicyOverrideId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: previousOverride?.overrideId
            ?: return null
        if (previousOverride != null && previousOverride.overrideId.equals(overrideId, ignoreCase = true)) {
            return previousOverride
        }
        return TenantWorkflowPolicyOverride(
            overrideId = overrideId,
            tenantId = previousOverride?.tenantId?.takeIf { it.isNotBlank() } ?: "tenant_default",
            workflowTemplateId = template.templateId,
            policyProfile = previousOverride?.policyProfile ?: templatePolicy.copy(
                version = "${templatePolicy.version}_tenant",
                summary = templatePolicy.summary.ifBlank {
                    "Tenant override policy is active for ${template.name.ifBlank { template.templateId }}."
                }
            ),
            automationControls = previousOverride?.automationControls ?: WorkflowAutomationAdvancedControls(
                maxRunsPerCase = 1,
                cooldownMs = 15 * 60 * 1000L,
                throttleWindowMs = 60 * 60 * 1000L,
                maxRunsPerWindow = 1,
                summary = "Tenant override limits automation cadence for this workflow."
            ),
            source = WorkflowPolicyOverrideSource.TENANT_ADMIN,
            approvalState = WorkflowPolicyOverrideApprovalState.APPROVED,
            effectiveFromMs = now,
            effectiveUntilMs = null,
            summary = previousOverride?.summary?.takeIf { it.isNotBlank() }
                ?: "Tenant override $overrideId is active for ${template.name.ifBlank { template.templateId }}.",
            updatedAtMs = now
        )
    }

    private fun resolveWorkspaceWorkflowOverride(
        command: GovernanceCollaborationCommand?,
        template: OperatorWorkflowTemplate,
        templatePolicy: WorkflowPolicyProfile,
        now: Long,
        previousOverride: WorkspaceWorkflowPolicyOverride?
    ): WorkspaceWorkflowPolicyOverride? {
        val overrideId = command?.workspacePolicyOverrideId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: previousOverride?.overrideId
            ?: return null
        if (previousOverride != null && previousOverride.overrideId.equals(overrideId, ignoreCase = true)) {
            return previousOverride
        }
        return WorkspaceWorkflowPolicyOverride(
            overrideId = overrideId,
            workspaceId = previousOverride?.workspaceId?.takeIf { it.isNotBlank() } ?: "workspace_default",
            workflowTemplateId = template.templateId,
            policyProfile = previousOverride?.policyProfile ?: templatePolicy.copy(
                version = "${templatePolicy.version}_workspace",
                summary = templatePolicy.summary.ifBlank {
                    "Workspace override policy is active for ${template.name.ifBlank { template.templateId }}."
                }
            ),
            automationControls = previousOverride?.automationControls ?: WorkflowAutomationAdvancedControls(
                maxRunsPerCase = 1,
                cooldownMs = 20 * 60 * 1000L,
                throttleWindowMs = 90 * 60 * 1000L,
                maxRunsPerWindow = 1,
                suppressionStages = listOf(OperatorWorkflowStage.TRIAGE),
                summary = "Workspace override limits automation in triage while preserving manual review."
            ),
            source = WorkflowPolicyOverrideSource.WORKSPACE_ADMIN,
            approvalState = WorkflowPolicyOverrideApprovalState.APPROVED,
            effectiveFromMs = now,
            effectiveUntilMs = null,
            summary = previousOverride?.summary?.takeIf { it.isNotBlank() }
                ?: "Workspace override $overrideId is active for ${template.name.ifBlank { template.templateId }}.",
            updatedAtMs = now
        )
    }

    private fun isWorkflowOverrideActive(
        approvalState: WorkflowPolicyOverrideApprovalState,
        effectiveFromMs: Long,
        effectiveUntilMs: Long?,
        now: Long
    ): Boolean {
        if (approvalState == WorkflowPolicyOverrideApprovalState.REJECTED ||
            approvalState == WorkflowPolicyOverrideApprovalState.PENDING
        ) {
            return false
        }
        if (effectiveFromMs > 0L && now < effectiveFromMs) return false
        if (effectiveUntilMs != null && effectiveUntilMs > 0L && now > effectiveUntilMs) return false
        return true
    }

    private fun workflowAutomationControlsFromPolicy(
        policy: WorkflowPolicyProfile
    ): WorkflowAutomationAdvancedControls {
        val guardrail = policy.automationGuardrail ?: WorkflowAutomationGuardrail()
        return WorkflowAutomationAdvancedControls(
            maxRunsPerCase = guardrail.maxRunsPerWindow.coerceAtLeast(1),
            cooldownMs = guardrail.cooldownMs,
            throttleWindowMs = guardrail.throttleWindowMs,
            maxRunsPerWindow = guardrail.maxRunsPerWindow.coerceAtLeast(1),
            suppressionStages = guardrail.suppressedStages,
            simulationOnly = false,
            summary = "Automation controls derived from workflow guardrails."
        )
    }

    private fun mergeWorkflowAutomationControls(
        base: WorkflowAutomationAdvancedControls,
        override: WorkflowAutomationAdvancedControls?
    ): WorkflowAutomationAdvancedControls {
        if (override == null) return base
        return WorkflowAutomationAdvancedControls(
            maxRunsPerCase = if (override.maxRunsPerCase > 0) override.maxRunsPerCase else base.maxRunsPerCase,
            cooldownMs = if (override.cooldownMs > 0L) override.cooldownMs else base.cooldownMs,
            throttleWindowMs = if (override.throttleWindowMs > 0L) override.throttleWindowMs else base.throttleWindowMs,
            maxRunsPerWindow = if (override.maxRunsPerWindow > 0) override.maxRunsPerWindow else base.maxRunsPerWindow,
            suppressionStages = (base.suppressionStages + override.suppressionStages).distinct(),
            quietHours = override.quietHours ?: base.quietHours,
            maintenanceWindow = override.maintenanceWindow ?: base.maintenanceWindow,
            simulationOnly = base.simulationOnly || override.simulationOnly,
            summary = listOf(base.summary, override.summary)
                .firstOrNull { it.isNotBlank() }
                ?: ""
        )
    }

    private fun precedenceReasonCodeFor(
        source: WorkflowPolicyPrecedenceSource
    ): String {
        return when (source) {
            WorkflowPolicyPrecedenceSource.EXPLICIT_CONSTRAINT ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_EXPLICIT_CONSTRAINT
            WorkflowPolicyPrecedenceSource.OPERATOR_OVERRIDE ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_OPERATOR_OVERRIDE
            WorkflowPolicyPrecedenceSource.WORKSPACE_OVERRIDE ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_WORKSPACE_OVERRIDE
            WorkflowPolicyPrecedenceSource.TENANT_OVERRIDE ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_TENANT_OVERRIDE
            WorkflowPolicyPrecedenceSource.POLICY_PACK ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_POLICY_PACK
            WorkflowPolicyPrecedenceSource.TEMPLATE_DEFAULT ->
                RoleReasonCodes.ROLE_WORKFLOW_POLICY_PRECEDENCE_TEMPLATE_DEFAULT
        }
    }

    private fun isWithinAutomationWindow(
        window: WorkflowAutomationExecutionWindow?,
        now: Long
    ): Boolean {
        if (window == null) return true
        val zone = runCatching {
            java.time.ZoneId.of(window.timezone.ifBlank { "UTC" })
        }.getOrElse { java.time.ZoneOffset.UTC }
        val localNow = java.time.Instant.ofEpochMilli(now).atZone(zone)
        val minuteOfDay = localNow.hour * 60 + localNow.minute
        val dayOfWeek = localNow.dayOfWeek.value
        if (window.daysOfWeek.isNotEmpty() && !window.daysOfWeek.contains(dayOfWeek)) {
            return false
        }
        val start = window.startMinuteOfDay.coerceIn(0, 1439)
        val end = window.endMinuteOfDay.coerceIn(0, 1439)
        return if (start <= end) {
            minuteOfDay in start..end
        } else {
            minuteOfDay >= start || minuteOfDay <= end
        }
    }

    private fun isWorkflowTransitionAllowed(
        policy: WorkflowPolicyProfile,
        from: OperatorWorkflowStage?,
        to: OperatorWorkflowStage
    ): Boolean {
        if (from == null) return true
        val transition = policy.transitionPolicies.firstOrNull { it.from == from } ?: return true
        if (transition.allowedTo.isEmpty()) return true
        return transition.allowedTo.contains(to)
    }

    private fun workflowStageSummary(
        template: OperatorWorkflowTemplate,
        stage: OperatorWorkflowStage
    ): String {
        return template.stages
            .firstOrNull { it.stage == stage }
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: stage.name.lowercase().replace('_', ' ').replaceFirstChar { it.uppercase() }
    }

    private fun nextWorkflowActionForStage(
        template: OperatorWorkflowTemplate,
        stage: OperatorWorkflowStage
    ): WorkflowNextActionSuggestion? {
        val stageDefinition = template.stages.firstOrNull { it.stage == stage } ?: return null
        val actionTemplate = stageDefinition.recommendedActions.firstOrNull() ?: return null
        return WorkflowNextActionSuggestion(
            title = actionTemplate.summary.ifBlank {
                actionTemplate.action.name.lowercase().replace('_', ' ').replaceFirstChar { it.uppercase() }
            },
            detail = stageDefinition.summary,
            action = actionTemplate.action,
            automationEligible = actionTemplate.safeAutomationEligible
        )
    }

    private fun workflowRunStatusForStage(stage: OperatorWorkflowStage): OperatorWorkflowRunStatus {
        return when (stage) {
            OperatorWorkflowStage.RESOLVED -> OperatorWorkflowRunStatus.COMPLETED
            else -> OperatorWorkflowRunStatus.ACTIVE
        }
    }

    private fun collaborationStatusForWorkflowStage(
        stage: OperatorWorkflowStage,
        currentStatus: OperatorCollaborationStatus
    ): OperatorCollaborationStatus {
        return when (stage) {
            OperatorWorkflowStage.WAITING_PROVIDER,
            OperatorWorkflowStage.WAITING_SYNC,
            OperatorWorkflowStage.AWAITING_ESCALATION -> OperatorCollaborationStatus.FOLLOW_UP_PENDING

            OperatorWorkflowStage.RESOLVED -> OperatorCollaborationStatus.RESOLVED
            else -> if (currentStatus == OperatorCollaborationStatus.UNCLAIMED) {
                OperatorCollaborationStatus.REVIEW_IN_PROGRESS
            } else {
                currentStatus
            }
        }
    }

    private fun inferAutomationTriggerForState(
        state: GovernanceCaseCollaborationState,
        workflowRun: OperatorWorkflowRun?
    ): RemoteOpsAutomationTrigger {
        return when {
            state.escalation?.escalated == true -> RemoteOpsAutomationTrigger.ROLLBACK_FAILURE
            state.followUp?.ackPending == true -> RemoteOpsAutomationTrigger.PROVIDER_ISSUE
            workflowRun?.currentStage == OperatorWorkflowStage.WAITING_SYNC ->
                RemoteOpsAutomationTrigger.SYNC_PENDING
            workflowRun?.currentStage == OperatorWorkflowStage.AWAITING_ESCALATION ->
                RemoteOpsAutomationTrigger.ROLLBACK_FAILURE
            workflowRun?.currentStage == OperatorWorkflowStage.WAITING_PROVIDER ->
                RemoteOpsAutomationTrigger.PROVIDER_ISSUE
            state.status == OperatorCollaborationStatus.FOLLOW_UP_PENDING ->
                RemoteOpsAutomationTrigger.DISPUTE_FOLLOW_UP
            else -> RemoteOpsAutomationTrigger.SYNC_PENDING
        }
    }

    private fun isSafeAutomationAction(action: GovernanceActionType): Boolean {
        return action == GovernanceActionType.RETRY_SYNC_INTENT ||
            action == GovernanceActionType.ADD_NOTE
    }

    private fun buildOperatorAlertRoutingRecord(
        userId: String,
        runId: String,
        summary: String,
        command: GovernanceCollaborationCommand,
        operatorIdentity: OperatorIdentity,
        operatorResolution: OperatorResolution,
        remoteAuthorization: RemoteAuthorizationResult,
        preferredTargets: List<AlertRoutingTargetType> = emptyList(),
        now: Long
    ): AlertRoutingRecord {
        val targetTypes = if (preferredTargets.isEmpty()) {
            listOf(
                AlertRoutingTargetType.LOCAL_CONSOLE,
                AlertRoutingTargetType.SLACK_STUB,
                AlertRoutingTargetType.JIRA_STUB,
                AlertRoutingTargetType.ZENDESK_STUB,
                AlertRoutingTargetType.CRM_STUB,
                AlertRoutingTargetType.GENERIC_WEBHOOK
            )
        } else {
            (preferredTargets + AlertRoutingTargetType.LOCAL_CONSOLE).distinct()
        }
        val resourceSnapshot = synchronized(dynamicStateLock) {
            ensureRemoteResourcesInitializedLocked(userId)
            RemoteResourceSnapshot(
                routeBindings = connectorRouteBindingsByUser[userId]
                    ?.toList()
                    ?.sortedBy { it.priority }
                    .orEmpty(),
                destinations = connectorDestinationsByUser[userId]
                    ?.toList()
                    ?.sortedByDescending { it.updatedAtMs }
                    .orEmpty(),
                authProfiles = connectorAuthProfilesByUser[userId]
                    ?.toList()
                    ?.sortedByDescending { it.issuedAtMs ?: 0L }
                    .orEmpty()
            )
        }

        data class ResolvedRoutingTarget(
            val target: AlertRoutingTarget,
            val binding: ConnectorRouteBinding?,
            val destination: ConnectorDestination?,
            val authProfile: ConnectorAuthProfile?,
            val idpProviderConfig: EnterpriseIdpProviderConfig?,
            val idpSessionExchange: EnterpriseIdpSessionExchangeResult?,
            val idpProviderHealth: EnterpriseAuthProviderHealth?,
            val scimProviderConfig: ScimProviderConfig?,
            val scimProviderResult: DirectorySyncProviderResult?,
            val directorySyncCheckpoint: DirectorySyncCheckpoint?,
            val credentialLifecycle: ConnectorCredentialLifecycleSummary?,
            val vaultCredential: VaultCredentialReference?,
            val vaultProviderConfig: VaultProviderConfig?,
            val vaultResolution: VaultResolutionResult?,
            val vaultMaterialization: VaultMaterializationResult?,
            val vaultProviderHealth: VaultProviderHealth?,
            val vaultCredentialHealthCheck: VaultCredentialHealthCheckResult?,
            val vaultAccessAudit: VaultAccessAuditRecord?,
            val credentialBinding: ConnectorCredentialBinding?,
            val tenantRolloutProfile: TenantRolloutProfile?,
            val workspaceRolloutProfile: WorkspaceRolloutProfile?,
            val cutoverReadiness: CutoverReadinessSummary?,
            val fallbackPolicy: EnterpriseFallbackPolicy?,
            val featureGateDecision: FeatureGateDecision?,
            val degradationMode: ExecutionDegradationMode,
            val routeBlockReason: CredentialRouteBlockReason,
            val blockedByCredential: Boolean
        )

        val routingIdentitySource = remoteAuthorization.provenance?.identitySource
            ?: operatorResolution.identity.remoteDirectorySource
        val routingDirectoryStatus = remoteAuthorization.provenance?.directorySyncStatus
            ?: operatorResolution.directoryEntry?.directorySync?.status
            ?: DirectorySyncStatus.NOT_TRACKED
        val idpProvider = remoteAuthorization.sessionAuthContext?.idpProvider
            ?: remoteAuthorization.provenance?.idpProvider
            ?: idpProviderFor(routingIdentitySource)
        val idpProviderConfig = buildIdpProviderConfig(
            userId = userId,
            source = routingIdentitySource,
            provider = idpProvider,
            now = now
        )
        val idpSessionExchange = remoteAuthorization.sessionAuthContext?.idpSessionExchange
            ?: enterpriseIdpProviderPort.exchange(
                request = EnterpriseIdpSessionExchangeRequest(
                    requestId = "idp_exchange_${runId}_${now}",
                    runId = runId,
                    userId = userId,
                    operatorId = remoteAuthorization.operatorId.takeIf { it.isNotBlank() },
                    sessionRef = remoteAuthorization.sessionAuthContext?.sessionRef,
                    provider = idpProvider,
                    adapterType = idpProviderConfig?.adapterType ?: idpAdapterTypeFor(idpProvider),
                    allowFallback = remoteAuthorization.status != RemoteAuthorizationStatus.DENIED,
                    requestedAtMs = now
                ),
                config = idpProviderConfig,
                nowMs = now
            )
        val idpProviderHealth = remoteAuthorization.sessionAuthContext?.idpProviderHealth
            ?: enterpriseIdpProviderPort.health(idpProviderConfig, now)
        val scimProviderConfig = buildScimProviderConfig(
            userId = userId,
            source = routingIdentitySource,
            now = now
        )
        val routingDirectorySnapshot = operatorResolution.directoryEntry?.directorySync?.copy(
            status = routingDirectoryStatus,
            freshnessStatus = freshnessStatusForDirectorySync(routingDirectoryStatus),
            providerType = scimProviderConfig?.providerType ?: scimProviderTypeFor(routingIdentitySource),
            providerConfigId = scimProviderConfig?.configId
        ) ?: DirectorySyncSnapshot(
            snapshotId = "directory_sync_${userId.lowercase()}_$now",
            source = enterpriseSourceFor(routingIdentitySource),
            status = routingDirectoryStatus,
            freshnessStatus = freshnessStatusForDirectorySync(routingDirectoryStatus),
            providerType = scimProviderConfig?.providerType ?: scimProviderTypeFor(routingIdentitySource),
            providerConfigId = scimProviderConfig?.configId,
            syncedAtMs = operatorResolution.directoryEntry?.syncedAtMs?.takeIf { it > 0L },
            summary = "Directory sync state captured during connector routing."
        )
        val scimProviderResult = scimDirectoryProviderPort.evaluate(
            snapshot = routingDirectorySnapshot,
            config = scimProviderConfig,
            nowMs = now
        )
        val directorySyncCheckpoint = scimProviderResult.checkpoint
            ?: routingDirectorySnapshot.checkpoint

        val resolvedTargets = targetTypes.map { targetType ->
            val providerType = connectorProviderTypeFor(targetType)
            val binding = resolveRouteBindingForTarget(
                snapshot = resourceSnapshot,
                targetType = targetType,
                command = command
            )
            val destination = resolveConnectorDestinationForTarget(
                snapshot = resourceSnapshot,
                binding = binding,
                command = command,
                providerType = providerType,
                operatorResolution = operatorResolution
            )
            val authProfile = resolveConnectorAuthProfileForTarget(
                snapshot = resourceSnapshot,
                binding = binding,
                destination = destination,
                command = command,
                providerType = providerType
            )
            val credentialLifecycle = resolveConnectorCredentialLifecycle(
                authProfile = authProfile,
                destination = destination,
                now = now
            )
            val vaultCredential = resolveVaultCredentialReference(
                authProfile = authProfile,
                destination = destination,
                now = now
            )
            val vaultResolution = vaultRuntimePort.resolve(
                request = VaultResolutionRequest(
                    runId = runId,
                    targetType = targetType,
                    credentialRef = authProfile?.credentialRef ?: destination?.credentialRef,
                    vaultCredential = vaultCredential
                ),
                nowMs = now
            )
            val directoryStatus = scimProviderResult.status
            val tenantRolloutProfile = buildTenantRolloutProfile(
                userId = userId,
                targetType = targetType,
                binding = binding,
                destination = destination,
                authProfile = authProfile,
                now = now
            )
            val workspaceRolloutProfile = buildWorkspaceRolloutProfile(
                tenantProfile = tenantRolloutProfile,
                targetType = targetType,
                now = now
            )
            val cutoverReadiness = buildCutoverReadinessSummary(
                rolloutProfile = tenantRolloutProfile,
                workspaceProfile = workspaceRolloutProfile,
                directorySyncStatus = directoryStatus,
                remoteAuthorization = remoteAuthorization,
                vaultResolution = vaultResolution,
                now = now
            )
            val featureGateDecision = buildFeatureGateDecision(
                userId = userId,
                targetType = targetType,
                tenantProfile = tenantRolloutProfile,
                workspaceProfile = workspaceRolloutProfile,
                cutoverReadiness = cutoverReadiness
            )
            val fallbackPolicy = buildEnterpriseFallbackPolicy(featureGateDecision)
            val vaultProviderConfig = buildVaultProviderConfig(
                vaultCredential = vaultCredential,
                tenantRolloutProfile = tenantRolloutProfile,
                cutoverReadiness = cutoverReadiness,
                now = now
            )
            val vaultMaterialization = vaultProviderIntegrationPort.materialize(
                request = VaultMaterializationRequest(
                    requestId = "vault_materialization_${runId}_${targetType.name.lowercase()}_$now",
                    runId = runId,
                    targetType = targetType,
                    credentialId = authProfile?.credentialRef?.credentialId ?: destination?.credentialRef?.credentialId,
                    providerType = vaultProviderConfig?.providerType ?: vaultProviderTypeFor(vaultCredential?.vaultProvider),
                    rolloutStage = tenantRolloutProfile.stage,
                    cutoverStatus = cutoverReadiness.status,
                    requestedAtMs = now
                ),
                config = vaultProviderConfig,
                resolution = vaultResolution,
                nowMs = now
            )
            val vaultProviderHealth = vaultProviderIntegrationPort.health(
                config = vaultProviderConfig,
                resolution = vaultResolution,
                nowMs = now
            )
            val vaultCredentialHealthCheck = vaultProviderIntegrationPort.checkCredential(
                config = vaultProviderConfig,
                resolution = vaultResolution,
                nowMs = now
            )
            val routeBlockReason = credentialRouteBlockReasonFor(
                lifecycle = credentialLifecycle,
                vaultCredential = vaultCredential,
                directorySyncStatus = directoryStatus,
                remoteAuthorization = remoteAuthorization,
                idpSessionExchange = idpSessionExchange,
                scimProviderResult = scimProviderResult,
                vaultResolution = vaultResolution,
                vaultMaterialization = vaultMaterialization,
                featureGateDecision = featureGateDecision,
                cutoverReadiness = cutoverReadiness
            )
            val blockedByCredential = routeBlockReason != CredentialRouteBlockReason.NONE ||
                (credentialLifecycle?.state?.let(::isCredentialLifecycleBlocking) ?: false) ||
                vaultMaterialization.status == VaultMaterializationStatus.BLOCKED ||
                featureGateDecision.degradationMode != ExecutionDegradationMode.NONE
            val effectiveDestination = if (blockedByCredential) null else destination
            val effectiveAuthProfile = if (blockedByCredential) null else authProfile
            val fallbackLabel = "${targetType.name.lowercase().replace('_', ' ')} (fallback)"
            val blockedLabel = "${targetType.name.lowercase().replace('_', ' ')} (policy fallback)"
            val vaultAccessAudit = buildVaultAccessAuditRecord(
                runId = runId,
                targetType = targetType,
                resolution = vaultResolution,
                now = now
            )
            val credentialBinding = ConnectorCredentialBinding(
                bindingId = binding?.bindingId ?: "binding_${targetType.name.lowercase()}_$now",
                destinationId = destination?.destinationId,
                authProfileId = authProfile?.authProfileId ?: destination?.authProfileId,
                credentialRef = authProfile?.credentialRef ?: destination?.credentialRef,
                vaultCredential = vaultCredential,
                status = authProfile?.status
                    ?: destination?.credentialRef?.status
                    ?: ConnectorCredentialStatus.UNKNOWN,
                blockReason = routeBlockReason,
                vaultResolution = vaultResolution,
                summary = buildString {
                    append("Credential binding ")
                    append(if (blockedByCredential) "blocked" else "ready")
                    append(" for ")
                    append(targetType.name.lowercase().replace('_', ' '))
                    if (routeBlockReason != CredentialRouteBlockReason.NONE) {
                        append(" (")
                        append(routeBlockReason.name.lowercase().replace('_', ' '))
                        append(")")
                    }
                },
                updatedAtMs = now
            )
            ResolvedRoutingTarget(
                target = AlertRoutingTarget(
                    targetId = effectiveDestination?.destinationId ?: "fallback_${targetType.name.lowercase()}",
                    label = when {
                        blockedByCredential -> blockedLabel
                        effectiveDestination != null -> effectiveDestination.label
                        else -> fallbackLabel
                    },
                    targetType = targetType,
                    endpointHint = effectiveDestination?.endpointHint,
                    connectorProviderType = providerType,
                    credentialRef = effectiveAuthProfile?.credentialRef ?: effectiveDestination?.credentialRef,
                    credentialLifecycle = credentialLifecycle,
                    credentialRouteBlockReason = routeBlockReason,
                    featureGateDecision = featureGateDecision,
                    degradationMode = featureGateDecision.degradationMode,
                    vaultResolution = vaultResolution,
                    vaultMaterialization = vaultMaterialization,
                    vaultProviderHealth = vaultProviderHealth,
                    idpSessionExchange = idpSessionExchange,
                    scimProviderResult = scimProviderResult,
                    vaultAccessAudit = vaultAccessAudit,
                    credentialBinding = credentialBinding,
                    destinationId = effectiveDestination?.destinationId,
                    authProfileId = effectiveAuthProfile?.authProfileId ?: effectiveDestination?.authProfileId,
                    routeBindingId = binding?.bindingId
                ),
                binding = binding,
                destination = destination,
                authProfile = authProfile,
                idpProviderConfig = idpProviderConfig,
                idpSessionExchange = idpSessionExchange,
                idpProviderHealth = idpProviderHealth,
                scimProviderConfig = scimProviderConfig,
                scimProviderResult = scimProviderResult,
                directorySyncCheckpoint = directorySyncCheckpoint,
                credentialLifecycle = credentialLifecycle,
                vaultCredential = vaultCredential,
                vaultProviderConfig = vaultProviderConfig,
                vaultResolution = vaultResolution,
                vaultMaterialization = vaultMaterialization,
                vaultProviderHealth = vaultProviderHealth,
                vaultCredentialHealthCheck = vaultCredentialHealthCheck,
                vaultAccessAudit = vaultAccessAudit,
                credentialBinding = credentialBinding,
                tenantRolloutProfile = tenantRolloutProfile,
                workspaceRolloutProfile = workspaceRolloutProfile,
                cutoverReadiness = cutoverReadiness,
                fallbackPolicy = fallbackPolicy,
                featureGateDecision = featureGateDecision,
                degradationMode = featureGateDecision.degradationMode,
                routeBlockReason = routeBlockReason,
                blockedByCredential = blockedByCredential
            )
        }

        val attempts = resolvedTargets.map { resolved ->
            val target = resolved.target
            val dedupeKey = "alert_route:${runId}:GOVERNANCE_ALERT_OPERATOR_FOLLOW_UP:${target.targetType.name.lowercase()}"
            val attemptSummary = if (resolved.blockedByCredential) {
                routeBlockSummaryFor(
                    reason = resolved.routeBlockReason,
                    lifecycle = resolved.credentialLifecycle,
                    vaultCredential = resolved.vaultCredential,
                    featureGateDecision = resolved.featureGateDecision,
                    cutoverReadiness = resolved.cutoverReadiness
                )
            } else {
                summary
            }
            alertRoutingPort.route(
                runId = runId,
                alertCode = "GOVERNANCE_ALERT_OPERATOR_FOLLOW_UP",
                target = target,
                dedupeKey = dedupeKey,
                summary = attemptSummary,
                authorization = remoteAuthorization,
                requestedByOperator = operatorIdentity,
                nowMs = now
            ).copy(
                credentialRouteBlockReason = resolved.routeBlockReason,
                degradationMode = resolved.degradationMode,
                vaultResolution = resolved.vaultResolution,
                vaultMaterialization = resolved.vaultMaterialization,
                idpSessionExchange = resolved.idpSessionExchange,
                scimProviderResult = resolved.scimProviderResult
            )
        }
        val status = when {
            attempts.any { it.status == AlertRoutingStatus.FAILED } -> AlertRoutingStatus.FAILED
            attempts.any { it.status == AlertRoutingStatus.QUEUED } -> AlertRoutingStatus.QUEUED
            attempts.any { it.status == AlertRoutingStatus.LOCAL_ONLY } -> AlertRoutingStatus.LOCAL_ONLY
            attempts.any { it.status == AlertRoutingStatus.DUPLICATE_SUPPRESSED } -> AlertRoutingStatus.DUPLICATE_SUPPRESSED
            else -> AlertRoutingStatus.DELIVERED
        }
        val deliveryRecords = buildConnectorDeliveryRecordsFromAttempts(
            runId = runId,
            alertCode = "GOVERNANCE_ALERT_OPERATOR_FOLLOW_UP",
            attempts = attempts
        )
        val deadLetterRecords = deliveryRecords.mapNotNull { it.deadLetter }
        val connectorHealthSummary = buildConnectorHealthSummaryFromAttempts(
            attempts = attempts,
            deadLetterCount = deadLetterRecords.size,
            now = now
        )
        val resolvedBindings = resolvedTargets
            .mapNotNull { it.binding }
            .distinctBy { it.bindingId }
        val resolvedDestinations = resolvedTargets
            .mapNotNull { it.destination }
            .distinctBy { it.destinationId }
        val resolvedAuthProfiles = resolvedTargets
            .mapNotNull { it.authProfile }
            .distinctBy { it.authProfileId }
        val credentialLifecycleSummaries = resolvedTargets
            .mapNotNull { it.credentialLifecycle }
            .distinctBy { "${it.state}:${it.expiresAtMs}:${it.rotationRequired}:${it.revoked}" }
        val directoryStatus = remoteAuthorization.provenance?.directorySyncStatus
            ?: operatorResolution.directoryEntry?.directorySync?.status
            ?: DirectorySyncStatus.NOT_TRACKED
        val directoryErrorState = directorySyncErrorStateFor(
            status = directoryStatus,
            lastError = operatorResolution.directoryEntry?.directorySync?.lastError
                ?: remoteAuthorization.reason
        )
        val directorySyncSnapshot = operatorResolution.directoryEntry?.directorySync
            ?: DirectorySyncSnapshot(
                snapshotId = "directory_sync_${userId.lowercase()}_$now",
                source = enterpriseSourceFor(operatorResolution.identity.remoteDirectorySource),
                status = directoryStatus,
                errorState = directoryErrorState,
                freshnessStatus = scimProviderResult.freshnessStatus,
                providerType = scimProviderResult.providerType,
                providerConfigId = scimProviderConfig?.configId,
                providerHealth = scimProviderResult.health,
                providerResult = scimProviderResult,
                checkpoint = directorySyncCheckpoint,
                directoryVersion = operatorResolution.directoryEntry?.identity?.directoryVersion,
                syncedAtMs = operatorResolution.directoryEntry?.syncedAtMs?.takeIf { it > 0 },
                lastUpdate = DirectorySyncUpdate(
                    updateId = "directory_update_${userId.lowercase()}_$now",
                    updateType = DirectorySyncUpdateType.SCIM_WEBHOOK,
                    status = directoryStatus,
                    errorState = directoryErrorState,
                    receivedAtMs = remoteAuthorization.evaluatedAtMs.takeIf { it > 0 } ?: now,
                    processedAtMs = now,
                    summary = "Directory sync state was captured during connector routing."
                ),
                summary = "Directory sync state was captured during connector routing."
            )
        val enterpriseAuthIntegration = buildEnterpriseAuthIntegrationSummary(
            remoteAuthorization = remoteAuthorization,
            directorySyncSnapshot = directorySyncSnapshot,
            targets = resolvedTargets.map { it.target },
            idpProviderConfig = idpProviderConfig,
            idpSessionExchange = idpSessionExchange,
            idpProviderHealth = idpProviderHealth,
            scimProviderConfig = scimProviderConfig,
            scimProviderResult = scimProviderResult,
            directorySyncCheckpoint = directorySyncCheckpoint,
            tenantRolloutProfile = resolvedTargets.mapNotNull { it.tenantRolloutProfile }.maxByOrNull { it.updatedAtMs },
            workspaceRolloutProfile = resolvedTargets.mapNotNull { it.workspaceRolloutProfile }.maxByOrNull { it.updatedAtMs },
            cutoverReadiness = resolvedTargets.mapNotNull { it.cutoverReadiness }.maxByOrNull { it.updatedAtMs },
            fallbackPolicy = resolvedTargets.mapNotNull { it.fallbackPolicy }.lastOrNull(),
            vaultProviderConfig = resolvedTargets.mapNotNull { it.vaultProviderConfig }.lastOrNull(),
            vaultMaterialization = resolvedTargets.mapNotNull { it.vaultMaterialization }.lastOrNull(),
            vaultProviderHealth = resolvedTargets.mapNotNull { it.vaultProviderHealth }.lastOrNull(),
            vaultCredentialHealthCheck = resolvedTargets.mapNotNull { it.vaultCredentialHealthCheck }.lastOrNull(),
            vaultResolution = resolvedTargets.mapNotNull { it.vaultResolution }.lastOrNull(),
            vaultHealth = buildVaultHealthSummary(resolvedTargets.mapNotNull { it.vaultResolution }, now),
            now = now
        )
        val rolloutProfile = resolvedTargets.mapNotNull { it.tenantRolloutProfile }.maxByOrNull { it.updatedAtMs }
        val workspaceProfile = resolvedTargets.mapNotNull { it.workspaceRolloutProfile }.maxByOrNull { it.updatedAtMs }
        val cutoverReadiness = resolvedTargets.mapNotNull { it.cutoverReadiness }.maxByOrNull { it.updatedAtMs }
        val fallbackPolicy = resolvedTargets.mapNotNull { it.fallbackPolicy }.lastOrNull()
        val vaultResolutions = resolvedTargets.mapNotNull { it.vaultResolution }
        val vaultMaterializationResults = resolvedTargets.mapNotNull { it.vaultMaterialization }
            .distinctBy { "${it.providerType}:${it.status}:${it.summary}" }
        val vaultCredentialHealthChecks = resolvedTargets.mapNotNull { it.vaultCredentialHealthCheck }
            .distinctBy { "${it.providerType}:${it.status}:${it.materialState}" }
        val vaultAudit = resolvedTargets.mapNotNull { it.vaultAccessAudit }
        val vaultHealth = buildVaultHealthSummary(vaultResolutions, now)
        return AlertRoutingRecord(
            recordId = "alert_routing_${runId}_$now",
            runId = runId,
            alertCode = "GOVERNANCE_ALERT_OPERATOR_FOLLOW_UP",
            status = status,
            dedupeKey = "alert_route:${runId}:GOVERNANCE_ALERT_OPERATOR_FOLLOW_UP",
            targets = resolvedTargets.map { it.target },
            attempts = attempts,
            deliveryRecords = deliveryRecords,
            deadLetterRecords = deadLetterRecords,
            connectorHealthSummary = connectorHealthSummary,
            routeBindings = resolvedBindings,
            destinations = resolvedDestinations,
            authProfiles = resolvedAuthProfiles,
            idpProviderConfig = idpProviderConfig,
            idpSessionExchange = idpSessionExchange,
            idpProviderHealth = idpProviderHealth,
            scimProviderConfig = scimProviderConfig,
            scimProviderResult = scimProviderResult,
            directorySyncCheckpoint = directorySyncCheckpoint,
            vaultProviderConfig = resolvedTargets.mapNotNull { it.vaultProviderConfig }.lastOrNull(),
            authorization = remoteAuthorization,
            credentialLifecycleSummaries = credentialLifecycleSummaries,
            tenantRolloutProfile = rolloutProfile,
            workspaceRolloutProfile = workspaceProfile,
            cutoverReadiness = cutoverReadiness,
            fallbackPolicy = fallbackPolicy,
            vaultHealth = vaultHealth,
            vaultProviderHealth = resolvedTargets.mapNotNull { it.vaultProviderHealth }.lastOrNull(),
            vaultMaterializationResults = vaultMaterializationResults,
            vaultCredentialHealthChecks = vaultCredentialHealthChecks,
            vaultResolutions = vaultResolutions,
            vaultAccessAudit = vaultAudit,
            directorySync = directorySyncSnapshot,
            enterpriseAuthIntegration = enterpriseAuthIntegration,
            lastAttemptAtMs = now,
            deliveredAtMs = if (status == AlertRoutingStatus.DELIVERED) now else null,
            lastErrorSummary = attempts.firstOrNull { it.status == AlertRoutingStatus.FAILED }?.summary
        )
    }

    private fun appendRoutingActions(
        existing: List<GovernanceRoutingActionRecord>,
        record: AlertRoutingRecord,
        actor: OperatorAssigneeRef,
        actionType: GovernanceRoutingActionType,
        summary: String,
        now: Long
    ): List<GovernanceRoutingActionRecord> {
        val normalizedTargets = if (record.targets.isNotEmpty()) {
            record.targets
        } else {
            record.attempts.map { attempt ->
                AlertRoutingTarget(
                    targetId = attempt.targetId,
                    label = attempt.targetType.name.lowercase().replace('_', ' '),
                    targetType = attempt.targetType,
                    connectorProviderType = connectorProviderTypeFor(attempt.targetType)
                )
            }
        }
            .distinctBy { "${it.targetId}:${it.targetType}" }

        val routingActions = normalizedTargets.map { target ->
            val providerType = target.connectorProviderType ?: connectorProviderTypeFor(target.targetType)
            val delivery = record.deliveryRecords.lastOrNull { delivery ->
                delivery.target.targetId == target.targetId && delivery.target.providerType == providerType
            }
            val deadLetter = record.deadLetterRecords.lastOrNull { dead ->
                dead.targetId == target.targetId && dead.providerType == providerType
            }
            val reasonCodes = mutableListOf(RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_REQUESTED)
            reasonCodes += if (record.status == AlertRoutingStatus.FAILED) {
                RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
            } else {
                RoleReasonCodes.ROLE_CONNECTOR_ROUTE_SELECTED
            }
            if (delivery?.status == ConnectorDeliveryStatus.ACKNOWLEDGED || delivery?.status == ConnectorDeliveryStatus.DELIVERED) {
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
            }
            if (
                delivery?.status == ConnectorDeliveryStatus.LOCAL_ONLY ||
                delivery?.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE
            ) {
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE
            }
            if (deadLetter != null || delivery?.status == ConnectorDeliveryStatus.DEAD_LETTER) {
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_HEALTH_DEGRADED
            }
            when (target.credentialLifecycle?.state) {
                ConnectorCredentialLifecycleState.HEALTHY -> {
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_HEALTHY
                }
                ConnectorCredentialLifecycleState.EXPIRING -> {
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_EXPIRING
                }
                ConnectorCredentialLifecycleState.REVOKED -> {
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_REVOKED
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
                }
                ConnectorCredentialLifecycleState.ROTATION_REQUIRED -> {
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_ROTATION_REQUIRED
                }
                ConnectorCredentialLifecycleState.EXPIRED,
                ConnectorCredentialLifecycleState.MISCONFIGURED -> {
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
                }
                ConnectorCredentialLifecycleState.UNKNOWN,
                null -> Unit
            }
            val actionSeed = "${record.runId}:${record.alertCode}:${actionType.name}:${target.targetId}:${record.dedupeKey}"
            val actionId = "routing_action_${actionSeed.hashCode().toString().replace('-', 'n')}"
            GovernanceRoutingActionRecord(
                actionId = actionId,
                actionType = actionType,
                actor = actor,
                targetType = target.targetType,
                connectorProviderType = providerType,
                summary = deadLetter?.summary
                    ?: delivery?.lastFailureReason
                        ?.name
                        ?.lowercase()
                        ?.replace('_', ' ')
                        ?.let { "Connector delivery state: $it." }
                    ?: target.credentialLifecycle
                        ?.let { lifecycle ->
                            lifecycle.summary.takeIf {
                                it.isNotBlank() && isCredentialLifecycleBlocking(lifecycle.state)
                            }
                        }
                    ?: summary,
                reasonCodes = reasonCodes.distinct(),
                timestampMs = now
            )
        }

        return (existing + routingActions)
            .distinctBy { it.actionId }
            .sortedBy { it.timestampMs }
            .takeLast(30)
    }

    private fun deadLetterSummaryForRouting(
        routing: List<AlertRoutingRecord>,
        connectorSummary: ConnectorRoutingSummary?,
        deadLetters: List<ConnectorDeadLetterRecord>
    ): String? {
        val normalizedDeadLetters = deadLetters
            .ifEmpty { routing.flatMap { it.deadLetterRecords } }
            .distinctBy { "${it.targetId}:${it.providerType}:${it.dedupeKey}:${it.createdAtMs}" }
        val deadLetterCount = maxOf(
            normalizedDeadLetters.size,
            connectorSummary?.deadLetterTargets ?: 0
        )
        if (deadLetterCount <= 0) {
            val unavailableTargets = maxOf(
                connectorSummary?.unavailableTargets ?: 0,
                routing.sumOf { record ->
                    record.deliveryRecords.count { delivery ->
                        delivery.status == ConnectorDeliveryStatus.LOCAL_ONLY ||
                            delivery.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE
                    }
                }
            )
            return if (unavailableTargets > 0) {
                "$unavailableTargets connector target(s) are unavailable; no dead-letter records yet."
            } else {
                null
            }
        }
        val providerSummary = normalizedDeadLetters
            .map { it.providerType.name.lowercase().replace('_', ' ') }
            .distinct()
            .joinToString(", ")
        val latestSummary = normalizedDeadLetters
            .maxByOrNull { it.createdAtMs }
            ?.summary
            ?.takeIf { it.isNotBlank() }
        return buildString {
            append("$deadLetterCount connector dead-letter event(s) recorded")
            if (providerSummary.isNotBlank()) {
                append(" across $providerSummary")
            }
            append('.')
            if (latestSummary != null) {
                append(" Latest: $latestSummary")
            }
        }
    }

    private fun connectorProviderTypeFor(targetType: AlertRoutingTargetType): ConnectorProviderType {
        return when (targetType) {
            AlertRoutingTargetType.LOCAL_CONSOLE -> ConnectorProviderType.LOCAL_CONSOLE
            AlertRoutingTargetType.SLACK_DESTINATION,
            AlertRoutingTargetType.SLACK_STUB -> ConnectorProviderType.SLACK
            AlertRoutingTargetType.JIRA_DESTINATION,
            AlertRoutingTargetType.JIRA_STUB,
            AlertRoutingTargetType.TICKET_STUB -> ConnectorProviderType.JIRA
            AlertRoutingTargetType.ZENDESK_DESTINATION,
            AlertRoutingTargetType.ZENDESK_STUB -> ConnectorProviderType.ZENDESK
            AlertRoutingTargetType.CRM_DESTINATION,
            AlertRoutingTargetType.CRM_STUB -> ConnectorProviderType.CRM
            AlertRoutingTargetType.GENERIC_WEBHOOK,
            AlertRoutingTargetType.WEBHOOK_STUB,
            AlertRoutingTargetType.EMAIL_STUB -> ConnectorProviderType.WEBHOOK
        }
    }

    private fun GovernanceCollaborationCommand.toActor(): OperatorAssigneeRef {
        val identity = operatorIdentity
        val userId = (identity?.userId ?: actorUserId).trim().ifBlank { "local-user" }
        val displayName = (identity?.displayName ?: actorDisplayName).trim().ifBlank { "Local Operator" }
        return OperatorAssigneeRef(userId = userId, displayName = displayName)
    }

    private fun resolveOperatorIdentity(
        command: GovernanceCollaborationCommand? = null,
        fallbackUserId: String
    ): OperatorIdentity {
        return resolveOperatorContext(command = command, fallbackUserId = fallbackUserId).identity
    }

    private fun resolveOperatorContext(
        command: GovernanceCollaborationCommand? = null,
        fallbackUserId: String
    ): OperatorResolution {
        val preferred = command?.operatorIdentity
        val requestedUserId = preferred?.userId
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: command?.actorUserId
                ?.trim()
                ?.takeIf { it.isNotBlank() }
            ?: fallbackUserId.trim().ifBlank { "local-user" }
        val requestedDisplay = preferred?.displayName
            ?.trim()
            ?.takeIf { it.isNotBlank() }
            ?: command?.actorDisplayName
                ?.trim()
                ?.takeIf { it.isNotBlank() }
            ?: defaultOperatorDisplayName(requestedUserId)
        val remoteAuthContext = command?.remoteAuthorizationContext
        val directoryEntry = synchronized(dynamicStateLock) {
            ensureRemoteResourcesInitializedLocked(fallbackUserId)
            ensureRemoteDirectoryEntryForActorLocked(
                userId = fallbackUserId,
                actorUserId = requestedUserId,
                displayName = requestedDisplay
            )
            resolveDirectoryEntryLocked(
                userId = fallbackUserId,
                actorUserId = requestedUserId,
                requestedOperatorId = preferred?.remoteOperatorId ?: remoteAuthContext?.operatorId,
                requestedTeamId = preferred?.remoteTeamId ?: remoteAuthContext?.teamId
            )
        }
        val remoteIdentity = directoryEntry?.identity
        val remoteTeam = directoryEntry?.team
        val role = preferred?.role
            ?: remoteIdentity?.role
            ?: defaultOperatorRole(requestedUserId)
        val permissions = (
            preferred?.permissions?.takeIf { it.isNotEmpty() }
                ?: remoteIdentity?.permissions?.takeIf { it.isNotEmpty() }
                ?: (defaultPermissionsForRole(role) + remoteTeam?.permissionDefaults.orEmpty())
            ).distinct()
        val scope = preferred?.scope ?: remoteIdentity?.scope ?: PermissionScope.ANY_CASE
        val identity = OperatorIdentity(
            userId = requestedUserId,
            displayName = remoteIdentity?.displayName?.takeIf { it.isNotBlank() } ?: requestedDisplay,
            role = role,
            permissions = permissions,
            scope = scope,
            remoteOperatorId = remoteIdentity?.operatorId ?: preferred?.remoteOperatorId,
            remoteTeamId = remoteIdentity?.teamId ?: preferred?.remoteTeamId,
            remoteDirectoryEntryId = directoryEntry?.entryId ?: preferred?.remoteDirectoryEntryId,
            remoteDirectorySource = remoteIdentity?.directorySource ?: preferred?.remoteDirectorySource,
            enterpriseIdentityId = remoteIdentity?.enterpriseIdentityId ?: preferred?.enterpriseIdentityId,
            enterpriseDirectorySource = remoteIdentity?.enterpriseDirectorySource
                ?: preferred?.enterpriseDirectorySource
                ?: EnterpriseDirectorySource.LOCAL_ONLY
        )
        return OperatorResolution(
            identity = identity,
            directoryEntry = directoryEntry,
            remoteTeam = remoteTeam
        )
    }

    private fun ensureRemoteDirectoryEntryForActorLocked(
        userId: String,
        actorUserId: String,
        displayName: String
    ): RemoteOperatorDirectoryEntry {
        val queue = remoteOperatorDirectoryByUser.getOrPut(userId) { ArrayDeque() }
        val existing = queue.lastOrNull {
            it.userId.equals(actorUserId, ignoreCase = true) ||
                it.identity.operatorId.equals(actorUserId, ignoreCase = true)
        }
        if (existing != null) return existing
        val now = nowMs()
        val role = defaultOperatorRole(actorUserId)
        val team = RemoteOperatorTeam(
            teamId = "team_local_ops",
            displayName = "Local Ops",
            slug = "local-ops",
            permissionDefaults = defaultPermissionsForRole(role),
            updatedAtMs = now
        )
        val created = RemoteOperatorDirectoryEntry(
            entryId = "directory_${userId.lowercase()}_${actorUserId.lowercase()}_$now",
            userId = actorUserId,
            identity = RemoteOperatorIdentity(
                operatorId = "op_${actorUserId.lowercase()}",
                displayName = displayName,
                teamId = team.teamId,
                role = role,
                permissions = defaultPermissionsForRole(role),
                scope = PermissionScope.ANY_CASE,
                active = true,
                directorySource = RemoteOperatorDirectorySource.LOCAL_FALLBACK,
                directoryVersion = "local_fallback_v1",
                enterpriseIdentityId = "ent_${actorUserId.lowercase()}",
                enterpriseDirectorySource = EnterpriseDirectorySource.LOCAL_ONLY,
                enterpriseDirectoryVersion = "local_only_v1",
                scimRecord = ScimLikeDirectoryRecord(
                    recordId = "scim_${actorUserId.lowercase()}",
                    externalId = actorUserId,
                    userName = actorUserId,
                    active = true,
                    teamIds = listOf(team.teamId),
                    sourceVersion = "local_scim_v1",
                    lastSyncedAtMs = now,
                    summary = "Local fallback directory record is active."
                ),
                updatedAtMs = now
            ),
            team = team,
            version = 1,
            syncedAtMs = now,
            directorySync = DirectorySyncSnapshot(
                snapshotId = "directory_sync_${actorUserId.lowercase()}_$now",
                source = EnterpriseDirectorySource.LOCAL_ONLY,
                status = DirectorySyncStatus.NOT_TRACKED,
                errorState = DirectorySyncErrorState.NONE,
                directoryVersion = "local_fallback_v1",
                syncedAtMs = now,
                lastUpdate = DirectorySyncUpdate(
                    updateId = "directory_update_${actorUserId.lowercase()}_$now",
                    updateType = DirectorySyncUpdateType.MANUAL_REFRESH,
                    status = DirectorySyncStatus.NOT_TRACKED,
                    errorState = DirectorySyncErrorState.NONE,
                    receivedAtMs = now,
                    processedAtMs = now,
                    summary = "Local fallback directory update recorded."
                ),
                summary = "Local fallback directory context is active."
            ),
            remoteIdentityLink = RemoteIdentityLink(
                operatorId = "op_${actorUserId.lowercase()}",
                directoryEntryId = "directory_${userId.lowercase()}_${actorUserId.lowercase()}_$now",
                status = RemoteIdentityLinkStatus.LOCAL_ONLY,
                source = EnterpriseDirectorySource.LOCAL_ONLY,
                identityAssertion = EnterpriseIdentityAssertion(
                    assertionId = "assertion_local_${actorUserId.lowercase()}_$now",
                    idpProvider = EnterpriseIdpProvider.UNKNOWN,
                    subjectId = actorUserId,
                    assertedAtMs = now,
                    summary = "No enterprise SSO assertion was provided; local fallback identity is active."
                ),
                linkedAtMs = now,
                summary = "No remote enterprise directory link is configured."
            )
        )
        queue.addLast(created)
        while (queue.size > MAX_REMOTE_PIPELINE_RECORDS) {
            queue.removeFirst()
        }
        return created
    }

    private fun resolveDirectoryEntryLocked(
        userId: String,
        actorUserId: String,
        requestedOperatorId: String? = null,
        requestedTeamId: String? = null
    ): RemoteOperatorDirectoryEntry? {
        val queue = remoteOperatorDirectoryByUser[userId] ?: return null
        val entries = queue.toList()
        val normalizedOperatorId = requestedOperatorId?.trim()?.takeIf { it.isNotBlank() }
        val normalizedTeamId = requestedTeamId?.trim()?.takeIf { it.isNotBlank() }

        if (normalizedOperatorId != null) {
            val byOperatorId = entries.lastOrNull { entry ->
                entry.identity.operatorId.equals(normalizedOperatorId, ignoreCase = true) && entry.identity.active
            }
            if (byOperatorId != null) return byOperatorId
        }
        if (normalizedTeamId != null) {
            val byTeam = entries.lastOrNull { entry ->
                (entry.identity.teamId ?: entry.team?.teamId).equals(normalizedTeamId, ignoreCase = true) &&
                    entry.identity.active
            }
            if (byTeam != null) return byTeam
        }
        return entries.lastOrNull { entry ->
            (
                entry.userId.equals(actorUserId, ignoreCase = true) ||
                    entry.identity.operatorId.equals(actorUserId, ignoreCase = true)
                ) && entry.identity.active
        } ?: entries.lastOrNull { it.identity.active }
    }

    private fun buildOperatorSessionSummary(
        identity: OperatorIdentity,
        now: Long,
        remoteAuthorization: RemoteAuthorizationResult? = null
    ): OperatorSessionSummary {
        val resolvedDirectoryStatus = remoteAuthorization?.provenance?.directorySyncStatus
            ?: DirectorySyncStatus.NOT_TRACKED
        val resolvedSessionProvenance = remoteAuthorization?.provenance?.sessionProvenance
            ?: sessionProvenanceFor(
                source = identity.remoteDirectorySource,
                directorySyncStatus = resolvedDirectoryStatus,
                usedFallback = remoteAuthorization?.provenance?.usedFallback == true
            )
        val resolvedIdpProvider = remoteAuthorization?.provenance?.idpProvider
            ?: idpProviderFor(identity.remoteDirectorySource)
        val identityAssertion = remoteAuthorization?.provenance?.identityAssertion
            ?: remoteAuthorization?.sessionAuthContext?.identityAssertion
            ?: buildIdentityAssertion(
                identity = identity,
                idpProvider = resolvedIdpProvider,
                now = now
            )
        val directorySync = remoteAuthorization?.provenance?.directorySyncStatus?.let { status ->
            DirectorySyncSnapshot(
                snapshotId = "directory_sync_${identity.userId.lowercase()}_$now",
                source = enterpriseSourceFor(identity.remoteDirectorySource),
                status = status,
                errorState = directorySyncErrorStateFor(status = status),
                directoryVersion = null,
                syncedAtMs = remoteAuthorization.evaluatedAtMs.takeIf { it > 0 } ?: now,
                lastUpdate = DirectorySyncUpdate(
                    updateId = "directory_update_${identity.userId.lowercase()}_$now",
                    updateType = DirectorySyncUpdateType.SCIM_WEBHOOK,
                    status = status,
                    errorState = directorySyncErrorStateFor(status = status),
                    receivedAtMs = remoteAuthorization.evaluatedAtMs.takeIf { it > 0 } ?: now,
                    processedAtMs = now,
                    summary = "Directory sync update was captured from remote authorization provenance."
                ),
                summary = when (status) {
                    DirectorySyncStatus.SYNCED -> "Directory sync is current for this operator context."
                    DirectorySyncStatus.SYNC_PENDING -> "Directory sync is pending; local policy remains authoritative."
                    DirectorySyncStatus.STALE -> "Directory sync is stale; fallback guardrails are active."
                    DirectorySyncStatus.FAILED -> "Directory sync failed; local policy fallback is active."
                    DirectorySyncStatus.DIRECTORY_UNAVAILABLE -> "Directory service unavailable; local policy fallback is active."
                    DirectorySyncStatus.NOT_TRACKED -> "Directory sync metadata is not tracked for this session."
                }
            )
        }
        val identityLink = RemoteIdentityLink(
            operatorId = identity.remoteOperatorId.orEmpty(),
            directoryEntryId = identity.remoteDirectoryEntryId,
            status = when {
                identity.remoteOperatorId.isNullOrBlank() -> RemoteIdentityLinkStatus.LOCAL_ONLY
                directorySync?.status == DirectorySyncStatus.STALE -> RemoteIdentityLinkStatus.STALE
                directorySync?.status == DirectorySyncStatus.FAILED ||
                    directorySync?.status == DirectorySyncStatus.DIRECTORY_UNAVAILABLE -> RemoteIdentityLinkStatus.INVALID
                else -> RemoteIdentityLinkStatus.LINKED
            },
            source = enterpriseSourceFor(identity.remoteDirectorySource),
            identityAssertion = identityAssertion,
            linkedAtMs = now,
            summary = if (identity.remoteOperatorId.isNullOrBlank()) {
                "Operator session is local-only; no remote directory link was applied."
            } else {
                "Operator session is linked to remote identity ${identity.remoteOperatorId}."
            }
        )
        val identityProvenance = OperatorIdentityProvenance(
            identitySource = identity.remoteDirectorySource,
            enterpriseSource = enterpriseSourceFor(identity.remoteDirectorySource),
            directorySync = directorySync,
            remoteIdentityLink = identityLink,
            summary = when (identity.remoteDirectorySource) {
                RemoteOperatorDirectorySource.REMOTE_LIVE ->
                    "Identity was resolved from live remote directory data."
                RemoteOperatorDirectorySource.REMOTE_CACHE ->
                    "Identity was resolved from cached remote directory data."
                RemoteOperatorDirectorySource.LOCAL_FALLBACK, null ->
                    "Identity was resolved from local fallback context."
            }
        )
        val authContext = remoteAuthorization?.sessionAuthContext ?: SessionAuthContext(
            sessionRef = null,
            authority = remoteAuthorization?.provenance?.authority
                ?: sessionAuthorityFor(identity.remoteDirectorySource, usedFallback = false),
            sessionProvenance = resolvedSessionProvenance,
            idpProvider = resolvedIdpProvider,
            identityAssertion = identityAssertion,
            freshness = remoteAuthorization?.provenance?.sessionFreshness
                ?: sessionFreshnessFor(
                    directorySyncStatus = directorySync?.status ?: DirectorySyncStatus.NOT_TRACKED
                ),
            issuedAtMs = now,
            validatedAtMs = now,
            summary = remoteAuthorization?.provenance?.summary
                ?: "Session authority was resolved from local operator context."
        )
        val source = when (identity.remoteDirectorySource) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> "remote-directory-live"
            RemoteOperatorDirectorySource.REMOTE_CACHE -> "remote-directory-cache"
            RemoteOperatorDirectorySource.LOCAL_FALLBACK -> "remote-directory-local-fallback"
            null -> "local-user"
        }
        return OperatorSessionSummary(
            identity = identity,
            authenticated = remoteAuthorization?.allowed ?: true,
            source = source,
            issuedAtMs = now,
            authContext = authContext,
            identityProvenance = identityProvenance,
            directorySync = directorySync,
            remoteIdentityLink = identityLink,
            remoteAuthorization = remoteAuthorization
        )
    }

    private fun enterpriseSourceFor(source: RemoteOperatorDirectorySource?): EnterpriseDirectorySource {
        return when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> EnterpriseDirectorySource.ENTERPRISE_DIRECTORY_LIVE
            RemoteOperatorDirectorySource.REMOTE_CACHE -> EnterpriseDirectorySource.ENTERPRISE_DIRECTORY_CACHE
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> EnterpriseDirectorySource.LOCAL_ONLY
        }
    }

    private fun idpProviderFor(source: RemoteOperatorDirectorySource?): EnterpriseIdpProvider {
        return when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> EnterpriseIdpProvider.OKTA
            RemoteOperatorDirectorySource.REMOTE_CACHE -> EnterpriseIdpProvider.CUSTOM
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> EnterpriseIdpProvider.UNKNOWN
        }
    }

    private fun idpAdapterTypeFor(provider: EnterpriseIdpProvider?): EnterpriseIdpAdapterType {
        return when (provider ?: EnterpriseIdpProvider.UNKNOWN) {
            EnterpriseIdpProvider.OKTA -> EnterpriseIdpAdapterType.OKTA_OIDC
            EnterpriseIdpProvider.AZURE_AD -> EnterpriseIdpAdapterType.AZURE_AD_OIDC
            EnterpriseIdpProvider.GOOGLE_WORKSPACE -> EnterpriseIdpAdapterType.GOOGLE_WORKSPACE_OIDC
            EnterpriseIdpProvider.PING -> EnterpriseIdpAdapterType.PING_OIDC
            EnterpriseIdpProvider.AUTH0 -> EnterpriseIdpAdapterType.AUTH0_OIDC
            EnterpriseIdpProvider.CUSTOM -> EnterpriseIdpAdapterType.CUSTOM_OIDC
            EnterpriseIdpProvider.UNKNOWN -> EnterpriseIdpAdapterType.UNKNOWN
        }
    }

    private fun scimProviderTypeFor(source: RemoteOperatorDirectorySource?): ScimProviderAdapterType {
        return when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> ScimProviderAdapterType.OKTA_SCIM
            RemoteOperatorDirectorySource.REMOTE_CACHE -> ScimProviderAdapterType.CUSTOM_SCIM
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> ScimProviderAdapterType.LOCAL_CACHE
        }
    }

    private fun freshnessStatusForDirectorySync(status: DirectorySyncStatus): DirectorySyncFreshnessStatus {
        return when (status) {
            DirectorySyncStatus.SYNCED -> DirectorySyncFreshnessStatus.FRESH
            DirectorySyncStatus.STALE -> DirectorySyncFreshnessStatus.STALE_SOFT
            DirectorySyncStatus.SYNC_PENDING -> DirectorySyncFreshnessStatus.STALE_HARD
            DirectorySyncStatus.FAILED,
            DirectorySyncStatus.DIRECTORY_UNAVAILABLE -> DirectorySyncFreshnessStatus.OUT_OF_SYNC
            DirectorySyncStatus.NOT_TRACKED -> DirectorySyncFreshnessStatus.UNKNOWN
        }
    }

    private fun buildIdpProviderConfig(
        userId: String,
        source: RemoteOperatorDirectorySource?,
        provider: EnterpriseIdpProvider?,
        now: Long
    ): EnterpriseIdpProviderConfig? {
        val resolvedProvider = provider ?: idpProviderFor(source)
        if (resolvedProvider == EnterpriseIdpProvider.UNKNOWN && source == null) {
            return null
        }
        val rolloutStage = when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> EnterpriseRolloutStage.GA
            RemoteOperatorDirectorySource.REMOTE_CACHE -> EnterpriseRolloutStage.CANARY
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> EnterpriseRolloutStage.DISABLED
        }
        val cutoverStatus = when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> CutoverReadinessStatus.READY
            RemoteOperatorDirectorySource.REMOTE_CACHE -> CutoverReadinessStatus.DEGRADED
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> CutoverReadinessStatus.FALLBACK_ONLY
        }
        val enabled = resolvedProvider != EnterpriseIdpProvider.UNKNOWN &&
            rolloutStage != EnterpriseRolloutStage.DISABLED &&
            rolloutStage != EnterpriseRolloutStage.BLOCKED
        return EnterpriseIdpProviderConfig(
            configId = "idp_cfg_${userId.lowercase()}_${resolvedProvider.name.lowercase()}",
            provider = resolvedProvider,
            adapterType = idpAdapterTypeFor(resolvedProvider),
            tenantId = userId.substringBefore('_', userId),
            enabled = enabled,
            rolloutStage = rolloutStage,
            cutoverStatus = cutoverStatus,
            updatedAtMs = now,
            summary = buildString {
                append("IdP provider ")
                append(resolvedProvider.name.lowercase().replace('_', ' '))
                append(" is ")
                append(if (enabled) "enabled" else "fallback-only")
                append(" (")
                append(rolloutStage.name.lowercase().replace('_', ' '))
                append(").")
            }
        )
    }

    private fun buildScimProviderConfig(
        userId: String,
        source: RemoteOperatorDirectorySource?,
        now: Long
    ): ScimProviderConfig? {
        val providerType = scimProviderTypeFor(source)
        if (providerType == ScimProviderAdapterType.UNKNOWN && source == null) {
            return null
        }
        val rolloutStage = when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> EnterpriseRolloutStage.GA
            RemoteOperatorDirectorySource.REMOTE_CACHE -> EnterpriseRolloutStage.CANARY
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> EnterpriseRolloutStage.DISABLED
        }
        val cutoverStatus = when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> CutoverReadinessStatus.READY
            RemoteOperatorDirectorySource.REMOTE_CACHE -> CutoverReadinessStatus.DEGRADED
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> CutoverReadinessStatus.FALLBACK_ONLY
        }
        val enabled = source == RemoteOperatorDirectorySource.REMOTE_LIVE ||
            source == RemoteOperatorDirectorySource.REMOTE_CACHE
        return ScimProviderConfig(
            configId = "scim_cfg_${userId.lowercase()}_${providerType.name.lowercase()}",
            providerType = providerType,
            providerLabel = providerType.name.lowercase().replace('_', ' '),
            tenantId = userId.substringBefore('_', userId),
            enabled = enabled,
            rolloutStage = rolloutStage,
            cutoverStatus = cutoverStatus,
            updatedAtMs = now,
            summary = buildString {
                append("SCIM provider ")
                append(providerType.name.lowercase().replace('_', ' '))
                append(" is ")
                append(if (enabled) "enabled" else "fallback-only")
                append(" (")
                append(rolloutStage.name.lowercase().replace('_', ' '))
                append(").")
            }
        )
    }

    private fun vaultProviderTypeFor(vaultProvider: String?): VaultProviderType {
        val normalized = vaultProvider.orEmpty().trim().lowercase()
        return when {
            normalized.isBlank() -> VaultProviderType.UNKNOWN
            normalized.contains("hashicorp") || normalized == "vault" -> VaultProviderType.HASHICORP_VAULT
            normalized.contains("aws") || normalized.contains("secretmanager") -> VaultProviderType.AWS_SECRETS_MANAGER
            normalized.contains("gcp") || normalized.contains("google") -> VaultProviderType.GCP_SECRET_MANAGER
            normalized.contains("azure") || normalized.contains("keyvault") -> VaultProviderType.AZURE_KEY_VAULT
            normalized.contains("local") -> VaultProviderType.LOCAL_DURABLE
            else -> VaultProviderType.CUSTOM
        }
    }

    private fun buildVaultProviderConfig(
        vaultCredential: VaultCredentialReference?,
        tenantRolloutProfile: TenantRolloutProfile?,
        cutoverReadiness: CutoverReadinessSummary?,
        now: Long
    ): VaultProviderConfig? {
        val providerType = vaultProviderTypeFor(vaultCredential?.vaultProvider)
        if (providerType == VaultProviderType.UNKNOWN && vaultCredential == null) {
            return null
        }
        val stage = tenantRolloutProfile?.stage ?: EnterpriseRolloutStage.GA
        val cutoverStatus = cutoverReadiness?.status ?: CutoverReadinessStatus.READY
        val enabled = providerType != VaultProviderType.UNKNOWN &&
            stage != EnterpriseRolloutStage.DISABLED &&
            stage != EnterpriseRolloutStage.BLOCKED &&
            cutoverStatus != CutoverReadinessStatus.BLOCKED &&
            cutoverStatus != CutoverReadinessStatus.NOT_READY
        return VaultProviderConfig(
            configId = "vault_cfg_${providerType.name.lowercase()}_${tenantRolloutProfile?.tenantId ?: "default"}",
            providerType = providerType,
            providerLabel = providerType.name.lowercase().replace('_', ' '),
            enabled = enabled,
            rolloutStage = stage,
            cutoverStatus = cutoverStatus,
            updatedAtMs = now,
            summary = buildString {
                append("Vault provider ")
                append(providerType.name.lowercase().replace('_', ' '))
                append(" is ")
                append(if (enabled) "eligible" else "gated")
                append(" (stage ")
                append(stage.name.lowercase().replace('_', ' '))
                append(", cutover ")
                append(cutoverStatus.name.lowercase().replace('_', ' '))
                append(").")
            }
        )
    }

    private fun sessionProvenanceFor(
        source: RemoteOperatorDirectorySource?,
        directorySyncStatus: DirectorySyncStatus,
        usedFallback: Boolean
    ): EnterpriseSessionProvenance {
        if (usedFallback) return EnterpriseSessionProvenance.SSO_STALE_FALLBACK
        return when {
            source == null || source == RemoteOperatorDirectorySource.LOCAL_FALLBACK ->
                EnterpriseSessionProvenance.LOCAL_ONLY
            directorySyncStatus == DirectorySyncStatus.DIRECTORY_UNAVAILABLE ->
                EnterpriseSessionProvenance.IDP_UNAVAILABLE_FALLBACK
            directorySyncStatus == DirectorySyncStatus.STALE || directorySyncStatus == DirectorySyncStatus.SYNC_PENDING ->
                EnterpriseSessionProvenance.SSO_STALE_FALLBACK
            directorySyncStatus == DirectorySyncStatus.SYNCED ->
                EnterpriseSessionProvenance.SSO_ASSERTED
            else ->
                EnterpriseSessionProvenance.SSO_REFRESHED
        }
    }

    private fun buildIdentityAssertion(
        identity: OperatorIdentity,
        idpProvider: EnterpriseIdpProvider,
        now: Long
    ): EnterpriseIdentityAssertion {
        val subjectId = identity.enterpriseIdentityId
            ?: identity.remoteOperatorId
            ?: identity.userId
        return EnterpriseIdentityAssertion(
            assertionId = "assertion_${subjectId.lowercase()}_$now",
            idpProvider = idpProvider,
            subjectId = subjectId,
            subjectEmail = null,
            assertedAtMs = now,
            expiresAtMs = now + 8L * 60L * 60L * 1000L,
            assuranceLevel = if (idpProvider == EnterpriseIdpProvider.UNKNOWN) null else "standard",
            summary = when (idpProvider) {
                EnterpriseIdpProvider.UNKNOWN ->
                    "No enterprise IdP assertion was available; local fallback identity remained active."
                else ->
                    "Enterprise identity assertion was captured from ${idpProvider.name.lowercase().replace('_', ' ')}."
            }
        )
    }

    private fun directorySyncErrorStateFor(
        status: DirectorySyncStatus,
        lastError: String? = null
    ): DirectorySyncErrorState {
        val errorText = lastError.orEmpty().lowercase()
        return when {
            status == DirectorySyncStatus.SYNCED || status == DirectorySyncStatus.NOT_TRACKED ->
                DirectorySyncErrorState.NONE
            status == DirectorySyncStatus.DIRECTORY_UNAVAILABLE ->
                DirectorySyncErrorState.DIRECTORY_UNAVAILABLE
            status == DirectorySyncStatus.FAILED && errorText.contains("rate") ->
                DirectorySyncErrorState.RATE_LIMITED
            status == DirectorySyncStatus.FAILED && errorText.contains("auth") ->
                DirectorySyncErrorState.AUTH_FAILED
            status == DirectorySyncStatus.FAILED && errorText.contains("payload") ->
                DirectorySyncErrorState.PAYLOAD_INVALID
            status == DirectorySyncStatus.FAILED ->
                DirectorySyncErrorState.UNKNOWN
            else ->
                DirectorySyncErrorState.NONE
        }
    }

    private fun sessionAuthorityFor(
        source: RemoteOperatorDirectorySource?,
        usedFallback: Boolean
    ): SessionAuthority {
        if (usedFallback) return SessionAuthority.LOCAL_FALLBACK_POLICY
        return when (source) {
            RemoteOperatorDirectorySource.REMOTE_LIVE -> SessionAuthority.ENTERPRISE_DIRECTORY_POLICY
            RemoteOperatorDirectorySource.REMOTE_CACHE -> SessionAuthority.REMOTE_DIRECTORY_POLICY
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> SessionAuthority.LOCAL_POLICY
        }
    }

    private fun directorySyncStatusFor(
        entry: RemoteOperatorDirectoryEntry?,
        source: RemoteOperatorDirectorySource?,
        now: Long
    ): DirectorySyncStatus {
        entry?.directorySync?.status?.let { return it }
        if (source == null || source == RemoteOperatorDirectorySource.LOCAL_FALLBACK) {
            return DirectorySyncStatus.NOT_TRACKED
        }
        val syncedAt = entry?.syncedAtMs ?: 0L
        if (syncedAt <= 0L) return DirectorySyncStatus.SYNC_PENDING
        val ageMs = now - syncedAt
        return when {
            ageMs <= 6L * 60L * 60L * 1000L -> DirectorySyncStatus.SYNCED
            ageMs <= 24L * 60L * 60L * 1000L -> DirectorySyncStatus.STALE
            else -> DirectorySyncStatus.SYNC_PENDING
        }
    }

    private fun sessionFreshnessFor(directorySyncStatus: DirectorySyncStatus): SessionFreshnessState {
        return when (directorySyncStatus) {
            DirectorySyncStatus.SYNCED -> SessionFreshnessState.FRESH
            DirectorySyncStatus.STALE, DirectorySyncStatus.SYNC_PENDING -> SessionFreshnessState.STALE
            DirectorySyncStatus.FAILED, DirectorySyncStatus.DIRECTORY_UNAVAILABLE -> SessionFreshnessState.INVALIDATED
            DirectorySyncStatus.NOT_TRACKED -> SessionFreshnessState.UNKNOWN
        }
    }

    private fun authorizeRemoteOperatorActionLocked(
        userId: String,
        action: GovernanceActionType,
        identity: OperatorIdentity,
        requiredPermission: OperatorPermission?,
        command: GovernanceCollaborationCommand?,
        currentState: GovernanceCaseCollaborationState?
    ): RemoteAuthorizationDecision {
        ensureRemoteResourcesInitializedLocked(userId)
        val now = nowMs()
        val requestedContext = command?.remoteAuthorizationContext
        val required = requestedContext?.requiredPermission ?: requiredPermission
        val directoryEntry = resolveDirectoryEntryLocked(
            userId = userId,
            actorUserId = identity.userId,
            requestedOperatorId = requestedContext?.operatorId ?: identity.remoteOperatorId,
            requestedTeamId = requestedContext?.teamId ?: identity.remoteTeamId
        )
        val resolvedSource = directoryEntry?.identity?.directorySource ?: identity.remoteDirectorySource
        val resolvedDirectorySync = directorySyncStatusFor(
            entry = directoryEntry,
            source = resolvedSource,
            now = now
        )
        val resolvedIdpProvider = idpProviderFor(resolvedSource)
        fun buildProvenance(
            status: RemoteAuthorizationStatus,
            reason: String,
            usedFallback: Boolean,
            identitySource: RemoteOperatorDirectorySource? = resolvedSource,
            syncStatus: DirectorySyncStatus = resolvedDirectorySync
        ): Pair<RemoteAuthorizationProvenance, SessionAuthContext> {
            val effectiveSyncStatus = when (status) {
                RemoteAuthorizationStatus.DIRECTORY_UNAVAILABLE -> DirectorySyncStatus.DIRECTORY_UNAVAILABLE
                else -> syncStatus
            }
            val inferredProvider = idpProviderFor(identitySource)
            val idpConfig = buildIdpProviderConfig(
                userId = userId,
                source = identitySource,
                provider = inferredProvider,
                now = now
            )
            val idpExchange = enterpriseIdpProviderPort.exchange(
                request = EnterpriseIdpSessionExchangeRequest(
                    requestId = "idp_exchange_${userId.lowercase()}_${now}",
                    runId = currentState?.runId ?: "governance_auth_${userId.lowercase()}",
                    userId = userId,
                    operatorId = identity.remoteOperatorId,
                    sessionRef = requestedContext?.sessionRef,
                    provider = inferredProvider,
                    adapterType = idpConfig?.adapterType ?: idpAdapterTypeFor(inferredProvider),
                    allowFallback = usedFallback || status != RemoteAuthorizationStatus.DENIED,
                    requestedAtMs = now
                ),
                config = idpConfig,
                nowMs = now
            )
            val idpHealth = enterpriseIdpProviderPort.health(idpConfig, now)
            val scimConfig = buildScimProviderConfig(
                userId = userId,
                source = identitySource,
                now = now
            )
            val scimSnapshot = directoryEntry?.directorySync?.copy(
                status = effectiveSyncStatus
            ) ?: DirectorySyncSnapshot(
                snapshotId = "directory_sync_${userId.lowercase()}_$now",
                source = enterpriseSourceFor(identitySource),
                status = effectiveSyncStatus,
                freshnessStatus = freshnessStatusForDirectorySync(effectiveSyncStatus),
                providerType = scimConfig?.providerType ?: scimProviderTypeFor(identitySource),
                providerConfigId = scimConfig?.configId,
                syncedAtMs = directoryEntry?.syncedAtMs?.takeIf { it > 0L },
                summary = "Directory sync status captured during remote authorization evaluation."
            )
            val scimResult = scimDirectoryProviderPort.evaluate(
                snapshot = scimSnapshot,
                config = scimConfig,
                nowMs = now
            )
            val authority = requestedContext?.sessionAuthorityHint
                ?: sessionAuthorityFor(identitySource, usedFallback)
            val freshness = when (idpExchange.freshness) {
                SessionFreshnessState.UNKNOWN -> sessionFreshnessFor(scimResult.status)
                else -> idpExchange.freshness
            }
            val sessionProvenance = when (idpExchange.sessionProvenance) {
                EnterpriseSessionProvenance.LOCAL_ONLY -> sessionProvenanceFor(
                    source = identitySource,
                    directorySyncStatus = scimResult.status,
                    usedFallback = usedFallback
                )
                else -> idpExchange.sessionProvenance
            }
            val assertion = idpExchange.identityAssertion
                ?: directoryEntry?.remoteIdentityLink?.identityAssertion
                ?: buildIdentityAssertion(
                    identity = identity,
                    idpProvider = inferredProvider,
                    now = now
                )
            val provenance = RemoteAuthorizationProvenance(
                authority = authority,
                sessionProvenance = sessionProvenance,
                idpProvider = inferredProvider,
                identityAssertion = assertion,
                idpAdapterType = idpExchange.adapterType,
                idpExchangeStatus = idpExchange.status,
                idpProviderHealth = idpHealth,
                identitySource = identitySource,
                directorySyncStatus = scimResult.status,
                scimProviderResult = scimResult,
                usedFallback = usedFallback,
                sessionFreshness = freshness,
                summary = reason
            )
            val sessionContext = SessionAuthContext(
                sessionRef = requestedContext?.sessionRef,
                authority = authority,
                sessionProvenance = sessionProvenance,
                idpProvider = inferredProvider,
                identityAssertion = assertion,
                idpAdapterType = idpExchange.adapterType,
                idpProviderConfigId = idpConfig?.configId,
                idpProviderHealth = idpHealth,
                idpSessionExchange = idpExchange,
                freshness = freshness,
                issuedAtMs = now,
                validatedAtMs = now,
                summary = reason
            )
            return provenance to sessionContext
        }
        if (requestedContext != null && directoryEntry == null) {
            val (provenance, sessionContext) = buildProvenance(
                status = RemoteAuthorizationStatus.DIRECTORY_UNAVAILABLE,
                reason = "Remote directory entry is missing for requested operator authorization context.",
                usedFallback = false,
                identitySource = requestedContext.source,
                syncStatus = DirectorySyncStatus.DIRECTORY_UNAVAILABLE
            )
            return RemoteAuthorizationDecision(
                result = RemoteAuthorizationResult(
                    status = RemoteAuthorizationStatus.DIRECTORY_UNAVAILABLE,
                    allowed = false,
                    operatorId = requestedContext.operatorId,
                    teamId = requestedContext.teamId,
                    requiredPermission = required,
                    reason = "Remote directory entry is missing for requested operator authorization context.",
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED,
                        RoleReasonCodes.ROLE_REMOTE_IDENTITY_SYNC_PENDING,
                        RoleReasonCodes.ROLE_SCIM_DIRECTORY_UNAVAILABLE,
                        RoleReasonCodes.ROLE_ENTERPRISE_SESSION_INVALIDATED,
                        RoleReasonCodes.ROLE_REMOTE_AUTH_PROVENANCE_RECORDED
                    ),
                    provenance = provenance,
                    sessionAuthContext = sessionContext,
                    evaluatedAtMs = now
                ),
                denialReason = OperatorPermissionDenialReason.REMOTE_DIRECTORY_ENTRY_MISSING
            )
        }
        val activeEntry = directoryEntry?.takeIf { it.identity.active }
        if (requestedContext != null && activeEntry != null) {
            if (
                requestedContext.operatorId.isNotBlank() &&
                !activeEntry.identity.operatorId.equals(requestedContext.operatorId, ignoreCase = true)
            ) {
                val denialReason = "Remote authorization context does not match the resolved operator identity."
                val (provenance, sessionContext) = buildProvenance(
                    status = RemoteAuthorizationStatus.DENIED,
                    reason = denialReason,
                    usedFallback = false
                )
                return RemoteAuthorizationDecision(
                    result = RemoteAuthorizationResult(
                        status = RemoteAuthorizationStatus.DENIED,
                        allowed = false,
                        operatorId = activeEntry.identity.operatorId,
                        teamId = activeEntry.identity.teamId,
                        requiredPermission = required,
                        reason = denialReason,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED,
                            RoleReasonCodes.ROLE_REMOTE_AUTH_PROVENANCE_RECORDED
                        ),
                        provenance = provenance,
                        sessionAuthContext = sessionContext,
                        evaluatedAtMs = now
                    ),
                    denialReason = OperatorPermissionDenialReason.REMOTE_AUTH_CONTEXT_INVALID
                )
            }
            if (
                !requestedContext.teamId.isNullOrBlank() &&
                !(activeEntry.identity.teamId ?: activeEntry.team?.teamId)
                    .equals(requestedContext.teamId, ignoreCase = true)
            ) {
                val denialReason = "Remote authorization context team does not match the resolved operator team."
                val (provenance, sessionContext) = buildProvenance(
                    status = RemoteAuthorizationStatus.DENIED,
                    reason = denialReason,
                    usedFallback = false
                )
                return RemoteAuthorizationDecision(
                    result = RemoteAuthorizationResult(
                        status = RemoteAuthorizationStatus.DENIED,
                        allowed = false,
                        operatorId = activeEntry.identity.operatorId,
                        teamId = activeEntry.identity.teamId ?: activeEntry.team?.teamId,
                        requiredPermission = required,
                        reason = denialReason,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED,
                            RoleReasonCodes.ROLE_REMOTE_AUTH_PROVENANCE_RECORDED
                        ),
                        provenance = provenance,
                        sessionAuthContext = sessionContext,
                        evaluatedAtMs = now
                    ),
                    denialReason = OperatorPermissionDenialReason.REMOTE_AUTH_CONTEXT_INVALID
                )
            }
        }
        val permissionPool = (
            activeEntry?.identity?.permissions.orEmpty() +
            activeEntry?.team?.permissionDefaults.orEmpty() +
                identity.permissions
            ).distinct()
        if (required != null && !permissionPool.contains(required)) {
            val denialReason = "Remote authorization denied: required permission ${required.name.lowercase().replace('_', ' ')} is missing."
            val (provenance, sessionContext) = buildProvenance(
                status = RemoteAuthorizationStatus.DENIED,
                reason = denialReason,
                usedFallback = false
            )
            return RemoteAuthorizationDecision(
                result = RemoteAuthorizationResult(
                    status = RemoteAuthorizationStatus.DENIED,
                    allowed = false,
                    operatorId = activeEntry?.identity?.operatorId.orEmpty(),
                    teamId = activeEntry?.identity?.teamId ?: activeEntry?.team?.teamId,
                    requiredPermission = required,
                    reason = denialReason,
                    reasonCodes = listOf(
                        RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED,
                        RoleReasonCodes.ROLE_REMOTE_AUTH_PROVENANCE_RECORDED
                    ),
                    provenance = provenance,
                    sessionAuthContext = sessionContext,
                    evaluatedAtMs = now
                ),
                denialReason = OperatorPermissionDenialReason.REMOTE_AUTH_DENIED
            )
        }
        val status = when (resolvedSource) {
            RemoteOperatorDirectorySource.LOCAL_FALLBACK, null -> RemoteAuthorizationStatus.FALLBACK_ALLOWED
            else -> RemoteAuthorizationStatus.ALLOWED
        }
        val successReason = if (status == RemoteAuthorizationStatus.FALLBACK_ALLOWED) {
            "Remote authorization allowed via local directory fallback."
        } else {
            "Remote authorization allowed by directory policy."
        }
        val (provenance, sessionContext) = buildProvenance(
            status = status,
            reason = successReason,
            usedFallback = status == RemoteAuthorizationStatus.FALLBACK_ALLOWED
        )
        val reasonCodes = buildList {
            add(RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_ALLOWED)
            if (provenance.identityAssertion != null) {
                add(RoleReasonCodes.ROLE_ENTERPRISE_SSO_ASSERTION_APPLIED)
            } else {
                add(RoleReasonCodes.ROLE_ENTERPRISE_SSO_ASSERTION_MISSING)
            }
            if (status == RemoteAuthorizationStatus.FALLBACK_ALLOWED) {
                add(RoleReasonCodes.ROLE_REMOTE_OPERATOR_DIRECTORY_FALLBACK)
                add(RoleReasonCodes.ROLE_REMOTE_SESSION_FALLBACK_USED)
                add(RoleReasonCodes.ROLE_ENTERPRISE_SESSION_STALE_FALLBACK)
            }
            if (activeEntry != null) {
                add(RoleReasonCodes.ROLE_REMOTE_IDENTITY_LINKED)
            }
            when (provenance.idpExchangeStatus) {
                EnterpriseIdpSessionExchangeStatus.ALLOWED -> add(RoleReasonCodes.ROLE_ENTERPRISE_IDP_PROVIDER_APPLIED)
                EnterpriseIdpSessionExchangeStatus.FALLBACK_ALLOWED -> add(RoleReasonCodes.ROLE_ENTERPRISE_IDP_PROVIDER_DEGRADED)
                EnterpriseIdpSessionExchangeStatus.DENIED,
                EnterpriseIdpSessionExchangeStatus.PROVIDER_UNAVAILABLE -> add(RoleReasonCodes.ROLE_ENTERPRISE_IDP_PROVIDER_BLOCKED)
                EnterpriseIdpSessionExchangeStatus.UNKNOWN,
                null -> Unit
            }
            if (resolvedDirectorySync == DirectorySyncStatus.SYNC_PENDING ||
                resolvedDirectorySync == DirectorySyncStatus.STALE ||
                resolvedDirectorySync == DirectorySyncStatus.DIRECTORY_UNAVAILABLE
            ) {
                add(RoleReasonCodes.ROLE_REMOTE_IDENTITY_SYNC_PENDING)
            }
            when (provenance.scimProviderResult?.freshnessStatus) {
                DirectorySyncFreshnessStatus.FRESH -> add(RoleReasonCodes.ROLE_SCIM_PROVIDER_FRESH)
                DirectorySyncFreshnessStatus.STALE_SOFT,
                DirectorySyncFreshnessStatus.STALE_HARD -> add(RoleReasonCodes.ROLE_SCIM_PROVIDER_STALE)
                DirectorySyncFreshnessStatus.OUT_OF_SYNC -> add(RoleReasonCodes.ROLE_SCIM_PROVIDER_BLOCKED)
                DirectorySyncFreshnessStatus.UNKNOWN,
                null -> Unit
            }
            when (resolvedDirectorySync) {
                DirectorySyncStatus.SYNCED -> add(RoleReasonCodes.ROLE_SCIM_DIRECTORY_SYNC_APPLIED)
                DirectorySyncStatus.STALE,
                DirectorySyncStatus.SYNC_PENDING -> add(RoleReasonCodes.ROLE_SCIM_DIRECTORY_SYNC_STALE)
                DirectorySyncStatus.FAILED -> add(RoleReasonCodes.ROLE_SCIM_DIRECTORY_SYNC_FAILED)
                DirectorySyncStatus.DIRECTORY_UNAVAILABLE -> add(RoleReasonCodes.ROLE_SCIM_DIRECTORY_UNAVAILABLE)
                DirectorySyncStatus.NOT_TRACKED -> Unit
            }
            when (provenance.sessionProvenance) {
                EnterpriseSessionProvenance.SSO_ASSERTED,
                EnterpriseSessionProvenance.SSO_REFRESHED -> add(RoleReasonCodes.ROLE_ENTERPRISE_SESSION_FRESH)
                EnterpriseSessionProvenance.SSO_STALE_FALLBACK,
                EnterpriseSessionProvenance.IDP_UNAVAILABLE_FALLBACK -> add(RoleReasonCodes.ROLE_ENTERPRISE_SESSION_STALE_FALLBACK)
                EnterpriseSessionProvenance.LOCAL_ONLY -> Unit
            }
            if (provenance.sessionFreshness == SessionFreshnessState.INVALIDATED) {
                add(RoleReasonCodes.ROLE_ENTERPRISE_SESSION_INVALIDATED)
            }
            if (currentState?.assignedTo?.userId.equals(identity.userId, ignoreCase = true)) {
                add(RoleReasonCodes.ROLE_REMOTE_ASSIGNMENT_BOUND)
            }
            add(RoleReasonCodes.ROLE_REMOTE_AUTH_PROVENANCE_RECORDED)
        }.distinct()
        return RemoteAuthorizationDecision(
            result = RemoteAuthorizationResult(
                status = status,
                allowed = true,
                operatorId = activeEntry?.identity?.operatorId ?: identity.remoteOperatorId.orEmpty(),
                teamId = activeEntry?.identity?.teamId
                    ?: activeEntry?.team?.teamId
                    ?: identity.remoteTeamId,
                requiredPermission = required,
                reason = successReason,
                reasonCodes = reasonCodes,
                provenance = provenance,
                sessionAuthContext = sessionContext,
                evaluatedAtMs = now
            )
        )
    }

    private fun resolveRouteBindingForTarget(
        snapshot: RemoteResourceSnapshot,
        targetType: AlertRoutingTargetType,
        command: GovernanceCollaborationCommand
    ): ConnectorRouteBinding? {
        val explicitBindingId = command.routeBindingId?.trim()?.takeIf { it.isNotBlank() }
        if (explicitBindingId != null) {
            return snapshot.routeBindings.lastOrNull { it.bindingId == explicitBindingId && it.enabled }
        }
        return snapshot.routeBindings
            .filter { it.enabled && it.targetType == targetType }
            .minByOrNull { it.priority }
    }

    private fun resolveConnectorDestinationForTarget(
        snapshot: RemoteResourceSnapshot,
        binding: ConnectorRouteBinding?,
        command: GovernanceCollaborationCommand,
        providerType: ConnectorProviderType,
        operatorResolution: OperatorResolution
    ): ConnectorDestination? {
        val explicitDestinationId = command.destinationId?.trim()?.takeIf { it.isNotBlank() }
        if (explicitDestinationId != null) {
            return snapshot.destinations.lastOrNull {
                it.destinationId == explicitDestinationId && it.enabled
            }
        }
        val bindingDestinationId = binding?.destinationId?.takeIf { it.isNotBlank() }
        if (bindingDestinationId != null) {
            return snapshot.destinations.lastOrNull {
                it.destinationId == bindingDestinationId && it.enabled
            }
        }
        val preferredTeamId = operatorResolution.remoteTeam?.teamId ?: operatorResolution.identity.remoteTeamId
        return snapshot.destinations
            .filter { it.enabled && it.providerType == providerType }
            .sortedWith(compareByDescending<ConnectorDestination> { it.ownerTeamId == preferredTeamId }.thenByDescending { it.updatedAtMs })
            .firstOrNull()
    }

    private fun resolveConnectorAuthProfileForTarget(
        snapshot: RemoteResourceSnapshot,
        binding: ConnectorRouteBinding?,
        destination: ConnectorDestination?,
        command: GovernanceCollaborationCommand,
        providerType: ConnectorProviderType
    ): ConnectorAuthProfile? {
        val explicitAuthProfileId = command.authProfileId?.trim()?.takeIf { it.isNotBlank() }
        if (explicitAuthProfileId != null) {
            return snapshot.authProfiles.lastOrNull { it.authProfileId == explicitAuthProfileId }
        }
        val bindingAuthProfileId = binding?.authProfileId?.takeIf { it.isNotBlank() }
        if (bindingAuthProfileId != null) {
            return snapshot.authProfiles.lastOrNull { it.authProfileId == bindingAuthProfileId }
        }
        val destinationAuthProfileId = destination?.authProfileId?.takeIf { it.isNotBlank() }
        if (destinationAuthProfileId != null) {
            return snapshot.authProfiles.lastOrNull { it.authProfileId == destinationAuthProfileId }
        }
        return snapshot.authProfiles.lastOrNull { it.providerType == providerType }
    }

    private fun resolveConnectorCredentialLifecycle(
        authProfile: ConnectorAuthProfile?,
        destination: ConnectorDestination?,
        now: Long
    ): ConnectorCredentialLifecycleSummary? {
        val lifecycle = authProfile?.credentialLifecycle
            ?: authProfile?.credentialRef?.lifecycle
            ?: destination?.credentialLifecycle
            ?: destination?.credentialRef?.lifecycle

        if (lifecycle != null) {
            return if (lifecycle.evaluatedAtMs > 0) {
                lifecycle
            } else {
                lifecycle.copy(evaluatedAtMs = now)
            }
        }

        val credentialRef = authProfile?.credentialRef ?: destination?.credentialRef
        val vaultCredential = authProfile?.vaultCredential
            ?: authProfile?.credentialRef?.vaultCredential
            ?: destination?.vaultCredential
            ?: destination?.credentialRef?.vaultCredential
        val status = authProfile?.status ?: credentialRef?.status ?: ConnectorCredentialStatus.UNKNOWN
        val expiresAt = authProfile?.expiresAtMs ?: credentialRef?.expiresAtMs
        val rotationRequired = credentialRef?.rotationRequired == true
        val revoked = credentialRef?.revokedAtMs != null || status == ConnectorCredentialStatus.REVOKED
        val vaultStatus = vaultCredential?.status ?: VaultCredentialStatus.UNKNOWN
        val vaultLeaseExpired = vaultCredential?.leaseExpiresAtMs?.let { it <= now } == true ||
            vaultStatus == VaultCredentialStatus.LEASE_EXPIRED
        val vaultRotationRequired = vaultStatus == VaultCredentialStatus.ROTATION_DUE ||
            (
                vaultCredential?.rotationState == VaultCredentialRotationState.SCHEDULED ||
                    vaultCredential?.rotationState == VaultCredentialRotationState.IN_PROGRESS
                )
        val vaultRevoked = vaultStatus == VaultCredentialStatus.REVOKED
        val vaultUnavailable = vaultStatus == VaultCredentialStatus.BACKEND_UNAVAILABLE
        val vaultAccessDenied = vaultStatus == VaultCredentialStatus.ACCESS_DENIED
        val state = when {
            vaultRevoked -> ConnectorCredentialLifecycleState.REVOKED
            vaultLeaseExpired -> ConnectorCredentialLifecycleState.EXPIRED
            vaultUnavailable || vaultAccessDenied -> ConnectorCredentialLifecycleState.MISCONFIGURED
            vaultRotationRequired -> ConnectorCredentialLifecycleState.ROTATION_REQUIRED
            revoked -> ConnectorCredentialLifecycleState.REVOKED
            status == ConnectorCredentialStatus.EXPIRED -> ConnectorCredentialLifecycleState.EXPIRED
            status == ConnectorCredentialStatus.MISSING || status == ConnectorCredentialStatus.INVALID ->
                ConnectorCredentialLifecycleState.MISCONFIGURED
            rotationRequired -> ConnectorCredentialLifecycleState.ROTATION_REQUIRED
            expiresAt != null && expiresAt <= now -> ConnectorCredentialLifecycleState.EXPIRED
            expiresAt != null && expiresAt - now <= 24L * 60L * 60L * 1000L ->
                ConnectorCredentialLifecycleState.EXPIRING
            status == ConnectorCredentialStatus.CONFIGURED -> ConnectorCredentialLifecycleState.HEALTHY
            else -> ConnectorCredentialLifecycleState.UNKNOWN
        }
        val summary = when (state) {
            ConnectorCredentialLifecycleState.HEALTHY -> "Credential is healthy for connector delivery."
            ConnectorCredentialLifecycleState.EXPIRING -> "Credential is expiring soon; rotation should be scheduled."
            ConnectorCredentialLifecycleState.EXPIRED -> "Credential has expired; route is restricted."
            ConnectorCredentialLifecycleState.REVOKED -> "Credential is revoked; route is blocked."
            ConnectorCredentialLifecycleState.ROTATION_REQUIRED ->
                if (vaultStatus == VaultCredentialStatus.ROTATION_DUE) {
                    "Vault rotation is required before connector routing."
                } else {
                    "Credential rotation is required before routing."
                }
            ConnectorCredentialLifecycleState.MISCONFIGURED -> "Credential is missing or invalid for this connector route."
            ConnectorCredentialLifecycleState.UNKNOWN -> "Credential lifecycle state is not tracked."
        }
        return ConnectorCredentialLifecycleSummary(
            state = state,
            summary = summary,
            expiresAtMs = expiresAt,
            lastRotatedAtMs = credentialRef?.lastRotatedAtMs,
            rotationRequired = rotationRequired,
            revoked = revoked,
            evaluatedAtMs = now
        )
    }

    private fun resolveVaultCredentialReference(
        authProfile: ConnectorAuthProfile?,
        destination: ConnectorDestination?,
        now: Long
    ): VaultCredentialReference? {
        val vault = authProfile?.vaultCredential
            ?: authProfile?.credentialRef?.vaultCredential
            ?: destination?.vaultCredential
            ?: destination?.credentialRef?.vaultCredential
            ?: return null
        return if (vault.summary.isNotBlank()) {
            vault
        } else {
            val statusText = vault.status.name.lowercase().replace('_', ' ')
            val rotationText = vault.rotationState.name.lowercase().replace('_', ' ')
            vault.copy(
                summary = "Vault credential is $statusText (rotation $rotationText).",
                leaseExpiresAtMs = vault.leaseExpiresAtMs,
                lastRotatedAtMs = vault.lastRotatedAtMs ?: now
            )
        }
    }

    private fun credentialRouteBlockReasonFor(
        lifecycle: ConnectorCredentialLifecycleSummary?,
        vaultCredential: VaultCredentialReference?,
        directorySyncStatus: DirectorySyncStatus,
        remoteAuthorization: RemoteAuthorizationResult,
        idpSessionExchange: EnterpriseIdpSessionExchangeResult?,
        scimProviderResult: DirectorySyncProviderResult?,
        vaultResolution: VaultResolutionResult?,
        vaultMaterialization: VaultMaterializationResult?,
        featureGateDecision: FeatureGateDecision,
        cutoverReadiness: CutoverReadinessSummary
    ): CredentialRouteBlockReason {
        val vaultStatus = vaultCredential?.status
        val resolutionStatus = vaultResolution?.status
        val materializationStatus = vaultMaterialization?.status
        return when {
            idpSessionExchange?.status == EnterpriseIdpSessionExchangeStatus.DENIED ||
                idpSessionExchange?.status == EnterpriseIdpSessionExchangeStatus.PROVIDER_UNAVAILABLE ->
                CredentialRouteBlockReason.REMOTE_AUTH_INVALID
            scimProviderResult?.freshnessStatus == DirectorySyncFreshnessStatus.OUT_OF_SYNC ->
                CredentialRouteBlockReason.DIRECTORY_SYNC_REQUIRED
            lifecycle?.state?.let(::isCredentialLifecycleBlocking) == true ->
                CredentialRouteBlockReason.CREDENTIAL_LIFECYCLE_BLOCK
            vaultStatus == VaultCredentialStatus.BACKEND_UNAVAILABLE ->
                CredentialRouteBlockReason.VAULT_UNAVAILABLE
            resolutionStatus == VaultCredentialStatus.BACKEND_UNAVAILABLE ->
                CredentialRouteBlockReason.VAULT_UNAVAILABLE
            vaultStatus == VaultCredentialStatus.ACCESS_DENIED ->
                CredentialRouteBlockReason.VAULT_ACCESS_DENIED
            resolutionStatus == VaultCredentialStatus.ACCESS_DENIED ->
                CredentialRouteBlockReason.VAULT_ACCESS_DENIED
            vaultStatus == VaultCredentialStatus.LEASE_EXPIRED ||
                resolutionStatus == VaultCredentialStatus.LEASE_EXPIRED ||
                (vaultCredential?.leaseExpiresAtMs?.let { it <= nowMs() } == true) ->
                CredentialRouteBlockReason.VAULT_LEASE_EXPIRED
            materializationStatus == VaultMaterializationStatus.BLOCKED ->
                CredentialRouteBlockReason.VAULT_ACCESS_DENIED
            materializationStatus == VaultMaterializationStatus.DEGRADED ->
                CredentialRouteBlockReason.VAULT_UNAVAILABLE
            remoteAuthorization.status == RemoteAuthorizationStatus.DENIED ||
                remoteAuthorization.status == RemoteAuthorizationStatus.DIRECTORY_UNAVAILABLE ->
                CredentialRouteBlockReason.REMOTE_AUTH_INVALID
            directorySyncStatus == DirectorySyncStatus.DIRECTORY_UNAVAILABLE ->
                CredentialRouteBlockReason.DIRECTORY_SYNC_REQUIRED
            featureGateDecision.rolloutStage == EnterpriseRolloutStage.BLOCKED ||
                featureGateDecision.rolloutStage == EnterpriseRolloutStage.DISABLED ->
                CredentialRouteBlockReason.ROLLOUT_BLOCKED
            featureGateDecision.rolloutStage == EnterpriseRolloutStage.CANARY &&
                !featureGateDecision.allowed ->
                CredentialRouteBlockReason.CANARY_RESTRICTED
            featureGateDecision.degradationMode == ExecutionDegradationMode.DRY_RUN_ONLY ->
                CredentialRouteBlockReason.DRY_RUN_ONLY
            cutoverReadiness.status == CutoverReadinessStatus.NOT_READY ||
                cutoverReadiness.status == CutoverReadinessStatus.BLOCKED ||
                cutoverReadiness.blockReasons.any {
                    it == DirectoryCutoverBlockReason.DIRECTORY_UNAVAILABLE ||
                        it == DirectoryCutoverBlockReason.DIRECTORY_STALE ||
                        it == DirectoryCutoverBlockReason.SESSION_INVALID ||
                        it == DirectoryCutoverBlockReason.VAULT_UNHEALTHY
                } ->
                CredentialRouteBlockReason.CUTOVER_NOT_READY
            else ->
                CredentialRouteBlockReason.NONE
        }
    }

    private fun routeBlockSummaryFor(
        reason: CredentialRouteBlockReason,
        lifecycle: ConnectorCredentialLifecycleSummary?,
        vaultCredential: VaultCredentialReference?,
        featureGateDecision: FeatureGateDecision?,
        cutoverReadiness: CutoverReadinessSummary?
    ): String {
        val lifecycleText = lifecycle?.state?.name?.lowercase()?.replace('_', ' ')
        return when (reason) {
            CredentialRouteBlockReason.NONE ->
                "Connector route proceeded without policy block."
            CredentialRouteBlockReason.CREDENTIAL_LIFECYCLE_BLOCK ->
                "Connector route blocked by credential lifecycle (${lifecycleText ?: "unknown"}); local fallback route was used."
            CredentialRouteBlockReason.VAULT_UNAVAILABLE ->
                "Connector route blocked because vault backend is unavailable; local fallback route was used."
            CredentialRouteBlockReason.VAULT_ACCESS_DENIED ->
                "Connector route blocked because vault access is denied for this credential binding."
            CredentialRouteBlockReason.VAULT_LEASE_EXPIRED ->
                "Connector route blocked because vault lease expired and credential refresh is required."
            CredentialRouteBlockReason.DIRECTORY_SYNC_REQUIRED ->
                "Connector route blocked until enterprise directory sync recovers; local fallback route was used."
            CredentialRouteBlockReason.REMOTE_AUTH_INVALID ->
                "Connector route blocked because remote authorization context is invalid."
            CredentialRouteBlockReason.ROLLOUT_BLOCKED ->
                "Connector route blocked by enterprise rollout stage ${featureGateDecision?.rolloutStage?.name?.lowercase()?.replace('_', ' ') ?: "blocked"}."
            CredentialRouteBlockReason.CANARY_RESTRICTED ->
                "Connector route restricted by enterprise canary rollout policy; local fallback route was used."
            CredentialRouteBlockReason.CUTOVER_NOT_READY ->
                cutoverReadiness?.summary
                    ?.takeIf { it.isNotBlank() }
                    ?: "Connector route blocked because enterprise cutover readiness checks are not satisfied."
            CredentialRouteBlockReason.DRY_RUN_ONLY ->
                "Connector route is in dry-run-only rollout mode; local execution fallback was applied."
        } + (
            vaultCredential?.summary
                ?.takeIf { it.isNotBlank() }
                ?.let { " $it" }
                ?: ""
            )
    }

    private fun buildEnterpriseAuthIntegrationSummary(
        remoteAuthorization: RemoteAuthorizationResult,
        directorySyncSnapshot: DirectorySyncSnapshot?,
        targets: List<AlertRoutingTarget>,
        idpProviderConfig: EnterpriseIdpProviderConfig?,
        idpSessionExchange: EnterpriseIdpSessionExchangeResult?,
        idpProviderHealth: EnterpriseAuthProviderHealth?,
        scimProviderConfig: ScimProviderConfig?,
        scimProviderResult: DirectorySyncProviderResult?,
        directorySyncCheckpoint: DirectorySyncCheckpoint?,
        tenantRolloutProfile: TenantRolloutProfile?,
        workspaceRolloutProfile: WorkspaceRolloutProfile?,
        cutoverReadiness: CutoverReadinessSummary?,
        fallbackPolicy: EnterpriseFallbackPolicy?,
        vaultProviderConfig: VaultProviderConfig?,
        vaultMaterialization: VaultMaterializationResult?,
        vaultProviderHealth: VaultProviderHealth?,
        vaultCredentialHealthCheck: VaultCredentialHealthCheckResult?,
        vaultResolution: VaultResolutionResult?,
        vaultHealth: VaultHealthSummary?,
        now: Long
    ): EnterpriseAuthIntegrationSummary {
        val provenance = remoteAuthorization.provenance
        val authContext = remoteAuthorization.sessionAuthContext
        val assertion = authContext?.identityAssertion ?: provenance?.identityAssertion
        val directoryUpdate = directorySyncSnapshot?.lastUpdate
            ?: DirectorySyncUpdate(
                updateId = "directory_update_${remoteAuthorization.operatorId.ifBlank { "operator" }}_$now",
                updateType = DirectorySyncUpdateType.SCIM_WEBHOOK,
                status = directorySyncSnapshot?.status ?: DirectorySyncStatus.NOT_TRACKED,
                errorState = directorySyncSnapshot?.errorState ?: DirectorySyncErrorState.NONE,
                receivedAtMs = remoteAuthorization.evaluatedAtMs.takeIf { it > 0 } ?: now,
                processedAtMs = now,
                summary = "Directory sync integration state was captured from remote authorization metadata."
            )
        val binding = targets
            .mapNotNull { it.credentialBinding }
            .firstOrNull()
        val providerText = authContext?.idpProvider
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
            ?: "unknown idp"
        val idpStatusText = idpSessionExchange?.status
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
        val sessionText = authContext?.sessionProvenance
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
            ?: "local only"
        val scimText = scimProviderResult?.freshnessStatus
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
        val blockReason = binding?.blockReason?.takeIf { it != CredentialRouteBlockReason.NONE }
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
        val summary = buildString {
            append("Enterprise session ")
            append(sessionText)
            append(" via ")
            append(providerText)
            if (idpStatusText != null) {
                append(" (")
                append(idpStatusText)
                append(")")
            }
            directorySyncSnapshot?.status?.let {
                append(" · directory ")
                append(it.name.lowercase().replace('_', ' '))
            }
            if (!scimText.isNullOrBlank()) {
                append(" · scim ")
                append(scimText)
            }
            if (blockReason != null) {
                append(" · route block ")
                append(blockReason)
            }
            vaultMaterialization?.let {
                append(" · vault materialization ")
                append(it.status.name.lowercase().replace('_', ' '))
            }
            tenantRolloutProfile?.let {
                append(" · rollout ")
                append(it.stage.name.lowercase().replace('_', ' '))
            }
            cutoverReadiness?.let {
                append(" · cutover ")
                append(it.status.name.lowercase().replace('_', ' '))
            }
        }
        return EnterpriseAuthIntegrationSummary(
            identityAssertion = assertion,
            idpProviderConfig = idpProviderConfig,
            idpSessionExchange = idpSessionExchange,
            idpProviderHealth = idpProviderHealth,
            identityResolution = EnterpriseIdentityResolutionResult(
                source = enterpriseSourceFor(remoteAuthorization.provenance?.identitySource),
                provider = authContext?.idpProvider
                    ?: remoteAuthorization.provenance?.idpProvider
                    ?: EnterpriseIdpProvider.UNKNOWN,
                adapterType = idpSessionExchange?.adapterType ?: EnterpriseIdpAdapterType.UNKNOWN,
                directoryStatus = directorySyncSnapshot?.status ?: DirectorySyncStatus.NOT_TRACKED,
                sessionProvenance = authContext?.sessionProvenance
                    ?: remoteAuthorization.provenance?.sessionProvenance
                    ?: EnterpriseSessionProvenance.LOCAL_ONLY,
                usedFallback = remoteAuthorization.provenance?.usedFallback == true,
                reasonCodes = (idpSessionExchange?.reasonCodes.orEmpty() + scimProviderResult?.reasonCodes.orEmpty()).distinct(),
                summary = "Identity resolution captured for provider-aware authorization."
            ),
            sessionProvenance = authContext?.sessionProvenance
                ?: provenance?.sessionProvenance
                ?: EnterpriseSessionProvenance.LOCAL_ONLY,
            scimProviderConfig = scimProviderConfig,
            scimProviderResult = scimProviderResult,
            directorySyncCheckpoint = directorySyncCheckpoint,
            directorySync = directorySyncSnapshot,
            directoryUpdate = directoryUpdate,
            directoryErrorState = directorySyncSnapshot?.errorState
                ?: directorySyncErrorStateFor(directorySyncSnapshot?.status ?: DirectorySyncStatus.NOT_TRACKED),
            credentialBinding = binding,
            tenantRolloutProfile = tenantRolloutProfile,
            workspaceRolloutProfile = workspaceRolloutProfile,
            cutoverReadiness = cutoverReadiness,
            fallbackPolicy = fallbackPolicy,
            vaultProviderConfig = vaultProviderConfig,
            vaultMaterialization = vaultMaterialization,
            vaultProviderHealth = vaultProviderHealth,
            vaultCredentialHealthCheck = vaultCredentialHealthCheck,
            vaultResolution = vaultResolution,
            vaultHealth = vaultHealth,
            summary = summary
        )
    }

    private fun buildTenantRolloutProfile(
        userId: String,
        targetType: AlertRoutingTargetType,
        binding: ConnectorRouteBinding?,
        destination: ConnectorDestination?,
        authProfile: ConnectorAuthProfile?,
        now: Long
    ): TenantRolloutProfile {
        val tags = (destination?.tags.orEmpty() + authProfile?.scopeTags.orEmpty())
            .map { it.trim().lowercase() }
        val reasonText = binding?.reason?.lowercase().orEmpty()
        val stage = when {
            targetType == AlertRoutingTargetType.LOCAL_CONSOLE -> EnterpriseRolloutStage.GA
            tags.contains("rollout:disabled") || reasonText.contains("rollout_disabled") -> EnterpriseRolloutStage.DISABLED
            tags.contains("rollout:blocked") || reasonText.contains("rollout_blocked") -> EnterpriseRolloutStage.BLOCKED
            tags.contains("rollout:degraded") || reasonText.contains("rollout_degraded") -> EnterpriseRolloutStage.DEGRADED
            tags.contains("rollout:internal_only") || reasonText.contains("internal_only") -> EnterpriseRolloutStage.INTERNAL_ONLY
            tags.contains("rollout:canary") || reasonText.contains("rollout_canary") -> EnterpriseRolloutStage.CANARY
            tags.contains("rollout:limited_beta") || reasonText.contains("limited_beta") -> EnterpriseRolloutStage.LIMITED_BETA
            else -> EnterpriseRolloutStage.GA
        }
        val canaryUsers = tags.mapNotNull { tag ->
            if (tag.startsWith("canary_user:")) {
                tag.substringAfter("canary_user:").trim().takeIf { it.isNotBlank() }
            } else {
                null
            }
        }
        val workspaceId = destination?.ownerTeamId
            ?: tags.mapNotNull { tag ->
                if (tag.startsWith("workspace:")) {
                    tag.substringAfter("workspace:").trim().takeIf { it.isNotBlank() }
                } else {
                    null
                }
            }.firstOrNull()
        val tenantId = tags.mapNotNull { tag ->
            if (tag.startsWith("tenant:")) {
                tag.substringAfter("tenant:").trim().takeIf { it.isNotBlank() }
            } else {
                null
            }
        }.firstOrNull() ?: userId.substringBefore('_', userId)
        val dryRunOnly = tags.contains("rollout:dry_run") || reasonText.contains("dry_run")
        val externalEnabled = !tags.contains("external:false") && stage != EnterpriseRolloutStage.DISABLED &&
            stage != EnterpriseRolloutStage.BLOCKED
        return TenantRolloutProfile(
            tenantId = tenantId,
            workspaceId = workspaceId,
            environment = "production",
            stage = stage,
            externalConnectorEnabled = externalEnabled,
            canaryUserIds = canaryUsers,
            dryRunOnly = dryRunOnly,
            updatedAtMs = now,
            summary = "Rollout ${stage.name.lowercase().replace('_', ' ')} for ${targetType.name.lowercase().replace('_', ' ')}."
        )
    }

    private fun buildWorkspaceRolloutProfile(
        tenantProfile: TenantRolloutProfile,
        targetType: AlertRoutingTargetType,
        now: Long
    ): WorkspaceRolloutProfile {
        val cutover = if (tenantProfile.dryRunOnly) {
            CutoverReadinessStatus.FALLBACK_ONLY
        } else {
            CutoverReadinessStatus.READY
        }
        val degradation = if (tenantProfile.dryRunOnly) {
            ExecutionDegradationMode.DRY_RUN_ONLY
        } else {
            ExecutionDegradationMode.NONE
        }
        return WorkspaceRolloutProfile(
            workspaceId = tenantProfile.workspaceId ?: "workspace_default",
            stage = if (targetType == AlertRoutingTargetType.LOCAL_CONSOLE) {
                EnterpriseRolloutStage.GA
            } else {
                tenantProfile.stage
            },
            cutoverStatus = cutover,
            degradationMode = degradation,
            updatedAtMs = now,
            summary = "Workspace rollout ${tenantProfile.stage.name.lowercase().replace('_', ' ')}."
        )
    }

    private fun buildCutoverReadinessSummary(
        rolloutProfile: TenantRolloutProfile,
        workspaceProfile: WorkspaceRolloutProfile,
        directorySyncStatus: DirectorySyncStatus,
        remoteAuthorization: RemoteAuthorizationResult,
        vaultResolution: VaultResolutionResult?,
        now: Long
    ): CutoverReadinessSummary {
        val blockReasons = mutableListOf<DirectoryCutoverBlockReason>()
        if (
            rolloutProfile.stage == EnterpriseRolloutStage.DISABLED ||
            rolloutProfile.stage == EnterpriseRolloutStage.BLOCKED
        ) {
            blockReasons += DirectoryCutoverBlockReason.ROLLOUT_DISABLED
        }
        when (directorySyncStatus) {
            DirectorySyncStatus.DIRECTORY_UNAVAILABLE,
            DirectorySyncStatus.FAILED -> blockReasons += DirectoryCutoverBlockReason.DIRECTORY_UNAVAILABLE
            DirectorySyncStatus.STALE -> blockReasons += DirectoryCutoverBlockReason.DIRECTORY_STALE
            else -> Unit
        }
        if (remoteAuthorization.status == RemoteAuthorizationStatus.DENIED) {
            blockReasons += DirectoryCutoverBlockReason.SESSION_INVALID
        }
        val sessionFreshness = remoteAuthorization.sessionAuthContext?.freshness
            ?: remoteAuthorization.provenance?.sessionFreshness
        if (sessionFreshness == SessionFreshnessState.INVALIDATED) {
            blockReasons += DirectoryCutoverBlockReason.SESSION_INVALID
        }
        val sessionProvenance = remoteAuthorization.sessionAuthContext?.sessionProvenance
            ?: remoteAuthorization.provenance?.sessionProvenance
        val assertion = remoteAuthorization.sessionAuthContext?.identityAssertion
            ?: remoteAuthorization.provenance?.identityAssertion
        if (
            sessionProvenance != null &&
            sessionProvenance != EnterpriseSessionProvenance.LOCAL_ONLY &&
            assertion == null
        ) {
            blockReasons += DirectoryCutoverBlockReason.ASSERTION_MISSING
        }
        when (vaultResolution?.status) {
            VaultCredentialStatus.BACKEND_UNAVAILABLE,
            VaultCredentialStatus.ACCESS_DENIED,
            VaultCredentialStatus.LEASE_EXPIRED,
            VaultCredentialStatus.REVOKED -> blockReasons += DirectoryCutoverBlockReason.VAULT_UNHEALTHY
            else -> Unit
        }
        val status = when {
            blockReasons.contains(DirectoryCutoverBlockReason.ROLLOUT_DISABLED) -> CutoverReadinessStatus.BLOCKED
            blockReasons.contains(DirectoryCutoverBlockReason.SESSION_INVALID) -> CutoverReadinessStatus.BLOCKED
            blockReasons.contains(DirectoryCutoverBlockReason.DIRECTORY_UNAVAILABLE) -> CutoverReadinessStatus.BLOCKED
            blockReasons.contains(DirectoryCutoverBlockReason.VAULT_UNHEALTHY) -> CutoverReadinessStatus.BLOCKED
            workspaceProfile.cutoverStatus == CutoverReadinessStatus.FALLBACK_ONLY || rolloutProfile.dryRunOnly ->
                CutoverReadinessStatus.FALLBACK_ONLY
            rolloutProfile.stage == EnterpriseRolloutStage.DEGRADED -> CutoverReadinessStatus.DEGRADED
            blockReasons.contains(DirectoryCutoverBlockReason.DIRECTORY_STALE) ||
                blockReasons.contains(DirectoryCutoverBlockReason.ASSERTION_MISSING) ->
                CutoverReadinessStatus.NOT_READY
            else -> CutoverReadinessStatus.READY
        }
        val checks = listOf(
            DirectoryCutoverCheck(
                checkId = "rollout_stage",
                name = "Rollout stage",
                status = if (
                    rolloutProfile.stage == EnterpriseRolloutStage.BLOCKED ||
                    rolloutProfile.stage == EnterpriseRolloutStage.DISABLED
                ) {
                    CutoverReadinessStatus.BLOCKED
                } else {
                    CutoverReadinessStatus.READY
                },
                summary = "Stage ${rolloutProfile.stage.name.lowercase().replace('_', ' ')}."
            ),
            DirectoryCutoverCheck(
                checkId = "directory_sync",
                name = "Directory sync",
                status = when (directorySyncStatus) {
                    DirectorySyncStatus.DIRECTORY_UNAVAILABLE,
                    DirectorySyncStatus.FAILED -> CutoverReadinessStatus.BLOCKED
                    DirectorySyncStatus.STALE -> CutoverReadinessStatus.NOT_READY
                    else -> CutoverReadinessStatus.READY
                },
                summary = "Directory ${directorySyncStatus.name.lowercase().replace('_', ' ')}."
            ),
            DirectoryCutoverCheck(
                checkId = "vault_runtime",
                name = "Vault runtime",
                status = when (vaultResolution?.status) {
                    VaultCredentialStatus.BACKEND_UNAVAILABLE,
                    VaultCredentialStatus.ACCESS_DENIED,
                    VaultCredentialStatus.LEASE_EXPIRED,
                    VaultCredentialStatus.REVOKED -> CutoverReadinessStatus.BLOCKED
                    VaultCredentialStatus.ROTATION_DUE -> CutoverReadinessStatus.DEGRADED
                    else -> CutoverReadinessStatus.READY
                },
                summary = vaultResolution?.summary
                    ?: "No vault runtime resolution was required for this route."
            )
        )
        val summary = when (status) {
            CutoverReadinessStatus.READY -> "Enterprise cutover checks passed."
            CutoverReadinessStatus.NOT_READY -> "Enterprise cutover is not ready; local-first fallback remains active."
            CutoverReadinessStatus.DEGRADED -> "Enterprise cutover is degraded; execute with fallback safeguards."
            CutoverReadinessStatus.BLOCKED -> "Enterprise cutover blocked by rollout/directory/vault checks."
            CutoverReadinessStatus.FALLBACK_ONLY -> "Enterprise rollout is fallback-only in current workspace."
        }
        return CutoverReadinessSummary(
            status = status,
            blockReasons = blockReasons.distinct(),
            checks = checks,
            updatedAtMs = now,
            summary = summary
        )
    }

    private fun buildFeatureGateDecision(
        userId: String,
        targetType: AlertRoutingTargetType,
        tenantProfile: TenantRolloutProfile,
        workspaceProfile: WorkspaceRolloutProfile,
        cutoverReadiness: CutoverReadinessSummary
    ): FeatureGateDecision {
        if (targetType == AlertRoutingTargetType.LOCAL_CONSOLE) {
            return FeatureGateDecision(
                featureKey = "connector_route_${targetType.name.lowercase()}",
                allowed = true,
                rolloutStage = EnterpriseRolloutStage.GA,
                cutoverStatus = CutoverReadinessStatus.READY,
                degradationMode = ExecutionDegradationMode.NONE,
                reasonCodes = listOf(RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_STAGE_APPLIED),
                summary = "Local console route remains enabled."
            )
        }
        val isInternalUser = isInternalOperatorUser(userId)
        val canaryList = tenantProfile.canaryUserIds.map { it.lowercase() }
        val isCanaryAllowed = canaryList.isEmpty() || canaryList.contains(userId.lowercase())
        val decision = when {
            tenantProfile.stage == EnterpriseRolloutStage.DISABLED ||
                tenantProfile.stage == EnterpriseRolloutStage.BLOCKED ||
                !tenantProfile.externalConnectorEnabled ->
                Triple(false, ExecutionDegradationMode.BLOCKED, "Rollout stage blocks this connector route.")
            tenantProfile.stage == EnterpriseRolloutStage.INTERNAL_ONLY && !isInternalUser ->
                Triple(false, ExecutionDegradationMode.LOCAL_FALLBACK, "Internal-only rollout; local fallback applied.")
            tenantProfile.stage == EnterpriseRolloutStage.CANARY && !isCanaryAllowed ->
                Triple(false, ExecutionDegradationMode.LOCAL_FALLBACK, "Canary rollout restriction; local fallback applied.")
            tenantProfile.dryRunOnly || workspaceProfile.degradationMode == ExecutionDegradationMode.DRY_RUN_ONLY ->
                Triple(false, ExecutionDegradationMode.DRY_RUN_ONLY, "Dry-run rollout active; local execution fallback applied.")
            cutoverReadiness.status == CutoverReadinessStatus.BLOCKED ||
                cutoverReadiness.status == CutoverReadinessStatus.NOT_READY ->
                Triple(false, ExecutionDegradationMode.LOCAL_FALLBACK, cutoverReadiness.summary)
            cutoverReadiness.status == CutoverReadinessStatus.FALLBACK_ONLY ->
                Triple(false, ExecutionDegradationMode.LOCAL_FALLBACK, "Cutover fallback-only; local-first path retained.")
            tenantProfile.stage == EnterpriseRolloutStage.DEGRADED ||
                cutoverReadiness.status == CutoverReadinessStatus.DEGRADED ->
                Triple(false, ExecutionDegradationMode.LOCAL_FALLBACK, "Degraded enterprise rollout; local fallback applied.")
            else ->
                Triple(true, ExecutionDegradationMode.NONE, "Enterprise rollout and cutover checks allow connector route.")
        }
        val reasonCodes = mutableListOf(RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_STAGE_APPLIED)
        if (tenantProfile.stage == EnterpriseRolloutStage.CANARY && isCanaryAllowed) {
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_CANARY_ALLOWED
        }
        if (decision.first) {
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_READY
        } else {
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_BLOCKED
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
            if (cutoverReadiness.status == CutoverReadinessStatus.BLOCKED ||
                cutoverReadiness.status == CutoverReadinessStatus.NOT_READY
            ) {
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_BLOCKED
            } else if (cutoverReadiness.status == CutoverReadinessStatus.DEGRADED) {
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_DEGRADED
            }
        }
        return FeatureGateDecision(
            featureKey = "connector_route_${targetType.name.lowercase()}",
            allowed = decision.first,
            rolloutStage = tenantProfile.stage,
            cutoverStatus = cutoverReadiness.status,
            degradationMode = decision.second,
            reasonCodes = reasonCodes.distinct(),
            summary = decision.third
        )
    }

    private fun buildEnterpriseFallbackPolicy(
        decision: FeatureGateDecision
    ): EnterpriseFallbackPolicy {
        return if (decision.degradationMode == ExecutionDegradationMode.NONE) {
            EnterpriseFallbackPolicy(
                localFirst = true,
                degradationMode = ExecutionDegradationMode.NONE,
                summary = "Enterprise route allowed; local-first fallback remains available."
            )
        } else {
            EnterpriseFallbackPolicy(
                localFirst = true,
                degradationMode = decision.degradationMode,
                summary = "Enterprise route degraded to ${decision.degradationMode.name.lowercase().replace('_', ' ')}."
            )
        }
    }

    private fun buildVaultAccessAuditRecord(
        runId: String,
        targetType: AlertRoutingTargetType,
        resolution: VaultResolutionResult?,
        now: Long
    ): VaultAccessAuditRecord? {
        val resolved = resolution ?: return null
        val leaseStatus = when (resolved.status) {
            VaultCredentialStatus.BOUND,
            VaultCredentialStatus.LEASE_ACTIVE -> VaultLeaseStatus.ACTIVE
            VaultCredentialStatus.ROTATION_DUE -> VaultLeaseStatus.EXPIRING
            VaultCredentialStatus.LEASE_EXPIRED -> VaultLeaseStatus.EXPIRED
            VaultCredentialStatus.REVOKED -> VaultLeaseStatus.REVOKED
            VaultCredentialStatus.ACCESS_DENIED -> VaultLeaseStatus.DENIED
            VaultCredentialStatus.BACKEND_UNAVAILABLE -> VaultLeaseStatus.BACKEND_UNAVAILABLE
            VaultCredentialStatus.NOT_CONFIGURED,
            VaultCredentialStatus.UNKNOWN -> VaultLeaseStatus.UNKNOWN
        }
        return VaultAccessAuditRecord(
            auditId = "vault_audit_${runId}_${targetType.name.lowercase()}_$now",
            action = "resolve_credential_for_connector_route",
            status = leaseStatus,
            resolutionId = resolved.resolutionId.takeIf { it.isNotBlank() },
            summary = resolved.summary.ifBlank { "Vault runtime resolution evaluated for connector route." },
            timestampMs = now
        )
    }

    private fun buildVaultHealthSummary(
        resolutions: List<VaultResolutionResult>,
        now: Long
    ): VaultHealthSummary {
        if (resolutions.isEmpty()) return vaultRuntimePort.health(now)
        val statuses = resolutions.map { it.status }
        val leaseStatus = when {
            statuses.any { it == VaultCredentialStatus.ACCESS_DENIED } -> VaultLeaseStatus.DENIED
            statuses.any { it == VaultCredentialStatus.BACKEND_UNAVAILABLE } -> VaultLeaseStatus.BACKEND_UNAVAILABLE
            statuses.any { it == VaultCredentialStatus.LEASE_EXPIRED } -> VaultLeaseStatus.EXPIRED
            statuses.any { it == VaultCredentialStatus.REVOKED } -> VaultLeaseStatus.REVOKED
            statuses.any { it == VaultCredentialStatus.ROTATION_DUE } -> VaultLeaseStatus.EXPIRING
            statuses.any { it == VaultCredentialStatus.BOUND || it == VaultCredentialStatus.LEASE_ACTIVE } -> VaultLeaseStatus.ACTIVE
            else -> VaultLeaseStatus.UNKNOWN
        }
        val summary = when (leaseStatus) {
            VaultLeaseStatus.ACTIVE -> "Vault runtime healthy for current connector routes."
            VaultLeaseStatus.EXPIRING -> "Vault runtime healthy but one or more leases are expiring."
            VaultLeaseStatus.EXPIRED -> "Vault runtime reports expired leases; connector routes degrade to local fallback."
            VaultLeaseStatus.REVOKED -> "Vault runtime reports revoked credentials; affected routes are blocked."
            VaultLeaseStatus.DENIED -> "Vault runtime access denied for at least one route."
            VaultLeaseStatus.BACKEND_UNAVAILABLE -> "Vault backend unavailable; local-first fallback remains active."
            VaultLeaseStatus.UNKNOWN -> "Vault runtime state is not fully tracked for current routes."
        }
        return VaultHealthSummary(
            status = leaseStatus,
            summary = summary,
            lastCheckedAtMs = now
        )
    }

    private fun isInternalOperatorUser(userId: String): Boolean {
        val normalized = userId.trim().lowercase()
        return normalized == "local-user" ||
            normalized.contains("admin") ||
            normalized.contains("ops") ||
            normalized.contains("internal")
    }

    private fun isCredentialLifecycleBlocking(state: ConnectorCredentialLifecycleState): Boolean {
        return when (state) {
            ConnectorCredentialLifecycleState.EXPIRED,
            ConnectorCredentialLifecycleState.REVOKED,
            ConnectorCredentialLifecycleState.MISCONFIGURED -> true
            ConnectorCredentialLifecycleState.UNKNOWN,
            ConnectorCredentialLifecycleState.HEALTHY,
            ConnectorCredentialLifecycleState.EXPIRING,
            ConnectorCredentialLifecycleState.ROTATION_REQUIRED -> false
        }
    }

    private fun remoteAuthorizationSummaryFor(result: RemoteAuthorizationResult?): String? {
        val auth = result ?: return null
        val provenance = auth.provenance
        return when {
            auth.reason.isNotBlank() -> auth.reason
            provenance?.summary?.isNotBlank() == true -> provenance.summary
            auth.allowed -> "Remote operator authorization passed."
            else -> "Remote operator authorization failed."
        }
    }

    private fun connectorDestinationSummaryFor(records: List<AlertRoutingRecord>): String? {
        val destinations = records
            .flatMap { it.destinations }
            .distinctBy { it.destinationId }
        if (destinations.isEmpty()) return null
        return destinations.joinToString("; ") { destination ->
            val provider = destination.providerType.name.lowercase().replace('_', ' ')
            "$provider -> ${destination.label.ifBlank { destination.destinationId }}"
        }
    }

    private fun connectorAuthProfileSummaryFor(records: List<AlertRoutingRecord>): String? {
        val profiles = records
            .flatMap { it.authProfiles }
            .distinctBy { it.authProfileId }
        if (profiles.isEmpty()) return null
        return profiles.joinToString("; ") { profile ->
            val lifecycle = profile.credentialLifecycle?.state
                ?: profile.credentialRef?.lifecycle?.state
            val vaultStatus = profile.vaultCredential?.status
                ?: profile.credentialRef?.vaultCredential?.status
            val lifecycleText = lifecycle
                ?.name
                ?.lowercase()
                ?.replace('_', ' ')
                ?.let { ", $it" }
                ?: ""
            val vaultText = vaultStatus
                ?.name
                ?.lowercase()
                ?.replace('_', ' ')
                ?.let { ", vault $it" }
                ?: ""
            "${profile.providerType.name.lowercase().replace('_', ' ')} auth ${profile.authScheme} (${profile.status.name.lowercase().replace('_', ' ')}$lifecycleText$vaultText)"
        }
    }

    private fun directorySyncSummaryFor(
        authorization: RemoteAuthorizationResult?,
        routingRecords: List<AlertRoutingRecord>
    ): String? {
        val snapshot = routingRecords
            .mapNotNull { it.directorySync }
            .maxByOrNull { it.syncedAtMs ?: 0L }
        val authSyncStatus = authorization?.provenance?.directorySyncStatus
        val errorText = snapshot?.errorState
            ?.takeIf { it != DirectorySyncErrorState.NONE }
            ?.name
            ?.lowercase()
            ?.replace('_', ' ')
            ?.let { " (error: $it)" }
            ?: ""
        return when {
            snapshot != null && snapshot.summary.isNotBlank() -> snapshot.summary + errorText
            snapshot != null -> "Directory sync is ${snapshot.status.name.lowercase().replace('_', ' ')}$errorText."
            authSyncStatus != null -> "Directory sync is ${authSyncStatus.name.lowercase().replace('_', ' ')}."
            else -> null
        }
    }

    private fun sessionAuthProvenanceSummaryFor(authorization: RemoteAuthorizationResult?): String? {
        val auth = authorization ?: return null
        val provenance = auth.provenance
        val context = auth.sessionAuthContext
        if (provenance == null && context == null) return null
        return buildString {
            val authority = provenance?.authority ?: context?.authority
            authority?.let {
                append("Authority: ")
                append(it.name.lowercase().replace('_', ' '))
            }
            val provider = provenance?.idpProvider ?: context?.idpProvider
            provider?.let {
                if (isNotBlank()) append(" · ")
                append("IdP ")
                append(it.name.lowercase().replace('_', ' '))
            }
            val sessionProvenance = provenance?.sessionProvenance ?: context?.sessionProvenance
            sessionProvenance?.let {
                if (isNotBlank()) append(" · ")
                append("Session provenance ")
                append(it.name.lowercase().replace('_', ' '))
            }
            val freshness = provenance?.sessionFreshness ?: context?.freshness
            freshness?.let {
                if (isNotBlank()) append(" · ")
                append("Session ")
                append(it.name.lowercase().replace('_', ' '))
            }
            if (provenance?.usedFallback == true) {
                if (isNotBlank()) append(" · ")
                append("Local fallback applied")
            }
            val assertionSummary = context?.identityAssertion?.summary
                ?: provenance?.identityAssertion?.summary
            assertionSummary?.takeIf { it.isNotBlank() }?.let {
                if (isNotBlank()) append(" · ")
                append(it)
            }
        }.takeIf { it.isNotBlank() }
    }

    private fun connectorCredentialSummaryFor(records: List<AlertRoutingRecord>): String? {
        val lifecycles = records
            .flatMap { record ->
                buildList {
                    addAll(record.credentialLifecycleSummaries)
                    addAll(record.targets.mapNotNull { it.credentialLifecycle })
                    addAll(record.authProfiles.mapNotNull { it.credentialLifecycle })
                    addAll(record.destinations.mapNotNull { it.credentialLifecycle })
                }
            }
            .distinctBy { "${it.state}:${it.expiresAtMs}:${it.rotationRequired}:${it.revoked}" }
        val vaultStates = records
            .flatMap { record ->
                buildList {
                    addAll(record.targets.mapNotNull { it.credentialBinding?.vaultCredential?.status })
                    addAll(record.authProfiles.mapNotNull { it.vaultCredential?.status ?: it.credentialRef?.vaultCredential?.status })
                    addAll(record.destinations.mapNotNull { it.vaultCredential?.status ?: it.credentialRef?.vaultCredential?.status })
                }
            }
            .distinct()
        if (lifecycles.isEmpty() && vaultStates.isEmpty()) return null
        if (vaultStates.contains(VaultCredentialStatus.ACCESS_DENIED)) {
            return "Vault access denied for at least one connector credential; local fallback route is active."
        }
        if (vaultStates.contains(VaultCredentialStatus.BACKEND_UNAVAILABLE)) {
            return "Vault backend unavailable for at least one connector credential; local fallback route is active."
        }
        if (vaultStates.contains(VaultCredentialStatus.LEASE_EXPIRED)) {
            return "Vault lease expired for at least one connector credential; connector refresh is required."
        }
        if (vaultStates.contains(VaultCredentialStatus.REVOKED)) {
            return "Vault credential revoked for at least one connector target; route fallback is active."
        }
        if (vaultStates.contains(VaultCredentialStatus.ROTATION_DUE)) {
            return "Vault credential rotation is due for at least one connector target."
        }
        if (lifecycles.isEmpty()) return null
        val states = lifecycles.map { it.state }.distinct()
        val summary = when {
            states.contains(ConnectorCredentialLifecycleState.REVOKED) ->
                "Credential revoked; connector route fallback is active."
            states.contains(ConnectorCredentialLifecycleState.EXPIRED) ->
                "Credential expired; connector route fallback is active."
            states.contains(ConnectorCredentialLifecycleState.MISCONFIGURED) ->
                "Credential misconfigured; connector route fallback is active."
            states.contains(ConnectorCredentialLifecycleState.ROTATION_REQUIRED) ->
                "Credential rotation is required for at least one connector target."
            states.contains(ConnectorCredentialLifecycleState.EXPIRING) ->
                "Credential is expiring soon for at least one connector target."
            states.contains(ConnectorCredentialLifecycleState.HEALTHY) ->
                "Connector credentials are healthy for selected targets."
            else ->
                "Credential lifecycle metadata is available for connector routing."
        }
        return summary
    }

    private fun buildOperatorConnectorAuditLink(
        operatorIdentity: OperatorIdentity,
        directoryEntry: RemoteOperatorDirectoryEntry?,
        remoteAuthorization: RemoteAuthorizationResult?,
        routingRecord: AlertRoutingRecord?,
        now: Long
    ): OperatorConnectorAuditLink? {
        val target = routingRecord?.targets?.lastOrNull()
        val credentialBinding = target?.credentialBinding
        val routeBlockReason = target?.credentialRouteBlockReason ?: CredentialRouteBlockReason.NONE
        val credentialLifecycle = target?.credentialLifecycle
            ?: routingRecord?.credentialLifecycleSummaries?.lastOrNull()
        val deliveryStatus = routingRecord?.deliveryRecords
            ?.lastOrNull { delivery ->
                target == null ||
                    (
                        delivery.target.targetId == target.targetId &&
                            delivery.target.providerType == (target.connectorProviderType ?: connectorProviderTypeFor(target.targetType))
                        )
            }
            ?.status
            ?: routingRecord?.deliveryRecords?.lastOrNull()?.status
        if (remoteAuthorization == null && target == null && directoryEntry == null) return null
        val directorySyncSnapshot = directoryEntry?.directorySync
        val identityProvenance = OperatorIdentityProvenance(
            identitySource = operatorIdentity.remoteDirectorySource ?: directoryEntry?.identity?.directorySource,
            enterpriseSource = enterpriseSourceFor(operatorIdentity.remoteDirectorySource ?: directoryEntry?.identity?.directorySource),
            directorySync = directorySyncSnapshot,
            remoteIdentityLink = directoryEntry?.remoteIdentityLink ?: RemoteIdentityLink(
                operatorId = operatorIdentity.remoteOperatorId
                    ?: directoryEntry?.identity?.operatorId
                    ?: "",
                directoryEntryId = operatorIdentity.remoteDirectoryEntryId ?: directoryEntry?.entryId,
                status = if (
                    operatorIdentity.remoteOperatorId.isNullOrBlank() &&
                    directoryEntry?.identity?.operatorId.isNullOrBlank()
                ) {
                    RemoteIdentityLinkStatus.LOCAL_ONLY
                } else {
                    RemoteIdentityLinkStatus.LINKED
                },
                source = enterpriseSourceFor(operatorIdentity.remoteDirectorySource ?: directoryEntry?.identity?.directorySource),
                linkedAtMs = now,
                summary = "Identity linkage recorded for connector audit trace."
            ),
            summary = remoteAuthorization?.provenance?.summary
                ?: "Identity provenance captured for connector routing audit."
        )
        val reasonCodes = mutableListOf<String>()
        reasonCodes += remoteAuthorization?.reasonCodes.orEmpty()
        if (target?.destinationId != null) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DESTINATION_SELECTED
        } else {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DESTINATION_DENIED
        }
        if (!target?.authProfileId.isNullOrBlank()) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_AUTH_PROFILE_APPLIED
        }
        when (credentialLifecycle?.state) {
            ConnectorCredentialLifecycleState.HEALTHY -> reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_HEALTHY
            ConnectorCredentialLifecycleState.EXPIRING -> reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_EXPIRING
            ConnectorCredentialLifecycleState.REVOKED -> {
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_REVOKED
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
            }
            ConnectorCredentialLifecycleState.ROTATION_REQUIRED ->
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_ROTATION_REQUIRED
            ConnectorCredentialLifecycleState.EXPIRED,
            ConnectorCredentialLifecycleState.MISCONFIGURED ->
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
            ConnectorCredentialLifecycleState.UNKNOWN,
            null -> Unit
        }
        when (credentialBinding?.vaultCredential?.status) {
            VaultCredentialStatus.BOUND,
            VaultCredentialStatus.LEASE_ACTIVE -> {
                reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BOUND
                reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_ACTIVE
            }
            VaultCredentialStatus.ROTATION_DUE -> reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ROTATION_SCHEDULED
            VaultCredentialStatus.REVOKED -> reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_REVOKED
            VaultCredentialStatus.ACCESS_DENIED -> reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ACCESS_DENIED
            VaultCredentialStatus.BACKEND_UNAVAILABLE -> reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BACKEND_UNAVAILABLE
            VaultCredentialStatus.LEASE_EXPIRED -> reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_EXPIRED
            VaultCredentialStatus.NOT_CONFIGURED,
            VaultCredentialStatus.UNKNOWN,
            null -> Unit
        }
        if (routeBlockReason != CredentialRouteBlockReason.NONE) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        target?.featureGateDecision?.let { gate ->
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_STAGE_APPLIED
            if (!gate.allowed) {
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_BLOCKED
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_ROLLOUT
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
            }
            when (gate.cutoverStatus) {
                CutoverReadinessStatus.READY -> reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_READY
                CutoverReadinessStatus.DEGRADED -> {
                    reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_DEGRADED
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
                }
                CutoverReadinessStatus.NOT_READY,
                CutoverReadinessStatus.BLOCKED,
                CutoverReadinessStatus.FALLBACK_ONLY -> {
                    reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_BLOCKED
                    reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
                }
            }
        }
        when (target?.degradationMode) {
            ExecutionDegradationMode.NONE,
            null -> Unit
            ExecutionDegradationMode.LOCAL_FALLBACK,
            ExecutionDegradationMode.DRY_RUN_ONLY,
            ExecutionDegradationMode.BLOCKED -> reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
        }
        when (target?.vaultResolution?.status) {
            VaultCredentialStatus.BOUND,
            VaultCredentialStatus.LEASE_ACTIVE -> reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_RESOLVED
            VaultCredentialStatus.ROTATION_DUE,
            VaultCredentialStatus.LEASE_EXPIRED -> reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_DEGRADED
            VaultCredentialStatus.ACCESS_DENIED,
            VaultCredentialStatus.BACKEND_UNAVAILABLE -> reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_BLOCKED
            VaultCredentialStatus.NOT_CONFIGURED,
            VaultCredentialStatus.REVOKED,
            VaultCredentialStatus.UNKNOWN,
            null -> Unit
        }
        return OperatorConnectorAuditLink(
            operatorUserId = operatorIdentity.userId,
            operatorDisplayName = operatorIdentity.displayName,
            operatorTeamId = operatorIdentity.remoteTeamId ?: directoryEntry?.identity?.teamId ?: directoryEntry?.team?.teamId,
            remoteOperatorId = operatorIdentity.remoteOperatorId ?: directoryEntry?.identity?.operatorId,
            directoryEntryId = operatorIdentity.remoteDirectoryEntryId ?: directoryEntry?.entryId,
            identityProvenance = identityProvenance,
            sessionAuthContext = remoteAuthorization?.sessionAuthContext,
            destinationId = target?.destinationId,
            authProfileId = target?.authProfileId,
            routeBindingId = target?.routeBindingId,
            credentialBinding = credentialBinding,
            credentialRouteBlockReason = routeBlockReason,
            authorizationStatus = remoteAuthorization?.status,
            credentialLifecycle = credentialLifecycle,
            deliveryStatus = deliveryStatus,
            summary = buildString {
                append("Operator ")
                append(operatorIdentity.displayName)
                append(" routed follow-up")
                target?.let {
                    append(" to ")
                    append(it.label.ifBlank { it.targetType.name.lowercase().replace('_', ' ') })
                }
                remoteAuthorization?.let {
                    append(" (auth ")
                    append(it.status.name.lowercase().replace('_', ' '))
                    append(")")
                }
                credentialLifecycle?.let {
                    append(" [credential ")
                    append(it.state.name.lowercase().replace('_', ' '))
                    append("]")
                }
                if (routeBlockReason != CredentialRouteBlockReason.NONE) {
                    append(" [route block ")
                    append(routeBlockReason.name.lowercase().replace('_', ' '))
                    append("]")
                }
            },
            reasonCodes = reasonCodes.distinct(),
            recordedAtMs = now
        )
    }

    private fun defaultOperatorRole(userId: String): OperatorRole {
        val normalized = userId.trim().lowercase()
        return when {
            normalized.contains("admin") || normalized == "local-user" -> OperatorRole.ADMIN
            normalized.contains("dispute") -> OperatorRole.DISPUTE_MANAGER
            normalized.contains("triage") -> OperatorRole.TRIAGE_OPERATOR
            normalized.contains("compliance") -> OperatorRole.COMPLIANCE_REVIEWER
            normalized.contains("viewer") || normalized.contains("readonly") -> OperatorRole.READ_ONLY
            else -> OperatorRole.LOCAL_OPERATOR
        }
    }

    private fun defaultOperatorDisplayName(userId: String): String {
        return userId.trim()
            .takeIf { it.isNotBlank() }
            ?.replace('_', ' ')
            ?.replaceFirstChar { it.uppercase() }
            ?: "Local Operator"
    }

