                OperatorPermission.RETRY_SYNC,
                OperatorPermission.CLAIM_CASE,
                OperatorPermission.RELEASE_CASE,
                OperatorPermission.ASSIGN_CASE,
                OperatorPermission.REASSIGN_CASE,
                OperatorPermission.ESCALATE_CASE,
                OperatorPermission.ADD_NOTE,
                OperatorPermission.REQUEST_FOLLOW_UP,
                OperatorPermission.ACK_REMOTE_HANDOFF,
                OperatorPermission.COPY_CASE_SUMMARY,
                OperatorPermission.EXPORT_CASE_SUMMARY,
                OperatorPermission.OPEN_RECEIPT_TRAIL,
                OperatorPermission.APPLY_WORKFLOW_TEMPLATE,
                OperatorPermission.ADVANCE_WORKFLOW_STAGE,
                OperatorPermission.RUN_SAFE_AUTOMATION,
                OperatorPermission.MANAGE_POLICY_ROLLOUT,
                OperatorPermission.APPROVE_POLICY_ROLLOUT
            )

            OperatorRole.TRIAGE_OPERATOR -> listOf(
                OperatorPermission.MARK_REVIEWED,
                OperatorPermission.CLAIM_CASE,
                OperatorPermission.RELEASE_CASE,
                OperatorPermission.ASSIGN_CASE,
                OperatorPermission.REASSIGN_CASE,
                OperatorPermission.ADD_NOTE,
                OperatorPermission.REQUEST_FOLLOW_UP,
                OperatorPermission.COPY_CASE_SUMMARY,
                OperatorPermission.OPEN_RECEIPT_TRAIL,
                OperatorPermission.APPLY_WORKFLOW_TEMPLATE,
                OperatorPermission.ADVANCE_WORKFLOW_STAGE,
                OperatorPermission.RUN_SAFE_AUTOMATION
            )

            OperatorRole.COMPLIANCE_REVIEWER -> listOf(
                OperatorPermission.MARK_REVIEWED,
                OperatorPermission.ADD_NOTE,
                OperatorPermission.COPY_CASE_SUMMARY,
                OperatorPermission.OPEN_RECEIPT_TRAIL,
                OperatorPermission.APPLY_WORKFLOW_TEMPLATE,
                OperatorPermission.ADVANCE_WORKFLOW_STAGE,
                OperatorPermission.APPROVE_POLICY_ROLLOUT
            )

            OperatorRole.READ_ONLY -> listOf(
                OperatorPermission.COPY_CASE_SUMMARY,
                OperatorPermission.OPEN_RECEIPT_TRAIL
            )

            OperatorRole.LOCAL_OPERATOR -> listOf(
                OperatorPermission.MARK_REVIEWED,
                OperatorPermission.RETRY_SYNC,
                OperatorPermission.CLAIM_CASE,
                OperatorPermission.RELEASE_CASE,
                OperatorPermission.ASSIGN_CASE,
                OperatorPermission.ADD_NOTE,
                OperatorPermission.REQUEST_FOLLOW_UP,
                OperatorPermission.ACK_REMOTE_HANDOFF,
                OperatorPermission.COPY_CASE_SUMMARY,
                OperatorPermission.EXPORT_CASE_SUMMARY,
                OperatorPermission.OPEN_RECEIPT_TRAIL,
                OperatorPermission.APPLY_WORKFLOW_TEMPLATE,
                OperatorPermission.ADVANCE_WORKFLOW_STAGE,
                OperatorPermission.RUN_SAFE_AUTOMATION,
                OperatorPermission.MANAGE_POLICY_ROLLOUT
            )
        }
    }

    private fun requiredPermissionForAction(action: GovernanceActionType): OperatorPermission? {
        return when (action) {
            GovernanceActionType.CLAIM_CASE -> OperatorPermission.CLAIM_CASE
            GovernanceActionType.UNCLAIM_CASE,
            GovernanceActionType.RELEASE_CASE -> OperatorPermission.RELEASE_CASE
            GovernanceActionType.ASSIGN_CASE -> OperatorPermission.ASSIGN_CASE
            GovernanceActionType.REASSIGN_CASE -> OperatorPermission.REASSIGN_CASE
            GovernanceActionType.ESCALATE_CASE -> OperatorPermission.ESCALATE_CASE
            GovernanceActionType.ADD_NOTE -> OperatorPermission.ADD_NOTE
            GovernanceActionType.REQUEST_FOLLOW_UP -> OperatorPermission.REQUEST_FOLLOW_UP
            GovernanceActionType.ACK_REMOTE_HANDOFF -> OperatorPermission.ACK_REMOTE_HANDOFF
            GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE -> OperatorPermission.APPLY_WORKFLOW_TEMPLATE
            GovernanceActionType.ADVANCE_WORKFLOW_STAGE -> OperatorPermission.ADVANCE_WORKFLOW_STAGE
            GovernanceActionType.RUN_SAFE_AUTOMATION -> OperatorPermission.RUN_SAFE_AUTOMATION
            GovernanceActionType.REQUEST_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.PROMOTE_POLICY_ROLLOUT,
            GovernanceActionType.ENFORCE_POLICY_ROLLOUT,
            GovernanceActionType.PAUSE_POLICY_ROLLOUT,
            GovernanceActionType.RESUME_POLICY_ROLLOUT,
            GovernanceActionType.FREEZE_POLICY_ROLLOUT,
            GovernanceActionType.ROLLBACK_POLICY_ROLLOUT,
            GovernanceActionType.EXPAND_POLICY_ROLLOUT_SCOPE,
            GovernanceActionType.REQUEST_POLICY_PROMOTION,
            GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
            GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
            GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
            GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
            GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
            GovernanceActionType.DEPRECATE_POLICY_PACK,
            GovernanceActionType.RETIRE_POLICY_PACK,
            GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT,
            GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
            GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
            GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.PAUSE_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.RESUME_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.CANCEL_POLICY_ESTATE_REMEDIATION,
            GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION -> OperatorPermission.MANAGE_POLICY_ROLLOUT
            GovernanceActionType.APPROVE_POLICY_ROLLOUT,
            GovernanceActionType.DENY_POLICY_ROLLOUT_APPROVAL,
            GovernanceActionType.APPROVE_POLICY_PROMOTION,
            GovernanceActionType.REJECT_POLICY_PROMOTION -> OperatorPermission.APPROVE_POLICY_ROLLOUT
            GovernanceActionType.MARK_REVIEWED -> OperatorPermission.MARK_REVIEWED
            GovernanceActionType.RETRY_SYNC_INTENT -> OperatorPermission.RETRY_SYNC
            GovernanceActionType.COPY_CASE_SUMMARY -> OperatorPermission.COPY_CASE_SUMMARY
            GovernanceActionType.EXPORT_CASE_SUMMARY -> OperatorPermission.EXPORT_CASE_SUMMARY
            GovernanceActionType.OPEN_RECEIPT_TRAIL -> OperatorPermission.OPEN_RECEIPT_TRAIL
            GovernanceActionType.FILTER_PROVIDER_CASES,
            GovernanceActionType.FILTER_ROLE_CASES -> null
        }
    }

    private fun authorizeOperatorAction(
        action: GovernanceActionType,
        identity: OperatorIdentity,
        currentState: GovernanceCaseCollaborationState?,
        command: GovernanceCollaborationCommand? = null
    ): OperatorPermissionDecision {
        val requiredPermission = requiredPermissionForAction(action)
        if (requiredPermission != null && !identity.permissions.contains(requiredPermission)) {
            return OperatorPermissionDecision(
                allowed = false,
                identity = identity,
                requiredPermission = requiredPermission,
                denialReason = OperatorPermissionDenialReason.PERMISSION_MISSING,
                message = "Operator ${identity.displayName} lacks ${requiredPermission.name.lowercase().replace('_', ' ')} permission."
            )
        }
        if (action == GovernanceActionType.ASSIGN_CASE || action == GovernanceActionType.REASSIGN_CASE) {
            if (command?.assignee == null) {
                return OperatorPermissionDecision(
                    allowed = false,
                    identity = identity,
                    requiredPermission = requiredPermission,
                    denialReason = OperatorPermissionDenialReason.INVALID_ASSIGNMENT_PAYLOAD,
                    message = "Assignee is required for ${action.name.lowercase().replace('_', ' ')}."
                )
            }
        }
        if (action == GovernanceActionType.ESCALATE_CASE) {
            val target = command?.escalationTarget?.trim().orEmpty()
            if (target.isBlank()) {
                return OperatorPermissionDecision(
                    allowed = false,
                    identity = identity,
                    requiredPermission = requiredPermission,
                    denialReason = OperatorPermissionDenialReason.INVALID_ESCALATION_PAYLOAD,
                    message = "Escalation target is required for escalation action."
                )
            }
        }
        if (action == GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE) {
            val templateId = command?.workflowTemplateId?.trim().orEmpty()
            if (templateId.isBlank()) {
                return OperatorPermissionDecision(
                    allowed = false,
                    identity = identity,
                    requiredPermission = requiredPermission,
                    denialReason = OperatorPermissionDenialReason.INVALID_WORKFLOW_PAYLOAD,
                    message = "Workflow template ID is required to attach workflow template."
                )
            }
        }
        if (action == GovernanceActionType.ADVANCE_WORKFLOW_STAGE && command?.workflowStage == null) {
            return OperatorPermissionDecision(
                allowed = false,
                identity = identity,
                requiredPermission = requiredPermission,
                denialReason = OperatorPermissionDenialReason.INVALID_WORKFLOW_PAYLOAD,
                message = "Workflow stage is required to advance workflow."
            )
        }
        when (identity.scope) {
            PermissionScope.ANY_CASE -> Unit
            PermissionScope.ASSIGNED_CASES -> {
                val assignedTo = currentState?.assignedTo
                if (
                    assignedTo?.userId != null &&
                    assignedTo.userId != identity.userId &&
                    action != GovernanceActionType.CLAIM_CASE
                ) {
                    return OperatorPermissionDecision(
                        allowed = false,
                        identity = identity,
                        requiredPermission = requiredPermission,
                        denialReason = OperatorPermissionDenialReason.SCOPE_RESTRICTED,
                        message = "Action blocked: operator scope allows assigned cases only."
                    )
                }
            }

            PermissionScope.OWNED_CASES -> {
                val claimedBy = currentState?.claimedBy
                if (
                    claimedBy?.userId != null &&
                    claimedBy.userId != identity.userId &&
                    action != GovernanceActionType.CLAIM_CASE
                ) {
                    return OperatorPermissionDecision(
                        allowed = false,
                        identity = identity,
                        requiredPermission = requiredPermission,
                        denialReason = OperatorPermissionDenialReason.SCOPE_RESTRICTED,
                        message = "Action blocked: operator scope allows owned cases only."
                    )
                }
            }
        }
        return OperatorPermissionDecision(
            allowed = true,
            identity = identity,
            requiredPermission = requiredPermission
        )
    }

    private fun assignmentFromState(
        runId: String,
        state: GovernanceCaseCollaborationState,
        now: Long
    ): GovernanceCaseAssignment {
        return GovernanceCaseAssignment(
            runId = runId,
            claimedBy = state.claimedBy,
            assignedTo = state.assignedTo,
            claimStatus = state.claimStatus,
            escalated = state.escalation?.escalated == true,
            escalationTarget = state.escalation?.target,
            version = state.version,
            updatedAtMs = now
        )
    }

    private fun assignmentEventFrom(
        eventId: String,
        type: GovernanceCaseAssignmentEventType,
        actor: OperatorAssigneeRef,
        summary: String,
        reasonCodes: List<String>,
        now: Long
    ): GovernanceCaseAssignmentEvent {
        return GovernanceCaseAssignmentEvent(
            eventId = eventId,
            type = type,
            actor = actor,
            summary = summary,
            reasonCodes = reasonCodes,
            timestampMs = now
        )
    }

    private fun upsertCollaborationStateLocked(userId: String, incoming: GovernanceCaseCollaborationState) {
        val queue = collaborationStateByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val index = records.indexOfLast { it.runId == incoming.runId }
        if (index >= 0) {
            records[index] = mergeCollaborationState(records[index], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun recordPermissionDeniedLocked(
        userId: String,
        runId: String,
        action: GovernanceActionType,
        actor: OperatorAssigneeRef,
        denialReason: OperatorPermissionDenialReason,
        message: String,
        requiredPermission: OperatorPermission?,
        now: Long
    ): Boolean {
        val ledger = executionLedgerByUser[userId] ?: return false
        val records = ledger.toMutableList()
        val targetIndex = records.indexOfLast { it.runId == runId }
        if (targetIndex < 0) return false
        val target = records[targetIndex]
        val denialCodes = buildList {
            add(RoleReasonCodes.ROLE_OPERATOR_PERMISSION_DENIED)
            when (denialReason) {
                OperatorPermissionDenialReason.REMOTE_AUTH_DENIED,
                OperatorPermissionDenialReason.REMOTE_AUTH_CONTEXT_INVALID,
                OperatorPermissionDenialReason.REMOTE_DIRECTORY_ENTRY_MISSING ->
                    add(RoleReasonCodes.ROLE_REMOTE_OPERATOR_AUTH_DENIED)

                OperatorPermissionDenialReason.CONNECTOR_DESTINATION_UNAVAILABLE ->
                    add(RoleReasonCodes.ROLE_CONNECTOR_DESTINATION_DENIED)

                OperatorPermissionDenialReason.CONNECTOR_CREDENTIAL_INVALID ->
                    add(RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_MISSING)

                else -> Unit
            }
            requiredPermission?.let { permission ->
                add("ROLE_PERMISSION_REQUIRED_${permission.name}")
            }
            add("ROLE_PERMISSION_DENIAL_${denialReason.name}")
        }
        val denialRecord = OperatorPermissionDenialRecord(
            denialId = "denial_${runId}_${action.name.lowercase()}_$now",
            action = action,
            reason = denialReason,
            message = message,
            actor = actor,
            timestampMs = now
        )
        val existingCollaboration = target.collaborationState
            ?: collaborationStateForRunLocked(userId, runId)
            ?: GovernanceCaseCollaborationState(runId = runId)
        val updatedCollaboration = existingCollaboration.copy(
            permissionDenials = (existingCollaboration.permissionDenials + denialRecord).takeLast(20),
            lastActionSummary = message,
            updatedAtMs = now
        )
        upsertCollaborationStateLocked(userId, updatedCollaboration)
        val denialEvent = RunEventRecord(
            eventId = "perm_denied_${runId}_${action.name.lowercase()}_$now",
            type = ProofLedgerEventType.OPERATOR_PERMISSION_DENIED,
            title = "Operator permission denied",
            detail = message,
            timestampMs = now,
            reasonCodes = denialCodes
        )
        records[targetIndex] = target.copy(
            runEvents = (target.runEvents + denialEvent)
                .distinctBy { "${it.type}:${it.detail}:${it.timestampMs}" }
                .sortedBy { it.timestampMs }
                .takeLast(MAX_LEDGER_EVENTS_PER_RUN),
            collaborationState = updatedCollaboration,
            updatedAtMs = now
        )
        executionLedgerByUser[userId] = ArrayDeque(records.takeLast(MAX_LEDGER_RECORDS))
        return true
    }

    private fun mergeCollaborationState(
        previous: GovernanceCaseCollaborationState,
        incoming: GovernanceCaseCollaborationState
    ): GovernanceCaseCollaborationState {
        val mergedNotes = (previous.notes + incoming.notes)
            .distinctBy { "${it.actor.userId}:${it.note}:${it.createdAtMs}" }
            .sortedBy { it.createdAtMs }
            .takeLast(20)
        val mergedAssignmentEvents = (previous.assignmentEvents + incoming.assignmentEvents)
            .distinctBy { "${it.eventId}:${it.type}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(20)
        val mergedPermissionDenials = (previous.permissionDenials + incoming.permissionDenials)
            .distinctBy { "${it.denialId}:${it.action}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(20)
        val mergedRoutingActions = (previous.routingActions + incoming.routingActions)
            .distinctBy { "${it.actionId}:${it.actionType}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(20)
        val mergedFollowUp = incoming.followUp ?: previous.followUp
        return incoming.copy(
            status = incoming.status,
            claimStatus = incoming.claimStatus,
            claimedBy = incoming.claimedBy ?: previous.claimedBy,
            assignedTo = incoming.assignedTo ?: previous.assignedTo,
            operatorSession = incoming.operatorSession ?: previous.operatorSession,
            assignment = incoming.assignment ?: previous.assignment,
            assignmentEvents = mergedAssignmentEvents,
            escalation = incoming.escalation ?: previous.escalation,
            permissionDenials = mergedPermissionDenials,
            followUp = mergedFollowUp,
            notes = mergedNotes,
            routingActions = mergedRoutingActions,
            lastActionSummary = incoming.lastActionSummary.ifBlank { previous.lastActionSummary },
            version = maxOf(previous.version, incoming.version),
            updatedAtMs = maxOf(previous.updatedAtMs, incoming.updatedAtMs)
        )
    }

    private fun upsertRemoteOperatorHandoffRecordLocked(userId: String, incoming: RemoteOperatorHandoffRecord) {
        val queue = remoteOperatorHandoffByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val index = records.indexOfLast { it.runId == incoming.runId }
        if (index >= 0) {
            records[index] = mergeRemoteOperatorHandoffRecord(records[index], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun mergeRemoteOperatorHandoffRecord(
        previous: RemoteOperatorHandoffRecord?,
        incoming: RemoteOperatorHandoffRecord
    ): RemoteOperatorHandoffRecord {
        if (previous == null) return incoming
        val mergedAttempts = (previous.attempts + incoming.attempts)
            .distinctBy { "${it.status}:${it.dedupeKey}:${it.errorCode}:${it.timestampMs}" }
            .sortedBy { it.timestampMs }
            .takeLast(12)
        val mergedStatus = when {
            previous.status == RemoteOperatorHandoffStatus.FAILED || incoming.status == RemoteOperatorHandoffStatus.FAILED ->
                RemoteOperatorHandoffStatus.FAILED
            previous.status == RemoteOperatorHandoffStatus.ACKNOWLEDGED || incoming.status == RemoteOperatorHandoffStatus.ACKNOWLEDGED ->
                RemoteOperatorHandoffStatus.ACKNOWLEDGED
            previous.status == RemoteOperatorHandoffStatus.ACK_PENDING || incoming.status == RemoteOperatorHandoffStatus.ACK_PENDING ->
                RemoteOperatorHandoffStatus.ACK_PENDING
            previous.status == RemoteOperatorHandoffStatus.HANDED_OFF || incoming.status == RemoteOperatorHandoffStatus.HANDED_OFF ->
                RemoteOperatorHandoffStatus.HANDED_OFF
            previous.status == RemoteOperatorHandoffStatus.HANDOFF_PENDING || incoming.status == RemoteOperatorHandoffStatus.HANDOFF_PENDING ->
                RemoteOperatorHandoffStatus.HANDOFF_PENDING
            previous.status == RemoteOperatorHandoffStatus.REQUESTED || incoming.status == RemoteOperatorHandoffStatus.REQUESTED ->
                RemoteOperatorHandoffStatus.REQUESTED
            else -> RemoteOperatorHandoffStatus.NOT_REQUESTED
        }
        return incoming.copy(
            status = mergedStatus,
            dedupeKey = incoming.dedupeKey.ifBlank { previous.dedupeKey },
            request = incoming.request ?: previous.request,
            attempts = mergedAttempts,
            lastAttemptAtMs = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs),
            lastErrorSummary = incoming.lastErrorSummary ?: previous.lastErrorSummary
        )
    }

    private fun upsertAlertRoutingRecordLocked(userId: String, incoming: AlertRoutingRecord) {
        val queue = alertRoutingByUser.getOrPut(userId) { ArrayDeque() }
        val records = queue.toMutableList()
        val index = records.indexOfLast {
            it.runId == incoming.runId && it.alertCode == incoming.alertCode
        }
        if (index >= 0) {
            records[index] = mergeAlertRoutingRecord(records[index], incoming)
        } else {
            records += incoming
        }
        queue.clear()
        records.takeLast(MAX_REMOTE_PIPELINE_RECORDS).forEach(queue::addLast)
    }

    private fun mergeAlertRoutingRecord(
        previous: AlertRoutingRecord,
        incoming: AlertRoutingRecord
    ): AlertRoutingRecord {
        val mergedAttempts = (previous.attempts + incoming.attempts)
            .distinctBy {
                it.connectorDeliveryAttempt?.attemptId
                    ?: "${it.targetType}:${it.status}:${it.dedupeKey}:${it.timestampMs}"
            }
            .sortedBy { it.timestampMs }
            .takeLast(16)
        val mergedTargets = (previous.targets + incoming.targets)
            .distinctBy { "${it.targetId}:${it.targetType}" }
            .takeLast(8)
        val mergedDeliveryRecords = buildConnectorDeliveryRecordsFromAttempts(
            runId = incoming.runId.ifBlank { previous.runId },
            alertCode = incoming.alertCode.ifBlank { previous.alertCode },
            attempts = mergedAttempts
        )
        val mergedDeadLetters = mergeConnectorDeadLetterRecords(
            runId = incoming.runId.ifBlank { previous.runId },
            alertCode = incoming.alertCode.ifBlank { previous.alertCode },
            previous = previous.deadLetterRecords,
            incoming = incoming.deadLetterRecords,
            deliveryRecords = mergedDeliveryRecords,
            referenceTs = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs)
        )
        val mergedHealthSummary = buildConnectorHealthSummaryFromDeliveryRecords(
            deliveryRecords = mergedDeliveryRecords,
            deadLetterCount = mergedDeadLetters.size,
            now = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs)
        )
        val mergedStatus = when {
            mergedDeadLetters.isNotEmpty() -> AlertRoutingStatus.FAILED
            previous.status == AlertRoutingStatus.FAILED || incoming.status == AlertRoutingStatus.FAILED ->
                AlertRoutingStatus.FAILED
            previous.status == AlertRoutingStatus.QUEUED || incoming.status == AlertRoutingStatus.QUEUED ->
                AlertRoutingStatus.QUEUED
            previous.status == AlertRoutingStatus.LOCAL_ONLY || incoming.status == AlertRoutingStatus.LOCAL_ONLY ->
                AlertRoutingStatus.LOCAL_ONLY
            previous.status == AlertRoutingStatus.DUPLICATE_SUPPRESSED || incoming.status == AlertRoutingStatus.DUPLICATE_SUPPRESSED ->
                AlertRoutingStatus.DUPLICATE_SUPPRESSED
            else -> AlertRoutingStatus.DELIVERED
        }
        return incoming.copy(
            status = mergedStatus,
            dedupeKey = incoming.dedupeKey.ifBlank { previous.dedupeKey },
            targets = mergedTargets,
            attempts = mergedAttempts,
            deliveryRecords = mergedDeliveryRecords,
            deadLetterRecords = mergedDeadLetters,
            connectorHealthSummary = mergedHealthSummary,
            lastAttemptAtMs = maxOf(previous.lastAttemptAtMs, incoming.lastAttemptAtMs),
            deliveredAtMs = incoming.deliveredAtMs ?: previous.deliveredAtMs,
            lastErrorSummary = mergedDeadLetters.lastOrNull()?.summary
                ?: incoming.lastErrorSummary
                ?: previous.lastErrorSummary
        )
    }

    private fun buildConnectorDeliveryRecordsFromAttempts(
        runId: String,
        alertCode: String,
        attempts: List<AlertRoutingAttempt>
    ): List<ConnectorDeliveryRecord> {
        val connectorAttempts = attempts.mapNotNull { attempt ->
            val deliveryAttempt = attempt.connectorDeliveryAttempt ?: return@mapNotNull null
            val deliveryRequest = attempt.connectorDeliveryRequest
            Triple(attempt, deliveryRequest, deliveryAttempt)
        }
        return connectorAttempts
            .groupBy { (_, request, deliveryAttempt) ->
                val provider = request?.target?.providerType ?: deliveryAttempt.providerType
                val targetId = request?.target?.targetId ?: deliveryAttempt.targetId
                "$targetId:$provider"
            }
            .values
            .mapNotNull { grouped ->
                val latest = grouped.maxByOrNull { (_, _, deliveryAttempt) -> deliveryAttempt.timestampMs }
                    ?: return@mapNotNull null
                val latestRequest = latest.second
                val latestAttempt = latest.third
                val attemptsForRecord = grouped.map { it.third }
                    .distinctBy { attempt -> "${attempt.attemptId}:${attempt.status}:${attempt.timestampMs}" }
                    .sortedBy { it.timestampMs }
                    .takeLast(12)
                val status = connectorDeliveryStatusForRecord(attemptsForRecord)
                ConnectorDeliveryRecord(
                    recordId = "connector_record_${runId}_${latestAttempt.targetId}_${latestAttempt.providerType.name.lowercase()}",
                    runId = runId,
                    alertCode = alertCode,
                    target = latestRequest?.target ?: com.lumi.coredomain.contract.ConnectorDeliveryTarget(
                        targetId = latestAttempt.targetId,
                        label = latestAttempt.providerType.name.lowercase().replace('_', ' '),
                        providerType = latestAttempt.providerType
                    ),
                    dedupeKey = latestAttempt.dedupeKey,
                    status = status,
                    attempts = attemptsForRecord,
                    lastAck = attemptsForRecord.lastOrNull { attempt ->
                        attempt.ack?.status == ConnectorAckStatus.ACKNOWLEDGED
                    }?.ack ?: attemptsForRecord.lastOrNull()?.ack,
                    lastFailureReason = attemptsForRecord.lastOrNull { attempt ->
                        attempt.status == ConnectorDeliveryStatus.FAILED ||
                            attempt.status == ConnectorDeliveryStatus.DEAD_LETTER
                    }?.failureReason,
                    deadLetter = attemptsForRecord.lastOrNull { attempt ->
                        attempt.status == ConnectorDeliveryStatus.DEAD_LETTER
                    }?.deadLetter,
                    lastAttemptAtMs = attemptsForRecord.maxOfOrNull { it.timestampMs } ?: latestAttempt.timestampMs
                )
            }
            .sortedBy { it.lastAttemptAtMs }
            .takeLast(8)
    }

    private fun connectorDeliveryStatusForRecord(attempts: List<ConnectorDeliveryAttempt>): ConnectorDeliveryStatus {
        return when {
            attempts.any { it.status == ConnectorDeliveryStatus.DEAD_LETTER } -> ConnectorDeliveryStatus.DEAD_LETTER
            attempts.any { it.status == ConnectorDeliveryStatus.FAILED } -> ConnectorDeliveryStatus.FAILED
            attempts.any { it.status == ConnectorDeliveryStatus.ACK_PENDING } -> ConnectorDeliveryStatus.ACK_PENDING
            attempts.any { it.status == ConnectorDeliveryStatus.QUEUED } -> ConnectorDeliveryStatus.QUEUED
            attempts.any { it.status == ConnectorDeliveryStatus.LOCAL_ONLY } -> ConnectorDeliveryStatus.LOCAL_ONLY
            attempts.any { it.status == ConnectorDeliveryStatus.DUPLICATE_SUPPRESSED } -> ConnectorDeliveryStatus.DUPLICATE_SUPPRESSED
            attempts.any {
                it.status == ConnectorDeliveryStatus.ACKNOWLEDGED ||
                    it.status == ConnectorDeliveryStatus.DELIVERED
            } -> ConnectorDeliveryStatus.ACKNOWLEDGED
            else -> ConnectorDeliveryStatus.REQUESTED
        }
    }

    private fun mergeConnectorDeadLetterRecords(
        runId: String,
        alertCode: String,
        previous: List<ConnectorDeadLetterRecord>,
        incoming: List<ConnectorDeadLetterRecord>,
        deliveryRecords: List<ConnectorDeliveryRecord>,
        referenceTs: Long
    ): List<ConnectorDeadLetterRecord> {
        val existing = (previous + incoming)
            .distinctBy { "${it.targetId}:${it.providerType}:${it.dedupeKey}:${it.summary}" }
            .toMutableList()
        deliveryRecords.forEach { delivery ->
            val failedAttempts = delivery.attempts.count { attempt ->
                attempt.status == ConnectorDeliveryStatus.FAILED ||
                    attempt.status == ConnectorDeliveryStatus.DEAD_LETTER
            }
            val acknowledged = delivery.attempts.any { attempt ->
                attempt.status == ConnectorDeliveryStatus.ACKNOWLEDGED
            }
            val shouldDeadLetter = failedAttempts >= CONNECTOR_DEAD_LETTER_THRESHOLD && !acknowledged
            if (shouldDeadLetter && existing.none { it.targetId == delivery.target.targetId && it.providerType == delivery.target.providerType }) {
                val latestFailure = delivery.attempts.lastOrNull { it.failureReason != null }
                existing += ConnectorDeadLetterRecord(
                    deadLetterId = "dead_letter_${runId}_${delivery.target.targetId}_${referenceTs}",
                    runId = runId,
                    alertCode = alertCode,
                    targetId = delivery.target.targetId,
                    providerType = delivery.target.providerType,
                    dedupeKey = delivery.dedupeKey,
                    failureReason = latestFailure?.failureReason ?: ConnectorFailureReason.UNKNOWN,
                    summary = latestFailure?.summary
                        ?: "Connector delivery moved to dead-letter after repeated failures.",
                    attemptCount = failedAttempts,
                    createdAtMs = referenceTs
                )
            }
        }
        return existing
            .sortedBy { it.createdAtMs }
            .takeLast(12)
    }

    private fun buildConnectorHealthSummaryFromAttempts(
        attempts: List<AlertRoutingAttempt>,
        deadLetterCount: Int,
        now: Long
    ): ConnectorHealthSummary {
        val deliveryRecords = buildConnectorDeliveryRecordsFromAttempts(
            runId = attempts.firstOrNull()?.connectorDeliveryRequest?.runId.orEmpty(),
            alertCode = attempts.firstOrNull()?.connectorDeliveryRequest?.alertCode.orEmpty(),
            attempts = attempts
        )
        return buildConnectorHealthSummaryFromDeliveryRecords(
            deliveryRecords = deliveryRecords,
            deadLetterCount = deadLetterCount,
            now = now
        )
    }

    private fun buildConnectorHealthSummaryFromDeliveryRecords(
        deliveryRecords: List<ConnectorDeliveryRecord>,
        deadLetterCount: Int,
        now: Long
    ): ConnectorHealthSummary {
        if (deliveryRecords.isEmpty()) {
            return ConnectorHealthSummary(
                overallStatus = "unknown",
                lastUpdatedAtMs = now
            )
        }
        val degraded = deliveryRecords.count {
            it.status == ConnectorDeliveryStatus.FAILED ||
                it.status == ConnectorDeliveryStatus.ACK_PENDING ||
                it.status == ConnectorDeliveryStatus.QUEUED
        }
        val unavailable = deliveryRecords.count {
            it.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE ||
                it.status == ConnectorDeliveryStatus.LOCAL_ONLY
        }
        val healthy = deliveryRecords.count {
            it.status == ConnectorDeliveryStatus.ACKNOWLEDGED ||
                it.status == ConnectorDeliveryStatus.DELIVERED
        }
        val overall = when {
            deadLetterCount > 0 -> "critical"
            degraded > 0 -> "degraded"
            healthy > 0 -> "healthy"
            else -> "unknown"
        }
        return ConnectorHealthSummary(
            overallStatus = overall,
            healthyTargets = healthy,
            degradedTargets = degraded,
            deadLetterTargets = deadLetterCount,
            unavailableTargets = unavailable,
            lastUpdatedAtMs = deliveryRecords.maxOfOrNull { it.lastAttemptAtMs }.takeIf { it != null && it > 0 } ?: now
        )
    }

    private fun collaborationStateForRunLocked(userId: String, runId: String): GovernanceCaseCollaborationState? {
        return collaborationStateByUser[userId]
            ?.lastOrNull { it.runId == runId }
    }

    private fun remoteOperatorHandoffForRunLocked(userId: String, runId: String): RemoteOperatorHandoffRecord? {
        return remoteOperatorHandoffByUser[userId]
            ?.lastOrNull { it.runId == runId }
    }

    private fun alertRoutingForRunLocked(userId: String, runId: String): List<AlertRoutingRecord> {
        return alertRoutingByUser[userId]
            ?.filter { it.runId == runId }
            .orEmpty()
            .takeLast(4)
    }

    private fun buildRemoteOperatorHandoffSummary(
        handoff: RemoteOperatorHandoffRecord?
    ): RemoteOperatorHandoffSummary? {
        if (handoff == null) return null
        val reasonCodes = mutableListOf(RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_REQUESTED)
        when (handoff.status) {
            RemoteOperatorHandoffStatus.ACK_PENDING -> reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_ACK_PENDING
            RemoteOperatorHandoffStatus.HANDOFF_PENDING -> reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_PENDING
            RemoteOperatorHandoffStatus.ACKNOWLEDGED -> reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED
            RemoteOperatorHandoffStatus.FAILED -> reasonCodes += RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_FAILED
            else -> Unit
        }
        val summary = when (handoff.status) {
            RemoteOperatorHandoffStatus.NOT_REQUESTED -> "Remote operator handoff was not requested."
            RemoteOperatorHandoffStatus.REQUESTED -> "Remote operator handoff was requested."
            RemoteOperatorHandoffStatus.HANDOFF_PENDING -> "Remote handoff is pending operator workflow processing."
            RemoteOperatorHandoffStatus.HANDED_OFF -> "Remote handoff was sent to operator workflow."
            RemoteOperatorHandoffStatus.ACK_PENDING -> "Remote handoff is waiting manual acknowledgement."
            RemoteOperatorHandoffStatus.ACKNOWLEDGED -> "Remote handoff was acknowledged."
            RemoteOperatorHandoffStatus.FAILED -> handoff.lastErrorSummary ?: "Remote handoff failed and needs retry."
        }
        return RemoteOperatorHandoffSummary(
            status = handoff.status,
            summary = summary,
            ackRequired = handoff.status == RemoteOperatorHandoffStatus.ACK_PENDING,
            reasonCodes = reasonCodes.distinct(),
            lastUpdatedAtMs = handoff.lastAttemptAtMs
        )
    }

    private fun buildAlertRoutingSummary(records: List<AlertRoutingRecord>): AlertRoutingSummary? {
        if (records.isEmpty()) return null
        val attempts = records.flatMap { it.attempts }
        val deadLetterCount = records.sumOf { it.deadLetterRecords.size }
        val pending = attempts.count {
            it.status == AlertRoutingStatus.QUEUED || it.status == AlertRoutingStatus.LOCAL_ONLY
        }
        val delivered = attempts.count { it.status == AlertRoutingStatus.DELIVERED }
        val failed = attempts.count { it.status == AlertRoutingStatus.FAILED }
        val status = when {
            failed > 0 -> AlertRoutingStatus.FAILED
            pending > 0 -> AlertRoutingStatus.QUEUED
            attempts.any { it.status == AlertRoutingStatus.LOCAL_ONLY } -> AlertRoutingStatus.LOCAL_ONLY
            attempts.any { it.status == AlertRoutingStatus.DUPLICATE_SUPPRESSED } -> AlertRoutingStatus.DUPLICATE_SUPPRESSED
            else -> AlertRoutingStatus.DELIVERED
        }
        val reasonCodes = mutableListOf(
            when (status) {
                AlertRoutingStatus.DELIVERED -> RoleReasonCodes.ROLE_ALERT_ROUTING_DELIVERED
                AlertRoutingStatus.FAILED -> RoleReasonCodes.ROLE_ALERT_ROUTING_FAILED
                AlertRoutingStatus.QUEUED,
                AlertRoutingStatus.LOCAL_ONLY,
                AlertRoutingStatus.DUPLICATE_SUPPRESSED -> RoleReasonCodes.ROLE_ALERT_ROUTING_QUEUED
            }
        )
        if (pending > 0 && status != AlertRoutingStatus.FAILED) {
            reasonCodes += RoleReasonCodes.ROLE_ALERT_ROUTING_RETRY_SCHEDULED
        }
        if (deadLetterCount > 0) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
        }
        val latest = attempts.maxOfOrNull { it.timestampMs } ?: nowMs()
        return AlertRoutingSummary(
            status = status,
            summary = "Alert routing ${status.name.lowercase().replace('_', ' ')} (pending $pending, delivered $delivered, failed $failed, dead-letter $deadLetterCount).",
            pendingTargets = pending,
            deliveredTargets = delivered,
            failedTargets = failed,
            reasonCodes = reasonCodes.distinct(),
            lastUpdatedAtMs = latest
        )
    }

    private fun buildConnectorRoutingSummary(records: List<AlertRoutingRecord>): ConnectorRoutingSummary? {
        if (records.isEmpty()) return null
        val attempts = records.flatMap { it.attempts }
        val deliveryRecords = records.flatMap { it.deliveryRecords }
        val selectedTargets = attempts.map { it.targetType }.distinct()
        val failedTargets = attempts
            .filter { it.status == AlertRoutingStatus.FAILED }
            .map { it.targetType }
            .distinct()
        val deadLetterTargets = records.flatMap { it.deadLetterRecords }
            .map { it.targetId }
            .distinct()
            .size
        val ackedTargets = deliveryRecords.count {
            it.status == ConnectorDeliveryStatus.ACKNOWLEDGED || it.status == ConnectorDeliveryStatus.DELIVERED
        }
        val unavailableTargets = deliveryRecords.count {
            it.status == ConnectorDeliveryStatus.LOCAL_ONLY ||
                it.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE
        }
        val health = buildConnectorHealthSummaryFromDeliveryRecords(
            deliveryRecords = deliveryRecords,
            deadLetterCount = deadLetterTargets,
            now = attempts.maxOfOrNull { it.timestampMs } ?: nowMs()
        )
        val status = when {
            deadLetterTargets > 0 -> AlertRoutingStatus.FAILED
            failedTargets.isNotEmpty() -> AlertRoutingStatus.FAILED
            attempts.any { it.status == AlertRoutingStatus.QUEUED || it.status == AlertRoutingStatus.LOCAL_ONLY } ->
                AlertRoutingStatus.QUEUED
            attempts.any { it.status == AlertRoutingStatus.DUPLICATE_SUPPRESSED } ->
                AlertRoutingStatus.DUPLICATE_SUPPRESSED
            else -> AlertRoutingStatus.DELIVERED
        }
        val reasonCodes = mutableListOf(
            RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_REQUESTED,
            if (failedTargets.isNotEmpty()) {
                RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
            } else {
                RoleReasonCodes.ROLE_CONNECTOR_ROUTE_SELECTED
            }
        )
        if (status == AlertRoutingStatus.QUEUED && failedTargets.isEmpty()) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_RETRIED
        }
        if (deadLetterTargets > 0) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_HEALTH_DEGRADED
        } else if (health.overallStatus == "healthy") {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_HEALTH_RECOVERED
        }
        if (unavailableTargets > 0) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE
        }
        if (ackedTargets > 0) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
        }
        val lifecycleStates = records
            .flatMap { it.credentialLifecycleSummaries }
            .map { it.state }
            .distinct()
        val blockedRouteReasons = records
            .flatMap { routing -> routing.targets.map { it.credentialRouteBlockReason } }
            .filter { it != CredentialRouteBlockReason.NONE }
            .distinct()
        val vaultStates = records
            .flatMap { routing ->
                routing.targets.mapNotNull { it.credentialBinding?.vaultCredential?.status } +
                    routing.vaultResolutions.map { it.status } +
                    routing.authProfiles.mapNotNull { it.vaultCredential?.status ?: it.credentialRef?.vaultCredential?.status } +
                    routing.destinations.mapNotNull { it.vaultCredential?.status ?: it.credentialRef?.vaultCredential?.status }
            }
            .distinct()
        val rolloutStage = records
            .mapNotNull { it.tenantRolloutProfile?.stage }
            .maxByOrNull { it.ordinal }
            ?: EnterpriseRolloutStage.GA
        val cutoverStatus = records
            .mapNotNull { it.cutoverReadiness?.status }
            .maxByOrNull { it.ordinal }
            ?: CutoverReadinessStatus.READY
        val degradationMode = records
            .flatMap { routing -> routing.targets.map { it.degradationMode } }
            .maxByOrNull { it.ordinal }
            ?: ExecutionDegradationMode.NONE
        val featureGateDecisions = records.flatMap { routing ->
            routing.targets.mapNotNull { it.featureGateDecision }
        }
        val rolloutSummary = records
            .mapNotNull { it.tenantRolloutProfile?.summary }
            .firstOrNull { it.isNotBlank() }
            ?: "Enterprise rollout stage ${rolloutStage.name.lowercase().replace('_', ' ')}."
        val cutoverSummary = records
            .mapNotNull { it.cutoverReadiness?.summary }
            .firstOrNull { it.isNotBlank() }
            ?: "Enterprise cutover ${cutoverStatus.name.lowercase().replace('_', ' ')}."
        val fallbackSummary = records
            .mapNotNull { it.fallbackPolicy?.summary }
            .firstOrNull { it.isNotBlank() }
            ?: if (degradationMode == ExecutionDegradationMode.NONE) {
                "Enterprise route allowed with local-first fallback available."
            } else {
                "Local-first fallback is active due to rollout/cutover safeguards."
            }
        val vaultRuntimeSummary = buildVaultHealthSummary(
            resolutions = records.flatMap { it.vaultResolutions },
            now = attempts.maxOfOrNull { it.timestampMs } ?: nowMs()
        ).summary
        if (lifecycleStates.contains(ConnectorCredentialLifecycleState.HEALTHY)) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_HEALTHY
        }
        if (lifecycleStates.contains(ConnectorCredentialLifecycleState.EXPIRING)) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_EXPIRING
        }
        if (lifecycleStates.contains(ConnectorCredentialLifecycleState.ROTATION_REQUIRED)) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_ROTATION_REQUIRED
        }
        if (lifecycleStates.contains(ConnectorCredentialLifecycleState.REVOKED)) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_REVOKED
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
        }
        if (
            lifecycleStates.contains(ConnectorCredentialLifecycleState.EXPIRED) ||
            lifecycleStates.contains(ConnectorCredentialLifecycleState.MISCONFIGURED)
        ) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
        }
        if (vaultStates.contains(VaultCredentialStatus.BOUND) || vaultStates.contains(VaultCredentialStatus.LEASE_ACTIVE)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BOUND
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_ACTIVE
        }
        if (vaultStates.contains(VaultCredentialStatus.ROTATION_DUE)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ROTATION_SCHEDULED
        }
        if (vaultStates.contains(VaultCredentialStatus.REVOKED)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_REVOKED
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        if (vaultStates.contains(VaultCredentialStatus.ACCESS_DENIED)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ACCESS_DENIED
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        if (vaultStates.contains(VaultCredentialStatus.BACKEND_UNAVAILABLE)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BACKEND_UNAVAILABLE
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        if (vaultStates.contains(VaultCredentialStatus.LEASE_EXPIRED)) {
            reasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_EXPIRED
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        if (blockedRouteReasons.isNotEmpty()) {
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
        }
        reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_STAGE_APPLIED
        when (rolloutStage) {
            EnterpriseRolloutStage.CANARY -> {
                if (featureGateDecisions.any { it.allowed }) {
                    reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_CANARY_ALLOWED
                }
            }

            EnterpriseRolloutStage.BLOCKED,
            EnterpriseRolloutStage.DISABLED,
            EnterpriseRolloutStage.DEGRADED,
            EnterpriseRolloutStage.INTERNAL_ONLY,
            EnterpriseRolloutStage.LIMITED_BETA,
            EnterpriseRolloutStage.GA -> Unit
        }
        if (featureGateDecisions.any { !it.allowed }) {
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_BLOCKED
            reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
            reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_ROLLOUT
        }
        when (cutoverStatus) {
            CutoverReadinessStatus.READY -> reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_READY
            CutoverReadinessStatus.DEGRADED -> {
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_DEGRADED
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
            }
            CutoverReadinessStatus.NOT_READY,
            CutoverReadinessStatus.BLOCKED,
            CutoverReadinessStatus.FALLBACK_ONLY -> {
                reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_BLOCKED
                reasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
            }
        }
        when (degradationMode) {
            ExecutionDegradationMode.NONE -> Unit
            ExecutionDegradationMode.LOCAL_FALLBACK,
            ExecutionDegradationMode.DRY_RUN_ONLY,
            ExecutionDegradationMode.BLOCKED -> reasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
        }
        when {
            vaultStates.any { it == VaultCredentialStatus.BACKEND_UNAVAILABLE || it == VaultCredentialStatus.ACCESS_DENIED } -> {
                reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_BLOCKED
            }
            vaultStates.any { it == VaultCredentialStatus.LEASE_EXPIRED || it == VaultCredentialStatus.ROTATION_DUE } -> {
                reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_DEGRADED
            }
            vaultStates.any { it == VaultCredentialStatus.BOUND || it == VaultCredentialStatus.LEASE_ACTIVE } -> {
                reasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_RESOLVED
            }
        }
        val latest = attempts.maxOfOrNull { it.timestampMs } ?: nowMs()
        return ConnectorRoutingSummary(
            status = status,
            summary = "Connector routing ${status.name.lowercase().replace('_', ' ')} across ${selectedTargets.size} target(s) (acked $ackedTargets, dead-letter $deadLetterTargets, unavailable $unavailableTargets).",
            selectedTargetTypes = selectedTargets,
            failedTargetTypes = failedTargets,
            ackedTargets = ackedTargets,
            deadLetterTargets = deadLetterTargets,
            unavailableTargets = unavailableTargets,
            connectorHealthSummary = health,
            reasonCodes = reasonCodes.distinct(),
            rolloutStage = rolloutStage,
            cutoverStatus = cutoverStatus,
            degradationMode = degradationMode,
            rolloutSummary = rolloutSummary,
            cutoverSummary = cutoverSummary,
            vaultRuntimeSummary = vaultRuntimeSummary,
            enterpriseFallbackSummary = fallbackSummary,
            featureGateDecisions = featureGateDecisions,
            blockedRouteReasons = blockedRouteReasons,
            lastUpdatedAtMs = latest
        )
    }

    private fun buildCollaborationRoutingRunEvents(
        runId: String,
        records: List<AlertRoutingRecord>,
        fallbackTimestampMs: Long
    ): List<RunEventRecord> {
        if (records.isEmpty()) return emptyList()
        return records.flatMap { record ->
            val recordKey = record.recordId.ifBlank {
                "alert_${runId}_${record.alertCode}_${record.lastAttemptAtMs.takeIf { it > 0 } ?: fallbackTimestampMs}"
            }
            val eventTimestamp = record.lastAttemptAtMs.takeIf { it > 0 } ?: fallbackTimestampMs
            val targetTypes = if (record.targets.isNotEmpty()) {
                record.targets.map { it.targetType }
            } else {
                record.attempts.map { it.targetType }
            }.distinct()
            val targetSummary = if (targetTypes.isEmpty()) {
                "no explicit targets"
            } else {
                targetTypes.joinToString(", ") { it.name.lowercase().replace('_', ' ') }
            }
            val alertReasonCodes = mutableListOf(
                when (record.status) {
                    AlertRoutingStatus.DELIVERED -> RoleReasonCodes.ROLE_ALERT_ROUTING_DELIVERED
                    AlertRoutingStatus.FAILED -> RoleReasonCodes.ROLE_ALERT_ROUTING_FAILED
                    AlertRoutingStatus.QUEUED,
                    AlertRoutingStatus.LOCAL_ONLY,
                    AlertRoutingStatus.DUPLICATE_SUPPRESSED -> RoleReasonCodes.ROLE_ALERT_ROUTING_QUEUED
                }
            )
            if (record.status == AlertRoutingStatus.QUEUED || record.status == AlertRoutingStatus.LOCAL_ONLY) {
                alertReasonCodes += RoleReasonCodes.ROLE_ALERT_ROUTING_RETRY_SCHEDULED
            }
            val connectorReasonCodes = mutableListOf(
                if (record.status == AlertRoutingStatus.FAILED) {
                    RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
                } else {
                    RoleReasonCodes.ROLE_CONNECTOR_ROUTE_SELECTED
                }
            )
            if (record.deliveryRecords.isNotEmpty()) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_REQUESTED
            }
            if (record.status == AlertRoutingStatus.QUEUED || record.status == AlertRoutingStatus.LOCAL_ONLY) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_RETRIED
            }
            if (record.deliveryRecords.any { delivery ->
                    delivery.status == ConnectorDeliveryStatus.ACKNOWLEDGED ||
                        delivery.status == ConnectorDeliveryStatus.DELIVERED
                }
            ) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
            }
            if (record.deliveryRecords.any { delivery ->
                    delivery.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE ||
                        delivery.status == ConnectorDeliveryStatus.LOCAL_ONLY
                }
            ) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE
            }
            if (record.deadLetterRecords.isNotEmpty()) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
            }
            val lifecycleStates = record.credentialLifecycleSummaries.map { it.state }.distinct()
            if (lifecycleStates.contains(ConnectorCredentialLifecycleState.HEALTHY)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_HEALTHY
            }
            if (lifecycleStates.contains(ConnectorCredentialLifecycleState.EXPIRING)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_EXPIRING
            }
            if (lifecycleStates.contains(ConnectorCredentialLifecycleState.ROTATION_REQUIRED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_ROTATION_REQUIRED
            }
            if (lifecycleStates.contains(ConnectorCredentialLifecycleState.REVOKED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_REVOKED
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
            }
            if (
                lifecycleStates.contains(ConnectorCredentialLifecycleState.EXPIRED) ||
                lifecycleStates.contains(ConnectorCredentialLifecycleState.MISCONFIGURED)
            ) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
            }
            val blockedRouteReasons = record.targets
                .map { it.credentialRouteBlockReason }
                .filter { it != CredentialRouteBlockReason.NONE }
                .distinct()
            if (blockedRouteReasons.isNotEmpty()) {
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
            }
            val vaultStates = record.targets
                .mapNotNull { it.credentialBinding?.vaultCredential?.status }
                .distinct()
            if (vaultStates.contains(VaultCredentialStatus.BOUND) || vaultStates.contains(VaultCredentialStatus.LEASE_ACTIVE)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BOUND
            }
            if (vaultStates.contains(VaultCredentialStatus.ROTATION_DUE)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ROTATION_SCHEDULED
            }
            if (vaultStates.contains(VaultCredentialStatus.REVOKED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_REVOKED
            }
            if (vaultStates.contains(VaultCredentialStatus.ACCESS_DENIED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ACCESS_DENIED
            }
            if (vaultStates.contains(VaultCredentialStatus.BACKEND_UNAVAILABLE)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BACKEND_UNAVAILABLE
            }
            if (vaultStates.contains(VaultCredentialStatus.LEASE_EXPIRED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_EXPIRED
            }
            val gateDecisions = record.targets.mapNotNull { it.featureGateDecision }
            if (gateDecisions.isNotEmpty()) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_STAGE_APPLIED
            }
            if (gateDecisions.any { !it.allowed }) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_ROLLOUT_BLOCKED
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_ROLLOUT
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
            }
            val cutoverStatuses = gateDecisions.map { it.cutoverStatus }.distinct()
            if (cutoverStatuses.contains(CutoverReadinessStatus.READY)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_READY
            }
            if (
                cutoverStatuses.contains(CutoverReadinessStatus.NOT_READY) ||
                cutoverStatuses.contains(CutoverReadinessStatus.BLOCKED) ||
                cutoverStatuses.contains(CutoverReadinessStatus.FALLBACK_ONLY)
            ) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_BLOCKED
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
            } else if (cutoverStatuses.contains(CutoverReadinessStatus.DEGRADED)) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_CUTOVER_DEGRADED
                connectorReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_DEGRADED_BY_CUTOVER
            }
            if (record.targets.any { it.degradationMode != ExecutionDegradationMode.NONE }) {
                connectorReasonCodes += RoleReasonCodes.ROLE_ENTERPRISE_FALLBACK_LOCAL_FIRST
            }
            val vaultResolutionStates = record.targets.mapNotNull { it.vaultResolution?.status }.distinct()
            if (vaultResolutionStates.any { it == VaultCredentialStatus.BOUND || it == VaultCredentialStatus.LEASE_ACTIVE }) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_RESOLVED
            }
            if (vaultResolutionStates.any { it == VaultCredentialStatus.ROTATION_DUE || it == VaultCredentialStatus.LEASE_EXPIRED }) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_DEGRADED
            }
            if (vaultResolutionStates.any { it == VaultCredentialStatus.ACCESS_DENIED || it == VaultCredentialStatus.BACKEND_UNAVAILABLE }) {
                connectorReasonCodes += RoleReasonCodes.ROLE_VAULT_RUNTIME_BLOCKED
            }
            val alertEventType = when (record.status) {
                AlertRoutingStatus.DELIVERED -> ProofLedgerEventType.ALERT_ROUTING_DELIVERED
                AlertRoutingStatus.FAILED -> ProofLedgerEventType.ALERT_ROUTING_FAILED
                AlertRoutingStatus.QUEUED,
                AlertRoutingStatus.LOCAL_ONLY,
                AlertRoutingStatus.DUPLICATE_SUPPRESSED -> ProofLedgerEventType.ALERT_ROUTING_QUEUED
            }
            val events = mutableListOf<RunEventRecord>()
            events += listOf(
                RunEventRecord(
                    eventId = "${recordKey}:alert",
                    type = alertEventType,
                    title = "Alert routing ${record.status.name.lowercase().replace('_', ' ')}",
                    detail = "Alert ${record.alertCode} routed via $targetSummary.",
                    timestampMs = eventTimestamp,
                    reasonCodes = alertReasonCodes.distinct()
                ),
                RunEventRecord(
                    eventId = "${recordKey}:connector",
                    type = ProofLedgerEventType.CONNECTOR_ROUTING_REQUESTED,
                    title = "Connector routing requested",
                    detail = "Connector routing evaluated ${targetTypes.size} target(s): $targetSummary.",
                    timestampMs = eventTimestamp,
                    reasonCodes = connectorReasonCodes.distinct()
                )
            )
            record.deliveryRecords.forEach { delivery ->
                val deliveryTimestamp = delivery.lastAttemptAtMs.takeIf { it > 0 } ?: eventTimestamp
                val targetLabel = delivery.target.label.ifBlank {
                    delivery.target.providerType.name.lowercase().replace('_', ' ')
                }
                val attemptReasonCodes = mutableListOf(RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_REQUESTED)
                val matchingTarget = record.targets.firstOrNull { it.targetId == delivery.target.targetId }
                val lifecycle = matchingTarget?.credentialLifecycle
                when (lifecycle?.state) {
                    ConnectorCredentialLifecycleState.HEALTHY ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_HEALTHY
                    ConnectorCredentialLifecycleState.EXPIRING ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_EXPIRING
                    ConnectorCredentialLifecycleState.ROTATION_REQUIRED ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_ROTATION_REQUIRED
                    ConnectorCredentialLifecycleState.REVOKED -> {
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_CREDENTIAL_REVOKED
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
                    }
                    ConnectorCredentialLifecycleState.EXPIRED,
                    ConnectorCredentialLifecycleState.MISCONFIGURED ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_CREDENTIAL_STATE
                    ConnectorCredentialLifecycleState.UNKNOWN,
                    null -> Unit
                }
                if (matchingTarget?.credentialRouteBlockReason != null &&
                    matchingTarget.credentialRouteBlockReason != CredentialRouteBlockReason.NONE
                ) {
                    attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_BLOCKED_BY_VAULT_STATE
                }
                when (matchingTarget?.credentialBinding?.vaultCredential?.status) {
                    VaultCredentialStatus.BOUND,
                    VaultCredentialStatus.LEASE_ACTIVE ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BOUND
                    VaultCredentialStatus.ROTATION_DUE ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ROTATION_SCHEDULED
                    VaultCredentialStatus.REVOKED ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_REVOKED
                    VaultCredentialStatus.ACCESS_DENIED ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_ACCESS_DENIED
                    VaultCredentialStatus.BACKEND_UNAVAILABLE ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_BACKEND_UNAVAILABLE
                    VaultCredentialStatus.LEASE_EXPIRED ->
                        attemptReasonCodes += RoleReasonCodes.ROLE_VAULT_CREDENTIAL_LEASE_EXPIRED
                    VaultCredentialStatus.NOT_CONFIGURED,
                    VaultCredentialStatus.UNKNOWN,
                    null -> Unit
                }
                when (delivery.status) {
                    ConnectorDeliveryStatus.ACKNOWLEDGED,
                    ConnectorDeliveryStatus.DELIVERED -> attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
                    ConnectorDeliveryStatus.LOCAL_ONLY -> attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE
                    ConnectorDeliveryStatus.FAILED,
                    ConnectorDeliveryStatus.DEAD_LETTER -> attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
                    ConnectorDeliveryStatus.DUPLICATE_SUPPRESSED -> attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_RETRIED
                    ConnectorDeliveryStatus.QUEUED,
                    ConnectorDeliveryStatus.REQUESTED,
                    ConnectorDeliveryStatus.ACK_PENDING -> attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_RETRIED
                }
                if (delivery.deadLetter != null || delivery.status == ConnectorDeliveryStatus.DEAD_LETTER) {
                    attemptReasonCodes += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
                }
                events += RunEventRecord(
                    eventId = "${recordKey}:connector_attempt:${delivery.target.targetId}",
                    type = ProofLedgerEventType.CONNECTOR_DELIVERY_ATTEMPTED,
                    title = "Connector delivery attempted",
                    detail = "Connector delivery to $targetLabel is ${delivery.status.name.lowercase().replace('_', ' ')}.",
                    timestampMs = deliveryTimestamp,
                    reasonCodes = attemptReasonCodes.distinct()
                )
                val statusEvent = when {
                    delivery.deadLetter != null || delivery.status == ConnectorDeliveryStatus.DEAD_LETTER ->
                        RunEventRecord(
                            eventId = "${recordKey}:connector_dead_letter:${delivery.target.targetId}",
                            type = ProofLedgerEventType.CONNECTOR_DELIVERY_DEAD_LETTERED,
                            title = "Connector delivery dead-lettered",
                            detail = delivery.deadLetter?.summary
                                ?: "Connector delivery moved to dead-letter for target $targetLabel.",
                            timestampMs = deliveryTimestamp,
                            reasonCodes = listOf(
                                RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED,
                                RoleReasonCodes.ROLE_CONNECTOR_HEALTH_DEGRADED
                            )
                        )

                    delivery.status == ConnectorDeliveryStatus.FAILED ->
                        RunEventRecord(
                            eventId = "${recordKey}:connector_failed:${delivery.target.targetId}",
                            type = ProofLedgerEventType.CONNECTOR_DELIVERY_FAILED,
                            title = "Connector delivery failed",
                            detail = delivery.lastFailureReason?.name
                                ?.lowercase()
                                ?.replace('_', ' ')
                                ?.let { "Connector delivery failed: $it." }
                                ?: "Connector delivery failed for target $targetLabel.",
                            timestampMs = deliveryTimestamp,
                            reasonCodes = listOf(
                                RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
                            )
                        )

                    delivery.status == ConnectorDeliveryStatus.ACKNOWLEDGED ||
                        delivery.status == ConnectorDeliveryStatus.DELIVERED ->
                        RunEventRecord(
                            eventId = "${recordKey}:connector_acked:${delivery.target.targetId}",
                            type = ProofLedgerEventType.CONNECTOR_DELIVERY_ACKED,
                            title = "Connector delivery acknowledged",
                            detail = "Connector destination acknowledged delivery for target $targetLabel.",
                            timestampMs = deliveryTimestamp,
                            reasonCodes = listOf(
                                RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
                            )
                        )

                    else -> null
                }
                statusEvent?.let { events += it }
            }
            val healthSummary = record.connectorHealthSummary
            if (healthSummary != null) {
                when (healthSummary.overallStatus.lowercase()) {
                    "critical", "degraded" -> events += RunEventRecord(
                        eventId = "${recordKey}:connector_health_degraded",
                        type = ProofLedgerEventType.CONNECTOR_HEALTH_DEGRADED,
                        title = "Connector health degraded",
                        detail = "Connector health is ${healthSummary.overallStatus} with ${healthSummary.deadLetterTargets} dead-letter target(s).",
                        timestampMs = healthSummary.lastUpdatedAtMs.takeIf { it > 0 } ?: eventTimestamp,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_CONNECTOR_HEALTH_DEGRADED
                        )
                    )

                    "healthy" -> events += RunEventRecord(
                        eventId = "${recordKey}:connector_health_recovered",
                        type = ProofLedgerEventType.CONNECTOR_HEALTH_RECOVERED,
                        title = "Connector health recovered",
                        detail = "Connector health recovered with ${healthSummary.healthyTargets} healthy target(s).",
                        timestampMs = healthSummary.lastUpdatedAtMs.takeIf { it > 0 } ?: eventTimestamp,
                        reasonCodes = listOf(
                            RoleReasonCodes.ROLE_CONNECTOR_HEALTH_RECOVERED
                        )
                    )
                }
            }
            events
        }
    }

    private data class CollaborationMutationResult(
        val success: Boolean,
        val message: String,
        val updatedCollaborationState: GovernanceCaseCollaborationState? = null,
        val updatedRemoteHandoff: RemoteOperatorHandoffRecord? = null,
        val updatedAlertRoutingRecords: List<AlertRoutingRecord> = emptyList(),
        val connectorRoutingSummary: ConnectorRoutingSummary? = null,
        val event: RunEventRecord? = null,
        val denialReason: OperatorPermissionDenialReason? = null,
        val requiredPermission: OperatorPermission? = null,
        val operatorIdentity: OperatorIdentity? = null,
        val remoteAuthorizationResult: RemoteAuthorizationResult? = null,
        val operatorConnectorAudit: OperatorConnectorAuditLink? = null
    )

    private data class OperatorResolution(
        val identity: OperatorIdentity,
        val directoryEntry: RemoteOperatorDirectoryEntry? = null,
        val remoteTeam: RemoteOperatorTeam? = null
    )

    private data class RemoteResourceSnapshot(
