        val requiredPermission: OperatorPermission? = null,
        val denialReason: OperatorPermissionDenialReason? = null,
        val message: String = ""
    )

    private fun normalizeGovernanceConsoleFilter(filter: GovernanceConsoleFilter): GovernanceConsoleFilter {
        return filter.copy(
            providerId = filter.providerId?.trim()?.takeIf { it.isNotBlank() },
            policySnapshotVersion = filter.policySnapshotVersion?.trim()?.takeIf { it.isNotBlank() },
            assigneeUserId = filter.assigneeUserId?.trim()?.takeIf { it.isNotBlank() },
            workflowTemplateId = filter.workflowTemplateId?.trim()?.takeIf { it.isNotBlank() },
            workflowPolicyPackId = filter.workflowPolicyPackId?.trim()?.takeIf { it.isNotBlank() },
            workflowPolicyPackVersion = filter.workflowPolicyPackVersion?.trim()?.takeIf { it.isNotBlank() },
            capacityPoolKey = filter.capacityPoolKey?.trim()?.takeIf { it.isNotBlank() },
            portfolioOptimizationDecisionId = filter.portfolioOptimizationDecisionId?.trim()?.takeIf { it.isNotBlank() },
            portfolioCalibrationSnapshotId = filter.portfolioCalibrationSnapshotId?.trim()?.takeIf { it.isNotBlank() },
            portfolioObjectiveProfileSnapshotId = filter.portfolioObjectiveProfileSnapshotId
                ?.trim()
                ?.takeIf { it.isNotBlank() },
            portfolioGovernancePortfolioId = filter.portfolioGovernancePortfolioId
                ?.trim()
                ?.takeIf { it.isNotBlank() },
            portfolioCrossBoundaryProgramId = filter.portfolioCrossBoundaryProgramId
                ?.trim()
                ?.takeIf { it.isNotBlank() },
            limit = filter.limit.coerceIn(1, MAX_GOVERNANCE_QUERY_LIMIT)
        )
    }

    private fun portfolioOptimizationLearningContextForRun(
        userId: String,
        runId: String
    ): PortfolioOptimizationLearningContext? {
        if (runId.isBlank()) return null
        return synchronized(dynamicStateLock) {
            portfolioOptimizationLearningContextForRunLocked(userId, runId)
        }
    }

    private fun portfolioOptimizationLearningContextForRunLocked(
        userId: String,
        runId: String
    ): PortfolioOptimizationLearningContext? {
        if (runId.isBlank()) return null
        recomputePortfolioOptimizationCrossBoundaryGovernancePortfolios(userId, nowMs())
        val resultsById = portfolioOptimizationResultsByUser[userId]?.toList().orEmpty()
            .associateBy { it.resultId }
        val decisions = portfolioOptimizationDecisionsByUser[userId]?.toList().orEmpty()
            .sortedWith(
                compareByDescending<PortfolioOptimizationDecisionRecord> { it.selectedAtMs }
                    .thenBy { it.decisionId }
            )
        val matchedDecision = decisions.firstOrNull { decision ->
            val candidate = resultsById[decision.resultId]
                ?.candidateSchedules
                ?.firstOrNull { it.candidateId == decision.candidateId }
            candidate?.scheduledActions?.any { it.sourceRunId == runId } == true ||
                candidate?.deferredActions?.any { it.sourceRunId == runId } == true
        } ?: return null
        val latestOutcome = portfolioOptimizationOutcomesByUser[userId]?.toList().orEmpty()
            .filter { it.decisionId == matchedDecision.decisionId }
            .maxWithOrNull(
                compareBy<PortfolioScheduleOutcomeRecord> { it.recordedAtMs }
                    .thenBy { it.outcomeId }
            )
        val latestDrift = latestOutcome?.driftSummaryId?.let { driftId ->
            portfolioOptimizationDriftSummariesByUser[userId]?.toList().orEmpty()
                .firstOrNull { it.driftId == driftId }
        }
        val latestSuggestion = portfolioOptimizationTuningSuggestionsByUser[userId]?.toList().orEmpty()
            .filter { it.decisionId == matchedDecision.decisionId }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationTuningSuggestion> { it.createdAtMs }
                    .thenBy { it.suggestionId }
            )
        val latestTuningDecision = portfolioOptimizationTuningDecisionsByUser[userId]?.toList().orEmpty()
            .filter { it.decisionId == matchedDecision.decisionId }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationTuningDecisionRecord> { it.decidedAtMs }
                    .thenBy { it.tuningDecisionId }
            )
        val objectiveProfileSnapshotId = matchedDecision.objectiveProfileSnapshotId
            .ifBlank { resultsById[matchedDecision.resultId]?.objectiveProfileSnapshotId.orEmpty() }
        val objectiveProfileSnapshot = findPortfolioOptimizationObjectiveProfileSnapshotLocked(
            userId = userId,
            snapshotId = objectiveProfileSnapshotId
        )
        val latestPropagationAttempt = portfolioOptimizationPropagationAttemptsByUser[userId]?.toList().orEmpty()
            .filter { attempt ->
                objectiveProfileSnapshotId.isNotBlank() &&
                    portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                        userId = userId,
                        leftSnapshotId = attempt.sourceObjectiveProfileSnapshotId,
                        rightSnapshotId = objectiveProfileSnapshotId
                    )
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationPropagationAttemptRecord> { it.createdAtMs }
                    .thenBy { it.attemptId }
            )
        val latestPropagationAdoption = portfolioOptimizationPropagationAdoptionsByUser[userId]?.toList().orEmpty()
            .filter { adoption ->
                objectiveProfileSnapshotId.isNotBlank() &&
                    (
                        adoption.sourceObjectiveProfileSnapshotId == objectiveProfileSnapshotId ||
                            adoption.targetObjectiveProfileSnapshotId == objectiveProfileSnapshotId ||
                            portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                                userId = userId,
                                leftSnapshotId = adoption.sourceObjectiveProfileSnapshotId,
                                rightSnapshotId = objectiveProfileSnapshotId
                            )
                        )
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationPropagationAdoptionRecord> { it.adoptedAtMs }
                    .thenBy { it.adoptionId }
            )
        val objectiveProfileSummary = buildString {
            objectiveProfileSnapshot?.let { snapshot ->
                append(portfolioOptimizationScopeLabel(snapshot.binding.scope))
                append(" scope")
                append(" · ")
                append(snapshot.provenance.type.name.lowercase().replace('_', ' '))
                snapshot.summary.takeIf { it.isNotBlank() }?.let {
                    append(" · ")
                    append(it)
                }
            }
        }
        val propagationSummary = latestPropagationAdoption?.summary
            ?.takeIf { it.isNotBlank() }
            ?: latestPropagationAttempt?.summary.orEmpty()
        val envelopesById = portfolioOptimizationLearningSyncEnvelopesByUser[userId]
            ?.toList()
            .orEmpty()
            .associateBy { it.envelopeId }
        val latestSyncAttempt = portfolioOptimizationLearningSyncAttemptsByUser[userId]?.toList().orEmpty()
            .filter { attempt ->
                envelopesById[attempt.envelopeId]?.let { envelope ->
                    portfolioOptimizationLearningSyncEnvelopeAppliesToObjectiveProfileLineageLocked(
                        userId = userId,
                        envelope = envelope,
                        objectiveProfileSnapshotId = objectiveProfileSnapshotId
                    )
                } == true
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationLearningSyncAttemptRecord> { it.processedAtMs }
                    .thenBy { it.attemptId }
            )
        val latestSyncConflict = portfolioOptimizationLearningSyncConflictsByUser[userId]?.toList().orEmpty()
            .filter { conflict ->
                portfolioOptimizationLearningSyncConflictAppliesToObjectiveProfileLineageLocked(
                    userId = userId,
                    conflict = conflict,
                    objectiveProfileSnapshotId = objectiveProfileSnapshotId,
                    envelopesById = envelopesById
                )
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationLearningSyncConflictRecord> { it.detectedAtMs }
                    .thenBy { it.conflictId }
            )
        val consentNow = nowMs()
        val learningSyncConsent = objectiveProfileSnapshot?.binding?.let { binding ->
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.LEARNING_SYNC,
                binding = binding,
                now = consentNow
            )
        }
        val remoteTransportConsent = objectiveProfileSnapshot?.binding?.let { binding ->
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT,
                binding = binding,
                now = consentNow
            )
        }
        val auditExportConsent = objectiveProfileSnapshot?.binding?.let { binding ->
            effectivePortfolioOptimizationConsentRecordLocked(
                userId = userId,
                purpose = PortfolioOptimizationConsentPurpose.AUDIT_EXPORT,
                binding = binding,
                now = consentNow
            )
        }
        val latestConsent = portfolioOptimizationConsentRecordsByUser[userId]?.toList().orEmpty()
            .filter { consent ->
                objectiveProfileSnapshot?.binding?.let { binding ->
                    portfolioOptimizationConsentScopeMatches(userId, binding, consent.scopeBinding)
                } ?: true
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationConsentRecord> { it.recordedAtMs }
                    .thenBy { it.consentId }
            )
        val latestRemoteTransportAttempt = portfolioOptimizationRemoteLearningTransportAttemptsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { attempt ->
                portfolioOptimizationRemoteLearningEnvelopesByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.remoteEnvelopeId == attempt.remoteEnvelopeId }
                    ?.sourceEnvelopeId
                    ?.let { envelopeId ->
                        envelopesById[envelopeId]?.let { envelope ->
                            portfolioOptimizationLearningSyncEnvelopeAppliesToObjectiveProfileLineageLocked(
                                userId = userId,
                                envelope = envelope,
                                objectiveProfileSnapshotId = objectiveProfileSnapshotId
                            )
                        }
                    } == true
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationRemoteLearningTransportAttemptRecord> { it.processedAtMs }
                    .thenBy { it.attemptId }
            )
        val latestRemoteTransportConnectorProfile = latestRemoteTransportAttempt
            ?.connectorBinding
            ?.profileId
            ?.let { profileId ->
                portfolioOptimizationRemoteTransportConnectorProfilesByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.profileId == profileId }
            }
            ?: portfolioOptimizationRemoteTransportConnectorProfilesByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationRemoteTransportConnectorProfile> { it.updatedAtMs }
                        .thenBy { it.profileId }
                )
        val latestEnterpriseKeyReference = latestRemoteTransportAttempt
            ?.enterpriseKeyReference
            ?.keyRefId
            ?.let { keyRefId ->
                portfolioOptimizationEnterpriseKeyReferencesByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.keyRefId == keyRefId }
            }
            ?: portfolioOptimizationEnterpriseKeyReferencesByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationEnterpriseKeyReference> { it.updatedAtMs }
                        .thenBy { it.keyRefId }
                )
        val latestRemoteTransportDeadLetter = latestRemoteTransportAttempt
            ?.deadLetterRecordId
            ?.let { deadLetterId ->
                portfolioOptimizationRemoteTransportDeadLettersByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.deadLetterId == deadLetterId }
            }
        val latestAuditExportResult = portfolioOptimizationComplianceAuditExportResultsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { result ->
                portfolioOptimizationComplianceAuditExportRequestsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.requestId == result.requestId }
                    ?.objectiveProfileSnapshotId
                    ?.let { requestSnapshotId ->
                        objectiveProfileSnapshotId.isNotBlank() &&
                            portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                                userId = userId,
                                leftSnapshotId = requestSnapshotId,
                                rightSnapshotId = objectiveProfileSnapshotId
                            )
                    } == true
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationComplianceAuditExportResult> { it.completedAtMs }
                    .thenBy { it.resultId }
            )
        val latestDestinationDecision = latestRemoteTransportAttempt?.destinationDecision
            ?: latestAuditExportResult?.destinationDecision
            ?: portfolioOptimizationRemoteDestinationDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { decision ->
                    when (decision.purpose) {
                        PortfolioOptimizationConsentPurpose.REMOTE_TRANSPORT ->
                            latestRemoteTransportAttempt?.destinationDecision?.decisionId == decision.decisionId
                        PortfolioOptimizationConsentPurpose.AUDIT_EXPORT ->
                            latestAuditExportResult?.destinationDecision?.decisionId == decision.decisionId
                        else -> false
                    }
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationRemoteDestinationDecisionRecord> { it.createdAtMs }
                        .thenBy { it.decisionId }
                )
        val latestComplianceExportRoute = latestAuditExportResult?.exportRoute
            ?: portfolioOptimizationComplianceExportRoutesByUser[userId]
                ?.toList()
                .orEmpty()
                .filter { route ->
                    latestAuditExportResult?.requestId == route.requestId
                }
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationComplianceExportRouteRecord> { it.createdAtMs }
                        .thenBy { it.routeId }
                )
        val latestDataExchangeBundle = latestRemoteTransportAttempt?.dataExchangeBundle
            ?: latestAuditExportResult?.dataExchangeBundle
            ?: portfolioOptimizationDataExchangeBundlesByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationSafeDestinationBundle> { it.createdAtMs }
                        .thenBy { it.bundleId }
                )
        val latestDataExchangeDecision = latestRemoteTransportAttempt?.bundleDecision
            ?: latestAuditExportResult?.bundleDecision
            ?: portfolioOptimizationDataExchangeBundleDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationDestinationBundleDecisionRecord> { it.createdAtMs }
                        .thenBy { it.decisionId }
                )
        val latestDataExchangeManifest = latestRemoteTransportAttempt?.dataExchangeManifest
            ?: latestAuditExportResult?.dataExchangeManifest
            ?: portfolioOptimizationDataExchangeManifestsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationDataExchangeManifest> { it.createdAtMs }
                        .thenBy { it.manifestId }
                )
        val latestCrossBoundaryApproval = portfolioOptimizationCrossBoundaryApprovalsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { approval ->
                latestDataExchangeDecision == null || approval.bundleDecisionId == latestDataExchangeDecision.decisionId
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationCrossBoundaryApprovalRecord> { it.recordedAtMs }
                    .thenBy { it.approvalId }
            )
        val latestCrossBoundaryAudit = portfolioOptimizationCrossBoundaryAuditsByUser[userId]
            ?.toList()
            .orEmpty()
            .filter { audit ->
                latestDataExchangeDecision == null || audit.bundleDecisionId == latestDataExchangeDecision.decisionId
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationCrossBoundaryAuditRecord> { it.recordedAtMs }
                    .thenBy { it.auditId }
            )
        val matchedCrossBoundaryProgram = portfolioOptimizationCrossBoundaryProgramsByUser[userId]
            ?.toList()
            .orEmpty()
            .firstOrNull { program ->
                latestDataExchangeDecision?.decisionId?.let(program.bundleDecisionIds::contains) == true ||
                    latestDataExchangeBundle?.bundleId?.let(program.bundleIds::contains) == true
            }
            ?: portfolioOptimizationCrossBoundaryProgramsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationCrossBoundaryProgramRecord> { it.updatedAtMs }
                        .thenBy { it.programId }
                )
        val matchedGovernancePortfolio = matchedCrossBoundaryProgram
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationCrossBoundaryGovernancePortfoliosByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationCrossBoundaryGovernancePortfoliosByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationCrossBoundaryGovernancePortfolio> { it.updatedAtMs }
                        .thenBy { it.portfolioId }
                )
        val matchedTrustTierProgram = matchedCrossBoundaryProgram
            ?.let { program ->
                portfolioOptimizationTrustTierProgramsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { summary ->
                        summary.portfolioId == program.portfolioId &&
                            summary.trustTier == program.destinationTrustTier
                    }
            }
            ?: portfolioOptimizationTrustTierProgramsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationTrustTierProgramSummary> { it.updatedAtMs }
                        .thenBy { it.summaryId }
                )
        val matchedJurisdictionRolloutPlan = matchedCrossBoundaryProgram
            ?.let { program ->
                portfolioOptimizationJurisdictionRolloutPlansByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { plan ->
                        plan.portfolioId == program.portfolioId && plan.jurisdiction == program.jurisdiction
                    }
            }
            ?: portfolioOptimizationJurisdictionRolloutPlansByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationJurisdictionRolloutPlan> { it.updatedAtMs }
                        .thenBy { it.planId }
                )
        val matchedPortfolioBlocker = matchedCrossBoundaryProgram
            ?.programId
            ?.let { programId ->
                portfolioOptimizationPortfolioBlockersByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { blocker -> blocker.programIds.contains(programId) }
            }
            ?: portfolioOptimizationPortfolioBlockersByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioBlockerSummary> { it.updatedAtMs }
                        .thenBy { it.blockerId }
                )
        val matchedPortfolioDependency = matchedCrossBoundaryProgram
            ?.programId
            ?.let { programId ->
                portfolioOptimizationPortfolioDependenciesByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { dependency ->
                        dependency.programId == programId ||
                            dependency.dependsOnProgramIds.contains(programId)
                    }
            }
            ?: matchedCrossBoundaryProgram
                ?.portfolioId
                ?.let { portfolioId ->
                    portfolioOptimizationPortfolioDependenciesByUser[userId]
                        ?.toList()
                        .orEmpty()
                        .firstOrNull { it.portfolioId == portfolioId }
                }
            ?: portfolioOptimizationPortfolioDependenciesByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioDependencySummary> { it.updatedAtMs }
                        .thenBy { it.dependencyId }
                )
        val matchedPortfolioConflict = matchedCrossBoundaryProgram
            ?.programId
            ?.let { programId ->
                portfolioOptimizationPortfolioConflictsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { conflict -> conflict.programIds.contains(programId) }
            }
            ?: portfolioOptimizationPortfolioConflictsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioConflictSummary> { it.updatedAtMs }
                        .thenBy { it.conflictId }
                )
        val matchedPortfolioRecommendation = matchedGovernancePortfolio
            ?.recommendationId
            ?.let { recommendationId ->
                portfolioOptimizationPortfolioRecommendationsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.recommendationId == recommendationId }
            }
            ?: matchedCrossBoundaryProgram
                ?.portfolioId
                ?.let { portfolioId ->
                    portfolioOptimizationPortfolioRecommendationsByUser[userId]
                        ?.toList()
                        .orEmpty()
                        .firstOrNull { it.portfolioId == portfolioId }
                }
            ?: portfolioOptimizationPortfolioRecommendationsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioCoordinationRecommendation> { it.createdAtMs }
                        .thenBy { it.recommendationId }
                )
        val matchedPortfolioPriority = matchedGovernancePortfolio
            ?.priorityDecisionId
            ?.let { priorityDecisionId ->
                portfolioOptimizationPortfolioPriorityDecisionsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.decisionId == priorityDecisionId }
            }
            ?: matchedCrossBoundaryProgram
                ?.portfolioId
                ?.let { portfolioId ->
                    portfolioOptimizationPortfolioPriorityDecisionsByUser[userId]
                        ?.toList()
                        .orEmpty()
                        .firstOrNull { it.portfolioId == portfolioId }
                }
            ?: portfolioOptimizationPortfolioPriorityDecisionsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioPriorityDecision> { it.createdAtMs }
                        .thenBy { it.decisionId }
                )
        val matchedPortfolioAnalytics = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationCrossBoundaryPortfolioAnalyticsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationCrossBoundaryPortfolioAnalyticsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationCrossBoundaryPortfolioAnalyticsSummary> { it.updatedAtMs }
                        .thenBy { it.analyticsId }
                )
        val matchedRiskBudget = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationRiskBudgetsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationRiskBudgetsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationRiskBudget> { it.updatedAtMs }
                        .thenBy { it.budgetId }
                )
        val matchedTrustTierDrift = matchedTrustTierProgram
            ?.let { summary ->
                portfolioOptimizationTrustTierDriftsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull {
                        it.portfolioId == summary.portfolioId && it.trustTier == summary.trustTier
                    }
            }
            ?: matchedGovernancePortfolio
                ?.portfolioId
                ?.let { portfolioId ->
                    portfolioOptimizationTrustTierDriftsByUser[userId]
                        ?.toList()
                        .orEmpty()
                        .firstOrNull { it.portfolioId == portfolioId }
                }
            ?: portfolioOptimizationTrustTierDriftsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationTrustTierDriftSummary> { it.updatedAtMs }
                        .thenBy { it.driftId }
                )
        val matchedJurisdictionDrift = matchedJurisdictionRolloutPlan
            ?.let { plan ->
                portfolioOptimizationJurisdictionDriftsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull {
                        it.portfolioId == plan.portfolioId && it.jurisdiction == plan.jurisdiction
                    }
            }
            ?: matchedGovernancePortfolio
                ?.portfolioId
                ?.let { portfolioId ->
                    portfolioOptimizationJurisdictionDriftsByUser[userId]
                        ?.toList()
                        .orEmpty()
                        .firstOrNull { it.portfolioId == portfolioId }
                }
            ?: portfolioOptimizationJurisdictionDriftsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationJurisdictionDriftSummary> { it.updatedAtMs }
                        .thenBy { it.driftId }
                )
        val matchedDestinationRiskConcentration = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationDestinationRiskConcentrationsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationDestinationRiskConcentrationsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationDestinationRiskConcentrationSummary> { it.updatedAtMs }
                        .thenBy { it.concentrationId }
                )
        val matchedPortfolioBlockerTrend = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationPortfolioBlockerTrendsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationPortfolioBlockerTrendsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioBlockerTrendSummary> { it.updatedAtMs }
                        .thenBy { it.trendId }
                )
        val matchedPortfolioRiskRecommendation = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationPortfolioRiskRecommendationsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationPortfolioRiskRecommendationsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioRiskRecommendation> { it.createdAtMs }
                        .thenBy { it.recommendationId }
                )
        val matchedPortfolioCorrectiveAction = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationCrossBoundaryCorrectiveActionsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationCrossBoundaryCorrectiveActionsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationCrossBoundaryCorrectiveActionRecord> {
                        it.recordedAtMs
                    }.thenBy { it.actionRecordId }
                )
        val matchedPortfolioSafetyRail = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationPortfolioSafetyRailsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationPortfolioSafetyRailsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioSafetyRail> { it.updatedAtMs }
                        .thenBy { it.safetyRailId }
                )
        val matchedBudgetGuardrail = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationBudgetGuardrailsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationBudgetGuardrailsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationBudgetGuardrail> { it.updatedAtMs }
                        .thenBy { it.guardrailId }
                )
        val matchedPortfolioSafetySummary = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationPortfolioSafetySummariesByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationPortfolioSafetySummariesByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationPortfolioSafetySummary> { it.updatedAtMs }
                        .thenBy { it.summaryId }
                )
        val matchedRemediationAutomationControl = matchedGovernancePortfolio
            ?.portfolioId
            ?.let { portfolioId ->
                portfolioOptimizationRemediationAutomationControlsByUser[userId]
                    ?.toList()
                    .orEmpty()
                    .firstOrNull { it.portfolioId == portfolioId }
            }
            ?: portfolioOptimizationRemediationAutomationControlsByUser[userId]
                ?.toList()
                .orEmpty()
                .maxWithOrNull(
                    compareBy<PortfolioOptimizationRemediationAutomationControl> { it.updatedAtMs }
                        .thenBy { it.controlId }
                )
        val latestAggregation = portfolioOptimizationFederatedAggregationSummariesByUser[userId]?.toList().orEmpty()
            .filter { summary ->
                objectiveProfileSnapshot?.binding?.tenantId?.let { tenantId ->
                    summary.boundary.tenantId == tenantId
                } ?: true
            }
            .filter { summary ->
                objectiveProfileSnapshot?.binding?.workspaceId?.let { workspaceId ->
                    summary.boundary.workspaceId == null || summary.boundary.workspaceId == workspaceId
                } ?: true
            }
            .maxWithOrNull(
                compareBy<PortfolioOptimizationFederatedAggregationSummary> { it.updatedAtMs }
                    .thenBy { it.aggregationId }
            )
        return PortfolioOptimizationLearningContext(
            decisionId = matchedDecision.decisionId,
            resultId = matchedDecision.resultId,
            calibrationSnapshotId = matchedDecision.calibrationSnapshotId,
            objectiveProfileSnapshotId = objectiveProfileSnapshotId,
            objectiveProfileScope = objectiveProfileSnapshot?.binding?.scope
                ?: matchedDecision.objectiveProfileBinding.scope,
            objectiveProfileProvenance = objectiveProfileSnapshot?.provenance?.type
                ?: matchedDecision.objectiveProfileProvenance.type,
            driftSeverity = latestDrift?.highestSeverity,
            driftSummary = latestDrift?.summary.orEmpty(),
            tuningStatus = latestTuningDecision?.status ?: latestSuggestion?.status,
            tuningTargetFamily = latestSuggestion?.targetFamily,
            tuningSummary = latestTuningDecision?.summary
                ?.takeIf { it.isNotBlank() }
                ?: latestSuggestion?.summary.orEmpty(),
            propagationStatus = latestPropagationAdoption?.status ?: latestPropagationAttempt?.status,
            propagationReviewRequired = latestPropagationAdoption?.reviewRequired == true ||
                latestPropagationAttempt?.reviewRequired == true,
            syncMode = latestSyncAttempt?.mode,
            syncStatus = latestSyncAttempt?.status,
            syncConflictResolution = latestSyncConflict?.resolution,
            syncReviewRequired = latestSyncConflict?.reviewRequired == true ||
                latestSyncAttempt?.status == PortfolioOptimizationLearningSyncStatus.CONFLICT_REVIEW_REQUIRED,
            objectiveProfileSummary = objectiveProfileSummary,
            propagationSummary = propagationSummary,
            syncSummary = listOfNotNull(
                latestSyncAttempt?.summary?.takeIf { it.isNotBlank() },
                latestSyncConflict?.summary?.takeIf { it.isNotBlank() }
            ).joinToString(" "),
            syncBoundarySummary = latestSyncAttempt?.boundary?.summary.orEmpty(),
            syncPrivacySummary = latestSyncAttempt?.privacyPolicy?.summary.orEmpty(),
            syncConsentDecision = learningSyncConsent?.decision,
            consentSummary = listOfNotNull(
                learningSyncConsent?.summary?.takeIf { it.isNotBlank() },
                remoteTransportConsent?.summary?.takeIf { it.isNotBlank() },
                auditExportConsent?.summary?.takeIf { it.isNotBlank() },
                latestConsent?.summary?.takeIf { it.isNotBlank() }
            ).joinToString(" "),
            remoteTransportStatus = latestRemoteTransportAttempt?.status,
            remoteDestinationStatus = latestDestinationDecision?.status,
            remoteDestinationType = latestDestinationDecision?.selectedDestinationType,
            residencyRegion = latestDestinationDecision?.residencyRegion,
            jurisdiction = latestDestinationDecision?.jurisdiction,
            remoteTransportConnectorType = latestRemoteTransportAttempt?.connectorBinding?.type
                ?: latestRemoteTransportConnectorProfile?.type,
            enterpriseKeyStatus = latestRemoteTransportAttempt?.enterpriseKeyReference?.status
                ?: latestEnterpriseKeyReference?.status,
            complianceGateDecision = latestRemoteTransportAttempt?.complianceGateResult?.decision
                ?: latestAuditExportResult?.complianceGateResult?.decision,
            remoteTransportLocalFallbackUsed = latestRemoteTransportAttempt?.deliveryResult?.localFallbackUsed == true,
            remoteTransportDeadLettered = latestRemoteTransportDeadLetter != null ||
                latestRemoteTransportAttempt?.status == PortfolioOptimizationRemoteLearningDeliveryStatus.DEAD_LETTERED,
            remoteTransportSummary = latestRemoteTransportAttempt?.summary.orEmpty(),
            remoteDestinationSummary = latestDestinationDecision?.summary.orEmpty(),
            residencySummary = latestDestinationDecision?.residencyPolicy?.summary.orEmpty(),
            remoteTransportConnectorSummary = latestRemoteTransportAttempt?.transportSummary?.connectorSummary
                ?.takeIf { it.isNotBlank() }
                ?: latestRemoteTransportConnectorProfile?.summary.orEmpty(),
            enterpriseKeySummary = latestRemoteTransportAttempt?.transportSummary?.keySummary
                ?.takeIf { it.isNotBlank() }
                ?: latestEnterpriseKeyReference?.summary.orEmpty(),
            complianceGateSummary = latestRemoteTransportAttempt?.transportSummary?.complianceSummary
                ?.takeIf { it.isNotBlank() }
                ?: latestAuditExportResult?.complianceGateResult?.summary.orEmpty(),
            complianceAuditExportStatus = latestAuditExportResult?.status,
            complianceAuditExportSummary = latestAuditExportResult?.summary.orEmpty(),
            complianceExportRouteSummary = latestComplianceExportRoute?.summary.orEmpty(),
            dataExchangeBundleType = latestDataExchangeDecision?.bundleType
                ?: latestDataExchangeBundle?.bundleType,
            dataExchangeDecisionStatus = latestDataExchangeDecision?.status,
            dataExchangeApprovalStatus = latestCrossBoundaryApproval?.status,
            crossBoundaryAuditOperationType = latestCrossBoundaryAudit?.operationType,
            crossBoundaryAuditResult = latestCrossBoundaryAudit?.result,
            governancePortfolioId = matchedGovernancePortfolio?.portfolioId,
            crossBoundaryProgramId = matchedCrossBoundaryProgram?.programId,
            governancePortfolioStatus = matchedGovernancePortfolio?.status,
            destinationTrustTier = matchedCrossBoundaryProgram?.destinationTrustTier,
            crossBoundaryProgramStatus = matchedCrossBoundaryProgram?.programStatus,
            trustTierRolloutState = matchedTrustTierProgram?.rolloutState,
            jurisdictionRolloutState = matchedJurisdictionRolloutPlan?.rolloutState,
            portfolioHealthStatus = matchedPortfolioAnalytics?.healthStatus,
            portfolioTrajectoryState = matchedPortfolioAnalytics?.trajectoryState,
            riskBudgetStatus = matchedRiskBudget?.status,
            portfolioSafetyState = matchedPortfolioSafetySummary?.safetyState
                ?: matchedPortfolioSafetyRail?.safetyState,
            budgetGuardrailState = matchedBudgetGuardrail?.state,
            portfolioEnforcementMode = matchedPortfolioSafetySummary?.enforcementMode
                ?: matchedBudgetGuardrail?.enforcementMode
                ?: matchedRemediationAutomationControl?.enforcementMode,
            remediationAutomationState = matchedRemediationAutomationControl?.automationState,
            trustTierDriftState = matchedTrustTierDrift?.driftState,
            jurisdictionDriftState = matchedJurisdictionDrift?.driftState,
            portfolioBlockerType = matchedPortfolioBlocker?.type,
            portfolioConflictType = matchedPortfolioConflict?.type,
            governancePriority = matchedPortfolioPriority?.priority ?: matchedCrossBoundaryProgram?.priority,
            portfolioRecommendationAction = matchedPortfolioRecommendation?.action
                ?: matchedCrossBoundaryProgram?.nextAction,
            portfolioRiskRecommendationAction = matchedPortfolioRiskRecommendation?.action,
            portfolioCorrectiveActionType = matchedPortfolioCorrectiveAction?.actionType,
            governancePortfolioSummary = matchedGovernancePortfolio?.summary.orEmpty(),
            trustTierProgramSummary = matchedTrustTierProgram?.summary.orEmpty(),
            jurisdictionRolloutSummary = matchedJurisdictionRolloutPlan?.summary.orEmpty(),
            portfolioBlockerSummary = matchedPortfolioBlocker?.summary.orEmpty(),
            portfolioDependencySummary = matchedPortfolioDependency?.summary.orEmpty(),
            portfolioConflictSummary = matchedPortfolioConflict?.summary.orEmpty(),
            sharedBlockerCount = matchedGovernancePortfolio?.sharedBlockerCount ?: 0,
            conflictCount = matchedGovernancePortfolio?.conflictCount ?: 0,
            portfolioRecommendationSummary = matchedPortfolioRecommendation?.summary.orEmpty(),
            portfolioAnalyticsSummary = matchedPortfolioAnalytics?.summary.orEmpty(),
            trustTierDriftSummary = matchedTrustTierDrift?.summary.orEmpty(),
            jurisdictionDriftSummary = matchedJurisdictionDrift?.summary.orEmpty(),
            riskBudgetSummary = matchedRiskBudget?.summary.orEmpty(),
            destinationRiskConcentrationSummary = matchedDestinationRiskConcentration?.summary.orEmpty(),
            portfolioBlockerTrendSummary = matchedPortfolioBlockerTrend?.summary.orEmpty(),
            portfolioRiskRecommendationSummary = matchedPortfolioRiskRecommendation?.summary.orEmpty(),
            portfolioCorrectiveActionSummary = matchedPortfolioCorrectiveAction?.summary.orEmpty(),
            riskBudgetBreached = matchedRiskBudget?.status in setOf(
                PortfolioOptimizationRiskBudgetStatus.EXCEEDED,
                PortfolioOptimizationRiskBudgetStatus.HELD
            ),
            portfolioQuarantined = matchedPortfolioSafetySummary?.quarantineActive == true ||
                matchedRemediationAutomationControl?.quarantined == true,
            portfolioRemediationApprovalRequired = matchedPortfolioSafetySummary?.approvalRequired == true ||
                matchedBudgetGuardrail?.approvalRequired == true ||
                matchedRemediationAutomationControl?.approvalRequired == true,
            dataExchangeBundleSummary = latestDataExchangeBundle?.summary.orEmpty(),
            dataExchangeBoundarySummary =
                latestDataExchangeDecision?.boundarySummary?.summary
                    ?: latestDataExchangeManifest?.boundarySummary?.summary.orEmpty(),
            dataExchangeApprovalSummary = latestCrossBoundaryApproval?.summary.orEmpty(),
            crossBoundaryAuditSummary = latestCrossBoundaryAudit?.summary.orEmpty(),
            portfolioSafetySummary = matchedPortfolioSafetySummary?.summary.orEmpty(),
            portfolioSafetyRailSummary = matchedPortfolioSafetyRail?.summary.orEmpty(),
            budgetGuardrailSummary = matchedBudgetGuardrail?.summary.orEmpty(),
            remediationAutomationSummary = matchedRemediationAutomationControl?.summary.orEmpty(),
            enterprisePrivacySummary = objectiveProfileSnapshot?.binding?.let { binding ->
                derivePortfolioOptimizationEnterprisePrivacyPolicySummary(
                    userId = userId,
                    binding = binding,
                    activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL,
                    learningSyncConsent = learningSyncConsent,
                    remoteTransportConsent = remoteTransportConsent,
                    auditExportConsent = auditExportConsent
                ).summary
            }.orEmpty(),
            federatedAggregationSummary = latestAggregation?.summary.orEmpty(),
            summary = listOf(
                objectiveProfileSummary,
                latestOutcome?.summary,
                latestDrift?.summary,
                latestTuningDecision?.summary ?: latestSuggestion?.summary,
                propagationSummary,
                latestSyncAttempt?.summary,
                latestConsent?.summary,
                latestDestinationDecision?.summary,
                latestRemoteTransportAttempt?.summary,
                latestAuditExportResult?.summary,
                latestComplianceExportRoute?.summary,
                latestDataExchangeDecision?.summary,
                latestCrossBoundaryApproval?.summary,
                latestCrossBoundaryAudit?.summary,
                matchedGovernancePortfolio?.summary,
                matchedCrossBoundaryProgram?.summary,
                matchedTrustTierProgram?.summary,
                matchedJurisdictionRolloutPlan?.summary,
                matchedPortfolioBlocker?.summary,
                matchedPortfolioDependency?.summary,
                matchedPortfolioConflict?.summary,
                matchedPortfolioRecommendation?.summary,
                matchedPortfolioAnalytics?.summary,
                matchedTrustTierDrift?.summary,
                matchedJurisdictionDrift?.summary,
                matchedRiskBudget?.summary,
                matchedPortfolioSafetySummary?.summary,
                matchedPortfolioSafetyRail?.summary,
                matchedBudgetGuardrail?.summary,
                matchedRemediationAutomationControl?.summary,
                matchedDestinationRiskConcentration?.summary,
                matchedPortfolioBlockerTrend?.summary,
                matchedPortfolioRiskRecommendation?.summary,
                matchedPortfolioCorrectiveAction?.summary,
                latestAggregation?.summary
            ).filterNotNull().filter { it.isNotBlank() }.joinToString(" ")
        )
    }

    private fun applyPortfolioOptimizationLearningContextToLedgerRecordLocked(
        userId: String,
        record: ExecutionReceiptRecord
    ): ExecutionReceiptRecord {
        val context = portfolioOptimizationLearningContextForRunLocked(userId, record.runId) ?: return record
        val baseReceipt = record.receipt ?: ExecutionReceipt(
            runId = record.runId,
            intentSummary = record.legacySummary.ifBlank { record.runId },
            status = record.status,
            activeRole = record.activeRole,
            roleSource = record.roleSource,
            delegationMode = record.delegationMode,
            updatedAt = record.updatedAtMs,
            completedAt = record.updatedAtMs.takeIf { it > 0L }
        )
        val updatedReceipt = baseReceipt.copy(
            portfolioOptimizationDecisionId = context.decisionId,
            portfolioOptimizationResultId = context.resultId,
            portfolioCalibrationSnapshotId = context.calibrationSnapshotId,
            portfolioObjectiveProfileSnapshotId = context.objectiveProfileSnapshotId.ifBlank {
                baseReceipt.portfolioObjectiveProfileSnapshotId.orEmpty()
            },
            portfolioObjectiveProfileScope = context.objectiveProfileScope,
            portfolioObjectiveProfileProvenance = context.objectiveProfileProvenance,
            portfolioDriftSeverity = context.driftSeverity,
            portfolioTuningStatus = context.tuningStatus,
            portfolioPropagationStatus = context.propagationStatus,
            portfolioPropagationReviewRequired = context.propagationReviewRequired,
            portfolioLearningSyncMode = context.syncMode,
            portfolioLearningSyncStatus = context.syncStatus,
            portfolioLearningSyncConflictResolution = context.syncConflictResolution,
            portfolioLearningSyncReviewRequired = context.syncReviewRequired,
            portfolioLearningSyncConsentDecision = context.syncConsentDecision,
            portfolioRemoteTransportStatus = context.remoteTransportStatus,
            portfolioRemoteDestinationStatus = context.remoteDestinationStatus,
            portfolioRemoteDestinationType = context.remoteDestinationType,
            portfolioResidencyRegion = context.residencyRegion,
            portfolioJurisdiction = context.jurisdiction,
            portfolioRemoteTransportConnectorType = context.remoteTransportConnectorType,
            portfolioEnterpriseKeyStatus = context.enterpriseKeyStatus,
            portfolioComplianceGateDecision = context.complianceGateDecision,
            portfolioRemoteTransportLocalFallbackUsed = context.remoteTransportLocalFallbackUsed,
            portfolioRemoteTransportDeadLettered = context.remoteTransportDeadLettered,
            portfolioComplianceAuditExportStatus = context.complianceAuditExportStatus,
            portfolioDataExchangeVisibility =
                PortfolioOptimizationDataExchangeVisibilitySummary(
                    bundleType = context.dataExchangeBundleType,
                    decisionStatus = context.dataExchangeDecisionStatus,
                    approvalStatus = context.dataExchangeApprovalStatus,
                    crossBoundaryAuditOperationType = context.crossBoundaryAuditOperationType,
                    crossBoundaryAuditResult = context.crossBoundaryAuditResult,
                    governancePortfolioStatus = context.governancePortfolioStatus,
                    destinationTrustTier = context.destinationTrustTier,
                    crossBoundaryProgramStatus = context.crossBoundaryProgramStatus,
                    trustTierRolloutState = context.trustTierRolloutState,
                    jurisdictionRolloutState = context.jurisdictionRolloutState,
                    portfolioPriority = context.governancePriority,
                    portfolioRecommendationAction = context.portfolioRecommendationAction,
                    portfolioHealthStatus = context.portfolioHealthStatus,
                    portfolioTrajectoryState = context.portfolioTrajectoryState,
                    riskBudgetStatus = context.riskBudgetStatus,
                    portfolioSafetyState = context.portfolioSafetyState,
                    budgetGuardrailState = context.budgetGuardrailState,
                    enforcementMode = context.portfolioEnforcementMode,
                    remediationAutomationState = context.remediationAutomationState,
                    trustTierDriftState = context.trustTierDriftState,
                    jurisdictionDriftState = context.jurisdictionDriftState,
                    portfolioRiskRecommendationAction = context.portfolioRiskRecommendationAction,
                    correctiveActionType = context.portfolioCorrectiveActionType,
                    riskBudgetBreached = context.riskBudgetBreached,
                    quarantined = context.portfolioQuarantined,
                    approvalRequired = context.portfolioRemediationApprovalRequired,
                    sharedBlockerCount = context.sharedBlockerCount,
                    conflictCount = context.conflictCount,
                    bundleSummary = context.dataExchangeBundleSummary.ifBlank {
                        baseReceipt.portfolioDataExchangeBundleSummary.orEmpty()
                    },
                    boundarySummary = context.dataExchangeBoundarySummary.ifBlank {
                        baseReceipt.portfolioDataExchangeBoundarySummary.orEmpty()
                    },
                    approvalSummary = context.dataExchangeApprovalSummary.ifBlank {
                        baseReceipt.portfolioDataExchangeApprovalSummary.orEmpty()
                    },
                    crossBoundaryAuditSummary = context.crossBoundaryAuditSummary.ifBlank {
                        baseReceipt.portfolioCrossBoundaryAuditSummary.orEmpty()
                    },
                    governancePortfolioSummary = context.governancePortfolioSummary.ifBlank {
                        baseReceipt.portfolioGovernancePortfolioSummary.orEmpty()
                    },
                    trustTierProgramSummary = context.trustTierProgramSummary.ifBlank {
                        baseReceipt.portfolioTrustTierProgramSummary.orEmpty()
                    },
                    jurisdictionRolloutSummary = context.jurisdictionRolloutSummary.ifBlank {
                        baseReceipt.portfolioJurisdictionRolloutSummary.orEmpty()
                    },
                    portfolioBlockerSummary = context.portfolioBlockerSummary.ifBlank {
                        baseReceipt.portfolioGovernanceBlockerSummary.orEmpty()
                    },
                    portfolioDependencySummary = context.portfolioDependencySummary.ifBlank {
                        baseReceipt.portfolioGovernanceDependencySummary.orEmpty()
                    },
                    portfolioConflictSummary = context.portfolioConflictSummary.ifBlank {
