                        },
                ),
            portfolioObjectiveProfileSummary = context.objectiveProfileSummary.ifBlank {
                baseReceipt.portfolioObjectiveProfileSummary.orEmpty()
            },
            portfolioLearningSummary = context.summary.ifBlank {
                baseReceipt.portfolioLearningSummary.orEmpty()
            },
            portfolioDriftSummary = context.driftSummary.ifBlank {
                baseReceipt.portfolioDriftSummary.orEmpty()
            },
            portfolioTuningSummary = context.tuningSummary.ifBlank {
                baseReceipt.portfolioTuningSummary.orEmpty()
            },
            portfolioPropagationSummary = context.propagationSummary.ifBlank {
                baseReceipt.portfolioPropagationSummary.orEmpty()
            },
            portfolioLearningSyncSummary = context.syncSummary.ifBlank {
