            portfolioLearningConsentSummary = context.consentSummary.ifBlank {
                baseReceipt.portfolioLearningConsentSummary.orEmpty()
            },
            portfolioRemoteTransportSummary = context.remoteTransportSummary.ifBlank {
                baseReceipt.portfolioRemoteTransportSummary.orEmpty()
            },
            portfolioRemoteDestinationSummary = context.remoteDestinationSummary.ifBlank {
                baseReceipt.portfolioRemoteDestinationSummary.orEmpty()
            },
            portfolioResidencySummary = context.residencySummary.ifBlank {
