            portfolioLearningSyncConflictResolution = context.syncConflictResolution,
            portfolioLearningSyncReviewRequired = context.syncReviewRequired,
            portfolioLearningSyncConsentDecision = context.syncConsentDecision,
            portfolioRemoteTransportStatus = context.remoteTransportStatus,
            portfolioRemoteDestinationStatus = context.remoteDestinationStatus,
            portfolioRemoteDestinationType = context.remoteDestinationType,
            portfolioResidencyRegion = context.residencyRegion,
            portfolioJurisdiction = context.jurisdiction,
            portfolioRemoteTransportConnectorType = context.remoteTransportConnectorType,
            portfolioEnterpriseKeyStatus = context.enterpriseKeyStatus,
            portfolioComplianceGateDecision = context.complianceGateDecision,
            portfolioRemoteTransportLocalFallbackUsed = context.remoteTransportLocalFallbackUsed,
            portfolioRemoteTransportDeadLettered = context.remoteTransportDeadLettered,
            portfolioComplianceAuditExportStatus = context.complianceAuditExportStatus,
            portfolioDataExchangeBundleType = context.dataExchangeBundleType,
            portfolioDataExchangeDecisionStatus = context.dataExchangeDecisionStatus,
            portfolioDataExchangeApprovalStatus = context.dataExchangeApprovalStatus,
            portfolioCrossBoundaryAuditOperationType = context.crossBoundaryAuditOperationType,
