            },
            portfolioFederatedAggregationSummary = context.federatedAggregationSummary.ifBlank {
                record.portfolioFederatedAggregationSummary.orEmpty()
            },
            receipt = updatedReceipt
        )
    }

    private fun portfolioOptimizationLearningSyncEnvelopeAppliesToObjectiveProfileLineageLocked(
        userId: String,
        envelope: PortfolioOptimizationLearningSyncEnvelope,
        objectiveProfileSnapshotId: String
    ): Boolean {
        if (objectiveProfileSnapshotId.isBlank()) return false
        val objectiveProfileSnapshot = findPortfolioOptimizationObjectiveProfileSnapshotLocked(
            userId = userId,
            snapshotId = objectiveProfileSnapshotId
        )
        val effectiveBinding = objectiveProfileSnapshot?.let {
            resolvePortfolioOptimizationScopeBinding(userId, it.binding)
        }
        if (
            effectiveBinding != null &&
            envelope.boundary.sameTenantOnly &&
            envelope.boundary.tenantId != null &&
            envelope.boundary.tenantId != effectiveBinding.tenantId
        ) {
            return false
        }
        return envelope.artifacts.any { artifact ->
            when (artifact.artifactType) {
                PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT ->
                    artifact.objectiveProfileSnapshot?.snapshotId?.let { artifactSnapshotId ->
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = artifactSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        )
                    } == true

                PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT ->
                    artifact.calibrationSnapshot?.objectiveProfileSnapshotId?.let { artifactSnapshotId ->
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = artifactSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        )
                    } == true

                PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY ->
                    artifact.driftSummary?.objectiveProfileSnapshotId?.let { artifactSnapshotId ->
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = artifactSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        )
                    } == true

                PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE ->
                    artifact.outcomeAggregate?.objectiveProfileSnapshotId?.let { artifactSnapshotId ->
                        portfolioOptimizationObjectiveProfileSnapshotsShareLineage(
                            userId = userId,
                            leftSnapshotId = artifactSnapshotId,
                            rightSnapshotId = objectiveProfileSnapshotId
                        )
                    } == true

                PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY ->
                    artifact.federatedAggregationSummary?.let { aggregation ->
                        effectiveBinding?.tenantId == aggregation.boundary.tenantId &&
                            (
                                aggregation.boundary.workspaceId == null ||
                                    aggregation.boundary.workspaceId ==
                                    effectiveBinding?.workspaceId
                                )
                    } == true
            }
        }
    }

    private fun portfolioOptimizationLearningSyncConflictAppliesToObjectiveProfileLineageLocked(
        userId: String,
        conflict: PortfolioOptimizationLearningSyncConflictRecord,
        objectiveProfileSnapshotId: String,
        envelopesById: Map<String, PortfolioOptimizationLearningSyncEnvelope>
    ): Boolean {
        if (objectiveProfileSnapshotId.isBlank()) return false
        return when (conflict.artifactType) {
            PortfolioOptimizationLearningSyncArtifactType.OBJECTIVE_PROFILE_SNAPSHOT,
            PortfolioOptimizationLearningSyncArtifactType.CALIBRATION_SNAPSHOT,
            PortfolioOptimizationLearningSyncArtifactType.DRIFT_SUMMARY,
            PortfolioOptimizationLearningSyncArtifactType.OUTCOME_AGGREGATE ->
                portfolioOptimizationLearningSyncEnvelopeAppliesToObjectiveProfileLineageLocked(
                    userId = userId,
                    envelope = envelopesById[conflict.envelopeId] ?: return false,
                    objectiveProfileSnapshotId = objectiveProfileSnapshotId
                )

            PortfolioOptimizationLearningSyncArtifactType.FEDERATED_AGGREGATION_SUMMARY ->
                envelopesById[conflict.envelopeId]?.boundary?.tenantId?.let { tenantId ->
                    findPortfolioOptimizationObjectiveProfileSnapshotLocked(
                        userId = userId,
                        snapshotId = objectiveProfileSnapshotId
                    )?.let { snapshot ->
                        resolvePortfolioOptimizationScopeBinding(userId, snapshot.binding).tenantId == tenantId
                    }
                } == true
        }
    }

    private fun buildGovernanceCaseRecord(
        userId: String,
        record: ExecutionReceiptRecord,
        includeRemotePipeline: Boolean = true
    ): GovernanceCaseRecord {
        val signal = toGovernanceSignal(record)
        val reasonCodes = collectReasonCodes(record).toList().sorted()
        val settlementStatus = settlementStatusFor(record)
        val disputeStatus = disputeStatusFor(record)
        val syncState = syncStateFor(record)
        val reviewed = record.runEvents.any { it.type == ProofLedgerEventType.OPERATOR_MARKED_REVIEWED }
        val providerLabel = providerLabelFor(record)
        val queueTags = queueTagsFor(
            record = record,
            signal = signal,
            settlementStatus = settlementStatus,
            disputeStatus = disputeStatus,
            syncState = syncState
        )
        val primaryQueue = queueTags.firstOrNull() ?: GovernanceQueueType.NEEDS_ATTENTION
        val priority = governancePriorityFor(queueTags, signal)
        val title = caseTitleFor(queueTags, syncState, disputeStatus)
        val summary = caseSummaryFor(
            record = record,
            providerLabel = providerLabel,
            settlementStatus = settlementStatus,
            disputeStatus = disputeStatus,
            syncState = syncState
        )
        val reasonFamilies = signal.reasonFamilies.toList().sortedBy { it.ordinal }
        val collaborationState = record.collaborationState
            ?: collaborationStateForRunLocked(userId, record.runId)
        val remoteOperatorHandoff = record.remoteOperatorHandoff
            ?: remoteOperatorHandoffForRunLocked(userId, record.runId)
        val alertRoutingRecords = if (record.alertRoutingRecords.isNotEmpty()) {
            record.alertRoutingRecords
        } else {
            alertRoutingForRunLocked(userId, record.runId)
        }
        val connectorRoutingSummary = record.connectorRoutingSummary
            ?: record.receipt?.connectorRoutingSummary
            ?: buildConnectorRoutingSummary(alertRoutingRecords)
        val connectorDeadLetterCount = maxOf(
            connectorRoutingSummary?.deadLetterTargets ?: 0,
            alertRoutingRecords.sumOf { it.deadLetterRecords.size }
        )
        val connectorFailedCount = maxOf(
            connectorRoutingSummary?.failedTargetTypes?.size ?: 0,
            alertRoutingRecords.sumOf { routing ->
                routing.deliveryRecords.count { delivery ->
                    delivery.status == ConnectorDeliveryStatus.FAILED ||
                        delivery.status == ConnectorDeliveryStatus.DEAD_LETTER
                }
            }
        )
        val connectorHealthSummary = record.connectorHealthSummary
            ?: connectorRoutingSummary?.connectorHealthSummary
            ?: alertRoutingRecords
                .mapNotNull { it.connectorHealthSummary }
                .maxByOrNull { it.lastUpdatedAtMs }
        val portfolioLearningContext = portfolioOptimizationLearningContextForRun(
            userId = userId,
            runId = record.runId
        )
        val remoteAuthorization = record.remoteAuthorizationResult
            ?: collaborationState?.operatorSession?.remoteAuthorization
            ?: alertRoutingRecords
                .mapNotNull { it.authorization }
                .maxByOrNull { it.evaluatedAtMs }
        val operatorConnectorAudit = record.operatorConnectorAudit
            ?: buildOperatorConnectorAuditLink(
                operatorIdentity = collaborationState?.operatorSession?.identity ?: OperatorIdentity(
                    userId = collaborationState?.claimedBy?.userId
                        ?: collaborationState?.assignedTo?.userId
                        ?: "local-user",
                    displayName = collaborationState?.claimedBy?.displayName
                        ?: collaborationState?.assignedTo?.displayName
                        ?: "Local Operator"
                ),
                directoryEntry = null,
                remoteAuthorization = remoteAuthorization,
                routingRecord = alertRoutingRecords.lastOrNull(),
                now = record.updatedAtMs.takeIf { it > 0 } ?: nowMs()
            )
        val remoteDirectoryEntry = synchronized(dynamicStateLock) {
            val actorUserId = collaborationState?.assignedTo?.userId
                ?: collaborationState?.claimedBy?.userId
                ?: operatorConnectorAudit?.operatorUserId
                ?: userId
            ensureRemoteResourcesInitializedLocked(userId)
            resolveDirectoryEntryLocked(
                userId = userId,
                actorUserId = actorUserId,
                requestedOperatorId = operatorConnectorAudit?.remoteOperatorId
                    ?: remoteAuthorization?.operatorId?.takeIf { it.isNotBlank() },
                requestedTeamId = operatorConnectorAudit?.operatorTeamId
                    ?: remoteAuthorization?.teamId
            )
        }
        val remoteOperatorIdentity = remoteDirectoryEntry?.identity
        val remoteOperatorTeam = remoteDirectoryEntry?.team
        val connectorDestinationSummary = record.receipt?.connectorDestinationSummary
            ?: connectorDestinationSummaryFor(alertRoutingRecords)
            ?: "No connector destination metadata tracked."
        val connectorAuthProfileSummary = record.receipt?.connectorAuthProfileSummary
            ?: connectorAuthProfileSummaryFor(alertRoutingRecords)
            ?: "No connector auth profile metadata tracked."
        val remoteAuthorizationSummary = record.receipt?.remoteAuthorizationSummary
            ?: remoteAuthorizationSummaryFor(remoteAuthorization)
            ?: "No remote authorization metadata tracked."
        val identityProvenance = record.operatorIdentityProvenance
            ?: record.receipt?.operatorIdentityProvenance
            ?: operatorConnectorAudit?.identityProvenance
        val lastDirectorySyncSnapshot = record.directorySyncSnapshot
            ?: record.receipt?.directorySyncSnapshot
            ?: alertRoutingRecords
                .mapNotNull { it.directorySync }
                .maxByOrNull { it.syncedAtMs ?: 0L }
            ?: identityProvenance?.directorySync
        val lastSessionAuthContext = record.sessionAuthContext
            ?: remoteAuthorization?.sessionAuthContext
            ?: record.receipt?.sessionAuthContext
            ?: operatorConnectorAudit?.sessionAuthContext
        val lastCredentialLifecycle = record.connectorCredentialLifecycle
            ?: record.receipt?.connectorCredentialLifecycle
            ?: alertRoutingRecords
                .flatMap { routing ->
                    buildList {
                        addAll(routing.credentialLifecycleSummaries)
                        addAll(routing.targets.mapNotNull { it.credentialLifecycle })
                    }
                }
                .maxByOrNull { it.evaluatedAtMs }
            ?: operatorConnectorAudit?.credentialLifecycle
        val directorySyncSummary = record.receipt?.directorySyncSummary
            ?: directorySyncSummaryFor(remoteAuthorization, alertRoutingRecords)
            ?: lastDirectorySyncSnapshot?.summary
            ?: "Directory sync metadata is not tracked for this case."
        val sessionAuthProvenanceSummary = record.receipt?.sessionAuthProvenanceSummary
            ?: sessionAuthProvenanceSummaryFor(remoteAuthorization)
            ?: "Session authorization provenance is not tracked for this case."
        val connectorCredentialSummary = record.receipt?.connectorCredentialSummary
            ?: connectorCredentialSummaryFor(alertRoutingRecords)
            ?: lastCredentialLifecycle?.summary
            ?: "Connector credential lifecycle metadata is not tracked for this case."
        val enterpriseAuthIntegration = record.enterpriseAuthIntegration
            ?: record.receipt?.enterpriseAuthIntegration
            ?: alertRoutingRecords
                .mapNotNull { it.enterpriseAuthIntegration }
                .maxByOrNull { it.directoryUpdate?.processedAtMs ?: it.directorySync?.syncedAtMs ?: 0L }
        val idpProviderConfig = record.receipt?.idpProviderConfig
            ?: enterpriseAuthIntegration?.idpProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.idpProviderConfig }.lastOrNull()
        val idpSessionExchange = record.receipt?.idpSessionExchange
            ?: enterpriseAuthIntegration?.idpSessionExchange
            ?: alertRoutingRecords.mapNotNull { it.idpSessionExchange }.lastOrNull()
            ?: lastSessionAuthContext?.idpSessionExchange
        val idpProviderHealth = record.receipt?.idpProviderHealth
            ?: enterpriseAuthIntegration?.idpProviderHealth
            ?: alertRoutingRecords.mapNotNull { it.idpProviderHealth }.lastOrNull()
            ?: lastSessionAuthContext?.idpProviderHealth
        val scimProviderConfig = record.receipt?.scimProviderConfig
            ?: enterpriseAuthIntegration?.scimProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.scimProviderConfig }.lastOrNull()
        val scimProviderResult = record.receipt?.scimProviderResult
            ?: enterpriseAuthIntegration?.scimProviderResult
            ?: alertRoutingRecords.mapNotNull { it.scimProviderResult }.lastOrNull()
            ?: remoteAuthorization?.provenance?.scimProviderResult
        val directorySyncCheckpoint = record.receipt?.directorySyncCheckpoint
            ?: enterpriseAuthIntegration?.directorySyncCheckpoint
            ?: alertRoutingRecords.mapNotNull { it.directorySyncCheckpoint }.lastOrNull()
            ?: scimProviderResult?.checkpoint
        val vaultProviderConfig = record.receipt?.vaultProviderConfig
            ?: enterpriseAuthIntegration?.vaultProviderConfig
            ?: alertRoutingRecords.mapNotNull { it.vaultProviderConfig }.lastOrNull()
        val vaultMaterialization = record.receipt?.vaultMaterialization
            ?: enterpriseAuthIntegration?.vaultMaterialization
            ?: alertRoutingRecords.flatMap { it.vaultMaterializationResults }.maxByOrNull { it.evaluatedAtMs }
        val vaultProviderHealth = record.receipt?.vaultProviderHealth
            ?: enterpriseAuthIntegration?.vaultProviderHealth
            ?: alertRoutingRecords.mapNotNull { it.vaultProviderHealth }.lastOrNull()
        val vaultCredentialHealthCheck = record.receipt?.vaultCredentialHealthCheck
            ?: enterpriseAuthIntegration?.vaultCredentialHealthCheck
            ?: alertRoutingRecords.flatMap { it.vaultCredentialHealthChecks }.maxByOrNull { it.checkedAtMs }
        val enterpriseIdentitySummary = record.receipt?.enterpriseIdentitySummary
            ?: enterpriseAuthIntegration?.identityAssertion?.summary
            ?: identityProvenance?.remoteIdentityLink?.identityAssertion?.summary
            ?: "Enterprise identity assertion is not tracked for this case."
        val enterpriseSessionSummary = record.receipt?.enterpriseSessionSummary
            ?: enterpriseAuthIntegration?.summary
            ?: sessionAuthProvenanceSummary
        val idpProviderSummary = record.receipt?.idpProviderSummary
            ?: idpSessionExchange?.summary
            ?: idpProviderHealth?.summary
            ?: idpProviderConfig?.summary
            ?: "IdP provider health is not tracked for this case."
        val scimDirectorySummary = record.receipt?.scimDirectorySummary
            ?: enterpriseAuthIntegration?.directoryUpdate?.summary
            ?: directorySyncSummary
        val scimProviderSummary = record.receipt?.scimProviderSummary
            ?: scimProviderResult?.summary
            ?: scimProviderResult?.health?.summary
            ?: scimProviderConfig?.summary
            ?: "SCIM provider health is not tracked for this case."
        val vaultCredentialSummary = record.receipt?.vaultCredentialSummary
            ?: enterpriseAuthIntegration?.credentialBinding?.vaultCredential?.summary
            ?: connectorCredentialSummary
        val vaultProviderSummary = record.receipt?.vaultProviderSummary
            ?: vaultMaterialization?.summary
            ?: vaultProviderHealth?.summary
            ?: vaultProviderConfig?.summary
            ?: "Vault provider health is not tracked for this case."
        val tenantRolloutProfile = record.tenantRolloutProfile
            ?: record.receipt?.tenantRolloutProfile
            ?: enterpriseAuthIntegration?.tenantRolloutProfile
            ?: alertRoutingRecords.mapNotNull { it.tenantRolloutProfile }.maxByOrNull { it.updatedAtMs }
        val workspaceRolloutProfile = record.workspaceRolloutProfile
            ?: record.receipt?.workspaceRolloutProfile
            ?: enterpriseAuthIntegration?.workspaceRolloutProfile
            ?: alertRoutingRecords.mapNotNull { it.workspaceRolloutProfile }.maxByOrNull { it.updatedAtMs }
        val cutoverReadiness = record.cutoverReadiness
            ?: record.receipt?.cutoverReadiness
            ?: enterpriseAuthIntegration?.cutoverReadiness
            ?: alertRoutingRecords.mapNotNull { it.cutoverReadiness }.maxByOrNull { it.updatedAtMs }
        val vaultHealth = record.vaultHealth
            ?: record.receipt?.vaultHealth
            ?: enterpriseAuthIntegration?.vaultHealth
            ?: alertRoutingRecords.mapNotNull { it.vaultHealth }.maxByOrNull { it.lastCheckedAtMs }
        val vaultResolution = record.vaultResolution
            ?: record.receipt?.vaultResolution
            ?: enterpriseAuthIntegration?.vaultResolution
            ?: alertRoutingRecords.flatMap { it.vaultResolutions }.maxByOrNull { it.lease?.expiresAtMs ?: 0L }
        val fallbackPolicy = record.fallbackPolicy
            ?: record.receipt?.fallbackPolicy
            ?: enterpriseAuthIntegration?.fallbackPolicy
            ?: alertRoutingRecords.mapNotNull { it.fallbackPolicy }.lastOrNull()
        val rolloutSummary = record.receipt?.rolloutSummary
            ?: connectorRoutingSummary?.rolloutSummary
            ?: tenantRolloutProfile?.summary
            ?: "Rollout metadata is not tracked for this case."
        val cutoverReadinessSummary = record.receipt?.cutoverReadinessSummary
            ?: connectorRoutingSummary?.cutoverSummary
            ?: cutoverReadiness?.summary
            ?: "Cutover readiness metadata is not tracked for this case."
        val vaultRuntimeSummary = record.receipt?.vaultRuntimeSummary
            ?: connectorRoutingSummary?.vaultRuntimeSummary
            ?: vaultHealth?.summary
            ?: vaultResolution?.summary
            ?: "Vault runtime metadata is not tracked for this case."
        val enterpriseFallbackSummary = record.receipt?.enterpriseFallbackSummary
            ?: connectorRoutingSummary?.enterpriseFallbackSummary
            ?: fallbackPolicy?.summary
            ?: "Local-first fallback remains available."
        val deadLetterSummary = record.receipt?.deadLetterSummary?.takeIf { it.isNotBlank() }
            ?: deadLetterSummaryForRouting(
                routing = alertRoutingRecords,
                connectorSummary = connectorRoutingSummary,
                deadLetters = record.deadLetterRecords
                    .ifEmpty { alertRoutingRecords.flatMap { it.deadLetterRecords } }
            )
        val workflowRun = record.workflowRun
            ?: collaborationState?.workflowRun
        val workflowTemplate = workflowRun?.templateId
            ?.takeIf { it.isNotBlank() }
            ?.let { templateId ->
                resolveOperatorWorkflowTemplate(
                    templateId = templateId,
                    state = collaborationState ?: GovernanceCaseCollaborationState(runId = record.runId)
                )
            }
        val latestCollaborationEvent = (
            record.collaborationEvents + (collaborationState?.collaborationEvents ?: emptyList())
            )
            .distinctBy { it.eventId }
            .maxByOrNull { it.timestampMs }
        val latestAutomationAudit = (
            record.automationAudit + (collaborationState?.automationAudit ?: emptyList())
            )
            .distinctBy { it.auditId }
            .maxByOrNull { it.timestampMs }
        val workflowSummary = buildString {
            if (workflowTemplate != null) {
                append("Template ${workflowTemplate.name.ifBlank { workflowTemplate.templateId }}")
            } else if (!workflowRun?.templateName.isNullOrBlank()) {
                append("Template ${workflowRun?.templateName}")
            }
            workflowRun?.currentStage?.let { stage ->
                if (isNotEmpty()) append(" · ")
                append("Stage ${stage.name.lowercase().replace('_', ' ')}")
            }
            workflowRun?.nextAction?.title
                ?.takeIf { it.isNotBlank() }
                ?.let { title ->
                    if (isNotEmpty()) append(" · ")
                    append("Next $title")
                }
        }.ifBlank { "Workflow template is not attached for this case." }
        val workflowPolicySummary = workflowRun?.workflowPolicySummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.workflowPolicySummary
                ?.takeIf { it.isNotBlank() }
            ?: "Workflow policy is not tracked for this case."
        val slaSummary = workflowRun?.slaSummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.slaSummary
                ?.takeIf { it.isNotBlank() }
            ?: "SLA state is not tracked for this case."
        val stageTimerSummary = workflowRun?.stageTimerSummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.stageTimerSummary
                ?.takeIf { it.isNotBlank() }
            ?: "Stage timer is not tracked for this case."
        val escalationTimerSummary = workflowRun?.escalationTimerSummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.escalationTimerSummary
                ?.takeIf { it.isNotBlank() }
            ?: "Escalation timer is not tracked for this case."
        val automationGuardrailSummary = workflowRun?.automationGuardrailSummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.automationGuardrailSummary
                ?.takeIf { it.isNotBlank() }
            ?: "Automation guardrail state is not tracked for this case."
        val automationSuppressionSummary = workflowRun?.automationSuppressionSummary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.automationSuppressionSummary
                ?.takeIf { it.isNotBlank() }
            ?: ""
        val nextRequiredHumanAction = workflowRun?.nextRequiredHumanAction
            ?: record.receipt?.nextRequiredHumanAction
            ?: ""
        val slaStatus = workflowRun?.slaClock?.status ?: record.receipt?.slaStatus
        val stageTimerStatus = workflowRun?.stageTimer?.status ?: record.receipt?.stageTimerStatus
        val escalationTimerStatus = workflowRun?.escalationTimer?.status ?: record.receipt?.escalationTimerStatus
        val automationEligibility = workflowRun?.automationGuardrailDecision?.status
            ?: record.receipt?.automationEligibility
        val workflowPolicyPackId = workflowRun?.policyPack?.packId
            ?: record.receipt?.workflowPolicyPackId
        val workflowPolicyPackVersion = workflowRun?.policyPackBinding?.versionId
            ?: record.receipt?.workflowPolicyPackVersion
        val workflowPolicyPrecedenceSource = workflowRun?.policyResolution?.precedenceSource
            ?: record.receipt?.workflowPolicyPrecedenceSource
        val workflowSimulationOnly = workflowRun?.workflowSimulationOnly
            ?: record.receipt?.workflowSimulationOnly
            ?: false
        val workflowRolloutState = workflowRun?.policyRolloutState
            ?: record.receipt?.workflowPolicyRolloutState
        val workflowRolloutSummaryBase = workflowRun?.workflowRolloutSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowRolloutSummary.orEmpty()
        val workflowRolloutSummary = buildList {
            workflowRolloutSummaryBase.takeIf { it.isNotBlank() }?.let { add(it) }
            workflowRolloutState?.scheduleSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it) }
            workflowRolloutState?.rolloutCalendarSummary
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it) }
        }.joinToString(" ").ifBlank { workflowRolloutSummaryBase }
        val workflowRolloutApprovalSummary = workflowRun?.workflowRolloutApprovalSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowRolloutApprovalSummary.orEmpty()
        val workflowRolloutFreezeSummary = workflowRun?.workflowRolloutFreezeSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowRolloutFreezeSummary.orEmpty()
        val workflowRolloutRollbackSummary = workflowRun?.workflowRolloutRollbackSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowRolloutRollbackSummary.orEmpty()
        val policyPromotionStatus = workflowRolloutState?.promotionStatus
            ?: record.receipt?.policyPromotionStatus
        val policyPromotionReadinessStatus = workflowRolloutState?.promotionReadiness?.status
            ?: record.receipt?.policyPromotionReadiness?.status
        val policyApprovalPending = workflowRolloutState?.approvalState == PolicyRolloutApprovalState.PENDING ||
            workflowRolloutState?.approvalOperations?.any { it.status == ApprovalOperationStatus.PENDING } == true ||
            record.receipt?.policyApprovalOperations?.any { it.status == ApprovalOperationStatus.PENDING } == true
        val policyEstateSnapshot = workflowRolloutState?.policyEstateSnapshot
            ?: record.receipt?.policyEstateSnapshot
            ?: record.policyEstateSnapshot
        val policyEstateRemediationPlan = workflowRolloutState?.policyEstateRemediationPlan
            ?: record.receipt?.policyEstateRemediationPlan
            ?: record.policyEstateRemediationPlan
        val policyEstateRemediationActions = workflowRolloutState?.policyEstateRemediationActions
            ?.takeIf { it.isNotEmpty() }
            ?: record.receipt?.policyEstateRemediationActions
                ?.takeIf { it.isNotEmpty() }
            ?: record.policyEstateRemediationActions
        val policyEstateDriftSeverity = policyEstateSnapshot
            ?.driftRecords
            ?.maxByOrNull { it.severity.ordinal }
            ?.severity
        val policyEstateBlockerCount = policyEstateSnapshot
            ?.blockers
            ?.count { blocker -> !blocker.acknowledged }
            ?: 0
        val policyEstateRemediationPending = policyEstateRemediationPlan
            ?.status
            ?.let { status ->
                status == PolicyEstateRemediationStatus.RECOMMENDED ||
                    status == PolicyEstateRemediationStatus.ACKNOWLEDGED ||
                    status == PolicyEstateRemediationStatus.SCHEDULED
            }
            ?: policyEstateRemediationActions.any { action ->
                action.status == PolicyEstateRemediationStatus.RECOMMENDED ||
                    action.status == PolicyEstateRemediationStatus.ACKNOWLEDGED ||
                    action.status == PolicyEstateRemediationStatus.SCHEDULED
            }
        val policyEstateSummary = workflowRolloutState?.policyEstateSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.policyEstateSummary
                ?.takeIf { it.isNotBlank() }
            ?: record.policyEstateSummary
                ?.takeIf { it.isNotBlank() }
            ?: policyEstateSnapshot?.summary.orEmpty()
        val policyEstateDriftSummary = workflowRolloutState?.policyEstateDriftSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.policyEstateDriftSummary
