            ?: "No estate blocker summary."
        val policyEstateRemediationSummary = workflowRolloutState?.policyEstateRemediationSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.policyEstateRemediationSummary
                ?.takeIf { it.isNotBlank() }
            ?: record.policyEstateRemediationSummary
                ?.takeIf { it.isNotBlank() }
            ?: policyEstateRemediationPlan?.summary.orEmpty()
        val estateAutomationRule = workflowRolloutState?.estateAutomationRule
            ?: record.receipt?.estateAutomationRule
            ?: record.estateAutomationRule
        val estateAutomationEligibility = workflowRolloutState?.estateAutomationEligibility
            ?: record.receipt?.estateAutomationEligibility
            ?: record.estateAutomationEligibility
        val scheduledRemediationPlan = workflowRolloutState?.scheduledRemediationPlan
