        val automationCancellationRecords = workflowRolloutState?.automationCancellationRecords
            ?.takeIf { it.isNotEmpty() }
            ?: record.receipt?.automationCancellationRecords
                ?.takeIf { it.isNotEmpty() }
            ?: record.automationCancellationRecords
        val automationEligible = automationEligibility == WorkflowAutomationEligibilityStatus.ALLOWED ||
