            estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.APPROVAL_REQUIRED ||
            reasonCodes.contains(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_APPROVAL_REQUIRED)
        val automationCooldownActive = automationEligibility == WorkflowAutomationEligibilityStatus.COOLDOWN_ACTIVE ||
            estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.COOLDOWN_ACTIVE ||
            reasonCodes.contains(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_COOLDOWN)
        val automationSuppressed = automationEligibility == WorkflowAutomationEligibilityStatus.SUPPRESSED ||
            estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.SUPPRESSED ||
            reasonCodes.contains(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_SUPPRESSED)
        val automationMaintenanceWindowBlocked = estateAutomationEligibility?.status == EstateAutomationEligibilityStatus.WINDOW_BLOCKED ||
            reasonCodes.contains(RoleReasonCodes.ROLE_ESTATE_AUTOMATION_WINDOW_BLOCKED)
