                ?.takeIf { it.isNotBlank() }
            ?: crossTenantRolloutSummary?.summary.orEmpty()
        val policyPackLifecycleSummary = workflowRolloutState?.packLifecycleSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowPackLifecycleSummary
                ?.takeIf { it.isNotBlank() }
