            ?: record.receipt?.workflowPackDeprecationSummary.orEmpty()
        val policyPackRetirementSummary = workflowRolloutState?.packRetirementSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.workflowPackRetirementSummary.orEmpty()
        val policyPackReplacementSummary = workflowPackReplacementPlan?.summary
