        val rolloutPromotionReadiness = workflowRolloutState?.promotionReadinessSummary
            ?: record.receipt?.rolloutPromotionReadiness
        val crossWaveAnalyticsSummary = workflowRolloutState?.crossWaveAnalyticsSummary
            ?: record.receipt?.crossWaveAnalyticsSummary
        val windowImpactSummary = workflowRolloutState?.windowImpactSummary
            ?: record.receipt?.windowImpactSummary
        val rolloutPromotionOperation = workflowRolloutState?.promotionOperationRecords
            ?.maxByOrNull { operation -> operation.timestampMs }
            ?: record.receipt?.rolloutPromotionOperation
        val programCoordination = workflowRolloutState?.programCoordination
            ?: record.receipt?.programCoordination
        val crossProgramGovernanceSummary = workflowRolloutState?.crossProgramGovernanceSummary
            ?: record.receipt?.crossProgramGovernanceSummary
        val programCoordinationSummary = workflowRolloutState?.programCoordinationSummary
            .takeUnless { it.isNullOrBlank() }
            ?: record.receipt?.programCoordinationSummary.orEmpty()
        val crossProgramSummary = crossProgramGovernanceSummary
            ?.summary
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.crossProgramSummary.orEmpty()
        val programEscalationSummary = programCoordination
