            collaborationState = collaborationState,
            remoteOperatorHandoff = remoteOperatorHandoff,
            workflowRun = workflowRun,
            workflowTemplate = workflowTemplate
        )
        val remotePipelineSummary = if (includeRemotePipeline) {
            remotePipelineSummaryForRun(userId, record.runId)
        } else {
            null
        }
        val remoteDeliveryIssues = if (includeRemotePipeline) {
            remoteDeliveryIssuesForRun(userId, record.runId)
        } else {
            emptyList()
        }
        val collaborationIssues = buildList {
            if (remoteOperatorHandoff?.status == RemoteOperatorHandoffStatus.FAILED) {
                add(
                    RemoteDeliveryIssue(
                        code = "REMOTE_OPERATOR_HANDOFF_FAILED",
                        severity = GovernanceAlertSeverity.HIGH,
                        title = "Remote handoff failed",
                        summary = remoteOperatorHandoff.lastErrorSummary
                            ?: "Remote operator handoff failed and needs retry.",
                        relatedRunId = record.runId,
                        lastOccurredAtMs = remoteOperatorHandoff.lastAttemptAtMs
                    )
                )
            }
            alertRoutingRecords
                .filter { it.status == AlertRoutingStatus.FAILED }
                .forEach { routing ->
                    add(
                        RemoteDeliveryIssue(
                            code = "ALERT_ROUTING_FAILED",
                            severity = GovernanceAlertSeverity.WARNING,
                            title = "Alert routing failed",
                            summary = routing.lastErrorSummary
                                ?: "One or more alert routing targets failed.",
                            relatedRunId = record.runId,
                            lastOccurredAtMs = routing.lastAttemptAtMs
                        )
                    )
                }
            if (connectorDeadLetterCount > 0) {
                val latestDeadLetter = alertRoutingRecords
                    .flatMap { it.deadLetterRecords }
                    .maxByOrNull { it.createdAtMs }
                add(
                    RemoteDeliveryIssue(
                        code = "CONNECTOR_DEAD_LETTER",
                        severity = GovernanceAlertSeverity.HIGH,
                        title = "Connector dead-letter detected",
                        summary = latestDeadLetter?.summary
                            ?: "Connector deliveries moved to dead-letter and need manual re-route.",
                        relatedRunId = record.runId,
                        lastOccurredAtMs = latestDeadLetter?.createdAtMs ?: record.updatedAtMs
                    )
                )
            }
            if ((connectorHealthSummary?.unavailableTargets ?: 0) > 0) {
                add(
                    RemoteDeliveryIssue(
                        code = "CONNECTOR_DESTINATION_UNAVAILABLE",
                        severity = GovernanceAlertSeverity.WARNING,
                        title = "Connector destination unavailable",
                        summary = "Connector destination is unavailable; local fallback remains active.",
                        relatedRunId = record.runId,
                        lastOccurredAtMs = connectorHealthSummary?.lastUpdatedAtMs ?: record.updatedAtMs
                    )
                )
            }
        }
        fun buildGovernanceSummaryResult(): GovernanceCaseSummary = GovernanceCaseSummary(
            caseId = "case_${record.runId.ifBlank { record.recordId }}",
            runId = record.runId,
            recordId = record.recordId,
            module = record.module,
            status = record.status,
            priority = priority,
            primaryQueue = primaryQueue,
            queueTags = queueTags,
            title = title,
            summary = summary,
            activeRole = record.activeRole ?: signal.role,
            assigneeDisplayName = collaborationState?.assignedTo?.displayName,
