            reasonFamilies = reasonFamilies,
            lastEventAtMs = recordTimestampMs(record),
            reviewed = reviewed,
            nextActionSummary = workflowRun?.nextAction?.detail
                ?.takeIf { it.isNotBlank() }
                ?: workflowRun?.nextAction?.title
                    ?.takeIf { it.isNotBlank() }
                ?: nextActionSummaryFor(queueTags),
            workflowTemplateName = workflowTemplate?.name
                ?.takeIf { it.isNotBlank() }
                ?: workflowRun?.templateName?.takeIf { it.isNotBlank() },
            workflowTemplateId = workflowTemplate?.templateId
                ?.takeIf { it.isNotBlank() }
                ?: workflowRun?.templateId?.takeIf { it.isNotBlank() },
            workflowPolicyPackId = workflowPolicyPackId,
            workflowPolicyPackVersion = workflowPolicyPackVersion,
            workflowStage = workflowRun?.currentStage,
            workflowNextAction = workflowRun?.nextAction?.title?.takeIf { it.isNotBlank() },
            workflowPolicyPrecedenceSource = workflowPolicyPrecedenceSource,
            workflowSimulationOnly = workflowSimulationOnly,
            workflowRolloutStage = workflowRolloutState?.stage ?: record.receipt?.workflowRolloutStage,
            workflowRolloutMode = workflowRolloutState?.mode ?: record.receipt?.workflowRolloutMode,
            workflowRolloutScope = workflowRolloutState?.target?.scope ?: record.receipt?.workflowRolloutScope,
            workflowRolloutApprovalState = workflowRolloutState?.approvalState
