            policyGovernanceProgramId = policyGovernanceProgram?.programId
                ?.takeIf { it.isNotBlank() },
            policyGovernanceProgramStatus = policyGovernanceProgram?.status,
            policyGovernanceWaveStatus = policyGovernanceProgram
                ?.waves
                ?.firstOrNull { wave -> wave.waveId == policyGovernanceProgram.currentWaveId }
                ?.status
                ?: policyGovernanceProgram
                    ?.waves
                    ?.maxByOrNull { wave -> wave.updatedAtMs }
                    ?.status,
            workflowPackLifecycleStatus = workflowPackLifecycleStatus,
            crossTenantReadinessStatus = crossTenantRolloutSummary?.readinessStatus,
            crossTenantDriftedTargets = crossTenantRolloutSummary?.driftedTargets ?: 0,
            crossTenantExemptedTargets = crossTenantRolloutSummary?.exemptedTargets ?: 0,
            crossTenantPinnedTargets = crossTenantRolloutSummary?.pinnedTargets ?: 0,
            policyEstateDriftSeverity = policyEstateDriftSeverity,
            policyEstateBlockerCount = policyEstateBlockerCount,
            policyEstateRemediationPending = policyEstateRemediationPending,
            policyApprovalPending = policyApprovalPending,
            slaStatus = slaStatus,
            stageTimerStatus = stageTimerStatus,
            escalationTimerStatus = escalationTimerStatus,
            automationEligibility = automationEligibility,
            automationEligible = automationEligible,
            scheduledRemediationStatus = scheduledRemediationStatus,
            automationApprovalRequired = automationApprovalRequired,
            automationCooldownActive = automationCooldownActive,
            automationSuppressed = automationSuppressed,
            automationMaintenanceWindowBlocked = automationMaintenanceWindowBlocked,
