                ?: record.receipt?.currentRolloutWindowEligibility,
            rolloutCarryForwardPending = workflowRolloutState?.rolloutWaves
                ?.firstOrNull { wave -> wave.waveId == workflowRolloutState.currentRolloutWaveId }
                ?.carryForwardState
