                ?: record.receipt?.rolloutCarryForwardPending
                ?: false,
            rolloutCrossWindowPaused = workflowRolloutState?.crossWindowGovernanceControl?.pauseState ==
                CrossWindowPauseState.PAUSED ||
                record.receipt?.rolloutCrossWindowPaused == true,
            rolloutNextWindowPending = when {
                workflowRolloutState?.calendarAwarePromotionDecision?.windowEligibility == PromotionWindowEligibility.ELIGIBLE -> false
                workflowRolloutState?.calendarAwarePromotionDecision?.nextEligibleWindow?.nextEligibleAtMs != null -> true
                workflowRolloutState?.nextEligibleWindowSummary?.isNotBlank() == true -> true
                else -> record.receipt?.rolloutNextWindowPending ?: false
