    private fun buildOperatorCaseTimeline(
        record: ExecutionReceiptRecord,
        collaborationState: GovernanceCaseCollaborationState?,
        handoffRecord: RemoteOperatorHandoffRecord?,
        routingRecords: List<AlertRoutingRecord>
    ): List<OperatorCaseTimelineItem> {
        val runEvents = record.runEvents.map { event ->
            OperatorCaseTimelineItem(
                timelineId = event.eventId.ifBlank {
                    "timeline_${record.runId}_${event.type.name.lowercase()}_${event.timestampMs}"
                },
                type = timelineTypeFor(event.type),
                title = event.title.ifBlank { readableTimelineTitle(event.type) },
                detail = event.detail,
                timestampMs = event.timestampMs,
                severity = timelineSeverityFor(event.type),
                reasonCodes = event.reasonCodes
            )
        }
        val collaborationArtifacts = (
            record.collaborationEvents + (collaborationState?.collaborationEvents ?: emptyList())
            )
            .distinctBy { it.eventId }
            .map { event ->
                OperatorCaseTimelineItem(
                    timelineId = "collab_artifact_${event.eventId}",
                    type = OperatorCaseTimelineItemType.OPERATOR_ACTION,
                    title = when (event.type) {
                        GovernanceCollaborationEventType.WORKFLOW_TEMPLATE_ATTACHED -> "Workflow template attached"
                        GovernanceCollaborationEventType.WORKFLOW_STAGE_CHANGED -> "Workflow stage changed"
                        GovernanceCollaborationEventType.WORKFLOW_POLICY_APPLIED -> "Workflow policy applied"
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_UPDATED -> "Workflow rollout updated"
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_APPROVAL_UPDATED -> "Workflow rollout approval updated"
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_ROLLED_BACK -> "Workflow rollout rolled back"
                        GovernanceCollaborationEventType.SLA_STATUS_CHANGED -> "Workflow SLA updated"
                        GovernanceCollaborationEventType.ESCALATION_TIMER_STATUS_CHANGED -> "Escalation timer updated"
                        GovernanceCollaborationEventType.NOTE_ADDED -> "Operator note added"
                        GovernanceCollaborationEventType.HANDOFF_CREATED -> "Operator handoff created"
                        GovernanceCollaborationEventType.ESCALATION_CREATED -> "Operator escalation created"
                        GovernanceCollaborationEventType.AUTOMATION_RULE_TRIGGERED -> "Automation rule triggered"
                        GovernanceCollaborationEventType.AUTOMATION_ACTION_EXECUTED -> "Automation action executed"
                        GovernanceCollaborationEventType.AUTOMATION_ACTION_SKIPPED -> "Automation action skipped"
                        GovernanceCollaborationEventType.AUTOMATION_GUARDRAIL_EVALUATED -> "Automation guardrail evaluated"
                    },
                    detail = event.summary,
                    timestampMs = event.timestampMs,
                    severity = when (event.type) {
                        GovernanceCollaborationEventType.AUTOMATION_ACTION_SKIPPED,
                        GovernanceCollaborationEventType.AUTOMATION_GUARDRAIL_EVALUATED,
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_APPROVAL_UPDATED,
                        GovernanceCollaborationEventType.WORKFLOW_ROLLOUT_ROLLED_BACK,
                        GovernanceCollaborationEventType.SLA_STATUS_CHANGED,
                        GovernanceCollaborationEventType.ESCALATION_TIMER_STATUS_CHANGED -> GovernanceAlertSeverity.WARNING
                        else -> GovernanceAlertSeverity.INFO
                    },
                    reasonCodes = event.reasonCodes
                )
            }
        val automationArtifacts = (
            record.automationAudit + (collaborationState?.automationAudit ?: emptyList())
            )
            .distinctBy { it.auditId }
            .map { audit ->
                OperatorCaseTimelineItem(
                    timelineId = "automation_${record.runId}_${audit.auditId}",
                    type = OperatorCaseTimelineItemType.OPERATOR_ACTION,
                    title = when (audit.status) {
                        RemoteOpsAutomationDecisionStatus.EXECUTED -> "Safe automation executed"
                        RemoteOpsAutomationDecisionStatus.TRIGGERED -> "Safe automation triggered"
                        RemoteOpsAutomationDecisionStatus.SKIPPED -> "Safe automation skipped"
                        RemoteOpsAutomationDecisionStatus.BLOCKED -> "Safe automation blocked"
                        RemoteOpsAutomationDecisionStatus.SUPPRESSED -> "Safe automation suppressed"
                        RemoteOpsAutomationDecisionStatus.THROTTLED -> "Safe automation throttled"
                        RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> "Safe automation cooldown active"
                        RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY -> "Safe automation simulated"
                    },
                    detail = audit.summary,
                    timestampMs = audit.timestampMs,
                    severity = when (audit.status) {
                        RemoteOpsAutomationDecisionStatus.SKIPPED,
                        RemoteOpsAutomationDecisionStatus.BLOCKED,
                        RemoteOpsAutomationDecisionStatus.SUPPRESSED,
                        RemoteOpsAutomationDecisionStatus.THROTTLED,
                        RemoteOpsAutomationDecisionStatus.SIMULATION_ONLY,
                        RemoteOpsAutomationDecisionStatus.COOLDOWN_ACTIVE -> GovernanceAlertSeverity.WARNING
                        else -> GovernanceAlertSeverity.INFO
                    },
                    reasonCodes = audit.reasonCodes
                )
            }
        val collaborationEvent = collaborationState
            ?.lastActionSummary
            ?.takeIf { it.isNotBlank() }
            ?.let { summary ->
                val collaborationReasonCodes = buildSet {
                    addAll(collaborationState.assignmentEvents.lastOrNull()?.reasonCodes.orEmpty())
                    addAll(collaborationState.routingActions.lastOrNull()?.reasonCodes.orEmpty())
                    if (collaborationState.claimStatus == OperatorCaseClaimStatus.CLAIMED) {
                        add(RoleReasonCodes.ROLE_OPERATOR_CASE_CLAIMED)
                    }
                    if (collaborationState.assignedTo != null) {
                        add(RoleReasonCodes.ROLE_OPERATOR_CASE_ASSIGNED)
                    }
                    if (collaborationState.followUp?.requested == true) {
                        add(RoleReasonCodes.ROLE_OPERATOR_FOLLOW_UP_REQUESTED)
                    }
                    if (collaborationState.permissionDenials.isNotEmpty()) {
                        add(RoleReasonCodes.ROLE_OPERATOR_PERMISSION_DENIED)
                    }
                }.toList()
                OperatorCaseTimelineItem(
                    timelineId = "collaboration_${record.runId}_${collaborationState.updatedAtMs}",
                    type = OperatorCaseTimelineItemType.OPERATOR_ACTION,
                    title = "Operator collaboration update",
                    detail = summary,
                    timestampMs = collaborationState.updatedAtMs,
                    severity = GovernanceAlertSeverity.INFO,
                    reasonCodes = collaborationReasonCodes
                )
            }
        val handoffEvent = handoffRecord
            ?.let { handoff ->
                val handoffReasonCodes = buildRemoteOperatorHandoffSummary(handoff)?.reasonCodes.orEmpty()
                OperatorCaseTimelineItem(
                    timelineId = "handoff_${record.runId}_${handoff.lastAttemptAtMs}",
                    type = OperatorCaseTimelineItemType.OPERATOR_ACTION,
                    title = "Remote handoff ${handoff.status.name.lowercase().replace('_', ' ')}",
                    detail = handoff.lastErrorSummary
                        ?: handoff.attempts.lastOrNull { it.summary.isNotBlank() }?.summary
                        ?: handoff.request?.summary
                        ?: "Remote handoff status updated.",
                    timestampMs = handoff.lastAttemptAtMs,
                    severity = if (handoff.status == RemoteOperatorHandoffStatus.FAILED) {
                        GovernanceAlertSeverity.HIGH
                    } else {
                        GovernanceAlertSeverity.INFO
                    },
                    reasonCodes = handoffReasonCodes
                )
            }
        val routingEvents = routingRecords.map { routing ->
            val routingReasonCodes = buildSet {
                addAll(buildAlertRoutingSummary(listOf(routing))?.reasonCodes.orEmpty())
                addAll(buildConnectorRoutingSummary(listOf(routing))?.reasonCodes.orEmpty())
                addAll(routing.authorization?.reasonCodes.orEmpty())
            }.toList()
            OperatorCaseTimelineItem(
                timelineId = "routing_${record.runId}_${routing.recordId}_${routing.lastAttemptAtMs}",
                type = OperatorCaseTimelineItemType.ALERT_DELIVERY,
                title = "Alert routing ${routing.status.name.lowercase().replace('_', ' ')}",
                detail = routing.lastErrorSummary
                    ?: routing.attempts.lastOrNull { it.summary.isNotBlank() }?.summary
                    ?: "Alert routing state updated.",
                timestampMs = routing.lastAttemptAtMs,
                severity = when (routing.status) {
                    AlertRoutingStatus.FAILED -> GovernanceAlertSeverity.HIGH
                    AlertRoutingStatus.QUEUED -> GovernanceAlertSeverity.WARNING
                    AlertRoutingStatus.DELIVERED -> GovernanceAlertSeverity.INFO
                    AlertRoutingStatus.DUPLICATE_SUPPRESSED -> GovernanceAlertSeverity.INFO
                    AlertRoutingStatus.LOCAL_ONLY -> GovernanceAlertSeverity.WARNING
                },
                reasonCodes = routingReasonCodes
                )
            }
        return (
            runEvents +
                collaborationArtifacts +
                automationArtifacts +
                listOfNotNull(collaborationEvent, handoffEvent) +
                routingEvents
            )
            .distinctBy { it.timelineId }
            .sortedByDescending { it.timestampMs }
            .take(20)
    }

    private fun readableTimelineTitle(type: ProofLedgerEventType): String {
