            ProofLedgerEventType.VERIFICATION_FAILED,
            ProofLedgerEventType.ROLLBACK_FAILED,
            ProofLedgerEventType.DISPUTE_OPENED,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_FAILED,
            ProofLedgerEventType.ALERT_ROUTING_FAILED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_FAILED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_DEAD_LETTERED,
            ProofLedgerEventType.OPERATOR_PERMISSION_DENIED,
            ProofLedgerEventType.REMOTE_OPERATOR_AUTH_DENIED,
            ProofLedgerEventType.WORKFLOW_POLICY_ROLLOUT_APPROVAL_DENIED -> GovernanceAlertSeverity.HIGH

            ProofLedgerEventType.SYNC_PENDING,
            ProofLedgerEventType.RECONCILIATION_MISMATCH_DETECTED,
            ProofLedgerEventType.ROLLBACK_AVAILABLE,
            ProofLedgerEventType.APPROVAL_REQUESTED,
