    private fun assignmentSummaryFor(state: GovernanceCaseCollaborationState?): String {
        if (state == null) return ""
        val owner = state.claimedBy?.displayName ?: "unclaimed"
        val assignee = state.assignedTo?.displayName ?: "unassigned"
        return "Owner $owner · Assignee $assignee"
    }

    private fun escalationSummaryFor(state: GovernanceCaseCollaborationState?): String {
        val escalation = state?.escalation ?: return ""
        if (!escalation.escalated) return ""
        val target = escalation.target ?: "unspecified target"
        return "Escalated to $target (level ${escalation.level})."
    }

    private fun permissionDenialSummaryFor(state: GovernanceCaseCollaborationState?): String {
        val lastDenial = state?.permissionDenials?.lastOrNull() ?: return ""
        return "Permission denied: ${lastDenial.action.name.lowercase().replace('_', ' ')} (${lastDenial.reason.name.lowercase().replace('_', ' ')})."
    }

    private fun providerLabelFor(record: ExecutionReceiptRecord): String? {
        return record.receipt?.providerSelectionSummary?.selectedProviderName
            ?.takeIf { it.isNotBlank() }
            ?: record.receipt?.providerSelectionSummary?.selectedProviderId
                ?.takeIf { it.isNotBlank() }
            ?: record.settlementRecord?.selectedProviderName
                ?.takeIf { it.isNotBlank() }
            ?: record.settlementRecord?.selectedProviderId
                ?.takeIf { it.isNotBlank() }
            ?: record.providerDecisions.firstOrNull()
                ?.let { decision ->
                    decision.providerName.takeIf { it.isNotBlank() } ?: decision.providerId.takeIf { it.isNotBlank() }
                }
            ?: record.syncIssues.firstOrNull { !it.providerId.isNullOrBlank() }?.providerId
    }

    private fun queueTagsFor(
        record: ExecutionReceiptRecord,
        signal: GovernanceSignal,
        settlementStatus: SettlementStatus,
        disputeStatus: DisputeStatus,
        syncState: SettlementSyncState
    ): List<GovernanceQueueType> {
        val output = linkedSetOf<GovernanceQueueType>()
        val rollbackFailed = signal.rollbackFailed
        if (syncState == SettlementSyncState.MISMATCH || signal.reconciliationMismatch) {
            output += GovernanceQueueType.RECONCILIATION_MISMATCH
        }
        if (rollbackFailed) {
            output += GovernanceQueueType.ROLLBACK_FAILURE
        }
        if (
            disputeStatus == DisputeStatus.OPENED ||
            disputeStatus == DisputeStatus.SYNC_PENDING ||
            disputeStatus == DisputeStatus.ACKNOWLEDGED ||
            disputeStatus == DisputeStatus.UNDER_REVIEW
        ) {
            output += GovernanceQueueType.DISPUTE_FOLLOW_UP
        }
        if (syncState == SettlementSyncState.SYNC_PENDING || signal.settlementSyncPending) {
            output += GovernanceQueueType.SYNC_PENDING
        }
        if (signal.verificationFailed) {
            output += GovernanceQueueType.VERIFICATION_FAILURE
        }
        if (hasProviderIssue(record) || signal.providerDenied || signal.providerAckTimeout) {
            output += GovernanceQueueType.PROVIDER_ISSUE
        }
        if (
            hasUnresolvedSettlementOrDispute(record) ||
            settlementStatus == SettlementStatus.SYNC_PENDING ||
            settlementStatus == SettlementStatus.DISPUTED ||
            settlementStatus == SettlementStatus.ROLLBACK_REQUESTED
        ) {
            output += GovernanceQueueType.NEEDS_ATTENTION
        }
        if (output.isEmpty() && record.status == ResponseStatus.ERROR) {
            output += GovernanceQueueType.NEEDS_ATTENTION
        }
        val ordering = listOf(
            GovernanceQueueType.RECONCILIATION_MISMATCH,
            GovernanceQueueType.ROLLBACK_FAILURE,
            GovernanceQueueType.DISPUTE_FOLLOW_UP,
            GovernanceQueueType.SYNC_PENDING,
            GovernanceQueueType.VERIFICATION_FAILURE,
            GovernanceQueueType.PROVIDER_ISSUE,
            GovernanceQueueType.NEEDS_ATTENTION
        )
        return ordering.filter(output::contains)
    }

    private fun governancePriorityFor(
        queueTags: List<GovernanceQueueType>,
        signal: GovernanceSignal
    ): GovernanceCasePriority {
        var score = 0
        if (queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH)) score += 50
        if (queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE)) score += 45
        if (queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP)) score += 35
        if (queueTags.contains(GovernanceQueueType.SYNC_PENDING)) score += 30
        if (queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE)) score += 30
        if (queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE)) score += 20
        if (queueTags.contains(GovernanceQueueType.NEEDS_ATTENTION)) score += 10
        if (signal.approvalDenied) score += 10
        if (signal.providerAckTimeout) score += 10
        if (signal.duplicateCallbackIgnored) score += 5
        return when {
            score >= 90 -> GovernanceCasePriority.CRITICAL
            score >= 65 -> GovernanceCasePriority.HIGH
            score >= 35 -> GovernanceCasePriority.MEDIUM
            else -> GovernanceCasePriority.LOW
        }
    }

    private fun caseTitleFor(
        queueTags: List<GovernanceQueueType>,
        syncState: SettlementSyncState,
        disputeStatus: DisputeStatus
    ): String {
        return when {
            queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) ->
                "Settlement mismatch requires reconciliation"
            queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE) ->
                "Rollback failed after external execution"
            queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) &&
                (disputeStatus == DisputeStatus.SYNC_PENDING || syncState == SettlementSyncState.SYNC_PENDING) ->
                "Dispute pending provider acknowledgement"
            queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) ->
                "Dispute requires operator follow-up"
            queueTags.contains(GovernanceQueueType.SYNC_PENDING) ->
                "Sync pending between local and provider state"
            queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE) ->
                "Verification failed and needs review"
            queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE) ->
                "Provider issue requires manual review"
            else ->
                "Run requires governance review"
        }
    }

    private fun caseSummaryFor(
        record: ExecutionReceiptRecord,
        providerLabel: String?,
        settlementStatus: SettlementStatus,
        disputeStatus: DisputeStatus,
        syncState: SettlementSyncState
    ): String {
        val issue = record.receipt?.issueSummary?.takeIf { it.isNotBlank() }
            ?: record.syncIssues.firstOrNull()?.summary?.takeIf { it.isNotBlank() }
        if (issue != null) return issue
        val roleLabel = (record.activeRole ?: record.policySnapshot?.activeRole)?.name
            ?.lowercase()
            ?.replaceFirstChar { it.uppercase() }
            ?: "Unknown role"
        val providerPart = providerLabel ?: "No provider specified"
        val syncPart = syncState.name.lowercase().replace('_', ' ')
        val disputePart = disputeStatus.name.lowercase().replace('_', ' ')
        val settlementPart = settlementStatus.name.lowercase().replace('_', ' ')
        return "$roleLabel · $providerPart · settlement $settlementPart · dispute $disputePart · sync $syncPart"
    }

    private fun nextActionSummaryFor(queueTags: List<GovernanceQueueType>): String {
        return when {
            queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) ->
                "Review mismatch evidence, then request sync retry before escalating provider-side resolution."
            queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE) ->
                "Escalate rollback failure and verify provider acknowledgement before any further commit."
            queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) ->
                "Review dispute evidence and keep local dispute status aligned with remote acknowledgement."
            queueTags.contains(GovernanceQueueType.SYNC_PENDING) ->
                "Trigger sync retry and monitor acknowledgement state until reconciled."
            queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE) ->
                "Inspect verification/proof trail and decide rollback or dispute path."
            queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE) ->
                "Review provider policy fit and compare alternatives if issue cluster persists."
            else ->
                "Mark reviewed after checking receipt and ledger trail."
        }
    }

