            GovernanceActionSuggestion(
                action = GovernanceActionType.ROLLBACK_POLICY_ROLLOUT,
                title = "Rollback rollout",
                detail = "Rollback rollout to last safe state without rewriting history."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.REQUEST_POLICY_PROMOTION,
                title = "Request promotion",
                detail = "Request policy promotion with readiness analytics and blockers."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.APPROVE_POLICY_PROMOTION,
                title = "Approve promotion",
                detail = "Approve policy promotion after readiness and guardrail review."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.REJECT_POLICY_PROMOTION,
                title = "Reject promotion",
                detail = "Reject policy promotion and keep rollout in a safe state."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ADVANCE_POLICY_ROLLOUT,
                title = "Advance rollout",
                detail = "Advance rollout stage when readiness and approvals allow."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.CREATE_POLICY_GOVERNANCE_PROGRAM,
                title = "Create policy program",
                detail = "Create a governance program for staged cross-tenant rollout."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ADVANCE_POLICY_GOVERNANCE_WAVE,
                title = "Advance governance wave",
                detail = "Advance the active governance wave with durable audit records."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.PAUSE_POLICY_GOVERNANCE_WAVE,
                title = "Pause governance wave",
                detail = "Pause governance wave progression for blocker review."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ADD_POLICY_ROLLOUT_EXEMPTION,
                title = "Add rollout exemption",
                detail = "Exempt a target from rollout while keeping a durable reason trail."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.REMOVE_POLICY_ROLLOUT_EXEMPTION,
                title = "Remove rollout exemption",
                detail = "Remove a rollout exemption after blocker remediation."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.PIN_POLICY_ROLLOUT_TARGET,
                title = "Pin rollout target",
                detail = "Pin a target to a specific pack version for controlled adoption."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.UNPIN_POLICY_ROLLOUT_TARGET,
                title = "Unpin rollout target",
                detail = "Unpin target and resume governed rollout progression."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.DEPRECATE_POLICY_PACK,
                title = "Deprecate policy pack",
                detail = "Mark policy pack as deprecated while preparing replacement."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.RETIRE_POLICY_PACK,
                title = "Retire policy pack",
                detail = "Begin pack retirement with cross-tenant blocker safeguards."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ATTACH_POLICY_PACK_REPLACEMENT,
                title = "Attach replacement plan",
                detail = "Attach replacement pack/version plan for retirement cutover."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ATTACH_POLICY_ESTATE_REMEDIATION_PLAN,
                title = "Attach estate remediation",
                detail = "Attach a policy-estate remediation plan for drift and lifecycle blockers."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.ACK_POLICY_ESTATE_BLOCKER,
                title = "Acknowledge estate blocker",
                detail = "Acknowledge an active policy-estate blocker with durable operator trace."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.SCHEDULE_POLICY_ESTATE_REMEDIATION,
                title = "Schedule remediation",
                detail = "Schedule a safe policy-estate remediation action for execution."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.APPLY_SAFE_POLICY_ESTATE_REMEDIATION,
                title = "Apply safe remediation",
                detail = "Apply a safe policy-estate remediation action with durable audit trail."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.MARK_REVIEWED,
                title = "Mark reviewed",
                detail = "Hide this case from default unresolved queue until a new event reopens it."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.COPY_CASE_SUMMARY,
                title = "Copy summary",
                detail = "Copy a concise case summary for support handoff or escalation."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.EXPORT_CASE_SUMMARY,
                title = "Export summary",
                detail = "Export this case summary in plain text for internal records."
            ),
            GovernanceActionSuggestion(
                action = GovernanceActionType.OPEN_RECEIPT_TRAIL,
                title = "Open receipt trail",
                detail = "Open the related execution receipt and ledger trail for this run."
            )
        )
        if (collaborationState?.status == OperatorCollaborationStatus.UNCLAIMED) {
            actions.removeAll { it.action == GovernanceActionType.UNCLAIM_CASE }
            actions.removeAll { it.action == GovernanceActionType.RELEASE_CASE }
        }
        if (workflowRun != null) {
            actions.removeAll { it.action == GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE }
        }
        if (workflowTemplate != null && workflowRun == null) {
            actions += GovernanceActionSuggestion(
                action = GovernanceActionType.ATTACH_WORKFLOW_TEMPLATE,
                title = "Attach ${workflowTemplate.name.ifBlank { "workflow" }}",
                detail = "Attach workflow template ${workflowTemplate.templateId}."
            )
        }
        val workflowNextAction = workflowRun?.nextAction
        val workflowNextActionType = workflowNextAction?.action
        if (workflowNextActionType != null) {
            actions += GovernanceActionSuggestion(
                action = workflowNextActionType,
                title = "Workflow next action",
                detail = workflowNextAction.detail.ifBlank {
                    workflowNextAction.title
                }
            )
        }
        if (remoteOperatorHandoff?.status == RemoteOperatorHandoffStatus.ACK_PENDING) {
            actions += GovernanceActionSuggestion(
                action = GovernanceActionType.ACK_REMOTE_HANDOFF,
                title = "Acknowledge handoff",
                detail = "Mark remote handoff acknowledgement in the local durable trail."
            )
        }
        if (
            queueTags.contains(GovernanceQueueType.SYNC_PENDING) ||
            queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) ||
            queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP)
        ) {
            actions += GovernanceActionSuggestion(
                action = GovernanceActionType.RETRY_SYNC_INTENT,
                title = "Retry sync intent",
                detail = "Record a local sync retry request for settlement/dispute reconciliation."
            )
        }
        if (!providerLabel.isNullOrBlank()) {
            actions += GovernanceActionSuggestion(
                action = GovernanceActionType.FILTER_PROVIDER_CASES,
                title = "Filter provider cases",
                detail = "Narrow the queue to runs touching provider \"$providerLabel\"."
            )
        }
        if (role != null) {
            actions += GovernanceActionSuggestion(
                action = GovernanceActionType.FILTER_ROLE_CASES,
                title = "Filter role cases",
                detail = "Narrow the queue to runs executing under ${role.name.lowercase()} role."
            )
        }
        return actions.distinctBy { it.action }
    }

    private fun caseAlertsFor(
        summary: GovernanceCaseSummary,
        reasonCodes: List<String>
    ): List<GovernanceAlert> {
        val alerts = mutableListOf<GovernanceAlert>()
        if (summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_SETTLEMENT_MISMATCH",
                severity = GovernanceAlertSeverity.CRITICAL,
                title = "Settlement mismatch",
                summary = "Local and provider settlement states disagree for this run.",
                count = 1,
                relatedQueue = GovernanceQueueType.RECONCILIATION_MISMATCH
            )
        }
        if (summary.queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) &&
            summary.syncState == SettlementSyncState.SYNC_PENDING
        ) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_DISPUTE_SYNC_PENDING",
                severity = GovernanceAlertSeverity.HIGH,
                title = "Dispute sync pending",
                summary = "Dispute is open locally and still pending provider/gateway acknowledgement.",
                count = 1,
                relatedQueue = GovernanceQueueType.DISPUTE_FOLLOW_UP
            )
        }
        if (summary.queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_ROLLBACK_FAILED",
                severity = GovernanceAlertSeverity.HIGH,
                title = "Rollback failed",
                summary = "Rollback did not complete successfully and needs manual review.",
                count = 1,
                relatedQueue = GovernanceQueueType.ROLLBACK_FAILURE
            )
        }
        if (summary.queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_VERIFICATION_FAILED",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Verification failed",
                summary = "Verification failed or proof is incomplete for this run.",
                count = 1,
                relatedQueue = GovernanceQueueType.VERIFICATION_FAILURE
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_DUPLICATE_CALLBACK_CLUSTER",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Duplicate callback observed",
                summary = "Duplicate provider callback was ignored by idempotency safeguards.",
                count = 1,
                relatedQueue = GovernanceQueueType.PROVIDER_ISSUE
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_REMOTE_OPERATOR_HANDOFF_FAILED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_REMOTE_HANDOFF_FAILED",
                severity = GovernanceAlertSeverity.HIGH,
                title = "Remote handoff failed",
                summary = "Operator handoff to remote workflow failed and needs retry.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_ALERT_ROUTING_FAILED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_ALERT_ROUTING_FAILED",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Alert routing failed",
                summary = "At least one alert target failed; check routing attempts in case detail.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_OPERATOR_PERMISSION_DENIED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_OPERATOR_PERMISSION_DENIED",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Operator permission denied",
                summary = "One or more operator actions were blocked by permission scope.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_CONNECTOR_ROUTE_FAILED",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Connector routing failed",
                summary = "At least one connector target failed delivery and requires retry.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_CONNECTOR_DEAD_LETTER",
                severity = GovernanceAlertSeverity.HIGH,
                title = "Connector dead-letter backlog",
                summary = "One or more connector deliveries moved into dead-letter state.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (reasonCodes.contains(RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE)) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_CONNECTOR_UNAVAILABLE",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Connector unavailable",
                summary = "At least one connector target is unavailable; local fallback is active.",
                count = 1,
                relatedQueue = GovernanceQueueType.PROVIDER_ISSUE
            )
        }
        summary.policyEstateDriftSeverity?.let { severity ->
            val alertSeverity = when (severity) {
                PolicyEstateDriftSeverity.CRITICAL -> GovernanceAlertSeverity.HIGH
                PolicyEstateDriftSeverity.HIGH -> GovernanceAlertSeverity.WARNING
                PolicyEstateDriftSeverity.MEDIUM,
                PolicyEstateDriftSeverity.LOW -> GovernanceAlertSeverity.INFO
            }
            if (severity == PolicyEstateDriftSeverity.CRITICAL || severity == PolicyEstateDriftSeverity.HIGH) {
                alerts += GovernanceAlert(
                    code = "GOVERNANCE_ALERT_POLICY_ESTATE_DRIFT",
                    severity = alertSeverity,
                    title = "Policy estate drift detected",
                    summary = "Policy-estate drift severity is ${severity.name.lowercase()} for this run.",
                    count = 1,
                    relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
                )
            }
        }
        if (summary.policyEstateBlockerCount > 0) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_POLICY_ESTATE_BLOCKERS",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Policy estate blockers active",
                summary = "Policy-estate blockers remain unresolved for this run.",
                count = summary.policyEstateBlockerCount,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        if (summary.policyEstateRemediationPending) {
            alerts += GovernanceAlert(
                code = "GOVERNANCE_ALERT_POLICY_ESTATE_REMEDIATION_PENDING",
                severity = GovernanceAlertSeverity.INFO,
                title = "Policy estate remediation pending",
                summary = "A policy-estate remediation plan is pending operator completion.",
                count = 1,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        return alerts
    }

    private fun aggregateGovernanceAlerts(cases: List<GovernanceCaseRecord>): List<GovernanceAlert> {
        if (cases.isEmpty()) return emptyList()
        val alerts = mutableListOf<GovernanceAlert>()
        fun addAlert(
            code: String,
            severity: GovernanceAlertSeverity,
            title: String,
            summary: String,
            count: Int,
            relatedQueue: GovernanceQueueType?
        ) {
            if (count <= 0) return
            alerts += GovernanceAlert(
                code = code,
                severity = severity,
                title = title,
                summary = summary,
                count = count,
                relatedQueue = relatedQueue
            )
        }

        val disputeSyncPendingCount = cases.count {
            it.summary.queueTags.contains(GovernanceQueueType.DISPUTE_FOLLOW_UP) &&
                it.summary.syncState == SettlementSyncState.SYNC_PENDING
        }
        addAlert(
            code = "GOVERNANCE_ALERT_DISPUTE_SYNC_PENDING",
            severity = GovernanceAlertSeverity.HIGH,
            title = "Dispute sync pending",
            summary = "Disputes are open locally while provider/gateway acknowledgement is still pending.",
            count = disputeSyncPendingCount,
            relatedQueue = GovernanceQueueType.DISPUTE_FOLLOW_UP
        )

        val mismatchCount = cases.count { it.summary.queueTags.contains(GovernanceQueueType.RECONCILIATION_MISMATCH) }
        addAlert(
            code = "GOVERNANCE_ALERT_SETTLEMENT_MISMATCH",
            severity = GovernanceAlertSeverity.CRITICAL,
            title = "Settlement mismatch cluster",
            summary = "Local and provider settlement states disagree in active runs.",
            count = mismatchCount,
            relatedQueue = GovernanceQueueType.RECONCILIATION_MISMATCH
        )

        val rollbackFailedCount = cases.count { it.summary.queueTags.contains(GovernanceQueueType.ROLLBACK_FAILURE) }
        addAlert(
            code = "GOVERNANCE_ALERT_ROLLBACK_FAILED",
            severity = GovernanceAlertSeverity.HIGH,
            title = "Rollback failures detected",
            summary = "Rollback failed in one or more runs and requires operator follow-up.",
            count = rollbackFailedCount,
            relatedQueue = GovernanceQueueType.ROLLBACK_FAILURE
        )

        val verificationFailedCount = cases.count { it.summary.queueTags.contains(GovernanceQueueType.VERIFICATION_FAILURE) }
        addAlert(
            code = "GOVERNANCE_ALERT_VERIFICATION_FAILED",
            severity = GovernanceAlertSeverity.WARNING,
            title = "Verification failures",
            summary = "Proof or verification failed in recent external runs.",
            count = verificationFailedCount,
            relatedQueue = GovernanceQueueType.VERIFICATION_FAILURE
        )

        val duplicateCallbackCount = cases.count { case ->
            case.reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED)
        }
        if (duplicateCallbackCount >= 2) {
            addAlert(
                code = "GOVERNANCE_ALERT_DUPLICATE_CALLBACK_CLUSTER",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Duplicate callback cluster",
                summary = "Repeated duplicate provider callbacks were ignored by idempotency safeguards.",
                count = duplicateCallbackCount,
                relatedQueue = GovernanceQueueType.PROVIDER_ISSUE
            )
        }

        val topProviderIssue = cases
            .filter { it.summary.queueTags.contains(GovernanceQueueType.PROVIDER_ISSUE) && !it.summary.providerLabel.isNullOrBlank() }
            .groupBy { it.summary.providerLabel.orEmpty() }
            .maxByOrNull { (_, items) -> items.size }
        if (topProviderIssue != null && topProviderIssue.value.size >= 2) {
            addAlert(
                code = "GOVERNANCE_ALERT_PROVIDER_ISSUE_CLUSTER",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Provider issue cluster",
                summary = "Provider \"${topProviderIssue.key}\" appears in repeated unresolved issue cases.",
                count = topProviderIssue.value.size,
                relatedQueue = GovernanceQueueType.PROVIDER_ISSUE
            )
        }
        val connectorDeadLetterCases = cases.count { it.summary.connectorDeadLetterCount > 0 }
        if (connectorDeadLetterCases > 0) {
            addAlert(
                code = "GOVERNANCE_ALERT_CONNECTOR_DEAD_LETTER",
                severity = GovernanceAlertSeverity.HIGH,
                title = "Connector dead-letter backlog",
                summary = "Connector deliveries entered dead-letter state and require operator triage.",
                count = connectorDeadLetterCases,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }
        val connectorUnavailableCases = cases.count { case ->
            (case.connectorRoutingSummary?.unavailableTargets ?: 0) > 0 ||
                (case.connectorHealthSummary?.unavailableTargets ?: 0) > 0
        }
        if (connectorUnavailableCases > 0) {
            addAlert(
                code = "GOVERNANCE_ALERT_CONNECTOR_UNAVAILABLE",
                severity = GovernanceAlertSeverity.WARNING,
                title = "Connector destination unavailable",
                summary = "Connector targets are unavailable and runs are relying on local fallback.",
                count = connectorUnavailableCases,
                relatedQueue = GovernanceQueueType.PROVIDER_ISSUE
            )
        }

        val policyFrictionCount = cases.count { case ->
            case.summary.reasonFamilies.contains(GovernanceReasonFamily.POLICY_APPROVAL) &&
                case.approvalSummary.contains("denied", ignoreCase = true)
        }
        if (policyFrictionCount >= 2) {
            addAlert(
                code = "GOVERNANCE_ALERT_POLICY_FRICTION_CLUSTER",
                severity = GovernanceAlertSeverity.INFO,
                title = "Policy friction cluster",
                summary = "Approval policy denials are clustered across current unresolved runs.",
                count = policyFrictionCount,
                relatedQueue = GovernanceQueueType.NEEDS_ATTENTION
            )
        }

        return alerts
            .distinctBy { it.code }
            .sortedByDescending { it.severity.ordinal }
    }

    private fun metric(
        key: GovernanceMetricKey,
        numerator: Int,
        denominator: Int,
        dimension: String? = null,
        value: String? = null
    ): GovernanceMetricValue {
        val safeNumerator = numerator.coerceAtLeast(0)
        val safeDenominator = denominator.coerceAtLeast(0)
        val rate = if (safeDenominator <= 0) 0.0 else safeNumerator.toDouble() / safeDenominator.toDouble()
        return GovernanceMetricValue(
            key = key,
            numerator = safeNumerator,
            denominator = safeDenominator,
            rate = rate,
            dimension = dimension,
            value = value
        )
    }

    private fun bucketSummary(bucket: String, signals: List<GovernanceSignal>): GovernanceBucketSummary {
        return GovernanceBucketSummary(
            bucket = bucket,
            runCount = signals.size,
            approvalRequiredCount = signals.count { it.approvalRequired },
            approvalDeniedCount = signals.count { it.approvalDenied },
            externalAttemptCount = signals.count { it.externalAttempt },
            providerSelectedCount = signals.count { it.providerSelected },
            providerDeniedCount = signals.count { it.providerDenied },
            dataScopeBlockedCount = signals.count { it.dataScopeBlocked },
            verificationFailedCount = signals.count { it.verificationFailed },
            rollbackTriggeredCount = signals.count { it.rollbackTriggered },
            disputeOpenedCount = signals.count { it.disputeOpened },
            settlementSyncPendingCount = signals.count { it.settlementSyncPending },
            reconciliationMismatchCount = signals.count { it.reconciliationMismatch },
            duplicateCallbackIgnoredCount = signals.count { it.duplicateCallbackIgnored },
            rollbackFailureCount = signals.count { it.rollbackFailed },
            unresolvedDisputeCount = signals.count { it.unresolvedDispute }
        )
    }

    private fun aggregateByProvider(signals: List<GovernanceSignal>): List<GovernanceBucketSummary> {
        val grouped = mutableMapOf<String, MutableList<GovernanceSignal>>()
        signals.forEach { signal ->
            signal.providerIds.forEach { providerId ->
                grouped.getOrPut(providerId) { mutableListOf() }.add(signal)
            }
        }
        return grouped
            .map { (bucket, items) -> bucketSummary(bucket, items) }
            .sortedByDescending { it.runCount }
    }

    private fun aggregateByReasonFamily(signals: List<GovernanceSignal>): List<GovernanceBucketSummary> {
        val grouped = mutableMapOf<String, MutableList<GovernanceSignal>>()
        signals.forEach { signal ->
            signal.reasonFamilies.forEach { family ->
                grouped.getOrPut(family.name.lowercase()) { mutableListOf() }.add(signal)
            }
        }
        return grouped
            .map { (bucket, items) -> bucketSummary(bucket, items) }
            .sortedByDescending { it.runCount }
    }

    private fun toGovernanceSignal(record: ExecutionReceiptRecord): GovernanceSignal {
        val receipt = record.receipt
        val reasonCodes = collectReasonCodes(record)
        val approvalState = approvalStateFor(record)
        val verificationState = verificationStateFor(record)
        val role = record.activeRole ?: record.policySnapshot?.activeRole ?: receipt?.activeRole
        val roleSource = record.roleSource ?: record.policySnapshot?.roleSource ?: receipt?.roleSource
        val providerIds = buildSet {
            receipt?.selectedProviderId
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it.lowercase()) }
            receipt?.providerSelectionSummary?.selectedProviderId
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it.lowercase()) }
            record.settlementRecord?.selectedProviderId
                ?.takeIf { it.isNotBlank() }
                ?.let { add(it.lowercase()) }
            record.providerDecisions.forEach { decision ->
                if (decision.providerId.isNotBlank()) add(decision.providerId.lowercase())
                if (decision.providerName.isNotBlank()) add(decision.providerName.lowercase())
            }
            record.syncIssues.forEach { issue ->
                issue.providerId
                    ?.takeIf { it.isNotBlank() }
                    ?.let { add(it.lowercase()) }
            }
        }
        val dataSummary = receipt?.externalDataScopeSummary
        val dataScopeBlocked = dataSummary?.blocked == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_BLOCKED)
        val dataScopeReduced = dataSummary?.reduced == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_DATA_SCOPE_REDUCED) ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DATA_SCOPE_REDUCED)
        val dataScopeRedacted = dataSummary?.redactedFields?.isNotEmpty() == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_FIELD_REDACTED)
        val dataScopeFull = !dataScopeBlocked && !dataScopeReduced && !dataScopeRedacted
        val selectedProvider = receipt?.providerSelectionSummary?.selectedProviderId
            ?.takeIf { it.isNotBlank() }
            ?: receipt?.selectedProviderId
        val providerSelected = selectedProvider != null ||
            record.providerDecisions.any { it.decision == ProviderDecisionStatus.SELECTED }
        val providerDenied = record.providerDecisions.any { it.decision == ProviderDecisionStatus.DENIED } ||
            record.runEvents.any { it.type == ProofLedgerEventType.PROVIDER_DENIED }
        val quoteSelectionDivergence = reasonCodes.contains(RoleReasonCodes.ROLE_QUOTE_POLICY_FIT_APPLIED)
        val quoteCompared = receipt?.quoteSummary
            ?.takeIf { it.isNotBlank() }
            ?.startsWith("No external quote comparison", ignoreCase = true)
            ?.not() == true
        val externalAttempt = quoteCompared ||
            providerSelected ||
            providerDenied ||
            providerIds.isNotEmpty() ||
            record.runEvents.any {
                it.type == ProofLedgerEventType.QUOTE_COLLECTED ||
                    it.type == ProofLedgerEventType.PROVIDER_SELECTED ||
                    it.type == ProofLedgerEventType.PROVIDER_DENIED
            }
        val approvalRequired = receipt?.externalApprovalSummary?.required == true || approvalState == "required"
        val approvalDenied = receipt?.externalApprovalSummary?.denied == true || approvalState == "denied"
        val autoRun = !approvalRequired && !approvalDenied
        val proofRequired = record.verificationRecord?.proofRequired == true || receipt?.externalProofSummary?.required == true
        val proofProvided = record.verificationRecord?.proofProvided == true ||
            receipt?.externalProofSummary?.provided == true ||
            receipt?.proofLinks?.isNotEmpty() == true
        val proofMissing = proofRequired && !proofProvided
        val verificationPassed = record.verificationRecord?.passed == true || verificationState == "passed"
        val verificationFailed = record.verificationRecord?.status?.equals("failed", ignoreCase = true) == true ||
            verificationState == "failed"
        val rollbackAvailable = record.rollbackRecord?.available == true || receipt?.externalRollbackSummary?.available == true
        val rollbackTriggered = record.rollbackRecord?.triggered == true || receipt?.externalRollbackSummary?.triggered == true
        val rollbackFailed = record.rollbackAttempts.any { it.outcome == RollbackOutcome.FAILED } ||
            record.rollbackRecord?.summary?.contains("failed", ignoreCase = true) == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_ROLLBACK_FAILED)
        val disputeOpened = record.disputeRecord?.opened == true ||
            receipt?.externalDisputeSummary?.opened == true ||
            record.status == ResponseStatus.DISPUTED
        val disputeStatus = disputeStatusFor(record)
        val settlementSyncState = syncStateFor(record)
        val settlementSyncPending = settlementSyncState == SettlementSyncState.SYNC_PENDING
        val reconciliationMismatch = settlementSyncState == SettlementSyncState.MISMATCH ||
            record.reconciliationSummary?.mismatchDetected == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_RECONCILIATION_MISMATCH)
        val duplicateCallbackIgnored = record.settlementRecord?.attempts?.any { it.duplicateIgnored } == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_DUPLICATE_CALLBACK_IGNORED)
        val disputeAckDelayed = disputeStatus == DisputeStatus.SYNC_PENDING &&
            record.disputeRecord?.syncState.equals("sync_pending", ignoreCase = true)
        val disputeResolved = disputeStatus == DisputeStatus.RESOLVED || disputeStatus == DisputeStatus.CLOSED
        val unresolvedDispute = disputeStatus == DisputeStatus.OPENED ||
            disputeStatus == DisputeStatus.SYNC_PENDING ||
            disputeStatus == DisputeStatus.ACKNOWLEDGED ||
            disputeStatus == DisputeStatus.UNDER_REVIEW
        val providerAckTimeout = record.settlementRecord?.providerAcks?.any { it.status == ProviderAckStatus.TIMEOUT } == true ||
            reasonCodes.contains(RoleReasonCodes.ROLE_EXTERNAL_PROVIDER_ACK_TIMEOUT)
        val explicitConstraintPrecedence = receipt?.constraintPrecedenceSummary
            ?.contains("overrode role defaults", ignoreCase = true) == true
        val policyOverrideApplied = reasonCodes.contains(RoleReasonCodes.ROLE_POLICY_USER_OVERRIDE_APPLIED) ||
            record.runEvents.any { it.type == ProofLedgerEventType.ROLE_POLICY_OVERRIDE_APPLIED }
        val reasonFamilies = collectReasonFamilies(record, reasonCodes)
        val policySnapshotVersion = record.policySnapshot?.policyVersion
            ?: record.snapshotBinding?.snapshotVersion
            ?: receipt?.policySnapshotVersion
        val snapshotBound = record.snapshotBinding != null || !receipt?.policySnapshotId.isNullOrBlank()
        val receiptTraceable = receipt != null
        return GovernanceSignal(
            role = role,
            roleSource = roleSource,
            providerIds = providerIds,
            policySnapshotVersion = policySnapshotVersion,
            outcomeStatus = record.status,
            reasonFamilies = reasonFamilies,
            approvalRequired = approvalRequired,
            approvalDenied = approvalDenied,
            autoRun = autoRun,
            policyOverrideApplied = policyOverrideApplied,
            explicitConstraintPrecedence = explicitConstraintPrecedence,
            externalAttempt = externalAttempt,
            providerSelected = providerSelected,
            providerDenied = providerDenied,
            quoteSelectionDivergence = quoteSelectionDivergence,
            dataScopeFull = dataScopeFull,
            dataScopeReduced = dataScopeReduced,
            dataScopeRedacted = dataScopeRedacted,
            dataScopeBlocked = dataScopeBlocked,
            cloudSyncBlocked = reasonCodes.contains(RoleReasonCodes.ROLE_CLOUD_SYNC_BLOCKED),
            verificationPassed = verificationPassed,
            verificationFailed = verificationFailed,
            proofMissing = proofMissing,
            rollbackAvailable = rollbackAvailable,
            rollbackTriggered = rollbackTriggered,
            disputeOpened = disputeOpened,
            settlementSyncPending = settlementSyncPending,
            reconciliationMismatch = reconciliationMismatch,
            duplicateCallbackIgnored = duplicateCallbackIgnored,
            rollbackFailed = rollbackFailed,
            disputeAckDelayed = disputeAckDelayed,
            disputeResolved = disputeResolved,
            unresolvedDispute = unresolvedDispute,
            providerAckTimeout = providerAckTimeout,
            receiptTraceable = receiptTraceable,
            snapshotBound = snapshotBound
        )
    }

    private fun recordTimestampMs(record: ExecutionReceiptRecord): Long {
        return when {
            record.updatedAtMs > 0L -> record.updatedAtMs
            record.createdAtMs > 0L -> record.createdAtMs
            else -> 0L
        }
    }

    private fun collectReasonCodes(record: ExecutionReceiptRecord): Set<String> {
        val output = mutableSetOf<String>()
        record.receipt?.roleImpactReasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.remoteOperatorHandoffSummary?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.alertRoutingSummary?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.connectorRoutingSummary?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.connectorRoutingSummary?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.providerSelectionSummary?.decisionReasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.idpSessionExchange?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.idpProviderHealth?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.scimProviderResult?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.scimProviderResult?.health?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.vaultMaterialization?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.vaultProviderHealth?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.receipt?.vaultCredentialHealthCheck?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.providerDecisions.flatMap { it.reasonCodes }
            .mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.verificationRecord?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.settlementRecord?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.settlementRecord?.reconciliation?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.rollbackRecord?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.rollbackAttempts.flatMap { it.reasonCodes }
            .mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.disputeRecord?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.disputeCaseRecord?.reasonCodes
            ?.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.syncIssues.flatMap { it.reasonCodes }
            .mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.runEvents.flatMap { it.reasonCodes }
            .mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.alertRoutingRecords.flatMap { routing ->
            routing.idpSessionExchange?.reasonCodes.orEmpty() +
                routing.idpProviderHealth?.reasonCodes.orEmpty() +
                routing.scimProviderResult?.reasonCodes.orEmpty() +
                routing.scimProviderResult?.health?.reasonCodes.orEmpty() +
                routing.vaultProviderHealth?.reasonCodes.orEmpty() +
                routing.vaultMaterializationResults.flatMap { it.reasonCodes } +
                routing.vaultCredentialHealthChecks.flatMap { it.reasonCodes } +
                routing.attempts.flatMap { attempt ->
                    attempt.idpSessionExchange?.reasonCodes.orEmpty() +
                        attempt.scimProviderResult?.reasonCodes.orEmpty() +
                        attempt.vaultMaterialization?.reasonCodes.orEmpty()
                }
        }.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.alertRoutingRecords.flatMap { routing ->
            routing.attempts.mapNotNull { attempt ->
                when (attempt.status) {
                    AlertRoutingStatus.DELIVERED -> RoleReasonCodes.ROLE_ALERT_ROUTING_DELIVERED
                    AlertRoutingStatus.FAILED -> RoleReasonCodes.ROLE_ALERT_ROUTING_FAILED
                    AlertRoutingStatus.QUEUED,
                    AlertRoutingStatus.LOCAL_ONLY,
                    AlertRoutingStatus.DUPLICATE_SUPPRESSED -> RoleReasonCodes.ROLE_ALERT_ROUTING_QUEUED
                }
            }
        }.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        record.alertRoutingRecords.flatMap { routing ->
            routing.deliveryRecords.mapNotNull { delivery ->
                when (delivery.status) {
                    ConnectorDeliveryStatus.ACKNOWLEDGED,
                    ConnectorDeliveryStatus.DELIVERED -> RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_ACKNOWLEDGED
                    ConnectorDeliveryStatus.FAILED -> RoleReasonCodes.ROLE_CONNECTOR_ROUTE_FAILED
                    ConnectorDeliveryStatus.DEAD_LETTER -> RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
                    ConnectorDeliveryStatus.LOCAL_ONLY -> RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_UNAVAILABLE
                    ConnectorDeliveryStatus.QUEUED,
                    ConnectorDeliveryStatus.REQUESTED,
                    ConnectorDeliveryStatus.ACK_PENDING,
                    ConnectorDeliveryStatus.DUPLICATE_SUPPRESSED -> RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_RETRIED
                }
            }
        }.mapNotNullTo(output) { code -> code.takeIf { it.isNotBlank() } }
        if (record.alertRoutingRecords.any { it.deadLetterRecords.isNotEmpty() }) {
            output += RoleReasonCodes.ROLE_CONNECTOR_DELIVERY_DEAD_LETTERED
            output += RoleReasonCodes.ROLE_CONNECTOR_HEALTH_DEGRADED
        }
        return output
    }

    private fun collectReasonFamilies(
        record: ExecutionReceiptRecord,
        reasonCodes: Set<String>
    ): Set<GovernanceReasonFamily> {
        val families = mutableSetOf<GovernanceReasonFamily>()
        reasonCodes.mapTo(families) { reasonFamilyForCode(it) }
        record.runEvents.mapNotNullTo(families) { reasonFamilyForEventType(it.type) }
        if (record.settlementRecord != null || record.reconciliationSummary != null) {
            families += GovernanceReasonFamily.SETTLEMENT_RECONCILIATION
        }
        if (record.snapshotBinding != null || record.policySnapshot != null) {
            families += GovernanceReasonFamily.DURABILITY
        }
        families.remove(GovernanceReasonFamily.UNKNOWN)
        if (families.isEmpty()) {
            families += GovernanceReasonFamily.UNKNOWN
        }
        return families
    }

    private fun reasonFamilyForEventType(type: ProofLedgerEventType): GovernanceReasonFamily? {
        return when (type) {
            ProofLedgerEventType.ROLE_SELECTED,
            ProofLedgerEventType.ROLE_SOURCE_RESOLVED -> GovernanceReasonFamily.ROLE_SELECTION
            ProofLedgerEventType.ROLE_POLICY_OVERRIDE_APPLIED,
            ProofLedgerEventType.APPROVAL_REQUESTED,
            ProofLedgerEventType.APPROVAL_GRANTED,
            ProofLedgerEventType.APPROVAL_DENIED,
            ProofLedgerEventType.WORKFLOW_POLICY_APPLIED,
            ProofLedgerEventType.SLA_STATUS_CHANGED,
            ProofLedgerEventType.ESCALATION_TIMER_STATUS_CHANGED,
            ProofLedgerEventType.AUTOMATION_GUARDRAIL_EVALUATED,
            ProofLedgerEventType.AUTOMATION_GUARDRAIL_BLOCKED,
            ProofLedgerEventType.AUTOMATION_GUARDRAIL_THROTTLED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CREATED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_ADVANCED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_WAVE_PAUSED,
            ProofLedgerEventType.WORKFLOW_POLICY_TARGET_EXEMPTED,
            ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNEXEMPTED,
            ProofLedgerEventType.WORKFLOW_POLICY_TARGET_PINNED,
            ProofLedgerEventType.WORKFLOW_POLICY_TARGET_UNPINNED,
            ProofLedgerEventType.WORKFLOW_POLICY_PACK_DEPRECATED,
            ProofLedgerEventType.WORKFLOW_POLICY_PACK_RETIREMENT_STARTED,
            ProofLedgerEventType.WORKFLOW_POLICY_PACK_REPLACEMENT_ATTACHED,
            ProofLedgerEventType.WORKFLOW_POLICY_CROSS_TENANT_ROLLOUT_HELD,
            ProofLedgerEventType.WORKFLOW_POLICY_APPROVAL_OPERATION_QUEUED,
            ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_SNAPSHOT_COMPUTED,
            ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_PLAN_ATTACHED,
            ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_BLOCKER_ACKNOWLEDGED,
            ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_SCHEDULED,
            ProofLedgerEventType.WORKFLOW_POLICY_ESTATE_REMEDIATION_APPLIED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_PRIORITY_APPLIED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_DEFERRED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_DEPENDENCY_BLOCKED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CONFLICT_DETECTED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_CONTENTION_DETECTED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_ESCALATION_OPENED,
            ProofLedgerEventType.WORKFLOW_POLICY_PROGRAM_ESCALATION_RESOLVED ->
                GovernanceReasonFamily.POLICY_APPROVAL
            ProofLedgerEventType.PROVIDER_SELECTED,
            ProofLedgerEventType.PROVIDER_DENIED,
            ProofLedgerEventType.QUOTE_COLLECTED -> GovernanceReasonFamily.PROVIDER_POLICY
            ProofLedgerEventType.DATA_SCOPE_REDUCED,
            ProofLedgerEventType.DATA_SCOPE_BLOCKED -> GovernanceReasonFamily.DATA_SCOPE
            ProofLedgerEventType.PROOF_RECEIVED,
            ProofLedgerEventType.VERIFICATION_PASSED,
            ProofLedgerEventType.VERIFICATION_FAILED -> GovernanceReasonFamily.VERIFICATION_PROOF
            ProofLedgerEventType.SETTLEMENT_STARTED,
            ProofLedgerEventType.SETTLEMENT_COMMITTED,
            ProofLedgerEventType.SETTLEMENT_SYNC_PENDING,
            ProofLedgerEventType.SETTLEMENT_RECONCILED,
            ProofLedgerEventType.PROVIDER_ACK_RECEIVED,
            ProofLedgerEventType.RECONCILIATION_MISMATCH_DETECTED,
            ProofLedgerEventType.RECONCILIATION_RETRY_SCHEDULED -> GovernanceReasonFamily.SETTLEMENT_RECONCILIATION
            ProofLedgerEventType.ROLLBACK_AVAILABLE,
            ProofLedgerEventType.ROLLBACK_REQUESTED,
            ProofLedgerEventType.ROLLBACK_TRIGGERED,
            ProofLedgerEventType.ROLLBACK_FAILED,
            ProofLedgerEventType.DISPUTE_OPENED,
            ProofLedgerEventType.DISPUTE_SYNC_PENDING,
            ProofLedgerEventType.DISPUTE_ACKNOWLEDGED,
            ProofLedgerEventType.DISPUTE_RESOLVED,
            ProofLedgerEventType.DISPUTE_CLOSED -> GovernanceReasonFamily.ROLLBACK_DISPUTE
            ProofLedgerEventType.ROLE_POLICY_SNAPSHOT_BOUND,
            ProofLedgerEventType.DISPUTE_SYNCED,
            ProofLedgerEventType.SYNC_PENDING,
            ProofLedgerEventType.SYNC_RESOLVED,
            ProofLedgerEventType.OPERATOR_MARKED_REVIEWED,
            ProofLedgerEventType.OPERATOR_SYNC_RETRY_REQUESTED,
            ProofLedgerEventType.OPERATOR_CASE_CLAIMED,
            ProofLedgerEventType.OPERATOR_CASE_UNCLAIMED,
            ProofLedgerEventType.OPERATOR_CASE_RELEASED,
            ProofLedgerEventType.OPERATOR_CASE_ASSIGNED,
            ProofLedgerEventType.OPERATOR_CASE_REASSIGNED,
            ProofLedgerEventType.OPERATOR_CASE_ESCALATED,
            ProofLedgerEventType.OPERATOR_NOTE_ADDED,
            ProofLedgerEventType.OPERATOR_FOLLOW_UP_REQUESTED,
            ProofLedgerEventType.OPERATOR_PERMISSION_DENIED,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_REQUESTED,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_PENDING,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_ACK_PENDING,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_ACKNOWLEDGED,
            ProofLedgerEventType.REMOTE_OPERATOR_HANDOFF_FAILED,
            ProofLedgerEventType.ALERT_ROUTING_QUEUED,
            ProofLedgerEventType.ALERT_ROUTING_DELIVERED,
            ProofLedgerEventType.ALERT_ROUTING_FAILED,
            ProofLedgerEventType.CONNECTOR_ROUTING_REQUESTED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_ATTEMPTED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_FAILED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_ACKED,
            ProofLedgerEventType.REMOTE_OPERATOR_AUTH_ALLOWED,
            ProofLedgerEventType.REMOTE_OPERATOR_AUTH_DENIED,
            ProofLedgerEventType.CONNECTOR_DESTINATION_SELECTED,
            ProofLedgerEventType.CONNECTOR_DESTINATION_DENIED,
            ProofLedgerEventType.CONNECTOR_AUTH_PROFILE_APPLIED,
            ProofLedgerEventType.CONNECTOR_DELIVERY_DEAD_LETTERED,
            ProofLedgerEventType.CONNECTOR_HEALTH_DEGRADED,
            ProofLedgerEventType.CONNECTOR_HEALTH_RECOVERED,
            ProofLedgerEventType.WORKFLOW_TEMPLATE_ATTACHED,
            ProofLedgerEventType.WORKFLOW_STAGE_CHANGED,
            ProofLedgerEventType.WORKFLOW_NEXT_ACTION_SUGGESTED,
            ProofLedgerEventType.AUTOMATION_RULE_TRIGGERED,
            ProofLedgerEventType.AUTOMATION_ACTION_EXECUTED,
            ProofLedgerEventType.AUTOMATION_ACTION_SKIPPED -> GovernanceReasonFamily.DURABILITY
            else -> null
        }
    }

    private fun reasonFamilyForCode(code: String): GovernanceReasonFamily {
        val normalized = code.trim().uppercase()
        return when {
            normalized.startsWith("ROLE_EXPLICIT_") ||
                normalized.startsWith("ROLE_PROFILE_") ||
                normalized.startsWith("ROLE_TASK_") ||
                normalized.startsWith("ROLE_SAFE_") ||
                normalized.startsWith("ROLE_SYSTEM_FALLBACK_") ||
                normalized.startsWith("ROLE_CHANGED_") -> GovernanceReasonFamily.ROLE_SELECTION
            normalized.contains("APPROVAL") ||
                normalized.contains("WORKFLOW_POLICY") ||
                normalized.contains("SLA_") ||
                normalized.contains("ESCALATION_") ||
                normalized.contains("AUTOMATION_") ||
                normalized.startsWith("ROLE_POLICY_") -> GovernanceReasonFamily.POLICY_APPROVAL
            normalized.contains("ROUTE") ||
                normalized.contains("RANKING") -> GovernanceReasonFamily.ROUTING_RANKING
            normalized.contains("PROVIDER") ||
                normalized.contains("QUOTE") -> GovernanceReasonFamily.PROVIDER_POLICY
            normalized.contains("DATA_SCOPE") ||
                normalized.contains("FIELD_REDACTED") ||
                normalized.contains("CLOUD_SYNC_BLOCKED") -> GovernanceReasonFamily.DATA_SCOPE
            normalized.contains("PROOF") ||
                normalized.contains("VERIFICATION") -> GovernanceReasonFamily.VERIFICATION_PROOF
            normalized.contains("ROLLBACK") ||
                normalized.contains("DISPUTE") -> GovernanceReasonFamily.ROLLBACK_DISPUTE
            normalized.contains("SETTLEMENT") ||
                normalized.contains("RECONCILIATION") ||
                normalized.contains("ACK_TIMEOUT") ||
                normalized.contains("DUPLICATE_CALLBACK") -> GovernanceReasonFamily.SETTLEMENT_RECONCILIATION
            normalized.contains("GOVERNANCE_CAPACITY") ||
                normalized.contains("GOVERNANCE_APPROVAL_QUEUE") ||
                normalized.contains("GOVERNANCE_APPROVAL_LOAD") ||
                normalized.contains("GOVERNANCE_PORTFOLIO") ||
                normalized.contains("PORTFOLIO_SIMULATION") ||
                normalized.contains("CRITICAL_PROGRAM_RESERVED") -> GovernanceReasonFamily.POLICY_APPROVAL
            normalized.contains("SNAPSHOT") ||
                normalized.contains("TRACEABILITY") ||
                normalized.contains("RESTORE") ||
            normalized.contains("TELEMETRY") ||
            normalized.contains("ALERT_DELIVERY") ||
            normalized.contains("ALERT_ROUTING") ||
            normalized.contains("REMOTE_HANDOFF") ||
            normalized.contains("REMOTE_PIPELINE") ||
            normalized.contains("ROLLOUT") ||
            normalized.contains("CUTOVER") ||
            normalized.contains("SSO") ||
            normalized.contains("IDP") ||
            normalized.contains("SCIM") ||
            normalized.contains("DIRECTORY_SYNC") ||
            normalized.contains("VAULT") ||
                normalized.contains("CREDENTIAL") ||
                normalized.contains("OPERATOR") -> GovernanceReasonFamily.DURABILITY
            else -> GovernanceReasonFamily.UNKNOWN
        }
    }

    private fun providerMatches(record: ExecutionReceiptRecord, providerId: String): Boolean {
        val normalized = providerId.lowercase()
        val selectedProviderMatches = record.receipt?.selectedProviderId
            ?.lowercase()
            ?.contains(normalized) == true
        val settlementProviderMatches = record.settlementRecord?.selectedProviderId
            ?.lowercase()
            ?.contains(normalized) == true
        val decisionMatches = record.providerDecisions.any { decision ->
            decision.providerId.lowercase().contains(normalized) ||
                decision.providerName.lowercase().contains(normalized)
        }
        val syncIssueMatches = record.syncIssues.any { issue ->
            issue.providerId?.lowercase()?.contains(normalized) == true
        }
        return selectedProviderMatches || settlementProviderMatches || decisionMatches || syncIssueMatches
    }

    private fun approvalStateFor(record: ExecutionReceiptRecord): String {
        val typedStatus = record.receipt?.externalApprovalSummary?.status
            ?.lowercase()
            ?.takeIf { it.isNotBlank() }
        if (typedStatus != null) return typedStatus
        val summary = record.receipt?.approvalSummary.orEmpty().lowercase()
        return when {
            summary.contains("denied") -> "denied"
            summary.contains("required") -> "required"
            summary.contains("satisfied") || summary.contains("granted") -> "granted"
            else -> "not_required"
        }
    }

    private fun verificationStateFor(record: ExecutionReceiptRecord): String {
        val typedStatus = record.verificationRecord?.status
            ?.lowercase()
            ?.takeIf { it.isNotBlank() }
        if (typedStatus != null) return typedStatus
        val summary = record.receipt?.verificationSummary.orEmpty().lowercase()
        return when {
            summary.contains("failed") -> "failed"
            summary.contains("partial") -> "partial"
            summary.contains("pending") -> "pending"
            summary.contains("passed") -> "passed"
            else -> "not_required"
        }
    }

    private fun disputeOrRollbackStateFor(record: ExecutionReceiptRecord): String {
        return when {
            record.rollbackRecord?.triggered == true || record.status == ResponseStatus.ROLLED_BACK -> "rolled_back"
            record.disputeRecord?.opened == true || record.status == ResponseStatus.DISPUTED -> "disputed"
            record.rollbackRecord?.available == true -> "rollback_available"
            else -> "none"
        }
    }

    private fun settlementStatusFor(record: ExecutionReceiptRecord): SettlementStatus {
        return record.settlementRecord?.status
            ?: record.receipt?.externalSettlementSummary?.status
            ?: when {
                record.status == ResponseStatus.ROLLED_BACK -> SettlementStatus.ROLLED_BACK
                record.status == ResponseStatus.DISPUTED -> SettlementStatus.DISPUTED
                record.status == ResponseStatus.COMMITTED ||
                    record.status == ResponseStatus.SUCCESS ||
                    record.status == ResponseStatus.PARTIAL -> SettlementStatus.COMMITTED
                else -> SettlementStatus.NOT_REQUIRED
            }
    }

    private fun disputeStatusFor(record: ExecutionReceiptRecord): DisputeStatus {
        record.disputeCaseRecord?.status?.let { return it }
        if (record.disputeRecord?.opened != true && record.status != ResponseStatus.DISPUTED) {
            return DisputeStatus.NOT_OPEN
        }
        val summary = record.disputeRecord?.summary.orEmpty().lowercase()
        return when {
            summary.contains("closed") -> DisputeStatus.CLOSED
            summary.contains("resolved") -> DisputeStatus.RESOLVED
            summary.contains("under review") -> DisputeStatus.UNDER_REVIEW
            summary.contains("acknowledged") -> DisputeStatus.ACKNOWLEDGED
            summary.contains("sync pending") -> DisputeStatus.SYNC_PENDING
            else -> DisputeStatus.OPENED
        }
    }

    private fun syncStateFor(record: ExecutionReceiptRecord): SettlementSyncState {
        return record.settlementRecord?.syncState
            ?: record.reconciliationSummary?.syncState
            ?: when {
                record.disputeRecord?.syncState.equals("sync_pending", ignoreCase = true) -> SettlementSyncState.SYNC_PENDING
                record.disputeRecord?.syncState.equals("sync_resolved", ignoreCase = true) -> SettlementSyncState.RECONCILED
                else -> SettlementSyncState.NOT_REQUIRED
            }
    }

    private fun hasUnresolvedSettlementOrDispute(record: ExecutionReceiptRecord): Boolean {
        val syncState = syncStateFor(record)
        val disputeStatus = disputeStatusFor(record)
        val unresolvedRunState = record.status == ResponseStatus.WAITING_USER ||
            record.status == ResponseStatus.AUTH_REQUIRED ||
            record.status == ResponseStatus.QUOTING ||
            record.status == ResponseStatus.VERIFYING ||
            record.status == ResponseStatus.RUNNING ||
            record.status == ResponseStatus.PROCESSING
        val rollbackFailed = record.rollbackAttempts.any { it.outcome == RollbackOutcome.FAILED } ||
            record.rollbackRecord?.summary?.contains("failed", ignoreCase = true) == true
        return unresolvedRunState ||
            syncState == SettlementSyncState.SYNC_PENDING ||
            syncState == SettlementSyncState.MISMATCH ||
            disputeStatus == DisputeStatus.OPENED ||
            disputeStatus == DisputeStatus.SYNC_PENDING ||
            disputeStatus == DisputeStatus.ACKNOWLEDGED ||
            disputeStatus == DisputeStatus.UNDER_REVIEW ||
            rollbackFailed
    }

    private fun isSyncPendingRecord(record: ExecutionReceiptRecord): Boolean {
        val syncState = syncStateFor(record)
        return syncState == SettlementSyncState.SYNC_PENDING ||
            record.disputeRecord?.syncState.equals("sync_pending", ignoreCase = true)
    }

    private fun hasProviderIssue(record: ExecutionReceiptRecord): Boolean {
        val connectorIssue = (record.connectorRoutingSummary?.status == AlertRoutingStatus.FAILED) ||
            (record.connectorHealthSummary?.deadLetterTargets ?: 0) > 0 ||
            (record.connectorHealthSummary?.unavailableTargets ?: 0) > 0 ||
            record.alertRoutingRecords.any { routing ->
                routing.status == AlertRoutingStatus.FAILED ||
                    routing.deadLetterRecords.isNotEmpty() ||
                    routing.deliveryRecords.any { delivery ->
                        delivery.status == ConnectorDeliveryStatus.FAILED ||
                            delivery.status == ConnectorDeliveryStatus.DEAD_LETTER ||
                            delivery.status == ConnectorDeliveryStatus.LOCAL_ONLY ||
                            delivery.lastFailureReason == ConnectorFailureReason.DESTINATION_UNAVAILABLE
                    }
            }
        return connectorIssue ||
            record.providerDecisions.any { it.decision == ProviderDecisionStatus.DENIED } ||
            record.syncIssues.any { issue ->
                !issue.providerId.isNullOrBlank() ||
                    issue.issueType.contains("provider", ignoreCase = true)
            } ||
            record.settlementRecord?.providerAcks?.any { it.status == ProviderAckStatus.TIMEOUT || it.status == ProviderAckStatus.CONFLICT } == true
    }

    private fun policySnapshotMatches(record: ExecutionReceiptRecord, snapshotId: String): Boolean {
        val normalized = snapshotId.lowercase()
        return record.policySnapshot?.snapshotId?.lowercase() == normalized ||
            record.snapshotBinding?.snapshotId?.lowercase() == normalized
    }

    private fun editableRolePolicyFields(role: UserRole): EditableRolePolicyFields {
        return when (role) {
            UserRole.PARENT -> EditableRolePolicyFields(
                cloudSyncAllowance = false
            )
            else -> EditableRolePolicyFields()
        }
    }

    private fun protectedRolePolicyFields(role: UserRole): ProtectedRolePolicyFields {
        val items = mutableListOf(
            ProtectedRolePolicyField(
                key = "requiresExplicitConfirmationForHighRisk",
                reason = "High-risk execution always requires explicit confirmation."
            )
        )
        if (role == UserRole.PARENT) {
            items += ProtectedRolePolicyField(
                key = "cloudSyncAllowed",
                reason = "Parent role keeps cloud sync blocked by default safety policy."
            )
            items += ProtectedRolePolicyField(
                key = "sharingMode",
                reason = "Parent role data sharing mode is protected as local-only."
            )
        }
        return ProtectedRolePolicyFields(items = items)
    }

    private fun applyRolePolicyDraft(
        base: RolePolicyProfile,
        role: UserRole,
        draft: RolePolicyDraft
    ): RolePolicyProfile {
        val resolvedDelegation = draft.delegationMode ?: base.delegationPolicy.mode
        val resolvedRisk = draft.riskToleranceDefault?.let(::normalizeRiskTolerance)
            ?: normalizeRiskTolerance(base.preferences.riskToleranceDefault)
        val resolvedCost = draft.maxCostPerStepDefault?.let(::normalizeCostTier)
            ?: normalizeCostTier(base.preferences.maxCostPerStepDefault)
        val resolvedSharingMode = draft.sharingMode
            ?.trim()
            ?.lowercase()
            ?.replace(' ', '_')
            ?.ifBlank { null }
            ?: base.dataPolicy.sharingMode
        val resolvedScopes = draft.allowedScopes
            ?.asSequence()
            ?.map { it.trim().lowercase().replace(' ', '_') }
            ?.filter { it.isNotBlank() }
            ?.distinct()
            ?.toList()
            ?: base.dataPolicy.allowedScopes
        val resolvedTrustedTags = draft.trustedProviderTags?.let(::normalizedTags)
            ?: base.preferences.trustedProviderTags
        val resolvedBlockedTags = draft.blockedProviderTags?.let(::normalizedTags)
            ?: base.preferences.blockedProviderTags
        val externalFulfillmentAllowed = draft.externalFulfillmentAllowed
            ?: base.preferences.externalFulfillmentAllowed
        val externalFulfillmentPreference = draft.externalFulfillmentPreference
            ?: base.preferences.externalFulfillmentPreference
        return base.copy(
            role = role,
            preferences = base.preferences.copy(
                riskToleranceDefault = resolvedRisk,
                maxCostPerStepDefault = resolvedCost,
                trustedProviderTags = resolvedTrustedTags,
                blockedProviderTags = resolvedBlockedTags,
                externalFulfillmentAllowed = externalFulfillmentAllowed,
                externalFulfillmentPreference = externalFulfillmentPreference
            ),
            approvalPolicy = base.approvalPolicy.copy(
                delegationMode = resolvedDelegation,
                requiresExplicitConfirmationForHighRisk = draft.requiresExplicitConfirmationForHighRisk
                    ?: base.approvalPolicy.requiresExplicitConfirmationForHighRisk,
                requiresConfirmationTokenForExternalSpend = draft.requiresConfirmationTokenForExternalSpend
                    ?: base.approvalPolicy.requiresConfirmationTokenForExternalSpend,
                autoApprovalBudgetLimit = draft.autoApprovalBudgetLimit
                    ?: base.approvalPolicy.autoApprovalBudgetLimit,
                maxExternalBudget = draft.maxExternalBudget
                    ?: base.approvalPolicy.maxExternalBudget
            ),
            dataPolicy = base.dataPolicy.copy(
                sharingMode = resolvedSharingMode,
                allowedScopes = resolvedScopes,
                cloudSyncAllowed = draft.cloudSyncAllowed ?: base.dataPolicy.cloudSyncAllowed
            ),
            delegationPolicy = base.delegationPolicy.copy(mode = resolvedDelegation)
        )
    }

    private fun validateRolePolicyDraft(
        role: UserRole,
        candidate: RolePolicyProfile,
        draft: RolePolicyDraft
    ): RolePolicyValidationResult {
        val issues = mutableListOf<RolePolicyValidationIssue>()
        val maxBudget = candidate.approvalPolicy.maxExternalBudget
        val autoBudget = candidate.approvalPolicy.autoApprovalBudgetLimit
        val sharingMode = candidate.dataPolicy.sharingMode.lowercase()
        val risk = candidate.preferences.riskToleranceDefault.orEmpty().lowercase()
        val cost = candidate.preferences.maxCostPerStepDefault.orEmpty().lowercase()
        val trusted = candidate.preferences.trustedProviderTags.toSet()
        val blocked = candidate.preferences.blockedProviderTags.toSet()
        if (draft.requiresExplicitConfirmationForHighRisk == false ||
            !candidate.approvalPolicy.requiresExplicitConfirmationForHighRisk
        ) {
            issues += RolePolicyValidationIssue(
                field = "requiresExplicitConfirmationForHighRisk",
                message = "High-risk confirmation is protected and cannot be disabled.",
                blocking = true
            )
        }
        if (maxBudget != null && maxBudget <= 0.0) {
            issues += RolePolicyValidationIssue(
                field = "maxExternalBudget",
                message = "Max external budget must be a positive number.",
                blocking = true
            )
        }
        if (autoBudget != null && autoBudget < 0.0) {
            issues += RolePolicyValidationIssue(
                field = "autoApprovalBudgetLimit",
                message = "Auto-approval budget cannot be negative.",
                blocking = true
            )
        }
        if (maxBudget != null && autoBudget != null && autoBudget > maxBudget) {
            issues += RolePolicyValidationIssue(
                field = "autoApprovalBudgetLimit",
                message = "Auto-approval budget cannot exceed max external budget.",
                blocking = true
            )
        }
        if (candidate.approvalPolicy.delegationMode == DelegationMode.MANUAL &&
            autoBudget != null &&
            autoBudget > 0.0
        ) {
            issues += RolePolicyValidationIssue(
                field = "delegationMode",
                message = "Manual delegation cannot keep auto-approval budget above zero.",
                blocking = true
            )
        }
        if (candidate.dataPolicy.allowedScopes.isEmpty()) {
            issues += RolePolicyValidationIssue(
                field = "allowedScopes",
                message = "At least one provider-facing data scope must be selected.",
                blocking = true
            )
        }
        if (sharingMode.contains("local_only") && candidate.dataPolicy.cloudSyncAllowed) {
            issues += RolePolicyValidationIssue(
                field = "cloudSyncAllowed",
                message = "Local-only sharing mode cannot enable cloud sync.",
                blocking = true
            )
        }
        if (risk.isNotBlank() && risk !in setOf("low", "medium", "high")) {
            issues += RolePolicyValidationIssue(
                field = "riskToleranceDefault",
                message = "Risk tolerance must be low, medium, or high.",
                blocking = true
            )
        }
        if (cost.isNotBlank() && cost !in setOf("low", "mid", "high")) {
            issues += RolePolicyValidationIssue(
                field = "maxCostPerStepDefault",
                message = "Max cost per step must be low, mid, or high.",
                blocking = true
            )
        }
        val overlap = trusted.intersect(blocked)
        if (overlap.isNotEmpty()) {
            issues += RolePolicyValidationIssue(
                field = "providerTags",
                message = "Trusted and blocked provider tags cannot overlap: ${overlap.joinToString(", ")}.",
                blocking = true
            )
        }
        if (!candidate.preferences.externalFulfillmentAllowed &&
            candidate.preferences.externalFulfillmentPreference == ExternalFulfillmentPreference.EXTERNAL_PREFERRED
        ) {
            issues += RolePolicyValidationIssue(
                field = "externalFulfillmentPreference",
                message = "External preference cannot be external-preferred when external fulfillment is disabled.",
                blocking = true
            )
        }
        if (role == UserRole.PARENT) {
            val requestedSharingMode = draft.sharingMode
            if (draft.cloudSyncAllowed == true || candidate.dataPolicy.cloudSyncAllowed) {
                issues += RolePolicyValidationIssue(
                    field = "cloudSyncAllowed",
                    message = "Parent role cloud sync is protected and remains disabled.",
                    blocking = true
                )
            }
            if (requestedSharingMode != null && requestedSharingMode.lowercase().replace(' ', '_') != "local_only") {
                issues += RolePolicyValidationIssue(
                    field = "sharingMode",
                    message = "Parent role sharing mode is protected as local_only.",
                    blocking = true
                )
            }
        }
        return RolePolicyValidationResult(
            valid = issues.none { it.blocking },
            issues = issues,
            previewLines = buildRolePolicyPreviewLines(candidate)
        )
    }

    private fun buildRolePolicyPreviewLines(policy: RolePolicyProfile): List<String> {
        val autoBudget = policy.approvalPolicy.autoApprovalBudgetLimit?.let { formatPolicyAmount(it) } ?: "disabled"
        val maxBudget = policy.approvalPolicy.maxExternalBudget?.let { formatPolicyAmount(it) } ?: "not set"
        val providerTrusted = policy.preferences.trustedProviderTags.joinToString(", ").ifBlank { "none" }
        val providerBlocked = policy.preferences.blockedProviderTags.joinToString(", ").ifBlank { "none" }
        val scopes = policy.dataPolicy.allowedScopes.joinToString(", ").ifBlank { "minimal_task_context" }
        val externalMode = when (policy.preferences.externalFulfillmentPreference) {
            ExternalFulfillmentPreference.INTERNAL_FIRST -> "internal-first"
            ExternalFulfillmentPreference.BALANCED -> "balanced"
            ExternalFulfillmentPreference.EXTERNAL_PREFERRED -> "external-preferred"
        }
        return listOf(
            "Delegation default: ${policy.delegationPolicy.mode.name.lowercase().replace('_', ' ')}.",
            "Approval policy: token required for external spend = ${if (policy.approvalPolicy.requiresConfirmationTokenForExternalSpend) "yes" else "no"}; auto-approval budget = $autoBudget; max external budget = $maxBudget.",
            "Data policy: ${policy.dataPolicy.sharingMode} with scopes [$scopes]; cloud sync allowed = ${if (policy.dataPolicy.cloudSyncAllowed) "yes" else "no"}.",
            "Provider policy: trusted tags [$providerTrusted]; blocked tags [$providerBlocked].",
            "External fulfillment: ${if (policy.preferences.externalFulfillmentAllowed) "enabled" else "disabled"}, preference = $externalMode."
        )
    }

    private fun formatPolicyAmount(value: Double): String {
        val rounded = if (value >= 1000) value.toLong().toString() else String.format("%.2f", value)
        return "£$rounded"
    }

    private suspend fun fetchCloudEnhancement(
        module: ModuleId,
        intent: IntentType,
        request: AgentRequest,
        cloudGateway: CloudGateway,
        meta: OrchestrationMeta,
        resolvedRequestConstraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext
    ): CloudEnhancement {
        val problemFrame = buildProblemFrame(
            request = request,
            module = module,
            meta = meta,
            constraints = resolvedRequestConstraints
        )
        val requiredLinkKinds = requiredLinkKindsForDomain(problemFrame)
        val constraints = AgentTaskConstraints(
            timeoutMs = 0,
            preferRealtime = true,
            maxResults = 3,
            contextPacket = request.stateVector ?: dynamicStateByUser[request.userId],
            reasoningMode = "auto",
            cloudModelProvider = "gemini"
        )

        return when (module) {
            ModuleId.CHAT -> {
                val openClawHints = OpenClawCapabilityMapper.mapHints(request.rawText, ModuleId.CHAT)
                val twinProfilePrompt = buildTwinProfilePrompt(request.userId, request.locale)
                val twinAwareQuery = buildTwinAwareTask(
                    rawTask = request.rawText,
                    userId = request.userId,
                    locale = request.locale,
                    constraints = resolvedRequestConstraints
                )
                val userRequestedLixEscalation = isUserRequestingLixEscalation(
                    rawText = request.rawText,
                    module = ModuleId.CHAT
                )
                val pendingEscalation = pendingEscalationForUser(request.userId)
                if (pendingEscalation != null) {
                    if (isEscalationCancelCommand(request.rawText) || isEscalationDeclineCommand(request.rawText)) {
                        pendingLixEscalations.remove(request.userId)
                        return CloudEnhancement(
                            cards = listOf(
                                AgentCard(
                                    id = "lix-escalation-cancelled",
                                    title = "Escalation cancelled",
                                    summary = "Cancelled LIX supplier escalation for this task.",
                                    deeplink = LumiRoutes.CHAT
                                )
                            ),
                            summary = "Escalation cancelled. Continue with direct OpenClaw collaboration if needed.",
                            payload = ModulePayload.ChatPayload(
                                suggestionTitle = "Escalation cancelled",
                                hints = listOf("Cancelled by user", "Ready for a new query"),
                                taskTrack = TaskTrackBuilder.build(
                                    module = ModuleId.CHAT,
                                    query = pendingEscalation.originalQuery,
                                    traceId = pendingEscalation.traceId,
                                    phase = "lix_escalation_cancelled",
                                    status = ResponseStatus.CANCELLED,
                                    evidenceItems = emptyList(),
                                    nowMs = nowMs()
                                )
                            ),
                            status = ResponseStatus.CANCELLED
                        )
                    }

                    val escalationConstraints = resolveRequestConstraints(request)
                        .mergeWith(resolvedRequestConstraints)
                        .withRoleContext(roleContext)
                    val hasEscalationInputs = containsEscalationConstraintKeywords(request.rawText)
                    val consentedForEscalation = userRequestedLixEscalation ||
                        isEscalationConfirmationReply(request.rawText) ||
                        hasEscalationInputs
                    if (!consentedForEscalation) {
                        // Treat this as a new direct-solve request and clear stale pending escalation context.
                        pendingLixEscalations.remove(request.userId)
                    } else {
                    val missingFields = missingRequiredConstraintFields(escalationConstraints)
                    if (missingFields.isNotEmpty()) {
                        return buildBudgetPromptEnhancement(
                            request = request,
                            escalation = pendingEscalation,
                            reasonCode = "constraints_missing_for_lix_escalation",
                            missingFields = missingFields
                        )
                    }
                    if (escalationConstraints.userConfirmationToken.isNullOrBlank()) {
                        return buildBudgetPromptEnhancement(
                            request = request,
                            escalation = pendingEscalation,
                            reasonCode = "confirmation_token_missing_for_spend_action",
                            missingFields = listOf("user_confirmation_token")
                        )
                    }
                    return publishEscalationToLix(
                        request = request,
                        cloudGateway = cloudGateway,
                        escalation = pendingEscalation,
                        requestConstraints = escalationConstraints,
                        openClawHints = openClawHints,
                        roleContext = roleContext
                    )
                    }
                }

                // ── Cloud-first Super Agent path ──
                val execution = cloudGateway.executeAgent(twinAwareQuery, constraints)
                val exec = execution.data
                if (execution.success && exec != null) {
                    val mappedExecutionStatus = mapExecutionStatus(exec.status)
                    val evidence = if (exec.evidenceItems.isNotEmpty()) {
                        exec.evidenceItems
                    } else {
                        exec.evidence.mapIndexed { index, row ->
                            EvidenceItemPayload(
                                source = "super_agent",
                                title = "evidence ${index + 1}",
                                snippet = row
                            )
                        }
                    }
                    val effectiveRoutingDecision = exec.routingDecision ?: meta.routingDecision
                    val effectiveTaskGraph = exec.taskGraph ?: meta.taskGraph
                    val cloudBudgetPrompt = exec.resultSummary.lowercase().let { summary ->
                        summary.contains("provide budget") && summary.contains("lix")
                    }
                    if (cloudBudgetPrompt && userRequestedLixEscalation) {
                        val escalation = LixEscalationContext(
                            userId = request.userId,
                            originalQuery = request.rawText,
                            domain = OpenClawCapabilityMapper.inferDomain(request.rawText),
                            requiredCapabilities = effectiveTaskGraph.tasks
                                .flatMap { it.requiredCapabilities }
                                .ifEmpty { requiredCapabilitiesForIntent(intent) }
                                .distinct()
                                .take(6),
                            reasonCode = "budget_required_from_cloud",
                            traceId = execution.traceId,
                            createdAtMs = nowMs(),
                            twinProfilePrompt = twinProfilePrompt
                        )
                        return continueEscalationOrPrompt(
                            request = request,
                            cloudGateway = cloudGateway,
                            escalation = escalation,
                            reasonCode = "budget_required_from_cloud",
                            openClawHints = openClawHints,
                            resolvedRequestConstraints = resolvedRequestConstraints,
                            roleContext = roleContext
                        )
                    }
                    val escalationReason = detectEscalationReason(
                        request = request,
                        routingDecision = effectiveRoutingDecision,
                        taskGraph = effectiveTaskGraph,
                        execution = exec,
                        evidence = evidence,
                        skillGap = meta.skillGap
                    )
                    if (escalationReason != null && userRequestedLixEscalation) {
                        val escalation = LixEscalationContext(
                            userId = request.userId,
                            originalQuery = request.rawText,
                            domain = OpenClawCapabilityMapper.inferDomain(request.rawText),
                            requiredCapabilities = effectiveTaskGraph.tasks
                                .flatMap { it.requiredCapabilities }
                                .ifEmpty { requiredCapabilitiesForIntent(intent) }
                                .distinct()
                                .take(6),
                            reasonCode = escalationReason,
                            traceId = execution.traceId,
                            createdAtMs = nowMs(),
                            twinProfilePrompt = twinProfilePrompt
                        )
                        return continueEscalationOrPrompt(
                            request = request,
                            cloudGateway = cloudGateway,
                            escalation = escalation,
                            reasonCode = escalationReason,
                            openClawHints = openClawHints,
                            resolvedRequestConstraints = resolvedRequestConstraints,
                            roleContext = roleContext
                        )
                    }
                    val verifiedEvidence = sanitizeEvidenceWithVerifiedUrls(evidence)
                    val coverageEnrichment = autoEnrichEvidenceCoverage(
                        request = request,
                        cloudGateway = cloudGateway,
                        constraints = constraints,
                        summary = exec.resultSummary,
                        evidence = verifiedEvidence,
                        requiredLinkKinds = requiredLinkKinds
                    )
                    val enrichedExecution = exec.copy(resultSummary = coverageEnrichment.summary)
                    val synthesizedSummary = synthesizeCloudFinalSummary(
                        request = request,
                        cloudGateway = cloudGateway,
                        constraints = constraints,
                        execution = enrichedExecution,
                        taskGraph = effectiveTaskGraph,
                        evidence = coverageEnrichment.evidence
                    )
                    val cardList = executionEvidenceCards(enrichedExecution, coverageEnrichment.evidence)
                    val modeHint = if (effectiveRoutingDecision.mode == RoutingMode.MULTI_AGENT) {
                        "Upgraded to multi-agent collaboration"
                    } else {
                        "Single-agent + skills completed"
                    }
                    val coverageHints = listOfNotNull(coverageEnrichment.hint)
                    CloudEnhancement(
                        cards = cardList,
                        summary = synthesizedSummary,
                        payload = ModulePayload.ChatPayload(
                            suggestionTitle = "Cloud decomposition and synthesis completed",
                            hints = listOf(
                                modeHint,
                                "Cloud LLM finalized integrated subtask results",
                                "All returned links are URL-validated before rendering"
                            ) + coverageHints + openClawHints.take(3),
                                taskTrack = TaskTrackBuilder.build(
                                module = ModuleId.CHAT,
                                query = request.rawText,
                                traceId = execution.traceId,
                                phase = "cloud_super_agent_done",
                                status = mappedExecutionStatus,
                                evidenceItems = coverageEnrichment.evidence,
                                nowMs = nowMs()
                                ),
                                evidenceItems = coverageEnrichment.evidence,
                                routingDecision = effectiveRoutingDecision,
                                taskGraph = effectiveTaskGraph,
                                skillInvocations = exec.skillInvocations,
                                selectedAgents = exec.selectedAgents,
                                reasoningProtocol = exec.reasoningProtocol
                            ),
                            status = mappedExecutionStatus
                        )
                } else {
                    if (meta.routingDecision.mode == RoutingMode.MULTI_AGENT && userRequestedLixEscalation) {
                        val escalation = LixEscalationContext(
                            userId = request.userId,
                            originalQuery = request.rawText,
                            domain = OpenClawCapabilityMapper.inferDomain(request.rawText),
                            requiredCapabilities = meta.taskGraph.tasks
                                .flatMap { it.requiredCapabilities }
                                .ifEmpty { requiredCapabilitiesForIntent(intent) }
                                .distinct()
                                .take(6),
                            reasonCode = "openclaw_team_execution_failed",
                            traceId = execution.traceId,
                            createdAtMs = nowMs(),
                            twinProfilePrompt = twinProfilePrompt
                        )
                        return continueEscalationOrPrompt(
                            request = request,
                            cloudGateway = cloudGateway,
                            escalation = escalation,
                            reasonCode = "openclaw_team_execution_failed",
                            openClawHints = openClawHints,
                            resolvedRequestConstraints = resolvedRequestConstraints,
                            roleContext = roleContext
                        )
                    }
                    val result = cloudGateway.liveSearch(twinAwareQuery, constraints)
                    if (!result.success) {
                        val fallbackBudget = resolvedRequestConstraints.budget ?: "not specified"
                        val fallbackDeadline = resolvedRequestConstraints.deadline ?: "not specified"
                        val fallbackAcceptance = resolvedRequestConstraints.acceptanceCriteria
                            ?: "Evidence-backed actionable plan with clickable official links."
                        val cloudIssueNote = buildCloudIssueNote(
                            error = execution.error,
                            httpStatus = execution.httpStatus
                        )
                        val interimSummary = buildInterimFallbackSummary(
                            domain = problemFrame.primaryDomain,
                            topCandidate = "OpenClaw relay fallback",
                            budget = fallbackBudget,
                            deadline = fallbackDeadline,
                            acceptanceCriteria = fallbackAcceptance,
                            userQuery = request.rawText,
                            userId = request.userId,
                            locale = request.locale
                        ) + cloudIssueNote
                        val interimEvidence = sanitizeEvidenceWithVerifiedUrls(
                            buildInterimFallbackEvidence(
                                domain = problemFrame.primaryDomain,
                                topCandidate = "OpenClaw relay fallback",
                                budget = fallbackBudget,
                                deadline = fallbackDeadline,
                                acceptanceCriteria = fallbackAcceptance,
                                userQuery = request.rawText,
                                userId = request.userId,
                                locale = request.locale
                            )
                        )
                        val coverageEnrichment = autoEnrichEvidenceCoverage(
                            request = request,
                            cloudGateway = cloudGateway,
                            constraints = constraints,
                            summary = interimSummary,
                            evidence = interimEvidence,
                            requiredLinkKinds = requiredLinkKinds
                        )
                        CloudEnhancement(
                            summary = coverageEnrichment.summary,
                            payload = ModulePayload.ChatPayload(
                                suggestionTitle = "Verified fallback plan generated",
                                hints = listOf(
                                    "Super Agent temporarily unavailable",
                                    "Generated evidence-backed fallback with verified links",
                                    "Use this plan now, then rerun cloud reasoning later"
                                ) + listOfNotNull(coverageEnrichment.hint) + openClawHints.take(2),
                                taskTrack = TaskTrackBuilder.build(
                                    module = ModuleId.CHAT,
                                    query = request.rawText,
                                    traceId = execution.traceId,
                                    phase = "fallback_verified_plan",
                                    status = if (coverageEnrichment.missingKinds.isEmpty()) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL,
                                    evidenceItems = coverageEnrichment.evidence,
                                    nowMs = nowMs()
                                ),
                                evidenceItems = coverageEnrichment.evidence
                            ),
                            status = if (coverageEnrichment.missingKinds.isEmpty()) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL
                        )
                    } else {
                        val evidence = sanitizeEvidenceWithVerifiedUrls(evidenceFromLiveSearch(result.data))
                        val fallbackSummary = result.data?.items?.firstOrNull()?.snippet
                            ?.takeIf { it.isNotBlank() }
                            ?: "Live evidence synced. Continue refining the task."
                        val coverageEnrichment = autoEnrichEvidenceCoverage(
                            request = request,
                            cloudGateway = cloudGateway,
                            constraints = constraints,
                            summary = fallbackSummary,
                            evidence = evidence,
                            requiredLinkKinds = requiredLinkKinds
                        )
                        CloudEnhancement(
                            cards = liveSearchCards(result.data),
                            summary = coverageEnrichment.summary,
                            payload = ModulePayload.ChatPayload(
                                suggestionTitle = "Live evidence synced (Super Agent degraded)",
                                hints = listOf("Continue refining", "Open app for deep processing in one tap") +
                                    listOfNotNull(coverageEnrichment.hint) +
                                    openClawHints.take(3),
                                taskTrack = TaskTrackBuilder.build(
                                    module = ModuleId.CHAT,
                                    query = request.rawText,
                                    traceId = result.traceId,
                                    phase = "evidence_ready",
                                    status = ResponseStatus.SUCCESS,
                                    evidenceItems = coverageEnrichment.evidence,
                                    nowMs = nowMs()
                                ),
                                evidenceItems = coverageEnrichment.evidence
                            ),
                            status = ResponseStatus.SUCCESS
                        )
                    }
                }
            }

            ModuleId.AGENT_MARKET -> {
                if (isBuildProductAgentsCommand(request.rawText)) {
                    val statuses = ProductAgentCatalog.constructionStatus()
                    val readyCount = statuses.count { it.status == "constructed" }
                    val scaffoldCount = statuses.count { it.status != "constructed" }
                    return CloudEnhancement(
                        cards = ProductAgentCatalog.constructionCards(limit = 10),
                        summary = "Product agents constructed: $readyCount ready, $scaffoldCount scaffold-only.",
                        payload = ModulePayload.MarketPayload(
                            candidateCount = statuses.size,
                            selectedCount = readyCount,
                            traceId = "product-agent-build"
                        ),
                        status = ResponseStatus.SUCCESS
                    )
                }

                if (isProductAgentsCommand(request.rawText)) {
                    val catalog = ProductAgentCatalog.all()
                    val liveCount = catalog.count { it.stage.equals("live", ignoreCase = true) }
                    return CloudEnhancement(
                        cards = ProductAgentCatalog.governanceCards(limit = 10),
                        summary = "Agent governance matrix ready: ${catalog.size} agents, with clear responsibility, activation timing, and authority scope.",
                        payload = ModulePayload.MarketPayload(
                            candidateCount = catalog.size,
                            selectedCount = liveCount,
                            traceId = "product-agent-catalog"
                        ),
                        status = ResponseStatus.SUCCESS
                    )
                }

                if (isGithubConnectCommand(request.rawText)) {
                    val connect = cloudGateway.githubConnect()
                    val repos = cloudGateway.githubRepos()
                    return CloudEnhancement(
                        cards = listOf(
                            AgentCard(
                                id = "market-github-connect",
                                title = if (connect.data?.connected == true) "GitHub connected" else "GitHub connection failed",
                                summary = connect.data?.account?.let { "Account: $it" } ?: "Continue configuration in Agent Market",
                                deeplink = LumiRoutes.AGENT_MARKET
                            ),
                            AgentCard(
                                id = "market-github-repos",
                                title = "GitHub repositories",
                                summary = "Importable repositories ${repos.data?.repos?.size ?: 0}",
                                deeplink = LumiRoutes.AGENT_MARKET
                            )
                        ),
                        payload = ModulePayload.MarketPayload(
                            candidateCount = repos.data?.repos?.size ?: 0,
                            selectedCount = 0,
                            traceId = connect.traceId,
                            githubRepoCount = repos.data?.repos?.size ?: 0
                        ),
                        status = if (connect.success) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL
                    )
                }

                val importRepo = extractGithubRepo(request.rawText)
                if (isGithubImportCommand(request.rawText) && importRepo != null) {
                    val manifestPath = extractManifestPath(request.rawText) ?: ".lix/agent.manifest.json"
                    val import = cloudGateway.githubImport(
                        repoFullName = importRepo,
                        manifestPath = manifestPath
                    )
                    return CloudEnhancement(
                        cards = listOf(
                            AgentCard(
                                id = "market-github-import",
                                title = if (import.success) "GitHub import submitted" else "GitHub import failed",
                                summary = "Repository: $importRepo · Path: $manifestPath · Status: ${import.data?.status ?: "pending_review"}",
                                deeplink = LumiRoutes.AGENT_MARKET
                            )
                        ),
                        payload = ModulePayload.MarketPayload(
                            candidateCount = 0,
                            selectedCount = if (import.success) 1 else 0,
                            traceId = import.traceId,
                            githubRepoCount = 1
                        ),
                        status = if (import.success) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL
                    )
                }

                val result = cloudGateway.discoverAgents(
                    query = request.rawText,
                    twinContext = soulStore.toTwinContext(request.userId, request.locale)
                )
                if (!result.success) {
                    CloudEnhancement(status = ResponseStatus.PARTIAL)
                } else {
                    val leaderboard = cloudGateway.leaderboard()
                    val topAgentId = result.data?.items?.firstOrNull()?.id
                    val trends = cloudGateway.trends(agentId = topAgentId)
                    val repos = cloudGateway.githubRepos()
                    val execution = if (shouldRunMarketExecution(request.rawText)) {
                        cloudGateway.executeAgent(request.rawText, constraints)
                    } else {
                        null
                    }
                    val cards = buildList {
                        addAll(discoveryCards(result.data?.items.orEmpty()))
                        addAll(leaderboardCards(leaderboard.data))
                        if (execution?.success == true) {
                            addAll(executionCards(execution.data))
                        }
                        if (trends.data?.points?.isNotEmpty() == true) {
                            add(
                                AgentCard(
                                    id = "market-trend-${topAgentId ?: "top"}",
                                    title = "Popularity trend synced",
                                    summary = "Fetched ${trends.data?.points?.size ?: 0} trend points",
                                    deeplink = LumiRoutes.AGENT_MARKET
                                )
                            )
                        }
                        if (repos.success) {
                            add(
                                AgentCard(
                                    id = "market-github",
                                    title = "GitHub import",
                                    summary = "Available repositories ${repos.data?.repos?.size ?: 0}",
                                    deeplink = LumiRoutes.AGENT_MARKET
                                )
                            )
                        }
                    }
                    CloudEnhancement(
                        cards = cards,
                        payload = ModulePayload.MarketPayload(
                            candidateCount = result.data?.items?.size ?: 0,
                            selectedCount = if (execution?.success == true) 1 else 0,
                            traceId = leaderboard.traceId,
                            leaderboardTop = leaderboard.data?.entries.orEmpty().take(5),
                            trendPoints = trends.data?.points.orEmpty().take(7),
                            githubRepoCount = repos.data?.repos?.size ?: 0
                        ),
                        status = if (leaderboard.success) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL
                    )
                }
            }

            ModuleId.LIX -> {
                val publishContext = parseLixPublishContext(request.rawText, intent)
                val requestConstraints = resolvedRequestConstraints
                val providerFacingScope = projectProviderFacingDataScope(
                    query = publishContext.query,
                    roleContext = roleContext
                )
                val twinPosterior = loadCloudTwinPosterior(cloudGateway, request.userId)
                if (isLixMyAgentsCommand(request.rawText)) {
                    val myAgents = cloudGateway.lixMyAgents(ownerId = request.userId)
                    val items = myAgents.data?.agents.orEmpty().map {
                        AgentDiscoveryItem(
                            id = it.agentId,
                            name = it.name,
                            summary = "Status ${it.status}",
                            score = 0.72,
                            actionDeeplink = LumiRoutes.AGENT_MARKET,
                            actionLabel = "Open agent market"
                        )
                    }
                    return CloudEnhancement(
                        cards = items.take(3).map { agent ->
                            AgentCard(
                                id = "lix-my-agent-${agent.id}",
                                title = agent.name,
                                summary = agent.summary,
                                deeplink = LumiRoutes.lixIntent("latest")
                            )
                        },
                        payload = ModulePayload.LixPayload(
                            intentId = "latest",
                            stage = "my_agents",
                            offerCount = items.size,
                            summary = "My LIX agents ${items.size}",
                            offers = items,
                            intentContract = buildIntentContract(
                                goal = publishContext.query,
                                constraints = requestConstraints,
                                domain = publishContext.domain,
                                roleContext = roleContext
                            ),
                            capabilityCards = buildCapabilityCards(items),
                            quotes = buildQuotes(items),
                            rollbackPolicy = defaultRollbackPolicy("latest")
                        ).withPosterior(twinPosterior),
                        status = if (myAgents.success) ResponseStatus.SUCCESS else ResponseStatus.PARTIAL
                    )
                }

                if (isLixAcceptCommand(request.rawText)) {
                    val intentId = extractIntentId(request.rawText)
                    val offerId = extractOfferId(request.rawText)
                    if (!intentId.isNullOrBlank() && !offerId.isNullOrBlank()) {
                        val accepted = cloudGateway.lixAcceptOffer(intentId = intentId, offerId = offerId)
                        val acceptedStatus = accepted.data?.status.orEmpty()
                        val lifecycleStatus = when {
                            !accepted.success -> ResponseStatus.PARTIAL
                            acceptedStatus.contains("auth", ignoreCase = true) ||
                                acceptedStatus.contains("payment", ignoreCase = true) -> ResponseStatus.AUTH_REQUIRED
                            acceptedStatus.contains("verify", ignoreCase = true) -> ResponseStatus.VERIFYING
                            else -> ResponseStatus.VERIFYING
                        }
                        return CloudEnhancement(
                            cards = listOf(
                                AgentCard(
                                    id = "lix-accept-${accepted.data?.offerId ?: offerId}",
                                    title = if (accepted.success) "Offer accepted" else "Offer acceptance failed",
                                    summary = "intent: ${accepted.data?.intentId ?: intentId}",
                                    deeplink = LumiRoutes.lixIntent(accepted.data?.intentId ?: intentId)
                                )
                            ),
                            payload = ModulePayload.LixPayload(
                                intentId = accepted.data?.intentId ?: intentId,
                                stage = accepted.data?.status ?: "accepted",
                                offerCount = 1,
                                summary = if (accepted.success) "Offer accepted and awaiting authorization/verification." else "Offer acceptance failed",
                                intentContract = buildIntentContract(
                                    goal = publishContext.query,
                                    constraints = requestConstraints,
                                    domain = publishContext.domain,
                                    roleContext = roleContext
                                ),
                                verificationProof = VerificationProof(
                                    proofId = "proof-${accepted.data?.intentId ?: intentId}",
                                    method = "provider_status",
                                    verifier = "lix_gateway",
                                    proofUrl = LumiRoutes.lixIntent(accepted.data?.intentId ?: intentId),
                                    passed = accepted.success,
                                    checkedAtMs = nowMs()
                                ),
                                rollbackPolicy = defaultRollbackPolicy(accepted.data?.intentId ?: intentId)
                            ).withPosterior(twinPosterior),
                            status = lifecycleStatus
                        )
                    }
                }

                if (isLixDeliveryCommand(request.rawText)) {
                    val intentId = extractIntentId(request.rawText)
                    val offerId = extractOfferId(request.rawText)
                    if (!intentId.isNullOrBlank() && !offerId.isNullOrBlank()) {
                        val delivery = cloudGateway.lixDelivery(
                            intentId = intentId,
                            offerId = offerId,
                            name = "Lumi Mobile Agent",
                            executeRef = "tool:web_search"
                        )
                        return CloudEnhancement(
                            cards = listOf(
                                AgentCard(
                                    id = "lix-delivery-${delivery.data?.intentId ?: intentId}",
                                    title = if (delivery.success) "Delivery submitted" else "Delivery submission failed",
                                    summary = delivery.data?.manifestName ?: "Pending review",
                                    deeplink = LumiRoutes.lixIntent(delivery.data?.intentId ?: intentId)
                                )
                            ),
                            payload = ModulePayload.LixPayload(
                                intentId = delivery.data?.intentId ?: intentId,
                                stage = delivery.data?.status ?: "delivery_submitted",
                                offerCount = 1,
                                summary = if (delivery.success) "Delivery manifest submitted; verification in progress." else "Delivery failed",
                                intentContract = buildIntentContract(
                                    goal = publishContext.query,
                                    constraints = requestConstraints,
                                    domain = publishContext.domain,
                                    roleContext = roleContext
                                ),
                                verificationProof = VerificationProof(
                                    proofId = "proof-delivery-${delivery.data?.intentId ?: intentId}",
                                    method = "delivery_manifest",
                                    verifier = "lix_gateway",
                                    proofUrl = LumiRoutes.lixIntent(delivery.data?.intentId ?: intentId),
                                    passed = delivery.success,
                                    checkedAtMs = nowMs()
                                ),
                                rollbackPolicy = defaultRollbackPolicy(delivery.data?.intentId ?: intentId)
                            ).withPosterior(twinPosterior),
                            status = if (delivery.success) ResponseStatus.VERIFYING else ResponseStatus.PARTIAL
                        )
                    }
                }

                if (isLixReviewCommand(request.rawText)) {
                    val intentId = extractIntentId(request.rawText)
                    if (!intentId.isNullOrBlank()) {
                        val decision = if (request.rawText.contains("reject", ignoreCase = true)) "rejected" else "approved"
                        val review = cloudGateway.lixReview(intentId = intentId, decision = decision)
                        val approvedDecision = decision.equals("approved", ignoreCase = true)
                        val lifecycleStatus = when {
                            approvedDecision && !review.success -> ResponseStatus.PARTIAL
                            approvedDecision -> ResponseStatus.COMMITTED
                            else -> ResponseStatus.DISPUTED
                        }
                        return CloudEnhancement(
                            cards = listOf(
                                AgentCard(
                                    id = "lix-review-${review.data?.intentId ?: intentId}",
                                    title = if (review.success) "Review completed" else "Review failed",
                                    summary = "Decision: ${review.data?.decision ?: decision}",
                                    deeplink = LumiRoutes.lixIntent(review.data?.intentId ?: intentId)
                                )
                            ),
                            payload = ModulePayload.LixPayload(
                                intentId = review.data?.intentId ?: intentId,
                                stage = review.data?.status ?: decision,
                                offerCount = 1,
                                summary = if (review.success) {
                                    if (approvedDecision) {
                                        "Review completed and outcome committed."
                                    } else {
                                        "Review completed and moved to dispute resolution."
                                    }
                                } else {
                                    if (approvedDecision) {
                                        "Review approval sync failed. Local state is partial until gateway confirmation."
                                    } else {
                                        "Review rejection recorded locally and dispute path opened; gateway sync pending."
                                    }
                                },
                                verificationProof = VerificationProof(
                                    proofId = "proof-review-${review.data?.intentId ?: intentId}",
                                    method = "review_decision",
                                    verifier = "lix_gateway",
                                    passed = review.success && approvedDecision,
                                    checkedAtMs = nowMs()
                                ),
                                rollbackPolicy = defaultRollbackPolicy(review.data?.intentId ?: intentId)
                            ).withPosterior(twinPosterior),
                            status = lifecycleStatus
                        )
                    }
                }

                if (providerFacingScope.blocked) {
                    return CloudEnhancement(
                        cards = listOf(
                            AgentCard(
                                id = "lix-data-scope-blocked",
                                title = "External data scope blocked",
                                summary = providerFacingScope.summary.summary,
                                deeplink = LumiRoutes.lixIntent("latest"),
                                riskLevel = "medium"
                            )
                        ),
                        payload = ModulePayload.LixPayload(
                            stage = "data_scope_blocked",
                            summary = providerFacingScope.summary.summary,
                            intentContract = buildIntentContract(
                                goal = publishContext.query,
                                constraints = requestConstraints,
                                domain = publishContext.domain,
                                roleContext = roleContext
                            ),
                            externalDataScopeSummary = providerFacingScope.summary,
                            rollbackPolicy = defaultRollbackPolicy("latest")
                        ).withPosterior(twinPosterior),
                        status = ResponseStatus.WAITING_USER
                    )
                }

                if (isLixExecutorCommand(request.rawText)) {
                    val executor = cloudGateway.lixExecutor(
                        query = providerFacingScope.providerQuery,
                        domain = publishContext.domain
                    )
                    return CloudEnhancement(
                        cards = listOf(
                            AgentCard(
                                id = "lix-executor",
                                title = if (executor.success) "LIX execution completed" else "LIX execution failed",
                                summary = executor.data?.summary ?: "Please retry later",
                                deeplink = LumiRoutes.lixIntent("latest")
                            )
                        ),
                        payload = ModulePayload.LixPayload(
                            intentId = "latest",
                            stage = if (executor.success) "executor_success" else "executor_failed",
                            offerCount = if (executor.success) 1 else 0,
                            summary = executor.data?.summary ?: "Execution failed",
                            intentContract = buildIntentContract(
                                goal = providerFacingScope.providerQuery,
                                constraints = requestConstraints,
                                domain = publishContext.domain,
                                roleContext = roleContext
                            ),
                            rollbackPolicy = defaultRollbackPolicy("latest")
                        ).withPosterior(twinPosterior),
                        status = if (executor.success) ResponseStatus.QUOTING else ResponseStatus.PARTIAL
                    )
                }

                val overflowMode = if (
                    publishContext.requiredCapabilities.size >= 3 ||
                    request.rawText.contains("parallel") ||
                    request.rawText.contains("multiple plans")
                ) {
                    "capability_auction"
                } else {
                    "lumi_primary"
                }
                val broadcast = cloudGateway.lixBroadcast(
                    query = providerFacingScope.providerQuery,
                    domain = publishContext.domain,
                    requiredCapabilities = publishContext.requiredCapabilities,
                    reasoningTraceId = request.sessionId,
                    overflowContext = LixOverflowContextPayload(
                        mode = overflowMode,
                        overflowReason = if (overflowMode == "capability_auction") "required_capabilities>=3" else "lumi_handle_first",
                        complexity = if (overflowMode == "capability_auction") 0.72 else 0.46,
                        risk = if (publishContext.domain == "travel") 0.58 else 0.44,
                        requiredCapabilities = publishContext.requiredCapabilities.size,
                        superAgentQueueDepth = 0
                    ),
                    dispatchPolicyVersion = "lix_1_5",
                    preferPaidExpert = true
                )
                if (!broadcast.success) {
                    val broadcastError = broadcast.errorCode ?: broadcast.error ?: "lix_broadcast_unavailable"
                    CloudEnhancement(
                        cards = listOf(
                            AgentCard(
                                id = "lix-broadcast-failed",
                                title = "LIX broadcast failed",
                                summary = "Exchange live endpoint unavailable: $broadcastError",
                                deeplink = LumiRoutes.lixIntent("latest"),
                                riskLevel = "high"
                            )
                        ),
                        payload = ModulePayload.LixPayload(
                            stage = "broadcast_failed",
                            offerCount = 0,
                            summary = "Exchange dispatch unavailable now. Request is retained and will retry later.",
                            intentContract = buildIntentContract(
                                goal = providerFacingScope.providerQuery,
                                constraints = requestConstraints,
                                domain = publishContext.domain,
                                roleContext = roleContext
                            ),
                            externalDataScopeSummary = providerFacingScope.summary,
                            userGuaranteeSummary = "Trade guarantee activates automatically after successful dispatch",
                            userView = LixUserViewPayload(
                                executablePlanSummary = "Request saved, waiting for exchange recovery",
                                expectedCompletionEta = "Updated after recovery",
                                guaranteeSummary = "Platform guarantee is ready",
                                paymentAndCompensationRule = "First order 30% / repeat 10%; failed tasks compensated by guarantee policy"
                            ),
                            rollbackPolicy = defaultRollbackPolicy("latest")
                        ).withPosterior(twinPosterior),
                        status = ResponseStatus.ERROR
                    )
                } else {
                    val data = broadcast.data ?: LixSolutionPayload("", "created", 0)
                    val offers = if (data.intentId.isBlank()) {
                        null
                    } else {
                        cloudGateway.lixOffers(data.intentId)
                    }
                    val offerItems = offers?.data?.items.orEmpty()
                    val normalizedOffers = offerItems.map { offer ->
                        if (!offer.actionDeeplink.isNullOrBlank()) {
                            offer
                        } else {
                            offer.copy(
                                actionDeeplink = LumiRoutes.lixIntent(data.intentId.ifBlank { "latest" }),
                                actionLabel = offer.actionLabel ?: "Open in LIX"
                            )
                        }
                    }
                    val offersFailed = offers != null && !offers.success
                    val offersError = offers?.errorCode ?: offers?.error ?: "unknown_error"
                    val summary = if (offersFailed) {
                        "Intent broadcasted, but offer retrieval failed: $offersError"
                    } else {
                        "Custom request has been broadcasted to exchange"
                    }
                    CloudEnhancement(
                        cards = buildList {
                            add(
                                AgentCard(
                                    id = "lix-intent-${data.intentId}",
                                    title = "LIX intent created",
                                    summary = "Status ${data.status} · Offers ${data.offersCount}",
                                    deeplink = LumiRoutes.lixIntent(data.intentId)
                                )
                            )
                            addAll(
                                normalizedOffers.take(3).map { offer ->
                                    AgentCard(
                                        id = "lix-offer-${offer.id}",
                                        title = offer.name,
                                        summary = offer.summary,
                                        deeplink = LumiRoutes.lixIntent(data.intentId)
                                    )
                                }
                            )
                        },
                        payload = ModulePayload.LixPayload(
                            intentId = data.intentId,
                            stage = data.status,
                            offerCount = normalizedOffers.size.takeIf { it > 0 } ?: data.offersCount,
                            summary = summary,
                            offers = normalizedOffers.take(8),
                            intentContract = buildIntentContract(
                                goal = providerFacingScope.providerQuery,
                                constraints = requestConstraints,
                                domain = publishContext.domain,
                                roleContext = roleContext
                            ),
                            capabilityCards = buildCapabilityCards(normalizedOffers),
                            quotes = buildQuotes(normalizedOffers),
                            verificationProof = VerificationProof(
                                proofId = "proof-intent-${data.intentId.ifBlank { "latest" }}",
                                method = "offer_verification_links",
                                verifier = "lix_gateway",
                                proofUrl = normalizedOffers.firstOrNull()?.actionDeeplink?.takeIf { it.isNotBlank() },
                                passed = !offersFailed,
                                checkedAtMs = nowMs()
                            ),
                            rollbackPolicy = defaultRollbackPolicy(data.intentId.ifBlank { "latest" }),
                            dispatchDecision = data.dispatchDecision,
                            bondStatus = data.bondStatus,
                            takeRateTier = data.takeRateTier,
                            etaMinutes = data.etaMinutes,
                            userGuaranteeSummary = data.userGuaranteeSummary,
                            userView = data.userView,
                            externalDataScopeSummary = providerFacingScope.summary
                        ).withPosterior(twinPosterior),
                        status = if (offersFailed) ResponseStatus.PARTIAL else ResponseStatus.QUOTING
                    )
                }
            }

            ModuleId.AVATAR -> {
                val summary = soulStore.summary(request.userId)
                val twinPosterior = loadCloudTwinPosterior(cloudGateway, request.userId)
                val activeRole = roleContext.activeRole
                CloudEnhancement(
                    payload = buildAvatarPayload(
                        userId = request.userId,
                        summary = summary,
                        posterior = twinPosterior,
                        activeRole = activeRole
                    )
                )
            }

            ModuleId.DESTINY -> {
                val result = cloudGateway.tavilySearch(destinySearchQuery(request.rawText))
                if (!result.success) {
                    CloudEnhancement(
                        payload = ModulePayload.DestinyPayload(
                            strategyLabel = "Destiny navigation degraded strategy",
                            riskLevel = "medium",
                            nextSteps = listOf("Use local strategy template", "Retry cloud retrieval later"),
                            nextBestAction = "Capture time and budget constraints, then continue with local Bellman suggestions.",
                            alternatives = listOf(
                                DestinyAlternativePayload(
                                    actionId = "destiny_local_template",
                                    summary = "Use local strategy template",
                                    riskLevel = "low",
                                    rationale = "No cloud dependency; stable fallback route."
                                ),
                                DestinyAlternativePayload(
                                    actionId = "destiny_retry_cloud",
                                    summary = "Retry cloud retrieval in better network conditions",
                                    riskLevel = "medium",
                                    rationale = "Improves evidence coverage after connectivity recovers."
                                )
                            ),
                            constraintNotes = listOf(
                                "Cloud evidence retrieval is currently unavailable.",
                                "Treat current recommendation as a fallback and avoid irreversible commitments."
                            ),
                            auditTrail = destinyAuditTrail(
                                source = "cloud_destiny",
                                selectedAction = "local_template_fallback",
                                detail = "Cloud search failed, switched to local-only strategy scaffold."
                            )
                        ),
                        status = ResponseStatus.PARTIAL
                    )
                } else {
                    val cards = liveSearchCards(result.data?.items?.let { LiveSearchPayload(it) })
                    val evidence = evidenceFromLiveItems(result.data?.items.orEmpty())
                    val safeCards = if (cards.isEmpty()) {
                        listOf(
                            AgentCard(
                                id = "destiny-strategy",
                                title = "Destiny navigation strategy summary",
                                summary = "Next-action suggestions generated. See full chain in Navigation page.",
                                deeplink = LumiRoutes.DESTINY
                            )
                        )
                    } else {
                        cards
                    }
                    CloudEnhancement(
                        cards = safeCards,
                        payload = ModulePayload.DestinyPayload(
                            strategyLabel = "Bellman path suggestion",
                            riskLevel = "medium",
                            nextSteps = listOf("View evidence", "Execute next step", "Review on Navigation page"),
                            routeSteps = listOf("Identify current state", "Estimate transition return", "Choose optimal action"),
                            evidenceItems = evidence,
                            nextBestAction = "Execute the highest-confidence step, then verify with evidence references.",
                            alternatives = listOf(
                                DestinyAlternativePayload(
                                    actionId = "destiny_review_evidence",
                                    summary = "Review evidence before commitment",
                                    score = 0.74,
                                    riskLevel = "low",
                                    rationale = "Reduces decision error under uncertainty."
                                ),
                                DestinyAlternativePayload(
                                    actionId = "destiny_parallel_probe",
                                    summary = "Run a small parallel probe before full rollout",
                                    score = 0.67,
                                    riskLevel = "medium",
                                    rationale = "Improves confidence with bounded cost."
                                )
                            ),
                            constraintNotes = listOf(
                                "External evidence is advisory; validate assumptions before irreversible actions.",
                                "If evidence conflicts, switch to local Bellman fallback and re-evaluate."
                            ),
                            auditTrail = destinyAuditTrail(
                                source = "cloud_destiny",
                                selectedAction = "evidence_first_execution",
                                detail = "Cloud evidence retrieved and mapped to navigation strategy."
                            )
                        ),
                        status = ResponseStatus.SUCCESS
                    )
                }
            }

            ModuleId.HOME -> {
                val leaderboard = cloudGateway.leaderboard()
                val summary = soulStore.summary(request.userId)
                val metrics = computeSettingsObservabilityMetrics(DEFAULT_SETTINGS_EVENT_WINDOW_HOURS)
                val apiHealth = loadApiHealthSnapshot(
                    cloudGateway = cloudGateway,
                    userId = request.userId,
                    locale = request.locale,
                    forceRefresh = false
                )
                val healthMetric = "${apiHealth.healthyCount}/${apiHealth.totalCount}"
                val healthStatus = apiHealth.overallStatus
                val homeStatus = if (!leaderboard.success || healthStatus == "down") {
                    ResponseStatus.PARTIAL
                } else {
                    ResponseStatus.SUCCESS
                }
                val healthCards = healthAlertCards(apiHealth)
                CloudEnhancement(
                    cards = (leaderboardCards(leaderboard.data) + healthCards).distinctBy { it.id },
                    payload = ModulePayload.HomePayload(
                        profileLabel = summary.profileLabel,
                        pendingTasks = if (homeStatus == ResponseStatus.SUCCESS) 0 else 1,
                        completionRate = if (homeStatus == ResponseStatus.SUCCESS) 0.86 else 0.62,
                        quickRoutes = listOf(
                            LumiRoutes.CHAT,
                            LumiRoutes.lixIntent("latest"),
                            LumiRoutes.AGENT_MARKET,
                            LumiRoutes.AVATAR,
                            LumiRoutes.DESTINY
                        ),
                        snapshot = ModuleSnapshotPayload(
                            module = ModuleId.HOME,
                            status = homeStatus,
                            headline = "Home aggregated status refreshed",
                            updatedAtMs = nowMs(),
                            keyMetrics = linkedMapOf(
                                "leaderboard_rows" to "${leaderboard.data?.entries?.size ?: 0}",
                                "task_confirm_24h" to "${metrics.taskConfirmCount}",
                                "task_cancel_24h" to "${metrics.taskCancelCount}",
                                "task_confirm_rate_24h" to "${(metrics.taskConfirmRate * 100).toInt()}%",
                                "dtoe_uplift_24h" to formatSignedPercentagePoints(metrics.dtoeAdoptionUplift),
                                "dtoe_calibration_error_24h" to formatPercentage(metrics.dtoeCalibrationError),
                                "dtoe_confidence_coverage_24h" to formatPercentage(metrics.dtoeConfidenceCoverage),
                                "dtoe_calibration_samples_24h" to "${metrics.dtoeCalibrationSampleCount}",
                                "top_module_24h" to (metrics.moduleTaskMetrics.firstOrNull()?.moduleLabel ?: "N/A"),
                                "api_health" to healthMetric,
                                "api_status" to healthStatus,
                                "profile_label" to summary.profileLabel
                            )
                        )
                    ),
                    status = homeStatus
                )
            }

            ModuleId.SETTINGS -> {
                val health = loadApiHealthSnapshot(
                    cloudGateway = cloudGateway,
                    userId = request.userId,
                    locale = request.locale,
                    forceRefresh = true
                )
                val payload = buildSettingsPayload(
                    userId = request.userId,
                    backendStatus = when (health.overallStatus) {
                        "up" -> "online"
                        "degraded" -> "degraded"
                        "down" -> "offline"
                        else -> "unknown"
                    },
                    serpConfigured = health.serpConfigured,
                    cloudBaseUrl = cloudGateway.cloudBaseUrl(),
                    apiHealth = health
                )
                CloudEnhancement(
                    cards = settingsHealthCards(health),
                    payload = payload,
                    status = when (health.overallStatus) {
                        "up" -> ResponseStatus.SUCCESS
                        "degraded" -> ResponseStatus.PARTIAL
                        "down" -> ResponseStatus.ERROR
                        else -> ResponseStatus.PARTIAL
                    }
                )
            }
        }
    }

    private fun payloadForModule(
        module: ModuleId,
        userId: String,
        locale: String,
        query: String,
        traceId: String,
        meta: OrchestrationMeta? = null
    ): ModulePayload {
        return when (module) {
            ModuleId.HOME -> {
                val summary = soulStore.summary(userId)
                val metrics = computeSettingsObservabilityMetrics(DEFAULT_SETTINGS_EVENT_WINDOW_HOURS)
                val cachedHealth = latestApiHealthSnapshot()
                ModulePayload.HomePayload(
                    profileLabel = summary.profileLabel,
                    pendingTasks = 0,
                    completionRate = 0.82,
                    quickRoutes = listOf(
                        LumiRoutes.CHAT,
                        LumiRoutes.lixIntent("latest"),
                        LumiRoutes.AGENT_MARKET,
                        LumiRoutes.AVATAR,
                        LumiRoutes.DESTINY
                    ),
                    snapshot = ModuleSnapshotPayload(
                        module = ModuleId.HOME,
                        status = ResponseStatus.SUCCESS,
                        headline = "Home capabilities are ready",
                        updatedAtMs = nowMs(),
                        keyMetrics = linkedMapOf(
                            "task_confirm_24h" to "${metrics.taskConfirmCount}",
                            "task_cancel_24h" to "${metrics.taskCancelCount}",
                            "task_confirm_rate_24h" to "${(metrics.taskConfirmRate * 100).toInt()}%",
                            "dtoe_uplift_24h" to formatSignedPercentagePoints(metrics.dtoeAdoptionUplift),
                            "dtoe_calibration_error_24h" to formatPercentage(metrics.dtoeCalibrationError),
                            "dtoe_confidence_coverage_24h" to formatPercentage(metrics.dtoeConfidenceCoverage),
                            "dtoe_calibration_samples_24h" to "${metrics.dtoeCalibrationSampleCount}",
                            "top_module_24h" to (metrics.moduleTaskMetrics.firstOrNull()?.moduleLabel ?: "N/A"),
                            "api_health" to "${cachedHealth?.healthyCount ?: 0}/${cachedHealth?.totalCount ?: 0}",
                            "api_status" to (cachedHealth?.overallStatus ?: "unknown"),
                            "profile_label" to summary.profileLabel,
                            "top_traits" to "${summary.topTraits.size}",
                            "locale" to locale
                        )
                    )
                )
            }

            ModuleId.AVATAR -> {
                val summary = soulStore.summary(userId)
                buildAvatarPayload(
                    userId = userId,
                    summary = summary,
                    activeRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
                )
            }

            ModuleId.CHAT -> ModulePayload.ChatPayload(
                suggestionTitle = "Chat orchestration",
                hints = listOf("Rewrite", "Multi-turn context", "Open app in one tap"),
                taskTrack = TaskTrackBuilder.build(
                    module = ModuleId.CHAT,
                    query = query,
                    traceId = traceId,
                    phase = "planned",
                    status = ResponseStatus.PROCESSING,
                    evidenceItems = emptyList(),
                    nowMs = nowMs()
                ),
                routingDecision = meta?.routingDecision,
                taskGraph = meta?.taskGraph,
                skillInvocations = meta?.skillInvocations.orEmpty(),
                skillGap = meta?.skillGap,
                skillSelectionTrace = meta?.skillSelectionTrace.orEmpty()
            )

            ModuleId.LIX -> ModulePayload.LixPayload(stage = "discovery", summary = "Waiting to broadcast intent")

            ModuleId.AGENT_MARKET -> ModulePayload.MarketPayload(candidateCount = 0, selectedCount = 0)

            ModuleId.DESTINY -> {
                // Use Bellman solver if available, otherwise static fallback
                bellmanBridge?.evaluate(userId, quick = true) ?: ModulePayload.DestinyPayload(
                    strategyLabel = "Long-term optimal path",
                    riskLevel = "medium",
                    nextSteps = listOf("Evaluate opportunities", "Execute actions", "Review results"),
                    routeSteps = listOf("Model state", "Estimate value", "Select action"),
                    nextBestAction = "Collect minimum constraints and execute the smallest reversible step first.",
                    alternatives = listOf(
                        DestinyAlternativePayload(
                            actionId = "destiny_collect_constraints",
                            summary = "Collect constraints before taking action",
                            riskLevel = "low",
                            rationale = "Improves model quality with minimal cost."
                        ),
                        DestinyAlternativePayload(
                            actionId = "destiny_small_reversible_action",
                            summary = "Take a reversible pilot action",
                            riskLevel = "medium",
                            rationale = "Balances learning speed and downside risk."
                        )
                    ),
                    constraintNotes = listOf(
                        "Bellman bridge unavailable, using static strategy fallback.",
                        "Avoid irreversible decisions until full DTOE scoring resumes."
                    ),
                    auditTrail = destinyAuditTrail(
                        source = "destiny_fallback",
                        selectedAction = "static_fallback",
                        detail = "Bellman bridge unavailable, emitted static safe strategy."
                    )
                )
            }

            ModuleId.SETTINGS -> buildSettingsPayload(
                userId = userId,
                backendStatus = "online",
                apiHealth = latestApiHealthSnapshot()
            )
        }
    }

    private fun buildSettingsPayload(
        userId: String,
        backendStatus: String,
        serpConfigured: Boolean? = null,
        cloudBaseUrl: String? = null,
        apiHealth: ApiHealthSnapshot? = null
    ): ModulePayload.SettingsPayload {
        val metrics = computeSettingsObservabilityMetrics(DEFAULT_SETTINGS_EVENT_WINDOW_HOURS)
        val resolvedApiHealth = apiHealth ?: latestApiHealthSnapshot()
        val twinSync = twinSyncStatusProvider()
        val optimizationSummary = userId.takeIf { it.isNotBlank() }
            ?.let { getPortfolioOptimizationState(it).summary }
        return ModulePayload.SettingsPayload(
            backendStatus = backendStatus,
            serpConfigured = serpConfigured ?: resolvedApiHealth?.serpConfigured,
            cloudBaseUrl = cloudBaseUrl,
            imeBackendV2Enabled = imeBackendV2Enabled,
            appFullFeatureParityEnabled = appFullFeatureParityEnabled,
            digitalTwinCloudSyncEnabled = digitalTwinCloudSyncEnabled,
            digitalTwinEdgeModelMode = digitalTwinEdgeModelMode,
            digitalTwinEdgeModelVersion = digitalTwinEdgeModelVersion,
            digitalTwinEdgeFallbackEnabled = digitalTwinEdgeFallbackEnabled,
            cloudAdapterFallbackEnabled = cloudAdapterFallbackEnabled,
            taskConfirmCount = metrics.taskConfirmCount,
            taskCancelCount = metrics.taskCancelCount,
            taskConfirmRate = metrics.taskConfirmRate,
            draftAcceptCount = metrics.draftAcceptCount,
            cardClickCount = metrics.cardClickCount,
            eventWindowHours = metrics.eventWindowHours,
            lastEventAtMs = metrics.lastEventAtMs,
            moduleTaskMetrics = metrics.moduleTaskMetrics,
            dtoeDecisionCount = metrics.dtoeDecisionCount,
            dtoeAdoptionRate = metrics.dtoeAdoptionRate,
            baselineDecisionCount = metrics.baselineDecisionCount,
            baselineAdoptionRate = metrics.baselineAdoptionRate,
            dtoeAdoptionUplift = metrics.dtoeAdoptionUplift,
            dtoeCalibrationError = metrics.dtoeCalibrationError,
            dtoeCalibrationSampleCount = metrics.dtoeCalibrationSampleCount,
            dtoeConfidenceCoverage = metrics.dtoeConfidenceCoverage,
            apiOverallStatus = resolvedApiHealth?.overallStatus ?: "unknown",
            apiHealthyCount = resolvedApiHealth?.healthyCount ?: 0,
            apiTotalCount = resolvedApiHealth?.totalCount ?: 0,
            apiLastCheckedAtMs = resolvedApiHealth?.checkedAtMs,
            apiHealthChecks = resolvedApiHealth?.checks.orEmpty(),
            twinSyncStatus = twinSync?.status ?: if (digitalTwinCloudSyncEnabled) "pending" else "disabled",
            twinSyncLastSyncAtMs = twinSync?.lastSyncAtMs,
            twinSyncSuccessCount = twinSync?.successCount ?: 0,
            twinSyncConflictCount = twinSync?.conflictCount ?: 0,
            twinSyncFallbackCount = twinSync?.fallbackCount ?: 0,
            twinSyncLastSummary = twinSync?.lastSummary,
            twinSyncLastResolution = twinSync?.lastResolution,
            twinSyncLastConflictAtMs = twinSync?.lastConflictAtMs,
            twinSyncLastConflictSummary = twinSync?.lastConflictSummary,
            activeObjectiveProfileSnapshotId = optimizationSummary?.activeObjectiveProfileSnapshotId,
            activeObjectiveProfileScope = optimizationSummary?.activeObjectiveProfileScope,
            activeObjectiveProfileProvenance = optimizationSummary?.activeObjectiveProfileProvenance,
            activeObjectiveProfileSummary = optimizationSummary?.activeObjectiveProfileSummary.orEmpty(),
            pendingPropagationCount = optimizationSummary?.pendingPropagationCount ?: 0,
            reviewRequiredPropagationCount = optimizationSummary?.reviewRequiredPropagationCount ?: 0,
            latestPropagationSummary = optimizationSummary?.latestPropagationSummary.orEmpty(),
            externalFulfillmentTelemetry = externalFulfillmentTelemetrySnapshot()
        )
    }

    private fun externalFulfillmentTelemetrySnapshot(): Map<String, Int> {
        return synchronized(externalTelemetryLock) {
            externalTelemetryCounters.toMap()
        }
    }

    private fun computeSettingsObservabilityMetrics(windowHours: Int): SettingsObservabilityMetrics {
        val safeWindowHours = windowHours.coerceAtLeast(1)
        val now = nowMs()
        val windowStart = now - safeWindowHours * 60L * 60L * 1000L
        val events = synchronized(interactionLock) {
            interactionEvents.filter { it.timestampMs >= windowStart }
        }
        val taskConfirm = events.count { it.eventType == InteractionEventType.TASK_CONFIRM }
        val taskCancel = events.count { it.eventType == InteractionEventType.TASK_CANCEL }
        val draftAccept = events.count { it.eventType == InteractionEventType.DRAFT_ACCEPT }
        val cardClick = events.count { it.eventType == InteractionEventType.CARD_CLICK }
        val totalTask = taskConfirm + taskCancel
        val taskEvents = events.filter {
            it.eventType == InteractionEventType.TASK_CONFIRM ||
                it.eventType == InteractionEventType.TASK_CANCEL
        }
        val dtoeTaskEvents = taskEvents.filter(::isDtoeDecisionEvent)
        val baselineTaskEvents = taskEvents.filterNot(::isDtoeDecisionEvent)
        val dtoeDecisionCount = dtoeTaskEvents.size
        val baselineDecisionCount = baselineTaskEvents.size
        val dtoeAdoptionRate = decisionAdoptionRate(dtoeTaskEvents)
        val baselineAdoptionRate = decisionAdoptionRate(baselineTaskEvents)
        val calibrationAbsErrors = taskEvents.mapNotNull { event ->
            val predicted = extractPredictedSuccessProbability(event) ?: return@mapNotNull null
            val observed = if (event.eventType == InteractionEventType.TASK_CONFIRM) 1.0 else 0.0
            abs(predicted - observed)
        }
        val dtoeCalibrationSampleCount = calibrationAbsErrors.size
        val dtoeCalibrationError = if (dtoeCalibrationSampleCount == 0) {
            0.0
        } else {
            calibrationAbsErrors.average()
        }
        val dtoeConfidenceCoverage = if (totalTask == 0) {
            0.0
        } else {
            dtoeCalibrationSampleCount.toDouble() / totalTask
        }
        val moduleTaskMetrics = events
            .asSequence()
            .filter {
                it.eventType == InteractionEventType.TASK_CONFIRM ||
                    it.eventType == InteractionEventType.TASK_CANCEL
            }
            .groupBy(::normalizeModuleKey)
            .map { (moduleKey, moduleEvents) ->
                val confirms = moduleEvents.count { it.eventType == InteractionEventType.TASK_CONFIRM }
                val cancels = moduleEvents.count { it.eventType == InteractionEventType.TASK_CANCEL }
                val total = confirms + cancels
                ModuleTaskMetricPayload(
                    moduleKey = moduleKey,
                    moduleLabel = moduleLabelForKey(moduleKey),
                    taskConfirmCount = confirms,
                    taskCancelCount = cancels,
                    taskConfirmRate = if (total == 0) 0.0 else confirms.toDouble() / total
                )
            }
            .sortedByDescending { it.taskConfirmCount + it.taskCancelCount }
            .take(6)
            .toList()

        return SettingsObservabilityMetrics(
            taskConfirmCount = taskConfirm,
            taskCancelCount = taskCancel,
            taskConfirmRate = if (totalTask == 0) 0.0 else taskConfirm.toDouble() / totalTask,
            draftAcceptCount = draftAccept,
            cardClickCount = cardClick,
            eventWindowHours = safeWindowHours,
            lastEventAtMs = events.maxOfOrNull { it.timestampMs },
            moduleTaskMetrics = moduleTaskMetrics,
            dtoeDecisionCount = dtoeDecisionCount,
            dtoeAdoptionRate = dtoeAdoptionRate,
            baselineDecisionCount = baselineDecisionCount,
            baselineAdoptionRate = baselineAdoptionRate,
            dtoeAdoptionUplift = dtoeAdoptionRate - baselineAdoptionRate,
            dtoeCalibrationError = dtoeCalibrationError,
            dtoeCalibrationSampleCount = dtoeCalibrationSampleCount,
            dtoeConfidenceCoverage = dtoeConfidenceCoverage
        )
    }

    private fun isDtoeDecisionEvent(event: InteractionEvent): Boolean {
        val source = event.payload["decision_source"]?.trim()?.lowercase().orEmpty()
        return source == "dtoe" || normalizeModuleKey(event) == "destiny"
    }

    private fun decisionAdoptionRate(events: List<InteractionEvent>): Double {
        if (events.isEmpty()) return 0.0
        val confirms = events.count { it.eventType == InteractionEventType.TASK_CONFIRM }
        return confirms.toDouble() / events.size
    }

    private fun extractPredictedSuccessProbability(event: InteractionEvent): Double? {
        val raw = event.payload["predicted_success_prob"] ?: event.payload["confidence"]
        val parsed = raw?.toDoubleOrNull() ?: return null
        return parsed.coerceIn(0.0, 1.0)
    }

    private fun formatPercentage(value: Double): String {
        return "${(value.coerceIn(0.0, 1.0) * 100).toInt()}%"
    }

    private fun formatSignedPercentagePoints(delta: Double): String {
        val points = (delta * 100).toInt()
        return if (points >= 0) "+${points}pp" else "${points}pp"
    }

    private fun normalizeModuleKey(event: InteractionEvent): String {
        val raw = event.payload["module"]?.trim()?.lowercase().orEmpty()
        return when {
            raw.isBlank() -> "unknown"
            raw.contains("home") || raw.contains("首页") -> "home"
            raw.contains("chat") || raw.contains("对话") -> "chat"
            raw.contains("lix") || raw.contains("external fulfillment") -> "lix"
            raw.contains("agent") || raw.contains("market") || raw.contains("external capabilities") || raw.contains("代理") -> "agent_market"
            raw.contains("avatar") || raw.contains("preferences & permissions") || raw.contains("画像") || raw.contains("分身") -> "avatar"
            raw.contains("destiny") || raw.contains("recommendations & risk") || raw.contains("navigation") || raw.contains("导航") -> "destiny"
            raw.contains("setting") || raw.contains("设置") -> "settings"
            else -> raw.replace(' ', '_')
        }
    }

    private fun moduleLabelForKey(moduleKey: String): String {
        return when (moduleKey) {
            "home" -> "Home"
            "chat" -> "Chat"
            "lix" -> "External Fulfillment"
            "agent_market" -> "External Capabilities"
            "avatar" -> "Preferences & Permissions"
            "destiny" -> "Recommendations & Risk"
            "settings" -> "Settings"
            else -> "Uncategorized"
        }
    }

    private fun latestApiHealthSnapshot(): ApiHealthSnapshot? {
        return synchronized(apiHealthLock) { apiHealthSnapshot }
    }

    private suspend fun loadApiHealthSnapshot(
        cloudGateway: CloudGateway,
        userId: String,
        locale: String,
        forceRefresh: Boolean
    ): ApiHealthSnapshot {
        val now = nowMs()
        synchronized(apiHealthLock) {
            val cached = apiHealthSnapshot
            if (!forceRefresh && cached != null && (now - cached.checkedAtMs) <= API_HEALTH_CACHE_TTL_MS) {
                return cached
            }
        }

        val twinContext = soulStore.toTwinContext(userId, locale)
        val checks = listOf(
            probeCloudEndpoint(
                checkId = "chat_live_search",
                moduleKey = "chat",
                moduleLabel = "Chat",
                endpoint = "/api/live-search"
            ) {
                cloudGateway.liveSearch(
                    query = "lumi api health check",
                    constraints = AgentTaskConstraints(timeoutMs = 0, preferRealtime = true, maxResults = 1)
                )
            },
            probeCloudEndpoint(
                checkId = "lix_executor",
                moduleKey = "lix",
                moduleLabel = "LIX",
                endpoint = "/api/lix/solution/executor",
                statusResolver = { result ->
                    when {
                        result.success -> "up"
                        (result.httpStatus ?: 0) in 200..499 -> "degraded"
                        else -> "down"
                    }
                },
                errorResolver = { result ->
                    if (result.success) null else result.errorCode ?: result.error
                }
            ) {
                cloudGateway.lixExecutor(
                    query = "health check",
                    domain = "general"
                )
            },
            probeCloudEndpoint(
                checkId = "market_discover",
                moduleKey = "agent_market",
                moduleLabel = "Agent",
                endpoint = "/api/agent-market/discover"
            ) {
                cloudGateway.discoverAgents(query = "health probe", twinContext = twinContext)
            },
            probeCloudEndpoint(
                checkId = "serp_status",
                moduleKey = "settings",
                moduleLabel = "SerpAPI",
                endpoint = "/api/serpapi/status",
                healthyResolver = { result ->
                    result.success && result.data?.configured == true
                },
                statusResolver = { result ->
                    when {
                        !result.success -> "down"
                        result.data?.configured == true -> "up"
                        else -> "degraded"
                    }
                },
                errorResolver = { result ->
                    when {
                        !result.success -> result.errorCode ?: result.error
                        result.data?.configured == true -> null
                        else -> "serp_not_configured"
                    }
                }
            ) {
                cloudGateway.serpStatus()
            }
        )

        val healthyCount = checks.count { it.healthy }
        val overallStatus = when {
            checks.isEmpty() -> "unknown"
            checks.all { it.status == "up" } -> "up"
            checks.any { it.status == "up" || it.status == "degraded" } -> "degraded"
            else -> "down"
        }
        val serpConfigured = checks
            .firstOrNull { it.checkId == "serp_status" }
            ?.status == "up"

        val snapshot = ApiHealthSnapshot(
            checks = checks,
            overallStatus = overallStatus,
            healthyCount = healthyCount,
            totalCount = checks.size,
            checkedAtMs = now,
            serpConfigured = serpConfigured
        )
        synchronized(apiHealthLock) {
            apiHealthSnapshot = snapshot
        }
        return snapshot
    }

    private suspend fun <T> probeCloudEndpoint(
        checkId: String,
        moduleKey: String,
        moduleLabel: String,
        endpoint: String,
        healthyResolver: (CloudResult<T>) -> Boolean = { it.success },
        statusResolver: (CloudResult<T>) -> String = { if (it.success) "up" else "down" },
        errorResolver: (CloudResult<T>) -> String? = { if (it.success) null else (it.errorCode ?: it.error) },
        call: suspend () -> CloudResult<T>
    ): ModulePayload.ApiHealthCheckPayload {
        val started = nowMs()
        val result = runCatching { call() }.getOrElse { error ->
            CloudResult(
                success = false,
                error = error.message ?: "probe_error",
                traceId = traceFactory(),
                retryable = true,
                errorCode = "probe_error"
            )
        }
        val latency = (nowMs() - started).coerceAtLeast(0)
        return ModulePayload.ApiHealthCheckPayload(
            checkId = checkId,
            moduleKey = moduleKey,
            moduleLabel = moduleLabel,
            endpoint = endpoint,
            status = statusResolver(result),
            healthy = healthyResolver(result),
            latencyMs = latency,
            httpStatus = result.httpStatus,
            errorCode = errorResolver(result),
            traceId = result.traceId
        )
    }

    private fun settingsHealthCards(snapshot: ApiHealthSnapshot?): List<AgentCard> {
        if (snapshot == null) {
            return listOf(
                AgentCard(
                    id = "settings-health-empty",
                    title = "API health checks not run",
                    summary = "Refresh in Settings and try again",
                    deeplink = LumiRoutes.SETTINGS
                )
            )
        }

        val summaryCard = AgentCard(
            id = "settings-health-summary",
            title = "API health: ${snapshot.healthyCount}/${snapshot.totalCount}",
            summary = "Status ${snapshot.overallStatus}",
            deeplink = LumiRoutes.SETTINGS
        )
        val checkCards = snapshot.checks.take(4).map { check ->
            val latency = check.latencyMs?.let { "${it}ms" } ?: "-"
            val error = check.errorCode?.let { " · $it" } ?: ""
            AgentCard(
                id = "settings-health-${check.checkId}",
                title = "${check.moduleLabel}: ${check.status}",
                summary = "${check.endpoint} · ${latency}${error}",
                deeplink = LumiRoutes.SETTINGS,
                riskLevel = if (check.status == "down") "high" else "safe"
            )
        }
        return listOf(summaryCard) + checkCards
    }

    private fun healthAlertCards(snapshot: ApiHealthSnapshot?): List<AgentCard> {
        if (snapshot == null || snapshot.overallStatus == "up") return emptyList()
        val degradedModules = snapshot.checks
            .filter { it.status != "up" }
            .take(2)
            .joinToString(" / ") { it.moduleLabel }
            .ifBlank { "Pipeline degraded" }
        return listOf(
            AgentCard(
                id = "home-api-health",
                title = "API status ${snapshot.overallStatus}",
                summary = "Available ${snapshot.healthyCount}/${snapshot.totalCount} · $degradedModules",
                deeplink = LumiRoutes.SETTINGS,
                riskLevel = if (snapshot.overallStatus == "down") "high" else "safe"
            )
        )
    }

