            ModuleId.AGENT_MARKET -> {
                actions += AgentAction(
                    id = "open_market",
                    label = "Open Agent Market",
                    type = AgentActionType.OPEN_DEEPLINK,
                    deeplink = LumiRoutes.AGENT_MARKET
                )
            }

            ModuleId.AVATAR -> {
                actions += AgentAction(
                    id = "open_avatar",
                    label = "Open Avatar",
                    type = AgentActionType.OPEN_DEEPLINK,
                    deeplink = LumiRoutes.AVATAR
                )
            }

            ModuleId.DESTINY -> {
                actions += AgentAction(
                    id = "open_destiny",
                    label = "Open Navigation",
                    type = AgentActionType.OPEN_DEEPLINK,
                    deeplink = LumiRoutes.DESTINY
