    private fun builtInAgentMarketResponse(
        request: AgentRequest,
        module: ModuleId,
        startMs: Long,
        traceId: String,
        orchestrationMeta: OrchestrationMeta
    ): AgentResponse? {
        if (module != ModuleId.AGENT_MARKET) return null
        if (isBuildProductAgentsCommand(request.rawText)) {
            val statuses = ProductAgentCatalog.constructionStatus()
            val readyCount = statuses.count { it.status == "constructed" }
            val scaffoldCount = statuses.count { it.status != "constructed" }
            return AgentResponse(
                type = AgentResponseType.CARDS,
                cards = ProductAgentCatalog.constructionCards(limit = 10),
                summary = "Product agents constructed: $readyCount ready, $scaffoldCount scaffold-only.",
                appDeeplink = routeForModule(module, traceId),
                traceId = traceId,
                latencyMs = nowMs() - startMs,
                confidence = 0.93,
                module = module,
                payload = ModulePayload.MarketPayload(
                    candidateCount = statuses.size,
                    selectedCount = readyCount,
                    traceId = "product-agent-build"
                ),
                actions = defaultActions(module, request.rawText),
                status = ResponseStatus.SUCCESS,
                routingDecision = orchestrationMeta.routingDecision,
                taskGraph = orchestrationMeta.taskGraph,
                skillInvocations = orchestrationMeta.skillInvocations,
                skillGapReport = orchestrationMeta.skillGap,
                skillRequirements = orchestrationMeta.skillRequirements,
                skillCandidates = orchestrationMeta.skillCandidates,
                skillAcquisitionDecisions = orchestrationMeta.skillAcquisitionDecisions,
                skillCanaryReports = orchestrationMeta.skillCanaryReports,
                skillPromotionRecords = orchestrationMeta.skillPromotionRecords
            )
        }
        if (isProductAgentsCommand(request.rawText)) {
            val catalog = ProductAgentCatalog.all()
            val liveCount = catalog.count { it.stage.equals("live", ignoreCase = true) }
            return AgentResponse(
                type = AgentResponseType.CARDS,
                cards = ProductAgentCatalog.governanceCards(limit = 10),
                summary = "Agent governance matrix ready: ${catalog.size} agents, with clear responsibility, activation timing, and authority scope.",
                appDeeplink = routeForModule(module, traceId),
                traceId = traceId,
                latencyMs = nowMs() - startMs,
                confidence = 0.92,
                module = module,
                payload = ModulePayload.MarketPayload(
                    candidateCount = catalog.size,
                    selectedCount = liveCount,
                    traceId = "product-agent-catalog"
                ),
                actions = defaultActions(module, request.rawText),
                status = ResponseStatus.SUCCESS,
                routingDecision = orchestrationMeta.routingDecision,
                taskGraph = orchestrationMeta.taskGraph,
                skillInvocations = orchestrationMeta.skillInvocations,
                skillGapReport = orchestrationMeta.skillGap,
                skillRequirements = orchestrationMeta.skillRequirements,
                skillCandidates = orchestrationMeta.skillCandidates,
                skillAcquisitionDecisions = orchestrationMeta.skillAcquisitionDecisions,
                skillCanaryReports = orchestrationMeta.skillCanaryReports,
                skillPromotionRecords = orchestrationMeta.skillPromotionRecords
            )
        }
        return null
    }

