    private fun pendingEscalationForUser(userId: String): LixEscalationContext? {
        val existing = pendingLixEscalations[userId] ?: return null
        if (nowMs() - existing.createdAtMs > PENDING_ESCALATION_TTL_MS) {
            pendingLixEscalations.remove(userId)
            return null
        }
        return existing
    }

    private fun mapExecutionStatus(raw: String?): ResponseStatus {
        return when (raw?.trim()?.lowercase()) {
            "processing" -> ResponseStatus.PROCESSING
            "running" -> ResponseStatus.RUNNING
            "waiting_user", "waiting", "needs_user" -> ResponseStatus.WAITING_USER
            "quoting", "quote", "collecting_quotes" -> ResponseStatus.QUOTING
            "auth_required", "authorization_required", "payment_required" -> ResponseStatus.AUTH_REQUIRED
            "verifying", "verification", "proof_check" -> ResponseStatus.VERIFYING
            "committed", "confirmed", "finalized" -> ResponseStatus.COMMITTED
            "partial" -> ResponseStatus.PARTIAL
            "rolled_back", "rollback", "reverted" -> ResponseStatus.ROLLED_BACK
            "disputed", "conflict" -> ResponseStatus.DISPUTED
            "cancelled", "canceled" -> ResponseStatus.CANCELLED
            "error", "failed", "failure" -> ResponseStatus.ERROR
            "success", "completed", "done" -> ResponseStatus.SUCCESS
            else -> ResponseStatus.SUCCESS
        }
    }

    private fun detectEscalationReason(
        request: AgentRequest,
        routingDecision: RoutingDecisionPayload,
        taskGraph: TaskGraphPayload,
        execution: AgentExecutionPayload,
        evidence: List<EvidenceItemPayload>,
        skillGap: SkillGapPayload?
    ): String? {
        if (routingDecision.mode != RoutingMode.MULTI_AGENT) return null

        val execStatus = mapExecutionStatus(execution.status)
        if (execStatus == ResponseStatus.ERROR) {
            return "openclaw_team_execution_failed"
        }
        if (execStatus == ResponseStatus.WAITING_USER) {
            return "constraints_or_confirmation_required"
        }
        if (skillGap?.recommendedAction == SkillGapRecommendation.ADD_SKILL) {
            return "market_skill_gap:${skillGap.missingCapability}"
        }
        if (taskGraph.tasks.size >= 3) {
            val successfulSkills = execution.skillInvocations.count { it.status == ResponseStatus.SUCCESS }
            if (successfulSkills < taskGraph.tasks.size) {
                return "skill_coverage_insufficient"
            }
        }
        if (evidence.isEmpty()) {
            return "no_verifiable_evidence"
        }
        if (!verifySolutionAgainstTwin(request.userId, execution.resultSummary, evidence)) {
            return "twin_validation_failed"
        }
        return null
    }

    private fun verifySolutionAgainstTwin(
        userId: String,
        resultSummary: String,
        evidence: List<EvidenceItemPayload>
    ): Boolean {
        if (resultSummary.isBlank()) return false
        val summaryLower = resultSummary.lowercase()
        if (
            summaryLower.contains("unable") ||
            summaryLower.contains("not available") ||
            summaryLower.contains("cannot")
        ) {
            return false
        }
        if (evidence.isEmpty()) return false

        val topTraits = soulStore.summary(userId).topTraits.associate { it.key to it.value }
        val riskAvoidance = topTraits.entries
            .firstOrNull { it.key.contains("risk_avoidance") }
            ?.value ?: 0.0
        val privacyAwareness = topTraits.entries
            .firstOrNull { it.key.contains("privacy_awareness") }
            ?.value ?: 0.0
        if (riskAvoidance >= 0.04 || privacyAwareness >= 0.04) {
            val highRiskWords = listOf("aggressive", "leverage", "speculative", "high risk")
            if (highRiskWords.any(summaryLower::contains)) {
                return false
            }
        }
        return true
    }

    private fun isUserRequestingLixEscalation(rawText: String, module: ModuleId): Boolean {
        if (module == ModuleId.LIX) return true
        val lower = rawText.lowercase()
        return lower.contains("lix") ||
            lower.contains("agent marketplace") ||
            lower.contains("agent market") ||
            lower.contains("builder") ||
            lower.contains("publish requirement") ||
            lower.contains("publish to market") ||
            lower.contains("发布需求") ||
            lower.contains("构建agent") ||
            lower.contains("构建skill")
    }

    private fun containsEscalationConstraintKeywords(rawText: String): Boolean {
        val lower = rawText.lowercase()
        return lower.contains("budget") ||
            lower.contains("deadline") ||
            lower.contains("acceptance criteria") ||
            lower.contains("acceptance") ||
            lower.contains("confirmation token") ||
            lower.contains("confirm token") ||
            lower.contains("user_confirmation_token") ||
            lower.contains("预算") ||
            lower.contains("时限") ||
            lower.contains("期限") ||
            lower.contains("验收标准") ||
            lower.contains("验收") ||
            lower.contains("确认令牌")
    }

    private fun shouldTreatAsEscalationIntent(rawText: String, module: ModuleId): Boolean {
        return isUserRequestingLixEscalation(rawText, module) ||
            isEscalationConfirmationReply(rawText) ||
            containsEscalationConstraintKeywords(rawText)
    }

    private fun isEscalationConfirmationReply(rawText: String): Boolean {
        val normalized = rawText.trim().lowercase()
        if (normalized.isBlank()) return false
        return normalized == "yes" ||
            normalized == "y" ||
            normalized == "ok" ||
            normalized == "okay" ||
            normalized == "sure" ||
            normalized == "proceed" ||
            normalized == "continue" ||
            normalized == "confirm" ||
            normalized == "同意" ||
            normalized == "确认" ||
            normalized == "继续" ||
            normalized == "可以" ||
            normalized == "好的" ||
            normalized == "是"
    }

    private fun isEscalationDeclineCommand(rawText: String): Boolean {
        val normalized = rawText.trim().lowercase()
        if (normalized.isBlank()) return false
        return normalized == "no" ||
            normalized == "n" ||
            normalized == "not now" ||
            normalized == "skip" ||
            normalized == "decline" ||
            normalized == "cancel" ||
            normalized == "不要" ||
            normalized == "不需要" ||
            normalized == "取消"
    }

    private fun isEscalationCancelCommand(rawText: String): Boolean {
        val lower = rawText.lowercase()
        return lower.contains("cancel escalation") ||
            lower.contains("stop escalation") ||
            lower.contains("取消升级") ||
            lower.contains("停止升级")
    }

    private fun extractBudgetForEscalation(rawText: String): String? {
        val lines = rawText
            .replace("\r", "")
            .lines()
            .map { it.trim() }
            .filter { it.isNotBlank() }
        val explicit = extractLixField(lines, "budget", "max budget", "price cap", "预算")
        if (!explicit.isNullOrBlank()) return explicit

        val inlineBudget = Regex(
            "(?i)(?:budget|预算)\\s*[:：]?\\s*([\\p{Sc}A-Za-z\\s]*\\d[\\d,\\.]*\\s*[A-Za-z]*)"
        ).find(rawText)?.groupValues?.getOrNull(1)?.trim()
        if (!inlineBudget.isNullOrBlank()) return inlineBudget

        val amount = Regex(
            "(?i)(?:[\\p{Sc}]\\s*)?\\d{2,8}(?:[\\.,]\\d{1,2})?\\s*(?:usd|gbp|eur|cny|rmb|k|m|千|万)?"
        ).find(rawText)?.value?.trim()
        return amount?.takeIf { it.any(Char::isDigit) }
    }

    private fun buildBudgetPromptEnhancement(
        request: AgentRequest,
        escalation: LixEscalationContext,
        reasonCode: String,
        missingFields: List<String> = emptyList()
    ): CloudEnhancement {
        val missingSummary = missingFields.joinToString(", ").ifBlank {
            "budget, deadline, acceptance_criteria"
        }
        return CloudEnhancement(
            cards = listOf(
                AgentCard(
                    id = "lix-budget-required",
                    title = "Constraints required for supplier escalation",
                    summary = "Current market coverage is insufficient. Please provide complete constraints before LIX publishing.",
                    deeplink = LumiRoutes.CHAT,
                    riskLevel = "medium"
                ),
                AgentCard(
                    id = "lix-budget-format",
                    title = "Reply format",
                    summary = "Budget: 5000 CNY; Deadline: 14 days; Acceptance criteria: evidence-backed plan; Confirmation token: CONFIRM-LIX-001",
                    deeplink = LumiRoutes.CHAT
                )
            ),
            summary = "OpenClaw decomposition is complete, but strict gates are blocking escalation. Missing fields: $missingSummary.",
            payload = ModulePayload.ChatPayload(
                suggestionTitle = "Awaiting constraints for LIX escalation",
                hints = listOf(
                    "Reason: $reasonCode",
                    "Missing: $missingSummary",
                    "Use 'cancel escalation' to stop this flow"
                ),
                taskTrack = TaskTrackBuilder.build(
                    module = ModuleId.CHAT,
                    query = request.rawText,
                    traceId = escalation.traceId,
                    phase = "lix_budget_required",
                    status = ResponseStatus.WAITING_USER,
                    evidenceItems = emptyList(),
                    nowMs = nowMs()
                )
            ),
            status = ResponseStatus.WAITING_USER
        )
    }

    private suspend fun continueEscalationOrPrompt(
        request: AgentRequest,
        cloudGateway: CloudGateway,
        escalation: LixEscalationContext,
        reasonCode: String,
        openClawHints: List<String>,
        resolvedRequestConstraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext
    ): CloudEnhancement {
        val requestConstraints = resolveRequestConstraints(request)
            .mergeWith(resolvedRequestConstraints)
            .withRoleContext(roleContext)
        val missingFields = missingRequiredConstraintFields(requestConstraints)
        if (missingFields.isNotEmpty()) {
            pendingLixEscalations[request.userId] = escalation
            return buildBudgetPromptEnhancement(
                request = request,
                escalation = escalation,
                reasonCode = reasonCode,
                missingFields = missingFields
            )
        }
        if (requestConstraints.userConfirmationToken.isNullOrBlank()) {
            pendingLixEscalations[request.userId] = escalation
            return buildBudgetPromptEnhancement(
                request = request,
                escalation = escalation,
                reasonCode = "confirmation_token_missing_for_spend_action",
                missingFields = listOf("user_confirmation_token")
            )
        }
        return publishEscalationToLix(
            request = request,
            cloudGateway = cloudGateway,
            escalation = escalation,
            requestConstraints = requestConstraints,
            openClawHints = openClawHints,
            roleContext = roleContext
        )
    }

    private suspend fun publishEscalationToLix(
        request: AgentRequest,
        cloudGateway: CloudGateway,
        escalation: LixEscalationContext,
        requestConstraints: AgentRequestConstraints,
        openClawHints: List<String>,
        roleContext: RoleExecutionContext
    ): CloudEnhancement {
        val budget = requestConstraints.budget.orEmpty()
        val deadline = requestConstraints.deadline.orEmpty()
        val acceptanceCriteria = requestConstraints.acceptanceCriteria.orEmpty()
        val confirmationToken = requestConstraints.userConfirmationToken.orEmpty()
        val budgetAmount = parseBudgetAmount(budget)
        if (budgetAmount != null && budgetAmount > MAX_ESCALATION_BUDGET) {
            return CloudEnhancement(
                cards = listOf(
                    AgentCard(
                        id = "lix-budget-exceeds-limit",
                        title = "Budget outside allowed range",
                        summary = "Provided budget exceeds safety threshold. Please confirm a bounded budget before publication.",
                        deeplink = LumiRoutes.CHAT,
                        riskLevel = "high"
                    )
                ),
                summary = "Escalation blocked by budget gate. Provide a bounded budget below ${MAX_ESCALATION_BUDGET.toInt()} to continue.",
                payload = ModulePayload.ChatPayload(
                    suggestionTitle = "Budget gate blocked escalation",
                    hints = listOf("Provided budget: $budget", "Allowed max: ${MAX_ESCALATION_BUDGET.toInt()}"),
                    taskTrack = TaskTrackBuilder.build(
                        module = ModuleId.CHAT,
                        query = escalation.originalQuery,
                        traceId = escalation.traceId,
                        phase = "lix_budget_blocked",
                        status = ResponseStatus.WAITING_USER,
                        evidenceItems = emptyList(),
                        nowMs = nowMs()
                    )
                ),
                status = ResponseStatus.WAITING_USER
            )
        }
        val publishQuery = buildString {
            append(escalation.originalQuery)
            append("\nBudget: ").append(budget)
            append("\nDeadline: ").append(deadline)
            append("\nAcceptance criteria: ").append(acceptanceCriteria)
            append("\nConfirmation token: ").append(confirmationToken)
            append("\nRequirement: personalized supplier plan aligned with user's digital twin.")
            if (escalation.twinProfilePrompt.isNotBlank()) {
                append("\n").append(escalation.twinProfilePrompt)
                append("\nUse the digital twin profile as a hard personalization signal when proposing options.")
            }
        }
        val requiredCapabilities = escalation.requiredCapabilities
            .ifEmpty { listOf("negotiation") }
            .distinct()
            .take(6)
        val broadcast = cloudGateway.lixBroadcast(
            query = publishQuery,
            domain = escalation.domain,
            requiredCapabilities = requiredCapabilities,
            reasoningTraceId = request.sessionId,
            overflowContext = LixOverflowContextPayload(
                mode = if (requiredCapabilities.size >= 3) "capability_auction" else "lumi_primary",
                overflowReason = "openclaw_team_escalation",
                complexity = 0.76,
                risk = 0.52,
                requiredCapabilities = requiredCapabilities.size,
                superAgentQueueDepth = 0
            ),
            dispatchPolicyVersion = "lix_1_6",
            preferPaidExpert = true
        )

        if (!broadcast.success) {
            return CloudEnhancement(
                cards = listOf(
                    AgentCard(
                        id = "lix-escalation-failed",
                        title = "LIX escalation failed",
                        summary = "Unable to publish to LIX market now: ${broadcast.errorCode ?: broadcast.error ?: "unknown"}",
                        deeplink = LumiRoutes.lixIntent("latest"),
                        riskLevel = "high"
                    )
                ),
                summary = "LIX publication failed. You can adjust budget/constraints and retry.",
                payload = ModulePayload.ChatPayload(
                    suggestionTitle = "Escalation retry required",
                    hints = listOf("Budget: $budget", "Retry after adjusting constraints"),
                    taskTrack = TaskTrackBuilder.build(
                        module = ModuleId.CHAT,
                        query = escalation.originalQuery,
                        traceId = broadcast.traceId,
                        phase = "lix_escalation_failed",
                        status = ResponseStatus.PARTIAL,
                        evidenceItems = emptyList(),
                        nowMs = nowMs()
                    )
                ),
                status = ResponseStatus.PARTIAL
            )
        }

        val data = broadcast.data ?: LixSolutionPayload("", "created", 0)
        val offersResult = data.intentId.takeIf { it.isNotBlank() }?.let { cloudGateway.lixOffers(it) }
        val offers = offersResult?.data?.items.orEmpty()
        val twinContext = soulStore.toTwinContext(request.userId, request.locale)
        val activeRole = requestConstraints.activeRole ?: roleContext.activeRole
        val validations = offers.map { offer ->
            evaluateSupplierFit(
                offer = offer,
                twinContext = twinContext,
                budgetAmount = budgetAmount,
                activeRole = activeRole
            )
        }.sortedByDescending { it.fitScore }

        val matched = validations.firstOrNull { it.fitScore >= SUPPLIER_FIT_THRESHOLD }
        if (matched == null) {
            val negotiationEvidence = validations.take(3).map { evaluation ->
                EvidenceItemPayload(
                    source = "lix_supplier",
                    title = evaluation.offer.name,
                    snippet = "fit ${(evaluation.fitScore * 100).toInt()}% · ${evaluation.reasonSummary}"
                )
            }
            val topCandidate = validations.firstOrNull()?.offer?.name ?: "top supplier candidate"
            val interimEvidence = buildInterimFallbackEvidence(
                domain = escalation.domain,
                topCandidate = topCandidate,
                budget = budget,
                deadline = deadline,
                acceptanceCriteria = acceptanceCriteria,
                userQuery = escalation.originalQuery,
                userId = request.userId,
                locale = request.locale
            )
            val combinedEvidence = (negotiationEvidence + interimEvidence).distinctBy { "${it.source}:${it.title}:${it.snippet}" }
            val negotiation = cloudGateway.lixExecutor(
                query = buildString {
                    append("Negotiate with supplier agents for personalized plan: ${escalation.originalQuery} | Budget: $budget")
                    if (escalation.twinProfilePrompt.isNotBlank()) {
                        append(" | ").append(escalation.twinProfilePrompt)
                    }
                },
                domain = escalation.domain
            )
            pendingLixEscalations[request.userId] = escalation.copy(
                traceId = broadcast.traceId,
                createdAtMs = nowMs()
            )
            return CloudEnhancement(
                cards = listOf(
                    AgentCard(
                        id = "lix-escalation-intent-${data.intentId.ifBlank { "latest" }}",
                        title = "Intent published to LIX market",
                        summary = "Lumio agent is negotiating with supplier agents for a better personalized fit.",
                        deeplink = LumiRoutes.lixIntent(data.intentId.ifBlank { "latest" }),
                        riskLevel = "medium"
                    )
                ),
                summary = if (negotiation.success) {
                    buildInterimFallbackSummary(
                        domain = escalation.domain,
                        topCandidate = topCandidate,
                        budget = budget,
                        deadline = deadline,
                        acceptanceCriteria = acceptanceCriteria,
                        userQuery = escalation.originalQuery,
                        userId = request.userId,
                        locale = request.locale
                    )
                } else {
                    "No validated supplier yet, and negotiation call failed. Please refine budget/constraints and retry."
                },
                payload = ModulePayload.ChatPayload(
                    suggestionTitle = "Interim executable plan ready",
                    hints = buildInterimFallbackHints(
                        domain = escalation.domain,
                        topCandidate = topCandidate,
                        budget = budget,
                        deadline = deadline,
                        acceptanceCriteria = acceptanceCriteria,
                        userQuery = escalation.originalQuery,
                        offerCount = offers.size,
                        userId = request.userId,
                        locale = request.locale
                    ) + listOfNotNull(
                        escalation.twinProfilePrompt.takeIf { it.isNotBlank() }?.let { "Twin signals applied: ${it.take(84)}" }
                    ) + openClawHints.take(2),
                    taskTrack = TaskTrackBuilder.build(
                        module = ModuleId.CHAT,
                        query = escalation.originalQuery,
                        traceId = broadcast.traceId,
                        phase = "lix_supplier_negotiation",
                        status = if (negotiation.success) ResponseStatus.WAITING_USER else ResponseStatus.PARTIAL,
                        evidenceItems = combinedEvidence,
                        nowMs = nowMs()
                    ),
                    evidenceItems = combinedEvidence
                ),
                status = if (negotiation.success) ResponseStatus.WAITING_USER else ResponseStatus.PARTIAL
            )
        }

        val accept = if (data.intentId.isNotBlank()) {
            cloudGateway.lixAcceptOffer(data.intentId, matched.offer.id)
        } else {
            null
        }
        pendingLixEscalations.remove(request.userId)
        val supplierEvidence = validations.take(3).map { evaluation ->
            EvidenceItemPayload(
                source = "lix_supplier",
                title = evaluation.offer.name,
                snippet = "fit ${(evaluation.fitScore * 100).toInt()}% · ${evaluation.reasonSummary}"
            )
        }
        val finalLifecycleStatus = when {
            accept == null -> ResponseStatus.VERIFYING
            accept.success -> ResponseStatus.COMMITTED
            else -> ResponseStatus.DISPUTED
        }
        return CloudEnhancement(
            cards = buildList {
                add(
                    AgentCard(
                        id = "lix-escalation-intent-${data.intentId.ifBlank { "latest" }}",
                        title = "Supplier solution validated",
                        summary = "Top supplier ${matched.offer.name} passed digital-twin validation (${(matched.fitScore * 100).toInt()}%).",
                        deeplink = LumiRoutes.lixIntent(data.intentId.ifBlank { "latest" }),
                        riskLevel = if (matched.fitScore >= 0.75) "low" else "medium"
                    )
                )
                validations.take(2).forEachIndexed { index, eval ->
                    add(
                        AgentCard(
                            id = "lix-supplier-rank-${index + 1}",
                            title = eval.offer.name,
                            summary = "Fit ${(eval.fitScore * 100).toInt()}% · ${eval.reasonSummary}",
                            deeplink = LumiRoutes.lixIntent(data.intentId.ifBlank { "latest" })
                        )
                    )
                }
            },
            summary = "OpenClaw team delivered and Lumio completed supplier validation. Best personalized solution is ready.",
            payload = ModulePayload.ChatPayload(
                suggestionTitle = "LIX supplier validated by digital twin",
                hints = listOfNotNull(
                    "Budget: $budget",
                    "Deadline: $deadline",
                    "Selected supplier: ${matched.offer.name}",
                    if (accept?.success == true) "Offer accepted in LIX flow" else "Review and accept in LIX page",
                    escalation.twinProfilePrompt.takeIf { it.isNotBlank() }?.let { "Twin signals applied: ${it.take(84)}" }
                ) + openClawHints.take(2),
                taskTrack = TaskTrackBuilder.build(
                    module = ModuleId.CHAT,
                    query = escalation.originalQuery,
                    traceId = broadcast.traceId,
                    phase = "lix_supplier_validated",
                    status = finalLifecycleStatus,
                    evidenceItems = supplierEvidence,
                    nowMs = nowMs()
                ),
                evidenceItems = supplierEvidence
            ),
            status = finalLifecycleStatus
        )
    }

    private fun buildIntentContract(
        goal: String,
        constraints: AgentRequestConstraints,
        domain: String,
        roleContext: RoleExecutionContext
    ): IntentContract {
        val activeRole = constraints.activeRole ?: roleContext.activeRole
        val rolePolicy = roleContext.rolePolicyProfile
        val delegationMode = roleContext.delegationMode
        val roleImpactReasonCodes = mergeRoleReasonCodes(
            constraints.roleImpactReasonCodes,
            roleContext.canonicalRoleReasonCodes,
            roleContext.legacyRoleDetailReasons
        )
        val hard = buildList {
            constraints.budget?.takeIf { it.isNotBlank() }?.let { add("budget=$it") }
            constraints.deadline?.takeIf { it.isNotBlank() }?.let { add("deadline=$it") }
            constraints.acceptanceCriteria?.takeIf { it.isNotBlank() }?.let { add("acceptance=$it") }
            constraints.maxCostPerStep?.takeIf { it.isNotBlank() }?.let { add("max_cost_per_step=$it") }
            constraints.riskTolerance?.takeIf { it.isNotBlank() }?.let { add("risk_tolerance=$it") }
        }
        val soft = buildList {
            if (constraints.budget.isNullOrBlank()) add("prefer budget-safe options")
            if (constraints.deadline.isNullOrBlank()) add("prefer earlier ETA")
            if (constraints.acceptanceCriteria.isNullOrBlank()) add("prefer verifiable deliverables")
            rolePolicy.preferences.riskToleranceDefault
                ?.takeIf { it.isNotBlank() }
                ?.let { add("role_default_risk_tolerance=$it") }
            rolePolicy.preferences.maxCostPerStepDefault
                ?.takeIf { it.isNotBlank() }
                ?.let { add("role_default_max_cost_per_step=$it") }
            if (rolePolicy.preferences.trustedProviderTags.isNotEmpty()) {
                add("prefer_providers=${rolePolicy.preferences.trustedProviderTags.joinToString("|")}")
            }
            if (rolePolicy.preferences.blockedProviderTags.isNotEmpty()) {
                add("block_providers=${rolePolicy.preferences.blockedProviderTags.joinToString("|")}")
            }
            if (!rolePolicy.preferences.externalFulfillmentAllowed) {
                add("external_fulfillment=disabled_by_role_policy")
            } else {
                add("external_fulfillment_preference=${rolePolicy.preferences.externalFulfillmentPreference.name.lowercase()}")
            }
        }
        return IntentContract(
            goal = goal.ifBlank { "Fulfill user intent in domain=$domain" },
            activeRole = activeRole,
            roleSource = constraints.roleSource ?: roleContext.roleSource,
            roleChangeReason = constraints.roleChangeReason ?: roleContext.roleChangeReason,
            roleImpactReasonCodes = roleImpactReasonCodes,
            hardConstraints = hard,
            softPreferences = soft,
            budget = constraints.budget,
            deadline = constraints.deadline,
            dataScope = if (digitalTwinCloudSyncEnabled && rolePolicy.dataPolicy.cloudSyncAllowed) {
                rolePolicy.dataPolicy.sharingMode
            } else {
                "local_only"
            },
            approvalClass = when {
                constraints.userConfirmationToken.isNullOrBlank().not() -> "pre_confirmed"
                delegationMode == DelegationMode.AUTONOMOUS_WITHIN_POLICY -> "role_autonomous_within_policy"
                else -> "explicit_confirmation_required"
            },
            deliverableSchema = "final_output+steps+evidence+pricing+rollback",
            proofRequired = true,
            rollbackRule = "rollback_if_verification_fails_or_user_disputes",
            delegationMode = delegationMode
        )
    }

    private fun buildCapabilityCards(offers: List<AgentDiscoveryItem>): List<CapabilityCard> {
        return offers.take(8).map { offer ->
            val trusted = offer.summary.contains("trusted", ignoreCase = true) ||
                offer.id.startsWith("trusted:", ignoreCase = true)
            CapabilityCard(
                id = offer.id,
                name = offer.name,
                provider = readableOfferProvider(offer.id),
                description = offer.summary.take(220),
                priceEstimate = parseBudgetAmount(offer.summary)?.let { "¥${it.toInt()}" } ?: "not listed",
                eta = extractEtaLabel(offer.summary),
                riskLevel = deriveOfferRisk(offer.summary),
                proofMethod = "verification_link_and_evidence_snippet",
                rollbackTerms = "Dispute or rollback available when verification fails.",
                disputeTerms = "Dispute window available after delivery check.",
                providerTrustFit = if (trusted) "high" else "medium",
                rolePolicyFit = "pending",
                verificationUrl = offer.actionDeeplink,
                trusted = trusted
            )
        }
    }

    private fun buildQuotes(offers: List<AgentDiscoveryItem>): List<Quote> {
        return offers.take(8).map { offer ->
            val summaryLower = offer.summary.lowercase()
            val proofMethod = when {
                summaryLower.contains("no proof") || summaryLower.contains("proof unavailable") -> "none"
                summaryLower.contains("invoice") -> "invoice_and_verification_link"
                else -> "verification_link_and_evidence_snippet"
            }
            val rollbackTerms = when {
                summaryLower.contains("no rollback") -> "No rollback support declared."
                summaryLower.contains("rollback") -> "Rollback supported when verification fails."
                else -> "Rollback support requires dispute review."
            }
            val disputeTerms = when {
                summaryLower.contains("no dispute") -> "No dispute support declared."
                summaryLower.contains("dispute") -> "Dispute workflow available for mismatched outcomes."
                else -> "Dispute handling available through platform review."
            }
            Quote(
                quoteId = "quote-${offer.id}",
                capabilityId = offer.id,
                supplier = offer.name,
                price = parseBudgetAmount(offer.summary)?.let { "¥${it.toInt()}" } ?: "not listed",
                eta = extractEtaLabel(offer.summary),
                riskLevel = deriveOfferRisk(offer.summary),
                proofMethod = proofMethod,
                rollbackTerms = rollbackTerms,
                disputeTerms = disputeTerms,
                providerTrustFit = if (offer.summary.contains("trusted", ignoreCase = true) ||
                    offer.id.startsWith("trusted:", ignoreCase = true)
                ) {
                    "high"
                } else {
                    "medium"
                },
                rolePolicyFit = "pending",
                rolePolicyNotes = "Awaiting role-aware comparison.",
                providerDecision = ProviderDecisionStatus.PENDING,
                reasonCodes = listOf(RoleReasonCodes.ROLE_QUOTE_COLLECTED)
            )
        }
    }

    private fun defaultRollbackPolicy(intentId: String?): RollbackPolicy {
        val safeIntentId = intentId?.ifBlank { "latest" } ?: "latest"
        return RollbackPolicy(
            policyId = "rollback-$safeIntentId",
            triggerConditions = listOf(
                "proof_verification_failed",
                "delivered_outcome_mismatch",
                "policy_conflict_detected"
            ),
            disputeWindowHours = 24,
            rollbackSteps = listOf(
                "Freeze settlement and preserve evidence links.",
                "Revert committed state to pre-commit snapshot.",
                "Re-run quoting with tighter constraints if user approves."
            ),
            compensationRule = "Apply platform dispute and compensation terms for failed verified outcomes."
        )
    }

    private fun extractEtaLabel(summary: String): String {
        val lower = summary.lowercase()
        val hourMatch = Regex("""(\d{1,2})\s*h""").find(lower)?.groupValues?.getOrNull(1)?.toIntOrNull()
        if (hourMatch != null) return "${hourMatch}h"
        val dayMatch = Regex("""(\d{1,2})\s*d""").find(lower)?.groupValues?.getOrNull(1)?.toIntOrNull()
        if (dayMatch != null) return "${dayMatch}d"
        val minuteMatch = Regex("""(\d{1,3})\s*min""").find(lower)?.groupValues?.getOrNull(1)?.toIntOrNull()
        if (minuteMatch != null) return "${minuteMatch}m"
        return "unknown"
    }

    private fun deriveOfferRisk(summary: String): String {
        val lower = summary.lowercase()
        return when {
            lower.contains("high risk") || lower.contains("speculative") -> "high"
            lower.contains("verified") || lower.contains("trusted") -> "low"
            else -> "medium"
        }
    }

    private fun readableOfferProvider(offerId: String): String {
        return when {
            offerId.startsWith("ext:gh:") -> "github_market"
            offerId.startsWith("trusted:", ignoreCase = true) -> "trusted_catalog"
            else -> "external_market"
        }
    }

    private fun evaluateSupplierFit(
        offer: AgentDiscoveryItem,
        twinContext: com.lumi.coredomain.contract.TwinContext,
        budgetAmount: Double?,
        activeRole: UserRole
    ): SupplierFitEvaluation {
        val summaryLower = offer.summary.lowercase()
        var fit = if (offer.score > 0.0) offer.score.coerceIn(0.0, 1.0) else 0.55
        val reasons = mutableListOf<String>()

        val riskAvoidance = twinContext.topTraits
            .firstOrNull { it.key.contains("risk_avoidance") }
            ?.value ?: 0.0
        if (riskAvoidance >= 0.04) {
            val riskWords = listOf("aggressive", "high risk", "speculative")
            if (riskWords.any(summaryLower::contains)) {
                fit -= 0.22
                reasons += "risk profile mismatch"
            }
        }

        val offerPrice = parseBudgetAmount(offer.summary)
        if (budgetAmount != null && offerPrice != null && offerPrice > budgetAmount * 1.1) {
            fit -= 0.2
            reasons += "over budget"
        }
        if (
            summaryLower.contains("personalized") ||
            summaryLower.contains("custom") ||
            summaryLower.contains("tailored") ||
            summaryLower.contains("bespoke")
        ) {
            fit += 0.12
            reasons += "personalized response"
        }
        if (summaryLower.contains("evidence") || summaryLower.contains("verified")) {
            fit += 0.08
            reasons += "evidence-backed"
        }
        when (activeRole) {
            UserRole.BUYER -> {
                if (summaryLower.contains("rollback") || summaryLower.contains("dispute")) {
                    fit += 0.07
                    reasons += "buyer rollback/dispute protection"
                }
                if (summaryLower.contains("high risk") || summaryLower.contains("speculative")) {
                    fit -= 0.12
                    reasons += "buyer role risk penalty"
                }
            }

            UserRole.TRAVELER -> {
                val eta = extractEtaLabel(offer.summary)
                if (eta.endsWith("m") || eta.endsWith("h")) {
                    fit += 0.05
                    reasons += "traveler ETA preference"
                }
                if (summaryLower.contains("real-time") || summaryLower.contains("live")) {
                    fit += 0.04
                    reasons += "traveler live-data fit"
                }
            }

            UserRole.WORK -> {
                if (summaryLower.contains("verified") || summaryLower.contains("traceable")) {
                    fit += 0.05
                    reasons += "work role auditability preference"
                }
            }

            UserRole.PARENT -> {
                if (summaryLower.contains("high risk") || summaryLower.contains("speculative")) {
                    fit -= 0.18
                    reasons += "parent role safety boundary"
                }
            }

            UserRole.PERSONAL, UserRole.CUSTOM -> Unit
        }

        val clipped = fit.coerceIn(0.0, 1.0)
        return SupplierFitEvaluation(
            offer = offer,
            fitScore = clipped,
            reasonSummary = reasons.joinToString(", ").ifBlank { "general fit evaluation" }
        )
    }

    private fun parseBudgetAmount(raw: String): Double? {
        val token = Regex("""(\d{1,9}(?:[.,]\d{1,2})?)""")
            .find(raw)
            ?.groupValues
            ?.getOrNull(1)
            ?.replace(",", "")
            ?: return null
        return token.toDoubleOrNull()
    }

    private fun normalizeConfirmationToken(raw: String): String {
        val match = Regex("""[A-Za-z0-9][A-Za-z0-9._-]{3,}""")
            .find(raw.trim())
            ?.value
        return (match ?: raw).trim().trim(' ', ';', ',', '.', ':')
    }

    private fun buildTwinProfilePrompt(userId: String, locale: String): String {
        val twin = soulStore.toTwinContext(userId, locale)
        val summary = soulStore.summary(userId)
        if (twin.topTraits.isEmpty()) {
            return "Digital twin profile unavailable; use explicit user constraints only. Request missing preferences directly from the user."
        }
        val traits = twin.topTraits
            .take(6)
            .joinToString(", ") { trait ->
                val normalized = normalizeTwinTraitScore(trait.value)
                "${trait.key}=${"%.2f".format(normalized)}"
            }
        val directives = buildTwinPersonalizationDirectives(twin.topTraits)
        return buildString {
            append("Digital twin profile: label=${summary.profileLabel}; locale=${twin.locale}; traits={$traits}.")
            if (directives.isNotEmpty()) {
                append("\nTwin personalization directives: ")
                append(directives.joinToString("; "))
                append(".")
            }
            append("\nHard requirement: treat digital twin as personalization-only context from the edge model (preferences + current state), not as a source of fabricated requirements.")
            append("\nHard requirement: current task constraints override long-term digital twin preferences for this run.")
            append("\nHard requirement: rank and explain options using digital twin signals before generic defaults.")
        }
    }

    private fun normalizeTwinTraitScore(raw: Double): Double {
        return if (raw > 1.0) {
            (raw / 10.0).coerceIn(0.0, 1.0)
        } else {
            raw.coerceIn(0.0, 1.0)
        }
    }

    private fun buildTwinPersonalizationDirectives(
        traits: List<com.lumi.coredomain.contract.TraitScore>
    ): List<String> {
        if (traits.isEmpty()) return emptyList()
        val normalizedMap = traits.associate { trait ->
            trait.key.lowercase() to normalizeTwinTraitScore(trait.value)
        }
        val directives = mutableListOf<String>()
        val riskAvoidance = normalizedMap["risk_avoidance"] ?: 0.0
        val planning = normalizedMap["planning"] ?: 0.0
        val execution = maxOf(normalizedMap["execution"] ?: 0.0, normalizedMap["task_commitment"] ?: 0.0)
        val privacy = normalizedMap["privacy_awareness"] ?: 0.0
        val precision = normalizedMap["precision"] ?: 0.0
        val exploration = normalizedMap["exploration"] ?: 0.0

        if (riskAvoidance >= 0.35) directives += "prefer refundable and lower-risk options first"
        if (planning >= 0.35) directives += "return a day-by-day sequence with clear time windows"
        if (execution >= 0.35) directives += "prioritize actionable steps with direct links"
        if (privacy >= 0.35) directives += "avoid sharing sensitive details and prefer trusted providers"
        if (precision >= 0.35) directives += "include concrete times, prices, and acceptance checks"
        if (exploration >= 0.35) directives += "offer one conservative and one exploratory alternative"

        if (directives.isNotEmpty()) return directives.take(4)

        return traits
            .sortedByDescending { normalizeTwinTraitScore(it.value) }
            .take(2)
            .map { trait ->
                val traitLabel = trait.key.replace('_', ' ')
                "optimize decision ranking for $traitLabel"
            }
    }

    private fun buildTwinAwareTask(
        rawTask: String,
        userId: String,
        locale: String,
        constraints: AgentRequestConstraints
    ): String {
        val prompt = buildTwinProfilePrompt(userId, locale)
        val constraintOverrideClause = buildConstraintOverrideClause(constraints)
        return buildString {
            append(rawTask.trim())
            append("\n")
            append(prompt)
            append("\n")
            append("Cloud responsibility: reason first, decompose into subtasks, assign sub-agents and skills, execute, then synthesize one final user-facing result.")
            append("\n")
            append("Edge responsibility: provide digital twin preference + current state signals only; do not let edge heuristics decide the final content.")
            append("\n")
            append("Use digital twin signals to personalize option ranking, execution order, and risk/budget trade-offs.")
            append("\n")
            append(constraintOverrideClause)
            append("\n")
            append("Do not fabricate user requirements. If key preferences are missing, ask the user directly and mark them as pending.")
            append("\n")
            append("Output contract: include Final Output, Action Steps, Action Links, Evidence, Risks, Fallback, Next Action.")
            append("\n")
            append("Every SUCCESS claim must map to evidence. Never return empty output.")
        }.trim()
    }

    private fun buildConstraintOverrideClause(constraints: AgentRequestConstraints): String {
        val activeRole = constraints.activeRole ?: UserRole.PERSONAL
        val activeConstraints = buildList {
            constraints.budget?.takeIf { it.isNotBlank() }?.let { add("budget=$it") }
            constraints.deadline?.takeIf { it.isNotBlank() }?.let { add("deadline=$it") }
            constraints.acceptanceCriteria?.takeIf { it.isNotBlank() }?.let { add("acceptance=$it") }
            constraints.maxCostPerStep?.takeIf { it.isNotBlank() }?.let { add("max_cost_per_step=$it") }
            constraints.riskTolerance?.takeIf { it.isNotBlank() }?.let { add("risk_tolerance=$it") }
        }
        return if (activeConstraints.isEmpty()) {
            "Constraint precedence rule: no explicit hard constraints provided yet; active role (${activeRole.name.lowercase()}) may suggest defaults, but ask follow-up questions before irreversible actions."
        } else {
            "Constraint precedence rule: apply explicit task constraints first (${activeConstraints.joinToString("; ")}), then active role policy (${activeRole.name.lowercase()}), then long-term twin preferences."
        }
    }

    private fun buildInterimFallbackSummary(
        domain: String,
        topCandidate: String,
        budget: String,
        deadline: String,
        acceptanceCriteria: String,
        userQuery: String,
        userId: String,
        locale: String
    ): String {
        val twinSignals = buildTwinPersonalizationDirectives(
            soulStore.toTwinContext(userId, locale).topTraits
        )
        return """
Cloud execution is temporarily degraded; returning a non-empty interim plan.
Interim Plan:
1. Keep this task in reversible mode with $topCandidate under budget ($budget).
2. Build a structured execution draft with owner, ETA, dependencies, and rollback before deadline ($deadline).
3. Validate each key claim against acceptance criteria: ${acceptanceCriteria.take(88)}.
4. Preserve strict gates and block irreversible actions until cloud verification recovers.
Task Domain:
- $domain
Query Preview:
- ${userQuery.take(96)}
Personalization Basis (Edge Digital Twin Signals):
${if (twinSignals.isNotEmpty()) twinSignals.joinToString("\n") { "- $it" } else "- Twin signals currently limited; using neutral ranking."}
Missing Inputs Policy:
- Do not infer missing requirements. Ask the user directly when constraints are incomplete.
Fallback:
- Continue cloud retry in background and refresh this plan with cloud-synthesized output once available.
Next Action:
- Confirm the highest-priority outcome to narrow execution scope in the next run.
        """.trimIndent()
    }

    private fun buildInterimFallbackHints(
        domain: String,
        topCandidate: String,
        budget: String,
        deadline: String,
        acceptanceCriteria: String,
        userQuery: String,
        offerCount: Int,
        userId: String,
        locale: String
    ): List<String> {
        val twinSignals = buildTwinPersonalizationDirectives(
            soulStore.toTwinContext(userId, locale).topTraits
        )
        val base = mutableListOf(
            "Budget: $budget",
            "Deadline: $deadline",
            "Acceptance: ${acceptanceCriteria.take(48)}",
            "Matched suppliers: 0/$offerCount",
            "Top candidate: $topCandidate",
            "Interim action: execute reversible steps only",
            "Domain: $domain",
            "Cloud-first orchestration: enabled",
            "Edge role: twin preference/state signals only",
            "Query preview: ${userQuery.take(48)}"
        )
        if (twinSignals.isNotEmpty()) {
            base += "Twin signals: ${twinSignals.joinToString("; ").take(120)}"
        }
        return base
    }

    private fun buildInterimFallbackEvidence(
        domain: String,
        topCandidate: String,
        budget: String,
        deadline: String,
        acceptanceCriteria: String,
        userQuery: String,
        userId: String,
        locale: String
    ): List<EvidenceItemPayload> {
        val twinSignals = buildTwinPersonalizationDirectives(
            soulStore.toTwinContext(userId, locale).topTraits
        )
        val evidence = mutableListOf(
            EvidenceItemPayload(
                source = "interim_plan",
                title = "Pilot execution scope",
                snippet = "Top candidate: $topCandidate · domain=$domain · budget=$budget · deadline=$deadline"
            ),
            EvidenceItemPayload(
                source = "interim_plan",
                title = "Acceptance mapping",
                snippet = "Criteria mapped for validation: ${acceptanceCriteria.take(88)}"
            ),
            EvidenceItemPayload(
                source = "interim_plan",
                title = "Risk boundary",
                snippet = "Only reversible actions are allowed before supplier validation passes."
            ),
            EvidenceItemPayload(
                source = "interim_plan",
                title = "Cloud-first degradation notice",
                snippet = "Cloud reasoning path degraded; interim plan is temporary and awaits cloud synthesis recovery. Query: ${userQuery.take(88)}"
            )
        )
        evidence += EvidenceItemPayload(
            source = "digital_twin",
            title = "Twin personalization basis",
            snippet = if (twinSignals.isNotEmpty()) {
                twinSignals.joinToString("; ").take(220)
            } else {
                "Twin profile has limited signals; neutral ranking applied."
            }
        )
        evidence += EvidenceItemPayload(
            source = "user_input",
            title = "No fabricated requirements",
            snippet = "Missing constraints must be asked directly from the user before final execution."
        )
        return evidence
    }

