    private fun extractTravelRouteHint(userQuery: String): TravelRouteHint {
        val normalized = userQuery
            .replace('\n', ' ')
            .replace(Regex("\\s+"), " ")
            .trim()
        val explicitFromTo = Regex(
            pattern = """(?i)\bfrom\s+([a-z][a-z\s]{1,40}?)\s+to\s+([a-z][a-z\s]{1,40}?)(?=\s+(?:on|for|budget|deadline|acceptance|confirmation|token|hard|do|must|$)|[,.])"""
        ).find(normalized)
        val simpleTo = Regex(
            pattern = """(?i)\b([a-z][a-z\s]{1,32}?)\s+to\s+([a-z][a-z\s]{1,40}?)(?=\s+(?:from|on|for|budget|deadline|acceptance|confirmation|token|$)|[,.])"""
        ).find(normalized)

        val originRaw = explicitFromTo?.groupValues?.getOrNull(1)
            ?: simpleTo?.groupValues?.getOrNull(1)
        val destinationRaw = explicitFromTo?.groupValues?.getOrNull(2)
            ?: simpleTo?.groupValues?.getOrNull(2)

        var origin = cleanRouteToken(originRaw)
            ?: if (normalized.contains("london", ignoreCase = true)) "London" else ""
        val destination = cleanRouteToken(destinationRaw)
            ?: when {
                normalized.contains("jersey island", ignoreCase = true) -> "Jersey Island (JER)"
                normalized.contains("jersey", ignoreCase = true) || normalized.contains(" JER ", ignoreCase = true) -> "Jersey (JER)"
                else -> ""
            }
        if (origin.equals(destination, ignoreCase = true) && normalized.contains("london", ignoreCase = true)) {
            origin = if (destination.contains("jersey", ignoreCase = true)) "London" else ""
        }

        val stayNights = Regex("""(?i)\b(\d+)\s*night(?:s)?\b""")
            .find(normalized)
            ?.groupValues
            ?.getOrNull(1)
            ?.toIntOrNull()
            ?.takeIf { it in 1..30 }
            ?: when {
                normalized.contains("one-week", ignoreCase = true) || normalized.contains("one week", ignoreCase = true) -> 7
                normalized.contains("7-day", ignoreCase = true) || normalized.contains("7 day", ignoreCase = true) -> 7
                else -> null
            }
        val stayNightsLabel = stayNights?.let { "${it}-night" }
        return TravelRouteHint(origin = origin, destination = destination, stayNightsLabel = stayNightsLabel)
    }

    private fun cleanRouteToken(raw: String?): String? {
        if (raw.isNullOrBlank()) return null
        val stopWords = setOf(
            "travel",
            "traveler",
            "itinerary",
            "flight",
            "agent",
            "skill",
            "market",
            "builder",
            "request",
            "requirement",
            "task",
            "query",
            "for",
            "with",
            "use",
            "run",
            "execute",
            "plan",
            "trip",
            "round",
            "roundtrip",
            "round-trip",
            "build",
            "realistic",
            "a",
            "an",
            "the",
            "from",
            "to",
            "next",
            "week",
            "monday",
            "tuesday",
            "wednesday",
            "thursday",
            "friday",
            "saturday",
            "sunday",
            "mon",
            "tue",
            "wed",
            "thu",
            "fri",
            "sat",
            "sun"
        )
        val cleaned = raw
            .replace(Regex("""\bmust\b.*$""", RegexOption.IGNORE_CASE), "")
            .trim()
        if (cleaned.isBlank()) return null
        val words = cleaned.split(" ")
            .map { it.trim() }
            .filter { it.isNotBlank() }
            .dropWhile { token -> stopWords.contains(token.lowercase()) }
            .take(4)
        if (words.isEmpty()) return null
        val loweredWords = words.map { it.lowercase() }
        if (loweredWords.any { it.contains("london") }) return "London"
        if (loweredWords.any { it.contains("jersey") }) {
            return if (loweredWords.any { it == "island" }) {
                "Jersey Island (JER)"
            } else {
                "Jersey (JER)"
            }
        }
        if (loweredWords.all { parseWeekday(it) != null }) return null
        if (loweredWords.any { it == "round" || it == "trip" || it == "roundtrip" || it == "round-trip" }) {
            return null
        }
        return words.joinToString(" ") { token ->
            token.lowercase().replaceFirstChar { it.uppercase() }
        }
    }

    private fun extractTravelDateWindow(userQuery: String): TravelDateWindowHint {
        val normalized = userQuery.lowercase()
        val dayPattern = Regex(
            """\b(mon(?:day)?|tue(?:sday)?|wed(?:nesday)?|thu(?:rsday)?|fri(?:day)?|sat(?:urday)?|sun(?:day)?)\s*(?:-|to|until|through|~|–)\s*(mon(?:day)?|tue(?:sday)?|wed(?:nesday)?|thu(?:rsday)?|fri(?:day)?|sat(?:urday)?|sun(?:day)?)\b""",
            RegexOption.IGNORE_CASE
        )
        val range = dayPattern.find(normalized)
        if (range != null) {
            val startDay = parseWeekday(range.groupValues.getOrNull(1))
            val endDay = parseWeekday(range.groupValues.getOrNull(2))
            if (startDay != null && endDay != null) {
                val forceNextWeek = normalized.contains("next week")
                val startDate = nextWeekday(startDay, forceNextWeek)
                var endDate = nextWeekday(endDay, forceNextWeek)
                if (endDate.isBefore(startDate)) {
                    endDate = endDate.plusWeeks(1)
                }
                return TravelDateWindowHint(
                    startDate = startDate.toString(),
                    endDate = endDate.toString()
                )
            }
        }

        val withoutDeadlineDate = userQuery.replace(
            Regex("""(?is)(?:deadline|时限|期限)\s*(?:[:：]|=)\s*20\d{2}-\d{2}-\d{2}"""),
            " "
        )
        val isoDates = Regex("""\b(20\d{2}-\d{2}-\d{2})\b""")
            .findAll(withoutDeadlineDate)
            .map { it.groupValues[1] }
            .toList()
        val explicitStart = isoDates.getOrNull(0)
        val explicitEnd = isoDates.getOrNull(1)
        if (!explicitStart.isNullOrBlank()) {
            return TravelDateWindowHint(
                startDate = explicitStart,
                endDate = explicitEnd ?: explicitStart
            )
        }

        val fallbackIsoDates = Regex("""\b(20\d{2}-\d{2}-\d{2})\b""")
            .findAll(userQuery)
            .map { it.groupValues[1] }
            .toList()
        if (fallbackIsoDates.size >= 2) {
            return TravelDateWindowHint(
                startDate = fallbackIsoDates[0],
                endDate = fallbackIsoDates[1]
            )
        }
        return TravelDateWindowHint(startDate = null, endDate = null)
    }

    private fun parseWeekday(raw: String?): DayOfWeek? {
        if (raw.isNullOrBlank()) return null
        val token = raw.trim().lowercase()
        return when {
            token.startsWith("mon") -> DayOfWeek.MONDAY
            token.startsWith("tue") -> DayOfWeek.TUESDAY
            token.startsWith("wed") -> DayOfWeek.WEDNESDAY
            token.startsWith("thu") -> DayOfWeek.THURSDAY
            token.startsWith("fri") -> DayOfWeek.FRIDAY
            token.startsWith("sat") -> DayOfWeek.SATURDAY
            token.startsWith("sun") -> DayOfWeek.SUNDAY
            else -> null
        }
    }

    private fun nextWeekday(day: DayOfWeek, forceNextWeek: Boolean): LocalDate {
        val today = Instant.ofEpochMilli(nowMs()).atZone(ZoneOffset.UTC).toLocalDate()
        var candidate = today
        while (candidate.dayOfWeek != day || candidate.isBefore(today)) {
            candidate = candidate.plusDays(1)
        }
        if (forceNextWeek && !candidate.isAfter(today.plusDays(6))) {
            candidate = candidate.plusWeeks(1)
        }
        return candidate
    }

    private fun buildTravelExecutionLinks(
        route: TravelRouteHint,
        dateWindow: TravelDateWindowHint,
        preferredArea: String,
        cuisinePreference: String,
        attractionPreference: String
    ): List<ActionLink> {
        val origin = route.origin.trim()
        val destination = route.destination.trim()
        val departDate = dateWindow.startDate ?: ""
        val returnDate = dateWindow.endDate ?: departDate
        val hotelSearchTarget = when {
            preferredArea.isNotBlank() -> preferredArea
            destination.isNotBlank() -> "$destination city center"
            else -> "city center hotels"
        }
        val cuisineTarget = when {
            cuisinePreference.isNotBlank() && destination.isNotBlank() -> "$cuisinePreference in $destination"
            cuisinePreference.isNotBlank() -> cuisinePreference
            destination.isNotBlank() -> "top rated restaurants in $destination"
            else -> "top rated restaurants"
        }
        val attractionTarget = when {
            attractionPreference.isNotBlank() && destination.isNotBlank() -> "$attractionPreference in $destination"
            attractionPreference.isNotBlank() -> attractionPreference
            destination.isNotBlank() -> "top attractions in $destination"
            else -> "top attractions"
        }
        val transportTarget = when {
            destination.isNotBlank() && preferredArea.isNotBlank() -> "transport from ${destination} airport to $preferredArea"
            destination.isNotBlank() -> "transport from ${destination} airport to city center"
            else -> "airport to city center transport"
        }
        val flightQuery = buildString {
            when {
                origin.isNotBlank() && destination.isNotBlank() -> append("Flights from $origin to $destination")
                destination.isNotBlank() -> append("Flights to $destination")
                else -> append("Flight options")
            }
            if (departDate.isNotBlank()) append(" $departDate")
            if (returnDate.isNotBlank()) append(" return $returnDate")
        }
        return listOf(
            ActionLink(
                title = "Flight options (Google Flights)",
                url = "https://www.google.com/travel/flights?q=${urlEncode(flightQuery)}"
            ),
            ActionLink(
                title = "Hotel options (Booking)",
                url = "https://www.booking.com/searchresults.en-gb.html?ss=${urlEncode(hotelSearchTarget)}"
            ),
            ActionLink(
                title = "Restaurant shortlist (Google Maps)",
                url = "https://www.google.com/maps/search/?api=1&query=${urlEncode(cuisineTarget)}"
            ),
            ActionLink(
                title = "Attractions shortlist (Google Maps)",
                url = "https://www.google.com/maps/search/?api=1&query=${urlEncode(attractionTarget)}"
            ),
            ActionLink(
                title = "Local transport (Google Maps)",
                url = "https://www.google.com/maps/search/?api=1&query=${urlEncode(transportTarget)}"
            )
        )
    }

