            ),
            TravelNamedOption(
                title = "Hotel A · The Royal Yacht",
                url = "https://www.google.com/maps/search/?api=1&query=${urlEncode("The Royal Yacht Jersey")}"
            ),
            TravelNamedOption(
                title = "Hotel B · Pomme d'Or Hotel",
                url = "https://www.google.com/maps/search/?api=1&query=${urlEncode("Pomme d'Or Hotel Jersey")}"
            ),
