    private fun ensureVerifiedTravelActionLinks(links: List<ActionLink>): List<ActionLink> {
        val verified = links.mapNotNull { link ->
            val verifiedUrl = verifiedExternalUrlOrNull(link.url) ?: return@mapNotNull null
            link.copy(url = verifiedUrl)
        }
        return verified
    }

    private fun ensureVerifiedTravelNamedOptions(options: List<TravelNamedOption>): List<TravelNamedOption> {
        val verified = options.mapNotNull { option ->
            val verifiedUrl = verifiedExternalUrlOrNull(option.url) ?: return@mapNotNull null
            option.copy(url = verifiedUrl)
        }
        return verified
    }

    private fun renderActionLinksSection(links: List<ActionLink>): String {
        if (links.isEmpty()) {
            return "- No verified external link is available yet. Please rerun verification."
        }
        return links.joinToString("\n") { link -> "- ${link.title}: ${link.url}" }
    }

    private fun extractPreferenceHint(userQuery: String, labels: List<String>): String? {
        val pattern = Regex(
            pattern = """(?i)\b(?:${labels.joinToString("|") { Regex.escape(it) }})\b\s*[:：]?\s*(.+?)(?=\b(?:budget|deadline|acceptance|confirmation|token|proceed|do not|fallback)\b|$)"""
        )
        val raw = pattern.find(userQuery)?.groupValues?.getOrNull(1)?.trim() ?: return null
        return raw
            .trim(' ', '.', ',', ';', ':')
            .takeIf { it.isNotBlank() }
    }

    private fun resolveTravelPreferenceContext(
        userQuery: String,
        userId: String,
        locale: String
    ): TravelPreferenceContext {
        val preferredAirline = extractPreferenceHint(
            userQuery = userQuery,
            labels = listOf("preferred airline", "airline")
        )
        val preferredArea = extractPreferenceHint(
            userQuery = userQuery,
            labels = listOf("preferred hotel area", "hotel area", "stay area")
        )
        val cuisinePreference = extractPreferenceHint(
            userQuery = userQuery,
            labels = listOf("preferred cuisine", "food preference", "cuisine", "restaurant style")
        )
        val attractionPreference = extractPreferenceHint(
            userQuery = userQuery,
            labels = listOf("attraction preference", "sightseeing style", "interest", "must-see")
        )
        val missing = mutableListOf<String>()
        if (preferredAirline.isNullOrBlank()) missing += "preferred airline"
        if (preferredArea.isNullOrBlank()) missing += "preferred hotel area"
        if (cuisinePreference.isNullOrBlank()) missing += "preferred cuisine"
        if (attractionPreference.isNullOrBlank()) missing += "attraction preference"

        val twinTraits = soulStore.toTwinContext(userId, locale).topTraits
        val twinSignals = buildTwinPersonalizationDirectives(twinTraits).ifEmpty {
            listOf("optimize ranking using available twin traits only")
        }

        return TravelPreferenceContext(
            preferredAirline = preferredAirline,
            preferredArea = preferredArea,
            cuisinePreference = cuisinePreference,
            attractionPreference = attractionPreference,
            preferredAreaForLinks = preferredArea ?: "city center",
            cuisineForLinks = cuisinePreference ?: "top rated restaurants",
            attractionForLinks = attractionPreference ?: "top attractions",
            missingUserInputs = missing,
            twinSignals = twinSignals
        )
    }

    private fun parseLixPublishContext(rawText: String, intent: IntentType): LixPublishContext {
        val lines = rawText
            .replace("\r", "")
            .lines()
            .map { it.trim() }
            .filter { it.isNotBlank() }

        val need = extractLixField(lines, "request", "request description", "user request", "query", "需求", "请求")
        val goal = extractLixField(lines, "goal", "business goal", "目标")
        val budget = extractLixField(lines, "budget", "预算")
        val deadline = extractLixField(lines, "deadline", "completion deadline", "时限", "期限")
        val customDomain = extractLixField(lines, "domain", "industry", "scenario", "领域", "行业", "场景")
        val resolvedDomain = mapLixDomainHint(customDomain).ifBlank { inferLixDomain(intent) }

        val query = buildString {
            append(need ?: rawText)
            if (!goal.isNullOrBlank()) append("；goal: $goal")
            if (!budget.isNullOrBlank()) append("；budget: $budget")
            if (!deadline.isNullOrBlank()) append("；deadline: $deadline")
        }.trim().ifBlank { rawText }

        val requiredCapabilities = (
            requiredCapabilitiesForIntent(intent) +
                inferLixCapabilities(query, resolvedDomain)
            ).distinct().take(4)

        return LixPublishContext(
            query = query,
            domain = resolvedDomain,
            requiredCapabilities = requiredCapabilities
        )
    }

    private fun extractLixField(lines: List<String>, vararg keys: String): String? {
        val pattern = Regex(
            "^\\s*(${keys.joinToString("|") { Regex.escape(it) }})\\s*(?:[:：]|=)\\s*(.+)\\s*$",
            RegexOption.IGNORE_CASE
        )
        val match = lines.firstNotNullOfOrNull { line ->
            pattern.find(line)?.groupValues?.getOrNull(2)?.trim()
        } ?: return null
        return match.takeIf { it.isNotBlank() }
    }

    private fun mapLixDomainHint(rawDomain: String?): String {
        val text = rawDomain?.trim()?.lowercase().orEmpty()
        if (text.isBlank()) return ""
        return when {
            text.contains("travel") || text.contains("flight") || text.contains("hotel") || text.contains("旅行") || text.contains("出行") -> "travel"
            text.contains("recruit") || text.contains("recruitment") || text.contains("position") || text.contains("招聘") -> "recruitment"
            text.contains("local") || text.contains("life") || text.contains("restaurant") || text.contains("本地") || text.contains("生活") -> "local_service"
            text.contains("shop") || text.contains("shopping") || text.contains("ecommerce") -> "shopping"
            text.contains("knowledge") || text.contains("consulting") -> "knowledge"
            else -> "general"
        }
    }

    private fun inferLixCapabilities(query: String, domain: String): List<String> {
        val text = query.lowercase()
        val caps = mutableListOf<String>()
        if (domain == "travel" || text.contains("flight") || text.contains("机票")) caps += "flight_search"
        if (domain == "travel" || text.contains("hotel") || text.contains("酒店")) caps += "hotel_search"
        if (domain == "travel" || text.contains("restaurant") || text.contains("餐厅") || text.contains("美食")) {
            caps += "restaurant_search"
        }
        if (domain == "travel" || text.contains("attraction") || text.contains("sightseeing") || text.contains("景点")) {
            caps += "attraction_search"
        }
        if (domain == "travel" || text.contains("transport") || text.contains("交通")) caps += "local_transport"
        if (domain == "travel" || text.contains("itinerary") || text.contains("行程")) caps += "itinerary_plan"
        if (domain == "recruitment" || text.contains("recruitment") || text.contains("position") || text.contains("招聘")) caps += "job_sourcing"
        if (domain == "recruitment" || text.contains("resume") || text.contains("简历")) caps += "resume_optimization"
        if (domain == "recruitment" || text.contains("salary") || text.contains("薪资")) caps += "salary_benchmark"
        if (domain == "local_service" || text.contains("restaurant") || text.contains("nearby") || text.contains("附近")) {
            caps += listOf("local_search", "live_search")
        }
        if (domain == "shopping" || text.contains("price compare") || text.contains("product") || text.contains("比价")) {
            caps += listOf("shopping_search", "price_compare")
        }
        if (text.contains("evidence") || text.contains("verification") || text.contains("证据") || text.contains("验证")) {
            caps += listOf("web_search", "live_search")
        }
        if (text.contains("execute") || text.contains("delivery") || text.contains("执行") || text.contains("交付")) {
            caps += "live_search"
        }
        caps += "negotiation"
        return caps.distinct()
    }

