    private fun extractGithubRepo(rawText: String): String? {
        return Regex("""([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)""")
            .find(rawText)
            ?.groupValues
            ?.getOrNull(1)
    }

    private fun extractManifestPath(rawText: String): String? {
        val explicitPath = Regex("""([./A-Za-z0-9_-]+\.json)""")
            .findAll(rawText)
            .mapNotNull { it.groupValues.getOrNull(1) }
            .firstOrNull { candidate ->
                val lower = candidate.lowercase()
                lower.contains("manifest") || lower.startsWith(".lix/")
            }
        return explicitPath?.takeIf { it.isNotBlank() }
    }

