    private fun requiredCapabilitiesForIntent(intent: IntentType): List<String> {
        return when (intent) {
            IntentType.TRAVEL -> listOf(
                "flight_search",
                "hotel_search",
                "restaurant_search",
                "attraction_search",
                "local_transport",
                "itinerary_plan"
            )
            IntentType.AGENT_MARKET -> listOf("agent_discovery")
            IntentType.LIX -> listOf("negotiation")
            else -> emptyList()
        }
    }

    private fun mergePayload(
        base: ModulePayload,
        enhancement: ModulePayload?,
        meta: OrchestrationMeta
    ): ModulePayload {
        val candidate = enhancement ?: base
        return if (candidate is ModulePayload.ChatPayload) {
            val baseChat = base as? ModulePayload.ChatPayload
            candidate.copy(
                routingDecision = candidate.routingDecision ?: meta.routingDecision,
                taskGraph = candidate.taskGraph ?: meta.taskGraph,
                skillInvocations = if (candidate.skillInvocations.isNotEmpty()) {
                    candidate.skillInvocations
                } else {
                    meta.skillInvocations
                },
                skillGap = candidate.skillGap ?: meta.skillGap,
                skillSelectionTrace = if (candidate.skillSelectionTrace.isNotEmpty()) {
                    candidate.skillSelectionTrace
                } else {
                    meta.skillSelectionTrace
                },
                reasoningProtocol = candidate.reasoningProtocol ?: baseChat?.reasoningProtocol
            )
        } else {
            candidate
        }
    }

    private fun buildOrchestrationMeta(
        request: AgentRequest,
        module: ModuleId,
        intent: IntentType,
        resolvedConstraints: AgentRequestConstraints,
        roleContext: RoleExecutionContext
    ): OrchestrationMeta {
        val routingConfig = routingScoreConfigProvider()
        val raw = request.rawText.lowercase()
        val requiredCapabilities = detectCapabilities(raw = raw, module = module, intent = intent)
        val domains = detectDomains(requiredCapabilities, module)
        val activeRole = roleContext.activeRole
        val crossDomainCount = domains.size.coerceAtLeast(1)
        val dependencyDepth = inferDependencyDepth(
            raw = raw,
            requiredCapabilityCount = requiredCapabilities.size,
            config = routingConfig
        )
        val riskScore = inferRiskScore(raw = raw, module = module, config = routingConfig)
        val evidenceRequired = riskScore >= routingConfig.thresholds.riskMin
        val explicitMultiAgent = routingConfig.explicitMultiAgentKeywords.any(raw::contains)

        val reasonCodes = mutableListOf<String>()
        var mode = RoutingMode.SINGLE_AGENT

        if (crossDomainCount >= routingConfig.thresholds.crossDomainMin) {
            mode = RoutingMode.MULTI_AGENT
            reasonCodes += "cross_domain_count>=${routingConfig.thresholds.crossDomainMin}"
        }
        if (requiredCapabilities.size >= routingConfig.thresholds.capabilitiesMin) {
            mode = RoutingMode.MULTI_AGENT
            reasonCodes += "required_capabilities>=${routingConfig.thresholds.capabilitiesMin}"
        }
        if (dependencyDepth >= routingConfig.thresholds.dependencyMin) {
            mode = RoutingMode.MULTI_AGENT
            reasonCodes += "dependency_depth>=${routingConfig.thresholds.dependencyMin}"
        }
        val riskEscalate = riskScore >= routingConfig.thresholds.riskMin &&
            (!routingConfig.thresholds.requireEvidenceOnRisk || evidenceRequired)
        if (riskEscalate) {
            mode = RoutingMode.MULTI_AGENT
            reasonCodes += "risk_score>=${routingConfig.thresholds.riskMin}_and_evidence_required"
        }
        if (explicitMultiAgent) {
            mode = RoutingMode.MULTI_AGENT
            reasonCodes += "explicit_multi_agent_request"
        }
        val requiresLiveData = requiredCapabilities.any { capability ->
            capability.contains("live", ignoreCase = true) ||
                capability.contains("search", ignoreCase = true) ||
                capability.contains("flight", ignoreCase = true) ||
                capability.contains("hotel", ignoreCase = true) ||
                capability.contains("restaurant", ignoreCase = true) ||
                capability.contains("attraction", ignoreCase = true)
        } ||
            raw.contains("latest") ||
            raw.contains("real-time") ||
            raw.contains("realtime") ||
            raw.contains("实时")

        val complexityScore = (
            ((crossDomainCount - 1).coerceAtLeast(0) * routingConfig.complexityWeights.crossDomainWeight) +
                ((requiredCapabilities.size - 1).coerceAtLeast(0) * routingConfig.complexityWeights.capabilityWeight) +
                ((dependencyDepth - 1).coerceAtLeast(0) * routingConfig.complexityWeights.dependencyWeight)
            ).coerceIn(0.0, 1.0)

        if (mode == RoutingMode.SINGLE_AGENT) {
            when (activeRole) {
                UserRole.WORK -> {
                    if (complexityScore >= 0.35 || requiredCapabilities.size >= 2) {
                        mode = RoutingMode.MULTI_AGENT
                        reasonCodes += RoleReasonCodes.ROLE_ROUTE_BIAS_APPLIED
                        reasonCodes += "role_work_prefers_parallel_specialists"
                    }
                }

                UserRole.BUYER, UserRole.TRAVELER -> {
                    val rolePolicy = roleContext.rolePolicyProfile
                    val routeEscalationEnabled = rolePolicy.preferences.externalFulfillmentAllowed &&
                        rolePolicy.preferences.externalFulfillmentPreference != ExternalFulfillmentPreference.INTERNAL_FIRST
                    if (routeEscalationEnabled && requiresLiveData && riskScore >= 0.32) {
                        mode = RoutingMode.MULTI_AGENT
                        reasonCodes += RoleReasonCodes.ROLE_ROUTE_BIAS_APPLIED
                        reasonCodes += "role_market_needs_quote_comparison"
                    } else if (!routeEscalationEnabled && requiresLiveData) {
                        reasonCodes += RoleReasonCodes.ROLE_ROUTE_EXCLUDED
                        reasonCodes += "role_policy_internal_first_or_external_disabled"
                    }
                }

                UserRole.PARENT -> {
                    if (riskScore >= 0.45) {
                        mode = RoutingMode.MULTI_AGENT
                        reasonCodes += RoleReasonCodes.ROLE_ROUTE_BIAS_APPLIED
                        reasonCodes += "role_parent_prefers_extra_verification"
                    }
                }

                UserRole.PERSONAL, UserRole.CUSTOM -> Unit
            }
        }
        if (mode == RoutingMode.MULTI_AGENT) {
            reasonCodes.remove("default_single_agent")
        }
        if (reasonCodes.isEmpty()) {
            reasonCodes += "default_single_agent"
        }

        val routingDecision = RoutingDecisionPayload(
            mode = mode,
            reasonCodes = reasonCodes,
            scores = RoutingScoresPayload(
                complexity = complexityScore,
                risk = riskScore,
                dependency = if (dependencyDepth >= routingConfig.thresholds.dependencyMin) 0.85 else 0.35
            )
        )

        val taskGraph = buildTaskGraph(requiredCapabilities, dependencyDepth, mode)
        val primaryDomain = inferPrimaryDomain(domains, module)
        val riskClass = when {
            riskScore >= routingConfig.thresholds.riskMin -> "high"
            riskScore >= 0.4 -> "medium"
            else -> "low"
        }
        val skillRequirements = skillPolicyEngine.buildRequirements(
            tasks = taskGraph.tasks,
            constraints = resolvedConstraints,
            activeRole = activeRole,
            primaryDomain = primaryDomain,
            riskClass = riskClass,
            requiresLiveData = requiresLiveData
        )
        val selectionBundle = skillSelectionEngine.select(
            requirements = skillRequirements,
            twinState = request.stateVector ?: dynamicStateByUser[request.userId],
            activeRole = activeRole,
            discovery = ::discoverSkillCandidates
        )

        return OrchestrationMeta(
            routingDecision = routingDecision,
            taskGraph = taskGraph,
            skillInvocations = selectionBundle.skillInvocations,
            skillGap = selectionBundle.skillGap,
            skillRequirements = skillRequirements,
            skillCandidates = selectionBundle.skillCandidates,
            skillAcquisitionDecisions = selectionBundle.decisions,
            skillCanaryReports = selectionBundle.canaryReports,
            skillPromotionRecords = selectionBundle.promotionRecords,
            skillSelectionTrace = selectionBundle.selectionTrace
        )
    }

    private fun detectCapabilities(
        raw: String,
        module: ModuleId,
        intent: IntentType
    ): List<String> {
        val caps = mutableListOf<String>()
        caps += requiredCapabilitiesForIntent(intent)

        if (raw.contains("rewrite") || raw.contains("rephrase") || raw.contains("reply")) {
            caps += "rewrite_assist"
        }
        if (raw.contains("flight") || raw.contains("机票")) {
            caps += "flight_search"
        }
        if (raw.contains("hotel") || raw.contains("酒店")) {
            caps += "hotel_search"
        }
        if (
            raw.contains("restaurant") ||
            raw.contains("dining") ||
            raw.contains("food") ||
            raw.contains("餐厅") ||
            raw.contains("美食")
        ) {
            caps += "restaurant_search"
        }
        if (
            raw.contains("attraction") ||
            raw.contains("sightseeing") ||
            raw.contains("landmark") ||
            raw.contains("museum") ||
            raw.contains("景点")
        ) {
            caps += "attraction_search"
        }
        if (raw.contains("transport") || raw.contains("airport transfer") || raw.contains("交通")) {
            caps += "local_transport"
        }
        if (raw.contains("itinerary") || raw.contains("行程")) {
            caps += "itinerary_plan"
        }
        if (raw.contains("search") || raw.contains("query") || raw.contains("搜索")) {
            caps += "web_search"
        }
        if (raw.contains("live") || raw.contains("latest") || raw.contains("market") || raw.contains("实时")) {
            caps += "live_search"
        }
        if (raw.contains("github") || raw.contains("repository") || raw.contains("manifest")) {
            caps += "github_import"
        }
        if (raw.contains("Avatar") || raw.contains("twin") || raw.contains("avatar")) {
            caps += "avatar_profile"
        }
        if (raw.contains("destiny") || raw.contains("navigation") || raw.contains("bellman")) {
            caps += "destiny_navigation"
        }
        if (raw.contains("lix") || raw.contains("offer") || raw.contains("close") || raw.contains("intent")) {
            caps += "lix_negotiation"
        }

        if (caps.isEmpty()) {
            caps += when (module) {
                ModuleId.LIX -> "lix_negotiation"
                ModuleId.AGENT_MARKET -> "agent_discovery"
                ModuleId.AVATAR -> "avatar_profile"
                ModuleId.DESTINY -> "destiny_navigation"
                else -> "general_reasoning"
            }
        }
        val capLimit = when {
            intent == IntentType.TRAVEL ||
                raw.contains("travel") ||
                raw.contains("trip") ||
                raw.contains("旅行") ||
                raw.contains("机票") ||
                raw.contains("酒店") -> 6
            else -> 4
        }
        return caps.distinct().take(capLimit)
    }

    private fun detectDomains(capabilities: List<String>, module: ModuleId): Set<String> {
        val domains = mutableSetOf<String>()
        capabilities.forEach { cap ->
            when {
                cap.contains("flight") ||
                    cap.contains("hotel") ||
                    cap.contains("transport") ||
                    cap.contains("itinerary") ||
                    cap.contains("restaurant") ||
                    cap.contains("attraction") -> domains += "travel"
                cap.contains("lix") || cap.contains("negotiation") -> domains += "lix"
                cap.contains("agent") || cap.contains("github") -> domains += "agent_market"
                cap.contains("avatar") || cap.contains("profile") -> domains += "avatar"
                cap.contains("destiny") -> domains += "destiny"
                else -> domains += "chat"
            }
        }
        domains += when (module) {
            ModuleId.CHAT -> "chat"
            ModuleId.LIX -> "lix"
            ModuleId.AGENT_MARKET -> "agent_market"
            ModuleId.AVATAR -> "avatar"
            ModuleId.DESTINY -> "destiny"
            ModuleId.HOME -> "home"
            ModuleId.SETTINGS -> "settings"
        }
        return domains
    }

    private fun inferPrimaryDomain(domains: Set<String>, module: ModuleId): String {
        val normalized = domains.map { it.lowercase() }.toSet()
        val priority = listOf(
            "travel",
            "finance",
            "health",
            "legal",
            "lix",
            "agent_market",
            "avatar",
            "destiny",
            "chat"
        )
        priority.firstOrNull { normalized.contains(it) }?.let { return it }
        return when (module) {
            ModuleId.CHAT -> "chat"
            ModuleId.LIX -> "lix"
            ModuleId.AGENT_MARKET -> "agent_market"
            ModuleId.AVATAR -> "avatar"
            ModuleId.DESTINY -> "destiny"
            ModuleId.HOME -> "home"
            ModuleId.SETTINGS -> "settings"
        }
    }

    private fun inferDependencyDepth(
        raw: String,
        requiredCapabilityCount: Int,
        config: RoutingScoreConfig
    ): Int {
        if (requiredCapabilityCount >= config.thresholds.capabilitiesMin) return 2
        val hasDependencyKeyword = config.dependencyKeywords.any(raw::contains) ||
            raw.contains("然后") ||
            raw.contains("先") ||
            raw.contains("再") ||
            raw.contains("同时")
        return if (hasDependencyKeyword) {
            2
        } else {
            1
        }
    }

    private fun inferRiskScore(raw: String, module: ModuleId, config: RoutingScoreConfig): Double {
        val highRiskKeyword = config.highRiskKeywords.any(raw::contains)
        if (highRiskKeyword) return config.riskProfile.highRiskScore
        if (module == ModuleId.SETTINGS) return config.riskProfile.settingsRiskScore
        return config.riskProfile.defaultRiskScore
    }

    private fun buildTaskGraph(
        capabilities: List<String>,
        dependencyDepth: Int,
        mode: RoutingMode
    ): TaskGraphPayload {
        val tasks = capabilities.mapIndexed { index, capability ->
            TaskGraphTaskPayload(
                id = "task_${index + 1}",
                title = readableTaskTitle(capability),
                requiredCapabilities = listOf(capability)
            )
        }

        val edges = mutableListOf<TaskGraphEdgePayload>()
        if (dependencyDepth >= 2 && tasks.size >= 2) {
            for (i in 0 until tasks.lastIndex) {
                edges += TaskGraphEdgePayload(fromTaskId = tasks[i].id, toTaskId = tasks[i + 1].id)
            }
        }

        val criticalPath = when {
            tasks.isEmpty() -> emptyList()
            edges.isEmpty() -> listOf(tasks.first().id)
            else -> tasks.map { it.id }
        }

        val parallelGroups = if (mode == RoutingMode.MULTI_AGENT && tasks.size > 1) {
            if (dependencyDepth >= 2 && tasks.size > 2) {
                listOf(tasks.dropLast(1).map { it.id })
            } else {
                listOf(tasks.map { it.id })
            }
        } else {
            emptyList()
        }

        return TaskGraphPayload(
            tasks = tasks,
            edges = edges,
            criticalPath = criticalPath,
            parallelGroups = parallelGroups
        )
    }

    private fun readableTaskTitle(capability: String): String {
        return when {
            capability.contains("rewrite") -> "Rewrite and expression optimization"
            capability.contains("flight") -> "Flight retrieval"
            capability.contains("hotel") -> "Hotel retrieval"
            capability.contains("restaurant") -> "Restaurant shortlisting"
            capability.contains("attraction") -> "Attraction shortlisting"
            capability.contains("transport") -> "Local transport plan"
            capability.contains("itinerary") -> "Itinerary planning"
            capability.contains("live") -> "Live evidence retrieval"
            capability.contains("web_search") -> "Web search"
            capability.contains("github") -> "GitHub capability discovery"
            capability.contains("lix") -> "LIX intent and offer handling"
            capability.contains("avatar") -> "Digital twin avatar update"
            capability.contains("destiny") -> "Navigation strategy evaluation"
            else -> "General task reasoning"
        }
    }

    private fun buildSkillRequirements(
        tasks: List<TaskGraphTaskPayload>,
        constraints: AgentRequestConstraints
    ): List<SkillRequirement> {
        val maxCostTier = normalizeCostTier(constraints.maxCostPerStep)
        val minimumEvidence = when (normalizeRiskTolerance(constraints.riskTolerance)) {
            "low" -> "strong"
            "medium" -> "mid"
            else -> "weak"
        }
        return tasks.map { task ->
            val capability = task.requiredCapabilities.firstOrNull() ?: "general_reasoning"
            SkillRequirement(
                taskId = task.id,
                capability = capability,
                maxLatencyMs = when {
                    capability.contains("live") || capability.contains("flight") || capability.contains("hotel") -> 4_500
                    else -> 7_500
                },
                minimumEvidenceLevel = minimumEvidence,
                maxCostTier = maxCostTier
            )
        }
    }

    private fun runSkillAcquisition(requirements: List<SkillRequirement>): SkillAcquisitionBundle {
        val candidates = mutableListOf<SkillCandidate>()
        val decisions = mutableListOf<SkillAcquisitionDecision>()
        val canaryReports = mutableListOf<SkillCanaryReport>()
        val promotionRecords = mutableListOf<SkillPromotionRecord>()
        val invocations = mutableListOf<SkillInvocationPayload>()
        val missingCapabilities = mutableListOf<String>()

        requirements.forEach { requirement ->
            val discovered = discoverSkillCandidates(requirement)
            candidates += discovered

            val selected = discovered
                .filter { passesSkillGates(it, requirement) }
                .maxByOrNull { it.score.totalScore }

            if (selected == null) {
                missingCapabilities += requirement.capability
                decisions += SkillAcquisitionDecision(
                    taskId = requirement.taskId,
                    capability = requirement.capability,
                    selectedSkillId = null,
                    status = SkillAcquisitionDecisionStatus.FALLBACK_TO_MARKET,
                    reason = "no_admitted_candidate"
                )
                invocations += SkillInvocationPayload(
                    skillId = "template:${requirement.capability}",
                    source = SkillSource.LOCAL_TEMPLATE,
                    status = ResponseStatus.PARTIAL,
                    latencyMs = 0,
                    evidenceCount = 0,
                    sandboxLevel = SkillSandboxLevel.NONE
                )
                return@forEach
            }

            if (selected.source == SkillSource.GITHUB) {
                val canary = runCanary(selected, requirement)
                canaryReports += canary
                if (!canary.passed) {
                    missingCapabilities += requirement.capability
                    decisions += SkillAcquisitionDecision(
                        taskId = requirement.taskId,
                        capability = requirement.capability,
                        selectedSkillId = selected.id,
                        status = SkillAcquisitionDecisionStatus.QUARANTINED,
                        reason = "canary_failed"
                    )
                    promotionRecords += SkillPromotionRecord(
                        skillId = selected.id,
                        fromLevel = SkillSandboxLevel.SANDBOX,
                        toLevel = SkillSandboxLevel.QUARANTINE,
                        promoted = false,
                        reason = "canary_validation_failed"
                    )
                    invocations += SkillInvocationPayload(
                        skillId = "template:${requirement.capability}",
                        source = SkillSource.LOCAL_TEMPLATE,
                        status = ResponseStatus.PARTIAL,
                        latencyMs = 0,
                        evidenceCount = 0,
                        sandboxLevel = SkillSandboxLevel.NONE
                    )
                    return@forEach
                }
                promotionRecords += SkillPromotionRecord(
                    skillId = selected.id,
                    fromLevel = SkillSandboxLevel.SANDBOX,
                    toLevel = SkillSandboxLevel.APPROVED,
                    promoted = true,
                    reason = "canary_passed_with_evidence"
                )
            }

            decisions += SkillAcquisitionDecision(
                taskId = requirement.taskId,
                capability = requirement.capability,
                selectedSkillId = selected.id,
                status = SkillAcquisitionDecisionStatus.SELECTED,
                reason = "best_scored_admitted_candidate"
            )
            invocations += SkillInvocationPayload(
                skillId = selected.id,
                source = selected.source,
                status = ResponseStatus.SUCCESS,
                latencyMs = selected.latencyP95Ms,
                evidenceCount = evidenceLevelRank(selected.evidenceLevel),
                sandboxLevel = selected.sandboxLevel
            )
        }

        return SkillAcquisitionBundle(
            skillInvocations = invocations.take(12),
            skillGap = buildSkillGap(missingCapabilities),
            skillCandidates = candidates.take(18),
            decisions = decisions.take(12),
            canaryReports = canaryReports.take(12),
            promotionRecords = promotionRecords.take(12)
        )
    }

    private fun discoverSkillCandidates(requirement: SkillRequirement): List<SkillCandidate> {
        val capability = requirement.capability
        val localCatalog = localSkillCatalog()
        val matchedLocal = localCatalog.filter { profile ->
            profile.capabilities.any { candidateCapability ->
                candidateCapability.equals(capability, ignoreCase = true) ||
                    candidateCapability.contains(capability, ignoreCase = true) ||
                    capability.contains(candidateCapability, ignoreCase = true)
            }
        }
        val githubCandidate = SkillCandidateProfile(
            id = "github:$capability",
            source = SkillSource.GITHUB,
            capabilities = setOf(capability),
            successRate = 0.91,
            latencyP95Ms = 3_600,
            evidenceLevel = if (capability.contains("search")) "strong" else "mid",
            costTier = "mid",
            sandboxLevel = SkillSandboxLevel.SANDBOX,
            policyTags = listOf("decision_support_only"),
            requiredPermissions = listOf("network"),
            safetyLevel = "decision_support_only",
            lastVerifiedAt = nowMs(),
            policyPassed = true
        )

        val merged = (matchedLocal + githubCandidate).map { profile ->
            val score = scoreSkillCandidate(profile, requirement)
            val admissionPassed = when (profile.source) {
                SkillSource.LOCAL -> true
                SkillSource.GITHUB -> profile.successRate >= 0.9 &&
                    profile.latencyP95Ms <= 4_000 &&
                    evidenceLevelRank(profile.evidenceLevel) >= 2
                SkillSource.TRUSTED_CATALOG -> true
                SkillSource.LOCAL_TEMPLATE -> true
            }
            val effectiveSandbox = when {
                profile.source == SkillSource.LOCAL -> SkillSandboxLevel.APPROVED
                !admissionPassed -> SkillSandboxLevel.QUARANTINE
                else -> SkillSandboxLevel.SANDBOX
            }
            SkillCandidate(
                id = profile.id,
                source = profile.source,
                capabilities = profile.capabilities.toList(),
                successRate = profile.successRate,
                latencyP95Ms = profile.latencyP95Ms,
                evidenceLevel = profile.evidenceLevel,
                costTier = profile.costTier,
                policyTags = profile.policyTags,
                requiredPermissions = profile.requiredPermissions,
                safetyLevel = profile.safetyLevel,
                lastVerifiedAt = profile.lastVerifiedAt,
                policyPassed = profile.policyPassed,
                sandboxLevel = effectiveSandbox,
                admissionPassed = admissionPassed,
                score = score
            )
        }
        return merged
            .sortedByDescending { it.score.totalScore }
            .take(4)
    }

    private fun scoreSkillCandidate(
        candidate: SkillCandidateProfile,
        requirement: SkillRequirement
    ): SkillScoreBreakdown {
        val capabilityFit = if (candidate.capabilities.contains(requirement.capability)) 1.0 else 0.0
        val successRateScore = candidate.successRate.coerceIn(0.0, 1.0)
        val baselineLatency = (requirement.maxLatencyMs ?: 8_000L).coerceAtLeast(1L)
        val latencyScore = (1.0 - (candidate.latencyP95Ms.toDouble() / baselineLatency.toDouble())).coerceIn(0.0, 1.0)
        val evidenceScore = (evidenceLevelRank(candidate.evidenceLevel) / 3.0).coerceIn(0.0, 1.0)
        val costScore = when (candidate.costTier.lowercase()) {
            "low" -> 1.0
            "mid" -> 0.7
            "high" -> 0.4
            else -> 0.5
        }
        val policyScore = if (candidate.policyPassed) 1.0 else 0.0
        val total = (
            capabilityFit * 0.30 +
                successRateScore * 0.20 +
                evidenceScore * 0.20 +
                latencyScore * 0.10 +
                costScore * 0.10 +
                policyScore * 0.10
            ).coerceIn(0.0, 1.0)
        return SkillScoreBreakdown(
            capabilityFit = capabilityFit,
            successRateScore = successRateScore,
            latencyScore = latencyScore,
            evidenceLevelScore = evidenceScore,
            costScore = costScore,
            policyScore = policyScore,
            finalScore = total,
            totalScore = total
        )
    }

    private fun passesSkillGates(candidate: SkillCandidate, requirement: SkillRequirement): Boolean {
        if (!candidate.admissionPassed) return false
        if (candidate.sandboxLevel == SkillSandboxLevel.QUARANTINE) return false
        val maxLatencyMs = requirement.maxLatencyMs
        if (maxLatencyMs != null && candidate.latencyP95Ms > maxLatencyMs) return false
        if (evidenceLevelRank(candidate.evidenceLevel) < evidenceLevelRank(requirement.minimumEvidenceLevel)) return false
        val maxCostTier = requirement.maxCostTier?.lowercase()?.takeIf { it.isNotBlank() } ?: return true
        val candidateRank = costTierRank(candidate.costTier)
        val maxRank = costTierRank(maxCostTier)
        return candidateRank <= maxRank
    }

    private fun runCanary(candidate: SkillCandidate, requirement: SkillRequirement): SkillCanaryReport {
        val evidenceCount = evidenceLevelRank(candidate.evidenceLevel).coerceAtLeast(1)
        val passed = candidate.successRate >= 0.92 &&
            candidate.latencyP95Ms <= (requirement.maxLatencyMs ?: 5_000) &&
            evidenceCount >= evidenceLevelRank(requirement.minimumEvidenceLevel)
        return SkillCanaryReport(
            taskId = requirement.taskId,
            skillId = candidate.id,
            passed = passed,
            sampleSize = 3,
            evidenceCount = evidenceCount,
            acceptanceNote = if (passed) {
                "canary_passed_with_traceable_evidence"
            } else {
                "canary_failed_or_evidence_insufficient"
            }
        )
    }

    private fun buildSkillGap(missingCapabilities: List<String>): SkillGapPayload? {
        if (missingCapabilities.isEmpty()) return null
        val frequency = if (missingCapabilities.size >= 2) 28 else 12
        return SkillGapPayload(
            missingCapability = missingCapabilities.first(),
            frequency7d = frequency,
            recommendedAction = if (frequency >= 20) {
                SkillGapRecommendation.ADD_SKILL
            } else {
                SkillGapRecommendation.REROUTE
            }
        )
    }

