    private fun normalizeRiskTolerance(raw: String?): String {
        val text = raw?.trim()?.lowercase().orEmpty()
        return when {
            text.contains("low") || text.contains("strict") || text.contains("保守") -> "low"
            text.contains("medium") || text.contains("mid") || text.contains("中") -> "medium"
            text.contains("high") || text.contains("aggressive") || text.contains("高") -> "high"
            else -> "medium"
        }
    }

    private fun normalizeCostTier(raw: String?): String? {
        val text = raw?.trim()?.lowercase().orEmpty()
        if (text.isBlank()) return null
        return when {
            text.contains("low") || text.contains("低") -> "low"
            text.contains("mid") || text.contains("medium") || text.contains("中") -> "mid"
            text.contains("high") || text.contains("高") -> "high"
            else -> null
        }
    }

    private fun costTierRank(raw: String): Int {
        return when (raw.trim().lowercase()) {
            "low" -> 1
            "mid", "medium" -> 2
            "high" -> 3
            else -> 2
        }
    }

    private fun evidenceLevelRank(raw: String): Int {
        return when (raw.trim().lowercase()) {
            "weak" -> 1
            "mid", "medium" -> 2
            "strong" -> 3
            else -> 1
        }
    }

    private suspend fun loadCloudTwinPosterior(
        cloudGateway: CloudGateway,
        userId: String
    ): TwinPosteriorPayload? {
        if (!digitalTwinCloudSyncEnabled || userId.isBlank()) return null
        return runCatching {
            val result = cloudGateway.twinPosterior(userId)
            if (result.success) result.data else null
        }.getOrNull()
    }

    private fun ModulePayload.LixPayload.withPosterior(
        posterior: TwinPosteriorPayload?
    ): ModulePayload.LixPayload {
        return if (posterior == null) this else this.copy(posterior = posterior)
    }

    private fun buildAvatarPayload(
        userId: String,
        summary: com.lumi.coredomain.contract.DigitalSoulSummary,
        posterior: TwinPosteriorPayload? = null,
        activeRole: UserRole = activeRoleByUser[userId] ?: UserRole.PERSONAL
    ): ModulePayload.AvatarPayload {
        restoreDynamicStateIfNeeded(userId)
        val dynamicState = dynamicStateByUser[userId]
        val twinSync = twinSyncStatusProvider()
        val syncStatus = twinSync?.status ?: if (digitalTwinCloudSyncEnabled) "pending" else "local_only"
        val rolePolicy = effectiveRolePolicyProfile(userId, activeRole)
        return ModulePayload.AvatarPayload(
            profileLabel = summary.profileLabel,
            topTraits = summary.topTraits,
            cloudSyncEnabled = digitalTwinCloudSyncEnabled,
            consensus = dynamicState?.let(::buildStateConsensus),
            trajectory = loadTrajectory(userId, 14),
            auraState = dynamicState?.let(::buildAuraState),
            stateVector = dynamicState,
            posterior = posterior,
            activeRole = activeRole,
            rolePolicyProfile = rolePolicy,
            rolePolicyEditor = getRolePolicyEditorState(userId, activeRole),
            stablePreferences = buildStablePreferenceSummary(summary.topTraits),
            approvalRules = buildApprovalRules(rolePolicy),
            dataSharingScope = buildDataSharingScope(syncStatus, rolePolicy),
            syncStatus = syncStatus,
            syncLastUpdatedAtMs = twinSync?.lastSyncAtMs,
            localCloudExplanation = buildLocalCloudExplanation(syncStatus),
            constraintPriorityNote = "Current task constraints override long-term preferences in every run."
        )
    }

    fun shouldSyncTwinToCloud(
        userId: String,
        activeRole: UserRole? = null
    ): Boolean {
        if (!digitalTwinCloudSyncEnabled || userId.isBlank()) return false
        restoreDynamicStateIfNeeded(userId)
        val resolvedRole = activeRole ?: activeRoleByUser[userId] ?: UserRole.PERSONAL
        return effectiveRolePolicyProfile(userId, resolvedRole).dataPolicy.cloudSyncAllowed
    }

    private fun buildStablePreferenceSummary(
        traits: List<com.lumi.coredomain.contract.TraitScore>
    ): List<String> {
        if (traits.isEmpty()) {
            return listOf("No stable preferences learned yet. Continue using WORK and IME to build profile continuity.")
        }
        return traits
            .sortedByDescending { normalizeTwinTraitScore(it.value) }
            .take(4)
            .map { trait ->
                val normalized = (normalizeTwinTraitScore(trait.value) * 100).toInt()
                "${trait.key.replace('_', ' ')}: $normalized%"
            }
    }

    private fun hasRolePolicyOverride(userId: String, role: UserRole): Boolean {
        return rolePolicyOverridesByUser[userId]?.containsKey(role) == true
    }

    private fun effectiveRolePolicyProfile(userId: String, role: UserRole): RolePolicyProfile {
        val default = rolePolicyProfile(role)
        val override = rolePolicyOverridesByUser[userId]?.get(role) ?: return default
        return mergeRolePolicy(default, override)
    }

    private fun mergeRolePolicy(
        default: RolePolicyProfile,
        override: RolePolicyProfile
    ): RolePolicyProfile {
        return default.copy(
            role = default.role,
            preferences = default.preferences.copy(
                riskToleranceDefault = normalizeRiskTolerance(
                    override.preferences.riskToleranceDefault ?: default.preferences.riskToleranceDefault
                ),
                maxCostPerStepDefault = normalizeCostTier(
                    override.preferences.maxCostPerStepDefault ?: default.preferences.maxCostPerStepDefault
                ) ?: default.preferences.maxCostPerStepDefault,
                trustedProviderTags = normalizedTags(
                    override.preferences.trustedProviderTags.ifEmpty { default.preferences.trustedProviderTags }
                ),
                blockedProviderTags = normalizedTags(
                    override.preferences.blockedProviderTags.ifEmpty { default.preferences.blockedProviderTags }
                ),
                externalFulfillmentAllowed = override.preferences.externalFulfillmentAllowed,
                externalFulfillmentPreference = override.preferences.externalFulfillmentPreference
            ),
            approvalPolicy = default.approvalPolicy.copy(
                delegationMode = override.approvalPolicy.delegationMode,
                requiresExplicitConfirmationForHighRisk = override.approvalPolicy.requiresExplicitConfirmationForHighRisk,
                requiresConfirmationTokenForExternalSpend = override.approvalPolicy.requiresConfirmationTokenForExternalSpend,
                autoApprovalBudgetLimit = override.approvalPolicy.autoApprovalBudgetLimit,
                maxExternalBudget = override.approvalPolicy.maxExternalBudget
            ),
            dataPolicy = default.dataPolicy.copy(
                sharingMode = override.dataPolicy.sharingMode.ifBlank { default.dataPolicy.sharingMode },
                allowedScopes = override.dataPolicy.allowedScopes.ifEmpty { default.dataPolicy.allowedScopes },
                cloudSyncAllowed = override.dataPolicy.cloudSyncAllowed
            ),
            delegationPolicy = default.delegationPolicy.copy(
                mode = override.delegationPolicy.mode,
                requiresReapprovalOnRoleChange = override.delegationPolicy.requiresReapprovalOnRoleChange
            ),
            version = default.version
        )
    }

    private fun normalizedTags(tags: List<String>): List<String> {
        return tags
            .asSequence()
            .map { it.trim().lowercase().replace(' ', '_') }
            .filter { it.isNotBlank() }
            .distinct()
            .toList()
    }

