    private fun buildApprovalRules(rolePolicy: RolePolicyProfile): List<String> {
        val rules = mutableListOf(
            "High-risk actions require explicit user confirmation.",
            "Active role: ${rolePolicy.role.name.lowercase()} (${rolePolicy.approvalPolicy.delegationMode.name.lowercase()})",
            "External spend or contract steps require a valid confirmation token unless explicitly auto-approved within role policy.",
            "Missing constraints always trigger follow-up prompts; requirements are never fabricated."
        )
        rolePolicy.approvalPolicy.autoApprovalBudgetLimit?.takeIf { it >= 0.0 }?.let { autoLimit ->
            if (autoLimit == 0.0) {
                rules += "Auto-approval budget is disabled for this role."
            } else {
                rules += "Auto-approval budget: ${autoLimit.toInt()}."
            }
        }
        rolePolicy.approvalPolicy.maxExternalBudget?.takeIf { it > 0 }?.let { maxBudget ->
            rules += "Role budget guard: external budget must stay within ${maxBudget.toInt()}."
        }
        val externalPreference = rolePolicy.preferences.externalFulfillmentPreference.name
            .lowercase()
            .replace('_', ' ')
        rules += if (rolePolicy.preferences.externalFulfillmentAllowed) {
            "External fulfillment is enabled with $externalPreference preference."
        } else {
            "External fulfillment is disabled by role policy."
        }
        rules += if (digitalTwinCloudSyncEnabled) {
            "Cloud sync writes only approved, scoped data after local-first processing."
        } else {
            "Cloud sync is disabled; twin state remains local by default."
        }
        return rules
    }

    private fun buildDataSharingScope(syncStatus: String, rolePolicy: RolePolicyProfile): List<String> {
        val scope = mutableListOf(
            "Local scope: profile traits, dynamic state vector, and trajectory history.",
            "Role policy scope: ${rolePolicy.dataPolicy.allowedScopes.joinToString(", ").ifBlank { "minimal_task_context" }}",
            "Sensitive actions remain gated by explicit confirmation and policy checks."
        )
        if (rolePolicy.preferences.trustedProviderTags.isNotEmpty()) {
            scope += "Trusted provider tags: ${rolePolicy.preferences.trustedProviderTags.joinToString(", ")}."
        }
        if (rolePolicy.preferences.blockedProviderTags.isNotEmpty()) {
            scope += "Blocked provider tags: ${rolePolicy.preferences.blockedProviderTags.joinToString(", ")}."
        }
        if (digitalTwinCloudSyncEnabled && rolePolicy.dataPolicy.cloudSyncAllowed) {
            scope += "Cloud scope: redacted state packet + limited trajectory for continuity."
            scope += "Current sync status: $syncStatus"
        } else {
            scope += "Cloud scope: disabled (local-only mode)."
        }
        return scope
    }

    private fun buildLocalCloudExplanation(syncStatus: String): String {
        if (!digitalTwinCloudSyncEnabled) {
            return "Local-first mode: preferences and state stay on-device unless cloud sync is explicitly enabled."
        }
        return when (syncStatus.lowercase()) {
            "synced" -> "Local and cloud twin snapshots are aligned; personalization can resume seamlessly across sessions."
            "conflict_fallback" -> "A sync conflict was detected; local state stayed authoritative while fallback reconciliation was applied."
            "failed_fallback" -> "Cloud sync failed; local state remains authoritative and safe fallback mode is active."
            "pending" -> "Cloud sync is enabled but pending first successful upload."
            else -> "Cloud sync is enabled with local-first safeguards."
        }
    }

    private fun buildStateConsensus(state: DynamicHumanStatePayload): StateConsensusPayload {
        val stress = state.l3.stressScore
        val focus = state.l3.focusScore
        val polarity = state.l3.polarity

        val energyLabel = when {
            state.l2.energyLevel >= 0.72 -> "high"
            state.l2.energyLevel >= 0.42 -> "medium"
            else -> "low"
        }
        val moodLabel = when {
            polarity >= 0.25 -> "positive"
            polarity <= -0.25 -> "negative"
            else -> "steady"
        }
        val focusLabel = when {
            focus >= 75 -> "focused"
            focus >= 45 -> "normal"
            else -> "scattered"
        }
        val strategyLabel = when {
            stress >= 70 -> "short_action_first"
            focus >= 75 -> "deep_reasoning"
            else -> "balanced"
        }

        return StateConsensusPayload(
            energyLabel = energyLabel,
            moodLabel = moodLabel,
            focusLabel = focusLabel,
            strategyLabel = strategyLabel
        )
    }

    private fun buildAuraState(state: DynamicHumanStatePayload): AuraStatePayload {
        val color = when {
            state.l3.stressScore >= 70 -> "#FF6B5A"
            state.l3.polarity >= 0.2 -> "#2AC7FF"
            else -> "#5B8CFF"
        }
        val intensity = (
            (state.l3.stressScore / 100.0) * 0.65 +
                ((100 - state.l3.focusScore) / 100.0) * 0.35
            ).coerceIn(0.15, 1.0)
        val breathingRate = (0.9 + intensity * 0.8).coerceIn(0.9, 1.7)
        return AuraStatePayload(
            colorHex = color,
            intensity = intensity,
            breathingRate = breathingRate
        )
    }

    private fun loadTrajectory(userId: String, maxDays: Int): List<TrajectoryPointPayload> {
        val cutoff = nowMs() - maxDays.coerceAtLeast(1) * 24L * 60L * 60L * 1000L
        return synchronized(dynamicStateLock) {
            trajectoryByUser[userId]
                ?.filter { it.ts >= cutoff }
                ?.toList()
                .orEmpty()
        }
    }

    private fun updateDynamicState(userId: String, state: DynamicHumanStatePayload) {
        dynamicStateByUser[userId] = state
        val point = TrajectoryPointPayload(
            ts = state.updatedAtMs.takeIf { it > 0 } ?: nowMs(),
            value = computeTrajectoryScore(state),
            label = "state_update"
        )
        synchronized(dynamicStateLock) {
            val queue = trajectoryByUser.getOrPut(userId) { ArrayDeque() }
            queue.addLast(point)
            while (queue.size > MAX_TRAJECTORY_POINTS) {
                queue.removeFirst()
            }
        }
        persistDynamicState(userId)
    }

    private fun ensureRemoteResourcesInitializedLocked(userId: String) {
        if (userId.isBlank()) return
        val now = nowMs()

        val directoryQueue = remoteOperatorDirectoryByUser.getOrPut(userId) { ArrayDeque() }
        if (directoryQueue.isEmpty()) {
            val fallbackRole = defaultOperatorRole(userId)
            val fallbackTeam = RemoteOperatorTeam(
                teamId = "team_local_ops",
                displayName = "Local Ops",
                slug = "local-ops",
                permissionDefaults = defaultPermissionsForRole(fallbackRole),
                updatedAtMs = now
            )
            directoryQueue.addLast(
                RemoteOperatorDirectoryEntry(
                    entryId = "directory_${userId.lowercase()}_fallback",
                    userId = userId,
                    identity = RemoteOperatorIdentity(
                        operatorId = "op_${userId.lowercase()}",
                        displayName = defaultOperatorDisplayName(userId),
                        teamId = fallbackTeam.teamId,
                        role = fallbackRole,
                        permissions = defaultPermissionsForRole(fallbackRole),
                        scope = PermissionScope.ANY_CASE,
                        active = true,
                        directorySource = RemoteOperatorDirectorySource.LOCAL_FALLBACK,
                        directoryVersion = "local_fallback_v1",
                        enterpriseIdentityId = "ent_${userId.lowercase()}",
                        enterpriseDirectorySource = EnterpriseDirectorySource.LOCAL_ONLY,
                        enterpriseDirectoryVersion = "local_only_v1",
                        scimRecord = ScimLikeDirectoryRecord(
                            recordId = "scim_${userId.lowercase()}",
                            externalId = userId,
