                        status = RemoteIdentityLinkStatus.LOCAL_ONLY,
                        source = EnterpriseDirectorySource.LOCAL_ONLY,
                        identityAssertion = EnterpriseIdentityAssertion(
                            assertionId = "assertion_local_${userId.lowercase()}_$now",
                            idpProvider = EnterpriseIdpProvider.UNKNOWN,
                            subjectId = userId,
                            assertedAtMs = now,
                            summary = "No enterprise SSO assertion is configured for local fallback context."
                        ),
                        linkedAtMs = now,
                        summary = "No remote enterprise directory link is configured."
                    )
                )
            )
        }

        val destinationQueue = connectorDestinationsByUser.getOrPut(userId) { ArrayDeque() }
        if (destinationQueue.isEmpty()) {
            destinationQueue.addAll(defaultConnectorDestinations(now))
        }

        val authProfileQueue = connectorAuthProfilesByUser.getOrPut(userId) { ArrayDeque() }
        if (authProfileQueue.isEmpty()) {
            authProfileQueue.addAll(defaultConnectorAuthProfiles(now))
        }

        val routeBindingQueue = connectorRouteBindingsByUser.getOrPut(userId) { ArrayDeque() }
        if (routeBindingQueue.isEmpty()) {
            routeBindingQueue.addAll(defaultConnectorRouteBindings())
        }
    }

