    private fun restoreDynamicStateIfNeeded(userId: String) {
        if (userId.isBlank()) return
        if (!restoredUsers.add(userId)) return

        val restored = runCatching {
            dynamicStatePersistence?.load(userId)
        }.getOrNull() ?: return

        restored.dynamicState?.let { dynamicStateByUser[userId] = it }
        if (restored.trajectory.isNotEmpty()) {
            synchronized(dynamicStateLock) {
                val queue = trajectoryByUser.getOrPut(userId) { ArrayDeque() }
                queue.clear()
                restored.trajectory
                    .takeLast(MAX_TRAJECTORY_POINTS)
                    .forEach(queue::addLast)
            }
        }
        restored.activeRole?.let { restoredRole ->
            activeRoleByUser[userId] = restoredRole
            val restoredSource = restored.roleSource ?: RoleSource.USER_PROFILE_DEFAULT
            activeRoleSourceByUser[userId] = restoredSource
            pendingSystemRecoveryByUser.add(userId)
            if (restoredSource == RoleSource.USER_PROFILE_DEFAULT) {
                roleSessionByUser.remove(userId)
            }
        }
        if (restored.rolePolicyOverrides.isNotEmpty()) {
            val map = rolePolicyOverridesByUser.getOrPut(userId) { ConcurrentHashMap() }
            map.clear()
            restored.rolePolicyOverrides.forEach { (role, policy) ->
                map[role] = policy
            }
        }
        if (restored.executionLedgerRecords.isNotEmpty()) {
            synchronized(dynamicStateLock) {
                val queue = executionLedgerByUser.getOrPut(userId) { ArrayDeque() }
                queue.clear()
                restored.executionLedgerRecords
                    .takeLast(MAX_LEDGER_RECORDS)
                    .forEach(queue::addLast)
            }
        }
        if (restored.telemetryEmissionRecords.isNotEmpty()) {
            synchronized(dynamicStateLock) {
                val queue = telemetryRecordsByUser.getOrPut(userId) { ArrayDeque() }
                queue.clear()
                restored.telemetryEmissionRecords
