            trajectoryByUser[userId]?.toList().orEmpty()
        }
        val roleSource = activeRoleSourceByUser[userId]
        val activeRole = if (roleSource == RoleSource.SAFE_SYSTEM_INFERENCE || roleSource == RoleSource.SYSTEM_FALLBACK) {
            null
        } else {
            activeRoleByUser[userId]
        }
        val rolePolicyOverrides = rolePolicyOverridesByUser[userId]?.toMap().orEmpty()
