    private fun computeTrajectoryScore(state: DynamicHumanStatePayload): Double {
        val assetScore = (0.35 + state.l1.riskPreference * 0.3).coerceIn(0.0, 1.0)
        val capabilityScore = (0.4 + state.l2.contextLoad * 0.35 + state.l3.focusScore / 100.0 * 0.25).coerceIn(0.0, 1.0)
        val wellbeingScore = (
            0.5 +
                state.l3.polarity * 0.22 -
                (state.l3.stressScore / 100.0) * 0.28
            ).coerceIn(0.0, 1.0)
        return (
            assetScore * 0.30 +
                capabilityScore * 0.35 +
                wellbeingScore * 0.35
            ).coerceIn(0.0, 1.0)
    }

    private fun buildFallbackDynamicState(
        request: AgentRequest,
        keystroke: KeystrokeDynamicsPayload
    ): DynamicHumanStatePayload {
        val stress = (keystroke.stressProxy.coerceIn(0.0, 1.0) * 100).toInt().coerceIn(0, 100)
        val focus = (
            100.0 -
                (keystroke.pauseCount * 6.0) -
                (keystroke.backspaceCount * 4.0)
            ).toInt().coerceIn(15, 95)
        return DynamicHumanStatePayload(
            l1 = L1CoreStatePayload(
                profileId = "fallback-lite",
                valueAnchor = "balanced",
                riskPreference = 0.5
            ),
            l2 = L2ContextStatePayload(
                sourceApp = request.sourceApp,
                appCategory = "general",
                energyLevel = (1.0 - stress / 100.0).coerceIn(0.0, 1.0),
                contextLoad = (keystroke.keyCount / 40.0).coerceIn(0.0, 1.0)
            ),
            l3 = L3EmotionStatePayload(
                stressScore = stress,
                polarity = (0.2 - keystroke.stressProxy * 0.6).coerceIn(-1.0, 1.0),
                focusScore = focus
            ),
            updatedAtMs = request.timestampMs
        )
    }

