    private fun ModuleId.label(): String {
        return when (this) {
            ModuleId.HOME -> "Home"
            ModuleId.CHAT -> "Chat"
            ModuleId.LIX -> "LIX"
            ModuleId.AGENT_MARKET -> "Agent"
            ModuleId.AVATAR -> "Avatar"
            ModuleId.DESTINY -> "Navigation"
            ModuleId.SETTINGS -> "Settings"
        }
    }

